import { useState } from "react";
import { useGetLogs } from "@workspace/api-client-react";
import { Card, Badge, Modal } from "@/components/ui/Shared";
import { CheckCircle2, AlertCircle, Clock, Send, Search, ListFilter } from "lucide-react";
import { format } from "date-fns";

type LogStatus = "all" | "delivered" | "sent" | "failed" | "pending";

export default function Logs() {
  const [statusFilter, setStatusFilter] = useState<LogStatus>("all");
  const [selectedLog, setSelectedLog] = useState<any | null>(null);

  const { data, isLoading } = useGetLogs(
    { 
      status: statusFilter === "all" ? undefined : statusFilter, 
      limit: 100 
    }, 
    { query: { refetchInterval: 5000 } }
  );

  const getStatusIcon = (status: string) => {
    switch(status) {
      case 'delivered': return <CheckCircle2 className="w-4 h-4 text-primary" />;
      case 'sent': return <Send className="w-4 h-4 text-secondary" />;
      case 'failed': return <AlertCircle className="w-4 h-4 text-destructive" />;
      default: return <Clock className="w-4 h-4 text-warning" />;
    }
  };

  const getBadgeVariant = (status: string) => {
    switch(status) {
      case 'delivered': return 'success';
      case 'sent': return 'secondary';
      case 'failed': return 'destructive';
      default: return 'warning';
    }
  };

  return (
    <div className="space-y-8 pb-12 h-full flex flex-col">
      <header>
        <h1 className="text-3xl md:text-4xl font-display font-bold text-foreground">Message Logs</h1>
        <p className="text-muted-foreground mt-2">Comprehensive history of all API dispatches.</p>
      </header>

      {/* Filters */}
      <div className="flex flex-wrap items-center gap-2 p-1 bg-card border border-border/50 rounded-xl w-max shadow-sm">
        {(["all", "delivered", "sent", "failed", "pending"] as LogStatus[]).map((s) => (
          <button
            key={s}
            onClick={() => setStatusFilter(s)}
            className={`px-4 py-2 rounded-lg text-sm font-medium capitalize transition-all duration-200 ${
              statusFilter === s 
                ? "bg-primary/20 text-primary shadow-[0_0_10px_-2px_rgba(0,240,160,0.2)]" 
                : "text-muted-foreground hover:bg-white/5"
            }`}
          >
            {s}
          </button>
        ))}
      </div>

      <Card className="flex-1 overflow-hidden flex flex-col border-border/50">
        <div className="overflow-x-auto">
          <table className="w-full text-left border-collapse">
            <thead>
              <tr className="border-b border-border/50 bg-muted/30">
                <th className="p-4 font-mono text-xs uppercase text-muted-foreground font-medium tracking-wider">Status</th>
                <th className="p-4 font-mono text-xs uppercase text-muted-foreground font-medium tracking-wider">Recipient</th>
                <th className="p-4 font-mono text-xs uppercase text-muted-foreground font-medium tracking-wider">Message Preview</th>
                <th className="p-4 font-mono text-xs uppercase text-muted-foreground font-medium tracking-wider">Time</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-border/30">
              {isLoading ? (
                <tr><td colSpan={4} className="p-8 text-center text-muted-foreground animate-pulse">Loading logs...</td></tr>
              ) : data?.logs.length === 0 ? (
                <tr>
                  <td colSpan={4} className="p-16 text-center">
                    <ListFilter className="w-12 h-12 text-border mx-auto mb-4" />
                    <p className="text-foreground font-medium">No messages found</p>
                    <p className="text-sm text-muted-foreground">Adjust filters or send a new message.</p>
                  </td>
                </tr>
              ) : (
                data?.logs.map((log) => (
                  <tr 
                    key={log.id} 
                    className="hover:bg-white/[0.03] transition-colors cursor-pointer group"
                    onClick={() => setSelectedLog(log)}
                  >
                    <td className="p-4">
                      <Badge variant={getBadgeVariant(log.status)} className="flex w-max items-center gap-1.5 px-2.5 py-1">
                        {getStatusIcon(log.status)}
                        <span className="capitalize">{log.status}</span>
                      </Badge>
                    </td>
                    <td className="p-4 font-mono text-sm">{log.toMasked}</td>
                    <td className="p-4 text-sm text-foreground/80 max-w-xs md:max-w-md lg:max-w-lg truncate">
                      {log.template && <span className="text-xs text-secondary border border-secondary/30 rounded px-1 py-0.5 mr-2">{log.template}</span>}
                      {log.body}
                    </td>
                    <td className="p-4 font-mono text-xs text-muted-foreground whitespace-nowrap">
                      {format(new Date(log.createdAt), "MMM d, HH:mm:ss")}
                    </td>
                  </tr>
                ))
              )}
            </tbody>
          </table>
        </div>
      </Card>

      <Modal isOpen={!!selectedLog} onClose={() => setSelectedLog(null)} title="Message Details">
        {selectedLog && (
          <div className="space-y-6">
            <div className="flex items-center justify-between pb-4 border-b border-border/50">
              <div>
                <p className="text-xs text-muted-foreground font-mono uppercase mb-1">Message ID</p>
                <p className="font-mono text-sm text-foreground">{selectedLog.messageId}</p>
              </div>
              <Badge variant={getBadgeVariant(selectedLog.status)} className="capitalize text-sm px-3 py-1">
                {selectedLog.status}
              </Badge>
            </div>

            <div className="grid grid-cols-2 gap-4">
              <div>
                <p className="text-xs text-muted-foreground font-mono uppercase mb-1">To</p>
                <p className="font-mono text-sm">{selectedLog.toMasked}</p>
              </div>
              <div>
                <p className="text-xs text-muted-foreground font-mono uppercase mb-1">Template</p>
                <p className="font-mono text-sm">{selectedLog.template || 'None (Raw)'}</p>
              </div>
              <div>
                <p className="text-xs text-muted-foreground font-mono uppercase mb-1">Created At</p>
                <p className="font-mono text-sm">{format(new Date(selectedLog.createdAt), "yyyy-MM-dd HH:mm:ss")}</p>
              </div>
              <div>
                <p className="text-xs text-muted-foreground font-mono uppercase mb-1">Delivered At</p>
                <p className="font-mono text-sm">{selectedLog.deliveredAt ? format(new Date(selectedLog.deliveredAt), "yyyy-MM-dd HH:mm:ss") : '--'}</p>
              </div>
            </div>

            <div>
              <p className="text-xs text-muted-foreground font-mono uppercase mb-2">Message Body</p>
              <div className="p-4 rounded-xl bg-muted/30 border border-border/50 text-sm font-mono whitespace-pre-wrap">
                {selectedLog.body}
              </div>
            </div>

            {selectedLog.error && (
              <div>
                <p className="text-xs text-destructive font-mono uppercase mb-2">Error Detail</p>
                <div className="p-3 rounded-lg bg-destructive/10 text-destructive text-sm font-mono border border-destructive/20">
                  {selectedLog.error}
                </div>
              </div>
            )}
          </div>
        )}
      </Modal>
    </div>
  );
}

import { useState } from "react";
import { useSendMessage, useListTemplates } from "@workspace/api-client-react";
import { Card, Button, Input, Textarea, Badge } from "@/components/ui/Shared";
import { Send, Smartphone, FileCode2, Info } from "lucide-react";
import { useToast } from "@/hooks/use-toast";

export default function SendSms() {
  const { toast } = useToast();
  const { data: templatesData } = useListTemplates();
  const sendMessageMutation = useSendMessage();

  const [to, setTo] = useState("");
  const [template, setTemplate] = useState<string>("");
  const [body, setBody] = useState("");
  const [vars, setVars] = useState<Record<string, string>>({});

  const selectedTemplateDef = templatesData?.templates.find(t => t.name === template);

  const handleVarChange = (key: string, value: string) => {
    setVars(prev => ({ ...prev, [key]: value }));
  };

  const handleSend = () => {
    if (!to) {
      toast({ title: "Error", description: "Phone number is required", variant: "destructive" });
      return;
    }

    if (!template && !body) {
      toast({ title: "Error", description: "Select a template or provide a message body", variant: "destructive" });
      return;
    }

    sendMessageMutation.mutate({
      data: {
        to,
        template: template || undefined,
        body: !template ? body : undefined,
        vars: template ? vars : undefined
      }
    }, {
      onSuccess: (data) => {
        toast({
          title: "Message Queued",
          description: `ID: ${data.messageId} - Status: ${data.status}`,
        });
        // Reset form slightly
        setTo("");
        setBody("");
        setVars({});
      },
      onError: (error: any) => {
        toast({
          title: "Failed to send",
          description: error.data?.error || error.message || "Unknown error occurred",
          variant: "destructive"
        });
      }
    });
  };

  return (
    <div className="space-y-8 max-w-4xl mx-auto pb-12">
      <header>
        <h1 className="text-3xl md:text-4xl font-display font-bold text-foreground">Send SMS</h1>
        <p className="text-muted-foreground mt-2">Queue a new message through the gateway.</p>
      </header>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
        <div className="lg:col-span-2 space-y-6">
          <Card className="p-6 space-y-6">
            <div className="space-y-3">
              <label className="text-sm font-semibold text-foreground flex items-center gap-2">
                <Smartphone className="w-4 h-4 text-primary" /> Recipient
              </label>
              <Input 
                placeholder="+1234567890 (E.164 format)" 
                value={to} 
                onChange={(e) => setTo(e.target.value)}
                className="text-lg"
              />
            </div>

            <div className="space-y-3">
              <label className="text-sm font-semibold text-foreground flex items-center gap-2">
                <FileCode2 className="w-4 h-4 text-secondary" /> Message Template
              </label>
              <div className="relative">
                <select 
                  className="flex h-12 w-full appearance-none rounded-xl border border-border/50 bg-input px-4 py-2 text-sm text-foreground shadow-inner focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-primary/50 font-mono cursor-pointer"
                  value={template}
                  onChange={(e) => {
                    setTemplate(e.target.value);
                    setVars({});
                    setBody("");
                  }}
                >
                  <option value="">-- Custom Raw Message --</option>
                  {templatesData?.templates.map(t => (
                    <option key={t.id} value={t.name}>{t.name}</option>
                  ))}
                </select>
                <div className="pointer-events-none absolute right-4 top-1/2 -translate-y-1/2">
                  <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinelinejoin="round" className="text-muted-foreground"><path d="m6 9 6 6 6-6"/></svg>
                </div>
              </div>
            </div>

            {template && selectedTemplateDef ? (
              <div className="space-y-4 p-5 rounded-xl border border-border/50 bg-muted/20">
                <h3 className="text-sm font-semibold flex items-center gap-2 mb-4">Template Variables</h3>
                {selectedTemplateDef.vars.length === 0 ? (
                  <p className="text-sm text-muted-foreground italic">No variables required for this template.</p>
                ) : (
                  <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                    {selectedTemplateDef.vars.map(v => (
                      <div key={v} className="space-y-2">
                        <label className="text-xs font-mono text-muted-foreground uppercase">{v}</label>
                        <Input 
                          placeholder={`Enter ${v}`} 
                          value={vars[v] || ''}
                          onChange={(e) => handleVarChange(v, e.target.value)}
                        />
                      </div>
                    ))}
                  </div>
                )}
                
                <div className="mt-6 pt-4 border-t border-border/50">
                  <p className="text-xs text-muted-foreground mb-2">Preview (approximate):</p>
                  <p className="text-sm font-mono text-foreground/80 whitespace-pre-wrap break-words">
                    {selectedTemplateDef.body.replace(/\{\{(\w+)\}\}/g, (match, p1) => vars[p1] || match)}
                  </p>
                </div>
              </div>
            ) : (
              <div className="space-y-3">
                <label className="text-sm font-semibold text-foreground flex items-center gap-2">
                  Raw Body
                </label>
                <Textarea 
                  placeholder="Type your message here..." 
                  value={body}
                  onChange={(e) => setBody(e.target.value)}
                  className="min-h-[160px]"
                />
                <p className="text-xs text-muted-foreground text-right">{body.length} / 640 chars</p>
              </div>
            )}

            <div className="pt-4 flex justify-end">
              <Button 
                size="lg" 
                className="w-full sm:w-auto"
                onClick={handleSend}
                isLoading={sendMessageMutation.isPending}
              >
                <Send className="w-5 h-5 mr-2" />
                Dispatch Message
              </Button>
            </div>
          </Card>
        </div>

        <div className="space-y-6">
          <Card className="p-6 bg-gradient-to-br from-card to-muted/30 border-secondary/20">
            <h3 className="font-display font-bold text-lg mb-3 flex items-center gap-2">
              <Info className="w-5 h-5 text-secondary" />
              How it works
            </h3>
            <p className="text-sm text-muted-foreground mb-4 leading-relaxed">
              Messages submitted here are instantly pushed to your Android device's in-memory queue via local network.
            </p>
            <ul className="space-y-3 text-sm text-muted-foreground">
              <li className="flex gap-2"><div className="w-1.5 h-1.5 rounded-full bg-primary mt-1.5 shrink-0" /> End-to-end latency &lt; 3s</li>
              <li className="flex gap-2"><div className="w-1.5 h-1.5 rounded-full bg-warning mt-1.5 shrink-0" /> Max 1000 items in queue</li>
              <li className="flex gap-2"><div className="w-1.5 h-1.5 rounded-full bg-secondary mt-1.5 shrink-0" /> Respects app rate limits</li>
            </ul>
          </Card>
        </div>
      </div>
    </div>
  );
}

import { useState } from "react";
import { 
  useListTemplates, 
  useCreateTemplate, 
  useUpdateTemplate, 
  useDeleteTemplate 
} from "@workspace/api-client-react";
import { useQueryClient } from "@tanstack/react-query";
import { getListTemplatesQueryKey } from "@workspace/api-client-react";
import { Card, Button, Input, Textarea, Badge, Modal } from "@/components/ui/Shared";
import { FileCode2, Plus, Edit2, Trash2, Search } from "lucide-react";
import { useToast } from "@/hooks/use-toast";
import { format } from "date-fns";

export default function Templates() {
  const { toast } = useToast();
  const queryClient = useQueryClient();
  const { data, isLoading } = useListTemplates();
  
  const createMutation = useCreateTemplate();
  const updateMutation = useUpdateTemplate();
  const deleteMutation = useDeleteTemplate();

  const [search, setSearch] = useState("");
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [editingTemplate, setEditingTemplate] = useState<{name: string, body: string} | null>(null);
  
  const [formName, setFormName] = useState("");
  const [formBody, setFormBody] = useState("");

  const filteredTemplates = data?.templates.filter(t => 
    t.name.toLowerCase().includes(search.toLowerCase()) || 
    t.body.toLowerCase().includes(search.toLowerCase())
  );

  const openCreateModal = () => {
    setEditingTemplate(null);
    setFormName("");
    setFormBody("");
    setIsModalOpen(true);
  };

  const openEditModal = (template: any) => {
    setEditingTemplate(template);
    setFormName(template.name);
    setFormBody(template.body);
    setIsModalOpen(true);
  };

  const handleSave = () => {
    if (!formName || !formBody) {
      toast({ title: "Error", description: "Name and body are required", variant: "destructive" });
      return;
    }

    const onSuccess = () => {
      queryClient.invalidateQueries({ queryKey: getListTemplatesQueryKey() });
      setIsModalOpen(false);
      toast({ title: "Success", description: "Template saved successfully" });
    };

    const onError = (e: any) => {
      toast({ title: "Error", description: e.data?.error || "Operation failed", variant: "destructive" });
    };

    if (editingTemplate) {
      updateMutation.mutate({ name: editingTemplate.name, data: { body: formBody } }, { onSuccess, onError });
    } else {
      createMutation.mutate({ data: { name: formName, body: formBody } }, { onSuccess, onError });
    }
  };

  const handleDelete = (name: string) => {
    if (confirm(`Are you sure you want to delete template '${name}'?`)) {
      deleteMutation.mutate({ name }, {
        onSuccess: () => {
          queryClient.invalidateQueries({ queryKey: getListTemplatesQueryKey() });
          toast({ title: "Deleted", description: "Template removed" });
        },
        onError: (e: any) => {
          toast({ title: "Error", description: e.data?.error || "Deletion failed", variant: "destructive" });
        }
      });
    }
  };

  return (
    <div className="space-y-8 pb-12">
      <header className="flex flex-col sm:flex-row sm:items-center justify-between gap-4">
        <div>
          <h1 className="text-3xl md:text-4xl font-display font-bold text-foreground">Templates</h1>
          <p className="text-muted-foreground mt-2">Manage reusable SMS blueprints with variables.</p>
        </div>
        <Button onClick={openCreateModal} className="shrink-0">
          <Plus className="w-5 h-5 mr-2" />
          New Template
        </Button>
      </header>

      <div className="relative max-w-md">
        <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-5 h-5 text-muted-foreground" />
        <Input 
          placeholder="Search templates..." 
          className="pl-10"
          value={search}
          onChange={(e) => setSearch(e.target.value)}
        />
      </div>

      {isLoading ? (
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
          {[1,2,3].map(i => (
            <Card key={i} className="h-48 animate-pulse bg-muted/20" />
          ))}
        </div>
      ) : filteredTemplates?.length === 0 ? (
        <div className="text-center py-20 border border-dashed border-border rounded-2xl">
          <FileCode2 className="w-12 h-12 text-muted-foreground mx-auto mb-4 opacity-50" />
          <h3 className="text-lg font-medium text-foreground mb-1">No templates found</h3>
          <p className="text-muted-foreground">Create your first template to get started.</p>
        </div>
      ) : (
        <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
          {filteredTemplates?.map((template) => (
            <Card key={template.id} className="flex flex-col hover:border-primary/30 transition-colors group">
              <div className="p-5 border-b border-border/50 flex items-center justify-between bg-white/[0.01]">
                <div className="flex items-center gap-3">
                  <div className="w-10 h-10 rounded-lg bg-primary/10 flex items-center justify-center text-primary">
                    <FileCode2 className="w-5 h-5" />
                  </div>
                  <div>
                    <h3 className="font-bold text-foreground font-mono">{template.name}</h3>
                    <p className="text-xs text-muted-foreground">Updated {format(new Date(template.updatedAt), "MMM d, yyyy")}</p>
                  </div>
                </div>
                <div className="flex items-center gap-2 opacity-0 group-hover:opacity-100 transition-opacity">
                  <button onClick={() => openEditModal(template)} className="p-2 text-muted-foreground hover:text-primary transition-colors">
                    <Edit2 className="w-4 h-4" />
                  </button>
                  <button onClick={() => handleDelete(template.name)} className="p-2 text-muted-foreground hover:text-destructive transition-colors">
                    <Trash2 className="w-4 h-4" />
                  </button>
                </div>
              </div>
              <div className="p-5 flex-1 flex flex-col">
                <p className="text-sm text-foreground/80 font-mono whitespace-pre-wrap flex-1 mb-4">
                  {template.body}
                </p>
                <div>
                  <div className="flex flex-wrap gap-2">
                    {template.vars.length > 0 ? template.vars.map(v => (
                      <Badge key={v} variant="secondary" className="bg-secondary/5 border-secondary/20">
                        {v}
                      </Badge>
                    )) : (
                      <span className="text-xs italic text-muted-foreground">No variables</span>
                    )}
                  </div>
                </div>
              </div>
            </Card>
          ))}
        </div>
      )}

      <Modal 
        isOpen={isModalOpen} 
        onClose={() => setIsModalOpen(false)} 
        title={editingTemplate ? "Edit Template" : "Create Template"}
      >
        <div className="space-y-5">
          <div className="space-y-2">
            <label className="text-sm font-medium">Template Name</label>
            <Input 
              value={formName} 
              onChange={(e) => setFormName(e.target.value.toLowerCase().replace(/\s+/g, '_'))} 
              placeholder="e.g. order_shipped"
              disabled={!!editingTemplate}
            />
            {!editingTemplate && <p className="text-xs text-muted-foreground">Lowercase, underscores only. Cannot be changed later.</p>}
          </div>
          
          <div className="space-y-2">
            <label className="text-sm font-medium flex justify-between">
              <span>Message Body</span>
              <span className="text-muted-foreground font-mono text-xs">{formBody.length} / 640</span>
            </label>
            <Textarea 
              value={formBody} 
              onChange={(e) => setFormBody(e.target.value)}
              placeholder="Hi {{name}}, your order {{order_id}} has shipped!"
              className="h-32"
            />
            <p className="text-xs text-muted-foreground">Use {'{{variable_name}}'} syntax to inject variables.</p>
          </div>

          <div className="pt-4 flex justify-end gap-3">
            <Button variant="ghost" onClick={() => setIsModalOpen(false)}>Cancel</Button>
            <Button 
              onClick={handleSave} 
              isLoading={createMutation.isPending || updateMutation.isPending}
            >
              {editingTemplate ? "Save Changes" : "Create Template"}
            </Button>
          </div>
        </div>
      </Modal>
    </div>
  );
}

import type { Request, Response, NextFunction, Router } from 'express';
import type { Server } from 'http';
import { OpenSMSServer } from '../server.js';

export function createExpressRouter(gateway: OpenSMSServer, opts: {
  publicUrl: string;
  basePath?: string;
}): Router {
  const { publicUrl, basePath = '/opensms' } = opts;
  const h = gateway.handler();

  const router = (require('express') as typeof import('express')).Router();

  router.get('/qr', async (_req: Request, res: Response) => {
    await h.handleHttp(_req as any, res as any, basePath, publicUrl);
  });

  router.get('/status', (_req: Request, res: Response) => {
    h.handleHttp(_req as any, res as any, basePath, publicUrl);
  });

  return router;
}

export function attachToServer(server: Server, gateway: OpenSMSServer, opts: {
  basePath?: string;
  publicUrl?: string;
}): void {
  gateway.handler().attach(server, opts.basePath, opts.publicUrl);
}

import type { NextApiRequest, NextApiResponse } from 'next';
import { OpenSMSServer } from '../server.js';
import { generateQRPage } from '../qr.js';

export function createNextHandler(gateway: OpenSMSServer, opts: {
  publicUrl: string;
  basePath?: string;
}) {
  const { publicUrl, basePath = '/api/opensms' } = opts;

  return async function handler(req: NextApiRequest, res: NextApiResponse) {
    const path = (req.query['path'] as string[]) ?? [];
    const route = path.join('/');

    if (route === 'qr' || route === 'qr/') {
      const wsUrl = `${publicUrl.replace(/^http/, 'ws')}${basePath}/ws`;
      const html  = await generateQRPage({
        wsUrl,
        apiKey: (gateway as any).apiKey,
        baseUrl: publicUrl,
        isConnected: gateway.isConnected,
      });
      res.setHeader('Content-Type', 'text/html');
      res.status(200).send(html);
      return;
    }

    if (route === 'status') {
      res.status(200).json({
        connected:   gateway.isConnected,
      });
      return;
    }

    res.status(404).json({ error: 'Not found' });
  };
}

import { EventEmitter } from 'events';
import { WebSocketServer, WebSocket } from 'ws';
import type { IncomingMessage } from 'http';
import type { Server } from 'http';
import {
  type AuthMessage,
  type TemplatesSyncMessage,
  type StatusMessage,
  type SendParams,
  type SmsStatus,
  generateId,
} from './protocol.js';
import { TemplateStore } from './template.js';
import { generateQRPage } from './qr.js';

export interface OpenSMSServerConfig {
  apiKey: string;
  deviceName?: string;
}

export class OpenSMSServer extends EventEmitter {
  private readonly apiKey: string;
  private readonly deviceName: string;
  private readonly wss: WebSocketServer;
  private readonly templateStore = new TemplateStore();
  private readonly pendingJobs = new Map<string, {
    resolve: (s: SmsStatus) => void;
    reject:  (e: Error) => void;
    timer:   ReturnType<typeof setTimeout>;
  }>();

  private connectedSocket: WebSocket | null = null;
  private connectedDeviceId: string | null = null;
  private connectedAt: number | null = null;

  constructor(config: OpenSMSServerConfig) {
    super();
    this.apiKey     = config.apiKey;
    this.deviceName = config.deviceName ?? 'My SMS Gateway';
    this.wss        = new WebSocketServer({ noServer: true });
    this.wss.on('connection', (ws) => this.handleConnection(ws));
  }

  get isConnected(): boolean {
    return this.connectedSocket?.readyState === WebSocket.OPEN;
  }

  get templates() {
    return this.templateStore;
  }

  async send(params: SendParams): Promise<SmsStatus> {
    if (!this.isConnected) {
      throw new Error('No APK connected. Visit /opensms/qr to connect a phone first.');
    }

    const messageId = generateId();
    let body: string;

    if (params.body) {
      body = params.body;
    } else if (params.template) {
      body = this.templateStore.render({ template: params.template, vars: params.vars });
    } else {
      throw new Error('Provide either body or template.');
    }

    this.connectedSocket!.send(JSON.stringify({
      type: 'job',
      messageId,
      to:   params.to,
      body,
      template: params.template,
    }));

    return new Promise((resolve, reject) => {
      const timer = setTimeout(() => {
        this.pendingJobs.delete(messageId);
        reject(new Error(`SMS timeout: no status received in 30s for ${messageId}`));
      }, 30_000);

      this.pendingJobs.set(messageId, { resolve, reject, timer });
    });
  }

  handler(): {
    handleUpgrade: (req: IncomingMessage, socket: any, head: Buffer, wsPath: string) => boolean;
    handleHttp: (req: IncomingMessage, res: any, basePath: string, publicUrl: string) => Promise<boolean>;
    attach: (server: Server, basePath?: string, publicUrl?: string) => void;
  } {
    const self = this;

    return {
      handleUpgrade(req, socket, head, wsPath) {
        if (req.url !== wsPath) return false;
        self.wss.handleUpgrade(req, socket, head, (ws) => {
          self.wss.emit('connection', ws, req);
        });
        return true;
      },

      async handleHttp(req, res, basePath, publicUrl) {
        const url = req.url?.split('?')[0] ?? '';

        if (url === `${basePath}/qr` || url === `${basePath}/qr/`) {
          const wsUrl = `${publicUrl.replace(/^http/, 'ws')}${basePath}/ws`;
          const html  = await generateQRPage({
            wsUrl,
            apiKey: self.apiKey,
            baseUrl: publicUrl,
            isConnected: self.isConnected,
          });
          res.writeHead(200, { 'Content-Type': 'text/html' });
          res.end(html);
          return true;
        }

        if (url === `${basePath}/status`) {
          res.writeHead(200, { 'Content-Type': 'application/json' });
          res.end(JSON.stringify({
            connected:   self.isConnected,
            deviceId:    self.connectedDeviceId,
            connectedAt: self.connectedAt,
          }));
          return true;
        }

        return false;
      },

      attach(server, basePath = '/opensms', publicUrl = '') {
        server.on('upgrade', (req, socket, head) => {
          if (req.url === `${basePath}/ws`) {
            self.wss.handleUpgrade(req, socket, head, (ws) => {
              self.wss.emit('connection', ws, req);
            });
          }
        });

        const origListener = server.listeners('request')[0] as any;
        server.removeAllListeners('request');
        server.on('request', async (req, res) => {
          const handled = await self.handler().handleHttp(req, res, basePath, publicUrl || `http://localhost`);
          if (!handled && origListener) origListener(req, res);
        });
      },
    };
  }

  private handleConnection(ws: WebSocket) {
    let authed = false;

    const authTimeout = setTimeout(() => {
      if (!authed) ws.terminate();
    }, 10_000);

    ws.on('message', (raw) => {
      let msg: any;
      try { msg = JSON.parse(raw.toString()); } catch { return; }

      if (!authed) {
        if (msg.type === 'auth') {
          const authMsg = msg as AuthMessage;
          if (authMsg.apiKey !== this.apiKey) {
            ws.send(JSON.stringify({ type: 'auth_fail', reason: 'Invalid API key' }));
            ws.terminate();
            return;
          }
          clearTimeout(authTimeout);
          authed = true;
          this.connectedSocket   = ws;
          this.connectedDeviceId = authMsg.deviceId;
          this.connectedAt       = Date.now();
          ws.send(JSON.stringify({ type: 'auth_ok' }));
          this.emit('connected', { deviceId: authMsg.deviceId });
        }
        return;
      }

      if (msg.type === 'templates_sync') {
        const syncMsg = msg as TemplatesSyncMessage;
        this.templateStore.syncFromDevice(syncMsg.templates);
        this.emit('templates_sync', syncMsg.templates);
        return;
      }

      if (msg.type === 'status') {
        const statusMsg = msg as StatusMessage;
        const pending = this.pendingJobs.get(statusMsg.messageId);
        if (pending) {
          clearTimeout(pending.timer);
          this.pendingJobs.delete(statusMsg.messageId);
          const result: SmsStatus = {
            messageId: statusMsg.messageId,
            status:    statusMsg.status,
            error:     statusMsg.error,
            timestamp: statusMsg.timestamp,
          };
          if (statusMsg.status === 'failed') {
            pending.reject(Object.assign(new Error(statusMsg.error ?? 'SMS failed'), result));
          } else {
            pending.resolve(result);
          }
        }
        this.emit('status', statusMsg);
        return;
      }

      if (msg.type === 'pong') return;
    });

    ws.on('close', () => {
      if (this.connectedSocket === ws) {
        this.connectedSocket   = null;
        this.connectedDeviceId = null;
        this.connectedAt       = null;
        this.emit('disconnected');
        for (const [id, pending] of this.pendingJobs) {
          clearTimeout(pending.timer);
          pending.reject(new Error('APK disconnected while waiting for delivery'));
          this.pendingJobs.delete(id);
        }
      }
    });
  }
}

