import { useState } from "react";
import { Loader2, MapPin, Camera, Bell } from "lucide-react";
import { Button } from "@/components/ui/button";
import { requestLocationPermission, requestCameraPermission } from "@/lib/capacitorUtils";
import { requestNotificationPermission } from "@/hooks/useNotifications";

interface Props {
  onComplete: () => void;
}

const PERMISSIONS = [
  {
    icon: MapPin,
    title: "Location Access",
    description:
      "Required to verify you're at the store when recording sales, find nearby stores, and enable turn-by-turn navigation.",
    color: "text-blue-500",
    bg: "bg-blue-500/10",
    borderColor: "border-blue-500/30",
    request: requestLocationPermission,
  },
  {
    icon: Camera,
    title: "Camera Access",
    description:
      "Used to scan QR codes at stores, capture store photos for KYC, and upload receipts.",
    color: "text-green-500",
    bg: "bg-green-500/10",
    borderColor: "border-green-500/30",
    request: requestCameraPermission,
  },
  {
    icon: Bell,
    title: "Push Notifications",
    description:
      "Stay updated with new orders assigned to you, payment confirmations, and important alerts from managers.",
    color: "text-amber-500",
    bg: "bg-amber-500/10",
    borderColor: "border-amber-500/30",
    request: requestNotificationPermission,
  },
];

export function PermissionSetup({ onComplete }: Props) {
  const [step, setStep] = useState(0);
  const [loading, setLoading] = useState(false);

  const current = PERMISSIONS[step];
  const Icon = current.icon;

  const advance = () => {
    if (step < PERMISSIONS.length - 1) {
      setStep((s) => s + 1);
    } else {
      localStorage.setItem("mobile_permissions_done", "1");
      onComplete();
    }
  };

  const handleAllow = async () => {
    setLoading(true);
    try { await current.request(); } catch {}
    setLoading(false);
    advance();
  };

  return (
    <div className="flex flex-col min-h-screen bg-background text-foreground px-6 pt-16 pb-10">
      {/* Progress dots */}
      <div className="flex gap-2 justify-center mb-16">
        {PERMISSIONS.map((_, i) => (
          <div
            key={i}
            className={`h-2 rounded-full transition-all duration-300 ${
              i === step ? "w-8 bg-primary" : i < step ? "w-2 bg-primary/50" : "w-2 bg-muted"
            }`}
          />
        ))}
      </div>

      <div className="flex-1 flex flex-col items-center justify-center text-center gap-6">
        <div className={`rounded-full p-6 border-2 ${current.bg} ${current.borderColor}`}>
          <Icon className={`h-12 w-12 ${current.color}`} />
        </div>
        <div>
          <h1 className="text-2xl font-bold mb-3">{current.title}</h1>
          <p className="text-muted-foreground text-base leading-relaxed max-w-sm mx-auto">
            {current.description}
          </p>
        </div>
      </div>

      <div className="space-y-3 mt-8">
        <Button
          className="w-full h-14 text-base font-semibold rounded-2xl"
          onClick={handleAllow}
          disabled={loading}
        >
          {loading ? <Loader2 className="h-5 w-5 animate-spin" /> : "Allow Access"}
        </Button>
        <Button
          variant="ghost"
          className="w-full h-12 text-sm text-muted-foreground"
          onClick={advance}
          disabled={loading}
        >
          {step < PERMISSIONS.length - 1 ? "Skip for now" : "Done"}
        </Button>
      </div>
    </div>
  );
}

import { useState } from "react";
import { useQuery, useQueryClient } from "@tanstack/react-query";
import { Search, Phone, Navigation2, Plus, Loader2, MapPin, X } from "lucide-react";
import { Input } from "@/components/ui/input";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import { Card, CardContent } from "@/components/ui/card";
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select";
import { supabase } from "@/integrations/supabase/client";
import { useAuth } from "@/contexts/AuthContext";
import { CreateStoreWizard } from "@/components/stores/CreateStoreWizard";
import { cn } from "@/lib/utils";

const TYPE_COLORS: Record<string, string> = {
  RETAIL: "bg-blue-500",
  RESTAURANT: "bg-orange-500",
  WHOLESALE: "bg-green-500",
  DEFAULT: "bg-muted-foreground",
};

function getTypeColor(typeName: string) {
  const key = typeName?.toUpperCase();
  return TYPE_COLORS[key] ?? TYPE_COLORS.DEFAULT;
}

export function AgentCustomers() {
  const { user } = useAuth();
  const qc = useQueryClient();
  const [query, setQuery] = useState("");
  const [filterRoute, setFilterRoute] = useState("all");
  const [filterType, setFilterType] = useState("all");
  const [showCreateStore, setShowCreateStore] = useState(false);

  const { data: stores, isLoading } = useQuery({
    queryKey: ["mobile-customers-stores"],
    queryFn: async () => {
      const { data } = await supabase
        .from("stores")
        .select(
          "id, name, display_id, outstanding, address, phone, lat, lng, route_id, is_active, customers(id, name, phone), store_types(id, name), routes(name)"
        )
        .eq("is_active", true)
        .order("name");
      return (data as any[]) || [];
    },
    enabled: !!user,
  });

  const { data: routes } = useQuery({
    queryKey: ["mobile-routes-list"],
    queryFn: async () => {
      const { data } = await supabase.from("routes").select("id, name").eq("is_active", true).order("name");
      return data || [];
    },
  });

  const { data: storeTypes } = useQuery({
    queryKey: ["mobile-store-types"],
    queryFn: async () => {
      const { data } = await supabase.from("store_types").select("id, name").order("name");
      return data || [];
    },
  });

  const filtered = (stores || []).filter((s: any) => {
    const q = query.toLowerCase();
    const matchSearch =
      !q ||
      s.name?.toLowerCase().includes(q) ||
      s.customers?.name?.toLowerCase().includes(q) ||
      s.address?.toLowerCase().includes(q) ||
      s.display_id?.toLowerCase().includes(q);
    const matchRoute = filterRoute === "all" || s.route_id === filterRoute;
    const matchType = filterType === "all" || s.store_types?.id === filterType;
    return matchSearch && matchRoute && matchType;
  });

  const handleCall = (phone: string) => {
    window.open(`tel:${phone}`, "_self");
  };

  const handleNavigate = (s: any) => {
    if (s.lat && s.lng) {
      window.open(`https://www.google.com/maps/dir/?api=1&destination=${s.lat},${s.lng}`, "_blank");
    } else if (s.address) {
      window.open(`https://www.google.com/maps/dir/?api=1&destination=${encodeURIComponent(s.address)}`, "_blank");
    }
  };

  return (
    <div className="flex flex-col h-full">
      {/* Search + filter bar */}
      <div className="px-4 pb-3 space-y-2">
        <div className="relative">
          <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-muted-foreground" />
          <Input
            value={query}
            onChange={(e) => setQuery(e.target.value)}
            placeholder="Search store, customer, address..."
            className="pl-9 pr-9 h-10 rounded-xl"
          />
          {query && (
            <button className="absolute right-3 top-1/2 -translate-y-1/2" onClick={() => setQuery("")}>
              <X className="h-4 w-4 text-muted-foreground" />
            </button>
          )}
        </div>

        <div className="flex gap-2">
          <Select value={filterRoute} onValueChange={setFilterRoute}>
            <SelectTrigger className="h-8 text-xs rounded-lg flex-1">
              <SelectValue placeholder="All Routes" />
            </SelectTrigger>
            <SelectContent>
              <SelectItem value="all">All Routes</SelectItem>
              {(routes as any[])?.map((r: any) => (
                <SelectItem key={r.id} value={r.id}>{r.name}</SelectItem>
              ))}
            </SelectContent>
          </Select>
          <Select value={filterType} onValueChange={setFilterType}>
            <SelectTrigger className="h-8 text-xs rounded-lg flex-1">
              <SelectValue placeholder="All Types" />
            </SelectTrigger>
            <SelectContent>
              <SelectItem value="all">All Types</SelectItem>
              {(storeTypes as any[])?.map((t: any) => (
                <SelectItem key={t.id} value={t.id}>{t.name}</SelectItem>
              ))}
            </SelectContent>
          </Select>
        </div>
      </div>

      {/* Stores list */}
      <div className="flex-1 overflow-y-auto px-4 pb-4">
        {isLoading ? (
          <div className="flex justify-center py-10">
            <Loader2 className="h-5 w-5 animate-spin text-muted-foreground" />
          </div>
        ) : filtered.length === 0 ? (
          <div className="flex flex-col items-center justify-center py-12 gap-2 text-center">
            <MapPin className="h-8 w-8 text-muted-foreground/40" />
            <p className="text-sm text-muted-foreground">No stores found</p>
          </div>
        ) : (
          <div className="space-y-2">
            {filtered.map((s: any) => {
              const typeName = s.store_types?.name ?? "";
              const colorClass = getTypeColor(typeName);
              const phone = s.phone || s.customers?.phone;
              return (
                <Card key={s.id} className="overflow-hidden">
                  <div className="flex">
                    {/* Colored left border */}
                    <div className={cn("w-1 shrink-0 rounded-l-xl", colorClass)} />
                    <CardContent className="p-3 flex-1 min-w-0">
                      <div className="flex items-start justify-between gap-2">
                        <div className="min-w-0 flex-1">
                          <div className="flex items-center gap-1.5 flex-wrap">
                            <span className="text-sm font-semibold truncate">{s.name}</span>
                            <span className="text-[10px] text-muted-foreground">({s.display_id})</span>
                          </div>
                          {s.customers?.name && (
                            <p className="text-xs text-muted-foreground mt-0.5">{s.customers.name}</p>
                          )}
                          {s.address && (
                            <p className="text-xs text-muted-foreground mt-0.5 line-clamp-1">{s.address}</p>
                          )}
                          <div className="flex items-center gap-2 mt-1 flex-wrap">
                            {typeName && (
                              <Badge variant="outline" className="text-[10px] h-4 px-1.5">{typeName}</Badge>
                            )}
                            {s.routes?.name && (
                              <span className="text-[10px] text-muted-foreground/70">{s.routes.name}</span>
                            )}
                          </div>
                        </div>
                        <div className="text-right shrink-0">
                          <p className={cn("text-sm font-bold", s.outstanding > 0 ? "text-destructive" : "text-green-600")}>
                            ₹{Number(s.outstanding).toLocaleString()}
                          </p>
                          {s.outstanding > 0 && (
                            <p className="text-[10px] text-muted-foreground">Outstanding</p>
                          )}
                        </div>
                      </div>

                      {/* Action buttons */}
                      <div className="flex gap-2 mt-2">
                        <Button
                          variant="outline"
                          size="sm"
                          className="flex-1 h-8 text-xs gap-1 rounded-lg"
                          onClick={() => handleNavigate(s)}
                          disabled={!s.lat && !s.lng && !s.address}
                        >
                          <Navigation2 className="h-3 w-3" />
                          Navigate
                        </Button>
                        {phone && (
                          <Button
                            variant="outline"
                            size="sm"
                            className="flex-1 h-8 text-xs gap-1 rounded-lg"
                            onClick={() => handleCall(phone)}
                          >
                            <Phone className="h-3 w-3" />
                            Call
                          </Button>
                        )}
                      </div>
                    </CardContent>
                  </div>
                </Card>
              );
            })}
          </div>
        )}
      </div>

      {/* FAB — add store */}
      <button
        className="fixed bottom-20 right-4 h-14 w-14 rounded-full bg-primary text-primary-foreground shadow-lg flex items-center justify-center z-30 active:scale-95 transition-transform"
        onClick={() => setShowCreateStore(true)}
        style={{ bottom: "calc(env(safe-area-inset-bottom) + 5rem)" }}
      >
        <Plus className="h-6 w-6" />
      </button>

      <CreateStoreWizard
        open={showCreateStore}
        onOpenChange={setShowCreateStore}
        onCreated={() => {
          qc.invalidateQueries({ queryKey: ["mobile-customers-stores"] });
          setShowCreateStore(false);
        }}
      />
    </div>
  );
}

import { useState } from "react";
import { useQuery, useQueryClient } from "@tanstack/react-query";
import {
  Banknote, Loader2, Send, CheckCircle, Clock, ChevronDown, ChevronUp,
  TrendingUp, Package, ArrowUpRight,
} from "lucide-react";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Textarea } from "@/components/ui/textarea";
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select";
import {
  Sheet,
  SheetContent,
  SheetHeader,
  SheetTitle,
} from "@/components/ui/sheet";
import { toast } from "sonner";
import { supabase } from "@/integrations/supabase/client";
import { useAuth } from "@/contexts/AuthContext";
import { sendNotification } from "@/lib/notifications";
import { cn } from "@/lib/utils";
import { startOfDay } from "date-fns";

export function AgentHistory() {
  const { user } = useAuth();
  const qc = useQueryClient();
  const [handoverOpen, setHandoverOpen] = useState(false);
  const [amount, setAmount] = useState("");
  const [handoverNotes, setHandoverNotes] = useState("");
  const [toUserId, setToUserId] = useState("");
  const [submitting, setSubmitting] = useState(false);
  const [expandedDate, setExpandedDate] = useState<string | null>(null);

  const today = new Date().toISOString().split("T")[0];
  const todayStart = startOfDay(new Date()).toISOString();

  const { data: mySales, isLoading: loadingSales } = useQuery({
    queryKey: ["mobile-history-sales", user?.id],
    queryFn: async () => {
      const { data } = await supabase
        .from("sales")
        .select("id, total_amount, cash_amount, upi_amount, created_at, sale_items(quantity, unit_price, products(name))")
        .eq("recorded_by", user!.id)
        .order("created_at", { ascending: false })
        .limit(200);
      return (data as any[]) || [];
    },
    enabled: !!user,
    refetchInterval: 60_000,
  });

  const { data: myHandovers } = useQuery({
    queryKey: ["mobile-history-handovers", user?.id],
    queryFn: async () => {
      const { data } = await supabase
        .from("handovers")
        .select("id, cash_amount, upi_amount, status, created_at, notes")
        .eq("user_id", user!.id)
        .order("created_at", { ascending: false });
      return (data as any[]) || [];
    },
    enabled: !!user,
    refetchInterval: 60_000,
  });

  const { data: staffUsers } = useQuery({
    queryKey: ["mobile-staff-users"],
    queryFn: async () => {
      const { data: roles } = await supabase.from("user_roles").select("user_id").neq("role", "customer");
      const ids = (roles || []).map((r: any) => r.user_id).filter((id: string) => id !== user!.id);
      const { data: profiles } = await supabase.from("profiles").select("user_id, full_name").in("user_id", ids).eq("is_active", true);
      return profiles || [];
    },
    enabled: !!user,
  });

  const todaySales = (mySales || []).filter((s: any) => s.created_at >= todayStart);
  const todayCash = todaySales.reduce((s: number, r: any) => s + Number(r.cash_amount), 0);
  const todayUpi = todaySales.reduce((s: number, r: any) => s + Number(r.upi_amount), 0);
  const todayTotal = todayCash + todayUpi;

  const confirmedHandovers = (myHandovers || []).filter((h: any) => h.status === "confirmed");
  const pendingHandover = (myHandovers || []).filter((h: any) => h.status === "awaiting_confirmation");
  const totalHandedOver = confirmedHandovers.reduce((s: number, h: any) => s + Number(h.cash_amount) + Number(h.upi_amount), 0);
  const pendingTotal = pendingHandover.reduce((s: number, h: any) => s + Number(h.cash_amount) + Number(h.upi_amount), 0);
  const allSalesTotal = (mySales || []).reduce((s: number, r: any) => s + Number(r.cash_amount) + Number(r.upi_amount), 0);
  const notHandedOver = Math.max(0, allSalesTotal - totalHandedOver - pendingTotal);

  const salesByDate = (mySales || []).reduce((acc: Record<string, any[]>, s: any) => {
    const date = s.created_at.split("T")[0];
    if (!acc[date]) acc[date] = [];
    acc[date].push(s);
    return acc;
  }, {});

  const handleHandover = async () => {
    if (!toUserId || !amount || Number(amount) <= 0) {
      toast.error("Select a recipient and enter a valid amount");
      return;
    }
    setSubmitting(true);
    const { error } = await supabase.from("handovers").insert({
      user_id: user!.id,
      handed_to: toUserId,
      cash_amount: Number(amount),
      upi_amount: 0,
      status: "awaiting_confirmation",
      notes: handoverNotes || null,
    });
    setSubmitting(false);
    if (error) { toast.error(error.message); return; }

    toast.success("Handover sent for confirmation");
    sendNotification({
      userId: toUserId,
      title: "Handover Received",
      message: `₹${Number(amount).toLocaleString()} handover awaiting your confirmation`,
      type: "handover",
      entityType: "handover",
    });
    setHandoverOpen(false);
    setAmount("");
    setHandoverNotes("");
    setToUserId("");
    qc.invalidateQueries({ queryKey: ["mobile-history-handovers"] });
  };

  return (
    <div className="pb-6">
      {/* Hero section */}
      <div className="bg-gradient-to-br from-blue-600 via-blue-700 to-indigo-700 dark:from-slate-900 dark:via-blue-950 dark:to-indigo-950 px-4 pt-4 pb-10">
        <p className="text-blue-200 text-xs font-medium uppercase tracking-widest">Overview</p>
        <h2 className="text-white text-xl font-bold mt-0.5">History & Handovers</h2>
      </div>

      <div className="px-4 -mt-6 space-y-4">
        {/* Today summary card */}
        <div className="rounded-2xl bg-white dark:bg-slate-800 shadow-xl border border-slate-100 dark:border-slate-700 p-4">
          <p className="text-xs font-bold text-slate-500 dark:text-slate-400 uppercase tracking-widest mb-3">Today's Sales</p>
          <div className="grid grid-cols-2 gap-4">
            <div>
              <p className="text-3xl font-bold text-slate-900 dark:text-white">₹{todayTotal.toLocaleString("en-IN")}</p>
              <div className="flex gap-3 mt-2">
                <span className="flex items-center gap-1 text-xs text-slate-500">
                  <span className="h-2 w-2 rounded-full bg-emerald-400" />
                  ₹{todayCash.toLocaleString("en-IN")} cash
                </span>
              </div>
              <div className="flex gap-3 mt-1">
                <span className="flex items-center gap-1 text-xs text-slate-500">
                  <span className="h-2 w-2 rounded-full bg-violet-400" />
                  ₹{todayUpi.toLocaleString("en-IN")} UPI
                </span>
              </div>
            </div>
            <div className="border-l border-slate-100 dark:border-slate-700 pl-4">
              <p className="text-[10px] text-slate-400 uppercase tracking-widest font-semibold mb-1">Pending Handover</p>
              <p className="text-2xl font-bold text-amber-500">₹{notHandedOver.toLocaleString("en-IN")}</p>
              {pendingTotal > 0 && (
                <p className="text-[11px] text-amber-400 mt-1">{pendingHandover.length} awaiting</p>
              )}
              {confirmedHandovers.length > 0 && (
                <p className="text-[11px] text-slate-400 mt-1">
                  ₹{totalHandedOver.toLocaleString("en-IN")} handed over
                </p>
              )}
            </div>
          </div>

          <button
            onClick={() => setHandoverOpen(true)}
            disabled={notHandedOver <= 0}
            className={cn(
              "w-full mt-4 h-12 rounded-xl text-sm font-bold flex items-center justify-center gap-2 transition-all",
              notHandedOver > 0
                ? "bg-gradient-to-r from-blue-600 to-indigo-600 hover:from-blue-700 hover:to-indigo-700 text-white shadow-sm active:scale-[0.98]"
                : "bg-slate-100 dark:bg-slate-700 text-slate-400 cursor-not-allowed"
            )}
          >
            <Send className="h-4 w-4" />
            Mark as Handed Over
          </button>
        </div>

        {/* Recent handovers */}
        {(myHandovers?.length ?? 0) > 0 && (
          <div>
            <p className="text-xs font-bold text-slate-500 dark:text-slate-400 uppercase tracking-widest mb-2.5">
              Recent Handovers
            </p>
            <div className="space-y-2">
              {myHandovers!.slice(0, 5).map((h: any) => {
                const amt = Number(h.cash_amount) + Number(h.upi_amount);
                const isConfirmed = h.status === "confirmed";
                return (
                  <div
                    key={h.id}
                    className="flex items-center gap-3 p-3.5 rounded-2xl bg-white dark:bg-slate-800 border border-slate-100 dark:border-slate-700 shadow-sm"
                  >
                    <div className={cn(
                      "h-9 w-9 rounded-xl flex items-center justify-center shrink-0",
                      isConfirmed
                        ? "bg-emerald-50 dark:bg-emerald-900/30"
                        : "bg-amber-50 dark:bg-amber-900/30"
                    )}>
                      {isConfirmed
                        ? <CheckCircle className="h-4.5 w-4.5 text-emerald-500" />
                        : <Clock className="h-4.5 w-4.5 text-amber-500" />
                      }
                    </div>
                    <div className="flex-1 min-w-0">
                      <p className="text-base font-bold text-slate-800 dark:text-white">
                        ₹{amt.toLocaleString("en-IN")}
                      </p>
                      <p className="text-xs text-slate-400">
                        {new Date(h.created_at).toLocaleDateString("en-IN", { day: "numeric", month: "short", year: "numeric" })}
                      </p>
                    </div>
                    <Badge
                      className={cn(
                        "text-[10px] font-bold px-2 shrink-0",
                        isConfirmed
                          ? "bg-emerald-50 dark:bg-emerald-900/30 text-emerald-600 dark:text-emerald-400 border-emerald-200 dark:border-emerald-700"
                          : "bg-amber-50 dark:bg-amber-900/30 text-amber-600 dark:text-amber-400 border-amber-200 dark:border-amber-700"
                      )}
                      variant="outline"
                    >
                      {isConfirmed ? "✓ Confirmed" : "⏳ Pending"}
                    </Badge>
                  </div>
                );
              })}
            </div>
          </div>
        )}

        {/* Daily logs */}
        <div>
          <p className="text-xs font-bold text-slate-500 dark:text-slate-400 uppercase tracking-widest mb-2.5">
            Daily Sales Log
          </p>

          {loadingSales ? (
            <div className="flex justify-center items-center py-10 gap-2">
              <Loader2 className="h-6 w-6 animate-spin text-blue-500" />
              <span className="text-sm text-slate-400">Loading history...</span>
            </div>
          ) : Object.keys(salesByDate).length === 0 ? (
            <div className="rounded-2xl border-2 border-dashed border-slate-200 dark:border-slate-700 p-8 text-center bg-slate-50/50 dark:bg-slate-800/30">
              <div className="h-12 w-12 rounded-2xl bg-slate-100 dark:bg-slate-700 flex items-center justify-center mx-auto mb-3">
                <TrendingUp className="h-6 w-6 text-slate-400" />
              </div>
              <p className="text-sm font-semibold text-slate-600 dark:text-slate-300">No sales recorded yet</p>
              <p className="text-xs text-slate-400 mt-1">Your daily logs will appear here</p>
            </div>
          ) : (
            <div className="space-y-2">
              {Object.entries(salesByDate).map(([date, daySales]) => {
                const dayTotal = (daySales as any[]).reduce((s, r) => s + Number(r.total_amount), 0);
                const dayCash = (daySales as any[]).reduce((s, r) => s + Number(r.cash_amount), 0);
                const dayUpi = (daySales as any[]).reduce((s, r) => s + Number(r.upi_amount), 0);
                const isToday = date === today;
                const isExpanded = expandedDate === date;

                const productTotals: Record<string, number> = {};
                (daySales as any[]).forEach((sale: any) => {
                  (sale.sale_items || []).forEach((item: any) => {
                    const n = item.products?.name ?? "Unknown";
                    productTotals[n] = (productTotals[n] ?? 0) + item.quantity;
                  });
                });

                return (
                  <div
                    key={date}
                    className={cn(
                      "rounded-2xl bg-white dark:bg-slate-800 border shadow-sm overflow-hidden transition-all",
                      isToday
                        ? "border-blue-100 dark:border-blue-800/40"
                        : "border-slate-100 dark:border-slate-700"
                    )}
                  >
                    <button
                      className="w-full text-left"
                      onClick={() => setExpandedDate(isExpanded ? null : date)}
                    >
                      <div className="flex items-center gap-3 p-4">
                        <div className={cn(
                          "h-10 w-10 rounded-xl flex items-center justify-center shrink-0",
                          isToday
                            ? "bg-blue-50 dark:bg-blue-900/30"
                            : "bg-slate-50 dark:bg-slate-700"
                        )}>
                          <TrendingUp className={cn(
                            "h-4.5 w-4.5",
                            isToday ? "text-blue-500" : "text-slate-400"
                          )} />
                        </div>
                        <div className="flex-1 min-w-0">
                          <div className="flex items-center gap-2 flex-wrap">
                            <p className="text-sm font-bold text-slate-800 dark:text-white">
                              {isToday ? "Today" : new Date(date + "T12:00:00").toLocaleDateString("en-IN", { day: "numeric", month: "short" })}
                            </p>
                            {isToday && (
                              <Badge className="text-[9px] h-4 px-1.5 bg-blue-600 text-white font-bold">Today</Badge>
                            )}
                          </div>
                          <p className="text-xs text-slate-400 mt-0.5">
                            {(daySales as any[]).length} sale{(daySales as any[]).length > 1 ? "s" : ""}
                            {" · "}₹{dayCash.toLocaleString("en-IN")} cash
                            {" · "}₹{dayUpi.toLocaleString("en-IN")} UPI
                          </p>
                        </div>
                        <div className="flex items-center gap-2 shrink-0">
                          <p className="text-base font-bold text-slate-900 dark:text-white">
                            ₹{dayTotal.toLocaleString("en-IN")}
                          </p>
                          <div className="h-7 w-7 rounded-full bg-slate-100 dark:bg-slate-700 flex items-center justify-center">
                            {isExpanded
                              ? <ChevronUp className="h-3.5 w-3.5 text-slate-500" />
                              : <ChevronDown className="h-3.5 w-3.5 text-slate-500" />}
                          </div>
                        </div>
                      </div>
                    </button>

                    {/* Expanded product breakdown */}
                    {isExpanded && Object.keys(productTotals).length > 0 && (
                      <div className="px-4 pb-4 border-t border-slate-100 dark:border-slate-700 pt-3">
                        <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest mb-2 flex items-center gap-1.5">
                          <Package className="h-3 w-3" /> Products Sold
                        </p>
                        <div className="space-y-1.5">
                          {Object.entries(productTotals).map(([name, qty]) => (
                            <div key={name} className="flex justify-between items-center">
                              <span className="text-sm text-slate-700 dark:text-slate-300">{name}</span>
                              <span className="text-xs font-semibold text-slate-500 dark:text-slate-400 bg-slate-100 dark:bg-slate-700 px-2 py-0.5 rounded-full">
                                {qty} units
                              </span>
                            </div>
                          ))}
                        </div>
                      </div>
                    )}
                  </div>
                );
              })}
            </div>
          )}
        </div>
      </div>

      {/* Handover Sheet */}
      <Sheet open={handoverOpen} onOpenChange={setHandoverOpen}>
        <SheetContent side="bottom" className="rounded-t-3xl pb-10 px-0">
          <div className="px-6">
            <SheetHeader className="mb-5 text-left">
              <div className="flex items-center gap-3">
                <div className="h-10 w-10 rounded-2xl bg-gradient-to-br from-blue-500 to-indigo-600 flex items-center justify-center">
                  <ArrowUpRight className="h-5 w-5 text-white" />
                </div>
                <div>
                  <SheetTitle className="text-lg font-bold">Hand Over Cash</SheetTitle>
                  <p className="text-xs text-slate-400">Available: ₹{notHandedOver.toLocaleString("en-IN")}</p>
                </div>
              </div>
            </SheetHeader>

            <div className="space-y-4">
              <div>
                <Label className="text-xs font-bold text-slate-500 uppercase tracking-widest mb-2 block">Hand over to</Label>
                <Select value={toUserId} onValueChange={setToUserId}>
                  <SelectTrigger className="rounded-xl h-12 border-slate-200 dark:border-slate-600">
                    <SelectValue placeholder="Select recipient..." />
                  </SelectTrigger>
                  <SelectContent>
                    {(staffUsers as any[] || []).map((s: any) => (
                      <SelectItem key={s.user_id} value={s.user_id}>{s.full_name}</SelectItem>
                    ))}
                  </SelectContent>
                </Select>
              </div>

              <div>
                <Label className="text-xs font-bold text-slate-500 uppercase tracking-widest mb-2 block">Amount</Label>
                <div className="relative">
                  <span className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400 text-base font-semibold">₹</span>
                  <Input
                    type="number"
                    min="0"
                    value={amount}
                    onChange={(e) => setAmount(e.target.value)}
                    placeholder="0"
                    className="pl-8 h-13 rounded-xl text-lg font-bold border-slate-200 dark:border-slate-600"
                  />
                </div>
              </div>

              <div>
                <Label className="text-xs font-bold text-slate-500 uppercase tracking-widest mb-2 block">Notes (optional)</Label>
                <Textarea
                  value={handoverNotes}
                  onChange={(e) => setHandoverNotes(e.target.value)}
                  placeholder="e.g. Cash bag #2, reference number..."
                  className="rounded-xl resize-none border-slate-200 dark:border-slate-600"
                  rows={2}
                />
              </div>

              <button
                className={cn(
                  "w-full h-13 rounded-xl text-base font-bold flex items-center justify-center gap-2 transition-all",
                  submitting
                    ? "bg-blue-400 text-white cursor-not-allowed"
                    : "bg-gradient-to-r from-blue-600 to-indigo-600 hover:from-blue-700 hover:to-indigo-700 text-white shadow-sm active:scale-[0.98]"
                )}
                onClick={handleHandover}
                disabled={submitting}
              >
                {submitting ? (
                  <Loader2 className="h-5 w-5 animate-spin" />
                ) : (
                  <>
                    <Send className="h-4 w-4" />
                    Submit Handover
                  </>
                )}
              </button>
            </div>
          </div>
        </SheetContent>
      </Sheet>
    </div>
  );
}

import { useQuery } from "@tanstack/react-query";
import {
  MapPin, Phone, Navigation2, TrendingUp, IndianRupee,
  Store, ShoppingCart, Loader2, Banknote, Wallet, ArrowRight,
} from "lucide-react";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import { supabase } from "@/integrations/supabase/client";
import { useAuth } from "@/contexts/AuthContext";
import { cn } from "@/lib/utils";

export function AgentHome() {
  const { user, profile } = useAuth();
  const today = new Date().toISOString().split("T")[0];

  const { data: salesData } = useQuery({
    queryKey: ["mobile-agent-sales-today", user?.id, today],
    queryFn: async () => {
      const { data } = await supabase
        .from("sales")
        .select("total_amount, cash_amount, upi_amount")
        .eq("recorded_by", user!.id)
        .gte("created_at", today);
      return data || [];
    },
    enabled: !!user,
    refetchInterval: 60_000,
  });

  const { data: txData } = useQuery({
    queryKey: ["mobile-agent-tx-today", user?.id, today],
    queryFn: async () => {
      const { data } = await supabase
        .from("transactions")
        .select("total_amount, cash_amount, upi_amount")
        .eq("recorded_by", user!.id)
        .gte("created_at", today);
      return data || [];
    },
    enabled: !!user,
    refetchInterval: 60_000,
  });

  const { data: visitCount } = useQuery({
    queryKey: ["mobile-agent-visits-today", user?.id, today],
    queryFn: async () => {
      const { count } = await supabase
        .from("store_visits")
        .select("id", { count: "exact", head: true })
        .gte("visited_at", today);
      return count ?? 0;
    },
    enabled: !!user,
    refetchInterval: 60_000,
  });

  const { data: activeSession } = useQuery({
    queryKey: ["mobile-active-session", user?.id],
    queryFn: async () => {
      const { data } = await (supabase as any)
        .from("route_sessions")
        .select("*, routes(name, stores(id, name, address, lat, lng, store_order, phone))")
        .eq("user_id", user!.id)
        .eq("status", "active")
        .maybeSingle();
      return data;
    },
    enabled: !!user,
    refetchInterval: 30_000,
  });

  const { data: visits } = useQuery({
    queryKey: ["mobile-session-visits", activeSession?.id],
    queryFn: async () => {
      const { data } = await supabase
        .from("store_visits")
        .select("store_id")
        .eq("session_id", activeSession!.id);
      return new Set((data || []).map((v: any) => v.store_id));
    },
    enabled: !!activeSession,
  });

  const { data: pendingOrders } = useQuery({
    queryKey: ["mobile-agent-pending-orders"],
    queryFn: async () => {
      const { data } = await supabase
        .from("orders")
        .select("id, display_id, notes, stores(name), customers(name)")
        .eq("status", "pending")
        .order("created_at", { ascending: false })
        .limit(5);
      return (data as any[]) || [];
    },
    enabled: !!user,
    refetchInterval: 60_000,
  });

  const totalSales = salesData?.reduce((s, r) => s + (r.total_amount ?? 0), 0) ?? 0;
  const cashSales = salesData?.reduce((s, r) => s + (r.cash_amount ?? 0), 0) ?? 0;
  const upiSales = salesData?.reduce((s, r) => s + (r.upi_amount ?? 0), 0) ?? 0;
  const cashCollected = txData?.reduce((s, r) => s + (r.cash_amount ?? 0), 0) ?? 0;
  const upiCollected = txData?.reduce((s, r) => s + (r.upi_amount ?? 0), 0) ?? 0;

  const routeStores: any[] = (activeSession as any)?.routes?.stores ?? [];
  const sortedStores = [...routeStores].sort((a, b) => (a.store_order ?? 0) - (b.store_order ?? 0));
  const nextStore = sortedStores.find((s) => !visits?.has(s.id));
  const visitedCount = sortedStores.filter((s) => visits?.has(s.id)).length;
  const progressPct = routeStores.length ? (visitedCount / routeStores.length) * 100 : 0;

  const greeting = () => {
    const h = new Date().getHours();
    if (h < 12) return "Good morning";
    if (h < 17) return "Good afternoon";
    return "Good evening";
  };

  const firstName = (profile?.full_name ?? "Agent").split(" ")[0];

  return (
    <div className="pb-6">
      {/* Hero greeting banner */}
      <div className="bg-gradient-to-br from-blue-600 via-blue-700 to-indigo-700 dark:from-slate-900 dark:via-blue-950 dark:to-indigo-950 px-4 pt-4 pb-8">
        <p className="text-blue-200 text-sm font-medium">{greeting()},</p>
        <h2 className="text-white text-2xl font-bold mt-0.5">{firstName} 👋</h2>
        <p className="text-blue-200/80 text-xs mt-1">
          {new Date().toLocaleDateString("en-IN", { weekday: "long", day: "numeric", month: "long" })}
        </p>
      </div>

      {/* Overlapping stats cards */}
      <div className="px-4 -mt-5 space-y-3">
        {/* Hero total sales card */}
        <div className="rounded-2xl bg-white dark:bg-slate-800 shadow-xl border border-slate-100 dark:border-slate-700 p-4">
          <div className="flex items-center justify-between mb-3">
            <p className="text-xs font-semibold text-slate-500 dark:text-slate-400 uppercase tracking-wider">
              Today's Revenue
            </p>
            <div className="flex items-center gap-1.5 bg-blue-50 dark:bg-blue-900/40 px-2 py-1 rounded-full">
              <Store className="h-3 w-3 text-blue-500" />
              <span className="text-[11px] font-semibold text-blue-600 dark:text-blue-400">
                {visitCount ?? 0} stores
              </span>
            </div>
          </div>
          <p className="text-3xl font-bold text-slate-900 dark:text-white tracking-tight">
            ₹{totalSales.toLocaleString("en-IN")}
          </p>
          <div className="flex gap-4 mt-3 pt-3 border-t border-slate-100 dark:border-slate-700">
            <div className="flex items-center gap-1.5">
              <div className="h-2 w-2 rounded-full bg-emerald-400" />
              <span className="text-xs text-slate-500 dark:text-slate-400">
                Cash <strong className="text-slate-700 dark:text-slate-200">₹{(cashSales + cashCollected).toLocaleString("en-IN")}</strong>
              </span>
            </div>
            <div className="flex items-center gap-1.5">
              <div className="h-2 w-2 rounded-full bg-violet-400" />
              <span className="text-xs text-slate-500 dark:text-slate-400">
                UPI <strong className="text-slate-700 dark:text-slate-200">₹{(upiSales + upiCollected).toLocaleString("en-IN")}</strong>
              </span>
            </div>
          </div>
        </div>

        {/* Stats row */}
        <div className="grid grid-cols-3 gap-2">
          <MiniStat
            label="Sales"
            value={`₹${totalSales >= 1000 ? `${(totalSales / 1000).toFixed(1)}k` : totalSales.toLocaleString()}`}
            color="from-blue-500 to-blue-600"
            icon={TrendingUp}
          />
          <MiniStat
            label="Cash"
            value={`₹${(cashSales + cashCollected) >= 1000 ? `${((cashSales + cashCollected) / 1000).toFixed(1)}k` : (cashSales + cashCollected).toLocaleString()}`}
            color="from-emerald-500 to-green-600"
            icon={Banknote}
          />
          <MiniStat
            label="UPI"
            value={`₹${(upiSales + upiCollected) >= 1000 ? `${((upiSales + upiCollected) / 1000).toFixed(1)}k` : (upiSales + upiCollected).toLocaleString()}`}
            color="from-violet-500 to-purple-600"
            icon={Wallet}
          />
        </div>
      </div>

      {/* Active route section */}
      {activeSession ? (
        <div className="px-4 mt-5">
          <SectionLabel>Active Route</SectionLabel>
          <div className="rounded-2xl bg-white dark:bg-slate-800 border border-slate-100 dark:border-slate-700 shadow-sm overflow-hidden">
            {/* Route header */}
            <div className="bg-gradient-to-r from-blue-50 to-indigo-50 dark:from-blue-900/30 dark:to-indigo-900/30 px-4 py-3 flex items-center justify-between">
              <div>
                <p className="font-semibold text-slate-800 dark:text-white text-base">
                  {(activeSession as any).routes?.name ?? "Route"}
                </p>
                <p className="text-xs text-slate-500 dark:text-slate-400 mt-0.5">
                  {visitedCount} of {routeStores.length} stores done
                </p>
              </div>
              <Badge className="bg-blue-600 text-white text-[10px] font-semibold px-2">
                🟢 Active
              </Badge>
            </div>
            {/* Progress bar */}
            <div className="px-4 py-3">
              <div className="h-2.5 bg-slate-100 dark:bg-slate-700 rounded-full overflow-hidden">
                <div
                  className="h-full bg-gradient-to-r from-blue-500 to-indigo-500 rounded-full transition-all duration-700"
                  style={{ width: `${progressPct}%` }}
                />
              </div>
              <div className="flex justify-between mt-1.5">
                <span className="text-[11px] text-slate-400">{Math.round(progressPct)}% complete</span>
                <span className="text-[11px] text-slate-400">{routeStores.length - visitedCount} remaining</span>
              </div>
            </div>
          </div>
        </div>
      ) : (
        <div className="px-4 mt-5">
          <div className="rounded-2xl border-2 border-dashed border-slate-200 dark:border-slate-700 p-5 text-center bg-slate-50/50 dark:bg-slate-800/30">
            <div className="h-12 w-12 rounded-2xl bg-slate-100 dark:bg-slate-700 flex items-center justify-center mx-auto mb-3">
              <MapPin className="h-6 w-6 text-slate-400" />
            </div>
            <p className="text-sm font-semibold text-slate-700 dark:text-slate-200">No Active Route</p>
            <p className="text-xs text-slate-400 mt-1">Go to Routes tab to start your day</p>
          </div>
        </div>
      )}

      {/* Next store */}
      {nextStore && (
        <div className="px-4 mt-5">
          <SectionLabel>Next Stop</SectionLabel>
          <div className="rounded-2xl bg-white dark:bg-slate-800 border border-slate-100 dark:border-slate-700 shadow-sm p-4">
            <div className="flex items-start gap-3">
              <div className="h-11 w-11 rounded-xl bg-gradient-to-br from-orange-400 to-amber-500 flex items-center justify-center shrink-0 shadow-sm">
                <Store className="h-5 w-5 text-white" />
              </div>
              <div className="flex-1 min-w-0">
                <div className="flex items-start justify-between gap-2">
                  <p className="font-semibold text-slate-800 dark:text-white text-base leading-tight truncate">
                    {nextStore.name}
                  </p>
                  <Badge variant="outline" className="text-[10px] shrink-0 border-orange-200 text-orange-600 dark:border-orange-700 dark:text-orange-400 bg-orange-50 dark:bg-orange-900/20">
                    Up Next
                  </Badge>
                </div>
                {nextStore.address && (
                  <p className="text-xs text-slate-400 mt-0.5 line-clamp-1">{nextStore.address}</p>
                )}
              </div>
            </div>
            <div className="flex gap-2 mt-3">
              <Button
                size="sm"
                className="flex-1 h-10 rounded-xl gap-1.5 bg-blue-600 hover:bg-blue-700 text-white text-xs font-semibold"
                onClick={() => {
                  if (nextStore.lat && nextStore.lng) {
                    window.open(`https://www.google.com/maps/dir/?api=1&destination=${nextStore.lat},${nextStore.lng}`, "_blank");
                  } else if (nextStore.address) {
                    window.open(`https://www.google.com/maps/dir/?api=1&destination=${encodeURIComponent(nextStore.address)}`, "_blank");
                  }
                }}
              >
                <Navigation2 className="h-3.5 w-3.5" />
                Navigate
              </Button>
              {nextStore.phone && (
                <Button
                  size="sm"
                  variant="outline"
                  className="flex-1 h-10 rounded-xl gap-1.5 text-xs font-semibold border-slate-200 dark:border-slate-600"
                  onClick={() => window.open(`tel:${nextStore.phone}`, "_self")}
                >
                  <Phone className="h-3.5 w-3.5" />
                  Call
                </Button>
              )}
            </div>
          </div>
        </div>
      )}

      {/* Pending orders */}
      {(pendingOrders?.length ?? 0) > 0 && (
        <div className="px-4 mt-5">
          <SectionLabel>{pendingOrders!.length} Pending Orders</SectionLabel>
          <div className="space-y-2">
            {pendingOrders!.map((order: any) => (
              <div
                key={order.id}
                className="flex items-center gap-3 p-3.5 rounded-xl bg-white dark:bg-slate-800 border border-slate-100 dark:border-slate-700 shadow-sm"
              >
                <div className="h-9 w-9 rounded-xl bg-amber-50 dark:bg-amber-900/30 flex items-center justify-center shrink-0">
                  <ShoppingCart className="h-4 w-4 text-amber-500" />
                </div>
                <div className="min-w-0 flex-1">
                  <p className="text-sm font-semibold text-slate-800 dark:text-white truncate">
                    {order.stores?.name ?? "Unknown Store"}
                  </p>
                  {order.notes && (
                    <p className="text-xs text-slate-400 truncate">{order.notes}</p>
                  )}
                </div>
                <div className="flex items-center gap-1 shrink-0">
                  <Badge variant="secondary" className="text-[10px] bg-amber-50 dark:bg-amber-900/30 text-amber-600 dark:text-amber-400 border-amber-200 dark:border-amber-700">
                    {order.display_id}
                  </Badge>
                  <ArrowRight className="h-3.5 w-3.5 text-slate-300 dark:text-slate-600" />
                </div>
              </div>
            ))}
          </div>
        </div>
      )}
    </div>
  );
}

function SectionLabel({ children }: { children: React.ReactNode }) {
  return (
    <p className="text-xs font-bold text-slate-500 dark:text-slate-400 uppercase tracking-widest mb-2.5">
      {children}
