import { Badge } from "@/components/ui/badge";
import { parseUpiQr } from "@/lib/upiParser";
import { getCurrentPosition } from "@/lib/proximity";
import { supabase } from "@/integrations/supabase/client";
import { useAuth } from "@/contexts/AuthContext";
import {
  ScanLine, MapPin, ShoppingCart, Banknote, CheckCircle,
  Navigation, Loader2, Camera, RefreshCw, X, Store,
  ArrowRight,
} from "lucide-react";
import { toast } from "sonner";
import { Dialog, DialogContent, DialogHeader, DialogTitle } from "@/components/ui/dialog";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { Label } from "@/components/ui/label";
import { Html5Qrcode } from "html5-qrcode";

const SCANNER_ID = "quick-action-qr-reader";

interface ScannedStoreDetail {
  id: string;
  name: string;
  display_id: string;
  address: string | null;
  photo_url: string | null;
  store_type: string | null;
}

interface NearbyStore {
  id: string;
  name: string;
  display_id: string;
  distance: number;
}

export function QuickActionDrawer() {
  const navigate = useNavigate();
  const { role } = useAuth();
  const isAdmin = role === "super_admin" || role === "manager";
  const [open, setOpen] = useState(false);

  // scanner state
  const [scannerStarted, setScannerStarted] = useState(false);
  const [scannerError, setScannerError] = useState<string | null>(null);

  // scanned store (full detail for display)
  const [scannedStore, setScannedStore] = useState<ScannedStoreDetail | null>(null);

  // nearby
  const [nearbyStores, setNearbyStores] = useState<NearbyStore[]>([]);
  const [loadingNearby, setLoadingNearby] = useState(false);
  const [showNearby, setShowNearby] = useState(false);

  // qr-not-found dialog
  const [notFoundDialog, setNotFoundDialog] = useState(false);
  const [scannedUpi, setScannedUpi] = useState({ upiId: "", payeeName: "", raw: "" });
  const [linkMode, setLinkMode] = useState(false);
  const [linkStoreId, setLinkStoreId] = useState("");
  const [allStores, setAllStores] = useState<any[]>([]);
  const [saving, setSaving] = useState(false);

  const scannerRef = useRef<Html5Qrcode | null>(null);
  const onScanRef = useRef<(data: string) => void>();

  // ── scanner controls ──────────────────────────────────────────────────────

  const stopScanner = useCallback(async () => {
    if (scannerRef.current) {
      await scannerRef.current.stop().catch(() => {});
      scannerRef.current = null;
    }
    setScannerStarted(false);
  }, []);

  const startScanner = useCallback(async () => {
    setScannerError(null);
    try {
      if (scannerRef.current) {
        await scannerRef.current.stop().catch(() => {});
        scannerRef.current = null;
      }
      const scanner = new Html5Qrcode(SCANNER_ID);
      scannerRef.current = scanner;
      await scanner.start(
        { facingMode: "environment" },
        { fps: 10, qrbox: { width: 200, height: 200 } },
        (decodedText) => { onScanRef.current?.(decodedText); },
        () => {}
      );
      setScannerStarted(true);
    } catch (err: any) {
      const msg = err?.message || String(err);
      if (msg.includes("NotAllowedError") || msg.includes("Permission")) {
        setScannerError("Camera permission denied. Allow access in browser settings.");
      } else if (msg.includes("NotFoundError") || msg.includes("not found")) {
        setScannerError("No camera found on this device.");
      } else {
        setScannerError("Could not start camera. Please retry.");
      }
    }
  }, []);

  // auto-start on drawer open; stop on close
  useEffect(() => {
    if (open && !scannedStore) {
      const t = setTimeout(() => startScanner(), 250);
      return () => clearTimeout(t);
    }
    if (!open) {
      stopScanner();
      setScannerError(null);
    }
  }, [open, scannedStore, startScanner, stopScanner]);

  // cleanup on unmount
  useEffect(() => () => { stopScanner(); }, [stopScanner]);

  // ── QR scan handler ───────────────────────────────────────────────────────

  const handleQrScan = useCallback(async (data: string) => {
    await stopScanner();

    const upi = parseUpiQr(data);
    if (!upi) {
      toast.error("Not a valid UPI QR code");
      setTimeout(() => startScanner(), 500);
      return;
    }

    const { data: qrRecord } = await supabase
      .from("store_qr_codes")
      .select("store_id, stores(id, name, display_id, address, photo_url, store_types(name))")
      .eq("upi_id", upi.pa)
      .maybeSingle();

    if (qrRecord?.store_id && qrRecord.stores) {
      const s = qrRecord.stores as any;
      setScannedStore({
        id: s.id,
        name: s.name,
        display_id: s.display_id,
        address: s.address ?? null,
        photo_url: s.photo_url ?? null,
        store_type: s.store_types?.name ?? null,
      });
      toast.success(`Store found: ${s.name}`);
    } else {
      setScannedUpi({ upiId: upi.pa, payeeName: upi.pn, raw: upi.raw });
      setNotFoundDialog(true);
    }
  }, [stopScanner, startScanner]);

  onScanRef.current = handleQrScan;

  // dismiss scanned store → restart camera
  const dismissStore = useCallback(async () => {
    setScannedStore(null);
    await stopScanner();
    setTimeout(() => startScanner(), 200);
  }, [stopScanner, startScanner]);

  // ── actions ───────────────────────────────────────────────────────────────

  const handleAction = (action: "sale" | "transaction" | "visit") => {
    setOpen(false);
    const storeParam = scannedStore ? `?store=${scannedStore.id}` : "";
    if (action === "sale") navigate(`/sales${storeParam}`);
    else if (action === "transaction") navigate(`/transactions${storeParam}`);
    else toast.info("Mark visit functionality requires an active route session");
  };

  const findNearbyStores = async () => {
    setLoadingNearby(true);
    setShowNearby(true);
    const loc = await getCurrentPosition();
    if (!loc) {
      toast.error("Could not get your location. Enable GPS.");
      setLoadingNearby(false);
      return;
    }
    const { data: stores } = await supabase
      .from("stores")
      .select("id, name, display_id, lat, lng")
      .eq("is_active", true)
      .not("lat", "is", null)
      .not("lng", "is", null);

    if (!stores?.length) {
      toast.info("No stores with GPS coordinates found");
      setNearbyStores([]);
      setLoadingNearby(false);
      return;
    }

    const nearby = stores
      .map((store) => {
        const R = 6371000;
        const dLat = ((store.lat! - loc.lat) * Math.PI) / 180;
        const dLng = ((store.lng! - loc.lng) * Math.PI) / 180;
        const a =
          Math.sin(dLat / 2) ** 2 +
          Math.cos((loc.lat * Math.PI) / 180) *
            Math.cos((store.lat! * Math.PI) / 180) *
            Math.sin(dLng / 2) ** 2;
        return { ...store, distance: Math.round(R * 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1 - a))) };
      })
      .filter((s) => s.distance <= 100)
      .sort((a, b) => a.distance - b.distance)
      .slice(0, 5);

    setNearbyStores(nearby);
    setLoadingNearby(false);
    if (nearby.length === 0) toast.info("No stores within 100m");
    else toast.success(`Found ${nearby.length} nearby store(s)`);
  };

  // ── QR-not-found helpers ──────────────────────────────────────────────────

  const handleLinkStore = async () => {
    const { data } = await supabase.from("stores").select("id, name, display_id").eq("is_active", true);
    setAllStores(data || []);
    setLinkMode(true);
  };

  const confirmLink = async () => {
    if (!linkStoreId) return;
    setSaving(true);
    const { error } = await supabase.from("store_qr_codes").insert({
      store_id: linkStoreId,
      upi_id: scannedUpi.upiId,
      payee_name: scannedUpi.payeeName || null,
      raw_data: scannedUpi.raw,
    });
    setSaving(false);
    if (error) { toast.error(error.message); return; }
    const store = allStores.find((s) => s.id === linkStoreId);
    toast.success("QR linked to store");
    setScannedStore({
      id: linkStoreId,
      name: store?.name || "",
      display_id: store?.display_id || "",
      address: null,
      photo_url: null,
      store_type: null,
    });
    setNotFoundDialog(false);
    setLinkMode(false);
    setLinkStoreId("");
  };

  const handleCreateStore = () => {
    setNotFoundDialog(false);
    setOpen(false);
    navigate("/stores", {
      state: { prefillQr: { name: scannedUpi.payeeName || "", upiId: scannedUpi.upiId, rawQr: scannedUpi.raw } },
    });
  };

  // ── render ────────────────────────────────────────────────────────────────

  return (
    <>
      <Drawer open={open} onOpenChange={setOpen}>
        <DrawerTrigger asChild>
          <Button size="lg" className="gap-2 rounded-full shadow-lg px-4 sm:px-6">
            <ScanLine className="h-5 w-5" />
            <span className="hidden sm:inline">Quick Actions</span>
            <span className="sm:hidden">Scan</span>
          </Button>
        </DrawerTrigger>

        <DrawerContent className="h-[92vh] flex flex-col p-0 overflow-hidden">

          {/* ═══════════════════════════════════════════════════════════════ */}
          {/* TOP HALF: camera OR store card                                 */}
          {/* ═══════════════════════════════════════════════════════════════ */}
          <div className="relative flex-shrink-0 overflow-hidden" style={{ height: "48%" }}>

            {/* ── CAMERA VIEW (shown when no store selected) ── */}
            {!scannedStore && (
              <div className="absolute inset-0 bg-black">
                {/* Html5Qrcode video target */}
                <div
                  id={SCANNER_ID}
                  className="w-full h-full [&>video]:w-full [&>video]:h-full [&>video]:object-cover [&_#qr-shaded-region]:!border-none"
                />

                {/* Viewfinder overlay */}
                {scannerStarted && !scannerError && (
                  <div className="pointer-events-none absolute inset-0 flex flex-col items-center justify-center">
                    {/* Dim corners */}
                    <div className="relative w-52 h-52">
                      <div className="absolute inset-0 rounded-lg" />
                      {/* corner brackets */}
                      <span className="absolute top-0 left-0 w-8 h-8 border-t-[3px] border-l-[3px] border-white rounded-tl-lg" />
                      <span className="absolute top-0 right-0 w-8 h-8 border-t-[3px] border-r-[3px] border-white rounded-tr-lg" />
                      <span className="absolute bottom-0 left-0 w-8 h-8 border-b-[3px] border-l-[3px] border-white rounded-bl-lg" />
                      <span className="absolute bottom-0 right-0 w-8 h-8 border-b-[3px] border-r-[3px] border-white rounded-br-lg" />
                      {/* animated scan line */}
                      <span className="absolute left-1 right-1 h-px bg-primary shadow-[0_0_6px_2px] shadow-primary/60 animate-[scan_2s_ease-in-out_infinite]" />
                    </div>
                    <p className="mt-4 text-xs text-white/70 tracking-wide">Align QR code within the frame</p>
                  </div>
                )}

                {/* Loading */}
                {!scannerStarted && !scannerError && (
                  <div className="absolute inset-0 flex flex-col items-center justify-center gap-3 bg-black">
                    <Loader2 className="h-8 w-8 animate-spin text-white/50" />
                    <p className="text-xs text-white/50 tracking-wide">Starting camera…</p>
                  </div>
                )}

                {/* Error */}
                {scannerError && (
                  <div className="absolute inset-0 flex flex-col items-center justify-center gap-4 bg-black px-8">
                    <Camera className="h-12 w-12 text-white/25" />
                    <p className="text-sm text-white/60 text-center leading-relaxed">{scannerError}</p>
                    <Button
                      variant="outline"
                      size="sm"
                      onClick={startScanner}
                      className="gap-2 bg-white/10 border-white/30 text-white hover:bg-white/20 hover:text-white"
                    >
                      <RefreshCw className="h-3.5 w-3.5" /> Retry
                    </Button>
                  </div>
                )}

                {/* Close drawer button */}
                <button
                  onClick={() => setOpen(false)}
                  className="absolute top-3 right-3 z-10 flex h-8 w-8 items-center justify-center rounded-full bg-black/60 text-white/80 hover:bg-black/80 hover:text-white transition-colors"
                >
                  <X className="h-4 w-4" />
                </button>

                {/* Bottom label */}
                {scannerStarted && (
                  <div className="absolute bottom-0 inset-x-0 py-2 text-center bg-gradient-to-t from-black/80 to-transparent">
                    <p className="text-[11px] text-white/60 font-medium uppercase tracking-widest">Store QR Scanner</p>
                  </div>
                )}
              </div>
            )}

            {/* ── STORE CARD (shown after successful scan) ── */}
            {scannedStore && (
              <div className="absolute inset-0 bg-card">
                {/* Store photo or placeholder */}
                {scannedStore.photo_url ? (
                  <img
                    src={scannedStore.photo_url}
                    alt={scannedStore.name}
                    className="absolute inset-0 w-full h-full object-cover"
                  />
                ) : (
                  <div className="absolute inset-0 bg-gradient-to-br from-primary/20 via-primary/10 to-background flex items-center justify-center">
                    <Store className="h-20 w-20 text-primary/30" />
                  </div>
                )}

                {/* Gradient overlay for text readability */}
                <div className="absolute inset-0 bg-gradient-to-t from-black/80 via-black/20 to-transparent" />

                {/* Store info overlay at bottom */}
                <div className="absolute bottom-0 inset-x-0 px-4 pb-4 pt-12">
                  {scannedStore.store_type && (
                    <Badge variant="secondary" className="mb-1.5 text-[10px] bg-white/20 text-white border-white/30 backdrop-blur-sm">
                      {scannedStore.store_type}
                    </Badge>
                  )}
                  <h2 className="text-xl font-bold text-white leading-tight">{scannedStore.name}</h2>
                  <p className="text-xs text-white/70 mt-0.5">{scannedStore.display_id}</p>
                  {scannedStore.address && (
                    <p className="text-xs text-white/60 mt-1 flex items-start gap-1">
                      <MapPin className="h-3 w-3 mt-0.5 shrink-0" />
                      <span className="line-clamp-1">{scannedStore.address}</span>
                    </p>
                  )}
                </div>

                {/* Dismiss (X) — restarts camera */}
                <button
                  onClick={dismissStore}
                  className="absolute top-3 right-3 z-10 flex h-9 w-9 items-center justify-center rounded-full bg-black/60 text-white/90 hover:bg-black/80 hover:text-white transition-colors backdrop-blur-sm"
                  title="Dismiss & scan again"
                >
                  <X className="h-4 w-4" />
                </button>

                {/* "Scan again" subtle hint */}
                <div className="absolute top-3 left-3">
                  <Badge variant="outline" className="text-[10px] bg-emerald-500/90 text-white border-emerald-400/50 gap-1 backdrop-blur-sm">
                    <CheckCircle className="h-2.5 w-2.5" /> Scanned
                  </Badge>
                </div>
              </div>
            )}
          </div>

          {/* ═══════════════════════════════════════════════════════════════ */}
          {/* BOTTOM HALF: actions + nearby                                  */}
          {/* ═══════════════════════════════════════════════════════════════ */}
          <div className="flex-1 overflow-y-auto bg-background">
            {/* Drag handle */}
            <div className="mx-auto mt-2.5 mb-0.5 h-1 w-10 rounded-full bg-border" />

            <div className="px-4 pb-safe-area-inset-bottom pb-6 pt-3 space-y-4">

              {/* ── Quick action buttons — always visible ── */}
              <div className="space-y-2.5">
                <div className="flex items-center justify-between">
                  <p className="text-xs font-semibold text-muted-foreground uppercase tracking-wider">Quick Actions</p>
                  {scannedStore && (
                    <span className="flex items-center gap-1 text-[11px] text-emerald-600 font-medium">
                      <CheckCircle className="h-3 w-3" />
                      {scannedStore.name}
                    </span>
                  )}
                </div>

                <button
                  onClick={() => handleAction("sale")}
                  className="w-full flex items-center justify-between rounded-xl bg-primary px-4 py-3.5 text-primary-foreground shadow-sm hover:bg-primary/90 active:scale-[0.98] transition-all"
                >
                  <span className="flex items-center gap-3">
                    <div className="flex h-8 w-8 items-center justify-center rounded-lg bg-white/20">
                      <ShoppingCart className="h-4 w-4" />
                    </div>
                    <div className="text-left">
                      <p className="font-semibold text-sm">Record Sale</p>
                      <p className="text-[11px] text-primary-foreground/70">
                        {scannedStore ? scannedStore.name : "Tap to go to Sales"}
                      </p>
                    </div>
                  </span>
                  <ArrowRight className="h-4 w-4 opacity-60" />
                </button>

                <button
                  onClick={() => handleAction("transaction")}
                  className="w-full flex items-center justify-between rounded-xl border bg-card px-4 py-3.5 shadow-sm hover:bg-accent active:scale-[0.98] transition-all"
                >
                  <span className="flex items-center gap-3">
                    <div className="flex h-8 w-8 items-center justify-center rounded-lg bg-muted">
                      <Banknote className="h-4 w-4 text-foreground/70" />
                    </div>
                    <div className="text-left">
                      <p className="font-semibold text-sm">Record Payment</p>
                      <p className="text-[11px] text-muted-foreground">
                        {scannedStore ? scannedStore.name : "Tap to go to Transactions"}
                      </p>
                    </div>
                  </span>
                  <ArrowRight className="h-4 w-4 opacity-30" />
                </button>

                <button
                  onClick={() => handleAction("visit")}
                  className="w-full flex items-center justify-between rounded-xl border bg-card px-4 py-3.5 shadow-sm hover:bg-accent active:scale-[0.98] transition-all"
                >
                  <span className="flex items-center gap-3">
                    <div className="flex h-8 w-8 items-center justify-center rounded-lg bg-muted">
                      <CheckCircle className="h-4 w-4 text-foreground/70" />
                    </div>
                    <div className="text-left">
                      <p className="font-semibold text-sm">Mark Visited</p>
                      <p className="text-[11px] text-muted-foreground">
                        {scannedStore ? scannedStore.name : "Requires active route session"}
                      </p>
                    </div>
                  </span>
                  <ArrowRight className="h-4 w-4 opacity-30" />
                </button>
              </div>

              {/* Divider */}
              <div className="flex items-center gap-2 pt-1">
                <div className="flex-1 h-px bg-border" />
                <span className="text-[10px] font-semibold text-muted-foreground uppercase tracking-widest">Nearby</span>
                <div className="flex-1 h-px bg-border" />
              </div>

              {/* ── Nearby stores ── */}
              <div className="space-y-2">
                <div className="flex items-center justify-between">
                  <p className="text-xs text-muted-foreground">Stores within 100m of your location</p>
                  <Button
                    variant="outline"
                    size="sm"
                    onClick={findNearbyStores}
                    disabled={loadingNearby}
                    className="h-7 gap-1.5 text-xs"
                  >
                    {loadingNearby
                      ? <Loader2 className="h-3 w-3 animate-spin" />
                      : <Navigation className="h-3 w-3" />}
                    Find
                  </Button>
                </div>

                {showNearby && (
                  <div className="space-y-1.5">
                    {nearbyStores.length === 0 ? (
                      <p className="text-sm text-muted-foreground text-center py-3 rounded-lg bg-muted/30">
                        No stores found within 100m
                      </p>
                    ) : (
                      nearbyStores.map((store) => (
                        <button
                          key={store.id}
                          onClick={() => {
                            setScannedStore({ id: store.id, name: store.name, display_id: store.display_id, address: null, photo_url: null, store_type: null });
                            toast.success(`Store selected: ${store.name}`);
                          }}
                          className="w-full flex items-center justify-between rounded-lg border bg-card px-3 py-2.5 text-left hover:bg-accent transition-colors"
                        >
                          <div>
                            <p className="font-medium text-sm">{store.name}</p>
                            <p className="text-xs text-muted-foreground">{store.display_id}</p>
                          </div>
                          <Badge variant="secondary" className="text-xs font-semibold">{store.distance}m</Badge>
                        </button>
                      ))
                    )}
                  </div>
                )}
              </div>
            </div>
          </div>
        </DrawerContent>
      </Drawer>

      {/* QR Not Found Dialog */}
      <Dialog open={notFoundDialog} onOpenChange={(v) => { if (!v) { setNotFoundDialog(false); setLinkMode(false); } }}>
        <DialogContent className="max-w-sm">
          <DialogHeader>
            <DialogTitle>QR Code Not Linked</DialogTitle>
          </DialogHeader>
          {!linkMode ? (
            <div className="space-y-4">
              <div className="rounded-lg border bg-muted/40 p-3 text-sm space-y-1.5">
                <p><span className="text-muted-foreground text-xs uppercase tracking-wide">UPI ID</span></p>
                <p className="font-mono text-sm">{scannedUpi.upiId}</p>
                {scannedUpi.payeeName && (
                  <>
                    <p className="text-muted-foreground text-xs uppercase tracking-wide pt-1">Payee Name</p>
                    <p className="text-sm">{scannedUpi.payeeName}</p>
                  </>
                )}
              </div>
              <p className="text-sm text-muted-foreground">This QR is not linked to any store. What would you like to do?</p>
              <div className="flex flex-col gap-2">
                {isAdmin ? (
                  <>
                    <Button onClick={handleCreateStore} className="gap-2 w-full">
                      <Store className="h-4 w-4" /> Create New Store
                    </Button>
                    <Button variant="outline" onClick={handleLinkStore} className="gap-2 w-full">
                      <MapPin className="h-4 w-4" /> Link to Existing Store
                    </Button>
                  </>
                ) : (
                  <div className="rounded-lg border bg-muted/40 p-3 text-sm text-muted-foreground text-center">
                    This QR is not linked to any store yet. Ask your manager to set it up, then try scanning again.
                  </div>
                )}
              </div>
            </div>
          ) : (
            <div className="space-y-4">
              <div>
                <Label>Select Store to Link</Label>
                <Select value={linkStoreId} onValueChange={setLinkStoreId}>
                  <SelectTrigger className="mt-1.5"><SelectValue placeholder="Choose a store…" /></SelectTrigger>
                  <SelectContent>
                    {allStores.map((s) => (
                      <SelectItem key={s.id} value={s.id}>{s.name} ({s.display_id})</SelectItem>
                    ))}
                  </SelectContent>
                </Select>
              </div>
              <div className="flex gap-2">
                <Button variant="outline" className="flex-1" onClick={() => setLinkMode(false)}>Back</Button>
                <Button className="flex-1" disabled={!linkStoreId || saving} onClick={confirmLink}>
                  {saving ? <Loader2 className="h-4 w-4 animate-spin" /> : "Link QR"}
                </Button>
              </div>
            </div>
          )}
        </DialogContent>
      </Dialog>
    </>
  );
}

import { useQuery } from "@tanstack/react-query";
import { supabase } from "@/integrations/supabase/client";
import {
  Carousel,
  CarouselContent,
  CarouselItem,
} from "@/components/ui/carousel";

interface BannerCarouselProps {
  storeTypeIds?: string[];
}

export function BannerCarousel({ storeTypeIds }: BannerCarouselProps) {
  const { data: banners } = useQuery({
    queryKey: ["banners-carousel", storeTypeIds],
    queryFn: async () => {
      const now = new Date().toISOString();
      let q = supabase
        .from("promotional_banners")
        .select("*")
        .eq("is_active", true)
        .order("sort_order");

      const { data } = await q;

      // Load banner_store_types associations
      const bannerIds = (data || []).map((b: any) => b.id);
      let associations: any[] = [];
      if (bannerIds.length > 0) {
        const { data: assocData } = await supabase
          .from("banner_store_types" as any)
          .select("banner_id, store_type_id")
          .in("banner_id", bannerIds);
        associations = assocData || [];
      }

      // Client-side filter for store type targeting and date range
      return (data || []).filter((b: any) => {
        if (b.starts_at && b.starts_at > now) return false;
        if (b.ends_at && b.ends_at < now) return false;

        // Check multi-store type associations first
        const bannerStoreTypeIds = associations
          .filter((a: any) => a.banner_id === b.id)
          .map((a: any) => a.store_type_id);

        if (bannerStoreTypeIds.length > 0) {
          // Banner targets specific store types
          if (!storeTypeIds || storeTypeIds.length === 0) return true;
          return bannerStoreTypeIds.some((stId: string) => storeTypeIds.includes(stId));
        }

        // Fallback to legacy single store_type_id
        if (!b.store_type_id) return true; // null = all types
        if (storeTypeIds && storeTypeIds.includes(b.store_type_id)) return true;
        if (!storeTypeIds || storeTypeIds.length === 0) return true;
        return false;
      });
    },
  });

  if (!banners || banners.length === 0) return null;

  return (
    <Carousel opts={{ loop: true }} className="w-full">
      <CarouselContent>
        {banners.map((b: any) => (
          <CarouselItem key={b.id}>
            <a
              href={b.link_url || undefined}
              target={b.link_url ? "_blank" : undefined}
              rel="noopener noreferrer"
              className="block"
            >
              <div className="relative rounded-xl overflow-hidden" style={{ aspectRatio: "3" }}>
                <img
                  src={b.image_url}
                  alt={b.title}
                  className="absolute inset-0 w-full h-full"
                  style={{
                    objectFit: "cover",
                    transform: b.crop_data
                      ? `translate(${b.crop_data.offsetX}px, ${b.crop_data.offsetY}px) scale(${b.crop_data.scale})`
                      : undefined,
                    transformOrigin: "center center",
                  }}
                />
                <div className="absolute inset-0 bg-gradient-to-t from-black/60 to-transparent" />
                <div className="absolute bottom-0 left-0 right-0 p-4">
                  <h3 className="text-sm sm:text-base font-semibold text-white">{b.title}</h3>
                  {b.description && (
                    <p className="text-xs text-white/80 mt-0.5 line-clamp-1">{b.description}</p>
                  )}
                </div>
              </div>
            </a>
          </CarouselItem>
        ))}
      </CarouselContent>
    </Carousel>
  );
}

import { useState, useRef, useCallback, useEffect } from "react";
import { Button } from "@/components/ui/button";
import { Slider } from "@/components/ui/slider";
import { ZoomIn, ZoomOut, Move, RotateCcw } from "lucide-react";

interface CropState {
  scale: number;
  offsetX: number;
  offsetY: number;
}

interface BannerImageEditorProps {
  imageUrl: string;
  cropData?: CropState | null;
  onCropChange: (crop: CropState) => void;
  /** Display window aspect ratio width/height — default 3 (600x200) */
  aspectRatio?: number;
}

export function BannerImageEditor({
  imageUrl,
  cropData,
  onCropChange,
  aspectRatio = 3,
}: BannerImageEditorProps) {
  const containerRef = useRef<HTMLDivElement>(null);
  const imgRef = useRef<HTMLImageElement>(null);

  const [scale, setScale] = useState(cropData?.scale ?? 1);
  const [offsetX, setOffsetX] = useState(cropData?.offsetX ?? 0);
  const [offsetY, setOffsetY] = useState(cropData?.offsetY ?? 0);
  const [isDragging, setIsDragging] = useState(false);
  const [dragStart, setDragStart] = useState({ x: 0, y: 0 });

  // Reset when image changes
  useEffect(() => {
    if (cropData) {
      setScale(cropData.scale);
      setOffsetX(cropData.offsetX);
      setOffsetY(cropData.offsetY);
    } else {
      setScale(1);
      setOffsetX(0);
      setOffsetY(0);
    }
  }, [imageUrl]);

  const emitChange = useCallback(
    (s: number, x: number, y: number) => {
      onCropChange({ scale: s, offsetX: x, offsetY: y });
    },
    [onCropChange]
  );

  const handleReset = () => {
    setScale(1);
    setOffsetX(0);
    setOffsetY(0);
    emitChange(1, 0, 0);
  };

  const handleScaleChange = (val: number[]) => {
    const newScale = val[0];
    setScale(newScale);
    emitChange(newScale, offsetX, offsetY);
  };

  const handleZoomIn = () => {
    const newScale = Math.min(scale + 0.1, 5);
    setScale(newScale);
    emitChange(newScale, offsetX, offsetY);
  };

  const handleZoomOut = () => {
    const newScale = Math.max(scale - 0.1, 0.1);
    setScale(newScale);
    emitChange(newScale, offsetX, offsetY);
  };

  const handleMouseDown = useCallback(
    (e: React.MouseEvent) => {
      e.preventDefault();
      setIsDragging(true);
      setDragStart({ x: e.clientX - offsetX, y: e.clientY - offsetY });
    },
    [offsetX, offsetY]
  );

  const handleMouseMove = useCallback(
    (e: React.MouseEvent) => {
      if (!isDragging) return;
      const newX = e.clientX - dragStart.x;
      const newY = e.clientY - dragStart.y;
      setOffsetX(newX);
      setOffsetY(newY);
    },
    [isDragging, dragStart]
  );

  const handleMouseUp = useCallback(() => {
    if (isDragging) {
      setIsDragging(false);
      emitChange(scale, offsetX, offsetY);
    }
  }, [isDragging, scale, offsetX, offsetY, emitChange]);

  // Touch support
  const handleTouchStart = useCallback(
    (e: React.TouchEvent) => {
      if (e.touches.length === 1) {
        const touch = e.touches[0];
        setIsDragging(true);
        setDragStart({ x: touch.clientX - offsetX, y: touch.clientY - offsetY });
      }
    },
    [offsetX, offsetY]
  );

  const handleTouchMove = useCallback(
    (e: React.TouchEvent) => {
      if (!isDragging || e.touches.length !== 1) return;
      const touch = e.touches[0];
      const newX = touch.clientX - dragStart.x;
      const newY = touch.clientY - dragStart.y;
      setOffsetX(newX);
      setOffsetY(newY);
    },
    [isDragging, dragStart]
  );

  const handleTouchEnd = useCallback(() => {
    if (isDragging) {
      setIsDragging(false);
      emitChange(scale, offsetX, offsetY);
    }
  }, [isDragging, scale, offsetX, offsetY, emitChange]);

  // Mouse wheel zoom
  const handleWheel = useCallback(
    (e: React.WheelEvent) => {
      e.preventDefault();
      const delta = e.deltaY > 0 ? -0.1 : 0.1;
      const newScale = Math.min(Math.max(scale + delta, 0.1), 5);
      setScale(newScale);
      emitChange(newScale, offsetX, offsetY);
    },
    [scale, offsetX, offsetY, emitChange]
  );

  if (!imageUrl) return null;

  return (
    <div className="space-y-3">
      {/* Display Window Preview */}
      <div className="relative">
        <div className="absolute top-2 left-2 z-10 bg-black/60 text-white text-[10px] px-2 py-0.5 rounded">
          Display Preview ({aspectRatio === 3 ? "3:1" : `${aspectRatio}:1`})
        </div>
        <div
          ref={containerRef}
          className="relative rounded-xl overflow-hidden border-2 border-primary/20 bg-muted/30 select-none shadow-inner"
          style={{
            aspectRatio: `${aspectRatio}`,
            maxHeight: "300px",
            cursor: isDragging ? "grabbing" : "grab",
          }}
          onMouseDown={handleMouseDown}
          onMouseMove={handleMouseMove}
          onMouseUp={handleMouseUp}
          onMouseLeave={handleMouseUp}
          onTouchStart={handleTouchStart}
          onTouchMove={handleTouchMove}
          onTouchEnd={handleTouchEnd}
          onWheel={handleWheel}
        >
          <img
            ref={imgRef}
            src={imageUrl}
            alt="Banner preview"
            draggable={false}
            className="absolute select-none pointer-events-none"
            style={{
              transform: `translate(${offsetX}px, ${offsetY}px) scale(${scale})`,
              transformOrigin: "center center",
              width: "100%",
              height: "100%",
              objectFit: "contain",
              transition: isDragging ? "none" : "transform 0.1s ease-out",
            }}
          />
        </div>
      </div>

      {/* Zoom Controls */}
      <div className="flex items-center gap-3">
        <Button
          type="button"
          variant="outline"
          size="icon"
          className="h-8 w-8 shrink-0"
          onClick={handleZoomOut}
        >
          <ZoomOut className="h-4 w-4" />
        </Button>
        <Slider
          value={[scale]}
          min={0.1}
          max={5}
          step={0.05}
          onValueChange={handleScaleChange}
          className="flex-1"
        />
        <Button
          type="button"
          variant="outline"
          size="icon"
          className="h-8 w-8 shrink-0"
          onClick={handleZoomIn}
        >
          <ZoomIn className="h-4 w-4" />
        </Button>
        <span className="text-xs text-muted-foreground w-12 text-center">
          {Math.round(scale * 100)}%
        </span>
        <Button
          type="button"
          variant="ghost"
          size="sm"
          className="gap-1 text-xs"
          onClick={handleReset}
        >
          <RotateCcw className="h-3 w-3" />
          Reset
        </Button>
      </div>

      {/* Instructions */}
      <p className="text-xs text-muted-foreground flex items-center gap-1">
        <Move className="h-3 w-3" />
        Drag to pan, scroll to zoom. This is how the banner will appear to customers.
      </p>
    </div>
  );
}

import { useState } from "react";
import { useQuery, useQueryClient } from "@tanstack/react-query";
import { supabase } from "@/integrations/supabase/client";
import { useAuth } from "@/contexts/AuthContext";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Switch } from "@/components/ui/switch";
import { Badge } from "@/components/ui/badge";
import { Checkbox } from "@/components/ui/checkbox";
import { ImageUpload } from "@/components/shared/ImageUpload";
import { BannerImageEditor } from "@/components/banners/BannerImageEditor";
import {
  Dialog, DialogContent, DialogHeader, DialogTitle,
} from "@/components/ui/dialog";
import { Loader2, Plus, Pencil, Trash2, Image } from "lucide-react";
import { toast } from "sonner";

interface CropState {
  scale: number;
  offsetX: number;
  offsetY: number;
}

export function BannerManagement() {
  const { user } = useAuth();
  const qc = useQueryClient();
  const [showForm, setShowForm] = useState(false);
  const [editId, setEditId] = useState<string | null>(null);
  const [saving, setSaving] = useState(false);

  // Form
  const [title, setTitle] = useState("");
  const [description, setDescription] = useState("");
  const [imageUrl, setImageUrl] = useState("");
  const [linkUrl, setLinkUrl] = useState("");
  const [selectedStoreTypeIds, setSelectedStoreTypeIds] = useState<string[]>([]);
  const [isActive, setIsActive] = useState(true);
  const [sortOrder, setSortOrder] = useState("0");
  const [cropData, setCropData] = useState<CropState | null>(null);

  const { data: banners, isLoading } = useQuery({
    queryKey: ["banners-admin"],
    queryFn: async () => {
      const { data } = await supabase
        .from("promotional_banners")
        .select("*, store_types(name)")
        .order("sort_order");

      if (data) {
        const bannerIds = data.map((b: any) => b.id);
        const { data: associations } = await supabase
          .from("banner_store_types" as any)
          .select("banner_id, store_type_id")
          .in("banner_id", bannerIds);

        return data.map((b: any) => ({
          ...b,
          _storeTypeIds: (associations || [])
            .filter((a: any) => a.banner_id === b.id)
            .map((a: any) => a.store_type_id),
        }));
      }
      return data || [];
    },
  });

  const { data: storeTypes } = useQuery({
    queryKey: ["store-types-banners"],
    queryFn: async () => {
      const { data } = await supabase.from("store_types").select("id, name").eq("is_active", true);
      return data || [];
    },
  });

  const resetForm = () => {
    setEditId(null);
    setTitle(""); setDescription(""); setImageUrl(""); setLinkUrl("");
    setSelectedStoreTypeIds([]); setIsActive(true); setSortOrder("0");
    setCropData(null);
  };

  const openEdit = async (b: any) => {
    setEditId(b.id);
    setTitle(b.title);
    setDescription(b.description || "");
    setImageUrl(b.image_url);
    setLinkUrl(b.link_url || "");
    setIsActive(b.is_active);
    setSortOrder(String(b.sort_order));
    setCropData(b.crop_data || null);

    // Load store type associations
    const ids: string[] = b._storeTypeIds || [];
    if (ids.length > 0) {
      setSelectedStoreTypeIds(ids);
    } else if (b.store_type_id) {
      setSelectedStoreTypeIds([b.store_type_id]);
    } else {
      setSelectedStoreTypeIds([]);
    }

    setShowForm(true);
  };

  const toggleStoreType = (storeTypeId: string) => {
    setSelectedStoreTypeIds((prev) =>
      prev.includes(storeTypeId)
        ? prev.filter((id) => id !== storeTypeId)
        : [...prev, storeTypeId]
    );
  };

  const handleSave = async () => {
    if (!title.trim() || !imageUrl.trim()) {
      toast.error("Title and image are required");
      return;
    }
    setSaving(true);
    const payload = {
      title,
      description: description || null,
      image_url: imageUrl,
      link_url: linkUrl || null,
      store_type_id: selectedStoreTypeIds.length === 1 ? selectedStoreTypeIds[0] : null,
      is_active: isActive,
      sort_order: Number(sortOrder) || 0,
      created_by: user!.id,
      crop_data: cropData,
    };

    let bannerId: string;

    if (editId) {
      const { error } = await supabase.from("promotional_banners").update(payload).eq("id", editId);
      if (error) { toast.error(error.message); setSaving(false); return; }
      bannerId = editId;
      toast.success("Banner updated");
    } else {
      const { data: inserted, error } = await supabase.from("promotional_banners").insert(payload).select("id").single();
      if (error) { toast.error(error.message); setSaving(false); return; }
      bannerId = inserted.id;
      toast.success("Banner created");
    }

    // Sync banner_store_types
    await supabase.from("banner_store_types" as any).delete().eq("banner_id", bannerId);
    if (selectedStoreTypeIds.length > 0) {
      const rows = selectedStoreTypeIds.map((stId) => ({
        banner_id: bannerId,
        store_type_id: stId,
      }));
      await supabase.from("banner_store_types" as any).insert(rows);
    }

    setSaving(false);
    setShowForm(false);
    resetForm();
    qc.invalidateQueries({ queryKey: ["banners-admin"] });
  };

  const handleDelete = async (id: string) => {
    const { error } = await supabase.from("promotional_banners").delete().eq("id", id);
    if (error) toast.error(error.message);
    else { toast.success("Banner deleted"); qc.invalidateQueries({ queryKey: ["banners-admin"] }); }
  };

  if (isLoading) return <div className="flex justify-center py-8"><Loader2 className="h-6 w-6 animate-spin text-primary" /></div>;

  return (
    <div className="space-y-4">
      <div className="flex items-center justify-between">
        <h3 className="text-sm font-semibold">Promotional Banners</h3>
        <Button size="sm" onClick={() => { resetForm(); setShowForm(true); }}>
          <Plus className="mr-1 h-3.5 w-3.5" /> Add Banner
        </Button>
      </div>

      {banners?.length === 0 ? (
        <div className="rounded-xl border bg-card p-8 text-center text-muted-foreground">
          <Image className="h-8 w-8 mx-auto mb-2 opacity-40" />
          <p className="text-sm">No banners yet. Create one to display on customer dashboards.</p>
        </div>
      ) : (
        <div className="space-y-3">
          {banners?.map((b: any) => (
            <div key={b.id} className="rounded-xl border bg-card p-3 flex items-center gap-3">
              <div
                className="h-16 w-28 rounded-lg overflow-hidden shrink-0 relative bg-muted"
                style={{ aspectRatio: "3" }}
              >
                <img
                  src={b.image_url}
                  alt={b.title}
                  loading="lazy"
                  className="absolute inset-0 w-full h-full"
                  style={{
                    objectFit: "cover",
                    transform: b.crop_data
                      ? `translate(${b.crop_data.offsetX * 0.5}px, ${b.crop_data.offsetY * 0.5}px) scale(${b.crop_data.scale})`
                      : undefined,
                    transformOrigin: "center center",
                  }}
                />
              </div>
              <div className="flex-1 min-w-0">
                <div className="flex items-center gap-2">
                  <p className="text-sm font-medium truncate">{b.title}</p>
                  {!b.is_active && <Badge variant="secondary" className="text-[10px]">Inactive</Badge>}
                </div>
                {b.description && <p className="text-xs text-muted-foreground truncate">{b.description}</p>}
                <div className="flex items-center gap-1 mt-1 flex-wrap">
                  {(b._storeTypeIds || []).length === 0 ? (
                    <Badge variant="outline" className="text-[10px]">All Types</Badge>
                  ) : (
                    (b._storeTypeIds || []).map((id: string) => (
                      <Badge key={id} variant="secondary" className="text-[10px]">
                        {storeTypes?.find((t: any) => t.id === id)?.name || "Unknown"}
                      </Badge>
                    ))
                  )}
                  <span className="text-[10px] text-muted-foreground ml-1">Order: {b.sort_order}</span>
                </div>
              </div>
              <div className="flex gap-2 shrink-0">
                <Button variant="ghost" size="icon" className="h-8 w-8 hover:bg-primary/10 hover:text-primary transition-colors" onClick={() => openEdit(b)}>
                  <Pencil className="h-3.5 w-3.5" />
                </Button>
                <Button variant="ghost" size="icon" className="h-8 w-8 text-destructive hover:bg-destructive/10 transition-colors" onClick={() => handleDelete(b.id)}>
                  <Trash2 className="h-3.5 w-3.5" />
                </Button>
              </div>
            </div>
          ))}
        </div>
      )}

      <Dialog open={showForm} onOpenChange={(v) => { setShowForm(v); if (!v) resetForm(); }}>
        <DialogContent className="sm:max-w-[600px] max-h-[90vh] overflow-y-auto">
          <DialogHeader><DialogTitle>{editId ? "Edit Banner" : "Create Banner"}</DialogTitle></DialogHeader>
          <div className="space-y-4">
            <div><Label>Title *</Label><Input value={title} onChange={(e) => setTitle(e.target.value)} className="mt-1" /></div>
            <div><Label>Description</Label><Input value={description} onChange={(e) => setDescription(e.target.value)} className="mt-1" /></div>
            <div>
              <Label>Banner Image *</Label>
              <div className="mt-1">
                <ImageUpload folder="banners" currentUrl={imageUrl || null} onUploaded={setImageUrl} onRemoved={() => { setImageUrl(""); setCropData(null); }} size="lg" />
              </div>
            </div>

            {/* Image Editor */}
            {imageUrl && (
              <div>
                <Label>Adjust Display — Zoom & Pan</Label>
                <div className="mt-1">
                  <BannerImageEditor
                    imageUrl={imageUrl}
                    cropData={cropData}
                    onCropChange={setCropData}
                    aspectRatio={3}
                  />
                </div>
              </div>
            )}

            <div><Label>Link URL</Label><Input value={linkUrl} onChange={(e) => setLinkUrl(e.target.value)} className="mt-1" placeholder="https://..." /></div>

            {/* Multi-Store Type Selection */}
            <div>
              <Label>Target Store Types</Label>
              <p className="text-xs text-muted-foreground mb-2">
                Select store types. Leave all unchecked for all customers.
              </p>
              <div className="flex flex-wrap gap-2 mt-2">
                {storeTypes?.map((t: any) => {
                  const isSelected = selectedStoreTypeIds.includes(t.id);
                  return (
                    <Badge
                      key={t.id}
                      variant={isSelected ? "default" : "outline"}
                      className={`cursor-pointer py-1.5 px-3 text-xs transition-all ${
                        isSelected 
                          ? "bg-primary text-primary-foreground shadow-sm scale-105" 
                          : "hover:bg-accent border-muted-foreground/20"
                      }`}
                      onClick={() => toggleStoreType(t.id)}
                    >
                      {t.name}
                    </Badge>
                  );
                })}
              </div>
            </div>

            <div className="grid grid-cols-2 gap-3">
              <div>
                <Label>Sort Order</Label>
                <Input type="number" value={sortOrder} onChange={(e) => setSortOrder(e.target.value)} className="mt-1" />
              </div>
              <div className="flex items-center gap-2 pt-6">
                <Switch checked={isActive} onCheckedChange={setIsActive} />
                <Label>Active</Label>
              </div>
            </div>
            <Button className="w-full" onClick={handleSave} disabled={saving}>
              {saving && <Loader2 className="mr-2 h-4 w-4 animate-spin" />}
              {editId ? "Update Banner" : "Create Banner"}
            </Button>
          </div>
        </DialogContent>
      </Dialog>
    </div>
  );
}

import { useState } from "react";
import { supabase } from "@/integrations/supabase/client";
import { useAuth } from "@/contexts/AuthContext";
import { logActivity } from "@/lib/activityLogger";
import {
  Dialog, DialogContent, DialogHeader, DialogTitle,
} from "@/components/ui/dialog";
import { Button } from "@/components/ui/button";
import { Textarea } from "@/components/ui/textarea";
import { Label } from "@/components/ui/label";
import { Badge } from "@/components/ui/badge";
import { Loader2, CheckCircle2, XCircle, ExternalLink } from "lucide-react";
import { toast } from "sonner";

interface KycReviewDialogProps {
  customer: any;
  open: boolean;
  onOpenChange: (open: boolean) => void;
  onDone: () => void;
}

export function KycReviewDialog({ customer, open, onOpenChange, onDone }: KycReviewDialogProps) {
  const { user } = useAuth();
  const [rejectionReason, setRejectionReason] = useState("");
  const [saving, setSaving] = useState(false);

  if (!customer) return null;

  const getPublicUrl = (path: string | null) => {
    if (!path) return null;
    const { data } = supabase.storage.from("kyc-documents").getPublicUrl(path);
    return data.publicUrl;
  };

  const handleApprove = async () => {
    setSaving(true);
    const { error } = await supabase.from("customers").update({
      kyc_status: "verified",
      kyc_verified_at: new Date().toISOString(),
      kyc_verified_by: user!.id,
      kyc_rejection_reason: null,
    }).eq("id", customer.id);
    setSaving(false);
    if (error) toast.error(error.message);
    else {
      toast.success("KYC approved");
      logActivity(user!.id, "Approved KYC", "customer", customer.name, customer.id);
      onDone();
    }
  };

  const handleReject = async () => {
    if (!rejectionReason.trim()) { toast.error("Please provide a rejection reason"); return; }
    setSaving(true);
    const { error } = await supabase.from("customers").update({
      kyc_status: "rejected",
      kyc_rejection_reason: rejectionReason,
      kyc_verified_by: user!.id,
    }).eq("id", customer.id);
    setSaving(false);
    if (error) toast.error(error.message);
    else {
      toast.success("KYC rejected");
      logActivity(user!.id, "Rejected KYC", "customer", customer.name, customer.id);
      onDone();
    }
  };

  const docs = [
    { label: "Selfie", url: customer.kyc_selfie_url },
    { label: "Aadhar Front", url: customer.kyc_aadhar_front_url },
    { label: "Aadhar Back", url: customer.kyc_aadhar_back_url },
  ];

  return (
    <Dialog open={open} onOpenChange={onOpenChange}>
      <DialogContent className="max-w-lg">
        <DialogHeader>
          <DialogTitle>KYC Review — {customer.name}</DialogTitle>
        </DialogHeader>
        <div className="space-y-4">
          <div className="flex items-center gap-2">
            <span className="text-sm text-muted-foreground">Current Status:</span>
            <Badge variant={customer.kyc_status === "verified" ? "default" : customer.kyc_status === "pending" ? "secondary" : "destructive"}>
              {customer.kyc_status.replace("_", " ")}
            </Badge>
          </div>

          <div className="space-y-2">
            <Label>Uploaded Documents</Label>
            <div className="grid grid-cols-3 gap-3">
              {docs.map((doc) => (
                <div key={doc.label} className="rounded-lg border bg-muted/30 p-3 text-center space-y-2">
                  <p className="text-xs font-medium">{doc.label}</p>
                  {doc.url ? (
                    <a href={getPublicUrl(doc.url) || "#"} target="_blank" rel="noopener noreferrer" className="inline-flex items-center gap-1 text-xs text-primary hover:underline">
                      View <ExternalLink className="h-3 w-3" />
                    </a>
                  ) : (
                    <p className="text-xs text-muted-foreground">Not uploaded</p>
                  )}
                </div>
              ))}
            </div>
          </div>

          {customer.kyc_status === "pending" && (
            <>
              <div>
                <Label>Rejection Reason (if rejecting)</Label>
                <Textarea value={rejectionReason} onChange={(e) => setRejectionReason(e.target.value)} className="mt-1" placeholder="Blurry photo, name mismatch..." />
              </div>
              <div className="flex gap-3">
                <Button onClick={handleApprove} disabled={saving} className="flex-1">
                  {saving ? <Loader2 className="mr-2 h-4 w-4 animate-spin" /> : <CheckCircle2 className="mr-2 h-4 w-4" />}
                  Approve
                </Button>
                <Button onClick={handleReject} disabled={saving} variant="destructive" className="flex-1">
                  {saving ? <Loader2 className="mr-2 h-4 w-4 animate-spin" /> : <XCircle className="mr-2 h-4 w-4" />}
                  Reject
                </Button>
              </div>
            </>
          )}
        </div>
      </DialogContent>
    </Dialog>
  );
}

