interface OrderItem {
  id: string;
  product_id: string;
  quantity: number;
  unit_price: number | null;
  products?: {
    id: string;
    name: string;
    sku: string;
    base_price: number;
    image_url?: string;
  };
}

interface Order {
  id: string;
  display_id: string;
  store_id: string;
  customer_id: string | null;
  order_type: "simple" | "detailed";
  status: string;
  requirement_note: string | null;
  order_items?: OrderItem[];
  stores?: {
    id: string;
    name: string;
    store_type_id: string | null;
    customer_id: string | null;
  };
}

interface FulfillmentItem {
  product_id: string;
  product_name: string;
  sku: string;
  image_url?: string;
  quantity: number;
  unit_price: number;
  base_price: number;
  total: number;
}

interface Product {
  id: string;
  name: string;
  sku: string;
  base_price: number;
  image_url?: string;
}

interface OrderFulfillmentDialogProps {
  order: Order | null;
  open: boolean;
  onOpenChange: (open: boolean) => void;
  onFulfilled?: () => void;
}

export function OrderFulfillmentDialog({
  order,
  open,
  onOpenChange,
  onFulfilled,
}: OrderFulfillmentDialogProps) {
  const { toast } = useToast();
  const queryClient = useQueryClient();

  // State
  const [items, setItems] = useState<FulfillmentItem[]>([]);
  const [products, setProducts] = useState<Product[]>([]);
  const [storePricing, setStorePricing] = useState<Map<string, number>>(new Map());
  const [storeTypePricing, setStoreTypePricing] = useState<Map<string, number>>(new Map());
  const [cashAmount, setCashAmount] = useState<string>("0");
  const [upiAmount, setUpiAmount] = useState<string>("0");
  const [notes, setNotes] = useState<string>("");
  const [selectedProduct, setSelectedProduct] = useState<string>("");
  const [loading, setLoading] = useState(false);
  const [submitting, setSubmitting] = useState(false);
  const [oldOutstanding, setOldOutstanding] = useState<number>(0);

  // Calculate totals
  const { subtotal, totalPaid, outstandingAmount, newOutstanding } = useMemo(() => {
    const subtotal = items.reduce((sum, item) => sum + item.total, 0);
    const cash = parseFloat(cashAmount) || 0;
    const upi = parseFloat(upiAmount) || 0;
    const totalPaid = cash + upi;
    const outstandingAmount = Math.max(0, subtotal - totalPaid);
    const newOutstanding = oldOutstanding + outstandingAmount;
    return { subtotal, totalPaid, outstandingAmount, newOutstanding };
  }, [items, cashAmount, upiAmount, oldOutstanding]);

  // Get price for a product using hierarchy
  const getProductPrice = (productId: string, basePrice: number): number => {
    // Store-specific price takes precedence
    if (storePricing.has(productId)) {
      return storePricing.get(productId)!;
    }
    // Store type pricing is second
    if (storeTypePricing.has(productId)) {
      return storeTypePricing.get(productId)!;
    }
    // Fall back to base price
    return basePrice;
  };

  // Load data when order changes
  useEffect(() => {
    if (!order || !open) return;

    const loadData = async () => {
      setLoading(true);
      try {
        // Load products
        const { data: productsData, error: productsError } = await supabase
          .from("products")
          .select("id, name, sku, base_price, image_url")
          .eq("is_active", true)
          .order("name");

        if (productsError) throw productsError;
        setProducts(productsData || []);

        // Load store-specific pricing
        if (order.store_id) {
          const { data: storePrices, error: storePricesError } = await supabase
            .from("store_pricing")
            .select("product_id, custom_price")
            .eq("store_id", order.store_id);

          if (!storePricesError && storePrices) {
            const priceMap = new Map<string, number>();
            storePrices.forEach((sp) => priceMap.set(sp.product_id, sp.custom_price));
            setStorePricing(priceMap);
          }

          // Load store type pricing
          if (order.stores?.store_type_id) {
            const { data: typePrices, error: typePricesError } = await supabase
              .from("store_type_pricing")
              .select("product_id, price")
              .eq("store_type_id", order.stores.store_type_id);

            if (!typePricesError && typePrices) {
              const priceMap = new Map<string, number>();
              typePrices.forEach((tp) => priceMap.set(tp.product_id, tp.price));
              setStoreTypePricing(priceMap);
            }
          }
        }

        // Load customer outstanding balance
        if (order.stores?.customer_id) {
          const { data: balanceData, error: balanceError } = await supabase
            .from("customer_balances")
            .select("outstanding_balance")
            .eq("customer_id", order.stores.customer_id)
            .maybeSingle();

          if (!balanceError && balanceData) {
            setOldOutstanding(balanceData.outstanding_balance || 0);
          }
        }

        // Pre-fill items from order if detailed
        if (order.order_type === "detailed" && order.order_items?.length) {
          const productMap = new Map(productsData?.map((p) => [p.id, p]) || []);
          const initialItems: FulfillmentItem[] = [];

          for (const item of order.order_items) {
            const product = productMap.get(item.product_id) || item.products;
            if (!product) continue;

            const basePrice = product.base_price;
            const unitPrice = item.unit_price ?? getProductPrice(item.product_id, basePrice);

            initialItems.push({
              product_id: item.product_id,
              product_name: product.name,
              sku: product.sku,
              image_url: product.image_url,
              quantity: item.quantity,
              unit_price: unitPrice,
              base_price: basePrice,
              total: unitPrice * item.quantity,
            });
          }

          setItems(initialItems);
        } else {
          setItems([]);
        }

        setNotes(order.requirement_note || "");
        setCashAmount("0");
        setUpiAmount("0");
      } catch (error) {
        console.error("Error loading fulfillment data:", error);
        toast({
          title: "Error loading data",
          description: "Failed to load order details. Please try again.",
          variant: "destructive",
        });
      } finally {
        setLoading(false);
      }
    };

    loadData();
  }, [order, open]);

  // Add product to items
  const handleAddProduct = () => {
    if (!selectedProduct) return;

    const product = products.find((p) => p.id === selectedProduct);
    if (!product) return;

    // Check if already in items
    if (items.some((item) => item.product_id === selectedProduct)) {
      toast({
        title: "Product already added",
        description: "Increase quantity instead of adding again.",
        variant: "destructive",
      });
      return;
    }

    const unitPrice = getProductPrice(product.id, product.base_price);

    setItems([
      ...items,
      {
        product_id: product.id,
        product_name: product.name,
        sku: product.sku,
        image_url: product.image_url,
        quantity: 1,
        unit_price: unitPrice,
        base_price: product.base_price,
        total: unitPrice,
      },
    ]);
    setSelectedProduct("");
  };

  // Update item quantity
  const handleQuantityChange = (productId: string, delta: number) => {
    setItems(
      items
        .map((item) => {
          if (item.product_id !== productId) return item;
          const newQty = Math.max(0, item.quantity + delta);
          if (newQty === 0) return null;
          return {
            ...item,
            quantity: newQty,
            total: newQty * item.unit_price,
          };
        })
        .filter(Boolean) as FulfillmentItem[]
    );
  };

  // Update item price
  const handlePriceChange = (productId: string, price: string) => {
    const numPrice = parseFloat(price) || 0;
    setItems(
      items.map((item) => {
        if (item.product_id !== productId) return item;
        return {
          ...item,
          unit_price: numPrice,
          total: numPrice * item.quantity,
        };
      })
    );
  };

  // Remove item
  const handleRemoveItem = (productId: string) => {
    setItems(items.filter((item) => item.product_id !== productId));
  };

  // Set full amount as cash
  const handlePayFullCash = () => {
    setCashAmount(subtotal.toString());
    setUpiAmount("0");
  };

  // Set full amount as UPI
  const handlePayFullUpi = () => {
    setUpiAmount(subtotal.toString());
    setCashAmount("0");
  };

  // Submit fulfillment
  const handleSubmit = async () => {
    if (!order) return;
    if (items.length === 0) {
      toast({
        title: "No items",
        description: "Please add at least one item to the order.",
        variant: "destructive",
      });
      return;
    }

    setSubmitting(true);
    try {
      // Generate display ID for sale
      const { data: displayIdData, error: displayIdError } = await supabase.rpc(
        "generate_display_id",
        { prefix: "SALE" }
      );
      if (displayIdError) throw displayIdError;

      const saleDisplayId = displayIdData as string;

      // Get current user
      const {
        data: { user },
      } = await supabase.auth.getUser();
      if (!user) throw new Error("Not authenticated");

      // Prepare sale items
      const saleItems = items.map((item) => ({
        product_id: item.product_id,
        quantity: item.quantity,
        unit_price: item.unit_price,
      }));

      // Call record_sale RPC
      const { error: saleError } = await supabase.rpc("record_sale", {
        p_display_id: saleDisplayId,
        p_store_id: order.store_id,
        p_customer_id: order.stores?.customer_id || null,
        p_recorded_by: user.id,
        p_total_amount: subtotal,
        p_cash_amount: parseFloat(cashAmount) || 0,
        p_upi_amount: parseFloat(upiAmount) || 0,
        p_outstanding_amount: outstandingAmount,
        p_old_outstanding: oldOutstanding,
        p_new_outstanding: newOutstanding,
        p_notes: notes || null,
        p_items: saleItems,
      });

      if (saleError) throw saleError;

      // Get the sale we just created to link it to the order
      const { data: newSale, error: fetchSaleError } = await supabase
        .from("sales")
        .select("id")
        .eq("display_id", saleDisplayId)
        .single();

      if (fetchSaleError) throw fetchSaleError;

      // Update the sale with order_id reference
      const { error: linkError } = await supabase
        .from("sales")
        .update({ order_id: order.id })
        .eq("id", newSale.id);

      if (linkError) throw linkError;

      // Update order status to delivered
      const { error: orderError } = await supabase
        .from("orders")
        .update({
          status: "delivered",
          fulfilled_by: user.id,
          delivered_at: new Date().toISOString(),
        })
        .eq("id", order.id);

      if (orderError) throw orderError;

      // Send notification to customer if exists
      if (order.stores?.customer_id) {
        await supabase.from("notifications").insert({
          user_id: order.stores.customer_id,
          title: "Order Delivered",
          message: `Your order ${order.display_id} has been delivered and recorded as sale ${saleDisplayId}.`,
          type: "order",
          reference_id: order.id,
          reference_type: "order",
        });
      }

      // Log activity
      await supabase.from("activity_log").insert({
        action: "order_fulfilled",
        entity_type: "order",
        entity_id: order.id,
        user_id: user.id,
        details: {
          order_display_id: order.display_id,
          sale_display_id: saleDisplayId,
          total_amount: subtotal,
          items_count: items.length,
        },
      });

      toast({
        title: "Order Fulfilled",
        description: `Sale ${saleDisplayId} created successfully.`,
      });

      // Invalidate queries
      queryClient.invalidateQueries({ queryKey: ["orders"] });
      queryClient.invalidateQueries({ queryKey: ["sales"] });
      queryClient.invalidateQueries({ queryKey: ["customer-balances"] });

      onOpenChange(false);
      onFulfilled?.();
    } catch (error) {
      console.error("Fulfillment error:", error);
      toast({
        title: "Fulfillment Failed",
        description:
          error instanceof Error
            ? error.message
            : "Failed to complete order. Please try again.",
        variant: "destructive",
      });
    } finally {
      setSubmitting(false);
    }
  };

  // Available products not yet added
  const availableProducts = products.filter(
    (p) => !items.some((item) => item.product_id === p.id)
  );

  if (!order) return null;

  return (
    <Dialog open={open} onOpenChange={onOpenChange}>
      <DialogContent className="max-w-2xl max-h-[90vh] overflow-hidden flex flex-col">
        <DialogHeader>
          <DialogTitle className="flex items-center gap-2">
            <Package className="h-5 w-5" />
            Fulfill Order {order.display_id}
          </DialogTitle>
          <DialogDescription>
            Edit items, prices, and payment before completing delivery.
          </DialogDescription>
        </DialogHeader>

        {loading ? (
          <div className="flex items-center justify-center py-12">
            <Loader2 className="h-8 w-8 animate-spin text-muted-foreground" />
          </div>
        ) : (
          <ScrollArea className="flex-1 -mx-6 px-6">
            <div className="space-y-6 pb-4">
              {/* Order Info */}
              <div className="flex flex-wrap gap-2">
                <Badge variant="outline">
                  {order.order_type === "detailed" ? "Detailed Order" : "Simple Order"}
                </Badge>
                <Badge variant="secondary">{order.stores?.name || "Unknown Store"}</Badge>
              </div>

              {/* Requirement Note */}
              {order.requirement_note && (
                <Alert>
                  <AlertCircle className="h-4 w-4" />
                  <AlertDescription>{order.requirement_note}</AlertDescription>
                </Alert>
              )}

              {/* Add Product */}
              <div className="flex gap-2">
                <Select value={selectedProduct} onValueChange={setSelectedProduct}>
                  <SelectTrigger className="flex-1">
                    <SelectValue placeholder="Add product..." />
                  </SelectTrigger>
                  <SelectContent>
                    {availableProducts.map((product) => (
                      <SelectItem key={product.id} value={product.id}>
                        {product.name} - {product.sku}
                      </SelectItem>
                    ))}
                  </SelectContent>
                </Select>
                <Button onClick={handleAddProduct} disabled={!selectedProduct}>
                  <Plus className="h-4 w-4" />
                </Button>
              </div>

              {/* Items List */}
              <div className="space-y-3">
                {items.length === 0 ? (
                  <div className="text-center py-8 text-muted-foreground border-2 border-dashed rounded-lg">
                    {order.order_type === "simple"
                      ? "Add products to this order"
                      : "No items in order"}
                  </div>
                ) : (
                  items.map((item) => (
                    <Card key={item.product_id}>
                      <CardContent className="p-3">
                        <div className="flex items-center gap-3">
                          <Avatar className="h-10 w-10">
                            <AvatarImage src={item.image_url} alt={item.product_name} />
                            <AvatarFallback>
                              {item.product_name.charAt(0).toUpperCase()}
                            </AvatarFallback>
                          </Avatar>

                          <div className="flex-1 min-w-0">
                            <div className="font-medium truncate">{item.product_name}</div>
                            <div className="text-xs text-muted-foreground">{item.sku}</div>
                          </div>

                          {/* Quantity controls */}
                          <div className="flex items-center gap-1">
                            <Button
                              variant="outline"
                              size="icon"
                              className="h-8 w-8"
                              onClick={() => handleQuantityChange(item.product_id, -1)}
                            >
                              <Minus className="h-3 w-3" />
                            </Button>
                            <span className="w-8 text-center font-medium">{item.quantity}</span>
                            <Button
                              variant="outline"
                              size="icon"
                              className="h-8 w-8"
                              onClick={() => handleQuantityChange(item.product_id, 1)}
                            >
                              <Plus className="h-3 w-3" />
                            </Button>
                          </div>

                          {/* Price input */}
                          <div className="w-24">
                            <Input
                              type="number"
                              value={item.unit_price}
                              onChange={(e) =>
                                handlePriceChange(item.product_id, e.target.value)
                              }
                              className="h-8 text-right"
                              min={0}
                              step={0.01}
                            />
                          </div>

                          {/* Total */}
                          <div className="w-20 text-right font-medium">
                            ₹{item.total.toFixed(2)}
                          </div>

                          {/* Remove */}
                          <Button
                            variant="ghost"
                            size="icon"
                            className="h-8 w-8 text-destructive"
                            onClick={() => handleRemoveItem(item.product_id)}
                          >
                            <Trash2 className="h-4 w-4" />
                          </Button>
                        </div>
                      </CardContent>
                    </Card>
                  ))
                )}
              </div>

              <Separator />

              {/* Subtotal */}
              <div className="flex justify-between items-center text-lg font-semibold">
                <span>Subtotal</span>
                <span>₹{subtotal.toFixed(2)}</span>
              </div>

              {/* Payment Section */}
              <div className="space-y-4">
                <Label className="text-base font-medium">Payment</Label>

                <div className="flex gap-2 mb-3">
                  <Button
                    variant="outline"
                    size="sm"
                    onClick={handlePayFullCash}
                    className="flex-1"
                  >
                    <DollarSign className="h-4 w-4 mr-1" />
                    Full Cash
                  </Button>
                  <Button
                    variant="outline"
                    size="sm"
                    onClick={handlePayFullUpi}
                    className="flex-1"
                  >
                    <CreditCard className="h-4 w-4 mr-1" />
                    Full UPI
                  </Button>
                </div>

                <div className="grid grid-cols-2 gap-4">
                  <div>
                    <Label htmlFor="cash">Cash Amount</Label>
                    <Input
                      id="cash"
                      type="number"
                      value={cashAmount}
                      onChange={(e) => setCashAmount(e.target.value)}
                      min={0}
                      step={0.01}
                    />
                  </div>
                  <div>
                    <Label htmlFor="upi">UPI Amount</Label>
                    <Input
                      id="upi"
                      type="number"
                      value={upiAmount}
                      onChange={(e) => setUpiAmount(e.target.value)}
                      min={0}
                      step={0.01}
                    />
                  </div>
                </div>

                {/* Outstanding Info */}
                <div className="bg-muted p-3 rounded-lg space-y-1 text-sm">
                  <div className="flex justify-between">
                    <span className="text-muted-foreground">Previous Outstanding</span>
                    <span>₹{oldOutstanding.toFixed(2)}</span>
                  </div>
                  <div className="flex justify-between">
                    <span className="text-muted-foreground">This Order Outstanding</span>
                    <span>₹{outstandingAmount.toFixed(2)}</span>
                  </div>
                  <Separator className="my-2" />
                  <div className="flex justify-between font-medium">
                    <span>New Total Outstanding</span>
                    <span className={newOutstanding > 0 ? "text-orange-600" : "text-green-600"}>
                      ₹{newOutstanding.toFixed(2)}
                    </span>
                  </div>
                </div>
              </div>

              {/* Notes */}
              <div>
                <Label htmlFor="notes">Notes</Label>
                <Textarea
                  id="notes"
                  value={notes}
                  onChange={(e) => setNotes(e.target.value)}
                  placeholder="Any delivery notes..."
                  className="mt-1"
                />
              </div>
            </div>
          </ScrollArea>
        )}

        <DialogFooter className="gap-2 sm:gap-0">
          <Button variant="outline" onClick={() => onOpenChange(false)} disabled={submitting}>
            Cancel
          </Button>
          <Button
            onClick={handleSubmit}
            disabled={loading || submitting || items.length === 0}
            className="gap-2"
          >
            {submitting ? (
              <>
                <Loader2 className="h-4 w-4 animate-spin" />
                Processing...
              </>
            ) : (
              <>
                <Check className="h-4 w-4" />
                Complete Fulfillment
              </>
            )}
          </Button>
        </DialogFooter>
      </DialogContent>
    </Dialog>
  );
}

export default OrderFulfillmentDialog;

import { useState } from "react";
import { useQuery, useQueryClient } from "@tanstack/react-query";
import { supabase } from "@/integrations/supabase/client";
import {
  Dialog, DialogContent, DialogHeader, DialogTitle,
} from "@/components/ui/dialog";
import { Input } from "@/components/ui/input";
import { Button } from "@/components/ui/button";
import { Checkbox } from "@/components/ui/checkbox";
import { Badge } from "@/components/ui/badge";
import { Loader2, Save } from "lucide-react";
import { toast } from "sonner";

interface ProductAccessDialogProps {
  product: any;
  open: boolean;
  onOpenChange: (open: boolean) => void;
}

export function ProductAccessDialog({ product, open, onOpenChange }: ProductAccessDialogProps) {
  const qc = useQueryClient();
  const [saving, setSaving] = useState(false);
  const [accessMap, setAccessMap] = useState<Record<string, boolean>>({});
  const [priceMap, setPriceMap] = useState<Record<string, string>>({});

  const { data: storeTypes } = useQuery({
    queryKey: ["store-types-all"],
    queryFn: async () => {
      const { data } = await supabase.from("store_types").select("*").eq("is_active", true).order("name");
      return data || [];
    },
  });

  const { data: currentAccess, isLoading: loadingAccess } = useQuery({
    queryKey: ["product-store-type-access", product?.id],
    queryFn: async () => {
      const { data } = await supabase.from("store_type_products").select("store_type_id").eq("product_id", product.id);
      return data || [];
    },
    enabled: !!product,
  });

  const { data: currentPricing, isLoading: loadingPricing } = useQuery({
    queryKey: ["product-store-type-pricing", product?.id],
    queryFn: async () => {
      const { data } = await supabase.from("store_type_pricing").select("store_type_id, price").eq("product_id", product.id);
      return data || [];
    },
    enabled: !!product,
  });

  if (!product) return null;

  const accessSet = new Set(currentAccess?.map((a) => a.store_type_id) || []);
  const pricingLookup: Record<string, number> = {};
  currentPricing?.forEach((p) => { pricingLookup[p.store_type_id] = Number(p.price); });

  const isChecked = (storeTypeId: string) => {
    if (storeTypeId in accessMap) return accessMap[storeTypeId];
    return accessSet.has(storeTypeId);
  };

  const getPrice = (storeTypeId: string) => {
    if (storeTypeId in priceMap) return priceMap[storeTypeId];
    if (storeTypeId in pricingLookup) return String(pricingLookup[storeTypeId]);
    return "";
  };

  const handleSave = async () => {
    setSaving(true);

    // Determine final access
    const finalAccess = (storeTypes || []).filter((st) => isChecked(st.id)).map((st) => st.id);

    // Delete existing access for this product, re-insert
    await supabase.from("store_type_products").delete().eq("product_id", product.id);
    if (finalAccess.length > 0) {
      await supabase.from("store_type_products").insert(
        finalAccess.map((stId) => ({ store_type_id: stId, product_id: product.id }))
      );
    }

    // Pricing: delete existing for this product, insert non-empty
    await supabase.from("store_type_pricing").delete().eq("product_id", product.id);
    const pricingInserts = (storeTypes || [])
      .filter((st) => {
        const val = getPrice(st.id);
        return val !== "" && Number(val) > 0;
      })
      .map((st) => ({
        store_type_id: st.id,
        product_id: product.id,
        price: Number(getPrice(st.id)),
      }));
    if (pricingInserts.length > 0) {
      await supabase.from("store_type_pricing").insert(pricingInserts);
    }

    setSaving(false);
    toast.success("Access & pricing saved");
    qc.invalidateQueries({ queryKey: ["product-store-type-access", product.id] });
    qc.invalidateQueries({ queryKey: ["product-store-type-pricing", product.id] });
    qc.invalidateQueries({ queryKey: ["store-type-products"] });
    qc.invalidateQueries({ queryKey: ["store-type-pricing"] });
    setAccessMap({});
    setPriceMap({});
  };

  const loading = loadingAccess || loadingPricing;

  return (
    <Dialog open={open} onOpenChange={onOpenChange}>
      <DialogContent className="max-w-lg">
        <DialogHeader>
          <DialogTitle className="flex items-center gap-2">
            Store Type Access
            <Badge variant="outline" className="text-xs font-mono">{product.sku}</Badge>
          </DialogTitle>
          <p className="text-sm text-muted-foreground mt-1">
            Control which store types can access <span className="font-medium text-foreground">{product.name}</span> and set type-level pricing.
          </p>
        </DialogHeader>

        {loading ? (
          <div className="flex items-center justify-center py-8">
            <Loader2 className="h-6 w-6 animate-spin text-primary" />
          </div>
        ) : (
          <div className="space-y-1 max-h-80 overflow-y-auto">
            <div className="grid grid-cols-[auto,1fr,auto] gap-x-3 px-3 py-2 text-xs font-medium text-muted-foreground border-b">
              <span>Enable</span><span>Store Type</span><span>Type Price (₹)</span>
            </div>
            {storeTypes?.map((st) => (
              <div
                key={st.id}
                className={`grid grid-cols-[auto,1fr,auto] gap-x-3 items-center px-3 py-2.5 rounded-lg transition-colors ${
                  isChecked(st.id) ? "bg-accent/50" : ""
                }`}
              >
                <Checkbox
                  checked={isChecked(st.id)}
                  onCheckedChange={(v) => setAccessMap({ ...accessMap, [st.id]: !!v })}
                />
                <span className="text-sm font-medium">{st.name}</span>
                <Input
                  type="number"
                  value={getPrice(st.id)}
                  onChange={(e) => setPriceMap({ ...priceMap, [st.id]: e.target.value })}
                  placeholder={`₹${Number(product.base_price).toLocaleString()}`}
                  className="w-28 h-8 text-sm"
                  disabled={!isChecked(st.id)}
                />
              </div>
            ))}
            {(!storeTypes || storeTypes.length === 0) && (
              <p className="text-sm text-muted-foreground text-center py-4">No store types found. Create store types first.</p>
            )}
          </div>
        )}

        <Button onClick={handleSave} disabled={saving || loading} className="w-full">
          {saving ? <Loader2 className="mr-2 h-4 w-4 animate-spin" /> : <Save className="mr-2 h-4 w-4" />}
          Save Access & Pricing
        </Button>
      </DialogContent>
    </Dialog>
  );
}

import { useState, useMemo } from "react";
import { useQuery } from "@tanstack/react-query";
import { supabase } from "@/integrations/supabase/client";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { Input } from "@/components/ui/input";
import { Loader2, Users, ShoppingCart, CreditCard, TrendingUp, TrendingDown, Search, Package, DollarSign } from "lucide-react";
import { format, subMonths, startOfMonth } from "date-fns";
import { ReportFilters, DateRange } from "./ReportFilters";
import { ReportExportBar } from "./ReportExportBar";
import { ReportSummaryCards } from "./ReportSummaryCards";
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, Legend, PieChart, Pie, Cell } from "recharts";
import jsPDF from "jspdf";
import autoTable from "jspdf-autotable";
import * as XLSX from "xlsx";

interface CustomerData {
  id: string;
  name: string;
  phone: string;
  display_id: string;
  store_type: string;
  total_sales: number;
  total_orders: number;
  total_payments: number;
  outstanding: number;
  last_sale_date: string | null;
  avg_order_value: number;
  payment_ratio: number;
}

const COLORS = ["#3b82f6", "#10b981", "#f59e0b", "#ef4444", "#8b5cf6", "#ec4899", "#06b6d4", "#84cc16"];

export default function CustomerReport() {
  const [dateRange, setDateRange] = useState<DateRange>({
    from: startOfMonth(subMonths(new Date(), 3)),
    to: new Date(),
  });
  const [search, setSearch] = useState("");
  const [sortBy, setSortBy] = useState<"sales" | "orders" | "outstanding">("sales");

  // Fetch customers
  const { data: customers = [], isLoading: custLoading } = useQuery({
    queryKey: ["customer-report-customers"],
    queryFn: async () => {
      const { data } = await supabase
        .from("customers")
        .select("id, name, phone, display_id, outstanding_balance, store_types(name)");
      return data || [];
    },
  });

  // Fetch sales
  const { data: sales = [], isLoading: salesLoading } = useQuery({
    queryKey: ["customer-report-sales", dateRange],
    queryFn: async () => {
      const { data } = await supabase
        .from("sales")
        .select("id, customer_id, total_amount, created_at")
        .gte("created_at", format(dateRange.from, "yyyy-MM-dd"))
        .lte("created_at", format(dateRange.to, "yyyy-MM-dd") + "T23:59:59");
      return data || [];
    },
  });

  // Fetch transactions (payments)
  const { data: transactions = [], isLoading: txnLoading } = useQuery({
    queryKey: ["customer-report-transactions", dateRange],
    queryFn: async () => {
      const { data } = await supabase
        .from("transactions")
        .select("id, customer_id, amount, created_at")
        .eq("type", "payment")
        .gte("created_at", format(dateRange.from, "yyyy-MM-dd"))
        .lte("created_at", format(dateRange.to, "yyyy-MM-dd") + "T23:59:59");
      return data || [];
    },
  });

  const isLoading = custLoading || salesLoading || txnLoading;

  // Combine customer data
  const customerData = useMemo(() => {
    const data: CustomerData[] = customers.map((c: any) => {
      const custSales = sales.filter((s: any) => s.customer_id === c.id);
      const custPayments = transactions.filter((t: any) => t.customer_id === c.id);
      
      const totalSales = custSales.reduce((sum: number, s: any) => sum + Number(s.total_amount), 0);
      const totalPayments = custPayments.reduce((sum: number, t: any) => sum + Number(t.amount), 0);
      const lastSale = custSales.length > 0 
        ? custSales.reduce((latest: any, s: any) => s.created_at > latest.created_at ? s : latest).created_at
        : null;

      return {
        id: c.id,
        name: c.name,
        phone: c.phone,
        display_id: c.display_id,
        store_type: c.store_types?.name || "General",
        total_sales: totalSales,
        total_orders: custSales.length,
        total_payments: totalPayments,
        outstanding: Number(c.outstanding_balance) || 0,
        last_sale_date: lastSale,
        avg_order_value: custSales.length > 0 ? totalSales / custSales.length : 0,
        payment_ratio: totalSales > 0 ? (totalPayments / totalSales) * 100 : 100,
      };
    });

    // Sort
    if (sortBy === "sales") {
      data.sort((a, b) => b.total_sales - a.total_sales);
    } else if (sortBy === "orders") {
      data.sort((a, b) => b.total_orders - a.total_orders);
    } else {
      data.sort((a, b) => b.outstanding - a.outstanding);
    }

    return data;
  }, [customers, sales, transactions, sortBy]);

  // Filter
  const filteredData = useMemo(() => {
    if (!search) return customerData;
    const s = search.toLowerCase();
    return customerData.filter((c: CustomerData) => 
      c.name.toLowerCase().includes(s) || 
      c.phone.includes(s) ||
      c.display_id.toLowerCase().includes(s)
    );
  }, [customerData, search]);

  // Summary
  const summary = useMemo(() => {
    const totalCustomers = filteredData.length;
    const activeCustomers = filteredData.filter((c: CustomerData) => c.total_orders > 0).length;
    const totalRevenue = filteredData.reduce((sum, c) => sum + c.total_sales, 0);
    const totalOutstanding = filteredData.reduce((sum, c) => sum + c.outstanding, 0);
    const totalPayments = filteredData.reduce((sum, c) => sum + c.total_payments, 0);

    return { totalCustomers, activeCustomers, totalRevenue, totalOutstanding, totalPayments };
  }, [filteredData]);

  // Top customers chart
  const topCustomersChart = useMemo(() => {
    return filteredData.slice(0, 10).map((c: CustomerData) => ({
      name: c.name.length > 15 ? c.name.substring(0, 15) + "..." : c.name,
      sales: c.total_sales,
      payments: c.total_payments,
    }));
  }, [filteredData]);

  // Outstanding distribution
  const outstandingByType = useMemo(() => {
    const byType: Record<string, number> = {};
    filteredData.forEach((c: CustomerData) => {
      const type = c.store_type;
      byType[type] = (byType[type] || 0) + c.outstanding;
    });
    return Object.entries(byType)
      .filter(([_, v]) => v > 0)
      .map(([name, value]) => ({ name, value }));
  }, [filteredData]);

  const summaryCards = [
    { label: "Total Customers", value: summary.totalCustomers.toString(), icon: Users, iconColor: "blue" },
    { label: "Active Customers", value: summary.activeCustomers.toString(), icon: ShoppingCart, iconColor: "green" },
    { label: "Total Revenue", value: `₹${(summary.totalRevenue / 1000).toFixed(0)}K`, icon: TrendingUp, iconColor: "purple" },
    { label: "Outstanding", value: `₹${(summary.totalOutstanding / 1000).toFixed(0)}K`, icon: DollarSign, iconColor: "red" },
  ];

  const exportPDF = () => {
    const doc = new jsPDF();
    doc.setFontSize(16);
    doc.text("Customer Report", 14, 15);
    doc.setFontSize(10);
    doc.text(`Period: ${format(dateRange.from, "MMM d, yyyy")} - ${format(dateRange.to, "MMM d, yyyy")}`, 14, 23);

    autoTable(doc, {
      startY: 30,
      head: [["Customer", "Type", "Orders", "Sales", "Payments", "Outstanding"]],
      body: filteredData.map((c: CustomerData) => [
        c.name,
        c.store_type,
        c.total_orders.toString(),
        `₹${c.total_sales.toLocaleString()}`,
        `₹${c.total_payments.toLocaleString()}`,
        `₹${c.outstanding.toLocaleString()}`,
      ]),
      styles: { fontSize: 8 },
      headStyles: { fillColor: [59, 130, 246] },
    });

    doc.save(`customer-report-${format(dateRange.from, "yyyyMMdd")}-${format(dateRange.to, "yyyyMMdd")}.pdf`);
  };

  const exportExcel = () => {
    const ws = XLSX.utils.json_to_sheet(filteredData.map((c: CustomerData) => ({
      "Customer ID": c.display_id,
      "Name": c.name,
      "Phone": c.phone,
      "Store Type": c.store_type,
      "Total Orders": c.total_orders,
      "Total Sales": c.total_sales,
      "Total Payments": c.total_payments,
      "Outstanding": c.outstanding,
      "Avg Order Value": c.avg_order_value.toFixed(2),
      "Payment Ratio %": c.payment_ratio.toFixed(1),
      "Last Sale": c.last_sale_date || "",
    })));
    const wb = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(wb, ws, "Customers");
    XLSX.writeFile(wb, `customer-report-${format(dateRange.from, "yyyyMMdd")}-${format(dateRange.to, "yyyyMMdd")}.xlsx`);
  };

  return (
    <div className="space-y-6">
      <div className="flex flex-col lg:flex-row lg:items-end gap-4">
        <ReportFilters dateRange={dateRange} onDateRangeChange={setDateRange} />
        <div className="relative flex-1 max-w-xs">
          <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-muted-foreground" />
          <Input
            placeholder="Search customers..."
            value={search}
            onChange={(e) => setSearch(e.target.value)}
            className="pl-9"
          />
        </div>
        <div className="flex gap-2">
          <Badge 
            variant={sortBy === "sales" ? "default" : "outline"} 
            className="cursor-pointer"
            onClick={() => setSortBy("sales")}
          >
            By Sales
          </Badge>
          <Badge 
            variant={sortBy === "orders" ? "default" : "outline"} 
            className="cursor-pointer"
            onClick={() => setSortBy("orders")}
          >
            By Orders
          </Badge>
          <Badge 
            variant={sortBy === "outstanding" ? "default" : "outline"} 
            className="cursor-pointer"
            onClick={() => setSortBy("outstanding")}
          >
            By Outstanding
          </Badge>
        </div>
      </div>

      <ReportExportBar onExportPDF={exportPDF} onExportExcel={exportExcel} />

      {isLoading ? (
        <div className="flex items-center justify-center py-12">
          <Loader2 className="h-8 w-8 animate-spin text-muted-foreground" />
        </div>
      ) : (
        <>
          <ReportSummaryCards cards={summaryCards} />

          <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
            {/* Top Customers Chart */}
            <Card>
              <CardHeader>
                <CardTitle className="text-base">Top 10 Customers</CardTitle>
              </CardHeader>
              <CardContent>
                {topCustomersChart.length > 0 ? (
                  <ResponsiveContainer width="100%" height={300}>
                    <BarChart data={topCustomersChart} layout="vertical">
                      <CartesianGrid strokeDasharray="3 3" />
                      <XAxis type="number" tickFormatter={(v) => `₹${(v / 1000).toFixed(0)}K`} />
                      <YAxis type="category" dataKey="name" width={100} tick={{ fontSize: 11 }} />
                      <Tooltip formatter={(v: number) => `₹${v.toLocaleString()}`} />
                      <Legend />
                      <Bar dataKey="sales" name="Sales" fill="#3b82f6" />
                      <Bar dataKey="payments" name="Payments" fill="#10b981" />
                    </BarChart>
                  </ResponsiveContainer>
                ) : (
                  <p className="text-center text-muted-foreground py-12">No customer data</p>
                )}
              </CardContent>
            </Card>

            {/* Outstanding by Type */}
            <Card>
              <CardHeader>
                <CardTitle className="text-base">Outstanding by Store Type</CardTitle>
              </CardHeader>
              <CardContent>
                {outstandingByType.length > 0 ? (
                  <ResponsiveContainer width="100%" height={300}>
                    <PieChart>
                      <Pie
                        data={outstandingByType}
                        cx="50%"
                        cy="50%"
                        labelLine={false}
                        label={({ name, percent }) => `${name} (${(percent * 100).toFixed(0)}%)`}
                        outerRadius={100}
                        fill="#8884d8"
                        dataKey="value"
                      >
                        {outstandingByType.map((_, index) => (
                          <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} />
                        ))}
                      </Pie>
                      <Tooltip formatter={(v: number) => `₹${v.toLocaleString()}`} />
                    </PieChart>
                  </ResponsiveContainer>
                ) : (
                  <p className="text-center text-muted-foreground py-12">No outstanding balances</p>
                )}
              </CardContent>
            </Card>
          </div>

          {/* Customer Table */}
          <Card>
            <CardHeader>
              <CardTitle className="text-base">Customer Details ({filteredData.length})</CardTitle>
            </CardHeader>
            <CardContent>
              {filteredData.length === 0 ? (
                <p className="text-center text-muted-foreground py-12">No customers found</p>
              ) : (
                <div className="overflow-x-auto">
                  <table className="w-full text-sm">
                    <thead>
                      <tr className="border-b bg-muted/50">
                        <th className="text-left p-3 font-medium">Customer</th>
                        <th className="text-left p-3 font-medium hidden md:table-cell">Type</th>
                        <th className="text-center p-3 font-medium">Orders</th>
                        <th className="text-right p-3 font-medium">Sales</th>
                        <th className="text-right p-3 font-medium hidden lg:table-cell">Payments</th>
                        <th className="text-right p-3 font-medium">Outstanding</th>
                        <th className="text-center p-3 font-medium hidden xl:table-cell">Pay %</th>
                      </tr>
                    </thead>
                    <tbody>
                      {filteredData.slice(0, 50).map((c: CustomerData) => (
                        <tr key={c.id} className="border-b hover:bg-muted/30">
                          <td className="p-3">
                            <p className="font-medium">{c.name}</p>
                            <p className="text-xs text-muted-foreground">{c.display_id}</p>
                          </td>
                          <td className="p-3 hidden md:table-cell">
                            <Badge variant="outline" className="text-xs">{c.store_type}</Badge>
                          </td>
                          <td className="p-3 text-center">{c.total_orders}</td>
                          <td className="p-3 text-right font-medium">₹{c.total_sales.toLocaleString()}</td>
                          <td className="p-3 text-right hidden lg:table-cell text-green-600">
                            ₹{c.total_payments.toLocaleString()}
                          </td>
                          <td className="p-3 text-right">
                            <span className={c.outstanding > 0 ? "text-red-600 font-semibold" : "text-green-600"}>
                              ₹{c.outstanding.toLocaleString()}
                            </span>
                          </td>
                          <td className="p-3 text-center hidden xl:table-cell">
                            <Badge variant={c.payment_ratio >= 80 ? "default" : c.payment_ratio >= 50 ? "secondary" : "destructive"}>
                              {c.payment_ratio.toFixed(0)}%
                            </Badge>
                          </td>
                        </tr>
                      ))}
                    </tbody>
                  </table>
                </div>
              )}
              {filteredData.length > 50 && (
                <p className="text-center text-muted-foreground mt-4 text-sm">
                  Showing 50 of {filteredData.length} customers. Export to see all.
                </p>
              )}
            </CardContent>
          </Card>
        </>
      )}
    </div>
  );
}

import { useState, useMemo } from "react";
import { useQuery } from "@tanstack/react-query";
import { supabase } from "@/integrations/supabase/client";
import { Button } from "@/components/ui/button";
import { Card, CardContent } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { Loader2, FileText, ShoppingCart, CreditCard, RotateCcw, Download, Printer, X } from "lucide-react";
import { format, subMonths, startOfMonth, endOfMonth } from "date-fns";
import { ReportFilters, DateRange } from "./ReportFilters";
import { PrintPreview, PrintHeader, PrintFooter, PrintTable } from "./PrintPreview";
import jsPDF from "jspdf";
import autoTable from "jspdf-autotable";

interface CustomerStatementProps {
  customerId: string;
  customerName: string;
  storeId?: string;
  storeName?: string;
  onClose?: () => void;
}

interface StatementEntry {
  id: string;
  type: "sale" | "payment" | "return" | "adjustment" | "opening";
  display_id: string;
  date: string;
  description: string;
  debit: number;
  credit: number;
  balance: number;
  payment_method?: string;
  handled_by?: string;
  notes?: string;
}

export function CustomerStatement({ customerId, customerName, storeId, storeName, onClose }: CustomerStatementProps) {
  const [dateRange, setDateRange] = useState<DateRange>({
    from: startOfMonth(subMonths(new Date(), 2)),
    to: new Date(),
  });
  const [showPrint, setShowPrint] = useState(false);

  // Fetch business info
  const { data: businessInfo } = useQuery({
    queryKey: ["business-info"],
    queryFn: async () => {
      const { data } = await supabase.from("business_info").select("*").single();
      return data;
    },
  });

  // Fetch customer details
  const { data: customer } = useQuery({
    queryKey: ["customer-detail", customerId],
    queryFn: async () => {
      const { data } = await supabase
        .from("customers")
        .select("*, stores(id, name, display_id, opening_balance, outstanding)")
        .eq("id", customerId)
        .single();
      return data;
    },
    enabled: !!customerId,
  });

  // Fetch sales for the customer's stores
  const { data: sales = [], isLoading: salesLoading } = useQuery({
    queryKey: ["statement-sales", customerId, storeId, dateRange],
    queryFn: async () => {
      let query = supabase
        .from("sales")
        .select("id, display_id, total_amount, cash_amount, upi_amount, notes, created_at, recorded_by, stores(id, name), profiles:recorded_by(full_name)")
        .gte("created_at", format(dateRange.from, "yyyy-MM-dd"))
        .lte("created_at", format(dateRange.to, "yyyy-MM-dd") + "T23:59:59");

      if (storeId) {
        query = query.eq("store_id", storeId);
      } else {
        // Get all stores for this customer
        const { data: stores } = await supabase.from("stores").select("id").eq("customer_id", customerId);
        if (stores && stores.length > 0) {
          query = query.in("store_id", stores.map(s => s.id));
        }
      }

      const { data } = await query.order("created_at", { ascending: true });
      return data || [];
    },
    enabled: !!customerId,
  });

  // Fetch transactions (payments)
  const { data: transactions = [], isLoading: txnLoading } = useQuery({
    queryKey: ["statement-transactions", customerId, storeId, dateRange],
    queryFn: async () => {
      let query = supabase
        .from("transactions")
        .select("id, display_id, transaction_date, amount, type, payment_method, notes, created_at, recorded_by, stores(id, name), profiles:recorded_by(full_name)")
        .gte("transaction_date", format(dateRange.from, "yyyy-MM-dd"))
        .lte("transaction_date", format(dateRange.to, "yyyy-MM-dd"));

      if (storeId) {
        query = query.eq("store_id", storeId);
      } else {
        const { data: stores } = await supabase.from("stores").select("id").eq("customer_id", customerId);
        if (stores && stores.length > 0) {
          query = query.in("store_id", stores.map(s => s.id));
        }
      }

      const { data } = await query.order("transaction_date", { ascending: true });
      return data || [];
    },
    enabled: !!customerId,
  });

  // Fetch sale returns
  const { data: returns = [], isLoading: returnsLoading } = useQuery({
    queryKey: ["statement-returns", customerId, storeId, dateRange],
    queryFn: async () => {
      let query = supabase
        .from("sale_returns")
        .select("id, display_id, return_date, total_amount, reason, notes, created_at, stores(id, name)")
        .eq("status", "completed")
        .gte("return_date", format(dateRange.from, "yyyy-MM-dd"))
        .lte("return_date", format(dateRange.to, "yyyy-MM-dd"));

      if (storeId) {
        query = query.eq("store_id", storeId);
      } else {
        const { data: stores } = await supabase.from("stores").select("id").eq("customer_id", customerId);
        if (stores && stores.length > 0) {
          query = query.in("store_id", stores.map(s => s.id));
        }
      }

      const { data } = await query.order("return_date", { ascending: true });
      return data || [];
    },
    enabled: !!customerId,
  });

  const isLoading = salesLoading || txnLoading || returnsLoading;

  // Calculate opening balance before the date range
  const openingBalance = useMemo(() => {
    if (storeId) {
      const store = customer?.stores?.find((s: any) => s.id === storeId);
      return Number(store?.opening_balance || 0);
    }
    return customer?.stores?.reduce((sum: number, s: any) => sum + Number(s.opening_balance || 0), 0) || 0;
  }, [customer, storeId]);

  // Combine and calculate running balance
  const entries = useMemo(() => {
    const allEntries: StatementEntry[] = [];
    
    // Add opening balance entry
    allEntries.push({
      id: "opening",
      type: "opening",
      display_id: "—",
      date: format(dateRange.from, "yyyy-MM-dd"),
      description: "Opening Balance",
      debit: openingBalance > 0 ? openingBalance : 0,
      credit: openingBalance < 0 ? Math.abs(openingBalance) : 0,
      balance: openingBalance,
    });

    // Add sales (debit - customer owes us)
    sales.forEach((s: any) => {
      const paymentMethod = (s.upi_amount > 0 && s.cash_amount > 0) ? "Mixed" : s.upi_amount > 0 ? "UPI" : "Cash";
      allEntries.push({
        id: s.id,
        type: "sale",
        display_id: s.display_id,
        date: format(new Date(s.created_at), "yyyy-MM-dd"),
        description: `Sale ${s.stores?.name ? `at ${s.stores.name}` : ""}`,
        debit: Number(s.total_amount),
        credit: 0,
        balance: 0,
        payment_method: paymentMethod,
        handled_by: s.profiles?.full_name,
        notes: s.notes,
      });
    });

    // Add payments (credit - customer paid us)
    transactions.forEach((t: any) => {
      if (t.type === "payment") {
        allEntries.push({
          id: t.id,
          type: "payment",
          display_id: t.display_id,
          date: t.transaction_date,
          description: `Payment Received${t.stores?.name ? ` (${t.stores.name})` : ""}`,
          debit: 0,
          credit: Number(t.amount),
          balance: 0,
          payment_method: t.payment_method,
          handled_by: t.profiles?.full_name,
          notes: t.notes,
        });
      } else if (t.type === "adjustment") {
        const isDebit = Number(t.amount) > 0;
        allEntries.push({
          id: t.id,
          type: "adjustment",
          display_id: t.display_id,
          date: t.transaction_date,
          description: `Balance Adjustment${t.stores?.name ? ` (${t.stores.name})` : ""}`,
          debit: isDebit ? Number(t.amount) : 0,
          credit: isDebit ? 0 : Math.abs(Number(t.amount)),
          balance: 0,
          notes: t.notes,
        });
      }
    });

    // Add returns (credit - reduces what customer owes)
    returns.forEach((r: any) => {
      allEntries.push({
        id: r.id,
        type: "return",
        display_id: r.display_id,
        date: r.return_date,
        description: `Sale Return${r.stores?.name ? ` (${r.stores.name})` : ""}`,
        debit: 0,
        credit: Number(r.total_amount),
        balance: 0,
        notes: r.reason,
      });
    });

    // Sort by date
    allEntries.sort((a, b) => {
      if (a.type === "opening") return -1;
      if (b.type === "opening") return 1;
      return new Date(a.date).getTime() - new Date(b.date).getTime();
    });

    // Calculate running balance
    let balance = 0;
    allEntries.forEach((entry) => {
      balance += entry.debit - entry.credit;
      entry.balance = balance;
    });

    return allEntries;
  }, [sales, transactions, returns, openingBalance, dateRange]);

  // Totals
  const totals = useMemo(() => {
    const totalDebit = entries.reduce((sum, e) => sum + e.debit, 0);
    const totalCredit = entries.reduce((sum, e) => sum + e.credit, 0);
    const closingBalance = entries.length > 0 ? entries[entries.length - 1].balance : openingBalance;
    return { totalDebit, totalCredit, closingBalance };
  }, [entries, openingBalance]);

  const getTypeIcon = (type: string) => {
    switch (type) {
      case "sale": return <ShoppingCart className="h-4 w-4 text-blue-600" />;
      case "payment": return <CreditCard className="h-4 w-4 text-green-600" />;
      case "return": return <RotateCcw className="h-4 w-4 text-orange-600" />;
      default: return <FileText className="h-4 w-4 text-gray-600" />;
    }
  };

  const exportPDF = () => {
    const doc = new jsPDF();
    
    // Header
    if (businessInfo) {
      doc.setFontSize(14);
      doc.text(businessInfo.company_name || "Company", 14, 15);
      doc.setFontSize(9);
      if (businessInfo.address) doc.text(businessInfo.address, 14, 22);
      if (businessInfo.gstin) doc.text(`GSTIN: ${businessInfo.gstin}`, 14, 27);
    }
    
    doc.setFontSize(12);
    doc.text("Customer Statement", 14, 38);
    doc.setFontSize(10);
    doc.text(`Customer: ${customerName}`, 14, 45);
    if (storeName) doc.text(`Store: ${storeName}`, 14, 51);
    doc.text(`Period: ${format(dateRange.from, "MMM d, yyyy")} - ${format(dateRange.to, "MMM d, yyyy")}`, 14, storeName ? 57 : 51);

    const startY = storeName ? 65 : 58;

    autoTable(doc, {
      startY,
      head: [["Date", "ID", "Description", "Debit (₹)", "Credit (₹)", "Balance (₹)"]],
      body: entries.map((e) => [
        format(new Date(e.date), "dd/MM/yyyy"),
        e.display_id,
        e.description + (e.payment_method ? ` (${e.payment_method})` : ""),
        e.debit > 0 ? e.debit.toLocaleString() : "",
        e.credit > 0 ? e.credit.toLocaleString() : "",
        e.balance.toLocaleString(),
      ]),
      foot: [[
        "", "", "TOTAL",
        totals.totalDebit.toLocaleString(),
        totals.totalCredit.toLocaleString(),
        totals.closingBalance.toLocaleString()
      ]],
      styles: { fontSize: 9 },
      headStyles: { fillColor: [59, 130, 246] },
      footStyles: { fillColor: [229, 231, 235], textColor: [0, 0, 0], fontStyle: "bold" },
    });

    // Closing summary
    const finalY = (doc as any).lastAutoTable.finalY || startY + 50;
    doc.setFontSize(10);
    doc.text(`Closing Balance: ₹${totals.closingBalance.toLocaleString()}`, 14, finalY + 10);
    doc.setFontSize(8);
    doc.text(`Generated on ${format(new Date(), "dd/MM/yyyy HH:mm")}`, 14, finalY + 18);

    doc.save(`statement-${customerName.replace(/\s+/g, "-")}-${format(dateRange.from, "yyyyMMdd")}-${format(dateRange.to, "yyyyMMdd")}.pdf`);
  };

  return (
    <div className="space-y-6">
      <div className="flex flex-col sm:flex-row sm:items-center sm:justify-between gap-4">
        <div>
          <h2 className="text-xl font-semibold">Customer Statement</h2>
          <p className="text-sm text-muted-foreground">
            {customerName} {storeName && `• ${storeName}`}
          </p>
        </div>
        <div className="flex items-center gap-2">
          <Button variant="outline" size="sm" onClick={exportPDF}>
            <Download className="h-4 w-4 mr-2" />
            Download PDF
          </Button>
          <Button variant="outline" size="sm" onClick={() => setShowPrint(true)}>
            <Printer className="h-4 w-4 mr-2" />
            Print
          </Button>
          {onClose && (
            <Button variant="ghost" size="sm" onClick={onClose}>
              <X className="h-4 w-4" />
            </Button>
          )}
        </div>
      </div>

      <ReportFilters dateRange={dateRange} onDateRangeChange={setDateRange} />

      {/* Summary Cards */}
      <div className="grid grid-cols-2 lg:grid-cols-4 gap-4">
        <Card className="p-4">
          <p className="text-sm text-muted-foreground">Opening Balance</p>
          <p className="text-2xl font-bold">₹{openingBalance.toLocaleString()}</p>
        </Card>
        <Card className="p-4">
          <p className="text-sm text-muted-foreground">Total Debit (Sales)</p>
          <p className="text-2xl font-bold text-blue-600">₹{totals.totalDebit.toLocaleString()}</p>
        </Card>
        <Card className="p-4">
          <p className="text-sm text-muted-foreground">Total Credit (Payments)</p>
          <p className="text-2xl font-bold text-green-600">₹{totals.totalCredit.toLocaleString()}</p>
        </Card>
        <Card className="p-4">
          <p className="text-sm text-muted-foreground">Closing Balance</p>
          <p className={`text-2xl font-bold ${totals.closingBalance >= 0 ? "text-red-600" : "text-green-600"}`}>
            ₹{Math.abs(totals.closingBalance).toLocaleString()}
            <span className="text-xs font-normal ml-1">{totals.closingBalance >= 0 ? "Due" : "Advance"}</span>
          </p>
        </Card>
      </div>

      {isLoading ? (
        <div className="flex items-center justify-center py-12">
          <Loader2 className="h-8 w-8 animate-spin text-muted-foreground" />
        </div>
      ) : (
        <Card>
          <CardContent className="p-0">
            <div className="overflow-x-auto">
              <table className="w-full">
                <thead className="bg-muted/50">
                  <tr className="text-left text-sm">
                    <th className="px-4 py-3 font-medium">Date</th>
                    <th className="px-4 py-3 font-medium">Type</th>
                    <th className="px-4 py-3 font-medium">ID</th>
                    <th className="px-4 py-3 font-medium">Description</th>
                    <th className="px-4 py-3 font-medium text-right">Debit</th>
                    <th className="px-4 py-3 font-medium text-right">Credit</th>
                    <th className="px-4 py-3 font-medium text-right">Balance</th>
                  </tr>
                </thead>
                <tbody className="divide-y">
                  {entries.map((entry, idx) => (
                    <tr key={`${entry.type}-${entry.id}`} className={entry.type === "opening" ? "bg-muted/30" : "hover:bg-muted/20"}>
                      <td className="px-4 py-3 text-sm">{format(new Date(entry.date), "dd MMM yyyy")}</td>
                      <td className="px-4 py-3">
                        <div className="flex items-center gap-2">
                          {getTypeIcon(entry.type)}
                          <Badge variant="outline" className="text-xs capitalize">{entry.type}</Badge>
                        </div>
                      </td>
                      <td className="px-4 py-3 text-sm font-mono text-muted-foreground">{entry.display_id}</td>
                      <td className="px-4 py-3 text-sm">
                        <div>
                          <span>{entry.description}</span>
                          {entry.payment_method && (
                            <span className="text-xs text-muted-foreground ml-2 capitalize">({entry.payment_method.replace("_", " ")})</span>
                          )}
                        </div>
                        {entry.handled_by && <p className="text-xs text-muted-foreground">By: {entry.handled_by}</p>}
                      </td>
                      <td className="px-4 py-3 text-sm text-right font-medium text-blue-600">
                        {entry.debit > 0 ? `₹${entry.debit.toLocaleString()}` : "—"}
                      </td>
                      <td className="px-4 py-3 text-sm text-right font-medium text-green-600">
                        {entry.credit > 0 ? `₹${entry.credit.toLocaleString()}` : "—"}
                      </td>
                      <td className="px-4 py-3 text-sm text-right font-bold">
                        <span className={entry.balance >= 0 ? "text-red-600" : "text-green-600"}>
                          ₹{Math.abs(entry.balance).toLocaleString()}
                        </span>
                      </td>
                    </tr>
                  ))}
                </tbody>
                <tfoot className="bg-muted/70 font-semibold">
                  <tr>
                    <td colSpan={4} className="px-4 py-3 text-right">TOTAL</td>
                    <td className="px-4 py-3 text-right text-blue-600">₹{totals.totalDebit.toLocaleString()}</td>
                    <td className="px-4 py-3 text-right text-green-600">₹{totals.totalCredit.toLocaleString()}</td>
                    <td className="px-4 py-3 text-right">
                      <span className={totals.closingBalance >= 0 ? "text-red-600" : "text-green-600"}>
                        ₹{Math.abs(totals.closingBalance).toLocaleString()}
                      </span>
                    </td>
                  </tr>
                </tfoot>
              </table>
            </div>
          </CardContent>
        </Card>
      )}

      {/* Print Preview Dialog */}
      <PrintPreview 
        open={showPrint} 
        onOpenChange={setShowPrint}
        title="Customer Statement"
        onDownloadPDF={exportPDF}
      >
        <PrintHeader
          companyName={businessInfo?.company_name}
          address={businessInfo?.address}
          phone={businessInfo?.phone}
          gstin={businessInfo?.gstin}
          title="Customer Statement"
          subtitle={`${customerName}${storeName ? ` • ${storeName}` : ""}`}
          dateRange={`${format(dateRange.from, "dd MMM yyyy")} - ${format(dateRange.to, "dd MMM yyyy")}`}
        />

        <div className="mb-4 p-3 bg-gray-50 rounded">
          <div className="grid grid-cols-4 gap-4 text-sm">
            <div>
              <p className="text-gray-500">Opening Balance</p>
              <p className="font-semibold">₹{openingBalance.toLocaleString()}</p>
            </div>
            <div>
              <p className="text-gray-500">Total Debit</p>
              <p className="font-semibold">₹{totals.totalDebit.toLocaleString()}</p>
            </div>
            <div>
              <p className="text-gray-500">Total Credit</p>
              <p className="font-semibold">₹{totals.totalCredit.toLocaleString()}</p>
            </div>
            <div>
              <p className="text-gray-500">Closing Balance</p>
              <p className="font-bold text-lg">₹{Math.abs(totals.closingBalance).toLocaleString()} {totals.closingBalance >= 0 ? "Due" : "Advance"}</p>
            </div>
          </div>
        </div>

        <PrintTable
          headers={["Date", "Type", "ID", "Description", "Debit", "Credit", "Balance"]}
          rows={entries.map((e) => [
            format(new Date(e.date), "dd/MM/yy"),
            e.type.charAt(0).toUpperCase() + e.type.slice(1),
            e.display_id,
            `${e.description}${e.payment_method ? ` (${e.payment_method})` : ""}`,
            e.debit > 0 ? `₹${e.debit.toLocaleString()}` : "—",
            e.credit > 0 ? `₹${e.credit.toLocaleString()}` : "—",
            `₹${Math.abs(e.balance).toLocaleString()}`,
          ])}
          footer={["", "", "", "TOTAL", `₹${totals.totalDebit.toLocaleString()}`, `₹${totals.totalCredit.toLocaleString()}`, `₹${Math.abs(totals.closingBalance).toLocaleString()}`]}
        />

        <PrintFooter generatedAt={format(new Date(), "dd/MM/yyyy HH:mm")} />
      </PrintPreview>
    </div>
  );
}

import { useState } from "react";
import { useQuery } from "@tanstack/react-query";
import { supabase } from "@/integrations/supabase/client";
import { StatCard } from "@/components/shared/StatCard";
import { DataTable } from "@/components/shared/DataTable";
import { TableSkeleton } from "@/components/shared/TableSkeleton";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Button } from "@/components/ui/button";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { Tabs, TabsContent, TabsList, TabsTrigger } from "@/components/ui/tabs";
import { toast } from "sonner";
import {
  DollarSign, Banknote, Smartphone, TrendingUp, Download,
  ShoppingCart, Package, Users, HandCoins, FileText, FileSpreadsheet,
} from "lucide-react";
import * as XLSX from "xlsx";

const fmt = (n: number) => `₹${n.toLocaleString("en-IN")}`;

export default function DailyReport() {
  const today = new Date().toISOString().split("T")[0];
  const [date, setDate] = useState(today);

  const startOfDay = date + "T00:00:00";
  const endOfDay = date + "T23:59:59";

  const { data, isLoading } = useQuery({
    queryKey: ["daily-report", date],
    queryFn: async () => {
      const [salesRes, txnRes, ordersRes, saleItemsRes, storesRes, handoversRes, profilesRes, rolesRes, routesRes, visitsRes] = await Promise.all([
        supabase.from("sales").select("*, stores(name, route_id)").gte("created_at", startOfDay).lte("created_at", endOfDay).order("created_at", { ascending: false }),
        supabase.from("transactions").select("*, stores(name, route_id)").gte("created_at", startOfDay).lte("created_at", endOfDay).order("created_at", { ascending: false }),
        supabase.from("orders").select("*, stores(name)").gte("created_at", startOfDay).lte("created_at", endOfDay),
        supabase.from("sale_items").select("*, products(name, unit)").gte("created_at", startOfDay).lte("created_at", endOfDay),
        supabase.from("stores").select("id, name, display_id, outstanding, route_id").eq("is_active", true),
        supabase.from("handovers").select("*").eq("handover_date", date),
        supabase.from("profiles").select("user_id, full_name"),
        supabase.from("user_roles").select("user_id, role").neq("role", "customer"),
        supabase.from("routes").select("id, name").eq("is_active", true).order("name"),
        supabase.from("store_visits").select("store_id, stores(route_id)").gte("visited_at", startOfDay).lte("visited_at", endOfDay),
      ]);

      const sales = salesRes.data || [];
      const txns = txnRes.data || [];
      const orders = ordersRes.data || [];
      const saleItems = saleItemsRes.data || [];
      const stores = storesRes.data || [];
      const handovers = handoversRes.data || [];
      const profiles = profilesRes.data || [];
      const roles = rolesRes.data || [];
      const routes = routesRes.data || [];
      const visits = visitsRes.data || [];

      const profileMap = Object.fromEntries(profiles.map((p) => [p.user_id, p.full_name]));
      
      // Pre-build lookup maps for O(1) access instead of O(n) find/filter in loops
      const roleMap = new Map(roles.map((r) => [r.user_id, r.role]));
      const salesByUser = new Map<string, typeof sales>();
      const txnsByUser = new Map<string, typeof txns>();
      const handoversBySender = new Map<string, typeof handovers>();
      const handoversByReceiver = new Map<string, typeof handovers>();
      const storesByRoute = new Map<string, typeof stores>();
      const visitsByRoute = new Map<string, typeof visits>();
      
      // Group data by user/route for O(1) lookups
      sales.forEach((s) => {
        const key = s.recorded_by;
        if (!salesByUser.has(key)) salesByUser.set(key, []);
        salesByUser.get(key)!.push(s);
      });
      txns.forEach((t) => {
        const key = t.recorded_by;
        if (!txnsByUser.has(key)) txnsByUser.set(key, []);
        txnsByUser.get(key)!.push(t);
      });
      handovers.forEach((h) => {
        if (!handoversBySender.has(h.user_id)) handoversBySender.set(h.user_id, []);
        handoversBySender.get(h.user_id)!.push(h);
        if (!handoversByReceiver.has(h.handed_to)) handoversByReceiver.set(h.handed_to, []);
        handoversByReceiver.get(h.handed_to)!.push(h);
      });
      stores.forEach((s) => {
        const key = s.route_id;
        if (key) {
          if (!storesByRoute.has(key)) storesByRoute.set(key, []);
          storesByRoute.get(key)!.push(s);
        }
      });
      visits.forEach((v: any) => {
        const key = v.stores?.route_id;
        if (key) {
          if (!visitsByRoute.has(key)) visitsByRoute.set(key, []);
          visitsByRoute.get(key)!.push(v);
        }
      });

      // Sales metrics
      const totalSaleAmount = sales.reduce((s, r) => s + Number(r.total_amount), 0);
      const salesCash = sales.reduce((s, r) => s + Number(r.cash_amount), 0);
      const salesUpi = sales.reduce((s, r) => s + Number(r.upi_amount), 0);
      const salesOutstanding = sales.reduce((s, r) => s + Number(r.outstanding_amount), 0);

      // Payment/Collections metrics
      const totalCollections = txns.reduce((s, r) => s + Number(r.total_amount), 0);
      const txnCash = txns.reduce((s, r) => s + Number(r.cash_amount), 0);
      const txnUpi = txns.reduce((s, r) => s + Number(r.upi_amount), 0);

      // Total cash & UPI collected across sales + payments
      const totalCash = salesCash + txnCash;
      const totalUpi = salesUpi + txnUpi;

      // Total income = sale amount + collections
      const totalIncome = totalSaleAmount + totalCollections;

      // Items sold
      const totalItemsSold = saleItems.reduce((s, r) => s + Number(r.quantity), 0);

      // Product-wise breakdown
      const productMap: Record<string, { name: string; unit: string; qty: number; revenue: number }> = {};
      saleItems.forEach((item: any) => {
        const key = item.product_id;
        if (!productMap[key]) {
          productMap[key] = { name: item.products?.name || "Unknown", unit: item.products?.unit || "PCS", qty: 0, revenue: 0 };
        }
        productMap[key].qty += Number(item.quantity);
        productMap[key].revenue += Number(item.total_price);
      });
      const productBreakdown = Object.values(productMap).sort((a, b) => b.revenue - a.revenue);

      // Staff-wise balance calculation using pre-built maps (O(n) instead of O(n²))
      const staffIds = roles.map((r) => r.user_id);
      const staffBalances = staffIds.map((uid) => {
        const name = profileMap[uid] || "Unknown";
        const role = roleMap.get(uid) || "";

        // Sales recorded by this user (cash + upi collected) - O(1) lookup
        const userSales = salesByUser.get(uid) || [];
        const collectedFromSales = userSales.reduce((s, r) => s + Number(r.cash_amount) + Number(r.upi_amount), 0);

        // Transactions/payments recorded by this user - O(1) lookup
        const userTxns = txnsByUser.get(uid) || [];
        const collectedFromTxns = userTxns.reduce((s, r) => s + Number(r.total_amount), 0);

        const totalCollected = collectedFromSales + collectedFromTxns;

        // Handovers - O(1) lookup for sender/receiver
        const sentHandovers = handoversBySender.get(uid) || [];
        const receivedHandovers = handoversByReceiver.get(uid) || [];
        
        const sentConfirmed = sentHandovers.filter((h) => h.status === "confirmed")
          .reduce((s, h) => s + Number(h.cash_amount) + Number(h.upi_amount), 0);
        const sentPending = sentHandovers.filter((h) => h.status === "pending")
          .reduce((s, h) => s + Number(h.cash_amount) + Number(h.upi_amount), 0);
        const receivedConfirmed = receivedHandovers.filter((h) => h.status === "confirmed")
          .reduce((s, h) => s + Number(h.cash_amount) + Number(h.upi_amount), 0);

        const balance = totalCollected - sentConfirmed - sentPending + receivedConfirmed;

        return {
          user_id: uid,
          name,
          role,
          sales_count: userSales.length,
          txn_count: userTxns.length,
          collected: totalCollected,
          handed_over: sentConfirmed,
          pending_handover: sentPending,
          received: receivedConfirmed,
          balance,
        };
      }).filter((s) => s.collected > 0 || s.balance > 0 || s.received > 0);

      // Outstanding totals
      const totalOutstanding = stores.reduce((s, st) => s + Number(st.outstanding), 0);
      const storesWithOutstanding = stores.filter((s) => Number(s.outstanding) > 0)
        .sort((a, b) => Number(b.outstanding) - Number(a.outstanding));

      // Orders
      const delivered = orders.filter((o) => o.status === "delivered").length;
      const pending = orders.filter((o) => o.status === "pending").length;
      const cancelled = orders.filter((o) => o.status === "cancelled").length;

      // Route performance using pre-built maps (O(n) instead of O(n²))
      const routePerformance = routes.map((route) => {
        const routeStores = storesByRoute.get(route.id) || [];
        const totalStores = routeStores.length;
        const routeVisits = visitsByRoute.get(route.id) || [];
        const visitedStoreIds = new Set(routeVisits.map((v: any) => v.store_id));
        const storesCovered = visitedStoreIds.size;
        const pctCovered = totalStores > 0 ? Math.round((storesCovered / totalStores) * 100) : 0;
        const routeSales = sales.filter((s: any) => s.stores?.route_id === route.id)
          .reduce((sum: number, s: any) => sum + Number(s.total_amount), 0);
        const routeCollected = txns.filter((t: any) => t.stores?.route_id === route.id)
          .reduce((sum: number, t: any) => sum + Number(t.total_amount), 0);
        const routePending = routeStores.reduce((sum, s) => sum + Number(s.outstanding), 0);
        return { name: route.name, totalStores, storesCovered, pctCovered, sales: routeSales, collected: routeCollected, pending: routePending };
      }).filter((r) => r.totalStores > 0);

      return {
        sales, txns, orders, saleItems, productBreakdown, staffBalances,
        storesWithOutstanding, routePerformance,
        totalSaleAmount, salesCash, salesUpi, salesOutstanding,
        totalCollections, txnCash, txnUpi,
        totalCash, totalUpi, totalIncome,
        totalItemsSold, totalOutstanding,
        salesCount: sales.length, txnCount: txns.length,
        ordersDelivered: delivered, ordersPending: pending, ordersCancelled: cancelled,
      };
    },
  });

  if (isLoading) return <TableSkeleton columns={5} rows={6} />;

  const d = data!;

  // ── Sales table columns ──
  const salesCols = [
    { header: "ID", accessor: "display_id" as const, className: "font-mono text-xs" },
    { header: "Store", accessor: (r: any) => r.stores?.name || "—", className: "font-medium" },
    { header: "Total", accessor: (r: any) => fmt(Number(r.total_amount)), className: "font-semibold" },
    { header: "Cash", accessor: (r: any) => fmt(Number(r.cash_amount)) },
    { header: "UPI", accessor: (r: any) => fmt(Number(r.upi_amount)) },
    { header: "Credit", accessor: (r: any) => fmt(Number(r.outstanding_amount)) },
    { header: "Time", accessor: (r: any) => new Date(r.created_at).toLocaleTimeString("en-IN", { hour: "2-digit", minute: "2-digit" }), className: "text-muted-foreground text-xs" },
  ];

  const txnCols = [
    { header: "ID", accessor: "display_id" as const, className: "font-mono text-xs" },
    { header: "Store", accessor: (r: any) => r.stores?.name || "—", className: "font-medium" },
    { header: "Total", accessor: (r: any) => fmt(Number(r.total_amount)), className: "font-semibold" },
    { header: "Cash", accessor: (r: any) => fmt(Number(r.cash_amount)) },
    { header: "UPI", accessor: (r: any) => fmt(Number(r.upi_amount)) },
    { header: "Time", accessor: (r: any) => new Date(r.created_at).toLocaleTimeString("en-IN", { hour: "2-digit", minute: "2-digit" }), className: "text-muted-foreground text-xs" },
  ];

  const productCols = [
    { header: "Product", accessor: "name" as const, className: "font-medium" },
    { header: "Qty", accessor: (r: any) => `${r.qty} ${r.unit}`, className: "font-semibold" },
    { header: "Revenue", accessor: (r: any) => fmt(r.revenue), className: "font-semibold" },
  ];

  const staffCols = [
    { header: "Staff", accessor: "name" as const, className: "font-medium" },
    { header: "Role", accessor: (r: any) => <Badge variant="outline" className="text-xs capitalize">{r.role.replace("_", " ")}</Badge> },
    { header: "Collected", accessor: (r: any) => fmt(r.collected), className: "font-medium" },
    { header: "Handed Over", accessor: (r: any) => fmt(r.handed_over), className: "text-success" },
    { header: "Pending", accessor: (r: any) => fmt(r.pending_handover), className: "text-warning" },
    { header: "Received", accessor: (r: any) => fmt(r.received) },
    { header: "Balance", accessor: (r: any) => fmt(r.balance), className: "font-bold" },
  ];

  // ── Export functions ──
  const generatePDF = () => {
    const dateStr = new Date(date).toLocaleDateString("en-IN", { weekday: "long", year: "numeric", month: "long", day: "numeric" });

    // Combine sales + payments into chronological list
    const chronological = [
      ...d.sales.map((s: any) => ({
        time: new Date(s.created_at).toLocaleTimeString("en-IN", { hour: "2-digit", minute: "2-digit", hour12: true }).toLowerCase(),
        type: "Sale",
        id: s.display_id,
        store: s.stores?.name || "—",
        detail: d.saleItems
          .filter((si: any) => si.sale_id === s.id)
          .map((si: any) => si.products?.name || "")
          .filter(Boolean)
          .join(", ") || "—",
        total: Number(s.total_amount),
        cash: Number(s.cash_amount),
        upi: Number(s.upi_amount),
        credit: Number(s.outstanding_amount),
        sortKey: new Date(s.created_at).getTime(),
      })),
      ...d.txns.map((t: any) => ({
        time: new Date(t.created_at).toLocaleTimeString("en-IN", { hour: "2-digit", minute: "2-digit", hour12: true }).toLowerCase(),
        type: "Payment",
        id: t.display_id,
        store: t.stores?.name || "—",
        detail: "Collection received",
        total: Number(t.total_amount),
        cash: Number(t.cash_amount),
        upi: Number(t.upi_amount),
        credit: 0,
        sortKey: new Date(t.created_at).getTime(),
      })),
    ].sort((a, b) => a.sortKey - b.sortKey);

    const html = `<!DOCTYPE html>
