        <thead><tr><th>Name</th><th>Role</th><th class="r">Collected</th><th class="r">Handed Over</th><th class="r">Received</th><th class="r">Balance</th></tr></thead>
        <tbody>
          ${d.staffBalances.length === 0
            ? '<tr><td colspan="6" class="muted" style="text-align:center">No staff activity</td></tr>'
            : d.staffBalances.map((s: any) => `<tr>
              <td><strong>${s.name}</strong></td>
              <td><span class="pill ${s.role === "agent" ? "pay" : "sale"}">${s.role.replace("_", " ")}</span></td>
              <td class="r num">${fmt(s.collected)}</td>
              <td class="r num">${fmt(s.handed_over)}</td>
              <td class="r num">${fmt(s.received)}</td>
              <td class="r ${s.balance > 0 ? "pos" : s.balance < 0 ? "neg" : "num"}">${fmt(s.balance)}</td>
            </tr>`).join("")}
        </tbody>
      </table>
    </div>
  </div>

  <div class="box">
    <div class="box-head">Sales &amp; Payments — Chronological <em>${chronological.length} entries</em></div>
    <table>
      <thead><tr>
        <th class="c" style="width:14mm">Time</th>
        <th style="width:16mm">Type</th>
        <th style="width:24mm">ID</th>
        <th>Store</th>
        <th>Product / Note</th>
        <th class="r">Total</th>
        <th class="r">Cash</th>
        <th class="r">UPI</th>
        <th class="r">Credit</th>
      </tr></thead>
      <tbody>
        ${chronological.length === 0
          ? '<tr><td colspan="9" class="muted" style="text-align:center">No entries</td></tr>'
          : chronological.map((e: any) => `<tr>
            <td class="mono c">${e.time}</td>
            <td><span class="pill ${e.type === "Sale" ? "sale" : "pay"}">${e.type}</span></td>
            <td class="mono muted">${e.id}</td>
            <td>${e.store}</td>
            <td class="muted">${e.detail}</td>
            <td class="r num">${fmt(e.total)}</td>
            <td class="r ${e.cash > 0 ? "pos" : "num"}">${fmt(e.cash)}</td>
            <td class="r ${e.upi > 0 ? "pos" : "num"}">${fmt(e.upi)}</td>
            <td class="r ${e.type === "Sale" && e.credit > 0 ? "neg" : "num"}">${e.type === "Payment" ? "—" : fmt(e.credit)}</td>
          </tr>`).join("")}
      </tbody>
    </table>
  </div>

  <div class="footer">
    <span>Generated: ${new Date().toLocaleDateString("en-IN", { day: "numeric", month: "long", year: "numeric" })} · Aqua Prime · Confidential</span>
    <span>Authorised Signature <span class="sig"></span></span>
    <span>Total Outstanding (All Stores): <strong style="color:var(--neg)">${fmt(d.totalOutstanding)}</strong> · Page 1 of 1</span>
  </div>

</div>
</body>
</html>`;

    const blob = new Blob([html], { type: "text/html" });
    const url = URL.createObjectURL(blob);
    const a = document.createElement("a");
    a.href = url;
    a.download = `daily-report-${date}.html`;
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
    URL.revokeObjectURL(url);
    toast.success("Report downloaded — open it in a browser and print to save as PDF");
  };

  const generateExcel = () => {
    const wb = XLSX.utils.book_new();

    // Summary sheet
    const summaryRows = [
      ["Daily Business Report", ""],
      ["Date", new Date(date).toLocaleDateString("en-IN")],
      ["", ""],
      ["Metric", "Value"],
      ["Total Sale Amount", d.totalSaleAmount],
      ["Total Collections", d.totalCollections],
      ["Total Income (Sales + Collections)", d.totalIncome],
      ["Cash Collected", d.totalCash],
      ["UPI Collected", d.totalUpi],
      ["Credit Given", d.salesOutstanding],
      ["Total Items Sold", d.totalItemsSold],
      ["Sales Count", d.salesCount],
      ["Payments Count", d.txnCount],
      ["Orders Delivered", d.ordersDelivered],
      ["Orders Pending", d.ordersPending],
      ["Total Outstanding", d.totalOutstanding],
    ];
    XLSX.utils.book_append_sheet(wb, XLSX.utils.aoa_to_sheet(summaryRows), "Summary");

    // Sales sheet
    if (d.sales.length > 0) {
      const salesData = d.sales.map((s: any) => ({
        "Sale ID": s.display_id, Store: s.stores?.name || "", Total: Number(s.total_amount),
        Cash: Number(s.cash_amount), UPI: Number(s.upi_amount), Credit: Number(s.outstanding_amount),
        "Old Outstanding": Number(s.old_outstanding), "New Outstanding": Number(s.new_outstanding),
        Time: new Date(s.created_at).toLocaleTimeString("en-IN"),
      }));
      XLSX.utils.book_append_sheet(wb, XLSX.utils.json_to_sheet(salesData), "Sales");
    }

    // Payments sheet
    if (d.txns.length > 0) {
      const txnData = d.txns.map((t: any) => ({
        "Payment ID": t.display_id, Store: t.stores?.name || "", Total: Number(t.total_amount),
        Cash: Number(t.cash_amount), UPI: Number(t.upi_amount),
        "Old Outstanding": Number(t.old_outstanding), "New Outstanding": Number(t.new_outstanding),
        Time: new Date(t.created_at).toLocaleTimeString("en-IN"),
      }));
      XLSX.utils.book_append_sheet(wb, XLSX.utils.json_to_sheet(txnData), "Payments");
    }

    // Products sheet
    if (d.productBreakdown.length > 0) {
      const prodData = d.productBreakdown.map((p) => ({ Product: p.name, Quantity: p.qty, Unit: p.unit, Revenue: p.revenue }));
      XLSX.utils.book_append_sheet(wb, XLSX.utils.json_to_sheet(prodData), "Products Sold");
    }

    // Staff balances sheet
    if (d.staffBalances.length > 0) {
      const staffData = d.staffBalances.map((s) => ({
        Staff: s.name, Role: s.role, Collected: s.collected, "Handed Over": s.handed_over,
        "Pending Handover": s.pending_handover, Received: s.received, Balance: s.balance,
      }));
      XLSX.utils.book_append_sheet(wb, XLSX.utils.json_to_sheet(staffData), "Staff Balances");
    }

    // Outstanding sheet
    if (d.storesWithOutstanding.length > 0) {
      const outData = d.storesWithOutstanding.map((s: any) => ({ "Store ID": s.display_id, Store: s.name, Outstanding: Number(s.outstanding) }));
      XLSX.utils.book_append_sheet(wb, XLSX.utils.json_to_sheet(outData), "Outstanding");
    }

    XLSX.writeFile(wb, `daily-report-${date}.xlsx`);
    toast.success("Excel downloaded");
  };

  return (
    <div className="space-y-6">
      {/* Date picker & export */}
      <div className="flex flex-wrap items-end gap-3">
        <div>
          <Label className="text-xs">Date</Label>
          <Input type="date" value={date} onChange={(e) => setDate(e.target.value)} className="w-44 mt-1" />
        </div>
        <Button variant="outline" size="sm" className="h-9" onClick={generatePDF}>
          <FileText className="mr-1.5 h-4 w-4" />
          Download PDF
        </Button>
        <Button variant="outline" size="sm" className="h-9" onClick={generateExcel}>
          <FileSpreadsheet className="mr-1.5 h-4 w-4" />
          Download Excel
        </Button>
      </div>

      {/* Summary stat cards */}
      <div className="grid grid-cols-2 sm:grid-cols-3 lg:grid-cols-6 gap-3">
        <StatCard title="Total Income" value={fmt(d.totalIncome)} change="Sales + Collections" changeType="positive" icon={TrendingUp} iconColor="primary" />
        <StatCard title="Sale Amount" value={fmt(d.totalSaleAmount)} change={`${d.salesCount} sales`} changeType="neutral" icon={ShoppingCart} iconColor="purple" />
        <StatCard title="Collections" value={fmt(d.totalCollections)} change={`${d.txnCount} payments`} changeType="neutral" icon={DollarSign} iconColor="success" />
        <StatCard title="Cash" value={fmt(d.totalCash)} icon={Banknote} iconColor="warning" />
        <StatCard title="UPI" value={fmt(d.totalUpi)} icon={Smartphone} iconColor="info" />
        <StatCard title="Items Sold" value={String(d.totalItemsSold)} icon={Package} iconColor="cyan" />
      </div>

      <div className="grid grid-cols-2 sm:grid-cols-4 gap-3">
        <StatCard title="Credit Given" value={fmt(d.salesOutstanding)} icon={HandCoins} iconColor="destructive" />
        <StatCard title="Total Outstanding" value={fmt(d.totalOutstanding)} icon={DollarSign} iconColor="destructive" />
        <StatCard title="Orders Delivered" value={String(d.ordersDelivered)} change={`${d.ordersPending} pending`} changeType="neutral" icon={ShoppingCart} iconColor="success" />
        <StatCard title="Orders Cancelled" value={String(d.ordersCancelled)} icon={ShoppingCart} iconColor="destructive" />
      </div>

      {/* Detailed tabs */}
      <Tabs defaultValue="sales">
        <TabsList className="flex-wrap h-auto">
          <TabsTrigger value="sales">Sales ({d.salesCount})</TabsTrigger>
          <TabsTrigger value="payments">Payments ({d.txnCount})</TabsTrigger>
          <TabsTrigger value="products">Products ({d.productBreakdown.length})</TabsTrigger>
          <TabsTrigger value="routes">Routes ({d.routePerformance.length})</TabsTrigger>
          <TabsTrigger value="staff">Staff Balances ({d.staffBalances.length})</TabsTrigger>
          <TabsTrigger value="outstanding">Outstanding ({d.storesWithOutstanding.length})</TabsTrigger>
        </TabsList>

        <TabsContent value="sales" className="mt-4">
          {d.sales.length === 0 ? (
            <Card><CardContent className="py-8 text-center text-muted-foreground">No sales recorded</CardContent></Card>
          ) : (
            <DataTable columns={salesCols} data={d.sales} searchKey="display_id" searchPlaceholder="Search sales..." />
          )}
        </TabsContent>

        <TabsContent value="payments" className="mt-4">
          {d.txns.length === 0 ? (
            <Card><CardContent className="py-8 text-center text-muted-foreground">No payments recorded</CardContent></Card>
          ) : (
            <DataTable columns={txnCols} data={d.txns} searchKey="display_id" searchPlaceholder="Search payments..." />
          )}
        </TabsContent>

        <TabsContent value="products" className="mt-4">
          {d.productBreakdown.length === 0 ? (
            <Card><CardContent className="py-8 text-center text-muted-foreground">No products sold</CardContent></Card>
          ) : (
            <DataTable columns={productCols} data={d.productBreakdown} searchKey="name" searchPlaceholder="Search products..." />
          )}
        </TabsContent>

        <TabsContent value="routes" className="mt-4">
          {d.routePerformance.length === 0 ? (
            <Card><CardContent className="py-8 text-center text-muted-foreground">No routes configured</CardContent></Card>
          ) : (
            <DataTable
              columns={[
                { header: "Route", accessor: "name" as const, className: "font-medium" },
                { header: "Total Stores", accessor: "totalStores" as const, className: "text-center" },
                { header: "Covered", accessor: (r: any) => `${r.storesCovered} / ${r.totalStores}`, className: "text-center" },
                { header: "% Done", accessor: (r: any) => (
                  <span className={r.pctCovered === 100 ? "text-success font-bold" : r.pctCovered >= 50 ? "text-warning font-semibold" : "text-destructive font-semibold"}>
                    {r.pctCovered}%
                  </span>
                ), className: "text-center" },
                { header: "Sales", accessor: (r: any) => fmt(r.sales), className: "font-semibold" },
                { header: "Collected", accessor: (r: any) => fmt(r.collected), className: "text-success" },
                { header: "Outstanding", accessor: (r: any) => fmt(r.pending), className: "text-destructive" },
              ]}
              data={d.routePerformance}
              searchKey="name"
              searchPlaceholder="Search routes..."
            />
          )}
        </TabsContent>

        <TabsContent value="staff" className="mt-4">
          {d.staffBalances.length === 0 ? (
            <Card><CardContent className="py-8 text-center text-muted-foreground">No staff activity</CardContent></Card>
          ) : (
            <>
              <Card className="mb-4 border-warning/30 bg-warning/5">
                <CardContent className="py-3 px-4 text-sm text-muted-foreground">
                  Balance = Total Collected − Handed Over − Pending Handover + Received from others
                </CardContent>
              </Card>
              <DataTable columns={staffCols} data={d.staffBalances} searchKey="name" searchPlaceholder="Search staff..." />
            </>
          )}
        </TabsContent>

        <TabsContent value="outstanding" className="mt-4">
          {d.storesWithOutstanding.length === 0 ? (
            <Card><CardContent className="py-8 text-center text-muted-foreground">No stores with outstanding</CardContent></Card>
          ) : (
            <DataTable
              columns={[
                { header: "Store ID", accessor: "display_id" as const, className: "font-mono text-xs" },
                { header: "Store", accessor: "name" as const, className: "font-medium" },
                { header: "Outstanding", accessor: (r: any) => fmt(Number(r.outstanding)), className: "font-semibold text-destructive" },
              ]}
              data={d.storesWithOutstanding}
              searchKey="name"
              searchPlaceholder="Search stores..."
            />
          )}
        </TabsContent>
      </Tabs>
    </div>
  );
}

import { useState, useMemo } from "react";
import { useQuery } from "@tanstack/react-query";
import { supabase } from "@/integrations/supabase/client";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { Loader2, ShoppingCart, CreditCard, RotateCcw, Receipt, Wallet, TrendingUp, TrendingDown } from "lucide-react";
import { format, subDays, startOfDay, endOfDay } from "date-fns";
import { ReportFilters, DateRange } from "./ReportFilters";
import { ReportExportBar } from "./ReportExportBar";
import { ReportSummaryCards } from "./ReportSummaryCards";
import jsPDF from "jspdf";
import autoTable from "jspdf-autotable";

interface DayBookEntry {
  id: string;
  type: "sale" | "payment" | "sale_return" | "purchase" | "purchase_return" | "expense" | "vendor_payment";
  display_id: string;
  date: string;
  time: string;
  description: string;
  party_name: string;
  debit: number;
  credit: number;
  balance: number;
  payment_method?: string;
  notes?: string;
}

export default function DayBookReport() {
  const [dateRange, setDateRange] = useState<DateRange>({
    from: subDays(new Date(), 0),
    to: new Date(),
  });

  // Fetch all data sources
  const { data: sales = [], isLoading: salesLoading } = useQuery({
    queryKey: ["daybook-sales", dateRange],
    queryFn: async () => {
      const { data } = await supabase
        .from("sales")
        .select("id, display_id, total_amount, cash_amount, upi_amount, notes, created_at, stores(name, customers(name))")
        .gte("created_at", format(dateRange.from, "yyyy-MM-dd"))
        .lte("created_at", format(dateRange.to, "yyyy-MM-dd") + "T23:59:59")
        .order("created_at", { ascending: true });
      return data || [];
    },
  });

  const { data: transactions = [], isLoading: txnLoading } = useQuery({
    queryKey: ["daybook-transactions", dateRange],
    queryFn: async () => {
      const { data } = await supabase
        .from("transactions")
        .select("id, display_id, transaction_date, amount, type, payment_method, notes, created_at, stores(name, customers(name))")
        .gte("transaction_date", format(dateRange.from, "yyyy-MM-dd"))
        .lte("transaction_date", format(dateRange.to, "yyyy-MM-dd"))
        .order("created_at", { ascending: true });
      return data || [];
    },
  });

  const { data: purchases = [], isLoading: purchLoading } = useQuery({
    queryKey: ["daybook-purchases", dateRange],
    queryFn: async () => {
      const { data } = await supabase
        .from("purchases")
        .select("id, display_id, purchase_date, total_amount, paid_amount, payment_method, notes, created_at, vendors(name)")
        .gte("purchase_date", format(dateRange.from, "yyyy-MM-dd"))
        .lte("purchase_date", format(dateRange.to, "yyyy-MM-dd"))
        .order("created_at", { ascending: true });
      return data || [];
    },
  });

  const { data: vendorPayments = [], isLoading: vpLoading } = useQuery({
    queryKey: ["daybook-vendor-payments", dateRange],
    queryFn: async () => {
      const { data } = await supabase
        .from("vendor_payments")
        .select("id, display_id, payment_date, amount, payment_method, notes, created_at, vendors(name)")
        .gte("payment_date", format(dateRange.from, "yyyy-MM-dd"))
        .lte("payment_date", format(dateRange.to, "yyyy-MM-dd"))
        .order("created_at", { ascending: true });
      return data || [];
    },
  });

  const { data: expenses = [], isLoading: expLoading } = useQuery({
    queryKey: ["daybook-expenses", dateRange],
    queryFn: async () => {
      const { data } = await supabase
        .from("expenses")
        .select("id, expense_date, amount, description, notes, created_at, expense_categories(name)")
        .gte("expense_date", format(dateRange.from, "yyyy-MM-dd"))
        .lte("expense_date", format(dateRange.to, "yyyy-MM-dd"))
        .order("created_at", { ascending: true });
      return data || [];
    },
  });

  const { data: saleReturns = [], isLoading: srLoading } = useQuery({
    queryKey: ["daybook-sale-returns", dateRange],
    queryFn: async () => {
      const { data } = await supabase
        .from("sale_returns")
        .select("id, display_id, return_date, total_amount, reason, created_at, stores(name, customers(name))")
        .gte("return_date", format(dateRange.from, "yyyy-MM-dd"))
        .lte("return_date", format(dateRange.to, "yyyy-MM-dd"))
        .eq("status", "completed")
        .order("created_at", { ascending: true });
      return data || [];
    },
  });

  const isLoading = salesLoading || txnLoading || purchLoading || vpLoading || expLoading || srLoading;

  // Combine and sort all entries
  const entries = useMemo(() => {
    const allEntries: DayBookEntry[] = [];
    let runningBalance = 0;

    // Sales (Credit - money coming in)
    sales.forEach((s: any) => {
      runningBalance += Number(s.total_amount);
      const cashReceived = Number(s.cash_amount || 0) + Number(s.upi_amount || 0);
      const paymentMethod = s.upi_amount > 0 && s.cash_amount > 0 ? "Mixed" : s.upi_amount > 0 ? "UPI" : "Cash";
      allEntries.push({
        id: s.id,
        type: "sale",
        display_id: s.display_id,
        date: format(new Date(s.created_at), "yyyy-MM-dd"),
        time: format(new Date(s.created_at), "HH:mm"),
        description: "Sale",
        party_name: s.stores?.customers?.name || s.stores?.name || "Walk-in",
        debit: 0,
        credit: Number(s.total_amount),
        balance: runningBalance,
        payment_method: paymentMethod,
        notes: s.notes,
      });
    });

    // Customer Payments (Credit - money coming in)
    transactions.forEach((t: any) => {
      if (t.type === "payment") {
        runningBalance += Number(t.amount);
        allEntries.push({
          id: t.id,
          type: "payment",
          display_id: t.display_id,
          date: t.transaction_date,
          time: format(new Date(t.created_at), "HH:mm"),
          description: "Payment Received",
          party_name: t.stores?.customers?.name || t.stores?.name || "Customer",
          debit: 0,
          credit: Number(t.amount),
          balance: runningBalance,
          payment_method: t.payment_method,
          notes: t.notes,
        });
      }
    });

    // Purchases (Debit - money going out / liability)
    purchases.forEach((p: any) => {
      runningBalance -= Number(p.total_amount);
      allEntries.push({
        id: p.id,
        type: "purchase",
        display_id: p.display_id,
        date: p.purchase_date,
        time: format(new Date(p.created_at), "HH:mm"),
        description: "Purchase",
        party_name: p.vendors?.name || "Vendor",
        debit: Number(p.total_amount),
        credit: 0,
        balance: runningBalance,
        payment_method: p.payment_method,
        notes: p.notes,
      });
    });

    // Vendor Payments (Debit - money going out)
    vendorPayments.forEach((vp: any) => {
      runningBalance -= Number(vp.amount);
      allEntries.push({
        id: vp.id,
        type: "vendor_payment",
        display_id: vp.display_id,
        date: vp.payment_date,
        time: format(new Date(vp.created_at), "HH:mm"),
        description: "Vendor Payment",
        party_name: vp.vendors?.name || "Vendor",
        debit: Number(vp.amount),
        credit: 0,
        balance: runningBalance,
        payment_method: vp.payment_method,
        notes: vp.notes,
      });
    });

    // Expenses (Debit - money going out)
    expenses.forEach((e: any) => {
      runningBalance -= Number(e.amount);
      allEntries.push({
        id: e.id,
        type: "expense",
        display_id: `EXP-${e.id.slice(0, 6)}`,
        date: e.expense_date,
        time: format(new Date(e.created_at), "HH:mm"),
        description: e.description || "Expense",
        party_name: e.expense_categories?.name || "Expense",
        debit: Number(e.amount),
        credit: 0,
        balance: runningBalance,
        notes: e.notes,
      });
    });

    // Sale Returns (Debit - money going back)
    saleReturns.forEach((sr: any) => {
      runningBalance -= Number(sr.total_amount);
      allEntries.push({
        id: sr.id,
        type: "sale_return",
        display_id: sr.display_id,
        date: sr.return_date,
        time: format(new Date(sr.created_at), "HH:mm"),
        description: "Sale Return",
        party_name: sr.stores?.customers?.name || sr.stores?.name || "Customer",
        debit: Number(sr.total_amount),
        credit: 0,
        balance: runningBalance,
        notes: sr.reason,
      });
    });

    // Sort by date and time
    allEntries.sort((a, b) => {
      const dateCompare = new Date(a.date).getTime() - new Date(b.date).getTime();
      if (dateCompare !== 0) return dateCompare;
      return a.time.localeCompare(b.time);
    });

    // Recalculate running balance after sorting
    let balance = 0;
    allEntries.forEach((entry) => {
      balance += entry.credit - entry.debit;
      entry.balance = balance;
    });

    return allEntries;
  }, [sales, transactions, purchases, vendorPayments, expenses, saleReturns]);

  // Calculate totals
  const totals = useMemo(() => {
    const totalCredit = entries.reduce((sum, e) => sum + e.credit, 0);
    const totalDebit = entries.reduce((sum, e) => sum + e.debit, 0);
    const netBalance = totalCredit - totalDebit;
    const totalSales = sales.reduce((sum, s: any) => sum + Number(s.total_amount), 0);
    const totalPayments = transactions.filter((t: any) => t.type === "payment").reduce((sum, t: any) => sum + Number(t.amount), 0);
    const totalPurchases = purchases.reduce((sum, p: any) => sum + Number(p.total_amount), 0);
    const totalExpenses = expenses.reduce((sum, e: any) => sum + Number(e.amount), 0);
    
    return { totalCredit, totalDebit, netBalance, totalSales, totalPayments, totalPurchases, totalExpenses };
  }, [entries, sales, transactions, purchases, expenses]);

  const getTypeIcon = (type: string) => {
    switch (type) {
      case "sale": return <ShoppingCart className="h-4 w-4 text-green-600" />;
      case "payment": return <CreditCard className="h-4 w-4 text-blue-600" />;
      case "sale_return": return <RotateCcw className="h-4 w-4 text-orange-600" />;
      case "purchase": return <Receipt className="h-4 w-4 text-purple-600" />;
      case "vendor_payment": return <Wallet className="h-4 w-4 text-red-600" />;
      case "expense": return <TrendingDown className="h-4 w-4 text-red-500" />;
      default: return null;
    }
  };

  const getTypeBadge = (type: string) => {
    const variants: Record<string, { label: string; variant: "default" | "secondary" | "destructive" | "outline" }> = {
      sale: { label: "Sale", variant: "default" },
      payment: { label: "Payment", variant: "secondary" },
      sale_return: { label: "Return", variant: "destructive" },
      purchase: { label: "Purchase", variant: "outline" },
      vendor_payment: { label: "Vendor Pay", variant: "destructive" },
      expense: { label: "Expense", variant: "destructive" },
    };
    const config = variants[type] || { label: type, variant: "secondary" };
    return <Badge variant={config.variant} className="text-xs">{config.label}</Badge>;
  };

  const exportPDF = () => {
    const doc = new jsPDF();
    doc.setFontSize(16);
    doc.text("Day Book Report", 14, 20);
    doc.setFontSize(10);
    doc.text(`${format(dateRange.from, "MMM d, yyyy")} - ${format(dateRange.to, "MMM d, yyyy")}`, 14, 28);

    autoTable(doc, {
      startY: 35,
      head: [["Date", "Time", "Type", "ID", "Party", "Description", "Debit", "Credit", "Balance"]],
      body: entries.map((e) => [
        format(new Date(e.date), "dd/MM/yy"),
        e.time,
        e.type.replace("_", " ").toUpperCase(),
        e.display_id,
        e.party_name,
        e.description,
        e.debit > 0 ? `₹${e.debit.toLocaleString()}` : "",
        e.credit > 0 ? `₹${e.credit.toLocaleString()}` : "",
        `₹${e.balance.toLocaleString()}`,
      ]),
      foot: [["", "", "", "", "", "TOTAL", `₹${totals.totalDebit.toLocaleString()}`, `₹${totals.totalCredit.toLocaleString()}`, `₹${totals.netBalance.toLocaleString()}`]],
      styles: { fontSize: 8 },
      headStyles: { fillColor: [41, 128, 185] },
      footStyles: { fillColor: [236, 240, 241], textColor: [0, 0, 0], fontStyle: "bold" },
    });

    doc.save(`daybook-${format(dateRange.from, "yyyy-MM-dd")}-${format(dateRange.to, "yyyy-MM-dd")}.pdf`);
  };

  const summaryCards = [
    { label: "Total Credits", value: `₹${totals.totalCredit.toLocaleString()}`, icon: TrendingUp, iconColor: "green" },
    { label: "Total Debits", value: `₹${totals.totalDebit.toLocaleString()}`, icon: TrendingDown, iconColor: "red" },
    { label: "Net Balance", value: `₹${totals.netBalance.toLocaleString()}`, icon: Wallet, iconColor: totals.netBalance >= 0 ? "green" : "red" },
    { label: "Transactions", value: entries.length.toString(), icon: Receipt, iconColor: "blue" },
  ];

  return (
    <div className="space-y-6">
      <div className="flex flex-col sm:flex-row sm:items-center sm:justify-between gap-4">
        <div>
          <h2 className="text-xl font-semibold">Day Book</h2>
          <p className="text-sm text-muted-foreground">Complete chronological record of all financial transactions</p>
        </div>
        <ReportExportBar onExportPDF={exportPDF} showExcel={false} showCSV={false} showPrint={false} />
      </div>

      <ReportFilters dateRange={dateRange} onDateRangeChange={setDateRange} />

      <ReportSummaryCards cards={summaryCards} />

      {isLoading ? (
        <div className="flex items-center justify-center py-12">
          <Loader2 className="h-8 w-8 animate-spin text-muted-foreground" />
        </div>
      ) : entries.length === 0 ? (
        <Card>
          <CardContent className="flex flex-col items-center justify-center py-12">
            <Receipt className="h-12 w-12 text-muted-foreground/30 mb-4" />
            <p className="text-muted-foreground">No transactions found for this period</p>
          </CardContent>
        </Card>
      ) : (
        <Card>
          <CardHeader className="pb-3">
            <CardTitle className="text-base">Transaction Ledger</CardTitle>
          </CardHeader>
          <CardContent className="p-0">
            <div className="overflow-x-auto">
              <table className="w-full">
                <thead className="bg-muted/50">
                  <tr className="text-left text-sm">
                    <th className="px-4 py-3 font-medium">Date</th>
                    <th className="px-4 py-3 font-medium">Type</th>
                    <th className="px-4 py-3 font-medium">ID</th>
                    <th className="px-4 py-3 font-medium">Party</th>
                    <th className="px-4 py-3 font-medium">Description</th>
                    <th className="px-4 py-3 font-medium text-right">Debit</th>
                    <th className="px-4 py-3 font-medium text-right">Credit</th>
                    <th className="px-4 py-3 font-medium text-right">Balance</th>
                  </tr>
                </thead>
                <tbody className="divide-y">
                  {entries.map((entry) => (
                    <tr key={`${entry.type}-${entry.id}`} className="hover:bg-muted/30 transition-colors">
                      <td className="px-4 py-3 text-sm">
                        <div className="flex flex-col">
                          <span className="font-medium">{format(new Date(entry.date), "dd MMM")}</span>
                          <span className="text-xs text-muted-foreground">{entry.time}</span>
                        </div>
                      </td>
                      <td className="px-4 py-3">
                        <div className="flex items-center gap-2">
                          {getTypeIcon(entry.type)}
                          {getTypeBadge(entry.type)}
                        </div>
                      </td>
                      <td className="px-4 py-3 text-sm font-mono text-muted-foreground">{entry.display_id}</td>
                      <td className="px-4 py-3 text-sm font-medium">{entry.party_name}</td>
                      <td className="px-4 py-3 text-sm">
                        <div className="flex flex-col">
                          <span>{entry.description}</span>
                          {entry.payment_method && (
                            <span className="text-xs text-muted-foreground capitalize">{entry.payment_method.replace("_", " ")}</span>
                          )}
                        </div>
                      </td>
                      <td className="px-4 py-3 text-sm text-right font-medium text-red-600">
                        {entry.debit > 0 ? `₹${entry.debit.toLocaleString()}` : "—"}
                      </td>
                      <td className="px-4 py-3 text-sm text-right font-medium text-green-600">
                        {entry.credit > 0 ? `₹${entry.credit.toLocaleString()}` : "—"}
                      </td>
                      <td className="px-4 py-3 text-sm text-right font-bold">
                        <span className={entry.balance >= 0 ? "text-green-600" : "text-red-600"}>
                          ₹{entry.balance.toLocaleString()}
                        </span>
                      </td>
                    </tr>
                  ))}
                </tbody>
                <tfoot className="bg-muted/70 font-semibold">
                  <tr>
                    <td colSpan={5} className="px-4 py-3 text-right">TOTAL</td>
                    <td className="px-4 py-3 text-right text-red-600">₹{totals.totalDebit.toLocaleString()}</td>
                    <td className="px-4 py-3 text-right text-green-600">₹{totals.totalCredit.toLocaleString()}</td>
                    <td className="px-4 py-3 text-right">
                      <span className={totals.netBalance >= 0 ? "text-green-600" : "text-red-600"}>
                        ₹{totals.netBalance.toLocaleString()}
                      </span>
                    </td>
                  </tr>
                </tfoot>
              </table>
            </div>
          </CardContent>
        </Card>
      )}
    </div>
  );
}

import { useState, useMemo } from "react";
import { useQuery } from "@tanstack/react-query";
import { supabase } from "@/integrations/supabase/client";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { Input } from "@/components/ui/input";
import { Loader2, Package, ArrowUpRight, ArrowDownRight, TrendingUp, TrendingDown, Search, History, RotateCcw } from "lucide-react";
import { format, subMonths, startOfMonth, eachDayOfInterval, eachWeekOfInterval, isSameDay, isSameWeek } from "date-fns";
import { ReportFilters, DateRange } from "./ReportFilters";
import { ReportExportBar } from "./ReportExportBar";
import { ReportSummaryCards } from "./ReportSummaryCards";
import { AreaChart, Area, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, Legend, BarChart, Bar } from "recharts";
import jsPDF from "jspdf";
import autoTable from "jspdf-autotable";
import * as XLSX from "xlsx";

interface StockMovement {
  id: string;
  date: string;
  type: "sale" | "purchase" | "return" | "adjustment" | "transfer";
  direction: "in" | "out";
  product_id: string;
  product_name: string;
  quantity: number;
  warehouse_name: string;
  reference_id: string;
  notes?: string;
}

type GroupBy = "day" | "week";

export default function InventoryTimelineReport() {
  const [dateRange, setDateRange] = useState<DateRange>({
    from: startOfMonth(subMonths(new Date(), 1)),
    to: new Date(),
  });
  const [search, setSearch] = useState("");
  const [groupBy, setGroupBy] = useState<GroupBy>("day");
  const [typeFilter, setTypeFilter] = useState<"all" | "in" | "out">("all");

  // Fetch sale items (stock out)
  const { data: saleItems = [], isLoading: saleLoading } = useQuery({
    queryKey: ["inventory-timeline-sales", dateRange],
    queryFn: async () => {
      // First get sales in date range
      const { data: salesInRange } = await supabase
        .from("sales")
        .select("id, display_id, created_at")
        .gte("created_at", format(dateRange.from, "yyyy-MM-dd"))
        .lte("created_at", format(dateRange.to, "yyyy-MM-dd") + "T23:59:59");
      
      if (!salesInRange || salesInRange.length === 0) return [];
      
      const saleIds = salesInRange.map((s: any) => s.id);
      
      const { data } = await supabase
        .from("sale_items")
        .select("id, product_id, quantity, sale_id, products(name)")
        .in("sale_id", saleIds);
      
      // Attach sale info
      return (data || []).map((si: any) => ({
        ...si,
        sales: salesInRange.find((s: any) => s.id === si.sale_id)
      }));
    },
  });

  // Fetch purchase items (stock in)
  const { data: purchaseItems = [], isLoading: purchLoading } = useQuery({
    queryKey: ["inventory-timeline-purchases", dateRange],
    queryFn: async () => {
      const { data } = await supabase
        .from("purchase_items")
        .select("id, item_type, item_id, quantity, purchases(display_id, purchase_date, warehouses(name)), products(name)")
        .eq("item_type", "product")
        .gte("purchases.purchase_date", format(dateRange.from, "yyyy-MM-dd"))
        .lte("purchases.purchase_date", format(dateRange.to, "yyyy-MM-dd"));
      return (data || []).filter((p: any) => p.purchases);
    },
  });

  // Fetch sale return items (stock in)
  const { data: saleReturnItems = [], isLoading: srLoading } = useQuery({
    queryKey: ["inventory-timeline-sale-returns", dateRange],
    queryFn: async () => {
      const { data } = await supabase
        .from("sale_return_items")
        .select("id, product_id, quantity, sale_returns(display_id, return_date, status), products(name)")
        .eq("sale_returns.status", "completed")
        .gte("sale_returns.return_date", format(dateRange.from, "yyyy-MM-dd"))
        .lte("sale_returns.return_date", format(dateRange.to, "yyyy-MM-dd"));
      return (data || []).filter((r: any) => r.sale_returns);
    },
  });

  // Fetch purchase return items (stock out)
  const { data: purchReturnItems = [], isLoading: prLoading } = useQuery({
    queryKey: ["inventory-timeline-purchase-returns", dateRange],
    queryFn: async () => {
      const { data } = await supabase
        .from("purchase_return_items")
        .select("id, item_type, item_id, quantity, purchase_returns(display_id, return_date, status), products(name)")
        .eq("purchase_returns.status", "completed")
        .eq("item_type", "product")
        .gte("purchase_returns.return_date", format(dateRange.from, "yyyy-MM-dd"))
        .lte("purchase_returns.return_date", format(dateRange.to, "yyyy-MM-dd"));
      return (data || []).filter((r: any) => r.purchase_returns);
    },
  });

  const isLoading = saleLoading || purchLoading || srLoading || prLoading;

  // Combine all movements
  const allMovements = useMemo(() => {
    const movements: StockMovement[] = [];

    // Sales (out)
    saleItems.forEach((si: any) => {
      movements.push({
        id: si.id,
        date: si.sales?.created_at ? format(new Date(si.sales.created_at), "yyyy-MM-dd") : format(new Date(), "yyyy-MM-dd"),
        type: "sale",
        direction: "out",
        product_id: si.product_id,
        product_name: si.products?.name || "Unknown",
        quantity: Number(si.quantity),
        warehouse_name: "Default",
        reference_id: si.sales?.display_id || "N/A",
      });
    });

    // Purchases (in)
    purchaseItems.forEach((pi: any) => {
      movements.push({
        id: pi.id,
        date: pi.purchases.purchase_date,
        type: "purchase",
        direction: "in",
        product_id: pi.item_id,
        product_name: pi.products?.name || "Unknown",
        quantity: Number(pi.quantity),
        warehouse_name: pi.purchases.warehouses?.name || "Default",
        reference_id: pi.purchases.display_id,
      });
    });

    // Sale returns (in)
    saleReturnItems.forEach((sri: any) => {
      movements.push({
        id: sri.id,
        date: sri.sale_returns.return_date,
        type: "return",
        direction: "in",
        product_id: sri.product_id,
        product_name: sri.products?.name || "Unknown",
        quantity: Number(sri.quantity),
        warehouse_name: "Default",
        reference_id: sri.sale_returns.display_id,
      });
    });

    // Purchase returns (out)
    purchReturnItems.forEach((pri: any) => {
      movements.push({
        id: pri.id,
        date: pri.purchase_returns.return_date,
        type: "return",
        direction: "out",
        product_id: pri.item_id,
        product_name: pri.products?.name || "Unknown",
        quantity: Number(pri.quantity),
        warehouse_name: "Default",
        reference_id: pri.purchase_returns.display_id,
      });
    });

    return movements.sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());
  }, [saleItems, purchaseItems, saleReturnItems, purchReturnItems]);

  // Filter movements
  const filteredMovements = useMemo(() => {
    let filtered = allMovements;

    if (search) {
      const s = search.toLowerCase();
      filtered = filtered.filter(m => 
        m.product_name.toLowerCase().includes(s) ||
        m.reference_id.toLowerCase().includes(s)
      );
    }

    if (typeFilter === "in") {
      filtered = filtered.filter(m => m.direction === "in");
    } else if (typeFilter === "out") {
      filtered = filtered.filter(m => m.direction === "out");
    }

    return filtered;
  }, [allMovements, search, typeFilter]);

  // Summary
  const summary = useMemo(() => {
    const totalIn = filteredMovements.filter(m => m.direction === "in").reduce((sum, m) => sum + m.quantity, 0);
    const totalOut = filteredMovements.filter(m => m.direction === "out").reduce((sum, m) => sum + m.quantity, 0);
    const netChange = totalIn - totalOut;
    const totalMovements = filteredMovements.length;
    const uniqueProducts = new Set(filteredMovements.map(m => m.product_id)).size;

    return { totalIn, totalOut, netChange, totalMovements, uniqueProducts };
  }, [filteredMovements]);

  // Time series data
  const timeSeriesData = useMemo(() => {
    const intervals = groupBy === "week" 
      ? eachWeekOfInterval({ start: dateRange.from, end: dateRange.to })
      : eachDayOfInterval({ start: dateRange.from, end: dateRange.to });
    
    const isSamePeriod = groupBy === "week" ? isSameWeek : isSameDay;
    const formatStr = groupBy === "week" ? "MMM d" : "MMM d";

    return intervals.map(date => {
      const periodMovements = filteredMovements.filter(m => isSamePeriod(new Date(m.date), date));
      const stockIn = periodMovements.filter(m => m.direction === "in").reduce((sum, m) => sum + m.quantity, 0);
      const stockOut = periodMovements.filter(m => m.direction === "out").reduce((sum, m) => sum + m.quantity, 0);

      return {
        date: format(date, formatStr),
        stockIn,
        stockOut,
        net: stockIn - stockOut,
      };
    });
  }, [filteredMovements, dateRange, groupBy]);

  // Movement type breakdown
  const typeBreakdown = useMemo(() => {
    const byType: Record<string, { in: number; out: number }> = {};
    
    filteredMovements.forEach(m => {
      const key = m.type;
      if (!byType[key]) byType[key] = { in: 0, out: 0 };
      if (m.direction === "in") {
        byType[key].in += m.quantity;
      } else {
        byType[key].out += m.quantity;
      }
    });

    return Object.entries(byType).map(([type, data]) => ({
      type: type.charAt(0).toUpperCase() + type.slice(1),
      in: data.in,
      out: data.out,
    }));
  }, [filteredMovements]);

  const summaryCards = [
    { label: "Stock In", value: summary.totalIn.toLocaleString(), icon: ArrowUpRight, iconColor: "green" as const },
    { label: "Stock Out", value: summary.totalOut.toLocaleString(), icon: ArrowDownRight, iconColor: "red" as const },
    { label: "Net Change", value: (summary.netChange >= 0 ? "+" : "") + summary.netChange.toLocaleString(), icon: summary.netChange >= 0 ? TrendingUp : TrendingDown, iconColor: summary.netChange >= 0 ? "blue" as const : "yellow" as const },
    { label: "Products Moved", value: summary.uniqueProducts.toString(), icon: Package, iconColor: "purple" as const },
  ];

  const exportPDF = () => {
    const doc = new jsPDF();
    doc.setFontSize(16);
    doc.text("Inventory Timeline Report", 14, 15);
    doc.setFontSize(10);
    doc.text(`Period: ${format(dateRange.from, "MMM d, yyyy")} - ${format(dateRange.to, "MMM d, yyyy")}`, 14, 23);

    autoTable(doc, {
      startY: 30,
      head: [["Date", "Type", "Direction", "Product", "Quantity", "Reference"]],
      body: filteredMovements.slice(0, 200).map(m => [
        format(new Date(m.date), "dd/MM/yy"),
        m.type,
        m.direction.toUpperCase(),
        m.product_name,
        m.quantity.toString(),
        m.reference_id,
      ]),
      styles: { fontSize: 8 },
      headStyles: { fillColor: [59, 130, 246] },
    });

    doc.save(`inventory-timeline-${format(dateRange.from, "yyyyMMdd")}-${format(dateRange.to, "yyyyMMdd")}.pdf`);
  };

  const exportExcel = () => {
    const ws = XLSX.utils.json_to_sheet(filteredMovements.map(m => ({
      "Date": m.date,
      "Type": m.type,
      "Direction": m.direction,
      "Product": m.product_name,
      "Quantity": m.quantity,
      "Warehouse": m.warehouse_name,
      "Reference": m.reference_id,
    })));
    const wb = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(wb, ws, "Movements");
    XLSX.writeFile(wb, `inventory-timeline-${format(dateRange.from, "yyyyMMdd")}-${format(dateRange.to, "yyyyMMdd")}.xlsx`);
  };

  return (
    <div className="space-y-6">
      <div className="flex flex-col lg:flex-row lg:items-end gap-4">
        <ReportFilters dateRange={dateRange} onDateRangeChange={setDateRange} />
        <div className="relative flex-1 max-w-xs">
          <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-muted-foreground" />
          <Input
            placeholder="Search products..."
            value={search}
            onChange={(e) => setSearch(e.target.value)}
            className="pl-9"
          />
        </div>
        <div className="flex gap-2">
          <Badge 
            variant={groupBy === "day" ? "default" : "outline"} 
            className="cursor-pointer"
            onClick={() => setGroupBy("day")}
          >
            Daily
          </Badge>
          <Badge 
            variant={groupBy === "week" ? "default" : "outline"} 
            className="cursor-pointer"
            onClick={() => setGroupBy("week")}
          >
            Weekly
          </Badge>
        </div>
        <div className="flex gap-2">
          <Badge 
            variant={typeFilter === "all" ? "default" : "outline"} 
            className="cursor-pointer"
            onClick={() => setTypeFilter("all")}
          >
            All
          </Badge>
          <Badge 
            variant={typeFilter === "in" ? "default" : "outline"} 
            className="cursor-pointer"
            onClick={() => setTypeFilter("in")}
          >
            <ArrowUpRight className="h-3 w-3 mr-1" />In
          </Badge>
          <Badge 
            variant={typeFilter === "out" ? "default" : "outline"} 
            className="cursor-pointer"
            onClick={() => setTypeFilter("out")}
          >
            <ArrowDownRight className="h-3 w-3 mr-1" />Out
          </Badge>
        </div>
      </div>

      <ReportExportBar onExportPDF={exportPDF} onExportExcel={exportExcel} />

      {isLoading ? (
        <div className="flex items-center justify-center py-12">
          <Loader2 className="h-8 w-8 animate-spin text-muted-foreground" />
        </div>
      ) : (
        <>
          <ReportSummaryCards cards={summaryCards} />

          {/* Timeline Chart */}
          <Card>
            <CardHeader>
              <CardTitle className="text-base">Stock Movement Timeline</CardTitle>
            </CardHeader>
            <CardContent>
              <ResponsiveContainer width="100%" height={300}>
                <AreaChart data={timeSeriesData}>
                  <CartesianGrid strokeDasharray="3 3" />
                  <XAxis dataKey="date" tick={{ fontSize: 11 }} interval={Math.floor(timeSeriesData.length / 10)} />
                  <YAxis />
                  <Tooltip />
                  <Legend />
                  <Area type="monotone" dataKey="stockIn" name="Stock In" stroke="#10b981" fill="#10b98133" stackId="1" />
                  <Area type="monotone" dataKey="stockOut" name="Stock Out" stroke="#ef4444" fill="#ef444433" stackId="2" />
                </AreaChart>
              </ResponsiveContainer>
            </CardContent>
          </Card>

          {/* Type Breakdown */}
          <Card>
            <CardHeader>
              <CardTitle className="text-base">Movement by Type</CardTitle>
            </CardHeader>
            <CardContent>
              {typeBreakdown.length > 0 ? (
                <ResponsiveContainer width="100%" height={200}>
                  <BarChart data={typeBreakdown} layout="vertical">
                    <CartesianGrid strokeDasharray="3 3" />
                    <XAxis type="number" />
                    <YAxis type="category" dataKey="type" width={80} />
                    <Tooltip />
                    <Legend />
                    <Bar dataKey="in" name="Stock In" fill="#10b981" />
                    <Bar dataKey="out" name="Stock Out" fill="#ef4444" />
                  </BarChart>
                </ResponsiveContainer>
              ) : (
                <p className="text-center text-muted-foreground py-8">No movement data</p>
              )}
            </CardContent>
          </Card>

          {/* Movement List */}
          <Card>
            <CardHeader>
              <CardTitle className="text-base">Recent Movements ({filteredMovements.length})</CardTitle>
            </CardHeader>
            <CardContent>
              {filteredMovements.length === 0 ? (
                <p className="text-center text-muted-foreground py-12">No stock movements found</p>
              ) : (
                <div className="overflow-x-auto">
                  <table className="w-full text-sm">
                    <thead>
                      <tr className="border-b bg-muted/50">
                        <th className="text-left p-3 font-medium">Date</th>
                        <th className="text-left p-3 font-medium">Product</th>
                        <th className="text-center p-3 font-medium">Type</th>
                        <th className="text-right p-3 font-medium">Quantity</th>
                        <th className="text-left p-3 font-medium hidden md:table-cell">Reference</th>
                      </tr>
                    </thead>
                    <tbody>
                      {filteredMovements.slice(0, 100).map((m) => (
                        <tr key={m.id + m.type} className="border-b hover:bg-muted/30">
                          <td className="p-3 text-muted-foreground text-xs">
                            {format(new Date(m.date), "dd/MM/yy")}
                          </td>
                          <td className="p-3 font-medium">{m.product_name}</td>
                          <td className="p-3 text-center">
                            <Badge variant={m.direction === "in" ? "default" : "secondary"} className="text-xs">
                              {m.direction === "in" ? (
                                <ArrowUpRight className="h-3 w-3 mr-1" />
                              ) : (
                                <ArrowDownRight className="h-3 w-3 mr-1" />
                              )}
                              {m.type}
                            </Badge>
                          </td>
                          <td className="p-3 text-right">
                            <span className={m.direction === "in" ? "text-green-600 font-semibold" : "text-red-600 font-semibold"}>
                              {m.direction === "in" ? "+" : "-"}{m.quantity}
                            </span>
                          </td>
                          <td className="p-3 hidden md:table-cell text-muted-foreground font-mono text-xs">
                            {m.reference_id}
                          </td>
                        </tr>
                      ))}
                    </tbody>
                  </table>
                </div>
              )}
              {filteredMovements.length > 100 && (
                <p className="text-center text-muted-foreground mt-4 text-sm">
                  Showing 100 of {filteredMovements.length} movements. Export to see all.
                </p>
              )}
            </CardContent>
          </Card>
        </>
      )}
    </div>
  );
}

import { useState, useMemo } from "react";
import { useQuery } from "@tanstack/react-query";
import { supabase } from "@/integrations/supabase/client";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { Input } from "@/components/ui/input";
import { Loader2, Package, TrendingUp, TrendingDown, DollarSign, Search, ArrowUpRight, ArrowDownRight } from "lucide-react";
import { format, subMonths, startOfMonth } from "date-fns";
import { ReportFilters, DateRange } from "./ReportFilters";
import { ReportExportBar } from "./ReportExportBar";
import { ReportSummaryCards } from "./ReportSummaryCards";
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, PieChart, Pie, Cell, Legend } from "recharts";
import jsPDF from "jspdf";
import autoTable from "jspdf-autotable";
import * as XLSX from "xlsx";

const COLORS = ["#10b981", "#3b82f6", "#f59e0b", "#ef4444", "#8b5cf6", "#ec4899", "#06b6d4", "#84cc16"];

interface ProductPL {
  id: string;
  name: string;
  display_id: string;
  category: string;
  mrp: number;
  gst_rate: number;
  quantitySold: number;
  revenue: number;
  costPrice: number;
  cogs: number;
  grossProfit: number;
  grossMargin: number;
  quantityReturned: number;
  returnValue: number;
  netProfit: number;
}

export default function ItemWisePLReport() {
  const [dateRange, setDateRange] = useState<DateRange>({
    from: startOfMonth(subMonths(new Date(), 1)),
    to: new Date(),
  });
  const [search, setSearch] = useState("");
  const [sortBy, setSortBy] = useState<"revenue" | "profit" | "margin">("profit");

  // Fetch products
  const { data: products = [], isLoading: prodLoading } = useQuery({
    queryKey: ["itemwise-pl-products"],
    queryFn: async () => {
      const { data } = await supabase
        .from("products")
        .select("id, name, display_id, mrp, gst_rate, product_categories(name)")
        .eq("is_active", true)
        .order("name");
      return data || [];
    },
  });

  // Fetch sale items in date range
  const { data: saleItems = [], isLoading: saleLoading } = useQuery({
    queryKey: ["itemwise-pl-sales", dateRange],
    queryFn: async () => {
      // First get sales in date range
      const { data: salesInRange } = await supabase
        .from("sales")
        .select("id")
        .gte("created_at", format(dateRange.from, "yyyy-MM-dd"))
        .lte("created_at", format(dateRange.to, "yyyy-MM-dd") + "T23:59:59");
      
      if (!salesInRange || salesInRange.length === 0) return [];
      
      const saleIds = salesInRange.map((s: any) => s.id);
      
      const { data } = await supabase
        .from("sale_items")
        .select("id, product_id, quantity, unit_price, total, sale_id")
        .in("sale_id", saleIds);
      return data || [];
    },
  });

  // Fetch purchase items for cost calculation
  const { data: purchaseItems = [], isLoading: purchLoading } = useQuery({
    queryKey: ["itemwise-pl-purchases", dateRange],
    queryFn: async () => {
      const { data } = await supabase
        .from("purchase_items")
        .select("id, item_type, item_id, quantity, unit_price, total, purchases(purchase_date)")
        .eq("item_type", "product")
        .gte("purchases.purchase_date", format(dateRange.from, "yyyy-MM-dd"))
        .lte("purchases.purchase_date", format(dateRange.to, "yyyy-MM-dd"));
      return (data || []).filter((p: any) => p.purchases);
    },
  });

  // Fetch sale returns
  const { data: returnItems = [], isLoading: retLoading } = useQuery({
    queryKey: ["itemwise-pl-returns", dateRange],
    queryFn: async () => {
      const { data } = await supabase
        .from("sale_return_items")
        .select("id, product_id, quantity, unit_price, total, sale_returns(return_date, status)")
        .eq("sale_returns.status", "completed")
        .gte("sale_returns.return_date", format(dateRange.from, "yyyy-MM-dd"))
        .lte("sale_returns.return_date", format(dateRange.to, "yyyy-MM-dd"));
      return (data || []).filter((r: any) => r.sale_returns);
    },
  });

  const isLoading = prodLoading || saleLoading || purchLoading || retLoading;

  // Calculate item-wise P&L
  const productPL = useMemo(() => {
    // Calculate average cost price per product
    const avgCostByProduct: Record<string, number> = {};
    purchaseItems.forEach((pi: any) => {
      if (pi.item_id) {
        if (!avgCostByProduct[pi.item_id]) {
          avgCostByProduct[pi.item_id] = { total: 0, qty: 0 };
        }
        avgCostByProduct[pi.item_id].total += Number(pi.total);
        avgCostByProduct[pi.item_id].qty += Number(pi.quantity);
      }
    });

    return products.map((p: any) => {
      // Sales data
      const productSales = saleItems.filter((si: any) => si.product_id === p.id);
      const quantitySold = productSales.reduce((sum: number, si: any) => sum + Number(si.quantity), 0);
      const revenue = productSales.reduce((sum: number, si: any) => sum + Number(si.total), 0);

      // Cost data - use purchase avg or estimate from MRP
      const avgCostData = avgCostByProduct[p.id];
      const costPrice = avgCostData 
        ? avgCostData.total / avgCostData.qty 
        : Number(p.mrp) * 0.7; // Estimate 30% margin if no purchase data
      const cogs = quantitySold * costPrice;

      // Returns
      const productReturns = returnItems.filter((ri: any) => ri.product_id === p.id);
      const quantityReturned = productReturns.reduce((sum: number, ri: any) => sum + Number(ri.quantity), 0);
      const returnValue = productReturns.reduce((sum: number, ri: any) => sum + Number(ri.total), 0);

      // Profit calculations
      const grossProfit = revenue - cogs;
      const grossMargin = revenue > 0 ? (grossProfit / revenue) * 100 : 0;
      const netProfit = grossProfit - returnValue;

      return {
        id: p.id,
        name: p.name,
        display_id: p.display_id,
        category: p.product_categories?.name || "Uncategorized",
        mrp: Number(p.mrp),
        gst_rate: Number(p.gst_rate),
        quantitySold,
        revenue,
        costPrice,
        cogs,
        grossProfit,
        grossMargin,
        quantityReturned,
        returnValue,
        netProfit,
      };
    }).filter((p: ProductPL) => p.quantitySold > 0 || p.quantityReturned > 0);
  }, [products, saleItems, purchaseItems, returnItems]);

  // Filter and sort
  const filteredProducts = useMemo(() => {
    let filtered = productPL;
    if (search) {
      const s = search.toLowerCase();
      filtered = filtered.filter((p: ProductPL) => 
        p.name.toLowerCase().includes(s) || 
        p.display_id?.toLowerCase().includes(s) ||
        p.category.toLowerCase().includes(s)
      );
    }

    // Sort
    return [...filtered].sort((a, b) => {
      switch (sortBy) {
        case "revenue": return b.revenue - a.revenue;
        case "profit": return b.netProfit - a.netProfit;
        case "margin": return b.grossMargin - a.grossMargin;
        default: return 0;
      }
    });
  }, [productPL, search, sortBy]);

  // Summary
  const summary = useMemo(() => {
    const totalRevenue = filteredProducts.reduce((sum, p) => sum + p.revenue, 0);
    const totalCOGS = filteredProducts.reduce((sum, p) => sum + p.cogs, 0);
    const totalGrossProfit = filteredProducts.reduce((sum, p) => sum + p.grossProfit, 0);
    const totalReturns = filteredProducts.reduce((sum, p) => sum + p.returnValue, 0);
    const totalNetProfit = filteredProducts.reduce((sum, p) => sum + p.netProfit, 0);
    const avgMargin = totalRevenue > 0 ? (totalGrossProfit / totalRevenue) * 100 : 0;

    return { totalRevenue, totalCOGS, totalGrossProfit, totalReturns, totalNetProfit, avgMargin };
  }, [filteredProducts]);

  // Charts
  const topProfitChart = useMemo(() => {
    return [...filteredProducts]
      .sort((a, b) => b.netProfit - a.netProfit)
      .slice(0, 10)
      .map(p => ({
        name: p.name.length > 15 ? p.name.substring(0, 15) + "..." : p.name,
        profit: p.netProfit,
        revenue: p.revenue,
      }));
  }, [filteredProducts]);

  const categoryProfitChart = useMemo(() => {
    const byCategory: Record<string, number> = {};
    filteredProducts.forEach(p => {
      byCategory[p.category] = (byCategory[p.category] || 0) + p.netProfit;
    });
    return Object.entries(byCategory)
      .filter(([_, v]) => v > 0)
      .sort((a, b) => b[1] - a[1])
      .slice(0, 8)
      .map(([name, value]) => ({ name, value }));
  }, [filteredProducts]);

  const summaryCards = [
    { label: "Total Revenue", value: `₹${summary.totalRevenue.toLocaleString()}`, icon: DollarSign, iconColor: "blue" },
    { label: "Total COGS", value: `₹${summary.totalCOGS.toLocaleString()}`, icon: Package, iconColor: "yellow" },
    { label: "Gross Profit", value: `₹${summary.totalGrossProfit.toLocaleString()}`, icon: TrendingUp, iconColor: "green" },
    { label: "Avg Margin", value: `${summary.avgMargin.toFixed(1)}%`, icon: summary.avgMargin > 20 ? ArrowUpRight : ArrowDownRight, iconColor: summary.avgMargin > 20 ? "green" : "red" },
  ];

  const exportPDF = () => {
    const doc = new jsPDF({ orientation: "landscape" });
    doc.setFontSize(16);
    doc.text("Item-wise Profit & Loss Report", 14, 15);
    doc.setFontSize(10);
    doc.text(`Period: ${format(dateRange.from, "MMM d, yyyy")} - ${format(dateRange.to, "MMM d, yyyy")}`, 14, 23);

    autoTable(doc, {
      startY: 30,
      head: [["Product", "Category", "Qty Sold", "Revenue", "COGS", "Gross Profit", "Margin %", "Returns", "Net Profit"]],
      body: filteredProducts.map(p => [
        p.name,
        p.category,
        p.quantitySold.toString(),
        `₹${p.revenue.toLocaleString()}`,
        `₹${p.cogs.toLocaleString()}`,
        `₹${p.grossProfit.toLocaleString()}`,
        `${p.grossMargin.toFixed(1)}%`,
        `₹${p.returnValue.toLocaleString()}`,
        `₹${p.netProfit.toLocaleString()}`,
      ]),
      foot: [[
        "TOTAL", "", "",
        `₹${summary.totalRevenue.toLocaleString()}`,
        `₹${summary.totalCOGS.toLocaleString()}`,
        `₹${summary.totalGrossProfit.toLocaleString()}`,
        `${summary.avgMargin.toFixed(1)}%`,
        `₹${summary.totalReturns.toLocaleString()}`,
        `₹${summary.totalNetProfit.toLocaleString()}`,
      ]],
      styles: { fontSize: 8 },
      headStyles: { fillColor: [59, 130, 246] },
      footStyles: { fillColor: [229, 231, 235], textColor: [0, 0, 0], fontStyle: "bold" },
    });

    doc.save(`item-pl-report-${format(dateRange.from, "yyyyMMdd")}-${format(dateRange.to, "yyyyMMdd")}.pdf`);
  };

  const exportExcel = () => {
    const ws = XLSX.utils.json_to_sheet(filteredProducts.map(p => ({
      "Product ID": p.display_id,
      "Product Name": p.name,
      "Category": p.category,
      "MRP": p.mrp,
      "GST Rate": p.gst_rate,
      "Qty Sold": p.quantitySold,
      "Revenue": p.revenue,
      "Cost Price": p.costPrice.toFixed(2),
      "COGS": p.cogs,
      "Gross Profit": p.grossProfit,
      "Gross Margin %": p.grossMargin.toFixed(2),
      "Qty Returned": p.quantityReturned,
      "Return Value": p.returnValue,
      "Net Profit": p.netProfit,
    })));
    const wb = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(wb, ws, "Item P&L");
    XLSX.writeFile(wb, `item-pl-report-${format(dateRange.from, "yyyyMMdd")}-${format(dateRange.to, "yyyyMMdd")}.xlsx`);
  };

  return (
    <div className="space-y-6">
      <div className="flex flex-col lg:flex-row lg:items-end gap-4">
        <ReportFilters dateRange={dateRange} onDateRangeChange={setDateRange} />
        <div className="relative flex-1 max-w-xs">
          <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-muted-foreground" />
          <Input
            placeholder="Search products..."
            value={search}
            onChange={(e) => setSearch(e.target.value)}
            className="pl-9"
          />
        </div>
        <div className="flex gap-2">
          <Badge 
            variant={sortBy === "profit" ? "default" : "outline"} 
            className="cursor-pointer"
            onClick={() => setSortBy("profit")}
          >
            By Profit
          </Badge>
          <Badge 
            variant={sortBy === "revenue" ? "default" : "outline"} 
            className="cursor-pointer"
            onClick={() => setSortBy("revenue")}
          >
            By Revenue
          </Badge>
          <Badge 
            variant={sortBy === "margin" ? "default" : "outline"} 
            className="cursor-pointer"
            onClick={() => setSortBy("margin")}
          >
            By Margin
          </Badge>
        </div>
      </div>

      <ReportExportBar onExportPDF={exportPDF} onExportExcel={exportExcel} />

      {isLoading ? (
        <div className="flex items-center justify-center py-12">
          <Loader2 className="h-8 w-8 animate-spin text-muted-foreground" />
        </div>
      ) : (
        <>
          <ReportSummaryCards cards={summaryCards} />

          {/* Charts */}
          <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
            {/* Top Products by Profit */}
            <Card>
              <CardHeader>
                <CardTitle className="text-base">Top Products by Profit</CardTitle>
              </CardHeader>
              <CardContent>
                {topProfitChart.length > 0 ? (
                  <ResponsiveContainer width="100%" height={300}>
                    <BarChart data={topProfitChart} layout="vertical">
                      <CartesianGrid strokeDasharray="3 3" />
                      <XAxis type="number" tickFormatter={(v) => `₹${(v/1000).toFixed(0)}k`} />
                      <YAxis type="category" dataKey="name" width={100} tick={{ fontSize: 11 }} />
                      <Tooltip formatter={(v: number) => `₹${v.toLocaleString()}`} />
                      <Legend />
                      <Bar dataKey="profit" name="Net Profit" fill="#10b981" />
                      <Bar dataKey="revenue" name="Revenue" fill="#3b82f6" />
                    </BarChart>
                  </ResponsiveContainer>
                ) : (
                  <p className="text-center text-muted-foreground py-12">No data available</p>
                )}
              </CardContent>
            </Card>

            {/* Category Profit Distribution */}
            <Card>
              <CardHeader>
                <CardTitle className="text-base">Profit by Category</CardTitle>
              </CardHeader>
              <CardContent>
                {categoryProfitChart.length > 0 ? (
                  <ResponsiveContainer width="100%" height={300}>
                    <PieChart>
                      <Pie
                        data={categoryProfitChart}
                        cx="50%"
                        cy="50%"
                        labelLine={false}
                        label={({ name, percent }) => `${name} (${(percent * 100).toFixed(0)}%)`}
                        outerRadius={100}
                        fill="#8884d8"
                        dataKey="value"
                      >
                        {categoryProfitChart.map((_, index) => (
                          <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} />
                        ))}
                      </Pie>
                      <Tooltip formatter={(v: number) => `₹${v.toLocaleString()}`} />
                    </PieChart>
                  </ResponsiveContainer>
                ) : (
                  <p className="text-center text-muted-foreground py-12">No category data</p>
                )}
              </CardContent>
            </Card>
          </div>

          {/* Product Table */}
          <Card>
            <CardHeader>
              <CardTitle className="text-base">Product Details ({filteredProducts.length} items)</CardTitle>
            </CardHeader>
            <CardContent>
              <div className="overflow-x-auto">
                <table className="w-full text-sm">
                  <thead>
                    <tr className="border-b bg-muted/50">
                      <th className="text-left p-3 font-medium">Product</th>
                      <th className="text-left p-3 font-medium hidden md:table-cell">Category</th>
                      <th className="text-right p-3 font-medium">Qty</th>
                      <th className="text-right p-3 font-medium">Revenue</th>
                      <th className="text-right p-3 font-medium hidden lg:table-cell">COGS</th>
                      <th className="text-right p-3 font-medium">Profit</th>
                      <th className="text-right p-3 font-medium">Margin</th>
                    </tr>
                  </thead>
                  <tbody>
                    {filteredProducts.slice(0, 50).map((p) => (
                      <tr key={p.id} className="border-b hover:bg-muted/30">
                        <td className="p-3">
                          <p className="font-medium">{p.name}</p>
                          <p className="text-xs text-muted-foreground">{p.display_id}</p>
                        </td>
                        <td className="p-3 hidden md:table-cell text-muted-foreground">{p.category}</td>
                        <td className="p-3 text-right">{p.quantitySold}</td>
                        <td className="p-3 text-right font-medium">₹{p.revenue.toLocaleString()}</td>
                        <td className="p-3 text-right hidden lg:table-cell text-muted-foreground">₹{p.cogs.toLocaleString()}</td>
                        <td className="p-3 text-right">
                          <span className={p.netProfit >= 0 ? "text-green-600 font-semibold" : "text-red-600 font-semibold"}>
                            ₹{p.netProfit.toLocaleString()}
                          </span>
                        </td>
                        <td className="p-3 text-right">
                          <Badge variant={p.grossMargin >= 25 ? "default" : p.grossMargin >= 15 ? "secondary" : "destructive"}>
                            {p.grossMargin.toFixed(1)}%
                          </Badge>
                        </td>
                      </tr>
                    ))}
                  </tbody>
                  <tfoot>
                    <tr className="bg-muted/50 font-semibold">
                      <td className="p-3">TOTAL</td>
                      <td className="p-3 hidden md:table-cell"></td>
                      <td className="p-3 text-right">{filteredProducts.reduce((s, p) => s + p.quantitySold, 0)}</td>
                      <td className="p-3 text-right">₹{summary.totalRevenue.toLocaleString()}</td>
                      <td className="p-3 text-right hidden lg:table-cell">₹{summary.totalCOGS.toLocaleString()}</td>
                      <td className="p-3 text-right text-green-600">₹{summary.totalNetProfit.toLocaleString()}</td>
                      <td className="p-3 text-right">{summary.avgMargin.toFixed(1)}%</td>
                    </tr>
                  </tfoot>
                </table>
              </div>
              {filteredProducts.length > 50 && (
                <p className="text-center text-muted-foreground mt-4 text-sm">
                  Showing 50 of {filteredProducts.length} products. Export to see all.
                </p>
              )}
            </CardContent>
          </Card>
        </>
      )}
    </div>
  );
}

import { useState } from "react";
import { useQuery } from "@tanstack/react-query";
import { supabase } from "@/integrations/supabase/client";
import { StatCard } from "@/components/shared/StatCard";
import { TableSkeleton } from "@/components/shared/TableSkeleton";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Tabs, TabsContent, TabsList, TabsTrigger } from "@/components/ui/tabs";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import { Table, TableBody, TableCell, TableHead, TableHeader, TableRow } from "@/components/ui/table";
import { toast } from "sonner";
import {
  ClipboardList, CheckCircle, XCircle, Clock, TrendingUp,
  FileText, FileSpreadsheet, Truck, BarChart3,
} from "lucide-react";
import {
  BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer,
  PieChart, Pie, Cell,
} from "recharts";
import jsPDF from "jspdf";
import autoTable from "jspdf-autotable";
import * as XLSX from "xlsx";

const COLORS = ["hsl(38, 92%, 50%)", "hsl(142, 72%, 42%)", "hsl(0, 72%, 51%)", "hsl(217, 91%, 50%)"];

export default function OrderReport() {
  const today = new Date();
  const thirtyAgo = new Date(today); thirtyAgo.setDate(thirtyAgo.getDate() - 30);
  const [from, setFrom] = useState(thirtyAgo.toISOString().split("T")[0]);
  const [to, setTo] = useState(today.toISOString().split("T")[0]);

  const { data, isLoading } = useQuery({
    queryKey: ["order-report", from, to],
    queryFn: async () => {
      const start = from + "T00:00:00", end = to + "T23:59:59";
      const [ordersRes, storesRes, storeTypesRes] = await Promise.all([
        supabase.from("orders").select("*, stores(name, store_type_id)").gte("created_at", start).lte("created_at", end).order("created_at"),
        supabase.from("stores").select("id, name, store_type_id"),
        supabase.from("store_types").select("id, name"),
      ]);
      const orders = ordersRes.data || [];
      const storeTypeMap = Object.fromEntries((storeTypesRes.data || []).map(t => [t.id, t.name]));
      const storeMap = Object.fromEntries((storesRes.data || []).map(s => [s.id, s]));

      const total = orders.length;
      const pending = orders.filter(o => o.status === "pending").length;
      const delivered = orders.filter(o => o.status === "delivered").length;
      const cancelled = orders.filter(o => o.status === "cancelled").length;
      const fulfillmentRate = total > 0 ? ((delivered / total) * 100).toFixed(1) : "0";
      const cancellationRate = total > 0 ? ((cancelled / total) * 100).toFixed(1) : "0";

      // Avg delivery time (hours)
      const deliveredOrders = orders.filter(o => o.status === "delivered" && o.delivered_at);
      const avgDeliveryHours = deliveredOrders.length > 0
        ? deliveredOrders.reduce((s, o) => s + (new Date(o.delivered_at!).getTime() - new Date(o.created_at).getTime()) / 3600000, 0) / deliveredOrders.length
        : 0;

      // Status pie
      const statusData = [
        { name: "Pending", value: pending },
        { name: "Delivered", value: delivered },
        { name: "Cancelled", value: cancelled },
      ].filter(s => s.value > 0);

      // Source breakdown
      const sourceMap: Record<string, number> = {};
      orders.forEach(o => { sourceMap[o.source] = (sourceMap[o.source] || 0) + 1; });
      const sourceData = Object.entries(sourceMap).map(([name, value]) => ({ name, value }));

      // Cancellation reasons
      const reasonMap: Record<string, number> = {};
      orders.filter(o => o.cancellation_reason).forEach(o => {
        const r = o.cancellation_reason!;
        reasonMap[r] = (reasonMap[r] || 0) + 1;
      });
      const cancellationReasons = Object.entries(reasonMap).sort((a, b) => b[1] - a[1]).map(([reason, count]) => ({ reason, count }));

      // Store frequency
      const storeFreq: Record<string, { name: string; type: string; total: number; delivered: number; cancelled: number }> = {};
      orders.forEach(o => {
        const sid = o.store_id;
        const st = storeMap[sid];
        const typeName = st ? storeTypeMap[st.store_type_id] || "Other" : "Unknown";
        if (!storeFreq[sid]) storeFreq[sid] = { name: (o.stores as any)?.name || "Unknown", type: typeName, total: 0, delivered: 0, cancelled: 0 };
        storeFreq[sid].total += 1;
        if (o.status === "delivered") storeFreq[sid].delivered += 1;
        if (o.status === "cancelled") storeFreq[sid].cancelled += 1;
      });
      const storeFreqData = Object.values(storeFreq).sort((a, b) => b.total - a.total);

      // Daily orders
      const dailyMap: Record<string, number> = {};
      orders.forEach(o => {
        const day = o.created_at.split("T")[0];
        dailyMap[day] = (dailyMap[day] || 0) + 1;
      });
      const dailyTrend = Object.entries(dailyMap).sort().map(([d, c]) => ({ date: d.slice(5), count: c }));

      // Peak days
      const dayOfWeekMap: Record<string, number> = { Sun: 0, Mon: 0, Tue: 0, Wed: 0, Thu: 0, Fri: 0, Sat: 0 };
      const dayNames = ["Sun", "Mon", "Tue", "Wed", "Thu", "Fri", "Sat"];
      orders.forEach(o => {
        const dow = dayNames[new Date(o.created_at).getDay()];
        dayOfWeekMap[dow] += 1;
      });
      const peakDays = Object.entries(dayOfWeekMap).map(([day, count]) => ({ day, count }));

      // Store type breakdown
      const typeOrders: Record<string, number> = {};
      orders.forEach(o => {
        const st = storeMap[o.store_id];
        const tn = st ? storeTypeMap[st.store_type_id] || "Other" : "Other";
        typeOrders[tn] = (typeOrders[tn] || 0) + 1;
      });
      const storeTypeData = Object.entries(typeOrders).sort((a, b) => b[1] - a[1]).map(([name, value]) => ({ name, value }));

      return {
        total, pending, delivered, cancelled, fulfillmentRate, cancellationRate,
        avgDeliveryHours, statusData, sourceData, cancellationReasons,
        storeFreqData, dailyTrend, peakDays, storeTypeData,
      };
    },
  });

  const exportPDF = () => {
    if (!data) return;
    const doc = new jsPDF({ orientation: "landscape", unit: "mm", format: "a4" });
    const pw = doc.internal.pageSize.getWidth();
    doc.setFillColor(30, 41, 59); doc.rect(0, 0, pw, 18, "F");
    doc.setTextColor(255, 255, 255); doc.setFontSize(14);
    doc.text("Order Report", 10, 12); doc.setFontSize(9);
    doc.text(`${from} to ${to}`, pw - 10, 12, { align: "right" });

    doc.setTextColor(0, 0, 0);
    autoTable(doc, { startY: 24, head: [["Metric", "Value"]], body: [
      ["Total Orders", data.total], ["Delivered", data.delivered], ["Pending", data.pending],
      ["Cancelled", data.cancelled], ["Fulfillment Rate", data.fulfillmentRate + "%"],
      ["Cancellation Rate", data.cancellationRate + "%"], ["Avg Delivery Time", data.avgDeliveryHours.toFixed(1) + " hrs"],
    ], theme: "grid", styles: { fontSize: 7, cellPadding: 1.5 }, headStyles: { fillColor: [30, 41, 59] }, margin: { left: 10 }, tableWidth: 80 });

    autoTable(doc, { startY: 24, head: [["Store", "Type", "Total", "Delivered", "Cancelled"]], body: data.storeFreqData.slice(0, 25).map(s => [s.name, s.type, s.total, s.delivered, s.cancelled]), theme: "grid", styles: { fontSize: 6, cellPadding: 1.2 }, headStyles: { fillColor: [30, 41, 59] }, margin: { left: 100 }, tableWidth: 187 });

    doc.save(`order-report-${from}-to-${to}.pdf`);
    toast.success("PDF downloaded");
  };

  const exportExcel = () => {
    if (!data) return;
    const wb = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(wb, XLSX.utils.aoa_to_sheet([
      ["Order Report", `${from} to ${to}`], [],
      ["Total", data.total], ["Delivered", data.delivered], ["Pending", data.pending], ["Cancelled", data.cancelled],
      ["Fulfillment %", data.fulfillmentRate], ["Avg Delivery Hrs", data.avgDeliveryHours.toFixed(1)],
    ]), "Summary");
    XLSX.utils.book_append_sheet(wb, XLSX.utils.json_to_sheet(data.storeFreqData), "Store Frequency");
    XLSX.utils.book_append_sheet(wb, XLSX.utils.json_to_sheet(data.dailyTrend), "Daily Trend");
    XLSX.writeFile(wb, `order-report-${from}-to-${to}.xlsx`);
    toast.success("Excel downloaded");
  };

  if (isLoading) return <TableSkeleton />;
  if (!data) return null;
  const d = data;

  return (
    <div className="space-y-4">
      <div className="flex flex-wrap items-end gap-3">
        <div><Label className="text-xs">From</Label><Input type="date" value={from} onChange={e => setFrom(e.target.value)} className="w-40" /></div>
        <div><Label className="text-xs">To</Label><Input type="date" value={to} onChange={e => setTo(e.target.value)} className="w-40" /></div>
        <Button variant="outline" size="sm" onClick={exportPDF}><FileText className="h-4 w-4 mr-1" />PDF</Button>
        <Button variant="outline" size="sm" onClick={exportExcel}><FileSpreadsheet className="h-4 w-4 mr-1" />Excel</Button>
      </div>

      <div className="grid grid-cols-2 md:grid-cols-4 lg:grid-cols-6 gap-3">
        <StatCard title="Total Orders" value={String(d.total)} icon={ClipboardList} iconColor="primary" />
        <StatCard title="Delivered" value={String(d.delivered)} icon={CheckCircle} iconColor="success" />
        <StatCard title="Pending" value={String(d.pending)} icon={Clock} iconColor="warning" />
        <StatCard title="Cancelled" value={String(d.cancelled)} icon={XCircle} iconColor="destructive" />
        <StatCard title="Fulfillment" value={d.fulfillmentRate + "%"} icon={TrendingUp} iconColor="success" />
        <StatCard title="Avg Delivery" value={d.avgDeliveryHours.toFixed(1) + "h"} icon={Truck} iconColor="purple" />
      </div>

      <Tabs defaultValue="status">
        <TabsList className="flex-wrap h-auto">
          <TabsTrigger value="status">Status</TabsTrigger>
          <TabsTrigger value="trend">Daily Trend</TabsTrigger>
          <TabsTrigger value="stores">Store Frequency</TabsTrigger>
          <TabsTrigger value="peak">Peak Days</TabsTrigger>
          <TabsTrigger value="reasons">Cancellations</TabsTrigger>
        </TabsList>

        <TabsContent value="status">
          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            <Card><CardHeader><CardTitle className="text-sm">Order Status</CardTitle></CardHeader><CardContent>
              {d.statusData.length === 0 ? <p className="text-sm text-muted-foreground text-center py-8">No data</p> : (
                <ResponsiveContainer width="100%" height={250}>
                  <PieChart><Pie data={d.statusData} cx="50%" cy="50%" innerRadius={40} outerRadius={80} dataKey="value" label={({ name, value }) => `${name}: ${value}`}>
                    {d.statusData.map((_, i) => <Cell key={i} fill={COLORS[i % COLORS.length]} />)}
                  </Pie><Tooltip /></PieChart>
                </ResponsiveContainer>
              )}
            </CardContent></Card>
            <Card><CardHeader><CardTitle className="text-sm">By Source</CardTitle></CardHeader><CardContent>
              {d.sourceData.length === 0 ? <p className="text-sm text-muted-foreground text-center py-8">No data</p> : (
                <ResponsiveContainer width="100%" height={250}>
                  <BarChart data={d.sourceData}>
                    <CartesianGrid strokeDasharray="3 3" stroke="hsl(var(--border))" />
                    <XAxis dataKey="name" tick={{ fontSize: 10 }} stroke="hsl(var(--muted-foreground))" />
                    <YAxis tick={{ fontSize: 10 }} stroke="hsl(var(--muted-foreground))" />
                    <Tooltip /><Bar dataKey="value" fill="hsl(var(--primary))" radius={[4, 4, 0, 0]} />
                  </BarChart>
                </ResponsiveContainer>
              )}
            </CardContent></Card>
          </div>
        </TabsContent>

        <TabsContent value="trend">
          <Card><CardContent className="pt-4">
            {d.dailyTrend.length === 0 ? <p className="text-sm text-muted-foreground text-center py-8">No data</p> : (
              <ResponsiveContainer width="100%" height={280}>
                <BarChart data={d.dailyTrend}>
                  <CartesianGrid strokeDasharray="3 3" stroke="hsl(var(--border))" />
                  <XAxis dataKey="date" tick={{ fontSize: 10 }} stroke="hsl(var(--muted-foreground))" />
                  <YAxis tick={{ fontSize: 10 }} stroke="hsl(var(--muted-foreground))" />
                  <Tooltip /><Bar dataKey="count" fill="hsl(var(--primary))" radius={[4, 4, 0, 0]} name="Orders" />
                </BarChart>
              </ResponsiveContainer>
            )}
          </CardContent></Card>
        </TabsContent>

        <TabsContent value="stores">
          <Card><CardContent className="pt-4">
            <Table><TableHeader><TableRow>
              <TableHead>#</TableHead><TableHead>Store</TableHead><TableHead>Type</TableHead>
              <TableHead className="text-right">Total</TableHead><TableHead className="text-right">Delivered</TableHead>
              <TableHead className="text-right">Cancelled</TableHead>
            </TableRow></TableHeader><TableBody>
              {d.storeFreqData.slice(0, 30).map((s, i) => (
                <TableRow key={i}>
                  <TableCell>{i + 1}</TableCell>
                  <TableCell className="font-medium">{s.name}</TableCell>
                  <TableCell><Badge variant="outline">{s.type}</Badge></TableCell>
                  <TableCell className="text-right">{s.total}</TableCell>
                  <TableCell className="text-right text-success">{s.delivered}</TableCell>
                  <TableCell className="text-right text-destructive">{s.cancelled}</TableCell>
                </TableRow>
              ))}
            </TableBody></Table>
          </CardContent></Card>
        </TabsContent>

        <TabsContent value="peak">
          <Card><CardContent className="pt-4">
            <ResponsiveContainer width="100%" height={250}>
              <BarChart data={d.peakDays}>
                <CartesianGrid strokeDasharray="3 3" stroke="hsl(var(--border))" />
                <XAxis dataKey="day" tick={{ fontSize: 10 }} stroke="hsl(var(--muted-foreground))" />
                <YAxis tick={{ fontSize: 10 }} stroke="hsl(var(--muted-foreground))" />
                <Tooltip /><Bar dataKey="count" fill="hsl(var(--chart-2))" radius={[4, 4, 0, 0]} name="Orders" />
              </BarChart>
            </ResponsiveContainer>
          </CardContent></Card>
        </TabsContent>

        <TabsContent value="reasons">
          <Card><CardContent className="pt-4">
            {d.cancellationReasons.length === 0 ? <p className="text-sm text-muted-foreground text-center py-8">No cancellations with reasons</p> : (
              <Table><TableHeader><TableRow>
                <TableHead>Reason</TableHead><TableHead className="text-right">Count</TableHead>
              </TableRow></TableHeader><TableBody>
                {d.cancellationReasons.map((r, i) => (
                  <TableRow key={i}><TableCell>{r.reason}</TableCell><TableCell className="text-right">{r.count}</TableCell></TableRow>
                ))}
              </TableBody></Table>
            )}
          </CardContent></Card>
        </TabsContent>
      </Tabs>
    </div>
  );
}

import { useState, useMemo } from "react";
import { useQuery } from "@tanstack/react-query";
import { supabase } from "@/integrations/supabase/client";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { Loader2, Wallet, ArrowUpRight, ArrowDownRight, DollarSign, CreditCard, Banknote, PiggyBank } from "lucide-react";
import { format, subMonths, startOfMonth, eachDayOfInterval, eachWeekOfInterval, eachMonthOfInterval, isSameDay, isSameWeek, isSameMonth } from "date-fns";
import { ReportFilters, DateRange } from "./ReportFilters";
import { ReportExportBar } from "./ReportExportBar";
import { ReportSummaryCards } from "./ReportSummaryCards";
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, LineChart, Line, Legend, PieChart, Pie, Cell } from "recharts";
import jsPDF from "jspdf";
import autoTable from "jspdf-autotable";
import * as XLSX from "xlsx";

const COLORS = ["#10b981", "#3b82f6", "#f59e0b", "#ef4444", "#8b5cf6", "#ec4899"];

type GroupBy = "day" | "week" | "month";

export default function PaymentFlowReport() {
  const [dateRange, setDateRange] = useState<DateRange>({
    from: startOfMonth(subMonths(new Date(), 2)),
    to: new Date(),
  });
  const [groupBy, setGroupBy] = useState<GroupBy>("day");

  // Fetch customer payments (transactions)
  const { data: customerPayments = [], isLoading: cpLoading } = useQuery({
    queryKey: ["payment-flow-customer", dateRange],
    queryFn: async () => {
      const { data } = await supabase
        .from("transactions")
        .select("id, display_id, amount, payment_method, transaction_date, type")
        .eq("type", "payment")
        .gte("transaction_date", format(dateRange.from, "yyyy-MM-dd"))
        .lte("transaction_date", format(dateRange.to, "yyyy-MM-dd"));
      return data || [];
    },
  });

  // Fetch vendor payments
  const { data: vendorPayments = [], isLoading: vpLoading } = useQuery({
    queryKey: ["payment-flow-vendor", dateRange],
    queryFn: async () => {
      const { data } = await supabase
        .from("vendor_payments")
        .select("id, display_id, amount, payment_method, payment_date")
        .gte("payment_date", format(dateRange.from, "yyyy-MM-dd"))
        .lte("payment_date", format(dateRange.to, "yyyy-MM-dd"));
      return data || [];
    },
  });

  // Fetch expenses
  const { data: expenses = [], isLoading: expLoading } = useQuery({
    queryKey: ["payment-flow-expenses", dateRange],
    queryFn: async () => {
      const { data } = await supabase
        .from("expenses")
        .select("id, display_id, amount, payment_method, expense_date, expense_categories(name)")
        .gte("expense_date", format(dateRange.from, "yyyy-MM-dd"))
        .lte("expense_date", format(dateRange.to, "yyyy-MM-dd"));
      return data || [];
    },
  });

  // Fetch worker payments
  const { data: workerPayments = [], isLoading: wpLoading } = useQuery({
    queryKey: ["payment-flow-worker", dateRange],
    queryFn: async () => {
      const { data } = await supabase
        .from("worker_payments")
        .select("id, amount, payment_method, payment_date")
        .gte("payment_date", format(dateRange.from, "yyyy-MM-dd"))
        .lte("payment_date", format(dateRange.to, "yyyy-MM-dd"));
      return data || [];
    },
  });

  const isLoading = cpLoading || vpLoading || expLoading || wpLoading;

  // Summary calculations
  const summary = useMemo(() => {
    const totalInflow = customerPayments.reduce((sum: number, p: any) => sum + Number(p.amount), 0);
    
    const vendorOutflow = vendorPayments.reduce((sum: number, p: any) => sum + Number(p.amount), 0);
    const expenseOutflow = expenses.reduce((sum: number, e: any) => sum + Number(e.amount), 0);
    const workerOutflow = workerPayments.reduce((sum: number, w: any) => sum + Number(w.amount), 0);
    const totalOutflow = vendorOutflow + expenseOutflow + workerOutflow;

    const netCashFlow = totalInflow - totalOutflow;

    // By payment method
    const inflowByMethod: Record<string, number> = {};
    customerPayments.forEach((p: any) => {
      const method = p.payment_method || "other";
      inflowByMethod[method] = (inflowByMethod[method] || 0) + Number(p.amount);
    });

    const outflowByMethod: Record<string, number> = {};
    [...vendorPayments, ...expenses, ...workerPayments].forEach((p: any) => {
      const method = p.payment_method || "other";
      outflowByMethod[method] = (outflowByMethod[method] || 0) + Number(p.amount);
    });

    return {
      totalInflow,
      totalOutflow,
      vendorOutflow,
      expenseOutflow,
      workerOutflow,
      netCashFlow,
      inflowByMethod,
      outflowByMethod,
    };
  }, [customerPayments, vendorPayments, expenses, workerPayments]);

  // Time-series data
  const timeSeriesData = useMemo(() => {
    let intervals: Date[];
    let formatStr: string;
    let isSamePeriod: (d1: Date, d2: Date) => boolean;

    switch (groupBy) {
      case "week":
        intervals = eachWeekOfInterval({ start: dateRange.from, end: dateRange.to });
        formatStr = "MMM d";
        isSamePeriod = isSameWeek;
        break;
      case "month":
        intervals = eachMonthOfInterval({ start: dateRange.from, end: dateRange.to });
        formatStr = "MMM yyyy";
        isSamePeriod = isSameMonth;
        break;
      default:
        intervals = eachDayOfInterval({ start: dateRange.from, end: dateRange.to });
        formatStr = "MMM d";
        isSamePeriod = isSameDay;
    }

    return intervals.map((date) => {
      const inflow = customerPayments
        .filter((p: any) => isSamePeriod(new Date(p.transaction_date), date))
        .reduce((sum: number, p: any) => sum + Number(p.amount), 0);

      const outflow = 
        vendorPayments.filter((p: any) => isSamePeriod(new Date(p.payment_date), date)).reduce((sum: number, p: any) => sum + Number(p.amount), 0) +
        expenses.filter((e: any) => isSamePeriod(new Date(e.expense_date), date)).reduce((sum: number, e: any) => sum + Number(e.amount), 0) +
        workerPayments.filter((w: any) => isSamePeriod(new Date(w.payment_date), date)).reduce((sum: number, w: any) => sum + Number(w.amount), 0);

      return {
        date: format(date, formatStr),
        inflow,
        outflow,
        net: inflow - outflow,
      };
    });
  }, [customerPayments, vendorPayments, expenses, workerPayments, dateRange, groupBy]);

  // Outflow breakdown pie chart
  const outflowBreakdown = useMemo(() => {
    return [
      { name: "Vendor Payments", value: summary.vendorOutflow },
      { name: "Expenses", value: summary.expenseOutflow },
      { name: "Worker Payments", value: summary.workerOutflow },
    ].filter(x => x.value > 0);
  }, [summary]);

  // Payment method breakdown
  const methodBreakdown = useMemo(() => {
    const methods = new Set([...Object.keys(summary.inflowByMethod), ...Object.keys(summary.outflowByMethod)]);
    return Array.from(methods).map(method => ({
      method: method.toUpperCase(),
      inflow: summary.inflowByMethod[method] || 0,
      outflow: summary.outflowByMethod[method] || 0,
    }));
  }, [summary]);

  const summaryCards = [
    { label: "Total Inflow", value: `₹${summary.totalInflow.toLocaleString()}`, icon: ArrowUpRight, iconColor: "green" },
    { label: "Total Outflow", value: `₹${summary.totalOutflow.toLocaleString()}`, icon: ArrowDownRight, iconColor: "red" },
    { label: "Net Cash Flow", value: `₹${summary.netCashFlow.toLocaleString()}`, icon: summary.netCashFlow >= 0 ? PiggyBank : Wallet, iconColor: summary.netCashFlow >= 0 ? "blue" : "yellow" },
    { label: "Transactions", value: (customerPayments.length + vendorPayments.length + expenses.length + workerPayments.length).toString(), icon: CreditCard, iconColor: "purple" },
  ];

  const exportPDF = () => {
    const doc = new jsPDF();
    doc.setFontSize(16);
    doc.text("Payment Flow Report", 14, 15);
    doc.setFontSize(10);
    doc.text(`Period: ${format(dateRange.from, "MMM d, yyyy")} - ${format(dateRange.to, "MMM d, yyyy")}`, 14, 23);

    // Summary
    doc.setFontSize(12);
    doc.text("Summary", 14, 35);
    doc.setFontSize(10);
    doc.text(`Total Inflow: ₹${summary.totalInflow.toLocaleString()}`, 14, 43);
    doc.text(`Total Outflow: ₹${summary.totalOutflow.toLocaleString()}`, 14, 50);
    doc.text(`Net Cash Flow: ₹${summary.netCashFlow.toLocaleString()}`, 14, 57);

    // Timeline table
    autoTable(doc, {
      startY: 65,
      head: [["Period", "Inflow", "Outflow", "Net"]],
      body: timeSeriesData.map(d => [
        d.date,
        `₹${d.inflow.toLocaleString()}`,
        `₹${d.outflow.toLocaleString()}`,
        `₹${d.net.toLocaleString()}`,
      ]),
      styles: { fontSize: 9 },
      headStyles: { fillColor: [59, 130, 246] },
    });

    doc.save(`payment-flow-${format(dateRange.from, "yyyyMMdd")}-${format(dateRange.to, "yyyyMMdd")}.pdf`);
  };

  const exportExcel = () => {
    // Summary sheet
    const summaryData = [
      { Metric: "Total Inflow", Value: summary.totalInflow },
      { Metric: "Total Outflow", Value: summary.totalOutflow },
      { Metric: "Net Cash Flow", Value: summary.netCashFlow },
      { Metric: "Vendor Payments", Value: summary.vendorOutflow },
      { Metric: "Expenses", Value: summary.expenseOutflow },
      { Metric: "Worker Payments", Value: summary.workerOutflow },
    ];

    // Timeline sheet
    const timelineData = timeSeriesData.map(d => ({
      Period: d.date,
      Inflow: d.inflow,
      Outflow: d.outflow,
      "Net Cash Flow": d.net,
    }));

    const wb = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(wb, XLSX.utils.json_to_sheet(summaryData), "Summary");
    XLSX.utils.book_append_sheet(wb, XLSX.utils.json_to_sheet(timelineData), "Timeline");
    XLSX.writeFile(wb, `payment-flow-${format(dateRange.from, "yyyyMMdd")}-${format(dateRange.to, "yyyyMMdd")}.xlsx`);
  };

  return (
    <div className="space-y-6">
      <div className="flex flex-col lg:flex-row lg:items-end gap-4">
        <ReportFilters dateRange={dateRange} onDateRangeChange={setDateRange} />
        <div className="flex gap-2">
          <Badge 
            variant={groupBy === "day" ? "default" : "outline"} 
            className="cursor-pointer"
            onClick={() => setGroupBy("day")}
          >
            Daily
          </Badge>
          <Badge 
            variant={groupBy === "week" ? "default" : "outline"} 
            className="cursor-pointer"
            onClick={() => setGroupBy("week")}
          >
            Weekly
          </Badge>
          <Badge 
            variant={groupBy === "month" ? "default" : "outline"} 
            className="cursor-pointer"
            onClick={() => setGroupBy("month")}
          >
            Monthly
          </Badge>
        </div>
      </div>

      <ReportExportBar onExportPDF={exportPDF} onExportExcel={exportExcel} />

      {isLoading ? (
        <div className="flex items-center justify-center py-12">
          <Loader2 className="h-8 w-8 animate-spin text-muted-foreground" />
        </div>
      ) : (
        <>
          <ReportSummaryCards cards={summaryCards} />

          {/* Cash Flow Chart */}
          <Card>
            <CardHeader>
              <CardTitle className="text-base">Cash Flow Timeline</CardTitle>
            </CardHeader>
            <CardContent>
              <ResponsiveContainer width="100%" height={350}>
                <BarChart data={timeSeriesData}>
                  <CartesianGrid strokeDasharray="3 3" />
                  <XAxis dataKey="date" tick={{ fontSize: 11 }} interval={groupBy === "day" ? Math.floor(timeSeriesData.length / 10) : 0} />
                  <YAxis tickFormatter={(v) => `₹${(v/1000).toFixed(0)}k`} />
                  <Tooltip formatter={(v: number) => `₹${v.toLocaleString()}`} />
                  <Legend />
                  <Bar dataKey="inflow" name="Inflow" fill="#10b981" />
                  <Bar dataKey="outflow" name="Outflow" fill="#ef4444" />
                </BarChart>
              </ResponsiveContainer>
            </CardContent>
          </Card>

          <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
            {/* Net Cash Flow Trend */}
            <Card>
              <CardHeader>
                <CardTitle className="text-base">Net Cash Flow Trend</CardTitle>
              </CardHeader>
              <CardContent>
                <ResponsiveContainer width="100%" height={250}>
                  <LineChart data={timeSeriesData}>
                    <CartesianGrid strokeDasharray="3 3" />
                    <XAxis dataKey="date" tick={{ fontSize: 10 }} interval={Math.floor(timeSeriesData.length / 6)} />
                    <YAxis tickFormatter={(v) => `₹${(v/1000).toFixed(0)}k`} />
                    <Tooltip formatter={(v: number) => `₹${v.toLocaleString()}`} />
                    <Line type="monotone" dataKey="net" name="Net Cash Flow" stroke="#3b82f6" strokeWidth={2} dot={false} />
                  </LineChart>
                </ResponsiveContainer>
              </CardContent>
            </Card>

            {/* Outflow Breakdown */}
            <Card>
              <CardHeader>
                <CardTitle className="text-base">Outflow Breakdown</CardTitle>
              </CardHeader>
              <CardContent>
                {outflowBreakdown.length > 0 ? (
                  <ResponsiveContainer width="100%" height={250}>
                    <PieChart>
                      <Pie
                        data={outflowBreakdown}
                        cx="50%"
                        cy="50%"
                        labelLine={false}
                        label={({ name, percent }) => `${name} (${(percent * 100).toFixed(0)}%)`}
                        outerRadius={80}
                        fill="#8884d8"
                        dataKey="value"
                      >
                        {outflowBreakdown.map((_, index) => (
                          <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} />
                        ))}
                      </Pie>
                      <Tooltip formatter={(v: number) => `₹${v.toLocaleString()}`} />
                    </PieChart>
                  </ResponsiveContainer>
                ) : (
                  <p className="text-center text-muted-foreground py-12">No outflow data</p>
                )}
              </CardContent>
            </Card>
          </div>

          {/* Payment Method Breakdown */}
          <Card>
            <CardHeader>
              <CardTitle className="text-base">By Payment Method</CardTitle>
            </CardHeader>
            <CardContent>
              <div className="overflow-x-auto">
                <table className="w-full text-sm">
                  <thead>
                    <tr className="border-b bg-muted/50">
                      <th className="text-left p-3 font-medium">Payment Method</th>
                      <th className="text-right p-3 font-medium">Inflow</th>
                      <th className="text-right p-3 font-medium">Outflow</th>
                      <th className="text-right p-3 font-medium">Net</th>
                    </tr>
                  </thead>
                  <tbody>
                    {methodBreakdown.map((m) => (
                      <tr key={m.method} className="border-b hover:bg-muted/30">
                        <td className="p-3 font-medium">{m.method}</td>
                        <td className="p-3 text-right text-green-600">₹{m.inflow.toLocaleString()}</td>
                        <td className="p-3 text-right text-red-600">₹{m.outflow.toLocaleString()}</td>
                        <td className="p-3 text-right">
                          <span className={m.inflow - m.outflow >= 0 ? "text-blue-600 font-semibold" : "text-yellow-600 font-semibold"}>
                            ₹{(m.inflow - m.outflow).toLocaleString()}
                          </span>
                        </td>
                      </tr>
                    ))}
                  </tbody>
                  <tfoot>
                    <tr className="bg-muted/50 font-semibold">
                      <td className="p-3">TOTAL</td>
                      <td className="p-3 text-right text-green-600">₹{summary.totalInflow.toLocaleString()}</td>
                      <td className="p-3 text-right text-red-600">₹{summary.totalOutflow.toLocaleString()}</td>
                      <td className="p-3 text-right text-blue-600">₹{summary.netCashFlow.toLocaleString()}</td>
                    </tr>
                  </tfoot>
                </table>
              </div>
            </CardContent>
          </Card>
        </>
      )}
    </div>
  );
}

import { useState } from "react";
import { useQuery } from "@tanstack/react-query";
import { supabase } from "@/integrations/supabase/client";
import { StatCard } from "@/components/shared/StatCard";
import { TableSkeleton } from "@/components/shared/TableSkeleton";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Tabs, TabsContent, TabsList, TabsTrigger } from "@/components/ui/tabs";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import { Table, TableBody, TableCell, TableHead, TableHeader, TableRow } from "@/components/ui/table";
import { toast } from "sonner";
import {
  Banknote, TrendingDown, AlertTriangle, UserX, Clock,
  FileText, FileSpreadsheet, Shield, DollarSign, Percent,
} from "lucide-react";
import {
  BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer,
  PieChart, Pie, Cell, LineChart, Line,
} from "recharts";
import jsPDF from "jspdf";
import autoTable from "jspdf-autotable";
import * as XLSX from "xlsx";

const fmt = (n: number) => `₹${n.toLocaleString("en-IN")}`;
const COLORS = ["hsl(142, 72%, 42%)", "hsl(38, 92%, 50%)", "hsl(280, 65%, 60%)", "hsl(0, 72%, 51%)"];

export default function PaymentOutstandingReport() {
  const today = new Date();
  const [inactiveDays, setInactiveDays] = useState(7);

  const { data, isLoading } = useQuery({
    queryKey: ["payment-outstanding-report", inactiveDays],
    queryFn: async () => {
      const [storesRes, txnRes, salesRes, storeTypesRes, customersRes, ordersRes] = await Promise.all([
        supabase.from("stores").select("id, name, display_id, outstanding, opening_balance, store_type_id, customer_id").eq("is_active", true),
        supabase.from("transactions").select("store_id, total_amount, cash_amount, upi_amount, created_at, recorded_by").order("created_at", { ascending: false }),
        supabase.from("sales").select("store_id, total_amount, outstanding_amount, created_at").order("created_at", { ascending: false }),
        supabase.from("store_types").select("id, name, credit_limit_kyc, credit_limit_no_kyc"),
        supabase.from("customers").select("id, name, phone, kyc_status, credit_limit_override"),
        supabase.from("orders").select("store_id, created_at").order("created_at", { ascending: false }),
      ]);

      const stores = storesRes.data || [];
      const txns = txnRes.data || [];
      const allSales = salesRes.data || [];
      const storeTypes = storeTypesRes.data || [];
      const customers = customersRes.data || [];
      const allOrders = ordersRes.data || [];

      const storeTypeMap = Object.fromEntries(storeTypes.map(t => [t.id, { name: t.name, creditKyc: Number(t.credit_limit_kyc), creditNoKyc: Number(t.credit_limit_no_kyc) }]));
      const customerMap = Object.fromEntries(customers.map(c => [c.id, c]));

      // Last order date per store
      const lastOrderDate: Record<string, string> = {};
      allOrders.forEach(o => {
        if (!lastOrderDate[o.store_id] || o.created_at > lastOrderDate[o.store_id]) lastOrderDate[o.store_id] = o.created_at;
      });

      // Total outstanding
      const totalOutstanding = stores.reduce((s, st) => s + Number(st.outstanding), 0);
      const totalOpeningBalance = stores.reduce((s, st) => s + Number(st.opening_balance), 0);

      // Total collections (all time recent 90 days for trend)
      const ninetyAgo = new Date(); ninetyAgo.setDate(ninetyAgo.getDate() - 90);
      const recentTxns = txns.filter(t => new Date(t.created_at) >= ninetyAgo);
      const totalCollections = recentTxns.reduce((s, t) => s + Number(t.total_amount), 0);
      const totalCollectionCash = recentTxns.reduce((s, t) => s + Number(t.cash_amount), 0);
      const totalCollectionUpi = recentTxns.reduce((s, t) => s + Number(t.upi_amount), 0);

      // Recent sales total for collection %
      const recentSales = allSales.filter(s => new Date(s.created_at) >= ninetyAgo);
      const recentSalesTotal = recentSales.reduce((s, r) => s + Number(r.total_amount), 0);
      const collectionRate = recentSalesTotal > 0 ? ((totalCollections / recentSalesTotal) * 100).toFixed(1) : "0";

      // Last sale and last payment per store
      const lastSaleDate: Record<string, string> = {};
      const lastPaymentDate: Record<string, string> = {};
      allSales.forEach(s => {
        if (!lastSaleDate[s.store_id] || s.created_at > lastSaleDate[s.store_id]) lastSaleDate[s.store_id] = s.created_at;
      });
      txns.forEach(t => {
        if (!lastPaymentDate[t.store_id] || t.created_at > lastPaymentDate[t.store_id]) lastPaymentDate[t.store_id] = t.created_at;
      });

      const nowMs = today.getTime();

      // Store analysis
      const storeAnalysis = stores.filter(s => Number(s.outstanding) > 0).map(s => {
        const outstanding = Number(s.outstanding);
        const openingBal = Number(s.opening_balance);
        const lastSale = lastSaleDate[s.id];
        const lastPayment = lastPaymentDate[s.id];
        const lastOrder = lastOrderDate[s.id];
        const daysSinceLastSale = lastSale ? Math.floor((nowMs - new Date(lastSale).getTime()) / 86400000) : 999;
        const daysSinceLastPayment = lastPayment ? Math.floor((nowMs - new Date(lastPayment).getTime()) / 86400000) : 999;
        const daysSinceLastOrder = lastOrder ? Math.floor((nowMs - new Date(lastOrder).getTime()) / 86400000) : 999;
        const typeInfo = storeTypeMap[s.store_type_id] || { name: "Other", creditKyc: 0, creditNoKyc: 0 };
        const typeName = typeInfo.name;
        const cust = customerMap[s.customer_id];
        const isKyc = cust?.kyc_status === "verified";
        const creditLimit = cust?.credit_limit_override
          ? Number(cust.credit_limit_override)
          : isKyc ? typeInfo.creditKyc : typeInfo.creditNoKyc;

        // Danger: outstanding > 2x credit limit OR no payment in 30+ days with high outstanding
        const isDanger = (creditLimit > 0 && outstanding > creditLimit * 2) || (daysSinceLastPayment > 30 && outstanding > 5000);
        // Inactive: has outstanding but no sale in X days
        const isInactive = daysSinceLastSale >= inactiveDays && outstanding > 0;
        // Credit limit exceeded
        const isCreditExceeded = creditLimit > 0 && outstanding > creditLimit;
        // No recent orders (15 days)
        const hasNoRecentOrders = daysSinceLastOrder >= 15;

        return {
          id: s.id, name: s.name, displayId: s.display_id, outstanding, openingBalance: openingBal,
          type: typeName, customerName: cust?.name || "-", customerPhone: cust?.phone || "-",
          daysSinceLastSale, daysSinceLastPayment, daysSinceLastOrder, isDanger, isInactive,
          isCreditExceeded, hasNoRecentOrders, creditLimit,
        };
      }).sort((a, b) => b.outstanding - a.outstanding);

      const dangerCustomers = storeAnalysis.filter(s => s.isDanger);
      const inactiveCustomers = storeAnalysis.filter(s => s.isInactive);
      const creditExceededStores = storeAnalysis.filter(s => s.isCreditExceeded);
      const noRecentOrdersStores = storeAnalysis.filter(s => s.hasNoRecentOrders);

      // Aging analysis
      const aging = { "0-30": 0, "31-60": 0, "61-90": 0, "90+": 0 };
      storeAnalysis.forEach(s => {
        const days = s.daysSinceLastPayment;
        if (days <= 30) aging["0-30"] += s.outstanding;
        else if (days <= 60) aging["31-60"] += s.outstanding;
        else if (days <= 90) aging["61-90"] += s.outstanding;
        else aging["90+"] += s.outstanding;
      });
      const agingData = Object.entries(aging).map(([name, value]) => ({ name, value }));

      // Outstanding by store type
      const outByType: Record<string, number> = {};
      stores.forEach(s => {
        const typeName = storeTypeMap[s.store_type_id] || "Other";
        outByType[typeName] = (outByType[typeName] || 0) + Number(s.outstanding);
      });
      const outstandingByType = Object.entries(outByType).sort((a, b) => b[1] - a[1]).map(([name, value]) => ({ name, value }));

      // Collection trend (daily last 30 days)
      const thirtyAgo = new Date(); thirtyAgo.setDate(thirtyAgo.getDate() - 30);
      const dailyCollections: Record<string, number> = {};
      const last30 = Array.from({ length: 30 }, (_, i) => {
        const d = new Date(); d.setDate(d.getDate() - (29 - i));
        return d.toISOString().split("T")[0];
      });
      last30.forEach(d => { dailyCollections[d] = 0; });
      recentTxns.forEach(t => {
        const day = t.created_at.split("T")[0];
        if (dailyCollections[day] !== undefined) dailyCollections[day] += Number(t.total_amount);
      });
      const collectionTrend = last30.map(d => ({ date: d.slice(5), amount: dailyCollections[d] }));

      // Payment split
      const paymentSplit = [
        { name: "Cash", value: totalCollectionCash },
        { name: "UPI", value: totalCollectionUpi },
      ].filter(p => p.value > 0);

      return {
        totalOutstanding, totalCollections, collectionRate, totalOpeningBalance,
        storeAnalysis, dangerCustomers, inactiveCustomers, creditExceededStores, noRecentOrdersStores,
        agingData, outstandingByType, collectionTrend, paymentSplit,
        storesWithOutstanding: storeAnalysis.length,
      };
    },
  });

  const exportPDF = () => {
    if (!data) return;
    const doc = new jsPDF({ orientation: "landscape", unit: "mm", format: "a4" });
    const pw = doc.internal.pageSize.getWidth();
    doc.setFillColor(30, 41, 59); doc.rect(0, 0, pw, 18, "F");
    doc.setTextColor(255, 255, 255); doc.setFontSize(14);
    doc.text("Payment & Outstanding Report", 10, 12);
    doc.setFontSize(9); doc.text(`Generated: ${new Date().toLocaleDateString()}`, pw - 10, 12, { align: "right" });

    doc.setTextColor(0, 0, 0);

    // Summary + Aging on left
    autoTable(doc, { startY: 24, head: [["Metric", "Value"]], body: [
      ["Total Outstanding", fmt(data.totalOutstanding)],
      ["Collections (90d)", fmt(data.totalCollections)],
      ["Collection Rate", data.collectionRate + "%"],
      ["Stores with Outstanding", data.storesWithOutstanding],
      ["Danger Customers", data.dangerCustomers.length],
      ["Inactive Customers", data.inactiveCustomers.length],
    ], theme: "grid", styles: { fontSize: 7, cellPadding: 1.5 }, headStyles: { fillColor: [30, 41, 59] }, margin: { left: 10 }, tableWidth: 80 });

    let y = (doc as any).lastAutoTable.finalY + 3;
    autoTable(doc, { startY: y, head: [["Aging Bucket", "Amount"]], body: data.agingData.map(a => [a.name + " days", fmt(a.value)]), theme: "grid", styles: { fontSize: 7, cellPadding: 1.5 }, headStyles: { fillColor: [150, 40, 40] }, margin: { left: 10 }, tableWidth: 80 });

    // Danger customers on right
    autoTable(doc, { startY: 24, head: [["Store", "Outstanding", "Last Sale", "Last Payment", "Type"]], body: data.dangerCustomers.slice(0, 20).map(s => [s.name, fmt(s.outstanding), s.daysSinceLastSale + "d ago", s.daysSinceLastPayment + "d ago", s.type]),
      theme: "grid", styles: { fontSize: 6, cellPadding: 1.2 }, headStyles: { fillColor: [150, 40, 40] }, margin: { left: 100 }, tableWidth: 187 });

    // Top outstanding stores on page 2
    doc.addPage();
    autoTable(doc, { startY: 10, head: [["#", "Store", "Customer", "Phone", "Outstanding", "Opening Bal", "Last Sale", "Last Payment"]],
      body: data.storeAnalysis.slice(0, 40).map((s, i) => [i + 1, s.name, s.customerName, s.customerPhone, fmt(s.outstanding), fmt(s.openingBalance), s.daysSinceLastSale + "d", s.daysSinceLastPayment + "d"]),
      theme: "grid", styles: { fontSize: 6, cellPadding: 1.2 }, headStyles: { fillColor: [30, 41, 59] }, margin: { left: 10, right: 10 },
    });

    doc.save(`payment-outstanding-report.pdf`);
    toast.success("PDF downloaded");
  };

  const exportExcel = () => {
    if (!data) return;
    const wb = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(wb, XLSX.utils.aoa_to_sheet([
      ["Payment & Outstanding Report"], [],
      ["Total Outstanding", data.totalOutstanding], ["Collections (90d)", data.totalCollections],
      ["Collection Rate", data.collectionRate + "%"], ["Danger Customers", data.dangerCustomers.length],
    ]), "Summary");
    XLSX.utils.book_append_sheet(wb, XLSX.utils.json_to_sheet(data.storeAnalysis), "All Stores");
    XLSX.utils.book_append_sheet(wb, XLSX.utils.json_to_sheet(data.dangerCustomers), "Danger");
    XLSX.utils.book_append_sheet(wb, XLSX.utils.json_to_sheet(data.inactiveCustomers), "Inactive");
    XLSX.utils.book_append_sheet(wb, XLSX.utils.json_to_sheet(data.agingData), "Aging");
    XLSX.utils.book_append_sheet(wb, XLSX.utils.json_to_sheet(data.collectionTrend), "Collection Trend");
    XLSX.writeFile(wb, `payment-outstanding-report.xlsx`);
    toast.success("Excel downloaded");
  };

  if (isLoading) return <TableSkeleton />;
  if (!data) return null;
  const d = data;

  return (
    <div className="space-y-4">
      <div className="flex flex-wrap items-end gap-3">
        <div><Label className="text-xs">Inactive threshold (days)</Label><Input type="number" value={inactiveDays} onChange={e => setInactiveDays(Number(e.target.value) || 7)} className="w-28" min={1} /></div>
        <Button variant="outline" size="sm" onClick={exportPDF}><FileText className="h-4 w-4 mr-1" />PDF</Button>
        <Button variant="outline" size="sm" onClick={exportExcel}><FileSpreadsheet className="h-4 w-4 mr-1" />Excel</Button>
      </div>

      <div className="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-6 gap-3">
        <StatCard title="Total Outstanding" value={fmt(d.totalOutstanding)} icon={TrendingDown} iconColor="destructive" />
        <StatCard title="Collections (90d)" value={fmt(d.totalCollections)} icon={Banknote} iconColor="success" />
        <StatCard title="Collection Rate" value={d.collectionRate + "%"} icon={Percent} iconColor="primary" />
        <StatCard title="Stores w/ Dues" value={String(d.storesWithOutstanding)} icon={DollarSign} iconColor="warning" />
        <StatCard title="Danger" value={String(d.dangerCustomers.length)} icon={AlertTriangle} iconColor="destructive" />
        <StatCard title="Inactive" value={String(d.inactiveCustomers.length)} icon={UserX} iconColor="warning" />
        <StatCard title="Credit Exceeded" value={String(d.creditExceededStores.length)} icon={Shield} iconColor="destructive" />
        <StatCard title="No Orders (15d)" value={String(d.noRecentOrdersStores.length)} icon={Clock} iconColor="warning" />
      </div>

      <Tabs defaultValue="danger">
        <TabsList className="flex-wrap h-auto">
          <TabsTrigger value="danger">⚠️ Danger</TabsTrigger>
          <TabsTrigger value="credit">💳 Credit Exceeded</TabsTrigger>
          <TabsTrigger value="noorders">📭 No Orders</TabsTrigger>
          <TabsTrigger value="inactive">Inactive</TabsTrigger>
          <TabsTrigger value="all">All Outstanding</TabsTrigger>
          <TabsTrigger value="aging">Aging</TabsTrigger>
          <TabsTrigger value="trend">Collection Trend</TabsTrigger>
          <TabsTrigger value="bytype">By Store Type</TabsTrigger>
        </TabsList>

        <TabsContent value="danger">
          <Card><CardHeader><CardTitle className="text-sm text-destructive flex items-center gap-2"><AlertTriangle className="h-4 w-4" />Danger Customers — Urgent Collection Needed</CardTitle></CardHeader><CardContent>
            {d.dangerCustomers.length === 0 ? <p className="text-sm text-muted-foreground text-center py-8">No danger customers 🎉</p> : (
              <Table><TableHeader><TableRow>
                <TableHead>#</TableHead><TableHead>Store</TableHead><TableHead>Customer</TableHead><TableHead>Phone</TableHead>
                <TableHead className="text-right">Outstanding</TableHead><TableHead className="text-right">Credit Limit</TableHead>
                <TableHead className="text-right">Last Sale</TableHead><TableHead className="text-right">Last Payment</TableHead>
              </TableRow></TableHeader><TableBody>
                {d.dangerCustomers.map((s, i) => (
                  <TableRow key={s.id} className="bg-destructive/5">
                    <TableCell>{i + 1}</TableCell>
                    <TableCell className="font-medium">{s.name}</TableCell>
                    <TableCell>{s.customerName}</TableCell>
                    <TableCell>{s.customerPhone}</TableCell>
                    <TableCell className="text-right font-bold text-destructive">{fmt(s.outstanding)}</TableCell>
                    <TableCell className="text-right">{fmt(s.openingBalance)}</TableCell>
                    <TableCell className="text-right">{s.daysSinceLastSale < 999 ? s.daysSinceLastSale + "d ago" : "Never"}</TableCell>
                    <TableCell className="text-right">{s.daysSinceLastPayment < 999 ? s.daysSinceLastPayment + "d ago" : "Never"}</TableCell>
                  </TableRow>
                ))}
              </TableBody></Table>
            )}
          </CardContent></Card>
        </TabsContent>

        <TabsContent value="credit">
          <Card><CardHeader><CardTitle className="text-sm flex items-center gap-2 text-destructive"><Shield className="h-4 w-4" />Credit Limit Exceeded — Outstanding greater than allowed credit</CardTitle></CardHeader><CardContent>
            {d.creditExceededStores.length === 0 ? <p className="text-sm text-muted-foreground text-center py-8">No stores exceeding credit limit 🎉</p> : (
              <Table><TableHeader><TableRow>
                <TableHead>#</TableHead><TableHead>Store</TableHead><TableHead>Type</TableHead><TableHead>Customer</TableHead><TableHead>Phone</TableHead>
                <TableHead className="text-right">Outstanding</TableHead><TableHead className="text-right">Credit Limit</TableHead><TableHead className="text-right">Excess</TableHead>
              </TableRow></TableHeader><TableBody>
                {d.creditExceededStores.map((s, i) => (
                  <TableRow key={s.id} className="bg-destructive/5">
                    <TableCell>{i + 1}</TableCell>
                    <TableCell className="font-medium">{s.name}</TableCell>
                    <TableCell><Badge variant="outline">{s.type}</Badge></TableCell>
                    <TableCell>{s.customerName}</TableCell>
                    <TableCell>{s.customerPhone}</TableCell>
                    <TableCell className="text-right font-bold text-destructive">{fmt(s.outstanding)}</TableCell>
                    <TableCell className="text-right">{s.creditLimit > 0 ? fmt(s.creditLimit) : "—"}</TableCell>
                    <TableCell className="text-right font-bold text-destructive">{s.creditLimit > 0 ? fmt(s.outstanding - s.creditLimit) : "—"}</TableCell>
                  </TableRow>
                ))}
              </TableBody></Table>
            )}
          </CardContent></Card>
        </TabsContent>

        <TabsContent value="noorders">
          <Card><CardHeader><CardTitle className="text-sm flex items-center gap-2 text-warning"><Clock className="h-4 w-4" />No Orders in Last 15 Days — Outstanding with no recent activity</CardTitle></CardHeader><CardContent>
            {d.noRecentOrdersStores.length === 0 ? <p className="text-sm text-muted-foreground text-center py-8">All active stores have recent orders</p> : (
              <Table><TableHeader><TableRow>
                <TableHead>#</TableHead><TableHead>Store</TableHead><TableHead>Type</TableHead><TableHead>Customer</TableHead>
                <TableHead className="text-right">Outstanding</TableHead><TableHead className="text-right">Last Order</TableHead><TableHead className="text-right">Last Sale</TableHead>
              </TableRow></TableHeader><TableBody>
                {d.noRecentOrdersStores.map((s, i) => (
                  <TableRow key={s.id}>
                    <TableCell>{i + 1}</TableCell>
                    <TableCell className="font-medium">{s.name}</TableCell>
                    <TableCell><Badge variant="outline">{s.type}</Badge></TableCell>
                    <TableCell>{s.customerName}</TableCell>
                    <TableCell className="text-right font-bold">{fmt(s.outstanding)}</TableCell>
                    <TableCell className="text-right">{s.daysSinceLastOrder < 999 ? s.daysSinceLastOrder + "d ago" : "Never"}</TableCell>
                    <TableCell className="text-right">{s.daysSinceLastSale < 999 ? s.daysSinceLastSale + "d ago" : "Never"}</TableCell>
                  </TableRow>
                ))}
              </TableBody></Table>
            )}
          </CardContent></Card>
        </TabsContent>

        <TabsContent value="inactive">
          <Card><CardHeader><CardTitle className="text-sm flex items-center gap-2"><UserX className="h-4 w-4" />Inactive — Outstanding but no orders in {inactiveDays}+ days</CardTitle></CardHeader><CardContent>
            {d.inactiveCustomers.length === 0 ? <p className="text-sm text-muted-foreground text-center py-8">No inactive customers</p> : (
              <Table><TableHeader><TableRow>
                <TableHead>#</TableHead><TableHead>Store</TableHead><TableHead>Type</TableHead>
                <TableHead className="text-right">Outstanding</TableHead><TableHead className="text-right">Last Sale</TableHead>
                <TableHead className="text-right">Last Payment</TableHead>
              </TableRow></TableHeader><TableBody>
                {d.inactiveCustomers.map((s, i) => (
                  <TableRow key={s.id}>
                    <TableCell>{i + 1}</TableCell>
                    <TableCell className="font-medium">{s.name}</TableCell>
                    <TableCell><Badge variant="outline">{s.type}</Badge></TableCell>
                    <TableCell className="text-right font-bold">{fmt(s.outstanding)}</TableCell>
                    <TableCell className="text-right">{s.daysSinceLastSale < 999 ? s.daysSinceLastSale + "d ago" : "Never"}</TableCell>
                    <TableCell className="text-right">{s.daysSinceLastPayment < 999 ? s.daysSinceLastPayment + "d ago" : "Never"}</TableCell>
                  </TableRow>
                ))}
              </TableBody></Table>
            )}
          </CardContent></Card>
        </TabsContent>

        <TabsContent value="all">
          <Card><CardContent className="pt-4">
            <Table><TableHeader><TableRow>
              <TableHead>#</TableHead><TableHead>Store</TableHead><TableHead>Type</TableHead><TableHead>Customer</TableHead>
              <TableHead className="text-right">Outstanding</TableHead><TableHead className="text-right">Credit Limit</TableHead>
              <TableHead className="text-right">Last Payment</TableHead><TableHead>Status</TableHead>
            </TableRow></TableHeader><TableBody>
              {d.storeAnalysis.slice(0, 50).map((s, i) => (
                <TableRow key={s.id}>
                  <TableCell>{i + 1}</TableCell>
                  <TableCell className="font-medium">{s.name}</TableCell>
                  <TableCell><Badge variant="outline">{s.type}</Badge></TableCell>
                  <TableCell>{s.customerName}</TableCell>
                  <TableCell className="text-right font-bold">{fmt(s.outstanding)}</TableCell>
                  <TableCell className="text-right">{fmt(s.openingBalance)}</TableCell>
                  <TableCell className="text-right">{s.daysSinceLastPayment < 999 ? s.daysSinceLastPayment + "d" : "-"}</TableCell>
                  <TableCell>
                    {s.isDanger && <Badge variant="destructive" className="text-[10px]">Danger</Badge>}
                    {s.isInactive && !s.isDanger && <Badge variant="secondary" className="text-[10px]">Inactive</Badge>}
                  </TableCell>
                </TableRow>
              ))}
            </TableBody></Table>
          </CardContent></Card>
        </TabsContent>

        <TabsContent value="aging">
          <Card><CardHeader><CardTitle className="text-sm">Outstanding Aging Analysis</CardTitle></CardHeader><CardContent>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
              <ResponsiveContainer width="100%" height={250}>
                <BarChart data={d.agingData}>
                  <CartesianGrid strokeDasharray="3 3" stroke="hsl(var(--border))" />
                  <XAxis dataKey="name" tick={{ fontSize: 10 }} stroke="hsl(var(--muted-foreground))" />
                  <YAxis tick={{ fontSize: 10 }} stroke="hsl(var(--muted-foreground))" />
                  <Tooltip formatter={(v: number) => fmt(v)} />
                  <Bar dataKey="value" radius={[4, 4, 0, 0]} name="Outstanding">
                    {d.agingData.map((_, i) => <Cell key={i} fill={COLORS[i % COLORS.length]} />)}
                  </Bar>
                </BarChart>
              </ResponsiveContainer>
              <div className="space-y-3 py-4">
                {d.agingData.map((a, i) => (
                  <div key={a.name} className="flex items-center justify-between">
                    <div className="flex items-center gap-2">
                      <div className="h-3 w-3 rounded-full" style={{ backgroundColor: COLORS[i] }} />
                      <span className="text-sm font-medium">{a.name} days</span>
                    </div>
                    <span className="font-bold">{fmt(a.value)}</span>
                  </div>
                ))}
              </div>
            </div>
          </CardContent></Card>
        </TabsContent>

        <TabsContent value="trend">
          <Card><CardHeader><CardTitle className="text-sm">Collection Trend (Last 30 Days)</CardTitle></CardHeader><CardContent>
            <ResponsiveContainer width="100%" height={280}>
              <LineChart data={d.collectionTrend}>
                <CartesianGrid strokeDasharray="3 3" stroke="hsl(var(--border))" />
                <XAxis dataKey="date" tick={{ fontSize: 10 }} stroke="hsl(var(--muted-foreground))" />
                <YAxis tick={{ fontSize: 10 }} stroke="hsl(var(--muted-foreground))" />
                <Tooltip contentStyle={{ backgroundColor: "hsl(var(--card))", border: "1px solid hsl(var(--border))", borderRadius: "8px" }} formatter={(v: number) => fmt(v)} />
                <Line type="monotone" dataKey="amount" stroke="hsl(var(--chart-2))" strokeWidth={2} dot={false} name="Collections" />
              </LineChart>
            </ResponsiveContainer>
          </CardContent></Card>
        </TabsContent>

        <TabsContent value="bytype">
          <Card><CardHeader><CardTitle className="text-sm">Outstanding by Store Type</CardTitle></CardHeader><CardContent>
            {d.outstandingByType.length === 0 ? <p className="text-sm text-muted-foreground text-center py-8">No data</p> : (
              <ResponsiveContainer width="100%" height={280}>
                <BarChart data={d.outstandingByType}>
                  <CartesianGrid strokeDasharray="3 3" stroke="hsl(var(--border))" />
                  <XAxis dataKey="name" tick={{ fontSize: 10 }} stroke="hsl(var(--muted-foreground))" />
                  <YAxis tick={{ fontSize: 10 }} stroke="hsl(var(--muted-foreground))" />
                  <Tooltip formatter={(v: number) => fmt(v)} />
                  <Bar dataKey="value" fill="hsl(0, 72%, 51%)" radius={[4, 4, 0, 0]} name="Outstanding" />
                </BarChart>
              </ResponsiveContainer>
            )}
          </CardContent></Card>
        </TabsContent>
      </Tabs>
    </div>
  );
}

import { useState, useMemo } from "react";
import { useQuery } from "@tanstack/react-query";
import { supabase } from "@/integrations/supabase/client";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { Input } from "@/components/ui/input";
import { Loader2, TrendingUp, TrendingDown, ArrowUpRight, ArrowDownRight, DollarSign, Search, History } from "lucide-react";
import { format, subMonths, startOfMonth } from "date-fns";
import { ReportFilters, DateRange } from "./ReportFilters";
import { ReportExportBar } from "./ReportExportBar";
import { ReportSummaryCards } from "./ReportSummaryCards";
import { LineChart, Line, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, Legend } from "recharts";
import jsPDF from "jspdf";
import autoTable from "jspdf-autotable";
import * as XLSX from "xlsx";

interface PriceChange {
  id: string;
  product_id: string;
  product_name: string;
  product_display_id: string;
  old_mrp: number;
  new_mrp: number;
  old_gst_rate: number;
  new_gst_rate: number;
  price_change: number;
  price_change_percent: number;
  changed_by_name: string;
  reason: string;
  changed_at: string;
}

export default function PriceChangeReport() {
  const [dateRange, setDateRange] = useState<DateRange>({
    from: startOfMonth(subMonths(new Date(), 3)),
    to: new Date(),
  });
  const [search, setSearch] = useState("");
  const [filter, setFilter] = useState<"all" | "increased" | "decreased">("all");

  // Fetch price change history
  const { data: priceChanges = [], isLoading } = useQuery({
    queryKey: ["price-change-history", dateRange],
    queryFn: async () => {
      const { data } = await supabase
        .from("price_change_history")
        .select(`
          id,
          product_id,
          old_mrp,
          new_mrp,
          old_gst_rate,
          new_gst_rate,
          reason,
          changed_at,
          products(name, display_id),
          profiles:changed_by(full_name)
        `)
        .gte("changed_at", format(dateRange.from, "yyyy-MM-dd"))
        .lte("changed_at", format(dateRange.to, "yyyy-MM-dd") + "T23:59:59")
        .order("changed_at", { ascending: false });
      
      return (data || []).map((pc: any) => ({
        id: pc.id,
        product_id: pc.product_id,
        product_name: pc.products?.name || "Unknown",
        product_display_id: pc.products?.display_id || "",
        old_mrp: Number(pc.old_mrp),
        new_mrp: Number(pc.new_mrp),
        old_gst_rate: Number(pc.old_gst_rate || 0),
        new_gst_rate: Number(pc.new_gst_rate || 0),
        price_change: Number(pc.new_mrp) - Number(pc.old_mrp),
        price_change_percent: Number(pc.old_mrp) > 0 
          ? ((Number(pc.new_mrp) - Number(pc.old_mrp)) / Number(pc.old_mrp)) * 100 
          : 0,
        changed_by_name: pc.profiles?.full_name || "System",
        reason: pc.reason || "",
        changed_at: pc.changed_at,
      }));
    },
  });

  // Filter and search
  const filteredChanges = useMemo(() => {
    let filtered = priceChanges;

    if (search) {
      const s = search.toLowerCase();
      filtered = filtered.filter((pc: PriceChange) =>
        pc.product_name.toLowerCase().includes(s) ||
        pc.product_display_id.toLowerCase().includes(s) ||
        pc.reason?.toLowerCase().includes(s)
      );
    }

    if (filter === "increased") {
      filtered = filtered.filter((pc: PriceChange) => pc.price_change > 0);
    } else if (filter === "decreased") {
      filtered = filtered.filter((pc: PriceChange) => pc.price_change < 0);
    }

    return filtered;
  }, [priceChanges, search, filter]);

  // Summary
  const summary = useMemo(() => {
    const totalChanges = filteredChanges.length;
    const increases = filteredChanges.filter((pc: PriceChange) => pc.price_change > 0);
    const decreases = filteredChanges.filter((pc: PriceChange) => pc.price_change < 0);
    
    const avgIncrease = increases.length > 0 
      ? increases.reduce((sum, pc) => sum + pc.price_change_percent, 0) / increases.length 
      : 0;
    const avgDecrease = decreases.length > 0 
      ? Math.abs(decreases.reduce((sum, pc) => sum + pc.price_change_percent, 0) / decreases.length)
      : 0;

    // Unique products changed
    const uniqueProducts = new Set(filteredChanges.map((pc: PriceChange) => pc.product_id)).size;

    return {
      totalChanges,
      increases: increases.length,
      decreases: decreases.length,
      avgIncrease,
      avgDecrease,
      uniqueProducts,
    };
  }, [filteredChanges]);

  // Price change trend by day
  const trendData = useMemo(() => {
    const byDate: Record<string, { date: string; increases: number; decreases: number }> = {};

    filteredChanges.forEach((pc: PriceChange) => {
      const date = format(new Date(pc.changed_at), "MMM d");
      if (!byDate[date]) {
        byDate[date] = { date, increases: 0, decreases: 0 };
      }
      if (pc.price_change > 0) {
        byDate[date].increases++;
      } else if (pc.price_change < 0) {
        byDate[date].decreases++;
      }
    });

    return Object.values(byDate).sort((a, b) => 
      new Date(a.date).getTime() - new Date(b.date).getTime()
    );
  }, [filteredChanges]);

  const summaryCards = [
    { label: "Total Changes", value: summary.totalChanges.toString(), icon: History, iconColor: "blue" as const },
    { label: "Price Increases", value: summary.increases.toString(), icon: TrendingUp, iconColor: "green" as const },
    { label: "Price Decreases", value: summary.decreases.toString(), icon: TrendingDown, iconColor: "red" as const },
    { label: "Products Affected", value: summary.uniqueProducts.toString(), icon: DollarSign, iconColor: "yellow" as const },
  ];

  const exportPDF = () => {
    const doc = new jsPDF();
    doc.setFontSize(16);
    doc.text("Price Change Report", 14, 15);
    doc.setFontSize(10);
    doc.text(`Period: ${format(dateRange.from, "MMM d, yyyy")} - ${format(dateRange.to, "MMM d, yyyy")}`, 14, 23);

    autoTable(doc, {
      startY: 30,
      head: [["Date", "Product", "Old Price", "New Price", "Change", "Change %", "Changed By"]],
      body: filteredChanges.map((pc: PriceChange) => [
        format(new Date(pc.changed_at), "dd/MM/yy HH:mm"),
        pc.product_name,
        `₹${pc.old_mrp.toLocaleString()}`,
        `₹${pc.new_mrp.toLocaleString()}`,
        `₹${pc.price_change.toLocaleString()}`,
        `${pc.price_change_percent.toFixed(1)}%`,
        pc.changed_by_name,
      ]),
      styles: { fontSize: 8 },
      headStyles: { fillColor: [59, 130, 246] },
    });

    doc.save(`price-change-report-${format(dateRange.from, "yyyyMMdd")}-${format(dateRange.to, "yyyyMMdd")}.pdf`);
  };

  const exportExcel = () => {
    const ws = XLSX.utils.json_to_sheet(filteredChanges.map((pc: PriceChange) => ({
      "Date": format(new Date(pc.changed_at), "yyyy-MM-dd HH:mm"),
      "Product ID": pc.product_display_id,
      "Product Name": pc.product_name,
      "Old MRP": pc.old_mrp,
      "New MRP": pc.new_mrp,
      "Price Change": pc.price_change,
      "Change %": pc.price_change_percent.toFixed(2),
      "Old GST Rate": pc.old_gst_rate,
      "New GST Rate": pc.new_gst_rate,
      "Changed By": pc.changed_by_name,
      "Reason": pc.reason,
    })));
    const wb = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(wb, ws, "Price Changes");
    XLSX.writeFile(wb, `price-change-report-${format(dateRange.from, "yyyyMMdd")}-${format(dateRange.to, "yyyyMMdd")}.xlsx`);
  };

  return (
    <div className="space-y-6">
      <div className="flex flex-col lg:flex-row lg:items-end gap-4">
        <ReportFilters dateRange={dateRange} onDateRangeChange={setDateRange} />
        <div className="relative flex-1 max-w-xs">
          <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-muted-foreground" />
          <Input
            placeholder="Search products..."
            value={search}
            onChange={(e) => setSearch(e.target.value)}
            className="pl-9"
          />
        </div>
        <div className="flex gap-2">
          <Badge 
            variant={filter === "all" ? "default" : "outline"} 
            className="cursor-pointer"
            onClick={() => setFilter("all")}
          >
            All
          </Badge>
          <Badge 
            variant={filter === "increased" ? "default" : "outline"} 
            className="cursor-pointer"
            onClick={() => setFilter("increased")}
          >
            <ArrowUpRight className="h-3 w-3 mr-1" />
            Increased
          </Badge>
          <Badge 
            variant={filter === "decreased" ? "default" : "outline"} 
            className="cursor-pointer"
            onClick={() => setFilter("decreased")}
          >
            <ArrowDownRight className="h-3 w-3 mr-1" />
            Decreased
          </Badge>
        </div>
      </div>

      <ReportExportBar onExportPDF={exportPDF} onExportExcel={exportExcel} />

      {isLoading ? (
        <div className="flex items-center justify-center py-12">
          <Loader2 className="h-8 w-8 animate-spin text-muted-foreground" />
        </div>
      ) : (
        <>
          <ReportSummaryCards cards={summaryCards} />

          {/* Trend Chart */}
          {trendData.length > 1 && (
            <Card>
              <CardHeader>
                <CardTitle className="text-base">Price Change Activity</CardTitle>
              </CardHeader>
              <CardContent>
                <ResponsiveContainer width="100%" height={250}>
                  <LineChart data={trendData}>
                    <CartesianGrid strokeDasharray="3 3" />
                    <XAxis dataKey="date" tick={{ fontSize: 11 }} />
                    <YAxis />
                    <Tooltip />
                    <Legend />
                    <Line type="monotone" dataKey="increases" name="Increases" stroke="#10b981" strokeWidth={2} />
                    <Line type="monotone" dataKey="decreases" name="Decreases" stroke="#ef4444" strokeWidth={2} />
                  </LineChart>
                </ResponsiveContainer>
              </CardContent>
            </Card>
          )}

          {/* Average Stats */}
          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            <Card>
              <CardContent className="pt-6">
                <div className="flex items-center gap-3">
                  <div className="p-3 rounded-full bg-green-100">
                    <TrendingUp className="h-5 w-5 text-green-600" />
                  </div>
                  <div>
                    <p className="text-sm text-muted-foreground">Average Price Increase</p>
                    <p className="text-2xl font-bold text-green-600">+{summary.avgIncrease.toFixed(1)}%</p>
                  </div>
                </div>
              </CardContent>
            </Card>
            <Card>
              <CardContent className="pt-6">
                <div className="flex items-center gap-3">
                  <div className="p-3 rounded-full bg-red-100">
                    <TrendingDown className="h-5 w-5 text-red-600" />
                  </div>
                  <div>
                    <p className="text-sm text-muted-foreground">Average Price Decrease</p>
                    <p className="text-2xl font-bold text-red-600">-{summary.avgDecrease.toFixed(1)}%</p>
                  </div>
                </div>
              </CardContent>
            </Card>
          </div>

          {/* Price Change List */}
          <Card>
            <CardHeader>
              <CardTitle className="text-base">Price Change History ({filteredChanges.length})</CardTitle>
            </CardHeader>
            <CardContent>
              {filteredChanges.length === 0 ? (
                <p className="text-center text-muted-foreground py-12">No price changes found for the selected period</p>
              ) : (
                <div className="overflow-x-auto">
                  <table className="w-full text-sm">
                    <thead>
                      <tr className="border-b bg-muted/50">
                        <th className="text-left p-3 font-medium">Date</th>
                        <th className="text-left p-3 font-medium">Product</th>
                        <th className="text-right p-3 font-medium">Old Price</th>
                        <th className="text-right p-3 font-medium">New Price</th>
                        <th className="text-right p-3 font-medium">Change</th>
                        <th className="text-left p-3 font-medium hidden md:table-cell">Changed By</th>
                        <th className="text-left p-3 font-medium hidden lg:table-cell">Reason</th>
                      </tr>
                    </thead>
                    <tbody>
                      {filteredChanges.slice(0, 100).map((pc: PriceChange) => (
                        <tr key={pc.id} className="border-b hover:bg-muted/30">
                          <td className="p-3 text-muted-foreground text-xs">
                            {format(new Date(pc.changed_at), "dd/MM/yy HH:mm")}
                          </td>
                          <td className="p-3">
                            <p className="font-medium">{pc.product_name}</p>
                            <p className="text-xs text-muted-foreground">{pc.product_display_id}</p>
                          </td>
                          <td className="p-3 text-right">₹{pc.old_mrp.toLocaleString()}</td>
                          <td className="p-3 text-right font-medium">₹{pc.new_mrp.toLocaleString()}</td>
                          <td className="p-3 text-right">
                            <div className="flex items-center justify-end gap-1">
                              {pc.price_change > 0 ? (
                                <ArrowUpRight className="h-4 w-4 text-green-600" />
                              ) : (
                                <ArrowDownRight className="h-4 w-4 text-red-600" />
                              )}
                              <span className={pc.price_change > 0 ? "text-green-600" : "text-red-600"}>
                                {pc.price_change_percent.toFixed(1)}%
                              </span>
                            </div>
                          </td>
                          <td className="p-3 hidden md:table-cell text-muted-foreground">{pc.changed_by_name}</td>
                          <td className="p-3 hidden lg:table-cell text-muted-foreground truncate max-w-[200px]">
                            {pc.reason || "—"}
                          </td>
                        </tr>
                      ))}
                    </tbody>
                  </table>
                </div>
              )}
              {filteredChanges.length > 100 && (
                <p className="text-center text-muted-foreground mt-4 text-sm">
                  Showing 100 of {filteredChanges.length} changes. Export to see all.
                </p>
              )}
            </CardContent>
          </Card>
        </>
      )}
    </div>
  );
}

import { useState } from "react";
import { useQuery } from "@tanstack/react-query";
import { supabase } from "@/integrations/supabase/client";
import { StatCard } from "@/components/shared/StatCard";
import { TableSkeleton } from "@/components/shared/TableSkeleton";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Tabs, TabsContent, TabsList, TabsTrigger } from "@/components/ui/tabs";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import { Table, TableBody, TableCell, TableHead, TableHeader, TableRow } from "@/components/ui/table";
import { toast } from "sonner";
import {
  Package, TrendingUp, TrendingDown, BarChart3,
  FileText, FileSpreadsheet, Layers,
} from "lucide-react";
import {
  BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, Legend,
  PieChart, Pie, Cell,
} from "recharts";
import jsPDF from "jspdf";
import autoTable from "jspdf-autotable";
import * as XLSX from "xlsx";

const fmt = (n: number) => `₹${n.toLocaleString("en-IN")}`;
const COLORS = ["hsl(217, 91%, 50%)", "hsl(142, 72%, 42%)", "hsl(38, 92%, 50%)", "hsl(280, 65%, 60%)", "hsl(0, 72%, 51%)", "hsl(190, 80%, 45%)", "hsl(330, 70%, 50%)"];

export default function ProductReport() {
  const today = new Date();
  const thirtyAgo = new Date(today); thirtyAgo.setDate(thirtyAgo.getDate() - 30);
  const [from, setFrom] = useState(thirtyAgo.toISOString().split("T")[0]);
  const [to, setTo] = useState(today.toISOString().split("T")[0]);

  const { data, isLoading } = useQuery({
    queryKey: ["product-report", from, to],
    queryFn: async () => {
      const start = from + "T00:00:00", end = to + "T23:59:59";
      const [saleItemsRes, salesRes, productsRes, storesRes, storeTypesRes] = await Promise.all([
        supabase.from("sale_items").select("*, products(name, unit, category, product_group)").gte("created_at", start).lte("created_at", end),
        supabase.from("sales").select("id, store_id, created_at").gte("created_at", start).lte("created_at", end),
        supabase.from("products").select("id, name, sku, unit, category, product_group, base_price, is_active"),
        supabase.from("stores").select("id, name, store_type_id"),
        supabase.from("store_types").select("id, name"),
      ]);

      const saleItems = saleItemsRes.data || [];
      const sales = salesRes.data || [];
      const products = productsRes.data || [];
      const stores = storesRes.data || [];
      const storeTypes = storeTypesRes.data || [];

      const storeTypeMap = Object.fromEntries(storeTypes.map(t => [t.id, t.name]));
      const storeMap = Object.fromEntries(stores.map(s => [s.id, s]));
      const saleStoreMap = Object.fromEntries(sales.map(s => [s.id, s.store_id]));

      // Product performance
      const prodPerf: Record<string, { name: string; unit: string; category: string; group: string; qty: number; revenue: number; saleCount: number }> = {};
      saleItems.forEach(item => {
        const key = item.product_id;
        const p = item.products as any;
        if (!prodPerf[key]) prodPerf[key] = { name: p?.name || "Unknown", unit: p?.unit || "PCS", category: p?.category || "Uncategorized", group: p?.product_group || "-", qty: 0, revenue: 0, saleCount: 0 };
        prodPerf[key].qty += Number(item.quantity);
        prodPerf[key].revenue += Number(item.total_price);
        prodPerf[key].saleCount += 1;
      });

      const productList = Object.entries(prodPerf).map(([id, p]) => ({ id, ...p, avgQty: p.saleCount > 0 ? p.qty / p.saleCount : 0 }));
      const fastMovers = [...productList].sort((a, b) => b.qty - a.qty);
      const slowMovers = [...productList].sort((a, b) => a.qty - b.qty);

      // Products not sold
      const soldIds = new Set(Object.keys(prodPerf));
      const notSold = products.filter(p => p.is_active && !soldIds.has(p.id)).map(p => ({ name: p.name, sku: p.sku, category: p.category || "-" }));

      // Category breakdown
      const catPerf: Record<string, { qty: number; revenue: number }> = {};
      productList.forEach(p => {
        if (!catPerf[p.category]) catPerf[p.category] = { qty: 0, revenue: 0 };
        catPerf[p.category].qty += p.qty;
        catPerf[p.category].revenue += p.revenue;
      });
      const categoryData = Object.entries(catPerf).sort((a, b) => b[1].revenue - a[1].revenue).map(([name, v]) => ({ name, ...v }));

      // Store type vs product (top 5 products x store types)
      const storeTypeProd: Record<string, Record<string, number>> = {};
      saleItems.forEach(item => {
        const saleId = item.sale_id;
        const storeId = saleStoreMap[saleId];
        if (!storeId) return;
        const st = storeMap[storeId];
        const typeName = st ? storeTypeMap[st.store_type_id] || "Other" : "Other";
        const pName = (item.products as any)?.name || "Unknown";
        if (!storeTypeProd[typeName]) storeTypeProd[typeName] = {};
        storeTypeProd[typeName][pName] = (storeTypeProd[typeName][pName] || 0) + Number(item.quantity);
      });

      // Flatten for chart: top 5 products across all types
      const top5Products = fastMovers.slice(0, 5).map(p => p.name);
      const storeTypeProductData = Object.entries(storeTypeProd).map(([type, prods]) => {
        const row: any = { type };
        top5Products.forEach(p => { row[p] = prods[p] || 0; });
        return row;
      });

      const totalQty = productList.reduce((s, p) => s + p.qty, 0);
      const totalRevenue = productList.reduce((s, p) => s + p.revenue, 0);

      return {
        fastMovers, slowMovers, notSold, categoryData, storeTypeProductData, top5Products,
        totalQty, totalRevenue, uniqueProducts: productList.length,
      };
    },
  });

  const exportPDF = () => {
    if (!data) return;
    const doc = new jsPDF({ orientation: "landscape", unit: "mm", format: "a4" });
    const pw = doc.internal.pageSize.getWidth();
    doc.setFillColor(30, 41, 59); doc.rect(0, 0, pw, 18, "F");
    doc.setTextColor(255, 255, 255); doc.setFontSize(14);
    doc.text("Product Report", 10, 12);
    doc.setFontSize(9); doc.text(`${from} to ${to}`, pw - 10, 12, { align: "right" });

    doc.setTextColor(0, 0, 0);
    autoTable(doc, {
      startY: 24,
      head: [["#", "Product", "Category", "Qty Sold", "Revenue", "Avg/Sale"]],
      body: data.fastMovers.map((p, i) => [i + 1, p.name, p.category, p.qty, fmt(p.revenue), p.avgQty.toFixed(1)]),
      theme: "grid", styles: { fontSize: 6, cellPadding: 1.2 }, headStyles: { fillColor: [30, 41, 59] },
      margin: { left: 10 }, tableWidth: 140,
    });

    if (data.notSold.length > 0) {
      autoTable(doc, {
        startY: 24, head: [["Not Sold Products", "SKU", "Category"]],
        body: data.notSold.map(p => [p.name, p.sku, p.category]),
        theme: "grid", styles: { fontSize: 6, cellPadding: 1.2 }, headStyles: { fillColor: [150, 40, 40] },
        margin: { left: 160 }, tableWidth: 127,
      });
    }
    doc.save(`product-report-${from}-to-${to}.pdf`);
    toast.success("PDF downloaded");
  };

  const exportExcel = () => {
    if (!data) return;
    const wb = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(wb, XLSX.utils.json_to_sheet(data.fastMovers), "Products");
    XLSX.utils.book_append_sheet(wb, XLSX.utils.json_to_sheet(data.categoryData), "Categories");
    XLSX.utils.book_append_sheet(wb, XLSX.utils.json_to_sheet(data.notSold), "Not Sold");
    XLSX.utils.book_append_sheet(wb, XLSX.utils.json_to_sheet(data.storeTypeProductData), "Store Type Products");
    XLSX.writeFile(wb, `product-report-${from}-to-${to}.xlsx`);
    toast.success("Excel downloaded");
  };

  if (isLoading) return <TableSkeleton />;
  if (!data) return null;
  const d = data;

  return (
    <div className="space-y-4">
      <div className="flex flex-wrap items-end gap-3">
        <div><Label className="text-xs">From</Label><Input type="date" value={from} onChange={e => setFrom(e.target.value)} className="w-40" /></div>
        <div><Label className="text-xs">To</Label><Input type="date" value={to} onChange={e => setTo(e.target.value)} className="w-40" /></div>
        <Button variant="outline" size="sm" onClick={exportPDF}><FileText className="h-4 w-4 mr-1" />PDF</Button>
        <Button variant="outline" size="sm" onClick={exportExcel}><FileSpreadsheet className="h-4 w-4 mr-1" />Excel</Button>
      </div>

      <div className="grid grid-cols-2 md:grid-cols-4 gap-3">
        <StatCard title="Total Qty Sold" value={String(d.totalQty)} icon={Package} iconColor="primary" />
        <StatCard title="Total Revenue" value={fmt(d.totalRevenue)} icon={TrendingUp} iconColor="success" />
        <StatCard title="Products Sold" value={String(d.uniqueProducts)} icon={Layers} iconColor="purple" />
        <StatCard title="Not Sold" value={String(d.notSold.length)} icon={TrendingDown} iconColor="destructive" />
      </div>

      <Tabs defaultValue="fast">
        <TabsList className="flex-wrap h-auto">
          <TabsTrigger value="fast">Fast Movers</TabsTrigger>
          <TabsTrigger value="slow">Slow Movers</TabsTrigger>
          <TabsTrigger value="category">By Category</TabsTrigger>
          <TabsTrigger value="storetype">Store Type × Product</TabsTrigger>
          <TabsTrigger value="notsold">Not Sold</TabsTrigger>
        </TabsList>

        <TabsContent value="fast">
          <Card><CardContent className="pt-4">
            <Table><TableHeader><TableRow>
              <TableHead>#</TableHead><TableHead>Product</TableHead><TableHead>Category</TableHead>
              <TableHead className="text-right">Qty</TableHead><TableHead className="text-right">Revenue</TableHead>
              <TableHead className="text-right">Avg/Sale</TableHead>
            </TableRow></TableHeader><TableBody>
              {d.fastMovers.slice(0, 25).map((p, i) => (
                <TableRow key={p.id}>
                  <TableCell><Badge variant={i < 3 ? "default" : "secondary"}>{i + 1}</Badge></TableCell>
                  <TableCell className="font-medium">{p.name}</TableCell>
                  <TableCell><Badge variant="outline">{p.category}</Badge></TableCell>
                  <TableCell className="text-right font-bold">{p.qty}</TableCell>
                  <TableCell className="text-right">{fmt(p.revenue)}</TableCell>
                  <TableCell className="text-right">{p.avgQty.toFixed(1)}</TableCell>
                </TableRow>
              ))}
            </TableBody></Table>
          </CardContent></Card>
        </TabsContent>

        <TabsContent value="slow">
          <Card><CardContent className="pt-4">
            <Table><TableHeader><TableRow>
              <TableHead>#</TableHead><TableHead>Product</TableHead><TableHead>Category</TableHead>
              <TableHead className="text-right">Qty</TableHead><TableHead className="text-right">Revenue</TableHead>
            </TableRow></TableHeader><TableBody>
              {d.slowMovers.slice(0, 25).map((p, i) => (
                <TableRow key={p.id}>
                  <TableCell>{i + 1}</TableCell>
                  <TableCell className="font-medium">{p.name}</TableCell>
                  <TableCell><Badge variant="outline">{p.category}</Badge></TableCell>
                  <TableCell className="text-right text-destructive font-bold">{p.qty}</TableCell>
                  <TableCell className="text-right">{fmt(p.revenue)}</TableCell>
                </TableRow>
              ))}
            </TableBody></Table>
          </CardContent></Card>
        </TabsContent>

        <TabsContent value="category">
          <Card><CardHeader><CardTitle className="text-sm">Revenue by Category</CardTitle></CardHeader><CardContent>
            {d.categoryData.length === 0 ? <p className="text-sm text-muted-foreground text-center py-8">No data</p> : (
              <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                <ResponsiveContainer width="100%" height={280}>
                  <BarChart data={d.categoryData}>
                    <CartesianGrid strokeDasharray="3 3" stroke="hsl(var(--border))" />
                    <XAxis dataKey="name" tick={{ fontSize: 9 }} stroke="hsl(var(--muted-foreground))" />
                    <YAxis tick={{ fontSize: 10 }} stroke="hsl(var(--muted-foreground))" />
                    <Tooltip /><Bar dataKey="revenue" fill="hsl(var(--primary))" radius={[4, 4, 0, 0]} name="Revenue" />
                  </BarChart>
                </ResponsiveContainer>
                <ResponsiveContainer width="100%" height={280}>
                  <PieChart><Pie data={d.categoryData} cx="50%" cy="50%" innerRadius={40} outerRadius={90} dataKey="revenue" label={({ name }) => name}>
                    {d.categoryData.map((_, i) => <Cell key={i} fill={COLORS[i % COLORS.length]} />)}
                  </Pie><Tooltip formatter={(v: number) => fmt(v)} /></PieChart>
                </ResponsiveContainer>
              </div>
            )}
          </CardContent></Card>
        </TabsContent>

        <TabsContent value="storetype">
          <Card><CardHeader><CardTitle className="text-sm">Top 5 Products by Store Type (Qty)</CardTitle></CardHeader><CardContent>
            {d.storeTypeProductData.length === 0 ? <p className="text-sm text-muted-foreground text-center py-8">No data</p> : (
              <ResponsiveContainer width="100%" height={300}>
                <BarChart data={d.storeTypeProductData}>
                  <CartesianGrid strokeDasharray="3 3" stroke="hsl(var(--border))" />
                  <XAxis dataKey="type" tick={{ fontSize: 10 }} stroke="hsl(var(--muted-foreground))" />
                  <YAxis tick={{ fontSize: 10 }} stroke="hsl(var(--muted-foreground))" />
                  <Tooltip /><Legend />
                  {d.top5Products.map((p, i) => (
                    <Bar key={p} dataKey={p} fill={COLORS[i % COLORS.length]} stackId="a" name={p} />
                  ))}
                </BarChart>
              </ResponsiveContainer>
            )}
          </CardContent></Card>
        </TabsContent>

        <TabsContent value="notsold">
          <Card><CardContent className="pt-4">
            {d.notSold.length === 0 ? <p className="text-sm text-muted-foreground text-center py-8">All products were sold!</p> : (
              <Table><TableHeader><TableRow>
                <TableHead>#</TableHead><TableHead>Product</TableHead><TableHead>SKU</TableHead><TableHead>Category</TableHead>
              </TableRow></TableHeader><TableBody>
                {d.notSold.map((p, i) => (
                  <TableRow key={i}>
                    <TableCell>{i + 1}</TableCell>
                    <TableCell className="font-medium">{p.name}</TableCell>
                    <TableCell>{p.sku}</TableCell>
                    <TableCell><Badge variant="outline">{p.category}</Badge></TableCell>
                  </TableRow>
                ))}
              </TableBody></Table>
            )}
          </CardContent></Card>
        </TabsContent>
      </Tabs>
    </div>
  );
}

import { useState, useMemo } from "react";
import { useQuery } from "@tanstack/react-query";
import { supabase } from "@/integrations/supabase/client";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { Loader2, TrendingUp, TrendingDown, DollarSign, ShoppingCart, Package, Receipt, Wallet, PieChart } from "lucide-react";
import { format, subDays, startOfMonth, endOfMonth } from "date-fns";
import { ReportFilters, DateRange } from "./ReportFilters";
import { ReportExportBar } from "./ReportExportBar";
import { ReportSummaryCards } from "./ReportSummaryCards";
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, PieChart as RechartsPie, Pie, Cell, Legend } from "recharts";
import jsPDF from "jspdf";
import autoTable from "jspdf-autotable";

const EXPENSE_COLORS = ["#3b82f6", "#10b981", "#f59e0b", "#ef4444", "#8b5cf6", "#ec4899", "#06b6d4", "#84cc16"];

export default function ProfitLossReport() {
  const [dateRange, setDateRange] = useState<DateRange>({
    from: startOfMonth(new Date()),
    to: new Date(),
  });

  // Fetch sales for revenue
  const { data: sales = [], isLoading: salesLoading } = useQuery({
    queryKey: ["pl-sales", dateRange],
    queryFn: async () => {
      const { data } = await supabase
        .from("sales")
        .select("id, total_amount, created_at")
        .gte("created_at", format(dateRange.from, "yyyy-MM-dd"))
        .lte("created_at", format(dateRange.to, "yyyy-MM-dd") + "T23:59:59");
      return data || [];
    },
  });

  // Fetch sale items for COGS calculation
  const { data: saleItems = [], isLoading: itemsLoading } = useQuery({
    queryKey: ["pl-sale-items", dateRange],
    queryFn: async () => {
      // First get sales in date range
      const { data: salesInRange } = await supabase
        .from("sales")
        .select("id")
        .gte("created_at", format(dateRange.from, "yyyy-MM-dd"))
        .lte("created_at", format(dateRange.to, "yyyy-MM-dd") + "T23:59:59");
      
      if (!salesInRange || salesInRange.length === 0) return [];
      
      const saleIds = salesInRange.map((s: any) => s.id);
      
      const { data } = await supabase
        .from("sale_items")
        .select("id, quantity, unit_price, total, product_id, sale_id, products(mrp, gst_rate)")
        .in("sale_id", saleIds);
      return data || [];
    },
  });

  // Fetch purchases for COGS
  const { data: purchases = [], isLoading: purchLoading } = useQuery({
    queryKey: ["pl-purchases", dateRange],
    queryFn: async () => {
      const { data } = await supabase
        .from("purchases")
        .select("id, total_amount, purchase_date")
        .gte("purchase_date", format(dateRange.from, "yyyy-MM-dd"))
        .lte("purchase_date", format(dateRange.to, "yyyy-MM-dd"));
      return data || [];
    },
  });

  // Fetch expenses
  const { data: expenses = [], isLoading: expLoading } = useQuery({
    queryKey: ["pl-expenses", dateRange],
    queryFn: async () => {
      const { data } = await supabase
        .from("expenses")
        .select("id, amount, expense_date, expense_categories(name)")
        .gte("expense_date", format(dateRange.from, "yyyy-MM-dd"))
        .lte("expense_date", format(dateRange.to, "yyyy-MM-dd"));
      return data || [];
    },
  });

  // Fetch sale returns
  const { data: saleReturns = [], isLoading: returnsLoading } = useQuery({
    queryKey: ["pl-returns", dateRange],
    queryFn: async () => {
      const { data } = await supabase
        .from("sale_returns")
        .select("id, total_amount, return_date")
        .eq("status", "completed")
        .gte("return_date", format(dateRange.from, "yyyy-MM-dd"))
        .lte("return_date", format(dateRange.to, "yyyy-MM-dd"));
      return data || [];
    },
  });

  const isLoading = salesLoading || itemsLoading || purchLoading || expLoading || returnsLoading;

  // Calculate P&L
  const plData = useMemo(() => {
    // Revenue
    const grossRevenue = sales.reduce((sum, s: any) => sum + Number(s.total_amount || 0), 0);
    const totalReturns = saleReturns.reduce((sum, r: any) => sum + Number(r.total_amount || 0), 0);
    const netRevenue = grossRevenue - totalReturns;

    // COGS (using purchases as proxy - ideally would use weighted average cost)
    const cogs = purchases.reduce((sum, p: any) => sum + Number(p.total_amount || 0), 0);

    // Gross Profit
    const grossProfit = netRevenue - cogs;
    const grossMargin = netRevenue > 0 ? (grossProfit / netRevenue) * 100 : 0;

    // Operating Expenses by category
    const expensesByCategory: Record<string, number> = {};
    expenses.forEach((e: any) => {
      const category = e.expense_categories?.name || "Other";
      expensesByCategory[category] = (expensesByCategory[category] || 0) + Number(e.amount || 0);
    });

    const totalExpenses = expenses.reduce((sum, e: any) => sum + Number(e.amount || 0), 0);

    // Operating Profit (EBIT)
    const operatingProfit = grossProfit - totalExpenses;
    const operatingMargin = netRevenue > 0 ? (operatingProfit / netRevenue) * 100 : 0;

    // Net Profit (assuming no interest/tax for simplicity)
    const netProfit = operatingProfit;
    const netMargin = netRevenue > 0 ? (netProfit / netRevenue) * 100 : 0;

    return {
      grossRevenue,
      totalReturns,
      netRevenue,
      cogs,
      grossProfit,
      grossMargin,
      expensesByCategory,
      totalExpenses,
      operatingProfit,
      operatingMargin,
      netProfit,
      netMargin,
    };
  }, [sales, saleReturns, purchases, expenses]);

  // Expense chart data
  const expenseChartData = useMemo(() => {
    return Object.entries(plData.expensesByCategory).map(([name, value]) => ({
      name,
      value,
    }));
  }, [plData]);

  // P&L breakdown for bar chart
  const plBreakdown = [
    { name: "Revenue", value: plData.netRevenue, fill: "#10b981" },
    { name: "COGS", value: -plData.cogs, fill: "#f59e0b" },
    { name: "Gross Profit", value: plData.grossProfit, fill: "#3b82f6" },
    { name: "Expenses", value: -plData.totalExpenses, fill: "#ef4444" },
    { name: "Net Profit", value: plData.netProfit, fill: plData.netProfit >= 0 ? "#10b981" : "#ef4444" },
  ];

  const exportPDF = () => {
    const doc = new jsPDF();
    doc.setFontSize(16);
    doc.text("Profit & Loss Statement", 14, 20);
    doc.setFontSize(10);
    doc.text(`Period: ${format(dateRange.from, "MMM d, yyyy")} - ${format(dateRange.to, "MMM d, yyyy")}`, 14, 28);

    const rows = [
      ["Gross Revenue", "", `₹${plData.grossRevenue.toLocaleString()}`],
      ["Less: Sales Returns", "", `(₹${plData.totalReturns.toLocaleString()})`],
      ["Net Revenue", "", `₹${plData.netRevenue.toLocaleString()}`],
      ["", "", ""],
      ["Less: Cost of Goods Sold", "", `(₹${plData.cogs.toLocaleString()})`],
      ["Gross Profit", `${plData.grossMargin.toFixed(1)}%`, `₹${plData.grossProfit.toLocaleString()}`],
      ["", "", ""],
      ["Operating Expenses:", "", ""],
      ...Object.entries(plData.expensesByCategory).map(([cat, amt]) => [
        `  ${cat}`, "", `(₹${amt.toLocaleString()})`
      ]),
      ["Total Operating Expenses", "", `(₹${plData.totalExpenses.toLocaleString()})`],
      ["", "", ""],
      ["Operating Profit (EBIT)", `${plData.operatingMargin.toFixed(1)}%`, `₹${plData.operatingProfit.toLocaleString()}`],
      ["", "", ""],
      ["Net Profit", `${plData.netMargin.toFixed(1)}%`, `₹${plData.netProfit.toLocaleString()}`],
    ];

    autoTable(doc, {
      startY: 35,
      head: [["Description", "Margin", "Amount"]],
      body: rows,
      styles: { fontSize: 10 },
      headStyles: { fillColor: [41, 128, 185] },
      columnStyles: {
        0: { cellWidth: 100 },
        1: { cellWidth: 30, halign: "right" },
        2: { cellWidth: 50, halign: "right" },
      },
    });

    doc.save(`profit-loss-${format(dateRange.from, "yyyyMMdd")}-${format(dateRange.to, "yyyyMMdd")}.pdf`);
  };

  const summaryCards = [
    { label: "Net Revenue", value: `₹${plData.netRevenue.toLocaleString()}`, icon: ShoppingCart, iconColor: "green" },
    { label: "COGS", value: `₹${plData.cogs.toLocaleString()}`, icon: Package, iconColor: "orange" },
    { label: "Gross Profit", value: `₹${plData.grossProfit.toLocaleString()}`, subValue: `${plData.grossMargin.toFixed(1)}% margin`, icon: TrendingUp, iconColor: "blue" },
    { label: "Expenses", value: `₹${plData.totalExpenses.toLocaleString()}`, icon: Receipt, iconColor: "red" },
    { label: "Net Profit", value: `₹${plData.netProfit.toLocaleString()}`, subValue: `${plData.netMargin.toFixed(1)}% margin`, icon: Wallet, iconColor: plData.netProfit >= 0 ? "green" : "red" },
  ];

  return (
    <div className="space-y-6">
      <div className="flex flex-col sm:flex-row sm:items-center sm:justify-between gap-4">
        <div>
          <h2 className="text-xl font-semibold">Profit & Loss Statement</h2>
          <p className="text-sm text-muted-foreground">Revenue, costs, and profitability analysis</p>
        </div>
        <ReportExportBar onExportPDF={exportPDF} showExcel={false} showCSV={false} showPrint={false} />
      </div>

      <ReportFilters dateRange={dateRange} onDateRangeChange={setDateRange} />

      {isLoading ? (
        <div className="flex items-center justify-center py-12">
          <Loader2 className="h-8 w-8 animate-spin text-muted-foreground" />
        </div>
      ) : (
        <>
          <ReportSummaryCards cards={summaryCards} columns={5} />

          <div className="grid lg:grid-cols-2 gap-6">
            {/* P&L Breakdown Chart */}
            <Card>
              <CardHeader className="pb-2">
                <CardTitle className="text-base">P&L Breakdown</CardTitle>
              </CardHeader>
              <CardContent>
                <ResponsiveContainer width="100%" height={300}>
                  <BarChart data={plBreakdown} layout="vertical">
                    <CartesianGrid strokeDasharray="3 3" />
                    <XAxis type="number" tickFormatter={(v) => `₹${(v / 1000).toFixed(0)}k`} />
                    <YAxis type="category" dataKey="name" width={100} />
                    <Tooltip formatter={(v: number) => `₹${v.toLocaleString()}`} />
                    <Bar dataKey="value" fill="#3b82f6" />
                  </BarChart>
                </ResponsiveContainer>
              </CardContent>
            </Card>

            {/* Expense Breakdown Pie */}
            <Card>
              <CardHeader className="pb-2">
                <CardTitle className="text-base">Expense Breakdown</CardTitle>
              </CardHeader>
              <CardContent>
                {expenseChartData.length > 0 ? (
                  <ResponsiveContainer width="100%" height={300}>
                    <RechartsPie>
                      <Pie
                        data={expenseChartData}
                        cx="50%"
                        cy="50%"
                        innerRadius={60}
                        outerRadius={100}
                        paddingAngle={2}
                        dataKey="value"
                        label={({ name, percent }) => `${name} (${(percent * 100).toFixed(0)}%)`}
                      >
                        {expenseChartData.map((_, idx) => (
                          <Cell key={idx} fill={EXPENSE_COLORS[idx % EXPENSE_COLORS.length]} />
                        ))}
                      </Pie>
                      <Tooltip formatter={(v: number) => `₹${v.toLocaleString()}`} />
                    </RechartsPie>
                  </ResponsiveContainer>
                ) : (
                  <div className="flex items-center justify-center h-[300px] text-muted-foreground">
                    No expenses recorded
                  </div>
                )}
              </CardContent>
            </Card>
          </div>

          {/* Detailed P&L Statement */}
          <Card>
            <CardHeader className="pb-2">
              <CardTitle className="text-base">Detailed Statement</CardTitle>
            </CardHeader>
            <CardContent className="p-0">
              <div className="overflow-x-auto">
                <table className="w-full">
                  <thead className="bg-muted/50">
                    <tr>
                      <th className="px-4 py-3 text-left font-medium">Description</th>
                      <th className="px-4 py-3 text-right font-medium">Amount</th>
                      <th className="px-4 py-3 text-right font-medium">% of Revenue</th>
                    </tr>
                  </thead>
                  <tbody className="divide-y">
                    <tr className="bg-green-50 dark:bg-green-900/20">
                      <td className="px-4 py-3 font-medium">Gross Revenue</td>
                      <td className="px-4 py-3 text-right font-medium text-green-600">₹{plData.grossRevenue.toLocaleString()}</td>
                      <td className="px-4 py-3 text-right">100%</td>
                    </tr>
                    <tr>
                      <td className="px-4 py-3 pl-8 text-muted-foreground">Less: Sales Returns</td>
                      <td className="px-4 py-3 text-right text-red-600">(₹{plData.totalReturns.toLocaleString()})</td>
                      <td className="px-4 py-3 text-right text-muted-foreground">
                        {plData.grossRevenue > 0 ? ((plData.totalReturns / plData.grossRevenue) * 100).toFixed(1) : 0}%
                      </td>
                    </tr>
                    <tr className="bg-blue-50 dark:bg-blue-900/20 font-medium">
                      <td className="px-4 py-3">Net Revenue</td>
                      <td className="px-4 py-3 text-right text-blue-600">₹{plData.netRevenue.toLocaleString()}</td>
                      <td className="px-4 py-3 text-right">—</td>
                    </tr>
                    <tr>
                      <td className="px-4 py-3 pl-8 text-muted-foreground">Less: Cost of Goods Sold</td>
                      <td className="px-4 py-3 text-right text-red-600">(₹{plData.cogs.toLocaleString()})</td>
                      <td className="px-4 py-3 text-right text-muted-foreground">
                        {plData.netRevenue > 0 ? ((plData.cogs / plData.netRevenue) * 100).toFixed(1) : 0}%
                      </td>
                    </tr>
                    <tr className="bg-blue-50 dark:bg-blue-900/20 font-medium">
                      <td className="px-4 py-3">Gross Profit</td>
                      <td className="px-4 py-3 text-right text-blue-600">₹{plData.grossProfit.toLocaleString()}</td>
                      <td className="px-4 py-3 text-right">{plData.grossMargin.toFixed(1)}%</td>
                    </tr>
                    <tr>
                      <td className="px-4 py-3 font-medium" colSpan={3}>Operating Expenses</td>
                    </tr>
                    {Object.entries(plData.expensesByCategory).map(([category, amount]) => (
                      <tr key={category}>
                        <td className="px-4 py-3 pl-8 text-muted-foreground">{category}</td>
                        <td className="px-4 py-3 text-right text-red-600">(₹{amount.toLocaleString()})</td>
                        <td className="px-4 py-3 text-right text-muted-foreground">
                          {plData.netRevenue > 0 ? ((amount / plData.netRevenue) * 100).toFixed(1) : 0}%
                        </td>
                      </tr>
                    ))}
                    <tr className="border-t-2">
                      <td className="px-4 py-3 pl-8 font-medium">Total Operating Expenses</td>
                      <td className="px-4 py-3 text-right font-medium text-red-600">(₹{plData.totalExpenses.toLocaleString()})</td>
                      <td className="px-4 py-3 text-right">
                        {plData.netRevenue > 0 ? ((plData.totalExpenses / plData.netRevenue) * 100).toFixed(1) : 0}%
                      </td>
                    </tr>
                    <tr className={`font-bold text-lg ${plData.netProfit >= 0 ? "bg-green-100 dark:bg-green-900/30" : "bg-red-100 dark:bg-red-900/30"}`}>
                      <td className="px-4 py-4">Net Profit</td>
                      <td className={`px-4 py-4 text-right ${plData.netProfit >= 0 ? "text-green-600" : "text-red-600"}`}>
                        ₹{plData.netProfit.toLocaleString()}
                      </td>
                      <td className="px-4 py-4 text-right">{plData.netMargin.toFixed(1)}%</td>
                    </tr>
                  </tbody>
                </table>
              </div>
            </CardContent>
          </Card>
        </>
      )}
    </div>
  );
}

import { useState, useMemo } from "react";
import { useQuery } from "@tanstack/react-query";
import { supabase } from "@/integrations/supabase/client";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { Input } from "@/components/ui/input";
import { Loader2, ShoppingBag, DollarSign, TrendingUp, Package, Search, Truck, Warehouse } from "lucide-react";
import { format, subMonths, startOfMonth, eachDayOfInterval } from "date-fns";
import { ReportFilters, DateRange } from "./ReportFilters";
import { ReportExportBar } from "./ReportExportBar";
import { ReportSummaryCards } from "./ReportSummaryCards";
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, Legend, LineChart, Line, PieChart, Pie, Cell } from "recharts";
import jsPDF from "jspdf";
import autoTable from "jspdf-autotable";
import * as XLSX from "xlsx";

interface PurchaseData {
  id: string;
  display_id: string;
  vendor_name: string;
  warehouse_name: string;
  purchase_date: string;
  total_amount: number;
  items_count: number;
  payment_status: string;
}

const COLORS = ["#3b82f6", "#10b981", "#f59e0b", "#ef4444", "#8b5cf6", "#ec4899", "#06b6d4"];

export default function PurchaseReport() {
  const [dateRange, setDateRange] = useState<DateRange>({
    from: startOfMonth(subMonths(new Date(), 1)),
    to: new Date(),
  });
  const [search, setSearch] = useState("");
  const [sortBy, setSortBy] = useState<"date" | "amount" | "vendor">("date");

  // Fetch purchases
  const { data: purchases = [], isLoading: purchLoading } = useQuery({
    queryKey: ["purchase-report", dateRange],
    queryFn: async () => {
      const { data } = await supabase
        .from("purchases")
        .select(`
          id, display_id, purchase_date, total_amount, payment_status,
          vendors(name),
          warehouses(name),
          purchase_items(id)
        `)
        .gte("purchase_date", format(dateRange.from, "yyyy-MM-dd"))
        .lte("purchase_date", format(dateRange.to, "yyyy-MM-dd"))
        .order("purchase_date", { ascending: false });
      
      return (data || []).map((p: any) => ({
        id: p.id,
        display_id: p.display_id,
        vendor_name: p.vendors?.name || "Unknown",
        warehouse_name: p.warehouses?.name || "Default",
        purchase_date: p.purchase_date,
        total_amount: Number(p.total_amount),
        items_count: p.purchase_items?.length || 0,
        payment_status: p.payment_status || "pending",
      }));
    },
  });

  // Fetch vendor payments
  const { data: vendorPayments = [], isLoading: payLoading } = useQuery({
    queryKey: ["purchase-report-payments", dateRange],
    queryFn: async () => {
      const { data } = await supabase
        .from("vendor_payments")
        .select("id, amount, payment_date")
        .gte("payment_date", format(dateRange.from, "yyyy-MM-dd"))
        .lte("payment_date", format(dateRange.to, "yyyy-MM-dd"));
      return data || [];
    },
  });

  const isLoading = purchLoading || payLoading;

  // Filter
  const filteredPurchases = useMemo(() => {
    let filtered = purchases;
    
    if (search) {
      const s = search.toLowerCase();
      filtered = filtered.filter((p: PurchaseData) =>
        p.vendor_name.toLowerCase().includes(s) ||
        p.warehouse_name.toLowerCase().includes(s) ||
        p.display_id.toLowerCase().includes(s)
      );
    }
    
    // Sort
    if (sortBy === "amount") {
      filtered = [...filtered].sort((a, b) => b.total_amount - a.total_amount);
    } else if (sortBy === "vendor") {
      filtered = [...filtered].sort((a, b) => a.vendor_name.localeCompare(b.vendor_name));
    }
    
    return filtered;
  }, [purchases, search, sortBy]);

  // Summary
  const summary = useMemo(() => {
    const totalPurchases = filteredPurchases.reduce((sum, p) => sum + p.total_amount, 0);
    const totalPayments = vendorPayments.reduce((sum: number, vp: any) => sum + Number(vp.amount), 0);
    const totalItems = filteredPurchases.reduce((sum, p) => sum + p.items_count, 0);
    const uniqueVendors = new Set(filteredPurchases.map(p => p.vendor_name)).size;
    
    const paidPurchases = filteredPurchases.filter(p => p.payment_status === "paid");
    const paidAmount = paidPurchases.reduce((sum, p) => sum + p.total_amount, 0);
    
    return {
      totalPurchases,
      totalPayments,
      totalItems,
      uniqueVendors,
      purchaseCount: filteredPurchases.length,
      pendingAmount: totalPurchases - paidAmount,
    };
  }, [filteredPurchases, vendorPayments]);

  // Purchases by vendor
  const vendorBreakdown = useMemo(() => {
    const byVendor: Record<string, number> = {};
    
    filteredPurchases.forEach((p: PurchaseData) => {
      byVendor[p.vendor_name] = (byVendor[p.vendor_name] || 0) + p.total_amount;
    });
    
    return Object.entries(byVendor)
      .map(([name, value]) => ({ name, value }))
      .sort((a, b) => b.value - a.value)
      .slice(0, 10);
  }, [filteredPurchases]);

  // Daily trend
  const dailyTrend = useMemo(() => {
    const days = eachDayOfInterval({ start: dateRange.from, end: dateRange.to });
    
    return days.map(day => {
      const dayStr = format(day, "yyyy-MM-dd");
      const dayPurchases = filteredPurchases.filter(p => p.purchase_date === dayStr);
      const dayPayments = vendorPayments.filter((vp: any) => vp.payment_date === dayStr);
      
      return {
        date: format(day, "MMM d"),
        purchases: dayPurchases.reduce((sum, p) => sum + p.total_amount, 0),
        payments: dayPayments.reduce((sum: number, vp: any) => sum + Number(vp.amount), 0),
      };
    }).filter(d => d.purchases > 0 || d.payments > 0);
  }, [filteredPurchases, vendorPayments, dateRange]);

  // Payment status breakdown
  const paymentStatusData = useMemo(() => {
    const byStatus: Record<string, number> = {};
    
    filteredPurchases.forEach((p: PurchaseData) => {
      const status = p.payment_status || "pending";
      byStatus[status] = (byStatus[status] || 0) + p.total_amount;
    });
    
    return Object.entries(byStatus).map(([name, value]) => ({ name, value }));
  }, [filteredPurchases]);

  const summaryCards = [
    { label: "Total Purchases", value: `₹${(summary.totalPurchases / 1000).toFixed(0)}K`, icon: ShoppingBag, iconColor: "blue" },
    { label: "Paid to Vendors", value: `₹${(summary.totalPayments / 1000).toFixed(0)}K`, icon: DollarSign, iconColor: "green" },
    { label: "Pending Amount", value: `₹${(summary.pendingAmount / 1000).toFixed(0)}K`, icon: TrendingUp, iconColor: "red" },
    { label: "Active Vendors", value: summary.uniqueVendors.toString(), icon: Truck, iconColor: "purple" },
  ];

  const paymentStatusColors: Record<string, string> = {
    pending: "bg-yellow-100 text-yellow-800",
    partial: "bg-blue-100 text-blue-800",
    paid: "bg-green-100 text-green-800",
  };

  const exportPDF = () => {
    const doc = new jsPDF();
    doc.setFontSize(16);
    doc.text("Purchase Report", 14, 15);
    doc.setFontSize(10);
    doc.text(`Period: ${format(dateRange.from, "MMM d, yyyy")} - ${format(dateRange.to, "MMM d, yyyy")}`, 14, 23);

    autoTable(doc, {
      startY: 30,
      head: [["Date", "Purchase ID", "Vendor", "Warehouse", "Items", "Amount", "Status"]],
      body: filteredPurchases.map((p: PurchaseData) => [
        format(new Date(p.purchase_date), "dd/MM/yy"),
        p.display_id,
        p.vendor_name,
        p.warehouse_name,
        p.items_count.toString(),
        `₹${p.total_amount.toLocaleString()}`,
        p.payment_status,
      ]),
      styles: { fontSize: 8 },
      headStyles: { fillColor: [59, 130, 246] },
    });

    doc.save(`purchase-report-${format(dateRange.from, "yyyyMMdd")}-${format(dateRange.to, "yyyyMMdd")}.pdf`);
  };

  const exportExcel = () => {
    const ws = XLSX.utils.json_to_sheet(filteredPurchases.map((p: PurchaseData) => ({
      "Date": p.purchase_date,
      "Purchase ID": p.display_id,
      "Vendor": p.vendor_name,
      "Warehouse": p.warehouse_name,
      "Items": p.items_count,
      "Amount": p.total_amount,
      "Payment Status": p.payment_status,
    })));
    const wb = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(wb, ws, "Purchases");
    XLSX.writeFile(wb, `purchase-report-${format(dateRange.from, "yyyyMMdd")}-${format(dateRange.to, "yyyyMMdd")}.xlsx`);
  };

  return (
    <div className="space-y-6">
      <div className="flex flex-col lg:flex-row lg:items-end gap-4">
        <ReportFilters dateRange={dateRange} onDateRangeChange={setDateRange} />
        <div className="relative flex-1 max-w-xs">
          <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-muted-foreground" />
          <Input
            placeholder="Search purchases..."
            value={search}
            onChange={(e) => setSearch(e.target.value)}
            className="pl-9"
          />
        </div>
        <div className="flex gap-2">
          <Badge 
            variant={sortBy === "date" ? "default" : "outline"} 
            className="cursor-pointer"
            onClick={() => setSortBy("date")}
          >
            By Date
          </Badge>
          <Badge 
            variant={sortBy === "amount" ? "default" : "outline"} 
            className="cursor-pointer"
            onClick={() => setSortBy("amount")}
          >
            By Amount
          </Badge>
          <Badge 
            variant={sortBy === "vendor" ? "default" : "outline"} 
            className="cursor-pointer"
            onClick={() => setSortBy("vendor")}
          >
            By Vendor
          </Badge>
        </div>
      </div>

      <ReportExportBar onExportPDF={exportPDF} onExportExcel={exportExcel} />

      {isLoading ? (
        <div className="flex items-center justify-center py-12">
          <Loader2 className="h-8 w-8 animate-spin text-muted-foreground" />
        </div>
      ) : (
        <>
          <ReportSummaryCards cards={summaryCards} />

          <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
            {/* Daily Trend */}
            {dailyTrend.length > 1 && (
              <Card>
                <CardHeader>
                  <CardTitle className="text-base">Purchase & Payment Trend</CardTitle>
                </CardHeader>
                <CardContent>
                  <ResponsiveContainer width="100%" height={250}>
                    <LineChart data={dailyTrend}>
                      <CartesianGrid strokeDasharray="3 3" />
                      <XAxis dataKey="date" tick={{ fontSize: 11 }} interval="preserveStartEnd" />
                      <YAxis tickFormatter={(v) => `₹${(v / 1000).toFixed(0)}K`} />
                      <Tooltip formatter={(v: number) => `₹${v.toLocaleString()}`} />
                      <Legend />
                      <Line type="monotone" dataKey="purchases" name="Purchases" stroke="#3b82f6" />
                      <Line type="monotone" dataKey="payments" name="Payments" stroke="#10b981" />
                    </LineChart>
                  </ResponsiveContainer>
                </CardContent>
              </Card>
            )}

            {/* Top Vendors */}
            <Card>
              <CardHeader>
                <CardTitle className="text-base">Top Vendors by Purchase</CardTitle>
              </CardHeader>
              <CardContent>
                {vendorBreakdown.length > 0 ? (
                  <ResponsiveContainer width="100%" height={250}>
                    <BarChart data={vendorBreakdown} layout="vertical">
                      <CartesianGrid strokeDasharray="3 3" />
                      <XAxis type="number" tickFormatter={(v) => `₹${(v / 1000).toFixed(0)}K`} />
                      <YAxis type="category" dataKey="name" width={100} tick={{ fontSize: 10 }} />
                      <Tooltip formatter={(v: number) => `₹${v.toLocaleString()}`} />
                      <Bar dataKey="value" name="Amount" fill="#3b82f6" />
                    </BarChart>
                  </ResponsiveContainer>
                ) : (
                  <p className="text-center text-muted-foreground py-12">No data</p>
                )}
              </CardContent>
            </Card>
          </div>

          {/* Payment Status Pie */}
          <Card>
            <CardHeader>
              <CardTitle className="text-base">Payment Status Distribution</CardTitle>
            </CardHeader>
            <CardContent>
              {paymentStatusData.length > 0 ? (
                <ResponsiveContainer width="100%" height={200}>
                  <PieChart>
                    <Pie
                      data={paymentStatusData}
                      cx="50%"
                      cy="50%"
                      labelLine={false}
                      label={({ name, percent }) => `${name} (${(percent * 100).toFixed(0)}%)`}
                      outerRadius={80}
                      fill="#8884d8"
                      dataKey="value"
                    >
                      {paymentStatusData.map((_, index) => (
                        <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} />
                      ))}
                    </Pie>
                    <Tooltip formatter={(v: number) => `₹${v.toLocaleString()}`} />
                  </PieChart>
                </ResponsiveContainer>
              ) : (
                <p className="text-center text-muted-foreground py-8">No data</p>
              )}
            </CardContent>
          </Card>

          {/* Purchase Table */}
          <Card>
            <CardHeader>
              <CardTitle className="text-base">Purchase Details ({filteredPurchases.length})</CardTitle>
            </CardHeader>
            <CardContent>
              {filteredPurchases.length === 0 ? (
                <p className="text-center text-muted-foreground py-12">No purchases found</p>
              ) : (
                <div className="overflow-x-auto">
                  <table className="w-full text-sm">
                    <thead>
                      <tr className="border-b bg-muted/50">
                        <th className="text-left p-3 font-medium">Date</th>
                        <th className="text-left p-3 font-medium">Purchase ID</th>
                        <th className="text-left p-3 font-medium">Vendor</th>
                        <th className="text-left p-3 font-medium hidden md:table-cell">Warehouse</th>
                        <th className="text-center p-3 font-medium hidden lg:table-cell">Items</th>
                        <th className="text-right p-3 font-medium">Amount</th>
                        <th className="text-center p-3 font-medium">Status</th>
                      </tr>
                    </thead>
                    <tbody>
                      {filteredPurchases.slice(0, 50).map((p: PurchaseData) => (
                        <tr key={p.id} className="border-b hover:bg-muted/30">
                          <td className="p-3 text-muted-foreground text-xs">
                            {format(new Date(p.purchase_date), "dd/MM/yy")}
                          </td>
                          <td className="p-3 font-mono text-xs">{p.display_id}</td>
                          <td className="p-3 font-medium">{p.vendor_name}</td>
                          <td className="p-3 hidden md:table-cell text-muted-foreground">{p.warehouse_name}</td>
                          <td className="p-3 text-center hidden lg:table-cell">{p.items_count}</td>
                          <td className="p-3 text-right font-semibold">₹{p.total_amount.toLocaleString()}</td>
                          <td className="p-3 text-center">
                            <Badge className={paymentStatusColors[p.payment_status] || "bg-gray-100 text-gray-800"} variant="secondary">
                              {p.payment_status}
                            </Badge>
                          </td>
                        </tr>
                      ))}
                    </tbody>
                  </table>
                </div>
              )}
              {filteredPurchases.length > 50 && (
                <p className="text-center text-muted-foreground mt-4 text-sm">
                  Showing 50 of {filteredPurchases.length} purchases. Export to see all.
                </p>
              )}
            </CardContent>
          </Card>
        </>
      )}
    </div>
  );
}

import { useState, useMemo } from "react";
import { useQuery } from "@tanstack/react-query";
import { supabase } from "@/integrations/supabase/client";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { Input } from "@/components/ui/input";
import { Loader2, ShoppingBag, DollarSign, TrendingUp, Package, Search, RotateCcw, AlertCircle, Truck } from "lucide-react";
import { format, subMonths, startOfMonth } from "date-fns";
import { ReportFilters, DateRange } from "./ReportFilters";
import { ReportExportBar } from "./ReportExportBar";
import { ReportSummaryCards } from "./ReportSummaryCards";
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, Legend, LineChart, Line } from "recharts";
import jsPDF from "jspdf";
import autoTable from "jspdf-autotable";
import * as XLSX from "xlsx";

interface PurchaseReturnData {
  id: string;
  display_id: string;
  vendor_name: string;
  warehouse_name: string;
  return_date: string;
  total_amount: number;
  status: string;
  reason: string;
  items_count: number;
}

export default function PurchaseReturnReport() {
  const [dateRange, setDateRange] = useState<DateRange>({
    from: startOfMonth(subMonths(new Date(), 3)),
    to: new Date(),
  });
  const [search, setSearch] = useState("");
  const [statusFilter, setStatusFilter] = useState<"all" | "pending" | "approved" | "completed" | "rejected">("all");

  // Fetch purchase returns
  const { data: purchaseReturns = [], isLoading: prLoading } = useQuery({
    queryKey: ["purchase-return-report", dateRange],
    queryFn: async () => {
      const { data } = await supabase
        .from("purchase_returns")
        .select(`
          id, display_id, return_date, total_amount, status, reason,
          vendors(name),
          warehouses(name),
          purchase_return_items(id)
        `)
        .gte("return_date", format(dateRange.from, "yyyy-MM-dd"))
        .lte("return_date", format(dateRange.to, "yyyy-MM-dd"))
        .order("return_date", { ascending: false });
      
      return (data || []).map((pr: any) => ({
        id: pr.id,
        display_id: pr.display_id,
        vendor_name: pr.vendors?.name || "Unknown",
        warehouse_name: pr.warehouses?.name || "Default",
        return_date: pr.return_date,
        total_amount: Number(pr.total_amount),
        status: pr.status,
        reason: pr.reason || "",
        items_count: pr.purchase_return_items?.length || 0,
      }));
    },
  });

  // Fetch purchases for comparison
  const { data: purchases = [], isLoading: purchLoading } = useQuery({
    queryKey: ["purchase-return-report-purchases", dateRange],
    queryFn: async () => {
      const { data } = await supabase
        .from("purchases")
        .select("id, total_amount, purchase_date")
        .gte("purchase_date", format(dateRange.from, "yyyy-MM-dd"))
        .lte("purchase_date", format(dateRange.to, "yyyy-MM-dd"));
      return data || [];
    },
  });

  const isLoading = prLoading || purchLoading;

  // Filter
  const filteredReturns = useMemo(() => {
    let filtered = purchaseReturns;
    
    if (search) {
      const s = search.toLowerCase();
      filtered = filtered.filter((r: PurchaseReturnData) =>
        r.vendor_name.toLowerCase().includes(s) ||
        r.warehouse_name.toLowerCase().includes(s) ||
        r.display_id.toLowerCase().includes(s) ||
        r.reason.toLowerCase().includes(s)
      );
    }
    
    if (statusFilter !== "all") {
      filtered = filtered.filter((r: PurchaseReturnData) => r.status === statusFilter);
    }
    
    return filtered;
  }, [purchaseReturns, search, statusFilter]);

  // Summary
  const summary = useMemo(() => {
    const totalPurchases = purchases.reduce((sum: number, p: any) => sum + Number(p.total_amount), 0);
    const totalReturns = filteredReturns
      .filter((r: PurchaseReturnData) => r.status === "completed")
      .reduce((sum, r) => sum + r.total_amount, 0);
    
    return {
      total_purchases: totalPurchases,
      total_returns: totalReturns,
      net_purchases: totalPurchases - totalReturns,
      return_rate: totalPurchases > 0 ? (totalReturns / totalPurchases) * 100 : 0,
      total_transactions: purchases.length,
      total_return_transactions: filteredReturns.length,
    };
  }, [purchases, filteredReturns]);

  // Returns by vendor
  const vendorBreakdown = useMemo(() => {
    const byVendor: Record<string, { count: number; amount: number }> = {};
    
    filteredReturns.forEach((r: PurchaseReturnData) => {
      const vendor = r.vendor_name;
      if (!byVendor[vendor]) byVendor[vendor] = { count: 0, amount: 0 };
      byVendor[vendor].count++;
      byVendor[vendor].amount += r.total_amount;
    });
    
    return Object.entries(byVendor)
      .map(([vendor, data]) => ({ vendor, ...data }))
      .sort((a, b) => b.amount - a.amount)
      .slice(0, 10);
  }, [filteredReturns]);

  // Returns by reason
  const reasonBreakdown = useMemo(() => {
    const byReason: Record<string, { count: number; amount: number }> = {};
    
    filteredReturns.forEach((r: PurchaseReturnData) => {
      const reason = r.reason || "Not specified";
      if (!byReason[reason]) byReason[reason] = { count: 0, amount: 0 };
      byReason[reason].count++;
      byReason[reason].amount += r.total_amount;
    });
    
    return Object.entries(byReason)
      .map(([reason, data]) => ({ reason, ...data }))
      .sort((a, b) => b.amount - a.amount)
      .slice(0, 8);
  }, [filteredReturns]);

  // Trend over time
  const trendData = useMemo(() => {
    const byDate: Record<string, { date: string; returns: number; amount: number }> = {};
    
    filteredReturns.forEach((r: PurchaseReturnData) => {
      const date = format(new Date(r.return_date), "MMM d");
      if (!byDate[date]) byDate[date] = { date, returns: 0, amount: 0 };
      byDate[date].returns++;
      byDate[date].amount += r.total_amount;
    });
    
    return Object.values(byDate).sort((a, b) => 
      new Date(a.date).getTime() - new Date(b.date).getTime()
    );
  }, [filteredReturns]);

  // Status breakdown
  const statusBreakdown = useMemo(() => {
    const byStatus: Record<string, number> = {};
    
    purchaseReturns.forEach((r: PurchaseReturnData) => {
      byStatus[r.status] = (byStatus[r.status] || 0) + 1;
    });
    
    return Object.entries(byStatus).map(([status, count]) => ({ status, count }));
  }, [purchaseReturns]);

  const summaryCards = [
    { label: "Total Purchases", value: `₹${(summary.total_purchases / 1000).toFixed(0)}K`, icon: ShoppingBag, iconColor: "blue" },
    { label: "Total Returns", value: `₹${(summary.total_returns / 1000).toFixed(0)}K`, icon: RotateCcw, iconColor: "red" },
    { label: "Net Purchases", value: `₹${(summary.net_purchases / 1000).toFixed(0)}K`, icon: DollarSign, iconColor: "green" },
    { label: "Return Rate", value: `${summary.return_rate.toFixed(1)}%`, icon: AlertCircle, iconColor: "yellow" },
  ];

  const statusColors: Record<string, string> = {
    pending: "bg-yellow-100 text-yellow-800",
    approved: "bg-blue-100 text-blue-800",
    completed: "bg-green-100 text-green-800",
    rejected: "bg-red-100 text-red-800",
  };

  const exportPDF = () => {
    const doc = new jsPDF();
    doc.setFontSize(16);
    doc.text("Purchase Returns Report", 14, 15);
    doc.setFontSize(10);
    doc.text(`Period: ${format(dateRange.from, "MMM d, yyyy")} - ${format(dateRange.to, "MMM d, yyyy")}`, 14, 23);

    autoTable(doc, {
      startY: 30,
      head: [["Date", "Return ID", "Vendor", "Warehouse", "Amount", "Status", "Reason"]],
      body: filteredReturns.map((r: PurchaseReturnData) => [
        format(new Date(r.return_date), "dd/MM/yy"),
        r.display_id,
        r.vendor_name,
        r.warehouse_name,
        `₹${r.total_amount.toLocaleString()}`,
        r.status,
        r.reason || "—",
      ]),
      styles: { fontSize: 8 },
      headStyles: { fillColor: [239, 68, 68] },
    });

    doc.save(`purchase-return-report-${format(dateRange.from, "yyyyMMdd")}-${format(dateRange.to, "yyyyMMdd")}.pdf`);
  };

  const exportExcel = () => {
    const ws = XLSX.utils.json_to_sheet(filteredReturns.map((r: PurchaseReturnData) => ({
      "Date": r.return_date,
      "Return ID": r.display_id,
      "Vendor": r.vendor_name,
      "Warehouse": r.warehouse_name,
      "Amount": r.total_amount,
      "Status": r.status,
      "Items": r.items_count,
      "Reason": r.reason,
    })));
    const wb = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(wb, ws, "Purchase Returns");
    XLSX.writeFile(wb, `purchase-return-report-${format(dateRange.from, "yyyyMMdd")}-${format(dateRange.to, "yyyyMMdd")}.xlsx`);
  };

  return (
    <div className="space-y-6">
      <div className="flex flex-col lg:flex-row lg:items-end gap-4">
        <ReportFilters dateRange={dateRange} onDateRangeChange={setDateRange} />
        <div className="relative flex-1 max-w-xs">
          <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-muted-foreground" />
          <Input
            placeholder="Search returns..."
            value={search}
            onChange={(e) => setSearch(e.target.value)}
            className="pl-9"
          />
        </div>
        <div className="flex gap-2 flex-wrap">
          {["all", "pending", "approved", "completed", "rejected"].map((status) => (
            <Badge
              key={status}
              variant={statusFilter === status ? "default" : "outline"}
              className="cursor-pointer capitalize"
              onClick={() => setStatusFilter(status as any)}
            >
              {status}
            </Badge>
          ))}
        </div>
      </div>

      <ReportExportBar onExportPDF={exportPDF} onExportExcel={exportExcel} />

      {isLoading ? (
        <div className="flex items-center justify-center py-12">
          <Loader2 className="h-8 w-8 animate-spin text-muted-foreground" />
        </div>
      ) : (
        <>
          <ReportSummaryCards cards={summaryCards} />

          <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
            {/* Returns by Vendor */}
            <Card>
              <CardHeader>
                <CardTitle className="text-base">Returns by Vendor</CardTitle>
              </CardHeader>
              <CardContent>
                {vendorBreakdown.length > 0 ? (
                  <ResponsiveContainer width="100%" height={250}>
                    <BarChart data={vendorBreakdown} layout="vertical">
                      <CartesianGrid strokeDasharray="3 3" />
                      <XAxis type="number" tickFormatter={(v) => `₹${(v / 1000).toFixed(0)}K`} />
                      <YAxis type="category" dataKey="vendor" width={100} tick={{ fontSize: 10 }} />
                      <Tooltip formatter={(v: number) => `₹${v.toLocaleString()}`} />
                      <Bar dataKey="amount" name="Amount" fill="#ef4444" />
                    </BarChart>
                  </ResponsiveContainer>
                ) : (
                  <p className="text-center text-muted-foreground py-12">No data</p>
                )}
              </CardContent>
            </Card>

            {/* Returns by Reason */}
            <Card>
              <CardHeader>
                <CardTitle className="text-base">Returns by Reason</CardTitle>
              </CardHeader>
              <CardContent>
                {reasonBreakdown.length > 0 ? (
                  <ResponsiveContainer width="100%" height={250}>
                    <BarChart data={reasonBreakdown} layout="vertical">
                      <CartesianGrid strokeDasharray="3 3" />
                      <XAxis type="number" tickFormatter={(v) => `₹${(v / 1000).toFixed(0)}K`} />
                      <YAxis type="category" dataKey="reason" width={120} tick={{ fontSize: 10 }} />
                      <Tooltip formatter={(v: number) => `₹${v.toLocaleString()}`} />
                      <Bar dataKey="amount" name="Amount" fill="#f59e0b" />
                    </BarChart>
                  </ResponsiveContainer>
                ) : (
                  <p className="text-center text-muted-foreground py-12">No data</p>
                )}
              </CardContent>
            </Card>
          </div>

          {/* Returns Trend */}
          {trendData.length > 1 && (
            <Card>
              <CardHeader>
                <CardTitle className="text-base">Returns Trend</CardTitle>
              </CardHeader>
              <CardContent>
                <ResponsiveContainer width="100%" height={250}>
                  <LineChart data={trendData}>
                    <CartesianGrid strokeDasharray="3 3" />
                    <XAxis dataKey="date" tick={{ fontSize: 11 }} />
                    <YAxis yAxisId="left" orientation="left" />
                    <YAxis yAxisId="right" orientation="right" tickFormatter={(v) => `₹${(v / 1000).toFixed(0)}K`} />
                    <Tooltip formatter={(v: number, name: string) => 
                      name === "amount" ? `₹${v.toLocaleString()}` : v
                    } />
                    <Legend />
                    <Line yAxisId="left" type="monotone" dataKey="returns" name="Count" stroke="#3b82f6" />
                    <Line yAxisId="right" type="monotone" dataKey="amount" name="Amount" stroke="#ef4444" />
                  </LineChart>
                </ResponsiveContainer>
              </CardContent>
            </Card>
          )}

          {/* Status Breakdown */}
          <Card>
            <CardHeader>
              <CardTitle className="text-base">Returns by Status</CardTitle>
            </CardHeader>
            <CardContent>
              <div className="flex flex-wrap gap-4">
                {statusBreakdown.map((s) => (
                  <div key={s.status} className="flex items-center gap-2">
                    <Badge className={statusColors[s.status]}>{s.status}</Badge>
                    <span className="font-semibold">{s.count}</span>
                  </div>
                ))}
              </div>
            </CardContent>
          </Card>

          {/* Returns Table */}
          <Card>
            <CardHeader>
              <CardTitle className="text-base">Return Details ({filteredReturns.length})</CardTitle>
            </CardHeader>
            <CardContent>
              {filteredReturns.length === 0 ? (
                <p className="text-center text-muted-foreground py-12">No returns found</p>
              ) : (
                <div className="overflow-x-auto">
                  <table className="w-full text-sm">
                    <thead>
                      <tr className="border-b bg-muted/50">
                        <th className="text-left p-3 font-medium">Date</th>
                        <th className="text-left p-3 font-medium">Return ID</th>
                        <th className="text-left p-3 font-medium">Vendor</th>
                        <th className="text-left p-3 font-medium hidden md:table-cell">Warehouse</th>
                        <th className="text-right p-3 font-medium">Amount</th>
                        <th className="text-center p-3 font-medium">Status</th>
                        <th className="text-left p-3 font-medium hidden lg:table-cell">Reason</th>
                      </tr>
                    </thead>
                    <tbody>
                      {filteredReturns.slice(0, 50).map((r: PurchaseReturnData) => (
                        <tr key={r.id} className="border-b hover:bg-muted/30">
                          <td className="p-3 text-muted-foreground text-xs">
                            {format(new Date(r.return_date), "dd/MM/yy")}
                          </td>
                          <td className="p-3 font-mono text-xs">{r.display_id}</td>
                          <td className="p-3 font-medium">{r.vendor_name}</td>
                          <td className="p-3 hidden md:table-cell text-muted-foreground">{r.warehouse_name}</td>
                          <td className="p-3 text-right font-semibold text-red-600">
                            ₹{r.total_amount.toLocaleString()}
                          </td>
                          <td className="p-3 text-center">
                            <Badge className={statusColors[r.status]} variant="secondary">
                              {r.status}
                            </Badge>
                          </td>
                          <td className="p-3 hidden lg:table-cell text-muted-foreground truncate max-w-[200px]">
                            {r.reason || "—"}
                          </td>
                        </tr>
                      ))}
                    </tbody>
                  </table>
                </div>
              )}
              {filteredReturns.length > 50 && (
                <p className="text-center text-muted-foreground mt-4 text-sm">
                  Showing 50 of {filteredReturns.length} returns. Export to see all.
                </p>
              )}
            </CardContent>
          </Card>
        </>
      )}
    </div>
  );
}

import { Button } from "@/components/ui/button";
import { Download, FileSpreadsheet, FileText, Printer } from "lucide-react";
import {
  DropdownMenu,
  DropdownMenuContent,
  DropdownMenuItem,
  DropdownMenuTrigger,
} from "@/components/ui/dropdown-menu";
import { cn } from "@/lib/utils";

export interface ReportExportBarProps {
  onExportPDF?: () => void;
  onExportExcel?: () => void;
  onExportCSV?: () => void;
  onPrint?: () => void;
  isExporting?: boolean;
  className?: string;
  // Control which exports to show
  showPDF?: boolean;
  showExcel?: boolean;
  showCSV?: boolean;
  showPrint?: boolean;
}

export function ReportExportBar({
  onExportPDF,
  onExportExcel,
  onExportCSV,
  onPrint,
  isExporting = false,
  className,
  showPDF = true,
  showExcel = true,
  showCSV = true,
  showPrint = true,
}: ReportExportBarProps) {
  const hasAnyExport = (showPDF && onExportPDF) || (showExcel && onExportExcel) || (showCSV && onExportCSV);
  
  // Count available options
  const exportOptions = [
    showPDF && onExportPDF && { label: "PDF", icon: FileText, onClick: onExportPDF },
    showExcel && onExportExcel && { label: "Excel", icon: FileSpreadsheet, onClick: onExportExcel },
    showCSV && onExportCSV && { label: "CSV", icon: FileText, onClick: onExportCSV },
  ].filter(Boolean) as Array<{ label: string; icon: typeof FileText; onClick: () => void }>;

  // If only one export option, show direct button
  const singleExport = exportOptions.length === 1;

  return (
    <div className={cn("flex items-center gap-2", className)}>
      {hasAnyExport && (
        singleExport ? (
          <Button
            variant="outline"
            size="sm"
            onClick={exportOptions[0].onClick}
            disabled={isExporting}
            className="gap-2"
          >
            <exportOptions[0].icon className="h-4 w-4" />
            Export {exportOptions[0].label}
          </Button>
        ) : (
          <DropdownMenu>
            <DropdownMenuTrigger asChild>
              <Button variant="outline" size="sm" disabled={isExporting} className="gap-2">
                <Download className="h-4 w-4" />
                Export
              </Button>
            </DropdownMenuTrigger>
            <DropdownMenuContent align="end">
              {exportOptions.map((option) => (
                <DropdownMenuItem key={option.label} onClick={option.onClick}>
                  <option.icon className="h-4 w-4 mr-2" />
                  Export as {option.label}
                </DropdownMenuItem>
              ))}
            </DropdownMenuContent>
          </DropdownMenu>
        )
      )}
      
      {showPrint && onPrint && (
        <Button variant="outline" size="sm" onClick={onPrint} disabled={isExporting} className="gap-2">
          <Printer className="h-4 w-4" />
          Print
        </Button>
      )}
    </div>
  );
}

import { useState } from "react";
import { useQuery } from "@tanstack/react-query";
import { supabase } from "@/integrations/supabase/client";
import { StatCard } from "@/components/shared/StatCard";
import { TableSkeleton } from "@/components/shared/TableSkeleton";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Tabs, TabsContent, TabsList, TabsTrigger } from "@/components/ui/tabs";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import { Table, TableBody, TableCell, TableHead, TableHeader, TableRow } from "@/components/ui/table";
import { toast } from "sonner";
import {
  ShoppingCart, TrendingUp, TrendingDown, DollarSign, Banknote,
  Smartphone, Download, FileText, FileSpreadsheet, Users, Store,
} from "lucide-react";
import {
  BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer,
  LineChart, Line, PieChart, Pie, Cell,
} from "recharts";
import jsPDF from "jspdf";
import autoTable from "jspdf-autotable";
import * as XLSX from "xlsx";

const fmt = (n: number) => `₹${n.toLocaleString("en-IN")}`;
const pct = (n: number, t: number) => t > 0 ? ((n / t) * 100).toFixed(1) + "%" : "0%";
const COLORS = ["hsl(217, 91%, 50%)", "hsl(142, 72%, 42%)", "hsl(38, 92%, 50%)", "hsl(280, 65%, 60%)", "hsl(0, 72%, 51%)", "hsl(190, 80%, 45%)"];

export default function SalesReport() {
  const today = new Date();
  const thirtyAgo = new Date(today);
  thirtyAgo.setDate(thirtyAgo.getDate() - 30);
  const [from, setFrom] = useState(thirtyAgo.toISOString().split("T")[0]);
  const [to, setTo] = useState(today.toISOString().split("T")[0]);

  const { data, isLoading } = useQuery({
    queryKey: ["sales-report", from, to],
    queryFn: async () => {
      const startOfDay = from + "T00:00:00";
      const endOfDay = to + "T23:59:59";

      const [salesRes, saleItemsRes, profilesRes, storesRes, storeTypesRes] = await Promise.all([
        supabase.from("sales").select("*, stores(name, store_type_id)").gte("created_at", startOfDay).lte("created_at", endOfDay).order("created_at"),
        supabase.from("sale_items").select("*, products(name, unit, category)").gte("created_at", startOfDay).lte("created_at", endOfDay),
        supabase.from("profiles").select("user_id, full_name"),
        supabase.from("stores").select("id, name, display_id, store_type_id, outstanding"),
        supabase.from("store_types").select("id, name"),
      ]);

      const sales = salesRes.data || [];
      const saleItems = saleItemsRes.data || [];
      const profiles = profilesRes.data || [];
      const stores = storesRes.data || [];
      const storeTypes = storeTypesRes.data || [];

      const profileMap = Object.fromEntries(profiles.map(p => [p.user_id, p.full_name]));
      const storeTypeMap = Object.fromEntries(storeTypes.map(t => [t.id, t.name]));
      const storeMap = Object.fromEntries(stores.map(s => [s.id, s]));

      // Summary
      const totalSales = sales.reduce((s, r) => s + Number(r.total_amount), 0);
      const totalCash = sales.reduce((s, r) => s + Number(r.cash_amount), 0);
      const totalUpi = sales.reduce((s, r) => s + Number(r.upi_amount), 0);
      const totalCredit = sales.reduce((s, r) => s + Number(r.outstanding_amount), 0);
      const avgSale = sales.length > 0 ? totalSales / sales.length : 0;

      // Daily trend
      const dailyMap: Record<string, { amount: number; count: number }> = {};
      sales.forEach(s => {
        const day = s.created_at.split("T")[0];
        if (!dailyMap[day]) dailyMap[day] = { amount: 0, count: 0 };
        dailyMap[day].amount += Number(s.total_amount);
        dailyMap[day].count += 1;
      });
      const dailyTrend = Object.entries(dailyMap).sort().map(([d, v]) => ({ date: d.slice(5), amount: v.amount, count: v.count }));

      // Days in range for EOM projection
      const fromDate = new Date(from);
      const toDate = new Date(to);
      const daysInRange = Math.max(1, Math.ceil((toDate.getTime() - fromDate.getTime()) / 86400000) + 1);
      const dailyAvgSales = totalSales / daysInRange;
      const currentMonth = new Date();
      const daysInMonth = new Date(currentMonth.getFullYear(), currentMonth.getMonth() + 1, 0).getDate();
      const dayOfMonth = currentMonth.getDate();
      const estimatedEOM = dailyAvgSales * daysInMonth;

      // Growth rate: compare first half vs second half
      const midpoint = Math.floor(dailyTrend.length / 2);
      const firstHalf = dailyTrend.slice(0, midpoint).reduce((s, d) => s + d.amount, 0);
      const secondHalf = dailyTrend.slice(midpoint).reduce((s, d) => s + d.amount, 0);
      const growthRate = firstHalf > 0 ? ((secondHalf - firstHalf) / firstHalf * 100).toFixed(1) : "0";

      // Agent performance
      const agentMap: Record<string, { name: string; amount: number; count: number; cash: number; upi: number; credit: number }> = {};
      sales.forEach(s => {
        const uid = s.recorded_by;
        if (!agentMap[uid]) agentMap[uid] = { name: profileMap[uid] || "Unknown", amount: 0, count: 0, cash: 0, upi: 0, credit: 0 };
        agentMap[uid].amount += Number(s.total_amount);
        agentMap[uid].count += 1;
        agentMap[uid].cash += Number(s.cash_amount);
        agentMap[uid].upi += Number(s.upi_amount);
        agentMap[uid].credit += Number(s.outstanding_amount);
      });
      const agentRanking = Object.values(agentMap).sort((a, b) => b.amount - a.amount);

      // Store performance
      const storePerf: Record<string, { name: string; type: string; amount: number; count: number; avgSale: number }> = {};
      sales.forEach(s => {
        const sid = s.store_id;
        const st = storeMap[sid];
        const typeName = st ? storeTypeMap[st.store_type_id] || "Other" : "Unknown";
        if (!storePerf[sid]) storePerf[sid] = { name: (s.stores as any)?.name || "Unknown", type: typeName, amount: 0, count: 0, avgSale: 0 };
        storePerf[sid].amount += Number(s.total_amount);
        storePerf[sid].count += 1;
      });
      Object.values(storePerf).forEach(s => { s.avgSale = s.count > 0 ? s.amount / s.count : 0; });
      const storeRanking = Object.values(storePerf).sort((a, b) => b.amount - a.amount);

      // Store type breakdown
      const storeTypePerf: Record<string, { name: string; amount: number; count: number }> = {};
      sales.forEach(s => {
        const st = storeMap[s.store_id];
        const typeName = st ? storeTypeMap[st.store_type_id] || "Other" : "Other";
        if (!storeTypePerf[typeName]) storeTypePerf[typeName] = { name: typeName, amount: 0, count: 0 };
        storeTypePerf[typeName].amount += Number(s.total_amount);
        storeTypePerf[typeName].count += 1;
      });
      const storeTypeData = Object.values(storeTypePerf).sort((a, b) => b.amount - a.amount);

      // Payment method split
      const paymentSplit = [
        { name: "Cash", value: totalCash },
        { name: "UPI", value: totalUpi },
        { name: "Credit", value: totalCredit },
      ].filter(p => p.value > 0);

      return {
        totalSales, totalCash, totalUpi, totalCredit, avgSale, salesCount: sales.length,
        dailyTrend, dailyAvgSales, estimatedEOM, growthRate,
        agentRanking, storeRanking, storeTypeData, paymentSplit,
      };
    },
  });

  const exportPDF = () => {
    if (!data) return;
    const doc = new jsPDF({ orientation: "landscape", unit: "mm", format: "a4" });
    const pw = doc.internal.pageSize.getWidth();

    doc.setFillColor(30, 41, 59);
    doc.rect(0, 0, pw, 18, "F");
    doc.setTextColor(255, 255, 255);
    doc.setFontSize(14);
    doc.text("Sales Report", 10, 12);
    doc.setFontSize(9);
    doc.text(`${from} to ${to}`, pw - 10, 12, { align: "right" });

    let y = 24;
    doc.setTextColor(0, 0, 0);
    doc.setFontSize(8);

    // Summary
    const summaryData = [
      ["Total Sales", fmt(data.totalSales), "Avg Sale", fmt(data.avgSale)],
      ["Cash", fmt(data.totalCash), "UPI", fmt(data.totalUpi)],
      ["Credit Given", fmt(data.totalCredit), "Sale Count", String(data.salesCount)],
      ["Daily Avg", fmt(data.dailyAvgSales), "Est. EOM", fmt(data.estimatedEOM)],
      ["Growth Rate", data.growthRate + "%", "", ""],
    ];
    autoTable(doc, { startY: y, head: [["Metric", "Value", "Metric", "Value"]], body: summaryData, theme: "grid", styles: { fontSize: 7, cellPadding: 1.5 }, headStyles: { fillColor: [30, 41, 59] }, margin: { left: 10 }, tableWidth: 120 });

    // Agent ranking
    y = (doc as any).lastAutoTable.finalY + 4;
    autoTable(doc, { startY: y, head: [["Agent", "Sales", "Count", "Cash", "UPI", "Credit"]], body: data.agentRanking.map(a => [a.name, fmt(a.amount), a.count, fmt(a.cash), fmt(a.upi), fmt(a.credit)]), theme: "grid", styles: { fontSize: 6, cellPadding: 1.2 }, headStyles: { fillColor: [30, 41, 59] }, margin: { left: 10 }, tableWidth: 130 });

    // Store ranking on right side
    autoTable(doc, { startY: 24, head: [["Store", "Type", "Sales", "Count", "Avg"]], body: data.storeRanking.slice(0, 20).map(s => [s.name, s.type, fmt(s.amount), s.count, fmt(s.avgSale)]), theme: "grid", styles: { fontSize: 6, cellPadding: 1.2 }, headStyles: { fillColor: [30, 41, 59] }, margin: { left: 150 }, tableWidth: 137 });

    doc.save(`sales-report-${from}-to-${to}.pdf`);
    toast.success("PDF downloaded");
  };

  const exportExcel = () => {
    if (!data) return;
    const wb = XLSX.utils.book_new();

    XLSX.utils.book_append_sheet(wb, XLSX.utils.aoa_to_sheet([
      ["Sales Report", `${from} to ${to}`],
      [], ["Metric", "Value"],
      ["Total Sales", data.totalSales], ["Cash", data.totalCash], ["UPI", data.totalUpi],
      ["Credit", data.totalCredit], ["Sale Count", data.salesCount], ["Avg Sale", data.avgSale],
      ["Daily Avg", data.dailyAvgSales], ["Est. EOM", data.estimatedEOM], ["Growth %", data.growthRate],
    ]), "Summary");

    XLSX.utils.book_append_sheet(wb, XLSX.utils.json_to_sheet(data.agentRanking), "Agents");
    XLSX.utils.book_append_sheet(wb, XLSX.utils.json_to_sheet(data.storeRanking), "Stores");
    XLSX.utils.book_append_sheet(wb, XLSX.utils.json_to_sheet(data.dailyTrend), "Daily Trend");

    XLSX.writeFile(wb, `sales-report-${from}-to-${to}.xlsx`);
    toast.success("Excel downloaded");
  };

  if (isLoading) return <TableSkeleton />;
  if (!data) return null;
  const d = data;

  return (
    <div className="space-y-4">
      <div className="flex flex-wrap items-end gap-3">
        <div><Label className="text-xs">From</Label><Input type="date" value={from} onChange={e => setFrom(e.target.value)} className="w-40" /></div>
        <div><Label className="text-xs">To</Label><Input type="date" value={to} onChange={e => setTo(e.target.value)} className="w-40" /></div>
        <Button variant="outline" size="sm" onClick={exportPDF}><FileText className="h-4 w-4 mr-1" />PDF</Button>
        <Button variant="outline" size="sm" onClick={exportExcel}><FileSpreadsheet className="h-4 w-4 mr-1" />Excel</Button>
      </div>

      <div className="grid grid-cols-2 md:grid-cols-4 lg:grid-cols-6 gap-3">
        <StatCard title="Total Sales" value={fmt(d.totalSales)} icon={ShoppingCart} iconColor="primary" />
        <StatCard title="Sale Count" value={String(d.salesCount)} icon={ShoppingCart} iconColor="purple" />
        <StatCard title="Cash" value={fmt(d.totalCash)} icon={Banknote} iconColor="success" />
        <StatCard title="UPI" value={fmt(d.totalUpi)} icon={Smartphone} iconColor="info" />
        <StatCard title="Credit Given" value={fmt(d.totalCredit)} icon={TrendingDown} iconColor="destructive" />
        <StatCard title="Avg Sale" value={fmt(d.avgSale)} icon={DollarSign} iconColor="warning" />
      </div>

      <div className="grid grid-cols-1 md:grid-cols-3 gap-3">
        <Card><CardContent className="pt-4 text-center">
          <p className="text-xs text-muted-foreground">Daily Average</p>
          <p className="text-xl font-bold">{fmt(d.dailyAvgSales)}</p>
        </CardContent></Card>
        <Card><CardContent className="pt-4 text-center">
          <p className="text-xs text-muted-foreground">Estimated EOM</p>
          <p className="text-xl font-bold">{fmt(d.estimatedEOM)}</p>
        </CardContent></Card>
        <Card><CardContent className="pt-4 text-center">
          <p className="text-xs text-muted-foreground">Growth Rate</p>
          <p className={`text-xl font-bold ${Number(d.growthRate) >= 0 ? "text-success" : "text-destructive"}`}>{d.growthRate}%</p>
        </CardContent></Card>
      </div>

      <Tabs defaultValue="trend">
        <TabsList className="flex-wrap h-auto">
          <TabsTrigger value="trend">Sales Trend</TabsTrigger>
          <TabsTrigger value="agents">Agent Ranking</TabsTrigger>
          <TabsTrigger value="stores">Store Ranking</TabsTrigger>
          <TabsTrigger value="types">By Store Type</TabsTrigger>
          <TabsTrigger value="split">Payment Split</TabsTrigger>
        </TabsList>

        <TabsContent value="trend">
          <Card><CardHeader><CardTitle className="text-sm">Daily Sales Trend</CardTitle></CardHeader><CardContent>
            {d.dailyTrend.length === 0 ? <p className="text-sm text-muted-foreground text-center py-8">No data</p> : (
              <ResponsiveContainer width="100%" height={280}>
                <LineChart data={d.dailyTrend}>
                  <CartesianGrid strokeDasharray="3 3" stroke="hsl(var(--border))" />
                  <XAxis dataKey="date" tick={{ fontSize: 10 }} stroke="hsl(var(--muted-foreground))" />
                  <YAxis tick={{ fontSize: 10 }} stroke="hsl(var(--muted-foreground))" />
                  <Tooltip contentStyle={{ backgroundColor: "hsl(var(--card))", border: "1px solid hsl(var(--border))", borderRadius: "8px" }} />
                  <Line type="monotone" dataKey="amount" stroke="hsl(var(--primary))" strokeWidth={2} dot={false} name="Amount" />
                </LineChart>
              </ResponsiveContainer>
            )}
          </CardContent></Card>
        </TabsContent>

        <TabsContent value="agents">
          <Card><CardContent className="pt-4">
            <Table><TableHeader><TableRow>
              <TableHead>#</TableHead><TableHead>Agent</TableHead><TableHead className="text-right">Sales</TableHead>
              <TableHead className="text-right">Count</TableHead><TableHead className="text-right">Cash</TableHead>
              <TableHead className="text-right">UPI</TableHead><TableHead className="text-right">Credit</TableHead>
            </TableRow></TableHeader><TableBody>
              {d.agentRanking.map((a, i) => (
                <TableRow key={i}>
                  <TableCell><Badge variant={i === 0 ? "default" : "secondary"}>{i + 1}</Badge></TableCell>
                  <TableCell className="font-medium">{a.name}</TableCell>
                  <TableCell className="text-right">{fmt(a.amount)}</TableCell>
                  <TableCell className="text-right">{a.count}</TableCell>
                  <TableCell className="text-right">{fmt(a.cash)}</TableCell>
                  <TableCell className="text-right">{fmt(a.upi)}</TableCell>
                  <TableCell className="text-right text-destructive">{fmt(a.credit)}</TableCell>
                </TableRow>
              ))}
            </TableBody></Table>
          </CardContent></Card>
        </TabsContent>

        <TabsContent value="stores">
          <Card><CardContent className="pt-4">
            <Table><TableHeader><TableRow>
              <TableHead>#</TableHead><TableHead>Store</TableHead><TableHead>Type</TableHead>
              <TableHead className="text-right">Sales</TableHead><TableHead className="text-right">Count</TableHead>
              <TableHead className="text-right">Avg Sale</TableHead>
            </TableRow></TableHeader><TableBody>
              {d.storeRanking.slice(0, 30).map((s, i) => (
                <TableRow key={i}>
                  <TableCell>{i + 1}</TableCell>
                  <TableCell className="font-medium">{s.name}</TableCell>
                  <TableCell><Badge variant="outline">{s.type}</Badge></TableCell>
                  <TableCell className="text-right">{fmt(s.amount)}</TableCell>
                  <TableCell className="text-right">{s.count}</TableCell>
                  <TableCell className="text-right">{fmt(s.avgSale)}</TableCell>
                </TableRow>
              ))}
            </TableBody></Table>
          </CardContent></Card>
        </TabsContent>

        <TabsContent value="types">
          <Card><CardHeader><CardTitle className="text-sm">Sales by Store Type</CardTitle></CardHeader><CardContent>
            {d.storeTypeData.length === 0 ? <p className="text-sm text-muted-foreground text-center py-8">No data</p> : (
              <ResponsiveContainer width="100%" height={280}>
                <BarChart data={d.storeTypeData}>
                  <CartesianGrid strokeDasharray="3 3" stroke="hsl(var(--border))" />
                  <XAxis dataKey="name" tick={{ fontSize: 10 }} stroke="hsl(var(--muted-foreground))" />
                  <YAxis tick={{ fontSize: 10 }} stroke="hsl(var(--muted-foreground))" />
                  <Tooltip contentStyle={{ backgroundColor: "hsl(var(--card))", border: "1px solid hsl(var(--border))", borderRadius: "8px" }} />
                  <Bar dataKey="amount" fill="hsl(var(--primary))" radius={[4, 4, 0, 0]} name="Sales" />
                </BarChart>
              </ResponsiveContainer>
            )}
          </CardContent></Card>
        </TabsContent>

        <TabsContent value="split">
          <Card><CardHeader><CardTitle className="text-sm">Payment Method Split</CardTitle></CardHeader><CardContent>
            {d.paymentSplit.length === 0 ? <p className="text-sm text-muted-foreground text-center py-8">No data</p> : (
              <div className="flex flex-col items-center">
                <ResponsiveContainer width="100%" height={250}>
                  <PieChart><Pie data={d.paymentSplit} cx="50%" cy="50%" innerRadius={50} outerRadius={90} paddingAngle={3} dataKey="value" label={({ name, value }) => `${name}: ${fmt(value)}`}>
                    {d.paymentSplit.map((_, i) => <Cell key={i} fill={COLORS[i % COLORS.length]} />)}
                  </Pie><Tooltip formatter={(v: number) => fmt(v)} /></PieChart>
                </ResponsiveContainer>
              </div>
            )}
          </CardContent></Card>
        </TabsContent>
      </Tabs>
    </div>
  );
}

import { useState, useMemo } from "react";
import { useQuery } from "@tanstack/react-query";
import { supabase } from "@/integrations/supabase/client";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { Input } from "@/components/ui/input";
import { Loader2, ShoppingCart, DollarSign, TrendingUp, Package, Search, RotateCcw, AlertCircle } from "lucide-react";
import { format, subMonths, startOfMonth } from "date-fns";
import { ReportFilters, DateRange } from "./ReportFilters";
import { ReportExportBar } from "./ReportExportBar";
import { ReportSummaryCards } from "./ReportSummaryCards";
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, Legend, LineChart, Line } from "recharts";
import jsPDF from "jspdf";
import autoTable from "jspdf-autotable";
import * as XLSX from "xlsx";

interface SaleReturnData {
  id: string;
  display_id: string;
  customer_name: string;
  store_name: string;
  return_date: string;
  total_amount: number;
  status: string;
  reason: string;
  items_count: number;
}

interface SalesReportData {
  total_sales: number;
  total_returns: number;
  net_sales: number;
  return_rate: number;
  total_transactions: number;
  total_return_transactions: number;
}

export default function SalesReturnReport() {
  const [dateRange, setDateRange] = useState<DateRange>({
    from: startOfMonth(subMonths(new Date(), 3)),
    to: new Date(),
  });
  const [search, setSearch] = useState("");
  const [statusFilter, setStatusFilter] = useState<"all" | "pending" | "approved" | "completed" | "rejected">("all");

  // Fetch sale returns
  const { data: saleReturns = [], isLoading: srLoading } = useQuery({
    queryKey: ["sales-return-report", dateRange],
    queryFn: async () => {
      const { data } = await supabase
        .from("sale_returns")
        .select(`
          id, display_id, return_date, total_amount, status, reason,
          customers(name),
          stores(name),
          sale_return_items(id)
        `)
        .gte("return_date", format(dateRange.from, "yyyy-MM-dd"))
        .lte("return_date", format(dateRange.to, "yyyy-MM-dd"))
        .order("return_date", { ascending: false });
      
      return (data || []).map((sr: any) => ({
        id: sr.id,
        display_id: sr.display_id,
        customer_name: sr.customers?.name || "Unknown",
        store_name: sr.stores?.name || "Direct",
        return_date: sr.return_date,
        total_amount: Number(sr.total_amount),
        status: sr.status,
        reason: sr.reason || "",
        items_count: sr.sale_return_items?.length || 0,
      }));
    },
  });

  // Fetch sales for comparison
  const { data: sales = [], isLoading: salesLoading } = useQuery({
    queryKey: ["sales-return-report-sales", dateRange],
    queryFn: async () => {
      const { data } = await supabase
        .from("sales")
        .select("id, total_amount, created_at")
        .gte("created_at", format(dateRange.from, "yyyy-MM-dd"))
        .lte("created_at", format(dateRange.to, "yyyy-MM-dd"));
      return data || [];
    },
  });

  const isLoading = srLoading || salesLoading;

  // Filter
  const filteredReturns = useMemo(() => {
    let filtered = saleReturns;
    
    if (search) {
      const s = search.toLowerCase();
      filtered = filtered.filter((r: SaleReturnData) =>
        r.customer_name.toLowerCase().includes(s) ||
        r.store_name.toLowerCase().includes(s) ||
        r.display_id.toLowerCase().includes(s) ||
        r.reason.toLowerCase().includes(s)
      );
    }
    
    if (statusFilter !== "all") {
      filtered = filtered.filter((r: SaleReturnData) => r.status === statusFilter);
    }
    
    return filtered;
  }, [saleReturns, search, statusFilter]);

  // Summary
  const summary = useMemo((): SalesReportData => {
    const totalSales = sales.reduce((sum: number, s: any) => sum + Number(s.total_amount), 0);
    const totalReturns = filteredReturns
      .filter((r: SaleReturnData) => r.status === "completed")
      .reduce((sum, r) => sum + r.total_amount, 0);
    
    return {
      total_sales: totalSales,
      total_returns: totalReturns,
      net_sales: totalSales - totalReturns,
      return_rate: totalSales > 0 ? (totalReturns / totalSales) * 100 : 0,
      total_transactions: sales.length,
      total_return_transactions: filteredReturns.length,
    };
  }, [sales, filteredReturns]);

  // Returns by reason
  const reasonBreakdown = useMemo(() => {
    const byReason: Record<string, { count: number; amount: number }> = {};
    
    filteredReturns.forEach((r: SaleReturnData) => {
      const reason = r.reason || "Not specified";
      if (!byReason[reason]) byReason[reason] = { count: 0, amount: 0 };
      byReason[reason].count++;
      byReason[reason].amount += r.total_amount;
    });
    
    return Object.entries(byReason)
      .map(([reason, data]) => ({ reason, ...data }))
      .sort((a, b) => b.amount - a.amount)
      .slice(0, 10);
  }, [filteredReturns]);

  // Returns by status
  const statusBreakdown = useMemo(() => {
    const byStatus: Record<string, number> = {};
    
    saleReturns.forEach((r: SaleReturnData) => {
      byStatus[r.status] = (byStatus[r.status] || 0) + 1;
    });
    
    return Object.entries(byStatus).map(([status, count]) => ({ status, count }));
  }, [saleReturns]);

  // Trend over time
  const trendData = useMemo(() => {
    const byDate: Record<string, { date: string; returns: number; amount: number }> = {};
    
    filteredReturns.forEach((r: SaleReturnData) => {
      const date = format(new Date(r.return_date), "MMM d");
      if (!byDate[date]) byDate[date] = { date, returns: 0, amount: 0 };
      byDate[date].returns++;
      byDate[date].amount += r.total_amount;
    });
    
    return Object.values(byDate).sort((a, b) => 
      new Date(a.date).getTime() - new Date(b.date).getTime()
    );
  }, [filteredReturns]);

  const summaryCards = [
    { label: "Total Sales", value: `₹${(summary.total_sales / 1000).toFixed(0)}K`, icon: ShoppingCart, iconColor: "blue" },
    { label: "Total Returns", value: `₹${(summary.total_returns / 1000).toFixed(0)}K`, icon: RotateCcw, iconColor: "red" },
    { label: "Net Sales", value: `₹${(summary.net_sales / 1000).toFixed(0)}K`, icon: DollarSign, iconColor: "green" },
    { label: "Return Rate", value: `${summary.return_rate.toFixed(1)}%`, icon: AlertCircle, iconColor: "yellow" },
  ];

  const statusColors: Record<string, string> = {
    pending: "bg-yellow-100 text-yellow-800",
    approved: "bg-blue-100 text-blue-800",
    completed: "bg-green-100 text-green-800",
    rejected: "bg-red-100 text-red-800",
  };

  const exportPDF = () => {
    const doc = new jsPDF();
    doc.setFontSize(16);
    doc.text("Sales Returns Report", 14, 15);
    doc.setFontSize(10);
    doc.text(`Period: ${format(dateRange.from, "MMM d, yyyy")} - ${format(dateRange.to, "MMM d, yyyy")}`, 14, 23);

    autoTable(doc, {
      startY: 30,
      head: [["Date", "Return ID", "Customer", "Store", "Amount", "Status", "Reason"]],
      body: filteredReturns.map((r: SaleReturnData) => [
        format(new Date(r.return_date), "dd/MM/yy"),
        r.display_id,
        r.customer_name,
        r.store_name,
        `₹${r.total_amount.toLocaleString()}`,
        r.status,
        r.reason || "—",
      ]),
      styles: { fontSize: 8 },
      headStyles: { fillColor: [239, 68, 68] },
    });

    doc.save(`sales-return-report-${format(dateRange.from, "yyyyMMdd")}-${format(dateRange.to, "yyyyMMdd")}.pdf`);
  };

  const exportExcel = () => {
    const ws = XLSX.utils.json_to_sheet(filteredReturns.map((r: SaleReturnData) => ({
      "Date": r.return_date,
      "Return ID": r.display_id,
      "Customer": r.customer_name,
      "Store": r.store_name,
      "Amount": r.total_amount,
      "Status": r.status,
      "Items": r.items_count,
      "Reason": r.reason,
    })));
    const wb = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(wb, ws, "Sales Returns");
    XLSX.writeFile(wb, `sales-return-report-${format(dateRange.from, "yyyyMMdd")}-${format(dateRange.to, "yyyyMMdd")}.xlsx`);
  };

  return (
    <div className="space-y-6">
      <div className="flex flex-col lg:flex-row lg:items-end gap-4">
        <ReportFilters dateRange={dateRange} onDateRangeChange={setDateRange} />
        <div className="relative flex-1 max-w-xs">
          <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-muted-foreground" />
          <Input
            placeholder="Search returns..."
            value={search}
            onChange={(e) => setSearch(e.target.value)}
            className="pl-9"
          />
        </div>
        <div className="flex gap-2 flex-wrap">
          {["all", "pending", "approved", "completed", "rejected"].map((status) => (
            <Badge
              key={status}
              variant={statusFilter === status ? "default" : "outline"}
              className="cursor-pointer capitalize"
              onClick={() => setStatusFilter(status as any)}
            >
              {status}
            </Badge>
          ))}
        </div>
      </div>

      <ReportExportBar onExportPDF={exportPDF} onExportExcel={exportExcel} />

      {isLoading ? (
        <div className="flex items-center justify-center py-12">
          <Loader2 className="h-8 w-8 animate-spin text-muted-foreground" />
        </div>
      ) : (
        <>
          <ReportSummaryCards cards={summaryCards} />

          <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
            {/* Returns Trend */}
            {trendData.length > 1 && (
              <Card>
                <CardHeader>
                  <CardTitle className="text-base">Returns Trend</CardTitle>
                </CardHeader>
                <CardContent>
                  <ResponsiveContainer width="100%" height={250}>
                    <LineChart data={trendData}>
                      <CartesianGrid strokeDasharray="3 3" />
                      <XAxis dataKey="date" tick={{ fontSize: 11 }} />
                      <YAxis yAxisId="left" orientation="left" />
                      <YAxis yAxisId="right" orientation="right" tickFormatter={(v) => `₹${(v / 1000).toFixed(0)}K`} />
                      <Tooltip formatter={(v: number, name: string) => 
                        name === "amount" ? `₹${v.toLocaleString()}` : v
                      } />
                      <Legend />
                      <Line yAxisId="left" type="monotone" dataKey="returns" name="Count" stroke="#3b82f6" />
                      <Line yAxisId="right" type="monotone" dataKey="amount" name="Amount" stroke="#ef4444" />
                    </LineChart>
                  </ResponsiveContainer>
                </CardContent>
              </Card>
            )}

            {/* Returns by Reason */}
            <Card>
              <CardHeader>
                <CardTitle className="text-base">Returns by Reason</CardTitle>
              </CardHeader>
              <CardContent>
                {reasonBreakdown.length > 0 ? (
                  <ResponsiveContainer width="100%" height={250}>
                    <BarChart data={reasonBreakdown} layout="vertical">
                      <CartesianGrid strokeDasharray="3 3" />
                      <XAxis type="number" tickFormatter={(v) => `₹${(v / 1000).toFixed(0)}K`} />
                      <YAxis type="category" dataKey="reason" width={120} tick={{ fontSize: 10 }} />
                      <Tooltip formatter={(v: number) => `₹${v.toLocaleString()}`} />
                      <Bar dataKey="amount" name="Amount" fill="#ef4444" />
                    </BarChart>
                  </ResponsiveContainer>
                ) : (
                  <p className="text-center text-muted-foreground py-12">No data</p>
                )}
              </CardContent>
            </Card>
          </div>

          {/* Status Breakdown */}
          <Card>
            <CardHeader>
              <CardTitle className="text-base">Returns by Status</CardTitle>
            </CardHeader>
            <CardContent>
              <div className="flex flex-wrap gap-4">
                {statusBreakdown.map((s) => (
                  <div key={s.status} className="flex items-center gap-2">
                    <Badge className={statusColors[s.status]}>{s.status}</Badge>
                    <span className="font-semibold">{s.count}</span>
                  </div>
                ))}
              </div>
            </CardContent>
          </Card>

          {/* Returns Table */}
          <Card>
            <CardHeader>
              <CardTitle className="text-base">Return Details ({filteredReturns.length})</CardTitle>
            </CardHeader>
            <CardContent>
              {filteredReturns.length === 0 ? (
                <p className="text-center text-muted-foreground py-12">No returns found</p>
              ) : (
                <div className="overflow-x-auto">
                  <table className="w-full text-sm">
                    <thead>
                      <tr className="border-b bg-muted/50">
                        <th className="text-left p-3 font-medium">Date</th>
                        <th className="text-left p-3 font-medium">Return ID</th>
                        <th className="text-left p-3 font-medium">Customer</th>
                        <th className="text-left p-3 font-medium hidden md:table-cell">Store</th>
                        <th className="text-right p-3 font-medium">Amount</th>
                        <th className="text-center p-3 font-medium">Status</th>
                        <th className="text-left p-3 font-medium hidden lg:table-cell">Reason</th>
                      </tr>
                    </thead>
                    <tbody>
                      {filteredReturns.slice(0, 50).map((r: SaleReturnData) => (
                        <tr key={r.id} className="border-b hover:bg-muted/30">
                          <td className="p-3 text-muted-foreground text-xs">
                            {format(new Date(r.return_date), "dd/MM/yy")}
                          </td>
                          <td className="p-3 font-mono text-xs">{r.display_id}</td>
                          <td className="p-3 font-medium">{r.customer_name}</td>
                          <td className="p-3 hidden md:table-cell text-muted-foreground">{r.store_name}</td>
                          <td className="p-3 text-right font-semibold text-red-600">
                            ₹{r.total_amount.toLocaleString()}
                          </td>
                          <td className="p-3 text-center">
                            <Badge className={statusColors[r.status]} variant="secondary">
                              {r.status}
                            </Badge>
                          </td>
                          <td className="p-3 hidden lg:table-cell text-muted-foreground truncate max-w-[200px]">
                            {r.reason || "—"}
                          </td>
                        </tr>
                      ))}
                    </tbody>
                  </table>
                </div>
              )}
              {filteredReturns.length > 50 && (
                <p className="text-center text-muted-foreground mt-4 text-sm">
                  Showing 50 of {filteredReturns.length} returns. Export to see all.
                </p>
              )}
            </CardContent>
          </Card>
        </>
      )}
    </div>
  );
}

import { useState, useMemo } from "react";
import { useQuery } from "@tanstack/react-query";
import { supabase } from "@/integrations/supabase/client";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Loader2, Package, AlertTriangle, TrendingDown, Archive, Search, Download } from "lucide-react";
import { ReportExportBar } from "./ReportExportBar";
import { ReportSummaryCards } from "./ReportSummaryCards";
import jsPDF from "jspdf";
import autoTable from "jspdf-autotable";
import * as XLSX from "xlsx";

interface StockItem {
  id: string;
  name: string;
  display_id: string;
  hsn_code: string | null;
  mrp: number;
  gst_rate: number;
  category: string | null;
  total_stock: number;
  warehouses: { id: string; name: string; quantity: number }[];
  status: "in_stock" | "low_stock" | "out_of_stock";
  stock_value: number;
}

export default function StockSummaryReport() {
  const [search, setSearch] = useState("");
  const [statusFilter, setStatusFilter] = useState<"all" | "in_stock" | "low_stock" | "out_of_stock">("all");

  // Fetch products with stock
  const { data: products = [], isLoading: productsLoading } = useQuery({
    queryKey: ["stock-summary-products"],
    queryFn: async () => {
      const { data } = await supabase
        .from("products")
        .select("id, name, display_id, hsn_code, mrp, gst_rate, is_active, product_categories(name)")
        .eq("is_active", true)
        .order("name");
      return data || [];
    },
  });

  // Fetch stock by product and warehouse
  const { data: stockData = [], isLoading: stockLoading } = useQuery({
    queryKey: ["stock-summary-stock"],
    queryFn: async () => {
      const { data } = await supabase
        .from("product_stock")
        .select("product_id, warehouse_id, quantity, warehouses(id, name)");
      return data || [];
    },
  });

  // Fetch warehouses
  const { data: warehouses = [] } = useQuery({
    queryKey: ["stock-summary-warehouses"],
    queryFn: async () => {
      const { data } = await supabase.from("warehouses").select("id, name").eq("is_active", true);
      return data || [];
    },
  });

  const isLoading = productsLoading || stockLoading;

  // Combine data
  const stockItems = useMemo(() => {
    const LOW_STOCK_THRESHOLD = 10;

    return products.map((p: any): StockItem => {
      const productStock = stockData.filter((s: any) => s.product_id === p.id);
      const totalStock = productStock.reduce((sum, s: any) => sum + Number(s.quantity || 0), 0);
      
      const warehouseStock = productStock.map((s: any) => ({
        id: s.warehouse_id,
        name: s.warehouses?.name || "Unknown",
        quantity: Number(s.quantity || 0),
      }));

      let status: "in_stock" | "low_stock" | "out_of_stock" = "in_stock";
      if (totalStock === 0) status = "out_of_stock";
      else if (totalStock <= LOW_STOCK_THRESHOLD) status = "low_stock";

      return {
        id: p.id,
        name: p.name,
        display_id: p.display_id || "",
        hsn_code: p.hsn_code,
        mrp: Number(p.mrp || 0),
        gst_rate: Number(p.gst_rate || 0),
        category: p.product_categories?.name || null,
        total_stock: totalStock,
        warehouses: warehouseStock,
        status,
        stock_value: totalStock * Number(p.mrp || 0),
      };
    });
  }, [products, stockData]);

  // Filter items
  const filteredItems = useMemo(() => {
    return stockItems.filter((item) => {
      const matchesSearch = !search || 
        item.name.toLowerCase().includes(search.toLowerCase()) ||
        item.display_id.toLowerCase().includes(search.toLowerCase()) ||
        (item.hsn_code && item.hsn_code.includes(search));
      
      const matchesStatus = statusFilter === "all" || item.status === statusFilter;
      
      return matchesSearch && matchesStatus;
    });
  }, [stockItems, search, statusFilter]);

  // Calculate totals
  const totals = useMemo(() => {
    const totalProducts = stockItems.length;
    const inStock = stockItems.filter(i => i.status === "in_stock").length;
    const lowStock = stockItems.filter(i => i.status === "low_stock").length;
    const outOfStock = stockItems.filter(i => i.status === "out_of_stock").length;
    const totalUnits = stockItems.reduce((sum, i) => sum + i.total_stock, 0);
    const totalValue = stockItems.reduce((sum, i) => sum + i.stock_value, 0);
    
    return { totalProducts, inStock, lowStock, outOfStock, totalUnits, totalValue };
  }, [stockItems]);

  const getStatusBadge = (status: string) => {
    switch (status) {
      case "in_stock":
        return <Badge variant="default" className="bg-green-100 text-green-800">In Stock</Badge>;
      case "low_stock":
        return <Badge variant="secondary" className="bg-yellow-100 text-yellow-800">Low Stock</Badge>;
      case "out_of_stock":
        return <Badge variant="destructive">Out of Stock</Badge>;
      default:
        return null;
    }
  };

  const exportPDF = () => {
    const doc = new jsPDF({ orientation: "landscape" });
    doc.setFontSize(16);
    doc.text("Stock Summary Report", 14, 20);
    doc.setFontSize(10);
    doc.text(`Generated: ${new Date().toLocaleDateString()}`, 14, 28);
    doc.text(`Total Stock Value: ₹${totals.totalValue.toLocaleString()}`, 14, 35);

    const headers = ["Product", "ID", "HSN", "Category", "MRP", "Stock", "Value", "Status"];
    if (warehouses.length > 1) {
      warehouses.forEach((wh: any) => headers.push(wh.name));
    }

    autoTable(doc, {
      startY: 42,
      head: [headers],
      body: filteredItems.map((item) => {
        const row = [
          item.name,
          item.display_id,
          item.hsn_code || "—",
          item.category || "—",
          `₹${item.mrp.toLocaleString()}`,
          item.total_stock.toString(),
          `₹${item.stock_value.toLocaleString()}`,
          item.status.replace("_", " ").toUpperCase(),
        ];
        if (warehouses.length > 1) {
          warehouses.forEach((wh: any) => {
            const whStock = item.warehouses.find(w => w.id === wh.id);
            row.push(whStock?.quantity?.toString() || "0");
          });
        }
        return row;
      }),
      styles: { fontSize: 8 },
      headStyles: { fillColor: [41, 128, 185] },
    });

    doc.save(`stock-summary-${new Date().toISOString().split("T")[0]}.pdf`);
  };

  const exportExcel = () => {
    const data = filteredItems.map((item) => {
      const row: any = {
        "Product Name": item.name,
        "Product ID": item.display_id,
        "HSN Code": item.hsn_code || "",
        "Category": item.category || "",
        "MRP": item.mrp,
        "Total Stock": item.total_stock,
        "Stock Value": item.stock_value,
        "Status": item.status.replace("_", " "),
      };
      warehouses.forEach((wh: any) => {
        const whStock = item.warehouses.find(w => w.id === wh.id);
        row[wh.name] = whStock?.quantity || 0;
      });
      return row;
    });

    const ws = XLSX.utils.json_to_sheet(data);
    const wb = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(wb, ws, "Stock Summary");
    XLSX.writeFile(wb, `stock-summary-${new Date().toISOString().split("T")[0]}.xlsx`);
  };

  const summaryCards = [
    { label: "Total Products", value: totals.totalProducts, icon: Package, iconColor: "blue" },
    { label: "In Stock", value: totals.inStock, icon: Package, iconColor: "green" },
    { label: "Low Stock", value: totals.lowStock, icon: AlertTriangle, iconColor: "yellow" },
    { label: "Out of Stock", value: totals.outOfStock, icon: TrendingDown, iconColor: "red" },
    { label: "Total Units", value: totals.totalUnits.toLocaleString(), icon: Archive, iconColor: "purple" },
    { label: "Stock Value", value: `₹${totals.totalValue.toLocaleString()}`, icon: Package, iconColor: "indigo" },
  ];

  return (
    <div className="space-y-6">
      <div className="flex flex-col sm:flex-row sm:items-center sm:justify-between gap-4">
        <div>
          <h2 className="text-xl font-semibold">Stock Summary</h2>
          <p className="text-sm text-muted-foreground">Current inventory levels across all warehouses</p>
        </div>
        <ReportExportBar onExportPDF={exportPDF} onExportExcel={exportExcel} showCSV={false} showPrint={false} />
      </div>

      <ReportSummaryCards cards={summaryCards} columns={6} />

      {/* Filters */}
      <Card className="p-4">
        <div className="flex flex-wrap items-center gap-4">
          <div className="relative flex-1 min-w-[200px]">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-muted-foreground" />
            <Input
              placeholder="Search products..."
              value={search}
              onChange={(e) => setSearch(e.target.value)}
              className="pl-9"
            />
          </div>
          <div className="flex gap-2">
            <Button
              variant={statusFilter === "all" ? "default" : "outline"}
              size="sm"
              onClick={() => setStatusFilter("all")}
            >
              All
            </Button>
            <Button
              variant={statusFilter === "in_stock" ? "default" : "outline"}
              size="sm"
              onClick={() => setStatusFilter("in_stock")}
              className={statusFilter === "in_stock" ? "bg-green-600" : ""}
            >
              In Stock ({totals.inStock})
            </Button>
            <Button
              variant={statusFilter === "low_stock" ? "default" : "outline"}
              size="sm"
              onClick={() => setStatusFilter("low_stock")}
              className={statusFilter === "low_stock" ? "bg-yellow-600" : ""}
            >
              Low Stock ({totals.lowStock})
            </Button>
            <Button
              variant={statusFilter === "out_of_stock" ? "default" : "outline"}
              size="sm"
              onClick={() => setStatusFilter("out_of_stock")}
              className={statusFilter === "out_of_stock" ? "bg-red-600" : ""}
            >
              Out of Stock ({totals.outOfStock})
            </Button>
          </div>
        </div>
      </Card>

      {isLoading ? (
        <div className="flex items-center justify-center py-12">
          <Loader2 className="h-8 w-8 animate-spin text-muted-foreground" />
        </div>
      ) : filteredItems.length === 0 ? (
        <Card>
          <CardContent className="flex flex-col items-center justify-center py-12">
            <Package className="h-12 w-12 text-muted-foreground/30 mb-4" />
            <p className="text-muted-foreground">No products found</p>
          </CardContent>
        </Card>
      ) : (
        <Card>
          <CardContent className="p-0">
            <div className="overflow-x-auto">
              <table className="w-full">
                <thead className="bg-muted/50">
                  <tr className="text-left text-sm">
                    <th className="px-4 py-3 font-medium">Product</th>
                    <th className="px-4 py-3 font-medium">HSN</th>
                    <th className="px-4 py-3 font-medium">Category</th>
                    <th className="px-4 py-3 font-medium text-right">MRP</th>
                    <th className="px-4 py-3 font-medium text-right">Stock</th>
                    {warehouses.length > 1 && warehouses.map((wh: any) => (
                      <th key={wh.id} className="px-4 py-3 font-medium text-right">{wh.name}</th>
                    ))}
                    <th className="px-4 py-3 font-medium text-right">Value</th>
                    <th className="px-4 py-3 font-medium">Status</th>
                  </tr>
                </thead>
                <tbody className="divide-y">
                  {filteredItems.map((item) => (
                    <tr key={item.id} className="hover:bg-muted/30 transition-colors">
                      <td className="px-4 py-3">
                        <div>
                          <p className="font-medium">{item.name}</p>
                          <p className="text-xs text-muted-foreground font-mono">{item.display_id}</p>
                        </div>
                      </td>
                      <td className="px-4 py-3 text-sm text-muted-foreground">{item.hsn_code || "—"}</td>
                      <td className="px-4 py-3 text-sm">{item.category || "—"}</td>
                      <td className="px-4 py-3 text-sm text-right">₹{item.mrp.toLocaleString()}</td>
                      <td className="px-4 py-3 text-right">
                        <span className={`font-semibold ${item.status === "out_of_stock" ? "text-red-600" : item.status === "low_stock" ? "text-yellow-600" : ""}`}>
                          {item.total_stock}
                        </span>
                      </td>
                      {warehouses.length > 1 && warehouses.map((wh: any) => {
                        const whStock = item.warehouses.find(w => w.id === wh.id);
                        return (
                          <td key={wh.id} className="px-4 py-3 text-sm text-right text-muted-foreground">
                            {whStock?.quantity || 0}
                          </td>
                        );
                      })}
                      <td className="px-4 py-3 text-right font-medium">₹{item.stock_value.toLocaleString()}</td>
                      <td className="px-4 py-3">{getStatusBadge(item.status)}</td>
                    </tr>
                  ))}
                </tbody>
                <tfoot className="bg-muted/70 font-semibold">
                  <tr>
                    <td colSpan={4} className="px-4 py-3 text-right">TOTAL</td>
                    <td className="px-4 py-3 text-right">{totals.totalUnits.toLocaleString()}</td>
                    {warehouses.length > 1 && warehouses.map((wh: any) => {
                      const whTotal = stockItems.reduce((sum, item) => {
                        const whStock = item.warehouses.find(w => w.id === wh.id);
                        return sum + (whStock?.quantity || 0);
                      }, 0);
                      return <td key={wh.id} className="px-4 py-3 text-right">{whTotal.toLocaleString()}</td>;
                    })}
                    <td className="px-4 py-3 text-right">₹{totals.totalValue.toLocaleString()}</td>
                    <td></td>
                  </tr>
                </tfoot>
              </table>
            </div>
          </CardContent>
        </Card>
      )}
    </div>
  );
}

import { useState, useMemo } from "react";
import { useQuery } from "@tanstack/react-query";
import { supabase } from "@/integrations/supabase/client";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Loader2, Building2, TrendingUp, TrendingDown, Package, DollarSign, Search, ArrowUpRight, ArrowDownRight } from "lucide-react";
import { format, subMonths, startOfMonth } from "date-fns";
import { ReportFilters, DateRange } from "./ReportFilters";
import { ReportExportBar } from "./ReportExportBar";
import { ReportSummaryCards } from "./ReportSummaryCards";
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, PieChart, Pie, Cell, Legend } from "recharts";
import jsPDF from "jspdf";
import autoTable from "jspdf-autotable";
import * as XLSX from "xlsx";

const COLORS = ["#3b82f6", "#10b981", "#f59e0b", "#ef4444", "#8b5cf6", "#ec4899", "#06b6d4", "#84cc16"];

export default function VendorReport() {
  const [dateRange, setDateRange] = useState<DateRange>({
    from: startOfMonth(subMonths(new Date(), 2)),
    to: new Date(),
  });
  const [search, setSearch] = useState("");

  // Fetch vendors
  const { data: vendors = [], isLoading: vendorsLoading } = useQuery({
    queryKey: ["vendor-report-vendors"],
    queryFn: async () => {
      const { data } = await supabase
        .from("vendors")
        .select("id, name, display_id, phone, email, outstanding, is_active")
        .order("name");
      return data || [];
    },
  });

  // Fetch purchases in date range
  const { data: purchases = [], isLoading: purchLoading } = useQuery({
    queryKey: ["vendor-report-purchases", dateRange],
    queryFn: async () => {
      const { data } = await supabase
        .from("purchases")
        .select("id, vendor_id, total_amount, purchase_date")
        .gte("purchase_date", format(dateRange.from, "yyyy-MM-dd"))
        .lte("purchase_date", format(dateRange.to, "yyyy-MM-dd"));
      return data || [];
    },
  });

  // Fetch vendor payments in date range
  const { data: payments = [], isLoading: payLoading } = useQuery({
    queryKey: ["vendor-report-payments", dateRange],
    queryFn: async () => {
      const { data } = await supabase
        .from("vendor_payments")
        .select("id, vendor_id, amount, payment_date")
        .gte("payment_date", format(dateRange.from, "yyyy-MM-dd"))
        .lte("payment_date", format(dateRange.to, "yyyy-MM-dd"));
      return data || [];
    },
  });

  // Fetch purchase returns
  const { data: returns = [], isLoading: retLoading } = useQuery({
    queryKey: ["vendor-report-returns", dateRange],
    queryFn: async () => {
      const { data } = await supabase
        .from("purchase_returns")
        .select("id, vendor_id, total_amount, return_date, status")
        .gte("return_date", format(dateRange.from, "yyyy-MM-dd"))
        .lte("return_date", format(dateRange.to, "yyyy-MM-dd"))
        .eq("status", "completed");
      return data || [];
    },
  });

  const isLoading = vendorsLoading || purchLoading || payLoading || retLoading;

  // Aggregate data by vendor
  const vendorStats = useMemo(() => {
    return vendors.map((v: any) => {
      const vendorPurchases = purchases.filter((p: any) => p.vendor_id === v.id);
      const vendorPayments = payments.filter((p: any) => p.vendor_id === v.id);
      const vendorReturns = returns.filter((r: any) => r.vendor_id === v.id);

      const totalPurchases = vendorPurchases.reduce((sum: number, p: any) => sum + Number(p.total_amount), 0);
      const totalPayments = vendorPayments.reduce((sum: number, p: any) => sum + Number(p.amount), 0);
      const totalReturns = vendorReturns.reduce((sum: number, r: any) => sum + Number(r.total_amount), 0);
      const purchaseCount = vendorPurchases.length;

      return {
        ...v,
        totalPurchases,
        totalPayments,
        totalReturns,
        purchaseCount,
        netPurchases: totalPurchases - totalReturns,
      };
    }).filter((v: any) => v.totalPurchases > 0 || v.outstanding > 0);
  }, [vendors, purchases, payments, returns]);

  // Filter by search
  const filteredVendors = useMemo(() => {
    if (!search) return vendorStats;
    const s = search.toLowerCase();
    return vendorStats.filter((v: any) => 
      v.name?.toLowerCase().includes(s) || 
      v.display_id?.toLowerCase().includes(s)
    );
  }, [vendorStats, search]);

  // Summary calculations
  const summary = useMemo(() => {
    const totalPurchases = filteredVendors.reduce((sum: number, v: any) => sum + v.totalPurchases, 0);
    const totalPayments = filteredVendors.reduce((sum: number, v: any) => sum + v.totalPayments, 0);
    const totalReturns = filteredVendors.reduce((sum: number, v: any) => sum + v.totalReturns, 0);
    const totalOutstanding = filteredVendors.reduce((sum: number, v: any) => sum + Number(v.outstanding || 0), 0);
    const activeVendors = filteredVendors.filter((v: any) => v.is_active).length;

    return { totalPurchases, totalPayments, totalReturns, totalOutstanding, activeVendors, totalVendors: filteredVendors.length };
  }, [filteredVendors]);

  // Top vendors by purchase
  const topVendorsChart = useMemo(() => {
    return [...filteredVendors]
      .sort((a: any, b: any) => b.totalPurchases - a.totalPurchases)
      .slice(0, 10)
      .map((v: any) => ({
        name: v.name?.length > 15 ? v.name.substring(0, 15) + "..." : v.name,
        purchases: v.totalPurchases,
        payments: v.totalPayments,
      }));
  }, [filteredVendors]);

  // Outstanding distribution
  const outstandingChart = useMemo(() => {
    return [...filteredVendors]
      .filter((v: any) => Number(v.outstanding) > 0)
      .sort((a: any, b: any) => Number(b.outstanding) - Number(a.outstanding))
      .slice(0, 8)
      .map((v: any) => ({
        name: v.name?.length > 12 ? v.name.substring(0, 12) + "..." : v.name,
        value: Number(v.outstanding),
      }));
  }, [filteredVendors]);

  const summaryCards = [
    { label: "Total Purchases", value: `₹${summary.totalPurchases.toLocaleString()}`, icon: Package, iconColor: "blue" },
    { label: "Total Payments", value: `₹${summary.totalPayments.toLocaleString()}`, icon: DollarSign, iconColor: "green" },
    { label: "Total Returns", value: `₹${summary.totalReturns.toLocaleString()}`, icon: TrendingDown, iconColor: "yellow" },
    { label: "Total Outstanding", value: `₹${summary.totalOutstanding.toLocaleString()}`, icon: TrendingUp, iconColor: "red" },
  ];

  const exportPDF = () => {
    const doc = new jsPDF();
    doc.setFontSize(16);
    doc.text("Vendor Report", 14, 15);
    doc.setFontSize(10);
    doc.text(`Period: ${format(dateRange.from, "MMM d, yyyy")} - ${format(dateRange.to, "MMM d, yyyy")}`, 14, 23);

    autoTable(doc, {
      startY: 30,
      head: [["Vendor", "Purchases", "Payments", "Returns", "Outstanding"]],
      body: filteredVendors.map((v: any) => [
        v.name,
        `₹${v.totalPurchases.toLocaleString()}`,
        `₹${v.totalPayments.toLocaleString()}`,
        `₹${v.totalReturns.toLocaleString()}`,
        `₹${Number(v.outstanding).toLocaleString()}`,
      ]),
      foot: [[
        "TOTAL",
        `₹${summary.totalPurchases.toLocaleString()}`,
        `₹${summary.totalPayments.toLocaleString()}`,
        `₹${summary.totalReturns.toLocaleString()}`,
        `₹${summary.totalOutstanding.toLocaleString()}`,
      ]],
      styles: { fontSize: 9 },
      headStyles: { fillColor: [59, 130, 246] },
      footStyles: { fillColor: [229, 231, 235], textColor: [0, 0, 0], fontStyle: "bold" },
    });

    doc.save(`vendor-report-${format(dateRange.from, "yyyyMMdd")}-${format(dateRange.to, "yyyyMMdd")}.pdf`);
  };

  const exportExcel = () => {
    const ws = XLSX.utils.json_to_sheet(filteredVendors.map((v: any) => ({
      "Vendor ID": v.display_id,
      "Vendor Name": v.name,
      "Total Purchases": v.totalPurchases,
      "Total Payments": v.totalPayments,
      "Total Returns": v.totalReturns,
      "Outstanding": Number(v.outstanding),
      "Purchase Count": v.purchaseCount,
      "Status": v.is_active ? "Active" : "Inactive",
    })));
    const wb = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(wb, ws, "Vendor Report");
    XLSX.writeFile(wb, `vendor-report-${format(dateRange.from, "yyyyMMdd")}-${format(dateRange.to, "yyyyMMdd")}.xlsx`);
  };

  return (
    <div className="space-y-6">
      <div className="flex flex-col lg:flex-row lg:items-end gap-4">
        <ReportFilters dateRange={dateRange} onDateRangeChange={setDateRange} />
        <div className="relative flex-1 max-w-xs">
          <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-muted-foreground" />
          <Input
            placeholder="Search vendors..."
            value={search}
            onChange={(e) => setSearch(e.target.value)}
            className="pl-9"
          />
        </div>
      </div>

      <ReportExportBar onExportPDF={exportPDF} onExportExcel={exportExcel} />

      {isLoading ? (
        <div className="flex items-center justify-center py-12">
          <Loader2 className="h-8 w-8 animate-spin text-muted-foreground" />
        </div>
      ) : (
        <>
          <ReportSummaryCards cards={summaryCards} />

          {/* Charts */}
          <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
            {/* Top Vendors */}
            <Card>
              <CardHeader>
                <CardTitle className="text-base">Top Vendors by Purchase</CardTitle>
              </CardHeader>
              <CardContent>
                {topVendorsChart.length > 0 ? (
                  <ResponsiveContainer width="100%" height={300}>
                    <BarChart data={topVendorsChart} layout="vertical">
                      <CartesianGrid strokeDasharray="3 3" />
                      <XAxis type="number" tickFormatter={(v) => `₹${(v/1000).toFixed(0)}k`} />
                      <YAxis type="category" dataKey="name" width={100} tick={{ fontSize: 11 }} />
                      <Tooltip formatter={(v: number) => `₹${v.toLocaleString()}`} />
                      <Legend />
                      <Bar dataKey="purchases" name="Purchases" fill="#3b82f6" />
                      <Bar dataKey="payments" name="Payments" fill="#10b981" />
                    </BarChart>
                  </ResponsiveContainer>
                ) : (
                  <p className="text-center text-muted-foreground py-12">No data available</p>
                )}
              </CardContent>
            </Card>

            {/* Outstanding Distribution */}
            <Card>
              <CardHeader>
                <CardTitle className="text-base">Outstanding Distribution</CardTitle>
              </CardHeader>
              <CardContent>
                {outstandingChart.length > 0 ? (
                  <ResponsiveContainer width="100%" height={300}>
                    <PieChart>
                      <Pie
                        data={outstandingChart}
                        cx="50%"
                        cy="50%"
                        labelLine={false}
                        label={({ name, percent }) => `${name} (${(percent * 100).toFixed(0)}%)`}
                        outerRadius={100}
                        fill="#8884d8"
                        dataKey="value"
                      >
                        {outstandingChart.map((_, index) => (
                          <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} />
                        ))}
                      </Pie>
                      <Tooltip formatter={(v: number) => `₹${v.toLocaleString()}`} />
                    </PieChart>
                  </ResponsiveContainer>
                ) : (
                  <p className="text-center text-muted-foreground py-12">No outstanding balances</p>
                )}
              </CardContent>
            </Card>
          </div>

          {/* Vendor List */}
          <Card>
            <CardHeader>
              <CardTitle className="text-base">Vendor Details</CardTitle>
            </CardHeader>
            <CardContent>
              <div className="overflow-x-auto">
                <table className="w-full text-sm">
                  <thead>
                    <tr className="border-b bg-muted/50">
                      <th className="text-left p-3 font-medium">Vendor</th>
                      <th className="text-right p-3 font-medium">Purchases</th>
                      <th className="text-right p-3 font-medium">Payments</th>
                      <th className="text-right p-3 font-medium">Returns</th>
                      <th className="text-right p-3 font-medium">Outstanding</th>
                      <th className="text-center p-3 font-medium">Status</th>
                    </tr>
                  </thead>
                  <tbody>
                    {filteredVendors.map((v: any) => (
                      <tr key={v.id} className="border-b hover:bg-muted/30">
                        <td className="p-3">
                          <div>
                            <p className="font-medium">{v.name}</p>
                            <p className="text-xs text-muted-foreground">{v.display_id}</p>
                          </div>
                        </td>
                        <td className="p-3 text-right font-medium">₹{v.totalPurchases.toLocaleString()}</td>
                        <td className="p-3 text-right text-green-600">₹{v.totalPayments.toLocaleString()}</td>
                        <td className="p-3 text-right text-yellow-600">₹{v.totalReturns.toLocaleString()}</td>
                        <td className="p-3 text-right">
                          <span className={Number(v.outstanding) > 0 ? "text-red-600 font-semibold" : "text-muted-foreground"}>
                            ₹{Number(v.outstanding).toLocaleString()}
                          </span>
                        </td>
                        <td className="p-3 text-center">
                          <Badge variant={v.is_active ? "default" : "secondary"}>
                            {v.is_active ? "Active" : "Inactive"}
                          </Badge>
                        </td>
                      </tr>
                    ))}
                  </tbody>
                  <tfoot>
                    <tr className="bg-muted/50 font-semibold">
                      <td className="p-3">TOTAL ({filteredVendors.length} vendors)</td>
                      <td className="p-3 text-right">₹{summary.totalPurchases.toLocaleString()}</td>
                      <td className="p-3 text-right text-green-600">₹{summary.totalPayments.toLocaleString()}</td>
                      <td className="p-3 text-right text-yellow-600">₹{summary.totalReturns.toLocaleString()}</td>
                      <td className="p-3 text-right text-red-600">₹{summary.totalOutstanding.toLocaleString()}</td>
                      <td className="p-3"></td>
                    </tr>
                  </tfoot>
                </table>
              </div>
            </CardContent>
          </Card>
        </>
      )}
    </div>
  );
}

import { useCallback, useState } from "react";
import { useQuery } from "@tanstack/react-query";
import { Loader2 } from "lucide-react";
import { toast } from "sonner";
import { supabase } from "@/integrations/supabase/client";
import { Checkbox } from "@/components/ui/checkbox";
import { ScrollArea, ScrollBar } from "@/components/ui/scroll-area";

const STAFF_ROLES = ["manager", "agent", "marketer", "pos"] as const;

const ROLE_BADGE: Record<string, string> = {
  manager: "bg-purple-500/15 text-purple-600 dark:text-purple-400",
  agent: "bg-blue-500/15 text-blue-600 dark:text-blue-400",
  marketer: "bg-emerald-500/15 text-emerald-600 dark:text-emerald-400",
  pos: "bg-orange-500/15 text-orange-600 dark:text-orange-400",
};

export function RouteAccessMatrix() {
  const [toggling, setToggling] = useState<Set<string>>(new Set());

  const { data: routes, isLoading: loadingRoutes } = useQuery({
    queryKey: ["route-access-routes"],
    queryFn: async () => {
      const { data, error } = await supabase
        .from("routes")
        .select("id, name, store_type_id, store_types(name)")
        .eq("is_active", true)
        .order("name");
      if (error) throw error;
      return data || [];
    },
  });

  const { data: staffUsers, isLoading: loadingUsers } = useQuery({
    queryKey: ["route-access-staff-users"],
    queryFn: async () => {
      const { data: rolesData, error: rolesError } = await supabase
        .from("user_roles")
        .select("user_id, role")
        .in("role", [...STAFF_ROLES]);
      if (rolesError) throw rolesError;

      const userIds = rolesData?.map((row) => row.user_id) || [];
      if (userIds.length === 0) return [];

      const { data: profiles, error: profilesError } = await supabase
        .from("profiles")
        .select("user_id, full_name, is_active")
        .in("user_id", userIds)
        .eq("is_active", true)
        .order("full_name");
      if (profilesError) throw profilesError;

      const roleMap = new Map((rolesData || []).map((row) => [row.user_id, row.role]));
      return (profiles || []).map((profile) => ({
        ...profile,
        role: roleMap.get(profile.user_id) || "agent",
      }));
    },
  });

  const { data: accessRows, isLoading: loadingAccess, refetch: refetchAccess } = useQuery({
    queryKey: ["route-access-rows"],
    queryFn: async () => {
      const { data, error } = await supabase
        .from("agent_routes")
        .select("user_id, route_id, enabled");
      if (error) throw error;
      return data || [];
    },
  });

  const isLoading = loadingRoutes || loadingUsers || loadingAccess;

  const groupedRoutes = (() => {
    const groups: { id: string; name: string; routes: any[] }[] = [];
    const indexes = new Map<string, number>();
    (routes || []).forEach((route: any) => {
      const typeId = route.store_type_id || "unknown";
      const typeName = route.store_types?.name || "Other";
      if (!indexes.has(typeId)) {
        indexes.set(typeId, groups.length);
        groups.push({ id: typeId, name: typeName, routes: [] });
      }
      groups[indexes.get(typeId)!].routes.push(route);
    });
    return groups;
  })();

  const isEnabled = useCallback((userId: string, routeId: string) => {
    return (accessRows || []).some((row) => row.user_id === userId && row.route_id === routeId && row.enabled);
  }, [accessRows]);

  const handleToggle = async (userId: string, routeId: string) => {
    const key = `${userId}:${routeId}`;
    if (toggling.has(key)) return;

    setToggling((prev) => new Set(prev).add(key));
    const currentlyEnabled = isEnabled(userId, routeId);
    const { error } = await supabase
      .from("agent_routes")
      .upsert({ user_id: userId, route_id: routeId, enabled: !currentlyEnabled }, { onConflict: "user_id,route_id" });

    if (error) {
      toast.error(error.message);
    } else {
      await refetchAccess();
    }

    setToggling((prev) => {
      const next = new Set(prev);
      next.delete(key);
      return next;
    });
  };

  if (isLoading) {
    return (
      <div className="flex items-center justify-center py-16">
        <Loader2 className="h-7 w-7 animate-spin text-primary" />
      </div>
    );
  }

  if (!groupedRoutes.length) {
    return <div className="rounded-xl border bg-card p-8 text-sm text-center text-muted-foreground">No active routes found.</div>;
  }

  if (!staffUsers?.length) {
    return <div className="rounded-xl border bg-card p-8 text-sm text-center text-muted-foreground">No active staff users found.</div>;
  }

  return (
    <div className="space-y-3">
      <p className="text-sm text-muted-foreground">Grant or revoke route visibility per staff member. Changes apply immediately.</p>

      <ScrollArea className="rounded-xl border bg-card w-full">
        <div className="min-w-max">
          <table className="border-collapse text-sm w-full">
            <thead>
              <tr className="border-b bg-muted/40">
                <th rowSpan={2} className="sticky left-0 z-20 bg-muted/40 px-5 py-3 text-left text-xs font-semibold text-muted-foreground min-w-[200px] border-r">
                  Staff Member
                </th>
                {groupedRoutes.map((group, groupIndex) => (
                  <th key={group.id} colSpan={group.routes.length} className={`px-3 py-2.5 text-center text-xs font-semibold ${groupIndex < groupedRoutes.length - 1 ? "border-r" : ""}`}>
                    <span className="inline-flex items-center gap-1 rounded-md bg-primary/10 text-primary px-2.5 py-1 font-semibold">{group.name}</span>
                  </th>
                ))}
              </tr>
              <tr className="border-b bg-muted/20">
                {groupedRoutes.map((group, groupIndex) =>
                  group.routes.map((route: any, routeIndex: number) => (
                    <th
                      key={route.id}
                      className={`px-3 py-2 text-center text-[11px] font-medium text-muted-foreground min-w-[120px] whitespace-nowrap ${
                        routeIndex === group.routes.length - 1 && groupIndex < groupedRoutes.length - 1
                          ? "border-r"
                          : routeIndex < group.routes.length - 1
                          ? "border-r border-border/30"
                          : ""
                      }`}
                    >
                      {route.name}
                    </th>
                  ))
                )}
              </tr>
            </thead>

            <tbody>
              {staffUsers.map((staff: any, userIndex: number) => (
                <tr
                  key={staff.user_id}
                  className={`border-b last:border-0 hover:bg-accent/30 transition-colors ${userIndex % 2 === 1 ? "bg-muted/10" : ""}`}
                >
                  <td
                    className="sticky left-0 z-10 border-r px-5 py-3 min-w-[200px]"
                    style={{ background: userIndex % 2 === 1 ? "hsl(var(--muted) / 0.1)" : "hsl(var(--background))" }}
                  >
                    <div className="min-w-0">
                      <p className="text-sm font-medium leading-tight truncate max-w-[140px]">{staff.full_name || "—"}</p>
                      <span className={`mt-0.5 inline-block text-[10px] uppercase font-bold px-1.5 py-0.5 rounded leading-none ${ROLE_BADGE[staff.role] || ""}`}>
                        {staff.role}
                      </span>
                    </div>
                  </td>

                  {groupedRoutes.map((group, groupIndex) =>
                    group.routes.map((route: any, routeIndex: number) => {
                      const key = `${staff.user_id}:${route.id}`;
                      const busy = toggling.has(key);
                      return (
                        <td
                          key={route.id}
                          className={`px-3 py-3 text-center ${
                            routeIndex === group.routes.length - 1 && groupIndex < groupedRoutes.length - 1
                              ? "border-r"
                              : routeIndex < group.routes.length - 1
                              ? "border-r border-border/30"
                              : ""
                          }`}
                        >
                          <div className="flex items-center justify-center">
                            {busy ? (
                              <Loader2 className="h-3.5 w-3.5 animate-spin text-primary" />
                            ) : (
                              <Checkbox
                                checked={isEnabled(staff.user_id, route.id)}
                                onCheckedChange={() => handleToggle(staff.user_id, route.id)}
                                className="h-4 w-4 cursor-pointer"
                                aria-label={`${staff.full_name} access to ${route.name}`}
                              />
                            )}
                          </div>
                        </td>
                      );
                    })
                  )}
                </tr>
              ))}
            </tbody>
          </table>
        </div>
        <ScrollBar orientation="horizontal" />
      </ScrollArea>
    </div>
  );
}

import { useState, useMemo, useEffect, useRef } from "react";
import { useQuery, useQueryClient } from "@tanstack/react-query";
import { supabase } from "@/integrations/supabase/client";
import { getCurrentPosition } from "@/lib/proximity";
import { useAuth } from "@/contexts/AuthContext";
import { logActivity } from "@/lib/activityLogger";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import { Loader2, Play, Square, MapPin, CheckCircle2, Navigation, ShoppingCart, CircleDot } from "lucide-react";
import {
  Dialog, DialogContent, DialogHeader, DialogTitle,
} from "@/components/ui/dialog";
import {
  Select, SelectContent, SelectItem, SelectTrigger, SelectValue,
} from "@/components/ui/select";
import { Label } from "@/components/ui/label";
import { toast } from "sonner";

function haversineDistance(lat1: number, lng1: number, lat2: number, lng2: number) {
  const R = 6371000;
  const dLat = ((lat2 - lat1) * Math.PI) / 180;
  const dLng = ((lng2 - lng1) * Math.PI) / 180;
  const a = Math.sin(dLat / 2) ** 2 + Math.cos((lat1 * Math.PI) / 180) * Math.cos((lat2 * Math.PI) / 180) * Math.sin(dLng / 2) ** 2;
  return R * 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1 - a));
}

export function RouteSessionPanel() {
  const { user, role } = useAuth();
  const isScopedStaff = role === "agent" || role === "marketer" || role === "pos" || role === "manager";
  const qc = useQueryClient();
  const [showStart, setShowStart] = useState(false);
  const [selectedRoute, setSelectedRoute] = useState("");
  const [saving, setSaving] = useState(false);
  const [agentLocation, setAgentLocation] = useState<{ lat: number; lng: number } | null>(null);

  const { data: activeSession, isLoading: loadingSession } = useQuery({
    queryKey: ["active-route-session", user?.id],
    queryFn: async () => {
      const { data } = await (supabase as any)
        .from("route_sessions")
        .select("*, routes(name, stores(id, name, address, lat, lng, store_order))")
        .eq("user_id", user!.id)
        .eq("status", "active")
        .maybeSingle();
      return data;
    },
    enabled: !!user,
  });

  const { data: visits } = useQuery({
    queryKey: ["session-visits", activeSession?.id],
    queryFn: async () => {
      const { data } = await supabase
        .from("store_visits")
        .select("store_id")
        .eq("session_id", activeSession!.id);
      return new Set((data || []).map((v) => v.store_id));
    },
    enabled: !!activeSession,
  });

  // Check for pending orders on route stores
  const routeStores = (activeSession as any)?.routes?.stores || [];
  const storeIds = routeStores.map((s: any) => s.id);

  const { data: pendingOrderStores } = useQuery({
    queryKey: ["pending-order-stores", storeIds],
    queryFn: async () => {
      const { data } = await supabase
        .from("orders")
        .select("store_id")
        .in("store_id", storeIds)
        .eq("status", "pending");
      return new Set((data || []).map((o) => o.store_id));
    },
    enabled: storeIds.length > 0,
  });

  const { data: routes } = useQuery({
    queryKey: ["routes-list-active", user?.id, role],
    queryFn: async () => {
      const { data, error } = await supabase.from("routes").select("id, name").eq("is_active", true);
      if (error) throw error;

      const allRoutes = data || [];
      if (!user?.id || !isScopedStaff) return allRoutes;

      const { data: accessRows, error: accessError } = await supabase
        .from("agent_routes")
        .select("route_id, enabled")
        .eq("user_id", user.id);
      if (accessError) throw accessError;

      if (!accessRows || accessRows.length === 0) return allRoutes;

      const enabledRouteIds = new Set(
        accessRows.filter((row: any) => row.enabled).map((row: any) => row.route_id)
      );
      return allRoutes.filter((route: any) => enabledRouteIds.has(route.id));
    },
    enabled: !!user,
  });

  // Continuously track agent location during an active session and push to DB
  const locationWatchRef = useRef<number | null>(null);
  const lastPushRef = useRef<number>(0);
  useEffect(() => {
    if (!activeSession || !navigator.geolocation) return;

    const pushLocation = async (lat: number, lng: number) => {
      setAgentLocation({ lat, lng });
      const now = Date.now();
      // Throttle DB writes to at most once per 15 seconds
      if (now - lastPushRef.current < 15000) return;
      lastPushRef.current = now;
      await (supabase as any).from("route_sessions").update({
        current_lat: lat,
        current_lng: lng,
        location_updated_at: new Date().toISOString(),
      }).eq("id", activeSession.id);
    };

    locationWatchRef.current = navigator.geolocation.watchPosition(
      (pos) => pushLocation(pos.coords.latitude, pos.coords.longitude),
      () => {},
      { enableHighAccuracy: true, maximumAge: 30000, timeout: 10000 }
    );

    return () => {
      if (locationWatchRef.current !== null) {
        navigator.geolocation.clearWatch(locationWatchRef.current);
        locationWatchRef.current = null;
      }
    };
  }, [activeSession?.id]);

  // Sort stores: unvisited first, then by pre-computed store_order (optimal route),
  // falling back to live distance from agent if no order set.
  const sortedStores = useMemo(() => {
    const stores = [...routeStores];
    stores.sort((a: any, b: any) => {
      const aVisited = visits?.has(a.id) ? 1 : 0;
      const bVisited = visits?.has(b.id) ? 1 : 0;
      if (aVisited !== bVisited) return aVisited - bVisited;
      // Primary: pre-computed optimal order
      if (a.store_order != null && b.store_order != null) return a.store_order - b.store_order;
      if (a.store_order != null) return -1;
      if (b.store_order != null) return 1;
      // Fallback: live distance from agent
      if (agentLocation && a.lat && a.lng && b.lat && b.lng) {
        const distA = haversineDistance(agentLocation.lat, agentLocation.lng, a.lat, a.lng);
        const distB = haversineDistance(agentLocation.lat, agentLocation.lng, b.lat, b.lng);
        return distA - distB;
      }
      return 0;
    });
    return stores;
  }, [routeStores, visits, agentLocation]);

  const nextStore = sortedStores.find((s: any) => !visits?.has(s.id));

  const handleStart = async () => {
    if (!selectedRoute) { toast.error("Select a route"); return; }
    setSaving(true);
    const loc = await getCurrentPosition();
    const { error } = await supabase.from("route_sessions").insert({
      user_id: user!.id,
      route_id: selectedRoute,
      start_lat: loc?.lat || null,
      start_lng: loc?.lng || null,
    });
    setSaving(false);
    if (error) toast.error(error.message);
    else {
      toast.success("Route session started!");
      setShowStart(false);
      setSelectedRoute("");
      qc.invalidateQueries({ queryKey: ["active-route-session"] });
      logActivity(user!.id, "Started route session", "route_session");
    }
  };

  const handleEnd = async () => {
    if (!activeSession) return;
    setSaving(true);
    const loc = await getCurrentPosition();
    await supabase.from("route_sessions").update({
      status: "completed",
      ended_at: new Date().toISOString(),
      end_lat: loc?.lat || null,
      end_lng: loc?.lng || null,
    }).eq("id", activeSession.id);
    setSaving(false);
    toast.success("Route session ended");
    qc.invalidateQueries({ queryKey: ["active-route-session"] });
    logActivity(user!.id, "Ended route session", "route_session");
  };

  const handleVisit = async (storeId: string) => {
    if (!activeSession) return;
    const store = routeStores.find((s: any) => s.id === storeId);
    // Proximity check
    if (store?.lat && store?.lng) {
      const { checkProximity } = await import("@/lib/proximity");
      const result = await checkProximity(store.lat, store.lng);
      if (!result.withinRange) {
        toast.error(result.message);
        return;
      }
    }
    const loc = await getCurrentPosition();
    const { error } = await supabase.from("store_visits").insert({
      session_id: activeSession.id,
      store_id: storeId,
      lat: loc?.lat || null,
      lng: loc?.lng || null,
    });
    if (error) toast.error(error.message);
    else {
      toast.success("Store marked as visited");
      qc.invalidateQueries({ queryKey: ["session-visits"] });
    }
  };

  const openDirections = (store: any) => {
    if (store.lat && store.lng) {
      window.open(`https://www.google.com/maps/dir/?api=1&destination=${store.lat},${store.lng}`, "_blank");
    } else if (store.address) {
      window.open(`https://www.google.com/maps/dir/?api=1&destination=${encodeURIComponent(store.address)}`, "_blank");
    }
  };

  if (loadingSession) return null;

  const visitedCount = routeStores.filter((s: any) => visits?.has(s.id)).length;

  return (
    <>
      {activeSession ? (
        <div className="rounded-xl border bg-card p-5 space-y-4">
          <div className="flex items-center justify-between">
            <div className="flex items-center gap-3">
              <div className="h-3 w-3 rounded-full bg-green-500 animate-pulse" />
              <div>
                <p className="font-semibold">Active Session: {(activeSession as any)?.routes?.name}</p>
                <p className="text-xs text-muted-foreground">
                  Started {new Date(activeSession.started_at).toLocaleTimeString("en-IN")} · {visitedCount}/{routeStores.length} visited
                </p>
              </div>
            </div>
            <Button variant="destructive" size="sm" onClick={handleEnd} disabled={saving}>
              {saving ? <Loader2 className="mr-2 h-4 w-4 animate-spin" /> : <Square className="mr-2 h-4 w-4" />}
              End Session
            </Button>
          </div>

          {/* Next nearest store highlight */}
          {nextStore && (
            <div className="rounded-lg border-2 border-primary/30 bg-primary/5 p-3 flex items-center justify-between">
              <div className="flex items-center gap-2">
                <Navigation className="h-4 w-4 text-primary" />
                <div>
                  <p className="text-sm font-semibold text-primary">Next: {nextStore.name}</p>
                  <p className="text-xs text-muted-foreground">
                    {nextStore.address || "No address"}
                    {agentLocation && nextStore.lat && nextStore.lng && (
                      <> · {(haversineDistance(agentLocation.lat, agentLocation.lng, nextStore.lat, nextStore.lng) / 1000).toFixed(1)} km away</>
                    )}
                  </p>
                </div>
              </div>
              <Button size="sm" variant="outline" onClick={() => openDirections(nextStore)}>
                <Navigation className="mr-1 h-3 w-3" />Directions
              </Button>
            </div>
          )}

          <div className="space-y-2">
            <p className="text-sm font-medium text-muted-foreground">Stores on route ({routeStores.length})</p>
            {sortedStores.map((store: any) => {
              const visited = visits?.has(store.id);
              const hasOrder = pendingOrderStores?.has(store.id);
              const isNext = nextStore?.id === store.id;
              return (
                <div key={store.id} className={`flex items-center justify-between rounded-lg border p-3 ${isNext ? "border-primary/30 bg-primary/5" : ""}`}>
                  <div className="flex items-center gap-2">
                    {visited ? (
                      <CheckCircle2 className="h-4 w-4 text-green-500" />
                    ) : (
                      <MapPin className="h-4 w-4 text-muted-foreground" />
                    )}
                    <div>
                      <div className="flex items-center gap-1.5">
                        <p className="text-sm font-medium">{store.name}</p>
                        {/* Colored badges */}
                        {!visited && activeSession && (
                          <span className="h-2.5 w-2.5 rounded-full bg-blue-500 inline-block" />
                        )}
                        {hasOrder && (
                          <span className="h-2.5 w-2.5 rounded-full bg-green-500 inline-block" />
                        )}
                      </div>
                      <p className="text-xs text-muted-foreground">
                        {store.address || "No address"}
                        {agentLocation && store.lat && store.lng && (
                          <> · {(haversineDistance(agentLocation.lat, agentLocation.lng, store.lat, store.lng) / 1000).toFixed(1)} km</>
                        )}
                      </p>
                    </div>
                  </div>
                  <div className="flex items-center gap-1.5">
                    {(store.lat || store.address) && (
                      <Button size="sm" variant="ghost" className="h-7 w-7 p-0" onClick={() => openDirections(store)} title="Get directions">
                        <Navigation className="h-3.5 w-3.5" />
                      </Button>
                    )}
                    {!visited && (
                      <Button size="sm" variant="outline" onClick={() => handleVisit(store.id)}>
                        Mark Visited
                      </Button>
                    )}
                    {visited && <Badge variant="secondary">Visited</Badge>}
                  </div>
                </div>
              );
            })}
          </div>
        </div>
      ) : (
        <Button onClick={() => setShowStart(true)}>
          <Play className="mr-2 h-4 w-4" />Start Route Session
        </Button>
      )}

      <Dialog open={showStart} onOpenChange={setShowStart}>
        <DialogContent>
          <DialogHeader><DialogTitle>Start Route Session</DialogTitle></DialogHeader>
          <div className="space-y-4">
            <div>
              <Label>Select Route</Label>
              <Select value={selectedRoute} onValueChange={setSelectedRoute}>
                <SelectTrigger className="mt-1"><SelectValue placeholder="Choose route" /></SelectTrigger>
                <SelectContent>
                  {routes?.map((r) => <SelectItem key={r.id} value={r.id}>{r.name}</SelectItem>)}
                </SelectContent>
              </Select>
            </div>
            <Button onClick={handleStart} className="w-full" disabled={saving}>
              {saving ? <Loader2 className="mr-2 h-4 w-4 animate-spin" /> : <Play className="mr-2 h-4 w-4" />}
              Start Session
            </Button>
          </div>
        </DialogContent>
      </Dialog>
    </>
  );
}

import { useState } from "react";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import {
  Select, SelectContent, SelectItem, SelectTrigger, SelectValue,
} from "@/components/ui/select";
import {
  Popover, PopoverContent, PopoverTrigger,
} from "@/components/ui/popover";
import { Calendar } from "@/components/ui/calendar";
import { cn } from "@/lib/utils";
import { Filter, X, CalendarIcon } from "lucide-react";
import { format } from "date-fns";

export interface FilterConfig {
  dateRange?: boolean;
  outstandingRange?: boolean;
  storeType?: { options: { id: string; name: string }[] };
  route?: { options: { id: string; name: string }[] };
  kycStatus?: boolean;
  status?: boolean;
}

export interface FilterValues {
  dateFrom?: Date;
  dateTo?: Date;
  outstandingMin?: string;
  outstandingMax?: string;
  storeTypeId?: string;
  routeId?: string;
  kycStatus?: string;
  status?: string;
}

interface Props {
  config: FilterConfig;
  values: FilterValues;
  onChange: (values: FilterValues) => void;
}

export function AdvancedFilters({ config, values, onChange }: Props) {
  const [open, setOpen] = useState(false);

  const activeCount = Object.values(values).filter((v) => v !== undefined && v !== "").length;

  const clear = () => onChange({});

  const set = (key: keyof FilterValues, value: any) => {
    onChange({ ...values, [key]: value || undefined });
  };

  return (
    <Popover open={open} onOpenChange={setOpen}>
      <PopoverTrigger asChild>
        <Button variant="outline" size="sm" className="gap-1.5">
          <Filter className="h-3.5 w-3.5" />
          Filters
          {activeCount > 0 && (
            <span className="ml-1 rounded-full bg-primary text-primary-foreground text-[10px] h-4 w-4 flex items-center justify-center">
              {activeCount}
            </span>
          )}
        </Button>
      </PopoverTrigger>
      <PopoverContent className="w-80 p-4 space-y-4" align="end">
        <div className="flex items-center justify-between">
          <p className="text-sm font-semibold">Filters</p>
          {activeCount > 0 && (
            <Button variant="ghost" size="sm" className="h-7 text-xs" onClick={clear}>
              <X className="h-3 w-3 mr-1" />Clear all
            </Button>
          )}
        </div>

        {config.dateRange && (
          <div className="space-y-2">
            <Label className="text-xs">Date Range</Label>
            <div className="flex gap-2">
              <Popover>
                <PopoverTrigger asChild>
                  <Button variant="outline" size="sm" className={cn("flex-1 justify-start text-left text-xs", !values.dateFrom && "text-muted-foreground")}>
                    <CalendarIcon className="mr-1 h-3 w-3" />
                    {values.dateFrom ? format(values.dateFrom, "dd MMM yy") : "From"}
                  </Button>
                </PopoverTrigger>
                <PopoverContent className="w-auto p-0" align="start">
                  <Calendar mode="single" selected={values.dateFrom} onSelect={(d) => set("dateFrom", d)} className="p-3 pointer-events-auto" />
                </PopoverContent>
              </Popover>
              <Popover>
                <PopoverTrigger asChild>
                  <Button variant="outline" size="sm" className={cn("flex-1 justify-start text-left text-xs", !values.dateTo && "text-muted-foreground")}>
                    <CalendarIcon className="mr-1 h-3 w-3" />
                    {values.dateTo ? format(values.dateTo, "dd MMM yy") : "To"}
                  </Button>
                </PopoverTrigger>
                <PopoverContent className="w-auto p-0" align="start">
                  <Calendar mode="single" selected={values.dateTo} onSelect={(d) => set("dateTo", d)} className="p-3 pointer-events-auto" />
                </PopoverContent>
              </Popover>
            </div>
          </div>
        )}

        {config.outstandingRange && (
          <div className="space-y-2">
            <Label className="text-xs">Outstanding Range (₹)</Label>
            <div className="flex gap-2">
              <Input type="number" placeholder="Min" className="h-8 text-xs" value={values.outstandingMin || ""} onChange={(e) => set("outstandingMin", e.target.value)} />
              <Input type="number" placeholder="Max" className="h-8 text-xs" value={values.outstandingMax || ""} onChange={(e) => set("outstandingMax", e.target.value)} />
            </div>
          </div>
        )}

        {config.storeType && (
          <div className="space-y-2">
            <Label className="text-xs">Store Type</Label>
            <Select value={values.storeTypeId || ""} onValueChange={(v) => set("storeTypeId", v === "all" ? "" : v)}>
              <SelectTrigger className="h-8 text-xs"><SelectValue placeholder="All types" /></SelectTrigger>
              <SelectContent>
                <SelectItem value="all">All types</SelectItem>
                {config.storeType.options.map((t) => <SelectItem key={t.id} value={t.id}>{t.name}</SelectItem>)}
              </SelectContent>
            </Select>
          </div>
        )}

        {config.route && (
          <div className="space-y-2">
            <Label className="text-xs">Route</Label>
            <Select value={values.routeId || ""} onValueChange={(v) => set("routeId", v === "all" ? "" : v)}>
              <SelectTrigger className="h-8 text-xs"><SelectValue placeholder="All routes" /></SelectTrigger>
              <SelectContent>
                <SelectItem value="all">All routes</SelectItem>
                {config.route.options.map((r) => <SelectItem key={r.id} value={r.id}>{r.name}</SelectItem>)}
              </SelectContent>
            </Select>
          </div>
        )}

        {config.kycStatus && (
          <div className="space-y-2">
            <Label className="text-xs">KYC Status</Label>
            <Select value={values.kycStatus || ""} onValueChange={(v) => set("kycStatus", v === "all" ? "" : v)}>
              <SelectTrigger className="h-8 text-xs"><SelectValue placeholder="All statuses" /></SelectTrigger>
              <SelectContent>
                <SelectItem value="all">All</SelectItem>
                <SelectItem value="not_requested">Not Requested</SelectItem>
                <SelectItem value="pending">Pending</SelectItem>
                <SelectItem value="verified">Verified</SelectItem>
                <SelectItem value="rejected">Rejected</SelectItem>
              </SelectContent>
            </Select>
          </div>
        )}

        {config.status && (
          <div className="space-y-2">
            <Label className="text-xs">Status</Label>
            <Select value={values.status || ""} onValueChange={(v) => set("status", v === "all" ? "" : v)}>
              <SelectTrigger className="h-8 text-xs"><SelectValue placeholder="All" /></SelectTrigger>
              <SelectContent>
                <SelectItem value="all">All</SelectItem>
                <SelectItem value="active">Active</SelectItem>
                <SelectItem value="inactive">Inactive</SelectItem>
              </SelectContent>
            </Select>
          </div>
        )}
      </PopoverContent>
    </Popover>
  );
}

// Helper to apply filters to data arrays
export function applyFilters<T extends Record<string, any>>(
  data: T[],
  filters: FilterValues,
  fieldMap: {
    dateField?: string;
    outstandingField?: string;
    storeTypeField?: string;
    routeField?: string;
    kycField?: string;
    statusField?: string;
  }
): T[] {
  return data.filter((item) => {
    if (filters.dateFrom && fieldMap.dateField) {
      const d = new Date(item[fieldMap.dateField]);
      if (d < filters.dateFrom) return false;
    }
    if (filters.dateTo && fieldMap.dateField) {
      const d = new Date(item[fieldMap.dateField]);
      const to = new Date(filters.dateTo);
      to.setHours(23, 59, 59, 999);
      if (d > to) return false;
    }
    if (filters.outstandingMin && fieldMap.outstandingField) {
      if (Number(item[fieldMap.outstandingField]) < Number(filters.outstandingMin)) return false;
    }
    if (filters.outstandingMax && fieldMap.outstandingField) {
      if (Number(item[fieldMap.outstandingField]) > Number(filters.outstandingMax)) return false;
    }
    if (filters.storeTypeId && fieldMap.storeTypeField) {
      if (item[fieldMap.storeTypeField] !== filters.storeTypeId) return false;
    }
    if (filters.routeId && fieldMap.routeField) {
      if (item[fieldMap.routeField] !== filters.routeId) return false;
    }
    if (filters.kycStatus && fieldMap.kycField) {
      if (item[fieldMap.kycField] !== filters.kycStatus) return false;
    }
    if (filters.status && fieldMap.statusField) {
      const isActive = item[fieldMap.statusField];
      if (filters.status === "active" && !isActive) return false;
      if (filters.status === "inactive" && isActive) return false;
    }
    return true;
  });
}

import { useState, useRef } from "react";
import {
  Dialog, DialogContent, DialogHeader, DialogTitle, DialogDescription,
} from "@/components/ui/dialog";
import { Button } from "@/components/ui/button";
import { Upload, FileText, AlertCircle, CheckCircle2, Download } from "lucide-react";
import { ScrollArea } from "@/components/ui/scroll-area";
import { toast } from "sonner";

interface CsvField {
  key: string;
  label: string;
  required?: boolean;
}

interface CsvImportDialogProps {
  open: boolean;
  onOpenChange: (open: boolean) => void;
  fields: CsvField[];
  onImport: (rows: Record<string, string>[]) => Promise<{ success: number; errors: string[] }>;
  templateName: string;
}

function parseCsv(text: string): { headers: string[]; rows: string[][] } {
  const lines = text.split(/\r?\n/).filter((l) => l.trim());
  if (lines.length === 0) return { headers: [], rows: [] };
  const headers = lines[0].split(",").map((h) => h.trim().toLowerCase().replace(/\s+/g, "_"));
  const rows = lines.slice(1).map((line) => {
    const values: string[] = [];
    let current = "";
    let inQuotes = false;
    for (const char of line) {
      if (char === '"') { inQuotes = !inQuotes; }
      else if (char === "," && !inQuotes) { values.push(current.trim()); current = ""; }
      else { current += char; }
    }
    values.push(current.trim());
    return values;
  });
  return { headers, rows };
}

export function CsvImportDialog({ open, onOpenChange, fields, onImport, templateName }: CsvImportDialogProps) {
  const [parsed, setParsed] = useState<Record<string, string>[] | null>(null);
  const [errors, setErrors] = useState<string[]>([]);
  const [importing, setImporting] = useState(false);
  const [result, setResult] = useState<{ success: number; errors: string[] } | null>(null);
  const fileRef = useRef<HTMLInputElement>(null);

  const handleFile = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    setResult(null);
    const reader = new FileReader();
    reader.onload = (ev) => {
      const text = ev.target?.result as string;
      const { headers, rows } = parseCsv(text);
      const fieldKeys = fields.map((f) => f.key);
      const errs: string[] = [];

      // Check required headers
      const requiredFields = fields.filter((f) => f.required);
      requiredFields.forEach((f) => {
        if (!headers.includes(f.key)) {
          errs.push(`Missing required column: "${f.label}" (expected header: ${f.key})`);
        }
      });

      if (errs.length > 0) {
        setErrors(errs);
        setParsed(null);
        return;
      }

      const mapped = rows.map((row, i) => {
        const obj: Record<string, string> = {};
        headers.forEach((h, j) => {
          if (fieldKeys.includes(h)) {
            obj[h] = row[j] || "";
          }
        });
        // Validate required fields per row
        requiredFields.forEach((f) => {
          if (!obj[f.key]?.trim()) {
            errs.push(`Row ${i + 2}: "${f.label}" is empty`);
          }
        });
        return obj;
      });

      setErrors(errs);
      setParsed(errs.length === 0 ? mapped : null);
    };
    reader.readAsText(file);
  };

  const handleImport = async () => {
    if (!parsed) return;
    setImporting(true);
    try {
      const res = await onImport(parsed);
      setResult(res);
      if (res.success > 0) {
        toast.success(`${res.success} records imported successfully`);
      }
    } catch (err: any) {
      toast.error(err.message || "Import failed");
    }
    setImporting(false);
  };

  const downloadTemplate = () => {
    const csv = fields.map((f) => f.key).join(",") + "\n";
    const blob = new Blob([csv], { type: "text/csv" });
    const url = URL.createObjectURL(blob);
    const a = document.createElement("a");
    a.href = url;
    a.download = `${templateName}_template.csv`;
    a.click();
    URL.revokeObjectURL(url);
  };

  const handleClose = (open: boolean) => {
    if (!open) {
      setParsed(null);
      setErrors([]);
      setResult(null);
    }
    onOpenChange(open);
  };

  return (
    <Dialog open={open} onOpenChange={handleClose}>
      <DialogContent className="sm:max-w-lg">
        <DialogHeader>
          <DialogTitle>Import from CSV</DialogTitle>
          <DialogDescription>Upload a CSV file with the required columns.</DialogDescription>
        </DialogHeader>

        <div className="space-y-4">
          <Button variant="outline" size="sm" onClick={downloadTemplate}>
            <Download className="mr-2 h-4 w-4" /> Download Template
          </Button>

          <div className="text-xs text-muted-foreground">
            <p className="font-medium mb-1">Expected columns:</p>
            <div className="flex flex-wrap gap-1">
              {fields.map((f) => (
                <span key={f.key} className={`px-2 py-0.5 rounded-md border text-xs ${f.required ? "bg-primary/10 border-primary/30 font-medium" : "bg-muted"}`}>
                  {f.key}{f.required ? " *" : ""}
                </span>
              ))}
            </div>
          </div>

          <div
            className="flex flex-col items-center gap-3 rounded-xl border-2 border-dashed border-muted-foreground/25 p-6 cursor-pointer hover:border-primary/50 transition-colors"
            onClick={() => fileRef.current?.click()}
          >
            <Upload className="h-8 w-8 text-muted-foreground" />
            <p className="text-sm text-muted-foreground">Click to select a CSV file</p>
            <input ref={fileRef} type="file" accept=".csv" className="hidden" onChange={handleFile} />
          </div>

          {errors.length > 0 && (
            <ScrollArea className="max-h-40">
              <div className="space-y-1 rounded-lg bg-destructive/10 p-3">
                {errors.map((e, i) => (
                  <p key={i} className="text-xs text-destructive flex items-start gap-1.5">
                    <AlertCircle className="h-3.5 w-3.5 mt-0.5 shrink-0" />{e}
                  </p>
                ))}
              </div>
            </ScrollArea>
          )}

          {parsed && !result && (
            <div className="rounded-lg bg-accent/50 p-3">
              <p className="text-sm font-medium flex items-center gap-2">
                <FileText className="h-4 w-4" /> {parsed.length} rows ready to import
              </p>
            </div>
          )}

          {result && (
            <div className="rounded-lg bg-accent/50 p-3 space-y-2">
              <p className="text-sm font-medium flex items-center gap-2">
                <CheckCircle2 className="h-4 w-4 text-green-500" /> {result.success} imported
              </p>
              {result.errors.length > 0 && (
                <ScrollArea className="max-h-32">
                  {result.errors.map((e, i) => (
                    <p key={i} className="text-xs text-destructive">{e}</p>
                  ))}
                </ScrollArea>
              )}
            </div>
          )}

          {parsed && !result && (
            <Button onClick={handleImport} disabled={importing} className="w-full">
              {importing ? "Importing..." : `Import ${parsed.length} Records`}
            </Button>
          )}
        </div>
      </DialogContent>
    </Dialog>
  );
}

import {
  Table,
  TableBody,
  TableCell,
  TableHead,
  TableHeader,
  TableRow,
} from "@/components/ui/table";
import { Input } from "@/components/ui/input";
import { Button } from "@/components/ui/button";
import { Search, ChevronLeft, ChevronRight } from "lucide-react";
import { useState } from "react";
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select";
import { cn } from "@/lib/utils";

interface Column<T> {
  header: string | (() => React.ReactNode);
  accessor: keyof T | ((row: T) => React.ReactNode);
  className?: string;
  /** Label used in mobile card view. Defaults to header string. */
  mobileLabel?: string;
  /** Hide this column entirely on mobile card view */
  hideOnMobile?: boolean;
}

interface DataTableProps<T> {
  columns: Column<T>[];
  data: T[];
  searchPlaceholder?: string;
  searchKey?: keyof T;
  onRowClick?: (row: T) => void;
  pageSize?: number;
  /** Custom mobile card renderer. When provided, replaces the default grid card. */
  renderMobileCard?: (row: T, index: number) => React.ReactNode;
  /** Message shown when there are no rows. Defaults to "No results found." */
  emptyMessage?: string;
}

export function DataTable<T extends Record<string, any>>({
  columns,
  data,
  searchPlaceholder = "Search...",
  searchKey,
  onRowClick,
  pageSize: defaultPageSize = 10,
  renderMobileCard,
  emptyMessage,
}: DataTableProps<T>) {
  const [search, setSearch] = useState("");
  const [page, setPage] = useState(0);
  const [pageSize, setPageSize] = useState(defaultPageSize);
  const resolvedEmptyMessage = emptyMessage ?? "No results found.";

  const filtered = searchKey
    ? data.filter((row) =>
        String(row[searchKey]).toLowerCase().includes(search.toLowerCase())
      )
    : data;

  const totalPages = Math.max(1, Math.ceil(filtered.length / pageSize));
  const safeP = Math.min(page, totalPages - 1);
  const paged = filtered.slice(safeP * pageSize, (safeP + 1) * pageSize);

  const handleSearch = (val: string) => {
    setSearch(val);
    setPage(0);
  };

  const getHeaderText = (col: Column<T>): string => {
    if (col.mobileLabel) return col.mobileLabel;
    if (typeof col.header === "string") return col.header;
    return "";
  };

  const getCellValue = (col: Column<T>, row: T): React.ReactNode => {
    if (typeof col.accessor === "function") return col.accessor(row);
    return row[col.accessor] as React.ReactNode;
  };

  return (
    <div className="space-y-4">
      {searchKey && (
        <div className="relative max-w-sm">
          <Search className="absolute left-3 top-1/2 h-4 w-4 -translate-y-1/2 text-muted-foreground" />
          <Input
            placeholder={searchPlaceholder}
            value={search}
            onChange={(e) => handleSearch(e.target.value)}
            className="pl-9"
          />
        </div>
      )}

      {/* Desktop table view */}
      <div className="rounded-xl border bg-card overflow-x-auto -mx-3 sm:mx-0 hidden md:block">
        <Table>
          <TableHeader>
            <TableRow className="bg-muted/30 hover:bg-muted/30 border-b border-border/50">
              {columns.map((col, i) => (
                <TableHead key={i} className={cn("text-[10px] uppercase tracking-wider font-bold text-muted-foreground py-3 h-auto", col.className)}>
                  {typeof col.header === "function" ? col.header() : col.header}
                </TableHead>
              ))}
            </TableRow>
          </TableHeader>
          <TableBody>
            {paged.length === 0 ? (
              <TableRow>
                <TableCell colSpan={columns.length} className="h-48 text-center">
                  <div className="flex flex-col items-center justify-center gap-2">
                    <div className="rounded-full bg-muted/50 p-3">
                      <Search className="h-6 w-6 text-muted-foreground/40" />
                    </div>
                    <p className="text-sm font-medium text-muted-foreground">{resolvedEmptyMessage}</p>
                  </div>
                </TableCell>
              </TableRow>
            ) : (
              paged.map((row, i) => (
                <TableRow key={i} className={`group hover:bg-muted/30 ${onRowClick ? "cursor-pointer" : ""}`} onClick={() => onRowClick?.(row)}>
                  {columns.map((col, j) => (
                    <TableCell key={j} className={col.className}>
                      {getCellValue(col, row)}
                    </TableCell>
                  ))}
                </TableRow>
              ))
            )}
          </TableBody>
        </Table>
      </div>

      {/* Mobile card view */}
      <div className="md:hidden space-y-3">
        {paged.length === 0 ? (
          <div className="rounded-xl border bg-card p-8 text-center">
            <p className="text-sm text-muted-foreground">{resolvedEmptyMessage}</p>
          </div>
        ) : renderMobileCard ? (
          paged.map((row, i) => (
            <div
              key={i}
              className={onRowClick ? "cursor-pointer" : ""}
              onClick={() => onRowClick?.(row)}
            >
              {renderMobileCard(row, i)}
            </div>
          ))
        ) : (
          paged.map((row, i) => (
            <div
              key={i}
              className={`rounded-xl border bg-card p-4 ${onRowClick ? "cursor-pointer active:bg-muted/30" : ""}`}
              onClick={() => onRowClick?.(row)}
            >
              <div className="grid grid-cols-2 gap-x-4 gap-y-2">
                {columns
                  .filter((col) => !col.hideOnMobile)
                  .map((col, j) => {
                    const label = getHeaderText(col);
                    const value = getCellValue(col, row);
                    if (!label) {
                      return (
                        <div key={j} className="col-span-2 flex items-center">
                          {value}
                        </div>
                      );
                    }
                    return (
                      <div key={j} className="min-w-0">
                        <p className="text-[11px] text-muted-foreground truncate">{label}</p>
                        <div className="text-sm font-medium truncate">{value}</div>
                      </div>
                    );
                  })}
              </div>
            </div>
          ))
        )}
      </div>

      {/* Pagination */}
      {filtered.length > 0 && (
        <div className="flex items-center justify-between gap-2 text-sm text-muted-foreground">
          <div className="flex items-center gap-2">
            <span>Rows per page</span>
            <Select value={String(pageSize)} onValueChange={(v) => { setPageSize(Number(v)); setPage(0); }}>
              <SelectTrigger className="h-8 w-[70px]">
                <SelectValue />
              </SelectTrigger>
              <SelectContent>
                {[10, 25, 50, 100].map((s) => (
                  <SelectItem key={s} value={String(s)}>{s}</SelectItem>
                ))}
              </SelectContent>
            </Select>
          </div>
          <div className="flex items-center gap-2">
            <span>{safeP * pageSize + 1}–{Math.min((safeP + 1) * pageSize, filtered.length)} of {filtered.length}</span>
            <Button variant="outline" size="icon" className="h-8 w-8" disabled={safeP === 0} onClick={() => setPage(safeP - 1)}>
              <ChevronLeft className="h-4 w-4" />
            </Button>
            <Button variant="outline" size="icon" className="h-8 w-8" disabled={safeP >= totalPages - 1} onClick={() => setPage(safeP + 1)}>
              <ChevronRight className="h-4 w-4" />
            </Button>
          </div>
        </div>
      )}
    </div>
  );
}

import { useEffect, useState } from "react";
import { useNavigate } from "react-router-dom";
import { supabase } from "@/integrations/supabase/client";
import {
  CommandDialog,
  CommandInput,
  CommandList,
  CommandEmpty,
  CommandGroup,
  CommandItem,
} from "@/components/ui/command";
import { Users, Store, Package, ShoppingCart, Receipt } from "lucide-react";

interface SearchResult {
  id: string;
  label: string;
  sub: string;
  path: string;
  type: "customer" | "store" | "product" | "sale" | "order";
}

const typeIcons = {
  customer: Users,
  store: Store,
  product: Package,
  sale: ShoppingCart,
  order: Receipt,
};

export function GlobalSearch() {
  const [open, setOpen] = useState(false);
  const [query, setQuery] = useState("");
  const [results, setResults] = useState<SearchResult[]>([]);
  const [searching, setSearching] = useState(false);
  const navigate = useNavigate();

  // Cmd+K shortcut
  useEffect(() => {
    const down = (e: KeyboardEvent) => {
      if (e.key === "k" && (e.metaKey || e.ctrlKey)) {
        e.preventDefault();
        setOpen((o) => !o);
      }
    };
    document.addEventListener("keydown", down);
    return () => document.removeEventListener("keydown", down);
  }, []);

  // Search on query change
  useEffect(() => {
    if (!query || query.length < 2) {
      setResults([]);
      return;
    }
    const timer = setTimeout(async () => {
      setSearching(true);
      const q = `%${query}%`;
      const [custRes, storeRes, prodRes, orderRes] = await Promise.all([
        supabase.from("customers").select("id, name, display_id, phone").ilike("name", q).limit(5),
        supabase.from("stores").select("id, name, display_id, address").ilike("name", q).limit(5),
        supabase.from("products").select("id, name, sku, category").ilike("name", q).limit(5),
        supabase.from("orders").select("id, display_id, status, stores(name)").ilike("display_id", q).limit(5),
      ]);

      const items: SearchResult[] = [];
      (custRes.data || []).forEach((c) =>
        items.push({ id: c.id, label: c.name, sub: c.display_id, path: `/customers/${c.id}`, type: "customer" })
      );
      (storeRes.data || []).forEach((s) =>
        items.push({ id: s.id, label: s.name, sub: s.display_id, path: `/stores/${s.id}`, type: "store" })
      );
      (prodRes.data || []).forEach((p) =>
        items.push({ id: p.id, label: p.name, sub: p.sku, path: `/products`, type: "product" })
      );
      (orderRes.data || []).forEach((o: any) =>
        items.push({ id: o.id, label: o.display_id, sub: o.stores?.name || o.status, path: `/orders`, type: "order" })
      );

      setResults(items);
      setSearching(false);
    }, 300);

    return () => clearTimeout(timer);
  }, [query]);

  const select = (path: string) => {
    setOpen(false);
    setQuery("");
    navigate(path);
  };

  const grouped = results.reduce<Record<string, SearchResult[]>>((acc, r) => {
    acc[r.type] = acc[r.type] || [];
    acc[r.type].push(r);
    return acc;
  }, {});

  const groupLabels: Record<string, string> = {
    customer: "Customers",
    store: "Stores",
    product: "Products",
    order: "Orders",
  };

  return (
    <>
      <CommandDialog open={open} onOpenChange={setOpen}>
        <CommandInput placeholder="Search customers, stores, products, orders..." value={query} onValueChange={setQuery} />
        <CommandList>
          <CommandEmpty>{searching ? "Searching..." : query.length < 2 ? "Type at least 2 characters..." : "No results found."}</CommandEmpty>
          {Object.entries(grouped).map(([type, items]) => {
            const Icon = typeIcons[type as keyof typeof typeIcons];
            return (
              <CommandGroup key={type} heading={groupLabels[type] || type}>
                {items.map((item) => (
                  <CommandItem key={item.id} onSelect={() => select(item.path)} className="gap-3">
                    <Icon className="h-4 w-4 text-muted-foreground shrink-0" />
                    <div className="min-w-0">
                      <p className="truncate font-medium">{item.label}</p>
                      <p className="text-xs text-muted-foreground truncate">{item.sub}</p>
                    </div>
                  </CommandItem>
                ))}
              </CommandGroup>
            );
          })}
        </CommandList>
      </CommandDialog>
    </>
  );
}

import { useState } from "react";
import { Button } from "@/components/ui/button";
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card";
import { supabase } from "@/integrations/supabase/client";
import { useAuth } from "@/contexts/AuthContext";
import { toast } from "sonner";
import { useQuery } from "@tanstack/react-query";
import { getOAuthRedirectUrl } from "@/lib/capacitorUtils";

export const GoogleAccountLink = () => {
  const { user } = useAuth();
  const [linking, setLinking] = useState(false);

  const { data: liveAuthUser, refetch: refetchLiveAuthUser } = useQuery({
    queryKey: ["auth-user-live", user?.id],
    queryFn: async () => {
      const { data, error } = await supabase.auth.getUser();
      if (error) throw error;
      return data.user;
    },
    enabled: !!user,
  });

  const googleIdentity = liveAuthUser?.identities?.find((identity) => identity.provider === "google");
  const isGoogleLinked = !!googleIdentity;

  // Get company settings to check if Google linking is enabled
  const { data: appSettings } = useQuery({
    queryKey: ["company-settings", "google-linking"],
    queryFn: async () => {
      const { data } = await supabase
        .from("company_settings")
        .select("*")
        .eq("key", "google_linking_enabled")
        .maybeSingle();
      return data;
    },
  });

  const googleLinkingEnabled = appSettings?.value === "true";

  const handleLinkGoogle = async () => {
    if (!googleLinkingEnabled) {
      toast.error("Google account linking is currently disabled by the administrator.");
      return;
    }

    setLinking(true);
    try {
      const { error } = await supabase.auth.linkIdentity({
        provider: "google",
        options: {
          redirectTo: getOAuthRedirectUrl("/"),
        },
      });

      if (error) {
        if (error.message.includes("Manual linking")) {
          toast.error(
            "Manual account linking is disabled in the system settings. Please contact support to enable this feature.",
            { duration: 5000 }
          );
        } else {
          toast.error(error.message);
        }
      } else {
        toast.success("Google account linking initiated. Please complete the OAuth flow.");
      }
    } catch (error: any) {
      toast.error(error.message || "Failed to link Google account");
    } finally {
      setLinking(false);
    }
  };

  const handleUnlinkGoogle = async () => {
    const { data: latestAuthData } = await supabase.auth.getUser();
    const latestGoogleIdentity = latestAuthData.user?.identities?.find((identity) => identity.provider === "google");

    if (!latestGoogleIdentity) {
      toast.success("Google account is already unlinked");
      await refetchLiveAuthUser();
      return;
    }

    setLinking(true);
    try {
      const { error } = await supabase.auth.unlinkIdentity(latestGoogleIdentity);
      if (error) {
        if (error.message?.toLowerCase().includes("identity doesn't exist")) {
          toast.success("Google account is already unlinked");
          await refetchLiveAuthUser();
        } else {
          toast.error(error.message);
        }
      } else {
        toast.success("Google account unlinked successfully");
        await refetchLiveAuthUser();
      }
    } catch (error: any) {
      toast.error(error.message || "Failed to unlink Google account");
    } finally {
      setLinking(false);
    }
  };

  return (
    <Card>
      <CardHeader>
        <CardTitle>Google Account</CardTitle>
        <CardDescription>
          {isGoogleLinked
            ? "Your account is linked to Google. You can sign in with Google or your phone number."
            : "Link your Google account for easy sign-in"}
        </CardDescription>
      </CardHeader>
      <CardContent className="space-y-4">
        {isGoogleLinked ? (
          <div className="space-y-3">
            <div className="flex items-center gap-2 text-sm text-muted-foreground">
              <svg className="h-5 w-5" viewBox="0 0 24 24">
                <path
                  fill="currentColor"
                  d="M22.56 12.25c0-.78-.07-1.53-.2-2.25H12v4.26h5.92c-.26 1.37-1.04 2.53-2.21 3.31v2.77h3.57c2.08-1.92 3.28-4.74 3.28-8.09z"
                />
                <path
                  fill="currentColor"
                  d="M12 23c2.97 0 5.46-.98 7.28-2.66l-3.57-2.77c-.98.66-2.23 1.06-3.71 1.06-2.86 0-5.29-1.93-6.16-4.53H2.18v2.84C3.99 20.53 7.7 23 12 23z"
                />
                <path
                  fill="currentColor"
                  d="M5.84 14.09c-.22-.66-.35-1.36-.35-2.09s.13-1.43.35-2.09V7.07H2.18C1.43 8.55 1 10.22 1 12s.43 3.45 1.18 4.93l2.85-2.22.81-.62z"
                />
                <path
                  fill="currentColor"
                  d="M12 5.38c1.62 0 3.06.56 4.21 1.64l3.15-3.15C17.45 2.09 14.97 1 12 1 7.7 1 3.99 3.47 2.18 7.07l3.66 2.84c.87-2.6 3.3-4.53 6.16-4.53z"
                />
              </svg>
              <span>Connected to Google</span>
            </div>
            <Button
              variant="outline"
              onClick={handleUnlinkGoogle}
              disabled={linking || !googleLinkingEnabled}
            >
              {linking ? "Unlinking..." : "Unlink Google Account"}
            </Button>
          </div>
        ) : (
          <Button
            onClick={handleLinkGoogle}
            disabled={linking || !googleLinkingEnabled}
            className="w-full"
          >
            {linking ? (
              "Linking..."
            ) : (
              <span className="flex items-center gap-2">
                <svg className="h-5 w-5" viewBox="0 0 24 24">
                  <path
                    fill="currentColor"
                    d="M22.56 12.25c0-.78-.07-1.53-.2-2.25H12v4.26h5.92c-.26 1.37-1.04 2.53-2.21 3.31v2.77h3.57c2.08-1.92 3.28-4.74 3.28-8.09z"
                  />
                  <path
                    fill="currentColor"
                    d="M12 23c2.97 0 5.46-.98 7.28-2.66l-3.57-2.77c-.98.66-2.23 1.06-3.71 1.06-2.86 0-5.29-1.93-6.16-4.53H2.18v2.84C3.99 20.53 7.7 23 12 23z"
                  />
                  <path
                    fill="currentColor"
                    d="M5.84 14.09c-.22-.66-.35-1.36-.35-2.09s.13-1.43.35-2.09V7.07H2.18C1.43 8.55 1 10.22 1 12s.43 3.45 1.18 4.93l2.85-2.22.81-.62z"
                  />
                  <path
                    fill="currentColor"
                    d="M12 5.38c1.62 0 3.06.56 4.21 1.64l3.15-3.15C17.45 2.09 14.97 1 12 1 7.7 1 3.99 3.47 2.18 7.07l3.66 2.84c.87-2.6 3.3-4.53 6.16-4.53z"
                  />
                </svg>
                Link Google Account
              </span>
            )}
          </Button>
        )}
        {!googleLinkingEnabled && (
          <p className="text-xs text-muted-foreground">
            Google account linking is currently disabled by the administrator.
          </p>
        )}
      </CardContent>
    </Card>
  );
};

import { useState } from "react";
import { QrScanner } from "./QrScanner";
import { parseUpiQr, isMerchantUpi } from "@/lib/upiParser";
import { supabase } from "@/integrations/supabase/client";
import { Button } from "@/components/ui/button";
import { Dialog, DialogContent, DialogHeader, DialogTitle } from "@/components/ui/dialog";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { Label } from "@/components/ui/label";
import { ScanLine, Plus, Link } from "lucide-react";
import { toast } from "sonner";

interface QrStoreSelectorProps {
  onStoreSelected: (storeId: string) => void;
  onCreateStore?: (prefill: { name?: string; upiId: string; rawQr: string }) => void;
  triggerClassName?: string;
}

export function QrStoreSelector({ onStoreSelected, onCreateStore, triggerClassName }: QrStoreSelectorProps) {
  const [scanning, setScanning] = useState(false);
  const [notFound, setNotFound] = useState(false);
  const [scannedUpi, setScannedUpi] = useState({ upiId: "", payeeName: "", raw: "" });
  const [linkMode, setLinkMode] = useState(false);
  const [linkStoreId, setLinkStoreId] = useState("");
  const [stores, setStores] = useState<any[]>([]);
  const [saving, setSaving] = useState(false);

  const handleScan = async (data: string) => {
    const upi = parseUpiQr(data);
    if (!upi) {
      toast.error("Not a valid UPI QR code");
      return;
    }

    // Look up store by upi_id
    const { data: qrRecord } = await supabase
      .from("store_qr_codes")
      .select("store_id")
      .eq("upi_id", upi.pa)
      .maybeSingle();

    if (qrRecord?.store_id) {
      onStoreSelected(qrRecord.store_id);
      toast.success("Store found via QR");
    } else {
      // Not found — show options
      setScannedUpi({ upiId: upi.pa, payeeName: upi.pn, raw: upi.raw });
      setNotFound(true);
    }
  };

  const handleCreateStore = () => {
    setNotFound(false);
    const isMerchant = scannedUpi.raw ? isMerchantUpi(parseUpiQr(scannedUpi.raw)!) : false;
    onCreateStore?.({
      name: scannedUpi.payeeName || "",
      upiId: scannedUpi.upiId,
      rawQr: scannedUpi.raw,
    });
  };

  const handleLinkStore = async () => {
    // Load stores for selection
    const { data } = await supabase.from("stores").select("id, name, display_id").eq("is_active", true);
    setStores(data || []);
    setLinkMode(true);
  };

  const confirmLink = async () => {
    if (!linkStoreId) return;
    setSaving(true);
    const { error } = await supabase.from("store_qr_codes").insert({
      store_id: linkStoreId,
      upi_id: scannedUpi.upiId,
      payee_name: scannedUpi.payeeName || null,
      raw_data: scannedUpi.raw,
    });
    setSaving(false);
    if (error) {
      toast.error(error.message);
      return;
    }
    toast.success("QR linked to store");
    onStoreSelected(linkStoreId);
    setNotFound(false);
    setLinkMode(false);
    setLinkStoreId("");
  };

  return (
    <>
      <Button
        type="button"
        variant="outline"
        size="icon"
        className={triggerClassName}
        onClick={() => setScanning(true)}
        title="Scan QR"
      >
        <ScanLine className="h-4 w-4" />
      </Button>

      <QrScanner
        open={scanning}
        onOpenChange={setScanning}
        onScan={handleScan}
        title="Scan Store QR"
      />

      {/* Not Found Dialog */}
      <Dialog open={notFound} onOpenChange={(v) => { if (!v) { setNotFound(false); setLinkMode(false); } }}>
        <DialogContent className="max-w-sm">
          <DialogHeader>
            <DialogTitle>QR Code Not Linked</DialogTitle>
          </DialogHeader>

          {!linkMode ? (
            <div className="space-y-4">
              <div className="rounded-lg border bg-muted/30 p-3 text-sm space-y-1">
                <p><span className="text-muted-foreground">UPI ID:</span> <span className="font-mono">{scannedUpi.upiId}</span></p>
                {scannedUpi.payeeName && <p><span className="text-muted-foreground">Name:</span> {scannedUpi.payeeName}</p>}
              </div>
              <p className="text-sm text-muted-foreground">This QR is not linked to any store. What would you like to do?</p>
              <div className="flex flex-col gap-2">
                {onCreateStore && (
                  <Button onClick={handleCreateStore} className="gap-2">
                    <Plus className="h-4 w-4" /> Create New Store
                  </Button>
                )}
                <Button variant="outline" onClick={handleLinkStore} className="gap-2">
                  <Link className="h-4 w-4" /> Link to Existing Store
                </Button>
              </div>
            </div>
          ) : (
            <div className="space-y-4">
              <div>
                <Label>Select Store</Label>
                <Select value={linkStoreId} onValueChange={setLinkStoreId}>
                  <SelectTrigger className="mt-1"><SelectValue placeholder="Choose a store" /></SelectTrigger>
                  <SelectContent>
                    {stores.map((s) => (
                      <SelectItem key={s.id} value={s.id}>{s.name} ({s.display_id})</SelectItem>
                    ))}
                  </SelectContent>
                </Select>
              </div>
              <div className="flex gap-2">
                <Button variant="outline" className="flex-1" onClick={() => setLinkMode(false)}>Back</Button>
                <Button className="flex-1" disabled={!linkStoreId || saving} onClick={confirmLink}>
                  Link QR
                </Button>
              </div>
            </div>
          )}
        </DialogContent>
      </Dialog>
    </>
  );
}

import React, { useState, useRef, useMemo } from 'react';
import { useVirtualizer } from '@tanstack/react-virtual';
import { cn } from "@/lib/utils";
import { Input } from "@/components/ui/input";
import { Search } from "lucide-react";
import { useIsMobile } from "@/hooks/use-mobile";

interface Column<T> {
  header: string | (() => React.ReactNode);
  accessor: keyof T | ((row: T) => React.ReactNode);
  className?: string;
  hideOnMobile?: boolean;
}

interface ResponsiveDataViewProps<T> {
  columns: Column<T>[];
  data: T[];
  searchPlaceholder?: string;
  searchKey?: keyof T;
  onRowClick?: (row: T) => void;
  height?: string | number;
  emptyMessage?: string;
  renderMobileCard?: (row: T) => React.ReactNode;
  renderDesktopCard?: (row: T) => React.ReactNode;
  useCardLayoutOnDesktop?: boolean;
}

export function ResponsiveDataView<T extends Record<string, any>>({
  columns,
  data,
  searchPlaceholder = "Search...",
  searchKey,
  onRowClick,
  height = "600px",
  emptyMessage = "No results found.",
  renderMobileCard,
  renderDesktopCard,
  useCardLayoutOnDesktop = false,
}: ResponsiveDataViewProps<T>) {
  const [search, setSearch] = useState("");
  const parentRef = useRef<HTMLDivElement>(null);
  const isMobile = useIsMobile();

  // Filter data based on searchKey
  const filteredData = useMemo(() => {
    if (!searchKey || !search) return data;
    const lowerSearch = search.toLowerCase();
    return data.filter((row) => {
      const val = row[searchKey];
      return String(val).toLowerCase().includes(lowerSearch);
    });
  }, [data, search, searchKey]);

  const rowVirtualizer = useVirtualizer({
    count: filteredData.length,
    getScrollElement: () => parentRef.current,
    estimateSize: () => (isMobile ? 120 : useCardLayoutOnDesktop ? 180 : 50),
    overscan: 5,
  });

  // Determine rendering mode
  const shouldRenderMobileCards = isMobile && !!renderMobileCard;
  const shouldRenderDesktopCards = !isMobile && useCardLayoutOnDesktop && !!renderDesktopCard;
  const shouldRenderTable = !shouldRenderMobileCards && !shouldRenderDesktopCards;

  return (
    <div className="space-y-4">
      {/* Search bar */}
      {searchKey && (
        <div className="relative">
          <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-muted-foreground" />
          <Input
            type="text"
            placeholder={searchPlaceholder}
            value={search}
            onChange={(e) => setSearch(e.target.value)}
            className="pl-9"
          />
        </div>
      )}

      {/* Virtualized container */}
      <div
        ref={parentRef}
        className="overflow-auto border rounded-lg bg-background"
        style={{ height }}
      >
        {filteredData.length === 0 ? (
          <div className="flex items-center justify-center h-full text-muted-foreground">
            {emptyMessage}
          </div>
        ) : (
          <div
            style={{
              height: `${rowVirtualizer.getTotalSize()}px`,
              width: '100%',
              position: 'relative',
            }}
          >
            {/* Mobile card layout */}
            {shouldRenderMobileCards &&
              rowVirtualizer.getVirtualItems().map((virtualRow) => {
                const row = filteredData[virtualRow.index];
                return (
                  <div
                    key={virtualRow.key}
                    style={{
                      position: 'absolute',
                      top: 0,
                      left: 0,
                      width: '100%',
                      height: `${virtualRow.size}px`,
                      transform: `translateY(${virtualRow.start}px)`,
                    }}
                    className="px-3 py-1.5"
                    onClick={() => onRowClick?.(row)}
                  >
                    {renderMobileCard!(row)}
                  </div>
                );
              })}

            {/* Desktop card layout */}
            {shouldRenderDesktopCards && (
              <div className="p-4">
                <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-4">
                  {rowVirtualizer.getVirtualItems().map((virtualRow) => {
                    const row = filteredData[virtualRow.index];
                    return (
                      <div
                        key={virtualRow.key}
                        onClick={() => onRowClick?.(row)}
                        className="cursor-pointer"
                      >
                        {renderDesktopCard!(row)}
                      </div>
                    );
                  })}
                </div>
              </div>
            )}

            {/* Table layout */}
            {shouldRenderTable && (
              <>
                {/* Table header - sticky */}
                <table className="w-full border-collapse">
                  <thead className="sticky top-0 bg-muted/50 backdrop-blur-sm z-10 border-b">
                    <tr>
                      {columns.map((col, idx) => {
                        if (isMobile && col.hideOnMobile) return null;
                        return (
                          <th
                            key={idx}
                            className={cn(
                              "px-4 py-3 text-left text-sm font-semibold text-muted-foreground",
                              col.className
                            )}
                          >
                            {typeof col.header === 'function' ? col.header() : col.header}
                          </th>
                        );
                      })}
                    </tr>
                  </thead>
                  <tbody>
                    {rowVirtualizer.getVirtualItems().map((virtualRow) => {
                      const row = filteredData[virtualRow.index];
                      return (
                        <tr
                          key={virtualRow.key}
                          style={{
                            position: 'absolute',
                            top: 0,
                            left: 0,
                            width: '100%',
                            height: `${virtualRow.size}px`,
                            transform: `translateY(${virtualRow.start}px)`,
                          }}
                          className={cn(
                            "border-b transition-colors hover:bg-muted/50",
                            onRowClick && "cursor-pointer"
                          )}
                          onClick={() => onRowClick?.(row)}
                        >
                          {columns.map((col, idx) => {
                            if (isMobile && col.hideOnMobile) return null;
                            const content =
                              typeof col.accessor === 'function'
                                ? col.accessor(row)
                                : row[col.accessor];
                            return (
                              <td
                                key={idx}
                                className={cn("px-4 py-3 text-sm", col.className)}
                              >
                                {content}
                              </td>
                            );
                          })}
                        </tr>
                      );
                    })}
                  </tbody>
                </table>
              </>
            )}
          </div>
        )}
      </div>
    </div>
  );
}

import { useRef } from "react";
import { Button } from "@/components/ui/button";
import { Dialog, DialogContent, DialogHeader, DialogTitle } from "@/components/ui/dialog";
import { useQuery } from "@tanstack/react-query";
import { supabase } from "@/integrations/supabase/client";
import { Loader2, Printer, Share2 } from "lucide-react";
import { toast } from "sonner";

// Simple HTML escape function to prevent XSS
const escapeHtml = (str: string): string => {
  const div = document.createElement("div");
  div.textContent = str;
  return div.innerHTML;
};

interface SaleReceiptProps {
  saleId: string;
  open: boolean;
  onClose: () => void;
}

export const SaleReceipt = ({ saleId, open, onClose }: SaleReceiptProps) => {
  const printRef = useRef<HTMLDivElement>(null);

  // Fetch sale details
  const { data: sale, isLoading } = useQuery({
    queryKey: ["sale-receipt", saleId],
    queryFn: async () => {
      const { data, error } = await supabase
        .from("sales")
        .select(`
          *,
          customers(name, phone),
          stores(name, address),
          profiles:recorded_by(full_name),
          sale_items(*, products(name, unit))
        `)
        .eq("id", saleId)
        .single();
      if (error) throw error;
      return data;
    },
    enabled: open && !!saleId,
  });

  // Fetch company settings
  const { data: settings = {} } = useQuery({
    queryKey: ["company-settings-receipt"],
    queryFn: async () => {
      const { data } = await supabase.from("company_settings").select("key, value");
      const map: Record<string, string> = {};
      data?.forEach((s: any) => { map[s.key] = s.value; });
      return map;
    },
  });

  // Calculate amounts from sale data (since sales table uses cash_amount, upi_amount, outstanding_amount)
  const amountPaid = Number(sale?.cash_amount || 0) + Number(sale?.upi_amount || 0);
  const outstandingAmount = Number(sale?.outstanding_amount || 0);

  const handlePrint = () => {
    if (!sale) return;

    const printWindow = window.open("", "_blank");
    if (!printWindow) {
      toast.error("Please allow popups to print");
      return;
    }

    // Generate safe HTML content using escaped values
    const itemsHtml = (sale.sale_items || []).map((item: any) => `
      <div style="margin: 8px 0;">
        <div style="display: flex; justify-content: space-between;">
          <span style="flex: 1; overflow: hidden; text-overflow: ellipsis; white-space: nowrap; padding-right: 8px;">${escapeHtml(item.products?.name || "Unknown")}</span>
