interface CreateStoreWizardProps {
  open: boolean;
  onOpenChange: (open: boolean) => void;
  onCreated?: () => void;
}

type Step = "customer" | "details" | "pricing";

export function CreateStoreWizard({ open, onOpenChange, onCreated }: CreateStoreWizardProps) {
  const { role, user } = useAuth();
  const { allowed: canSetOpeningBalance } = usePermission("opening_balance");
  const { canAccessRoute, hasMatrixRestrictions, enabledRouteIds } = useRouteAccess(user?.id, role);
  const qc = useQueryClient();
  const [step, setStep] = useState<Step>("customer");
  const [saving, setSaving] = useState(false);

  // Customer step
  const [customerMode, setCustomerMode] = useState<"select" | "create">("select");
  const [customerId, setCustomerId] = useState("");
  const [newCustName, setNewCustName] = useState("");
  const [newCustPhone, setNewCustPhone] = useState("");
  const [newCustEmail, setNewCustEmail] = useState("");
  const [newCustPhotoUrl, setNewCustPhotoUrl] = useState("");

  // Details step
  const [name, setName] = useState("");
  const [storeTypeId, setStoreTypeId] = useState("");
  const [routeId, setRouteId] = useState("");
  const [phone, setPhone] = useState("");
  const [photoUrl, setPhotoUrl] = useState("");
  const [lat, setLat] = useState<number | null>(null);
  const [lng, setLng] = useState<number | null>(null);
  const [street, setStreet] = useState("");
  const [area, setArea] = useState("");
  const [city, setCity] = useState("");
  const [district, setDistrict] = useState("");
  const [state, setState] = useState("");
  const [pincode, setPincode] = useState("");
  const [address, setAddress] = useState("");
  const [obAmount, setObAmount] = useState("");
  const [obType, setObType] = useState<"debit" | "credit">("debit");
  const [locating, setLocating] = useState(false);

  // Pricing step
  const [priceMap, setPriceMap] = useState<Record<string, string>>({});
  const [duplicateWarnings, setDuplicateWarnings] = useState<string[]>([]);
  const [checkingDupes, setCheckingDupes] = useState(false);
  const [custDuplicate, setCustDuplicate] = useState<{ id: string; name: string; display_id: string } | null>(null);

  const canEditPricing = role === "super_admin" || role === "manager";

  const getDistanceMeters = (lat1: number, lng1: number, lat2: number, lng2: number) => {
    const R = 6371000;
    const dLat = ((lat2 - lat1) * Math.PI) / 180;
    const dLng = ((lng2 - lng1) * Math.PI) / 180;
    const a = Math.sin(dLat / 2) ** 2 + Math.cos((lat1 * Math.PI) / 180) * Math.cos((lat2 * Math.PI) / 180) * Math.sin(dLng / 2) ** 2;
    return R * 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1 - a));
  };

  const checkDuplicates = async () => {
    setCheckingDupes(true);
    const warnings: string[] = [];
    
    // 1. Check matching names
    const nameTrimmed = name.trim();
    if (nameTrimmed) {
        const { data: nameMatches } = await supabase
            .from("stores")
            .select("id, name, display_id, area, district, city")
            .eq("is_active", true)
            .ilike("name", nameTrimmed);
        
        nameMatches?.forEach(s => {
            const suffix = s.area?.trim() || s.district?.trim() || s.city?.trim() || "";
            const suggestion = suffix ? ` → Try "${nameTrimmed} (${suffix})" instead` : "";
            warnings.push(`Store "${s.name}" (${s.display_id}) has the same name.${suggestion}`);
        });
    }

    // 2. Check matching phones
    const phoneTrimmed = phone.trim();
    if (phoneTrimmed) {
        const { data: phoneMatches } = await supabase
            .from("stores")
            .select("id, name, display_id")
            .eq("is_active", true)
            .eq("phone", phoneTrimmed);
        
        phoneMatches?.forEach(s => {
            warnings.push(`Store "${s.name}" (${s.display_id}) has the same phone number`);
        });
    }

    // 3. Advanced proximity detection
    if (lat && lng) {
        const { data: closeStores } = await supabase.rpc("check_store_proximity", {
           p_lat: lat,
           p_lng: lng,
           p_radius_m: 100
        });

        closeStores?.forEach(s => {
           if (s.distance_meters < 5) {
               warnings.push(`Store "${s.name}" (${s.display_id}) is at the exact same location (${Math.round(s.distance_meters)}m away)`);
           } else {
               warnings.push(`Store "${s.name}" (${s.display_id}) is only ${Math.round(s.distance_meters)}m away`);
           }
        });
    }

    setDuplicateWarnings(warnings);
    setCheckingDupes(false);
    return { warnings };
  };

  const { data: customers } = useQuery({
    queryKey: ["customers-list"],
    queryFn: async () => {
      const { data } = await supabase.from("customers").select("id, name, display_id, phone").eq("is_active", true);
      return data || [];
    },
    enabled: open,
  });

  const { data: storeTypes } = useQuery({
    queryKey: ["store-types", hasMatrixRestrictions, enabledRouteIds.size],
    queryFn: async () => {
      const { data } = await supabase.from("store_types").select("*").eq("is_active", true);
      let types = data || [];
      if (hasMatrixRestrictions && enabledRouteIds.size > 0) {
        const { data: accessibleRoutes } = await supabase
          .from("routes")
          .select("store_type_id")
          .in("id", Array.from(enabledRouteIds));
        const allowedTypeIds = new Set(accessibleRoutes?.map((r) => r.store_type_id));
        types = types.filter((t) => allowedTypeIds.has(t.id));
      } else if (hasMatrixRestrictions && enabledRouteIds.size === 0) {
        types = [];
      }
      return types;
    },
    enabled: open,
  });

  const { data: routes } = useQuery({
    queryKey: ["routes-list", storeTypeId, hasMatrixRestrictions],
    queryFn: async () => {
      let q = supabase.from("routes").select("*").eq("is_active", true);
      if (storeTypeId) q = q.eq("store_type_id", storeTypeId);
      const { data } = await q;
      let fetchedRoutes = data || [];
      if (hasMatrixRestrictions) {
        fetchedRoutes = fetchedRoutes.filter((r) => canAccessRoute(r.id));
      }
      return fetchedRoutes;
    },
    enabled: open,
  });

  const { data: products } = useQuery({
    queryKey: ["products-for-wizard", storeTypeId],
    queryFn: async () => {
      if (!storeTypeId) {
        const { data } = await supabase.from("products").select("id, name, sku, base_price").eq("is_active", true).order("name");
        return data || [];
      }
      const { data: accessData } = await supabase
        .from("store_type_products")
        .select("product_id, products(id, name, sku, base_price)")
        .eq("store_type_id", storeTypeId);
      if (accessData && accessData.length > 0) {
        return accessData.map((a: any) => a.products).filter(Boolean);
      }
      const { data } = await supabase.from("products").select("id, name, sku, base_price").eq("is_active", true).order("name");
      return data || [];
    },
    enabled: open && step === "pricing",
  });

  const { data: typePricing } = useQuery({
    queryKey: ["store-type-pricing-wizard", storeTypeId],
    queryFn: async () => {
      if (!storeTypeId) return {};
      const { data } = await supabase.from("store_type_pricing").select("product_id, price").eq("store_type_id", storeTypeId);
      const map: Record<string, number> = {};
      data?.forEach((p) => { map[p.product_id] = Number(p.price); });
      return map;
    },
    enabled: open && step === "pricing",
  });

  const captureLocation = async () => {
    setLocating(true);
    const pos = await getCurrentPosition();
    if (pos) {
      const lt = pos.lat;
      const ln = pos.lng;
      setLat(lt);
      setLng(ln);

      // Reverse geocode using Nominatim
      try {
        const res = await fetch(`https://nominatim.openstreetmap.org/reverse?lat=${lt}&lon=${ln}&format=json&addressdetails=1`, {
          headers: { "Accept-Language": "en" },
        });
        const data = await res.json();
        const addr = data.address || {};
        setStreet(addr.road || addr.street || "");
        setArea(addr.suburb || addr.neighbourhood || addr.village || "");
        setCity(addr.city || addr.town || addr.municipality || "");
        setDistrict(addr.county || addr.state_district || "");
        setState(addr.state || "");
        setPincode(addr.postcode || "");
        setAddress(data.display_name || "");
      } catch {
        toast.error("Could not fetch address");
      }
    } else {
      toast.error("Location error");
    }
    setLocating(false);
  };

  const resetForm = () => {
    setStep("customer");
    setCustomerMode("select");
    setCustomerId("");
    setNewCustName(""); setNewCustPhone(""); setNewCustEmail(""); setNewCustPhotoUrl("");
    setName(""); setStoreTypeId(""); setRouteId(""); setPhone("");
    setPhotoUrl(""); setLat(null); setLng(null);
    setStreet(""); setArea(""); setCity(""); setDistrict(""); setState(""); setPincode(""); setAddress("");
    setObAmount("");
    setObType("debit");
    setPriceMap({});
    setDuplicateWarnings([]);
  };

  const handleSave = async () => {
    setSaving(true);
    try {
      let finalCustomerId = customerId;

      // Create customer if needed
      if (customerMode === "create") {
        if (!newCustName.trim()) { toast.error("Customer name required"); setSaving(false); return; }
        if (!newCustPhone.trim() || newCustPhone.trim().length < 6) { toast.error("Valid customer phone number required"); setSaving(false); return; }

        const { data: allCusts } = await supabase.from("customers").select("id");
        const count = (allCusts?.length || 0) + 1;
        const displayId = `CUST-${String(count).padStart(6, "0")}`;
        const { data: newCust, error: custErr } = await supabase.from("customers").insert({
          display_id: displayId,
          name: newCustName,
          phone: newCustPhone || null,
          email: newCustEmail || null,
          photo_url: newCustPhotoUrl || null,
        }).select("id").single();
        if (custErr) { toast.error(custErr.message); setSaving(false); return; }
        finalCustomerId = newCust.id;
      }

      if (!finalCustomerId || !name.trim() || !storeTypeId) {
        toast.error("Please fill required fields");
        setSaving(false);
        return;
      }

      // Resolve store phone: if blank, fall back to customer's phone
      let storePhone = phone.trim() || null;
      if (!storePhone) {
        if (customerMode === "create") {
          storePhone = newCustPhone.trim() || null;
        } else {
          const selectedCust = (customers || []).find((c) => c.id === finalCustomerId);
          storePhone = selectedCust?.phone || null;
        }
      }

      // Create store
      const { data: allStores } = await supabase.from("stores").select("id");
      const storeCount = (allStores?.length || 0) + 1;
      const storeDisplayId = `STR-${String(storeCount).padStart(6, "0")}`;

      const ob = obAmount && Number(obAmount) > 0 ? (obType === "credit" ? -Number(obAmount) : Number(obAmount)) : 0;
      const { data: newStore, error: storeErr } = await supabase.from("stores").insert({
        display_id: storeDisplayId,
        name,
        customer_id: finalCustomerId,
        store_type_id: storeTypeId,
        route_id: routeId || null,
        phone: storePhone,
        photo_url: photoUrl || null,
        lat, lng,
        address: address || null,
        street: street || null,
        area: area || null,
        city: city || null,
        district: district || null,
        state: state || null,
        pincode: pincode || null,
        opening_balance: ob,
        outstanding: ob,
      }).select("id").single();

      if (storeErr) { toast.error(storeErr.message); setSaving(false); return; }

      // Save store pricing if any
      const pricingInserts = Object.entries(priceMap)
        .filter(([, v]) => v && Number(v) > 0)
        .map(([productId, price]) => ({
          store_id: newStore.id,
          product_id: productId,
          price: Number(price),
        }));
      if (pricingInserts.length > 0) {
        await supabase.from("store_pricing").insert(pricingInserts);
      }

      toast.success("Store created successfully!");
      resetForm();
      onOpenChange(false);
      qc.invalidateQueries({ queryKey: ["stores"] });
      qc.invalidateQueries({ queryKey: ["customers"] });
      onCreated?.();
    } catch (err: any) {
      toast.error(err.message || "Failed to create store");
    }
    setSaving(false);
  };

  const canGoToDetails = customerMode === "select" ? !!customerId : !!newCustName.trim() && newCustPhone.trim().length >= 6;
  const canGoToPricing = !!name.trim() && !!storeTypeId;

  // Debounced phone check for new customer
  useEffect(() => {
    if (!newCustPhone.trim() || newCustPhone.trim().length < 6) { setCustDuplicate(null); return; }
    const timer = setTimeout(() => {
      const match = (customers || []).find((c) => c.phone && c.phone === newCustPhone.trim());
      setCustDuplicate(match ? { id: match.id, name: match.name, display_id: match.display_id } : null);
    }, 400);
    return () => clearTimeout(timer);
  }, [newCustPhone, customers]);

  const getEffectivePrice = (product: any) => {
    if (typePricing && product.id in (typePricing as any)) return `₹${(typePricing as any)[product.id]} (type)`;
    return `₹${Number(product.base_price)} (base)`;
  };

  return (
    <Dialog open={open} onOpenChange={(o) => { if (!o) resetForm(); onOpenChange(o); }}>
      <DialogContent className="max-w-lg max-h-[90vh] overflow-y-auto">
        <DialogHeader>
          <DialogTitle>
            {step === "customer" ? "Step 1: Customer" : step === "details" ? "Step 2: Store Details" : "Step 3: Products & Pricing"}
          </DialogTitle>
        </DialogHeader>

        {/* Step indicators */}
        <div className="flex items-center gap-2 mb-2">
          {["customer", "details", "pricing"].map((s, i) => (
            <div key={s} className="flex items-center gap-1">
              <div className={`h-7 w-7 rounded-full flex items-center justify-center text-xs font-medium ${step === s ? "bg-primary text-primary-foreground" : i < ["customer", "details", "pricing"].indexOf(step) ? "bg-primary/20 text-primary" : "bg-muted text-muted-foreground"}`}>
                {i < ["customer", "details", "pricing"].indexOf(step) ? <Check className="h-3.5 w-3.5" /> : i + 1}
              </div>
              {i < 2 && <div className="w-8 h-0.5 bg-muted" />}
            </div>
          ))}
        </div>

        {/* Step 1: Customer */}
        {step === "customer" && (
          <div className="space-y-4">
            <div className="flex gap-2">
              <Button type="button" variant={customerMode === "select" ? "default" : "outline"} size="sm" onClick={() => setCustomerMode("select")}>
                Select Existing
              </Button>
              <Button type="button" variant={customerMode === "create" ? "default" : "outline"} size="sm" onClick={() => setCustomerMode("create")}>
                <Plus className="mr-1 h-3 w-3" /> Create New
              </Button>
            </div>

            {customerMode === "select" ? (
              <div>
                <Label>Customer</Label>
                <Select value={customerId} onValueChange={setCustomerId}>
                  <SelectTrigger className="mt-1"><SelectValue placeholder="Select customer" /></SelectTrigger>
                  <SelectContent>
                    {customers?.map(c => <SelectItem key={c.id} value={c.id}>{c.name} ({c.display_id})</SelectItem>)}
                  </SelectContent>
                </Select>
              </div>
            ) : (
              <div className="space-y-3">
                <div className="flex justify-center">
                  <ImageUpload folder="customers" currentUrl={newCustPhotoUrl || null} onUploaded={setNewCustPhotoUrl} onRemoved={() => setNewCustPhotoUrl("")} />
                </div>
                <div><Label>Name *</Label><Input value={newCustName} onChange={e => setNewCustName(e.target.value)} className="mt-1" /></div>
                <div>
                  <Label>Phone *</Label>
                  <Input value={newCustPhone} onChange={e => setNewCustPhone(e.target.value)} className="mt-1" required placeholder="+91 98765 43210" />
                  {custDuplicate && newCustPhone.trim() && (
                    <div className="flex items-start gap-2 mt-1.5 rounded-md border border-amber-300/60 bg-amber-50 dark:bg-amber-900/20 px-3 py-2 text-xs text-amber-700 dark:text-amber-400">
                      <AlertTriangle className="h-3.5 w-3.5 mt-0.5 shrink-0" />
                      <span>Phone already used by <span className="font-semibold">{custDuplicate.name}</span> ({custDuplicate.display_id}). You can still proceed or select them as existing customer.</span>
                    </div>
                  )}
                </div>
                <div><Label>Email</Label><Input type="email" value={newCustEmail} onChange={e => setNewCustEmail(e.target.value)} className="mt-1" /></div>
              </div>
            )}

            <Button className="w-full" disabled={!canGoToDetails} onClick={() => setStep("details")}>
              Next <ChevronRight className="ml-1 h-4 w-4" />
            </Button>
          </div>
        )}

        {/* Step 2: Store Details */}
        {step === "details" && (
          <div className="space-y-4">
            <div className="flex items-start gap-4">
              <ImageUpload folder="stores" currentUrl={photoUrl || null} onUploaded={setPhotoUrl} onRemoved={() => setPhotoUrl("")} size="lg" />
              <div className="flex-1 space-y-3">
                <div><Label>Store Name *</Label><Input value={name} onChange={e => setName(e.target.value)} className="mt-1" /></div>
                <div><Label>Phone</Label><Input value={phone} onChange={e => setPhone(e.target.value)} className="mt-1" /></div>
              </div>
            </div>

            <div className="grid grid-cols-2 gap-3">
              <div>
                <Label>Store Type *</Label>
                <Select value={storeTypeId} onValueChange={(v) => { setStoreTypeId(v); setRouteId(""); }}>
                  <SelectTrigger className="mt-1"><SelectValue placeholder="Select type" /></SelectTrigger>
                  <SelectContent>{storeTypes?.map(t => <SelectItem key={t.id} value={t.id}>{t.name}</SelectItem>)}</SelectContent>
                </Select>
              </div>
              <div>
                <Label>Route</Label>
                <Select value={routeId} onValueChange={setRouteId}>
                  <SelectTrigger className="mt-1"><SelectValue placeholder="Select route" /></SelectTrigger>
                  <SelectContent>{routes?.map(r => <SelectItem key={r.id} value={r.id}>{r.name}</SelectItem>)}</SelectContent>
                </Select>
              </div>
            </div>

            {/* Location */}
            <div>
              <div className="flex items-center justify-between mb-1">
                <Label>Location</Label>
                <Button type="button" variant="outline" size="sm" onClick={captureLocation} disabled={locating}>
                  {locating ? <Loader2 className="mr-1 h-3 w-3 animate-spin" /> : <MapPin className="mr-1 h-3 w-3" />}
                  {locating ? "Locating..." : "Capture Location"}
                </Button>
              </div>
              {lat && lng && (
                <p className="text-xs text-muted-foreground mb-2">{lat.toFixed(6)}, {lng.toFixed(6)}</p>
              )}
            </div>

            <div className="grid grid-cols-2 gap-3">
              <div><Label className="text-xs">Street</Label><Input value={street} onChange={e => setStreet(e.target.value)} className="mt-0.5 h-8 text-sm" /></div>
              <div><Label className="text-xs">Area</Label><Input value={area} onChange={e => setArea(e.target.value)} className="mt-0.5 h-8 text-sm" /></div>
              <div><Label className="text-xs">City</Label><Input value={city} onChange={e => setCity(e.target.value)} className="mt-0.5 h-8 text-sm" /></div>
              <div><Label className="text-xs">District</Label><Input value={district} onChange={e => setDistrict(e.target.value)} className="mt-0.5 h-8 text-sm" /></div>
              <div><Label className="text-xs">State</Label><Input value={state} onChange={e => setState(e.target.value)} className="mt-0.5 h-8 text-sm" /></div>
              <div><Label className="text-xs">Pincode</Label><Input value={pincode} onChange={e => setPincode(e.target.value)} className="mt-0.5 h-8 text-sm" /></div>
            </div>

            {canSetOpeningBalance && (
              <div>
                <Label>Opening Balance</Label>
                <div className="flex gap-2 mt-1">
                  <Input
                    type="number"
                    min="0"
                    value={obAmount}
                    onChange={e => setObAmount(e.target.value)}
                    placeholder="Enter amount"
                    className="flex-1"
                  />
                  <div className="flex rounded-md border overflow-hidden text-sm font-medium">
                    <button
                      type="button"
                      onClick={() => setObType("credit")}
                      className={`px-3 py-2 transition-colors ${
                        obType === "credit"
                          ? "bg-green-500 text-white"
                          : "bg-muted text-muted-foreground hover:bg-muted/70"
                      }`}
                    >
                      Credit
                    </button>
                    <button
                      type="button"
                      onClick={() => setObType("debit")}
                      className={`px-3 py-2 transition-colors ${
                        obType === "debit"
                          ? "bg-destructive text-destructive-foreground"
                          : "bg-muted text-muted-foreground hover:bg-muted/70"
                      }`}
                    >
                      Debit
                    </button>
                  </div>
                </div>
                {obAmount && Number(obAmount) > 0 ? (
                  <p className={`text-sm font-medium mt-1.5 ${
                    obType === "credit" ? "text-green-600" : "text-destructive"
                  }`}>
                    {obType === "credit" ? "+" : "-"}₹{Number(obAmount).toLocaleString()}
                    {" — "}
                    {obType === "credit" ? "Company owes this store" : "Store owes the company"}
                  </p>
                ) : (
                  <p className="text-[11px] text-muted-foreground mt-0.5">
                    Credit = company owes store &nbsp;·&nbsp; Debit = store owes company
                  </p>
                )}
              </div>
            )}

            {duplicateWarnings.length > 0 && (
              <Alert variant="default" className="border-amber-300/60 bg-amber-50 dark:bg-amber-900/20 text-amber-700 dark:text-amber-400 [&>svg]:text-amber-500">
                <AlertTriangle className="h-4 w-4" />
                <AlertTitle>Possible Duplicates Found</AlertTitle>
                <AlertDescription>
                  <ul className="list-disc pl-4 text-xs space-y-0.5 mt-1">
                    {duplicateWarnings.map((w, i) => <li key={i}>{w}</li>)}
                  </ul>
                  <p className="text-xs mt-2">You can still proceed if this is intentional.</p>
                </AlertDescription>
              </Alert>
            )}

            <div className="flex gap-2">
              <Button variant="outline" className="flex-1" onClick={() => { setStep("customer"); setDuplicateWarnings([]); }}>
                <ChevronLeft className="mr-1 h-4 w-4" /> Back
              </Button>
              <Button
                className="flex-1"
                disabled={!canGoToPricing || checkingDupes}
                onClick={async () => {
                  const { warnings } = await checkDuplicates();
                  if (warnings.length === 0 || duplicateWarnings.length > 0) {
                    setStep("pricing");
                  }
                  // If warnings found for first time, show them — second click proceeds anyway.
                }}
              >
                {checkingDupes ? <Loader2 className="mr-1 h-4 w-4 animate-spin" /> : null}
                {duplicateWarnings.length > 0 ? "Proceed Anyway" : "Next"} <ChevronRight className="ml-1 h-4 w-4" />
              </Button>
            </div>
          </div>
        )}

        {/* Step 3: Products & Pricing */}
        {step === "pricing" && (
          <div className="space-y-4">
            <p className="text-sm text-muted-foreground">
              {canEditPricing ? "Set store-level prices (leave blank to use type/base price)." : "Review product pricing for this store."}
            </p>
            <div className="space-y-2 max-h-60 overflow-y-auto">
              {products?.map((p: any) => (
                <div key={p.id} className="flex items-center justify-between gap-3 rounded-lg border p-2.5">
                  <div className="min-w-0 flex-1">
                    <p className="text-sm font-medium truncate">{p.name}</p>
                    <div className="flex items-center gap-2 mt-0.5">
                      <Badge variant="outline" className="text-[10px]">{p.sku}</Badge>
                      <span className="text-[11px] text-muted-foreground">{getEffectivePrice(p)}</span>
                    </div>
                  </div>
                  {canEditPricing && (
                    <Input
                      type="number"
                      value={priceMap[p.id] || ""}
                      onChange={(e) => setPriceMap({ ...priceMap, [p.id]: e.target.value })}
                      placeholder="—"
                      className="w-24 h-8 text-sm"
                    />
                  )}
                </div>
              ))}
              {(!products || products.length === 0) && (
                <p className="text-center text-sm text-muted-foreground py-4">No products available</p>
              )}
            </div>

            <div className="flex gap-2">
              <Button variant="outline" className="flex-1" onClick={() => setStep("details")}>
                <ChevronLeft className="mr-1 h-4 w-4" /> Back
              </Button>
              <Button className="flex-1" onClick={handleSave} disabled={saving}>
                {saving ? <Loader2 className="mr-2 h-4 w-4 animate-spin" /> : <Check className="mr-2 h-4 w-4" />}
                Create Store
              </Button>
            </div>
          </div>
        )}
      </DialogContent>
    </Dialog>
  );
}

import { useMemo, useState } from "react";
import { DataTable } from "@/components/shared/DataTable";
import { Avatar, AvatarFallback, AvatarImage } from "@/components/ui/avatar";
import { Badge } from "@/components/ui/badge";
import {
  Dialog, DialogContent, DialogHeader, DialogTitle,
} from "@/components/ui/dialog";
import { Loader2, Package, Tag } from "lucide-react";
import { useQuery } from "@tanstack/react-query";
import { supabase } from "@/integrations/supabase/client";

type LedgerEntry = {
  id: string;
  type: "sale" | "payment" | "correction";
  date: string;
  display_id: string;
  description: string;
  total_amount: number;
  cash_amount: number;
  upi_amount: number;
  outstanding: number; // new_outstanding = running balance
  notes: string | null;
  recorded_by: string;
  raw: any;
};

interface StoreLedgerProps {
  sales: any[];
  transactions: any[];
  balanceAdjustments?: any[];
  openingBalance: number;
  storeCreatedAt: string;
  profileMap: Map<string, { user_id: string; full_name: string; avatar_url: string | null }>;
}

export function StoreLedger({ sales, transactions, balanceAdjustments = [], openingBalance, storeCreatedAt, profileMap }: StoreLedgerProps) {
  const [selectedEntryId, setSelectedEntryId] = useState<string | null>(null);

  const ledgerEntries = useMemo(() => {
    const entries: LedgerEntry[] = [];

    for (const s of sales) {
      entries.push({
        id: s.id,
        type: "sale",
        date: s.created_at,
        display_id: s.display_id,
        description: `Sale #${s.display_id}`,
        total_amount: Number(s.total_amount),
        cash_amount: Number(s.cash_amount),
        upi_amount: Number(s.upi_amount),
        outstanding: Number(s.new_outstanding),
        notes: s.notes,
        recorded_by: s.recorded_by,
        raw: s,
      });
    }

    for (const t of transactions) {
      const paymentMethod = Number(t.cash_amount) > 0 && Number(t.upi_amount) > 0
        ? "Cash+UPI"
        : Number(t.upi_amount) > 0 ? "UPI" : "Cash";
      entries.push({
        id: t.id,
        type: "payment",
        date: t.created_at,
        display_id: t.display_id,
        description: `Payment (${paymentMethod}) #${t.display_id}`,
        total_amount: Number(t.total_amount),
        cash_amount: Number(t.cash_amount),
        upi_amount: Number(t.upi_amount),
        outstanding: Number(t.new_outstanding),
        notes: t.notes,
        recorded_by: t.recorded_by,
        raw: t,
      });
    }

    for (const adj of balanceAdjustments) {
      entries.push({
        id: adj.id,
        type: "correction",
        date: adj.created_at,
        display_id: "",
        description: `Balance Adjustment: ₹${Number(adj.old_outstanding).toLocaleString()} → ₹${Number(adj.new_outstanding).toLocaleString()}`,
        total_amount: Number(adj.adjustment_amount),
        cash_amount: 0,
        upi_amount: 0,
        outstanding: Number(adj.new_outstanding),
        notes: adj.reason,
        recorded_by: adj.adjusted_by,
        raw: adj,
      });
    }

    // Sort newest first
    entries.sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());

    // Add opening balance as the very last (oldest) entry
    entries.push({
      id: "__opening_balance__",
      type: "correction" as const,
      date: storeCreatedAt,
      display_id: "",
      description: "Opening Balance",
      total_amount: openingBalance,
      cash_amount: 0,
      upi_amount: 0,
      outstanding: openingBalance,
      notes: null,
      recorded_by: "",
      raw: null,
    });

    return entries;
  }, [sales, transactions, balanceAdjustments, openingBalance]);

  const selectedEntry = ledgerEntries.find((e) => e.id === selectedEntryId);
  const isSaleSelected = selectedEntry?.type === "sale";

  const { data: saleItems, isLoading: loadingSaleItems } = useQuery({
    queryKey: ["sale-items-detail", selectedEntryId],
    queryFn: async () => {
      const { data } = await supabase
        .from("sale_items")
        .select("*, products(name, sku)")
        .eq("sale_id", selectedEntryId!);
      return data || [];
    },
    enabled: !!selectedEntryId && isSaleSelected,
  });

  const getRecorder = (uid: string) => profileMap.get(uid);

  const columns = [
    {
      header: "Date",
      accessor: (row: LedgerEntry) => row.date ? new Date(row.date).toLocaleDateString("en-IN") : "—",
      className: "text-muted-foreground text-xs",
    },
    {
      header: "Description",
      accessor: (row: LedgerEntry) => {
        if (row.id === "__opening_balance__") {
          return (
            <div className="flex items-center gap-2">
              <div className="flex h-7 w-7 shrink-0 items-center justify-center rounded-md bg-muted shadow-sm">
                <Tag className="h-3.5 w-3.5 text-muted-foreground" />
              </div>
              <div>
                <p className="font-medium text-sm text-muted-foreground">Opening Balance</p>
                <p className="text-[11px] text-muted-foreground">Admin</p>
              </div>
            </div>
          );
        }
        return (
          <div>
            <p className="font-medium text-sm">{row.description}</p>
            <p className="text-[11px] text-muted-foreground uppercase">{row.type === "sale" ? "SALE" : row.type === "payment" ? "PAYMENT" : "CORRECTION"}</p>
            {row.notes && (
              <p className="text-[11px] text-muted-foreground mt-0.5 flex items-center gap-1">
                <span className="w-0.5 h-3 bg-primary/40 rounded-full inline-block" />
                <span className="italic">{row.notes}</span>
              </p>
            )}
          </div>
        );
      },
    },
    {
      header: "Debit (-)",
      accessor: (row: LedgerEntry) =>
        row.type === "sale" ? (
          <span className="text-destructive font-medium">₹{row.total_amount.toLocaleString()}</span>
        ) : row.id === "__opening_balance__" && row.total_amount > 0 ? (
          <span className="text-destructive font-medium">₹{row.total_amount.toLocaleString()}</span>
        ) : row.type === "correction" && row.id !== "__opening_balance__" && row.total_amount > 0 ? (
          <span className="text-destructive font-medium">₹{row.total_amount.toLocaleString()}</span>
        ) : (
          <span className="text-muted-foreground">—</span>
        ),
    },
    {
      header: "Credit (+)",
      accessor: (row: LedgerEntry) => {
        if (row.id === "__opening_balance__" && row.total_amount < 0) {
          return <span className="text-success font-medium">₹{Math.abs(row.total_amount).toLocaleString()}</span>;
        }
        if (row.id !== "__opening_balance__" && row.type === "payment") {
          return <span className="text-success font-medium">₹{row.total_amount.toLocaleString()}</span>;
        }
        if (row.type === "sale" && (row.cash_amount + row.upi_amount) > 0) {
          return <span className="text-success font-medium">₹{(row.cash_amount + row.upi_amount).toLocaleString()}</span>;
        }
        if (row.type === "correction" && row.id !== "__opening_balance__" && row.total_amount < 0) {
          return <span className="text-success font-medium">₹{Math.abs(row.total_amount).toLocaleString()}</span>;
        }
        return <span className="text-muted-foreground">—</span>;
      },
    },
    {
      header: "Balance",
      accessor: (row: LedgerEntry) => (
        <span className={row.outstanding > 0 ? "text-destructive font-semibold" : row.outstanding < 0 ? "text-success font-semibold" : "text-muted-foreground font-semibold"}>
          {row.outstanding < 0 ? "-" : ""}₹{Math.abs(row.outstanding).toLocaleString()}
        </span>
      ),
    },
  ];

  const renderMobileCard = (row: LedgerEntry) => {
    const p = getRecorder(row.recorded_by);

    if (row.id === "__opening_balance__") {
      const isCredit = row.total_amount < 0;
      const displayAmount = Math.abs(row.total_amount);
      return (
        <div className="rounded-xl border bg-card px-3 py-2.5 shadow-sm">
          <div className="flex items-center justify-between">
            <Badge variant={isCredit ? "secondary" : "destructive"} className="text-[10px] h-5">
              {isCredit ? "CREDIT" : "DEBIT"}
            </Badge>
            <span className="text-[11px] text-muted-foreground">
              {new Date(row.date).toLocaleDateString("en-IN")}
            </span>
          </div>
          <div className="flex items-center justify-between mt-1.5">
            <span className="font-medium text-sm text-muted-foreground">Opening Balance</span>
            <span className={`text-sm font-bold ${isCredit ? "text-success" : "text-destructive"}`}>
              {isCredit ? "+" : "-"}₹{displayAmount.toLocaleString()}
            </span>
          </div>
          <div className="flex items-center justify-between mt-1 text-[11px]">
            <span className={row.outstanding > 0 ? "text-destructive" : row.outstanding < 0 ? "text-success" : "text-muted-foreground"}>
              Bal: {row.outstanding < 0 ? "-" : ""}₹{Math.abs(row.outstanding).toLocaleString()}
            </span>
            <span className="text-muted-foreground">Admin</span>
          </div>
        </div>
      );
    }

    return (
      <div
        className="rounded-xl border bg-card px-3 py-2.5 shadow-sm cursor-pointer"
        onClick={() => setSelectedEntryId(row.id)}
      >
        <div className="flex items-center justify-between">
          <Badge variant={row.type === "sale" ? "destructive" : row.type === "correction" ? "outline" : "secondary"} className="text-[10px] h-5">
            {row.type === "sale" ? "SALE" : row.type === "correction" ? "ADJUSTMENT" : "PAYMENT"}
          </Badge>
          <span className="text-[11px] text-muted-foreground">
            {new Date(row.date).toLocaleDateString("en-IN")}
          </span>
        </div>
        <div className="flex items-center justify-between mt-1.5">
          <span className="font-mono text-xs text-muted-foreground">{row.display_id}</span>
          <div className="flex flex-col items-end gap-0.5">
            <span className="text-sm font-bold text-destructive">-₹{row.total_amount.toLocaleString()}</span>
            {(row.cash_amount + row.upi_amount) > 0 && (
              <span className="text-xs font-medium text-success">+₹{(row.cash_amount + row.upi_amount).toLocaleString()}</span>
            )}
          </div>
        </div>
        <div className="flex items-center justify-between mt-1 text-[11px]">
          <span className={row.outstanding > 0 ? "text-destructive" : row.outstanding < 0 ? "text-success" : "text-muted-foreground"}>
            Bal: {row.outstanding < 0 ? "-" : ""}₹{Math.abs(row.outstanding).toLocaleString()}
          </span>
          {p && <span className="text-muted-foreground">{p.full_name}</span>}
        </div>
      </div>
    );
  };

  return (
    <>
      {ledgerEntries.length === 0 ? (
        <div className="rounded-xl border border-dashed bg-card p-10 text-center text-muted-foreground">
          No ledger entries yet
        </div>
      ) : (
        <>
          <DataTable
            columns={columns}
            data={ledgerEntries}
            searchKey="display_id"
            searchPlaceholder="Search by ID..."
            onRowClick={(row: any) => setSelectedEntryId(row.id)}
            renderMobileCard={renderMobileCard}
          />
        </>
      )}

      {/* Entry Detail Dialog */}
      <Dialog open={!!selectedEntryId} onOpenChange={(v) => { if (!v) setSelectedEntryId(null); }}>
        <DialogContent className="max-w-md">
          <DialogHeader>
            <DialogTitle>
              {selectedEntry?.type === "sale" ? "Sale Details" : selectedEntry?.type === "payment" ? "Payment Details" : "Entry Details"}
            </DialogTitle>
          </DialogHeader>
          {selectedEntry && (
            <div className="space-y-4">
              <div className="flex items-center justify-between">
                <span className="font-mono text-sm text-muted-foreground">{selectedEntry.display_id}</span>
                <span className="text-xs text-muted-foreground">
                  {new Date(selectedEntry.date).toLocaleString("en-IN", { dateStyle: "medium", timeStyle: "short" })}
                </span>
              </div>
              <div className="rounded-lg border bg-muted/30 p-3 space-y-1 text-sm">
                <div className="flex justify-between">
                  <span>Total</span>
                  <span className="font-bold">₹{selectedEntry.total_amount.toLocaleString()}</span>
                </div>
                <div className="flex justify-between">
                  <span>Cash</span>
                  <span>₹{selectedEntry.cash_amount.toLocaleString()}</span>
                </div>
                <div className="flex justify-between">
                  <span>UPI</span>
                  <span>₹{selectedEntry.upi_amount.toLocaleString()}</span>
                </div>
                <div className="flex justify-between font-medium">
                  <span>Balance After</span>
                  <span className={selectedEntry.outstanding < 0 ? "text-destructive" : ""}>
                    ₹{Math.abs(selectedEntry.outstanding).toLocaleString()}
                  </span>
                </div>
              </div>

              {selectedEntry.notes && (
                <div className="rounded-lg border p-3">
                  <p className="text-xs text-muted-foreground mb-1">Notes</p>
                  <p className="text-sm italic">{selectedEntry.notes}</p>
                </div>
              )}

              {/* Sale items */}
              {isSaleSelected && (
                <div>
                  <p className="text-sm font-medium mb-2 flex items-center gap-1.5">
                    <Package className="h-4 w-4 text-muted-foreground" /> Items
                  </p>
                  {loadingSaleItems ? (
                    <div className="flex justify-center py-4">
                      <Loader2 className="h-5 w-5 animate-spin text-muted-foreground" />
                    </div>
                  ) : saleItems && saleItems.length > 0 ? (
                    <div className="space-y-1.5">
                      {saleItems.map((item: any) => (
                        <div key={item.id} className="flex items-center justify-between rounded-lg border bg-card p-2.5 text-sm">
                          <div>
                            <p className="font-medium">{item.products?.name || "—"}</p>
                            <p className="text-[11px] text-muted-foreground">{item.products?.sku} · Qty: {Number(item.quantity)}</p>
                          </div>
                          <div className="text-right">
                            <p className="font-semibold">₹{Number(item.total_price).toLocaleString()}</p>
                            <p className="text-[11px] text-muted-foreground">@ ₹{Number(item.unit_price).toLocaleString()}</p>
                          </div>
                        </div>
                      ))}
                    </div>
                  ) : (
                    <p className="text-xs text-muted-foreground">No items recorded</p>
                  )}
                </div>
              )}

              {(() => {
                const p = getRecorder(selectedEntry.recorded_by);
                return p ? (
                  <div className="flex items-center gap-2 pt-2 border-t">
                    <Avatar className="h-5 w-5">
                      <AvatarImage src={p?.avatar_url || undefined} />
                      <AvatarFallback className="text-[9px] bg-primary/10 text-primary">
                        {(p?.full_name || "?").charAt(0)}
                      </AvatarFallback>
                    </Avatar>
                    <span className="text-xs text-muted-foreground">Recorded by {p?.full_name || "—"}</span>
                  </div>
                ) : null;
              })()}
            </div>
          )}
        </DialogContent>
      </Dialog>
    </>
  );
}

import { useState } from "react";
import { useQuery, useQueryClient } from "@tanstack/react-query";
import { supabase } from "@/integrations/supabase/client";
import {
  Dialog, DialogContent, DialogHeader, DialogTitle,
} from "@/components/ui/dialog";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import { Loader2, Save } from "lucide-react";
import { toast } from "sonner";

interface StorePricingDialogProps {
  store: any;
  open: boolean;
  onOpenChange: (open: boolean) => void;
}

export function StorePricingDialog({ store, open, onOpenChange }: StorePricingDialogProps) {
  const qc = useQueryClient();
  const [saving, setSaving] = useState(false);
  const [priceMap, setPriceMap] = useState<Record<string, string>>({});

  const { data: products } = useQuery({
    queryKey: ["products-for-store", store?.store_type_id],
    queryFn: async () => {
      // Get products accessible to this store type
      const { data: accessData } = await supabase
        .from("store_type_products")
        .select("product_id, products(id, name, sku, base_price)")
        .eq("store_type_id", store.store_type_id);

      if (accessData && accessData.length > 0) {
        return accessData.map((a: any) => a.products).filter(Boolean);
      }
      // If no access matrix, show all active products
      const { data } = await supabase.from("products").select("id, name, sku, base_price").eq("is_active", true).order("name");
      return data || [];
    },
    enabled: !!store,
  });

  const { data: typePricing } = useQuery({
    queryKey: ["store-type-pricing-for", store?.store_type_id],
    queryFn: async () => {
      const { data } = await supabase.from("store_type_pricing").select("product_id, price").eq("store_type_id", store.store_type_id);
      const map: Record<string, number> = {};
      data?.forEach((p) => { map[p.product_id] = Number(p.price); });
      return map;
    },
    enabled: !!store,
  });

  const { data: storePricing, isLoading } = useQuery({
    queryKey: ["store-pricing", store?.id],
    queryFn: async () => {
      const { data } = await supabase.from("store_pricing").select("product_id, price").eq("store_id", store.id);
      const map: Record<string, number> = {};
      data?.forEach((p) => { map[p.product_id] = Number(p.price); });
      return map;
    },
    enabled: !!store,
  });

  if (!store) return null;

  const getStorePrice = (productId: string) => {
    if (productId in priceMap) return priceMap[productId];
    if (storePricing && productId in storePricing) return String(storePricing[productId]);
    return "";
  };

  const getEffectivePrice = (product: any) => {
    const storeP = getStorePrice(product.id);
    if (storeP && Number(storeP) > 0) return `₹${Number(storeP).toLocaleString()} (store)`;
    if (typePricing && product.id in typePricing) return `₹${typePricing[product.id].toLocaleString()} (type)`;
    return `₹${Number(product.base_price).toLocaleString()} (base)`;
  };

  const handleSave = async () => {
    setSaving(true);
    await supabase.from("store_pricing").delete().eq("store_id", store.id);
    const inserts = (products || [])
      .filter((p: any) => {
        const val = getStorePrice(p.id);
        return val !== "" && Number(val) > 0;
      })
      .map((p: any) => ({
        store_id: store.id,
        product_id: p.id,
        price: Number(getStorePrice(p.id)),
      }));
    if (inserts.length > 0) {
      await supabase.from("store_pricing").insert(inserts);
    }
    setSaving(false);
    toast.success("Store pricing saved");
    qc.invalidateQueries({ queryKey: ["store-pricing", store.id] });
    setPriceMap({});
  };

  return (
    <Dialog open={open} onOpenChange={onOpenChange}>
      <DialogContent className="max-w-lg">
        <DialogHeader>
          <DialogTitle>Pricing — {store.name}</DialogTitle>
        </DialogHeader>
        {isLoading ? (
          <div className="flex items-center justify-center py-8"><Loader2 className="h-6 w-6 animate-spin" /></div>
        ) : (
          <div className="space-y-3 max-h-96 overflow-y-auto">
            {products?.map((p: any) => (
              <div key={p.id} className="flex items-center justify-between gap-3 rounded-lg border p-3">
                <div className="min-w-0 flex-1">
                  <p className="text-sm font-medium truncate">{p.name}</p>
                  <div className="flex items-center gap-2 mt-0.5">
                    <Badge variant="outline" className="text-[10px]">{p.sku}</Badge>
                    <span className="text-xs text-muted-foreground">{getEffectivePrice(p)}</span>
                  </div>
                </div>
                <Input
                  type="number"
                  value={getStorePrice(p.id)}
                  onChange={(e) => setPriceMap({ ...priceMap, [p.id]: e.target.value })}
                  placeholder="—"
                  className="w-24 h-8 text-sm"
                />
              </div>
            ))}
          </div>
        )}
        <Button onClick={handleSave} disabled={saving} className="w-full">
          {saving ? <Loader2 className="mr-2 h-4 w-4 animate-spin" /> : <Save className="mr-2 h-4 w-4" />}
          Save Store Pricing
        </Button>
      </DialogContent>
    </Dialog>
  );
}

import { useQuery } from "@tanstack/react-query";
import { supabase } from "@/integrations/supabase/client";
import { Checkbox } from "@/components/ui/checkbox";
import { ScrollArea, ScrollBar } from "@/components/ui/scroll-area";
import { Badge } from "@/components/ui/badge";
import { Loader2 } from "lucide-react";
import { toast } from "sonner";
import { useState, useCallback } from "react";

import type { Database } from "@/integrations/supabase/types";
type AppRole = Database["public"]["Enums"]["app_role"];
const STAFF_ROLES: AppRole[] = ["manager", "agent", "marketer", "pos"];

const ROLE_BADGE: Record<string, string> = {
  manager: "bg-purple-500/15 text-purple-600 dark:text-purple-400",
  agent: "bg-blue-500/15 text-blue-600 dark:text-blue-400",
  marketer: "bg-emerald-500/15 text-emerald-600 dark:text-emerald-400",
  pos: "bg-orange-500/15 text-orange-600 dark:text-orange-400",
};

// Optimistically track toggling to avoid full refetch flicker
function useAccessMatrix() {
  const [toggling, setToggling] = useState<Set<string>>(new Set());

  const { data: routes, isLoading: routesLoading } = useQuery({
    queryKey: ["routes-access-matrix"],
    queryFn: async () => {
      const { data } = await supabase
        .from("routes")
        .select("id, name, store_type_id, store_types(id, name)")
        .eq("is_active", true)
        .order("name");
      return data || [];
    },
  });

  const { data: staffUsers, isLoading: usersLoading } = useQuery({
    queryKey: ["staff-for-access-matrix"],
    queryFn: async () => {
      const { data: rolesData } = await supabase
        .from("user_roles")
        .select("user_id, role")
        .in("role", STAFF_ROLES);
      const userIds = rolesData?.map((r) => r.user_id) || [];
      if (userIds.length === 0) return [];
      const { data: profiles } = await supabase
        .from("profiles")
        .select("user_id, full_name, is_active")
        .in("user_id", userIds)
        .eq("is_active", true)
        .order("full_name");
      const roleMap = new Map(rolesData?.map((r) => [r.user_id, r.role]));
      return (profiles || []).map((p) => ({ ...p, role: roleMap.get(p.user_id) || "agent" }));
    },
  });

  const { data: accessRecords, refetch: refetchAccess } = useQuery({
    queryKey: ["agent-routes-matrix"],
    queryFn: async () => {
      const { data } = await supabase.from("agent_routes").select("user_id, route_id, enabled");
      return data || [];
    },
  });

  const isEnabled = useCallback(
    (userId: string, routeId: string) =>
      (accessRecords || []).some((r) => r.user_id === userId && r.route_id === routeId && r.enabled),
    [accessRecords]
  );

  const handleToggle = async (userId: string, routeId: string) => {
    const key = `${userId}:${routeId}`;
    if (toggling.has(key)) return;
    setToggling((prev) => new Set(prev).add(key));
    const current = isEnabled(userId, routeId);
    const { error } = await supabase
      .from("agent_routes")
      .upsert(
        { user_id: userId, route_id: routeId, enabled: !current },
        { onConflict: "user_id,route_id" }
      );
    if (error) toast.error(error.message);
    else await refetchAccess();
    setToggling((prev) => { const s = new Set(prev); s.delete(key); return s; });
  };

  // Group routes by store type, preserving insertion order
  const storeTypeGroups: { id: string; name: string; routes: typeof routes }[] = [];
  const seenTypes = new Map<string, number>();
  (routes || []).forEach((route) => {
    const typeId = route.store_type_id;
    const typeName = (route.store_types as any)?.name || "Unknown";
    if (!seenTypes.has(typeId)) {
      seenTypes.set(typeId, storeTypeGroups.length);
      storeTypeGroups.push({ id: typeId, name: typeName, routes: [] });
    }
    storeTypeGroups[seenTypes.get(typeId)!].routes.push(route);
  });

  return { routes, staffUsers, isEnabled, handleToggle, toggling, storeTypeGroups, isLoading: routesLoading || usersLoading };
}

export function StoreTypeAccessMatrix() {
  const { staffUsers, isEnabled, handleToggle, toggling, storeTypeGroups, isLoading } = useAccessMatrix();

  if (isLoading) {
    return (
      <div className="flex items-center justify-center py-24">
        <Loader2 className="h-8 w-8 animate-spin text-primary" />
      </div>
    );
  }

  if (!staffUsers || staffUsers.length === 0) {
    return (
      <div className="rounded-xl border bg-card p-12 text-center text-muted-foreground">
        No active staff users found. Invite staff from Access Control to configure access.
      </div>
    );
  }

  if (storeTypeGroups.length === 0) {
    return (
      <div className="rounded-xl border bg-card p-12 text-center text-muted-foreground">
        No active routes found. Create routes first before configuring access.
      </div>
    );
  }

  const totalRouteCount = storeTypeGroups.reduce((s, g) => s + g.routes.length, 0);

  return (
    <div className="space-y-3">
      <p className="text-sm text-muted-foreground">
        Check a box to grant a staff member access to that route. They will only see and record sales/transactions for stores in their enabled routes.
      </p>

      <div className="text-xs text-muted-foreground flex items-center gap-4 pb-1">
        <span>{staffUsers.length} staff members</span>
        <span>·</span>
        <span>{storeTypeGroups.length} store types</span>
        <span>·</span>
        <span>{totalRouteCount} routes</span>
      </div>

      <ScrollArea className="rounded-xl border bg-card w-full">
        <div className="min-w-max">
          <table className="border-collapse text-sm w-full">
            <thead>
              {/* Row 1 — Store type group headers */}
              <tr className="border-b bg-muted/40">
                <th
                  className="sticky left-0 z-20 bg-muted/40 px-5 py-3 text-left text-xs font-semibold text-muted-foreground min-w-[200px] border-r"
                  rowSpan={2}
                >
                  Staff Member
                </th>
                {storeTypeGroups.map((st, gi) => (
                  <th
                    key={st.id}
                    colSpan={st.routes.length}
                    className={`px-3 py-2.5 text-center text-xs font-semibold ${gi < storeTypeGroups.length - 1 ? "border-r" : ""}`}
                  >
                    <span className="inline-flex items-center gap-1 rounded-md bg-primary/10 text-primary px-2.5 py-1 font-semibold">
                      {st.name}
                    </span>
                  </th>
                ))}
              </tr>

              {/* Row 2 — Route sub-headers */}
              <tr className="border-b bg-muted/20">
                {storeTypeGroups.map((st, gi) =>
                  st.routes.map((route, ri) => (
                    <th
                      key={route.id}
                      className={`px-3 py-2 text-center text-[11px] font-medium text-muted-foreground min-w-[120px] whitespace-nowrap ${
                        ri === st.routes.length - 1 && gi < storeTypeGroups.length - 1
                          ? "border-r"
                          : ri < st.routes.length - 1
                          ? "border-r border-border/30"
                          : ""
                      }`}
                    >
                      {route.name}
                    </th>
                  ))
                )}
              </tr>
            </thead>

            <tbody>
              {staffUsers.map((staff, idx) => (
                <tr
                  key={staff.user_id}
                  className={`border-b last:border-0 hover:bg-accent/30 transition-colors ${
                    idx % 2 === 1 ? "bg-muted/10" : ""
                  }`}
                >
                  {/* Sticky name cell */}
                  <td
                    className="sticky left-0 z-10 border-r px-5 py-3 min-w-[200px]"
                    style={{ background: idx % 2 === 1 ? "hsl(var(--muted) / 0.1)" : "hsl(var(--background))" }}
                  >
                    <div className="flex items-center gap-2.5">
                      <div className="min-w-0">
                        <p className="text-sm font-medium leading-tight truncate max-w-[140px]">
                          {staff.full_name || "—"}
                        </p>
                        <span
                          className={`mt-0.5 inline-block text-[10px] uppercase font-bold px-1.5 py-0.5 rounded leading-none ${
                            ROLE_BADGE[staff.role] || ""
                          }`}
                        >
                          {staff.role}
                        </span>
                      </div>
                    </div>
                  </td>

                  {/* One checkbox cell per route */}
                  {storeTypeGroups.map((st, gi) =>
                    st.routes.map((route, ri) => {
                      const key = `${staff.user_id}:${route.id}`;
                      const enabled = isEnabled(staff.user_id, route.id);
                      const busy = toggling.has(key);
                      return (
                        <td
                          key={route.id}
                          className={`px-3 py-3 text-center ${
                            ri === st.routes.length - 1 && gi < storeTypeGroups.length - 1
                              ? "border-r"
                              : ri < st.routes.length - 1
                              ? "border-r border-border/30"
                              : ""
                          }`}
                        >
                          <div className="flex items-center justify-center">
                            {busy ? (
                              <Loader2 className="h-3.5 w-3.5 animate-spin text-primary" />
                            ) : (
                              <Checkbox
                                checked={enabled}
                                onCheckedChange={() => handleToggle(staff.user_id, route.id)}
                                className="h-4 w-4 cursor-pointer"
                                aria-label={`${staff.full_name} access to ${route.name}`}
                              />
                            )}
                          </div>
                        </td>
                      );
                    })
                  )}
                </tr>
              ))}
            </tbody>
          </table>
        </div>
        <ScrollBar orientation="horizontal" />
      </ScrollArea>
    </div>
  );
}

import * as React from "react";
import { cva, type VariantProps } from "class-variance-authority";

import { cn } from "@/lib/utils";

const badgeVariants = cva(
  "inline-flex items-center rounded-full border px-2.5 py-0.5 text-xs font-semibold transition-colors focus:outline-none focus:ring-2 focus:ring-ring focus:ring-offset-2",
  {
    variants: {
      variant: {
        default: "border-transparent bg-primary text-primary-foreground hover:bg-primary/80",
        secondary: "border-transparent bg-secondary text-secondary-foreground hover:bg-secondary/80",
        destructive: "border-transparent bg-destructive text-destructive-foreground hover:bg-destructive/80",
        outline: "text-foreground",
      },
    },
    defaultVariants: {
      variant: "default",
    },
  },
);

export interface BadgeProps extends React.HTMLAttributes<HTMLDivElement>, VariantProps<typeof badgeVariants> {}

function Badge({ className, variant, ...props }: BadgeProps) {
  return <div className={cn(badgeVariants({ variant }), className)} {...props} />;
}

export { Badge, badgeVariants };

