import { createContext, useContext, useEffect, useState, ReactNode } from "react";
import { supabase } from "@/integrations/supabase/client";
import type { User, Session } from "@supabase/supabase-js";
import { logError } from "@/lib/logger";

type AppRole = "super_admin" | "manager" | "agent" | "marketer" | "pos" | "customer";

interface AuthContextType {
  user: User | null;
  session: Session | null;
  role: AppRole | null;
  profile: { full_name: string; email: string; avatar_url: string | null } | null;
  customer: { id: string; user_id: string | null; name: string; phone: string | null; email: string | null } | null;
  loading: boolean;
  signOut: () => Promise<void>;
}

const AuthContext = createContext<AuthContextType>({
  user: null,
  session: null,
  role: null,
  profile: null,
  customer: null,
  loading: true,
  signOut: async () => {},
});

export function AuthProvider({ children }: { children: ReactNode }) {
  const [user, setUser] = useState<User | null>(null);
  const [session, setSession] = useState<Session | null>(null);
  const [role, setRole] = useState<AppRole | null>(null);
  const [profile, setProfile] = useState<AuthContextType["profile"]>(null);
  const [customer, setCustomer] = useState<AuthContextType["customer"]>(null);
  const [loading, setLoading] = useState(true);

  const fetchUserData = async (userId: string) => {
    try {
      const [{ data: roleData }, { data: profileData }, { data: customerData }] = await Promise.all([
        supabase.from("user_roles").select("role").eq("user_id", userId).maybeSingle(),
        supabase.from("profiles").select("full_name, email, avatar_url, is_active").eq("user_id", userId).maybeSingle(),
        supabase.from("customers").select("id, user_id, name, phone, email").eq("user_id", userId).maybeSingle(),
      ]);

      // If user is disabled, sign them out immediately
      if (profileData && !profileData.is_active) {
        await supabase.auth.signOut();
        setUser(null);
        setSession(null);
        setRole(null);
        setProfile(null);
        return;
      }

      if (profileData) setProfile(profileData);
      setCustomer(customerData || null);

      if (roleData && roleData.role) {
        setRole(roleData.role as AppRole);
      } else {
        setRole("customer");
      }
    } catch (error) {
      logError("Error fetching user data", error);
      setRole("customer");
      setCustomer(null);
    }
  };

  useEffect(() => {
    let mounted = true;

    const { data: { subscription } } = supabase.auth.onAuthStateChange(
      (_event, session) => {
        if (!mounted) return;
        
        // Always block the UI from rendering auth-dependent routes 
        // until we finish resolving the new auth state.
        setLoading(true);
        setSession(session);
        setUser(session?.user ?? null);

        if (session?.user) {
          // Defer to avoid Supabase deadlock where DB query waits for Auth headers
          setTimeout(async () => {
            if (!mounted) return;
            try {
              await fetchUserData(session.user.id);
            } finally {
              if (mounted) setLoading(false);
            }
          }, 0);
        } else {
          setRole(null);
          setProfile(null);
          setCustomer(null);
          if (mounted) setLoading(false);
        }
      }
    );

    const initAuth = async () => {
      try {
        const { data: { session } } = await supabase.auth.getSession();
        if (!mounted) return;
        
        setSession(session);
        setUser(session?.user ?? null);
        
        if (session?.user) {
          // It's safe to await here since we aren't in the onAuthStateChange lock
          await fetchUserData(session.user.id);
        }
      } catch (error) {
        logError("Auth context initialization error", error);
      } finally {
        if (mounted) setLoading(false);
      }
    };

    initAuth();

    return () => {
      mounted = false;
      subscription.unsubscribe();
    };
  }, []);

  const signOut = async () => {
    await supabase.auth.signOut();
    setUser(null);
    setSession(null);
    setRole(null);
    setProfile(null);
    setCustomer(null);
  };

  return (
    <AuthContext.Provider value={{ user, session, role, profile, customer, loading, signOut }}>
      {children}
    </AuthContext.Provider>
  );
}

export function useAuth() {
  return useContext(AuthContext);
}

import { useState, useEffect, useCallback } from "react";
import { 
  getQueuedActions, 
  removeFromQueue, 
  getQueueCount,
  getQueuedFileUploads,
  removeFileUpload,
  markFileUploadFailed,
  getFileUploadCount,
  arrayBufferToBlob,
  PendingFileUpload,
} from "@/lib/offlineQueue";
import { supabase } from "@/integrations/supabase/client";
import { toast } from "sonner";
import { logError } from "@/lib/logger";

export function useOnlineStatus() {
  const [isOnline, setIsOnline] = useState(navigator.onLine);
  const [pendingCount, setPendingCount] = useState(0);
  const [syncing, setSyncing] = useState(false);

  useEffect(() => {
    const handleOnline = () => setIsOnline(true);
    const handleOffline = () => setIsOnline(false);
    const handleQueueChanged = async () => {
      try {
        const [actionCount, fileCount] = await Promise.all([
          getQueueCount(),
          getFileUploadCount(),
        ]);
        setPendingCount(actionCount + fileCount);
      } catch (err) {
        logError(err, { context: "useOnlineStatus.handleQueueChanged" });
      }
    };
    window.addEventListener("online", handleOnline);
    window.addEventListener("offline", handleOffline);
    window.addEventListener("offline-queue-changed", handleQueueChanged);
    // Load initial pending count
    handleQueueChanged();
    return () => {
      window.removeEventListener("online", handleOnline);
      window.removeEventListener("offline", handleOffline);
      window.removeEventListener("offline-queue-changed", handleQueueChanged);
    };
  }, []);

  const refreshCount = useCallback(async () => {
    const [actionCount, fileCount] = await Promise.all([
      getQueueCount(),
      getFileUploadCount(),
    ]);
    setPendingCount(actionCount + fileCount);
  }, []);

  /**
   * Sync queued file uploads
   */
  const syncFileUploads = useCallback(async (): Promise<{ synced: number; failed: number }> => {
    const files = await getQueuedFileUploads();
    let synced = 0;
    let failed = 0;

    for (const file of files) {
      try {
        const blob = arrayBufferToBlob(file.fileData, file.contentType);
        
        const { error: uploadErr } = await supabase.storage
          .from(file.bucket)
          .upload(file.path, blob, { upsert: true });

        if (uploadErr) throw uploadErr;

        // For KYC uploads, update the customer record
        if (file.type === "kyc" && file.metadata?.customerId && file.metadata?.field) {
          const { data: urlData } = supabase.storage.from(file.bucket).getPublicUrl(file.path);
          const field = file.metadata.field as string;
          
          // Get current KYC status to determine if we should mark as pending
          const { data: customer } = await supabase
            .from("customers")
            .select("kyc_selfie_url, kyc_aadhar_front_url, kyc_aadhar_back_url")
            .eq("id", file.metadata.customerId)
            .maybeSingle();

          const updated: Record<string, string | null> = { [field]: urlData.publicUrl };
          
          if (customer) {
            const current = {
              kyc_selfie_url: customer.kyc_selfie_url,
              kyc_aadhar_front_url: customer.kyc_aadhar_front_url,
              kyc_aadhar_back_url: customer.kyc_aadhar_back_url,
              [field]: urlData.publicUrl,
            };

            if (current.kyc_selfie_url && current.kyc_aadhar_front_url && current.kyc_aadhar_back_url) {
              updated.kyc_status = "pending";
              updated.kyc_submitted_at = new Date().toISOString();
            }
          }

          const { error: dbErr } = await supabase
            .from("customers")
            .update(updated)
            .eq("id", file.metadata.customerId);
            
          if (dbErr) throw dbErr;
        }

        await removeFileUpload(file.id);
        synced++;
      } catch (err: any) {
        logError(err, { context: "useOnlineStatus.syncFileUploads", fileId: file.id, fileType: file.type });
        const shouldRetry = await markFileUploadFailed(file.id, err.message || "Unknown error");
        if (!shouldRetry) {
          logError(new Error(`File upload ${file.id} exceeded max retries`), { 
            context: "useOnlineStatus.syncFileUploads.maxRetries" 
          });
        }
        failed++;
      }
    }

    return { synced, failed };
  }, []);

  const syncQueue = useCallback(async () => {
    if (syncing || !navigator.onLine) return;
    setSyncing(true);
    
    let totalSynced = 0;
    let totalFailed = 0;
    
    // Sync file uploads first
    const fileResult = await syncFileUploads();
    totalSynced += fileResult.synced;
    totalFailed += fileResult.failed;
    
    // Then sync regular actions
    const actions = await getQueuedActions();

    for (const action of actions) {
      try {
        if (action.type === "sale") {
          const { saleData, saleItems } = action.payload as any;
          const { data: displayId } = await supabase.rpc("generate_display_id", { prefix: "SALE", seq_name: "sale_display_seq" });
          const { error } = await supabase.rpc("record_sale", {
            p_display_id: displayId,
            p_store_id: saleData.store_id,
            p_customer_id: saleData.customer_id,
            p_recorded_by: saleData.recorded_by,
            p_logged_by: saleData.logged_by ?? null,
            p_total_amount: saleData.total_amount,
            p_cash_amount: saleData.cash_amount,
            p_upi_amount: saleData.upi_amount,
            p_outstanding_amount: saleData.outstanding_amount,
            p_sale_items: saleItems,
            p_created_at: saleData.created_at ?? null,
          });
          if (error) throw error;
        } else if (action.type === "transaction") {
          const { txData } = action.payload as any;
          const { data: displayId } = await supabase.rpc("generate_display_id", { prefix: "PAY", seq_name: "pay_display_seq" });
          // Use atomic RPC — server computes outstanding, locks store row
          const { error } = await supabase.rpc("record_transaction", {
            p_display_id: displayId,
            p_store_id: txData.store_id,
            p_customer_id: txData.customer_id,
            p_recorded_by: txData.recorded_by,
            p_logged_by: txData.logged_by ?? null,
            p_cash_amount: txData.cash_amount,
            p_upi_amount: txData.upi_amount,
            p_notes: txData.notes ?? null,
            p_created_at: txData.created_at ?? null,
          });
          if (error) throw error;
        } else if (action.type === "visit") {
          const { userId, storeId, lat, lng } = action.payload as any;
          const { data: session, error: sessionError } = await supabase
            .from("route_sessions")
            .select("id")
            .eq("user_id", userId)
            .eq("status", "active")
            .maybeSingle();
          if (sessionError) throw sessionError;
          if (!session?.id) throw new Error("No active route session available for queued visit");

          const { error } = await supabase.from("store_visits").insert({
            session_id: session.id,
            store_id: storeId,
            lat: lat ?? null,
            lng: lng ?? null,
          });
          if (error) throw error;
        } else if (action.type === "customer") {
          const { customerData } = action.payload as {
            customerData: {
              name: string;
              phone?: string | null;
              email?: string | null;
              address?: string | null;
              photo_url?: string | null;
            };
          };
          const { data: displayId } = await supabase.rpc("generate_display_id", {
            prefix: "CUST",
            seq_name: "customer_display_seq",
          });

          const { error } = await supabase.from("customers").insert({
            display_id: String(displayId),
            name: customerData.name,
            phone: customerData.phone ?? null,
            email: customerData.email ?? null,
            address: customerData.address ?? null,
            photo_url: customerData.photo_url ?? null,
          });
          if (error) throw error;
        }
        await removeFromQueue(action.id);
        totalSynced++;
      } catch (err) {
        logError(err, { context: "useOnlineStatus.syncQueue", actionType: action.type, actionId: action.id });
        totalFailed++;
      }
    }

    setSyncing(false);
    await refreshCount();

    if (totalSynced > 0) toast.success(`Synced ${totalSynced} offline item(s)`);
    if (totalFailed > 0) toast.error(`${totalFailed} item(s) failed to sync`);
  }, [syncing, refreshCount, syncFileUploads]);

  // Auto-sync when coming back online
  useEffect(() => {
    if (isOnline && pendingCount > 0) {
      syncQueue();
    }
  }, [isOnline, pendingCount, syncQueue]);

  return { isOnline, pendingCount, syncing, syncQueue, refreshCount };
}

import { useEffect } from "react";
import { useQueryClient } from "@tanstack/react-query";
import { supabase } from "@/integrations/supabase/client";
import { useAuth } from "@/contexts/AuthContext";

/**
 * Subscribes to Supabase Realtime changes on all key tables
 * and invalidates the relevant React Query caches automatically.
 * Only activates for staff roles (not customers) to limit connections.
 */

const TABLE_QUERY_MAP: Record<string, string[]> = {
  sales: ["sales", "dashboard", "agent-dashboard", "marketer-dashboard", "pos-dashboard"],
  sale_items: ["sales", "sale-items"],
  orders: ["orders", "dashboard", "marketer-dashboard"],
  order_items: ["orders", "order-items"],
  transactions: ["transactions", "dashboard", "agent-dashboard", "marketer-dashboard"],
  stores: ["stores", "dashboard", "store-detail"],
  store_pricing: ["store-pricing", "stores"],
  store_type_pricing: ["store-type-pricing"],
  store_type_products: ["store-type-products"],
  store_visits: ["session-visits", "store-visits"],
  handovers: ["handovers", "dashboard", "agent-dashboard"],
  handover_snapshots: ["handover-snapshots"],
  expense_claims: ["expense-claims", "handovers", "dashboard"],
  customers: ["customers", "dashboard", "customer-detail"],
  products: ["products", "products-active"],
  routes: ["routes", "routes-list-active"],
  route_sessions: ["active-route-session", "route-sessions"],
  balance_adjustments: ["balance-adjustments", "stores"],
  activity_logs: ["activity-logs"],
  user_roles: ["user-roles"],
  profiles: ["profiles", "staff-profiles"],
};

const STAFF_ROLES = ["super_admin", "manager", "agent", "marketer", "pos"];

export function useRealtimeSync() {
  const qc = useQueryClient();
  const { role, user } = useAuth();

  const isStaff = role && STAFF_ROLES.includes(role);
  const isAdmin = role === "super_admin" || role === "manager";

  useEffect(() => {
    if (!isStaff) return;

    const tables = Object.keys(TABLE_QUERY_MAP);

    let channel = supabase.channel("global-realtime-sync");

    tables.forEach((table) => {
      channel = channel.on(
        "postgres_changes",
        { event: "*", schema: "public", table },
        (payload: any) => {
          // For non-admins, skip invalidation if the record belongs to another user
          if (!isAdmin) {
            if (table === "sales" || table === "transactions") {
              const recordedBy = payload.new?.recorded_by ?? payload.old?.recorded_by;
              if (recordedBy && recordedBy !== user?.id) return;
            }
            if (table === "handovers") {
              const sender = payload.new?.user_id ?? payload.old?.user_id;
              const receiver = payload.new?.handed_to ?? payload.old?.handed_to;
              if (sender !== user?.id && receiver !== user?.id) return;
            }
            if (table === "expense_claims") {
              const claimOwner = payload.new?.user_id ?? payload.old?.user_id;
              if (claimOwner && claimOwner !== user?.id) return;
            }
          }
          const keys = TABLE_QUERY_MAP[table] || [];
          keys.forEach((key) => {
            qc.invalidateQueries({ queryKey: [key] });
          });
        }
      );
    });

    channel.subscribe();

    return () => {
      supabase.removeChannel(channel);
    };
  }, [qc, isStaff, isAdmin, user?.id]);
}

