import { toast } from "sonner";

export function getFriendlyErrorMessage(error: any): string {
  if (!error) return "Unknown error occurred";
  
  // Handle object with 'message' property
  const msg = typeof error === "string" ? error : (error.message || error.error_description || JSON.stringify(error));

  // Custom RPC business logic errors
  if (msg.includes("credit_limit_exceeded")) {
    return "Credit limit exceeded. Amount exceeds allowed limit for this store/customer.";
  }
  
  // RLS / Permission errors
  if (error.code === "42501" || msg.includes("permission denied")) {
    return "You do not have permission to perform this action.";
  }

  // Duplicate entry
  if (error.code === "23505" || msg.includes("unique constraint")) {
    if (msg.includes("phone")) return "Phone number is already in use.";
    if (msg.includes("email")) return "Email is already in use.";
    return "This record already exists.";
  }

  // Foreign key (invalid reference)
  if (error.code === "23503") {
    return "Operation failed: Referenced record (store, customer, or product) not found.";
  }

  // Check constraints
  if (error.code === "23514") {
    return "Invalid data provided (check constraint violation).";
  }

  // Network errors
  if (msg.includes("Failed to fetch") || msg.includes("Network request failed") || msg.includes("connection")) {
    return "Network error. Please check your internet connection and try again.";
  }

  // Supabase specific
  if (msg.includes("JWT")) {
    return "Your session has expired. Please sign in again.";
  }

  return msg;
}

export function showErrorToast(error: any) {
  const msg = getFriendlyErrorMessage(error);
  toast.error(msg);
}

/**
 * Production-ready logging utility
 * - Development: Logs to console
 * - Production: Can be extended to send to logging service (Sentry, LogRocket, etc.)
 */

type LogLevel = 'debug' | 'info' | 'warn' | 'error';

interface LogContext {
  [key: string]: unknown;
}

class Logger {
  private isDevelopment = import.meta.env.DEV;
  private isTest = import.meta.env.MODE === 'test';

  private shouldLog(level: LogLevel): boolean {
    // Don't log in tests unless explicitly needed
    if (this.isTest) return false;
    
    // In production, only log warnings and errors
    if (!this.isDevelopment && (level === 'debug' || level === 'info')) {
      return false;
    }
    
    return true;
  }

  private formatMessage(level: LogLevel, message: string, context?: LogContext): string {
    const timestamp = new Date().toISOString();
    const prefix = `[${timestamp}] [${level.toUpperCase()}]`;
    
    if (context && Object.keys(context).length > 0) {
      return `${prefix} ${message} ${JSON.stringify(context)}`;
    }
    
    return `${prefix} ${message}`;
  }

  debug(message: string, context?: LogContext) {
    if (!this.shouldLog('debug')) return;
    
    if (this.isDevelopment) {
      console.debug(this.formatMessage('debug', message, context));
    }
  }

  info(message: string, context?: LogContext) {
    if (!this.shouldLog('info')) return;
    
    if (this.isDevelopment) {
      console.info(this.formatMessage('info', message, context));
    }
  }

  warn(message: string, context?: LogContext) {
    if (!this.shouldLog('warn')) return;
    
    console.warn(this.formatMessage('warn', message, context));
    
    // In production, send to monitoring service
    if (!this.isDevelopment) {
      this.sendToMonitoring('warn', message, context);
    }
  }

  error(message: string, error?: Error | unknown, context?: LogContext) {
    if (!this.shouldLog('error')) return;
    
    const errorContext = {
      ...context,
      error: error instanceof Error ? {
        message: error.message,
        stack: error.stack,
        name: error.name,
      } : error,
    };

    console.error(this.formatMessage('error', message, errorContext));
    
    // In production, send to monitoring service
    if (!this.isDevelopment) {
      this.sendToMonitoring('error', message, errorContext);
    }
  }

  private sendToMonitoring(level: LogLevel, message: string, context?: LogContext) {
    if (typeof window !== 'undefined' && (window as any).Sentry) {
      const sentry = (window as any).Sentry;
      
      if (level === 'error') {
        const error = context?.error instanceof Error 
          ? context.error 
          : new Error(message);
        
        sentry.captureException(error, {
          level: 'error',
          extra: context,
        });
      } else if (level === 'warn') {
        sentry.captureMessage(message, {
          level: 'warning',
          extra: context,
        });
      }
    }
    
    // Fallback/Legacy storage
    if (level === 'error' && !this.isDevelopment) {
      try {
        const errors = JSON.parse(localStorage.getItem('app_errors') || '[]');
        errors.push({
          timestamp: new Date().toISOString(),
          message,
          context,
        });
        localStorage.setItem('app_errors', JSON.stringify(errors.slice(-50)));
      } catch {
        // Silently fail if localStorage is unavailable
      }
    }
  }
}

export const logger = new Logger();

