import { useQuery, useQueryClient } from "@tanstack/react-query";
import { Loader2, HandCoins, CheckCircle2, XCircle, ArrowRight, Clock, Info } from "lucide-react";
import { supabase } from "@/integrations/supabase/client";
import { useAuth } from "@/contexts/AuthContext";
import { cn } from "@/lib/utils";
import { format } from "date-fns";
import { toast } from "sonner";
import { useMemo } from "react";

export function AdminHandovers() {
  const { user } = useAuth();
  const qc = useQueryClient();

  const { data: handovers, isLoading } = useQuery({
    queryKey: ["admin-mobile-handovers"],
    queryFn: async () => {
      const { data, error } = await supabase
        .from("handovers")
        .select("id, user_id, handed_to, cash_amount, upi_amount, status, created_at, notes")
        .order("created_at", { ascending: false })
        .limit(100);
      if (error) throw error;
      return (data as any[]) || [];
    },
    refetchInterval: 60_000,
  });

  const { data: profiles } = useQuery({
    queryKey: ["admin-mobile-profiles"],
    queryFn: async () => {
      const { data } = await supabase.from("profiles").select("user_id, full_name").eq("is_active", true);
      const map = new Map<string, string>();
      (data || []).forEach((p: any) => map.set(p.user_id, p.full_name || "Staff"));
      return map;
    },
  });

  const getName = (id: string) => {
    if (id === user?.id) return "You";
    return profiles?.get(id) || "Staff";
  };

  const pendingCount = useMemo(() => (handovers || []).filter((h: any) => h.status === "awaiting_confirmation").length, [handovers]);

  const statusConfig = (status: string) => {
    if (status === "confirmed") return {
      color: "emerald",
      bgClass: "bg-emerald-50 dark:bg-emerald-500/10",
      textClass: "text-emerald-700 dark:text-emerald-400",
      icon: CheckCircle2
    };
    if (status === "rejected") return {
      color: "red",
      bgClass: "bg-red-50 dark:bg-red-500/10",
      textClass: "text-red-700 dark:text-red-400",
      icon: XCircle
    };
    return {
      color: "amber",
      bgClass: "bg-amber-50 dark:bg-amber-500/10",
      textClass: "text-amber-700 dark:text-amber-400",
      icon: Clock
    };
  };

  const handleAction = async (id: string, action: "confirm" | "reject") => {
    const update = action === "confirm"
      ? { status: "confirmed", confirmed_by: user!.id, confirmed_at: new Date().toISOString() }
      : { status: "rejected", rejected_at: new Date().toISOString() };
    const { error } = await supabase.from("handovers").update(update).eq("id", id);
    if (error) { toast.error(error.message); return; }
    toast.success(action === "confirm" ? "Handover confirmed" : "Handover rejected");
    qc.invalidateQueries({ queryKey: ["admin-mobile-handovers"] });
  };

  return (
    <div className="pb-8 bg-slate-50 dark:bg-[#0f1115] min-h-full">
      {/* Premium Hero Header */}
      <div className="bg-white dark:bg-[#1a1d24] px-5 pt-3 pb-6 rounded-b-[2rem] shadow-sm mb-6 relative overflow-hidden">
        <div className="absolute -top-10 -right-10 w-40 h-40 bg-indigo-500/10 blur-3xl rounded-full pointer-events-none" />
        <div className="absolute top-10 -left-10 w-32 h-32 bg-purple-500/10 blur-3xl rounded-full pointer-events-none" />

        <div className="relative z-10 flex flex-col items-center text-center">
          <p className="text-slate-500 dark:text-slate-400 text-[11px] font-bold uppercase tracking-widest mb-1">Cash Handovers</p>
          <h2 className="text-slate-900 dark:text-white text-5xl font-black tracking-tighter mt-1 mb-2">
            {handovers?.length ?? 0}
          </h2>
          <div className="flex items-center gap-1.5 bg-amber-50 dark:bg-amber-500/10 px-3 py-1.5 rounded-full mt-1 border border-amber-100 dark:border-amber-500/20">
            <span className="h-2 w-2 rounded-full bg-amber-500 animate-pulse" />
            <span className="text-xs font-semibold text-amber-700 dark:text-amber-400">
              {pendingCount} Pending Action
            </span>
          </div>
        </div>
      </div>

      <div className="px-5 space-y-4">
        <div className="flex items-center justify-between px-1 mt-4 mb-2">
          <h3 className="text-[15px] font-bold text-slate-800 dark:text-slate-100 tracking-tight">Recent Activity</h3>
        </div>

        {isLoading ? (
          <div className="flex justify-center py-10">
            <Loader2 className="h-6 w-6 animate-spin text-indigo-500" />
          </div>
        ) : (handovers?.length ?? 0) === 0 ? (
           <div className="bg-white dark:bg-[#1a1d24] rounded-2xl py-12 text-center shadow-sm">
            <div className="h-14 w-14 bg-slate-50 dark:bg-slate-800 rounded-full flex items-center justify-center mx-auto mb-3">
              <HandCoins className="h-6 w-6 text-slate-300 dark:text-slate-500" />
            </div>
            <p className="text-sm font-semibold text-slate-900 dark:text-white">No handovers found</p>
            <p className="text-xs text-slate-500 mt-1">There are no recent cash handover requests.</p>
          </div>
        ) : (
          <div className="space-y-4">
            {(handovers || []).map((h: any) => {
              const total = Number(h.cash_amount || 0) + Number(h.upi_amount || 0);
              const canAct = h.handed_to === user?.id && h.status === "awaiting_confirmation";
              const config = statusConfig(h.status);
              const StatusIcon = config.icon;

              return (
                <div 
                  key={h.id} 
                  className={cn(
                    "rounded-2xl shadow-sm p-4 transition-all relative overflow-hidden border",
                    canAct 
                      ? "bg-white dark:bg-[#1a1d24] border-indigo-200 dark:border-indigo-500/30 ring-1 ring-indigo-500/10 dark:ring-indigo-500/20" 
                      : "bg-white dark:bg-[#1a1d24] border-slate-100 dark:border-slate-800 border-transparent hover:border-slate-200 dark:hover:border-slate-700"
                  )}
                >
                  {canAct && (
                    <div className="absolute top-0 right-0 w-16 h-16 bg-gradient-to-bl from-indigo-500/10 to-transparent pointer-events-none" />
                  )}

                  <div className="flex items-start justify-between gap-3 mb-4">
                    <div className="flex-1 min-w-0 pr-2">
                      <div className="flex items-center gap-3">
                        <div className="flex items-center gap-2 mb-1 bg-slate-50 dark:bg-slate-800/50 px-2.5 py-1.5 rounded-lg border border-slate-100 dark:border-slate-800">
                          <p className="text-sm font-bold text-slate-700 dark:text-slate-200 truncate max-w-[100px]">{getName(h.user_id)}</p>
                          <ArrowRight className="h-3.5 w-3.5 text-slate-400 shrink-0" />
                          <p className="text-sm font-bold text-slate-900 dark:text-white truncate max-w-[100px]">{getName(h.handed_to)}</p>
                        </div>
                      </div>

                      {h.notes && (
                        <p className="text-[13px] text-slate-500 dark:text-slate-400 mt-2 flex items-start gap-1.5">
                          <Info className="h-3 w-3 mt-0.5 shrink-0" />
                          <span className="line-clamp-2 italic">"{h.notes}"</span>
                        </p>
                      )}
                    </div>

                    <div className="text-right shrink-0">
                      <p className="text-xl font-black text-slate-900 dark:text-white tracking-tight">
                        ₹{total.toLocaleString("en-IN")}
                      </p>
                      <div className={cn("inline-flex items-center gap-1.5 px-2 py-0.5 rounded-md mt-1", config.bgClass, config.textClass)}>
                        <StatusIcon className="h-3 w-3" />
                        <span className="text-[9px] font-bold uppercase tracking-widest">{h.status.replaceAll("_", " ")}</span>
                      </div>
                    </div>
                  </div>

                  <div className="pt-3 border-t border-slate-100 dark:border-slate-800/50 flex flex-col gap-3">
                    <p className="text-[11px] font-medium text-slate-400 flex items-center gap-1.5">
                      <Clock className="h-3 w-3" />
                      {format(new Date(h.created_at), "dd MMM yyyy • hh:mm a")}
                    </p>

                    {canAct && (
                      <div className="flex items-center gap-3 pt-1">
                        <button 
                          onClick={() => handleAction(h.id, "reject")}
                          className="flex-1 h-11 rounded-xl bg-slate-50 dark:bg-slate-800 text-slate-700 dark:text-slate-300 font-bold text-sm border border-slate-200 dark:border-slate-700 active:scale-95 transition-all flex items-center justify-center gap-2"
                        >
                          <XCircle className="h-4 w-4 text-slate-400" />
                          Reject
                        </button>
                        <button 
                          onClick={() => handleAction(h.id, "confirm")}
                          className="flex-1 h-11 rounded-xl bg-indigo-600 dark:bg-indigo-500 text-white font-bold text-sm shadow-md shadow-indigo-500/20 active:scale-95 transition-all flex items-center justify-center gap-2"
                        >
                          <CheckCircle2 className="h-4 w-4 text-indigo-200" />
                          Confirm
                        </button>
                      </div>
                    )}
                  </div>
                </div>
              );
            })}
          </div>
        )}
      </div>
    </div>
  );
}

import { useState } from "react";
import { useQuery, useQueryClient } from "@tanstack/react-query";
import { Search, X, ClipboardList, Clock, CheckCircle2, Truck, XCircle, Package, Loader2 } from "lucide-react";
import { supabase } from "@/integrations/supabase/client";
import { cn } from "@/lib/utils";
import { format } from "date-fns";
import { toast } from "sonner";
import { MobileListSkeleton } from "@/components/shared/MobileListSkeleton";
import { OrderFulfillmentDialog } from "@/components/orders/OrderFulfillmentDialog";
import { Button } from "@/components/ui/button";

const STATUS_CONFIG: Record<string, { color: string; icon: React.ElementType }> = {
  pending: { color: "amber", icon: Clock },
  confirmed: { color: "blue", icon: CheckCircle2 },
  delivered: { color: "emerald", icon: Truck },
  cancelled: { color: "red", icon: XCircle },
};

// Type for order fulfillment
interface FulfillOrder {
  id: string;
  display_id: string;
  store_id: string;
  customer_id: string | null;
  order_type: "simple" | "detailed";
  status: string;
  requirement_note: string | null;
  order_items?: Array<{
    id: string;
    product_id: string;
    quantity: number;
    unit_price: number | null;
    products?: {
      id: string;
      name: string;
      sku: string;
      base_price: number;
      image_url?: string;
    };
  }>;
  stores?: {
    id: string;
    name: string;
    store_type_id: string | null;
    customer_id: string | null;
  };
}

export function AdminOrders() {
  const qc = useQueryClient();
  const [search, setSearch] = useState("");
  const [statusFilter, setStatusFilter] = useState<string>("all");
  const [fulfillOrder, setFulfillOrder] = useState<FulfillOrder | null>(null);
  const [loadingOrderId, setLoadingOrderId] = useState<string | null>(null);

  const { data: orders, isLoading } = useQuery({
    queryKey: ["admin-mobile-orders"],
    queryFn: async () => {
      const { data, error } = await supabase
        .from("orders")
        .select("id, display_id, status, requirement_note, created_at, stores(name), customers(name)")
        .order("created_at", { ascending: false })
        .limit(100);
      if (error) throw error;
      return (data as any[]) || [];
    },
    refetchInterval: 60_000,
  });

  const statusCounts = (orders || []).reduce((acc: Record<string, number>, o: any) => {
    acc[o.status] = (acc[o.status] || 0) + 1;
    return acc;
  }, {});

  const filtered = (orders || []).filter((o: any) => {
    const matchStatus = statusFilter === "all" || o.status === statusFilter;
    if (!search) return matchStatus;
    const q = search.toLowerCase();
    return matchStatus && (
      o.display_id?.toLowerCase().includes(q) ||
      o.stores?.name?.toLowerCase().includes(q) ||
      o.customers?.name?.toLowerCase().includes(q)
    );
  });

  // Open fulfillment dialog for an order
  const handleOpenFulfillment = async (orderId: string) => {
    setLoadingOrderId(orderId);
    try {
      const { data: orderData, error } = await supabase
        .from("orders")
        .select(`
          *,
          stores(id, name, store_type_id, customer_id),
          order_items(id, product_id, quantity, unit_price, products(id, name, sku, base_price, image_url))
        `)
        .eq("id", orderId)
        .single();

      if (error) throw error;
      setFulfillOrder(orderData as unknown as FulfillOrder);
    } catch (error) {
      toast.error("Failed to load order details");
    } finally {
      setLoadingOrderId(null);
    }
  };

  return (
    <div className="pb-8 bg-slate-50 dark:bg-[#0f1115] min-h-full">
      {/* Premium Hero Header */}
      <div className="bg-white dark:bg-[#1a1d24] px-5 pt-3 pb-6 rounded-b-[2rem] shadow-sm mb-6 relative overflow-hidden">
        <div className="absolute -top-10 -right-10 w-40 h-40 bg-orange-500/10 blur-3xl rounded-full pointer-events-none" />
        <div className="absolute top-10 -left-10 w-32 h-32 bg-amber-500/10 blur-3xl rounded-full pointer-events-none" />

        <div className="relative z-10 flex flex-col items-center text-center">
          <p className="text-slate-500 dark:text-slate-400 text-[11px] font-bold uppercase tracking-widest mb-1">Total Orders</p>
          <h2 className="text-slate-900 dark:text-white text-5xl font-black tracking-tighter mt-1 mb-2">
            {orders?.length ?? 0}
          </h2>
          <div className="flex flex-wrap justify-center gap-2 mt-2">
            {Object.entries(statusCounts).map(([status, count]) => {
               if (!count) return null;
               const config = STATUS_CONFIG[status] || { color: "slate", icon: Clock };
               const colorClasses = {
                 amber: "text-amber-700 bg-amber-100 dark:text-amber-400 dark:bg-amber-500/20",
                 blue: "text-blue-700 bg-blue-100 dark:text-blue-400 dark:bg-blue-500/20",
                 emerald: "text-emerald-700 bg-emerald-100 dark:text-emerald-400 dark:bg-emerald-500/20",
                 red: "text-red-700 bg-red-100 dark:text-red-400 dark:bg-red-500/20",
               }[config.color as keyof typeof STATUS_CONFIG | "slate"];

               return (
                 <span key={status} className={cn("text-[10px] font-bold uppercase tracking-wider px-2 py-0.5 rounded-md", colorClasses)}>
                   {status}: {String(count)}
                 </span>
               );
            })}
          </div>
        </div>
      </div>

      <div className="px-5 space-y-4">
        {/* Modern floating search bar */}
        <div className="bg-white dark:bg-[#1a1d24] rounded-2xl p-2 shadow-sm flex items-center pr-3 border-transparent focus-within:border-orange-500 dark:focus-within:border-orange-500 transition-colors border">
          <Search className="h-5 w-5 text-slate-400 ml-2 shrink-0" />
          <input
            value={search}
            onChange={(e) => setSearch(e.target.value)}
            placeholder="Search store, customer, or ID..."
            className="flex-1 bg-transparent border-none focus:ring-0 text-sm px-3 h-10 text-slate-900 dark:text-white placeholder:text-slate-400"
          />
          {search && (
            <button onClick={() => setSearch("")} className="h-8 w-8 flex items-center justify-center bg-slate-100 dark:bg-slate-800 rounded-full active:scale-95 transition-transform shrink-0">
              <X className="h-4 w-4 text-slate-500" />
            </button>
          )}
        </div>

        {/* Status filter pills */}
        <div className="flex gap-2 overflow-x-auto pb-2 pt-1 scrollbar-hide -mx-5 px-5 snap-x">
          {["all", "pending", "confirmed", "delivered", "cancelled"].map((s) => {
            const isSelected = statusFilter === s;
            const count = s === "all" ? orders?.length ?? 0 : statusCounts[s] || 0;

            return (
              <button
                key={s}
                onClick={() => setStatusFilter(s)}
                className={cn(
                  "snap-start px-4 py-2 rounded-xl text-[13px] font-bold tracking-tight whitespace-nowrap transition-all active:scale-95 shadow-sm border",
                  isSelected
                    ? "bg-orange-500 text-white border-orange-500 dark:bg-orange-600 dark:border-orange-600"
                    : "bg-white dark:bg-[#1a1d24] text-slate-600 dark:text-slate-300 border-slate-100 dark:border-slate-800"
                )}
              >
                {s === "all" ? "All Orders" : s.charAt(0).toUpperCase() + s.slice(1)} <span className={cn("ml-1.5 px-1.5 py-0.5 rounded-md text-[10px]", isSelected ? "bg-white/20 text-white" : "bg-slate-100 dark:bg-slate-800 text-slate-400")}>{count}</span>
              </button>
            )
          })}
        </div>

        <div className="flex items-center justify-between px-1 mt-2 mb-2">
          <h3 className="text-[15px] font-bold text-slate-800 dark:text-slate-100 tracking-tight">Order Records</h3>
          <span className="text-[11px] font-semibold text-slate-400 uppercase tracking-widest">{filtered.length} found</span>
        </div>

        {isLoading ? (
          <MobileListSkeleton items={6} showStats={false} titleWidth="w-40" />
        ) : filtered.length === 0 ? (
          <div className="bg-white dark:bg-[#1a1d24] rounded-2xl py-12 text-center shadow-sm">
            <div className="h-14 w-14 bg-slate-50 dark:bg-slate-800 rounded-full flex items-center justify-center mx-auto mb-3">
              <ClipboardList className="h-6 w-6 text-slate-300 dark:text-slate-500" />
            </div>
            <p className="text-sm font-semibold text-slate-900 dark:text-white">No orders found</p>
            <p className="text-xs text-slate-500 mt-1">Change your filters or search</p>
          </div>
        ) : (
          <div className="space-y-3">
            {filtered.map((order: any) => {
              const config = STATUS_CONFIG[order.status] || { color: "slate", icon: Clock };
              const StatusIcon = config.icon;

              const colorClasses = {
                 amber: "text-amber-700 bg-amber-50 dark:text-amber-400 dark:bg-amber-500/10",
                 blue: "text-blue-700 bg-blue-50 dark:text-blue-400 dark:bg-blue-500/10",
                 emerald: "text-emerald-700 bg-emerald-50 dark:text-emerald-400 dark:bg-emerald-500/10",
                 red: "text-red-700 bg-red-50 dark:text-red-400 dark:bg-red-500/10",
                 slate: "text-slate-700 bg-slate-50 dark:text-slate-400 dark:bg-slate-500/10",
               }[config.color as keyof typeof STATUS_CONFIG | "slate"];

              return (
                <div 
                  key={order.id} 
                  className="bg-white dark:bg-[#1a1d24] rounded-2xl shadow-sm p-4 active:scale-[0.98] transition-all border border-transparent hover:border-slate-100 dark:hover:border-slate-800"
                >
                  <div className="flex justify-between items-start mb-2">
                    <div className="flex-1 min-w-0 pr-3">
                      <h4 className="text-[15px] font-bold text-slate-900 dark:text-white truncate">
                        {order.stores?.name ?? "Store"}
                      </h4>
                      <p className="text-xs text-slate-500 dark:text-slate-400 truncate mt-0.5">
                        {order.customers?.name ?? "Customer"}
                      </p>
                    </div>
                    <div className={cn("inline-flex items-center gap-1.5 px-2 py-1 rounded-md shrink-0", colorClasses)}>
                      <StatusIcon className="h-3 w-3" />
                      <span className="text-[10px] font-bold tracking-widest uppercase">
                        {order.status}
                      </span>
                    </div>
                  </div>

                  {order.requirement_note && (
                    <div className="bg-slate-50 dark:bg-slate-800/50 p-2.5 rounded-xl mb-3 mt-2 border border-slate-100 dark:border-slate-800">
                      <p className="text-xs text-slate-600 dark:text-slate-300 italic line-clamp-2">
                        "{order.requirement_note}"
                      </p>
                    </div>
                  )}

                  <div className="pt-3 mt-1 border-t border-slate-100 dark:border-slate-800/50 flex items-end justify-between">
                    <div className="flex items-center gap-1.5 text-[11px] text-slate-400 font-medium tracking-tight">
                      <Clock className="h-3.5 w-3.5" />
                      {format(new Date(order.created_at), "dd MMM, hh:mm a")}
                    </div>

                    <div className="flex items-center gap-2 shrink-0">
                      {order.status === "pending" && (
                        <Button 
                          size="sm" 
                          className="h-7 text-xs rounded-lg"
                          onClick={() => handleOpenFulfillment(order.id)}
                          disabled={loadingOrderId === order.id}
                        >
                          {loadingOrderId === order.id ? (
                            <Loader2 className="h-3.5 w-3.5 mr-1 animate-spin" />
                          ) : (
                            <Package className="h-3.5 w-3.5 mr-1" />
                          )}
                          Fulfill
                        </Button>
                      )}
                      <span className="text-[10px] font-bold text-slate-400 tracking-widest uppercase bg-slate-100 dark:bg-slate-800 px-1.5 py-0.5 rounded">
                        {order.display_id}
                      </span>
                    </div>
                  </div>
                </div>
              );
            })}
          </div>
        )}
      </div>

      {/* Order Fulfillment Dialog */}
      <OrderFulfillmentDialog
        order={fulfillOrder}
        open={!!fulfillOrder}
        onOpenChange={(open) => { if (!open) setFulfillOrder(null); }}
        onFulfilled={() => {
          qc.invalidateQueries({ queryKey: ["admin-mobile-orders"] });
          qc.invalidateQueries({ queryKey: ["orders"] });
          qc.invalidateQueries({ queryKey: ["sales"] });
        }}
      />
    </div>
  );
}

import { useState } from "react";
import { useQuery } from "@tanstack/react-query";
import { Search, X, Loader2, Package, ScanLine, Tag, IndianRupee } from "lucide-react";
import { Sheet, SheetContent } from "@/components/ui/sheet";
import { supabase } from "@/integrations/supabase/client";
import { cn } from "@/lib/utils";

export function AdminProducts() {
  const [search, setSearch] = useState("");
  const [categoryFilter, setCategoryFilter] = useState<string | null>(null);
  const [selectedProduct, setSelectedProduct] = useState<any>(null);

  const { data: products, isLoading } = useQuery({
    queryKey: ["admin-mobile-products"],
    queryFn: async () => {
      const { data, error } = await supabase
        .from("products")
        .select("*, product_categories(name)")
        .eq("is_active", true)
        .order("name");
      if (error) throw error;
      const { data: stockData } = await (supabase as any).from("product_stock").select("product_id, quantity");
      const stockMap: Record<string, number> = {};
      stockData?.forEach((item: any) => { stockMap[item.product_id] = (stockMap[item.product_id] || 0) + Number(item.quantity); });
      return (data || []).map((p: any) => ({ ...p, stock_quantity: stockMap[p.id] || 0 }));
    },
    staleTime: 300_000,
  });

  const { data: categories } = useQuery({
    queryKey: ["admin-mobile-product-categories"],
    queryFn: async () => {
      const { data } = await supabase.from("product_categories").select("id, name").order("name");
      return data || [];
    },
    staleTime: 3600_000,
  });

  const filtered = (products || []).filter((p: any) => {
    const matchSearch = !search || p.name.toLowerCase().includes(search.toLowerCase()) || p.sku?.toLowerCase().includes(search.toLowerCase());
    const matchCat = !categoryFilter || p.category === categoryFilter || p.product_categories?.name === categoryFilter;
    return matchSearch && matchCat;
  });

  return (
    <div className="pb-8 bg-slate-50 dark:bg-[#0f1115] min-h-full">
      {/* Premium Hero Header */}
      <div className="bg-white dark:bg-[#1a1d24] px-5 pt-3 pb-6 rounded-b-[2rem] shadow-sm mb-6 relative overflow-hidden">
        <div className="absolute -top-10 -right-10 w-40 h-40 bg-pink-500/10 blur-3xl rounded-full pointer-events-none" />
        <div className="absolute top-10 -left-10 w-32 h-32 bg-rose-500/10 blur-3xl rounded-full pointer-events-none" />

        <div className="relative z-10 flex flex-col items-center text-center">
          <p className="text-slate-500 dark:text-slate-400 text-[11px] font-bold uppercase tracking-widest mb-1">Product Catalog</p>
          <h2 className="text-slate-900 dark:text-white text-5xl font-black tracking-tighter mt-1 mb-2">
            {products?.length ?? 0}
          </h2>
          <div className="flex items-center gap-1.5 bg-slate-100 dark:bg-slate-800 px-3 py-1.5 rounded-full mt-1">
            <Package className="h-3.5 w-3.5 text-slate-500" />
            <span className="text-xs font-semibold text-slate-600 dark:text-slate-300">
              Active Items
            </span>
          </div>
        </div>
      </div>

      <div className="px-5 space-y-4">
        {/* Modern floating search bar */}
        <div className="bg-white dark:bg-[#1a1d24] rounded-2xl p-2 shadow-sm flex items-center pr-3 border-transparent focus-within:border-pink-500 dark:focus-within:border-pink-500 transition-colors border">
          <Search className="h-5 w-5 text-slate-400 ml-2 shrink-0" />
          <input
            value={search}
            onChange={(e) => setSearch(e.target.value)}
            placeholder="Search products, SKU..."
            className="flex-1 bg-transparent border-none focus:ring-0 text-sm px-3 h-10 text-slate-900 dark:text-white placeholder:text-slate-400"
          />
          {search && (
            <button onClick={() => setSearch("")} className="h-8 w-8 flex items-center justify-center bg-slate-100 dark:bg-slate-800 rounded-full active:scale-95 transition-transform shrink-0">
              <X className="h-4 w-4 text-slate-500" />
            </button>
          )}
        </div>

        {/* Category pills */}
        <div className="flex gap-2 overflow-x-auto pb-2 pt-1 scrollbar-hide -mx-5 px-5 snap-x">
          <button
            onClick={() => setCategoryFilter(null)}
            className={cn(
              "snap-start px-4 py-2 rounded-xl text-[13px] font-bold tracking-tight whitespace-nowrap transition-all active:scale-95 shadow-sm border",
              !categoryFilter
                ? "bg-pink-500 text-white border-pink-500 dark:bg-pink-600 dark:border-pink-600"
                : "bg-white dark:bg-[#1a1d24] text-slate-600 dark:text-slate-300 border-slate-100 dark:border-slate-800"
            )}
          >
            All Items
          </button>
          {(categories || []).map((c: any) => (
            <button
              key={c.id}
              onClick={() => setCategoryFilter(categoryFilter === c.name ? null : c.name)}
              className={cn(
                "snap-start px-4 py-2 rounded-xl text-[13px] font-bold tracking-tight whitespace-nowrap transition-all active:scale-95 shadow-sm border",
                categoryFilter === c.name
                  ? "bg-pink-500 text-white border-pink-500 dark:bg-pink-600 dark:border-pink-600"
                  : "bg-white dark:bg-[#1a1d24] text-slate-600 dark:text-slate-300 border-slate-100 dark:border-slate-800"
              )}
            >
              {c.name}
            </button>
          ))}
        </div>

        <div className="flex items-center justify-between px-1 mt-4 mb-2">
          <h3 className="text-[15px] font-bold text-slate-800 dark:text-slate-100 tracking-tight">Products</h3>
          <span className="text-[11px] font-semibold text-slate-400 uppercase tracking-widest">{filtered.length} found</span>
        </div>

        {isLoading ? (
          <div className="flex justify-center py-10">
            <Loader2 className="h-6 w-6 animate-spin text-pink-500" />
          </div>
        ) : filtered.length === 0 ? (
          <div className="bg-white dark:bg-[#1a1d24] rounded-2xl py-12 text-center shadow-sm">
            <div className="h-14 w-14 bg-slate-50 dark:bg-slate-800 rounded-full flex items-center justify-center mx-auto mb-3">
              <Package className="h-6 w-6 text-slate-300 dark:text-slate-500" />
            </div>
            <p className="text-sm font-semibold text-slate-900 dark:text-white">No products found</p>
            <p className="text-xs text-slate-500 mt-1">Try a different filter or search</p>
          </div>
        ) : (
          <div className="space-y-3">
            {filtered.map((p: any) => {
              const inStock = p.stock_quantity > 0;

              return (
                <button
                  key={p.id}
                  onClick={() => setSelectedProduct(p)}
                  className="w-full text-left bg-white dark:bg-[#1a1d24] rounded-2xl shadow-sm p-3.5 active:scale-[0.98] transition-all cursor-pointer border border-transparent hover:border-slate-100 dark:hover:border-slate-800"
                >
                  <div className="flex items-start gap-4">
                    <div className="h-16 w-16 rounded-2xl bg-slate-100 dark:bg-slate-800 overflow-hidden shrink-0 border border-slate-200/50 dark:border-slate-700/50 relative">
                      {p.image_url ? (
                        <img src={p.image_url} alt={p.name} loading="lazy" className="h-full w-full object-cover" />
                      ) : (
                        <div className="h-full w-full flex items-center justify-center bg-gradient-to-br from-pink-50 to-rose-50 dark:from-pink-900/30 dark:to-rose-900/30">
                          <Package className="h-6 w-6 text-pink-600/40 dark:text-pink-400/40" />
                        </div>
                      )}
                    </div>

                    <div className="flex-1 min-w-0 py-0.5">
                      <div className="flex justify-between items-start">
                        <div className="pr-2 min-w-0 flex-1">
                          <h4 className="text-[15px] font-bold text-slate-900 dark:text-white truncate">
                            {p.name}
                          </h4>
                          <div className="flex items-center gap-1.5 mt-1">
                            <span className="text-[10px] font-bold text-slate-500 dark:text-slate-400 uppercase tracking-widest bg-slate-100 dark:bg-slate-800 px-1.5 py-0.5 rounded truncate max-w-[80px]">
                              {p.sku || "N/A"}
                            </span>
                            {p.category && (
                              <span className="text-[10px] font-medium text-slate-400 truncate flex items-center gap-1">
                                <Tag className="h-2.5 w-2.5" />
                                {p.category}
                              </span>
                            )}
                          </div>
                        </div>
                      </div>

                      <div className="mt-2.5 pt-2.5 border-t border-slate-100 dark:border-slate-800/50 flex items-center justify-between">
                        <div>
                          <p className="text-[15px] font-black tracking-tight text-slate-900 dark:text-white flex items-center">
                            <IndianRupee className="h-3.5 w-3.5 -mr-0.5 text-slate-400" />
                            {Number(p.base_price).toLocaleString("en-IN")} 
                            <span className="text-[10px] font-medium text-slate-400 ml-1">/{p.unit}</span>
                          </p>
                        </div>

                        <div className={cn(
                          "px-2 py-1 rounded-md text-[10px] font-bold tracking-widest uppercase",
                          inStock 
                            ? "bg-emerald-50 text-emerald-600 dark:bg-emerald-500/10 dark:text-emerald-400" 
                            : "bg-red-50 text-red-600 dark:bg-red-500/10 dark:text-red-400"
                        )}>
                          {inStock ? `${p.stock_quantity} in stock` : "Out of stock"}
                        </div>
                      </div>
                    </div>
                  </div>
                </button>
              );
            })}
          </div>
        )}
      </div>

      {/* Modern Detail Sheet */}
      <Sheet open={!!selectedProduct} onOpenChange={(o) => !o && setSelectedProduct(null)}>
        <SheetContent side="bottom" className="h-[80vh] p-0 rounded-t-[2rem] border-t-0 bg-slate-50 dark:bg-[#0f1115] shadow-2xl outline-none">
          {selectedProduct && (
            <div className="h-full flex flex-col relative overflow-hidden">
              <div className="absolute top-3 left-1/2 -translate-x-1/2 w-12 h-1.5 bg-white/50 backdrop-blur-md rounded-full z-50"></div>

              <div className="relative h-[40%] bg-slate-100 dark:bg-slate-800 shrink-0 overflow-hidden">
                {selectedProduct.image_url ? (
                  <>
                    <img src={selectedProduct.image_url} alt={selectedProduct.name} className="h-full w-full object-cover" />
                    <div className="absolute inset-0 bg-gradient-to-t from-black/60 via-transparent to-transparent"></div>
                  </>
                ) : (
                  <div className="h-full w-full flex items-center justify-center bg-gradient-to-br from-pink-500/10 to-rose-500/10">
                    <Package className="h-20 w-20 text-pink-500/20" />
                  </div>
                )}

                <div className="absolute bottom-5 left-5 right-5">
                  <div className="flex gap-2 mb-2">
                    <span className="text-[10px] font-bold tracking-widest uppercase bg-white/20 backdrop-blur-md text-white px-2 py-1 rounded-md">
                      {selectedProduct.sku}
                    </span>
                    {selectedProduct.category && (
                      <span className="text-[10px] font-bold tracking-widest uppercase bg-white/20 backdrop-blur-md text-white px-2 py-1 rounded-md">
                        {selectedProduct.category}
                      </span>
                    )}
                  </div>
                  <h2 className="text-2xl font-black text-white leading-tight drop-shadow-md pb-[10px]">
                    {selectedProduct.name}
                  </h2>
                </div>

                <button
                  onClick={() => setSelectedProduct(null)}
                  className="absolute top-5 right-5 h-9 w-9 rounded-full bg-white/20 backdrop-blur-md border border-white/30 flex items-center justify-center text-white active:scale-95 transition-transform"
                >
                  <X className="h-4 w-4 text-white" />
                </button>
              </div>

              <div className="flex-1 overflow-y-auto px-5 pt-6 pb-24 bg-white dark:bg-[#1a1d24] rounded-t-3xl -mt-6 relative z-10 space-y-6">

                <div className="flex items-center justify-between p-4 bg-slate-50 dark:bg-[#0f1115] rounded-2xl border border-slate-100 dark:border-slate-800">
                  <div>
                    <p className="text-[11px] font-semibold text-slate-400 uppercase tracking-widest mb-1">Base Price</p>
                    <p className="text-3xl font-black text-slate-900 dark:text-white flex items-center">
                      <IndianRupee className="h-6 w-6 -mr-1 text-slate-400" />
                      {Number(selectedProduct.base_price).toLocaleString("en-IN")}
                      <span className="text-sm font-bold text-slate-400 ml-1">/{selectedProduct.unit}</span>
                    </p>
                  </div>

                  <div className="text-right">
                    <p className="text-[11px] font-semibold text-slate-400 uppercase tracking-widest mb-1">Inventory</p>
                    <div className={cn(
                      "inline-flex items-center gap-1.5 px-3 py-1.5 rounded-xl font-bold text-sm",
                      selectedProduct.stock_quantity > 0 
                        ? "bg-emerald-100 text-emerald-700 dark:bg-emerald-500/20 dark:text-emerald-400" 
                        : "bg-red-100 text-red-700 dark:bg-red-500/20 dark:text-red-400"
                    )}>
                      {selectedProduct.stock_quantity > 0 ? (
                        <>{selectedProduct.stock_quantity} Left</>
                      ) : (
                        "Out of Stock"
                      )}
                    </div>
                  </div>
                </div>

                <div>
                  <p className="text-[12px] font-bold text-slate-400 uppercase tracking-widest mb-3 flex items-center gap-2">
                    <ScanLine className="h-4 w-4" /> Description
                  </p>
                  <p className="text-[15px] text-slate-600 dark:text-slate-300 leading-relaxed font-medium">
                    {selectedProduct.description || "No detailed description available for this product."}
                  </p>
                </div>
              </div>

              <div className="absolute bottom-0 left-0 right-0 p-5 bg-gradient-to-t from-white via-white to-transparent dark:from-[#1a1d24] dark:via-[#1a1d24] z-20">
                <button 
                  className="w-full h-14 bg-slate-900 dark:bg-white text-white dark:text-slate-900 rounded-2xl font-bold text-[15px] shadow-xl active:scale-[0.98] transition-transform"
                  onClick={() => setSelectedProduct(null)}
                >
                  Close Details
                </button>
              </div>
            </div>
          )}
        </SheetContent>
      </Sheet>
    </div>
  );
}

import { useQuery } from "@tanstack/react-query";
import { Loader2, Map, Store, Route as RouteIcon, Navigation } from "lucide-react";
import { supabase } from "@/integrations/supabase/client";
import { cn } from "@/lib/utils";

export function AdminRoutes() {
  const { data: routes, isLoading } = useQuery({
    queryKey: ["admin-mobile-routes"],
    queryFn: async () => {
      const { data, error } = await supabase
        .from("routes")
        .select("id, name, is_active, stores(id)")
        .order("name");
      if (error) throw error;
      return (data as any[]) || [];
    },
    refetchInterval: 120_000,
  });

  const activeCount = (routes || []).filter((r: any) => r.is_active).length;

  return (
    <div className="pb-8 bg-slate-50 dark:bg-[#0f1115] min-h-full">
      {/* Premium Hero Header */}
      <div className="bg-white dark:bg-[#1a1d24] px-5 pt-3 pb-6 rounded-b-[2rem] shadow-sm mb-6 relative overflow-hidden">
        <div className="absolute -top-10 -right-10 w-40 h-40 bg-sky-500/10 blur-3xl rounded-full pointer-events-none" />
        <div className="absolute top-10 -left-10 w-32 h-32 bg-blue-500/10 blur-3xl rounded-full pointer-events-none" />

        <div className="relative z-10 flex flex-col items-center text-center">
          <p className="text-slate-500 dark:text-slate-400 text-[11px] font-bold uppercase tracking-widest mb-1">Service Routes</p>
