                        "text-[9px] font-bold uppercase tracking-widest px-2 py-0.5 rounded-full shrink-0 border",
                        r.is_active 
                          ? "bg-emerald-50 text-emerald-600 border-emerald-100 dark:bg-emerald-500/10 dark:text-emerald-400 dark:border-emerald-500/20" 
                          : "bg-slate-100 text-slate-500 border-slate-200 dark:bg-slate-800 dark:text-slate-400 dark:border-slate-700"
                      )}>
                        {r.is_active ? "Active" : "Inactive"}
                      </span>
                    </div>

                    <div className={cn("flex items-center gap-1.5 mt-2", 
                      r.is_active ? "text-slate-600 dark:text-slate-300" : "text-slate-400 dark:text-slate-500"
                    )}>
                      <Store className="h-3.5 w-3.5" /> 
                      <span className="text-sm font-medium">{r.stores?.length ?? 0} connected stores</span>
                    </div>
                  </div>
                </div>
              </div>
            ))}
          </div>
        )}
      </div>
    </div>
  );
}

import { useState } from "react";
import { useQuery } from "@tanstack/react-query";
import { Search, X, ShoppingCart, Calendar, TrendingUp } from "lucide-react";
import { supabase } from "@/integrations/supabase/client";
import { format } from "date-fns";
import { cn } from "@/lib/utils";
import { MobileListSkeleton } from "@/components/shared/MobileListSkeleton";

export function AdminSales() {
  const [search, setSearch] = useState("");
  const today = new Date().toISOString().split("T")[0];

  const { data: sales, isLoading } = useQuery({
    queryKey: ["admin-mobile-sales"],
    queryFn: async () => {
      const { data, error } = await supabase
        .from("sales")
        .select("id, display_id, total_amount, cash_amount, upi_amount, credit_amount, created_at, stores(name), customers(name)")
        .order("created_at", { ascending: false })
        .limit(100);
      if (error) throw error;
      return (data as any[]) || [];
    },
    refetchInterval: 60_000,
  });

  const { data: todayStats } = useQuery({
    queryKey: ["admin-mobile-sales-today-stats", today],
    queryFn: async () => {
      const { data } = await supabase
        .from("sales")
        .select("total_amount")
        .gte("created_at", today);
      const total = (data || []).reduce((s: number, r: any) => s + Number(r.total_amount || 0), 0);
      return { count: data?.length ?? 0, total };
    },
    refetchInterval: 60_000,
  });

  const filtered = (sales || []).filter((s: any) => {
    if (!search) return true;
    const q = search.toLowerCase();
    return (
      s.display_id?.toLowerCase().includes(q) ||
      s.stores?.name?.toLowerCase().includes(q) ||
      s.customers?.name?.toLowerCase().includes(q)
    );
  });

  return (
    <div className="pb-8 bg-slate-50 dark:bg-[#0f1115] min-h-full">
      {/* Premium Hero Header */}
      <div className="bg-white dark:bg-[#1a1d24] px-5 pt-3 pb-6 rounded-b-[2rem] shadow-sm mb-6 relative overflow-hidden">
        <div className="absolute -top-10 -right-10 w-40 h-40 bg-violet-500/10 blur-3xl rounded-full pointer-events-none" />
        <div className="absolute top-10 -left-10 w-32 h-32 bg-indigo-500/10 blur-3xl rounded-full pointer-events-none" />

        <div className="relative z-10 flex flex-col items-center text-center">
          <p className="text-slate-500 dark:text-slate-400 text-[11px] font-bold uppercase tracking-widest mb-1">Total Sales Today</p>
          <h2 className="text-slate-900 dark:text-white text-5xl font-black tracking-tighter mt-1 mb-2">
            <span className="text-3xl font-bold text-slate-400 dark:text-slate-500 mr-1">₹</span>
            {(todayStats?.total ?? 0).toLocaleString("en-IN")}
          </h2>
          <div className="inline-flex items-center gap-1.5 bg-violet-50 dark:bg-violet-500/10 px-3 py-1.5 rounded-full">
            <TrendingUp className="h-3.5 w-3.5 text-violet-600 dark:text-violet-400" />
            <span className="text-xs font-semibold text-violet-700 dark:text-violet-300">
              {todayStats?.count ?? 0} transactions
            </span>
          </div>
        </div>
      </div>

      <div className="px-5 space-y-4">
        {/* Modern floating search bar */}
        <div className="bg-white dark:bg-[#1a1d24] rounded-2xl p-2 shadow-sm flex items-center pr-3 border-transparent focus-within:border-violet-500 dark:focus-within:border-violet-500 transition-colors border">
          <Search className="h-5 w-5 text-slate-400 ml-2 shrink-0" />
          <input
            value={search}
            onChange={(e) => setSearch(e.target.value)}
            placeholder="Search store, customer, or ID..."
            className="flex-1 bg-transparent border-none focus:ring-0 text-sm px-3 h-10 text-slate-900 dark:text-white placeholder:text-slate-400"
          />
          {search && (
            <button onClick={() => setSearch("")} className="h-8 w-8 flex items-center justify-center bg-slate-100 dark:bg-slate-800 rounded-full active:scale-95 transition-transform shrink-0">
              <X className="h-4 w-4 text-slate-500" />
            </button>
          )}
        </div>

        <div className="flex items-center justify-between px-1 mt-6 mb-2">
          <h3 className="text-[15px] font-bold text-slate-800 dark:text-slate-100 tracking-tight">Sales Records</h3>
          <span className="text-[11px] font-semibold text-slate-400 uppercase tracking-widest">{filtered.length} found</span>
        </div>

        {isLoading ? (
          <MobileListSkeleton items={6} showStats={false} titleWidth="w-36" />
        ) : filtered.length === 0 ? (
          <div className="bg-white dark:bg-[#1a1d24] rounded-2xl py-12 text-center shadow-sm">
            <div className="h-14 w-14 bg-slate-50 dark:bg-slate-800 rounded-full flex items-center justify-center mx-auto mb-3">
              <ShoppingCart className="h-6 w-6 text-slate-300 dark:text-slate-500" />
            </div>
            <p className="text-sm font-semibold text-slate-900 dark:text-white">No sales found</p>
            <p className="text-xs text-slate-500 mt-1">Try adjusting your search</p>
          </div>
        ) : (
          <div className="space-y-3">
            {filtered.map((sale: any) => (
              <div 
                key={sale.id} 
                className="bg-white dark:bg-[#1a1d24] rounded-2xl shadow-sm p-4 active:scale-[0.98] transition-all cursor-pointer border border-transparent hover:border-slate-100 dark:hover:border-slate-800"
              >
                <div className="flex justify-between items-start mb-3">
                  <div className="flex-1 min-w-0 pr-3">
                    <h4 className="text-[15px] font-bold text-slate-900 dark:text-white truncate">
                      {sale.stores?.name ?? "Store"}
                    </h4>
                    <p className="text-xs text-slate-500 dark:text-slate-400 truncate mt-0.5">
                      {sale.customers?.name ?? "Customer"}
                    </p>
                  </div>
                  <div className="bg-slate-100 dark:bg-slate-800 px-2 py-1 rounded-md shrink-0">
                    <span className="text-[10px] font-bold text-slate-600 dark:text-slate-300 tracking-widest uppercase">
                      {sale.display_id}
                    </span>
                  </div>
                </div>

                <div className="pt-3 border-t border-slate-100 dark:border-slate-800/50 flex items-end justify-between">
                  <div className="space-y-1.5">
                    <div className="flex items-center gap-1.5 text-[11px] text-slate-400 font-medium">
                      <Calendar className="h-3.5 w-3.5" />
                      {format(new Date(sale.created_at), "dd MMM, hh:mm a")}
                    </div>

                    <div className="flex items-center gap-2">
                      {Number(sale.cash_amount || 0) > 0 && (
                        <span className="inline-flex items-center gap-1 text-[10px] font-semibold text-emerald-600 dark:text-emerald-400 bg-emerald-50 dark:bg-emerald-500/10 px-1.5 py-0.5 rounded">
                          CASH <span className="opacity-70">₹{Number(sale.cash_amount).toLocaleString("en-IN")}</span>
                        </span>
                      )}
                      {Number(sale.upi_amount || 0) > 0 && (
                        <span className="inline-flex items-center gap-1 text-[10px] font-semibold text-blue-600 dark:text-blue-400 bg-blue-50 dark:bg-blue-500/10 px-1.5 py-0.5 rounded">
                          UPI <span className="opacity-70">₹{Number(sale.upi_amount).toLocaleString("en-IN")}</span>
                        </span>
                      )}
                    </div>
                  </div>

                  <div className="text-right shrink-0">
                    <p className="text-[10px] font-bold text-slate-400 mb-0.5 uppercase tracking-widest">Total</p>
                    <p className="text-lg font-black text-slate-900 dark:text-white leading-none">
                      ₹{Number(sale.total_amount).toLocaleString("en-IN")}
                    </p>
                  </div>
                </div>
              </div>
            ))}
          </div>
        )}
      </div>
    </div>
  );
}

import { useState } from "react";
import { useQuery, useQueryClient } from "@tanstack/react-query";
import { Loader2, Save, Building, Phone, FileText, MapPin, Settings2 } from "lucide-react";
import { Input } from "@/components/ui/input";
import { Button } from "@/components/ui/button";
import { supabase } from "@/integrations/supabase/client";
import { toast } from "sonner";
import { cn } from "@/lib/utils";

const SETTINGS_KEYS = ["company_name", "customer_care_number", "gst_number", "address"] as const;

const CONFIG = {
  company_name: { label: "Company Name", icon: Building },
  customer_care_number: { label: "Customer Care Number", icon: Phone },
  gst_number: { label: "GST Number", icon: FileText },
  address: { label: "Company Address", icon: MapPin },
};

export function AdminSettings() {
  const qc = useQueryClient();
  const [values, setValues] = useState<Record<string, string>>({});
  const [saving, setSaving] = useState(false);

  const { isLoading } = useQuery({
    queryKey: ["admin-mobile-settings"],
    queryFn: async () => {
      const { data, error } = await supabase.from("company_settings").select("key, value");
      if (error) throw error;
      const map: Record<string, string> = {};
      (data || []).forEach((s: any) => { map[s.key] = s.value || ""; });
      setValues(map);
      return map;
    },
  });

  const handleSave = async () => {
    setSaving(true);
    try {
      for (const key of SETTINGS_KEYS) {
        if (values[key] !== undefined) {
          await supabase.from("company_settings").upsert({ key, value: values[key] }, { onConflict: "key" });
        }
      }
      toast.success("Settings saved successfully");
      qc.invalidateQueries({ queryKey: ["admin-mobile-settings"] });
    } catch {
      toast.error("Failed to save settings");
    } finally {
      setSaving(false);
    }
  };

  return (
    <div className="pb-8 bg-slate-50 dark:bg-[#0f1115] min-h-full">
      {/* Premium Hero Header */}
      <div className="bg-white dark:bg-[#1a1d24] px-5 pt-3 pb-6 rounded-b-[2rem] shadow-sm mb-6 relative overflow-hidden">
        <div className="absolute -top-10 -right-10 w-40 h-40 bg-zinc-500/10 blur-3xl rounded-full pointer-events-none" />
        <div className="absolute top-10 -left-10 w-32 h-32 bg-slate-500/10 blur-3xl rounded-full pointer-events-none" />

        <div className="relative z-10 flex flex-col items-center text-center mt-2">
          <div className="h-16 w-16 bg-gradient-to-br from-slate-100 to-slate-200 dark:from-slate-800 dark:to-slate-900 rounded-2xl flex items-center justify-center mb-4 shadow-sm border border-slate-200/50 dark:border-slate-700/50">
             <Settings2 className="h-8 w-8 text-slate-700 dark:text-slate-300" />
          </div>
          <h2 className="text-slate-900 dark:text-white text-3xl font-black tracking-tight">System Settings</h2>
          <p className="text-slate-500 dark:text-slate-400 text-[13px] font-medium mt-1">Manage global app configuration</p>
        </div>
      </div>

      <div className="px-5 space-y-4">
        {isLoading ? (
          <div className="flex justify-center py-10">
            <Loader2 className="h-6 w-6 animate-spin text-slate-500" />
          </div>
        ) : (
          <div className="bg-white dark:bg-[#1a1d24] rounded-3xl shadow-sm border border-slate-100 dark:border-slate-800 p-2 overflow-hidden mb-8">
             <div className="p-4 border-b border-slate-100 dark:border-slate-800/50 flex items-center gap-2">
               <Building className="h-5 w-5 text-slate-400" />
               <h3 className="text-sm font-bold text-slate-800 dark:text-slate-100 tracking-tight">Business Profile</h3>
             </div>

             <div className="p-4 space-y-5">
               {SETTINGS_KEYS.map((key) => {
                 const { label, icon: Icon } = CONFIG[key as keyof typeof CONFIG];
                 const isFocused = false; // Could add state for this if needed

                 return (
                   <div key={key} className="relative">
                     <label className="text-[11px] font-bold text-slate-500 dark:text-slate-400 uppercase tracking-widest mb-1.5 flex items-center gap-1.5">
                        <Icon className="h-3.5 w-3.5" />
                        {label}
                     </label>
                     <Input
                       value={values[key] || ""}
                       onChange={(e) => setValues((prev) => ({ ...prev, [key]: e.target.value }))}
                       className="h-12 rounded-xl bg-slate-50 dark:bg-[#0f1115] border-transparent focus-visible:ring-1 focus-visible:ring-slate-400 dark:focus-visible:ring-slate-600 focus-visible:border-slate-400 transition-all font-medium text-slate-900 dark:text-white"
                     />
                   </div>
                 );
               })}
             </div>
          </div>
        )}

        {!isLoading && (
          <div className="px-1 mt-6">
            <Button 
              onClick={handleSave} 
              disabled={saving} 
              className="w-full h-14 rounded-2xl bg-neutral-900 hover:bg-neutral-800 dark:bg-white dark:hover:bg-slate-200 dark:text-slate-900 text-white shadow-lg active:scale-[0.98] transition-all font-bold text-base gap-2"
            >
              {saving ? <Loader2 className="h-5 w-5 animate-spin" /> : <Save className="h-5 w-5" />}
              Save All Changes
            </Button>
          </div>
        )}
      </div>
    </div>
  );
}

import { useState } from "react";
import { useQuery } from "@tanstack/react-query";
import { Search, X, Loader2, Store, MapPin, Phone, Map } from "lucide-react";
import { supabase } from "@/integrations/supabase/client";
import { cn } from "@/lib/utils";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";

export function AdminStores() {
  const [search, setSearch] = useState("");
  const [filterRoute, setFilterRoute] = useState("all");

  const { data: stores, isLoading } = useQuery({
    queryKey: ["admin-mobile-stores"],
    queryFn: async () => {
      const { data, error } = await supabase
        .from("stores")
        .select("id, name, display_id, photo_url, outstanding, address, phone, is_active, route_id, customers(name), store_types(name), routes(name)")
        .eq("is_active", true)
        .order("name");
      if (error) throw error;
      return (data as any[]) || [];
    },
    refetchInterval: 120_000,
  });

  const { data: routes } = useQuery({
    queryKey: ["admin-mobile-routes-filter"],
    queryFn: async () => {
      const { data } = await supabase.from("routes").select("id, name").eq("is_active", true).order("name");
      return (data as any[]) || [];
    },
  });

  const totalOutstanding = (stores || []).reduce((s: number, st: any) => s + Number(st.outstanding || 0), 0);

  const filtered = (stores || []).filter((s: any) => {
    const matchRoute = filterRoute === "all" || s.route_id === filterRoute;
    if (!search) return matchRoute;
    const q = search.toLowerCase();
    return matchRoute && (
      s.name?.toLowerCase().includes(q) ||
      s.display_id?.toLowerCase().includes(q) ||
      s.customers?.name?.toLowerCase().includes(q) ||
      s.address?.toLowerCase().includes(q)
    );
  });

  return (
    <div className="pb-8 bg-slate-50 dark:bg-[#0f1115] min-h-full">
      {/* Premium Hero Header */}
      <div className="bg-white dark:bg-[#1a1d24] px-5 pt-3 pb-6 rounded-b-[2rem] shadow-sm mb-6 relative overflow-hidden">
        <div className="absolute -top-10 -right-10 w-40 h-40 bg-teal-500/10 blur-3xl rounded-full pointer-events-none" />
        <div className="absolute top-10 -left-10 w-32 h-32 bg-cyan-500/10 blur-3xl rounded-full pointer-events-none" />

        <div className="relative z-10 flex flex-col items-center text-center">
          <p className="text-slate-500 dark:text-slate-400 text-[11px] font-bold uppercase tracking-widest mb-1">Active Stores</p>
          <div className="flex items-center gap-3">
            <h2 className="text-slate-900 dark:text-white text-5xl font-black tracking-tighter mt-1 mb-2">
              {stores?.length ?? 0}
            </h2>
          </div>

          <div className="mt-3 bg-red-50 dark:bg-red-500/10 rounded-xl px-4 py-2.5 border border-red-100 dark:border-red-500/20">
            <p className="text-xs font-semibold text-red-600/80 dark:text-red-400/80 uppercase tracking-widest mb-0.5">Total Outstanding</p>
            <p className="text-lg font-bold text-red-700 dark:text-red-400">₹{totalOutstanding.toLocaleString("en-IN")}</p>
          </div>
        </div>
      </div>

      <div className="px-5 space-y-4">
        {/* Modern floating search bar */}
        <div className="bg-white dark:bg-[#1a1d24] rounded-2xl p-2 shadow-sm flex flex-col gap-2 border border-slate-100 dark:border-slate-800">
          <div className="flex items-center pr-3">
            <Search className="h-5 w-5 text-slate-400 ml-2 shrink-0" />
            <input
              value={search}
              onChange={(e) => setSearch(e.target.value)}
              placeholder="Search store, customer..."
              className="flex-1 bg-transparent border-none focus:ring-0 text-sm px-3 h-10 text-slate-900 dark:text-white placeholder:text-slate-400"
            />
            {search && (
              <button onClick={() => setSearch("")} className="h-8 w-8 flex items-center justify-center bg-slate-100 dark:bg-slate-800 rounded-full active:scale-95 transition-transform shrink-0">
                <X className="h-4 w-4 text-slate-500" />
              </button>
            )}
          </div>
          <div className="px-2 pb-2">
            <Select value={filterRoute} onValueChange={setFilterRoute}>
              <SelectTrigger className="h-10 text-[13px] font-medium bg-slate-50 dark:bg-slate-900 border-none rounded-xl">
                <div className="flex items-center gap-2">
                  <Map className="h-4 w-4 text-teal-600 dark:text-teal-400" />
                  <SelectValue placeholder="All Routes" />
                </div>
              </SelectTrigger>
              <SelectContent className="rounded-2xl shrink-0">
                <SelectItem value="all">All Routes</SelectItem>
                {(routes || []).map((r: any) => (
                  <SelectItem key={r.id} value={r.id}>{r.name}</SelectItem>
                ))}
              </SelectContent>
            </Select>
          </div>
        </div>

        <div className="flex items-center justify-between px-1 mt-6 mb-2">
          <h3 className="text-[15px] font-bold text-slate-800 dark:text-slate-100 tracking-tight">Store Directory</h3>
          <span className="text-[11px] font-semibold text-slate-400 uppercase tracking-widest">{filtered.length} found</span>
