                            <p className="text-[11px] font-medium text-slate-500 dark:text-slate-400 truncate flex items-center gap-1.5">
                              <span className="h-1.5 w-1.5 rounded-full bg-slate-300 dark:bg-slate-600 shrink-0" />
                              {s.customers.name}
                            </p>
                          )}
                          {s.routes?.name && (
                            <p className="text-[11px] font-medium text-teal-600 dark:text-teal-400 truncate flex items-center gap-1.5 mt-1">
                              <Map className="h-3 w-3 shrink-0" />
                              {s.routes.name}
                            </p>
                          )}
                        </div>

                        {s.phone && (
                          <button
                            onClick={(e) => {
                              e.stopPropagation();
                              window.open(`tel:${s.phone}`, "_self");
                            }}
                            className="h-8 w-8 rounded-full bg-slate-50 dark:bg-slate-800 flex items-center justify-center shrink-0 active:scale-90 transition-transform border border-slate-100 dark:border-slate-700"
                          >
                            <Phone className="h-3.5 w-3.5 text-slate-600 dark:text-slate-300" />
                          </button>
                        )}
                      </div>
                    </div>
                  </div>
                </div>
              );
            })}
          </div>
        )}
      </div>
    </div>
  );
}

import { useState } from "react";
import { useQuery } from "@tanstack/react-query";
import { Search, X, Loader2, Receipt, Calendar, IndianRupee, Store, Wallet } from "lucide-react";
import { supabase } from "@/integrations/supabase/client";
import { format } from "date-fns";
import { cn } from "@/lib/utils";

export function AdminTransactions() {
  const [search, setSearch] = useState("");
  const today = new Date().toISOString().split("T")[0];

  const { data: transactions, isLoading } = useQuery({
    queryKey: ["admin-mobile-transactions"],
    queryFn: async () => {
      const { data, error } = await supabase
        .from("transactions")
        .select("id, display_id, total_amount, cash_amount, upi_amount, created_at, stores(name), customers(name)")
        .order("created_at", { ascending: false })
        .limit(100);
      if (error) throw error;
      return (data as any[]) || [];
    },
    refetchInterval: 60_000,
  });

  const { data: todayStats } = useQuery({
    queryKey: ["admin-mobile-tx-today-stats", today],
    queryFn: async () => {
      const { data } = await supabase.from("transactions").select("total_amount").gte("created_at", today);
      const total = (data || []).reduce((s: number, r: any) => s + Number(r.total_amount || 0), 0);
      return { count: data?.length ?? 0, total };
    },
    refetchInterval: 60_000,
  });

  const filtered = (transactions || []).filter((t: any) => {
    if (!search) return true;
    const q = search.toLowerCase();
    return (
      t.display_id?.toLowerCase().includes(q) ||
      t.stores?.name?.toLowerCase().includes(q) ||
      t.customers?.name?.toLowerCase().includes(q)
    );
  });

  return (
    <div className="pb-8 bg-slate-50 dark:bg-[#0f1115] min-h-full">
      {/* Premium Hero Header */}
      <div className="bg-white dark:bg-[#1a1d24] px-5 pt-3 pb-6 rounded-b-[2rem] shadow-sm mb-6 relative overflow-hidden">
        <div className="absolute -top-10 -right-10 w-40 h-40 bg-emerald-500/10 blur-3xl rounded-full pointer-events-none" />
        <div className="absolute top-10 -left-10 w-32 h-32 bg-teal-500/10 blur-3xl rounded-full pointer-events-none" />

        <div className="relative z-10 flex flex-col items-center text-center">
          <p className="text-slate-500 dark:text-slate-400 text-[11px] font-bold uppercase tracking-widest mb-1">Today's Collections</p>
          <div className="flex items-center justify-center">
            <h2 className="text-emerald-600 dark:text-emerald-400 text-5xl font-black tracking-tighter mt-1 mb-2 flex items-center">
              <IndianRupee className="h-9 w-9 -mr-1 text-emerald-600/50 dark:text-emerald-400/50" />
              {(todayStats?.total ?? 0).toLocaleString("en-IN")}
            </h2>
          </div>
          <div className="flex items-center gap-1.5 bg-slate-100 dark:bg-slate-800 px-3 py-1.5 rounded-full mt-1">
            <Receipt className="h-3.5 w-3.5 text-slate-500" />
            <span className="text-xs font-semibold text-slate-600 dark:text-slate-300">
              {todayStats?.count ?? 0} payments today
            </span>
          </div>
        </div>
      </div>

      <div className="px-5 space-y-4">
        {/* Modern floating search bar */}
        <div className="bg-white dark:bg-[#1a1d24] rounded-2xl p-2 shadow-sm flex items-center pr-3 border-transparent focus-within:border-emerald-500 dark:focus-within:border-emerald-500 transition-colors border">
          <Search className="h-5 w-5 text-slate-400 ml-2 shrink-0" />
          <input
            value={search}
            onChange={(e) => setSearch(e.target.value)}
            placeholder="Search stores, customers, ID..."
            className="flex-1 bg-transparent border-none focus:ring-0 text-sm px-3 h-10 text-slate-900 dark:text-white placeholder:text-slate-400"
          />
          {search && (
            <button onClick={() => setSearch("")} className="h-8 w-8 flex items-center justify-center bg-slate-100 dark:bg-slate-800 rounded-full active:scale-95 transition-transform shrink-0">
              <X className="h-4 w-4 text-slate-500" />
            </button>
          )}
        </div>

        <div className="flex items-center justify-between px-1 mt-6 mb-2">
          <h3 className="text-[15px] font-bold text-slate-800 dark:text-slate-100 tracking-tight">Recent Transactions</h3>
          <span className="text-[11px] font-semibold text-slate-400 uppercase tracking-widest">{filtered.length} found</span>
        </div>

        {isLoading ? (
          <div className="flex justify-center py-10">
            <Loader2 className="h-6 w-6 animate-spin text-emerald-500" />
          </div>
        ) : filtered.length === 0 ? (
          <div className="bg-white dark:bg-[#1a1d24] rounded-2xl py-12 text-center shadow-sm">
            <div className="h-14 w-14 bg-slate-50 dark:bg-slate-800 rounded-full flex items-center justify-center mx-auto mb-3">
              <Receipt className="h-6 w-6 text-slate-300 dark:text-slate-500" />
            </div>
            <p className="text-sm font-semibold text-slate-900 dark:text-white">No transactions found</p>
            <p className="text-xs text-slate-500 mt-1">Try a different search term</p>
          </div>
        ) : (
          <div className="space-y-3">
            {filtered.map((tx: any) => {
              const cashAmt = Number(tx.cash_amount || 0);
              const upiAmt = Number(tx.upi_amount || 0);
              const hasSplitPayment = cashAmt > 0 && upiAmt > 0;

              return (
                <div 
                  key={tx.id} 
                  className="bg-white dark:bg-[#1a1d24] rounded-2xl shadow-sm p-4 active:scale-[0.98] transition-all cursor-pointer border border-transparent hover:border-slate-100 dark:hover:border-slate-800"
                >
                  <div className="flex justify-between items-start mb-3">
                    <div className="flex-1 min-w-0 pr-3">
                      <div className="flex items-center gap-2 mb-1">
                        <span className="text-[10px] font-bold text-slate-400 uppercase tracking-widest bg-slate-100 dark:bg-slate-800 px-1.5 py-0.5 rounded">
                          {tx.display_id}
                        </span>
                        <span className="text-[10px] font-medium text-slate-500 dark:text-slate-400 flex items-center gap-1">
                          <Calendar className="h-3 w-3" />
                          {format(new Date(tx.created_at), "dd MMM, hh:mm a")}
                        </span>
                      </div>

                      <h4 className="text-[15px] font-bold text-slate-900 dark:text-white truncate flex items-center gap-1.5 mt-2">
                        <Store className="h-4 w-4 text-slate-400 shrink-0" />
                        {tx.stores?.name ?? "Store"}
                      </h4>
                      <p className="text-xs text-slate-500 dark:text-slate-400 truncate pl-5.5 mt-0.5">
                        {tx.customers?.name ?? "Customer"}
                      </p>
                    </div>

                    <div className="text-right shrink-0">
                      <p className="text-lg font-black text-emerald-600 dark:text-emerald-400 flex items-center justify-end tracking-tight">
                        <IndianRupee className="h-4 w-4 -mr-0.5" />
                        {Number(tx.total_amount).toLocaleString("en-IN")}
                      </p>
                      <div className={cn(
                        "inline-flex items-center gap-1 px-1.5 py-0.5 rounded text-[9px] font-bold tracking-widest uppercase mt-0.5",
                         hasSplitPayment ? "bg-purple-50 text-purple-600 dark:bg-purple-500/10 dark:text-purple-400" : "bg-emerald-50 text-emerald-600 dark:bg-emerald-500/10 dark:text-emerald-400"
                      )}>
                        <Wallet className="h-2.5 w-2.5" />
                        {hasSplitPayment ? "Split" : (cashAmt > 0 ? "Cash" : "UPI")}
                      </div>
                    </div>
                  </div>

                  {/* Payment Breakdown */}
                  <div className="pt-3 mt-1 border-t border-slate-100 dark:border-slate-800/50 flex items-center gap-4">
                    {cashAmt > 0 && (
                      <div className="flex-1 bg-slate-50 dark:bg-slate-800/50 rounded-lg p-2 flex justify-between items-center border border-slate-100 dark:border-slate-800 text-xs">
                        <span className="font-semibold text-slate-500">Cash</span>
                        <span className="font-bold text-slate-900 dark:text-white text-[13px]">₹{cashAmt.toLocaleString("en-IN")}</span>
                      </div>
                    )}
                    {upiAmt > 0 && (
                      <div className="flex-1 bg-slate-50 dark:bg-slate-800/50 rounded-lg p-2 flex justify-between items-center border border-slate-100 dark:border-slate-800 text-xs">
                        <span className="font-semibold text-slate-500">UPI</span>
                        <span className="font-bold text-slate-900 dark:text-white text-[13px]">₹{upiAmt.toLocaleString("en-IN")}</span>
                      </div>
                    )}
                  </div>
                </div>
              );
            })}
          </div>
        )}
      </div>
    </div>
  );
}

import { useState } from "react";
// import { useNavigate } from "react-router-dom";
import { useQuery } from "@tanstack/react-query";
import { supabase } from "@/integrations/supabase/client";
import { useAuth } from "@/contexts/AuthContext";
import { useOnlineStatus } from "@/hooks/useOnlineStatus";
import { useRouteAccess } from "@/hooks/useRouteAccess";
import { addToQueue, queueFileUpload, fileToArrayBuffer } from "@/lib/offlineQueue";
import { getCurrentPosition, takePhoto } from "@/lib/capacitorUtils";
import { ArrowLeft, Check, ChevronRight, Loader2, MapPin, Store, User, UserPlus, Camera, WifiOff } from "lucide-react";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Textarea } from "@/components/ui/textarea";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { toast } from "sonner";

type Step = "type" | "customer" | "store" | "review";
type Mode = "customer" | "store" | "both";

export default function AddCustomerStore({ onClose }: { onClose: () => void }) {
  const { user, role } = useAuth();
  const { canAccessRoute, hasMatrixRestrictions, enabledRouteIds } = useRouteAccess(user?.id, role);
  const { isOnline } = useOnlineStatus();
  // const qc = useQueryClient();

  const [step, setStep] = useState<Step>("type");
  const [mode, setMode] = useState<Mode>("both");
  const [saving, setSaving] = useState(false);

  // Customer Data
  const [custId, setCustId] = useState(""); // For "store" mode (selecting existing)
  const [custName, setCustName] = useState("");
  const [custPhone, setCustPhone] = useState("");
  const [custEmail, setCustEmail] = useState("");
  // const [custPhoto, setCustPhoto] = useState("");
  const [custPhoto, setCustPhoto] = useState("");
  const [storePhoto, setStorePhoto] = useState("");
  // Track pending offline photos (stored as data URLs until sync)
  const [pendingCustPhoto, setPendingCustPhoto] = useState<string | null>(null);
  const [pendingStorePhoto, setPendingStorePhoto] = useState<string | null>(null);

  const handleTakePhoto = async (target: "customer" | "store") => {
    const dataUrl = await takePhoto();
    if (!dataUrl) return;

    const ext = "jpg";
    const path = `${target}s/${crypto.randomUUID()}.${ext}`; // customers/uuid.jpg or stores/uuid.jpg

    // If offline, queue for later upload
    if (!isOnline) {
      try {
        const res = await fetch(dataUrl);
        const blob = await res.blob();
        const fileData = await fileToArrayBuffer(blob);
        
        await queueFileUpload({
          id: `entity-photo-${target}-${Date.now()}`,
          type: target === "customer" ? "entity_photo" : "store_photo",
          fileName: `${target}_${Date.now()}.jpg`,
          bucket: "entity-photos",
          path,
          fileData,
          contentType: "image/jpeg",
          metadata: { target },
        });
        
        // Store locally to show preview (data URL)
        if (target === "customer") {
          setPendingCustPhoto(dataUrl);
          setCustPhoto(path); // Store path for later reference
        } else {
          setPendingStorePhoto(dataUrl);
          setStorePhoto(path);
        }
        
        toast.success("Photo saved for upload when online", {
          icon: <WifiOff className="h-4 w-4" />,
        });
      } catch (err: any) {
        toast.error("Failed to queue photo: " + err.message);
      }
      return;
    }

    // Online: Upload to Supabase immediately
    try {
        const res = await fetch(dataUrl);
        const blob = await res.blob();

        const { error } = await supabase.storage.from("entity-photos").upload(path, blob);
        if (error) throw error;

        const { data: { publicUrl } } = supabase.storage.from("entity-photos").getPublicUrl(path);
        
        if (target === "customer") {
          setCustPhoto(publicUrl);
          setPendingCustPhoto(null);
        } else {
          setStorePhoto(publicUrl);
          setPendingStorePhoto(null);
        }
        
        toast.success("Photo uploaded");
    } catch (err: any) {
        toast.error("Photo upload failed: " + err.message);
    }
  };

  // Store Data
  const [storeName, setStoreName] = useState("");
  // const [storePhone, setStorePhone] = useState("");
  const storePhone = ""; // Use cust phone by default or add input later
  const [storeTypeId, setStoreTypeId] = useState("");
  const [routeId, setRouteId] = useState("");
  const [address, setAddress] = useState("");
  const [lat, setLat] = useState<number | null>(null);
  const [lng, setLng] = useState<number | null>(null);
  const [locating, setLocating] = useState(false);

  // Fetch meta data
  const { data: storeTypes } = useQuery({
    queryKey: ["store-types", user?.id, hasMatrixRestrictions],
    queryFn: async () => {
      let q = supabase.from("store_types").select("*").eq("is_active", true);
      const { data } = await q;
      let types = data || [];

      if (hasMatrixRestrictions && enabledRouteIds.size > 0) {
        // If restricted, only show types that exist on allowed routes?
        // Actually, store_types are linked to routes. Routes are linked to store_types.
        // Let's filter available types based on accessible routes if we want strictness.
        // But usually permissions are handled by restricting routes.
        // For now, let's keep all store types unless we want to do heavy filtering.
        // But let's at least filter routes.
      }
      return types;
    },
    enabled: step === "store",
  });

  const { data: routes } = useQuery({
    queryKey: ["routes-list", storeTypeId, user?.id],
    queryFn: async () => {
      let q = supabase.from("routes").select("*").eq("is_active", true);
      if (storeTypeId) q = q.eq("store_type_id", storeTypeId);
      const { data } = await q;
      let fetchedRoutes = data || [];
      
      // Filter by access
      if (hasMatrixRestrictions) {
        fetchedRoutes = fetchedRoutes.filter(r => canAccessRoute(r.id));
      }
      return fetchedRoutes;
    },
    enabled: step === "store",
  });

  const { data: customers } = useQuery({
    queryKey: ["customers-list-simple"],
    queryFn: async () => {
      const { data } = await supabase.from("customers").select("id, name, phone, display_id").order("name");
      return data || [];
    },
    enabled: step === "customer" && mode === "store",
  });

  const handleNext = () => {
    if (step === "type") {
      if (mode === "store") setStep("customer"); // Select customer
      else setStep("customer"); // Create customer
    } else if (step === "customer") {
      if (mode === "customer") setStep("review");
      else setStep("store");
    } else if (step === "store") {
      setStep("review");
    }
  };

  const captureLocation = async () => {
    setLocating(true);
    const pos = await getCurrentPosition();
    if (pos) {
      setLat(pos.lat);
      setLng(pos.lng);
      // Optional: Reverse geocode could go here, but omitted for speed/simplicity or added later
      toast.success("Location captured");
    } else {
      toast.error("Could not get location");
    }
    setLocating(false);
  };

  const handleSubmit = async () => {
    if (mode !== "customer" && !storeName) return toast.error("Store name required");
    if (mode !== "store" && !custName) return toast.error("Customer name required");
    if (mode !== "store" && (!custPhone || custPhone.length < 10)) return toast.error("Valid customer phone required");

    setSaving(true);

    // Duplicate check if online
    if (isOnline && (mode === "store" || mode === "both")) {
        try {
            const warnings: string[] = [];
            const nameTrimmed = storeName.trim();
            if (nameTrimmed) {
                const { data: nameMatches } = await supabase.from("stores").select("name").eq("is_active", true).ilike("name", nameTrimmed);
                if (nameMatches && nameMatches.length > 0) warnings.push(`A store named "${nameTrimmed}" already exists.`);
            }
            if (lat && lng) {
                const { data: closeStores } = await supabase.rpc("check_store_proximity", { p_lat: lat, p_lng: lng, p_radius_m: 50 });
                if (closeStores && closeStores.length > 0) warnings.push(`There is already a store within 50 meters of this location.`);
            }
            if (warnings.length > 0) {
                const proceed = window.confirm(`WARNING:\n\n${warnings.join('\n')}\n\nDo you still want to create this store?`);
                if (!proceed) {
                    setSaving(false);
                    return;
                }
            }
        } catch (err) {
            console.error("Dupe check failed", err);
        }
    }

    try {
      await processSubmission();

      toast.success("Saved successfully");
      onClose();
    } catch (err: any) {
      toast.error(err.message || "Failed to save");
    } finally {
      setSaving(false);
    }
  };

  const processSubmission = async () => {
      const now = new Date().toISOString();
      let finalCustId = custId;

      // --- CUSTOMER ---
      if (mode === "customer" || mode === "both") {
          const custPayload = {
              name: custName,
              phone: custPhone,
              email: custEmail || null,
              photo_url: custPhoto || null,
              created_at: now,
          };

          if (isOnline) {
               const { data: did } = await supabase.rpc("generate_display_id", { prefix: "CUST", seq_name: "cust_display_seq" });
               const { data: newC, error } = await supabase.from("customers").insert({ ...custPayload, display_id: did }).select("id").single();
               if (error) throw error;
               finalCustId = newC.id;
          } else {
               finalCustId = crypto.randomUUID();
               await addToQueue({
                   id: crypto.randomUUID(),
                   type: "customer",
                   payload: { customerData: { ...custPayload, id: finalCustId } },
                   createdAt: now
               });
          }
      }

      // --- STORE ---
      if (mode === "store" || mode === "both") {
          if (!finalCustId) throw new Error("No customer linked");

          const storePayload = {
              name: storeName,
              customer_id: finalCustId,
              store_type_id: storeTypeId,
              route_id: routeId || null,
              phone: storePhone || custPhone, // Fallback
              address: address || null,
              lat: lat,
              lng: lng,
              created_at: now,
              is_active: true,
          };

          if (isOnline) {
               const { data: did } = await supabase.rpc("generate_display_id", { prefix: "STR", seq_name: "str_display_seq" });
               const { error } = await supabase.from("stores").insert({ ...storePayload, display_id: did });
               if (error) throw error;
          } else {
               await addToQueue({
                   id: crypto.randomUUID(),
                   type: "store",
                   payload: { storeData: { ...storePayload, id: crypto.randomUUID() }, storePricing: [] },
                   createdAt: now
               });
          }
      }
  };

  return (
    <div className="fixed inset-0 bg-slate-50 dark:bg-slate-950 z-50 flex flex-col pt-[env(safe-area-inset-top)]">
        {/* Header */}
        <div className="h-14 flex items-center justify-between px-4 bg-white dark:bg-slate-900 border-b border-slate-200 dark:border-slate-800">
            <button onClick={onClose} className="p-2 -ml-2 rounded-full hover:bg-slate-100 dark:hover:bg-slate-800">
                <ArrowLeft className="h-5 w-5 text-slate-600 dark:text-slate-300" />
            </button>
            <h1 className="text-base font-bold text-slate-800 dark:text-white">
                {step === "type" ? "Add New" : step === "review" ? "Review" : step === "customer" ? "Customer Details" : "Store Details"}
            </h1>
            <div className="w-9" />
        </div>

        {/* Content */}
        <div className="flex-1 overflow-y-auto p-4 pb-20">
            {step === "type" && (
                <div className="grid gap-4">
                    <button 
                        onClick={() => { setMode("both"); setStep("customer"); }}
                        className="p-4 bg-white dark:bg-slate-800 rounded-xl border border-slate-200 dark:border-slate-700 shadow-sm flex items-center gap-4 text-left active:scale-[0.98] transition-transform"
                    >
                        <div className="h-12 w-12 rounded-full bg-blue-100 dark:bg-blue-900/40 flex items-center justify-center">
                            <UserPlus className="h-6 w-6 text-blue-600 dark:text-blue-400" />
                        </div>
                        <div>
                            <h3 className="font-bold text-slate-800 dark:text-white">New Customer + Store</h3>
                            <p className="text-xs text-slate-500 mt-1">Add a new client and their shop location</p>
                        </div>
                        <ChevronRight className="h-5 w-5 text-slate-400 ml-auto" />
                    </button>

                    <button 
                         onClick={() => { setMode("store"); setStep("customer"); }}
                        className="p-4 bg-white dark:bg-slate-800 rounded-xl border border-slate-200 dark:border-slate-700 shadow-sm flex items-center gap-4 text-left active:scale-[0.98] transition-transform"
                    >
                        <div className="h-12 w-12 rounded-full bg-emerald-100 dark:bg-emerald-900/40 flex items-center justify-center">
                            <Store className="h-6 w-6 text-emerald-600 dark:text-emerald-400" />
                        </div>
                        <div>
                            <h3 className="font-bold text-slate-800 dark:text-white">New Store Only</h3>
                            <p className="text-xs text-slate-500 mt-1">For an existing customer</p>
                        </div>
                        <ChevronRight className="h-5 w-5 text-slate-400 ml-auto" />
                    </button>

                    <button 
                        onClick={() => { setMode("customer"); setStep("customer"); }}
                        className="p-4 bg-white dark:bg-slate-800 rounded-xl border border-slate-200 dark:border-slate-700 shadow-sm flex items-center gap-4 text-left active:scale-[0.98] transition-transform"
                    >
                        <div className="h-12 w-12 rounded-full bg-purple-100 dark:bg-purple-900/40 flex items-center justify-center">
                            <User className="h-6 w-6 text-purple-600 dark:text-purple-400" />
                        </div>
                        <div>
                            <h3 className="font-bold text-slate-800 dark:text-white">New Customer Only</h3>
                            <p className="text-xs text-slate-500 mt-1">Register a person without a shop</p>
                        </div>
                        <ChevronRight className="h-5 w-5 text-slate-400 ml-auto" />
                    </button>
                </div>
            )}

            {step === "customer" && (
                <div className="space-y-4">
                    {mode === "store" ? (
                        <div className="space-y-2">
                             <Label>Select Existing Customer</Label>
                             <Select onValueChange={setCustId} value={custId}>
                                <SelectTrigger className="h-12">
                                    <SelectValue placeholder="Search customer..." />
                                </SelectTrigger>
                                <SelectContent>
                                    {customers?.map(c => (
                                        <SelectItem key={c.id} value={c.id}>{c.name} ({c.phone})</SelectItem>
                                    ))}
                                </SelectContent>
                             </Select>
                        </div>
                    ) : (
                        <>
                            <div className="space-y-2">
                                <Label>Full Name</Label>
                                <Input value={custName} onChange={e => setCustName(e.target.value)} placeholder="Enter name" className="h-12" />
                            </div>
                            <div className="space-y-2">
                                <Label>Phone Number</Label>
                                <Input type="tel" value={custPhone} onChange={e => setCustPhone(e.target.value)} placeholder="10-digit mobile" className="h-12" />
                            </div>
                            <div className="space-y-2">
                                <Label>Email (Optional)</Label>
                                <Input type="email" value={custEmail} onChange={e => setCustEmail(e.target.value)} placeholder="email@example.com" className="h-12" />
                            </div>
                        </>
                    )}
                </div>
            )}

            {step === "store" && (
                <div className="space-y-4">
                    <div className="space-y-2">
                        <Label>Store Name</Label>
                        <Input value={storeName} onChange={e => setStoreName(e.target.value)} placeholder="Shop Name" className="h-12" />
                    </div>
                    
                    <div className="grid grid-cols-2 gap-3">
                         <div className="space-y-2">
                             <Label>Type</Label>
                             <Select onValueChange={setStoreTypeId} value={storeTypeId}>
                                <SelectTrigger className="h-12">
                                    <SelectValue placeholder="Select..." />
                                </SelectTrigger>
                                <SelectContent>
                                    {storeTypes?.map(t => <SelectItem key={t.id} value={t.id}>{t.name}</SelectItem>)}
                                </SelectContent>
                             </Select>
                         </div>
                         <div className="space-y-2">
                             <Label>Route</Label>
                             <Select onValueChange={setRouteId} value={routeId}>
                                <SelectTrigger className="h-12">
                                    <SelectValue placeholder="Select..." />
                                </SelectTrigger>
                                <SelectContent>
                                    {routes?.map(r => <SelectItem key={r.id} value={r.id}>{r.name}</SelectItem>)}
                                </SelectContent>
                             </Select>
                         </div>
                    </div>

                    <div className="space-y-2">
                        <Label>Location</Label>
                        <div className="flex gap-2">
                            <Button variant="outline" className="h-12 flex-1" onClick={captureLocation} type="button">
                                {locating ? <Loader2 className="h-4 w-4 animate-spin mr-2" /> : <MapPin className="h-4 w-4 mr-2 text-blue-600" />}
                                {lat ? "Update GPS" : "Capture GPS"}
                            </Button>
                        </div>
                        {lat && <p className="text-xs text-green-600 flex items-center mt-1"><Check className="h-3 w-3 mr-1" /> Coordinates captured: {lat.toFixed(5)}, {lng?.toFixed(5)}</p>}
                    </div>

                    <div className="space-y-2">
                        <Label>Address (Optional)</Label>
                        <Textarea value={address} onChange={e => setAddress(e.target.value)} placeholder="Street, landmark..." />
                    </div>

                    <div className="space-y-2">
                        <Label>Store Photo</Label>
                        <div className="flex gap-2">
                            <Button variant="outline" className="h-12 flex-1" onClick={() => handleTakePhoto("store")} type="button">
                                <Camera className="h-4 w-4 mr-2 text-blue-600" />
                                Upload Photo
                            </Button>
                        </div>
                        {storePhoto && <p className="text-xs text-blue-600 flex items-center mt-1"><Check className="h-3 w-3 mr-1" /> Photo uploaded</p>}
                    </div>
                </div>
            )}

            {step === "review" && (
                <div className="space-y-6">
                    <div className="bg-white dark:bg-slate-800 rounded-xl p-4 border border-slate-200 dark:border-slate-700 space-y-3">
                        <h3 className="font-bold text-sm text-slate-500 uppercase tracking-wider">Customer</h3>
                        <div className="flex items-center gap-3">
                            <div className="h-10 w-10 rounded-full bg-slate-100 flex items-center justify-center">
                                <User className="h-5 w-5 text-slate-500" />
                            </div>
                            <div>
                                <p className="font-semibold">{mode === "store" ? customers?.find(c => c.id === custId)?.name : custName}</p>
                                <p className="text-sm text-slate-500">{mode === "store" ? customers?.find(c => c.id === custId)?.phone : custPhone}</p>
                            </div>
                        </div>
                    </div>

                    {(mode === "store" || mode === "both") && (
                        <div className="bg-white dark:bg-slate-800 rounded-xl p-4 border border-slate-200 dark:border-slate-700 space-y-3">
                            <h3 className="font-bold text-sm text-slate-500 uppercase tracking-wider">Store</h3>
                            <div className="flex items-center gap-3">
                                <div className="h-10 w-10 rounded-xl bg-blue-50 flex items-center justify-center">
                                    <Store className="h-5 w-5 text-blue-600" />
                                </div>
                                <div>
                                    <p className="font-semibold">{storeName}</p>
                                    <p className="text-sm text-slate-500">{storeTypes?.find(t => t.id === storeTypeId)?.name || "No type"}</p>
                                </div>
                            </div>
                            {lat && lng && (
                                <div className="flex items-center gap-2 text-xs text-emerald-600 bg-emerald-50 p-2 rounded-lg">
                                    <MapPin className="h-3 w-3" />
                                    GPS Location included
                                </div>
                            )}
                        </div>
                    )}
                </div>
            )}
        </div>

        {/* Footer Actions */}
        <div className="p-4 bg-white dark:bg-slate-900 border-t border-slate-200 dark:border-slate-800">
            {step === "review" ? (
                <Button className="w-full h-12 text-base bg-blue-600 hover:bg-blue-700" onClick={handleSubmit} disabled={saving}>
                    {saving && <Loader2 className="mr-2 h-4 w-4 animate-spin" />}
                    {saving ? "Saving..." : "Confirm & Save"}
                </Button>
            ) : step !== "type" ? (
                <Button className="w-full h-12 text-base" onClick={handleNext}>
                    Next Step
                </Button>
            ) : null}
        </div>
    </div>
  );
}

import { useMemo, useState } from "react";
import { useQuery, useQueryClient } from "@tanstack/react-query";
import { format, startOfDay } from "date-fns";
import {
  ArrowLeft,
  CheckCircle2,
  HandCoins,
  Loader2,
  Receipt,
  Send,
  Wallet,
  XCircle,
} from "lucide-react";
import { Badge } from "@/components/ui/badge";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select";
import {
  Sheet,
  SheetContent,
  SheetHeader,
  SheetTitle,
} from "@/components/ui/sheet";
import {
  AlertDialog,
  AlertDialogAction,
  AlertDialogCancel,
  AlertDialogContent,
  AlertDialogDescription,
  AlertDialogFooter,
  AlertDialogHeader,
  AlertDialogTitle,
} from "@/components/ui/alert-dialog";
import { Textarea } from "@/components/ui/textarea";
import { useAuth } from "@/contexts/AuthContext";
import { supabase } from "@/integrations/supabase/client";
import { sendNotification } from "@/lib/notifications";
import { cn } from "@/lib/utils";
import { toast } from "sonner";

type TimelineItem = {
  id: string;
  type: "sale" | "transaction";
  amount: number;
  cash: number;
  upi: number;
  created_at: string;
  display_id: string | null;
  store_name: string | null;
};

export function AgentHistory() {
  const { user } = useAuth();
  const qc = useQueryClient();
  const [view, setView] = useState<"activity" | "handovers">("activity");
  const [selectedActivityDate, setSelectedActivityDate] = useState<string | null>(null);
  const [handoverOpen, setHandoverOpen] = useState(false);
  const [showHandoverConfirm, setShowHandoverConfirm] = useState(false);
  const [amount, setAmount] = useState("");
  const [handoverNotes, setHandoverNotes] = useState("");
  const [toUserId, setToUserId] = useState("");
  const [submitting, setSubmitting] = useState(false);

  const todayStart = startOfDay(new Date()).toISOString();

  const { data: handovers, isLoading: loadingHandovers } = useQuery({
    queryKey: ["handovers", user?.id, "mobile-history"],
    queryFn: async () => {
      const { data, error } = await supabase
        .from("handovers")
        .select("id, user_id, handed_to, cash_amount, upi_amount, status, created_at, notes")
        .or(`user_id.eq.${user!.id},handed_to.eq.${user!.id}`)
        .order("created_at", { ascending: false });
      if (error) throw error;
      return (data as any[]) || [];
    },
    enabled: !!user,
    refetchInterval: 60_000,
  });

  const { data: salesForBalance } = useQuery({
    queryKey: ["mobile-history-balance-sales", user?.id],
    queryFn: async () => {
      const { data, error } = await supabase
        .from("sales")
        .select("cash_amount, upi_amount, created_at")
        .eq("recorded_by", user!.id);
      if (error) throw error;
      return (data as any[]) || [];
    },
    enabled: !!user,
    refetchInterval: 60_000,
  });

  const { data: salesTimeline, isLoading: loadingSalesTimeline } = useQuery({
    queryKey: ["mobile-history-sales-timeline", user?.id],
    queryFn: async () => {
      const { data, error } = await supabase
        .from("sales")
        .select("id, display_id, total_amount, cash_amount, upi_amount, created_at, stores(name)")
        .eq("recorded_by", user!.id)
        .order("created_at", { ascending: false })
        .limit(500);
      if (error) throw error;
      return (data as any[]) || [];
    },
    enabled: !!user,
    refetchInterval: 60_000,
  });

  const { data: transactionsTimeline, isLoading: loadingTransactionsTimeline } = useQuery({
    queryKey: ["mobile-history-transactions-timeline", user?.id],
    queryFn: async () => {
      const { data, error } = await supabase
        .from("transactions")
        .select("id, display_id, total_amount, cash_amount, upi_amount, created_at, stores(name)")
        .eq("recorded_by", user!.id)
        .order("created_at", { ascending: false })
        .limit(500);
      if (error) throw error;
      return (data as any[]) || [];
    },
    enabled: !!user,
    refetchInterval: 60_000,
  });

  const { data: staffUsers } = useQuery({
    queryKey: ["mobile-staff-users"],
    queryFn: async () => {
      const { data: roles, error: rolesError } = await supabase
        .from("user_roles")
        .select("user_id, role")
        .in("role", ["super_admin", "manager", "agent", "marketer", "pos"]);

      const roleByUserId = new Map((roles || []).map((row: any) => [row.user_id, row.role]));
      const ids = Array.from(roleByUserId.keys()).filter((id: string) => id !== user!.id);

      let profiles: Array<{ user_id: string; full_name: string | null; email: string | null; phone: string | null }> = [];

      if (!rolesError && ids.length > 0) {
        const { data: filteredProfiles, error: filteredError } = await supabase
          .from("profiles")
          .select("user_id, full_name, email, phone")
          .in("user_id", ids)
          .eq("is_active", true);
        if (!filteredError) {
          profiles = (filteredProfiles || []) as typeof profiles;
        }
      }

      if (profiles.length === 0) {
        const { data: fallbackProfiles, error: fallbackError } = await supabase
          .from("profiles")
          .select("user_id, full_name, email, phone")
          .eq("is_active", true)
          .neq("user_id", user!.id);
        if (fallbackError) throw fallbackError;
        profiles = (fallbackProfiles || []) as typeof profiles;
      }

      const roleLabel: Record<string, string> = {
        super_admin: "Admin",
        manager: "Manager",
        agent: "Agent",
        marketer: "Marketer",
        pos: "POS",
      };

      return (profiles || []).map((profile: any) => {
        const role = roleByUserId.get(profile.user_id) || "agent";
        return {
          ...profile,
          role,
          roleLabel: roleLabel[role] || "Staff",
        };
      });
    },
    enabled: !!user,
  });

  const { data: profiles } = useQuery({
    queryKey: ["profiles", "mobile-history"],
    queryFn: async () => {
      const { data, error } = await supabase
        .from("profiles")
        .select("user_id, full_name")
        .eq("is_active", true);
      if (error) throw error;
      return (data || []) as Array<{ user_id: string; full_name: string | null }>;
    },
    enabled: !!user,
  });

  const profileNameMap = useMemo(() => {
    const map = new Map<string, string>();
    (profiles || []).forEach((profile) => {
      map.set(profile.user_id, profile.full_name || "Staff");
    });
    return map;
  }, [profiles]);

  const timeline = useMemo<TimelineItem[]>(() => {
    const sales = (salesTimeline || []).map((sale: any) => ({
      id: `sale-${sale.id}`,
      type: "sale" as const,
      amount: Number(sale.total_amount || 0),
      cash: Number(sale.cash_amount || 0),
      upi: Number(sale.upi_amount || 0),
      created_at: sale.created_at,
      display_id: sale.display_id || null,
      store_name: sale.stores?.name || null,
    }));

    const transactions = (transactionsTimeline || []).map((transaction: any) => ({
      id: `transaction-${transaction.id}`,
      type: "transaction" as const,
      amount: Number(transaction.total_amount || 0),
      cash: Number(transaction.cash_amount || 0),
      upi: Number(transaction.upi_amount || 0),
      created_at: transaction.created_at,
      display_id: transaction.display_id || null,
      store_name: transaction.stores?.name || null,
    }));

    return [...sales, ...transactions].sort(
      (left, right) => new Date(right.created_at).getTime() - new Date(left.created_at).getTime()
    );
  }, [salesTimeline, transactionsTimeline]);

  const timelineByDate = useMemo(() => {
    return timeline.reduce((groups: Record<string, TimelineItem[]>, item) => {
      const date = item.created_at.split("T")[0];
      if (!groups[date]) groups[date] = [];
      groups[date].push(item);
      return groups;
    }, {});
  }, [timeline]);

  const timelineDates = useMemo(
    () => Object.keys(timelineByDate).sort((left, right) => right.localeCompare(left)),
    [timelineByDate]
  );

  const dayCards = useMemo(
    () =>
      timelineDates.map((date) => {
        const items = timelineByDate[date] || [];
        const salesCount = items.filter((item) => item.type === "sale").length;
        const transactionsCount = items.filter((item) => item.type === "transaction").length;
        const total = items.reduce((sum, item) => sum + item.amount, 0);
        return {
          date,
          items,
          total,
          salesCount,
          transactionsCount,
        };
      }),
    [timelineByDate, timelineDates]
  );

  const getPersonName = (personId: string | null | undefined) => {
    if (!personId) return "Unassigned";
    if (personId === user?.id) return "You";
    return profileNameMap.get(personId) || "Staff";
  };

  const totalSales = (salesForBalance || []).reduce(
    (sum: number, sale: any) => sum + Number(sale.cash_amount || 0) + Number(sale.upi_amount || 0),
    0
  );
  const todaySales = (salesForBalance || []).filter((sale: any) => sale.created_at >= todayStart);
  const todayTotal = todaySales.reduce(
    (sum: number, sale: any) => sum + Number(sale.cash_amount || 0) + Number(sale.upi_amount || 0),
    0
  );

  const sentConfirmed = (handovers || [])
    .filter((handover: any) => handover.user_id === user?.id && handover.status === "confirmed")
    .reduce((sum: number, handover: any) => sum + Number(handover.cash_amount) + Number(handover.upi_amount), 0);
  const sentPending = (handovers || [])
    .filter((handover: any) => handover.user_id === user?.id && handover.status === "awaiting_confirmation")
    .reduce((sum: number, handover: any) => sum + Number(handover.cash_amount) + Number(handover.upi_amount), 0);
  const receivedConfirmed = (handovers || [])
    .filter((handover: any) => handover.handed_to === user?.id && handover.status === "confirmed")
    .reduce((sum: number, handover: any) => sum + Number(handover.cash_amount) + Number(handover.upi_amount), 0);
  const pendingIncoming = (handovers || []).filter(
    (handover: any) => handover.handed_to === user?.id && handover.status === "awaiting_confirmation"
  );
  const notHandedOver = Math.max(0, totalSales + receivedConfirmed - sentConfirmed - sentPending);

  const getStatusTone = (status: string) => {
    if (status === "confirmed") return "bg-emerald-50 dark:bg-emerald-900/30 text-emerald-600 dark:text-emerald-400 border-emerald-200 dark:border-emerald-700";
    if (status === "rejected") return "bg-red-50 dark:bg-red-900/30 text-red-600 dark:text-red-400 border-red-200 dark:border-red-700";
    return "bg-amber-50 dark:bg-amber-900/30 text-amber-600 dark:text-amber-400 border-amber-200 dark:border-amber-700";
  };

  const formatGroupDate = (date: string) => {
    const today = new Date().toISOString().split("T")[0];
    const yesterday = new Date(Date.now() - 86400000).toISOString().split("T")[0];
    if (date === today) return "Today";
    if (date === yesterday) return "Yesterday";
    return format(new Date(`${date}T12:00:00`), "dd MMM yyyy");
  };

  const validateAndConfirmHandover = () => {
    if (!toUserId || !amount || Number(amount) <= 0) {
      toast.error("Select a recipient and enter a valid amount");
      return;
    }
    setShowHandoverConfirm(true);
  };

  const handleHandover = async () => {
    setShowHandoverConfirm(false);
    
    if (!toUserId || !amount || Number(amount) <= 0) {
      toast.error("Select a recipient and enter a valid amount");
      return;
    }

    setSubmitting(true);
    const { error } = await supabase.from("handovers").insert({
      user_id: user!.id,
      handed_to: toUserId,
      cash_amount: Number(amount),
      upi_amount: 0,
      status: "awaiting_confirmation",
      notes: handoverNotes || null,
    });
    setSubmitting(false);

    if (error) {
      toast.error(error.message);
      return;
    }

    toast.success("Handover sent for confirmation");
    sendNotification({
      userId: toUserId,
      title: "Handover Received",
      message: `₹${Number(amount).toLocaleString()} handover awaiting your confirmation`,
      type: "handover",
      entityType: "handover",
    });

    setHandoverOpen(false);
    setAmount("");
    setHandoverNotes("");
    setToUserId("");
    qc.invalidateQueries({ queryKey: ["handovers"] });
  };

  const handleConfirm = async (handoverId: string) => {
    const { error } = await supabase
      .from("handovers")
      .update({
        status: "confirmed",
        confirmed_by: user!.id,
        confirmed_at: new Date().toISOString(),
      })
      .eq("id", handoverId);

    if (error) {
      toast.error(error.message);
      return;
    }

    toast.success("Handover confirmed");
    qc.invalidateQueries({ queryKey: ["handovers"] });
  };

  const handleReject = async (handoverId: string) => {
    const { error } = await supabase
      .from("handovers")
      .update({
        status: "rejected",
        rejected_at: new Date().toISOString(),
      })
      .eq("id", handoverId);

    if (error) {
      toast.error(error.message);
      return;
    }

    toast.success("Handover rejected");
    qc.invalidateQueries({ queryKey: ["handovers"] });
  };

  const timelineLoading = loadingSalesTimeline || loadingTransactionsTimeline;

  if (selectedActivityDate) {
    const selectedItems = timelineByDate[selectedActivityDate] || [];
    const selectedTotal = selectedItems.reduce((sum, item) => sum + item.amount, 0);

    return (
      <div className="pb-6">
        <div className="bg-gradient-to-br from-blue-600 via-blue-700 to-indigo-700 dark:from-slate-900 dark:via-blue-950 dark:to-indigo-950 px-4 pt-4 pb-6">
          <button
            type="button"
            className="h-9 px-3 rounded-xl bg-white/15 text-white text-sm font-semibold flex items-center gap-2"
            onClick={() => setSelectedActivityDate(null)}
          >
            <ArrowLeft className="h-4 w-4" />
            Back
          </button>
          <p className="text-blue-200 text-xs font-medium uppercase tracking-widest mt-3">Activity</p>
          <h2 className="text-white text-xl font-bold mt-0.5">{formatGroupDate(selectedActivityDate)} Records</h2>
          <p className="text-blue-100 text-xs mt-1">
            {selectedItems.length} entries · ₹{selectedTotal.toLocaleString("en-IN")}
          </p>
        </div>

        <div className="px-4 mt-3 space-y-3">
          {timelineLoading ? (
            <div className="flex justify-center items-center py-12 gap-2">
              <Loader2 className="h-6 w-6 animate-spin text-blue-500" />
              <span className="text-sm text-slate-400">Loading records...</span>
            </div>
          ) : selectedItems.length === 0 ? (
            <div className="rounded-2xl border-2 border-dashed border-slate-200 dark:border-slate-700 p-8 text-center bg-slate-50/50 dark:bg-slate-800/30">
              <p className="text-sm font-semibold text-slate-600 dark:text-slate-300">No records available</p>
              <p className="text-xs text-slate-400 mt-1">No sales or transactions were recorded on this day.</p>
            </div>
          ) : (
            selectedItems.map((item) => (
              <div
                key={item.id}
                className="rounded-2xl bg-white dark:bg-slate-800 border border-slate-100 dark:border-slate-700 p-3 shadow-sm"
              >
                <div className="flex items-start justify-between gap-3">
                  <div className="min-w-0 flex-1">
                    <div className="flex items-center gap-2 flex-wrap">
                      <Badge variant="outline" className={cn("text-[10px] font-semibold", item.type === "sale" ? "border-blue-200 text-blue-600 dark:border-blue-700 dark:text-blue-400" : "border-emerald-200 text-emerald-600 dark:border-emerald-700 dark:text-emerald-400")}>
                        {item.type === "sale" ? "Sale" : "Transaction"}
                      </Badge>
                      {item.display_id && <span className="text-[11px] text-slate-400">{item.display_id}</span>}
                    </div>
                    <p className="text-sm font-semibold text-slate-800 dark:text-white mt-1">
                      {item.store_name || "Store"}
                    </p>
                    <div className="flex items-center gap-3 mt-1 text-[11px] text-slate-400">
                      <span>{format(new Date(item.created_at), "hh:mm a")}</span>
                      <span>Cash ₹{item.cash.toLocaleString("en-IN")}</span>
                      <span>UPI ₹{item.upi.toLocaleString("en-IN")}</span>
                    </div>
                  </div>
                  <p className="text-base font-bold text-slate-800 dark:text-white">₹{item.amount.toLocaleString("en-IN")}</p>
                </div>
              </div>
            ))
          )}
        </div>
      </div>
    );
  }

  return (
    <div className="pb-6">
      <div className="bg-gradient-to-br from-blue-600 via-blue-700 to-indigo-700 dark:from-slate-900 dark:via-blue-950 dark:to-indigo-950 px-4 pt-4 pb-10">
        <p className="text-blue-200 text-xs font-medium uppercase tracking-widest">Overview</p>
        <h2 className="text-white text-xl font-bold mt-0.5">History & Handovers</h2>
      </div>

      <div className="px-4 -mt-6 space-y-4">
        <div className="rounded-2xl bg-white dark:bg-slate-800 shadow-xl border border-slate-100 dark:border-slate-700 p-4">
          <p className="text-xs font-bold text-slate-500 dark:text-slate-400 uppercase tracking-widest mb-3">Today's Summary</p>
          <div className="grid grid-cols-2 gap-4">
            <div>
              <p className="text-3xl font-bold text-slate-900 dark:text-white">₹{todayTotal.toLocaleString("en-IN")}</p>
              <div className="flex gap-3 mt-2">
                <span className="flex items-center gap-1 text-xs text-slate-500">
                  <Receipt className="h-3.5 w-3.5 text-blue-500" />
                  {timeline.filter((item) => item.created_at >= todayStart).length} records today
                </span>
              </div>
              <div className="flex gap-3 mt-1">
                <span className="flex items-center gap-1 text-xs text-slate-500">
                  <HandCoins className="h-3.5 w-3.5 text-amber-500" />
                  {(handovers || []).filter((item: any) => item.created_at >= todayStart).length} handovers
                </span>
              </div>
            </div>
            <div className="border-l border-slate-100 dark:border-slate-700 pl-4">
              <p className="text-[10px] text-slate-400 uppercase tracking-widest font-semibold mb-1">Pending Balance</p>
              <p className="text-2xl font-bold text-amber-500">₹{notHandedOver.toLocaleString("en-IN")}</p>
              {sentPending > 0 && (
                <p className="text-[11px] text-amber-400 mt-1">₹{sentPending.toLocaleString("en-IN")} awaiting confirmation</p>
              )}
              {pendingIncoming.length > 0 && (
                <p className="text-[11px] text-slate-400 mt-1">
                  {pendingIncoming.length} incoming request{pendingIncoming.length > 1 ? "s" : ""}
                </p>
              )}
            </div>
          </div>

          <button
            onClick={() => setHandoverOpen(true)}
            disabled={notHandedOver <= 0}
            className={cn(
              "w-full mt-4 h-12 rounded-xl text-sm font-bold flex items-center justify-center gap-2 transition-all",
              notHandedOver > 0
                ? "bg-gradient-to-r from-blue-600 to-indigo-600 hover:from-blue-700 hover:to-indigo-700 text-white shadow-sm active:scale-[0.98]"
                : "bg-slate-100 dark:bg-slate-700 text-slate-400 cursor-not-allowed"
            )}
          >
            <Send className="h-4 w-4" />
            Mark as Handed Over
          </button>
        </div>

        <div className="rounded-2xl bg-white dark:bg-slate-800 shadow-sm border border-slate-100 dark:border-slate-700 p-1 flex gap-1">
          <button
            type="button"
            onClick={() => setView("activity")}
            className={cn(
              "flex-1 rounded-xl px-3 py-3 text-sm font-bold transition-all",
              view === "activity"
                ? "bg-blue-600 text-white shadow-sm"
                : "text-slate-500 dark:text-slate-400 hover:bg-slate-50 dark:hover:bg-slate-700/50"
            )}
          >
            Activity
          </button>
          <button
            type="button"
            onClick={() => setView("handovers")}
            className={cn(
              "flex-1 rounded-xl px-3 py-3 text-sm font-bold transition-all",
              view === "handovers"
                ? "bg-blue-600 text-white shadow-sm"
                : "text-slate-500 dark:text-slate-400 hover:bg-slate-50 dark:hover:bg-slate-700/50"
            )}
          >
            Handovers
          </button>
        </div>

        {view === "activity" && (
          <div className="space-y-3">
            <p className="text-xs font-bold text-slate-500 dark:text-slate-400 uppercase tracking-widest">Daily Activity</p>
            {timelineLoading ? (
              <div className="flex justify-center items-center py-10 gap-2 rounded-2xl bg-white dark:bg-slate-800 border border-slate-100 dark:border-slate-700">
                <Loader2 className="h-6 w-6 animate-spin text-blue-500" />
                <span className="text-sm text-slate-400">Loading day cards...</span>
              </div>
            ) : dayCards.length === 0 ? (
              <div className="rounded-2xl border-2 border-dashed border-slate-200 dark:border-slate-700 p-8 text-center bg-slate-50/50 dark:bg-slate-800/30">
                <p className="text-sm font-semibold text-slate-600 dark:text-slate-300">No activity yet</p>
                <p className="text-xs text-slate-400 mt-1">Day cards will appear after your first sale or transaction.</p>
              </div>
            ) : (
              dayCards.map((card) => (
                <button
                  key={card.date}
                  type="button"
                  onClick={() => setSelectedActivityDate(card.date)}
                  className="w-full text-left rounded-2xl bg-white dark:bg-slate-800 border border-slate-100 dark:border-slate-700 p-4 shadow-sm"
                >
                  <div className="flex items-start justify-between gap-3">
                    <div>
                      <p className="text-sm font-bold text-slate-800 dark:text-white">{formatGroupDate(card.date)}</p>
                      <p className="text-[11px] text-slate-400 mt-1">{card.items.length} records · {card.salesCount} sales · {card.transactionsCount} transactions</p>
                    </div>
                    <p className="text-base font-bold text-slate-800 dark:text-white">₹{card.total.toLocaleString("en-IN")}</p>
                  </div>
                </button>
              ))
            )}
          </div>
        )}

        {view === "handovers" && (
          <div>
            <p className="text-xs font-bold text-slate-500 dark:text-slate-400 uppercase tracking-widest mb-2.5">
              All Handovers
            </p>

            {loadingHandovers ? (
              <div className="flex justify-center items-center py-10 gap-2">
                <Loader2 className="h-6 w-6 animate-spin text-blue-500" />
                <span className="text-sm text-slate-400">Loading handovers...</span>
              </div>
            ) : (handovers?.length ?? 0) === 0 ? (
              <div className="rounded-2xl border-2 border-dashed border-slate-200 dark:border-slate-700 p-8 text-center bg-slate-50/50 dark:bg-slate-800/30">
                <div className="h-12 w-12 rounded-2xl bg-slate-100 dark:bg-slate-700 flex items-center justify-center mx-auto mb-3">
                  <HandCoins className="h-6 w-6 text-slate-400" />
                </div>
                <p className="text-sm font-semibold text-slate-600 dark:text-slate-300">No handovers yet</p>
                <p className="text-xs text-slate-400 mt-1">Requested, confirmed, and rejected handovers will appear here.</p>
              </div>
            ) : (
              <div className="space-y-3">
                {(handovers || []).map((handover: any) => {
                  const total = Number(handover.cash_amount || 0) + Number(handover.upi_amount || 0);
                  const waitingForYou = handover.handed_to === user?.id && handover.status === "awaiting_confirmation";

                  return (
                    <div
                      key={handover.id}
                      className="rounded-2xl bg-white dark:bg-slate-800 border border-slate-100 dark:border-slate-700 shadow-sm p-4"
                    >
                      <div className="flex items-start justify-between gap-3">
                        <div className="min-w-0 flex-1">
                          <div className="flex items-center gap-2 flex-wrap">
                            <p className="text-base font-bold text-slate-800 dark:text-white">₹{total.toLocaleString("en-IN")}</p>
                            <Badge variant="outline" className={cn("text-[10px] font-semibold", getStatusTone(handover.status))}>
                              {handover.status.replaceAll("_", " ")}
                            </Badge>
                          </div>
                          <p className="text-sm text-slate-600 dark:text-slate-300 mt-1">
                            {getPersonName(handover.user_id)} to {getPersonName(handover.handed_to)}
                          </p>
                          <div className="flex items-center gap-2 mt-1 text-[11px] text-slate-400 flex-wrap">
                            <span>{format(new Date(handover.created_at), "dd MMM yyyy, hh:mm a")}</span>
                            {handover.user_id === user?.id && <span>Sent</span>}
                            {handover.handed_to === user?.id && <span>Received</span>}
                          </div>
                          {handover.notes && (
                            <p className="text-xs text-slate-500 dark:text-slate-400 mt-2 leading-relaxed">{handover.notes}</p>
                          )}
                        </div>
                      </div>

                      {waitingForYou && (
                        <div className="grid grid-cols-2 gap-2 mt-3">
                          <Button size="sm" className="h-9 rounded-xl" onClick={() => handleConfirm(handover.id)}>
                            <CheckCircle2 className="h-4 w-4 mr-1.5" />
                            Confirm
                          </Button>
                          <Button size="sm" variant="outline" className="h-9 rounded-xl" onClick={() => handleReject(handover.id)}>
                            <XCircle className="h-4 w-4 mr-1.5" />
                            Reject
                          </Button>
                        </div>
                      )}
                    </div>
                  );
                })}
              </div>
            )}
          </div>
        )}
      </div>

      <Sheet open={handoverOpen} onOpenChange={setHandoverOpen}>
        <SheetContent side="bottom" className="rounded-t-3xl pb-10 px-0">
          <div className="px-6">
            <SheetHeader className="mb-5 text-left">
              <SheetTitle className="text-lg font-bold">Hand Over Cash</SheetTitle>
              <p className="text-xs text-slate-400">Available: ₹{notHandedOver.toLocaleString("en-IN")}</p>
            </SheetHeader>

            <div className="space-y-4">
              <div>
                <Label className="text-xs font-bold text-slate-500 uppercase tracking-widest mb-2 block">Hand over to</Label>
                <Select value={toUserId} onValueChange={setToUserId}>
                  <SelectTrigger className="rounded-xl h-12 border-slate-200 dark:border-slate-600">
                    <SelectValue placeholder="Select recipient..." />
                  </SelectTrigger>
                  <SelectContent>
                    {(staffUsers as any[] || []).map((staff: any) => {
                      const detail = staff.phone || staff.email || "No contact";
                      return (
                        <SelectItem key={staff.user_id} value={staff.user_id}>
                          <div className="flex w-full items-center justify-between gap-3">
                            <span className="font-medium">{staff.full_name || "Staff"}</span>
                            <span className="text-xs text-slate-500 dark:text-slate-400">{staff.roleLabel}</span>
                          </div>
                          <p className="text-xs text-slate-500 dark:text-slate-400 truncate">{detail}</p>
                        </SelectItem>
                      );
                    })}
                  </SelectContent>
                </Select>
              </div>

              <div>
                <Label className="text-xs font-bold text-slate-500 uppercase tracking-widest mb-2 block">Amount</Label>
                <div className="relative">
                  <span className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400 text-base font-semibold">₹</span>
                  <Input
                    type="number"
                    min="0"
                    value={amount}
                    onChange={(event) => setAmount(event.target.value)}
                    placeholder="0"
                    className="pl-8 h-13 rounded-xl text-lg font-bold border-slate-200 dark:border-slate-600"
                  />
                </div>
              </div>

              <div>
                <Label className="text-xs font-bold text-slate-500 uppercase tracking-widest mb-2 block">Notes (optional)</Label>
                <Textarea
                  value={handoverNotes}
                  onChange={(event) => setHandoverNotes(event.target.value)}
                  placeholder="e.g. Cash bag #2, reference number..."
                  className="rounded-xl resize-none border-slate-200 dark:border-slate-600"
                  rows={2}
                />
              </div>

              <button
                className={cn(
                  "w-full h-13 rounded-xl text-base font-bold flex items-center justify-center gap-2 transition-all",
                  submitting
                    ? "bg-blue-400 text-white cursor-not-allowed"
                    : "bg-gradient-to-r from-blue-600 to-indigo-600 hover:from-blue-700 hover:to-indigo-700 text-white shadow-sm active:scale-[0.98]"
                )}
                onClick={validateAndConfirmHandover}
                disabled={submitting}
              >
                {submitting ? <Loader2 className="h-5 w-5 animate-spin" /> : <><Send className="h-4 w-4" />Submit Handover</>}
              </button>
            </div>
          </div>
        </SheetContent>
      </Sheet>

      {/* Handover Confirmation Dialog */}
      <AlertDialog open={showHandoverConfirm} onOpenChange={setShowHandoverConfirm}>
        <AlertDialogContent className="max-w-sm mx-4">
          <AlertDialogHeader>
            <AlertDialogTitle>Confirm Handover</AlertDialogTitle>
            <AlertDialogDescription asChild>
              <div className="space-y-2">
                <p className="text-amber-600 dark:text-amber-400 font-medium">
                  ⚠️ Please verify the amount before submitting!
                </p>
                <div className="bg-slate-50 dark:bg-slate-800 rounded-lg p-3 text-sm space-y-2">
                  <div className="flex justify-between">
                    <span>Amount:</span>
                    <span className="font-bold text-lg text-blue-600">₹{Number(amount || 0).toLocaleString("en-IN")}</span>
                  </div>
                  <div className="flex justify-between">
                    <span>To:</span>
                    <span className="font-medium">
                      {managerStaff?.find(s => s.user_id === toUserId)?.full_name || "Staff"}
                    </span>
                  </div>
                  {handoverNotes && (
                    <div className="border-t pt-2 mt-2">
                      <span className="text-xs text-slate-500">Notes: {handoverNotes}</span>
                    </div>
                  )}
                </div>
                <p className="text-xs text-slate-500 mt-2">
                  This action cannot be undone. The recipient will need to confirm receipt.
                </p>
              </div>
            </AlertDialogDescription>
          </AlertDialogHeader>
          <AlertDialogFooter>
            <AlertDialogCancel>Cancel</AlertDialogCancel>
            <AlertDialogAction onClick={handleHandover} disabled={submitting}>
              {submitting ? "Submitting..." : "Confirm Handover"}
            </AlertDialogAction>
          </AlertDialogFooter>
        </AlertDialogContent>
      </AlertDialog>
    </div>
  );
}

import { useState } from "react";
import { useQuery } from "@tanstack/react-query";
import { supabase } from "@/integrations/supabase/client";
import { VirtualDataTable } from "@/components/shared/VirtualDataTable";
import { Input } from "@/components/ui/input";
import { Badge } from "@/components/ui/badge";
import { Button } from "@/components/ui/button";
import { Search, Filter, ScanLine, X } from "lucide-react";
import { Sheet, SheetContent, SheetHeader, SheetTitle, SheetDescription } from "@/components/ui/sheet";
import { ScrollArea } from "@/components/ui/scroll-area";

export function AgentProducts() {
  const [search, setSearch] = useState("");
  const [categoryFilter, setCategoryFilter] = useState<string | null>(null);
  const [selectedProduct, setSelectedProduct] = useState<any>(null);

  const { data: products, isLoading } = useQuery({
    queryKey: ["mobile-products"],
    queryFn: async () => {
      // Fetch products
      const { data: productsData, error } = await supabase
        .from("products")
        .select(`
          *,
          product_categories(name)
        `)
        .eq("is_active", true)
        .order("name");
      
      if (error) throw error;

      // Fetch stock levels
      const { data: stockData } = await supabase
        .from("product_stock")
        .select("product_id, quantity");

      // Map stock to products (sum quantity across warehouses if multiple)
      const stockMap: Record<string, number> = {};
      stockData?.forEach((item) => {
        stockMap[item.product_id] = (stockMap[item.product_id] || 0) + Number(item.quantity);
      });

      // Merge
      return productsData.map(p => ({
        ...p,
        stock_quantity: stockMap[p.id] || 0
      }));
    },
    staleTime: 1000 * 60 * 5, // 5 minutes cache
  });

  const { data: categories } = useQuery({
    queryKey: ["product-categories"],
    queryFn: async () => {
      const { data } = await supabase
        .from("product_categories")
        .select("id, name")
        .order("name");
      return data || [];
    },
    staleTime: 1000 * 60 * 60, // 1 hour cache
  });

  const filteredProducts = products?.filter(p => {
    const matchesSearch = p.name.toLowerCase().includes(search.toLowerCase()) || 
                          p.sku?.toLowerCase().includes(search.toLowerCase());
    const matchesCategory = categoryFilter ? p.category === categoryFilter || p.product_categories?.name === categoryFilter : true;
    return matchesSearch && matchesCategory;
  }) || [];

  return (
    <div className="flex flex-col h-full bg-background">
      {/* Search Header */}
      <div className="sticky top-0 z-10 bg-background/95 backdrop-blur border-b p-3 space-y-3">
        <div className="relative">
          <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-muted-foreground" />
          <Input 
            value={search} 
            onChange={(e) => setSearch(e.target.value)} 
            placeholder="Search products..." 
            className="pl-9 bg-muted/50 border-none shadow-none focus-visible:ring-1"
          />
          {search && (
            <button 
              onClick={() => setSearch("")} 
              className="absolute right-3 top-1/2 -translate-y-1/2 p-1 text-muted-foreground"
            >
              <X className="h-4 w-4" />
            </button>
          )}
        </div>
        
        {/* Categories scroll */}
        <div className="flex gap-2 overflow-x-auto pb-1 scrollbar-none -mx-3 px-3">
          <Button 
            variant="outline" 
            size="sm" 
            className={`rounded-full h-8 whitespace-nowrap ${!categoryFilter ? "bg-primary text-primary-foreground border-primary" : ""}`}
            onClick={() => setCategoryFilter(null)}
          >
            All
          </Button>
          {categories?.map((c: any) => (
            <Button
              key={c.id}
              variant="outline"
              size="sm"
              className={`rounded-full h-8 whitespace-nowrap ${categoryFilter === c.name ? "bg-primary text-primary-foreground border-primary" : ""}`}
              onClick={() => setCategoryFilter(categoryFilter === c.name ? null : c.name)}
            >
              {c.name}
            </Button>
          ))}
        </div>
      </div>

      {/* Product List */}
      <div className="flex-1 p-0 overflow-y-auto">
        <VirtualDataTable
          columns={[]} // Not used for mobile card render
          data={filteredProducts}
          height="100%"
          renderMobileCard={(p: any) => (
            <div 
              onClick={() => setSelectedProduct(p)}
              className="flex items-center gap-3 p-4 border-b bg-card active:bg-muted/50 transition-colors"
            >
              <div className="h-14 w-14 rounded-lg bg-muted border overflow-hidden flex-shrink-0">
                {p.image_url ? (
                  <img src={p.image_url} alt={p.name} loading="lazy" className="h-full w-full object-cover" />
                ) : (
                  <div className="h-full w-full flex items-center justify-center text-muted-foreground">
                    <ScanLine className="h-6 w-6 opacity-30" />
                  </div>
                )}
              </div>
              <div className="flex-1 min-w-0">
                <h3 className="font-medium text-sm truncate pr-2">{p.name}</h3>
                <div className="flex items-center gap-2 mt-1">
                  <Badge variant="secondary" className="text-[10px] px-1.5 py-0 h-5 font-normal">
                    {p.sku || "No SKU"}
                  </Badge>
                  {p.category && (
                    <span className="text-[10px] text-muted-foreground truncate max-w-[80px]">
                      {p.category}
                    </span>
                  )}
                </div>
              </div>
              <div className="text-right">
                <span className="font-semibold text-sm block">₹{Number(p.base_price).toLocaleString()}</span>
                <span className="text-[10px] text-muted-foreground">per {p.unit}</span>
              </div>
            </div>
          )}
        />
      </div>

      {/* Product Detail Sheet */}
      <Sheet open={!!selectedProduct} onOpenChange={(o) => !o && setSelectedProduct(null)}>
        <SheetContent side="bottom" className="h-[85vh] p-0 rounded-t-xl">
          {selectedProduct && (
            <div className="h-full flex flex-col">
              <div className="relative h-64 bg-muted w-full">
                {selectedProduct.image_url ? (
                   <img 
                    src={selectedProduct.image_url} 
                    alt={selectedProduct.name} 
                    className="h-full w-full object-cover"
                   />
                ) : (
                  <div className="h-full w-full flex items-center justify-center text-muted-foreground">
                    <ScanLine className="h-16 w-16 opacity-20" />
                  </div>
                )}
                <div className="absolute top-4 right-4">
                  <Button size="icon" variant="secondary" className="rounded-full shadow-md h-8 w-8" onClick={() => setSelectedProduct(null)}>
                    <X className="h-4 w-4" />
                  </Button>
                </div>
              </div>

              <div className="flex-1 overflow-y-auto p-6 space-y-6">
                <div>
                  <div className="flex items-start justify-between gap-4">
                    <h2 className="text-xl font-bold leading-tight">{selectedProduct.name}</h2>
                    <div className="text-right shrink-0">
                      <div className="text-lg font-bold text-primary">₹{Number(selectedProduct.base_price).toLocaleString()}</div>
                      <div className="text-xs text-muted-foreground">Base Price</div>
                    </div>
                  </div>
                  <div className="flex flex-wrap gap-2 mt-3">
                    <Badge variant="outline">{selectedProduct.sku}</Badge>
                    <Badge variant="secondary">{selectedProduct.category}</Badge>
                    <Badge variant="outline">Unit: {selectedProduct.unit}</Badge>
                    {selectedProduct.stock_quantity !== null && (
                       <Badge variant={selectedProduct.stock_quantity > 0 ? "default" : "destructive"}>
                         {selectedProduct.stock_quantity > 0 ? `${selectedProduct.stock_quantity} in stock` : "Out of stock"}
                       </Badge>
                    )}
                  </div>
                </div>

                <div className="space-y-2">
                  <h3 className="text-sm font-medium text-foreground/80">Description</h3>
                  <p className="text-sm text-muted-foreground leading-relaxed whitespace-pre-wrap">
                    {selectedProduct.description || "No description available for this product."}
                  </p>
                </div>

                {/* Additional Details could go here (e.g., specific pricing for customer types, taxes) */}
              </div>
              
              <div className="p-4 border-t bg-background">
                <Button className="w-full" onClick={() => setSelectedProduct(null)}>Close</Button>
              </div>
            </div>
          )}
        </SheetContent>
      </Sheet>
    </div>
  );
}

import { useState, useEffect } from "react";
import { useQuery, useQueryClient } from "@tanstack/react-query";
import {
  Loader2, Minus, Plus, ChevronRight, Store as StoreIcon,
  IndianRupee, Banknote, CreditCard, AlertTriangle, ShoppingCart,
  Receipt,
} from "lucide-react";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import {
  AlertDialog,
  AlertDialogAction,
  AlertDialogCancel,
  AlertDialogContent,
  AlertDialogDescription,
  AlertDialogFooter,
  AlertDialogHeader,
  AlertDialogTitle,
} from "@/components/ui/alert-dialog";
import { toast } from "sonner";
import { supabase } from "@/integrations/supabase/client";
import { useAuth } from "@/contexts/AuthContext";
import { usePermission } from "@/hooks/usePermission";
import { addToQueue } from "@/lib/offlineQueue";
import { logActivity } from "@/lib/activityLogger";
import { sendNotificationToMany, getAdminUserIds } from "@/lib/notifications";
import { resolveCreditLimit } from "@/lib/creditLimit";
import { StorePickerSheet, StoreOption } from "@/mobile/components/StorePickerSheet";
import { cn } from "@/lib/utils";

interface SaleItem {
  product_id: string;
  quantity: number;
  unit_price: number;
}

// ─── Record Sale ─────────────────────────────────────────────────────────────
function RecordSale({ preselectStore }: { preselectStore?: StoreOption | null }) {
  const { user, role } = useAuth();
  const { allowed: canOverridePrice } = usePermission("price_override");
  const { allowed: canRecordBehalf } = usePermission("record_behalf");
  const qc = useQueryClient();
  const [saving, setSaving] = useState(false);
  const [showConfirmDialog, setShowConfirmDialog] = useState(false);
  const [store, setStore] = useState<StoreOption | null>(null);
  const [storePickerOpen, setStorePickerOpen] = useState(false);
  const [items, setItems] = useState<SaleItem[]>([]);
  const [cashAmount, setCashAmount] = useState("");
  const [upiAmount, setUpiAmount] = useState("");
  const [recordedFor, setRecordedFor] = useState("");
  const [saleDate, setSaleDate] = useState("");

  useEffect(() => {
    if (preselectStore) {
      setStore(preselectStore);
      setItems([]);
      setCashAmount("");
      setUpiAmount("");
      setRecordedFor("");
      setSaleDate("");
    }
  }, [preselectStore?.id]); // eslint-disable-line react-hooks/exhaustive-deps

  const { data: staffUsers } = useQuery({
    queryKey: ["mobile-staff-for-behalf-sale", user?.id],
    queryFn: async () => {
      const { data: roles } = await supabase.from("user_roles").select("user_id, role").neq("role", "customer");
      const staffIds = roles?.map((r) => r.user_id) || [];
      if (staffIds.length === 0) return [];
      const { data: profs } = await supabase.from("profiles").select("user_id, full_name").in("user_id", staffIds);
      return profs?.filter((p) => p.user_id !== user?.id) || [];
    },
    enabled: canRecordBehalf,
  });

  const { data: availableProducts, isLoading: loadingProducts } = useQuery({
    queryKey: ["mobile-products-for-sale", store?.store_type_id, store?.id],
    queryFn: async () => {
      const storeTypeId = store!.store_type_id!;
      const storeId = store!.id;
      const { data: accessData } = await supabase
        .from("store_type_products")
        .select("product_id, products(id, name, sku, base_price)")
        .eq("store_type_id", storeTypeId);

      let productList: any[];
      if (accessData && accessData.length > 0) {
        productList = accessData.map((a: any) => a.products).filter(Boolean);
      } else {
        const { data } = await supabase.from("products").select("id, name, base_price, sku").eq("is_active", true);
        productList = data || [];
      }

      const { data: typePricing } = await supabase.from("store_type_pricing").select("product_id, price").eq("store_type_id", storeTypeId);
      const typePriceMap: Record<string, number> = {};
      typePricing?.forEach((p: any) => { typePriceMap[p.product_id] = Number(p.price); });

      const { data: storePricing } = await supabase.from("store_pricing").select("product_id, price").eq("store_id", storeId);
      const storePriceMap: Record<string, number> = {};
      storePricing?.forEach((p: any) => { storePriceMap[p.product_id] = Number(p.price); });

      return productList.map((p: any) => {
        let effectivePrice = Number(p.base_price);
        if (typePriceMap[p.id]) effectivePrice = typePriceMap[p.id];
        if (storePriceMap[p.id]) effectivePrice = storePriceMap[p.id];
        return { ...p, effectivePrice };
      });
    },
    enabled: !!store?.store_type_id && !!store?.id,
  });

  const addItem = (productId: string) => {
    const exists = items.find((i) => i.product_id === productId);
    if (exists) {
      setItems(items.map((i) => i.product_id === productId ? { ...i, quantity: i.quantity + 1 } : i));
    } else {
      const p = availableProducts?.find((pr: any) => pr.id === productId);
      if (p) setItems([...items, { product_id: productId, quantity: 1, unit_price: p.effectivePrice }]);
    }
  };

  const updateQty = (productId: string, delta: number) => {
    setItems(items.map((i) => {
      if (i.product_id !== productId) return i;
      const newQty = Math.max(0, i.quantity + delta);
      if (newQty === 0) return null as any;
      return { ...i, quantity: newQty };
    }).filter(Boolean));
  };

  const totalAmount = items.reduce((s, i) => s + i.quantity * i.unit_price, 0);
  const cash = parseFloat(cashAmount) || 0;
  const upi = parseFloat(upiAmount) || 0;
  const outstandingFromSale = totalAmount - cash - upi;
  const oldOutstanding = Number(store?.outstanding ?? 0);
  const newOutstanding = oldOutstanding + outstandingFromSale;

  const { data: storeTypes } = useQuery({
    queryKey: ["mobile-store-types-credit"],
    queryFn: async () => {
      const { data } = await supabase.from("store_types").select("id, credit_limit_kyc, credit_limit_no_kyc");
      return data || [];
    },
  });

  const { data: customers } = useQuery({
    queryKey: ["mobile-customers-kyc-sale"],
    queryFn: async () => {
      const { data } = await supabase.from("customers").select("id, kyc_status, credit_limit_override");
      return data || [];
    },
  });

  const creditLimitInfo = store && storeTypes && customers
    ? resolveCreditLimit(store, storeTypes as any[], customers as any[])
    : null;

  const creditExceeded = !!(creditLimitInfo && creditLimitInfo.limit > 0 && newOutstanding > creditLimitInfo.limit);
  const creditWarning = !!(creditLimitInfo && creditLimitInfo.limit > 0 && newOutstanding > creditLimitInfo.limit * 0.8 && !creditExceeded);

  const updateUnitPrice = (productId: string, value: string) => {
    const parsed = Number(value);
    if (!Number.isFinite(parsed) || parsed < 0) return;
    setItems(items.map((item) => item.product_id === productId ? { ...item, unit_price: parsed } : item));
  };

  // Validation before showing confirmation
  const validateAndConfirm = () => {
    if (!store) { toast.error("Please select a store"); return; }
    if (items.length === 0) { toast.error("Add at least one product"); return; }
    if (totalAmount === 0) { toast.error("Sale total cannot be zero"); return; }
    if (!store.customer_id) { toast.error("Store has no linked customer"); return; }
    if (role === "pos" && outstandingFromSale !== 0) {
      toast.error("POS sales require full payment. Cash + UPI must equal total amount.");
      return;
    }
    if (creditExceeded) { toast.error("Credit limit exceeded. Increase payment or reduce items."); return; }
    
    // Show confirmation dialog
    setShowConfirmDialog(true);
  };

  const handleSubmit = async () => {
    if (!store) { toast.error("Please select a store"); return; }
    setShowConfirmDialog(false);

    setSaving(true);

    const effectiveRecordedBy = recordedFor || user!.id;
    const loggedBy = recordedFor ? user!.id : null;

    if (role === "agent" && store) {
      const { data: locSetting } = await supabase.from("company_settings").select("value").eq("key", "location_validation").maybeSingle();
      if (locSetting?.value === "true") {
        const { checkProximity } = await import("@/lib/proximity");
        const result = await checkProximity(store.lat ?? null, store.lng ?? null);
        if (!result.withinRange) { toast.error(result.message); setSaving(false); return; }
        if (result.skippedNoGps) toast.warning("Store has no GPS — location check skipped");
      }
    }

    const saleData = {
      store_id: store.id,
      customer_id: store.customer_id,
      recorded_by: effectiveRecordedBy,
      logged_by: loggedBy,
      total_amount: totalAmount,
      cash_amount: cash,
      upi_amount: upi,
      outstanding_amount: outstandingFromSale,
      old_outstanding: oldOutstanding,
      new_outstanding: newOutstanding,
      ...(saleDate ? { created_at: new Date(saleDate).toISOString() } : {}),
    };
    const saleItems = items.map((i) => ({ product_id: i.product_id, quantity: i.quantity, unit_price: i.unit_price }));

    if (!navigator.onLine) {
      await addToQueue({ id: crypto.randomUUID(), type: "sale", payload: { saleData, saleItems, storeUpdate: { outstanding: newOutstanding } }, createdAt: new Date().toISOString() });
      toast.warning("Offline — sale queued and will sync automatically");
      setSaving(false);
      resetSale();
      return;
    }

    const { data: displayId } = await (supabase as any).rpc("generate_display_id", { prefix: "SALE", seq_name: "sale_display_seq" });
    const { error } = await (supabase as any).rpc("record_sale", {
      p_display_id: displayId,
      p_store_id: store.id,
      p_customer_id: store.customer_id,
      p_recorded_by: effectiveRecordedBy,
      p_logged_by: loggedBy,
      p_total_amount: totalAmount,
      p_cash_amount: cash,
      p_upi_amount: upi,
      p_outstanding_amount: outstandingFromSale,
      p_sale_items: saleItems,
      p_created_at: saleDate ? new Date(saleDate).toISOString() : null,
    });

    if (error) { toast.error(error.message); setSaving(false); return; }

    logActivity(user!.id, "Recorded sale", "sale", String(displayId), undefined, { total: totalAmount, store: store.id });
    getAdminUserIds().then((ids) => {
      const others = ids.filter((id) => id !== user!.id);
      if (others.length > 0) {
        sendNotificationToMany(others, {
          title: "New Sale Recorded",
          message: `₹${totalAmount.toLocaleString()} sale at ${store.name} (${String(displayId)})`,
          type: "system",
          entityType: "sale",
          entityId: String(displayId),
        });
      }
    });

    toast.success("Sale recorded successfully");
    setSaving(false);
    resetSale();
    qc.invalidateQueries({ queryKey: ["sales"] });
    qc.invalidateQueries({ queryKey: ["mobile-agent-sales-today"] });
  };

  const resetSale = () => {
    setStore(null);
    setItems([]);
    setCashAmount("");
    setUpiAmount("");
    setRecordedFor("");
    setSaleDate("");
  };

  return (
    <div className="space-y-4 pb-6">
      {/* Store selector */}
      <div className="px-4">
        <p className="text-xs font-bold text-slate-500 dark:text-slate-400 uppercase tracking-widest mb-2">Select Store</p>
        <button
          className={cn(
            "w-full border-2 rounded-2xl p-4 flex items-center gap-3 text-left transition-all",
            store
              ? "border-blue-200 dark:border-blue-700 bg-blue-50/50 dark:bg-blue-900/20"
              : "border-dashed border-slate-200 dark:border-slate-700 hover:border-blue-200 dark:hover:border-blue-700 hover:bg-slate-50 dark:hover:bg-slate-800/50"
          )}
          onClick={() => setStorePickerOpen(true)}
          aria-label={store ? `Change store, currently ${store.name}` : "Select a store"}
        >
          <div className={cn(
            "h-10 w-10 rounded-xl flex items-center justify-center shrink-0",
            store ? "bg-blue-100 dark:bg-blue-900/40" : "bg-slate-100 dark:bg-slate-800"
          )}>
            <StoreIcon className={cn("h-5 w-5", store ? "text-blue-500" : "text-slate-400")} />
          </div>
          {store ? (
            <div className="flex-1 min-w-0">
              <p className="text-sm font-bold text-slate-800 dark:text-white truncate">{store.name}</p>
              <p className="text-xs text-slate-400">{store.display_id}</p>
            </div>
          ) : (
            <span className="text-slate-400 text-sm flex-1 font-medium">Tap to select store...</span>
          )}
          <ChevronRight className={cn("h-4 w-4 shrink-0", store ? "text-blue-400" : "text-slate-300")} />
        </button>
      </div>

      {/* Store balance info */}
      {store && (
        <div className="px-4">
          <div className="rounded-2xl bg-white dark:bg-slate-800 border border-slate-100 dark:border-slate-700 p-3.5 flex justify-between items-center">
            <div>
              <p className="text-[10px] text-slate-400 uppercase tracking-widest font-semibold">Current Balance</p>
              <p className={cn("text-xl font-bold mt-0.5", oldOutstanding > 0 ? "text-red-500" : "text-emerald-500")}>
                ₹{oldOutstanding.toLocaleString("en-IN")}
              </p>
            </div>
            {store.customers?.name && (
              <div className="text-right">
                <p className="text-[10px] text-slate-400 uppercase tracking-widest font-semibold">Customer</p>
                <p className="text-sm font-bold text-slate-700 dark:text-slate-200 mt-0.5">{store.customers.name}</p>
              </div>
            )}
          </div>
        </div>
      )}

      {/* Entry options */}
      <div className="px-4">
        <div className="rounded-2xl bg-white dark:bg-slate-800 border border-slate-100 dark:border-slate-700 p-3 space-y-2.5">
          {canRecordBehalf && (
            <div>
              <Label className="text-xs text-slate-500 dark:text-slate-400 font-semibold">Record For</Label>
              <select
                value={recordedFor || "self"}
                onChange={(e) => setRecordedFor(e.target.value === "self" ? "" : e.target.value)}
                className="mt-1 w-full h-10 rounded-xl border border-slate-200 dark:border-slate-600 bg-white dark:bg-slate-900 px-3 text-sm"
              >
                <option value="self">Self</option>
                {(staffUsers as any[])?.map((member: any) => (
                  <option key={member.user_id} value={member.user_id}>{member.full_name || "Staff"}</option>
                ))}
              </select>
            </div>
          )}
          <div>
            <Label className="text-xs text-slate-500 dark:text-slate-400 font-semibold">Sale Date (optional)</Label>
            <Input
              type="date"
              value={saleDate}
              onChange={(e) => setSaleDate(e.target.value)}
              className="mt-1 h-10 rounded-xl border-slate-200 dark:border-slate-600"
            />
          </div>
        </div>
      </div>

      {/* Products */}
      {store && (
        <div className="px-4">
          <p className="text-xs font-bold text-slate-500 dark:text-slate-400 uppercase tracking-widest mb-2.5">Products</p>
          {loadingProducts ? (
            <div className="flex justify-center items-center py-8 gap-2">
              <Loader2 className="h-5 w-5 animate-spin text-blue-500" />
              <span className="text-sm text-slate-400">Loading products...</span>
            </div>
          ) : (
            <div className="space-y-2">
              {(availableProducts || []).map((product: any) => {
                const inCart = items.find((i) => i.product_id === product.id);
                return (
                  <div
                    key={product.id}
                    className={cn(
                      "rounded-2xl border-2 transition-all overflow-hidden",
                      inCart
                        ? "border-blue-200 dark:border-blue-700 bg-blue-50/30 dark:bg-blue-900/10"
                        : "border-slate-100 dark:border-slate-700 bg-white dark:bg-slate-800"
                    )}
                  >
                    <div className="flex items-center p-3.5 gap-3">
                      <div className="flex-1 min-w-0">
                        <p className="text-sm font-semibold text-slate-800 dark:text-white truncate">{product.name}</p>
                        <p className="text-xs text-slate-400 mt-0.5">
                          ₹{product.effectivePrice.toLocaleString("en-IN")} each
                        </p>
                      </div>
                      {inCart ? (
                        <div className="flex items-center gap-2 shrink-0">
                          <span className="text-xs text-slate-400 font-medium">
                            ₹{(inCart.quantity * inCart.unit_price).toLocaleString("en-IN")}
                          </span>
                          <button
                            className="h-8 w-8 rounded-xl border-2 border-slate-200 dark:border-slate-600 flex items-center justify-center hover:bg-slate-100 dark:hover:bg-slate-700 transition-colors"
                            onClick={() => updateQty(product.id, -1)}
                            aria-label={`Decrease ${product.name} quantity`}
                          >
                            <Minus className="h-3.5 w-3.5 text-slate-600 dark:text-slate-300" />
                          </button>
                          <span className="text-sm font-bold text-slate-800 dark:text-white w-7 text-center">
                            {inCart.quantity}
                          </span>
                          <button
                            className="h-8 w-8 rounded-xl bg-blue-600 flex items-center justify-center hover:bg-blue-700 transition-colors"
                            onClick={() => updateQty(product.id, 1)}
                            aria-label={`Increase ${product.name} quantity`}
                          >
                            <Plus className="h-3.5 w-3.5 text-white" />
                          </button>
                        </div>
                      ) : (
                        <button
                          className="h-9 w-9 rounded-xl bg-blue-600 flex items-center justify-center hover:bg-blue-700 active:scale-90 transition-all shadow-sm"
                          onClick={() => addItem(product.id)}
                          aria-label={`Add ${product.name} to cart`}
                        >
                          <Plus className="h-4.5 w-4.5 text-white" />
                        </button>
                      )}
                    </div>
                  </div>
                );
              })}
            </div>
          )}
        </div>
      )}

      {/* Cart & payment */}
      {items.length > 0 && (
        <div className="px-4 space-y-4">
          {/* Cart summary */}
          <div className="rounded-2xl bg-white dark:bg-slate-800 border border-slate-100 dark:border-slate-700 p-4">
            <div className="flex items-center justify-between mb-3">
              <p className="text-xs font-bold text-slate-500 dark:text-slate-400 uppercase tracking-widest">Order Total</p>
              <p className="text-2xl font-bold text-slate-900 dark:text-white">₹{totalAmount.toLocaleString("en-IN")}</p>
            </div>
            <div className="space-y-2">
              {items.map((item) => {
                const p = availableProducts?.find((pr: any) => pr.id === item.product_id);
                return (
                  <div key={item.product_id} className="flex justify-between items-center gap-2 text-xs text-slate-500 dark:text-slate-400">
                    <span className="flex-1">{p?.name ?? "Product"} × {item.quantity}</span>
                    {canOverridePrice ? (
                      <Input
                        type="number"
                        min="0"
                        value={item.unit_price}
                        onChange={(e) => updateUnitPrice(item.product_id, e.target.value)}
                        className="h-7 w-24 text-xs rounded-lg"
                      />
                    ) : (
                      <span className="font-semibold text-slate-700 dark:text-slate-300">
                        ₹{(item.quantity * item.unit_price).toLocaleString("en-IN")}
                      </span>
                    )}
                  </div>
                );
              })}
            </div>
          </div>

          {/* Payment inputs */}
          <div>
            <p className="text-xs font-bold text-slate-500 dark:text-slate-400 uppercase tracking-widest mb-2.5">Payment Received</p>
            <div className="grid grid-cols-2 gap-2">
              <div className="rounded-2xl bg-white dark:bg-slate-800 border border-slate-100 dark:border-slate-700 p-3">
                <div className="flex items-center gap-1.5 mb-2">
                  <Banknote className="h-3.5 w-3.5 text-emerald-500" />
                  <Label className="text-xs text-slate-500 dark:text-slate-400 font-semibold">Cash</Label>
                </div>
                <div className="relative">
                  <span className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400 text-sm">₹</span>
                  <Input
                    type="number"
                    min="0"
                    value={cashAmount}
                    onChange={(e) => setCashAmount(e.target.value)}
                    placeholder="0"
                    className="pl-7 h-11 rounded-xl text-base font-semibold border-slate-200 dark:border-slate-600"
                  />
                </div>
              </div>
              <div className="rounded-2xl bg-white dark:bg-slate-800 border border-slate-100 dark:border-slate-700 p-3">
                <div className="flex items-center gap-1.5 mb-2">
                  <CreditCard className="h-3.5 w-3.5 text-violet-500" />
                  <Label className="text-xs text-slate-500 dark:text-slate-400 font-semibold">UPI</Label>
                </div>
                <div className="relative">
                  <span className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400 text-sm">₹</span>
                  <Input
                    type="number"
                    min="0"
                    value={upiAmount}
                    onChange={(e) => setUpiAmount(e.target.value)}
                    placeholder="0"
                    className="pl-7 h-11 rounded-xl text-base font-semibold border-slate-200 dark:border-slate-600"
                  />
                </div>
              </div>
            </div>
          </div>

          {/* Balance summary */}
          <div className={cn(
            "rounded-2xl p-4 border-2",
            outstandingFromSale > 0
              ? "border-amber-200 dark:border-amber-700/40 bg-amber-50/50 dark:bg-amber-900/10"
              : "border-emerald-200 dark:border-emerald-700/40 bg-emerald-50/50 dark:bg-emerald-900/10"
          )}>
            <div className="space-y-2">
              <div className="flex justify-between text-xs text-slate-500 dark:text-slate-400">
                <span>Existing balance</span>
                <span className="font-semibold">₹{oldOutstanding.toLocaleString("en-IN")}</span>
              </div>
              <div className="flex justify-between text-xs">
                <span className="text-slate-500 dark:text-slate-400">From this sale</span>
                <span className={cn("font-semibold", outstandingFromSale > 0 ? "text-amber-600 dark:text-amber-400" : "text-emerald-600 dark:text-emerald-400")}>
                  {outstandingFromSale >= 0 ? "+" : ""}₹{outstandingFromSale.toLocaleString("en-IN")}
                </span>
              </div>
              <div className="flex justify-between text-sm font-bold border-t border-slate-200 dark:border-slate-600 pt-2 mt-1">
                <span className="text-slate-700 dark:text-slate-200">New balance</span>
                <span className={cn("text-base", newOutstanding > 0 ? "text-red-500" : "text-emerald-500")}>
                  ₹{newOutstanding.toLocaleString("en-IN")}
                </span>
              </div>
            </div>
          </div>

          {creditExceeded && (
            <div className="flex items-center gap-2.5 bg-red-50 dark:bg-red-900/20 border border-red-200 dark:border-red-700/40 rounded-2xl px-4 py-3">
              <AlertTriangle className="h-4 w-4 text-red-500 shrink-0" />
              <span className="text-xs font-medium text-red-700 dark:text-red-400">
                Credit limit exceeded ({creditLimitInfo?.source}). Reduce items or collect more payment.
              </span>
            </div>
          )}

          {creditWarning && (
            <div className="flex items-center gap-2.5 bg-amber-50 dark:bg-amber-900/20 border border-amber-200 dark:border-amber-700/40 rounded-2xl px-4 py-3">
              <AlertTriangle className="h-4 w-4 text-amber-500 shrink-0" />
              <span className="text-xs font-medium text-amber-700 dark:text-amber-400">
                Approaching credit limit ({creditLimitInfo?.source}).
              </span>
            </div>
          )}

          {/* Submit */}
          <button
            className={cn(
              "w-full h-14 rounded-2xl text-white text-base font-bold tracking-wide flex items-center justify-center gap-2 transition-all shadow-lg",
              saving
                ? "bg-blue-400 cursor-not-allowed"
                : "bg-gradient-to-r from-blue-600 to-indigo-600 hover:from-blue-700 hover:to-indigo-700 active:scale-[0.98]"
            )}
            onClick={validateAndConfirm}
            disabled={saving}
          >
            {saving ? (
              <Loader2 className="h-5 w-5 animate-spin" />
            ) : (
              <>
                <Receipt className="h-5 w-5" />
                Record Sale · ₹{totalAmount.toLocaleString("en-IN")}
              </>
            )}
          </button>
        </div>
      )}

      {/* Confirmation Dialog */}
      <AlertDialog open={showConfirmDialog} onOpenChange={setShowConfirmDialog}>
        <AlertDialogContent className="max-w-sm mx-4">
          <AlertDialogHeader>
            <AlertDialogTitle>Confirm Sale</AlertDialogTitle>
            <AlertDialogDescription asChild>
              <div className="space-y-2">
                <p>Please review before recording:</p>
                <div className="bg-slate-50 dark:bg-slate-800 rounded-lg p-3 text-sm space-y-1">
                  <div className="flex justify-between">
                    <span>Store:</span>
                    <span className="font-medium">{store?.name}</span>
                  </div>
                  <div className="flex justify-between">
                    <span>Items:</span>
                    <span className="font-medium">{items.length} products</span>
                  </div>
                  <div className="flex justify-between">
                    <span>Total:</span>
                    <span className="font-bold text-blue-600">₹{totalAmount.toLocaleString("en-IN")}</span>
                  </div>
                  <div className="flex justify-between">
                    <span>Cash:</span>
                    <span>₹{cash.toLocaleString("en-IN")}</span>
                  </div>
                  <div className="flex justify-between">
                    <span>UPI:</span>
                    <span>₹{upi.toLocaleString("en-IN")}</span>
                  </div>
                  {outstandingFromSale > 0 && (
                    <div className="flex justify-between text-amber-600 dark:text-amber-400">
                      <span>Outstanding:</span>
                      <span>₹{outstandingFromSale.toLocaleString("en-IN")}</span>
                    </div>
                  )}
                </div>
              </div>
            </AlertDialogDescription>
          </AlertDialogHeader>
          <AlertDialogFooter>
            <AlertDialogCancel>Cancel</AlertDialogCancel>
            <AlertDialogAction onClick={handleSubmit} disabled={saving}>
              {saving ? "Recording..." : "Confirm Sale"}
            </AlertDialogAction>
          </AlertDialogFooter>
        </AlertDialogContent>
      </AlertDialog>

      <StorePickerSheet
        open={storePickerOpen}
        onOpenChange={setStorePickerOpen}
        onSelect={(s) => {
          setStore(s);
          setItems([]);
          setCashAmount("");
          setUpiAmount("");
        }}
      />
    </div>
  );
}

// ─── Record Payment ───────────────────────────────────────────────────────────
function RecordPayment({ preselectStore }: { preselectStore?: StoreOption | null }) {
  const { user } = useAuth();
  const { allowed: canRecordBehalf } = usePermission("record_behalf");
  const qc = useQueryClient();
  const [saving, setSaving] = useState(false);
  const [store, setStore] = useState<StoreOption | null>(null);
  const [storePickerOpen, setStorePickerOpen] = useState(false);
  const [cashAmount, setCashAmount] = useState("");
  const [upiAmount, setUpiAmount] = useState("");
  const [notes, setNotes] = useState("");
  const [recordedFor, setRecordedFor] = useState("");
  const [txnDate, setTxnDate] = useState("");

  useEffect(() => {
    if (preselectStore) {
      setStore(preselectStore);
      setCashAmount("");
      setUpiAmount("");
      setNotes("");
      setRecordedFor("");
      setTxnDate("");
    }
  }, [preselectStore?.id]); // eslint-disable-line react-hooks/exhaustive-deps

  const { data: staffUsers } = useQuery({
    queryKey: ["mobile-staff-for-behalf-payment", user?.id],
    queryFn: async () => {
      const { data: roles } = await supabase.from("user_roles").select("user_id, role").neq("role", "customer");
      const staffIds = roles?.map((r) => r.user_id) || [];
      if (staffIds.length === 0) return [];
      const { data: profs } = await supabase.from("profiles").select("user_id, full_name").in("user_id", staffIds);
      return profs?.filter((p) => p.user_id !== user?.id) || [];
    },
    enabled: canRecordBehalf,
  });

  const cash = parseFloat(cashAmount) || 0;
  const upi = parseFloat(upiAmount) || 0;
  const totalPayment = cash + upi;
  const oldOutstanding = Number(store?.outstanding ?? 0);
  const newOutstanding = Math.max(0, oldOutstanding - totalPayment);

  const handleSubmit = async () => {
    if (!store) { toast.error("Please select a store"); return; }
    if (totalPayment <= 0) { toast.error("Enter payment amount"); return; }
    if (!store.customer_id) { toast.error("Store has no linked customer"); return; }

    setSaving(true);

    const effectiveRecordedBy = recordedFor || user!.id;
    const loggedBy = recordedFor ? user!.id : null;

    // Offline queue — will sync via the same RPC when back online
    if (!navigator.onLine) {
      await addToQueue({
        id: crypto.randomUUID(),
        type: "transaction",
        payload: {
          txData: {
            store_id: store.id,
            customer_id: store.customer_id,
            recorded_by: effectiveRecordedBy,
            logged_by: loggedBy,
            cash_amount: cash,
            upi_amount: upi,
            notes: notes || null,
            ...(txnDate ? { created_at: new Date(txnDate).toISOString() } : {}),
          },
        },
        createdAt: new Date().toISOString(),
      });
      toast.warning("Offline — payment queued and will sync automatically");
      setSaving(false);
      resetPayment();
      return;
    }

    try {
      const { data: displayId } = await (supabase as any).rpc("generate_display_id", { prefix: "PAY", seq_name: "pay_display_seq" });

      // Use the same atomic RPC as the web Transactions page.
      // This locks the store row, computes outstanding server-side,
      // inserts the transaction, updates store balance, and handles backdated recalc.
      const { data, error } = await supabase.rpc("record_transaction", {
        p_display_id: String(displayId),
        p_store_id: store.id,
        p_customer_id: store.customer_id,
        p_recorded_by: effectiveRecordedBy,
        p_logged_by: loggedBy,
        p_cash_amount: cash,
        p_upi_amount: upi,
        p_notes: notes || null,
        p_created_at: txnDate ? new Date(txnDate).toISOString() : null,
      });

      if (error) { toast.error(error.message); setSaving(false); return; }

      const serverOutstanding = data?.[0]?.new_outstanding ?? newOutstanding;

      logActivity(user!.id, "Recorded transaction", "transaction", String(displayId), undefined, { total: totalPayment, store: store.id });
      getAdminUserIds().then((ids) => {
        const others = ids.filter((id) => id !== user!.id);
        if (others.length > 0) {
          sendNotificationToMany(others, {
            title: "Payment Collected",
            message: `₹${totalPayment.toLocaleString()} collected from ${store.name} (${String(displayId)})`,
            type: "payment",
            entityType: "transaction",
            entityId: String(displayId),
          });
        }
      });

      toast.success(`Payment recorded — Outstanding: ₹${Number(serverOutstanding).toLocaleString()}`);
      setSaving(false);
      resetPayment();
      qc.invalidateQueries({ queryKey: ["transactions"] });
      qc.invalidateQueries({ queryKey: ["mobile-agent-tx-today"] });
    } catch (err: any) {
      toast.error(err?.message || "Failed to record payment");
      setSaving(false);
    }
  };

  const resetPayment = () => {
    setStore(null);
    setCashAmount("");
    setUpiAmount("");
    setNotes("");
    setRecordedFor("");
    setTxnDate("");
  };

  return (
    <div className="space-y-4 pb-6">
      {/* Store selector */}
      <div className="px-4">
        <p className="text-xs font-bold text-slate-500 dark:text-slate-400 uppercase tracking-widest mb-2">Select Store</p>
        <button
          className={cn(
            "w-full border-2 rounded-2xl p-4 flex items-center gap-3 text-left transition-all",
            store
              ? "border-emerald-200 dark:border-emerald-700 bg-emerald-50/50 dark:bg-emerald-900/10"
              : "border-dashed border-slate-200 dark:border-slate-700 hover:border-emerald-200 dark:hover:border-emerald-700 hover:bg-slate-50 dark:hover:bg-slate-800/50"
          )}
          onClick={() => setStorePickerOpen(true)}
        >
          <div className={cn(
            "h-10 w-10 rounded-xl flex items-center justify-center shrink-0",
            store ? "bg-emerald-100 dark:bg-emerald-900/40" : "bg-slate-100 dark:bg-slate-800"
          )}>
            <StoreIcon className={cn("h-5 w-5", store ? "text-emerald-500" : "text-slate-400")} />
          </div>
          {store ? (
            <div className="flex-1 min-w-0">
              <p className="text-sm font-bold text-slate-800 dark:text-white truncate">{store.name}</p>
              <p className="text-xs text-slate-400">{store.display_id}</p>
            </div>
          ) : (
            <span className="text-slate-400 text-sm flex-1 font-medium">Tap to select store...</span>
          )}
          <ChevronRight className={cn("h-4 w-4 shrink-0", store ? "text-emerald-400" : "text-slate-300")} />
        </button>
      </div>

      {/* Balance info */}
      {store && (
        <div className="px-4">
          <div className="rounded-2xl bg-white dark:bg-slate-800 border border-slate-100 dark:border-slate-700 p-3.5 flex justify-between items-center">
            <div>
              <p className="text-[10px] text-slate-400 uppercase tracking-widest font-semibold">Outstanding Balance</p>
              <p className={cn("text-xl font-bold mt-0.5", oldOutstanding > 0 ? "text-red-500" : "text-emerald-500")}>
                ₹{oldOutstanding.toLocaleString("en-IN")}
              </p>
            </div>
            {store.customers?.name && (
              <div className="text-right">
                <p className="text-[10px] text-slate-400 uppercase tracking-widest font-semibold">Customer</p>
                <p className="text-sm font-bold text-slate-700 dark:text-slate-200 mt-0.5">{store.customers.name}</p>
              </div>
            )}
          </div>
        </div>
      )}

      {/* Payment inputs */}
      <div className="px-4">
        <p className="text-xs font-bold text-slate-500 dark:text-slate-400 uppercase tracking-widest mb-2.5">Payment Amount</p>
        <div className="grid grid-cols-2 gap-2">
          <div className="rounded-2xl bg-white dark:bg-slate-800 border border-slate-100 dark:border-slate-700 p-3">
            <div className="flex items-center gap-1.5 mb-2">
              <Banknote className="h-3.5 w-3.5 text-emerald-500" />
              <Label className="text-xs text-slate-500 dark:text-slate-400 font-semibold">Cash</Label>
            </div>
            <div className="relative">
              <span className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400 text-sm">₹</span>
              <Input
                type="number"
                min="0"
                value={cashAmount}
                onChange={(e) => setCashAmount(e.target.value)}
                placeholder="0"
                className="pl-7 h-11 rounded-xl text-base font-semibold border-slate-200 dark:border-slate-600"
              />
            </div>
          </div>
          <div className="rounded-2xl bg-white dark:bg-slate-800 border border-slate-100 dark:border-slate-700 p-3">
            <div className="flex items-center gap-1.5 mb-2">
              <CreditCard className="h-3.5 w-3.5 text-violet-500" />
              <Label className="text-xs text-slate-500 dark:text-slate-400 font-semibold">UPI</Label>
            </div>
            <div className="relative">
              <span className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400 text-sm">₹</span>
              <Input
                type="number"
                min="0"
                value={upiAmount}
                onChange={(e) => setUpiAmount(e.target.value)}
                placeholder="0"
                className="pl-7 h-11 rounded-xl text-base font-semibold border-slate-200 dark:border-slate-600"
              />
            </div>
          </div>
        </div>

        <div className="mt-2">
          <div className="rounded-xl bg-white dark:bg-slate-800 border border-slate-100 dark:border-slate-700 px-3 py-2.5">
            <Input
              value={notes}
              onChange={(e) => setNotes(e.target.value)}
              placeholder="Notes (e.g. cheque no., reference...)"
              className="border-0 p-0 h-auto text-sm bg-transparent shadow-none focus-visible:ring-0"
            />
          </div>
        </div>

        <div className="mt-2 rounded-2xl bg-white dark:bg-slate-800 border border-slate-100 dark:border-slate-700 p-3 space-y-2.5">
          {canRecordBehalf && (
            <div>
              <Label className="text-xs text-slate-500 dark:text-slate-400 font-semibold">Record For</Label>
              <select
                value={recordedFor || "self"}
                onChange={(e) => setRecordedFor(e.target.value === "self" ? "" : e.target.value)}
                className="mt-1 w-full h-10 rounded-xl border border-slate-200 dark:border-slate-600 bg-white dark:bg-slate-900 px-3 text-sm"
              >
                <option value="self">Self</option>
                {(staffUsers as any[])?.map((member: any) => (
                  <option key={member.user_id} value={member.user_id}>{member.full_name || "Staff"}</option>
                ))}
              </select>
            </div>
          )}
          <div>
            <Label className="text-xs text-slate-500 dark:text-slate-400 font-semibold">Payment Date (optional)</Label>
            <Input
              type="date"
              value={txnDate}
              onChange={(e) => setTxnDate(e.target.value)}
              className="mt-1 h-10 rounded-xl border-slate-200 dark:border-slate-600"
            />
          </div>
        </div>
      </div>

      {/* Summary + submit */}
      {store && totalPayment > 0 && (
        <div className="px-4 space-y-3">
          <div className="rounded-2xl bg-emerald-50/50 dark:bg-emerald-900/10 border-2 border-emerald-200 dark:border-emerald-700/40 p-4 space-y-2">
            <div className="flex justify-between text-xs text-slate-500 dark:text-slate-400">
              <span>Collecting</span>
              <span className="font-bold text-emerald-600 dark:text-emerald-400">₹{totalPayment.toLocaleString("en-IN")}</span>
            </div>
            <div className="flex justify-between text-xs text-slate-500 dark:text-slate-400">
              <span>Current balance</span>
              <span className="font-semibold">₹{oldOutstanding.toLocaleString("en-IN")}</span>
            </div>
            <div className="flex justify-between text-sm font-bold border-t border-emerald-200 dark:border-emerald-700/40 pt-2">
              <span className="text-slate-700 dark:text-slate-200">New balance</span>
              <span className={cn("text-base", newOutstanding > 0 ? "text-red-500" : "text-emerald-500")}>
                ₹{newOutstanding.toLocaleString("en-IN")}
              </span>
            </div>
          </div>

          {totalPayment > oldOutstanding && oldOutstanding > 0 && (
            <div className="flex items-center gap-2.5 bg-amber-50 dark:bg-amber-900/20 border border-amber-200 dark:border-amber-700/40 rounded-2xl px-4 py-3">
              <AlertTriangle className="h-4 w-4 text-amber-500 shrink-0" />
              <span className="text-xs font-medium text-amber-700 dark:text-amber-400">
                Payment exceeds outstanding balance
              </span>
            </div>
          )}

          <button
            className={cn(
              "w-full h-14 rounded-2xl text-white text-base font-bold tracking-wide flex items-center justify-center gap-2 transition-all shadow-lg",
              saving
                ? "bg-emerald-400 cursor-not-allowed"
                : "bg-gradient-to-r from-emerald-500 to-teal-600 hover:from-emerald-600 hover:to-teal-700 active:scale-[0.98]"
            )}
            onClick={handleSubmit}
            disabled={saving}
          >
            {saving ? (
              <Loader2 className="h-5 w-5 animate-spin" />
            ) : (
              <>
                <IndianRupee className="h-5 w-5" />
                Collect ₹{totalPayment.toLocaleString("en-IN")}
              </>
            )}
          </button>
        </div>
      )}

      <StorePickerSheet
        open={storePickerOpen}
        onOpenChange={setStorePickerOpen}
        onSelect={setStore}
      />
    </div>
  );
}

// ─── Combined Record Page ─────────────────────────────────────────────────────
interface AgentRecordProps {
  preselectStore?: StoreOption | null;
  preselectTab?: "sale" | "payment";
  allowSale?: boolean;
  allowPayment?: boolean;
}

export function AgentRecord({
  preselectStore,
  preselectTab,
  allowSale = true,
  allowPayment = true,
}: AgentRecordProps) {
  const initialTab = !allowSale ? "payment" : (preselectTab ?? "sale");
  const [activeTab, setActiveTab] = useState<string>(initialTab);

  useEffect(() => {
    if (!allowPayment) {
      setActiveTab("sale");
      return;
    }
    if (!allowSale) {
      setActiveTab("payment");
      return;
    }
    if (preselectStore && preselectTab) setActiveTab(preselectTab);
  }, [preselectStore?.id, preselectTab, allowSale, allowPayment]);

  return (
    <div className="pb-4">
      {/* Tab selector header */}
      <div className="bg-gradient-to-br from-blue-600 via-blue-700 to-indigo-700 dark:from-slate-900 dark:via-blue-950 dark:to-indigo-950 px-4 pt-4 pb-6">
        <p className="text-blue-200 text-xs font-medium uppercase tracking-widest mb-3">Action</p>
        <div className="bg-white/15 backdrop-blur-sm rounded-2xl p-1 flex gap-1">
          {allowSale && (
            <button
              onClick={() => setActiveTab("sale")}
              className={cn(
                "flex-1 flex items-center justify-center gap-2 py-2.5 rounded-xl text-sm font-bold transition-all",
                activeTab === "sale"
                  ? "bg-white text-blue-700 shadow-sm"
                  : "text-white/80 hover:text-white hover:bg-white/10"
              )}
            >
              <ShoppingCart className="h-4 w-4" />
              Record Sale
            </button>
          )}
          {allowPayment && (
            <button
              onClick={() => setActiveTab("payment")}
              className={cn(
                `${allowSale ? "flex-1" : "w-full"} flex items-center justify-center gap-2 py-2.5 rounded-xl text-sm font-bold transition-all`,
                activeTab === "payment"
                  ? "bg-white text-emerald-700 shadow-sm"
                  : "text-white/80 hover:text-white hover:bg-white/10"
              )}
            >
              <Banknote className="h-4 w-4" />
              Collect Payment
            </button>
          )}
        </div>
      </div>

      <div className="mt-4">
        {allowSale && activeTab === "sale" && <RecordSale preselectStore={preselectStore} />}
        {allowPayment && activeTab === "payment" && <RecordPayment preselectStore={preselectStore} />}
      </div>
    </div>
  );
}

import { useMemo, useState } from "react";
import { useQuery } from "@tanstack/react-query";
import { toast } from "sonner";
import {
  ArrowLeft,
  CheckCircle2,
  Loader2,
  MapPin,
  Navigation2,
  Package,
  Phone,
  Store,
  Wallet,
  ShoppingCart,
} from "lucide-react";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import { supabase } from "@/integrations/supabase/client";
import { useAuth } from "@/contexts/AuthContext";
import type { StoreOption } from "@/mobile/components/StorePickerSheet";
import { getCurrentPosition } from "@/lib/capacitorUtils";
import { addToQueue } from "@/lib/offlineQueue";

interface Props {
  store: StoreOption;
  onBack: () => void;
  onGoRecord: (store: StoreOption, action: "sale" | "payment") => void;
}

interface StoreProfileRow {
  id: string;
  name: string;
  display_id: string;
  photo_url: string | null;
  outstanding: number;
  address: string | null;
  phone: string | null;
  lat: number | null;
  lng: number | null;
  route_id: string | null;
  store_type_id: string | null;
  customers: { name: string; phone: string | null } | null;
  store_types: { name: string } | null;
  routes: { name: string } | null;
}

export function AgentStoreProfile({ store, onBack, onGoRecord }: Props) {
  const { user } = useAuth();
  const [visitLoading, setVisitLoading] = useState(false);

  const { data: storeRow, isLoading } = useQuery({
    queryKey: ["mobile-store-profile", store.id],
    queryFn: async () => {
      const { data, error } = await supabase
        .from("stores")
        .select("id, name, display_id, photo_url, outstanding, address, phone, lat, lng, route_id, store_type_id, customers(name, phone), store_types(name), routes(name)")
        .eq("id", store.id)
        .maybeSingle();
      if (error) throw error;
      return (data as unknown as StoreProfileRow | null) || null;
    },
    enabled: !!store.id,
  });

  const currentStore: StoreOption = useMemo(() => ({
    ...store,
    ...(storeRow || {}),
    customers: storeRow?.customers || store.customers || null,
    store_types: storeRow?.store_types || store.store_types || null,
    routes: storeRow?.routes || store.routes || null,
  }), [store, storeRow]);

  const storeTypeId = storeRow?.store_type_id || null;

  const { data: storeProducts } = useQuery({
    queryKey: ["mobile-store-products", store.id, storeTypeId],
    queryFn: async () => {
      if (!storeTypeId) {
        const { data } = await supabase.from("products").select("id, name, sku, base_price").eq("is_active", true).order("name");
        return data || [];
      }
      const { data: accessData } = await supabase
        .from("store_type_products")
        .select("product_id, products(id, name, sku, base_price)")
        .eq("store_type_id", storeTypeId);
      if (accessData && accessData.length > 0) {
        return accessData.map((a: any) => a.products).filter(Boolean);
      }
      const { data } = await supabase.from("products").select("id, name, sku, base_price").eq("is_active", true).order("name");
      return data || [];
    },
    enabled: !!storeRow,
  });

  const { data: typeP } = useQuery({
    queryKey: ["mobile-store-type-pricing", storeTypeId],
    queryFn: async () => {
      const { data } = await supabase.from("store_type_pricing").select("product_id, price").eq("store_type_id", storeTypeId!);
      const map: Record<string, number> = {};
      data?.forEach((p) => { map[p.product_id] = Number(p.price); });
      return map;
    },
    enabled: !!storeTypeId,
  });

  const { data: storeP } = useQuery({
    queryKey: ["mobile-store-pricing", store.id],
    queryFn: async () => {
      const { data } = await supabase.from("store_pricing").select("product_id, price").eq("store_id", store.id);
      const map: Record<string, number> = {};
      data?.forEach((p) => { map[p.product_id] = Number(p.price); });
      return map;
    },
    enabled: !!store.id,
  });

  const getPrice = (productId: string, basePrice: number) => {
    if (storeP && productId in storeP) return { price: storeP[productId], label: "store" as const };
    if (typeP && productId in typeP) return { price: typeP[productId], label: "type" as const };
    return { price: basePrice, label: "base" as const };
  };

  const handleNavigate = () => {
    if (currentStore.lat != null && currentStore.lng != null) {
      window.open(`https://www.google.com/maps/dir/?api=1&destination=${currentStore.lat},${currentStore.lng}`, "_blank");
      return;
    }

    if (currentStore.address) {
      window.open(`https://www.google.com/maps/dir/?api=1&destination=${encodeURIComponent(currentStore.address)}`, "_blank");
    }
  };

  const handleCall = () => {
    const phone = currentStore.phone || (currentStore.customers as any)?.phone || null;
    if (!phone) return;
    window.open(`tel:${phone}`, "_self");
  };

  const handleMarkVisited = async () => {
    if (!user) return;

    setVisitLoading(true);
    try {
      let lat: number | null = null;
      let lng: number | null = null;
      const pos = await getCurrentPosition();
      if (pos) {
        lat = pos.lat;
        lng = pos.lng;
      }

      if (!navigator.onLine) {
        await addToQueue({
          id: crypto.randomUUID(),
          type: "visit",
          payload: {
            userId: user.id,
            storeId: currentStore.id,
            lat,
            lng,
          },
          createdAt: new Date().toISOString(),
        });
        toast.warning(`Offline — visit queued for ${currentStore.name}`);
        return;
      }

      const { data: session } = await supabase
        .from("route_sessions")
        .select("id")
        .eq("user_id", user.id)
        .eq("status", "active")
        .maybeSingle();

      if (!session) {
        toast.error("No active route session. Start a route first.");
        setVisitLoading(false);
        return;
      }

      const { error } = await supabase.from("store_visits").insert({
        session_id: session.id,
        store_id: currentStore.id,
        lat,
        lng,
      });

      if (error) throw error;
      toast.success(`Visit recorded for ${currentStore.name}`);
    } catch {
      toast.error("Failed to record visit");
    } finally {
      setVisitLoading(false);
    }
  };

  const phone = currentStore.phone || (currentStore.customers as any)?.phone || null;
  const canNavigate = (currentStore.lat != null && currentStore.lng != null) || !!currentStore.address;

  return (
    <div className="pb-6">
      <div className="bg-gradient-to-br from-blue-600 via-blue-700 to-indigo-700 dark:from-slate-900 dark:via-blue-950 dark:to-indigo-950 px-4 pt-4 pb-6">
        <button
          type="button"
          className="h-9 px-3 rounded-xl bg-white/15 text-white text-sm font-semibold flex items-center gap-2"
          onClick={onBack}
        >
          <ArrowLeft className="h-4 w-4" />
          Back
        </button>
        <p className="text-blue-200 text-xs font-medium uppercase tracking-widest mt-3">Store Profile</p>
        <h2 className="text-white text-xl font-bold mt-0.5">{currentStore.name}</h2>
      </div>

      <div className="px-4 -mt-4 space-y-3">
        <div className="rounded-2xl bg-white dark:bg-slate-800 border border-slate-100 dark:border-slate-700 shadow-sm overflow-hidden">
          <div className="h-44 w-full bg-slate-100 dark:bg-slate-700">
            {currentStore.photo_url ? (
              <img src={currentStore.photo_url} alt={currentStore.name} loading="lazy" className="h-full w-full object-cover" />
            ) : (
              <div className="h-full w-full flex items-center justify-center">
                <Store className="h-10 w-10 text-slate-400" />
              </div>
            )}
          </div>

          <div className="p-4">
            <div className="flex items-start justify-between gap-2">
              <div>
                <p className="text-base font-bold text-slate-800 dark:text-white">{currentStore.name}</p>
                <p className="text-xs text-slate-400 mt-0.5">{currentStore.display_id}</p>
              </div>
              <p className={`text-base font-bold ${Number(currentStore.outstanding || 0) > 0 ? "text-red-500" : "text-emerald-500"}`}>
