            </div>
          </div>
        </div>

        <div className="rounded-2xl bg-white dark:bg-slate-800 border border-slate-100 dark:border-slate-700 p-4 shadow-sm">
          <p className="text-xs font-bold text-slate-500 dark:text-slate-400 uppercase tracking-widest mb-2">Quick Actions</p>
          {isLoading ? (
            <div className="flex justify-center py-5"><Loader2 className="h-5 w-5 animate-spin text-blue-500" /></div>
          ) : (
            <div className="grid grid-cols-3 gap-2">
              <button
                onClick={() => onGoRecord(currentStore, "sale")}
                className="flex flex-col items-center gap-2 p-3 rounded-2xl bg-blue-600 hover:bg-blue-700 active:scale-95 transition-all shadow-sm"
              >
                <ShoppingCart className="h-5 w-5 text-white" />
                <span className="text-[11px] font-bold text-white text-center">Record Sale</span>
              </button>
              <button
                onClick={() => onGoRecord(currentStore, "payment")}
                className="flex flex-col items-center gap-2 p-3 rounded-2xl bg-white dark:bg-slate-800 border border-slate-200 dark:border-slate-700 hover:bg-slate-50 dark:hover:bg-slate-750 active:scale-95 transition-all shadow-sm"
              >
                <Wallet className="h-5 w-5 text-emerald-500" />
                <span className="text-[11px] font-bold text-slate-700 dark:text-slate-200 text-center">Record Transaction</span>
              </button>
              <button
                onClick={handleMarkVisited}
                disabled={visitLoading}
                className="flex flex-col items-center gap-2 p-3 rounded-2xl bg-white dark:bg-slate-800 border border-emerald-200 dark:border-emerald-800/40 hover:bg-emerald-50 dark:hover:bg-emerald-900/20 active:scale-95 transition-all shadow-sm disabled:opacity-60"
              >
                {visitLoading ? <Loader2 className="h-5 w-5 text-emerald-500 animate-spin" /> : <CheckCircle2 className="h-5 w-5 text-emerald-500" />}
                <span className="text-[11px] font-bold text-emerald-600 dark:text-emerald-400 text-center">Mark Visited</span>
              </button>
            </div>
          )}
        </div>

        {/* Products Section */}
        {storeProducts && storeProducts.length > 0 && (
          <div className="rounded-2xl bg-white dark:bg-slate-800 border border-slate-100 dark:border-slate-700 p-4 shadow-sm">
            <p className="text-xs font-bold text-slate-500 dark:text-slate-400 uppercase tracking-widest mb-3 flex items-center gap-1.5">
              <Package className="h-3.5 w-3.5" />
              Products & Pricing ({storeProducts.length})
            </p>
            <div className="space-y-2">
              {storeProducts.map((p: any) => {
                const { price, label } = getPrice(p.id, Number(p.base_price));
                return (
                  <div key={p.id} className="flex items-center justify-between gap-3">
                    <div className="min-w-0 flex-1">
                      <p className="text-sm font-medium text-slate-800 dark:text-white truncate">{p.name}</p>
                      <span className="text-[10px] text-slate-400 font-mono">{p.sku}</span>
                    </div>
                    <div className="text-right shrink-0">
                      <p className="text-sm font-bold text-slate-800 dark:text-white">₹{price.toLocaleString("en-IN")}</p>
                      <span className={`text-[10px] font-semibold capitalize ${
                        label === "store" ? "text-blue-600 dark:text-blue-400" :
                        label === "type" ? "text-violet-600 dark:text-violet-400" :
                        "text-slate-400"
                      }`}>{label}</span>
                    </div>
                  </div>
                );
              })}
            </div>
          </div>
        )}
      </div>
    </div>
  );
}

import { useRef, useState } from "react";
import { useQuery, useQueryClient } from "@tanstack/react-query";
import { supabase } from "@/integrations/supabase/client";
import { useAuth } from "@/contexts/AuthContext";
import { useOnlineStatus } from "@/hooks/useOnlineStatus";
import { queueFileUpload, fileToArrayBuffer, PendingFileUpload } from "@/lib/offlineQueue";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import { Loader2, Upload, CheckCircle2, Clock, XCircle, Camera, Image as ImageIcon, FileText, WifiOff } from "lucide-react";
import { toast } from "sonner";
import { cn } from "@/lib/utils";

type KycField = "kyc_selfie_url" | "kyc_aadhar_front_url" | "kyc_aadhar_back_url";

interface CustomerKycData {
  id: string;
  name: string;
  kyc_status: string | null;
  kyc_selfie_url: string | null;
  kyc_aadhar_front_url: string | null;
  kyc_aadhar_back_url: string | null;
  kyc_rejection_reason: string | null;
  kyc_submitted_at: string | null;
}

const DOC_FIELDS: { label: string; hint: string; field: KycField; icon: React.ReactNode }[] = [
  { label: "Selfie Photo", hint: "Clear face photo in good lighting", field: "kyc_selfie_url", icon: <Camera className="h-5 w-5" /> },
  { label: "Aadhaar Front", hint: "Front side showing name and number", field: "kyc_aadhar_front_url", icon: <FileText className="h-5 w-5" /> },
  { label: "Aadhaar Back", hint: "Back side showing address", field: "kyc_aadhar_back_url", icon: <FileText className="h-5 w-5" /> },
];

function StatusBadge({ status }: { status: string | null }) {
  if (!status || status === "not_requested") return <Badge variant="outline">Not submitted</Badge>;
  if (status === "pending") return <Badge variant="secondary" className="bg-amber-100 text-amber-700 border-amber-200">Under review</Badge>;
  if (status === "verified") return <Badge className="bg-emerald-100 text-emerald-700 border-emerald-200">Verified</Badge>;
  if (status === "rejected") return <Badge variant="destructive">Rejected</Badge>;
  return <Badge variant="outline">{status}</Badge>;
}

export function CustomerKyc() {
  const { user } = useAuth();
  const qc = useQueryClient();
  const { isOnline } = useOnlineStatus();
  const [uploading, setUploading] = useState<KycField | null>(null);
  const fileRefs = {
    kyc_selfie_url: useRef<HTMLInputElement>(null),
    kyc_aadhar_front_url: useRef<HTMLInputElement>(null),
    kyc_aadhar_back_url: useRef<HTMLInputElement>(null),
  };

  const { data: customer, isLoading } = useQuery<CustomerKycData | null>({
    queryKey: ["customer-kyc", user?.id],
    queryFn: async () => {
      const { data } = await supabase
        .from("customers")
        .select("id, name, kyc_status, kyc_selfie_url, kyc_aadhar_front_url, kyc_aadhar_back_url, kyc_rejection_reason, kyc_submitted_at")
        .eq("linked_user_id", user!.id)
        .maybeSingle();
      return (data as CustomerKycData) || null;
    },
    enabled: !!user,
  });

  const uploadDoc = async (field: KycField, file: File) => {
    if (!customer) return;
    if (file.size > 10 * 1024 * 1024) { toast.error("File too large. Max 10MB."); return; }
    const allowed = ["image/jpeg", "image/png", "image/heic", "image/webp"];
    if (!allowed.includes(file.type)) { toast.error("Only JPG, PNG, HEIC or WebP images allowed."); return; }

    const ext = file.name.split(".").pop() || "jpg";
    const path = `${customer.id}/${field}_${Date.now()}.${ext}`;

    // If offline, queue the file upload for later
    if (!isOnline) {
      try {
        setUploading(field);
        const fileData = await fileToArrayBuffer(file);
        await queueFileUpload({
          id: `kyc-${customer.id}-${field}-${Date.now()}`,
          type: "kyc",
          fileName: file.name,
          bucket: "kyc-documents",
          path,
          fileData,
          contentType: file.type,
          metadata: {
            customerId: customer.id,
            field,
          },
        });
        setUploading(null);
        toast.success("Document saved for upload when online", {
          icon: <WifiOff className="h-4 w-4" />,
        });
        return;
      } catch (err: any) {
        setUploading(null);
        toast.error("Failed to queue file: " + err.message);
        return;
      }
    }

    setUploading(field);
    const { error: uploadErr } = await supabase.storage
      .from("kyc-documents")
      .upload(path, file, { upsert: true });

    if (uploadErr) {
      toast.error("Upload failed: " + uploadErr.message);
      setUploading(null);
      return;
    }

    const { data: urlData } = supabase.storage.from("kyc-documents").getPublicUrl(path);

    const updated: Record<string, string | null> = { [field]: urlData.publicUrl };

    const current = {
      kyc_selfie_url: customer.kyc_selfie_url,
      kyc_aadhar_front_url: customer.kyc_aadhar_front_url,
      kyc_aadhar_back_url: customer.kyc_aadhar_back_url,
      [field]: urlData.publicUrl,
    };

    if (current.kyc_selfie_url && current.kyc_aadhar_front_url && current.kyc_aadhar_back_url) {
      updated.kyc_status = "pending";
      updated.kyc_submitted_at = new Date().toISOString();
    }

    const { error: dbErr } = await supabase.from("customers").update(updated).eq("id", customer.id);
    setUploading(null);

    if (dbErr) { toast.error("Failed to save: " + dbErr.message); return; }

    if (updated.kyc_status === "pending") {
      toast.success("All documents uploaded! Your KYC is now under review.");
    } else {
      toast.success("Document uploaded successfully.");
    }
    qc.invalidateQueries({ queryKey: ["customer-kyc"] });
    qc.invalidateQueries({ queryKey: ["mobile-customer"] });
  };

  const handleFileChange = (field: KycField) => async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    await uploadDoc(field, file);
    e.target.value = "";
  };

  if (isLoading) {
    return (
      <div className="flex flex-col items-center justify-center min-h-[60vh] gap-3">
        <Loader2 className="h-8 w-8 animate-spin text-primary" />
        <p className="text-sm text-muted-foreground">Loading KYC details…</p>
      </div>
    );
  }

  if (!customer) {
    return (
      <div className="flex flex-col items-center justify-center min-h-[60vh] gap-3 px-6 text-center">
        <FileText className="h-10 w-10 text-muted-foreground/50" />
        <p className="text-sm text-muted-foreground">No customer account linked to your profile.</p>
      </div>
    );
  }

  const status = customer.kyc_status || "not_requested";
  const isVerified = status === "verified";
  const isPending = status === "pending";
  const isRejected = status === "rejected";
  const canUpload = !isPending && !isVerified;

  return (
    <div className="flex flex-col min-h-screen bg-slate-50 dark:bg-slate-950 pb-24">
      <div className="bg-white dark:bg-slate-900 border-b border-slate-100 dark:border-slate-800 px-4 pt-10 pb-5 safe-top">
        <p className="text-xs font-bold uppercase tracking-widest text-slate-400 mb-1">KYC Verification</p>
        <h1 className="text-xl font-bold text-slate-900 dark:text-white">{customer.name}</h1>
        <div className="mt-2"><StatusBadge status={status} /></div>
      </div>

      <div className="px-4 py-5 space-y-4">
        {isVerified && (
          <div className="flex items-center gap-3 rounded-2xl bg-emerald-50 dark:bg-emerald-900/20 border border-emerald-200 dark:border-emerald-800 px-4 py-4">
            <CheckCircle2 className="h-6 w-6 text-emerald-600 shrink-0" />
            <div>
              <p className="font-semibold text-emerald-800 dark:text-emerald-300">KYC Verified</p>
              <p className="text-sm text-emerald-600 dark:text-emerald-400">Your identity has been verified. You enjoy higher credit limits.</p>
            </div>
          </div>
        )}

        {isPending && (
          <div className="flex items-center gap-3 rounded-2xl bg-amber-50 dark:bg-amber-900/20 border border-amber-200 dark:border-amber-800 px-4 py-4">
            <Clock className="h-6 w-6 text-amber-600 shrink-0" />
            <div>
              <p className="font-semibold text-amber-800 dark:text-amber-300">Under Review</p>
              <p className="text-sm text-amber-600 dark:text-amber-400">Your documents have been submitted and are being reviewed by our team.</p>
            </div>
          </div>
        )}

        {isRejected && (
          <div className="flex items-center gap-3 rounded-2xl bg-red-50 dark:bg-red-900/20 border border-red-200 dark:border-red-800 px-4 py-4">
            <XCircle className="h-6 w-6 text-red-600 shrink-0" />
            <div>
              <p className="font-semibold text-red-800 dark:text-red-300">KYC Rejected</p>
              {customer.kyc_rejection_reason && (
                <p className="text-sm text-red-600 dark:text-red-400 mt-0.5">{customer.kyc_rejection_reason}</p>
              )}
              <p className="text-xs text-red-500 mt-1">Please re-upload your documents below.</p>
            </div>
          </div>
        )}

        {!isVerified && !isPending && (
          <div className="rounded-2xl bg-blue-50 dark:bg-blue-900/20 border border-blue-200 dark:border-blue-800 px-4 py-3">
            <p className="text-sm text-blue-800 dark:text-blue-300 font-medium">Why complete KYC?</p>
            <p className="text-xs text-blue-600 dark:text-blue-400 mt-1">Verified customers enjoy higher credit limits and faster order approvals.</p>
          </div>
        )}

        <div className="space-y-3">
          {DOC_FIELDS.map(({ label, hint, field, icon }) => {
            const hasDoc = !!customer[field];
            const isUploadingThis = uploading === field;
            const { data: publicUrlData } = customer[field]
              ? { data: { publicUrl: customer[field]! } }
              : supabase.storage.from("kyc-documents").getPublicUrl("");

            return (
              <div
                key={field}
                className="rounded-2xl bg-white dark:bg-slate-900 border border-slate-100 dark:border-slate-800 shadow-sm overflow-hidden"
              >
                <div className="flex items-center gap-3 px-4 py-3 border-b border-slate-50 dark:border-slate-800">
                  <div className={cn("h-9 w-9 rounded-xl flex items-center justify-center", hasDoc ? "bg-emerald-100 text-emerald-600" : "bg-slate-100 text-slate-400 dark:bg-slate-800 dark:text-slate-500")}>
                    {icon}
                  </div>
                  <div className="flex-1 min-w-0">
                    <p className="font-semibold text-sm text-slate-900 dark:text-white">{label}</p>
                    <p className="text-xs text-slate-400 dark:text-slate-500">{hint}</p>
                  </div>
                  {hasDoc && <CheckCircle2 className="h-5 w-5 text-emerald-500 shrink-0" />}
                </div>

                {hasDoc && (
                  <div className="px-4 py-3">
                    <img
                      src={customer[field]!}
                      alt={label}
                      className="h-24 w-full object-cover rounded-xl border border-slate-100 dark:border-slate-700"
                    />
                  </div>
                )}

                {canUpload && (
                  <div className="px-4 py-3">
                    <input
                      ref={fileRefs[field]}
                      type="file"
                      accept="image/jpeg,image/png,image/heic,image/webp"
                      className="hidden"
                      onChange={handleFileChange(field)}
                    />
                    <Button
                      variant={hasDoc ? "outline" : "default"}
                      size="sm"
                      className="w-full h-10 rounded-xl"
                      onClick={() => fileRefs[field].current?.click()}
                      disabled={!!uploading}
                    >
                      {isUploadingThis ? (
                        <><Loader2 className="h-4 w-4 mr-2 animate-spin" />Uploading…</>
                      ) : hasDoc ? (
                        <><ImageIcon className="h-4 w-4 mr-2" />Replace</>
                      ) : (
                        <><Upload className="h-4 w-4 mr-2" />Upload</>
                      )}
                    </Button>
                  </div>
                )}
              </div>
            );
          })}
        </div>

        {canUpload && (
          <p className="text-xs text-center text-slate-400 leading-relaxed px-4">
            Upload all three documents to submit your KYC for review. Files must be under 10MB each.
          </p>
        )}
      </div>
    </div>
  );
}

import { useEffect, useMemo, useState } from "react";
import { useQuery, useQueryClient } from "@tanstack/react-query";
import { Loader2, Plus, ShoppingCart } from "lucide-react";
import { toast } from "sonner";
import { supabase } from "@/integrations/supabase/client";
import { resolveCustomer } from "@/lib/resolveCustomer";
import { useAuth } from "@/contexts/AuthContext";
import { sendNotificationToMany, getAdminUserIds } from "@/lib/notifications";
import { Button } from "@/components/ui/button";
import { Textarea } from "@/components/ui/textarea";
import { Label } from "@/components/ui/label";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { Sheet, SheetContent, SheetHeader, SheetTitle } from "@/components/ui/sheet";

interface Props {
  selectedStoreId: string | null;
  onStoreChange: (storeId: string | null) => void;
}

interface CustomerRow {
  id: string;
}

interface StoreRow {
  id: string;
  name: string;
  is_active: boolean;
}

interface OrderRow {
  id: string;
  display_id: string;
  store_id: string;
  status: "pending" | "confirmed" | "delivered" | "cancelled" | string;
  requirement_note: string | null;
  created_at: string;
  stores: { name: string } | null;
}

interface SupabaseRpcClient {
  rpc: (fn: string, args: Record<string, unknown>) => Promise<{ data: string | null; error: Error | null }>;
}

export function CustomerOrders({ selectedStoreId, onStoreChange }: Props) {
  const { user } = useAuth();
  const qc = useQueryClient();
  const [openCreate, setOpenCreate] = useState(false);
  const [saving, setSaving] = useState(false);
  const [orderStoreId, setOrderStoreId] = useState("");
  const [orderNote, setOrderNote] = useState("");

  const { data: customer } = useQuery({
    queryKey: ["mobile-customer-orders-self", user?.id],
    queryFn: async () => {
      const res = await resolveCustomer(user!.id, "id");
      return res as unknown as CustomerRow | null;
    },
    enabled: !!user,
  });

  const { data: stores } = useQuery({
    queryKey: ["mobile-customer-orders-stores", customer?.id],
    queryFn: async () => {
      const { data, error } = await supabase
        .from("stores")
        .select("id, name, is_active")
        .eq("customer_id", customer!.id)
        .order("name");
      if (error) throw error;
      return (data as StoreRow[]) || [];
    },
    enabled: !!customer,
  });

  const { data: orders, isLoading } = useQuery({
    queryKey: ["mobile-customer-orders", customer?.id],
    queryFn: async () => {
      const { data, error } = await supabase
        .from("orders")
        .select("id, display_id, store_id, status, requirement_note, created_at, stores(name)")
        .eq("customer_id", customer!.id)
        .order("created_at", { ascending: false });
      if (error) throw error;
      return (data as unknown as OrderRow[]) || [];
    },
    enabled: !!customer,
    refetchInterval: 60_000,
  });

  useEffect(() => {
    if (openCreate) {
      setOrderStoreId(selectedStoreId || "");
    }
  }, [openCreate, selectedStoreId]);

  const filteredOrders = useMemo(() => {
    if (!selectedStoreId) return orders || [];
    return (orders || []).filter((order) => order.store_id === selectedStoreId);
  }, [orders, selectedStoreId]);

  const handleCreateOrder = async () => {
    if (!orderStoreId) {
      toast.error("Select a store");
      return;
    }

    const activeOrder = (orders || []).find(
      (order) => order.store_id === orderStoreId && (order.status === "pending" || order.status === "confirmed")
    );
    if (activeOrder) {
      toast.error("An active order already exists for this store");
      return;
    }

    setSaving(true);
    try {
      const rpcClient = supabase as unknown as SupabaseRpcClient;
      const { data: displayId, error: displayError } = await rpcClient.rpc("generate_display_id", {
        prefix: "ORD",
        seq_name: "ord_display_seq",
      });
      if (displayError) throw displayError;
      if (!displayId) throw new Error("Failed to generate order ID");

      const { error } = await supabase.from("orders").insert({
        display_id: displayId,
        store_id: orderStoreId,
        customer_id: customer!.id,
        order_type: "simple",
        source: "manual",
        created_by: user!.id,
        requirement_note: orderNote.trim() || null,
      });
      if (error) throw error;

      toast.success("Order placed");
      
      // Dispatch notification to admins
      getAdminUserIds().then(admins => {
        if (admins.length > 0) {
          sendNotificationToMany(admins, {
            title: "New Customer Order",
            message: `Order ${displayId} placed by customer`,
            type: "order" as any,
          });
        }
      }).catch(err => console.error("Failed to notify admins", err));

      setOpenCreate(false);
      setOrderNote("");
      onStoreChange(orderStoreId);
      qc.invalidateQueries({ queryKey: ["mobile-customer-orders"] });
    } catch (error) {
      const message = error instanceof Error ? error.message : "Failed to place order";
      toast.error(message);
    } finally {
      setSaving(false);
    }
  };

  return (
    <div className="pb-6">
      <div className="px-4 pt-4 flex justify-end">
        <Button size="sm" className="rounded-xl" onClick={() => setOpenCreate(true)}>
          <Plus className="h-4 w-4 mr-1" />
          Place Order
        </Button>
      </div>

      <div className="px-4 space-y-2 mt-2">
        {isLoading ? (
          <div className="flex justify-center py-10"><Loader2 className="h-6 w-6 animate-spin text-blue-500" /></div>
        ) : filteredOrders.length === 0 ? (
          <div className="rounded-2xl border-2 border-dashed border-slate-200 dark:border-slate-700 p-8 text-center bg-slate-50/50 dark:bg-slate-800/30">
            <ShoppingCart className="h-7 w-7 text-slate-400 mx-auto mb-2" />
            <p className="text-sm font-semibold text-slate-600 dark:text-slate-300">No orders found</p>
          </div>
        ) : (
          filteredOrders.map((order) => (
            <div key={order.id} className="rounded-2xl bg-white dark:bg-slate-800 border border-slate-100 dark:border-slate-700 p-3 shadow-sm">
              <div className="flex items-start justify-between gap-3">
                <div className="min-w-0">
                  <p className="text-sm font-bold text-slate-800 dark:text-white">{order.display_id}</p>
                  <p className="text-xs text-slate-500 mt-0.5">{order.stores?.name || "Store"}</p>
                  <p className="text-[11px] text-slate-400 mt-1">{new Date(order.created_at).toLocaleString("en-IN", { dateStyle: "short", timeStyle: "short" })}</p>
                </div>
                <span
                  className={`px-2 py-1 rounded-lg text-[10px] font-semibold capitalize ${
                    order.status === "pending"
                      ? "bg-amber-50 text-amber-700 dark:bg-amber-900/20 dark:text-amber-400"
                      : order.status === "delivered"
                      ? "bg-emerald-50 text-emerald-700 dark:bg-emerald-900/20 dark:text-emerald-400"
                      : order.status === "cancelled"
                      ? "bg-red-50 text-red-700 dark:bg-red-900/20 dark:text-red-400"
                      : "bg-slate-100 text-slate-700 dark:bg-slate-700 dark:text-slate-200"
                  }`}
                >
                  {order.status}
                </span>
              </div>
              {order.requirement_note && (
                <p className="text-xs text-slate-600 dark:text-slate-300 mt-2 line-clamp-2">{order.requirement_note}</p>
              )}
            </div>
          ))
        )}
      </div>

      <Sheet open={openCreate} onOpenChange={setOpenCreate}>
        <SheetContent side="bottom" className="rounded-t-3xl pb-10 px-0 max-h-[88vh] overflow-y-auto">
          <div className="px-6">
            <SheetHeader className="mb-5 text-left">
              <SheetTitle className="text-lg font-bold">Place Order</SheetTitle>
            </SheetHeader>

            <div className="space-y-4">
              <div>
                <Label className="text-xs font-bold uppercase tracking-widest text-slate-500 mb-2 block">Store</Label>
                <Select value={orderStoreId} onValueChange={setOrderStoreId}>
                  <SelectTrigger className="h-11 rounded-xl">
                    <SelectValue placeholder="Select store" />
                  </SelectTrigger>
                  <SelectContent>
                    {(stores || [])
                      .filter((store) => store.is_active)
                      .map((store) => (
                        <SelectItem key={store.id} value={store.id}>{store.name}</SelectItem>
                      ))}
                  </SelectContent>
                </Select>
              </div>

              <div>
                <Label className="text-xs font-bold uppercase tracking-widest text-slate-500 mb-2 block">Requirement Note</Label>
                <Textarea
                  value={orderNote}
                  onChange={(event) => setOrderNote(event.target.value)}
                  className="rounded-xl min-h-24"
                  placeholder="What do you need?"
                />
              </div>

              <Button className="w-full h-11 rounded-xl" onClick={handleCreateOrder} disabled={saving}>
                {saving && <Loader2 className="h-4 w-4 mr-2 animate-spin" />}
                Submit Order
              </Button>
            </div>
          </div>
        </SheetContent>
      </Sheet>
    </div>
  );
}

import { useQuery } from "@tanstack/react-query";
import { Loader2, Phone } from "lucide-react";
import { supabase } from "@/integrations/supabase/client";
import { resolveCustomer } from "@/lib/resolveCustomer";
import { useAuth } from "@/contexts/AuthContext";
import { useState } from "react";
import { toast } from "sonner";
import { getOAuthRedirectUrl } from "@/lib/capacitorUtils";

interface CustomerRow {
  id: string;
  name: string;
  display_id: string;
  phone: string | null;
  email: string | null;
  address: string | null;
}

interface StoreRow {
  id: string;
  name: string;
  outstanding: number;
}

export function CustomerProfile() {
  const { user } = useAuth();
  const [linking, setLinking] = useState(false);

  const { data: liveAuthUser, refetch: refetchLiveAuthUser } = useQuery({
    queryKey: ["mobile-auth-user-live", user?.id],
    queryFn: async () => {
      const { data, error } = await supabase.auth.getUser();
      if (error) throw error;
      return data.user;
    },
    enabled: !!user,
  });

  const googleIdentity = liveAuthUser?.identities?.find((identity) => identity.provider === "google");
  const isGoogleLinked = !!googleIdentity;

  const { data: customer, isLoading } = useQuery({
    queryKey: ["mobile-customer-profile", user?.id],
    queryFn: async () => (await resolveCustomer(user!.id, "id, name, display_id, phone, email, address")) as CustomerRow | null,
    enabled: !!user,
  });

  const { data: stores } = useQuery({
    queryKey: ["mobile-customer-profile-stores", customer?.id],
    queryFn: async () => {
      const { data, error } = await supabase
        .from("stores")
        .select("id, name, outstanding")
        .eq("customer_id", customer!.id)
        .eq("is_active", true)
        .order("name");
      if (error) throw error;
      return (data as StoreRow[]) || [];
    },
    enabled: !!customer,
  });

  const { data: customerCare } = useQuery({
    queryKey: ["mobile-customer-profile-care"],
    queryFn: async () => {
      const { data, error } = await supabase
        .from("company_settings")
        .select("value")
        .eq("key", "customer_care_number")
        .maybeSingle();
      if (error) throw error;
      return data?.value || "";
    },
  });

  const { data: appSettings } = useQuery({
    queryKey: ["company-settings", "google-linking"],
    queryFn: async () => {
      const { data } = await supabase
        .from("company_settings")
        .select("*")
        .eq("key", "google_linking_enabled")
        .maybeSingle();
      return data;
    },
  });

  const googleLinkingEnabled = appSettings?.value === "true";

  const handleLinkGoogle = async () => {
    if (!googleLinkingEnabled) {
      toast.error("Google account linking is currently disabled by the administrator.");
      return;
    }

    setLinking(true);
    try {
      const { error } = await supabase.auth.linkIdentity({
        provider: "google",
        options: {
          redirectTo: getOAuthRedirectUrl("/"),
        },
      });

      if (error) {
        if (error.message.includes("Manual linking")) {
          toast.error("Manual account linking is disabled. Please contact support.", { duration: 5000 });
        } else {
          toast.error(error.message);
        }
      } else {
        toast.success("Google account linking initiated.");
      }
    } catch (error: any) {
      toast.error(error.message || "Failed to link Google account");
    } finally {
      setLinking(false);
    }
  };

  const handleUnlinkGoogle = async () => {
    const { data: latestAuthData } = await supabase.auth.getUser();
    const latestGoogleIdentity = latestAuthData.user?.identities?.find((identity) => identity.provider === "google");

    if (!latestGoogleIdentity) {
      toast.success("Google account is already unlinked");
      await refetchLiveAuthUser();
      return;
    }

    setLinking(true);
    try {
      const { error } = await supabase.auth.unlinkIdentity(latestGoogleIdentity);
      if (error) {
        if (error.message?.toLowerCase().includes("identity doesn't exist")) {
          toast.success("Google account is already unlinked");
          await refetchLiveAuthUser();
        } else {
          toast.error(error.message);
        }
      } else {
        toast.success("Google account unlinked successfully");
        await refetchLiveAuthUser();
      }
    } catch (error: any) {
      toast.error(error.message || "Failed to unlink Google account");
    } finally {
      setLinking(false);
    }
  };

  if (isLoading) {
    return (
      <div className="flex justify-center py-10">
        <Loader2 className="h-6 w-6 animate-spin text-blue-500" />
      </div>
    );
  }

  if (!customer) {
    return <div className="px-4 py-10 text-center text-sm text-muted-foreground">No profile data found.</div>;
  }

  const totalOutstanding = (stores || []).reduce((sum, store) => sum + Number(store.outstanding || 0), 0);

  return (
    <div className="px-4 pt-4 pb-6 space-y-3">
      <div className="rounded-2xl bg-white dark:bg-slate-800 border border-slate-100 dark:border-slate-700 p-4 shadow-sm">
        <p className="text-base font-bold text-slate-900 dark:text-white">{customer.name}</p>
        <p className="text-xs text-slate-500 mt-0.5">{customer.display_id}</p>

        <div className="mt-3 space-y-2 text-sm">
          <InfoRow label="Phone" value={customer.phone || "—"} />
          <InfoRow label="Email" value={customer.email || "—"} />
          <InfoRow label="Address" value={customer.address || "—"} />
        </div>
      </div>

      <div className="rounded-2xl bg-white dark:bg-slate-800 border border-slate-100 dark:border-slate-700 p-4 shadow-sm">
        <p className="text-xs font-bold uppercase tracking-widest text-slate-500">Stores Summary</p>
        <div className="mt-2 space-y-1.5 text-sm">
          <InfoRow label="Total Stores" value={String((stores || []).length)} />
          <InfoRow label="Outstanding" value={`₹${totalOutstanding.toLocaleString("en-IN")}`} />
        </div>
        <div className="mt-3 pt-2 border-t border-slate-100 dark:border-slate-700 space-y-1.5">
          {(stores || []).map((store) => (
            <div key={store.id} className="flex items-center justify-between text-xs">
              <span className="text-slate-600 dark:text-slate-300 truncate">{store.name}</span>
              <span className="font-semibold">₹{Number(store.outstanding || 0).toLocaleString("en-IN")}</span>
            </div>
          ))}
          {(stores || []).length === 0 && <p className="text-xs text-muted-foreground text-center">No active stores</p>}
        </div>
      </div>

      {/* Google Account Link */}
      <div className="rounded-2xl bg-white dark:bg-slate-800 border border-slate-100 dark:border-slate-700 p-4 shadow-sm">
        <p className="text-xs font-bold uppercase tracking-widest text-slate-500 mb-2">Google Account</p>
        {isGoogleLinked ? (
          <div className="space-y-3">
            <div className="flex items-center gap-2 text-sm text-slate-600 dark:text-slate-300">
              <svg className="h-5 w-5" viewBox="0 0 24 24">
                <path
                  fill="currentColor"
                  d="M22.56 12.25c0-.78-.07-1.53-.2-2.25H12v4.26h5.92c-.26 1.37-1.04 2.53-2.21 3.31v2.77h3.57c2.08-1.92 3.28-4.74 3.28-8.09z"
                />
                <path
                  fill="currentColor"
                  d="M12 23c2.97 0 5.46-.98 7.28-2.66l-3.57-2.77c-.98.66-2.23 1.06-3.71 1.06-2.86 0-5.29-1.93-6.16-4.53H2.18v2.84C3.99 20.53 7.7 23 12 23z"
                />
                <path
                  fill="currentColor"
                  d="M5.84 14.09c-.22-.66-.35-1.36-.35-2.09s.13-1.43.35-2.09V7.07H2.18C1.43 8.55 1 10.22 1 12s.43 3.45 1.18 4.93l2.85-2.22.81-.62z"
                />
                <path
                  fill="currentColor"
                  d="M12 5.38c1.62 0 3.06.56 4.21 1.64l3.15-3.15C17.45 2.09 14.97 1 12 1 7.7 1 3.99 3.47 2.18 7.07l3.66 2.84c.87-2.6 3.3-4.53 6.16-4.53z"
                />
              </svg>
              <span>Connected to Google</span>
            </div>
            <button
              type="button"
              onClick={handleUnlinkGoogle}
              disabled={linking || !googleLinkingEnabled}
              className="w-full h-10 rounded-xl border border-slate-300 dark:border-slate-600 text-sm font-medium disabled:opacity-50"
            >
              {linking ? "Unlinking..." : "Unlink Google"}
            </button>
          </div>
        ) : (
          <>
            <p className="text-xs text-slate-500 mb-3">Link your Google account for easy sign-in</p>
            <button
              type="button"
              onClick={handleLinkGoogle}
              disabled={linking || !googleLinkingEnabled}
              className="w-full h-10 rounded-xl bg-primary text-primary-foreground font-semibold text-sm flex items-center justify-center gap-2 disabled:opacity-50"
            >
              {linking ? (
                "Linking..."
              ) : (
                <>
                  <svg className="h-5 w-5" viewBox="0 0 24 24">
                    <path
                      fill="currentColor"
                      d="M22.56 12.25c0-.78-.07-1.53-.2-2.25H12v4.26h5.92c-.26 1.37-1.04 2.53-2.21 3.31v2.77h3.57c2.08-1.92 3.28-4.74 3.28-8.09z"
                    />
                    <path
                      fill="currentColor"
                      d="M12 23c2.97 0 5.46-.98 7.28-2.66l-3.57-2.77c-.98.66-2.23 1.06-3.71 1.06-2.86 0-5.29-1.93-6.16-4.53H2.18v2.84C3.99 20.53 7.7 23 12 23z"
                    />
                    <path
                      fill="currentColor"
                      d="M5.84 14.09c-.22-.66-.35-1.36-.35-2.09s.13-1.43.35-2.09V7.07H2.18C1.43 8.55 1 10.22 1 12s.43 3.45 1.18 4.93l2.85-2.22.81-.62z"
                    />
                    <path
                      fill="currentColor"
                      d="M12 5.38c1.62 0 3.06.56 4.21 1.64l3.15-3.15C17.45 2.09 14.97 1 12 1 7.7 1 3.99 3.47 2.18 7.07l3.66 2.84c.87-2.6 3.3-4.53 6.16-4.53z"
                    />
                  </svg>
                  Link Google Account
                </>
              )}
            </button>
            {!googleLinkingEnabled && (
              <p className="text-xs text-slate-500 mt-2">Google linking is currently disabled.</p>
            )}
          </>
        )}
      </div>

      {customerCare && (
        <button
          type="button"
          onClick={() => window.open(`tel:${customerCare}`, "_self")}
          className="w-full h-11 rounded-xl border border-primary/30 text-primary font-semibold text-sm flex items-center justify-center gap-2"
        >
          <Phone className="h-4 w-4" />
          Call Support
        </button>
      )}
    </div>
  );
}

function InfoRow({ label, value }: { label: string; value: string }) {
  return (
    <div className="flex items-center justify-between gap-3">
      <span className="text-slate-500">{label}</span>
      <span className="text-slate-900 dark:text-slate-100 text-right">{value}</span>
    </div>
  );
}

import { PageHeader } from "@/components/shared/PageHeader";
import { StatusBadge } from "@/components/shared/StatusBadge";
import { Badge } from "@/components/ui/badge";
import { Checkbox } from "@/components/ui/checkbox";
import { useQuery, useQueryClient } from "@tanstack/react-query";
import { supabase } from "@/integrations/supabase/client";
import { useAuth } from "@/contexts/AuthContext";
import { Loader2, UserPlus, MapPin } from "lucide-react";
import { useState } from "react";
import {
  Dialog, DialogContent, DialogHeader, DialogTitle,
} from "@/components/ui/dialog";
import {
  AlertDialog, AlertDialogAction, AlertDialogCancel, AlertDialogContent,
  AlertDialogDescription, AlertDialogFooter, AlertDialogHeader, AlertDialogTitle,
} from "@/components/ui/alert-dialog";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Button } from "@/components/ui/button";
import {
  Select, SelectContent, SelectItem, SelectTrigger, SelectValue,
} from "@/components/ui/select";
import { Tabs, TabsContent, TabsList, TabsTrigger } from "@/components/ui/tabs";
import {
  Table, TableBody, TableCell, TableHead, TableHeader, TableRow,
} from "@/components/ui/table";
import { ScrollArea, ScrollBar } from "@/components/ui/scroll-area";
import { toast } from "sonner";
import {
  InlinePermissionCheckbox,
  useUserPermissions,
  PERMISSION_KEYS,
  ROLE_DEFAULTS,
  type PermissionKey,
} from "@/components/access/UserPermissionsPanel";

const STAFF_ROLES = [
  { value: "manager", label: "Manager" },
  { value: "agent", label: "Agent" },
  { value: "marketer", label: "Marketer" },
  { value: "pos", label: "POS" },
];

const PERM_HEADERS: { key: PermissionKey; label: string }[] = [
  { key: "price_override", label: "Price Override" },
  { key: "record_behalf", label: "Record On Behalf" },
  { key: "create_customers", label: "Create Customers" },
  { key: "create_stores", label: "Create Stores" },
  { key: "edit_balance", label: "Edit Balance" },
  { key: "opening_balance", label: "Opening Balance" },
  { key: "finalizer", label: "Finalizer" },
  { key: "see_handover_balance", label: "See Balances" },
  { key: "submit_expenses", label: "Submit Expenses" },
  { key: "view_vendors", label: "View Vendors" },
  { key: "manage_vendors", label: "Manage Vendors" },
  { key: "view_purchases", label: "View Purchases" },
  { key: "manage_purchases", label: "Manage Purchases" },
  { key: "view_vendor_payments", label: "View Payments" },
  { key: "manage_vendor_payments", label: "Manage Payments" },
  { key: "view_raw_materials", label: "View Raw Materials" },
  { key: "manage_raw_materials", label: "Manage Raw Materials" },
];

const AccessControl = () => {
  const { role: currentRole } = useAuth();
  const qc = useQueryClient();
  const isAdmin = currentRole === "super_admin";
  const [showInvite, setShowInvite] = useState(false);
  const [savingInvite, setSavingInvite] = useState(false);
  const [inviteEmail, setInviteEmail] = useState("");
  const [inviteName, setInviteName] = useState("");
  const [inviteRole, setInviteRole] = useState("agent");
  const [confirmBan, setConfirmBan] = useState<{ userId: string; name: string } | null>(null);

  const { allPermissions, isLoading: permsLoading, saving: permSaving, getPermissionsForUser, handleToggle } = useUserPermissions();

  const { data: agentRoutes, refetch: refetchAgentRoutes } = useQuery({
    queryKey: ["agent-routes"],
    queryFn: async () => {
      const { data } = await supabase.from("agent_routes").select("user_id, route_id, enabled");
      return data || [];
    },
  });

  const { data: routesWithTypes } = useQuery({
    queryKey: ["routes-for-access"],
    queryFn: async () => {
      const { data } = await supabase.from("routes").select("id, name, store_type_id, store_types(name)").eq("is_active", true).order("name");
      return data || [];
    },
  });

  const isRouteEnabled = (userId: string, routeId: string) =>
    (agentRoutes || []).some((r) => r.user_id === userId && r.route_id === routeId && r.enabled);

  const handleRouteToggle = async (userId: string, routeId: string) => {
    const current = isRouteEnabled(userId, routeId);
    const { error } = await supabase.from("agent_routes").upsert(
      { user_id: userId, route_id: routeId, enabled: !current },
      { onConflict: "user_id,route_id" }
    );
    if (error) toast.error(error.message);
    else refetchAgentRoutes();
  };

  const { data: users, isLoading } = useQuery({
    queryKey: ["all-users"],
    queryFn: async () => {
      const { data: profiles, error: pErr } = await supabase
        .from("profiles")
        .select("*")
        .order("created_at", { ascending: false });
      if (pErr) throw pErr;

      const { data: roles, error: rErr } = await supabase
        .from("user_roles")
        .select("user_id, role");
      if (rErr) throw rErr;

      const roleMap = new Map(roles?.map((r) => [r.user_id, r.role]) || []);
      return (profiles || []).map((p) => ({
        ...p,
        _role: roleMap.get(p.user_id) || "customer",
      }));
    },
  });

  const staffUsers = users?.filter((u) => {
    const role = u._role;
    return role && role !== "customer";
  }) || [];

  const customerUsers = users?.filter((u) => {
    return u._role === "customer";
  }) || [];

  const handleInvite = async (e: React.FormEvent) => {
    e.preventDefault();
    setSavingInvite(true);
    const { data, error } = await supabase.functions.invoke("invite-staff", {
      body: { email: inviteEmail, full_name: inviteName, role: inviteRole },
    });
    setSavingInvite(false);
    if (error || data?.error) {
      toast.error(data?.error || error?.message || "Failed to invite staff");
      return;
    }
    toast.success(`Staff account created for ${inviteName}. A password reset email will be sent.`);
    setShowInvite(false);
    setInviteEmail(""); setInviteName(""); setInviteRole("agent");
    qc.invalidateQueries({ queryKey: ["all-users"] });
  };

  const handleToggleActive = async (userId: string, currentlyActive: boolean) => {
    const newActive = !currentlyActive;
    // Update profile
    const { error } = await supabase.from("profiles").update({ is_active: newActive }).eq("user_id", userId);
    if (error) { toast.error(error.message); return; }

    // Ban/unban via edge function
    const { error: banError } = await supabase.functions.invoke("toggle-user-ban", {
      body: { user_id: userId, ban: !newActive },
    });
    if (banError) {
      toast.error("Profile updated but auth ban failed: " + banError.message);
    } else {
      toast.success(`User ${currentlyActive ? "disabled" : "enabled"}`);
    }
    qc.invalidateQueries({ queryKey: ["all-users"] });
  };

  const handleChangeRole = async (userId: string, newRole: string) => {
    const { error } = await supabase.from("user_roles").update({ role: newRole as any }).eq("user_id", userId);
    if (error) toast.error(error.message);
    else { toast.success("Role updated"); qc.invalidateQueries({ queryKey: ["all-users"] }); }
  };

  if (isLoading || permsLoading) {
    return <div className="flex items-center justify-center py-20"><Loader2 className="h-8 w-8 animate-spin text-primary" /></div>;
  }

  return (
    <div className="space-y-6 animate-fade-in">
      <PageHeader
        title="Access Control"
        subtitle="Manage users, roles, and permissions"
        primaryAction={isAdmin ? { label: "Invite Staff", icon: UserPlus, onClick: () => setShowInvite(true) } : undefined}
      />

      <Tabs defaultValue="staff">
        <TabsList>
          <TabsTrigger value="staff">Staff ({staffUsers.length})</TabsTrigger>
          <TabsTrigger value="customers">Customers ({customerUsers.length})</TabsTrigger>
          {isAdmin && <TabsTrigger value="routes"><MapPin className="h-3.5 w-3.5 mr-1" />Route Access</TabsTrigger>}
        </TabsList>

        {/* ── Staff Tab ── */}
        <TabsContent value="staff" className="mt-4">
          {/* Desktop: scrollable table with inline permissions */}
          <ScrollArea className="w-full hidden md:block">
            <div className="rounded-xl border bg-card min-w-[900px]">
              <Table>
                <TableHeader>
                  <TableRow className="bg-muted/50 hover:bg-muted/50">
                    <TableHead className="min-w-[160px]">Staff Member</TableHead>
                    <TableHead className="min-w-[120px]">Role</TableHead>
                    <TableHead className="min-w-[80px]">Status</TableHead>
                    {PERM_HEADERS.map((p) => (
                      <TableHead key={p.key} className="text-center min-w-[90px] text-xs">{p.label}</TableHead>
                    ))}
                    {isAdmin && <TableHead className="min-w-[80px]">Actions</TableHead>}
                  </TableRow>
                </TableHeader>
                <TableBody>
                  {staffUsers.map((row) => {
                    const userRole = row._role || "—";
                    const userPerms = getPermissionsForUser(row.user_id);
                    return (
                      <TableRow key={row.id}>
                        <TableCell>
                          <div>
                            <p className="font-medium text-sm">{row.full_name}</p>
                            <p className="text-xs text-muted-foreground">{row.email}</p>
                          </div>
                        </TableCell>
                        <TableCell>
                          {isAdmin && userRole !== "super_admin" ? (
                            <Select value={userRole} onValueChange={(v) => handleChangeRole(row.user_id, v)}>
                              <SelectTrigger className="h-8 w-28 text-xs font-medium uppercase">
                                <SelectValue />
                              </SelectTrigger>
                              <SelectContent>
                                {STAFF_ROLES.map((r) => (
                                  <SelectItem key={r.value} value={r.value}>{r.label}</SelectItem>
                                ))}
                              </SelectContent>
                            </Select>
                          ) : (
                            <Badge variant="default" className="uppercase text-[10px]">{userRole.replace("_", " ")}</Badge>
                          )}
                        </TableCell>
                        <TableCell>
                          <StatusBadge status={row.is_active ? "active" : "inactive"} />
                        </TableCell>
                        {PERM_HEADERS.map((p) => (
                          <TableCell key={p.key}>
                            <InlinePermissionCheckbox
                              userId={row.user_id}
                              userRole={userRole}
                              permissionKey={p.key}
                              permissions={userPerms}
                              onToggle={handleToggle}
                              saving={permSaving}
                            />
                          </TableCell>
                        ))}
                        {isAdmin && (
                          <TableCell>
                            {userRole !== "super_admin" && (
                              <Button
                                variant={row.is_active ? "destructive" : "default"}
                                size="sm"
                                className="h-7 text-xs"
                                onClick={() => row.is_active ? setConfirmBan({ userId: row.user_id, name: row.full_name }) : handleToggleActive(row.user_id, row.is_active)}
                              >
                                {row.is_active ? "Disable" : "Enable"}
                              </Button>
                            )}
                          </TableCell>
                        )}
                      </TableRow>
                    );
                  })}
                </TableBody>
              </Table>
            </div>
            <ScrollBar orientation="horizontal" />
          </ScrollArea>

          {/* Mobile: card view */}
          <div className="md:hidden space-y-3">
            {staffUsers.map((row) => {
              const userRole = row._role || "—";
              const userPerms = getPermissionsForUser(row.user_id);
              const isSA = userRole === "super_admin";
              return (
                <div key={row.id} className="rounded-xl border bg-card p-4 space-y-3">
                  <div className="flex items-center justify-between">
                    <div className="min-w-0">
                      <h3 className="text-sm font-semibold truncate">{row.full_name}</h3>
                      <p className="text-xs text-muted-foreground truncate">{row.email}</p>
                    </div>
                    <StatusBadge status={row.is_active ? "active" : "inactive"} />
                  </div>
                  <div className="flex items-center justify-between">
                    {isAdmin && !isSA ? (
                      <Select value={userRole} onValueChange={(v) => handleChangeRole(row.user_id, v)}>
                        <SelectTrigger className="h-7 w-28 text-xs uppercase font-medium"><SelectValue /></SelectTrigger>
                        <SelectContent>{STAFF_ROLES.map((r) => <SelectItem key={r.value} value={r.value}>{r.label}</SelectItem>)}</SelectContent>
                      </Select>
                    ) : (
                      <Badge variant="default" className="uppercase text-[10px]">{userRole.replace("_", " ")}</Badge>
                    )}
                    {isAdmin && !isSA && (
                      <Button variant={row.is_active ? "destructive" : "default"} size="sm" className="h-7 text-xs" onClick={() => row.is_active ? setConfirmBan({ userId: row.user_id, name: row.full_name }) : handleToggleActive(row.user_id, row.is_active)}>
                        {row.is_active ? "Disable" : "Enable"}
                      </Button>
                    )}
                  </div>
                  {/* Permissions grid */}
                  <div className="grid grid-cols-3 gap-2 pt-2 border-t">
                    {PERM_HEADERS.map((p) => {
                      const dbPerm = userPerms.find((up: any) => up.permission === p.key);
                      const isDefault = ROLE_DEFAULTS[userRole]?.includes(p.key) ?? false;
                      const isEnabled = dbPerm ? dbPerm.enabled : isDefault;
                      const isSaving = permSaving === `${row.user_id}-${p.key}`;
                      return (
                        <label key={p.key} className="flex items-center gap-1.5 text-[11px] text-muted-foreground cursor-pointer">
                          {isSaving ? (
                            <Loader2 className="h-3 w-3 animate-spin" />
                          ) : (
                            <Checkbox
                              checked={isEnabled}
                              onCheckedChange={() => handleToggle(row.user_id, p.key, isEnabled)}
                              disabled={isSA}
                              className="h-3.5 w-3.5"
                            />
                          )}
                          <span className="truncate">{p.label}</span>
                        </label>
                      );
                    })}
                  </div>
                </div>
              );
            })}
          </div>
        </TabsContent>

        {/* ── Customers Tab ── */}
        <TabsContent value="customers" className="mt-4">
          <div className="rounded-xl border bg-card hidden md:block">
            <Table>
              <TableHeader>
                <TableRow className="bg-muted/50 hover:bg-muted/50">
                  <TableHead>Name</TableHead>
                  <TableHead>Email</TableHead>
                  <TableHead>Status</TableHead>
                  {isAdmin && <TableHead>Actions</TableHead>}
                </TableRow>
              </TableHeader>
              <TableBody>
                {customerUsers.length === 0 ? (
                  <TableRow><TableCell colSpan={4} className="text-center text-muted-foreground py-8">No customer accounts</TableCell></TableRow>
                ) : customerUsers.map((row) => (
                  <TableRow key={row.id}>
                    <TableCell className="font-medium">{row.full_name}</TableCell>
                    <TableCell className="text-sm text-muted-foreground">{row.email || "—"}</TableCell>
                    <TableCell><StatusBadge status={row.is_active ? "active" : "inactive"} /></TableCell>
                    {isAdmin && (
                      <TableCell>
                        <Button variant={row.is_active ? "destructive" : "default"} size="sm" className="h-7 text-xs" onClick={() => row.is_active ? setConfirmBan({ userId: row.user_id, name: row.full_name }) : handleToggleActive(row.user_id, row.is_active)}>
                          {row.is_active ? "Disable" : "Enable"}
                        </Button>
                      </TableCell>
                    )}
                  </TableRow>
                ))}
              </TableBody>
            </Table>
          </div>
          {/* Mobile */}
          <div className="md:hidden space-y-3">
            {customerUsers.length === 0 ? (
              <div className="rounded-xl border bg-card p-6 text-center text-muted-foreground text-sm">No customer accounts</div>
            ) : customerUsers.map((row) => (
              <div key={row.id} className="rounded-xl border bg-card p-4 flex items-center justify-between">
                <div className="min-w-0">
                  <h3 className="text-sm font-semibold truncate">{row.full_name}</h3>
                  <p className="text-xs text-muted-foreground truncate">{row.email}</p>
                </div>
                <div className="flex items-center gap-2 shrink-0">
                  <StatusBadge status={row.is_active ? "active" : "inactive"} />
                  {isAdmin && (
                    <Button variant={row.is_active ? "destructive" : "default"} size="sm" className="h-7 text-xs" onClick={() => row.is_active ? setConfirmBan({ userId: row.user_id, name: row.full_name }) : handleToggleActive(row.user_id, row.is_active)}>
                      {row.is_active ? "Disable" : "Enable"}
                    </Button>
                  )}
                </div>
              </div>
            ))}
          </div>
        </TabsContent>

        {/* ── Route Access Tab ── */}
        {isAdmin && (
          <TabsContent value="routes" className="mt-4">
            {(() => {
              const agents = staffUsers.filter((u) => u._role === "agent" || u._role === "marketer");
              if (!routesWithTypes || routesWithTypes.length === 0) {
                return <div className="rounded-xl border bg-card p-10 text-center text-muted-foreground">No routes created yet. Create routes first.</div>;
              }
              if (agents.length === 0) {
                return <div className="rounded-xl border bg-card p-10 text-center text-muted-foreground">No agents or marketers found.</div>;
              }

              // Group routes by store type
              const byType: Record<string, { typeName: string; routes: typeof routesWithTypes }> = {};
              routesWithTypes.forEach((r: any) => {
                const tid = r.store_type_id;
                if (!byType[tid]) byType[tid] = { typeName: r.store_types?.name || "Other", routes: [] };
                byType[tid].routes.push(r);
              });

              return (
                <div className="space-y-4">
                  <p className="text-xs text-muted-foreground">Check a box to grant an agent access to that route. Changes take effect immediately.</p>
                  <ScrollArea className="w-full">
                    <div className="rounded-xl border bg-card min-w-[600px]">
                      <Table>
                        <TableHeader>
                          <TableRow className="bg-muted/50 hover:bg-muted/50">
                            <TableHead className="min-w-[180px]">Route</TableHead>
                            {agents.map((a) => (
                              <TableHead key={a.user_id} className="text-center min-w-[100px] text-xs">
                                <div className="font-medium truncate max-w-[96px]">{a.full_name}</div>
                                <div className="text-[10px] font-normal text-muted-foreground uppercase">{a._role}</div>
                              </TableHead>
                            ))}
                          </TableRow>
                        </TableHeader>
                        <TableBody>
                          {Object.entries(byType).map(([tid, group]) => (
                            <>
                              <TableRow key={`type-${tid}`} className="bg-accent/30 hover:bg-accent/30">
                                <TableCell colSpan={agents.length + 1} className="text-xs font-bold uppercase tracking-wider text-muted-foreground py-1.5 pl-4">
                                  {group.typeName}
                                </TableCell>
                              </TableRow>
                              {group.routes.map((route: any) => (
                                <TableRow key={route.id}>
                                  <TableCell className="font-medium text-sm pl-6">
                                    <div className="flex items-center gap-2">
                                      <MapPin className="h-3.5 w-3.5 text-muted-foreground" />
                                      {route.name}
                                    </div>
                                  </TableCell>
                                  {agents.map((agent) => (
                                    <TableCell key={agent.user_id} className="text-center">
                                      <Checkbox
                                        checked={isRouteEnabled(agent.user_id, route.id)}
                                        onCheckedChange={() => handleRouteToggle(agent.user_id, route.id)}
                                        className="h-4 w-4"
                                      />
                                    </TableCell>
                                  ))}
                                </TableRow>
                              ))}
                            </>
                          ))}
                        </TableBody>
                      </Table>
                    </div>
                    <ScrollBar orientation="horizontal" />
                  </ScrollArea>
                </div>
              );
            })()}
          </TabsContent>
        )}
      </Tabs>

      {/* Invite Staff Dialog */}
      <Dialog open={showInvite} onOpenChange={setShowInvite}>
        <DialogContent>
          <DialogHeader><DialogTitle>Invite Staff Member</DialogTitle></DialogHeader>
          <form onSubmit={handleInvite} className="space-y-4">
            <div><Label>Full Name</Label><Input value={inviteName} onChange={(e) => setInviteName(e.target.value)} required className="mt-1" /></div>
            <div><Label>Email</Label><Input type="email" value={inviteEmail} onChange={(e) => setInviteEmail(e.target.value)} required className="mt-1" /></div>
            <div>
              <Label>Role</Label>
              <Select value={inviteRole} onValueChange={setInviteRole}>
                <SelectTrigger className="mt-1"><SelectValue /></SelectTrigger>
                <SelectContent>{STAFF_ROLES.map((r) => <SelectItem key={r.value} value={r.value}>{r.label}</SelectItem>)}</SelectContent>
              </Select>
            </div>
            <p className="text-xs text-muted-foreground">The staff member will receive a password reset email to set their own password.</p>
            <Button type="submit" className="w-full" disabled={savingInvite}>
              {savingInvite && <Loader2 className="mr-2 h-4 w-4 animate-spin" />}
              Create Staff Account
            </Button>
          </form>
        </DialogContent>
      </Dialog>

      <AlertDialog open={!!confirmBan} onOpenChange={(v) => { if (!v) setConfirmBan(null); }}>
        <AlertDialogContent>
          <AlertDialogHeader>
            <AlertDialogTitle>Disable user account?</AlertDialogTitle>
            <AlertDialogDescription>
              <strong>{confirmBan?.name}</strong> will be immediately signed out and unable to access the app until re-enabled.
            </AlertDialogDescription>
          </AlertDialogHeader>
          <AlertDialogFooter>
            <AlertDialogCancel onClick={() => setConfirmBan(null)}>Cancel</AlertDialogCancel>
            <AlertDialogAction className="bg-destructive hover:bg-destructive/90" onClick={() => { if (confirmBan) { handleToggleActive(confirmBan.userId, true); setConfirmBan(null); } }}>Disable</AlertDialogAction>
          </AlertDialogFooter>
        </AlertDialogContent>
      </AlertDialog>
    </div>
  );
};

export default AccessControl;

import { PageHeader } from "@/components/shared/PageHeader";
import { DataTable } from "@/components/shared/DataTable";
import { Badge } from "@/components/ui/badge";
import { useQuery } from "@tanstack/react-query";
import { supabase } from "@/integrations/supabase/client";
import { Loader2 } from "lucide-react";
import { useAuth } from "@/contexts/AuthContext";
import { useMemo } from "react";

const Activity = () => {
  const { user } = useAuth();

  // Fetch activity logs
  const { data: activities, isLoading } = useQuery({
    queryKey: ["activity-logs"],
    queryFn: async () => {
      const { data, error } = await supabase
        .from("activity_logs")
        .select("*")
        .order("created_at", { ascending: false })
        .limit(100);
      if (error) throw error;
      return data;
    },
  });

  // Fetch all user profiles to map user_id to name
  const { data: profiles } = useQuery({
    queryKey: ["profiles-for-activity"],
    queryFn: async () => {
      const { data, error } = await supabase
        .from("profiles")
        .select("user_id, full_name");
      if (error) throw error;
      return data;
    },
  });

  // Create username lookup map - keyed by user_id, not id
  const userNameMap = useMemo(() => {
    const map = new Map<string, string>();
    profiles?.forEach((p) => {
      if (p.user_id && p.full_name) map.set(p.user_id, p.full_name);
    });
    return map;
  }, [profiles]);

  const getUserName = (userId: string | null) => {
    if (!userId) return "System";
    return userNameMap.get(userId) || userId.slice(0, 8);
  };

  const columns = [
    { header: "Time", accessor: (row: any) => new Date(row.created_at).toLocaleString("en-IN", { dateStyle: "short", timeStyle: "short" }), className: "font-mono text-xs" },
    { header: "User", accessor: (row: any) => getUserName(row.user_id), className: "text-sm" },
    { header: "Action", accessor: "action" as const },
    { header: "Entity", accessor: (row: any) => row.entity_name || row.entity_id || "—", className: "text-muted-foreground" },
    { header: "Type", accessor: (row: any) => <Badge variant="outline">{row.entity_type}</Badge> },
  ];

  if (isLoading) {
    return <div className="flex items-center justify-center py-20"><Loader2 className="h-8 w-8 animate-spin text-primary" /></div>;
  }

  return (
    <div className="space-y-6 animate-fade-in">
      <PageHeader title="Activity Log" subtitle="Track all system actions and changes" />
      {(!activities || activities.length === 0) ? (
        <div className="rounded-xl border bg-card p-8 text-center text-muted-foreground">
          No activity logs yet. Actions like recording sales, creating orders, and managing users will appear here.
        </div>
      ) : (
        <DataTable
          columns={columns}
          data={activities}
          searchKey="action"
          searchPlaceholder="Search actions..."
          renderMobileCard={(row: any) => (
            <div className="rounded-lg border bg-card p-3">
              {/* Action + Type */}
              <div className="flex items-start justify-between gap-2 mb-1.5">
                <p className="text-sm font-medium text-foreground leading-snug">{row.action}</p>
                <Badge variant="outline" className="text-[10px] h-5 px-1.5 shrink-0">{row.entity_type}</Badge>
              </div>
              {/* Entity name */}
              {(row.entity_name || row.entity_id) && (
                <p className="text-xs text-muted-foreground mb-2">{row.entity_name || row.entity_id}</p>
              )}
              {/* Footer: User + Time */}
              <div className="flex items-center justify-between text-xs text-muted-foreground pt-2 border-t border-border/50">
                <span className="font-medium">{getUserName(row.user_id)}</span>
                <span className="text-[10px]">{new Date(row.created_at).toLocaleString("en-IN", { dateStyle: "short", timeStyle: "short" })}</span>
              </div>
            </div>
          )}
        />
      )}
    </div>
  );
};

export default Activity;

import { PageHeader } from "@/components/shared/PageHeader";
import { StatusBadge } from "@/components/shared/StatusBadge";
import { useQuery, useQueryClient } from "@tanstack/react-query";
import { supabase } from "@/integrations/supabase/client";
import { useAuth } from "@/contexts/AuthContext";
import { Loader2, UserPlus, Trash2, Edit2, Phone, Mail, UserCheck, Clock } from "lucide-react";
import { useState } from "react";
import {
  Dialog, DialogContent, DialogHeader, DialogTitle,
} from "@/components/ui/dialog";
import {
  AlertDialog, AlertDialogAction, AlertDialogCancel, AlertDialogContent,
  AlertDialogDescription, AlertDialogFooter, AlertDialogHeader, AlertDialogTitle,
} from "@/components/ui/alert-dialog";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Button } from "@/components/ui/button";
import {
  Select, SelectContent, SelectItem, SelectTrigger, SelectValue,
} from "@/components/ui/select";
import {
  Table, TableBody, TableCell, TableHead, TableHeader, TableRow,
} from "@/components/ui/table";
import { Checkbox } from "@/components/ui/checkbox";
import { Tabs, TabsContent, TabsList, TabsTrigger } from "@/components/ui/tabs";
import { NoticeBox } from "@/components/shared/NoticeBox";
import { toast } from "sonner";

const STAFF_ROLES = [
  { value: "super_admin", label: "Super Admin" },
  { value: "manager", label: "Manager" },
  { value: "agent", label: "Agent" },
  { value: "marketer", label: "Marketer" },
  { value: "pos", label: "POS" },
];

interface StaffMember {
  id: string;
  phone: string | null;
  email: string | null;
  full_name: string | null;
  role: string;
  avatar_url: string | null;
  is_active: boolean;
  created_at: string;
}

export function AdminStaffDirectory() {
  const { role, user } = useAuth();
  const qc = useQueryClient();
  const isAdmin = role === "super_admin";

  const [editingStaff, setEditingStaff] = useState<StaffMember | null>(null);
  const [deleteConfirm, setDeleteConfirm] = useState<{ id: string; name: string } | null>(null);
  
  // Invitation states
  const [showInvite, setShowInvite] = useState(false);
  const [invitePhone, setInvitePhone] = useState("");
  const [inviteEmail, setInviteEmail] = useState("");
  const [inviteName, setInviteName] = useState("");
  const [inviteRole, setInviteRole] = useState("agent");
  const [inviteNotes, setInviteNotes] = useState("");
  const [inviteSaving, setInviteSaving] = useState(false);

  // Edit form states
  const [formRole, setFormRole] = useState("agent");
  const [formActive, setFormActive] = useState(true);
  const [formSaving, setFormSaving] = useState(false);

  const { data: staff, isLoading } = useQuery({
    queryKey: ["staff-directory"],
    queryFn: async () => {
      const { data, error } = await supabase
        .from("staff_directory" as any)
        .select("*")
        .not("user_id", "is", null) // Only show staff who have joined (have user_id)
        .order("full_name");
      if (error) throw error;
      return (data || []) as unknown as StaffMember[];
    },
  });
  
  const { data: invitations, isLoading: invitationsLoading } = useQuery({
    queryKey: ["staff-invitations"],
    queryFn: async () => {
      const { data, error } = await supabase
        .from("staff_invitations")
        .select("*")
        .eq("status", "pending") // Only show pending invitations
        .order("created_at", { ascending: false });
      if (error) throw error;
      return data || [];
    },
  });

  const resetInviteForm = () => {
    setInvitePhone("");
    setInviteEmail("");
    setInviteName("");
    setInviteRole("agent");
    setInviteNotes("");
  };

  const handleEditClick = (s: StaffMember) => {
    setFormRole(s.role);
    setFormActive(s.is_active);
    setEditingStaff(s);
  };

  const handleSave = async () => {
    if (!editingStaff) return;

    setFormSaving(true);
    try {
      // Update existing staff directory entry (role and active status only)
      const { error } = await supabase
        .from("staff_directory" as any)
        .update({
          role: formRole as any,
          is_active: formActive,
        })
        .eq("id", editingStaff.id);

      if (error) throw error;
      toast.success("Staff updated");

      qc.invalidateQueries({ queryKey: ["staff-directory"] });
      setEditingStaff(null);
    } catch (err: any) {
      toast.error(err.message || "Error updating staff");
    } finally {
      setFormSaving(false);
    }
  };

  const handleDelete = async () => {
    if (!deleteConfirm) return;

    try {
      const { error } = await supabase
        .from("staff_directory" as any)
        .delete()
        .eq("id", deleteConfirm.id);

      if (error) throw error;
      toast.success("Staff deleted");
      qc.invalidateQueries({ queryKey: ["staff-directory"] });
      setDeleteConfirm(null);
    } catch (err: any) {
      toast.error(err.message || "Error deleting staff");
    }
  };

  const handleInvite = async (e: React.FormEvent) => {
    e.preventDefault();
    
    if (!invitePhone && !inviteEmail) {
      toast.error("Please provide either phone number or email");
      return;
    }

    setInviteSaving(true);
    try {
      // Normalize phone number
      let normalizedPhone = invitePhone.trim();
      if (normalizedPhone && !normalizedPhone.startsWith('+')) {
        normalizedPhone = normalizedPhone.length === 10 ? `+91${normalizedPhone}` : normalizedPhone;
      }

      const { error } = await supabase.from("staff_invitations").insert({
        phone: normalizedPhone || null,
        email: inviteEmail.trim().toLowerCase() || "",
        full_name: inviteName.trim() || "",
        role: inviteRole as any,
        notes: inviteNotes.trim() || null,
        invited_by: user!.id,
      } as any);

      if (error) throw error;
      
      toast.success("Staff invitation sent! They'll be assigned this role when they sign up.");
      qc.invalidateQueries({ queryKey: ["staff-invitations"] });
      setShowInvite(false);
      resetInviteForm();
    } catch (err: any) {
      toast.error(err.message || "Error sending invitation");
    } finally {
      setInviteSaving(false);
    }
  };

  if (isLoading) {
    return (
      <div className="flex items-center justify-center py-20">
        <Loader2 className="h-8 w-8 animate-spin text-primary" />
      </div>
    );
  }

  return (
    <div className="space-y-6 animate-fade-in">
      <PageHeader
        title="Staff Directory"
        subtitle="Manage staff members and invitations"
        primaryAction={
          isAdmin ? { label: "Invite Staff", icon: UserCheck, onClick: () => { resetInviteForm(); setShowInvite(true); } } : undefined
        }
      />

      {!isAdmin && (
        <NoticeBox
          variant="error"
          message="Only super admins can manage the staff directory."
        />
      )}

      <Tabs defaultValue="directory" className="space-y-4">
        <TabsList>
          <TabsTrigger value="directory">Staff Directory</TabsTrigger>
          <TabsTrigger value="invitations">
            Invitations
            {invitations && invitations.filter((i: any) => i.status === 'pending').length > 0 && (
              <span className="ml-2 rounded-full bg-primary px-2 py-0.5 text-xs text-primary-foreground">
                {invitations.filter((i: any) => i.status === 'pending').length}
              </span>
            )}
          </TabsTrigger>
        </TabsList>

        <TabsContent value="directory" className="space-y-4">
          <div className="rounded-lg border">
            <Table>
              <TableHeader>
                <TableRow>
                  <TableHead>Phone</TableHead>
                  <TableHead>Email</TableHead>
                  <TableHead>Name</TableHead>
                  <TableHead>Role</TableHead>
                  <TableHead>Avatar</TableHead>
                  <TableHead className="text-center">Active</TableHead>
                  {isAdmin && <TableHead className="text-right">Actions</TableHead>}
                </TableRow>
              </TableHeader>
              <TableBody>
                {staff && staff.length === 0 ? (
                  <TableRow>
                    <TableCell colSpan={isAdmin ? 7 : 6} className="text-center py-8 text-muted-foreground">
                      No staff members have joined yet. Send invitations from the "Invitations" tab.
                    </TableCell>
                  </TableRow>
                ) : (
                  staff?.map((s) => (
                    <TableRow key={s.id}>
                      <TableCell className="font-mono text-sm">{s.phone || "—"}</TableCell>
                      <TableCell className="text-sm">{s.email || "—"}</TableCell>
                      <TableCell className="font-medium">{s.full_name || "—"}</TableCell>
                      <TableCell>
                        <span className="inline-flex items-center px-2 py-1 rounded-full text-xs font-medium bg-primary/10 text-primary">
                          {s.role}
                        </span>
                      </TableCell>
                      <TableCell className="text-sm text-muted-foreground truncate max-w-xs">
                        {s.avatar_url ? (
                          <a href={s.avatar_url} target="_blank" rel="noopener noreferrer" className="text-blue-600 hover:underline">
                            View
                          </a>
