                              <Edit2 className="h-4 w-4" />
                            </Button>
                            <Button
                              variant="ghost"
                              size="sm"
                              onClick={() => setDeleteConfirm({ id: s.id, name: s.full_name || s.email || s.phone || "Staff" })}
