              </TableHeader>
              <TableBody>
                {!invitations || invitations.length === 0 ? (
                  <TableRow>
                    <TableCell colSpan={6} className="text-center py-8 text-muted-foreground">
                      No pending invitations. Click "Invite Staff" to send an invitation.
                    </TableCell>
                  </TableRow>
