                              <Phone className="h-3.5 w-3.5 text-muted-foreground" />
                              <span className="font-mono">{inv.phone}</span>
                            </div>
                          )}
                          {inv.email && (
                            <div className="flex items-center gap-1.5 text-sm">
                              <Mail className="h-3.5 w-3.5 text-muted-foreground" />
                              <span>{inv.email}</span>
                            </div>
                          )}
                        </div>
                      </TableCell>
                      <TableCell className="font-medium">{inv.full_name || "—"}</TableCell>
                      <TableCell>
                        <span className="inline-flex items-center px-2 py-1 rounded-full text-xs font-medium bg-blue-500/10 text-blue-600">
                          {inv.role}
                        </span>
                      </TableCell>
                      <TableCell>
                        <StatusBadge 
                          status={inv.status === 'pending' ? 'pending' : inv.status === 'accepted' ? 'completed' : 'inactive'} 
                        />
                      </TableCell>
                      <TableCell className="text-sm text-muted-foreground">
                        <div className="flex items-center gap-1.5">
                          <Clock className="h-3.5 w-3.5" />
                          {new Date(inv.created_at).toLocaleDateString()}
                        </div>
                      </TableCell>
                      <TableCell className="text-right">
                        {inv.status === 'pending' && isAdmin && (
                          <Button
                            variant="ghost"
                            size="sm"
                            className="h-8 px-2 text-destructive hover:text-destructive"
                            onClick={async () => {
                              if (!confirm('Cancel this invitation?')) return;
                              const { error } = await supabase
                                .from('staff_invitations')
                                .update({ status: 'cancelled' })
                                .eq('id', inv.id);
                              if (error) {
                                toast.error(error.message);
                              } else {
                                toast.success('Invitation cancelled');
                                qc.invalidateQueries({ queryKey: ['staff-invitations'] });
                              }
                            }}
                          >
                            Cancel
                          </Button>
                        )}
                      </TableCell>
                    </TableRow>
                  ))
                )}
              </TableBody>
            </Table>
          </div>
        </TabsContent>
      </Tabs>

      {/* Edit Staff Dialog */}
      <Dialog open={!!editingStaff} onOpenChange={(open) => { if (!open) setEditingStaff(null); }}>
        <DialogContent>
          <DialogHeader>
            <DialogTitle>Edit Staff Member</DialogTitle>
          </DialogHeader>

          <div className="space-y-4">
            <div className="rounded-lg border bg-muted/50 p-3 space-y-1">
              <p className="text-sm font-medium">{editingStaff?.full_name}</p>
              <p className="text-xs text-muted-foreground">{editingStaff?.email || editingStaff?.phone}</p>
            </div>

            <div>
              <Label htmlFor="role">Role *</Label>
              <Select value={formRole} onValueChange={setFormRole} disabled={formSaving}>
                <SelectTrigger id="role">
                  <SelectValue />
                </SelectTrigger>
                <SelectContent>
                  {STAFF_ROLES.map((r) => (
                    <SelectItem key={r.value} value={r.value}>
                      {r.label}
                    </SelectItem>
                  ))}
                </SelectContent>
              </Select>
            </div>

            <div className="flex items-center gap-2">
              <Checkbox
                id="active"
                checked={formActive}
                onCheckedChange={(checked) => setFormActive(checked as boolean)}
                disabled={formSaving}
              />
              <Label htmlFor="active" className="font-normal cursor-pointer">
                Active
              </Label>
            </div>

            <div className="flex gap-2 justify-end pt-4">
              <Button
                variant="outline"
                onClick={() => setEditingStaff(null)}
                disabled={formSaving}
              >
                Cancel
              </Button>
              <Button
                onClick={handleSave}
                disabled={formSaving}
              >
                {formSaving ? <Loader2 className="h-4 w-4 mr-2 animate-spin" /> : null}
                Update Staff
              </Button>
            </div>
          </div>
        </DialogContent>
      </Dialog>

      {/* Delete Confirmation Dialog */}
      <AlertDialog open={!!deleteConfirm} onOpenChange={(open) => !open && setDeleteConfirm(null)}>
        <AlertDialogContent>
          <AlertDialogHeader>
            <AlertDialogTitle>Delete Staff Member?</AlertDialogTitle>
            <AlertDialogDescription>
              Are you sure you want to delete <strong>{deleteConfirm?.name}</strong>? This action cannot be undone.
            </AlertDialogDescription>
          </AlertDialogHeader>
          <AlertDialogFooter>
            <AlertDialogCancel>Cancel</AlertDialogCancel>
            <AlertDialogAction
              onClick={handleDelete}
              className="bg-destructive hover:bg-destructive/90"
            >
              Delete
            </AlertDialogAction>
          </AlertDialogFooter>
        </AlertDialogContent>
      </AlertDialog>

      {/* Invite Staff Dialog */}
      <Dialog open={showInvite} onOpenChange={setShowInvite}>
        <DialogContent>
          <DialogHeader>
            <DialogTitle>Invite Staff Member</DialogTitle>
          </DialogHeader>

          <form onSubmit={handleInvite} className="space-y-4">
            <NoticeBox
              variant="premium"
              title="Pre-register staff"
              message="When they sign up with this phone/email, they'll automatically get the assigned role and skip customer onboarding."
            />

            <div>
              <Label htmlFor="invite-phone">Phone Number</Label>
              <Input
                id="invite-phone"
                placeholder="e.g. 9876543210 or +919876543210"
                value={invitePhone}
                onChange={(e) => setInvitePhone(e.target.value)}
                disabled={inviteSaving}
              />
              <p className="text-xs text-muted-foreground mt-1">10-digit number or with +91 prefix</p>
            </div>

            <div>
              <Label htmlFor="invite-email">Email <span className="text-xs text-muted-foreground">(for Google login)</span></Label>
              <Input
                id="invite-email"
                type="email"
                placeholder="staff@example.com"
                value={inviteEmail}
                onChange={(e) => setInviteEmail(e.target.value)}
                disabled={inviteSaving}
              />
            </div>

            <div>
              <Label htmlFor="invite-name">Full Name <span className="text-xs text-muted-foreground">(optional)</span></Label>
              <Input
                id="invite-name"
                placeholder="John Doe"
                value={inviteName}
                onChange={(e) => setInviteName(e.target.value)}
                disabled={inviteSaving}
              />
            </div>

            <div>
              <Label htmlFor="invite-role">Role</Label>
              <Select value={inviteRole} onValueChange={setInviteRole} disabled={inviteSaving}>
                <SelectTrigger id="invite-role">
                  <SelectValue />
                </SelectTrigger>
                <SelectContent>
                  {STAFF_ROLES.map((r) => (
                    <SelectItem key={r.value} value={r.value}>
                      {r.label}
                    </SelectItem>
                  ))}
                </SelectContent>
              </Select>
            </div>

            <div>
              <Label htmlFor="invite-notes">Notes <span className="text-xs text-muted-foreground">(optional)</span></Label>
              <Input
                id="invite-notes"
                placeholder="Internal notes about this invitation"
                value={inviteNotes}
                onChange={(e) => setInviteNotes(e.target.value)}
                disabled={inviteSaving}
              />
            </div>

            <div className="flex gap-3 pt-2">
              <Button type="button" variant="outline" onClick={() => setShowInvite(false)} disabled={inviteSaving} className="flex-1">
                Cancel
              </Button>
              <Button type="submit" disabled={inviteSaving} className="flex-1">
                {inviteSaving ? (
                  <>
                    <Loader2 className="mr-2 h-4 w-4 animate-spin" />
                    Sending...
                  </>
                ) : (
                  "Send Invitation"
                )}
              </Button>
            </div>
          </form>
        </DialogContent>
      </Dialog>
    </div>
  );
}

import { StatCard } from "@/components/shared/StatCard";
import { PageHeader } from "@/components/shared/PageHeader";
import { useAuth } from "@/contexts/AuthContext";
import { useQuery } from "@tanstack/react-query";
import { supabase } from "@/integrations/supabase/client";
import { ShoppingCart, Banknote, Smartphone, MapPin, HandCoins, AlertCircle, WifiOff, RefreshCw, Loader2 } from "lucide-react";
import { DashboardSkeleton } from "@/components/shared/DashboardSkeleton";
import { QuickActionDrawer } from "@/components/agent/QuickActionDrawer";
import { useOnlineStatus } from "@/hooks/useOnlineStatus";
import { Button } from "@/components/ui/button";
import { RouteSessionPanel } from "@/components/routes/RouteSessionPanel";

const AgentDashboard = () => {
  const { user, profile } = useAuth();
  const { isOnline, pendingCount, syncing, syncQueue } = useOnlineStatus();

  const { data: stats, isLoading } = useQuery({
    queryKey: ["agent-dashboard", user?.id],
    queryFn: async () => {
      const today = new Date().toISOString().split("T")[0];

      const [salesRes, txnRes, visitsRes, ordersRes, allSalesRes, allTxnsRes, confirmedHandoversRes, todayHandoverRes] = await Promise.all([
        supabase.from("sales").select("total_amount, cash_amount, upi_amount").eq("recorded_by", user!.id).gte("created_at", today + "T00:00:00"),
        supabase.from("transactions").select("total_amount, cash_amount, upi_amount").eq("recorded_by", user!.id).gte("created_at", today + "T00:00:00"),
        supabase.from("store_visits").select("id, stores(name)").gte("visited_at", today + "T00:00:00"),
        supabase.from("orders").select("id, display_id, stores(name), created_at").eq("status", "pending").order("created_at", { ascending: false }).limit(10),
        supabase.from("sales").select("cash_amount, upi_amount").eq("recorded_by", user!.id),
        supabase.from("transactions").select("cash_amount, upi_amount").eq("recorded_by", user!.id),
        supabase.from("handovers").select("cash_amount, upi_amount").eq("user_id", user!.id).eq("status", "confirmed"),
        supabase.from("handovers").select("cash_amount, upi_amount, status").eq("user_id", user!.id).eq("handover_date", today).maybeSingle(),
      ]);

      const todaySales = salesRes.data || [];
      const todayTxns = txnRes.data || [];

      const totalSale = todaySales.reduce((s, r) => s + Number(r.total_amount), 0);
      const totalCash = todaySales.reduce((s, r) => s + Number(r.cash_amount), 0) + todayTxns.reduce((s, r) => s + Number(r.cash_amount), 0);
      const totalUpi = todaySales.reduce((s, r) => s + Number(r.upi_amount), 0) + todayTxns.reduce((s, r) => s + Number(r.upi_amount), 0);

      const allTimeCash = (allSalesRes.data || []).reduce((s, r) => s + Number(r.cash_amount), 0) + (allTxnsRes.data || []).reduce((s, r) => s + Number(r.cash_amount), 0);
      const allTimeUpi = (allSalesRes.data || []).reduce((s, r) => s + Number(r.upi_amount), 0) + (allTxnsRes.data || []).reduce((s, r) => s + Number(r.upi_amount), 0);
      const confirmedCash = (confirmedHandoversRes.data || []).reduce((s, r) => s + Number(r.cash_amount), 0);
      const confirmedUpi = (confirmedHandoversRes.data || []).reduce((s, r) => s + Number(r.upi_amount), 0);

      const todayHandover = todayHandoverRes.data;
      const todayConfirmed = todayHandover?.status === "confirmed" ? Number(todayHandover.cash_amount) + Number(todayHandover.upi_amount) : 0;
      const todayHandoverable = Math.max(0, totalCash + totalUpi - todayConfirmed);
      const totalPendingHandoverable = Math.max(0, allTimeCash + allTimeUpi - confirmedCash - confirmedUpi);

      return {
        storesCovered: visitsRes.data?.length || 0,
        totalSale,
        totalCash,
        totalUpi,
        todayHandoverable,
        totalPendingHandoverable,
        pendingOrders: ordersRes.data || [],
      };
    },
    enabled: !!user,
  });

  if (isLoading) return <DashboardSkeleton />;
  const s = stats!;

  return (
    <div className="space-y-6 animate-fade-in">
      <PageHeader title="Dashboard" subtitle={`Welcome, ${profile?.full_name || "Agent"}! Here's your daily summary.`} />

      {/* Offline / pending sync banner */}
      {(!isOnline || pendingCount > 0) && (
        <div className={`flex items-center justify-between gap-3 rounded-lg border px-4 py-3 text-sm ${!isOnline ? "border-destructive/30 bg-destructive/5 text-destructive" : "border-warning/30 bg-warning/5 text-warning"}`}>
          <div className="flex items-center gap-2">
            <WifiOff className="h-4 w-4 shrink-0" />
            <span>
              {!isOnline
                ? `You're offline${pendingCount > 0 ? ` — ${pendingCount} action${pendingCount > 1 ? "s" : ""} queued` : ""}`
                : `${pendingCount} action${pendingCount > 1 ? "s" : ""} pending sync`}
            </span>
          </div>
          {isOnline && pendingCount > 0 && (
            <Button size="sm" variant="outline" onClick={syncQueue} disabled={syncing} className="h-7 gap-1.5 text-xs shrink-0">
              {syncing ? <Loader2 className="h-3 w-3 animate-spin" /> : <RefreshCw className="h-3 w-3" />}
              Sync Now
            </Button>
          )}
        </div>
      )}

      {/* Quick Action Button - Floating */}
      <div className="fixed bottom-6 right-4 z-50 sm:bottom-8 sm:right-8">
        <QuickActionDrawer />
      </div>

      <div className="grid grid-cols-2 sm:grid-cols-3 gap-3 sm:gap-4">
        <StatCard title="Stores Covered" value={String(s.storesCovered)} icon={MapPin} iconColor="primary" />
        <StatCard title="Sales Recorded" value={`₹${s.totalSale.toLocaleString()}`} icon={ShoppingCart} iconColor="success" />
        <StatCard title="Cash Collected" value={`₹${s.totalCash.toLocaleString()}`} icon={Banknote} iconColor="warning" />
        <StatCard title="UPI Collected" value={`₹${s.totalUpi.toLocaleString()}`} icon={Smartphone} iconColor="info" />
        <StatCard title="Today's Handoverable" value={`₹${s.todayHandoverable.toLocaleString()}`} icon={HandCoins} iconColor="orange" />
        <StatCard title="Pending Handover" value={`₹${s.totalPendingHandoverable.toLocaleString()}`} icon={AlertCircle} iconColor="destructive" />
      </div>

      {/* Route session — next store navigation */}
      <RouteSessionPanel />

      <div className="rounded-xl border bg-card p-5">
        <h3 className="text-sm font-semibold mb-4">Pending Orders</h3>
        {s.pendingOrders.length === 0 ? (
          <p className="text-sm text-muted-foreground text-center py-6">No pending orders</p>
        ) : (
          <div className="space-y-3">
            {s.pendingOrders.map((order: any) => (
              <div key={order.id} className="flex items-center justify-between rounded-lg bg-muted/50 px-4 py-3">
                <div>
                  <p className="text-sm font-medium">{order.stores?.name || "—"}</p>
                  <p className="text-xs text-muted-foreground font-mono">{order.display_id}</p>
                </div>
                <div className="text-right">
                  <p className="text-xs font-medium text-warning">Pending</p>
                  <p className="text-xs text-muted-foreground">{new Date(order.created_at).toLocaleDateString("en-IN")}</p>
                </div>
              </div>
            ))}
          </div>
        )}
      </div>
    </div>
  );
};

export default AgentDashboard;

import { PageHeader } from "@/components/shared/PageHeader";
import { useQuery } from "@tanstack/react-query";
import { supabase } from "@/integrations/supabase/client";
import { Loader2, CalendarIcon } from "lucide-react";
import { useState } from "react";
import { Button } from "@/components/ui/button";
import { Calendar } from "@/components/ui/calendar";
import { Popover, PopoverContent, PopoverTrigger } from "@/components/ui/popover";
import { format } from "date-fns";
import {
  BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer,
  LineChart, Line, PieChart, Pie, Cell, AreaChart, Area, Legend,
} from "recharts";

const COLORS = ["hsl(217, 91%, 50%)", "hsl(142, 72%, 42%)", "hsl(38, 92%, 50%)", "hsl(280, 65%, 60%)", "hsl(0, 72%, 51%)"];

const Analytics = () => {
  const today = new Date();
  const thirtyAgo = new Date(today);
  thirtyAgo.setDate(thirtyAgo.getDate() - 29);
  const [from, setFrom] = useState(thirtyAgo.toISOString().split("T")[0]);
  const [to, setTo] = useState(today.toISOString().split("T")[0]);
  const [pending, setPending] = useState({ from: thirtyAgo.toISOString().split("T")[0], to: today.toISOString().split("T")[0] });

  const applyFilter = () => setPending({ from, to });

  const { data, isLoading } = useQuery({
    queryKey: ["analytics-enhanced", pending.from, pending.to],
    queryFn: async () => {
      const startOfDay = pending.from + "T00:00:00";
      const endOfDay = pending.to + "T23:59:59";

      const [salesRes, txnRes, storesRes, ordersRes, profilesRes, rolesRes, customersRes, routesRes, visitsRes] = await Promise.all([
        supabase.from("sales").select("total_amount, cash_amount, upi_amount, created_at, recorded_by, stores(name, store_type_id, route_id, store_types(name))").gte("created_at", startOfDay).lte("created_at", endOfDay).order("created_at").limit(2000),
        supabase.from("transactions").select("total_amount, cash_amount, upi_amount, created_at").gte("created_at", startOfDay).lte("created_at", endOfDay).limit(2000),
        supabase.from("stores").select("id, outstanding, store_type_id, route_id, is_active, created_at, store_types(name)").eq("is_active", true).limit(1000),
        supabase.from("orders").select("status").limit(1000),
        supabase.from("profiles").select("user_id, full_name").limit(500),
        supabase.from("user_roles").select("user_id, role").in("role", ["agent", "marketer"]).limit(100),
        supabase.from("customers").select("id, created_at, kyc_status").limit(2000),
        supabase.from("routes").select("id, name").eq("is_active", true).order("name").limit(100),
        supabase.from("store_visits").select("store_id, stores(route_id)").gte("visited_at", startOfDay).lte("visited_at", endOfDay).limit(2000),
      ]);

      const sales = salesRes.data || [];
      const txns = txnRes.data || [];
      const stores = storesRes.data || [];
      const orders = ordersRes.data || [];
      const profiles = profilesRes.data || [];
      const roles = rolesRes.data || [];
      const customers = customersRes.data || [];
      const routes = routesRes.data || [];
      const visits = visitsRes.data || [];

      const profileMap: Record<string, string> = {};
      profiles.forEach((p) => { profileMap[p.user_id] = p.full_name; });

      // Daily sales trend within the selected range
      const fromDate = new Date(pending.from);
      const toDate = new Date(pending.to);
      const dayMs = 86400000;
      const numDays = Math.min(Math.ceil((toDate.getTime() - fromDate.getTime()) / dayMs) + 1, 90);
      const rangeDays = Array.from({ length: numDays }, (_, i) => {
        const d = new Date(fromDate); d.setDate(fromDate.getDate() + i);
        return d.toISOString().split("T")[0];
      });
      const dailySales: Record<string, number> = {};
      rangeDays.forEach((d) => { dailySales[d] = 0; });
      sales.forEach((s) => {
        const day = s.created_at.split("T")[0];
        if (dailySales[day] !== undefined) dailySales[day] += Number(s.total_amount);
      });
      const salesTrend = rangeDays.map((d) => ({ date: d.slice(5), amount: dailySales[d] }));

      // Payment method split
      const totalCash = sales.reduce((s, r) => s + Number(r.cash_amount), 0) + txns.reduce((s, r) => s + Number(r.cash_amount), 0);
      const totalUpi = sales.reduce((s, r) => s + Number(r.upi_amount), 0) + txns.reduce((s, r) => s + Number(r.upi_amount), 0);
      const paymentSplit = [
        { name: "Cash", value: totalCash, color: "hsl(142, 72%, 42%)" },
        { name: "UPI", value: totalUpi, color: "hsl(217, 91%, 50%)" },
      ].filter((p) => p.value > 0);

      // Outstanding by store type
      const outByType: Record<string, number> = {};
      stores.forEach((s: any) => {
        const typeName = s.store_types?.name || "Other";
        outByType[typeName] = (outByType[typeName] || 0) + Number(s.outstanding);
      });
      const outstandingData = Object.entries(outByType).map(([name, value]) => ({ name, value }));

      // Order status breakdown
      const orderStatus: Record<string, number> = { pending: 0, delivered: 0, cancelled: 0 };
      orders.forEach((o) => { orderStatus[o.status] = (orderStatus[o.status] || 0) + 1; });
      const orderData = [
        { name: "Pending", value: orderStatus.pending, color: "hsl(38, 92%, 50%)" },
        { name: "Delivered", value: orderStatus.delivered, color: "hsl(142, 72%, 42%)" },
        { name: "Cancelled", value: orderStatus.cancelled, color: "hsl(0, 72%, 51%)" },
      ].filter((o) => o.value > 0);

      // Agent leaderboard (within range)
      const agentSales: Record<string, { total: number; count: number }> = {};
      const agentIds = new Set(roles.map((r) => r.user_id));
      sales.forEach((s) => {
        if (agentIds.has(s.recorded_by)) {
          if (!agentSales[s.recorded_by]) agentSales[s.recorded_by] = { total: 0, count: 0 };
          agentSales[s.recorded_by].total += Number(s.total_amount);
          agentSales[s.recorded_by].count += 1;
        }
      });
      const leaderboard = Object.entries(agentSales)
        .map(([uid, val]) => ({ name: profileMap[uid] || "Unknown", ...val }))
        .sort((a, b) => b.total - a.total)
        .slice(0, 10);

      // Customer growth (last 12 months, always)
      const monthlyCustomers: Record<string, number> = {};
      const last12 = Array.from({ length: 12 }, (_, i) => {
        const d = new Date(); d.setMonth(d.getMonth() - (11 - i));
        return `${d.getFullYear()}-${String(d.getMonth() + 1).padStart(2, "0")}`;
      });
      last12.forEach((m) => { monthlyCustomers[m] = 0; });
      customers.forEach((c) => {
        const month = c.created_at.slice(0, 7);
        if (monthlyCustomers[month] !== undefined) monthlyCustomers[month] += 1;
      });
      let cumulative = 0;
      const customerGrowth = last12.map((m) => {
        cumulative += monthlyCustomers[m];
        return { month: m.slice(5), newCustomers: monthlyCustomers[m], total: cumulative };
      });

      // Store analytics by type
      const storesByType: Record<string, { count: number; totalOutstanding: number }> = {};
      stores.forEach((s: any) => {
        const typeName = s.store_types?.name || "Other";
        if (!storesByType[typeName]) storesByType[typeName] = { count: 0, totalOutstanding: 0 };
        storesByType[typeName].count += 1;
        storesByType[typeName].totalOutstanding += Number(s.outstanding);
      });
      const storeAnalytics = Object.entries(storesByType).map(([name, val]) => ({ name, ...val }));

      // Revenue vs collections per day
      const dailyCollections: Record<string, number> = {};
      rangeDays.forEach((d) => { dailyCollections[d] = 0; });
      txns.forEach((t) => {
        const day = t.created_at.split("T")[0];
        if (dailyCollections[day] !== undefined) dailyCollections[day] += Number(t.total_amount);
      });
      const revenueVsCollections = rangeDays.map((d) => ({
        date: d.slice(5),
        sales: dailySales[d],
        collections: dailyCollections[d],
      }));

      // Top stores by sales in period
      const storeSalesMap: Record<string, { name: string; amount: number; count: number }> = {};
      sales.forEach((s: any) => {
        const storeId = (s.stores as any)?.name ? (s.stores as any).name : "Unknown";
        if (!storeSalesMap[storeId]) storeSalesMap[storeId] = { name: storeId, amount: 0, count: 0 };
        storeSalesMap[storeId].amount += Number(s.total_amount);
        storeSalesMap[storeId].count += 1;
      });
      const topStoresBySales = Object.values(storeSalesMap)
        .sort((a, b) => b.amount - a.amount)
        .slice(0, 10);

      // KYC status distribution
      const kycBuckets: Record<string, number> = { verified: 0, pending: 0, not_requested: 0, rejected: 0 };
      customers.forEach((c) => { const k = c.kyc_status || "not_requested"; kycBuckets[k] = (kycBuckets[k] || 0) + 1; });
      const kycData = [
        { name: "Verified", value: kycBuckets.verified, color: "hsl(142, 72%, 42%)" },
        { name: "Pending", value: kycBuckets.pending, color: "hsl(38, 92%, 50%)" },
        { name: "Not Requested", value: kycBuckets.not_requested, color: "hsl(215, 20%, 65%)" },
        { name: "Rejected", value: kycBuckets.rejected, color: "hsl(0, 72%, 51%)" },
      ].filter((k) => k.value > 0);

      // Outstanding distribution histogram
      const outBuckets: Record<string, number> = { "₹0": 0, "₹1–1K": 0, "₹1K–5K": 0, "₹5K–20K": 0, "₹20K+": 0 };
      stores.forEach((s) => {
        const amt = Number(s.outstanding);
        if (amt === 0) outBuckets["₹0"]++;
        else if (amt <= 1000) outBuckets["₹1–1K"]++;
        else if (amt <= 5000) outBuckets["₹1K–5K"]++;
        else if (amt <= 20000) outBuckets["₹5K–20K"]++;
        else outBuckets["₹20K+"]++;
      });
      const outstandingHistogram = Object.entries(outBuckets).map(([range, count]) => ({ range, count }));

      // Route-wise sales & completion
      const routeMap: Record<string, { name: string; sales: number; totalStores: number; visitedStores: Set<string> }> = {};
      routes.forEach((r) => { routeMap[r.id] = { name: r.name, sales: 0, totalStores: 0, visitedStores: new Set() }; });
      stores.forEach((s: any) => { if (s.route_id && routeMap[s.route_id]) routeMap[s.route_id].totalStores++; });
      visits.forEach((v: any) => { const rid = v.stores?.route_id; if (rid && routeMap[rid]) routeMap[rid].visitedStores.add(v.store_id); });
      sales.forEach((s: any) => { const rid = (s.stores as any)?.route_id; if (rid && routeMap[rid]) routeMap[rid].sales += Number(s.total_amount); });
      const routeSalesData = Object.values(routeMap)
        .filter((r) => r.totalStores > 0)
        .map((r) => ({ name: r.name, sales: r.sales, completion: r.totalStores > 0 ? Math.round((r.visitedStores.size / r.totalStores) * 100) : 0 }))
        .sort((a, b) => b.sales - a.sales);

      return { salesTrend, paymentSplit, outstandingData, orderData, totalCash, totalUpi, leaderboard, customerGrowth, storeAnalytics, revenueVsCollections, topStoresBySales, kycData, outstandingHistogram, routeSalesData };
    },
  });

  if (isLoading) {
    return <div className="flex items-center justify-center py-20"><Loader2 className="h-8 w-8 animate-spin text-primary" /></div>;
  }

  const d = data!;
  const hasData = d.salesTrend.some((s) => s.amount > 0) || d.paymentSplit.length > 0;

  return (
    <div className="space-y-6 animate-fade-in">
      <PageHeader title="Analytics" subtitle="Business intelligence and performance metrics" />

      <div className="flex flex-wrap items-center gap-2 rounded-xl border bg-card p-4">
        <Popover>
          <PopoverTrigger asChild>
            <Button variant="outline" className="h-8 text-xs gap-1.5 justify-start font-normal min-w-[110px]">
              <CalendarIcon className="h-3 w-3 shrink-0" />
              {from ? format(new Date(from + "T00:00:00"), "dd MMM yy") : "From"}
            </Button>
          </PopoverTrigger>
          <PopoverContent className="w-auto p-0" align="start">
            <Calendar mode="single" selected={from ? new Date(from + "T00:00:00") : undefined} onSelect={(d) => setFrom(d ? format(d, "yyyy-MM-dd") : "")} initialFocus />
          </PopoverContent>
        </Popover>
        <Popover>
          <PopoverTrigger asChild>
            <Button variant="outline" className="h-8 text-xs gap-1.5 justify-start font-normal min-w-[110px]">
              <CalendarIcon className="h-3 w-3 shrink-0" />
              {to ? format(new Date(to + "T00:00:00"), "dd MMM yy") : "To"}
            </Button>
          </PopoverTrigger>
          <PopoverContent className="w-auto p-0" align="start">
            <Calendar mode="single" selected={to ? new Date(to + "T00:00:00") : undefined} onSelect={(d) => setTo(d ? format(d, "yyyy-MM-dd") : "")} initialFocus />
          </PopoverContent>
        </Popover>
        <Button size="sm" onClick={applyFilter} disabled={isLoading} className="h-8">
          {isLoading ? <Loader2 className="h-3.5 w-3.5 animate-spin" /> : "Apply"}
        </Button>
        <Button size="sm" variant="ghost" className="h-8 text-xs text-muted-foreground" onClick={() => {
          const t = new Date(); const f = new Date(t); f.setDate(t.getDate() - 29);
          const fStr = f.toISOString().split("T")[0]; const tStr = t.toISOString().split("T")[0];
          setFrom(fStr); setTo(tStr); setPending({ from: fStr, to: tStr });
        }}>Last 30 days</Button>
      </div>

      {!hasData && d.leaderboard.length === 0 ? (
        <div className="rounded-xl border bg-card p-12 text-center">
          <p className="text-lg font-semibold">No data yet</p>
          <p className="text-sm text-muted-foreground mt-1">Start recording sales and transactions to see analytics here.</p>
        </div>
      ) : (
        <>
          {/* Row 1: Sales trend + Payment methods */}
          <div className="grid grid-cols-1 lg:grid-cols-2 gap-4">
            <div className="rounded-xl border bg-card p-5">
              <h3 className="text-sm font-semibold mb-4">Sales Trend ({pending.from} to {pending.to})</h3>
              <ResponsiveContainer width="100%" height={260}>
                <AreaChart data={d.salesTrend}>
                  <CartesianGrid strokeDasharray="3 3" stroke="hsl(var(--border))" />
                  <XAxis dataKey="date" tick={{ fontSize: 10 }} stroke="hsl(var(--muted-foreground))" />
                  <YAxis tick={{ fontSize: 12 }} stroke="hsl(var(--muted-foreground))" />
                  <Tooltip contentStyle={{ backgroundColor: "hsl(var(--card))", border: "1px solid hsl(var(--border))", borderRadius: "8px" }} />
                  <Area type="monotone" dataKey="amount" stroke="hsl(var(--primary))" fill="hsl(var(--primary))" fillOpacity={0.1} strokeWidth={2} />
                </AreaChart>
              </ResponsiveContainer>
            </div>

            <div className="rounded-xl border bg-card p-5">
              <h3 className="text-sm font-semibold mb-4">Payment Methods</h3>
              {d.paymentSplit.length === 0 ? (
                <p className="text-sm text-muted-foreground text-center py-16">No payments recorded</p>
              ) : (
                <>
                  <ResponsiveContainer width="100%" height={200}>
                    <PieChart>
                      <Pie data={d.paymentSplit} cx="50%" cy="50%" innerRadius={50} outerRadius={80} paddingAngle={4} dataKey="value">
                        {d.paymentSplit.map((e, i) => <Cell key={i} fill={e.color} />)}
                      </Pie>
                      <Tooltip formatter={(v: number) => `₹${v.toLocaleString()}`} />
                    </PieChart>
                  </ResponsiveContainer>
                  <div className="flex justify-center gap-6 mt-2 text-sm">
                    <span className="flex items-center gap-2"><div className="h-3 w-3 rounded-full" style={{ backgroundColor: "hsl(142, 72%, 42%)" }} />Cash: ₹{d.totalCash.toLocaleString()}</span>
                    <span className="flex items-center gap-2"><div className="h-3 w-3 rounded-full" style={{ backgroundColor: "hsl(217, 91%, 50%)" }} />UPI: ₹{d.totalUpi.toLocaleString()}</span>
                  </div>
                </>
              )}
            </div>
          </div>

          {/* Row 2: Agent Leaderboard + Customer Growth */}
          <div className="grid grid-cols-1 lg:grid-cols-2 gap-4">
            <div className="rounded-xl border bg-card p-5">
              <h3 className="text-sm font-semibold mb-4">Agent Leaderboard</h3>
              {d.leaderboard.length === 0 ? (
                <p className="text-sm text-muted-foreground text-center py-12">No agent sales yet</p>
              ) : (
                <ResponsiveContainer width="100%" height={280}>
                  <BarChart data={d.leaderboard} layout="vertical">
                    <CartesianGrid strokeDasharray="3 3" stroke="hsl(var(--border))" />
                    <XAxis type="number" tick={{ fontSize: 11 }} stroke="hsl(var(--muted-foreground))" />
                    <YAxis dataKey="name" type="category" tick={{ fontSize: 11 }} stroke="hsl(var(--muted-foreground))" width={100} />
                    <Tooltip
                      contentStyle={{ backgroundColor: "hsl(var(--card))", border: "1px solid hsl(var(--border))", borderRadius: "8px" }}
                      formatter={(v: number, name: string) => [name === "total" ? `₹${v.toLocaleString()}` : v, name === "total" ? "Revenue" : "Sales Count"]}
                    />
                    <Bar dataKey="total" fill="hsl(var(--primary))" radius={[0, 6, 6, 0]} />
                  </BarChart>
                </ResponsiveContainer>
              )}
            </div>

            <div className="rounded-xl border bg-card p-5">
              <h3 className="text-sm font-semibold mb-4">Customer Growth (Last 12 Months)</h3>
              {d.customerGrowth.every((c) => c.total === 0) ? (
                <p className="text-sm text-muted-foreground text-center py-12">No customers yet</p>
              ) : (
                <ResponsiveContainer width="100%" height={280}>
                  <AreaChart data={d.customerGrowth}>
                    <CartesianGrid strokeDasharray="3 3" stroke="hsl(var(--border))" />
                    <XAxis dataKey="month" tick={{ fontSize: 11 }} stroke="hsl(var(--muted-foreground))" />
                    <YAxis tick={{ fontSize: 12 }} stroke="hsl(var(--muted-foreground))" />
                    <Tooltip contentStyle={{ backgroundColor: "hsl(var(--card))", border: "1px solid hsl(var(--border))", borderRadius: "8px" }} />
                    <Area type="monotone" dataKey="total" stroke="hsl(142, 72%, 42%)" fill="hsl(142, 72%, 42%)" fillOpacity={0.1} strokeWidth={2} name="Total Customers" />
                    <Bar dataKey="newCustomers" fill="hsl(217, 91%, 50%)" opacity={0.6} name="New This Month" />
                  </AreaChart>
                </ResponsiveContainer>
              )}
            </div>
          </div>

          {/* Row 3: Store Analytics + Outstanding + Orders */}
          <div className="grid grid-cols-1 lg:grid-cols-3 gap-4">
            <div className="rounded-xl border bg-card p-5">
              <h3 className="text-sm font-semibold mb-4">Stores by Type</h3>
              {d.storeAnalytics.length === 0 ? (
                <p className="text-sm text-muted-foreground text-center py-12">No stores</p>
              ) : (
                <ResponsiveContainer width="100%" height={220}>
                  <BarChart data={d.storeAnalytics}>
                    <CartesianGrid strokeDasharray="3 3" stroke="hsl(var(--border))" />
                    <XAxis dataKey="name" tick={{ fontSize: 11 }} stroke="hsl(var(--muted-foreground))" />
                    <YAxis tick={{ fontSize: 12 }} stroke="hsl(var(--muted-foreground))" />
                    <Tooltip contentStyle={{ backgroundColor: "hsl(var(--card))", border: "1px solid hsl(var(--border))", borderRadius: "8px" }} />
                    <Bar dataKey="count" fill="hsl(217, 91%, 50%)" radius={[6, 6, 0, 0]} name="Store Count" />
                  </BarChart>
                </ResponsiveContainer>
              )}
            </div>

            <div className="rounded-xl border bg-card p-5">
              <h3 className="text-sm font-semibold mb-4">Outstanding by Store Type</h3>
              {d.outstandingData.length === 0 ? (
                <p className="text-sm text-muted-foreground text-center py-12">No outstanding</p>
              ) : (
                <ResponsiveContainer width="100%" height={220}>
                  <BarChart data={d.outstandingData}>
                    <CartesianGrid strokeDasharray="3 3" stroke="hsl(var(--border))" />
                    <XAxis dataKey="name" tick={{ fontSize: 11 }} stroke="hsl(var(--muted-foreground))" />
                    <YAxis tick={{ fontSize: 12 }} stroke="hsl(var(--muted-foreground))" />
                    <Tooltip contentStyle={{ backgroundColor: "hsl(var(--card))", border: "1px solid hsl(var(--border))", borderRadius: "8px" }} />
                    <Bar dataKey="value" fill="hsl(0, 72%, 51%)" radius={[6, 6, 0, 0]} />
                  </BarChart>
                </ResponsiveContainer>
              )}
            </div>

            <div className="rounded-xl border bg-card p-5">
              <h3 className="text-sm font-semibold mb-4">Order Status</h3>
              {d.orderData.length === 0 ? (
                <p className="text-sm text-muted-foreground text-center py-12">No orders</p>
              ) : (
                <ResponsiveContainer width="100%" height={220}>
                  <PieChart>
                    <Pie data={d.orderData} cx="50%" cy="50%" outerRadius={80} dataKey="value" label={({ name, value }) => `${name}: ${value}`}>
                      {d.orderData.map((e, i) => <Cell key={i} fill={e.color} />)}
                    </Pie>
                    <Tooltip />
                  </PieChart>
                </ResponsiveContainer>
              )}
            </div>
          </div>

          {/* Row 4: Revenue vs Collections + Agent Sales Count */}
          <div className="grid grid-cols-1 lg:grid-cols-2 gap-4">
            <div className="rounded-xl border bg-card p-5">
              <h3 className="text-sm font-semibold mb-4">Revenue vs Collections</h3>
              {d.revenueVsCollections.every((r) => r.sales === 0 && r.collections === 0) ? (
                <p className="text-sm text-muted-foreground text-center py-16">No data in range</p>
              ) : (
                <ResponsiveContainer width="100%" height={260}>
                  <LineChart data={d.revenueVsCollections}>
                    <CartesianGrid strokeDasharray="3 3" stroke="hsl(var(--border))" />
                    <XAxis dataKey="date" tick={{ fontSize: 10 }} stroke="hsl(var(--muted-foreground))" />
                    <YAxis tick={{ fontSize: 11 }} stroke="hsl(var(--muted-foreground))" />
                    <Tooltip
                      contentStyle={{ backgroundColor: "hsl(var(--card))", border: "1px solid hsl(var(--border))", borderRadius: "8px" }}
                      formatter={(v: number) => `₹${v.toLocaleString()}`}
                    />
                    <Legend wrapperStyle={{ fontSize: "12px" }} />
                    <Line type="monotone" dataKey="sales" stroke="hsl(217, 91%, 50%)" strokeWidth={2} dot={false} name="Sales" />
                    <Line type="monotone" dataKey="collections" stroke="hsl(142, 72%, 42%)" strokeWidth={2} dot={false} name="Collections" />
                  </LineChart>
                </ResponsiveContainer>
              )}
            </div>

            <div className="rounded-xl border bg-card p-5">
              <h3 className="text-sm font-semibold mb-4">Agent Performance (Count vs Revenue)</h3>
              {d.leaderboard.length === 0 ? (
                <p className="text-sm text-muted-foreground text-center py-16">No agent sales yet</p>
              ) : (
                <ResponsiveContainer width="100%" height={260}>
                  <BarChart data={d.leaderboard}>
                    <CartesianGrid strokeDasharray="3 3" stroke="hsl(var(--border))" />
                    <XAxis dataKey="name" tick={{ fontSize: 9 }} stroke="hsl(var(--muted-foreground))" angle={-30} textAnchor="end" height={50} />
                    <YAxis yAxisId="left" tick={{ fontSize: 11 }} stroke="hsl(var(--muted-foreground))" />
                    <YAxis yAxisId="right" orientation="right" tick={{ fontSize: 11 }} stroke="hsl(var(--muted-foreground))" />
                    <Tooltip
                      contentStyle={{ backgroundColor: "hsl(var(--card))", border: "1px solid hsl(var(--border))", borderRadius: "8px" }}
                      formatter={(v: number, name: string) => [name === "Revenue" ? `₹${v.toLocaleString()}` : v, name]}
                    />
                    <Legend wrapperStyle={{ fontSize: "12px" }} />
                    <Bar yAxisId="left" dataKey="total" fill="hsl(217, 91%, 50%)" radius={[4, 4, 0, 0]} name="Revenue" />
                    <Bar yAxisId="right" dataKey="count" fill="hsl(142, 72%, 42%)" radius={[4, 4, 0, 0]} name="Sales Count" />
                  </BarChart>
                </ResponsiveContainer>
              )}
            </div>
          </div>

          {/* Row 5: Top Stores by Sales */}
          {d.topStoresBySales.length > 0 && (
            <div className="rounded-xl border bg-card p-5">
              <h3 className="text-sm font-semibold mb-4">Top Stores by Sales</h3>
              <ResponsiveContainer width="100%" height={300}>
                <BarChart data={d.topStoresBySales} layout="vertical">
                  <CartesianGrid strokeDasharray="3 3" stroke="hsl(var(--border))" />
                  <XAxis type="number" tick={{ fontSize: 11 }} stroke="hsl(var(--muted-foreground))" tickFormatter={(v) => `₹${(v / 1000).toFixed(0)}k`} />
                  <YAxis dataKey="name" type="category" tick={{ fontSize: 11 }} stroke="hsl(var(--muted-foreground))" width={120} />
                  <Tooltip
                    contentStyle={{ backgroundColor: "hsl(var(--card))", border: "1px solid hsl(var(--border))", borderRadius: "8px" }}
                    formatter={(v: number) => `₹${v.toLocaleString()}`}
                  />
                  <Bar dataKey="amount" fill="hsl(38, 92%, 50%)" radius={[0, 6, 6, 0]} name="Sales Amount" />
                </BarChart>
              </ResponsiveContainer>
            </div>
          )}

          {/* Row 6: KYC Status + Outstanding Histogram + Route Sales */}
          <div className="grid grid-cols-1 lg:grid-cols-3 gap-4">
            <div className="rounded-xl border bg-card p-5">
              <h3 className="text-sm font-semibold mb-4">Customers by KYC Status</h3>
              {d.kycData.length === 0 ? (
                <p className="text-sm text-muted-foreground text-center py-12">No customers</p>
              ) : (
                <>
                  <ResponsiveContainer width="100%" height={200}>
                    <PieChart>
                      <Pie data={d.kycData} cx="50%" cy="50%" innerRadius={45} outerRadius={75} paddingAngle={3} dataKey="value">
                        {d.kycData.map((e, i) => <Cell key={i} fill={e.color} />)}
                      </Pie>
                      <Tooltip formatter={(v: number) => `${v} customers`} />
                    </PieChart>
                  </ResponsiveContainer>
                  <div className="flex flex-wrap justify-center gap-x-4 gap-y-1 mt-2 text-xs">
                    {d.kycData.map((k) => (
                      <span key={k.name} className="flex items-center gap-1.5">
                        <div className="h-2.5 w-2.5 rounded-full" style={{ backgroundColor: k.color }} />
                        {k.name}: {k.value}
                      </span>
                    ))}
                  </div>
                </>
              )}
            </div>

            <div className="rounded-xl border bg-card p-5">
              <h3 className="text-sm font-semibold mb-4">Outstanding Distribution</h3>
              {d.outstandingHistogram.every((b) => b.count === 0) ? (
                <p className="text-sm text-muted-foreground text-center py-12">No stores</p>
              ) : (
                <ResponsiveContainer width="100%" height={220}>
                  <BarChart data={d.outstandingHistogram}>
                    <CartesianGrid strokeDasharray="3 3" stroke="hsl(var(--border))" />
                    <XAxis dataKey="range" tick={{ fontSize: 11 }} stroke="hsl(var(--muted-foreground))" />
                    <YAxis allowDecimals={false} tick={{ fontSize: 11 }} stroke="hsl(var(--muted-foreground))" />
                    <Tooltip
                      contentStyle={{ backgroundColor: "hsl(var(--card))", border: "1px solid hsl(var(--border))", borderRadius: "8px" }}
                      formatter={(v: number) => [`${v} stores`, "Count"]}
                    />
                    <Bar dataKey="count" fill="hsl(0, 72%, 51%)" radius={[6, 6, 0, 0]} name="Stores" />
                  </BarChart>
                </ResponsiveContainer>
              )}
            </div>

            <div className="rounded-xl border bg-card p-5">
              <h3 className="text-sm font-semibold mb-4">Sales by Route</h3>
              {d.routeSalesData.length === 0 ? (
                <p className="text-sm text-muted-foreground text-center py-12">No routes</p>
              ) : (
                <ResponsiveContainer width="100%" height={220}>
                  <BarChart data={d.routeSalesData} layout="vertical">
                    <CartesianGrid strokeDasharray="3 3" stroke="hsl(var(--border))" />
                    <XAxis type="number" tick={{ fontSize: 10 }} stroke="hsl(var(--muted-foreground))" tickFormatter={(v) => v >= 1000 ? `₹${(v/1000).toFixed(0)}k` : `₹${v}`} />
                    <YAxis dataKey="name" type="category" tick={{ fontSize: 11 }} stroke="hsl(var(--muted-foreground))" width={90} />
                    <Tooltip
                      contentStyle={{ backgroundColor: "hsl(var(--card))", border: "1px solid hsl(var(--border))", borderRadius: "8px" }}
                      formatter={(v: number, name: string) => [name === "sales" ? `₹${v.toLocaleString()}` : `${v}%`, name === "sales" ? "Sales" : "Completion"]}
                    />
                    <Bar dataKey="sales" fill="hsl(280, 65%, 60%)" radius={[0, 6, 6, 0]} name="sales" />
                  </BarChart>
                </ResponsiveContainer>
              )}
            </div>
          </div>
        </>
      )}
    </div>
  );
};

export default Analytics;

