  is_active: boolean;
}

interface AttendanceRecord {
  id: string;
  display_id: string;
  attendance_date: string;
  factory_start_time: string;
  factory_end_time: string;
  is_finalized: boolean;
  recorded_by: string;
  notes?: string;
  entries_count?: number;
}

interface AttendanceEntry {
  id: string;
  attendance_id: string;
  user_id?: string;
  worker_id?: string;
  is_present: boolean;
  check_in_time?: string;
  check_out_time?: string;
  hours_worked: number;
  hourly_rate: number;
  amount_earned: number;
  adjustment_amount: number;
  adjustment_reason?: string;
  notes?: string;
  // Joined data
  worker?: { name: string; display_id: string };
  profile?: { full_name: string };
}

interface WorkerBalance {
  id: string;
  user_id?: string;
  worker_id?: string;
  total_earned: number;
  total_paid: number;
  outstanding_balance: number;
  worker?: { name: string; display_id: string };
  profile?: { full_name: string };
}

// Helper function to calculate pay based on hours worked and shift rates
function calculateShiftPay(hoursWorked: number, shiftRates: any[]): { rate: number; amount: number } {
  if (shiftRates.length === 0) return { rate: 0, amount: 0 };
  
  // Find the closest matching shift rate
  let closestShift = shiftRates[0];
  let minDiff = Math.abs(hoursWorked - shiftRates[0].duration_hours);
  
  for (const shift of shiftRates) {
    const diff = Math.abs(hoursWorked - shift.duration_hours);
    if (diff < minDiff) {
      minDiff = diff;
      closestShift = shift;
    }
  }
  
  // Calculate proportional pay based on closest shift
  // Guard against division by zero
  if (!closestShift.duration_hours || closestShift.duration_hours <= 0) {
    return { rate: 0, amount: 0 };
  }
  
  const proportionalAmount = (hoursWorked / closestShift.duration_hours) * closestShift.rate_amount;
  
  return {
    rate: closestShift.rate_amount / closestShift.duration_hours, // hourly rate for reference
    amount: Math.round(proportionalAmount * 100) / 100 // round to 2 decimals
  };
}

export default function Attendance() {
  const { user } = useAuth();
  const qc = useQueryClient();
  const [activeTab, setActiveTab] = useState("records");
  
  // Workers state
  const [showWorkerDialog, setShowWorkerDialog] = useState(false);
  const [editingWorker, setEditingWorker] = useState<Worker | null>(null);
  const [workerName, setWorkerName] = useState("");
  const [workerPhone, setWorkerPhone] = useState("");
  const [deletingWorkerId, setDeletingWorkerId] = useState<string | null>(null);
  
  // Shift rates state
  const [showShiftRatesDialog, setShowShiftRatesDialog] = useState(false);
  const [editingShiftRate, setEditingShiftRate] = useState<any>(null);
  const [shiftRateName, setShiftRateName] = useState("");
  const [shiftRateDuration, setShiftRateDuration] = useState("");
  const [shiftRateAmount, setShiftRateAmount] = useState("");
  
  // Attendance record state
  const [showAttendanceDialog, setShowAttendanceDialog] = useState(false);
  const [attendanceDate, setAttendanceDate] = useState(format(new Date(), "yyyy-MM-dd"));
  const [factoryStartTime, setFactoryStartTime] = useState("09:00");
  const [factoryEndTime, setFactoryEndTime] = useState("18:00");
  const [attendanceNotes, setAttendanceNotes] = useState("");
  const [attendanceEntries, setAttendanceEntries] = useState<{
    person_type: "staff" | "worker";
    person_id: string;
    person_name: string;
    is_present: boolean;
    check_in: string;
    check_out: string;
  }[]>([]);
  
  // Payment state
  const [showPaymentDialog, setShowPaymentDialog] = useState(false);
  const [paymentPersonType, setPaymentPersonType] = useState<"staff" | "worker">("worker");
  const [paymentPersonId, setPaymentPersonId] = useState("");
  const [paymentAmount, setPaymentAmount] = useState("");
  const [paymentMethod, setPaymentMethod] = useState("cash");
  const [paymentNotes, setPaymentNotes] = useState("");
  
  // Edit attendance state
  const [editingRecord, setEditingRecord] = useState<AttendanceRecord | null>(null);
  const [showEditEntriesDialog, setShowEditEntriesDialog] = useState(false);
  const [editEntries, setEditEntries] = useState<AttendanceEntry[]>([]);
  
  const [saving, setSaving] = useState(false);

  // Queries
  const { data: shiftRates = [] } = useQuery({
    queryKey: ["shift-rates"],
    queryFn: async () => {
      const { data, error } = await supabase
        .from("shift_rates")
        .select("*")
        .eq("is_active", true)
        .order("duration_hours");
      if (error) throw error;
      return data;
    },
  });

  const { data: workers = [], isLoading: loadingWorkers } = useQuery({
    queryKey: ["workers"],
    queryFn: async () => {
      const { data, error } = await supabase
        .from("workers")
        .select("*")
        .order("name");
      if (error) throw error;
      return data as Worker[];
    },
  });

  const { data: staffUsers = [] } = useQuery({
    queryKey: ["staff-for-attendance"],
    queryFn: async () => {
      // Get all staff (agents, marketers, pos) - exclude managers and customers
      const { data, error } = await supabase
        .from("user_roles")
        .select("user_id, role")
        .not("role", "in", "(manager,super_admin,customer)");
      if (error) throw error;
      
      if (!data || data.length === 0) return [];
      
      // Get profiles for these users
      const userIds = data.map(d => d.user_id);
      const { data: profiles } = await supabase
        .from("profiles")
        .select("id, full_name, hourly_rate")
        .in("id", userIds);
      
      // Merge data
      return data.map(ur => ({
        ...ur,
        profiles: profiles?.find(p => p.id === ur.user_id) || { full_name: "Unknown", hourly_rate: 0 }
      }));
    },
  });

  const { data: attendanceRecords = [], isLoading: loadingRecords } = useQuery({
    queryKey: ["attendance-records"],
    queryFn: async () => {
      const { data, error } = await supabase
        .from("attendance_records")
        .select(`
          *,
          attendance_entries(count)
        `)
        .order("attendance_date", { ascending: false });
      if (error) throw error;
      return data.map(r => ({
        ...r,
        entries_count: r.attendance_entries?.[0]?.count || 0
      })) as AttendanceRecord[];
    },
  });

  const { data: balances = [], isLoading: loadingBalances } = useQuery({
    queryKey: ["worker-balances"],
    queryFn: async () => {
      const { data, error } = await supabase
        .from("worker_balances")
        .select(`
          *,
          workers(name, display_id)
        `)
        .order("outstanding_balance", { ascending: false });
      if (error) throw error;
      
      if (!data || data.length === 0) return [];
      
      // Get profiles for users with user_id
      const userIds = data.filter(d => d.user_id).map(d => d.user_id!);
      let profilesMap: Record<string, { full_name: string }> = {};
      
      if (userIds.length > 0) {
        const { data: profiles } = await supabase
          .from("profiles")
          .select("id, full_name")
          .in("id", userIds);
        
        profiles?.forEach(p => { profilesMap[p.id] = { full_name: p.full_name }; });
      }
      
      return data.map(b => ({
        ...b,
        profiles: b.user_id ? profilesMap[b.user_id] : null
      })) as WorkerBalance[];
    },
  });

  // Worker mutations
  const resetWorkerForm = () => {
    setEditingWorker(null);
    setWorkerName("");
    setWorkerPhone("");
  };

  const saveWorkerMutation = useMutation({
    mutationFn: async () => {
      if (editingWorker) {
        const { error } = await supabase
          .from("workers")
          .update({
            name: workerName,
            phone: workerPhone || null,
            updated_at: new Date().toISOString(),
          })
          .eq("id", editingWorker.id);
        if (error) throw error;
      } else {
        const { data: idData } = await supabase.rpc("generate_display_id", {
          prefix: "WRK",
          seq_name: "workers_display_id_seq"
        });
        
        const { error } = await supabase.from("workers").insert({
          display_id: idData,
          name: workerName,
          phone: workerPhone || null,
        });
        if (error) throw error;
      }
    },
    onSuccess: () => {
      qc.invalidateQueries({ queryKey: ["workers"] });
      toast.success(editingWorker ? "Worker updated" : "Worker added");
      setShowWorkerDialog(false);
      resetWorkerForm();
    },
    onError: (e: Error) => toast.error(`Failed: ${e.message}`),
  });

  const deleteWorkerMutation = useMutation({
    mutationFn: async (id: string) => {
      const { error } = await supabase.from("workers").update({ is_active: false }).eq("id", id);
      if (error) throw error;
    },
    onSuccess: () => {
      qc.invalidateQueries({ queryKey: ["workers"] });
      toast.success("Worker deactivated");
      setDeletingWorkerId(null);
    },
    onError: (e: Error) => toast.error(`Failed: ${e.message}`),
  });

  // Shift rates mutations
  const resetShiftRateForm = () => {
    setEditingShiftRate(null);
    setShiftRateName("");
    setShiftRateDuration("");
    setShiftRateAmount("");
  };

  const saveShiftRateMutation = useMutation({
    mutationFn: async () => {
      if (editingShiftRate) {
        const { error } = await supabase
          .from("shift_rates")
          .update({
            shift_name: shiftRateName,
            duration_hours: parseFloat(shiftRateDuration),
            rate_amount: parseFloat(shiftRateAmount),
            updated_at: new Date().toISOString(),
          })
          .eq("id", editingShiftRate.id);
        if (error) throw error;
      } else {
        const { data: idData } = await supabase.rpc("generate_display_id", {
          prefix: "SR",
          seq_name: "shift_rates_display_id_seq"
        });
        
        const { error } = await supabase.from("shift_rates").insert({
          display_id: idData,
          shift_name: shiftRateName,
          duration_hours: parseFloat(shiftRateDuration),
          rate_amount: parseFloat(shiftRateAmount),
          created_by: user?.id,
        });
        if (error) throw error;
      }
    },
    onSuccess: () => {
      qc.invalidateQueries({ queryKey: ["shift-rates"] });
      toast.success(editingShiftRate ? "Shift rate updated" : "Shift rate added");
      resetShiftRateForm();
    },
    onError: (e: Error) => toast.error(`Failed: ${e.message}`),
  });

  const deleteShiftRateMutation = useMutation({
    mutationFn: async (id: string) => {
      const { error } = await supabase.from("shift_rates").update({ is_active: false }).eq("id", id);
      if (error) throw error;
    },
    onSuccess: () => {
      qc.invalidateQueries({ queryKey: ["shift-rates"] });
      toast.success("Shift rate deleted");
    },
    onError: (e: Error) => toast.error(`Failed: ${e.message}`),
  });

  // Attendance mutations
  const initAttendanceEntries = () => {
    const entries: typeof attendanceEntries = [];
    
    // Add all active workers
    workers.filter(w => w.is_active).forEach(w => {
      entries.push({
        person_type: "worker",
        person_id: w.id,
        person_name: w.name,
        is_present: true,
        check_in: factoryStartTime,
        check_out: factoryEndTime,
      });
    });
    
    // Add all staff (non-manager, non-admin)
    staffUsers.forEach((s: any) => {
      entries.push({
        person_type: "staff",
        person_id: s.user_id,
        person_name: s.profiles?.full_name || "Unknown",
        is_present: true,
        check_in: factoryStartTime,
        check_out: factoryEndTime,
      });
    });
    
    setAttendanceEntries(entries);
  };

  const saveAttendanceMutation = useMutation({
    mutationFn: async () => {
      // Generate display ID
      const { data: idData } = await supabase.rpc("generate_display_id", {
        prefix: "ATT",
        seq_name: "attendance_display_id_seq"
      });

      // Create attendance record
      const { data: record, error: recordError } = await supabase
        .from("attendance_records")
        .insert({
          display_id: idData,
          attendance_date: attendanceDate,
          recorded_by: user!.id,
          factory_start_time: factoryStartTime,
          factory_end_time: factoryEndTime,
          notes: attendanceNotes || null,
        })
        .select()
        .single();

      if (recordError) throw recordError;

      // Create attendance entries for present people
      const entries = attendanceEntries
        .filter(e => e.is_present)
        .map(e => {
          // Calculate hours worked
          const checkIn = new Date(`2000-01-01T${e.check_in}:00`);
          const checkOut = new Date(`2000-01-01T${e.check_out}:00`);
          const hoursWorked = (checkOut.getTime() - checkIn.getTime()) / (1000 * 60 * 60);
          
          // Calculate pay based on shift rates
          const { rate, amount } = calculateShiftPay(hoursWorked, shiftRates);
          
          return {
            attendance_id: record.id,
            user_id: e.person_type === "staff" ? e.person_id : null,
            worker_id: e.person_type === "worker" ? e.person_id : null,
            is_present: true,
            check_in_time: e.check_in,
            check_out_time: e.check_out,
            hourly_rate: rate, // Store calculated hourly rate for reference
          };
        });

      if (entries.length > 0) {
        const { error: entriesError } = await supabase
          .from("attendance_entries")
          .insert(entries);
        if (entriesError) throw entriesError;
      }

      return record;
    },
    onSuccess: (record) => {
      qc.invalidateQueries({ queryKey: ["attendance-records"] });
      qc.invalidateQueries({ queryKey: ["worker-balances"] });
      toast.success(`Attendance recorded: ${record.display_id}`);
      logActivity(user!.id, `Recorded attendance for ${attendanceDate}`, "attendance");
      setShowAttendanceDialog(false);
      setAttendanceEntries([]);
    },
    onError: (e: Error) => toast.error(`Failed: ${e.message}`),
  });

  // Payment mutation
  const savePaymentMutation = useMutation({
    mutationFn: async () => {
      const { data: idData } = await supabase.rpc("generate_display_id", {
        prefix: "WPY",
        seq_name: "worker_payments_display_id_seq"
      });

      const { error } = await supabase.from("worker_payments").insert({
        display_id: idData,
        user_id: paymentPersonType === "staff" ? paymentPersonId : null,
        worker_id: paymentPersonType === "worker" ? paymentPersonId : null,
        amount: parseFloat(paymentAmount),
        payment_method: paymentMethod,
        notes: paymentNotes || null,
        created_by: user!.id,
      });
      if (error) throw error;
    },
    onSuccess: () => {
      qc.invalidateQueries({ queryKey: ["worker-balances"] });
      toast.success("Payment recorded");
      setShowPaymentDialog(false);
      setPaymentPersonId("");
      setPaymentAmount("");
      setPaymentNotes("");
    },
    onError: (e: Error) => toast.error(`Failed: ${e.message}`),
  });

  // Edit entries for a record
  const loadEntriesForEdit = async (record: AttendanceRecord) => {
    const { data, error } = await supabase
      .from("attendance_entries")
      .select(`
        *,
        workers(name, display_id)
      `)
      .eq("attendance_id", record.id);
    
    if (error) {
      toast.error("Failed to load entries");
      return;
    }
    
    if (!data || data.length === 0) {
      setEditingRecord(record);
      setEditEntries([]);
      setShowEditEntriesDialog(true);
      return;
    }
    
    // Get profiles for users
    const userIds = data.filter(d => d.user_id).map(d => d.user_id!);
    let profilesMap: Record<string, { full_name: string }> = {};
    
    if (userIds.length > 0) {
      const { data: profiles } = await supabase
        .from("profiles")
        .select("id, full_name")
        .in("id", userIds);
      
      profiles?.forEach(p => { profilesMap[p.id] = { full_name: p.full_name }; });
    }
    
    const entriesWithProfiles = data.map(e => ({
      ...e,
      profiles: e.user_id ? profilesMap[e.user_id] : null
    }));
    
    setEditingRecord(record);
    setEditEntries(entriesWithProfiles as AttendanceEntry[]);
    setShowEditEntriesDialog(true);
  };

  const updateEntryMutation = useMutation({
    mutationFn: async (entry: AttendanceEntry) => {
      const { error } = await supabase
        .from("attendance_entries")
        .update({
          check_in_time: entry.check_in_time,
          check_out_time: entry.check_out_time,
          hourly_rate: entry.hourly_rate,
          adjustment_amount: entry.adjustment_amount,
          adjustment_reason: entry.adjustment_reason,
          notes: entry.notes,
          updated_at: new Date().toISOString(),
        })
        .eq("id", entry.id);
      if (error) throw error;
    },
    onSuccess: () => {
      qc.invalidateQueries({ queryKey: ["attendance-records"] });
      qc.invalidateQueries({ queryKey: ["worker-balances"] });
      toast.success("Entry updated");
    },
    onError: (e: Error) => toast.error(`Failed: ${e.message}`),
  });

  const handleEditWorker = (w: Worker) => {
    setEditingWorker(w);
    setWorkerName(w.name);
    setWorkerPhone(w.phone || "");
    setShowWorkerDialog(true);
  };

  const calculateHours = (checkIn: string, checkOut: string) => {
    if (!checkIn || !checkOut) return 0;
    const [inH, inM] = checkIn.split(":").map(Number);
    const [outH, outM] = checkOut.split(":").map(Number);
    return Math.max(0, (outH * 60 + outM - inH * 60 - inM) / 60);
  };

  const updateEntryTime = (index: number, field: "check_in" | "check_out", value: string) => {
    const updated = [...attendanceEntries];
    updated[index] = { ...updated[index], [field]: value };
    setAttendanceEntries(updated);
  };

  const totalOwed = balances.reduce((sum, b) => sum + Math.max(0, Number(b.outstanding_balance)), 0);
  const totalAdvance = balances.reduce((sum, b) => sum + Math.max(0, -Number(b.outstanding_balance)), 0);

  if (loadingRecords && loadingWorkers) {
    return <TableSkeleton columns={6} />;
  }

  return (
    <div className="space-y-6 animate-fade-in">
      <PageHeader
        title="Attendance"
        subtitle="Track daily attendance and calculate wages"
        primaryAction={{
          label: "Record Attendance",
          icon: Calendar,
          onClick: () => {
            initAttendanceEntries();
            setShowAttendanceDialog(true);
          },
        }}
        actions={[
          { label: "Add Worker", onClick: () => { resetWorkerForm(); setShowWorkerDialog(true); }, priority: 1 },
          { label: "Make Payment", onClick: () => setShowPaymentDialog(true), priority: 2 },
          { label: "Shift Rates", onClick: () => setShowShiftRatesDialog(true), priority: 3 },
        ]}
      />

      {/* Summary Cards */}
      <div className="grid grid-cols-1 md:grid-cols-4 gap-4">
        <Card>
          <CardContent className="pt-6">
            <div className="flex items-center justify-between">
              <div>
                <p className="text-sm text-muted-foreground">Total Workers</p>
                <p className="text-2xl font-bold">{workers.filter(w => w.is_active).length}</p>
              </div>
              <Users className="h-8 w-8 text-blue-500 opacity-80" />
            </div>
          </CardContent>
        </Card>
        <Card>
          <CardContent className="pt-6">
            <div className="flex items-center justify-between">
              <div>
                <p className="text-sm text-muted-foreground">Staff Members</p>
                <p className="text-2xl font-bold">{staffUsers.length}</p>
              </div>
              <UserPlus className="h-8 w-8 text-purple-500 opacity-80" />
            </div>
          </CardContent>
        </Card>
        <Card>
          <CardContent className="pt-6">
            <div className="flex items-center justify-between">
              <div>
                <p className="text-sm text-muted-foreground">Company Owes</p>
                <p className="text-2xl font-bold text-red-600">₹{totalOwed.toLocaleString()}</p>
              </div>
              <ArrowUpRight className="h-8 w-8 text-red-500 opacity-80" />
            </div>
          </CardContent>
        </Card>
        <Card>
          <CardContent className="pt-6">
            <div className="flex items-center justify-between">
              <div>
                <p className="text-sm text-muted-foreground">Advance Paid</p>
                <p className="text-2xl font-bold text-green-600">₹{totalAdvance.toLocaleString()}</p>
              </div>
              <ArrowDownRight className="h-8 w-8 text-green-500 opacity-80" />
            </div>
          </CardContent>
        </Card>
      </div>

      {/* Tabs */}
      <Tabs value={activeTab} onValueChange={setActiveTab}>
        <TabsList className="grid w-full grid-cols-3 lg:w-auto lg:inline-grid">
          <TabsTrigger value="records">Attendance Records</TabsTrigger>
          <TabsTrigger value="workers">Workers</TabsTrigger>
          <TabsTrigger value="balances">Balances</TabsTrigger>
        </TabsList>

        {/* Attendance Records Tab */}
        <TabsContent value="records" className="mt-4">
          <Card>
            <CardHeader>
              <CardTitle>Attendance History</CardTitle>
              <CardDescription>View and edit past attendance records</CardDescription>
            </CardHeader>
            <CardContent>
              <DataTable
                columns={[
                  { header: "ID", accessor: "display_id", className: "font-mono text-xs" },
                  { header: "Date", accessor: (r: AttendanceRecord) => format(parseISO(r.attendance_date), "dd MMM yyyy") },
                  { header: "Hours", accessor: (r: AttendanceRecord) => `${r.factory_start_time} - ${r.factory_end_time}` },
                  { header: "Entries", accessor: (r: AttendanceRecord) => r.entries_count || 0, className: "text-center" },
                  {
                    header: "Status",
                    accessor: (r: AttendanceRecord) => (
                      <StatusBadge status={r.is_finalized ? "active" : "pending"} label={r.is_finalized ? "Finalized" : "Draft"} />
                    ),
                  },
                  {
                    header: "Actions",
                    accessor: (r: AttendanceRecord) => (
                      <Button variant="ghost" size="sm" onClick={() => loadEntriesForEdit(r)}>
                        <Pencil className="h-4 w-4 mr-1" />
                        Edit
                      </Button>
                    ),
                  },
                ]}
                data={attendanceRecords}
                searchKey="display_id"
                searchPlaceholder="Search by ID..."
                emptyMessage="No attendance records yet"
                renderMobileCard={(r: AttendanceRecord) => (
                  <div className="entity-card-mobile flex-col !items-stretch">
                    <div className="flex items-start justify-between">
                      <div className="min-w-0">
                        <p className="entity-card-subtitle">{r.display_id}</p>
                        <p className="font-semibold">{format(parseISO(r.attendance_date), "dd MMM yyyy")}</p>
                        <p className="text-sm text-muted-foreground">{r.factory_start_time} - {r.factory_end_time}</p>
                      </div>
                      <StatusBadge status={r.is_finalized ? "active" : "pending"} label={r.is_finalized ? "Final" : "Draft"} />
                    </div>
                    <div className="flex items-center justify-between mt-2 pt-2 border-t">
                      <span className="text-sm">{r.entries_count} entries</span>
                      <Button variant="outline" size="sm" onClick={() => loadEntriesForEdit(r)}>
                        <Pencil className="h-4 w-4 mr-1" />
                        Edit
                      </Button>
                    </div>
                  </div>
                )}
              />
            </CardContent>
          </Card>
        </TabsContent>

        {/* Workers Tab */}
        <TabsContent value="workers" className="mt-4">
          <Card>
            <CardHeader>
              <CardTitle>Workers List</CardTitle>
              <CardDescription>Manage non-staff workers</CardDescription>
            </CardHeader>
            <CardContent>
              <DataTable
                columns={[
                  { header: "ID", accessor: "display_id", className: "font-mono text-xs" },
                  { header: "Name", accessor: "name", className: "font-medium" },
                  { header: "Phone", accessor: (w: Worker) => w.phone || "—" },
                  { header: "Hourly Rate", accessor: (w: Worker) => `₹${w.hourly_rate}/hr` },
                  {
                    header: "Status",
                    accessor: (w: Worker) => (
                      <StatusBadge status={w.is_active ? "active" : "inactive"} />
                    ),
                  },
                  {
                    header: "Actions",
                    accessor: (w: Worker) => (
                      <div className="flex gap-1">
                        <Button variant="ghost" size="icon" className="h-8 w-8" onClick={() => handleEditWorker(w)}>
                          <Pencil className="h-4 w-4" />
                        </Button>
                        <Button variant="ghost" size="icon" className="h-8 w-8 text-destructive" onClick={() => setDeletingWorkerId(w.id)}>
                          <Trash2 className="h-4 w-4" />
                        </Button>
                      </div>
                    ),
                  },
                ]}
                data={workers}
                searchKey="name"
                searchPlaceholder="Search workers..."
                emptyMessage="No workers added yet"
                renderMobileCard={(w: Worker) => (
                  <div className="entity-card-mobile flex-col !items-stretch">
                    <div className="flex items-start justify-between">
                      <div className="min-w-0">
                        <p className="entity-card-subtitle">{w.display_id}</p>
                        <p className="font-semibold">{w.name}</p>
                        <p className="text-sm text-muted-foreground">{w.phone || "No phone"}</p>
                      </div>
                      <StatusBadge status={w.is_active ? "active" : "inactive"} />
                    </div>
                    <div className="flex items-center justify-between mt-2 pt-2 border-t">
                      <span className="font-medium">₹{w.hourly_rate}/hr</span>
                      <div className="flex gap-2">
                        <Button variant="outline" size="sm" onClick={() => handleEditWorker(w)}>
                          <Pencil className="h-4 w-4" />
                        </Button>
                        <Button variant="outline" size="sm" className="text-destructive" onClick={() => setDeletingWorkerId(w.id)}>
                          <Trash2 className="h-4 w-4" />
                        </Button>
                      </div>
                    </div>
                  </div>
                )}
              />
            </CardContent>
          </Card>
        </TabsContent>

        {/* Balances Tab */}
        <TabsContent value="balances" className="mt-4">
          <Card>
            <CardHeader>
              <CardTitle>Outstanding Balances</CardTitle>
              <CardDescription>Track what company owes to workers/staff</CardDescription>
            </CardHeader>
            <CardContent>
              <DataTable
                columns={[
                  { 
                    header: "Person", 
                    accessor: (b: WorkerBalance) => b.workers?.name || (b as any).profiles?.full_name || "Unknown",
                    className: "font-medium"
                  },
                  { header: "Type", accessor: (b: WorkerBalance) => b.worker_id ? "Worker" : "Staff", className: "text-sm" },
                  { header: "Total Earned", accessor: (b: WorkerBalance) => `₹${Number(b.total_earned).toLocaleString()}` },
                  { header: "Total Paid", accessor: (b: WorkerBalance) => `₹${Number(b.total_paid).toLocaleString()}` },
                  { 
                    header: "Balance", 
                    accessor: (b: WorkerBalance) => {
                      const bal = Number(b.outstanding_balance);
                      return (
                        <span className={bal > 0 ? "text-red-600 font-semibold" : bal < 0 ? "text-green-600 font-semibold" : ""}>
                          ₹{Math.abs(bal).toLocaleString()}
                          {bal > 0 ? " (owed)" : bal < 0 ? " (advance)" : ""}
                        </span>
                      );
                    }
                  },
                ]}
                data={balances}
                searchKey="workers.name"
                searchPlaceholder="Search..."
                emptyMessage="No balance records yet"
                renderMobileCard={(b: WorkerBalance) => (
                  <div className="entity-card-mobile flex-col !items-stretch">
                    <div className="flex items-start justify-between">
                      <div className="min-w-0">
                        <p className="font-semibold">{b.workers?.name || (b as any).profiles?.full_name || "Unknown"}</p>
                        <p className="text-xs text-muted-foreground">{b.worker_id ? "Worker" : "Staff"}</p>
                      </div>
                      {Number(b.outstanding_balance) > 0 ? (
                        <span className="px-2 py-1 rounded-full text-xs bg-red-500/10 text-red-600 font-medium">Owed</span>
                      ) : Number(b.outstanding_balance) < 0 ? (
                        <span className="px-2 py-1 rounded-full text-xs bg-green-500/10 text-green-600 font-medium">Advance</span>
                      ) : null}
                    </div>
                    <div className="grid grid-cols-3 gap-2 mt-2 pt-2 border-t text-sm">
                      <div>
                        <p className="text-muted-foreground text-xs">Earned</p>
                        <p className="font-medium">₹{Number(b.total_earned).toLocaleString()}</p>
                      </div>
                      <div>
                        <p className="text-muted-foreground text-xs">Paid</p>
                        <p className="font-medium">₹{Number(b.total_paid).toLocaleString()}</p>
                      </div>
                      <div>
                        <p className="text-muted-foreground text-xs">Balance</p>
                        <p className={`font-bold ${Number(b.outstanding_balance) > 0 ? "text-red-600" : Number(b.outstanding_balance) < 0 ? "text-green-600" : ""}`}>
                          ₹{Math.abs(Number(b.outstanding_balance)).toLocaleString()}
                        </p>
                      </div>
                    </div>
                  </div>
                )}
              />
            </CardContent>
          </Card>
        </TabsContent>
      </Tabs>

      {/* Add/Edit Worker Dialog */}
      <Dialog open={showWorkerDialog} onOpenChange={(open) => { setShowWorkerDialog(open); if (!open) resetWorkerForm(); }}>
        <DialogContent className="max-w-md">
          <DialogHeader>
            <DialogTitle>{editingWorker ? "Edit Worker" : "Add Worker"}</DialogTitle>
          </DialogHeader>
          <div className="space-y-4 py-4">
            <div className="space-y-2">
              <Label>Name *</Label>
              <Input value={workerName} onChange={(e) => setWorkerName(e.target.value)} placeholder="Worker name" />
            </div>
            <div className="space-y-2">
              <Label>Phone</Label>
              <Input value={workerPhone} onChange={(e) => setWorkerPhone(e.target.value)} placeholder="Phone number" />
            </div>
          </div>
          <DialogFooter>
            <Button variant="outline" onClick={() => setShowWorkerDialog(false)}>Cancel</Button>
            <Button onClick={() => saveWorkerMutation.mutate()} disabled={!workerName.trim() || saveWorkerMutation.isPending}>
              {saveWorkerMutation.isPending && <Loader2 className="mr-2 h-4 w-4 animate-spin" />}
              {editingWorker ? "Update" : "Add"}
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>

      {/* Record Attendance Dialog */}
      <Dialog open={showAttendanceDialog} onOpenChange={setShowAttendanceDialog}>
        <DialogContent className="max-w-4xl max-h-[90vh] overflow-y-auto">
          <DialogHeader>
            <DialogTitle>Record Attendance</DialogTitle>
          </DialogHeader>
          <div className="space-y-6 py-4">
            {/* Date and Time Settings */}
            <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
              <div className="space-y-2">
                <Label>Date *</Label>
                <Input type="date" value={attendanceDate} onChange={(e) => setAttendanceDate(e.target.value)} />
              </div>
              <div className="space-y-2">
                <Label>Factory Start Time</Label>
                <Input 
                  type="time" 
                  value={factoryStartTime} 
                  onChange={(e) => {
                    setFactoryStartTime(e.target.value);
                    // Update all entries to use new start time
                    setAttendanceEntries(prev => prev.map(entry => ({ ...entry, check_in: e.target.value })));
                  }} 
                />
              </div>
              <div className="space-y-2">
                <Label>Factory End Time</Label>
                <Input 
                  type="time" 
                  value={factoryEndTime} 
                  onChange={(e) => {
                    setFactoryEndTime(e.target.value);
                    // Update all entries to use new end time
                    setAttendanceEntries(prev => prev.map(entry => ({ ...entry, check_out: e.target.value })));
                  }} 
                />
              </div>
            </div>

            {/* Attendance Entries */}
            <div>
              <Label className="mb-3 block">Attendance ({attendanceEntries.filter(e => e.is_present).length} present)</Label>
              <div className="border rounded-lg divide-y">
                {attendanceEntries.map((entry, index) => {
                  const hours = calculateHours(entry.check_in, entry.check_out);
                  const amount = hours * entry.hourly_rate;
                  
                  return (
                    <div key={`${entry.person_type}-${entry.person_id}`} className="p-3">
                      <div className="grid grid-cols-12 gap-3 items-center">
                        {/* Present toggle + Name - 4 cols */}
                        <div className="col-span-4 flex items-center gap-3">
                          <Switch 
                            checked={entry.is_present} 
                            onCheckedChange={(checked) => {
                              const updated = [...attendanceEntries];
                              updated[index] = { ...updated[index], is_present: checked };
                              setAttendanceEntries(updated);
                            }}
                          />
                          <div className="min-w-0">
                            <p className={`font-medium truncate ${!entry.is_present ? "text-muted-foreground line-through" : ""}`}>
                              {entry.person_name}
                            </p>
                            <p className="text-xs text-muted-foreground">
                              {entry.person_type === "worker" ? "Worker" : "Staff"} • ₹{entry.hourly_rate}/hr
                            </p>
                          </div>
                        </div>
                        
                        {/* Check In - 2 cols */}
                        <div className="col-span-2">
                          <Input 
                            type="time" 
                            value={entry.check_in} 
                            onChange={(e) => updateEntryTime(index, "check_in", e.target.value)}
                            disabled={!entry.is_present}
                            className="h-9"
                          />
                        </div>
                        
                        {/* Check Out - 2 cols */}
                        <div className="col-span-2">
                          <Input 
                            type="time" 
                            value={entry.check_out} 
                            onChange={(e) => updateEntryTime(index, "check_out", e.target.value)}
                            disabled={!entry.is_present}
                            className="h-9"
                          />
                        </div>
                        
                        {/* Hours - 2 cols */}
                        <div className="col-span-2 text-center">
                          <p className="text-sm font-medium">{entry.is_present ? hours.toFixed(1) : "—"} hrs</p>
                        </div>
                        
                        {/* Amount - 2 cols */}
                        <div className="col-span-2 text-right">
                          <p className="font-semibold text-green-600">
                            {entry.is_present ? `₹${amount.toFixed(0)}` : "—"}
                          </p>
                        </div>
                      </div>
                    </div>
                  );
                })}
              </div>
            </div>

            {/* Total */}
            <div className="flex items-center justify-between p-4 bg-muted rounded-lg">
              <span className="font-medium">Total Wages for Today</span>
              <span className="text-xl font-bold text-green-600">
                ₹{attendanceEntries
                  .filter(e => e.is_present)
                  .reduce((sum, e) => sum + calculateHours(e.check_in, e.check_out) * e.hourly_rate, 0)
                  .toFixed(0)}
              </span>
            </div>

            {/* Notes */}
            <div className="space-y-2">
              <Label>Notes</Label>
              <Textarea value={attendanceNotes} onChange={(e) => setAttendanceNotes(e.target.value)} placeholder="Any notes for this day..." />
            </div>
          </div>
          <DialogFooter>
            <Button variant="outline" onClick={() => setShowAttendanceDialog(false)}>Cancel</Button>
            <Button 
              onClick={() => saveAttendanceMutation.mutate()} 
              disabled={saveAttendanceMutation.isPending || attendanceEntries.filter(e => e.is_present).length === 0}
            >
              {saveAttendanceMutation.isPending && <Loader2 className="mr-2 h-4 w-4 animate-spin" />}
              Save Attendance
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>

      {/* Make Payment Dialog */}
      <Dialog open={showPaymentDialog} onOpenChange={setShowPaymentDialog}>
        <DialogContent className="max-w-md">
          <DialogHeader>
            <DialogTitle>Make Payment</DialogTitle>
          </DialogHeader>
          <div className="space-y-4 py-4">
            <div className="space-y-2">
              <Label>Person Type</Label>
              <Select value={paymentPersonType} onValueChange={(v: "staff" | "worker") => { setPaymentPersonType(v); setPaymentPersonId(""); }}>
                <SelectTrigger>
                  <SelectValue />
                </SelectTrigger>
                <SelectContent>
                  <SelectItem value="worker">Worker</SelectItem>
                  <SelectItem value="staff">Staff</SelectItem>
                </SelectContent>
              </Select>
            </div>
            <div className="space-y-2">
              <Label>Select Person *</Label>
              <Select value={paymentPersonId} onValueChange={setPaymentPersonId}>
                <SelectTrigger>
                  <SelectValue placeholder="Select person" />
                </SelectTrigger>
                <SelectContent>
                  {paymentPersonType === "worker"
                    ? workers.filter(w => w.is_active).map(w => (
                        <SelectItem key={w.id} value={w.id}>{w.name} ({w.display_id})</SelectItem>
                      ))
                    : staffUsers.map((s: any) => (
                        <SelectItem key={s.user_id} value={s.user_id}>{s.profiles?.full_name}</SelectItem>
                      ))
                  }
                </SelectContent>
              </Select>
            </div>
            <div className="space-y-2">
              <Label>Amount (₹) *</Label>
              <Input type="number" min="0" step="0.01" value={paymentAmount} onChange={(e) => setPaymentAmount(e.target.value)} />
            </div>
            <div className="space-y-2">
              <Label>Payment Method</Label>
              <Select value={paymentMethod} onValueChange={setPaymentMethod}>
                <SelectTrigger>
                  <SelectValue />
                </SelectTrigger>
                <SelectContent>
                  <SelectItem value="cash">Cash</SelectItem>
                  <SelectItem value="bank_transfer">Bank Transfer</SelectItem>
                  <SelectItem value="upi">UPI</SelectItem>
                  <SelectItem value="cheque">Cheque</SelectItem>
                </SelectContent>
              </Select>
            </div>
            <div className="space-y-2">
              <Label>Notes</Label>
              <Textarea value={paymentNotes} onChange={(e) => setPaymentNotes(e.target.value)} placeholder="Optional notes..." />
            </div>
          </div>
          <DialogFooter>
            <Button variant="outline" onClick={() => setShowPaymentDialog(false)}>Cancel</Button>
            <Button 
              onClick={() => savePaymentMutation.mutate()} 
              disabled={!paymentPersonId || !paymentAmount || savePaymentMutation.isPending}
            >
              {savePaymentMutation.isPending && <Loader2 className="mr-2 h-4 w-4 animate-spin" />}
              Record Payment
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>

      {/* Edit Entries Dialog */}
      <Dialog open={showEditEntriesDialog} onOpenChange={setShowEditEntriesDialog}>
        <DialogContent className="max-w-4xl max-h-[90vh] overflow-y-auto">
          <DialogHeader>
            <DialogTitle>Edit Attendance - {editingRecord?.display_id}</DialogTitle>
          </DialogHeader>
          <div className="space-y-4 py-4">
            {editEntries.map((entry, index) => (
              <div key={entry.id} className="p-4 border rounded-lg">
                <div className="grid grid-cols-12 gap-4 items-center">
                  {/* Name - 3 cols */}
                  <div className="col-span-3">
                    <p className="font-medium">{entry.workers?.name || (entry as any).profiles?.full_name || "Unknown"}</p>
                    <p className="text-xs text-muted-foreground">{entry.worker_id ? "Worker" : "Staff"}</p>
                  </div>
                  
                  {/* Check In - 2 cols */}
                  <div className="col-span-2">
                    <Label className="text-xs">Check In</Label>
                    <Input 
                      type="time" 
                      value={entry.check_in_time || ""} 
                      onChange={(e) => {
                        const updated = [...editEntries];
                        updated[index] = { ...updated[index], check_in_time: e.target.value };
                        setEditEntries(updated);
                      }}
                      className="h-9"
                    />
                  </div>
                  
                  {/* Check Out - 2 cols */}
                  <div className="col-span-2">
                    <Label className="text-xs">Check Out</Label>
                    <Input 
                      type="time" 
                      value={entry.check_out_time || ""} 
                      onChange={(e) => {
                        const updated = [...editEntries];
                        updated[index] = { ...updated[index], check_out_time: e.target.value };
                        setEditEntries(updated);
                      }}
                      className="h-9"
                    />
                  </div>
                  
                  {/* Rate - 2 cols */}
                  <div className="col-span-2">
                    <Label className="text-xs">Rate (₹/hr)</Label>
                    <Input 
                      type="number" 
                      min="0"
                      step="0.01"
                      value={entry.hourly_rate} 
                      onChange={(e) => {
                        const updated = [...editEntries];
                        updated[index] = { ...updated[index], hourly_rate: parseFloat(e.target.value) || 0 };
                        setEditEntries(updated);
                      }}
                      className="h-9"
                    />
                  </div>
                  
                  {/* Amount - 2 cols */}
                  <div className="col-span-2 text-right">
                    <p className="text-xs text-muted-foreground">Earned</p>
                    <p className="font-semibold text-green-600">₹{Number(entry.amount_earned).toFixed(0)}</p>
                  </div>
                  
                  {/* Save button - 1 col */}
                  <div className="col-span-1">
                    <Button 
                      size="sm" 
                      variant="outline"
                      onClick={() => updateEntryMutation.mutate(entry)}
                      disabled={updateEntryMutation.isPending}
                    >
                      Save
                    </Button>
                  </div>
                </div>
              </div>
            ))}
          </div>
          <DialogFooter>
            <Button variant="outline" onClick={() => setShowEditEntriesDialog(false)}>Close</Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>

      {/* Delete Worker Confirmation */}
      <AlertDialog open={!!deletingWorkerId} onOpenChange={() => setDeletingWorkerId(null)}>
        <AlertDialogContent>
          <AlertDialogHeader>
            <AlertDialogTitle>Deactivate Worker?</AlertDialogTitle>
            <AlertDialogDescription>
              This will deactivate the worker. They won't appear in attendance forms but their history will be preserved.
            </AlertDialogDescription>
          </AlertDialogHeader>
          <AlertDialogFooter>
            <AlertDialogCancel>Cancel</AlertDialogCancel>
            <AlertDialogAction onClick={() => deletingWorkerId && deleteWorkerMutation.mutate(deletingWorkerId)}>
              Deactivate
            </AlertDialogAction>
          </AlertDialogFooter>
        </AlertDialogContent>
      </AlertDialog>

      {/* Shift Rates Dialog */}
      <Dialog open={showShiftRatesDialog} onOpenChange={(open) => { setShowShiftRatesDialog(open); if (!open) resetShiftRateForm(); }}>
        <DialogContent className="max-w-2xl">
          <DialogHeader>
            <DialogTitle>Manage Shift Rates</DialogTitle>
            <DialogDescription>
              Define pay rates for different shift durations. Workers are paid proportionally based on hours worked.
            </DialogDescription>
          </DialogHeader>
          <div className="space-y-4 py-4">
            {/* Existing shift rates */}
            <div className="space-y-2">
              <Label className="text-sm font-medium">Current Shift Rates</Label>
              {shiftRates.length === 0 ? (
                <p className="text-sm text-muted-foreground">No shift rates defined yet. Add your first rate below.</p>
              ) : (
                <div className="border rounded-lg divide-y">
                  {shiftRates.map((rate: any) => (
                    <div key={rate.id} className="p-3 flex items-center justify-between">
                      <div>
                        <p className="font-medium">{rate.shift_name}</p>
                        <p className="text-sm text-muted-foreground">
                          {rate.duration_hours} hours = ₹{rate.rate_amount.toFixed(2)}
                        </p>
                      </div>
                      <div className="flex gap-2">
                        <Button 
                          variant="ghost" 
                          size="sm"
                          onClick={() => {
                            setEditingShiftRate(rate);
                            setShiftRateName(rate.shift_name);
                            setShiftRateDuration(String(rate.duration_hours));
                            setShiftRateAmount(String(rate.rate_amount));
                          }}
                        >
                          <Pencil className="h-4 w-4" />
                        </Button>
                        <Button 
                          variant="ghost" 
                          size="sm"
                          onClick={() => deleteShiftRateMutation.mutate(rate.id)}
                          disabled={deleteShiftRateMutation.isPending}
                        >
                          <Trash2 className="h-4 w-4 text-destructive" />
                        </Button>
                      </div>
                    </div>
                  ))}
                </div>
              )}
            </div>

            {/* Add/Edit form */}
            <div className="border-t pt-4">
              <Label className="text-sm font-medium">{editingShiftRate ? "Edit Shift Rate" : "Add New Shift Rate"}</Label>
              <div className="grid grid-cols-3 gap-3 mt-2">
                <div className="space-y-1">
                  <Label className="text-xs text-muted-foreground">Name</Label>
                  <Input 
                    value={shiftRateName} 
                    onChange={(e) => setShiftRateName(e.target.value)} 
                    placeholder="e.g., Full Day"
                  />
                </div>
                <div className="space-y-1">
                  <Label className="text-xs text-muted-foreground">Duration (hours)</Label>
                  <Input 
                    type="number" 
                    min="0.5" 
                    step="0.5"
                    value={shiftRateDuration} 
                    onChange={(e) => setShiftRateDuration(e.target.value)} 
                    placeholder="e.g., 9"
                  />
                </div>
                <div className="space-y-1">
                  <Label className="text-xs text-muted-foreground">Rate (₹)</Label>
                  <Input 
                    type="number" 
                    min="0" 
                    step="0.01"
                    value={shiftRateAmount} 
                    onChange={(e) => setShiftRateAmount(e.target.value)} 
                    placeholder="e.g., 500"
                  />
                </div>
              </div>
              <div className="flex gap-2 mt-3">
                <Button 
                  onClick={() => saveShiftRateMutation.mutate()} 
                  disabled={!shiftRateName.trim() || !shiftRateDuration || !shiftRateAmount || saveShiftRateMutation.isPending}
                  size="sm"
                >
                  {saveShiftRateMutation.isPending && <Loader2 className="mr-2 h-4 w-4 animate-spin" />}
                  {editingShiftRate ? "Update" : "Add"} Rate
                </Button>
                {editingShiftRate && (
                  <Button variant="outline" size="sm" onClick={resetShiftRateForm}>Cancel Edit</Button>
                )}
              </div>
            </div>
          </div>
          <DialogFooter>
            <Button variant="outline" onClick={() => setShowShiftRatesDialog(false)}>Close</Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>
    </div>
  );
}

import { useEffect, useState } from "react";
import { useNavigate } from "react-router-dom";
import { supabase } from "@/integrations/supabase/client";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Textarea } from "@/components/ui/textarea";
import { toast } from "sonner";
import { Loader2, ArrowLeft, Smartphone, MapPin, Navigation } from "lucide-react";
import { generateDisplayId } from "@/lib/displayId";
import { useQuery } from "@tanstack/react-query";
import { getCurrentPosition, getOAuthRedirectUrl } from "@/lib/capacitorUtils";

type Step = "phone" | "otp" | "register" | "add-store" | "link-google";
type IdentityResolution =
  | { type: "staff"; role: string; staffId?: string | null }
  | { type: "existing_customer"; customerId: string; googleLinked: boolean }
  | { type: "new_customer_known_phone"; maskedPhone: string }
  | { type: "onboarding_required"; authUserId: string; loginMethod: "google" | "phone" };

const Logo = () => (
  <div className="mx-auto flex h-14 w-14 items-center justify-center rounded-2xl bg-primary text-primary-foreground font-bold text-xl mb-4">
    AP
  </div>
);

async function resolveUserIdentity(): Promise<IdentityResolution> {
  const {
    data: { session },
  } = await supabase.auth.getSession();
  const accessToken = session?.access_token;
  const { data, error } = await supabase.functions.invoke("resolve-user-identity", {
    headers: accessToken ? { Authorization: `Bearer ${accessToken}` } : undefined,
  });
  if (error) throw error;
  if (!data?.type) throw new Error("Invalid identity resolution response");
  return data as IdentityResolution;
}

async function hasStaffOrCustomerAccess(userId: string): Promise<boolean> {
  const [{ data: roleData }, { data: customerData }] = await Promise.all([
    supabase.from("user_roles").select("role").eq("user_id", userId).maybeSingle(),
    supabase.from("customers").select("id").eq("user_id", userId).maybeSingle(),
  ]);

  if (roleData?.role && roleData.role !== "customer") {
    return true;
  }

  return !!customerData;
}

const Auth = () => {
  const navigate = useNavigate();
  const [loading, setLoading] = useState(true);
  const [sessionChecked, setSessionChecked] = useState(false);
  const [step, setStep] = useState<Step>("phone");
  const [resendTimer, setResendTimer] = useState(0);

  // Phone / OTP
  const [phoneNumber, setPhoneNumber] = useState("");
  const [phoneCode, setPhoneCode] = useState("");
  const [verifiedPhone, setVerifiedPhone] = useState("");
  const [pendingCustomerEmail, setPendingCustomerEmail] = useState<string | null>(null);
  const [otpSessionToken, setOtpSessionToken] = useState<string | null>(null);

  // New-customer registration
  const [regName, setRegName] = useState("");
  const [newCustomerId, setNewCustomerId] = useState<string | null>(null);

  // Store creation (step: add-store)
  const [storeName, setStoreName] = useState("");
  const [storeAddress, setStoreAddress] = useState("");
  const [storeCity, setStoreCity] = useState("");
  const [storeLat, setStoreLat] = useState<number | null>(null);
  const [storeLng, setStoreLng] = useState<number | null>(null);
  const [fetchingLocation, setFetchingLocation] = useState(false);

  // App settings
  const { data: appSettings } = useQuery({
    queryKey: ["app-settings-auth"],
    queryFn: async () => {
      const { data } = await supabase.from("company_settings").select("key, value");
      const map: Record<string, string> = {};
      data?.forEach((s: any) => { map[s.key] = s.value || ""; });
      return map;
    },
  });

  const customerSignupEnabled = appSettings?.customer_signup_enabled !== "false";
  const googleLinkingEnabled = appSettings?.google_linking_enabled !== "false";

  useEffect(() => {
    const resolveExistingSession = async () => {
      const { data: { session } } = await supabase.auth.getSession();
      
      if (!session?.user) {
        setLoading(false);
        setSessionChecked(true);
        return;
      }
      
      setLoading(true); // Ensure it stays loading
      
      try {
        const identity = await resolveUserIdentity();
        if (identity.type === "staff") {
          toast.success("Logged in as staff");
          navigate("/", { replace: true });
          return;
        }
        if (identity.type === "existing_customer") {
          navigate("/", { replace: true });
          return;
        }
        if (identity.type === "new_customer_known_phone") {
          toast.error(`This phone already exists. Please login with phone ending in ${identity.maskedPhone}.`);
          await supabase.auth.signOut();
          navigate("/auth", { replace: true });
          return;
        }

        if (await hasStaffOrCustomerAccess(session.user.id)) {
          navigate("/", { replace: true });
          return;
        }

        setVerifiedPhone(session.user.phone || "");
        setStep("register");
      } catch (error) {
        console.error("Identity resolution failed", error);

        const { data: { user } } = await supabase.auth.getUser();
        if (user && await hasStaffOrCustomerAccess(user.id)) {
          navigate("/", { replace: true });
          return;
        }

        if (session.user?.phone) {
          setVerifiedPhone(session.user.phone);
        }
        setStep("register");
      } finally {
        setLoading(false);
        setSessionChecked(true);
      }
    };

    resolveExistingSession();
  }, [navigate]);

  useEffect(() => {
    if (resendTimer > 0) {
      const timer = setTimeout(() => setResendTimer(resendTimer - 1), 1000);
      return () => clearTimeout(timer);
    }
  }, [resendTimer]);

  // ── Handlers ──

  const handleSendOtp = async (e: React.FormEvent) => {
    e.preventDefault();
    if (phoneNumber.length !== 10) {
      toast.error("Please enter a valid 10-digit phone number");
      return;
    }
    setLoading(true);
    try {
      const fullPhone = `+91${phoneNumber}`;

      // Use OpenSMS instead of Firebase
      const { data, error } = await supabase.functions.invoke("send-otp-opensms", {
        body: { phone: fullPhone }
      });

      if (error) {
        throw new Error(error.message || "Failed to send OTP");
      }

      if (!data?.success || !data?.session_token) {
        throw new Error(data?.error || "Failed to send OTP");
      }

      setOtpSessionToken(data.session_token);
      setVerifiedPhone(data.phone || fullPhone.replace(/(\d{2})(\d+)(\d{4})/, '$1***$3'));
      setStep("otp");
      setResendTimer(30);
      toast.success(`OTP sent to ${data.phone || fullPhone.replace(/(\d{2})(\d+)(\d{4})/, '$1***$3')}`);

      // Show OTP in development mode
      if (data.otp_for_dev) {
        toast.info(`Development OTP: ${data.otp_for_dev}`, { duration: 10000 });
      }
    } catch (error) {
      toast.error(error instanceof Error ? error.message : "Unable to send OTP");
    } finally {
      setLoading(false);
    }
  };

  const handleVerifyOtp = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!otpSessionToken) {
      toast.error("OTP session expired. Please request a new OTP.");
      setStep("phone");
      return;
    }
    setLoading(true);
    try {
      const { data, error } = await supabase.functions.invoke("verify-otp-opensms", {
        body: {
          session_token: otpSessionToken,
          otp_code: phoneCode,
        },
      });

      if (error || !data?.access_token) {
        throw error || new Error(data?.error || "OTP verification failed");
      }

      // Set the session
      const { error: sessionError } = await supabase.auth.setSession({
        access_token: data.access_token,
        refresh_token: data.refresh_token,
      });
      if (sessionError) throw sessionError;

      // Resolve user identity
      const identity = await resolveUserIdentity();
      if (identity.type === "staff") {
        toast.success("Logged in successfully");
        navigate("/");
        return;
      }

      if (identity.type === "existing_customer") {
        if (!identity.googleLinked) {
          const { data: linkedCustomer } = await supabase
            .from("customers")
            .select("email")
            .eq("id", identity.customerId)
            .maybeSingle();
          setPendingCustomerEmail(linkedCustomer?.email || "");
          setStep("link-google");
          setLoading(false);
          return;
        }
        toast.success("Logged in successfully");
        navigate("/");
        return;
      }

      if (identity.type === "new_customer_known_phone") {
        toast.error(`Phone already exists. Please login with phone ending in ${identity.maskedPhone}.`);
        await supabase.auth.signOut();
        navigate("/auth", { replace: true });
        return;
      }

      const { data: { user } } = await supabase.auth.getUser();
      if (user && await hasStaffOrCustomerAccess(user.id)) {
        toast.success("Logged in successfully");
        navigate("/");
        return;
      }

      // Brand-new customer — check if signup is enabled
      if (!customerSignupEnabled) {
        toast.error("New customer registration is currently disabled. Please contact support.");
        await supabase.auth.signOut();
        navigate("/auth", { replace: true });
        return;
      }

      // Continue in detailed Auth onboarding (profile + location-rich store setup).
      setStep("register");
      toast.success("Phone verified! Complete your profile to continue.");
    } catch (error) {
      const errorMsg = error instanceof Error ? error.message : "OTP verification failed";
      toast.error(errorMsg);
    } finally {
      setLoading(false);
    }
  };

  const handleRegister = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!regName.trim()) {
      toast.error("Name is required");
      return;
    }
    setLoading(true);
    try {
      const { data: { user } } = await supabase.auth.getUser();
      if (!user) throw new Error("Not authenticated");

      const displayId = generateDisplayId("CUST");

      const { data: cust, error } = await supabase
        .from("customers")
        .insert({
          user_id: user.id,
          display_id: displayId,
          name: regName.trim(),
          phone: verifiedPhone || null,
        })
        .select("id")
        .single();

      if (error) throw error;

      // Mark onboarding complete so user doesn't see it again
      await supabase.from("profiles").upsert({
        user_id: user.id,
        full_name: regName.trim(),
        phone: verifiedPhone || null,
        onboarding_complete: true,
        phone_verified: true,
      }, { onConflict: "user_id" });

      // Ensure user_roles has customer role
      await supabase.from("user_roles").upsert({
        user_id: user.id,
        role: "customer",
      }, { onConflict: "user_id" });

      setNewCustomerId(cust.id);
      setStep("add-store");
    } catch (error: any) {
      // Handle stale session (FK constraint violation)
      if (error.message?.includes("foreign key constraint") || error.code === "23503") {
        toast.error("Session expired. Please login again.");
        await supabase.auth.signOut();
        navigate("/auth", { replace: true });
        return;
      }
      toast.error(error instanceof Error ? error.message : "Registration failed");
    } finally {
      setLoading(false);
    }
  };

  const fetchLocationFromCoords = async (lat: number, lng: number) => {
    try {
      const response = await fetch(
        `https://nominatim.openstreetmap.org/reverse?format=json&lat=${lat}&lon=${lng}&addressdetails=1`
      );
      const data = await response.json();
      if (data?.address) {
        const addr = data.address;
        const city = addr.city || addr.town || addr.village || addr.county || "";
        const area = addr.suburb || addr.neighbourhood || addr.road || "";
        const state = addr.state || "";
        const postcode = addr.postcode || "";
        
        setStoreCity(city);
        setStoreAddress(`${area}${area && city ? ", " : ""}${city}${state ? ", " + state : ""}${postcode ? " - " + postcode : ""}`);
      }
    } catch (err) {
      console.error("Reverse geocoding failed:", err);
    }
  };

  const handleGetLocation = async () => {
    setFetchingLocation(true);
    try {
      const position = await getCurrentPosition();
      if (position) {
        setStoreLat(position.lat);
        setStoreLng(position.lng);
        await fetchLocationFromCoords(position.lat, position.lng);
        toast.success("Location captured!");
      } else {
        toast.error("Could not get location. Please enable GPS.");
      }
    } catch (err) {
      toast.error("Location access denied");
    } finally {
      setFetchingLocation(false);
    }
  };

  const handleAddStore = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!storeName.trim()) {
      toast.error("Store name is required");
      return;
    }
    if (!storeAddress.trim()) {
      toast.error("Address is required. Please use 'Get Current Location' or enter manually.");
      return;
    }
    setLoading(true);
    try {
      // Get default store type from settings
      let defaultStoreTypeId = appSettings?.default_store_type_id;
      
      if (!defaultStoreTypeId) {
        const { data: firstStoreType } = await supabase.from('store_types').select('id').limit(1).single();
        defaultStoreTypeId = firstStoreType?.id;
      }
      
      if (!defaultStoreTypeId) {
         throw new Error("System error: No store types configured. Cannot create store.");
      }
      
      const displayId = generateDisplayId("STR");
      const { error } = await supabase.from("stores").insert({
        customer_id: newCustomerId,
        store_type_id: defaultStoreTypeId,
        display_id: displayId,
        name: storeName.trim(),
        address: storeAddress.trim(),
        city: storeCity.trim() || null,
        lat: storeLat,
        lng: storeLng,
        phone: verifiedPhone || null,
      });
      if (error) throw error;
      toast.success("Account set up successfully! Welcome.");
      
      const { data: { user } } = await supabase.auth.getUser();
      const providers = (user?.app_metadata?.providers || []) as string[];
      if (googleLinkingEnabled && !providers.includes("google")) {
        setStep("link-google");
      } else {
        window.location.assign("/");
      }
    } catch (error) {
      toast.error(error instanceof Error ? error.message : "Could not create store");
    } finally {
      setLoading(false);
    }
  };

  if (loading || !sessionChecked) {
    return (
      <div className="flex min-h-screen items-center justify-center bg-background">
        <div className="text-center space-y-4">
          <Logo />
          <div className="flex flex-col items-center gap-3">
            <Loader2 className="h-8 w-8 animate-spin text-primary mx-auto" />
            <p className="text-sm font-medium animate-pulse">Buffering...</p>
          </div>
        </div>
      </div>
    );
  }

  // ── REGISTER STEP ──
  if (step === "register") {
    return (
      <div className="flex min-h-screen items-center justify-center bg-background p-4">
        <div className="w-full max-w-md space-y-6">
          <div className="text-center">
            <Logo />
            <h1 className="text-2xl font-bold tracking-tight">Create Your Account</h1>
            <p className="text-sm text-muted-foreground mt-1">Phone verified: {verifiedPhone}</p>
          </div>
          <div className="rounded-xl border bg-card p-6 shadow-sm">
            <form onSubmit={handleRegister} className="space-y-4">
              <div>
                <Label htmlFor="reg-name">Full Name <span className="text-destructive">*</span></Label>
                <Input id="reg-name" placeholder="Your full name" value={regName}
                  onChange={(e) => setRegName(e.target.value)} className="mt-1" required />
              </div>
              <Button type="submit" className="w-full" disabled={loading}>
                {loading && <Loader2 className="mr-2 h-4 w-4 animate-spin" />}
                Continue
              </Button>
            </form>
          </div>
        </div>
      </div>
    );
  }

  if (step === "link-google") {
    return (
      <div className="flex min-h-screen items-center justify-center bg-background p-4">
        <div className="w-full max-w-md space-y-6">
          <div className="text-center">
            <Logo />
            <h1 className="text-2xl font-bold tracking-tight">Link Google Account</h1>
            <p className="text-sm text-muted-foreground mt-1">
              Connect your Google account for easier login next time
            </p>
          </div>
          <div className="rounded-xl border bg-card p-6 shadow-sm space-y-3">
            <Button
              className="w-full flex items-center justify-center gap-2"
              onClick={async () => {
                const { error } = await supabase.auth.linkIdentity({
                  provider: "google",
                  options: { redirectTo: getOAuthRedirectUrl("/auth") },
                });
                if (error) {
                  if (error.message?.toLowerCase().includes("manual linking")) {
                    toast.error("Google linking is not configured. Please contact support or skip for now.");
                  } else {
                    toast.error(error.message || "Could not link Google account");
                  }
                }
              }}
            >
              <svg className="h-5 w-5" viewBox="0 0 24 24">
                <path fill="#4285F4" d="M22.56 12.25c0-.78-.07-1.53-.2-2.25H12v4.26h5.92c-.26 1.37-1.04 2.53-2.21 3.31v2.77h3.57c2.08-1.92 3.28-4.74 3.28-8.09z"/>
                <path fill="#34A853" d="M12 23c2.97 0 5.46-.98 7.28-2.66l-3.57-2.77c-.98.66-2.23 1.06-3.71 1.06-2.86 0-5.29-1.93-6.16-4.53H2.18v2.84C3.99 20.53 7.7 23 12 23z"/>
                <path fill="#FBBC05" d="M5.84 14.09c-.22-.66-.35-1.36-.35-2.09s.13-1.43.35-2.09V7.07H2.18C1.43 8.55 1 10.22 1 12s.43 3.45 1.18 4.93l2.85-2.22.81-.62z"/>
                <path fill="#EA4335" d="M12 5.38c1.62 0 3.06.56 4.21 1.64l3.15-3.15C17.45 2.09 14.97 1 12 1 7.7 1 3.99 3.47 2.18 7.07l3.66 2.84c.87-2.6 3.3-4.53 6.16-4.53z"/>
              </svg>
              Link Google Account
            </Button>
            <Button variant="ghost" className="w-full" onClick={() => window.location.assign("/")}>Skip for now</Button>
          </div>
        </div>
      </div>
    );
  }

  // ── ADD STORE STEP ──
  if (step === "add-store") {
    return (
      <div className="flex min-h-screen items-center justify-center bg-background p-4">
        <div className="w-full max-w-md space-y-6">
          <div className="text-center">
            <Logo />
            <h1 className="text-2xl font-bold tracking-tight">Add Your Store</h1>
            <p className="text-sm text-muted-foreground mt-1">Tell us about your business location</p>
          </div>
          <div className="rounded-xl border bg-card p-6 shadow-sm">
            <form onSubmit={handleAddStore} className="space-y-4">
              <div>
                <Label htmlFor="store-name">Store Name <span className="text-destructive">*</span></Label>
                <Input id="store-name" placeholder="e.g. My Shop" value={storeName}
                  onChange={(e) => setStoreName(e.target.value)} className="mt-1" required />
              </div>
              
              {/* Location Picker */}
              <div className="space-y-2">
                <Label>Store Location <span className="text-destructive">*</span></Label>
                <Button
                  type="button"
                  variant="outline"
                  className="w-full gap-2"
                  onClick={handleGetLocation}
                  disabled={fetchingLocation}
                >
                  {fetchingLocation ? (
                    <Loader2 className="h-4 w-4 animate-spin" />
                  ) : (
                    <Navigation className="h-4 w-4" />
                  )}
                  {storeLat ? "Update Location" : "Get Current Location"}
                </Button>
                {storeLat && storeLng && (
                  <div className="flex items-center gap-2 text-xs text-green-600 bg-green-50 p-2 rounded">
                    <MapPin className="h-3 w-3" />
                    Location captured ({storeLat.toFixed(4)}, {storeLng.toFixed(4)})
                  </div>
                )}
              </div>

              <div>
                <Label htmlFor="store-address">
                  Address <span className="text-destructive">*</span>
                </Label>
                <Textarea 
                  id="store-address" 
                  placeholder="Full store address (auto-filled from location or enter manually)" 
                  value={storeAddress}
                  onChange={(e) => setStoreAddress(e.target.value)} 
                  className="mt-1 min-h-[80px]" 
                  required 
                />
                <p className="text-xs text-muted-foreground mt-1">
                  Use "Get Current Location" button above or enter address manually
                </p>
              </div>

              <Button type="submit" className="w-full" disabled={loading || !storeName.trim() || !storeAddress.trim()}>
                {loading && <Loader2 className="mr-2 h-4 w-4 animate-spin" />}
                Create Store & Finish
              </Button>
            </form>
          </div>
        </div>
      </div>
    );
  }

  // Removed duplicate loading block

  return (
    <div className="flex min-h-screen items-center justify-center bg-background p-4">
      <div className="w-full max-w-md space-y-4">
        <div className="text-center">
          <Logo />
          <h1 className="text-2xl font-bold tracking-tight">Aqua Prime</h1>
          <p className="text-sm text-muted-foreground mt-1">
            {step === "otp" ? `Code sent to ${verifiedPhone}` : "Login or sign up with your phone"}
          </p>
        </div>

        <div className="rounded-xl border bg-card p-6 shadow-sm space-y-4">
          {/* Google OAuth — for returning users who have linked Google */}
          <Button
            variant="outline"
            className="w-full"
            disabled={loading}
            onClick={async () => {
              setLoading(true);
              const { error} = await supabase.auth.signInWithOAuth({
                provider: "google",
                options: { redirectTo: getOAuthRedirectUrl("/auth") },
              });
              if (error) {
                toast.error(error.message || "Google sign-in failed");
                setLoading(false);
              }
            }}
          >
            <svg className="mr-2 h-4 w-4" viewBox="0 0 24 24">
              <path d="M22.56 12.25c0-.78-.07-1.53-.2-2.25H12v4.26h5.92a5.06 5.06 0 0 1-2.2 3.32v2.77h3.57c2.08-1.92 3.27-4.74 3.27-8.1z" fill="#4285F4"/>
              <path d="M12 23c2.97 0 5.46-.98 7.28-2.66l-3.57-2.77c-.98.66-2.23 1.06-3.71 1.06-2.86 0-5.29-1.93-6.16-4.53H2.18v2.84C3.99 20.53 7.7 23 12 23z" fill="#34A853"/>
              <path d="M5.84 14.09c-.22-.66-.35-1.36-.35-2.09s.13-1.43.35-2.09V7.07H2.18C1.43 8.55 1 10.22 1 12s.43 3.45 1.18 4.93l2.85-2.22.81-.62z" fill="#FBBC05"/>
              <path d="M12 5.38c1.62 0 3.06.56 4.21 1.64l3.15-3.15C17.45 2.09 14.97 1 12 1 7.7 1 3.99 3.47 2.18 7.07l3.66 2.84c.87-2.6 3.3-4.53 6.16-4.53z" fill="#EA4335"/>
            </svg>
            Continue with Google
          </Button>

          <div className="relative">
            <div className="absolute inset-0 flex items-center"><span className="w-full border-t" /></div>
            <div className="relative flex justify-center text-xs uppercase">
              <span className="bg-card px-2 text-muted-foreground">or use phone OTP</span>
            </div>
          </div>

          {/* Phone number entry */}
          {step === "phone" && (
            <form onSubmit={handleSendOtp} className="space-y-4">
              <div>
                <Label htmlFor="phone-number">Phone Number</Label>
                <div className="relative mt-1">
                  <div className="absolute left-3 top-1/2 -translate-y-1/2 flex items-center gap-1.5 border-r pr-2 py-1 border-input/40 z-10">
                    <Smartphone className="h-4 w-4 text-muted-foreground" />
                    <span className="text-sm font-medium text-foreground">+91</span>
                  </div>
                  <Input
                    id="phone-number"
                    type="tel"
                    inputMode="numeric"
                    placeholder="9876543210"
                    value={phoneNumber}
                    onChange={(e) => {
                      const val = e.target.value.replace(/\D/g, "");
                      if (val.length <= 10) setPhoneNumber(val);
                    }}
                    className="pl-20"
                    required
                    maxLength={10}
                  />
                </div>
                <p className="mt-1 text-xs text-muted-foreground">Enter your 10-digit mobile number</p>
              </div>
              <Button type="submit" className="w-full" disabled={loading}>
                {loading && <Loader2 className="mr-2 h-4 w-4 animate-spin" />}
                Send OTP
              </Button>
            </form>
          )}

          {/* OTP entry */}
          {step === "otp" && (
            <form onSubmit={handleVerifyOtp} className="space-y-4">
              <div>
                <Label htmlFor="phone-otp">Verification Code</Label>
                <Input
                  id="phone-otp"
                  inputMode="numeric"
                  placeholder="• • • • • •"
                  value={phoneCode}
                  onChange={(e) => setPhoneCode(e.target.value)}
                  className="mt-1 text-center text-xl tracking-widest"
                  maxLength={6}
                  required
                />
              </div>
              <div className="flex flex-col gap-2">
                <Button type="submit" className="w-full" disabled={loading}>
                  {loading && <Loader2 className="mr-2 h-4 w-4 animate-spin" />}
                  Verify & Login
                </Button>
                <Button
                  type="button"
                  variant="outline"
                  className="w-full"
                  disabled={resendTimer > 0 || loading}
                  onClick={handleSendOtp}
                >
                  {resendTimer > 0 ? `Resend OTP in ${resendTimer}s` : "Resend OTP"}
                </Button>
              </div>
              <Button
                type="button"
                variant="ghost"
                className="w-full"
                onClick={() => { setStep("phone"); setPhoneCode(""); setVerifiedPhone(""); }}
              >
                <ArrowLeft className="mr-2 h-4 w-4" /> Use different number
              </Button>
            </form>
          )}
        </div>
      </div>
    </div>
  );
};

export default Auth;

import { PageHeader } from "@/components/shared/PageHeader";
import { DataTable } from "@/components/shared/DataTable";
import { StatusBadge } from "@/components/shared/StatusBadge";
import { Badge } from "@/components/ui/badge";
import { useQuery, useQueryClient } from "@tanstack/react-query";
import { supabase } from "@/integrations/supabase/client";
import { useAuth } from "@/contexts/AuthContext";
import { logActivity } from "@/lib/activityLogger";
import { Loader2, Plus, Trash2, Pencil, Link as LinkIcon } from "lucide-react";
import { useState } from "react";
import {
  Dialog, DialogContent, DialogHeader, DialogTitle, DialogFooter,
} from "@/components/ui/dialog";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Button } from "@/components/ui/button";
import { Textarea } from "@/components/ui/textarea";
import { Switch } from "@/components/ui/switch";
import { Checkbox } from "@/components/ui/checkbox";
import { toast } from "sonner";
import { ImageUpload } from "@/components/shared/ImageUpload";
import { BannerImageEditor } from "@/components/banners/BannerImageEditor";

interface CropState {
  scale: number;
  offsetX: number;
  offsetY: number;
}

const Banners = () => {
  const { user, role } = useAuth();
  const qc = useQueryClient();
  const canEdit = ["super_admin", "manager"].includes(role || "");

  const [showAdd, setShowAdd] = useState(false);
  const [editingBanner, setEditingBanner] = useState<any>(null);
  const [saving, setSaving] = useState(false);

  // Form State
  const [title, setTitle] = useState("");
  const [description, setDescription] = useState("");
  const [imageUrl, setImageUrl] = useState("");
  const [linkUrl, setLinkUrl] = useState("");
  const [selectedStoreTypeIds, setSelectedStoreTypeIds] = useState<string[]>([]);
  const [isActive, setIsActive] = useState(true);
  const [sortOrder, setSortOrder] = useState("0");
  const [cropData, setCropData] = useState<CropState | null>(null);

  const resetForm = () => {
    setTitle("");
    setDescription("");
    setImageUrl("");
    setLinkUrl("");
    setSelectedStoreTypeIds([]);
    setIsActive(true);
    setSortOrder("0");
    setCropData(null);
    setEditingBanner(null);
  };

  const handleEdit = async (banner: any) => {
    setEditingBanner(banner);
    setTitle(banner.title);
    setDescription(banner.description || "");
    setImageUrl(banner.image_url || "");
    setLinkUrl(banner.link_url || "");
    setIsActive(banner.is_active);
    setSortOrder(String(banner.sort_order || 0));
    setCropData(banner.crop_data || null);

    // Load store type associations
    const { data: associations } = await supabase
      .from("banner_store_types" as any)
      .select("store_type_id")
      .eq("banner_id", banner.id);

    if (associations && associations.length > 0) {
      setSelectedStoreTypeIds(associations.map((a: any) => a.store_type_id));
    } else if (banner.store_type_id) {
      // Fallback to legacy single store_type_id
      setSelectedStoreTypeIds([banner.store_type_id]);
    } else {
      setSelectedStoreTypeIds([]);
    }

    setShowAdd(true);
  };

  const { data: storeTypes } = useQuery({
    queryKey: ["store-types-simple"],
    queryFn: async () => {
      const { data } = await supabase.from("store_types").select("id, name").eq("is_active", true).order("name");
      return data || [];
    },
  });

  const { data: banners, isLoading } = useQuery({
    queryKey: ["promotional-banners"],
    queryFn: async () => {
      const { data } = await supabase
        .from("promotional_banners")
        .select(`*, store_types(name)`)
        .order("sort_order", { ascending: true })
        .order("created_at", { ascending: false });

      // Also load banner_store_types for display
      if (data) {
        const bannerIds = data.map((b: any) => b.id);
        const { data: associations } = await supabase
          .from("banner_store_types" as any)
          .select("banner_id, store_type_id")
          .in("banner_id", bannerIds);

        // Attach store type IDs to each banner
        return data.map((b: any) => ({
          ...b,
          _storeTypeIds: (associations || [])
            .filter((a: any) => a.banner_id === b.id)
            .map((a: any) => a.store_type_id),
        }));
      }
      return data || [];
    },
  });

  const toggleStoreType = (storeTypeId: string) => {
    setSelectedStoreTypeIds((prev) =>
      prev.includes(storeTypeId)
        ? prev.filter((id) => id !== storeTypeId)
        : [...prev, storeTypeId]
    );
  };

  const handleSave = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!title) {
      toast.error("Title is required");
      return;
    }
    setSaving(true);

    try {
      const basePayload = {
        title,
        description: description || null,
        image_url: imageUrl || "https://placehold.co/600x200?text=No+Image",
        link_url: linkUrl || null,
        store_type_id: selectedStoreTypeIds.length === 1 ? selectedStoreTypeIds[0] : null,
        is_active: isActive,
        sort_order: parseInt(sortOrder) || 0,
        crop_data: cropData,
      };

      let bannerId: string;

      if (editingBanner) {
        const { error } = await supabase
          .from("promotional_banners")
          .update(basePayload)
          .eq("id", editingBanner.id);
        if (error) throw error;
        bannerId = editingBanner.id;
        toast.success("Banner updated");
      } else {
        const { data: inserted, error } = await supabase
          .from("promotional_banners")
          .insert({ ...basePayload, created_by: user?.id })
          .select("id")
          .single();
        if (error) throw error;
        bannerId = inserted.id;
        toast.success("Banner created");
      }

      // Sync banner_store_types junction table
      // Delete existing associations
      await supabase
        .from("banner_store_types" as any)
        .delete()
        .eq("banner_id", bannerId);

      // Insert new associations
      if (selectedStoreTypeIds.length > 0) {
        const rows = selectedStoreTypeIds.map((stId) => ({
          banner_id: bannerId,
          store_type_id: stId,
        }));
        await supabase.from("banner_store_types" as any).insert(rows);
      }

      setShowAdd(false);
      resetForm();
      qc.invalidateQueries({ queryKey: ["promotional-banners"] });
      logActivity(user!.id, `${editingBanner ? "Updated" : "Created"} banner: ${title}`, "banner", title, editingBanner?.id || bannerId);
    } catch (err: any) {
      toast.error(err.message);
    } finally {
      setSaving(false);
    }
  };

  const handleDelete = async (id: string) => {
    if (!confirm("Are you sure you want to delete this banner?")) return;

    const { error } = await supabase.from("promotional_banners").delete().eq("id", id);
    if (error) {
      toast.error(error.message);
    } else {
      toast.success("Banner deleted");
      qc.invalidateQueries({ queryKey: ["promotional-banners"] });
    }
  };

  const getStoreTypeNames = (banner: any) => {
    const ids: string[] = banner._storeTypeIds || [];
    if (ids.length === 0) return "All Customers";
    return ids
      .map((id: string) => storeTypes?.find((t: any) => t.id === id)?.name || "Unknown")
      .join(", ");
  };

  const columns = [
    {
      header: "Image",
      accessor: (row: any) => (
        <div
          className="h-12 w-24 overflow-hidden rounded bg-slate-100 relative"
          style={{ aspectRatio: "3" }}
        >
          {row.image_url && (
            <img
              src={row.image_url}
              alt={row.title}
              loading="lazy"
              className="absolute inset-0 w-full h-full"
              style={{
                objectFit: "cover",
                transform: row.crop_data
                  ? `translate(${row.crop_data.offsetX * 0.5}px, ${row.crop_data.offsetY * 0.5}px) scale(${row.crop_data.scale})`
                  : undefined,
                transformOrigin: "center center",
              }}
            />
          )}
        </div>
      ),
    },
    { header: "Title", accessor: "title", className: "font-medium" },
    {
      header: "Target",
      accessor: (row: any) => {
        const names = getStoreTypeNames(row);
        if (names === "All Customers") {
          return <Badge variant="outline">All Customers</Badge>;
        }
        const ids: string[] = row._storeTypeIds || [];
        return (
          <div className="flex flex-wrap gap-1">
            {ids.map((id: string) => (
              <Badge key={id} variant="secondary" className="text-[10px]">
                {storeTypes?.find((t: any) => t.id === id)?.name || "Unknown"}
              </Badge>
            ))}
          </div>
        );
      },
    },
    { header: "Order", accessor: "sort_order" },
    { header: "Status", accessor: (row: any) => <StatusBadge status={row.is_active ? "active" : "inactive"} /> },
    {
      header: "Action",
      accessor: (row: any) =>
        canEdit && (
          <div className="flex items-center gap-2">
            <Button variant="ghost" size="icon" onClick={() => handleEdit(row)}>
              <Pencil className="h-4 w-4 text-muted-foreground" />
            </Button>
            <Button variant="ghost" size="icon" onClick={() => handleDelete(row.id)}>
              <Trash2 className="h-4 w-4 text-red-500" />
            </Button>
          </div>
        ),
    },
  ];

  return (
    <div className="space-y-6 animate-fade-in">
      <div className="flex flex-col sm:flex-row sm:items-center sm:justify-between gap-4">
        <PageHeader title="Promotional Banners" subtitle="Manage banners visible on customer portal" />
        {canEdit && (
          <Button onClick={() => { resetForm(); setShowAdd(true); }}>
            <Plus className="mr-2 h-4 w-4" /> Add Banner
          </Button>
        )}
      </div>

      {isLoading ? (
        <div className="flex justify-center py-10"><Loader2 className="animate-spin" /></div>
      ) : (
        <DataTable
          data={banners || []}
          columns={columns}
          searchKey="title"
        />
      )}

      <Dialog open={showAdd} onOpenChange={(open) => { if (!open) resetForm(); setShowAdd(open); }}>
        <DialogContent className="sm:max-w-[700px] max-h-[90vh] overflow-y-auto">
          <DialogHeader>
            <DialogTitle>{editingBanner ? "Edit Banner" : "Create New Banner"}</DialogTitle>
          </DialogHeader>
          <form onSubmit={handleSave} className="space-y-4">
            <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
              {/* Banner Image Upload */}
              <div className="space-y-2 sm:col-span-2">
                <Label>Banner Image</Label>
                <div className="flex justify-center rounded-lg border border-dashed p-4">
                  <ImageUpload
                    folder="banners"
                    currentUrl={imageUrl}
                    onUploaded={setImageUrl}
                    onRemoved={() => { setImageUrl(""); setCropData(null); }}
                  />
                </div>
              </div>

              {/* Image Editor - Zoom/Pan */}
              {imageUrl && (
                <div className="space-y-2 sm:col-span-2">
                  <Label>Adjust Display — Zoom & Pan</Label>
                  <BannerImageEditor
                    imageUrl={imageUrl}
                    cropData={cropData}
                    onCropChange={setCropData}
                    aspectRatio={3}
                  />
                </div>
              )}

              <div className="space-y-2 sm:col-span-2">
                <Label>Title</Label>
                <Input value={title} onChange={(e) => setTitle(e.target.value)} required placeholder="e.g. Summer Sale" />
              </div>

              <div className="space-y-2 sm:col-span-2">
                <Label>Description (Optional)</Label>
                <Textarea value={description} onChange={(e) => setDescription(e.target.value)} rows={2} />
              </div>

              {/* Multi-Store Type Selection */}
              <div className="space-y-2 sm:col-span-2">
                <Label>Target Store Types</Label>
                <p className="text-xs text-muted-foreground mb-2">
                  Select one or more store types. Leave all unchecked to show to all customers.
                </p>
                <div className="grid grid-cols-2 sm:grid-cols-3 gap-2">
                  {storeTypes?.map((t: any) => (
                    <label
                      key={t.id}
                      className={`flex items-center gap-2 rounded-lg border p-2.5 cursor-pointer transition-colors ${
                        selectedStoreTypeIds.includes(t.id)
                          ? "border-primary bg-primary/5"
                          : "border-border hover:bg-accent/50"
                      }`}
                    >
                      <Checkbox
                        checked={selectedStoreTypeIds.includes(t.id)}
                        onCheckedChange={() => toggleStoreType(t.id)}
                      />
                      <span className="text-sm">{t.name}</span>
                    </label>
                  ))}
                </div>
                {selectedStoreTypeIds.length === 0 && (
                  <p className="text-xs text-blue-600 mt-1">
                    No store types selected — banner will be visible to all customers.
                  </p>
                )}
              </div>

              <div className="space-y-2">
                <Label>Sort Order</Label>
                <Input type="number" value={sortOrder} onChange={(e) => setSortOrder(e.target.value)} />
              </div>

              <div className="space-y-2">
                <Label>External Link (Optional)</Label>
                <div className="flex items-center gap-2">
                  <LinkIcon className="h-4 w-4 text-muted-foreground shrink-0" />
                  <Input value={linkUrl} onChange={(e) => setLinkUrl(e.target.value)} placeholder="https://..." />
                </div>
              </div>

              <div className="space-y-2 flex items-center justify-between sm:col-span-2 rounded-lg border p-3">
                <div className="block space-y-0.5">
                  <Label className="text-base">Active Status</Label>
                  <p className="text-xs text-muted-foreground">Visible to customers when enabled</p>
                </div>
                <Switch checked={isActive} onCheckedChange={setIsActive} />
              </div>
            </div>
            <DialogFooter>
              <Button type="button" variant="outline" onClick={() => setShowAdd(false)}>Cancel</Button>
              <Button type="submit" disabled={saving}>
                {saving && <Loader2 className="mr-2 h-4 w-4 animate-spin" />}
                Save Banner
              </Button>
            </DialogFooter>
          </form>
        </DialogContent>
      </Dialog>
    </div>
  );
};

export default Banners;

import { useParams, useNavigate } from "react-router-dom";
import { useQuery, useQueryClient } from "@tanstack/react-query";
import { supabase } from "@/integrations/supabase/client";
import { DataTable } from "@/components/shared/DataTable";
import { StatusBadge } from "@/components/shared/StatusBadge";
import { Card, CardContent } from "@/components/ui/card";
import { Separator } from "@/components/ui/separator";
import { Switch } from "@/components/ui/switch";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Textarea } from "@/components/ui/textarea";
import { Badge } from "@/components/ui/badge";
import {
  Loader2, ArrowLeft, Store, User, Pencil, X, Save, AlertTriangle,
  Shield, CheckCircle2, XCircle, ExternalLink, Upload, Camera, Receipt, FileText,
} from "lucide-react";
import { Button } from "@/components/ui/button";
import { useState, useRef } from "react";
import { toast } from "sonner";
import { useAuth } from "@/contexts/AuthContext";
import { logActivity } from "@/lib/activityLogger";
import { ImageUpload } from "@/components/shared/ImageUpload";
import { CustomerStatement } from "@/components/reports/CustomerStatement";

const CustomerDetail = () => {
  const { id } = useParams<{ id: string }>();
  const navigate = useNavigate();
  const qc = useQueryClient();
  const { user, role } = useAuth();
  const canEdit = role === "super_admin" || role === "manager";
  const isCustomer = role === "customer";

  const [editing, setEditing] = useState(false);
  const [saving, setSaving] = useState(false);
  const [toggling, setToggling] = useState(false);
  const [rejectionReason, setRejectionReason] = useState("");
  const [kycSaving, setKycSaving] = useState(false);
  const [uploadingKyc, setUploadingKyc] = useState(false);
  const [showStatement, setShowStatement] = useState(false);
  const [form, setForm] = useState({
    name: "",
    phone: "",
    email: "",
    address: "",
    gst_number: "",
  });
  const [photoUrl, setPhotoUrl] = useState<string | null>(null);

  const { data: customer, isLoading } = useQuery({
    queryKey: ["customer", id],
    queryFn: async () => {
      const { data, error } = await supabase
        .from("customers")
        .select("*")
        .eq("id", id!)
        .maybeSingle();
      if (error) throw error;
      return data;
    },
    enabled: !!id,
  });

  const { data: stores } = useQuery({
    queryKey: ["customer-stores", id],
    queryFn: async () => {
      const { data } = await supabase
        .from("stores")
        .select("*, store_types(name), routes(name)")
        .eq("customer_id", id!)
        .order("created_at", { ascending: false });
      return data || [];
    },
    enabled: !!id,
  });

  const { data: customerTxns } = useQuery({
    queryKey: ["customer-transactions", id],
    queryFn: async () => {
      const { data } = await supabase
        .from("transactions")
        .select("id, display_id, total_amount, cash_amount, upi_amount, created_at, stores(name)")
        .eq("customer_id", id!)
        .order("created_at", { ascending: false })
        .limit(50);
      return data || [];
    },
    enabled: !!id,
  });

  const invalidateAll = () => {
    qc.invalidateQueries({ queryKey: ["customer", id] });
    qc.invalidateQueries({ queryKey: ["customers"] });
  };

  const startEditing = () => {
    if (!customer || !customer.is_active) return;
    setForm({
      name: customer.name || "",
      phone: customer.phone || "",
      email: customer.email || "",
      address: customer.address || "",
      gst_number: customer.gst_number || "",
    });
    setPhotoUrl(customer.photo_url || null);
    setEditing(true);
  };

  const handleSave = async () => {
    if (!id) return;
    setSaving(true);
    const { error } = await supabase
      .from("customers")
      .update({
        name: form.name,
        phone: form.phone || null,
        email: form.email || null,
        address: form.address || null,
        gst_number: form.gst_number || null,
        photo_url: photoUrl || null,
      })
      .eq("id", id);
    setSaving(false);
    if (error) { toast.error(error.message); return; }
    toast.success("Customer updated");
    setEditing(false);
    invalidateAll();
  };

  const handleToggleActive = async () => {
    if (!customer || !id) return;
    const newVal = !customer.is_active;
    setToggling(true);
    const { error } = await supabase.from("customers").update({ is_active: newVal }).eq("id", id);
    if (error) { toast.error(error.message); setToggling(false); return; }

    if (!newVal && stores && stores.length > 0) {
      const storeIds = stores.map((s) => s.id);
      const { error: storeError } = await supabase.from("stores").update({ is_active: false }).in("id", storeIds);
      if (storeError) toast.error("Customer deactivated but failed to deactivate stores");
      else toast.success(`Customer deactivated along with ${storeIds.length} store(s)`);
    } else {
      toast.success(`Customer ${newVal ? "activated" : "deactivated"}`);
    }

    setToggling(false);
    setEditing(false);
    invalidateAll();
    qc.invalidateQueries({ queryKey: ["customer-stores", id] });
    qc.invalidateQueries({ queryKey: ["stores"] });
  };

  // KYC actions
  const handleKycApprove = async () => {
    if (!customer || !user) return;
    setKycSaving(true);
    const { error } = await supabase.from("customers").update({
      kyc_status: "verified",
      kyc_verified_at: new Date().toISOString(),
      kyc_verified_by: user.id,
      kyc_rejection_reason: null,
    }).eq("id", customer.id);
    setKycSaving(false);
    if (error) toast.error(error.message);
    else {
      toast.success("KYC approved");
      logActivity(user.id, "Approved KYC", "customer", customer.name, customer.id);
      invalidateAll();
    }
  };

  const handleKycReject = async () => {
    if (!customer || !user) return;
    if (!rejectionReason.trim()) { toast.error("Please provide a rejection reason"); return; }
    setKycSaving(true);
    const { error } = await supabase.from("customers").update({
      kyc_status: "rejected",
      kyc_rejection_reason: rejectionReason,
      kyc_verified_by: user.id,
    }).eq("id", customer.id);
    setKycSaving(false);
    if (error) toast.error(error.message);
    else {
      toast.success("KYC rejected");
      logActivity(user.id, "Rejected KYC", "customer", customer.name, customer.id);
      setRejectionReason("");
      invalidateAll();
    }
  };

  const uploadKycFile = async (file: File, field: "kyc_selfie_url" | "kyc_aadhar_front_url" | "kyc_aadhar_back_url") => {
    if (!customer) return;
    setUploadingKyc(true);
    const ext = file.name.split(".").pop();
    const path = `${customer.id}/${field}-${Date.now()}.${ext}`;
    const { error: uploadError } = await supabase.storage.from("kyc-documents").upload(path, file, { upsert: true });
    if (uploadError) { toast.error("Upload failed: " + uploadError.message); setUploadingKyc(false); return; }

    const updateData: any = { [field]: path };
    // If all three docs will be present after this upload, set status to pending
    const currentDocs = {
      kyc_selfie_url: customer.kyc_selfie_url,
      kyc_aadhar_front_url: customer.kyc_aadhar_front_url,
      kyc_aadhar_back_url: customer.kyc_aadhar_back_url,
      [field]: path,
    };
    if (currentDocs.kyc_selfie_url && currentDocs.kyc_aadhar_front_url && currentDocs.kyc_aadhar_back_url) {
      updateData.kyc_status = "pending";
      updateData.kyc_submitted_at = new Date().toISOString();
    }

    const { error } = await supabase.from("customers").update(updateData).eq("id", customer.id);
    setUploadingKyc(false);
    if (error) toast.error(error.message);
    else { toast.success("Document uploaded"); invalidateAll(); }
  };

  if (isLoading) {
    return <div className="flex items-center justify-center py-20"><Loader2 className="h-8 w-8 animate-spin text-primary" /></div>;
  }
  if (!customer) {
    return <div className="text-center py-20 text-muted-foreground">Customer not found</div>;
  }

  const isInactive = !customer.is_active;
  const totalOutstanding = stores?.reduce((s, r) => s + Number(r.outstanding), 0) || 0;

  const storeColumns = [
    { header: "ID", accessor: "display_id" as const, className: "font-mono text-xs", hideOnMobile: true },
    { header: "Name", accessor: "name" as const, className: "font-medium" },
    { header: "Type", accessor: (row: any) => row.store_types?.name || "—", className: "hidden sm:table-cell" },
    { header: "Route", accessor: (row: any) => row.routes?.name || "—", className: "hidden md:table-cell" },
    { header: "Outstanding", accessor: (row: any) => `₹${Number(row.outstanding).toLocaleString()}`, className: "font-semibold" },
    { header: "Status", accessor: (row: any) => <StatusBadge status={row.is_active ? "active" : "inactive"} /> },
  ];

  const kycStatus = customer.kyc_status || "not_requested";
  const kycLabel = kycStatus.replace("_", " ");

  const getDocUrl = (path: string | null) => {
    if (!path) return null;
    const { data } = supabase.storage.from("kyc-documents").getPublicUrl(path);
    return data.publicUrl;
  };

  const kycDocs = [
    { label: "Selfie", field: "kyc_selfie_url" as const, url: customer.kyc_selfie_url },
    { label: "Aadhar Front", field: "kyc_aadhar_front_url" as const, url: customer.kyc_aadhar_front_url },
    { label: "Aadhar Back", field: "kyc_aadhar_back_url" as const, url: customer.kyc_aadhar_back_url },
  ];

  return (
    <div className="space-y-6 animate-fade-in">
      <Button variant="ghost" size="sm" onClick={() => navigate("/customers")} className="gap-1.5 text-muted-foreground hover:text-foreground -ml-2">
        <ArrowLeft className="h-4 w-4" /> Customers
      </Button>

      {isInactive && (
        <div className="flex items-center gap-3 rounded-xl border border-destructive/30 bg-destructive/5 p-4">
          <AlertTriangle className="h-5 w-5 text-destructive shrink-0" />
          <div>
            <p className="text-sm font-medium text-destructive">This customer is inactive</p>
            <p className="text-xs text-muted-foreground mt-0.5">Activate the customer to resume operations.</p>
          </div>
        </div>
      )}

      {/* Profile Card */}
      <Card className={`overflow-hidden ${isInactive ? "opacity-75" : ""}`}>
        <div className="h-16 sm:h-20 bg-gradient-to-r from-primary/20 via-accent/30 to-primary/10" />
        <CardContent className="relative px-4 sm:px-6 pb-5 -mt-8 sm:-mt-10">
          <div className="flex flex-col sm:flex-row sm:items-end gap-3">
            <div className="h-16 w-16 sm:h-20 sm:w-20 rounded-xl border-4 border-card bg-muted flex items-center justify-center overflow-hidden shadow-md shrink-0">
              {customer.photo_url ? (
                <img src={customer.photo_url} alt={customer.name} loading="lazy" className="w-full h-full object-cover" />
              ) : (
                <User className="h-8 w-8 text-muted-foreground/40" />
              )}
            </div>
            <div className="flex-1 min-w-0 sm:pb-0.5">
              <div className="flex flex-wrap items-center gap-2">
                <h1 className="text-lg sm:text-xl font-bold text-foreground truncate">{customer.name}</h1>
                <StatusBadge status={customer.is_active ? "active" : "inactive"} />
              </div>
              <p className="text-xs text-muted-foreground font-mono">{customer.display_id}</p>
            </div>
            <div className="flex items-center gap-2 shrink-0 flex-wrap">
              {canEdit && (
                <>
                  <div className="flex items-center gap-2">
                    <Label htmlFor="cust-toggle" className="text-xs text-muted-foreground">{customer.is_active ? "Active" : "Inactive"}</Label>
                    <Switch id="cust-toggle" checked={customer.is_active} onCheckedChange={handleToggleActive} disabled={toggling} />
                  </div>
                  {!isInactive && (
                    !editing ? (
                      <div className="flex gap-1.5">
                        <Button variant="outline" size="sm" onClick={() => setShowStatement(true)} className="gap-1.5"><FileText className="h-3.5 w-3.5" /> Statement</Button>
                        <Button variant="outline" size="sm" onClick={startEditing} className="gap-1.5"><Pencil className="h-3.5 w-3.5" /> Edit</Button>
                      </div>
                    ) : (
                      <div className="flex gap-1.5">
                        <Button variant="ghost" size="sm" onClick={() => setEditing(false)} disabled={saving}><X className="h-4 w-4" /></Button>
                        <Button size="sm" onClick={handleSave} disabled={saving} className="gap-1.5">
                          {saving ? <Loader2 className="h-3.5 w-3.5 animate-spin" /> : <Save className="h-3.5 w-3.5" />} Save
                        </Button>
                      </div>
                    )
                  )}
                </>
              )}
            </div>
          </div>

          <Separator className="my-3" />

          {editing ? (
            <div className="space-y-4">
              <div className="flex items-start gap-4">
                <ImageUpload folder="customers" currentUrl={photoUrl} onUploaded={setPhotoUrl} onRemoved={() => setPhotoUrl(null)} />
                <div className="flex-1 grid grid-cols-1 sm:grid-cols-2 gap-3">
                  <div className="space-y-1"><Label className="text-xs">Name</Label><Input value={form.name} onChange={(e) => setForm({ ...form, name: e.target.value })} /></div>
                  <div className="space-y-1"><Label className="text-xs">Phone</Label><Input value={form.phone} onChange={(e) => setForm({ ...form, phone: e.target.value })} /></div>
                  <div className="space-y-1"><Label className="text-xs">Email</Label><Input type="email" value={form.email} onChange={(e) => setForm({ ...form, email: e.target.value })} /></div>
                  <div className="space-y-1"><Label className="text-xs">GST Number</Label><Input value={form.gst_number} onChange={(e) => setForm({ ...form, gst_number: e.target.value })} /></div>
                  <div className="space-y-1 sm:col-span-2"><Label className="text-xs">Address</Label><Textarea value={form.address} onChange={(e) => setForm({ ...form, address: e.target.value })} rows={2} /></div>
                </div>
              </div>
            </div>
          ) : (
            <div className="grid grid-cols-2 sm:grid-cols-3 lg:grid-cols-5 gap-x-6 gap-y-2">
              <InfoItem label="Phone" value={customer.phone || "Not provided"} />
              <InfoItem label="Email" value={customer.email || "Not provided"} />
              <InfoItem label="Address" value={customer.address || "Not provided"} />
              <InfoItem label="GST" value={customer.gst_number || "—"} />
              <InfoItem label="Joined" value={new Date(customer.created_at).toLocaleDateString("en-IN", { year: "numeric", month: "short", day: "numeric" })} />
            </div>
          )}
        </CardContent>
      </Card>

      {/* Summary stats */}
      <div className="grid grid-cols-2 gap-3">
        <Card className="p-4">
          <p className="text-xs text-muted-foreground">Stores</p>
          <p className="text-xl font-bold">{stores?.length || 0}</p>
        </Card>
        <Card className="p-4">
          <p className="text-xs text-muted-foreground">Total Outstanding</p>
          <p className={`text-xl font-bold ${totalOutstanding > 0 ? "text-destructive" : ""}`}>₹{totalOutstanding.toLocaleString()}</p>
        </Card>
      </div>

      {/* KYC Section */}
      <Card>
        <CardContent className="p-4 sm:p-5 space-y-4">
          <div className="flex items-center justify-between">
            <h2 className="text-sm font-semibold flex items-center gap-2">
              <Shield className="h-4 w-4 text-muted-foreground" /> KYC Verification
            </h2>
            <Badge variant={kycStatus === "verified" ? "default" : kycStatus === "pending" ? "secondary" : kycStatus === "rejected" ? "destructive" : "outline"}>
              {kycLabel}
            </Badge>
          </div>

          {kycStatus === "rejected" && customer.kyc_rejection_reason && (
            <div className="rounded-lg border border-destructive/30 bg-destructive/5 p-3">
              <p className="text-xs text-destructive font-medium">Rejection reason</p>
              <p className="text-sm text-destructive/80 mt-0.5">{customer.kyc_rejection_reason}</p>
            </div>
          )}

          {/* Documents grid */}
          <div className="grid grid-cols-3 gap-3">
            {kycDocs.map((doc) => (
              <KycDocCard
                key={doc.field}
                label={doc.label}
                url={doc.url}
                getPublicUrl={getDocUrl}
                canUpload={isCustomer || canEdit}
                uploading={uploadingKyc}
                onUpload={(file) => uploadKycFile(file, doc.field)}
              />
            ))}
          </div>

          {/* Approve/Reject for admin/manager when status is pending */}
          {canEdit && kycStatus === "pending" && (
            <div className="space-y-3 pt-2 border-t">
              <div>
                <Label className="text-xs">Rejection Reason (if rejecting)</Label>
                <Textarea value={rejectionReason} onChange={(e) => setRejectionReason(e.target.value)} className="mt-1" placeholder="Blurry photo, name mismatch..." rows={2} />
              </div>
              <div className="flex gap-3">
                <Button onClick={handleKycApprove} disabled={kycSaving} className="flex-1" size="sm">
                  {kycSaving ? <Loader2 className="mr-1.5 h-3.5 w-3.5 animate-spin" /> : <CheckCircle2 className="mr-1.5 h-3.5 w-3.5" />}
                  Approve
                </Button>
                <Button onClick={handleKycReject} disabled={kycSaving} variant="destructive" className="flex-1" size="sm">
                  {kycSaving ? <Loader2 className="mr-1.5 h-3.5 w-3.5 animate-spin" /> : <XCircle className="mr-1.5 h-3.5 w-3.5" />}
                  Reject
                </Button>
              </div>
            </div>
          )}

          {kycStatus === "verified" && customer.kyc_verified_at && (
            <p className="text-xs text-muted-foreground">
              Verified on {new Date(customer.kyc_verified_at).toLocaleDateString("en-IN", { year: "numeric", month: "short", day: "numeric" })}
            </p>
          )}
        </CardContent>
      </Card>

      {/* Stores */}
      <div>
        <h2 className="text-sm font-semibold mb-3 flex items-center gap-2">
          <Store className="h-4 w-4 text-muted-foreground" /> Stores
        </h2>
        {(stores?.length || 0) === 0 ? (
          <div className="rounded-xl border border-dashed bg-card p-8 text-center text-muted-foreground text-sm">No stores yet</div>
        ) : (
          <DataTable columns={storeColumns} data={stores || []} searchKey="name" searchPlaceholder="Search stores..." onRowClick={(row) => navigate(`/stores/${row.id}`)} />
        )}
      </div>

      {/* Payment History */}
      <div>
        <h2 className="text-sm font-semibold mb-3 flex items-center gap-2">
          <Receipt className="h-4 w-4 text-muted-foreground" /> Payment History
          {customerTxns && customerTxns.length > 0 && (
            <span className="ml-1 text-xs font-normal text-muted-foreground">({customerTxns.length})</span>
          )}
        </h2>
        {(customerTxns?.length || 0) === 0 ? (
          <div className="rounded-xl border border-dashed bg-card p-8 text-center text-muted-foreground text-sm">No payments recorded</div>
        ) : (
          <DataTable
            columns={[
              { header: "Payment ID", accessor: "display_id" as const, className: "font-mono text-xs" },
              { header: "Store", accessor: (row: any) => (row.stores as any)?.name || "—", className: "font-medium" },
              { header: "Total", accessor: (row: any) => `₹${Number(row.total_amount).toLocaleString()}`, className: "font-semibold" },
              { header: "Cash", accessor: (row: any) => `₹${Number(row.cash_amount).toLocaleString()}`, className: "text-sm hidden md:table-cell" },
              { header: "UPI", accessor: (row: any) => `₹${Number(row.upi_amount).toLocaleString()}`, className: "text-sm hidden md:table-cell" },
              { header: "Date", accessor: (row: any) => new Date(row.created_at).toLocaleString("en-IN", { dateStyle: "short", timeStyle: "short" }), className: "text-muted-foreground text-xs" },
            ]}
            data={customerTxns || []}
            searchKey="display_id"
            searchPlaceholder="Search payments..."
          />
        )}
      </div>

      {/* Customer Statement Modal */}
      {showStatement && customer && (
        <div className="fixed inset-0 z-50 bg-background/80 backdrop-blur-sm overflow-y-auto">
          <div className="container max-w-4xl py-6">
            <CustomerStatement
              customerId={customer.id}
              customerName={customer.name}
              onClose={() => setShowStatement(false)}
            />
          </div>
        </div>
      )}
    </div>
  );
};

function InfoItem({ label, value }: { label: string; value: string }) {
  return (
    <div className="min-w-0">
      <p className="text-[10px] text-muted-foreground uppercase tracking-wider">{label}</p>
      <p className="text-sm font-medium text-foreground truncate">{value}</p>
    </div>
  );
}

function KycDocCard({
  label, url, getPublicUrl, canUpload, uploading, onUpload,
}: {
  label: string;
  url: string | null;
  getPublicUrl: (path: string | null) => string | null;
  canUpload: boolean;
  uploading: boolean;
  onUpload: (file: File) => void;
}) {
  const inputRef = useRef<HTMLInputElement>(null);
  const publicUrl = getPublicUrl(url);

  return (
    <div className="rounded-lg border bg-muted/30 p-3 text-center space-y-2">
      <p className="text-[11px] font-medium text-muted-foreground">{label}</p>
      {publicUrl ? (
        <div className="space-y-1.5">
          <img src={publicUrl} alt={label} loading="lazy" className="w-full h-16 object-cover rounded" />
          <a href={publicUrl} target="_blank" rel="noopener noreferrer" className="inline-flex items-center gap-1 text-[11px] text-primary hover:underline">
            View <ExternalLink className="h-3 w-3" />
          </a>
        </div>
      ) : canUpload ? (
        <>
          <input ref={inputRef} type="file" accept="image/*" className="hidden" onChange={(e) => { if (e.target.files?.[0]) onUpload(e.target.files[0]); }} />
          <Button variant="outline" size="sm" className="w-full text-[11px] h-7" onClick={() => inputRef.current?.click()} disabled={uploading}>
            {uploading ? <Loader2 className="h-3 w-3 animate-spin mr-1" /> : <Upload className="h-3 w-3 mr-1" />}
            Upload
          </Button>
        </>
      ) : (
        <p className="text-[11px] text-muted-foreground">Not uploaded</p>
      )}
    </div>
  );
}

export default CustomerDetail;

import { PageHeader } from "@/components/shared/PageHeader";
import { DataTable } from "@/components/shared/DataTable";
import { StatusBadge } from "@/components/shared/StatusBadge";
import { useQuery, useQueryClient } from "@tanstack/react-query";
import { supabase } from "@/integrations/supabase/client";
import { resolveCustomer } from "@/lib/resolveCustomer";
import { sendNotificationToMany, getAdminUserIds } from "@/lib/notifications";
import { useAuth } from "@/contexts/AuthContext";
import { Loader2 } from "lucide-react";
import { useState } from "react";
import { Dialog, DialogContent, DialogHeader, DialogTitle } from "@/components/ui/dialog";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Button } from "@/components/ui/button";
import { Textarea } from "@/components/ui/textarea";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { toast } from "sonner";
import { logActivity } from "@/lib/activityLogger";

const CustomerOrders = () => {
  const { user } = useAuth();
  const qc = useQueryClient();
  const [showOrder, setShowOrder] = useState(false);
  const [saving, setSaving] = useState(false);
  const [orderStoreId, setOrderStoreId] = useState("");
  const [orderNote, setOrderNote] = useState("");

  const { data: customer } = useQuery({
    queryKey: ["my-customer", user?.id],
    queryFn: async () => {
      const res = await resolveCustomer(user!.id);
      return res as any;
    },
    enabled: !!user,
  });

  const { data: stores } = useQuery({
    queryKey: ["my-stores", customer?.id],
    queryFn: async () => {
      const { data } = await supabase.from("stores").select("id, name, is_active").eq("customer_id", customer!.id);
      return data || [];
    },
    enabled: !!customer,
  });

  const { data: orders, isLoading } = useQuery({
    queryKey: ["my-orders", customer?.id],
    queryFn: async () => {
      const { data } = await supabase
        .from("orders")
        .select("*, stores(name)")
        .eq("customer_id", customer!.id)
        .order("created_at", { ascending: false });
      return data || [];
    },
    enabled: !!customer,
  });

  const handleCreateOrder = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!orderStoreId) { toast.error("Select a store"); return; }

    // Check for existing active order for this store
    const activeOrder = orders?.find(o => o.store_id === orderStoreId && (o.status === "pending" || o.status === "confirmed"));
    if (activeOrder) {
      toast.error("You already have an active order for this store. Wait until it's delivered or cancelled.");
      return;
    }

    setSaving(true);
    const { data: displayId } = await supabase.rpc("generate_display_id", { prefix: "ORD", seq_name: "ord_display_seq" });
    const { error } = await supabase.from("orders").insert({
      display_id: displayId,
      store_id: orderStoreId,
      customer_id: customer!.id,
      order_type: "simple",
      source: "manual",
      created_by: user!.id,
      requirement_note: orderNote || null,
    });
    setSaving(false);
    if (error) toast.error(error.message);
    else {
      getAdminUserIds().then(admins => {
        if (admins.length > 0) {
          sendNotificationToMany(admins, {
            title: "New Customer Order",
            message: `Order ${displayId} placed by customer`,
            type: "order" as any,
          });
        }
      });
      toast.success("Order placed!");
      setShowOrder(false);
      setOrderStoreId("");
      setOrderNote("");
      qc.invalidateQueries({ queryKey: ["my-orders"] });
      logActivity(user!.id, "Created order", "order", displayId);
    }
  };

  const columns = [
    { header: "Order ID", accessor: "display_id" as const, className: "font-mono text-xs" },
    { header: "Store", accessor: (row: any) => row.stores?.name || "—" },
    { header: "Type", accessor: (row: any) => row.order_type === "simple" ? "Simple" : "Detailed" },
    { header: "Note", accessor: (row: any) => row.requirement_note || "—", className: "max-w-[200px] truncate text-muted-foreground text-xs" },
    { header: "Status", accessor: (row: any) => <StatusBadge status={row.status === "delivered" ? "active" : row.status as any} label={row.status} /> },
    { header: "Date", accessor: (row: any) => new Date(row.created_at).toLocaleDateString("en-IN"), className: "text-muted-foreground text-xs" },
  ];

  if (isLoading) {
    return <div className="flex items-center justify-center py-20"><Loader2 className="h-8 w-8 animate-spin text-primary" /></div>;
  }

  return (
    <div className="space-y-6 animate-fade-in">
      <PageHeader title="My Orders" subtitle="Place and track your orders" primaryAction={{ label: "Place Order", onClick: () => setShowOrder(true) }} />
      <DataTable columns={columns} data={orders || []} searchKey="display_id" searchPlaceholder="Search orders..." />

      <Dialog open={showOrder} onOpenChange={setShowOrder}>
        <DialogContent>
          <DialogHeader><DialogTitle>Place Order</DialogTitle></DialogHeader>
          <form onSubmit={handleCreateOrder} className="space-y-4">
            <div>
              <Label>Store</Label>
              <Select value={orderStoreId} onValueChange={setOrderStoreId}>
                <SelectTrigger className="mt-1"><SelectValue placeholder="Select store" /></SelectTrigger>
                <SelectContent>
                  {stores?.filter((s) => s.is_active).map((s) => <SelectItem key={s.id} value={s.id}>{s.name}</SelectItem>)}
                </SelectContent>
              </Select>
            </div>
            <div>
              <Label>Requirement</Label>
              <Textarea value={orderNote} onChange={(e) => setOrderNote(e.target.value)} className="mt-1" placeholder="What do you need?" />
            </div>
            <Button type="submit" className="w-full" disabled={saving}>
              {saving && <Loader2 className="mr-2 h-4 w-4 animate-spin" />}
              Place Order
            </Button>
          </form>
        </DialogContent>
      </Dialog>
    </div>
  );
};

export default CustomerOrders;

import { PageHeader } from "@/components/shared/PageHeader";
import { StatCard } from "@/components/shared/StatCard";
import { StatusBadge } from "@/components/shared/StatusBadge";
import { Badge } from "@/components/ui/badge";
import { useQuery } from "@tanstack/react-query";
import { supabase } from "@/integrations/supabase/client";
import { resolveCustomer } from "@/lib/resolveCustomer";
import { useAuth } from "@/contexts/AuthContext";
import { Loader2, Store, ShoppingCart, DollarSign, FileCheck, Phone, Link2, X } from "lucide-react";
import { useState } from "react";
import { toast } from "sonner";
import { Button } from "@/components/ui/button";
import { useNavigate } from "react-router-dom";
import { DataTable } from "@/components/shared/DataTable";
import { BannerCarousel } from "@/components/banners/BannerCarousel";
import { NoticeBox } from "@/components/shared/NoticeBox";
import { getOAuthRedirectUrl } from "@/lib/capacitorUtils";

const CustomerPortal = () => {
  const { user } = useAuth();
  const navigate = useNavigate();
  const [linkDismissed, setLinkDismissed] = useState(
    () => localStorage.getItem("link_prompt_dismissed") === "true"
  );
  const [linkingGoogle, setLinkingGoogle] = useState(false);

  const googleIdentity = (user?.identities || []).find((i: any) => i?.provider === "google");
  const isGoogleLinked = !!googleIdentity;
  const isPhoneOnlyUser = !!user?.email?.endsWith("@phone.aquaprime.app");

  const handleLinkGoogle = async () => {
    setLinkingGoogle(true);
    const { error } = await supabase.auth.linkIdentity({
      provider: "google",
      options: { redirectTo: getOAuthRedirectUrl("/") },
    });
    if (error) {
      if (error.message?.toLowerCase().includes("manual linking")) {
        toast.error("Google linking is not configured. Please contact support.");
      } else {
        toast.error(error.message);
      }
      setLinkingGoogle(false);
    }
    // On success the browser will redirect to Google — no further action needed here
  };

  const handleDismissLinkPrompt = () => {
    localStorage.setItem("link_prompt_dismissed", "true");
    setLinkDismissed(true);
  };

  const { data: companySettings } = useQuery({
    queryKey: ["company-settings-portal"],
    queryFn: async () => {
      const { data } = await supabase.from("company_settings").select("key, value");
      const map: Record<string, string> = {};
      data?.forEach((s) => { map[s.key] = s.value || ""; });
      return map;
    },
  });

  const { data: customer, isLoading: loadingCustomer } = useQuery({
    queryKey: ["my-customer", user?.id],
    queryFn: async () => resolveCustomer(user!.id),
    enabled: !!user,
  });

  const { data: stores } = useQuery({
    queryKey: ["my-stores", customer?.id],
    queryFn: async () => {
      const { data } = await supabase.from("stores").select("*, store_types(name)").eq("customer_id", customer!.id).order("created_at", { ascending: false });
      return data || [];
    },
    enabled: !!customer,
  });

  const { data: orders } = useQuery({
    queryKey: ["my-orders-count", customer?.id],
    queryFn: async () => {
      const { data } = await supabase.from("orders").select("id, status").eq("customer_id", customer!.id);
      return data || [];
    },
    enabled: !!customer,
  });

  const totalOutstanding = stores?.reduce((s, st) => s + Number(st.outstanding), 0) || 0;
  const pendingOrders = orders?.filter((o) => o.status === "pending").length || 0;

  const storeColumns = [
    { header: "Store", accessor: "name" as const, className: "font-medium" },
    { header: "Type", accessor: (row: any) => <Badge variant="secondary">{row.store_types?.name || "—"}</Badge> },
    { header: "Outstanding", accessor: (row: any) => `₹${Number(row.outstanding).toLocaleString()}`, className: "font-semibold" },
    { header: "Status", accessor: (row: any) => <StatusBadge status={row.is_active ? "active" : "inactive"} /> },
  ];

  if (loadingCustomer) {
    return <div className="flex items-center justify-center py-20"><Loader2 className="h-8 w-8 animate-spin text-primary" /></div>;
  }

  if (!customer) {
    return (
      <div className="space-y-6 animate-fade-in">
        <PageHeader title="Customer Portal" subtitle="Your account is not linked to a customer profile yet." />
        <div className="rounded-xl border bg-card p-8 text-center text-muted-foreground">
          Please contact the admin to link your account to a customer profile.
        </div>
      </div>
    );
  }

  return (
    <div className="space-y-6 animate-fade-in">
      <PageHeader title="My Dashboard" subtitle={`Welcome, ${customer.name}`} primaryAction={{ label: "Place Order", onClick: () => navigate("/portal/orders") }} />

      {/* Promotional Banners */}
      <BannerCarousel storeTypeIds={stores?.map((s: any) => s.store_type_id).filter(Boolean)} />

      {/* Link Google account prompt for phone-only users who haven't linked yet */}
      {isPhoneOnlyUser && !isGoogleLinked && !linkDismissed && (
        <NoticeBox
          variant="premium"
          icon={Link2}
          onClose={handleDismissLinkPrompt}
          title="Secure your account"
          message={
            <div className="space-y-2">
              <p>Link Google for faster, passwordless login next time.</p>
              <Button
                size="sm"
                variant="outline"
                className="h-8 border-primary/20 bg-background/50 hover:bg-background"
                onClick={handleLinkGoogle}
                disabled={linkingGoogle}
              >
                {linkingGoogle ? (
                  <span className="flex items-center gap-1.5">
                    <Loader2 className="h-3 w-3 animate-spin" />
                    Redirecting…
                  </span>
                ) : (
                  <span className="flex items-center gap-1.5 capitalize">
                    Link Google Account
                  </span>
                )}
              </Button>
            </div>
          }
        />
      )}

      <div className="grid grid-cols-2 sm:grid-cols-3 gap-4">
        <StatCard title="My Stores" value={String(stores?.length || 0)} icon={Store} iconColor="primary" />
        <StatCard title="Total Outstanding" value={`₹${totalOutstanding.toLocaleString()}`} icon={DollarSign} iconColor="warning" />
        <StatCard title="Pending Orders" value={String(pendingOrders)} icon={ShoppingCart} iconColor="info" />
      </div>

      {/* Quick Actions */}
      <div className="grid grid-cols-2 sm:grid-cols-5 gap-3">
        <Button variant="outline" className="h-auto py-4 flex-col gap-2" onClick={() => navigate("/portal/orders")}>
          <ShoppingCart className="h-5 w-5" />
          <span className="text-xs">Place Order</span>
        </Button>
