import { PageHeader } from "@/components/shared/PageHeader";
import { VirtualDataTable } from "@/components/shared/VirtualDataTable";
import { DataTable } from "@/components/shared/DataTable";
import { StatusBadge } from "@/components/shared/StatusBadge";
import { KycReviewDialog } from "@/components/customers/KycReviewDialog";
import { ImageUpload } from "@/components/shared/ImageUpload";
import { CsvImportDialog } from "@/components/shared/CsvImportDialog";
import { AdvancedFilters, applyFilters, type FilterValues } from "@/components/shared/AdvancedFilters";
import { useInfiniteQuery, useQueryClient } from "@tanstack/react-query";
import { supabase } from "@/integrations/supabase/client";
import { useAuth } from "@/contexts/AuthContext";
import { logActivity } from "@/lib/activityLogger";
import { generateDisplayId } from "@/lib/displayId";
import { validatePhone, validateEmail, normalizePhone } from "@/lib/validation";
import { Loader2, User, Upload, AlertCircle, Phone, Mail, Store as StoreIcon } from "lucide-react";
import { usePermission } from "@/hooks/usePermission";
import { useRouteAccess } from "@/hooks/useRouteAccess";
import { addToQueue } from "@/lib/offlineQueue";
import { useOnlineStatus } from "@/hooks/useOnlineStatus";
import { TableSkeleton } from "@/components/shared/TableSkeleton";
import { Checkbox } from "@/components/ui/checkbox";
import { useState, useMemo, useEffect } from "react";
import { useNavigate } from "react-router-dom";
import { useIsMobile } from "@/hooks/use-mobile";
import {
  Dialog, DialogContent, DialogHeader, DialogTitle,
} from "@/components/ui/dialog";
import { NoticeBox } from "@/components/shared/NoticeBox";
import {
  AlertDialog, AlertDialogAction, AlertDialogCancel, AlertDialogContent,
  AlertDialogDescription, AlertDialogFooter, AlertDialogHeader, AlertDialogTitle,
} from "@/components/ui/alert-dialog";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Button } from "@/components/ui/button";
import { toast } from "sonner";

const Customers = () => {
  const navigate = useNavigate();
  const { user, role } = useAuth();
  const { isOnline } = useOnlineStatus();
  const isMobile = useIsMobile();
  const { allowed: canCreateCustomers } = usePermission("create_customers");
  const [showAdd, setShowAdd] = useState(false);
  const [showImport, setShowImport] = useState(false);
  const [kycCustomer, setKycCustomer] = useState<any>(null);
  const [name, setName] = useState("");
  const [phone, setPhone] = useState("");
  const [email, setEmail] = useState("");
  const [address, setAddress] = useState("");
  const [photoUrl, setPhotoUrl] = useState("");
  const [saving, setSaving] = useState(false);
  const [selected, setSelected] = useState<Set<string>>(new Set());
  const [selectMode, setSelectMode] = useState(false);
  const [editMode, setEditMode] = useState(false);
  const [editData, setEditData] = useState<Record<string, { name: string; phone: string; email: string }>>({});
  const [bulkSaving, setBulkSaving] = useState(false);
  const [confirmBulkDeactivate, setConfirmBulkDeactivate] = useState(false);
  const [filters, setFilters] = useState<FilterValues>({});
  const [duplicateCustomer, setDuplicateCustomer] = useState<any>(null);
  const qc = useQueryClient();
  const PAGE_SIZE = 50;
  // const [loadedPages, setLoadedPages] = useState(1); // No longer needed
  const canReviewKyc = role === "super_admin" || role === "manager";
  const canBulk = role === "super_admin" || role === "manager";
  const canEdit = role === "super_admin" || role === "manager";

  const { canAccessRoute, loading: routeLoading, hasMatrixRestrictions } = useRouteAccess(user?.id, role);

  const {
    data,
    fetchNextPage,
    hasNextPage,
    isFetchingNextPage,
    isLoading,
    isError,
    error: queryError
  } = useInfiniteQuery({
    queryKey: ["customers"],
    queryFn: async ({ pageParam = 0 }) => {
      const { data, error } = await supabase
        .from("customers")
        .select("*, stores(id, outstanding, route_id)")
        .order("created_at", { ascending: false })
        .range(pageParam * PAGE_SIZE, (pageParam + 1) * PAGE_SIZE - 1);
      if (error) throw error;
      return data;
    },
    initialPageParam: 0,
    getNextPageParam: (lastPage, allPages) => {
      if (!lastPage || lastPage.length < PAGE_SIZE) return undefined;
      return allPages.length;
    },
  });

  const customers = useMemo(() => data?.pages.flatMap((page) => page) || [], [data]);
  
  // Real-time phone duplicate check
  useEffect(() => {
    if (!phone.trim() || phone.trim().length < 6) { setDuplicateCustomer(null); return; }
    const timer = setTimeout(() => {
      const match = (customers || []).find((c: any) => c.phone && c.phone === phone.trim());
      setDuplicateCustomer(match || null);
    }, 400);
    return () => clearTimeout(timer);
  }, [phone, customers]);

    const handleAdd = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!name.trim()) {
      toast.error("Customer name is required");
      return;
    }
    
    // Validate phone with proper format check
    const phoneValidation = validatePhone(phone, true);
    if (!phoneValidation.valid) {
      toast.error(phoneValidation.message);
      return;
    }
    
    // Validate email if provided
    const emailValidation = validateEmail(email, false);
    if (!emailValidation.valid) {
      toast.error(emailValidation.message);
      return;
    }
    
    if (duplicateCustomer && phone.trim()) {
      toast.error(`Phone already in use by ${duplicateCustomer.name} (${duplicateCustomer.display_id})`);
      return;
    }
    setSaving(true);
    
    // Normalize phone number for storage
    const normalizedPhone = normalizePhone(phone);

    if (!isOnline) {
       await addToQueue({
        id: crypto.randomUUID(),
        type: "customer",
        payload: {
          customerData: {
            id: crypto.randomUUID(), // Generate ID on client for offline caching/relationships
            name,
            phone: normalizedPhone || null,
            email: email?.trim().toLowerCase() || null,
            address: address || null,
            photo_url: photoUrl || null,
            created_at: new Date().toISOString(),
          }
        },
        createdAt: new Date().toISOString(),
      });
      toast.warning("You're offline — customer queued and will sync automatically when back online");
      setSaving(false);
      setShowAdd(false);
      setName(""); setPhone(""); setEmail(""); setAddress(""); setPhotoUrl("");
      setDuplicateCustomer(null);
      qc.invalidateQueries({ queryKey: ["customers"] });
      return;
    }

    const displayId = generateDisplayId("CUST");

    const { error } = await supabase.from("customers").insert({
      display_id: displayId,
      name,
      phone: normalizedPhone || null,
      email: email?.trim().toLowerCase() || null,
      address: address || null,
      photo_url: photoUrl || null,
    });
    setSaving(false);
    if (error) {
      toast.error(error.message);
    } else {
      toast.success("Customer added");
      logActivity(user!.id, "Added customer", "customer", name);
      setShowAdd(false);
      setName(""); setPhone(""); setEmail(""); setAddress(""); setPhotoUrl("");
      setDuplicateCustomer(null);
      qc.invalidateQueries({ queryKey: ["customers"] });
    }
    };

  const handleCsvImport = async (rows: Record<string, string>[]) => {
    let success = 0;
    const errors: string[] = [];

    for (let i = 0; i < rows.length; i++) {
      const row = rows[i];
      
      // Validate required name
      if (!row.name?.trim()) {
        errors.push(`Row ${i + 2}: Customer name is required`);
        continue;
      }
      
      // Validate phone if provided
      if (row.phone) {
        const phoneValidation = validatePhone(row.phone);
        if (!phoneValidation.valid) {
          errors.push(`Row ${i + 2}: ${phoneValidation.message}`);
          continue;
        }
      }
      
      // Validate email if provided
      if (row.email) {
        const emailValidation = validateEmail(row.email);
        if (!emailValidation.valid) {
          errors.push(`Row ${i + 2}: ${emailValidation.message}`);
          continue;
        }
      }
      
      const displayId = generateDisplayId("CUST");
      const { error } = await supabase.from("customers").insert({
        display_id: displayId,
        name: row.name.trim(),
        phone: row.phone ? normalizePhone(row.phone) : null,
        email: row.email?.trim().toLowerCase() || null,
        address: row.address?.trim() || null,
      });
      if (error) {
        errors.push(`Row ${i + 2}: ${error.message}`);
      } else {
        success++;
      }
    }

    if (success > 0) {
      logActivity(user!.id, `Imported ${success} customers via CSV`, "customer");
      qc.invalidateQueries({ queryKey: ["customers"] });
    }
    return { success, errors };
  };

  const toggleSelect = (id: string) => {
    setSelected((prev) => {
      const next = new Set(prev);
      if (next.has(id)) next.delete(id); else next.add(id);
      return next;
    });
  };

  const toggleAll = () => {
    if (selected.size === (customers?.length || 0)) {
      setSelected(new Set());
    } else {
      setSelected(new Set(customers?.map((c) => c.id) || []));
    }
  };

  const handleBulkStatus = async (active: boolean) => {
    if (selected.size === 0) return;
    const ids = Array.from(selected);
    const { error } = await supabase.from("customers").update({ is_active: active }).in("id", ids);
    if (error) { toast.error(error.message); return; }

    if (!active) {
      const { error: storeError } = await supabase
        .from("stores")
        .update({ is_active: false })
        .in("customer_id", ids);
      if (storeError) {
        toast.error("Customers deactivated but failed to deactivate stores");
      }
    }

    toast.success(`${ids.length} customers ${active ? "activated" : "deactivated"}`);
    setSelected(new Set());
    qc.invalidateQueries({ queryKey: ["customers"] });
    qc.invalidateQueries({ queryKey: ["stores"] });
  };

  const enterEditMode = () => {
    const data: Record<string, { name: string; phone: string; email: string }> = {};
    (customers || []).forEach((c: any) => {
      data[c.id] = { name: c.name || "", phone: c.phone || "", email: c.email || "" };
    });
    setEditData(data);
    setEditMode(true);
  };

  const cancelEditMode = () => { setEditMode(false); setEditData({}); };

  const saveAllEdits = async () => {
    setBulkSaving(true);
    const changed = (customers || []).filter((c: any) => {
      const d = editData[c.id];
      if (!d) return false;
      return d.name !== (c.name || "") || d.phone !== (c.phone || "") || d.email !== (c.email || "");
    });
    if (changed.length === 0) {
      toast.info("No changes to save");
      setBulkSaving(false);
      setEditMode(false);
      return;
    }
    const results = await Promise.all(
      changed.map((c: any) => {
        const d = editData[c.id];
        return supabase.from("customers").update({ name: d.name || null, phone: d.phone || null, email: d.email || null }).eq("id", c.id);
      })
    );
    setBulkSaving(false);
    const errCount = results.filter((r) => r.error).length;
    if (errCount > 0) { toast.error(`${errCount} update(s) failed`); }
    else {
      toast.success(`${changed.length} customer(s) updated`);
      logActivity(user!.id, `Bulk updated ${changed.length} customers`, "customer");
    }
    setEditMode(false);
    setEditData({});
    qc.invalidateQueries({ queryKey: ["customers"] });
  };

  const setField = (id: string, field: keyof typeof editData[string], value: string) =>
    setEditData((prev) => ({ ...prev, [id]: { ...prev[id], [field]: value } }));

  const columns = [
    ...(canBulk && selectMode ? [{
      header: () => (
        <Checkbox
          checked={selected.size === (customers?.length || 0) && (customers?.length || 0) > 0}
          onCheckedChange={toggleAll}
        />
      ),
      accessor: (row: any) => (
        <Checkbox
          checked={selected.has(row.id)}
          onCheckedChange={() => toggleSelect(row.id)}
          onClick={(e: React.MouseEvent) => e.stopPropagation()}
        />
      ),
      className: "w-10",
      hideOnMobile: true,
    }] : []),
    { header: "ID", accessor: "display_id" as const, className: "font-mono text-xs hidden lg:table-cell", hideOnMobile: true },
    { header: "Name", accessor: (row: any) => (
      <div className="flex items-center gap-2">
        {row.photo_url && <img src={row.photo_url} alt="" loading="lazy" className="h-8 w-8 rounded-full object-cover" />}
        {editMode ? (
          <input
            className="border-none bg-accent/30 rounded px-2 py-1 text-sm w-32 focus:bg-accent/50 focus:ring-1 focus:ring-primary/20 outline-none transition-all font-medium"
            value={editData[row.id]?.name ?? row.name ?? ""}
            onChange={(e) => setField(row.id, "name", e.target.value)}
            onClick={(e) => e.stopPropagation()}
          />
        ) : (
          <span className="font-medium text-primary hover:underline">{row.name}</span>
        )}
      </div>
    )},
    { header: "Phone", accessor: (row: any) => editMode ? (
      <input
        className="border-none bg-accent/30 rounded px-2 py-1 text-sm w-32 focus:bg-accent/50 focus:ring-1 focus:ring-primary/20 outline-none transition-all font-mono"
        value={editData[row.id]?.phone ?? row.phone ?? ""}
        onChange={(e) => setField(row.id, "phone", e.target.value)}
        onClick={(e) => e.stopPropagation()}
        placeholder="Add phone"
      />
    ) : (
      <span className="text-muted-foreground text-sm">{row.phone || "—"}</span>
    ), className: "hidden sm:table-cell" },
    { header: "Email", accessor: (row: any) => editMode ? (
      <input
        className="border-none bg-accent/30 rounded px-2 py-1 text-sm w-44 focus:bg-accent/50 focus:ring-1 focus:ring-primary/20 outline-none transition-all"
        value={editData[row.id]?.email ?? row.email ?? ""}
        onChange={(e) => setField(row.id, "email", e.target.value)}
        onClick={(e) => e.stopPropagation()}
        placeholder="Add email"
      />
    ) : (
      <span className="text-muted-foreground text-sm">{row.email || "—"}</span>
    ), className: "hidden md:table-cell" },
    { header: "Stores", accessor: (row: any) => row.stores?.length || 0, className: "text-center hidden sm:table-cell" },
    { header: "Outstanding", accessor: (row: any) => {
      const total = (row.stores || []).reduce((s: number, st: any) => s + Number(st.outstanding || 0), 0);
      return `₹${total.toLocaleString()}`;
    }},
    { header: "KYC", accessor: (row: any) => (
      <button onClick={() => canReviewKyc && row.kyc_status !== "not_requested" ? setKycCustomer(row) : null} className={canReviewKyc && row.kyc_status !== "not_requested" ? "cursor-pointer hover:opacity-80" : ""}>
        <StatusBadge status={row.kyc_status === "verified" ? "verified" : row.kyc_status === "pending" ? "pending" : row.kyc_status === "rejected" ? "rejected" : "inactive"} label={row.kyc_status.replace("_", " ")} />
      </button>
    )},
    { header: "Status", accessor: (row: any) => <StatusBadge status={row.is_active ? "active" : "inactive"} /> },
  ];

  const filteredCustomers = useMemo(() => {
    let data = customers || [];
    if (hasMatrixRestrictions) {
      data = data.filter((c: any) => 
        c.stores?.some((s: any) => canAccessRoute(s.route_id))
      );
    }
    return applyFilters(data, filters, {
      dateField: "created_at",
      kycField: "kyc_status",
      statusField: "is_active",
    });
  }, [customers, filters, hasMatrixRestrictions, canAccessRoute]);

  if (isLoading || routeLoading) {
    return <TableSkeleton columns={7} />;
  }

  if (isError) {
    return (
      <div className="space-y-6 animate-fade-in">
        <PageHeader title="Customers" subtitle="Manage customer relationships" />
        <NoticeBox 
          variant="error" 
          icon={AlertCircle} 
          message={
            <div className="space-y-1">
              <p className="font-medium">Failed to load customers</p>
              <p className="text-sm">{queryError?.message || "An error occurred while fetching customer data. Please try again."}</p>
              <Button variant="outline" size="sm" className="mt-3" onClick={() => qc.invalidateQueries({ queryKey: ["customers"] })}>
                Retry
              </Button>
            </div>
          }
        />
      </div>
    );
  }

  return (
    <div className="space-y-6 animate-fade-in">
      <PageHeader
        title="Customers"
        subtitle="Manage customer accounts and KYC verification"
        primaryAction={canCreateCustomers ? { label: "Add Customer", onClick: () => setShowAdd(true) } : undefined}
        filterNode={
          <AdvancedFilters
            config={{ dateRange: true, kycStatus: true, status: true }}
            values={filters}
            onChange={setFilters}
          />
        }
        actions={[
          ...(canCreateCustomers ? [{ label: "Import CSV", icon: Upload, onClick: () => setShowImport(true), priority: 1 }] : []),
          ...(canBulk ? [{ label: selectMode ? "Done" : "Select", onClick: () => { setSelectMode((v) => !v); setSelected(new Set()); }, priority: 2 }] : []),
          ...(canEdit && !editMode ? [{ label: "Bulk Edit", onClick: enterEditMode, priority: 3 }] : []),
        ]}
      />

      {canBulk && selectMode && selected.size > 0 && (
        <NoticeBox
          variant="premium"
          message={
            <div className="flex flex-wrap items-center gap-2">
              <span className="font-semibold">{selected.size} selected</span>
              <div className="flex gap-2 ml-3">
                <Button variant="outline" size="sm" className="h-8 bg-background" onClick={() => handleBulkStatus(true)}>Activate</Button>
                <Button variant="outline" size="sm" className="h-8 text-destructive border-destructive/20 bg-background" onClick={() => setConfirmBulkDeactivate(true)}>Deactivate</Button>
                <Button variant="ghost" size="sm" className="h-8" onClick={() => setSelected(new Set())}>Clear</Button>
              </div>
            </div>
          }
        />
      )}

      {editMode && (
        <NoticeBox
          variant="premium"
          className="border-primary/30"
          message={
            <div className="flex flex-wrap items-center justify-between w-full">
              <span className="font-semibold text-primary">Bulk edit mode — modify any fields then save changes</span>
              <div className="flex gap-2">
                <Button size="sm" variant="outline" className="h-8 bg-background" onClick={cancelEditMode} disabled={bulkSaving}>Cancel</Button>
                <Button size="sm" className="h-8 shadow-sm" onClick={saveAllEdits} disabled={bulkSaving}>
                  {bulkSaving && <Loader2 className="mr-2 h-3.5 w-3.5 animate-spin" />}
                  Save All Changes
                </Button>
              </div>
            </div>
          }
        />
      )}

      {/* Desktop: Table, Mobile: Card Grid */}
      {isMobile ? (
        <div className="space-y-4">
          <div className="entity-grid">
            {filteredCustomers.map((row: any) => {
              const totalOutstanding = (row.stores || []).reduce((s: number, st: any) => s + Number(st.outstanding || 0), 0);
              const storeCount = row.stores?.length || 0;
              
              return (
                <div
                  key={row.id}
                  onClick={() => { if (!editMode) navigate(`/customers/${row.id}`); }}
                  className={`group entity-card ${!row.is_active ? "entity-card-inactive" : ""}`}
                >
                  {/* Header with image */}
                  <div className="entity-card-header">
                    {row.photo_url ? (
                      <img src={row.photo_url} alt={row.name} className="entity-card-avatar object-cover" />
                    ) : (
                      <div className="entity-card-avatar">
                        <User className="h-10 w-10 text-muted-foreground" />
                      </div>
                    )}
                    <div className="absolute top-2 right-2">
                      <StatusBadge status={row.is_active ? "active" : "inactive"} />
                    </div>
                  </div>

                  {/* Content */}
                  <div className="entity-card-content">
                    <div className="text-center">
                      <h3 className="entity-card-title">{row.name}</h3>
                      <p className="entity-card-subtitle mt-0.5">{row.display_id}</p>
                    </div>

                    {/* Contact info */}
                    <div className="space-y-1.5 text-sm">
                      {row.phone && (
                        <div className="flex items-center gap-2 text-muted-foreground">
                          <Phone className="h-3.5 w-3.5 shrink-0" />
                          <span className="truncate">{row.phone}</span>
                        </div>
                      )}
                      {row.email && (
                        <div className="flex items-center gap-2 text-muted-foreground">
                          <Mail className="h-3.5 w-3.5 shrink-0" />
                          <span className="truncate text-xs">{row.email}</span>
                        </div>
                      )}
                    </div>

                    {/* KYC Status */}
                    <div className="pt-2 border-t">
                      <StatusBadge 
                        status={row.kyc_status === "verified" ? "verified" : row.kyc_status === "pending" ? "pending" : "inactive"} 
                        label={`KYC: ${row.kyc_status.replace("_", " ")}`} 
                      />
                    </div>

                    {/* Stats */}
                    <div className="entity-card-stat">
                      <div className="flex items-center gap-1.5 text-muted-foreground">
                        <StoreIcon className="h-3.5 w-3.5" />
                        <span className="text-xs">{storeCount} {storeCount === 1 ? 'store' : 'stores'}</span>
                      </div>
                      <div className="text-right">
                        <p className="entity-card-label">Outstanding</p>
                        <p className="font-bold text-foreground">₹{totalOutstanding.toLocaleString()}</p>
                      </div>
                    </div>
                  </div>
                </div>
              );
            })}
          </div>
          {filteredCustomers.length === 0 && (
            <div className="text-center py-12 text-muted-foreground">
              No customers found.
            </div>
          )}
        </div>
      ) : (
        <VirtualDataTable
          columns={columns}
          data={filteredCustomers}
          searchKey="name"
          searchPlaceholder="Search customers..."
          onRowClick={(row) => { if (!editMode) navigate(`/customers/${row.id}`); }}
          height="calc(100vh - 240px)"
          renderMobileCard={(row: any) => (
            <div className={`entity-card-mobile ${!row.is_active ? "entity-card-inactive" : ""}`}>
              <div className="w-14 h-14 rounded-lg bg-muted flex items-center justify-center overflow-hidden shrink-0">
                {row.photo_url ? (
                  <img src={row.photo_url} alt={row.name} className="w-full h-full object-cover" />
                ) : (
                  <User className="h-6 w-6 text-muted-foreground/40" />
                )}
              </div>
              <div className="flex-1 min-w-0">
                <div className="flex items-start justify-between gap-2">
                  <h3 className="font-semibold text-sm text-foreground truncate">{row.name}</h3>
                  <StatusBadge status={row.is_active ? "active" : "inactive"} />
                </div>
                <p className="entity-card-subtitle truncate">{row.display_id}</p>
                <div className="flex items-center gap-3 mt-1">
                  <span className="text-sm font-bold text-foreground">₹{(row.stores || []).reduce((s: number, st: any) => s + Number(st.outstanding || 0), 0).toLocaleString()}</span>
                  <span className="text-xs text-muted-foreground">{row.stores?.length || 0} stores</span>
                </div>
              </div>
            </div>
          )}
        />
      )}

      {hasNextPage && (
        <div className="flex justify-center pt-2">
          <Button variant="outline" size="sm" onClick={() => fetchNextPage()} disabled={isFetchingNextPage} className="gap-1.5">
            {isFetchingNextPage ? <Loader2 className="h-3.5 w-3.5 animate-spin" /> : null}
            Load more
          </Button>
        </div>
      )}

      <Dialog open={showAdd} onOpenChange={setShowAdd}>
        <DialogContent className="max-w-lg">
          <DialogHeader>
            <DialogTitle>Add Customer</DialogTitle>
          </DialogHeader>
          <form onSubmit={handleAdd} className="space-y-4">
            <div className="flex items-start gap-4">
              <ImageUpload folder="customers" currentUrl={photoUrl || null} onUploaded={setPhotoUrl} onRemoved={() => setPhotoUrl("")} />
              <div className="flex-1 space-y-3">
                <div><Label>Name *</Label><Input value={name} onChange={e => setName(e.target.value)} required className="mt-1" /></div>
                <div><Label>Phone *</Label><Input value={phone} onChange={e => setPhone(e.target.value)} className="mt-1" placeholder="+91 98765 43210" required /></div>
              </div>
            </div>
            {duplicateCustomer && phone.trim() && (
              <div className="flex items-start gap-2 rounded-md border border-destructive/30 bg-destructive/5 px-3 py-2 text-xs text-destructive">
                <AlertCircle className="h-3.5 w-3.5 mt-0.5 shrink-0" />
                <span>Phone already used by <span className="font-semibold">{duplicateCustomer.name}</span> ({duplicateCustomer.display_id}).{" "}
                  <button type="button" className="underline" onClick={() => { setShowAdd(false); setDuplicateCustomer(null); navigate(`/customers/${duplicateCustomer.id}`); }}>View customer</button>
                </span>
              </div>
            )}
            <div><Label>Email</Label><Input type="email" value={email} onChange={e => setEmail(e.target.value)} className="mt-1" /></div>
            <div><Label>Address</Label><Input value={address} onChange={e => setAddress(e.target.value)} className="mt-1" /></div>
            <Button type="submit" className="w-full" disabled={saving || !!(duplicateCustomer && phone.trim())}>
              {saving ? <Loader2 className="mr-2 h-4 w-4 animate-spin" /> : null}
              Add Customer
            </Button>
          </form>
        </DialogContent>
      </Dialog>

      <CsvImportDialog
        open={showImport}
        onOpenChange={setShowImport}
        templateName="customers"
        fields={[
          { key: "name", label: "Name", required: true },
          { key: "phone", label: "Phone", required: true },
          { key: "email", label: "Email" },
          { key: "address", label: "Address" },
        ]}
        onImport={handleCsvImport}
      />

      <KycReviewDialog
        customer={kycCustomer}
        open={!!kycCustomer}
        onOpenChange={(open) => { if (!open) setKycCustomer(null); }}
        onDone={() => { setKycCustomer(null); qc.invalidateQueries({ queryKey: ["customers"] }); }}
      />

      <AlertDialog open={confirmBulkDeactivate} onOpenChange={setConfirmBulkDeactivate}>
        <AlertDialogContent>
          <AlertDialogHeader>
            <AlertDialogTitle>Deactivate {selected.size} customer(s)?</AlertDialogTitle>
            <AlertDialogDescription>
              This will deactivate the selected customers and all their stores. This cannot be undone without manually re-activating each one.
            </AlertDialogDescription>
          </AlertDialogHeader>
          <AlertDialogFooter>
            <AlertDialogCancel>Cancel</AlertDialogCancel>
            <AlertDialogAction className="bg-destructive hover:bg-destructive/90" onClick={() => { setConfirmBulkDeactivate(false); handleBulkStatus(false); }}>Deactivate</AlertDialogAction>
          </AlertDialogFooter>
        </AlertDialogContent>
      </AlertDialog>
    </div>
  );
};

export default Customers;

import { StatCard } from "@/components/shared/StatCard";
import { PageHeader } from "@/components/shared/PageHeader";
import { useAuth } from "@/contexts/AuthContext";
import { useQuery } from "@tanstack/react-query";
import { supabase } from "@/integrations/supabase/client";
import {
  DollarSign, Users, Store, ShoppingCart, TrendingUp, Banknote, Smartphone, Clock,
} from "lucide-react";
import { DashboardSkeleton } from "@/components/shared/DashboardSkeleton";
import {
  BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, PieChart, Pie, Cell,
} from "recharts";
import { QuickActionDrawer } from "@/components/agent/QuickActionDrawer";
import { isNativeApp } from "@/lib/capacitorUtils";
import { useFixedCostReminders } from "@/hooks/useFixedCostReminders";

const COLORS = ["hsl(217, 91%, 50%)", "hsl(142, 72%, 42%)", "hsl(38, 92%, 50%)", "hsl(280, 65%, 60%)", "hsl(0, 72%, 51%)"];

// Only fetch the most recent days for chart data to avoid unbounded queries
const CHART_DAYS = 7;
const MAX_SALES_FOR_CHART = 500;

const Dashboard = () => {
  const { profile } = useAuth();
  
  // Check and send fixed cost reminders when dashboard loads
  useFixedCostReminders();

  const { data: stats, isLoading } = useQuery({
    queryKey: ["dashboard-stats"],
    queryFn: async () => {
      const today = new Date().toISOString().split("T")[0];
      const sevenDaysAgo = new Date(Date.now() - CHART_DAYS * 24 * 60 * 60 * 1000).toISOString().split("T")[0];

      // Optimize: Separate queries for different purposes
      // 1. Today's sales aggregates (small dataset)
      // 2. Last 7 days for charts (bounded)
      // 3. Counts only where possible (head: true)
      const [
        todaySalesRes,
        recentSalesRes,
        customersRes,
        storesRes,
        ordersRes,
      ] = await Promise.all([
        // Today's sales - usually small, get full data for precise totals
        supabase.from("sales")
          .select("total_amount, cash_amount, upi_amount")
          .gte("created_at", today + "T00:00:00")
          .limit(500),
        // Recent sales for charts - bounded to 7 days and limited rows
        supabase.from("sales")
          .select("total_amount, created_at, stores(store_type_id, store_types(name))")
          .gte("created_at", sevenDaysAgo + "T00:00:00")
          .order("created_at", { ascending: false })
          .limit(MAX_SALES_FOR_CHART),
        // Customer count only
        supabase.from("customers")
          .select("*", { count: "exact", head: true })
          .eq("is_active", true),
        // Stores with outstanding - bounded and selected columns
        supabase.from("stores")
          .select("id, outstanding")
          .eq("is_active", true)
          .limit(500),
        // Pending orders - just a few for display
        supabase.from("orders")
          .select("id, status, display_id, stores(name), created_at")
          .eq("status", "pending")
          .order("created_at", { ascending: false })
          .limit(5),
      ]);

      const todaySales = todaySalesRes.data || [];
      const recentSales = recentSalesRes.data || [];
      const allStores = storesRes.data || [];

      // Calculate today's totals
      const todayTotal = todaySales.reduce((s, r) => s + Number(r.total_amount), 0);
      const todayCash = todaySales.reduce((s, r) => s + Number(r.cash_amount), 0);
      const todayUpi = todaySales.reduce((s, r) => s + Number(r.upi_amount), 0);
      
      // Calculate store outstanding totals
      const totalOutstanding = allStores.reduce((s, r) => s + Number(r.outstanding), 0);
      const overdueStores = allStores.filter((s) => Number(s.outstanding) > 0).length;

      // Sales by day of week (last 7 days)
      const dayNames = ["Sun", "Mon", "Tue", "Wed", "Thu", "Fri", "Sat"];
      const last7 = Array.from({ length: CHART_DAYS }, (_, i) => {
        const d = new Date();
        d.setDate(d.getDate() - (CHART_DAYS - 1 - i));
        return d;
      });
      const weeklySales = last7.map((d) => {
        const dateStr = d.toISOString().split("T")[0];
        const daySales = recentSales.filter((s) => s.created_at.startsWith(dateStr));
        return { day: dayNames[d.getDay()], sales: daySales.reduce((sum, s) => sum + Number(s.total_amount), 0) };
      });

      // Sales by store type (from recent sales only)
      const storeTypeSales: Record<string, number> = {};
      recentSales.forEach((s) => {
        const typeName = (s.stores as any)?.store_types?.name || "Other";
        storeTypeSales[typeName] = (storeTypeSales[typeName] || 0) + Number(s.total_amount);
      });
      const totalSalesAmount = Object.values(storeTypeSales).reduce((a, b) => a + b, 0) || 1;
      const storeTypeData = Object.entries(storeTypeSales).map(([name, value], i) => ({
        name,
        value: Math.round((value / totalSalesAmount) * 100),
        color: COLORS[i % COLORS.length],
      }));

      return {
        todayTotal, todayCash, todayUpi, totalOutstanding, overdueStores,
        customerCount: customersRes.count || 0,
        storeCount: allStores.length,
        pendingOrders: ordersRes.data || [],
        weeklySales,
        storeTypeData: storeTypeData.length > 0 ? storeTypeData : [{ name: "No data", value: 100, color: "hsl(220, 13%, 80%)" }],
      };
    },
  });

  if (isLoading) {
    return <DashboardSkeleton />;
  }

  const s = stats!;

  return (
    <div className="space-y-6 animate-fade-in">
      <PageHeader title="Dashboard" subtitle={`Welcome back, ${profile?.full_name || "User"}! Here's your business overview.`} />

      {/* Quick Action Button - Floating (hidden in native APK to avoid BottomNav overlap) */}
      {!isNativeApp() && (
        <div className="fixed bottom-6 right-4 z-50 sm:bottom-8 sm:right-8">
          <QuickActionDrawer />
        </div>
      )}

      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-3 sm:gap-4">
        <StatCard title="Total Sales (Today)" value={`₹${s.todayTotal.toLocaleString()}`} icon={DollarSign} iconColor="primary" />
        <StatCard title="Cash Collected" value={`₹${s.todayCash.toLocaleString()}`} icon={Banknote} iconColor="success" />
        <StatCard title="UPI Collected" value={`₹${s.todayUpi.toLocaleString()}`} icon={Smartphone} iconColor="info" />
        <StatCard title="Pending Outstanding" value={`₹${s.totalOutstanding.toLocaleString()}`} change={`${s.overdueStores} stores with balance`} changeType="negative" icon={Clock} iconColor="warning" />
      </div>

      <div className="grid grid-cols-1 xs:grid-cols-2 sm:grid-cols-4 gap-3 sm:gap-4">
        <StatCard title="Active Customers" value={String(s.customerCount)} icon={Users} iconColor="cyan" />
        <StatCard title="Active Stores" value={String(s.storeCount)} icon={Store} iconColor="purple" />
        <StatCard title="Pending Orders" value={String(s.pendingOrders.length)} icon={ShoppingCart} iconColor="orange" />
        <StatCard title="Store Types" value={String(s.storeTypeData.filter((t) => t.name !== "No data").length)} icon={TrendingUp} iconColor="emerald" />
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-4">
        <div className="lg:col-span-2 rounded-xl border bg-card p-5">
          <h3 className="text-sm font-semibold mb-4">Last 7 Days Sales</h3>
          <ResponsiveContainer width="100%" height={260}>
            <BarChart data={s.weeklySales}>
              <CartesianGrid strokeDasharray="3 3" stroke="hsl(var(--border))" />
              <XAxis dataKey="day" tick={{ fontSize: 12 }} stroke="hsl(var(--muted-foreground))" />
              <YAxis tick={{ fontSize: 12 }} stroke="hsl(var(--muted-foreground))" />
              <Tooltip contentStyle={{ backgroundColor: "hsl(var(--card))", border: "1px solid hsl(var(--border))", borderRadius: "8px", fontSize: "12px" }} />
              <Bar dataKey="sales" fill="hsl(var(--primary))" radius={[6, 6, 0, 0]} />
            </BarChart>
          </ResponsiveContainer>
        </div>

        <div className="rounded-xl border bg-card p-5">
          <h3 className="text-sm font-semibold mb-4">Sales by Store Type</h3>
          <ResponsiveContainer width="100%" height={200}>
            <PieChart>
              <Pie data={s.storeTypeData} cx="50%" cy="50%" innerRadius={50} outerRadius={80} paddingAngle={4} dataKey="value">
                {s.storeTypeData.map((entry, index) => <Cell key={index} fill={entry.color} />)}
              </Pie>
              <Tooltip />
            </PieChart>
          </ResponsiveContainer>
          <div className="mt-2 grid grid-cols-2 gap-2">
            {s.storeTypeData.map((item) => (
              <div key={item.name} className="flex items-center gap-2 text-xs">
                <div className="h-2.5 w-2.5 rounded-full" style={{ backgroundColor: item.color }} />
                <span className="text-muted-foreground">{item.name}</span>
                <span className="font-medium ml-auto">{item.value}%</span>
              </div>
            ))}
          </div>
        </div>
      </div>

      <div className="rounded-xl border bg-card p-5">
        <h3 className="text-sm font-semibold mb-4">Pending Orders</h3>
        {s.pendingOrders.length === 0 ? (
          <p className="text-sm text-muted-foreground text-center py-6">No pending orders</p>
        ) : (
          <div className="space-y-3">
            {s.pendingOrders.map((order: any) => (
              <div key={order.id} className="flex items-center justify-between rounded-lg bg-muted/50 px-4 py-3">
                <div>
                  <p className="text-sm font-medium">{order.stores?.name || "—"}</p>
                  <p className="text-xs text-muted-foreground font-mono">{order.display_id}</p>
                </div>
                <div className="text-right">
                  <p className="text-xs font-medium text-warning">Pending</p>
                  <p className="text-xs text-muted-foreground">{new Date(order.created_at).toLocaleDateString("en-IN")}</p>
                </div>
              </div>
            ))}
          </div>
        )}
      </div>
    </div>
  );
};

export default Dashboard;

import { useState, useMemo } from "react";
import { PageHeader } from "@/components/shared/PageHeader";
import { DataTable } from "@/components/shared/DataTable";
import { Badge } from "@/components/ui/badge";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Textarea } from "@/components/ui/textarea";
import { Card, CardContent } from "@/components/ui/card";
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogDescription } from "@/components/ui/dialog";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { Sheet, SheetContent, SheetHeader, SheetTitle, SheetDescription, SheetTrigger } from "@/components/ui/sheet";
import { ScrollArea } from "@/components/ui/scroll-area";
import { useQuery, useQueryClient } from "@tanstack/react-query";
import { supabase } from "@/integrations/supabase/client";
import { useAuth } from "@/contexts/AuthContext";
import { useFixedCostReminders } from "@/hooks/useFixedCostReminders";
import { 
  Loader2, Receipt, Calendar, TrendingUp, AlertCircle, 
  Users, Truck, Zap, Car, Megaphone, Briefcase, Wrench, MoreHorizontal,
  CheckCircle2, CreditCard, FolderOpen, Tag, Plus
} from "lucide-react";
import { toast } from "sonner";
import { logActivity } from "@/lib/activityLogger";

// Icon map for categories
const categoryIcons: Record<string, any> = {
  'users': Users,
  'truck': Truck,
  'calendar': Calendar,
  'zap': Zap,
  'car': Car,
  'megaphone': Megaphone,
  'briefcase': Briefcase,
  'wrench': Wrench,
  'more-horizontal': MoreHorizontal,
  'receipt': Receipt,
};

const Expenses = () => {
  const { user, role } = useAuth();
  const qc = useQueryClient();
  const isAdmin = role === "super_admin" || role === "manager";

  // Check and send fixed cost reminders
  useFixedCostReminders();

  // Dialog states
  const [showAddExpense, setShowAddExpense] = useState(false);
  const [showAddCategory, setShowAddCategory] = useState(false);
  const [showAddFixedCost, setShowAddFixedCost] = useState(false);
  const [showPayFixedCost, setShowPayFixedCost] = useState(false);
  const [showFixedCostsSheet, setShowFixedCostsSheet] = useState(false);
  const [selectedFixedCost, setSelectedFixedCost] = useState<any>(null);
  const [editingCategory, setEditingCategory] = useState<any>(null);
  const [selectedCategoryFilter, setSelectedCategoryFilter] = useState<string | null>(null);

  // Expense form state
  const [categoryId, setCategoryId] = useState("");
  const [amount, setAmount] = useState("");
  const [expenseDate, setExpenseDate] = useState(new Date().toISOString().split("T")[0]);
  const [description, setDescription] = useState("");
  const [paymentMethod, setPaymentMethod] = useState("cash");
  const [paymentReference, setPaymentReference] = useState("");
  const [notes, setNotes] = useState("");
  const [saving, setSaving] = useState(false);

  // Category form state
  const [catName, setCatName] = useState("");
  const [catDescription, setCatDescription] = useState("");
  const [catColor, setCatColor] = useState("#6366f1");

  // Fixed cost form state
  const [fcName, setFcName] = useState("");
  const [fcDescription, setFcDescription] = useState("");
  const [fcAmount, setFcAmount] = useState("");
  const [fcFrequency, setFcFrequency] = useState("monthly");
  const [fcDueDay, setFcDueDay] = useState("1");
  const [fcReminderDays, setFcReminderDays] = useState("3");
  const [fcVendorName, setFcVendorName] = useState("");

  // Fixed cost payment form
  const [fcPayAmount, setFcPayAmount] = useState("");
  const [fcPayDate, setFcPayDate] = useState(new Date().toISOString().split("T")[0]);
  const [fcPayMethod, setFcPayMethod] = useState("bank_transfer");
  const [fcPayReference, setFcPayReference] = useState("");
  const [fcPayNotes, setFcPayNotes] = useState("");

  // Date filter
  const [dateRange, setDateRange] = useState("month");

  // Fetch categories
  const { data: categories = [] } = useQuery({
    queryKey: ["expense-categories"],
    queryFn: async () => {
      const { data, error } = await supabase
        .from("expense_categories")
        .select("*")
        .eq("is_active", true)
        .order("is_system", { ascending: false })
        .order("name");
      if (error) throw error;
      return data;
    },
  });

  // Fetch expenses
  const { data: expenses = [], isLoading: loadingExpenses } = useQuery({
    queryKey: ["expenses", dateRange],
    queryFn: async () => {
      let query = supabase
        .from("expenses")
        .select("*, expense_categories(name, color, icon)")
        .order("expense_date", { ascending: false });

      // Apply date filter
      const now = new Date();
      if (dateRange === "week") {
        const weekAgo = new Date(now.getTime() - 7 * 24 * 60 * 60 * 1000);
        query = query.gte("expense_date", weekAgo.toISOString().split("T")[0]);
      } else if (dateRange === "month") {
        const monthStart = new Date(now.getFullYear(), now.getMonth(), 1);
        query = query.gte("expense_date", monthStart.toISOString().split("T")[0]);
      } else if (dateRange === "quarter") {
        const quarterStart = new Date(now.getFullYear(), Math.floor(now.getMonth() / 3) * 3, 1);
        query = query.gte("expense_date", quarterStart.toISOString().split("T")[0]);
      } else if (dateRange === "year") {
        const yearStart = new Date(now.getFullYear(), 0, 1);
        query = query.gte("expense_date", yearStart.toISOString().split("T")[0]);
      }

      const { data, error } = await query.limit(500);
      if (error) throw error;
      return data;
    },
  });

  // Fetch fixed costs
  const { data: fixedCosts = [], isLoading: loadingFixedCosts } = useQuery({
    queryKey: ["fixed-costs"],
    queryFn: async () => {
      const { data, error } = await supabase
        .from("fixed_costs")
        .select("*")
        .eq("is_active", true)
        .order("next_due_date");
      if (error) throw error;
      return data;
    },
  });

  // Calculate summary
  const summary = useMemo(() => {
    const total = expenses.reduce((sum, e) => sum + Number(e.amount), 0);
    const byCategory = categories.map((cat) => {
      const catExpenses = expenses.filter((e) => e.category_id === cat.id);
      return {
        ...cat,
        total: catExpenses.reduce((sum, e) => sum + Number(e.amount), 0),
        count: catExpenses.length,
      };
    }).filter(c => c.total > 0).sort((a, b) => b.total - a.total);

    const salaries = expenses.filter(e => e.source_type === 'salary').reduce((sum, e) => sum + Number(e.amount), 0);
    const purchases = expenses.filter(e => e.source_type === 'vendor_payment').reduce((sum, e) => sum + Number(e.amount), 0);
    const fixedCostPayments = expenses.filter(e => e.source_type === 'fixed_cost').reduce((sum, e) => sum + Number(e.amount), 0);
    const manual = expenses.filter(e => e.source_type === 'manual' || !e.source_type).reduce((sum, e) => sum + Number(e.amount), 0);

    return { total, byCategory, salaries, purchases, fixedCostPayments, manual };
  }, [expenses, categories]);

  // Fixed costs due soon
  const fixedCostsDue = useMemo(() => {
    const today = new Date();
    return fixedCosts.map(fc => {
      const dueDate = new Date(fc.next_due_date);
      const daysUntil = Math.ceil((dueDate.getTime() - today.getTime()) / (1000 * 60 * 60 * 24));
      return {
        ...fc,
        daysUntil,
        status: daysUntil < 0 ? 'overdue' : daysUntil <= 3 ? 'due_soon' : 'upcoming'
      };
    });
  }, [fixedCosts]);

  // Handlers
  const resetExpenseForm = () => {
    setCategoryId("");
    setAmount("");
    setExpenseDate(new Date().toISOString().split("T")[0]);
    setDescription("");
    setPaymentMethod("cash");
    setPaymentReference("");
    setNotes("");
  };

  const handleAddExpense = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!categoryId || !amount) {
      toast.error("Category and amount are required");
      return;
    }
    setSaving(true);

    try {
      const { data: idData } = await supabase.rpc("generate_display_id", {
        prefix: "EXP",
        seq_name: "expenses_display_id_seq"
      });

      const { error } = await supabase.from("expenses").insert({
        display_id: idData,
        category_id: categoryId,
        amount: parseFloat(amount),
        expense_date: expenseDate,
        description: description.trim() || null,
        payment_method: paymentMethod,
        payment_reference: paymentReference.trim() || null,
        source_type: "manual",
        notes: notes.trim() || null,
        created_by: user!.id,
      });

      if (error) throw error;

      toast.success("Expense recorded");
      logActivity(user!.id, `Recorded expense ${idData}`, "expense");
      qc.invalidateQueries({ queryKey: ["expenses"] });
      setShowAddExpense(false);
      resetExpenseForm();
    } catch (error: any) {
      toast.error(error.message || "Failed to record expense");
    } finally {
      setSaving(false);
    }
  };

  const handleAddCategory = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!catName.trim()) {
      toast.error("Category name is required");
      return;
    }
    setSaving(true);

    try {
      if (editingCategory) {
        const { error } = await supabase.from("expense_categories")
          .update({ name: catName.trim(), description: catDescription.trim() || null, color: catColor })
          .eq("id", editingCategory.id);
        if (error) throw error;
        toast.success("Category updated");
      } else {
        const { error } = await supabase.from("expense_categories").insert({
          name: catName.trim(),
          description: catDescription.trim() || null,
          color: catColor,
        });
        if (error) throw error;
        toast.success("Category added");
      }
      qc.invalidateQueries({ queryKey: ["expense-categories"] });
      setShowAddCategory(false);
      setEditingCategory(null);
      setCatName("");
      setCatDescription("");
      setCatColor("#6366f1");
    } catch (error: any) {
      toast.error(error.message || "Failed to save category");
    } finally {
      setSaving(false);
    }
  };

  const handleAddFixedCost = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!fcName.trim() || !fcAmount) {
      toast.error("Name and amount are required");
      return;
    }
    setSaving(true);

    try {
      const { data: idData } = await supabase.rpc("generate_display_id", {
        prefix: "FC",
        seq_name: "fixed_costs_display_id_seq"
      });

      // Calculate initial next due date
      const today = new Date();
      let nextDue: Date;
      const dueDay = parseInt(fcDueDay);
      
      if (fcFrequency === "monthly") {
        nextDue = new Date(today.getFullYear(), today.getMonth(), dueDay);
        if (nextDue <= today) {
          nextDue = new Date(today.getFullYear(), today.getMonth() + 1, dueDay);
        }
      } else if (fcFrequency === "weekly") {
        nextDue = new Date(today.getTime() + (7 - today.getDay() + dueDay) % 7 * 24 * 60 * 60 * 1000);
      } else if (fcFrequency === "quarterly") {
        const currentQuarter = Math.floor(today.getMonth() / 3);
        nextDue = new Date(today.getFullYear(), currentQuarter * 3 + 3, dueDay);
      } else {
        nextDue = new Date(today.getFullYear() + 1, 0, dueDay);
      }

      const { error } = await supabase.from("fixed_costs").insert({
        display_id: idData,
        name: fcName.trim(),
        description: fcDescription.trim() || null,
        amount: parseFloat(fcAmount),
        frequency: fcFrequency,
        due_day: parseInt(fcDueDay),
        next_due_date: nextDue.toISOString().split("T")[0],
        reminder_days_before: parseInt(fcReminderDays),
        vendor_name: fcVendorName.trim() || null,
        created_by: user!.id,
      });

      if (error) throw error;

      toast.success("Fixed cost added");
      logActivity(user!.id, `Added fixed cost: ${fcName}`, "fixed_cost");
      qc.invalidateQueries({ queryKey: ["fixed-costs"] });
      setShowAddFixedCost(false);
      setFcName("");
      setFcDescription("");
      setFcAmount("");
      setFcFrequency("monthly");
      setFcDueDay("1");
      setFcReminderDays("3");
      setFcVendorName("");
    } catch (error: any) {
      toast.error(error.message || "Failed to add fixed cost");
    } finally {
      setSaving(false);
    }
  };

  const handlePayFixedCost = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!selectedFixedCost || !fcPayAmount) {
      toast.error("Amount is required");
      return;
    }
    setSaving(true);

    try {
      const { data: idData } = await supabase.rpc("generate_display_id", {
        prefix: "FCP",
        seq_name: "fixed_cost_payments_display_id_seq"
      });

      const { error } = await supabase.from("fixed_cost_payments").insert({
        display_id: idData,
        fixed_cost_id: selectedFixedCost.id,
        amount: parseFloat(fcPayAmount),
        payment_date: fcPayDate,
        payment_method: fcPayMethod,
        payment_reference: fcPayReference.trim() || null,
        notes: fcPayNotes.trim() || null,
        created_by: user!.id,
      });

      if (error) throw error;

      toast.success("Payment recorded");
      logActivity(user!.id, `Paid fixed cost: ${selectedFixedCost.name}`, "fixed_cost_payment");
      qc.invalidateQueries({ queryKey: ["fixed-costs"] });
      qc.invalidateQueries({ queryKey: ["expenses"] });
      setShowPayFixedCost(false);
      setSelectedFixedCost(null);
      setFcPayAmount("");
      setFcPayDate(new Date().toISOString().split("T")[0]);
      setFcPayMethod("bank_transfer");
      setFcPayReference("");
      setFcPayNotes("");
    } catch (error: any) {
      toast.error(error.message || "Failed to record payment");
    } finally {
      setSaving(false);
    }
  };

  const openPayFixedCost = (fc: any) => {
    setSelectedFixedCost(fc);
    setFcPayAmount(String(fc.amount));
    setShowPayFixedCost(true);
  };

  // Filter expenses by selected category
  const filteredExpenses = useMemo(() => {
    if (!selectedCategoryFilter) return expenses;
    return expenses.filter((e) => e.category_id === selectedCategoryFilter);
  }, [expenses, selectedCategoryFilter]);

  // Calculate category totals for the sidebar
  const categoriesWithTotals = useMemo(() => {
    return categories.map((cat) => {
      const catExpenses = expenses.filter((e) => e.category_id === cat.id);
      return {
        ...cat,
        total: catExpenses.reduce((sum, e) => sum + Number(e.amount), 0),
        count: catExpenses.length,
      };
    });
  }, [expenses, categories]);

  // Table columns
  const expenseColumns = [
    { header: "ID", accessor: "display_id" as const, className: "font-mono text-xs" },
    { header: "Date", accessor: (row: any) => new Date(row.expense_date).toLocaleDateString("en-IN"), className: "text-sm" },
    { 
      header: "Category", 
      accessor: (row: any) => {
        const IconComponent = categoryIcons[row.expense_categories?.icon] || Receipt;
        return (
          <div className="flex items-center gap-2">
            <div 
              className="w-6 h-6 rounded flex items-center justify-center" 
              style={{ backgroundColor: row.expense_categories?.color + '20' }}
            >
              <IconComponent className="h-3.5 w-3.5" style={{ color: row.expense_categories?.color }} />
            </div>
            <span className="text-sm">{row.expense_categories?.name || "—"}</span>
          </div>
        );
      }
    },
    { header: "Description", accessor: (row: any) => row.description || "—", className: "text-sm truncate max-w-[200px]" },
    { 
      header: "Source", 
      accessor: (row: any) => {
        const sourceLabels: Record<string, string> = {
          manual: "Manual",
          salary: "Salary",
          vendor_payment: "Purchase",
          fixed_cost: "Fixed Cost"
        };
        return <Badge variant="outline" className="text-xs">{sourceLabels[row.source_type] || "Manual"}</Badge>;
      }
    },
    { header: "Amount", accessor: (row: any) => `₹${Number(row.amount).toLocaleString()}`, className: "font-semibold text-right" },
  ];

  // Category sidebar component (reusable for desktop and sheet)
  const CategorySidebar = () => (
    <div className="space-y-3">
      <div className="flex items-center justify-between">
        <h3 className="font-semibold text-sm uppercase tracking-wider text-muted-foreground">Categories</h3>
        <Button variant="ghost" size="icon" className="h-7 w-7" onClick={() => setShowAddCategory(true)}>
          <Plus className="h-4 w-4" />
        </Button>
      </div>
      
      {/* All categories button */}
      <button
        onClick={() => setSelectedCategoryFilter(null)}
        className={`w-full flex items-center gap-3 p-3 rounded-lg border transition-all text-left ${
          selectedCategoryFilter === null 
            ? 'bg-primary/10 border-primary/30' 
            : 'bg-background hover:bg-muted border-transparent'
        }`}
      >
        <div className="w-9 h-9 rounded-lg bg-gradient-to-br from-primary/20 to-primary/10 flex items-center justify-center">
          <FolderOpen className="h-4 w-4 text-primary" />
        </div>
        <div className="flex-1 min-w-0">
          <p className="font-medium text-sm">All Expenses</p>
          <p className="text-xs text-muted-foreground">{expenses.length} entries</p>
        </div>
        <span className="text-sm font-semibold">₹{summary.total.toLocaleString()}</span>
      </button>

      <div className="h-px bg-border my-2" />

      {/* Category list */}
      <ScrollArea className="h-[calc(100vh-400px)] lg:h-auto lg:max-h-[500px]">
        <div className="space-y-2 pr-2">
          {categoriesWithTotals.map((cat) => {
            const IconComponent = categoryIcons[cat.icon] || Receipt;
            const isSelected = selectedCategoryFilter === cat.id;
            return (
              <button
                key={cat.id}
                onClick={() => setSelectedCategoryFilter(isSelected ? null : cat.id)}
                className={`w-full flex items-center gap-3 p-3 rounded-lg border transition-all text-left ${
                  isSelected 
                    ? 'bg-primary/10 border-primary/30' 
                    : 'bg-background hover:bg-muted border-transparent'
                }`}
              >
                <div 
                  className="w-9 h-9 rounded-lg flex items-center justify-center"
                  style={{ backgroundColor: cat.color + '20' }}
                >
                  <IconComponent className="h-4 w-4" style={{ color: cat.color }} />
                </div>
                <div className="flex-1 min-w-0">
                  <p className="font-medium text-sm truncate">{cat.name}</p>
                  <p className="text-xs text-muted-foreground">{cat.count} expense{cat.count !== 1 ? 's' : ''}</p>
                </div>
                {cat.total > 0 && (
                  <span className="text-sm font-semibold">₹{cat.total.toLocaleString()}</span>
                )}
                {cat.is_system && (
                  <Badge variant="secondary" className="text-[10px] px-1.5">System</Badge>
                )}
              </button>
            );
          })}
        </div>
      </ScrollArea>
    </div>
  );

  // Fixed costs sidebar component (for sheet)
  const FixedCostsSidebar = () => (
    <div className="space-y-4">
      <div className="flex items-center justify-between">
        <h3 className="font-semibold">Fixed Costs</h3>
        <Button size="sm" onClick={() => { setShowFixedCostsSheet(false); setShowAddFixedCost(true); }}>
          <Plus className="h-4 w-4 mr-1" /> Add
        </Button>
      </div>

      {loadingFixedCosts ? (
        <div className="flex justify-center py-8">
          <Loader2 className="h-6 w-6 animate-spin" />
        </div>
      ) : fixedCostsDue.length === 0 ? (
        <div className="text-center py-8 text-muted-foreground">
          <Calendar className="h-10 w-10 mx-auto mb-2 opacity-50" />
          <p>No fixed costs configured</p>
          <p className="text-sm">Add recurring expenses like rent, utilities, etc.</p>
        </div>
      ) : (
        <ScrollArea className="h-[calc(100vh-200px)]">
          <div className="space-y-3 pr-2">
            {fixedCostsDue.map((fc) => (
              <Card key={fc.id} className={`relative overflow-hidden ${fc.status === 'overdue' ? 'border-red-300 bg-red-50/50' : fc.status === 'due_soon' ? 'border-amber-300 bg-amber-50/50' : ''}`}>
                {fc.status === 'overdue' && (
                  <div className="absolute top-0 right-0 bg-red-500 text-white text-[10px] px-2 py-0.5 rounded-bl font-medium">
                    OVERDUE
                  </div>
                )}
                {fc.status === 'due_soon' && (
                  <div className="absolute top-0 right-0 bg-amber-500 text-white text-[10px] px-2 py-0.5 rounded-bl font-medium">
                    DUE SOON
                  </div>
                )}
                <CardContent className="p-4">
                  <div className="flex items-start justify-between">
                    <div>
                      <h4 className="font-semibold text-sm">{fc.name}</h4>
                      <p className="text-xs text-muted-foreground mt-0.5">{fc.description || fc.vendor_name || '—'}</p>
                    </div>
                    <Badge variant="outline" className="capitalize text-[10px]">{fc.frequency}</Badge>
                  </div>
                  
                  <div className="mt-3 space-y-1.5 text-sm">
                    <div className="flex justify-between">
                      <span className="text-muted-foreground">Amount</span>
                      <span className="font-semibold">₹{Number(fc.amount).toLocaleString()}</span>
                    </div>
                    <div className="flex justify-between">
                      <span className="text-muted-foreground">Next Due</span>
                      <span className={fc.status === 'overdue' ? 'text-red-600 font-medium' : fc.status === 'due_soon' ? 'text-amber-600 font-medium' : ''}>
                        {new Date(fc.next_due_date).toLocaleDateString("en-IN")}
                      </span>
                    </div>
                  </div>

                  <Button size="sm" className="w-full mt-3" variant={fc.status === 'overdue' ? 'destructive' : 'default'} onClick={() => { setShowFixedCostsSheet(false); openPayFixedCost(fc); }}>
                    <CreditCard className="h-4 w-4 mr-1" /> Record Payment
                  </Button>
                </CardContent>
              </Card>
            ))}
          </div>
        </ScrollArea>
      )}
    </div>
  );

  return (
    <div className="space-y-6 animate-fade-in">
      <PageHeader
        title="Expenses"
        subtitle="Track and manage all business expenses"
        action={isAdmin ? (
          <div className="flex gap-2 flex-wrap">
            <Button variant="outline" onClick={() => setShowAddCategory(true)}>
              <Tag className="h-4 w-4 mr-2" /> Create Category
            </Button>
            <Button variant="outline" onClick={() => setShowAddFixedCost(true)}>
              <Calendar className="h-4 w-4 mr-2" /> Add Fixed Cost
            </Button>
            <Button onClick={() => setShowAddExpense(true)}>
              <Receipt className="h-4 w-4 mr-2" /> Record Expense
            </Button>
          </div>
        ) : (
          <Button onClick={() => setShowAddExpense(true)}>
            <Receipt className="h-4 w-4 mr-2" /> Record Expense
          </Button>
        )}
      />

      {/* Summary Cards */}
      <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
        <Card>
          <CardContent className="p-4">
            <div className="flex items-center justify-between">
              <div>
                <p className="text-xs text-muted-foreground uppercase tracking-wider">Total Expenses</p>
                <p className="text-2xl font-bold mt-1">₹{summary.total.toLocaleString()}</p>
              </div>
              <div className="h-10 w-10 rounded-full bg-red-100 flex items-center justify-center">
                <TrendingUp className="h-5 w-5 text-red-600" />
              </div>
            </div>
          </CardContent>
        </Card>
        
        <Card>
          <CardContent className="p-4">
            <div className="flex items-center justify-between">
              <div>
                <p className="text-xs text-muted-foreground uppercase tracking-wider">Salaries</p>
                <p className="text-2xl font-bold mt-1">₹{summary.salaries.toLocaleString()}</p>
              </div>
              <div className="h-10 w-10 rounded-full bg-green-100 flex items-center justify-center">
                <Users className="h-5 w-5 text-green-600" />
              </div>
            </div>
          </CardContent>
        </Card>

        <Card>
          <CardContent className="p-4">
            <div className="flex items-center justify-between">
              <div>
                <p className="text-xs text-muted-foreground uppercase tracking-wider">Purchases</p>
                <p className="text-2xl font-bold mt-1">₹{summary.purchases.toLocaleString()}</p>
              </div>
              <div className="h-10 w-10 rounded-full bg-amber-100 flex items-center justify-center">
                <Truck className="h-5 w-5 text-amber-600" />
              </div>
            </div>
          </CardContent>
        </Card>

        <Card>
          <CardContent className="p-4">
            <div className="flex items-center justify-between">
              <div>
                <p className="text-xs text-muted-foreground uppercase tracking-wider">Fixed Costs</p>
                <p className="text-2xl font-bold mt-1">₹{summary.fixedCostPayments.toLocaleString()}</p>
              </div>
              <div className="h-10 w-10 rounded-full bg-blue-100 flex items-center justify-center">
                <Calendar className="h-5 w-5 text-blue-600" />
              </div>
            </div>
          </CardContent>
        </Card>
      </div>

      {/* Fixed Costs Due Soon Alert */}
      {fixedCostsDue.filter(fc => fc.status === 'overdue' || fc.status === 'due_soon').length > 0 && (
        <Card className="border-amber-200 bg-amber-50/50">
          <CardContent className="p-4">
            <div className="flex items-start gap-3">
              <AlertCircle className="h-5 w-5 text-amber-600 mt-0.5" />
              <div className="flex-1">
                <h4 className="font-semibold text-amber-800">Fixed Costs Due Soon</h4>
                <div className="mt-2 space-y-2">
                  {fixedCostsDue.filter(fc => fc.status === 'overdue' || fc.status === 'due_soon').map((fc) => (
                    <div key={fc.id} className="flex items-center justify-between bg-white rounded-lg p-3 border">
                      <div>
                        <p className="font-medium">{fc.name}</p>
                        <p className="text-sm text-muted-foreground">
                          {fc.status === 'overdue' ? (
                            <span className="text-red-600 font-medium">Overdue by {Math.abs(fc.daysUntil)} days</span>
                          ) : (
                            <span>Due in {fc.daysUntil} day{fc.daysUntil !== 1 ? 's' : ''}</span>
                          )}
                          {' • '}₹{Number(fc.amount).toLocaleString()}
                        </p>
                      </div>
                      <Button size="sm" onClick={() => openPayFixedCost(fc)}>
                        <CreditCard className="h-4 w-4 mr-1" /> Pay Now
                      </Button>
                    </div>
                  ))}
                </div>
              </div>
            </div>
          </CardContent>
        </Card>
      )}

      {/* Main content with categories sidebar for desktop */}
      <div className="flex gap-6">
        {/* Categories sidebar - visible on large screens */}
        <Card className="hidden lg:block w-80 shrink-0 h-fit sticky top-6">
          <CardContent className="p-4">
            <CategorySidebar />
          </CardContent>
        </Card>

        {/* Main expenses table */}
        <div className="flex-1 min-w-0">
          {/* Date filter and category sheet trigger for mobile/tablet */}
          <div className="flex items-center justify-between mb-4 gap-4 flex-wrap">
            {/* Mobile: Categories Sheet */}
            <Sheet>
              <SheetTrigger asChild>
                <Button variant="outline" className="lg:hidden">
                  <Tag className="h-4 w-4 mr-2" />
                  {selectedCategoryFilter 
                    ? categoriesWithTotals.find(c => c.id === selectedCategoryFilter)?.name || 'Category'
                    : 'All Categories'
                  }
                </Button>
              </SheetTrigger>
              <SheetContent side="left" className="w-80">
                <SheetHeader>
                  <SheetTitle>Filter by Category</SheetTitle>
                  <SheetDescription>Select a category to filter expenses</SheetDescription>
                </SheetHeader>
                <div className="mt-4">
                  <CategorySidebar />
                </div>
              </SheetContent>
            </Sheet>

            <div className="flex items-center gap-2 ml-auto">
              {/* Fixed Costs Sheet */}
              <Sheet open={showFixedCostsSheet} onOpenChange={setShowFixedCostsSheet}>
                <SheetTrigger asChild>
                  <Button variant="outline" size="sm">
                    <Calendar className="h-4 w-4 mr-2" />
                    Fixed Costs
                    {fixedCostsDue.filter(fc => fc.status === 'overdue' || fc.status === 'due_soon').length > 0 && (
                      <Badge variant="destructive" className="ml-2 h-5 w-5 p-0 justify-center rounded-full">
                        {fixedCostsDue.filter(fc => fc.status === 'overdue' || fc.status === 'due_soon').length}
                      </Badge>
                    )}
                  </Button>
                </SheetTrigger>
                <SheetContent side="right" className="w-96">
                  <SheetHeader>
                    <SheetTitle>Fixed Costs</SheetTitle>
                    <SheetDescription>Manage recurring expenses</SheetDescription>
                  </SheetHeader>
                  <div className="mt-4">
                    <FixedCostsSidebar />
                  </div>
                </SheetContent>
              </Sheet>

              <Select value={dateRange} onValueChange={setDateRange}>
                <SelectTrigger className="w-[140px]">
                  <SelectValue />
                </SelectTrigger>
                <SelectContent>
                  <SelectItem value="week">This Week</SelectItem>
                  <SelectItem value="month">This Month</SelectItem>
                  <SelectItem value="quarter">This Quarter</SelectItem>
                  <SelectItem value="year">This Year</SelectItem>
                  <SelectItem value="all">All Time</SelectItem>
                </SelectContent>
              </Select>
            </div>
          </div>

          {/* Category filter badge */}
          {selectedCategoryFilter && (
            <div className="flex items-center gap-2 mb-4">
              <span className="text-sm text-muted-foreground">Filtered by:</span>
              <Badge 
                variant="secondary" 
                className="gap-1 pr-1"
                style={{ 
                  backgroundColor: (categoriesWithTotals.find(c => c.id === selectedCategoryFilter)?.color || '#6366f1') + '20',
                  color: categoriesWithTotals.find(c => c.id === selectedCategoryFilter)?.color || '#6366f1'
                }}
              >
                {categoriesWithTotals.find(c => c.id === selectedCategoryFilter)?.name}
                <Button 
                  variant="ghost" 
                  size="icon" 
                  className="h-4 w-4 ml-1 hover:bg-transparent" 
                  onClick={() => setSelectedCategoryFilter(null)}
                >
                  <span className="text-lg leading-none">&times;</span>
                </Button>
              </Badge>
            </div>
          )}

          {/* Expenses table */}
          {loadingExpenses ? (
            <div className="flex items-center justify-center py-12">
              <Loader2 className="h-8 w-8 animate-spin text-primary" />
            </div>
          ) : (
            <DataTable
              columns={expenseColumns}
              data={filteredExpenses}
              searchKey="description"
              searchPlaceholder="Search expenses..."
            />
          )}
        </div>
      </div>

      {/* Add Expense Dialog */}
      <Dialog open={showAddExpense} onOpenChange={setShowAddExpense}>
        <DialogContent className="max-w-lg">
          <DialogHeader>
            <DialogTitle>Record Expense</DialogTitle>
            <DialogDescription>Add a new expense entry to track your spending.</DialogDescription>
          </DialogHeader>
          <form onSubmit={handleAddExpense} className="space-y-4">
            <div className="grid grid-cols-2 gap-4">
              <div>
                <Label>Category *</Label>
                <Select value={categoryId} onValueChange={setCategoryId}>
                  <SelectTrigger className="mt-1">
                    <SelectValue placeholder="Select category" />
                  </SelectTrigger>
                  <SelectContent>
                    {categories.filter(c => !c.is_system).map((cat) => (
                      <SelectItem key={cat.id} value={cat.id}>
                        <div className="flex items-center gap-2">
                          <div className="w-3 h-3 rounded" style={{ backgroundColor: cat.color }} />
                          {cat.name}
                        </div>
                      </SelectItem>
                    ))}
                  </SelectContent>
                </Select>
              </div>
              <div>
                <Label>Amount (₹) *</Label>
                <Input
                  type="number"
                  min="0"
                  step="0.01"
                  value={amount}
                  onChange={(e) => setAmount(e.target.value)}
                  placeholder="0.00"
                  className="mt-1"
                  required
                />
              </div>
            </div>
            <div className="grid grid-cols-2 gap-4">
              <div>
                <Label>Date</Label>
                <Input
                  type="date"
                  value={expenseDate}
                  onChange={(e) => setExpenseDate(e.target.value)}
                  className="mt-1"
                />
              </div>
              <div>
                <Label>Payment Method</Label>
                <Select value={paymentMethod} onValueChange={setPaymentMethod}>
                  <SelectTrigger className="mt-1">
                    <SelectValue />
                  </SelectTrigger>
                  <SelectContent>
                    <SelectItem value="cash">Cash</SelectItem>
                    <SelectItem value="bank_transfer">Bank Transfer</SelectItem>
                    <SelectItem value="upi">UPI</SelectItem>
                    <SelectItem value="cheque">Cheque</SelectItem>
                    <SelectItem value="card">Card</SelectItem>
                    <SelectItem value="other">Other</SelectItem>
                  </SelectContent>
                </Select>
              </div>
            </div>
            <div>
              <Label>Description</Label>
              <Input
                value={description}
                onChange={(e) => setDescription(e.target.value)}
                placeholder="What was this expense for?"
                className="mt-1"
              />
            </div>
            <div>
              <Label>Payment Reference</Label>
              <Input
                value={paymentReference}
                onChange={(e) => setPaymentReference(e.target.value)}
                placeholder="Transaction ID, cheque number, etc."
                className="mt-1"
              />
            </div>
            <div>
              <Label>Notes</Label>
              <Textarea
                value={notes}
                onChange={(e) => setNotes(e.target.value)}
                placeholder="Additional notes..."
                className="mt-1"
                rows={2}
              />
            </div>
            <Button type="submit" className="w-full" disabled={saving}>
              {saving ? <Loader2 className="mr-2 h-4 w-4 animate-spin" /> : <Receipt className="mr-2 h-4 w-4" />}
              Record Expense
            </Button>
          </form>
        </DialogContent>
      </Dialog>

      {/* Add Category Dialog */}
      <Dialog open={showAddCategory} onOpenChange={(open) => { setShowAddCategory(open); if (!open) setEditingCategory(null); }}>
        <DialogContent>
          <DialogHeader>
            <DialogTitle>{editingCategory ? "Edit Category" : "Add Category"}</DialogTitle>
            <DialogDescription>Create expense categories to organize your spending.</DialogDescription>
          </DialogHeader>
          <form onSubmit={handleAddCategory} className="space-y-4">
            <div>
              <Label>Name *</Label>
              <Input
                value={catName}
                onChange={(e) => setCatName(e.target.value)}
                placeholder="e.g., Office Rent"
                className="mt-1"
                required
              />
            </div>
            <div>
              <Label>Description</Label>
              <Input
                value={catDescription}
                onChange={(e) => setCatDescription(e.target.value)}
                placeholder="Brief description"
                className="mt-1"
              />
            </div>
            <div>
              <Label>Color</Label>
              <div className="flex items-center gap-2 mt-1">
                <input
                  type="color"
                  value={catColor}
                  onChange={(e) => setCatColor(e.target.value)}
                  className="w-12 h-10 rounded border cursor-pointer"
                />
                <Input
                  value={catColor}
                  onChange={(e) => setCatColor(e.target.value)}
                  placeholder="#6366f1"
                  className="font-mono"
                />
              </div>
            </div>
            <Button type="submit" className="w-full" disabled={saving}>
              {saving ? <Loader2 className="mr-2 h-4 w-4 animate-spin" /> : null}
              {editingCategory ? "Update Category" : "Add Category"}
            </Button>
          </form>
        </DialogContent>
      </Dialog>

      {/* Add Fixed Cost Dialog */}
      <Dialog open={showAddFixedCost} onOpenChange={setShowAddFixedCost}>
        <DialogContent className="max-w-lg">
          <DialogHeader>
            <DialogTitle>Add Fixed Cost</DialogTitle>
            <DialogDescription>Set up recurring expenses like rent, utilities, subscriptions, etc.</DialogDescription>
          </DialogHeader>
          <form onSubmit={handleAddFixedCost} className="space-y-4">
            <div className="grid grid-cols-2 gap-4">
              <div className="col-span-2">
                <Label>Name *</Label>
                <Input
                  value={fcName}
                  onChange={(e) => setFcName(e.target.value)}
                  placeholder="e.g., Office Rent"
                  className="mt-1"
                  required
                />
              </div>
              <div className="col-span-2">
                <Label>Description</Label>
                <Input
                  value={fcDescription}
                  onChange={(e) => setFcDescription(e.target.value)}
                  placeholder="Brief description"
                  className="mt-1"
                />
              </div>
              <div>
                <Label>Amount (₹) *</Label>
                <Input
                  type="number"
                  min="0"
                  step="0.01"
                  value={fcAmount}
                  onChange={(e) => setFcAmount(e.target.value)}
                  placeholder="0.00"
                  className="mt-1"
                  required
                />
              </div>
              <div>
                <Label>Frequency</Label>
                <Select value={fcFrequency} onValueChange={setFcFrequency}>
                  <SelectTrigger className="mt-1">
                    <SelectValue />
                  </SelectTrigger>
                  <SelectContent>
                    <SelectItem value="weekly">Weekly</SelectItem>
                    <SelectItem value="monthly">Monthly</SelectItem>
                    <SelectItem value="quarterly">Quarterly</SelectItem>
                    <SelectItem value="yearly">Yearly</SelectItem>
                  </SelectContent>
                </Select>
              </div>
              <div>
                <Label>Due Day</Label>
                <Input
                  type="number"
                  min="1"
                  max="31"
                  value={fcDueDay}
                  onChange={(e) => setFcDueDay(e.target.value)}
                  className="mt-1"
                />
                <p className="text-xs text-muted-foreground mt-1">Day of month (1-31)</p>
              </div>
              <div>
                <Label>Remind Before</Label>
                <Select value={fcReminderDays} onValueChange={setFcReminderDays}>
                  <SelectTrigger className="mt-1">
                    <SelectValue />
                  </SelectTrigger>
                  <SelectContent>
                    <SelectItem value="1">1 day</SelectItem>
                    <SelectItem value="3">3 days</SelectItem>
                    <SelectItem value="5">5 days</SelectItem>
                    <SelectItem value="7">7 days</SelectItem>
                  </SelectContent>
                </Select>
              </div>
              <div className="col-span-2">
                <Label>Payee / Vendor</Label>
                <Input
                  value={fcVendorName}
                  onChange={(e) => setFcVendorName(e.target.value)}
                  placeholder="Who receives this payment?"
                  className="mt-1"
                />
              </div>
            </div>
            <Button type="submit" className="w-full" disabled={saving}>
              {saving ? <Loader2 className="mr-2 h-4 w-4 animate-spin" /> : <Calendar className="mr-2 h-4 w-4" />}
              Add Fixed Cost
            </Button>
          </form>
        </DialogContent>
      </Dialog>

      {/* Pay Fixed Cost Dialog */}
      <Dialog open={showPayFixedCost} onOpenChange={setShowPayFixedCost}>
        <DialogContent>
          <DialogHeader>
            <DialogTitle>Record Payment</DialogTitle>
            <DialogDescription>
              {selectedFixedCost && `Record payment for ${selectedFixedCost.name}`}
            </DialogDescription>
          </DialogHeader>
          {selectedFixedCost && (
            <form onSubmit={handlePayFixedCost} className="space-y-4">
              <Card className="bg-muted/50">
                <CardContent className="p-3">
                  <div className="flex justify-between text-sm">
                    <span>Expected Amount</span>
                    <span className="font-semibold">₹{Number(selectedFixedCost.amount).toLocaleString()}</span>
                  </div>
                  <div className="flex justify-between text-sm mt-1">
                    <span>Due Date</span>
                    <span>{new Date(selectedFixedCost.next_due_date).toLocaleDateString("en-IN")}</span>
                  </div>
                </CardContent>
              </Card>
              <div className="grid grid-cols-2 gap-4">
                <div>
                  <Label>Amount (₹) *</Label>
                  <Input
                    type="number"
                    min="0"
                    step="0.01"
                    value={fcPayAmount}
                    onChange={(e) => setFcPayAmount(e.target.value)}
                    className="mt-1"
                    required
                  />
                </div>
                <div>
                  <Label>Payment Date</Label>
                  <Input
                    type="date"
                    value={fcPayDate}
                    onChange={(e) => setFcPayDate(e.target.value)}
                    className="mt-1"
                  />
                </div>
              </div>
              <div className="grid grid-cols-2 gap-4">
                <div>
                  <Label>Payment Method</Label>
                  <Select value={fcPayMethod} onValueChange={setFcPayMethod}>
                    <SelectTrigger className="mt-1">
                      <SelectValue />
                    </SelectTrigger>
                    <SelectContent>
                      <SelectItem value="cash">Cash</SelectItem>
                      <SelectItem value="bank_transfer">Bank Transfer</SelectItem>
                      <SelectItem value="upi">UPI</SelectItem>
                      <SelectItem value="cheque">Cheque</SelectItem>
                      <SelectItem value="card">Card</SelectItem>
                      <SelectItem value="other">Other</SelectItem>
                    </SelectContent>
                  </Select>
                </div>
                <div>
                  <Label>Reference</Label>
                  <Input
                    value={fcPayReference}
                    onChange={(e) => setFcPayReference(e.target.value)}
                    placeholder="Transaction ID"
                    className="mt-1"
                  />
                </div>
              </div>
              <div>
                <Label>Notes</Label>
                <Textarea
                  value={fcPayNotes}
                  onChange={(e) => setFcPayNotes(e.target.value)}
                  placeholder="Additional notes..."
                  className="mt-1"
                  rows={2}
                />
              </div>
              <Button type="submit" className="w-full" disabled={saving}>
                {saving ? <Loader2 className="mr-2 h-4 w-4 animate-spin" /> : <CheckCircle2 className="mr-2 h-4 w-4" />}
                Record Payment
              </Button>
            </form>
          )}
        </DialogContent>
      </Dialog>
    </div>
  );
};

export default Expenses;

import { PageHeader } from "@/components/shared/PageHeader";
import { StatusBadge } from "@/components/shared/StatusBadge";
import { ImageUpload } from "@/components/shared/ImageUpload";
import {
  Banknote, CheckCircle, Clock, AlertCircle, Loader2, Send,
  ArrowDownLeft, XCircle, User, ChevronDown, Users, ShoppingCart, Wallet, Eye,
  Receipt, Tag, FileText, Edit2, Image
} from "lucide-react";
import { useQuery, useQueryClient } from "@tanstack/react-query";
import { supabase } from "@/integrations/supabase/client";
import { useAuth } from "@/contexts/AuthContext";
import { usePermission } from "@/hooks/usePermission";
import { Button } from "@/components/ui/button";
import { Avatar, AvatarFallback, AvatarImage } from "@/components/ui/avatar";
import { Input } from "@/components/ui/input";
import { Textarea } from "@/components/ui/textarea";
import { Label } from "@/components/ui/label";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogDescription, DialogFooter } from "@/components/ui/dialog";
import { Popover, PopoverContent, PopoverTrigger } from "@/components/ui/popover";
import { toast } from "sonner";
import { sendNotification, sendNotificationToMany, getAdminUserIds } from "@/lib/notifications";
import { useState, useMemo } from "react";
import { Tabs, TabsContent, TabsList, TabsTrigger } from "@/components/ui/tabs";
import { format, startOfDay } from "date-fns";

const Handovers = () => {
  const { user, role } = useAuth();
  const qc = useQueryClient();
  const [createOpen, setCreateOpen] = useState(false);
  const [amount, setAmount] = useState("");
  const [notes, setNotes] = useState("");
  const [toUserId, setToUserId] = useState("");
  const [submitting, setSubmitting] = useState(false);
  const [actionLoading, setActionLoading] = useState<string | null>(null);
  const [cancelConfirmId, setCancelConfirmId] = useState<string | null>(null);

  // Expense claim states
  const [expenseOpen, setExpenseOpen] = useState(false);
  const [expenseAmount, setExpenseAmount] = useState("");
  const [expenseDescription, setExpenseDescription] = useState("");
  const [expenseCategory, setExpenseCategory] = useState("");
  const [expenseDate, setExpenseDate] = useState(new Date().toISOString().split("T")[0]);
  const [expenseReceiptUrl, setExpenseReceiptUrl] = useState<string | null>(null);
  const [expenseSubmitting, setExpenseSubmitting] = useState(false);
  
  // Expense review states
  const [reviewExpense, setReviewExpense] = useState<any>(null);
  const [reviewCategory, setReviewCategory] = useState("");
  const [reviewAmount, setReviewAmount] = useState("");
  const [reviewNotes, setReviewNotes] = useState("");

  const isAdminOrManager = role === "super_admin" || role === "manager";
  const { allowed: isFinalizer } = usePermission("finalizer");
  const { allowed: canSeeBalances } = usePermission("see_handover_balance");
  const { allowed: canSubmitExpenses, loading: expensePermLoading } = usePermission("submit_expenses");
  
  // DEBUG: Remove after testing
  console.log("[Handovers] role:", role, "| isAdminOrManager:", isAdminOrManager, "| canSubmitExpenses:", canSubmitExpenses);

  const { data: staffProfiles } = useQuery({
    queryKey: ["staff-profiles", user?.id],
    queryFn: async () => {
      const { data: roles, error: rolesError } = await supabase
        .from("user_roles")
        .select("user_id, role")
        .in("role", ["super_admin", "manager", "agent", "marketer", "pos"]);

      const staffRoleMap = new Map((roles || []).map((row) => [row.user_id, row.role]));
      const staffIds = Array.from(staffRoleMap.keys()).filter((id) => id !== user?.id);

      let profiles: Array<{ user_id: string; full_name: string; email: string | null; phone: string | null }> = [];

      if (!rolesError && staffIds.length > 0) {
        const { data: filteredProfiles, error: filteredError } = await supabase
          .from("profiles")
          .select("user_id, full_name, email, phone")
          .in("user_id", staffIds)
          .eq("is_active", true);
        if (!filteredError) {
          profiles = (filteredProfiles || []) as typeof profiles;
        }
      }

      const roleLabel: Record<string, string> = {
        super_admin: "Admin",
        manager: "Manager",
        agent: "Agent",
        marketer: "Marketer",
        pos: "POS",
      };

      return (profiles || [])
        .map((profile) => ({
          ...profile,
          role: staffRoleMap.get(profile.user_id) || "agent",
          roleLabel: roleLabel[staffRoleMap.get(profile.user_id) || ""] || "Staff",
        }))
        .sort((a, b) => a.full_name.localeCompare(b.full_name));
    },
    enabled: !!user,
  });

  const { data: handovers, isLoading } = useQuery({
    queryKey: ["handovers", user?.id],
    queryFn: async () => {
      const { data, error } = await supabase
        .from("handovers")
        .select("*")
        .order("created_at", { ascending: false })
        .limit(500);
      if (error) throw error;
      return data || [];
    },
    enabled: !!user,
  });

  const { data: userSalesTotals } = useQuery({
    queryKey: ["user-sales-totals", user?.id],
    queryFn: async () => {
      const { data, error } = await supabase
        .from("sales")
        .select("cash_amount, upi_amount, created_at")
        .eq("recorded_by", user!.id);
      if (error) throw error;
      const todayStart = startOfDay(new Date()).toISOString();
      const all = data || [];
      const todaySales = all.filter((s) => s.created_at >= todayStart);
      return {
        totalCash: all.reduce((s, r) => s + Number(r.cash_amount), 0),
        totalUpi: all.reduce((s, r) => s + Number(r.upi_amount), 0),
        todayCash: todaySales.reduce((s, r) => s + Number(r.cash_amount), 0),
        todayUpi: todaySales.reduce((s, r) => s + Number(r.upi_amount), 0),
      };
    },
    enabled: !!user,
  });

  const { data: profileMap } = useQuery({
    queryKey: ["profile-map"],
    queryFn: async () => {
      const { data } = await supabase.from("profiles").select("user_id, full_name, avatar_url");
      const map: Record<string, { name: string; avatar: string | null }> = {};
      (data || []).forEach((p) => { map[p.user_id] = { name: p.full_name, avatar: p.avatar_url }; });
      return map;
    },
  });

  // For "See Balances" tab: fetch all staff sales and compute balances
  const { data: allStaffBalances } = useQuery({
    queryKey: ["all-staff-balances"],
    queryFn: async () => {
      // Get all staff user IDs
      const { data: roles } = await supabase.from("user_roles").select("user_id, role").neq("role", "customer").limit(200);
      const staffIds = (roles || []).map((r) => r.user_id);

      // Get all sales
      const { data: allSales } = await supabase.from("sales").select("recorded_by, cash_amount, upi_amount").limit(5000);

      // Get all handovers
      const { data: allHandovers } = await supabase.from("handovers").select("user_id, handed_to, cash_amount, upi_amount, status").limit(2000);

      const balances: Record<string, { sales: number; received: number; sentConfirmed: number; sentPending: number; total: number }> = {};

      for (const uid of staffIds) {
        const sales = (allSales || []).filter((s) => s.recorded_by === uid)
          .reduce((s, r) => s + Number(r.cash_amount) + Number(r.upi_amount), 0);
        const received = (allHandovers || []).filter((h) => h.handed_to === uid && h.status === "confirmed")
          .reduce((s, h) => s + Number(h.cash_amount) + Number(h.upi_amount), 0);
        const sentConfirmed = (allHandovers || []).filter((h) => h.user_id === uid && h.status === "confirmed")
          .reduce((s, h) => s + Number(h.cash_amount) + Number(h.upi_amount), 0);
        const sentPending = (allHandovers || []).filter((h) => h.user_id === uid && h.status === "awaiting_confirmation")
          .reduce((s, h) => s + Number(h.cash_amount) + Number(h.upi_amount), 0);
        const total = sales + received - sentConfirmed - sentPending;
        balances[uid] = { sales, received, sentConfirmed, sentPending, total };
      }
      return balances;
    },
    enabled: canSeeBalances,
  });

  const myHandovers = useMemo(() =>
    (handovers || []).filter((h) => h.user_id === user?.id || h.handed_to === user?.id),
    [handovers, user?.id]
  );

  const sentConfirmed = myHandovers
    .filter((h) => h.user_id === user?.id && h.status === "confirmed")
    .reduce((s, h) => s + Number(h.cash_amount) + Number(h.upi_amount), 0);
  const sentPending = myHandovers
    .filter((h) => h.user_id === user?.id && h.status === "awaiting_confirmation")
    .reduce((s, h) => s + Number(h.cash_amount) + Number(h.upi_amount), 0);
  const receivedConfirmed = myHandovers
    .filter((h) => h.handed_to === user?.id && h.status === "confirmed")
    .reduce((s, h) => s + Number(h.cash_amount) + Number(h.upi_amount), 0);

  const todayStart = startOfDay(new Date()).toISOString();
  const todayReceivedConfirmed = myHandovers
    .filter((h) => h.handed_to === user?.id && h.status === "confirmed" && h.created_at >= todayStart)
    .reduce((s, h) => s + Number(h.cash_amount) + Number(h.upi_amount), 0);

  const salesTotalAll = (userSalesTotals?.totalCash || 0) + (userSalesTotals?.totalUpi || 0);
  const salesToday = (userSalesTotals?.todayCash || 0) + (userSalesTotals?.todayUpi || 0);

  const notHandedOver = salesTotalAll + receivedConfirmed - sentConfirmed - sentPending;
  const awaitingAmount = sentPending;

  const breakdownSales = salesToday;
  const breakdownStaff = todayReceivedConfirmed;
  const breakdownPast = Math.max(0, notHandedOver - breakdownSales - breakdownStaff);

  const incoming = myHandovers.filter((h) => h.handed_to === user?.id && h.status === "awaiting_confirmation");

  // Fetch partial_collections setting
  const { data: partialSetting } = useQuery({
    queryKey: ["partial-collections-setting"],
    queryFn: async () => {
      const { data } = await supabase.from("company_settings").select("value").eq("key", "partial_collections").maybeSingle();
      return data?.value === "true";
    },
  });

  // Fetch expense categories
  const { data: expenseCategories = [] } = useQuery({
    queryKey: ["expense-categories"],
    queryFn: async () => {
      const { data, error } = await supabase
        .from("expense_categories")
        .select("*")
        .eq("is_active", true)
        .order("name");
      if (error) throw error;
      return data || [];
    },
  });

  // Fetch expense claims (own for staff, all for admin)
  const { data: expenseClaims = [], isLoading: expenseClaimsLoading } = useQuery({
    queryKey: ["expense-claims", user?.id, isAdminOrManager],
    queryFn: async () => {
      const { data, error } = await supabase
        .from("expense_claims")
        .select("*, expense_categories(id, name, color, icon)")
        .order("created_at", { ascending: false })
        .limit(200);
      if (error) throw error;
      return data || [];
    },
    enabled: !!user,
  });

  // Compute expense totals for balance
  const myApprovedExpenses = useMemo(() => {
    return (expenseClaims || [])
      .filter((e: any) => e.user_id === user?.id && e.status === "approved")
      .reduce((sum: number, e: any) => sum + Number(e.approved_amount || e.amount), 0);
  }, [expenseClaims, user?.id]);

  const myPendingExpenses = useMemo(() => {
    return (expenseClaims || [])
      .filter((e: any) => e.user_id === user?.id && e.status === "pending")
      .reduce((sum: number, e: any) => sum + Number(e.amount), 0);
  }, [expenseClaims, user?.id]);

  // Filter expenses by ownership
  const myExpenseClaims = useMemo(() => {
    return (expenseClaims || []).filter((e: any) => e.user_id === user?.id);
  }, [expenseClaims, user?.id]);

  const pendingExpenseClaimsForReview = useMemo(() => {
    return isAdminOrManager 
      ? (expenseClaims || []).filter((e: any) => e.status === "pending")
      : [];
  }, [expenseClaims, isAdminOrManager]);

  const handleCreate = async () => {
    if (!toUserId || !amount || Number(amount) <= 0) {
      toast.error("Select a recipient and enter a valid amount");
      return;
    }
    // If partial collections disabled, require exact full balance
    if (!partialSetting && !isFinalizer && Number(amount) < Math.max(0, notHandedOver)) {
      toast.error(`Partial handovers are disabled. Enter the full balance: ₹${Math.max(0, notHandedOver).toLocaleString()}`);
      return;
    }
    if (!isFinalizer && Number(amount) > Math.max(0, notHandedOver)) {
      toast.error("Amount exceeds your available balance");
      return;
    }
    setSubmitting(true);
    const { error } = await supabase.from("handovers").insert({
      user_id: user!.id,
      handed_to: toUserId,
      cash_amount: Number(amount),
      upi_amount: 0,
      status: "awaiting_confirmation",
      notes: notes || null,
    });
    setSubmitting(false);
    if (error) toast.error(error.message);
    else {
      toast.success("Handover sent for confirmation");

      // Notify the recipient
      sendNotification({
        userId: toUserId,
        title: "Handover Received",
        message: `₹${Number(amount).toLocaleString()} handover awaiting your confirmation`,
        type: "handover",
        entityType: "handover",
      });

      setCreateOpen(false);
      setAmount("");
      setNotes("");
      setToUserId("");
      qc.invalidateQueries({ queryKey: ["handovers"] });
    }
  };

  const handleConfirm = async (id: string) => {
    if (actionLoading) return;
    const handover = myHandovers.find((h) => h.id === id);
    if (handover?.user_id === user?.id) {
      toast.error("You cannot confirm your own handover");
      return;
    }
    setActionLoading(id);
    const { error } = await supabase.from("handovers").update({
      status: "confirmed",
      confirmed_by: user!.id,
      confirmed_at: new Date().toISOString(),
    }).eq("id", id);
    setActionLoading(null);
    if (error) toast.error(error.message);
    else {
      toast.success("Handover confirmed");
      if (handover?.user_id) {
        sendNotification({
          userId: handover.user_id,
          title: "Handover Confirmed",
          message: `Your ₹${Number(handover.cash_amount).toLocaleString()} handover was confirmed`,
          type: "handover",
          entityType: "handover",
          entityId: id,
        });
      }
      qc.invalidateQueries({ queryKey: ["handovers"] });
    }
  };

  const handleReject = async (id: string) => {
    if (actionLoading) return;
    const handover = myHandovers.find((h) => h.id === id);
    setActionLoading(id);
    const { error } = await supabase.from("handovers").update({
      status: "rejected",
      rejected_at: new Date().toISOString(),
    }).eq("id", id);
    setActionLoading(null);
    if (error) toast.error(error.message);
    else {
      toast.success("Handover rejected");
      if (handover?.user_id) {
        sendNotification({
          userId: handover.user_id,
          title: "Handover Rejected",
          message: `Your ₹${Number(handover.cash_amount).toLocaleString()} handover was rejected`,
          type: "handover",
          entityType: "handover",
          entityId: id,
        });
      }
      qc.invalidateQueries({ queryKey: ["handovers"] });
    }
  };

  const handleCancel = async (id: string) => {
    if (actionLoading) return;
    const handover = myHandovers.find((h) => h.id === id);
    if (!handover || handover.user_id !== user?.id) {
      toast.error("You can only cancel your own pending handovers");
      return;
    }
    if (handover.status !== "awaiting_confirmation") {
      toast.error("Only pending handovers can be cancelled");
      return;
    }
    setActionLoading(id);
    const { error } = await supabase.from("handovers").update({
      status: "cancelled",
    }).eq("id", id);
    setActionLoading(null);
    setCancelConfirmId(null);
    if (error) toast.error(error.message);
    else {
      toast.success("Handover cancelled");
      if (handover?.handed_to) {
        sendNotification({
          userId: handover.handed_to,
          title: "Handover Cancelled",
          message: `A ₹${Number(handover.cash_amount).toLocaleString()} handover was cancelled by sender`,
          type: "handover",
          entityType: "handover",
          entityId: id,
        });
      }
      qc.invalidateQueries({ queryKey: ["handovers"] });
    }
  };

  // ========== Expense Claim Handlers ==========
  const handleCreateExpenseClaim = async () => {
    if (!expenseCategory || !expenseAmount || Number(expenseAmount) <= 0 || !expenseDescription.trim()) {
      toast.error("Category, amount, and description are required");
      return;
    }
    if (new Date(expenseDate) > new Date()) {
      toast.error("Expense date cannot be in the future");
      return;
    }
    setExpenseSubmitting(true);
    try {
      // Generate display ID
      const { data: displayId } = await supabase.rpc("generate_display_id", {
        prefix: "EXC",
        seq_name: "expense_claims_display_seq"
      });

      const { error } = await supabase.from("expense_claims").insert({
        display_id: displayId || `EXC-${Date.now()}`,
        user_id: user!.id,
        category_id: expenseCategory,
        original_category_id: expenseCategory,
        amount: Number(expenseAmount),
        expense_date: expenseDate,
        description: expenseDescription.trim(),
        receipt_url: expenseReceiptUrl,
        status: "pending",
      });

      if (error) throw error;

      toast.success("Expense claim submitted for approval");
      
      // Notify admins
      const adminIds = await getAdminUserIds();
      sendNotificationToMany({
        userIds: adminIds,
        title: "New Expense Claim",
        message: `₹${Number(expenseAmount).toLocaleString()} expense claim requires your review`,
        type: "expense",
        entityType: "expense_claim",
      });

      setExpenseOpen(false);
      setExpenseAmount("");
      setExpenseDescription("");
      setExpenseCategory("");
      setExpenseDate(new Date().toISOString().split("T")[0]);
      setExpenseReceiptUrl(null);
      qc.invalidateQueries({ queryKey: ["expense-claims"] });
    } catch (err: any) {
      toast.error(err.message || "Failed to submit expense claim");
    } finally {
      setExpenseSubmitting(false);
    }
  };

  const handleReviewExpenseClaim = async (action: "approve" | "reject") => {
    if (!reviewExpense) return;
    setActionLoading(reviewExpense.id);

    try {
      const updates: any = {
        status: action === "approve" ? "approved" : "rejected",
        reviewed_by: user!.id,
        reviewed_at: new Date().toISOString(),
        reviewer_notes: reviewNotes.trim() || null,
      };

      // If approving with different category or amount
      if (action === "approve") {
        if (reviewCategory && reviewCategory !== reviewExpense.category_id) {
          updates.category_id = reviewCategory;
        }
        if (reviewAmount && Number(reviewAmount) !== Number(reviewExpense.amount)) {
          updates.approved_amount = Number(reviewAmount);
        } else {
          updates.approved_amount = Number(reviewExpense.amount);
        }
      }

      const { error } = await supabase
        .from("expense_claims")
        .update(updates)
        .eq("id", reviewExpense.id);

      if (error) throw error;

      toast.success(`Expense claim ${action === "approve" ? "approved" : "rejected"}`);
      
      // Notify the claimant
      sendNotification({
        userId: reviewExpense.user_id,
        title: `Expense Claim ${action === "approve" ? "Approved" : "Rejected"}`,
        message: action === "approve" 
          ? `Your ₹${Number(updates.approved_amount).toLocaleString()} expense claim was approved`
          : `Your ₹${Number(reviewExpense.amount).toLocaleString()} expense claim was rejected`,
        type: "expense",
        entityType: "expense_claim",
        entityId: reviewExpense.id,
      });

      setReviewExpense(null);
      setReviewCategory("");
      setReviewAmount("");
      setReviewNotes("");
      qc.invalidateQueries({ queryKey: ["expense-claims"] });
    } catch (err: any) {
      toast.error(err.message || "Failed to process expense claim");
    } finally {
      setActionLoading(null);
    }
  };

  const openReviewDialog = (expense: any) => {
    setReviewExpense(expense);
    setReviewCategory(expense.category_id || "");
    setReviewAmount(expense.amount?.toString() || "");
    setReviewNotes("");
  };

  const getCategoryName = (categoryId: string | null) => {
    const cat = expenseCategories.find((c: any) => c.id === categoryId);
    return cat?.name || "Unknown Category";
  };

  const getCategoryColor = (categoryId: string | null) => {
    const cat = expenseCategories.find((c: any) => c.id === categoryId);
    return cat?.color || "#6b7280";
  };

  const getProfile = (userId: string | null) => profileMap?.[userId || ""] || { name: "Unknown", avatar: null };
  const getName = (userId: string | null) => getProfile(userId).name;
  const getInitials = (name: string) => name.split(" ").map((n) => n[0]).join("").slice(0, 2).toUpperCase();

  const UserAvatar = ({ userId, size = "sm" }: { userId: string | null; size?: "sm" | "md" | "lg" }) => {
    const p = getProfile(userId);
    const cls = size === "lg" ? "h-10 w-10" : size === "md" ? "h-9 w-9" : "h-7 w-7";
    const textCls = size === "lg" ? "text-sm" : size === "md" ? "text-xs" : "text-[10px]";
    return (
      <Avatar className={`${cls} ring-2 ring-background`}>
        <AvatarImage src={p.avatar || undefined} alt={p.name} />
        <AvatarFallback className={`bg-primary/10 text-primary font-semibold ${textCls}`}>
          {getInitials(p.name) || <User className="h-3 w-3" />}
        </AvatarFallback>
      </Avatar>
    );
  };

  const HandoverCard = ({ item, showActions = false }: { item: typeof myHandovers[0]; showActions?: boolean }) => {
    const isSender = item.user_id === user?.id;
    const isReceiver = item.handed_to === user?.id;
    const total = Number(item.cash_amount) + Number(item.upi_amount);
    const statusLabel = item.status === "confirmed" ? "Confirmed" 
      : item.status === "rejected" ? "Rejected" 
      : item.status === "cancelled" ? "Cancelled"
      : "Pending";
    const isLoading = actionLoading === item.id;
    const canCancel = isSender && item.status === "awaiting_confirmation";

    return (
      <div className={`group flex items-center gap-4 rounded-lg border bg-card px-4 py-3 hover:shadow-sm transition-shadow border-l-4 ${
        item.status === "confirmed" ? "border-l-green-500" :
        item.status === "rejected" ? "border-l-red-500" :
        item.status === "cancelled" ? "border-l-slate-400" :
        "border-l-orange-500"
      }`}>
        <div className="flex items-center -space-x-2.5 shrink-0">
          <UserAvatar userId={item.user_id} size="lg" />
          <UserAvatar userId={item.handed_to} size="lg" />
        </div>

        <div className="flex-1 min-w-0">
          <div className="flex items-center gap-2 flex-wrap">
            <span className="text-base font-bold tabular-nums">₹{total.toLocaleString()}</span>
            <span className={`text-[11px] font-semibold px-1.5 py-0.5 rounded-full ${
              item.status === "confirmed" ? "bg-success/10 text-success" :
              item.status === "rejected" ? "bg-destructive/10 text-destructive" :
              item.status === "cancelled" ? "bg-muted text-muted-foreground" :
              "bg-warning/10 text-warning"
            }`}>{statusLabel}</span>
          </div>
          <p className="text-xs text-muted-foreground mt-0.5 truncate">
            {getName(item.user_id)} → {getName(item.handed_to)}
          </p>
          <div className="flex items-center gap-2 mt-0.5">
            <span className="text-[11px] text-muted-foreground">
              {format(new Date(item.created_at), "dd MMM, hh:mm a")}
            </span>
            {isSender && (
              <span className="text-[10px] font-medium bg-primary/8 text-primary px-1.5 py-px rounded">Sent</span>
            )}
            {isReceiver && (
              <span className="text-[10px] font-medium bg-accent text-accent-foreground px-1.5 py-px rounded">Received</span>
            )}
          </div>
          {item.notes && (
            <p className="text-[11px] text-muted-foreground/70 italic mt-1 truncate">"{item.notes}"</p>
          )}
        </div>

        {showActions && (
          <div className="flex flex-col gap-1.5 shrink-0">
            <Button size="sm" className="h-7 text-xs gap-1 px-2.5" onClick={() => handleConfirm(item.id)} disabled={isLoading}>
              {isLoading ? <Loader2 className="h-3 w-3 animate-spin" /> : <CheckCircle className="h-3 w-3" />} Accept
            </Button>
            <Button size="sm" variant="ghost" className="h-7 text-xs gap-1 px-2.5 text-destructive hover:text-destructive" onClick={() => handleReject(item.id)} disabled={isLoading}>
              {isLoading ? <Loader2 className="h-3 w-3 animate-spin" /> : <XCircle className="h-3 w-3" />} Reject
            </Button>
          </div>
        )}

        {canCancel && !showActions && (
          <Button 
            size="sm" 
            variant="ghost" 
            className="h-7 text-xs gap-1 px-2.5 text-muted-foreground hover:text-destructive shrink-0" 
            onClick={() => setCancelConfirmId(item.id)}
            disabled={isLoading}
          >
            {isLoading ? <Loader2 className="h-3 w-3 animate-spin" /> : <XCircle className="h-3 w-3" />} Cancel
          </Button>
        )}
      </div>
    );
  };

  // Expense Claim Card Component
  const ExpenseClaimCard = ({ item, showReviewAction = false }: { item: any; showReviewAction?: boolean }) => {
    const isOwner = item.user_id === user?.id;
    const isLoading = actionLoading === item.id;
    const statusLabel = item.status === "approved" ? "Approved" 
      : item.status === "rejected" ? "Rejected" 
      : "Pending";
    const displayAmount = item.status === "approved" && item.approved_amount 
      ? Number(item.approved_amount) 
      : Number(item.amount);
    const wasAmountChanged = item.status === "approved" && item.approved_amount && Number(item.approved_amount) !== Number(item.amount);
    const wasCategoryChanged = item.status === "approved" && item.category_id !== item.original_category_id;

    return (
      <div className={`group flex items-center gap-4 rounded-lg border bg-card px-4 py-3 hover:shadow-sm transition-shadow border-l-4 ${
        item.status === "approved" ? "border-l-green-500" :
        item.status === "rejected" ? "border-l-red-500" :
        "border-l-orange-500"
      }`}>
        <div className="flex items-center justify-center h-10 w-10 rounded-lg shrink-0" style={{ backgroundColor: `${getCategoryColor(item.category_id)}20` }}>
          <Receipt className="h-5 w-5" style={{ color: getCategoryColor(item.category_id) }} />
        </div>

        <div className="flex-1 min-w-0">
          <div className="flex items-center gap-2 flex-wrap">
            <span className="text-base font-bold tabular-nums">₹{displayAmount.toLocaleString()}</span>
            {wasAmountChanged && (
              <span className="text-[10px] text-muted-foreground line-through">₹{Number(item.amount).toLocaleString()}</span>
            )}
            <span className={`text-[11px] font-semibold px-1.5 py-0.5 rounded-full ${
              item.status === "approved" ? "bg-success/10 text-success" :
              item.status === "rejected" ? "bg-destructive/10 text-destructive" :
              "bg-warning/10 text-warning"
            }`}>{statusLabel}</span>
          </div>
          <p className="text-xs text-muted-foreground mt-0.5 truncate" title={item.description}>
            {item.description}
          </p>
          <div className="flex items-center gap-2 mt-0.5 flex-wrap">
            <span 
              className="text-[10px] font-medium px-1.5 py-px rounded"
              style={{ backgroundColor: `${getCategoryColor(item.category_id)}20`, color: getCategoryColor(item.category_id) }}
            >
              {getCategoryName(item.category_id)}
              {wasCategoryChanged && " (changed)"}
            </span>
            <span className="text-[11px] text-muted-foreground">
              {format(new Date(item.expense_date), "dd MMM yyyy")}
            </span>
            {!isOwner && (
              <span className="text-[10px] font-medium bg-primary/8 text-primary px-1.5 py-px rounded">
                by {getName(item.user_id)}
              </span>
            )}
          </div>
          {item.reviewer_notes && item.status !== "pending" && (
            <p className="text-[11px] text-muted-foreground/70 italic mt-1 truncate">Note: "{item.reviewer_notes}"</p>
          )}
        </div>

        {showReviewAction && item.status === "pending" && (
          <Button 
            size="sm" 
            className="h-7 text-xs gap-1 px-2.5 shrink-0" 
            onClick={() => openReviewDialog(item)}
            disabled={isLoading}
          >
            <Edit2 className="h-3 w-3" /> Review
          </Button>
        )}
      </div>
    );
  };

  const groupByDate = (items: typeof myHandovers) => {
    const groups: Record<string, typeof myHandovers> = {};
    items.forEach((item) => {
      const date = item.created_at.split("T")[0];
      if (!groups[date]) groups[date] = [];
      groups[date].push(item);
    });
    return Object.entries(groups).sort(([a], [b]) => b.localeCompare(a));
  };

  const formatDateGroup = (dateStr: string) => {
    const today = new Date().toISOString().split("T")[0];
    const yesterday = new Date(Date.now() - 86400000).toISOString().split("T")[0];
    if (dateStr === today) return "Today";
    if (dateStr === yesterday) return "Yesterday";
    return format(new Date(dateStr + "T00:00:00"), "dd MMM yyyy");
  };

  if (isLoading) {
    return <div className="flex items-center justify-center py-20"><Loader2 className="h-8 w-8 animate-spin text-primary" /></div>;
  }

  const balanceLabel = isFinalizer ? "Total Income" : "Not Handed Over";
  const balanceColor = isFinalizer ? "text-success" : "text-destructive";

  return (
    <div className="space-y-5 animate-fade-in">
      <PageHeader
        title="Handovers"
        subtitle="Track money flow between team members"
        primaryAction={!isFinalizer ? { label: "Create Handover", icon: Send, onClick: () => setCreateOpen(true) } : undefined}
      />

      {/* Balance Cards */}
      <div className="grid grid-cols-2 gap-3">
        <Popover>
          <PopoverTrigger asChild>
            <button className="stat-card text-left w-full cursor-pointer hover:ring-2 hover:ring-primary/20 transition-all group">
              <div className="flex items-center justify-between mb-1">
                <span className="text-xs font-medium text-muted-foreground">{balanceLabel}</span>
                <ChevronDown className="h-3.5 w-3.5 text-muted-foreground group-hover:text-primary transition-colors" />
              </div>
              <p className={`text-xl font-bold ${balanceColor}`}>₹{Math.max(0, notHandedOver - myApprovedExpenses).toLocaleString()}</p>
              {myApprovedExpenses > 0 && (
                <p className="text-[10px] text-success mt-0.5">₹{myApprovedExpenses.toLocaleString()} owed to you</p>
              )}
            </button>
          </PopoverTrigger>
          <PopoverContent className="w-64 p-3" align="start">
            <p className="text-xs font-semibold text-foreground mb-2.5">Balance Breakdown</p>
            <div className="space-y-2">
              <div className="flex items-center justify-between">
                <span className="flex items-center gap-1.5 text-xs text-muted-foreground">
                  <ShoppingCart className="h-3 w-3" /> Sales (Today)
                </span>
                <span className="text-xs font-semibold">₹{breakdownSales.toLocaleString()}</span>
              </div>
              <div className="flex items-center justify-between">
                <span className="flex items-center gap-1.5 text-xs text-muted-foreground">
                  <Users className="h-3 w-3" /> Staff (Today)
                </span>
                <span className="text-xs font-semibold">₹{breakdownStaff.toLocaleString()}</span>
              </div>
              <div className="flex items-center justify-between">
                <span className="flex items-center gap-1.5 text-xs text-muted-foreground">
                  <Clock className="h-3 w-3" /> Carried Forward
                </span>
                <span className="text-xs font-semibold">₹{breakdownPast.toLocaleString()}</span>
              </div>
              {myApprovedExpenses > 0 && (
                <div className="flex items-center justify-between">
                  <span className="flex items-center gap-1.5 text-xs text-success">
                    <Receipt className="h-3 w-3" /> Expenses Owed
                  </span>
                  <span className="text-xs font-semibold text-success">-₹{myApprovedExpenses.toLocaleString()}</span>
                </div>
              )}
              <div className="border-t pt-1.5 flex items-center justify-between">
                <span className="text-xs font-bold">Total</span>
                <span className="text-xs font-bold text-primary">₹{Math.max(0, notHandedOver - myApprovedExpenses).toLocaleString()}</span>
              </div>
            </div>
          </PopoverContent>
        </Popover>

        <div className="stat-card">
          <div className="mb-1">
            <span className="text-xs font-medium text-muted-foreground">Awaiting Confirmation</span>
          </div>
          <p className="text-xl font-bold text-warning">₹{awaitingAmount.toLocaleString()}</p>
        </div>
      </div>

      {/* Incoming requiring action */}
      {incoming.length > 0 && (
        <div className="space-y-2">
          <h3 className="text-xs font-semibold text-warning flex items-center gap-1.5 uppercase tracking-wide">
            <ArrowDownLeft className="h-3.5 w-3.5" /> Action Required ({incoming.length})
          </h3>
          <div className="space-y-2">
            {incoming.map((item) => (
              <HandoverCard key={item.id} item={item} showActions />
            ))}
          </div>
        </div>
      )}

      {/* Expense Claims requiring review (for admins) */}
      {isAdminOrManager && pendingExpenseClaimsForReview.length > 0 && (
        <div className="space-y-2">
          <h3 className="text-xs font-semibold text-warning flex items-center gap-1.5 uppercase tracking-wide">
            <Receipt className="h-3.5 w-3.5" /> Expense Claims to Review ({pendingExpenseClaimsForReview.length})
          </h3>
          <div className="space-y-2">
            {pendingExpenseClaimsForReview.slice(0, 3).map((item: any) => (
              <ExpenseClaimCard key={item.id} item={item} showReviewAction />
            ))}
            {pendingExpenseClaimsForReview.length > 3 && (
              <p className="text-xs text-muted-foreground text-center py-1">
                +{pendingExpenseClaimsForReview.length - 3} more in Expenses tab
              </p>
            )}
          </div>
        </div>
      )}

      {/* Tabs */}
      <Tabs defaultValue="mine" className="w-full">
        <TabsList className="w-full flex-wrap h-auto gap-1 p-1">
          <TabsTrigger value="mine" className="flex-1 gap-1.5 text-xs min-w-[80px]">
            <Banknote className="h-3.5 w-3.5" /> Handovers
          </TabsTrigger>
          {(canSubmitExpenses || isAdminOrManager) && (
            <TabsTrigger value="expenses" className="flex-1 gap-1.5 text-xs min-w-[80px]">
              <Receipt className="h-3.5 w-3.5" /> Expenses
              {myPendingExpenses > 0 && !isAdminOrManager && (
                <span className="ml-1 bg-warning/20 text-warning text-[10px] px-1 rounded">
                  {myExpenseClaims.filter((e: any) => e.status === "pending").length}
                </span>
              )}
            </TabsTrigger>
          )}
          {isAdminOrManager && (
            <TabsTrigger value="all" className="flex-1 gap-1.5 text-xs min-w-[80px]">
              <Users className="h-3.5 w-3.5" /> All
            </TabsTrigger>
          )}
          {canSeeBalances && (
            <TabsTrigger value="balances" className="flex-1 gap-1.5 text-xs min-w-[80px]">
              <Eye className="h-3.5 w-3.5" /> Balances
            </TabsTrigger>
          )}
        </TabsList>

        <TabsContent value="mine" className="space-y-4 mt-3">
          {myHandovers.filter(h => !(h.handed_to === user?.id && h.status === "awaiting_confirmation")).length === 0 ? (
            <div className="rounded-lg border bg-card p-8 text-center text-sm text-muted-foreground">No handovers yet.</div>
          ) : groupByDate(myHandovers.filter(h => !(h.handed_to === user?.id && h.status === "awaiting_confirmation"))).map(([date, items]) => (
            <div key={date} className="space-y-2">
              <div className="flex items-center gap-2">
                <span className="text-xs font-semibold text-muted-foreground uppercase tracking-wide">{formatDateGroup(date)}</span>
                <div className="flex-1 h-px bg-border" />
              </div>
              {items.map((item) => <HandoverCard key={item.id} item={item} />)}
            </div>
          ))}
        </TabsContent>

        {isAdminOrManager && (
          <TabsContent value="all" className="space-y-4 mt-3">
            {(handovers || []).length === 0 ? (
              <div className="rounded-lg border bg-card p-8 text-center text-sm text-muted-foreground">No handovers recorded.</div>
            ) : groupByDate(handovers || []).map(([date, items]) => (
              <div key={date} className="space-y-2">
                <div className="flex items-center gap-2">
                  <span className="text-xs font-semibold text-muted-foreground uppercase tracking-wide">{formatDateGroup(date)}</span>
                  <div className="flex-1 h-px bg-border" />
                </div>
                {items.map((item) => <HandoverCard key={item.id} item={item} />)}
              </div>
            ))}
          </TabsContent>
        )}

        {canSeeBalances && (
          <TabsContent value="balances" className="space-y-2 mt-3">
            {!allStaffBalances || Object.keys(allStaffBalances).length === 0 ? (
              <div className="rounded-lg border bg-card p-8 text-center text-sm text-muted-foreground">No staff balances to show.</div>
            ) : (
              <div className="space-y-2">
                {Object.entries(allStaffBalances)
                  .sort(([, a], [, b]) => b.total - a.total)
                  .map(([uid, bal]) => {
                    const withUser = bal.total + bal.sentPending; // awaiting is still "with" the user
                    return (
                      <div key={uid} className="flex items-center gap-3 rounded-lg border bg-card px-4 py-3">
                        <UserAvatar userId={uid} size="lg" />
                        <div className="flex-1 min-w-0">
                          <p className="text-sm font-semibold truncate">{getName(uid)}</p>
                          <div className="flex items-center gap-3 mt-0.5 text-[11px] text-muted-foreground">
                            <span>Sales: ₹{bal.sales.toLocaleString()}</span>
                            <span>Received: ₹{bal.received.toLocaleString()}</span>
                          </div>
                        </div>
                        <div className="text-right shrink-0">
                          <p className={`text-base font-bold tabular-nums ${withUser > 0 ? "text-destructive" : "text-success"}`}>
                            ₹{Math.max(0, withUser).toLocaleString()}
                          </p>
                          {bal.sentPending > 0 && (
                            <p className="text-[10px] text-warning">₹{bal.sentPending.toLocaleString()} awaiting</p>
                          )}
                        </div>
                      </div>
                    );
                  })}
              </div>
            )}
          </TabsContent>
        )}

        {/* Expenses Tab */}
        {(canSubmitExpenses || isAdminOrManager) && (
          <TabsContent value="expenses" className="space-y-4 mt-3">
            {/* Add Expense Button for users with permission or admins */}
            {(canSubmitExpenses || isAdminOrManager) && (
              <Button 
                onClick={() => setExpenseOpen(true)} 
                className="w-full gap-2"
                variant="outline"
              >
                <Receipt className="h-4 w-4" /> Submit Expense Claim
              </Button>
            )}

            {/* Summary Cards */}
            <div className="grid grid-cols-2 gap-3">
              <div className="stat-card">
                <span className="text-xs font-medium text-muted-foreground">Pending Claims</span>
                <p className="text-xl font-bold text-warning">₹{myPendingExpenses.toLocaleString()}</p>
              </div>
              <div className="stat-card">
                <span className="text-xs font-medium text-muted-foreground">Approved (Owed)</span>
                <p className="text-xl font-bold text-success">₹{myApprovedExpenses.toLocaleString()}</p>
              </div>
            </div>

            {/* Expense Claims List */}
            {expenseClaimsLoading ? (
              <div className="flex items-center justify-center py-8">
                <Loader2 className="h-6 w-6 animate-spin text-primary" />
              </div>
            ) : (isAdminOrManager ? expenseClaims : myExpenseClaims).length === 0 ? (
              <div className="rounded-lg border bg-card p-8 text-center text-sm text-muted-foreground">
                {canSubmitExpenses 
                  ? "No expense claims yet. Submit your first claim above."
                  : "No expense claims to show."}
              </div>
            ) : (
              <div className="space-y-2">
                {(isAdminOrManager ? expenseClaims : myExpenseClaims).map((item: any) => (
                  <ExpenseClaimCard 
                    key={item.id} 
                    item={item} 
                    showReviewAction={isAdminOrManager} 
                  />
                ))}
              </div>
            )}
          </TabsContent>
        )}
      </Tabs>

      {/* Create Handover Dialog */}
      <Dialog open={createOpen} onOpenChange={setCreateOpen}>
        <DialogContent>
          <DialogHeader>
            <DialogTitle>Create Handover</DialogTitle>
            <DialogDescription>Send money to another team member for confirmation.</DialogDescription>
          </DialogHeader>
          <div className="space-y-4">
            <div className="rounded-lg bg-primary/5 p-3 text-center">
              <p className="text-xs text-muted-foreground">Available Balance</p>
              <p className="text-2xl font-bold text-primary">₹{Math.max(0, notHandedOver).toLocaleString()}</p>
            </div>
            <div className="space-y-2">
              <Label>Send To</Label>
              <Select value={toUserId} onValueChange={setToUserId}>
                <SelectTrigger><SelectValue placeholder="Select staff member" /></SelectTrigger>
                <SelectContent>
                  {(staffProfiles || []).map((p) => {
                    const detail = p.phone || p.email || "No contact";
                    return (
                      <SelectItem key={p.user_id} value={p.user_id}>
                        <div className="flex w-full items-center justify-between gap-3">
                          <span className="font-medium">{p.full_name}</span>
                          <span className="text-xs text-muted-foreground">{p.roleLabel}</span>
                        </div>
                        <p className="text-xs text-muted-foreground truncate">{detail}</p>
                      </SelectItem>
                    );
                  })}
                </SelectContent>
              </Select>
            </div>
            <div className="space-y-2">
              <Label>Amount (₹)</Label>
              <Input type="number" value={amount} onChange={(e) => setAmount(e.target.value)} placeholder="Enter amount" min="1" />
              {partialSetting === false && !isFinalizer && (
                <p className="text-xs text-warning flex items-center gap-1">
                  <AlertCircle className="h-3 w-3 shrink-0" />
                  Partial handovers are disabled — full balance of ₹{Math.max(0, notHandedOver).toLocaleString()} required
                </p>
              )}
            </div>
            <div className="space-y-2">
              <Label>Notes (optional)</Label>
              <Textarea value={notes} onChange={(e) => setNotes(e.target.value)} placeholder="Add any notes..." rows={2} />
            </div>
          </div>
          <DialogFooter>
            <Button variant="outline" onClick={() => setCreateOpen(false)}>Cancel</Button>
            <Button onClick={handleCreate} disabled={submitting}>
              {submitting ? <Loader2 className="h-4 w-4 animate-spin mr-2" /> : <Send className="h-4 w-4 mr-2" />}
              Send Handover
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>

      {/* Cancel Confirmation Dialog */}
      <Dialog open={!!cancelConfirmId} onOpenChange={() => setCancelConfirmId(null)}>
        <DialogContent className="max-w-sm">
          <DialogHeader>
            <DialogTitle>Cancel Handover?</DialogTitle>
            <DialogDescription>
              This will cancel your pending handover. The recipient will be notified.
            </DialogDescription>
          </DialogHeader>
          <DialogFooter>
            <Button variant="outline" onClick={() => setCancelConfirmId(null)}>
              Keep it
            </Button>
            <Button 
              variant="destructive" 
              onClick={() => cancelConfirmId && handleCancel(cancelConfirmId)}
              disabled={!!actionLoading}
            >
              {actionLoading ? <Loader2 className="h-4 w-4 animate-spin mr-2" /> : <XCircle className="h-4 w-4 mr-2" />}
              Yes, Cancel
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>

      {/* Create Expense Claim Dialog */}
      <Dialog open={expenseOpen} onOpenChange={setExpenseOpen}>
        <DialogContent>
          <DialogHeader>
            <DialogTitle>Submit Expense Claim</DialogTitle>
            <DialogDescription>
              Claim reimbursement for out-of-pocket expenses. Your claim will be reviewed by management.
            </DialogDescription>
          </DialogHeader>
          <div className="space-y-4">
            <div className="space-y-2">
              <Label>Category *</Label>
              <Select value={expenseCategory} onValueChange={setExpenseCategory}>
                <SelectTrigger>
                  <SelectValue placeholder="Select expense category" />
                </SelectTrigger>
                <SelectContent>
                  {expenseCategories.map((cat: any) => (
                    <SelectItem key={cat.id} value={cat.id}>
                      <div className="flex items-center gap-2">
                        <div 
                          className="h-2.5 w-2.5 rounded-full" 
                          style={{ backgroundColor: cat.color || "#6b7280" }} 
                        />
                        {cat.name}
                      </div>
                    </SelectItem>
                  ))}
                </SelectContent>
              </Select>
            </div>
            <div className="grid grid-cols-2 gap-3">
              <div className="space-y-2">
                <Label>Amount (₹) *</Label>
                <Input 
                  type="number" 
                  value={expenseAmount} 
                  onChange={(e) => setExpenseAmount(e.target.value)} 
                  placeholder="0.00" 
                  min="1" 
                />
              </div>
              <div className="space-y-2">
                <Label>Date *</Label>
                <Input 
                  type="date" 
                  value={expenseDate} 
                  onChange={(e) => setExpenseDate(e.target.value)} 
                  max={new Date().toISOString().split("T")[0]}
                />
              </div>
            </div>
            <div className="space-y-2">
              <Label>Description *</Label>
              <Textarea 
                value={expenseDescription} 
                onChange={(e) => setExpenseDescription(e.target.value)} 
                placeholder="What was this expense for? (e.g., Taxi fare for customer visit, Office supplies purchase)"
                rows={3}
              />
            </div>
            <div className="space-y-2">
              <Label className="flex items-center gap-2">
                <Image className="h-4 w-4" />
                Receipt Photo (Optional)
              </Label>
              <p className="text-xs text-muted-foreground">
                Upload a photo of the receipt or bill for faster approval
              </p>
              <ImageUpload
                folder="expense-receipts"
                currentUrl={expenseReceiptUrl}
                onUploaded={(url) => setExpenseReceiptUrl(url)}
                onRemoved={() => setExpenseReceiptUrl(null)}
                size="lg"
              />
            </div>
          </div>
          <DialogFooter>
            <Button variant="outline" onClick={() => setExpenseOpen(false)}>Cancel</Button>
            <Button onClick={handleCreateExpenseClaim} disabled={expenseSubmitting}>
              {expenseSubmitting ? <Loader2 className="h-4 w-4 animate-spin mr-2" /> : <Receipt className="h-4 w-4 mr-2" />}
              Submit Claim
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>

      {/* Review Expense Claim Dialog */}
      <Dialog open={!!reviewExpense} onOpenChange={() => setReviewExpense(null)}>
        <DialogContent>
          <DialogHeader>
            <DialogTitle>Review Expense Claim</DialogTitle>
            <DialogDescription>
              Approve or reject this expense claim. You can adjust the category or amount if needed.
            </DialogDescription>
          </DialogHeader>
          {reviewExpense && (
            <div className="space-y-4">
              {/* Claim Details */}
              <div className="rounded-lg bg-muted/50 p-3 space-y-2">
                <div className="flex justify-between items-center">
                  <span className="text-xs text-muted-foreground">Submitted by</span>
                  <span className="text-sm font-medium">{getName(reviewExpense.user_id)}</span>
                </div>
                <div className="flex justify-between items-center">
                  <span className="text-xs text-muted-foreground">Original Amount</span>
                  <span className="text-sm font-bold">₹{Number(reviewExpense.amount).toLocaleString()}</span>
                </div>
                <div className="flex justify-between items-center">
                  <span className="text-xs text-muted-foreground">Expense Date</span>
                  <span className="text-sm">{format(new Date(reviewExpense.expense_date), "dd MMM yyyy")}</span>
                </div>
                <div className="pt-1 border-t">
                  <span className="text-xs text-muted-foreground">Description</span>
                  <p className="text-sm mt-0.5">{reviewExpense.description}</p>
                </div>
                {/* Receipt Image */}
                {reviewExpense.receipt_url && (
                  <div className="pt-2 border-t">
                    <span className="text-xs text-muted-foreground">Receipt</span>
                    <a
                      href={reviewExpense.receipt_url}
                      target="_blank"
                      rel="noopener noreferrer"
                      className="block mt-1"
                    >
                      <img
                        src={reviewExpense.receipt_url}
                        alt="Receipt"
                        className="max-h-40 rounded-md border cursor-pointer hover:opacity-90 transition-opacity"
                      />
                      <span className="text-xs text-primary mt-1 inline-flex items-center gap-1">
                        <Eye className="h-3 w-3" /> Click to view full size
                      </span>
                    </a>
                  </div>
                )}
              </div>

              {/* Adjustable Fields */}
              <div className="space-y-2">
                <Label>Category (can change for accounting)</Label>
                <Select value={reviewCategory} onValueChange={setReviewCategory}>
                  <SelectTrigger>
                    <SelectValue placeholder="Select category" />
                  </SelectTrigger>
                  <SelectContent>
                    {expenseCategories.map((cat: any) => (
                      <SelectItem key={cat.id} value={cat.id}>
                        <div className="flex items-center gap-2">
                          <div 
                            className="h-2.5 w-2.5 rounded-full" 
                            style={{ backgroundColor: cat.color || "#6b7280" }} 
                          />
                          {cat.name}
                        </div>
                      </SelectItem>
                    ))}
                  </SelectContent>
                </Select>
              </div>
              <div className="space-y-2">
                <Label>Approved Amount (₹)</Label>
                <Input 
                  type="number" 
                  value={reviewAmount} 
                  onChange={(e) => setReviewAmount(e.target.value)} 
                  placeholder="0.00" 
                  min="0"
                />
                {reviewAmount && Number(reviewAmount) !== Number(reviewExpense.amount) && (
                  <p className="text-xs text-warning flex items-center gap-1">
                    <AlertCircle className="h-3 w-3" />
                    Amount differs from original claim (₹{Number(reviewExpense.amount).toLocaleString()})
                  </p>
                )}
              </div>
              <div className="space-y-2">
                <Label>Notes (optional)</Label>
                <Textarea 
                  value={reviewNotes} 
                  onChange={(e) => setReviewNotes(e.target.value)} 
                  placeholder="Add notes for the claimant (e.g., reason for adjustment or rejection)"
                  rows={2}
                />
              </div>
            </div>
          )}
          <DialogFooter className="gap-2 sm:gap-0">
            <Button 
              variant="ghost" 
              onClick={() => setReviewExpense(null)}
            >
              Cancel
            </Button>
            <Button 
              variant="destructive" 
              onClick={() => handleReviewExpenseClaim("reject")}
              disabled={!!actionLoading}
            >
              {actionLoading === reviewExpense?.id ? <Loader2 className="h-4 w-4 animate-spin mr-2" /> : <XCircle className="h-4 w-4 mr-2" />}
              Reject
            </Button>
            <Button 
              onClick={() => handleReviewExpenseClaim("approve")}
              disabled={!!actionLoading || !reviewAmount || Number(reviewAmount) <= 0}
            >
              {actionLoading === reviewExpense?.id ? <Loader2 className="h-4 w-4 animate-spin mr-2" /> : <CheckCircle className="h-4 w-4 mr-2" />}
              Approve
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>
    </div>
  );
};

export default Handovers;

import { PageHeader } from "@/components/shared/PageHeader";
import { DataTable } from "@/components/shared/DataTable";
import { StatusBadge } from "@/components/shared/StatusBadge";
import { Badge } from "@/components/ui/badge";
import { useQuery, useQueryClient } from "@tanstack/react-query";
import { supabase } from "@/integrations/supabase/client";
import { useAuth } from "@/contexts/AuthContext";
import { logActivity } from "@/lib/activityLogger";
import { Loader2, Package, Plus, Minus, History, BoxSelect, ArrowUpRight, ArrowDownRight, FlaskConical, ImageIcon } from "lucide-react";
import { useState, useMemo, useEffect } from "react";
import { useIsMobile } from "@/hooks/use-mobile";
import {
  Dialog, DialogContent, DialogHeader, DialogTitle, DialogDescription, DialogFooter,
} from "@/components/ui/dialog";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Button } from "@/components/ui/button";
import {
  Select, SelectContent, SelectItem, SelectTrigger, SelectValue,
} from "@/components/ui/select";
import { Textarea } from "@/components/ui/textarea";
import { toast } from "sonner";
import { Tabs, TabsList, TabsTrigger, TabsContent } from "@/components/ui/tabs";
import { format } from "date-fns";
import { Avatar, AvatarImage, AvatarFallback } from "@/components/ui/avatar";

type MovementType = "purchase" | "sale" | "adjustment" | "return" | "transfer_in" | "transfer_out";
type RawMaterialAdjustType = "used" | "remaining";

const MOVEMENT_TYPES: Record<MovementType, string> = {
  purchase: "Purchase (In)",
  sale: "Sale (Out)",
  adjustment: "Correction (+/-)",
  return: "Return (In)",
  transfer_in: "Transfer (In)",
  transfer_out: "Transfer (Out)",
};

const RAW_MATERIAL_ADJUST_TYPES: Record<RawMaterialAdjustType, string> = {
  used: "Used (Consumption)",
  remaining: "Remaining (Physical Count)",
};

const Inventory = () => {
  const { user, role } = useAuth();
  const qc = useQueryClient();
  const isMobile = useIsMobile();
  const canEdit = ["super_admin", "manager", "pos"].includes(role || "");
  
  const [selectedWarehouseId, setSelectedWarehouseId] = useState<string>("");
  const [showAdjust, setShowAdjust] = useState(false);
  const [adjustProduct, setAdjustProduct] = useState<any>(null);
  const [adjustType, setAdjustType] = useState<MovementType>("adjustment");
  const [adjustQty, setAdjustQty] = useState("");
  const [adjustReason, setAdjustReason] = useState("");
  const [saving, setSaving] = useState(false);
  const [searchTerm, setSearchTerm] = useState("");
  
  // Raw materials state
  const [showRawMaterialAdjust, setShowRawMaterialAdjust] = useState(false);
  const [adjustRawMaterial, setAdjustRawMaterial] = useState<any>(null);
  const [rawMaterialAdjustType, setRawMaterialAdjustType] = useState<RawMaterialAdjustType>("used");
  const [rawMaterialQty, setRawMaterialQty] = useState("");
  const [rawMaterialReason, setRawMaterialReason] = useState("");
  const [rawMaterialSearchTerm, setRawMaterialSearchTerm] = useState("");

  // Fetch Warehouses
  const { data: warehouses, isLoading: loadWh } = useQuery({
    queryKey: ["warehouses"],
    queryFn: async () => {
      const { data } = await supabase.from("warehouses").select("*").eq("is_active", true).order("name");
      return data || [];
    },
  });

  // Set default warehouse - must be in useEffect to avoid state mutation during render
  useEffect(() => {
    if (warehouses?.length && !selectedWarehouseId) {
      setSelectedWarehouseId(warehouses[0].id);
    }
  }, [warehouses, selectedWarehouseId]);

  // Fetch Inventory for selected warehouse
  const { data: inventory, isLoading: loadInv } = useQuery({
    queryKey: ["inventory", selectedWarehouseId],
    queryFn: async () => {
      if (!selectedWarehouseId) return [];
      
      // We need products and their stock in this warehouse
      // Supabase join syntax: product_stock(quantity, warehouse_id)
      
      // Strategy: Fetch all products, then fetch stock for this warehouse
      const { data: products } = await supabase
        .from("products")
        .select("id, name, sku, unit, category, image_url")
        .eq("is_active", true)
        .order("name");
        
      if (!products) return [];

      const { data: stocks } = await supabase
        .from("product_stock")
        .select("product_id, quantity")
        .eq("warehouse_id", selectedWarehouseId);
      
      const stockMap = new Map(stocks?.map(s => [s.product_id, s.quantity]));

      return products.map(p => ({
        ...p,
        quantity: stockMap.get(p.id) || 0,
      }));
    },
    enabled: !!selectedWarehouseId,
  });

  // Fetch Raw Materials for selected warehouse
  const { data: rawMaterials, isLoading: loadRawMaterials } = useQuery({
    queryKey: ["raw-materials-inventory", selectedWarehouseId],
    queryFn: async () => {
      if (!selectedWarehouseId) return [];
      
      // Get raw materials with their stock in this warehouse
      const { data: materials, error: matError } = await supabase
        .from("raw_materials")
        .select("id, display_id, name, unit, category, min_stock_level, current_stock, unit_cost, image_url")
        .eq("is_active", true)
        .order("name");
        
      if (matError || !materials) return [];

      // Get per-warehouse stock
      const { data: stocks } = await supabase
        .from("raw_material_stock")
        .select("raw_material_id, quantity")
        .eq("warehouse_id", selectedWarehouseId);
      
      const stockMap = new Map(stocks?.map(s => [s.raw_material_id, s.quantity]));

      return materials.map(m => ({
        ...m,
        warehouse_quantity: stockMap.get(m.id) || 0,
      }));
    },
    enabled: !!selectedWarehouseId,
  });

  // Filter raw materials based on search term
  const filteredRawMaterials = useMemo(() => {
    if (!rawMaterials) return [];
    if (!rawMaterialSearchTerm.trim()) return rawMaterials;
    const term = rawMaterialSearchTerm.toLowerCase();
    return rawMaterials.filter((item: any) =>
      item.name?.toLowerCase().includes(term) ||
      item.display_id?.toLowerCase().includes(term) ||
      item.category?.toLowerCase().includes(term)
    );
  }, [rawMaterials, rawMaterialSearchTerm]);

  // Filter inventory based on search term
  const filteredInventory = useMemo(() => {
    if (!inventory) return [];
    if (!searchTerm.trim()) return inventory;
    const term = searchTerm.toLowerCase();
    return inventory.filter((item: any) =>
      item.name?.toLowerCase().includes(term) ||
      item.sku?.toLowerCase().includes(term) ||
      item.category?.toLowerCase().includes(term)
    );
  }, [inventory, searchTerm]);

  // Fetch Recent Movements
  const { data: movements } = useQuery({
    queryKey: ["stock-movements", selectedWarehouseId],
    queryFn: async () => {
        if (!selectedWarehouseId) return [];
        const { data } = await supabase
            .from("stock_movements")
            .select("*, products(name, sku)")
            .eq("warehouse_id", selectedWarehouseId)
            .order("created_at", { ascending: false })
            .limit(50);
        return data || [];
    },
    enabled: !!selectedWarehouseId,
  });

  const handleAdjust = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!selectedWarehouseId || !adjustProduct) return;
    setSaving(true);
    
    try {
        const qty = parseFloat(adjustQty);
        if (isNaN(qty) || qty === 0) throw new Error("Invalid quantity");

        // Calculate actual change based on type
        // For 'adjustment', we accept +/-. For others, we enforce sign logic?
        // Let's keep it simple: user inputs positive number, type determines sign
        
        let finalQty = qty;
        if (["sale", "transfer_out"].includes(adjustType)) {
            finalQty = -Math.abs(qty);
        } else if (["purchase", "return", "transfer_in"].includes(adjustType)) {
            finalQty = Math.abs(qty);
        }
        // 'adjustment' can be either, assume user entered correct sign or use UI toggle?
        // Let's make UI simple: Input always positive, Type determines direction
        
        // Actually for adjustment, allow negative input
        if (adjustType === "adjustment") {
            finalQty = qty; // User can type -5
        }

        // Call single RPC for atomic transaction
        const { error: stockError, data: result } = await supabase.rpc("record_stock_movement", {
            p_product_id: adjustProduct.id,
            p_warehouse_id: selectedWarehouseId,
            p_quantity: finalQty,
            p_type: adjustType,
            p_reason: adjustReason,
            p_user_id: user?.id
        });

        if (stockError) throw stockError;

        toast.success("Stock updated successfully");
        setShowAdjust(false);
        setAdjustQty("");
        setAdjustReason("");
        qc.invalidateQueries({ queryKey: ["inventory"] });
        qc.invalidateQueries({ queryKey: ["stock-movements"] });
        logActivity(user!.id, `Adjusted stock for ${adjustProduct.name}`, "stock", adjustProduct.id);

    } catch (err: any) {
        toast.error(err.message);
    } finally {
        setSaving(false);
    }
  };

  // Handle raw material adjustment
  const handleRawMaterialAdjust = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!selectedWarehouseId || !adjustRawMaterial) return;
    setSaving(true);
    
    try {
        const qty = parseFloat(rawMaterialQty);
        if (isNaN(qty) || qty < 0) throw new Error("Invalid quantity");

        const currentStock = adjustRawMaterial.warehouse_quantity || 0;
        let quantityChange: number;
        let quantityAfter: number;

        if (rawMaterialAdjustType === "used") {
            // "Used" reduces stock by the entered amount
            if (qty > currentStock) throw new Error(`Cannot use more than available stock (${currentStock})`);
            quantityChange = -qty;
            quantityAfter = currentStock - qty;
        } else {
            // "Remaining" sets stock to the entered value (physical count)
            quantityChange = qty - currentStock;
            quantityAfter = qty;
        }

        // Insert adjustment record
        const { error: adjError } = await supabase
            .from("raw_material_adjustments")
            .insert({
                raw_material_id: adjustRawMaterial.id,
                warehouse_id: selectedWarehouseId,
                adjustment_type: rawMaterialAdjustType,
                quantity_before: currentStock,
                quantity_change: quantityChange,
                quantity_after: quantityAfter,
                reason: rawMaterialReason || (rawMaterialAdjustType === "used" ? "Consumption" : "Physical count"),
                performed_by: user?.id,
            });

        if (adjError) throw adjError;

        // Update or insert stock record
        const { data: existingStock } = await supabase
            .from("raw_material_stock")
            .select("id")
            .eq("raw_material_id", adjustRawMaterial.id)
            .eq("warehouse_id", selectedWarehouseId)
            .single();

        if (existingStock) {
            await supabase
                .from("raw_material_stock")
                .update({ quantity: quantityAfter, updated_at: new Date().toISOString() })
                .eq("id", existingStock.id);
        } else {
            await supabase
                .from("raw_material_stock")
                .insert({
                    raw_material_id: adjustRawMaterial.id,
                    warehouse_id: selectedWarehouseId,
                    quantity: quantityAfter,
                });
        }

        toast.success(`Raw material ${rawMaterialAdjustType === "used" ? "consumption" : "count"} recorded`);
        setShowRawMaterialAdjust(false);
        setRawMaterialQty("");
        setRawMaterialReason("");
        qc.invalidateQueries({ queryKey: ["raw-materials-inventory"] });
        logActivity(user!.id, `Adjusted raw material: ${adjustRawMaterial.name} (${rawMaterialAdjustType})`, "raw_material", adjustRawMaterial.id);

    } catch (err: any) {
        toast.error(err.message);
    } finally {
        setSaving(false);
    }
  };

  const columns = [
    { header: "SKU", accessor: "sku", className: "w-[100px] font-mono text-xs" },
    { header: "Product", accessor: "name", className: "font-medium" },
    { header: "Category", accessor: "category" },
    { 
        header: "Stock", 
        accessor: (row: any) => (
            <div className={`font-bold ${row.quantity < 0 ? "text-red-500" : row.quantity === 0 ? "text-slate-400" : "text-green-600"}`}>
                {row.quantity} <span className="text-xs font-normal text-slate-500">{row.unit}</span>
            </div>
        ) 
    },
    {
        header: "Action",
        accessor: (row: any) => canEdit && (
            <Button variant="ghost" size="sm" onClick={() => {
                setAdjustProduct(row);
                setAdjustType("adjustment");
                setShowAdjust(true);
            }}>
                Adjust
            </Button>
        )
    }
  ];

  const movementColumns = [
      { header: "Date", accessor: (row: any) => format(new Date(row.created_at), "dd MMM HH:mm"), className: "text-xs text-slate-500" },
      { header: "Product", accessor: (row: any) => row.products?.name },
      { header: "Type", accessor: (row: any) => <Badge variant="outline">{row.type}</Badge> },
      { 
          header: "Qty", 
          accessor: (row: any) => (
             <span className={row.quantity > 0 ? "text-green-600 font-bold" : "text-red-600 font-bold"}>
                 {row.quantity > 0 ? "+" : ""}{row.quantity}
             </span>
          ) 
      },
      { header: "Reason", accessor: "reason", className: "text-xs block max-w-[200px] truncate" },
  ];

  return (
    <div className="space-y-6 animate-fade-in">
        <div className="flex flex-col sm:flex-row sm:items-center sm:justify-between gap-4">
            <PageHeader title="Inventory Management" subtitle="Manage stock levels across warehouses" />
            <div className="flex items-center gap-2">
                <BoxSelect className="h-4 w-4 text-muted-foreground" />
                <Select value={selectedWarehouseId} onValueChange={setSelectedWarehouseId}>
                    <SelectTrigger className="w-[200px]">
                        <SelectValue placeholder="Select Warehouse" />
                    </SelectTrigger>
                    <SelectContent>
                        {warehouses?.map((w: any) => (
                            <SelectItem key={w.id} value={w.id}>{w.name}</SelectItem>
                        ))}
                    </SelectContent>
                </Select>
            </div>
        </div>

        <Tabs defaultValue="stock">
            <TabsList>
                <TabsTrigger value="stock">Products</TabsTrigger>
                <TabsTrigger value="raw-materials">Raw Materials</TabsTrigger>
                <TabsTrigger value="movements">Recent Movements</TabsTrigger>
            </TabsList>

            <TabsContent value="stock" className="space-y-4">
                {loadInv ? (
                    <div className="flex items-center justify-center py-10"><Loader2 className="animate-spin" /></div>
                ) : !isMobile ? (
                    /* Desktop: Card Grid */
                    <div className="space-y-4">
                      <Input 
                        placeholder="Search products..." 
                        value={searchTerm}
                        onChange={(e) => setSearchTerm(e.target.value)}
                        className="max-w-sm"
                      />
                      <div className="entity-grid">
                        {filteredInventory.map((row: any) => {
                          const stockStatus = row.quantity < 0 ? "critical" : row.quantity === 0 ? "empty" : row.quantity < 10 ? "low" : "good";
                          const statusColors = {
                            critical: { badge: "bg-red-100 text-red-700", text: "text-red-600" },
                            empty: { badge: "bg-slate-100 text-slate-600", text: "text-slate-500" },
                            low: { badge: "bg-amber-100 text-amber-700", text: "text-amber-600" },
                            good: { badge: "bg-emerald-100 text-emerald-700", text: "text-emerald-600" },
                          };
                          const colors = statusColors[stockStatus];
                          
                          return (
                            <div
                              key={row.id}
                              className="group entity-card"
                            >
                              {/* Header */}
                              <div className="entity-card-header">
                                <div className="entity-card-icon-box">
                                  {row.image_url ? (
                                    <Avatar className="h-12 w-12 rounded-lg">
                                      <AvatarImage src={row.image_url} alt={row.name} className="object-cover" />
                                      <AvatarFallback className="rounded-lg bg-muted">
                                        <Package className={`h-6 w-6 ${colors.text}`} />
                                      </AvatarFallback>
                                    </Avatar>
                                  ) : (
                                    <Package className={`h-8 w-8 ${colors.text}`} />
                                  )}
                                </div>
                                {/* Status Badge */}
                                <div className={`absolute top-2 right-2 px-2 py-0.5 rounded-full text-[10px] font-semibold uppercase tracking-wider ${colors.badge}`}>
                                  {stockStatus === "critical" ? "Critical" : stockStatus === "empty" ? "Out of Stock" : stockStatus === "low" ? "Low Stock" : "In Stock"}
                                </div>
                              </div>
                              
                              {/* Content */}
                              <div className="entity-card-content">
                                <div>
                                  <h3 className="entity-card-title">{row.name}</h3>
                                  <p className="entity-card-subtitle mt-0.5">{row.sku}</p>
                                </div>

                                {row.category && (
                                  <Badge variant="outline" className="text-xs font-normal">{row.category}</Badge>
                                )}

                                {/* Stock display */}
                                <div className="bg-muted/50 rounded-xl p-3">
                                  <div className="flex items-center justify-between">
                                    <span className="entity-card-label">Current Stock</span>
                                  </div>
                                  <div className="flex items-baseline gap-1.5 mt-1">
                                    <span className={`text-2xl font-bold tracking-tight ${colors.text}`}>
                                      {row.quantity}
                                    </span>
                                    <span className="text-sm text-muted-foreground">{row.unit}</span>
                                  </div>
                                </div>

                                {/* Actions */}
                                {canEdit && (
                                  <Button 
                                    variant="default" 
                                    size="sm" 
                                    className="w-full h-9 font-medium"
                                    onClick={() => {
                                      setAdjustProduct(row);
                                      setAdjustType("adjustment");
                                      setShowAdjust(true);
                                    }}
                                  >
                                    <Plus className="h-4 w-4 mr-1.5" />
                                    Adjust Stock
                                  </Button>
                                )}
                              </div>
                            </div>
                          );
                        })}
                      </div>
                      {filteredInventory.length === 0 && (
                        <div className="text-center py-12 text-muted-foreground">
                          No products found.
                        </div>
                      )}
                    </div>
                ) : (
                    /* Mobile: DataTable with compact cards */
                    <DataTable 
                        data={filteredInventory || []} 
                        columns={columns} 
                        searchKey="name"
                        searchPlaceholder="Search products..."
                        renderMobileCard={(row: any) => {
                          const stockStatus = row.quantity < 0 ? "critical" : row.quantity === 0 ? "empty" : row.quantity < 10 ? "low" : "good";
                          const statusColors = {
                            critical: "text-red-600",
                            empty: "text-slate-400",
                            low: "text-amber-600",
                            good: "text-emerald-600",
                          };
                          return (
                            <div className="rounded-lg border bg-card p-3">
                              {/* SKU + Stock in one row */}
                              <div className="flex items-center justify-between mb-1">
                                <span className="font-mono text-xs text-muted-foreground">{row.sku}</span>
                                <span className={`font-bold text-sm ${statusColors[stockStatus]}`}>
                                  {row.quantity} <span className="text-xs font-normal text-muted-foreground">{row.unit}</span>
                                </span>
                              </div>
                              {/* Product name */}
                              <p className="font-medium text-sm truncate">{row.name}</p>
                              {/* Category + Action */}
                              <div className="flex items-center justify-between mt-2 pt-2 border-t border-border/50">
                                <span className="text-xs text-muted-foreground">{row.category || "—"}</span>
                                {canEdit && (
                                  <Button 
                                    variant="ghost" 
                                    size="sm" 
                                    className="h-7 text-xs"
                                    onClick={(e) => {
                                      e.stopPropagation();
                                      setAdjustProduct(row);
                                      setAdjustType("adjustment");
                                      setShowAdjust(true);
                                    }}
                                  >
                                    Adjust
                                  </Button>
                                )}
                              </div>
                            </div>
                          );
                        }}
                    />
                )}
            </TabsContent>

            <TabsContent value="movements">
                 <div className="rounded-md border">
                    <DataTable 
                        data={movements || []} 
                        columns={movementColumns} 
                    />
                 </div>
            </TabsContent>

            {/* Raw Materials Tab */}
            <TabsContent value="raw-materials" className="space-y-4">
                {loadRawMaterials ? (
                    <div className="flex items-center justify-center py-10"><Loader2 className="animate-spin" /></div>
                ) : !isMobile ? (
                    /* Desktop: Card Grid for Raw Materials */
                    <div className="space-y-4">
                      <Input 
                        placeholder="Search raw materials..." 
                        value={rawMaterialSearchTerm}
                        onChange={(e) => setRawMaterialSearchTerm(e.target.value)}
                        className="max-w-sm"
                      />
                      <div className="entity-grid">
                        {filteredRawMaterials.map((row: any) => {
                          const minStock = row.min_stock_level || 0;
                          const stockStatus = row.warehouse_quantity < 0 ? "critical" 
                            : row.warehouse_quantity === 0 ? "empty" 
                            : row.warehouse_quantity <= minStock ? "low" 
                            : "good";
                          const statusColors = {
                            critical: { badge: "bg-red-100 text-red-700", text: "text-red-600" },
                            empty: { badge: "bg-slate-100 text-slate-600", text: "text-slate-500" },
                            low: { badge: "bg-amber-100 text-amber-700", text: "text-amber-600" },
                            good: { badge: "bg-emerald-100 text-emerald-700", text: "text-emerald-600" },
                          };
                          const colors = statusColors[stockStatus];
                          
                          return (
                            <div
                              key={row.id}
                              className="group entity-card"
                            >
                              {/* Header */}
                              <div className="entity-card-header">
                                <div className="entity-card-icon-box">
                                  {row.image_url ? (
                                    <Avatar className="h-12 w-12 rounded-lg">
                                      <AvatarImage src={row.image_url} alt={row.name} className="object-cover" />
                                      <AvatarFallback className="rounded-lg bg-muted">
                                        <FlaskConical className={`h-6 w-6 ${colors.text}`} />
                                      </AvatarFallback>
                                    </Avatar>
                                  ) : (
                                    <FlaskConical className={`h-8 w-8 ${colors.text}`} />
                                  )}
                                </div>
                                {/* Status Badge */}
                                <div className={`absolute top-2 right-2 px-2 py-0.5 rounded-full text-[10px] font-semibold uppercase tracking-wider ${colors.badge}`}>
                                  {stockStatus === "critical" ? "Critical" : stockStatus === "empty" ? "Out of Stock" : stockStatus === "low" ? "Low Stock" : "In Stock"}
                                </div>
                              </div>
                              
                              {/* Content */}
                              <div className="entity-card-content">
                                <div>
                                  <h3 className="entity-card-title">{row.name}</h3>
                                  <p className="entity-card-subtitle mt-0.5">{row.display_id}</p>
                                </div>

                                {row.category && (
                                  <Badge variant="outline" className="text-xs font-normal">{row.category}</Badge>
                                )}

                                {/* Stock display */}
                                <div className="bg-muted/50 rounded-xl p-3">
                                  <div className="flex items-center justify-between">
                                    <span className="entity-card-label">Warehouse Stock</span>
                                    {minStock > 0 && (
                                      <span className="text-xs text-muted-foreground">Min: {minStock}</span>
                                    )}
                                  </div>
                                  <div className="flex items-baseline gap-1.5 mt-1">
                                    <span className={`text-2xl font-bold tracking-tight ${colors.text}`}>
                                      {row.warehouse_quantity}
                                    </span>
                                    <span className="text-sm text-muted-foreground">{row.unit}</span>
                                  </div>
                                  {row.unit_cost > 0 && (
                                    <p className="text-xs text-muted-foreground mt-1">
                                      Unit cost: ₹{row.unit_cost?.toFixed(2)}
                                    </p>
                                  )}
                                </div>

                                {/* Actions - Used/Remaining */}
                                {canEdit && (
                                  <div className="flex gap-2">
                                    <Button 
                                      variant="outline" 
                                      size="sm" 
                                      className="flex-1 h-9 font-medium"
                                      onClick={() => {
                                        setAdjustRawMaterial(row);
                                        setRawMaterialAdjustType("used");
                                        setShowRawMaterialAdjust(true);
                                      }}
                                    >
                                      <Minus className="h-4 w-4 mr-1.5" />
                                      Used
                                    </Button>
                                    <Button 
                                      variant="default" 
                                      size="sm" 
                                      className="flex-1 h-9 font-medium"
                                      onClick={() => {
                                        setAdjustRawMaterial(row);
                                        setRawMaterialAdjustType("remaining");
                                        setShowRawMaterialAdjust(true);
                                      }}
                                    >
                                      <Plus className="h-4 w-4 mr-1.5" />
                                      Remaining
                                    </Button>
                                  </div>
                                )}
                              </div>
                            </div>
                          );
                        })}
                      </div>
                      {filteredRawMaterials.length === 0 && (
                        <div className="text-center py-12 text-muted-foreground">
                          No raw materials found. Add raw materials in the Purchases section.
                        </div>
                      )}
                    </div>
                ) : (
                    /* Mobile: DataTable for Raw Materials */
                    <DataTable 
                        data={filteredRawMaterials || []} 
                        columns={[
                          { header: "ID", accessor: "display_id", className: "w-[80px] font-mono text-xs" },
                          { header: "Material", accessor: "name", className: "font-medium" },
                          { header: "Category", accessor: "category" },
                          { 
                              header: "Stock", 
                              accessor: (row: any) => (
                                  <div className={`font-bold ${row.warehouse_quantity < 0 ? "text-red-500" : row.warehouse_quantity === 0 ? "text-slate-400" : "text-green-600"}`}>
                                      {row.warehouse_quantity} <span className="text-xs font-normal text-slate-500">{row.unit}</span>
                                  </div>
                              ) 
                          },
                          {
                              header: "Action",
                              accessor: (row: any) => canEdit && (
                                <div className="flex gap-1">
                                  <Button variant="ghost" size="sm" className="h-7 px-2" onClick={() => {
                                      setAdjustRawMaterial(row);
                                      setRawMaterialAdjustType("used");
                                      setShowRawMaterialAdjust(true);
                                  }}>
                                      Used
                                  </Button>
                                  <Button variant="ghost" size="sm" className="h-7 px-2" onClick={() => {
                                      setAdjustRawMaterial(row);
                                      setRawMaterialAdjustType("remaining");
                                      setShowRawMaterialAdjust(true);
                                  }}>
                                      Count
                                  </Button>
                                </div>
                              )
                          }
                        ]} 
                        searchKey="name"
                        searchPlaceholder="Search raw materials..."
                    />
                )}
            </TabsContent>
        </Tabs>

        <Dialog open={showAdjust} onOpenChange={setShowAdjust}>
            <DialogContent>
                <DialogHeader>
                    <DialogTitle>Adjust Stock for {adjustProduct?.name}</DialogTitle>
                    <DialogDescription>
                        Record a stock movement. Current stock: {adjustProduct?.quantity} {adjustProduct?.unit}
                    </DialogDescription>
                </DialogHeader>
                <form onSubmit={handleAdjust} className="space-y-4">
                    <div className="space-y-2">
                        <Label>Movement Type</Label>
                        <Select value={adjustType} onValueChange={(v) => setAdjustType(v as MovementType)}>
                            <SelectTrigger>
                                <SelectValue />
                            </SelectTrigger>
                            <SelectContent>
                                {Object.entries(MOVEMENT_TYPES).map(([k, v]) => (
                                    <SelectItem key={k} value={k}>{v}</SelectItem>
                                ))}
                            </SelectContent>
                        </Select>
                    </div>

                    <div className="space-y-2">
                        <Label>Quantity ({adjustProduct?.unit})</Label>
                        <Input 
                            type="number" 
                            step="0.01"
                            placeholder="0.00" 
                            value={adjustQty}
                            onChange={(e) => setAdjustQty(e.target.value)}
                            required
                        />
                         <p className="text-xs text-muted-foreground">
                            {adjustType === "adjustment" ? "Use negative for reduction." : "Enter positive value, system will apply sign."}
                        </p>
                    </div>

                    <div className="space-y-2">
                        <Label>Reason / Note</Label>
                        <Textarea 
                            value={adjustReason}
                            onChange={(e) => setAdjustReason(e.target.value)}
                            placeholder="e.g. Broken stock, Received shipment #123"
                        />
                    </div>

                    <DialogFooter>
                        <Button type="button" variant="outline" onClick={() => setShowAdjust(false)}>Cancel</Button>
                        <Button type="submit" disabled={saving}>
                            {saving && <Loader2 className="mr-2 h-4 w-4 animate-spin" />}
                            Confirm Adjustment
                        </Button>
                    </DialogFooter>
                </form>
            </DialogContent>
        </Dialog>

        {/* Raw Material Adjustment Dialog */}
        <Dialog open={showRawMaterialAdjust} onOpenChange={setShowRawMaterialAdjust}>
            <DialogContent>
                <DialogHeader>
                    <DialogTitle>
                        {rawMaterialAdjustType === "used" ? "Record Usage" : "Physical Count"} - {adjustRawMaterial?.name}
                    </DialogTitle>
                    <DialogDescription>
                        {rawMaterialAdjustType === "used" 
                            ? `Record how much was consumed. Current stock: ${adjustRawMaterial?.warehouse_quantity || 0} ${adjustRawMaterial?.unit}`
                            : `Enter the actual remaining quantity. Current stock: ${adjustRawMaterial?.warehouse_quantity || 0} ${adjustRawMaterial?.unit}`
                        }
                    </DialogDescription>
                </DialogHeader>
                <form onSubmit={handleRawMaterialAdjust} className="space-y-4">
                    <div className="space-y-2">
                        <Label>Adjustment Type</Label>
                        <Select value={rawMaterialAdjustType} onValueChange={(v) => setRawMaterialAdjustType(v as RawMaterialAdjustType)}>
                            <SelectTrigger>
                                <SelectValue />
                            </SelectTrigger>
                            <SelectContent>
                                {Object.entries(RAW_MATERIAL_ADJUST_TYPES).map(([k, v]) => (
                                    <SelectItem key={k} value={k}>{v}</SelectItem>
                                ))}
                            </SelectContent>
                        </Select>
                    </div>

                    <div className="space-y-2">
                        <Label>
                            {rawMaterialAdjustType === "used" ? "Quantity Used" : "Remaining Quantity"} ({adjustRawMaterial?.unit})
                        </Label>
                        <Input 
                            type="number" 
                            step="0.01"
                            min="0"
                            placeholder="0.00" 
                            value={rawMaterialQty}
                            onChange={(e) => setRawMaterialQty(e.target.value)}
                            required
                        />
                        <p className="text-xs text-muted-foreground">
                            {rawMaterialAdjustType === "used" 
                                ? "This amount will be deducted from stock."
                                : "Stock will be set to this value. Difference = consumption."
                            }
                        </p>
                    </div>

                    <div className="space-y-2">
                        <Label>Reason / Note (optional)</Label>
                        <Textarea 
                            value={rawMaterialReason}
                            onChange={(e) => setRawMaterialReason(e.target.value)}
                            placeholder={rawMaterialAdjustType === "used" 
                                ? "e.g. Used for batch #123, Daily production"
                                : "e.g. Physical count, Stock audit"
                            }
                        />
                    </div>

                    <DialogFooter>
                        <Button type="button" variant="outline" onClick={() => setShowRawMaterialAdjust(false)}>Cancel</Button>
                        <Button type="submit" disabled={saving}>
                            {saving && <Loader2 className="mr-2 h-4 w-4 animate-spin" />}
                            {rawMaterialAdjustType === "used" ? "Record Usage" : "Update Count"}
                        </Button>
                    </DialogFooter>
                </form>
            </DialogContent>
        </Dialog>
    </div>
  );
};

export default Inventory;

import { useState, useEffect, useMemo } from "react";
import { useNavigate, useParams, useLocation } from "react-router-dom";
import { PageHeader } from "@/components/shared/PageHeader";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Textarea } from "@/components/ui/textarea";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { Checkbox } from "@/components/ui/checkbox";
import { Badge } from "@/components/ui/badge";
import { useQuery, useQueryClient } from "@tanstack/react-query";
import { supabase } from "@/integrations/supabase/client";
import { useAuth } from "@/contexts/AuthContext";
import { Loader2, Plus, Trash2, ArrowLeft, Save, FileText } from "lucide-react";
import { toast } from "sonner";
import { logActivity } from "@/lib/activityLogger";

interface InvoiceItem {
  id?: string;
  product_id: string | null;
  product_name: string;
  hsn_code: string;
  quantity: number;
  unit_price: number;
  tax_rate: number;
  tax_amount: number;
  discount_amount: number;
  total_amount: number;
  sale_item_id?: string;
}

const InvoiceForm = () => {
  const navigate = useNavigate();
  const { id } = useParams();
  const location = useLocation();
  const { user } = useAuth();
  const qc = useQueryClient();
  const isEdit = !!id && id !== "new";

  // Form state
  const [invoiceNumber, setInvoiceNumber] = useState("");
  const [invoiceDate, setInvoiceDate] = useState(new Date().toISOString().split("T")[0]);
  const [customerId, setCustomerId] = useState("");
  const [storeId, setStoreId] = useState("");
  const [customerName, setCustomerName] = useState("");
  const [customerAddress, setCustomerAddress] = useState("");
  const [customerPhone, setCustomerPhone] = useState("");
  const [customerGstin, setCustomerGstin] = useState("");
  const [customerState, setCustomerState] = useState("");
  const [isInterState, setIsInterState] = useState(false);
  const [warehouseId, setWarehouseId] = useState("");
  const [notes, setNotes] = useState("");
  const [items, setItems] = useState<InvoiceItem[]>([]);
  const [selectedSales, setSelectedSales] = useState<string[]>(location.state?.saleIds || []);
  const [saving, setSaving] = useState(false);
  const [loadingNext, setLoadingNext] = useState(true);

  // Fetch business info for state comparison
  const { data: businessInfo } = useQuery({
    queryKey: ["business-info"],
    queryFn: async () => {
      const { data } = await supabase
        .from("business_info")
        .select("*")
        .single();
      return data;
    },
  });

  // Fetch next invoice number
  useEffect(() => {
    if (!isEdit) {
      supabase.rpc("get_next_invoice_number").then(({ data }) => {
        if (data) setInvoiceNumber(data);
        setLoadingNext(false);
      });
    } else {
      setLoadingNext(false);
    }
  }, [isEdit]);

  // Fetch customers
  const { data: customers = [] } = useQuery({
    queryKey: ["customers-for-invoice"],
    queryFn: async () => {
      const { data } = await supabase
        .from("customers")
        .select("id, name, phone, address")
        .eq("is_active", true)
        .order("name");
      return data || [];
    },
  });

  // Fetch stores for selected customer
  const { data: stores = [] } = useQuery({
    queryKey: ["stores-for-invoice", customerId],
    queryFn: async () => {
      if (!customerId) return [];
      const { data } = await supabase
        .from("stores")
        .select("id, name, address, phone, store_type_id")
        .eq("customer_id", customerId)
        .eq("is_active", true);
      return data || [];
    },
    enabled: !!customerId,
  });

  // Get selected store's type for product filtering
  const selectedStore = stores.find((s: any) => s.id === storeId);
  const selectedStoreTypeId = selectedStore?.store_type_id;

  // Fetch warehouses
  const { data: warehouses = [] } = useQuery({
    queryKey: ["warehouses-for-invoice"],
    queryFn: async () => {
      const { data } = await supabase
        .from("warehouses")
        .select("id, name, address, city, state, is_default")
        .eq("is_active", true);
      return data || [];
    },
  });

  // Fetch products - filtered by store type if selected, else all active products
  const { data: products = [] } = useQuery({
    queryKey: ["products-for-invoice", selectedStoreTypeId],
    queryFn: async () => {
      // If store is selected, get products for that store type
      if (selectedStoreTypeId) {
        const { data: storeTypeProducts } = await supabase
          .from("store_type_products")
          .select("product_id, products(id, name, hsn_code, mrp, gst_rate)")
          .eq("store_type_id", selectedStoreTypeId);
        
        if (storeTypeProducts && storeTypeProducts.length > 0) {
          return storeTypeProducts.map((stp: any) => stp.products).filter(Boolean);
        }
      }
      
      // Fallback: all active products (when no store selected or no store_type_products configured)
      const { data } = await supabase
        .from("products")
        .select("id, name, hsn_code, mrp, gst_rate")
        .eq("is_active", true);
      return data || [];
    },
  });

  // Fetch uninvoiced sales for customer/store
  const { data: availableSales = [] } = useQuery({
    queryKey: ["uninvoiced-sales", customerId, storeId],
    queryFn: async () => {
      if (!customerId) return [];
      let query = supabase
        .from("sales")
        .select(`
          id, display_id, created_at, total_amount,
          sale_items(id, product_id, quantity, unit_price, total_amount, products(name, hsn_code, gst_rate))
        `)
        .eq("customer_id", customerId)
        .eq("has_invoice", false);
      
      if (storeId) {
        query = query.eq("store_id", storeId);
      }
      
      const { data } = await query.order("created_at", { ascending: false });
      return data || [];
    },
    enabled: !!customerId,
  });

  // Set default warehouse
  useEffect(() => {
    if (warehouses.length > 0 && !warehouseId) {
      const defaultWh = warehouses.find((w: any) => w.is_default);
      setWarehouseId(defaultWh?.id || warehouses[0].id);
    }
  }, [warehouses, warehouseId]);

  // Auto-fill customer details
  useEffect(() => {
    if (customerId) {
      const customer = customers.find((c: any) => c.id === customerId);
      if (customer) {
        setCustomerName(customer.name);
        setCustomerPhone(customer.phone || "");
        setCustomerAddress(customer.address || "");
      }
    }
  }, [customerId, customers]);

  // Auto-fill store details (override customer if store selected)
  useEffect(() => {
    if (storeId) {
      const store = stores.find((s: any) => s.id === storeId);
      if (store) {
        setCustomerAddress(store.address || customerAddress);
        setCustomerPhone(store.phone || customerPhone);
        setCustomerGstin(store.gstin || "");
      }
    }
  }, [storeId, stores]);

  // Load items from selected sales
  useEffect(() => {
    if (selectedSales.length > 0 && availableSales.length > 0) {
      const newItems: InvoiceItem[] = [];
      selectedSales.forEach((saleId) => {
        const sale = availableSales.find((s: any) => s.id === saleId);
        if (sale?.sale_items) {
          sale.sale_items.forEach((item: any) => {
            newItems.push({
              product_id: item.product_id,
              product_name: item.products?.name || "Unknown",
              hsn_code: item.products?.hsn_code || "",
              quantity: item.quantity,
              unit_price: item.unit_price,
              tax_rate: item.products?.gst_rate || 0,
              tax_amount: (item.total_amount * (item.products?.gst_rate || 0)) / 100,
              discount_amount: 0,
              total_amount: item.total_amount,
              sale_item_id: item.id,
            });
          });
        }
      });
      setItems(newItems);
    }
  }, [selectedSales, availableSales]);

  // Calculate totals with CGST/SGST/IGST breakdown
  const totals = useMemo(() => {
    // Calculate taxable amount (price / (1 + gst_rate/100) for GST-inclusive prices)
    let taxableAmount = 0;
    let totalTax = 0;
    let discountAmount = 0;
    
    items.forEach(item => {
      const lineTotal = item.quantity * item.unit_price;
      // Assume prices are GST-inclusive: base = price / (1 + gst_rate/100)
      const taxRate = item.tax_rate || 0;
      const baseAmount = taxRate > 0 ? lineTotal / (1 + taxRate / 100) : lineTotal;
      const lineTax = lineTotal - baseAmount;
      
      taxableAmount += baseAmount;
      totalTax += lineTax;
      discountAmount += item.discount_amount;
    });

    // Split tax based on inter-state or intra-state
    const cgstAmount = isInterState ? 0 : totalTax / 2;
    const sgstAmount = isInterState ? 0 : totalTax / 2;
    const igstAmount = isInterState ? totalTax : 0;
    
    const grandTotal = taxableAmount + totalTax - discountAmount;
    
    return { 
      taxableAmount: Math.round(taxableAmount * 100) / 100,
      cgstAmount: Math.round(cgstAmount * 100) / 100,
      sgstAmount: Math.round(sgstAmount * 100) / 100,
      igstAmount: Math.round(igstAmount * 100) / 100,
      totalTax: Math.round(totalTax * 100) / 100,
      discountAmount: Math.round(discountAmount * 100) / 100,
      grandTotal: Math.round(grandTotal * 100) / 100
    };
  }, [items, isInterState]);

  const handleSaleToggle = (saleId: string) => {
    setSelectedSales((prev) =>
      prev.includes(saleId) ? prev.filter((id) => id !== saleId) : [...prev, saleId]
    );
  };

  const addEmptyItem = () => {
    setItems([...items, {
      product_id: null,
      product_name: "",
      hsn_code: "",
      quantity: 1,
      unit_price: 0,
      tax_rate: 0,
      tax_amount: 0,
      discount_amount: 0,
      total_amount: 0,
    }]);
  };

  const updateItem = (index: number, field: keyof InvoiceItem, value: any) => {
    const newItems = [...items];
    const item = { ...newItems[index], [field]: value };
    
    // If product selected, auto-fill details
    if (field === "product_id" && value) {
      const product = products.find((p: any) => p.id === value);
      if (product) {
        item.product_name = product.name;
        item.hsn_code = product.hsn_code || "";
        item.unit_price = product.mrp || 0;
        item.tax_rate = product.gst_rate || 0;
      }
    }
    
    // Recalculate amounts
    const lineTotal = item.quantity * item.unit_price;
    item.tax_amount = (lineTotal * item.tax_rate) / 100;
    item.total_amount = lineTotal + item.tax_amount - item.discount_amount;
    
    newItems[index] = item;
    setItems(newItems);
  };

  const removeItem = (index: number) => {
    setItems(items.filter((_, i) => i !== index));
  };

  const handleSubmit = async (status: "draft" | "issued") => {
    if (!invoiceNumber.trim()) {
      toast.error("Invoice number is required");
      return;
    }
    if (!customerName.trim()) {
      toast.error("Customer name is required");
      return;
    }
    if (items.length === 0) {
      toast.error("Add at least one item");
      return;
    }

    setSaving(true);

    try {
      const warehouse = warehouses.find((w: any) => w.id === warehouseId);
      const dispatchAddress = warehouse 
        ? `${warehouse.name}, ${warehouse.address || ""}, ${warehouse.city || ""}, ${warehouse.state || ""}`.trim()
        : "";

      // Create invoice
      const invoiceData = {
        invoice_number: invoiceNumber.trim(),
        invoice_date: invoiceDate,
        customer_id: customerId || null,
        store_id: storeId || null,
        customer_name: customerName.trim(),
        customer_address: customerAddress.trim() || null,
        customer_phone: customerPhone.trim() || null,
        customer_gstin: customerGstin.trim() || null,
        buyer_state: customerState.trim() || null,
        dispatch_warehouse_id: warehouseId || null,
        dispatch_address: dispatchAddress || null,
        is_inter_state: isInterState,
        taxable_amount: totals.taxableAmount,
        cgst_rate: isInterState ? null : (totals.cgstAmount > 0 ? (totals.cgstAmount / totals.taxableAmount * 100) : 0),
        cgst_amount: totals.cgstAmount,
        sgst_rate: isInterState ? null : (totals.sgstAmount > 0 ? (totals.sgstAmount / totals.taxableAmount * 100) : 0),
        sgst_amount: totals.sgstAmount,
        igst_rate: isInterState ? (totals.igstAmount > 0 ? (totals.igstAmount / totals.taxableAmount * 100) : 0) : null,
        igst_amount: totals.igstAmount,
        subtotal: totals.taxableAmount,
        tax_amount: totals.totalTax,
        discount_amount: totals.discountAmount,
        total_amount: totals.grandTotal,
        status,
        notes: notes.trim() || null,
        created_by: user!.id,
      };

      const { data: invoice, error: invError } = await supabase
        .from("invoices")
        .insert(invoiceData)
        .select()
        .single();

      if (invError) throw invError;

      // Create invoice items
      const itemsData = items.map((item) => {
        const lineTotal = item.quantity * item.unit_price;
        const taxRate = item.tax_rate || 0;
        const taxableAmount = taxRate > 0 ? lineTotal / (1 + taxRate / 100) : lineTotal;
        const lineTax = lineTotal - taxableAmount;
        
        return {
          invoice_id: invoice.id,
          product_id: item.product_id,
          product_name: item.product_name,
          hsn_code: item.hsn_code || null,
          quantity: item.quantity,
          unit_price: item.unit_price,
          gst_rate: taxRate,
          taxable_amount: Math.round(taxableAmount * 100) / 100,
          cgst_amount: isInterState ? 0 : Math.round(lineTax / 2 * 100) / 100,
          sgst_amount: isInterState ? 0 : Math.round(lineTax / 2 * 100) / 100,
          igst_amount: isInterState ? Math.round(lineTax * 100) / 100 : 0,
          tax_rate: taxRate,
          tax_amount: Math.round(lineTax * 100) / 100,
          discount_amount: item.discount_amount,
          total_amount: lineTotal,
          sale_item_id: item.sale_item_id || null,
        };
      });

      const { error: itemsError } = await supabase
        .from("invoice_items")
        .insert(itemsData);

      if (itemsError) throw itemsError;

      // Link sales to invoice
      if (selectedSales.length > 0) {
        const salesLinks = selectedSales.map((saleId) => ({
          invoice_id: invoice.id,
          sale_id: saleId,
        }));

        const { error: linkError } = await supabase
          .from("invoice_sales")
          .insert(salesLinks);

        if (linkError) throw linkError;
      }

      toast.success(`Invoice ${invoiceNumber} ${status === "issued" ? "issued" : "saved as draft"}`);
      logActivity(user!.id, `Created invoice ${invoiceNumber}`, "invoice");
      qc.invalidateQueries({ queryKey: ["invoices"] });
      qc.invalidateQueries({ queryKey: ["sales"] });
      navigate("/invoices");
    } catch (error: any) {
      toast.error(error.message || "Failed to create invoice");
    } finally {
      setSaving(false);
    }
  };

  if (loadingNext) {
    return (
      <div className="flex items-center justify-center py-20">
        <Loader2 className="h-8 w-8 animate-spin text-primary" />
      </div>
    );
  }

  return (
    <div className="space-y-6 animate-fade-in pb-20">
      <PageHeader
        title={isEdit ? "Edit Invoice" : "Create Invoice"}
        subtitle="Generate a tax invoice"
        backButton={{ label: "Back to Invoices", onClick: () => navigate("/invoices") }}
      />

      <div className="grid gap-6 lg:grid-cols-3">
        {/* Left Column - Main Form */}
        <div className="lg:col-span-2 space-y-6">
          {/* Invoice Details */}
          <Card>
            <CardHeader>
              <CardTitle className="text-base">Invoice Details</CardTitle>
            </CardHeader>
            <CardContent className="space-y-4">
              <div className="grid grid-cols-2 gap-4">
                <div>
                  <Label>Invoice Number *</Label>
                  <Input
                    value={invoiceNumber}
                    onChange={(e) => setInvoiceNumber(e.target.value)}
                    placeholder="INV-000001"
                    className="mt-1 font-mono"
                  />
                </div>
                <div>
                  <Label>Invoice Date *</Label>
                  <Input
                    type="date"
                    value={invoiceDate}
                    onChange={(e) => setInvoiceDate(e.target.value)}
                    className="mt-1"
                  />
                </div>
              </div>
            </CardContent>
          </Card>

          {/* Customer Details */}
          <Card>
            <CardHeader>
              <CardTitle className="text-base">Bill To</CardTitle>
            </CardHeader>
            <CardContent className="space-y-4">
              <div className="grid grid-cols-2 gap-4">
                <div>
                  <Label>Select Customer</Label>
                  <Select value={customerId} onValueChange={setCustomerId}>
                    <SelectTrigger className="mt-1">
                      <SelectValue placeholder="Select customer" />
                    </SelectTrigger>
                    <SelectContent>
                      {customers.map((c: any) => (
                        <SelectItem key={c.id} value={c.id}>{c.name}</SelectItem>
                      ))}
                    </SelectContent>
                  </Select>
                </div>
                <div>
                  <Label>Select Store</Label>
                  <Select value={storeId} onValueChange={setStoreId} disabled={!customerId}>
                    <SelectTrigger className="mt-1">
                      <SelectValue placeholder={customerId ? "Select store" : "Select customer first"} />
                    </SelectTrigger>
                    <SelectContent>
                      {stores.map((s: any) => (
                        <SelectItem key={s.id} value={s.id}>{s.name}</SelectItem>
                      ))}
                    </SelectContent>
                  </Select>
                </div>
              </div>

              <div className="grid grid-cols-2 gap-4">
                <div>
                  <Label>Customer Name *</Label>
                  <Input
                    value={customerName}
                    onChange={(e) => setCustomerName(e.target.value)}
                    placeholder="Customer name"
                    className="mt-1"
                  />
                </div>
                <div>
                  <Label>Phone</Label>
                  <Input
                    value={customerPhone}
                    onChange={(e) => setCustomerPhone(e.target.value)}
                    placeholder="Phone number"
                    className="mt-1"
                  />
                </div>
              </div>

              <div className="grid grid-cols-2 gap-4">
                <div>
                  <Label>Address</Label>
                  <Textarea
                    value={customerAddress}
                    onChange={(e) => setCustomerAddress(e.target.value)}
                    placeholder="Billing address"
                    className="mt-1"
                    rows={2}
                  />
                </div>
                <div>
                  <Label>GSTIN</Label>
                  <Input
                    value={customerGstin}
                    onChange={(e) => setCustomerGstin(e.target.value.toUpperCase())}
                    placeholder="Customer GSTIN"
                    className="mt-1 font-mono"
                    maxLength={15}
                  />
                </div>
              </div>
            </CardContent>
          </Card>

          {/* Link Sales */}
          {customerId && availableSales.length > 0 && (
            <Card>
              <CardHeader>
                <CardTitle className="text-base">Link Sales (Optional)</CardTitle>
              </CardHeader>
              <CardContent>
                <div className="space-y-2 max-h-48 overflow-y-auto">
                  {availableSales.map((sale: any) => (
                    <div
                      key={sale.id}
                      className={`flex items-center gap-3 p-3 rounded-lg border cursor-pointer transition-colors ${
                        selectedSales.includes(sale.id) ? "border-primary bg-primary/5" : "hover:bg-muted/50"
                      }`}
                      onClick={() => handleSaleToggle(sale.id)}
                    >
                      <Checkbox checked={selectedSales.includes(sale.id)} />
                      <div className="flex-1">
                        <p className="font-mono text-sm font-medium">{sale.display_id}</p>
                        <p className="text-xs text-muted-foreground">
                          {new Date(sale.created_at).toLocaleDateString("en-IN")} • {sale.sale_items?.length || 0} items
                        </p>
                      </div>
                      <span className="font-semibold">₹{Number(sale.total_amount).toLocaleString()}</span>
                    </div>
                  ))}
                </div>
              </CardContent>
            </Card>
          )}

          {/* Invoice Items */}
          <Card>
            <CardHeader className="flex flex-row items-center justify-between">
              <CardTitle className="text-base">Items</CardTitle>
              <Button variant="outline" size="sm" onClick={addEmptyItem}>
                <Plus className="h-4 w-4 mr-1" /> Add Item
              </Button>
            </CardHeader>
            <CardContent>
              {items.length === 0 ? (
                <p className="text-center text-muted-foreground py-8">
                  {selectedSales.length > 0 ? "Loading items from sales..." : "No items added. Select sales above or add items manually."}
                </p>
              ) : (
                <div className="space-y-3">
                  {items.map((item, index) => (
                    <div key={index} className="grid grid-cols-12 gap-2 items-end p-3 bg-muted/30 rounded-lg">
                      <div className="col-span-4">
                        <Label className="text-xs">Product</Label>
                        <Select
                          value={item.product_id || ""}
                          onValueChange={(v) => updateItem(index, "product_id", v)}
                        >
                          <SelectTrigger className="mt-1 h-9">
                            <SelectValue placeholder="Select product" />
                          </SelectTrigger>
                          <SelectContent>
                            {products.map((p: any) => (
                              <SelectItem key={p.id} value={p.id}>{p.name}</SelectItem>
                            ))}
                          </SelectContent>
                        </Select>
                      </div>
                      <div className="col-span-2">
                        <Label className="text-xs">HSN</Label>
                        <Input
                          value={item.hsn_code}
                          onChange={(e) => updateItem(index, "hsn_code", e.target.value)}
                          className="mt-1 h-9 font-mono text-xs"
                        />
                      </div>
                      <div className="col-span-1">
                        <Label className="text-xs">Qty</Label>
                        <Input
                          type="number"
                          min="1"
                          value={item.quantity}
                          onChange={(e) => updateItem(index, "quantity", parseFloat(e.target.value) || 0)}
                          className="mt-1 h-9"
                        />
                      </div>
                      <div className="col-span-2">
                        <Label className="text-xs">Price</Label>
                        <Input
                          type="number"
                          min="0"
                          step="0.01"
                          value={item.unit_price}
                          onChange={(e) => updateItem(index, "unit_price", parseFloat(e.target.value) || 0)}
                          className="mt-1 h-9"
                        />
                      </div>
                      <div className="col-span-2">
                        <Label className="text-xs">Total</Label>
                        <div className="mt-1 h-9 flex items-center font-semibold">
                          ₹{item.total_amount.toLocaleString()}
                        </div>
                      </div>
                      <div className="col-span-1">
                        <Button
                          variant="ghost"
                          size="icon"
                          className="h-9 w-9 text-destructive"
                          onClick={() => removeItem(index)}
                        >
                          <Trash2 className="h-4 w-4" />
                        </Button>
                      </div>
                    </div>
                  ))}
                </div>
              )}
            </CardContent>
          </Card>

          {/* Notes */}
          <Card>
            <CardHeader>
              <CardTitle className="text-base">Notes</CardTitle>
            </CardHeader>
            <CardContent>
              <Textarea
                value={notes}
                onChange={(e) => setNotes(e.target.value)}
                placeholder="Additional notes for this invoice..."
                rows={3}
              />
            </CardContent>
          </Card>
        </div>

        {/* Right Column - Summary & Actions */}
        <div className="space-y-6">
          {/* Dispatch From */}
          <Card>
            <CardHeader>
              <CardTitle className="text-base">Dispatch From</CardTitle>
            </CardHeader>
            <CardContent>
              <Select value={warehouseId} onValueChange={setWarehouseId}>
                <SelectTrigger>
                  <SelectValue placeholder="Select warehouse" />
                </SelectTrigger>
                <SelectContent>
                  {warehouses.map((w: any) => (
                    <SelectItem key={w.id} value={w.id}>
                      {w.name} {w.is_default && "(Default)"}
                    </SelectItem>
                  ))}
                </SelectContent>
              </Select>
            </CardContent>
          </Card>

          {/* GST Type Toggle */}
          <Card>
            <CardHeader>
              <CardTitle className="text-base">GST Type</CardTitle>
            </CardHeader>
            <CardContent>
              <div className="flex items-center gap-4">
                <div className="flex items-center gap-2">
                  <input
                    type="radio"
                    id="intra-state"
                    name="gst-type"
                    checked={!isInterState}
                    onChange={() => setIsInterState(false)}
                    className="w-4 h-4"
                  />
                  <label htmlFor="intra-state" className="text-sm">Intra-State (CGST + SGST)</label>
                </div>
                <div className="flex items-center gap-2">
                  <input
                    type="radio"
                    id="inter-state"
                    name="gst-type"
                    checked={isInterState}
                    onChange={() => setIsInterState(true)}
                    className="w-4 h-4"
                  />
                  <label htmlFor="inter-state" className="text-sm">Inter-State (IGST)</label>
                </div>
              </div>
              {businessInfo?.state && (
                <p className="text-xs text-muted-foreground mt-2">
                  Business State: {businessInfo.state}
                </p>
              )}
            </CardContent>
          </Card>

          {/* Summary */}
          <Card>
            <CardHeader>
              <CardTitle className="text-base">Tax Summary</CardTitle>
            </CardHeader>
            <CardContent className="space-y-2">
              <div className="flex justify-between text-sm">
                <span className="text-muted-foreground">Taxable Amount</span>
                <span>₹{totals.taxableAmount.toLocaleString()}</span>
              </div>
              
              {!isInterState ? (
                <>
                  <div className="flex justify-between text-sm">
                    <span className="text-muted-foreground">CGST</span>
                    <span>₹{totals.cgstAmount.toLocaleString()}</span>
                  </div>
                  <div className="flex justify-between text-sm">
                    <span className="text-muted-foreground">SGST</span>
                    <span>₹{totals.sgstAmount.toLocaleString()}</span>
                  </div>
                </>
              ) : (
                <div className="flex justify-between text-sm">
                  <span className="text-muted-foreground">IGST</span>
                  <span>₹{totals.igstAmount.toLocaleString()}</span>
                </div>
              )}
              
              {totals.discountAmount > 0 && (
                <div className="flex justify-between text-sm">
                  <span className="text-muted-foreground">Discount</span>
                  <span className="text-green-600">-₹{totals.discountAmount.toLocaleString()}</span>
                </div>
              )}
              <div className="flex justify-between font-bold text-lg pt-3 border-t">
                <span>Grand Total</span>
                <span className="text-primary">₹{totals.grandTotal.toLocaleString()}</span>
              </div>
            </CardContent>
          </Card>

          {/* Actions */}
          <div className="space-y-3">
            <Button
              className="w-full"
              onClick={() => handleSubmit("issued")}
              disabled={saving || items.length === 0}
            >
              {saving ? <Loader2 className="mr-2 h-4 w-4 animate-spin" /> : <FileText className="mr-2 h-4 w-4" />}
              Issue Invoice
            </Button>
            <Button
              variant="outline"
              className="w-full"
              onClick={() => handleSubmit("draft")}
              disabled={saving || items.length === 0}
            >
              <Save className="mr-2 h-4 w-4" />
              Save as Draft
            </Button>
            <Button
              variant="ghost"
              className="w-full"
              onClick={() => navigate("/invoices")}
              disabled={saving}
            >
              <ArrowLeft className="mr-2 h-4 w-4" />
              Cancel
            </Button>
          </div>
        </div>
      </div>
    </div>
  );
};

export default InvoiceForm;

import { useState, useRef } from "react";
import { useNavigate, useParams } from "react-router-dom";
import { PageHeader } from "@/components/shared/PageHeader";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import { Card, CardContent } from "@/components/ui/card";
import { useQuery } from "@tanstack/react-query";
import { supabase } from "@/integrations/supabase/client";
import { Loader2, Printer, Download, ArrowLeft, Share2 } from "lucide-react";
import { toast } from "sonner";

// Number to words converter
const numberToWords = (num: number): string => {
  const ones = ["", "One", "Two", "Three", "Four", "Five", "Six", "Seven", "Eight", "Nine", "Ten",
    "Eleven", "Twelve", "Thirteen", "Fourteen", "Fifteen", "Sixteen", "Seventeen", "Eighteen", "Nineteen"];
  const tens = ["", "", "Twenty", "Thirty", "Forty", "Fifty", "Sixty", "Seventy", "Eighty", "Ninety"];
  
  const convert = (n: number): string => {
    if (n < 20) return ones[n];
    if (n < 100) return tens[Math.floor(n / 10)] + (n % 10 ? " " + ones[n % 10] : "");
    if (n < 1000) return ones[Math.floor(n / 100)] + " Hundred" + (n % 100 ? " " + convert(n % 100) : "");
    if (n < 100000) return convert(Math.floor(n / 1000)) + " Thousand" + (n % 1000 ? " " + convert(n % 1000) : "");
    if (n < 10000000) return convert(Math.floor(n / 100000)) + " Lakh" + (n % 100000 ? " " + convert(n % 100000) : "");
    return convert(Math.floor(n / 10000000)) + " Crore" + (n % 10000000 ? " " + convert(n % 10000000) : "");
  };
  
  const rupees = Math.floor(num);
  const paise = Math.round((num - rupees) * 100);
  
  let result = "Rupees " + convert(rupees);
  if (paise > 0) {
    result += " and " + convert(paise) + " Paise";
  }
  return result + " Only";
};

const InvoiceView = () => {
  const navigate = useNavigate();
  const { id } = useParams();
  const printRef = useRef<HTMLDivElement>(null);

  // Fetch invoice
  const { data: invoice, isLoading } = useQuery({
    queryKey: ["invoice", id],
    queryFn: async () => {
      const { data, error } = await supabase
        .from("invoices")
        .select(`
          *,
          customers(name, phone),
          stores(name),
          warehouses:dispatch_warehouse_id(name, address, city, state),
          invoice_items(*),
          invoice_sales(sale_id, sales(display_id))
        `)
        .eq("id", id)
        .single();
      if (error) throw error;
      return data;
    },
    enabled: !!id,
  });

  // Fetch company settings
  const { data: settings = {} } = useQuery({
    queryKey: ["company-settings-invoice"],
    queryFn: async () => {
      const { data } = await supabase.from("company_settings").select("key, value");
      const map: Record<string, string> = {};
      data?.forEach((s: any) => { map[s.key] = s.value; });
      return map;
    },
  });

  // Fetch business info for GST details
  const { data: businessInfo } = useQuery({
    queryKey: ["business-info-invoice"],
    queryFn: async () => {
      const { data } = await supabase.from("business_info").select("*").single();
      return data;
    },
  });

  const handlePrint = () => {
    window.print();
  };

  const handleShare = async () => {
    if (navigator.share) {
      try {
        await navigator.share({
          title: `Invoice ${invoice?.invoice_number}`,
          text: `Invoice ${invoice?.invoice_number} - ₹${Number(invoice?.total_amount).toLocaleString()}`,
          url: window.location.href,
        });
      } catch (err) {
        // User cancelled share
      }
    } else {
      navigator.clipboard.writeText(window.location.href);
      toast.success("Link copied to clipboard");
    }
  };

  if (isLoading) {
    return (
      <div className="flex items-center justify-center py-20">
        <Loader2 className="h-8 w-8 animate-spin text-primary" />
      </div>
    );
  }

  if (!invoice) {
    return (
      <div className="text-center py-20">
        <p className="text-muted-foreground">Invoice not found</p>
        <Button variant="link" onClick={() => navigate("/invoices")}>
          Back to Invoices
        </Button>
      </div>
    );
  }

  const amountInWords = numberToWords(Number(invoice.total_amount));

  return (
    <div className="space-y-6 animate-fade-in">
      {/* Header - Hide in print */}
      <div className="print:hidden">
        <PageHeader
          title={`Invoice ${invoice.invoice_number}`}
          subtitle={invoice.status === "cancelled" ? "This invoice has been cancelled" : undefined}
          backButton={{ label: "Back to Invoices", onClick: () => navigate("/invoices") }}
        />
        
        <div className="flex gap-2 mt-4">
          <Button onClick={handlePrint}>
            <Printer className="mr-2 h-4 w-4" /> Print
          </Button>
          <Button variant="outline" onClick={handleShare}>
            <Share2 className="mr-2 h-4 w-4" /> Share
          </Button>
        </div>
      </div>

      {/* Invoice Template */}
      <Card className="max-w-4xl mx-auto print:shadow-none print:border-none">
        <CardContent className="p-8 print:p-4" ref={printRef}>
          {/* Cancelled Watermark */}
          {invoice.status === "cancelled" && (
            <div className="absolute inset-0 flex items-center justify-center pointer-events-none">
              <span className="text-red-200 text-8xl font-bold rotate-[-30deg] opacity-50">
                CANCELLED
              </span>
            </div>
          )}

          {/* Header */}
          <div className="flex justify-between items-start mb-8 pb-4 border-b-2 border-gray-800">
            <div>
              {settings.business_logo_url && (
                <img src={settings.business_logo_url} alt="Logo" className="h-16 mb-2" />
              )}
              <h1 className="text-2xl font-bold">{businessInfo?.name || settings.business_name || "Your Company"}</h1>
              <p className="text-sm text-muted-foreground whitespace-pre-line">
                {businessInfo?.address || settings.business_address}
                {(businessInfo?.city || settings.business_city) && `, ${businessInfo?.city || settings.business_city}`}
                {(businessInfo?.state || settings.business_state) && `, ${businessInfo?.state || settings.business_state}`}
                {(businessInfo?.pincode || settings.business_pincode) && ` - ${businessInfo?.pincode || settings.business_pincode}`}
              </p>
              {(businessInfo?.phone || settings.business_phone) && <p className="text-sm">Phone: {businessInfo?.phone || settings.business_phone}</p>}
              {(businessInfo?.email || settings.business_email) && <p className="text-sm">Email: {businessInfo?.email || settings.business_email}</p>}
              {(businessInfo?.gstin || settings.business_gstin) && (
                <p className="text-sm font-mono font-semibold">GSTIN: {businessInfo?.gstin || settings.business_gstin}</p>
              )}
              {businessInfo?.pan && <p className="text-sm font-mono">PAN: {businessInfo.pan}</p>}
              {businessInfo?.state_code && <p className="text-sm">State Code: {businessInfo.state_code}</p>}
            </div>
            <div className="text-right">
              <h2 className="text-3xl font-bold text-primary">TAX INVOICE</h2>
              <p className="font-mono text-lg font-semibold mt-2">{invoice.invoice_number}</p>
              <p className="text-sm text-muted-foreground">
                Date: {new Date(invoice.invoice_date).toLocaleDateString("en-IN", { 
                  day: "2-digit", month: "short", year: "numeric" 
                })}
              </p>
              {invoice.is_inter_state !== undefined && (
                <Badge variant={invoice.is_inter_state ? "secondary" : "outline"} className="mt-2">
                  {invoice.is_inter_state ? "Inter-State (IGST)" : "Intra-State (CGST+SGST)"}
                </Badge>
              )}
            </div>
          </div>

          {/* Bill To / Ship From */}
          <div className="grid grid-cols-2 gap-8 mb-8">
            <div>
              <h3 className="font-semibold text-sm text-muted-foreground mb-2">BILL TO</h3>
              <p className="font-semibold">{invoice.customer_name}</p>
              {invoice.stores?.name && <p className="text-sm">{invoice.stores.name}</p>}
              {invoice.customer_address && <p className="text-sm whitespace-pre-line">{invoice.customer_address}</p>}
              {invoice.customer_phone && <p className="text-sm">Phone: {invoice.customer_phone}</p>}
              {invoice.customer_gstin && <p className="text-sm font-mono">GSTIN: {invoice.customer_gstin}</p>}
            </div>
            <div>
              <h3 className="font-semibold text-sm text-muted-foreground mb-2">DISPATCH FROM</h3>
              {invoice.warehouses ? (
                <>
                  <p className="font-semibold">{invoice.warehouses.name}</p>
                  <p className="text-sm whitespace-pre-line">
                    {invoice.warehouses.address}
                    {invoice.warehouses.city && `, ${invoice.warehouses.city}`}
                    {invoice.warehouses.state && `, ${invoice.warehouses.state}`}
                  </p>
                </>
              ) : (
                <p className="text-sm text-muted-foreground">—</p>
              )}
            </div>
          </div>

          {/* Items Table */}
          <table className="w-full mb-6 text-sm">
            <thead>
              <tr className="bg-gray-100">
                <th className="text-left p-2 border">#</th>
                <th className="text-left p-2 border">Description</th>
                <th className="text-left p-2 border">HSN</th>
                <th className="text-right p-2 border">Qty</th>
                <th className="text-right p-2 border">Rate</th>
                <th className="text-right p-2 border">Taxable</th>
                <th className="text-right p-2 border">GST %</th>
                <th className="text-right p-2 border">Amount</th>
              </tr>
            </thead>
            <tbody>
              {invoice.invoice_items?.map((item: any, index: number) => {
                const lineTotal = item.quantity * item.unit_price;
                const gstRate = item.gst_rate || item.tax_rate || 0;
                const taxableAmt = item.taxable_amount || (gstRate > 0 ? lineTotal / (1 + gstRate / 100) : lineTotal);
                return (
                  <tr key={item.id}>
                    <td className="p-2 border">{index + 1}</td>
                    <td className="p-2 border">{item.product_name}</td>
                    <td className="p-2 border font-mono text-xs">{item.hsn_code || "—"}</td>
                    <td className="p-2 border text-right">{item.quantity}</td>
                    <td className="p-2 border text-right">₹{Number(item.unit_price).toLocaleString()}</td>
                    <td className="p-2 border text-right">₹{Number(taxableAmt).toLocaleString()}</td>
                    <td className="p-2 border text-right">{gstRate}%</td>
                    <td className="p-2 border text-right font-semibold">₹{Number(lineTotal).toLocaleString()}</td>
                  </tr>
                );
              })}
            </tbody>
          </table>

          {/* GST Summary */}
          <div className="flex justify-end mb-8">
            <div className="w-80 border rounded-lg overflow-hidden">
              <div className="flex justify-between py-2 px-3 bg-gray-50 border-b">
                <span>Taxable Amount</span>
                <span className="font-medium">₹{Number(invoice.taxable_amount || invoice.subtotal).toLocaleString()}</span>
              </div>
              
              {/* Show CGST/SGST or IGST based on is_inter_state */}
              {invoice.is_inter_state ? (
                <div className="flex justify-between py-2 px-3 border-b">
                  <span>IGST {invoice.igst_rate ? `@ ${invoice.igst_rate}%` : ""}</span>
                  <span>₹{Number(invoice.igst_amount || invoice.tax_amount).toLocaleString()}</span>
                </div>
              ) : (
                <>
                  <div className="flex justify-between py-2 px-3 border-b">
                    <span>CGST {invoice.cgst_rate ? `@ ${invoice.cgst_rate}%` : ""}</span>
                    <span>₹{Number(invoice.cgst_amount || (invoice.tax_amount / 2)).toLocaleString()}</span>
                  </div>
                  <div className="flex justify-between py-2 px-3 border-b">
                    <span>SGST {invoice.sgst_rate ? `@ ${invoice.sgst_rate}%` : ""}</span>
                    <span>₹{Number(invoice.sgst_amount || (invoice.tax_amount / 2)).toLocaleString()}</span>
                  </div>
                </>
              )}
              
              {Number(invoice.discount_amount) > 0 && (
                <div className="flex justify-between py-2 px-3 text-green-600 border-b">
                  <span>Discount</span>
                  <span>-₹{Number(invoice.discount_amount).toLocaleString()}</span>
                </div>
              )}
              <div className="flex justify-between py-3 px-3 bg-primary/10 font-bold text-lg">
                <span>Grand Total</span>
                <span>₹{Number(invoice.total_amount).toLocaleString()}</span>
              </div>
            </div>
          </div>

          {/* Amount in Words */}
          <div className="bg-gray-50 p-3 rounded mb-8">
            <p className="text-sm">
              <span className="font-semibold">Amount in Words: </span>
              {amountInWords}
            </p>
          </div>

          {/* Bank Details */}
          {(businessInfo?.bank_name || settings.bank_name) && (
            <div className="grid grid-cols-2 gap-8 mb-8">
              <div>
                <h3 className="font-semibold text-sm text-muted-foreground mb-2">BANK DETAILS</h3>
                <p className="text-sm">Bank: {businessInfo?.bank_name || settings.bank_name}</p>
                <p className="text-sm font-mono">A/C No: {businessInfo?.bank_account_number || settings.bank_account_number}</p>
                <p className="text-sm font-mono">IFSC: {businessInfo?.bank_ifsc || settings.bank_ifsc}</p>
                {(businessInfo?.bank_branch || settings.bank_branch) && <p className="text-sm">Branch: {businessInfo?.bank_branch || settings.bank_branch}</p>}
              </div>
              <div className="text-right">
                <h3 className="font-semibold text-sm text-muted-foreground mb-2">FOR {(businessInfo?.name || settings.business_name || "").toUpperCase()}</h3>
                <div className="h-16"></div>
                <p className="text-sm">Authorized Signatory</p>
              </div>
            </div>
          )}

          {/* Terms */}
          {settings.invoice_terms && (
            <div className="border-t pt-4">
              <h3 className="font-semibold text-sm text-muted-foreground mb-1">TERMS & CONDITIONS</h3>
              <p className="text-xs text-muted-foreground whitespace-pre-line">{settings.invoice_terms}</p>
            </div>
          )}

          {/* Linked Sales */}
          {invoice.invoice_sales?.length > 0 && (
            <div className="border-t pt-4 mt-4 print:hidden">
              <h3 className="font-semibold text-sm text-muted-foreground mb-2">LINKED SALES</h3>
              <div className="flex flex-wrap gap-2">
                {invoice.invoice_sales.map((link: any) => (
                  <Badge key={link.sale_id} variant="outline" className="font-mono">
                    {link.sales?.display_id || link.sale_id.slice(0, 8)}
                  </Badge>
                ))}
              </div>
            </div>
          )}

          {/* Notes */}
          {invoice.notes && (
            <div className="border-t pt-4 mt-4">
              <h3 className="font-semibold text-sm text-muted-foreground mb-1">NOTES</h3>
              <p className="text-sm whitespace-pre-line">{invoice.notes}</p>
            </div>
          )}
        </CardContent>
      </Card>

      {/* Print Styles */}
      <style>{`
        @media print {
          body * { visibility: hidden; }
          .print\\:hidden { display: none !important; }
          [class*="CardContent"] * { visibility: visible; }
          [class*="CardContent"] { 
            position: absolute; 
            left: 0; 
            top: 0; 
            width: 100%;
            padding: 20px !important;
          }
        }
      `}</style>
    </div>
  );
};

export default InvoiceView;

import { useState } from "react";
import { useNavigate } from "react-router-dom";
import { PageHeader } from "@/components/shared/PageHeader";
import { DataTable } from "@/components/shared/DataTable";
import { StatusBadge } from "@/components/shared/StatusBadge";
import { Badge } from "@/components/ui/badge";
import { Button } from "@/components/ui/button";
import { useQuery, useQueryClient } from "@tanstack/react-query";
import { supabase } from "@/integrations/supabase/client";
import { useAuth } from "@/contexts/AuthContext";
import { TableSkeleton } from "@/components/shared/TableSkeleton";
import { FileText, Plus, Eye, Download, XCircle, Printer } from "lucide-react";
import { toast } from "sonner";
import {
  AlertDialog,
  AlertDialogAction,
  AlertDialogCancel,
  AlertDialogContent,
  AlertDialogDescription,
  AlertDialogFooter,
  AlertDialogHeader,
  AlertDialogTitle,
} from "@/components/ui/alert-dialog";
import { Input } from "@/components/ui/input";
