const Invoices = () => {
  const navigate = useNavigate();
  const { user } = useAuth();
  const qc = useQueryClient();
  const [cancelDialog, setCancelDialog] = useState<{ id: string; number: string } | null>(null);
  const [cancelReason, setCancelReason] = useState("");
  const [cancelling, setCancelling] = useState(false);

  const { data: invoices = [], isLoading } = useQuery({
    queryKey: ["invoices"],
    queryFn: async () => {
      const { data, error } = await supabase
        .from("invoices")
        .select(`
          *,
          customers(name),
          stores(name),
          warehouses:dispatch_warehouse_id(name),
          invoice_sales(sale_id)
        `)
        .order("invoice_date", { ascending: false });
      if (error) throw error;
      return data;
    },
  });

  const handleCancel = async () => {
    if (!cancelDialog) return;
    setCancelling(true);

    try {
      const { error } = await supabase
        .from("invoices")
        .update({
          status: "cancelled",
          cancelled_at: new Date().toISOString(),
          cancelled_reason: cancelReason.trim() || null,
          updated_at: new Date().toISOString(),
        })
        .eq("id", cancelDialog.id);

      if (error) throw error;

      toast.success(`Invoice ${cancelDialog.number} cancelled`);
      qc.invalidateQueries({ queryKey: ["invoices"] });
      setCancelDialog(null);
      setCancelReason("");
    } catch (error: any) {
      toast.error(error.message || "Failed to cancel invoice");
    } finally {
      setCancelling(false);
    }
  };

  const getStatusColor = (status: string) => {
    switch (status) {
      case "issued": return "active";
      case "draft": return "pending";
      case "cancelled": return "inactive";
      default: return "pending";
    }
  };

  const columns = [
    { 
      header: "Invoice #", 
      accessor: (row: any) => (
        <span className="font-mono font-medium">{row.invoice_number}</span>
      )
    },
    { 
      header: "Date", 
      accessor: (row: any) => new Date(row.invoice_date).toLocaleDateString("en-IN"),
      className: "text-sm"
    },
    { 
      header: "Customer", 
      accessor: (row: any) => (
        <div>
          <p className="font-medium text-sm">{row.customer_name}</p>
          {row.stores?.name && (
            <p className="text-xs text-muted-foreground">{row.stores.name}</p>
          )}
        </div>
      )
    },
    { 
      header: "Sales", 
      accessor: (row: any) => (
        <Badge variant="outline">{row.invoice_sales?.length || 0} linked</Badge>
      )
    },
    { 
      header: "Amount", 
      accessor: (row: any) => (
        <span className="font-semibold">₹{Number(row.total_amount).toLocaleString()}</span>
      )
    },
    { 
      header: "Status", 
      accessor: (row: any) => (
        <StatusBadge status={getStatusColor(row.status) as any} label={row.status} />
      )
    },
    {
      header: "Actions",
      accessor: (row: any) => (
        <div className="flex items-center gap-1">
          <Button
            variant="ghost"
            size="icon"
            className="h-8 w-8"
            onClick={(e) => { e.stopPropagation(); navigate(`/invoices/${row.id}`); }}
            title="View"
          >
            <Eye className="h-4 w-4" />
          </Button>
          <Button
            variant="ghost"
            size="icon"
            className="h-8 w-8"
            onClick={(e) => { e.stopPropagation(); navigate(`/invoices/${row.id}/print`); }}
            title="Print"
          >
            <Printer className="h-4 w-4" />
          </Button>
          {row.status !== "cancelled" && (
            <Button
              variant="ghost"
              size="icon"
              className="h-8 w-8 text-destructive hover:text-destructive"
              onClick={(e) => { 
                e.stopPropagation(); 
                setCancelDialog({ id: row.id, number: row.invoice_number }); 
              }}
              title="Cancel"
            >
              <XCircle className="h-4 w-4" />
            </Button>
          )}
        </div>
      ),
    },
  ];

  if (isLoading) {
    return <TableSkeleton columns={7} />;
  }

  return (
    <div className="space-y-6 animate-fade-in">
      <PageHeader
        title="Invoices"
        subtitle="Manage tax invoices and bills"
        primaryAction={{
          label: "Create Invoice",
          onClick: () => navigate("/invoices/new"),
          icon: Plus,
        }}
      />

      <DataTable
        columns={columns}
        data={invoices}
        searchKey="invoice_number"
        searchPlaceholder="Search by invoice number..."
        emptyMessage="No invoices yet"
        onRowClick={(row) => navigate(`/invoices/${row.id}`)}
        renderMobileCard={(row: any) => (
          <div className="entity-card-mobile flex-col !items-stretch">
            <div className="flex items-start justify-between gap-2">
              <div className="min-w-0">
                <p className="entity-card-subtitle">{row.invoice_number}</p>
                <h3 className="font-semibold text-sm mt-0.5 truncate">{row.customer_name}</h3>
                {row.stores?.name && (
                  <p className="text-xs text-muted-foreground truncate">{row.stores.name}</p>
                )}
              </div>
              <StatusBadge status={getStatusColor(row.status) as any} label={row.status} />
            </div>
            <div className="flex items-center justify-between mt-2 pt-2 border-t">
              <span className="text-xs text-muted-foreground">
                {new Date(row.invoice_date).toLocaleDateString("en-IN")}
              </span>
              <span className="font-semibold text-primary">₹{Number(row.total_amount).toLocaleString()}</span>
            </div>
          </div>
        )}
      />

      {/* Cancel Invoice Dialog */}
      <AlertDialog open={!!cancelDialog} onOpenChange={() => setCancelDialog(null)}>
        <AlertDialogContent>
          <AlertDialogHeader>
            <AlertDialogTitle>Cancel Invoice {cancelDialog?.number}?</AlertDialogTitle>
            <AlertDialogDescription>
              This will mark the invoice as cancelled. The linked sales will NOT be affected.
            </AlertDialogDescription>
          </AlertDialogHeader>
          <div className="py-2">
            <Label>Reason for cancellation (optional)</Label>
            <Input
              value={cancelReason}
              onChange={(e) => setCancelReason(e.target.value)}
              placeholder="Enter reason..."
              className="mt-2"
            />
          </div>
          <AlertDialogFooter>
            <AlertDialogCancel disabled={cancelling}>Keep Invoice</AlertDialogCancel>
            <AlertDialogAction
              onClick={handleCancel}
              disabled={cancelling}
              className="bg-destructive text-destructive-foreground hover:bg-destructive/90"
            >
              {cancelling ? "Cancelling..." : "Cancel Invoice"}
            </AlertDialogAction>
          </AlertDialogFooter>
        </AlertDialogContent>
      </AlertDialog>
    </div>
  );
};

export default Invoices;

import { PageHeader } from "@/components/shared/PageHeader";
import { getCurrentPosition } from "@/lib/proximity";
import { useQuery } from "@tanstack/react-query";
import { supabase } from "@/integrations/supabase/client";
import { MapPin, Navigation, Loader2 } from "lucide-react";
import { Badge } from "@/components/ui/badge";
import { Button } from "@/components/ui/button";
import { TableSkeleton } from "@/components/shared/TableSkeleton";
import { useEffect, useMemo, useRef, useState } from "react";
import L from "leaflet";
import "leaflet/dist/leaflet.css";

delete (L.Icon.Default.prototype as any)._getIconUrl;
L.Icon.Default.mergeOptions({
  iconRetinaUrl: "https://unpkg.com/leaflet@1.9.4/dist/images/marker-icon-2x.png",
  iconUrl: "https://unpkg.com/leaflet@1.9.4/dist/images/marker-icon.png",
  shadowUrl: "https://unpkg.com/leaflet@1.9.4/dist/images/marker-shadow.png",
});

const TYPE_COLORS = ["#3b82f6", "#10b981", "#f59e0b", "#8b5cf6", "#ef4444", "#06b6d4", "#ec4899", "#84cc16"];

const MapPage = () => {
  const mapRef = useRef<HTMLDivElement>(null);
  const leafletMap = useRef<L.Map | null>(null);
  const userMarkerRef = useRef<L.Marker | null>(null);
  const agentMarkersRef = useRef<L.Marker[]>([]);
  const [selectedRoute, setSelectedRoute] = useState<string>("");
  const [filterType, setFilterType] = useState<string>("");
  const [userLocation, setUserLocation] = useState<{ lat: number; lng: number } | null>(null);
  const [locating, setLocating] = useState(false);

  const { data: storeTypes } = useQuery({
    queryKey: ["store-types-for-map"],
    queryFn: async () => {
      const { data } = await supabase.from("store_types").select("id, name").order("name");
      return data || [];
    },
  });

  const { data: stores, isLoading } = useQuery({
    queryKey: ["stores-with-location", filterType],
    queryFn: async () => {
      let query = supabase
        .from("stores")
        .select("id, name, display_id, address, lat, lng, outstanding, is_active, phone, store_type_id, route_id, store_types(name), routes(name), customers(name)")
        .order("name")
        .limit(500);
      if (filterType) query = query.eq("store_type_id", filterType);
      const { data } = await query;
      return data || [];
    },
  });

  const { data: activeSessions } = useQuery({
    queryKey: ["active-sessions-map"],
    queryFn: async () => {
      const { data } = await supabase
        .from("route_sessions")
        .select("id, user_id, started_at, current_lat, current_lng, location_updated_at, routes(name), profiles(full_name)")
        .eq("status", "active") as any;
      return (data || []) as any[];
    },
    refetchInterval: 15000,
  });

  // Get visited store IDs from active sessions
  const activeSessionIds = activeSessions?.map((s) => s.id) || [];
  const { data: visitedStoreIds } = useQuery({
    queryKey: ["visited-stores-map", activeSessionIds],
    queryFn: async () => {
      if (activeSessionIds.length === 0) return new Set<string>();
      const { data } = await supabase
        .from("store_visits")
        .select("store_id")
        .in("session_id", activeSessionIds);
      return new Set((data || []).map((v) => v.store_id));
    },
    enabled: activeSessionIds.length > 0,
    refetchInterval: 15000,
  });

  // Pending orders
  const { data: pendingOrderStoreIds } = useQuery({
    queryKey: ["pending-orders-map"],
    queryFn: async () => {
      const { data } = await supabase.from("orders").select("store_id").eq("status", "pending");
      return new Set((data || []).map((o) => o.store_id));
    },
  });

  const { data: routes } = useQuery({
    queryKey: ["routes-for-map"],
    queryFn: async () => {
      const { data } = await supabase.from("routes").select("id, name").eq("is_active", true);
      return data || [];
    },
  });

  const { data: companySettings } = useQuery({
    queryKey: ["company-settings-map"],
    queryFn: async () => {
      const { data } = await supabase.from("company_settings").select("key, value");
      const map: Record<string, string> = {};
      data?.forEach((s: any) => { map[s.key] = s.value || ""; });
      return map;
    },
  });

  const companyCoords = useMemo(() => {
    if (!companySettings) return null;
    const lat = parseFloat(companySettings.company_lat || "");
    const lng = parseFloat(companySettings.company_lng || "");
    return !isNaN(lat) && !isNaN(lng) ? { lat, lng } : null;
  }, [companySettings]);

  const locateMe = async () => {
    setLocating(true);
    const pos = await getCurrentPosition();
    if (pos) {
      setUserLocation(pos);
      leafletMap.current?.setView([pos.lat, pos.lng], 16);
    }
    setLocating(false);
  };

  // Route stores for route visualization
  const activeRouteStoreIds = useMemo(() => {
    if (!selectedRoute || !stores) return new Set<string>();
    return new Set(stores.filter((s: any) => s.route_id === selectedRoute).map((s: any) => s.id));
  }, [selectedRoute, stores]);

  const storesWithLocation = useMemo(() => stores?.filter((s: any) => s.lat && s.lng) || [], [stores]);
  const storesWithoutLocation = useMemo(() => stores?.filter((s: any) => !s.lat || !s.lng) || [], [stores]);

  const storeTypeColorMap = useMemo(() => {
    const map = new Map<string, string>();
    stores?.forEach((s: any) => {
      const typeName = s.store_types?.name || "Other";
      if (!map.has(typeName)) map.set(typeName, TYPE_COLORS[map.size % TYPE_COLORS.length]);
    });
    return map;
  }, [stores]);

  useEffect(() => {
    if (!mapRef.current || (storesWithLocation.length === 0 && !companyCoords)) return;

    if (!leafletMap.current) {
      const initCenter: [number, number] = companyCoords
        ? [companyCoords.lat, companyCoords.lng]
        : storesWithLocation.length > 0
        ? [storesWithLocation[0].lat!, storesWithLocation[0].lng!]
        : [20.5937, 78.9629];
      const initZoom = companyCoords || storesWithLocation.length > 0 ? 13 : 5;
      leafletMap.current = L.map(mapRef.current, {
        center: initCenter,
        zoom: initZoom,
        scrollWheelZoom: true,
      });
      L.tileLayer("https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png", {
        attribution: '&copy; <a href="https://www.openstreetmap.org/copyright">OpenStreetMap</a>',
      }).addTo(leafletMap.current);
    }

    const map = leafletMap.current;
    map.eachLayer((layer) => {
      if (layer instanceof L.Marker || layer instanceof L.CircleMarker || layer instanceof L.Polyline) {
        if (!(layer as any)._url) map.removeLayer(layer);
      }
    });

    const bounds: L.LatLngExpression[] = [];
    const routePoints: L.LatLngExpression[] = [];

    storesWithLocation.forEach((store: any) => {
      const typeName = store.store_types?.name || "Other";
      const isVisited = visitedStoreIds?.has(store.id);
      const hasPendingOrder = pendingOrderStoreIds?.has(store.id);
      const isOnRoute = activeRouteStoreIds.has(store.id);

      // Determine color based on visit status
      let color: string;
      if (!store.is_active) {
        color = "#94a3b8"; // inactive gray
      } else if (isVisited) {
        color = "#10b981"; // green - visited
      } else if (hasPendingOrder) {
        color = "#f59e0b"; // amber - has pending order
      } else {
        color = storeTypeColorMap.get(typeName) || "#3b82f6";
      }

      const radius = isOnRoute ? 10 : 8;

      const marker = L.circleMarker([store.lat!, store.lng!], {
        radius,
        fillColor: color,
        color: isOnRoute ? "#1d4ed8" : "#fff",
        weight: isOnRoute ? 3 : 2,
        opacity: 1,
        fillOpacity: 0.85,
      }).addTo(map);

      const statusTag = isVisited ? '<span style="color:#10b981;font-weight:bold;">✓ Visited</span>' :
        hasPendingOrder ? '<span style="color:#f59e0b;font-weight:bold;">📦 Pending Order</span>' :
        '<span style="color:#94a3b8;">Not visited</span>';

      marker.bindPopup(`
        <div style="min-width: 200px; font-family: system-ui, sans-serif;">
          <strong style="font-size: 14px;">${store.name}</strong>
          <div style="color: #666; font-size: 11px; margin: 2px 0;">${store.display_id}</div>
          <div style="margin-top: 6px; font-size: 12px;">
            <div>${statusTag}</div>
            <div><b>Customer:</b> ${store.customers?.name || "—"}</div>
            <div><b>Type:</b> ${typeName}</div>
            <div><b>Route:</b> ${store.routes?.name || "—"}</div>
            <div><b>Outstanding:</b> <span style="color: ${Number(store.outstanding) > 0 ? '#ef4444' : '#10b981'};">₹${Number(store.outstanding).toLocaleString()}</span></div>
            ${store.phone ? `<div><b>Phone:</b> ${store.phone}</div>` : ""}
            ${store.address ? `<div style="margin-top:4px; color:#888;">${store.address}</div>` : ""}
          </div>
          <a href="https://www.google.com/maps?q=${store.lat},${store.lng}" target="_blank" rel="noopener" style="display:inline-block; margin-top:6px; font-size:11px; color:#3b82f6;">Open in Google Maps →</a>
        </div>
      `);

      bounds.push([store.lat!, store.lng!]);
      if (isOnRoute) routePoints.push([store.lat!, store.lng!]);
    });

    // Draw route line
    if (routePoints.length > 1) {
      L.polyline(routePoints, { color: "#3b82f6", weight: 3, opacity: 0.6, dashArray: "8 4" }).addTo(map);
    }

    // Company marker
    if (companyCoords) {
      const label = companySettings?.company_marker_label || companySettings?.company_name || "HQ";
      const companyIcon = L.divIcon({
        className: "",
        html: `<div style="background:#7c3aed;color:white;border-radius:8px;padding:4px 10px;font-size:12px;font-weight:700;white-space:nowrap;box-shadow:0 2px 10px rgba(124,58,237,0.5);border:2px solid white;">${label}</div>`,
        iconAnchor: [0, 0],
      });
      L.marker([companyCoords.lat, companyCoords.lng], { icon: companyIcon, zIndexOffset: 1000 })
        .addTo(map)
        .bindPopup(`
          <div style="font-family:system-ui;min-width:180px;">
            <strong style="font-size:14px;">${companySettings?.company_name || "Company"}</strong>
            <div style="color:#7c3aed;font-size:12px;font-weight:600;">${label}</div>
            ${companySettings?.address ? `<div style="margin-top:4px;font-size:12px;color:#666;">${companySettings.address}</div>` : ""}
            ${companySettings?.customer_care_number ? `<div style="font-size:11px;color:#888;">${companySettings.customer_care_number}</div>` : ""}
            <a href="https://www.google.com/maps?q=${companyCoords.lat},${companyCoords.lng}" target="_blank" rel="noopener" style="display:inline-block;margin-top:6px;font-size:11px;color:#7c3aed;">Open in Google Maps →</a>
          </div>
        `);
      bounds.push([companyCoords.lat, companyCoords.lng]);
    }

    if (bounds.length > 0) {
      map.fitBounds(bounds as L.LatLngBoundsExpression, { padding: [40, 40], maxZoom: 14 });
    }
  }, [storesWithLocation, storeTypeColorMap, visitedStoreIds, pendingOrderStoreIds, activeRouteStoreIds, companyCoords, companySettings]);

  useEffect(() => {
    return () => {
      if (leafletMap.current) { leafletMap.current.remove(); leafletMap.current = null; }
    };
  }, []);

  // User location marker
  useEffect(() => {
    if (!userLocation || !leafletMap.current) return;
    if (userMarkerRef.current) userMarkerRef.current.remove();
    const icon = L.divIcon({
      className: "",
      html: `<div style="width:18px;height:18px;background:#3b82f6;border:3px solid white;border-radius:50%;box-shadow:0 0 0 5px rgba(59,130,246,0.25);"></div>`,
      iconSize: [18, 18],
      iconAnchor: [9, 9],
    });
    userMarkerRef.current = L.marker([userLocation.lat, userLocation.lng], { icon, zIndexOffset: 2000 })
      .addTo(leafletMap.current)
      .bindPopup("<b>Your Location</b>");
    return () => { userMarkerRef.current?.remove(); userMarkerRef.current = null; };
  }, [userLocation]);

  // Agent location markers (real-time)
  useEffect(() => {
    if (!leafletMap.current) return;
    agentMarkersRef.current.forEach((m) => m.remove());
    agentMarkersRef.current = [];
    (activeSessions || []).forEach((session: any) => {
      if (!session.current_lat || !session.current_lng) return;
      const agentName = session.profiles?.full_name || "Agent";
      const routeName = session.routes?.name || "Route";
      const updatedAt = session.location_updated_at
        ? new Date(session.location_updated_at).toLocaleTimeString("en-IN", { hour: "2-digit", minute: "2-digit" })
        : "";
      const icon = L.divIcon({
        className: "",
        html: `<div style="background:#7c3aed;color:white;border-radius:50%;width:28px;height:28px;display:flex;align-items:center;justify-content:center;font-size:14px;border:2px solid white;box-shadow:0 2px 8px rgba(124,58,237,0.5);">🚶</div>`,
        iconSize: [28, 28],
        iconAnchor: [14, 14],
      });
      const marker = L.marker([session.current_lat, session.current_lng], { icon, zIndexOffset: 3000 })
        .addTo(leafletMap.current!)
        .bindPopup(`<div style="font-family:system-ui;min-width:150px;"><strong>${agentName}</strong><div style="color:#7c3aed;font-size:12px;">${routeName}</div>${updatedAt ? `<div style="color:#888;font-size:11px;">Updated: ${updatedAt}</div>` : ""}</div>`);
      agentMarkersRef.current.push(marker);
    });
  }, [activeSessions]);

  if (isLoading) return <TableSkeleton columns={3} rows={5} />;

  return (
    <div className="space-y-6 animate-fade-in">
      <PageHeader title="Map" subtitle="Store locations, visit status, and active agents" />

      {activeSessions && activeSessions.length > 0 && (
        <div className="rounded-xl border bg-card p-4 space-y-2">
          <p className="text-sm font-semibold flex items-center gap-2">
            <Navigation className="h-4 w-4 text-primary" />
            Active Route Sessions ({activeSessions.length})
          </p>
          <div className="flex flex-wrap gap-2">
            {activeSessions.map((session: any) => (
              <Badge key={session.id} variant="secondary" className="text-xs">
                Agent → {session.routes?.name || "Route"}
                <span className="ml-1 text-muted-foreground">since {new Date(session.started_at).toLocaleTimeString("en-IN", { hour: "2-digit", minute: "2-digit" })}</span>
              </Badge>
            ))}
          </div>
        </div>
      )}

      <div className="grid grid-cols-3 sm:grid-cols-5 gap-4">
        <div className="rounded-xl border bg-card p-4 text-center">
          <p className="text-2xl font-bold">{stores?.length || 0}{(stores?.length || 0) >= 500 ? "+" : ""}</p>
          <p className="text-xs text-muted-foreground">Total Stores</p>
        </div>
        <div className="rounded-xl border bg-card p-4 text-center">
          <p className="text-2xl font-bold text-primary">{storesWithLocation.length}</p>
          <p className="text-xs text-muted-foreground">With GPS</p>
        </div>
        <div className="rounded-xl border bg-card p-4 text-center">
          <p className="text-2xl font-bold text-destructive">{storesWithoutLocation.length}</p>
          <p className="text-xs text-muted-foreground">Missing GPS</p>
        </div>
        <div className="rounded-xl border bg-card p-4 text-center hidden sm:block">
          <p className="text-2xl font-bold text-green-500">{visitedStoreIds?.size || 0}</p>
          <p className="text-xs text-muted-foreground">Visited Today</p>
        </div>
        <div className="rounded-xl border bg-card p-4 text-center hidden sm:block">
          <p className="text-2xl font-bold text-amber-500">{pendingOrderStoreIds?.size || 0}</p>
          <p className="text-xs text-muted-foreground">Pending Orders</p>
        </div>
      </div>

      {/* Route filter + My Location */}
      <div className="space-y-3">
        <div className="flex flex-wrap items-center gap-3">
          <select
            value={selectedRoute}
            onChange={(e) => setSelectedRoute(e.target.value)}
            className="rounded-lg border bg-card px-3 py-1.5 text-sm"
          >
            <option value="">All Routes</option>
            {routes?.map((r) => <option key={r.id} value={r.id}>{r.name}</option>)}
          </select>

          <select
            value={filterType}
            onChange={(e) => setFilterType(e.target.value)}
            className="rounded-lg border bg-card px-3 py-1.5 text-sm"
          >
            <option value="">All Types</option>
            {storeTypes?.map((t: any) => <option key={t.id} value={t.id}>{t.name}</option>)}
          </select>

          <Button variant="outline" size="sm" onClick={locateMe} disabled={locating} className="h-8 gap-1.5">
            {locating ? <Loader2 className="h-3.5 w-3.5 animate-spin" /> : <Navigation className="h-3.5 w-3.5" />}
            My Location
          </Button>
        </div>

        {/* Legend — wraps naturally on mobile */}
        <div className="flex flex-wrap items-center gap-x-4 gap-y-2">
          {Array.from(storeTypeColorMap.entries()).map(([name, color]) => (
            <div key={name} className="flex items-center gap-1.5 text-xs">
              <div className="h-3 w-3 rounded-full border border-white shadow-sm shrink-0" style={{ backgroundColor: color }} />
              <span className="text-muted-foreground">{name}</span>
            </div>
          ))}
          <div className="flex items-center gap-1.5 text-xs">
            <div className="h-3 w-3 rounded-full border border-white shadow-sm bg-green-500 shrink-0" />
            <span className="text-muted-foreground">Visited</span>
          </div>
          <div className="flex items-center gap-1.5 text-xs">
            <div className="h-3 w-3 rounded-full border border-white shadow-sm bg-amber-500 shrink-0" />
            <span className="text-muted-foreground">Pending Order</span>
          </div>
          <div className="flex items-center gap-1.5 text-xs">
            <div className="h-3 w-3 rounded-full border border-white shadow-sm bg-slate-400 shrink-0" />
            <span className="text-muted-foreground">Inactive</span>
          </div>
          {companyCoords && (
            <div className="flex items-center gap-1.5 text-xs">
              <div className="h-3 w-3 rounded-[3px] border border-white shadow-sm bg-violet-600 shrink-0" />
              <span className="text-muted-foreground">{companySettings?.company_marker_label || "HQ"}</span>
            </div>
          )}
          {userLocation && (
            <div className="flex items-center gap-1.5 text-xs">
              <div className="h-3 w-3 rounded-full border border-white shadow-sm bg-blue-500 ring-2 ring-blue-200 shrink-0" />
              <span className="text-muted-foreground">You</span>
            </div>
          )}
          {activeSessions && activeSessions.some((s: any) => s.current_lat) && (
            <div className="flex items-center gap-1.5 text-xs">
              <span className="text-sm leading-none">🚶</span>
              <span className="text-muted-foreground">Agent (live)</span>
            </div>
          )}
        </div>
      </div>

      <div className="rounded-xl border bg-card overflow-hidden">
        {storesWithLocation.length > 0 || companyCoords ? (
          <div ref={mapRef} className="h-[500px] w-full" />
        ) : (
          <div className="flex flex-col items-center justify-center h-[400px] text-center px-6">
            <MapPin className="h-12 w-12 text-muted-foreground/40 mb-3" />
            <p className="text-sm font-medium text-muted-foreground">No stores with GPS coordinates</p>
            <p className="text-xs text-muted-foreground mt-1">Add GPS location to stores to see them on the map</p>
          </div>
        )}
      </div>

      {storesWithoutLocation.length > 0 && (
        <div className="rounded-xl border bg-card">
          <div className="p-4 border-b">
            <h3 className="font-semibold text-sm">Stores Missing GPS ({storesWithoutLocation.length})</h3>
          </div>
          <div className="divide-y max-h-[300px] overflow-y-auto">
            {storesWithoutLocation.map((store: any) => (
              <div key={store.id} className="flex items-center justify-between p-3 hover:bg-muted/30 transition-colors">
                <div className="flex items-center gap-3">
                  <div className="flex h-8 w-8 items-center justify-center rounded-lg bg-muted">
                    <MapPin className="h-4 w-4 text-muted-foreground" />
                  </div>
                  <div>
                    <p className="text-sm font-medium">{store.name}</p>
                    <p className="text-xs text-muted-foreground">{store.customers?.name} • {store.display_id}</p>
                  </div>
                </div>
                <span className="text-xs text-muted-foreground">{store.address || "No address"}</span>
              </div>
            ))}
          </div>
        </div>
      )}
    </div>
  );
};

export default MapPage;

import { useQuery, useQueryClient } from "@tanstack/react-query";
import { PageHeader } from "@/components/shared/PageHeader";
import { DataTable } from "@/components/shared/DataTable";
import { StatusBadge } from "@/components/shared/StatusBadge";
import { Badge } from "@/components/ui/badge";
import { supabase } from "@/integrations/supabase/client";
import { logActivity } from "@/lib/activityLogger";
import { sendNotificationToMany, getAdminUserIds } from "@/lib/notifications";
import { useAuth } from "@/contexts/AuthContext";
import { Loader2, Plus, Trash2, XCircle, Package, Download, X, CalendarIcon } from "lucide-react";
import { TableSkeleton } from "@/components/shared/TableSkeleton";
import { useState, useEffect } from "react";
import { OrderFulfillmentDialog } from "@/components/orders/OrderFulfillmentDialog";
import {
  Dialog, DialogContent, DialogHeader, DialogTitle,
} from "@/components/ui/dialog";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Button } from "@/components/ui/button";
import { Calendar } from "@/components/ui/calendar";
import { Popover, PopoverContent, PopoverTrigger } from "@/components/ui/popover";
import { Textarea } from "@/components/ui/textarea";
import {
  Select, SelectContent, SelectItem, SelectTrigger, SelectValue,
} from "@/components/ui/select";
import { Tabs, TabsList, TabsTrigger } from "@/components/ui/tabs";
import { toast } from "sonner";
import { format } from "date-fns";

interface OrderItem {
  product_id: string;
  quantity: number;
  unit_price?: number;
}

interface FulfillOrder {
  id: string;
  display_id: string;
  store_id: string;
  customer_id: string | null;
  order_type: "simple" | "detailed";
  status: string;
  requirement_note: string | null;
  order_items?: Array<{
    id: string;
    product_id: string;
    quantity: number;
    unit_price: number | null;
    products?: {
      id: string;
      name: string;
      sku: string;
      base_price: number;
      image_url?: string;
    };
  }>;
  stores?: {
    id: string;
    name: string;
    store_type_id: string | null;
    customer_id: string | null;
  };
}

const Orders = () => {
  const { user } = useAuth();
  const qc = useQueryClient();
  const [showAdd, setShowAdd] = useState(false);
  const [saving, setSaving] = useState(false);
  const [statusFilter, setStatusFilter] = useState("all");
  const [cancelOrderId, setCancelOrderId] = useState<string | null>(null);
  const [cancelReason, setCancelReason] = useState("");
  const [cancelling, setCancelling] = useState(false);
  const [fulfillOrder, setFulfillOrder] = useState<FulfillOrder | null>(null);
  const [loadingOrderDetails, setLoadingOrderDetails] = useState<string | null>(null);

  // List filters
  const today = new Date().toISOString().split("T")[0];
  const thirtyDaysAgo = new Date(Date.now() - 30 * 24 * 60 * 60 * 1000).toISOString().split("T")[0];
  const [filterFrom, setFilterFrom] = useState(thirtyDaysAgo);
  const [filterTo, setFilterTo] = useState(today);
  const [filterCustomer, setFilterCustomer] = useState("all");
  const PAGE_SIZE = 100;
  const [loadedPages, setLoadedPages] = useState(1);

  // Reset to page 1 whenever any filter changes
  useEffect(() => {
    setLoadedPages(1);
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [statusFilter, filterFrom, filterTo, filterCustomer]);

  // Form state
  const [customerId, setCustomerId] = useState("");
  const [storeId, setStoreId] = useState("");
  const [orderType, setOrderType] = useState("simple");
  const [requirementNote, setRequirementNote] = useState("");
  const [orderItems, setOrderItems] = useState<OrderItem[]>([{ product_id: "", quantity: 1 }]);

  const { data: orders, isLoading, isFetching } = useQuery({
    queryKey: ["orders", statusFilter, filterFrom, filterTo, filterCustomer, loadedPages],
    queryFn: async () => {
      let query = supabase
        .from("orders")
        .select("*, stores(name), customers(name)")
        .order("created_at", { ascending: false });
      // Server-side filters
      if (statusFilter !== "all") query = query.eq("status", statusFilter);
      if (filterFrom) query = query.gte("created_at", filterFrom + "T00:00:00");
      if (filterTo) query = query.lte("created_at", filterTo + "T23:59:59");
      if (filterCustomer !== "all") query = query.eq("customer_id", filterCustomer);
      // Cursor pagination
      query = query.range(0, loadedPages * PAGE_SIZE - 1);
      const { data, error } = await query;
      if (error) throw error;
      return data;
    },
  });

  const hasMoreOrders = (orders?.length || 0) >= loadedPages * PAGE_SIZE;

  const { data: customers = [] } = useQuery({
    queryKey: ["customers"],
    queryFn: async () => {
      const { data } = await supabase.from("customers").select("id, name").eq("is_active", true);
      return data || [];
    },
  });

  const { data: stores } = useQuery({
    queryKey: ["stores-for-order", customerId],
    queryFn: async () => {
      let q = supabase.from("stores").select("id, name, display_id, store_type_id, customer_id").eq("is_active", true);
      if (customerId) q = q.eq("customer_id", customerId);
      const { data } = await q;
      return data || [];
    },
    enabled: !!customerId,
  });

  const { data: products } = useQuery({
    queryKey: ["products"],
    queryFn: async () => {
      const { data } = await supabase.from("products").select("id, name, sku, base_price, image_url").eq("is_active", true);
      return data || [];
    },
  });

  // Load store pricing data for order creation
  const { data: storePricing } = useQuery({
    queryKey: ["store-pricing", storeId],
    queryFn: async () => {
      const { data } = await supabase.from("store_pricing").select("product_id, custom_price").eq("store_id", storeId);
      return new Map((data || []).map(sp => [sp.product_id, sp.custom_price]));
    },
    enabled: !!storeId,
  });

  const { data: storeTypePricing } = useQuery({
    queryKey: ["store-type-pricing", storeId],
    queryFn: async () => {
      const store = stores?.find(s => s.id === storeId);
      if (!store?.store_type_id) return new Map<string, number>();
      const { data } = await supabase.from("store_type_pricing").select("product_id, price").eq("store_type_id", store.store_type_id);
      return new Map((data || []).map(tp => [tp.product_id, tp.price]));
    },
    enabled: !!storeId && !!stores,
  });

  // Get price for product using hierarchy: store > store_type > base
  const getProductPrice = (productId: string): number => {
    const product = products?.find(p => p.id === productId);
    if (!product) return 0;
    if (storePricing?.has(productId)) return storePricing.get(productId)!;
    if (storeTypePricing?.has(productId)) return storeTypePricing.get(productId)!;
    return product.base_price;
  };

  const addItem = () => setOrderItems([...orderItems, { product_id: "", quantity: 1 }]);
  const removeItem = (idx: number) => setOrderItems(orderItems.filter((_, i) => i !== idx));

  const resetForm = () => {
    setCustomerId(""); setStoreId(""); setOrderType("simple"); setRequirementNote("");
    setOrderItems([{ product_id: "", quantity: 1 }]);
  };

  const handleAdd = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!storeId) { toast.error("Please select a store"); return; }
    if (orderType === "simple" && !requirementNote.trim()) { toast.error("Please describe the requirement"); return; }
    if (orderType === "detailed" && !orderItems.some((i) => i.product_id)) { toast.error("Please add at least one product"); return; }
    setSaving(true);

    const { data: displayId } = await supabase.rpc("generate_display_id", { prefix: "ORD", seq_name: "ord_display_seq" });

    const { data: order, error } = await supabase.from("orders").insert({
      display_id: displayId,
      store_id: storeId,
      customer_id: customerId,
      order_type: orderType,
      source: "manual",
      created_by: user!.id,
      requirement_note: requirementNote || null,
    }).select("id").single();

    if (error) { toast.error(error.message); setSaving(false); return; }

    if (orderType === "detailed") {
      const validItems = orderItems.filter((i) => i.product_id);
      if (validItems.length > 0) {
        await supabase.from("order_items").insert(
          validItems.map((i) => ({ 
            order_id: order.id, 
            product_id: i.product_id, 
            quantity: i.quantity,
            unit_price: getProductPrice(i.product_id)
          }))
        );
      }
    }

    logActivity(user!.id, "Created order", "order", displayId, order.id);
    toast.success("Order created");

    // Notify admins/managers
    const storeName = stores?.find((s) => s.id === storeId)?.name || "store";
    getAdminUserIds().then((ids) => {
      const others = ids.filter((id) => id !== user!.id);
      if (others.length > 0) {
        sendNotificationToMany(others, {
          title: "New Order Created",
          message: `Order ${displayId} (${orderType}) placed for ${storeName}`,
          type: "order",
          entityType: "order",
          entityId: order.id,
        });
      }
    });

    setSaving(false);
    setShowAdd(false);
    resetForm();
    qc.invalidateQueries({ queryKey: ["orders"] });
  };

  // Open fulfillment dialog with full order details
  const handleOpenFulfillment = async (orderId: string) => {
    setLoadingOrderDetails(orderId);
    try {
      // Fetch order with items and store info for the dialog
      const { data: orderData, error } = await supabase
        .from("orders")
        .select(`
          *,
          stores(id, name, store_type_id, customer_id),
          order_items(id, product_id, quantity, unit_price, products(id, name, sku, base_price, image_url))
        `)
        .eq("id", orderId)
        .single();

      if (error) throw error;

      setFulfillOrder(orderData as unknown as FulfillOrder);
    } catch (error) {
      console.error("Error loading order details:", error);
      toast.error("Failed to load order details");
    } finally {
      setLoadingOrderDetails(null);
    }
  };

  const exportCSV = () => {
    const rows = (filteredOrders || []).map((o) => ({
      "Order ID": o.display_id,
      "Store": (o as any).stores?.name || "",
      "Customer": (o as any).customers?.name || "",
      "Type": o.order_type,
      "Source": o.source,
      "Status": o.status,
      "Note": o.requirement_note || "",
      "Created": new Date(o.created_at).toLocaleString("en-IN"),
    }));
    
    // Handle empty data case
    if (rows.length === 0) {
      toast.info("No orders to export");
      return;
    }
    
    const header = Object.keys(rows[0]).join(",");
    const csv = [header, ...rows.map((r) => Object.values(r).map((v) => `"${String(v).replace(/"/g, '""')}"`).join(","))].join("\n");
    const blob = new Blob([csv], { type: "text/csv" });
    const url = URL.createObjectURL(blob);
    const a = document.createElement("a");
    a.href = url; a.download = `orders-${statusFilter}-${new Date().toISOString().split("T")[0]}.csv`;
    a.click(); URL.revokeObjectURL(url);
  };

  const handleCancel = async () => {
    if (!cancelOrderId || !cancelReason.trim()) { toast.error("Please provide a reason"); return; }
    setCancelling(true);
    const { error } = await supabase
      .from("orders")
      .update({
        status: "cancelled",
        cancellation_reason: cancelReason,
        cancelled_by: user!.id,
        cancelled_at: new Date().toISOString(),
      })
      .eq("id", cancelOrderId)
      .eq("status", "pending");
    setCancelling(false);
    if (error) { toast.error(error.message); return; }

    const order = orders?.find((o) => o.id === cancelOrderId);
    logActivity(user!.id, "Cancelled order", "order", order?.display_id || "", cancelOrderId, { reason: cancelReason });

    // Notify customer if linked
    if (order?.customers && (order as any).customer_id) {
      const { data: custData } = await supabase.from("customers").select("user_id").eq("id", (order as any).customer_id).single();
      if (custData?.user_id) {
        sendNotificationToMany([custData.user_id], {
          title: "Order Cancelled",
          message: `Order ${order?.display_id} was cancelled. Reason: ${cancelReason}`,
          type: "order",
          entityType: "order",
          entityId: cancelOrderId,
        });
      }
    }

    toast.success("Order cancelled");
    setCancelOrderId(null);
    setCancelReason("");
    qc.invalidateQueries({ queryKey: ["orders"] });
  };

  // Filtering is now done server-side; local array mirrors the fetched page(s)
  const filteredOrders = orders || [];

  const activeOrderFilterCount = [filterCustomer !== "all", filterFrom !== thirtyDaysAgo, filterTo !== today].filter(Boolean).length;

  const clearOrderFilters = () => {
    setFilterFrom(thirtyDaysAgo);
    setFilterTo(today);
    setFilterCustomer("all");
  };

  const columns = [
    { header: "Order ID", accessor: "display_id" as const, className: "font-mono text-xs" },
    { header: "Store", accessor: (row: any) => row.stores?.name || "—", className: "font-medium" },
    { header: "Type", accessor: (row: any) => <Badge variant="secondary">{row.order_type}</Badge>, className: "hidden sm:table-cell" },
    { header: "Source", accessor: (row: any) => <Badge variant="outline">{row.source}</Badge>, className: "hidden md:table-cell" },
    { header: "Customer", accessor: (row: any) => row.customers?.name || "—", className: "text-muted-foreground text-sm hidden lg:table-cell" },
    { header: "Status", accessor: (row: any) => <StatusBadge status={row.status === "delivered" ? "active" : row.status as any} label={row.status} /> },
    { header: "Date", accessor: (row: any) => new Date(row.created_at).toLocaleString("en-IN", { dateStyle: "short", timeStyle: "short" }), className: "text-muted-foreground text-xs hidden sm:table-cell" },
    {
      header: "Actions",
      accessor: (row: any) => row.status === "pending" ? (
        <div className="flex items-center gap-1">
          <Button variant="ghost" size="sm" className="h-7 text-xs text-green-600" onClick={() => handleOpenFulfillment(row.id)} disabled={loadingOrderDetails === row.id}>
            {loadingOrderDetails === row.id ? <Loader2 className="h-3.5 w-3.5 mr-1 animate-spin" /> : <Package className="h-3.5 w-3.5 mr-1" />}
            Fulfill
          </Button>
          <Button variant="ghost" size="sm" className="h-7 text-xs text-destructive" onClick={() => setCancelOrderId(row.id)}>
            <XCircle className="h-3.5 w-3.5 mr-1" /> Cancel
          </Button>
        </div>
      ) : row.status === "cancelled" ? (
        <span className="text-xs text-muted-foreground truncate max-w-[120px] block" title={row.cancellation_reason}>{row.cancellation_reason || "—"}</span>
      ) : null,
    },
  ];

  if (isLoading) {
    return <TableSkeleton columns={7} />;
  }

  return (
    <div className="space-y-6 animate-fade-in">
      <PageHeader title="Orders" subtitle="Manage customer orders and fulfillment" primaryAction={{ label: "Create Order", onClick: () => setShowAdd(true) }} actions={[{ label: "Export CSV", icon: Download, onClick: exportCSV, variant: "outline" as const }]} />

      <Tabs value={statusFilter} onValueChange={setStatusFilter} className="w-full">
        <TabsList className="bg-muted/50 p-1 h-11">
          <TabsTrigger value="all" className="px-6 rounded-md transition-all data-[state=active]:shadow-sm">All</TabsTrigger>
          <TabsTrigger value="pending" className="px-6 rounded-md transition-all data-[state=active]:shadow-sm">Pending</TabsTrigger>
          <TabsTrigger value="delivered" className="px-6 rounded-md transition-all data-[state=active]:shadow-sm">Delivered</TabsTrigger>
          <TabsTrigger value="cancelled" className="px-6 rounded-md transition-all data-[state=active]:shadow-sm">Cancelled</TabsTrigger>
        </TabsList>
      </Tabs>

      <div className="flex flex-wrap items-center gap-2 p-3 rounded-xl border bg-card shadow-sm">
        <Popover>
          <PopoverTrigger asChild>
            <Button variant="outline" className="h-9 text-xs gap-1.5 justify-start font-medium flex-1 min-w-[110px] sm:flex-none bg-accent/5 focus:bg-accent/10 transition-colors">
              <CalendarIcon className="h-3.5 w-3.5 shrink-0 text-primary/60" />
              {filterFrom ? format(new Date(filterFrom + "T00:00:00"), "dd MMM yy") : "From"}
            </Button>
          </PopoverTrigger>
          <PopoverContent className="w-auto p-0" align="start">
            <Calendar mode="single" selected={filterFrom ? new Date(filterFrom + "T00:00:00") : undefined} onSelect={(d) => setFilterFrom(d ? format(d, "yyyy-MM-dd") : "")} initialFocus />
          </PopoverContent>
        </Popover>
        <Popover>
          <PopoverTrigger asChild>
            <Button variant="outline" className="h-9 text-xs gap-1.5 justify-start font-medium flex-1 min-w-[110px] sm:flex-none bg-accent/5 focus:bg-accent/10 transition-colors">
              <CalendarIcon className="h-3.5 w-3.5 shrink-0 text-primary/60" />
              {filterTo ? format(new Date(filterTo + "T00:00:00"), "dd MMM yy") : "To"}
            </Button>
          </PopoverTrigger>
          <PopoverContent className="w-auto p-0" align="start">
            <Calendar mode="single" selected={filterTo ? new Date(filterTo + "T00:00:00") : undefined} onSelect={(d) => setFilterTo(d ? format(d, "yyyy-MM-dd") : "")} initialFocus />
          </PopoverContent>
        </Popover>
        <Select value={filterCustomer} onValueChange={setFilterCustomer}>
          <SelectTrigger className="h-9 text-xs flex-1 min-w-[140px] sm:flex-none sm:w-48 bg-accent/5 focus:bg-accent/10 transition-colors font-medium">
            <SelectValue placeholder="All customers" />
          </SelectTrigger>
          <SelectContent>
            <SelectItem value="all">All customers</SelectItem>
            {customers?.map((c) => <SelectItem key={c.id} value={c.id}>{c.name}</SelectItem>)}
          </SelectContent>
        </Select>
        {activeOrderFilterCount > 0 && (
          <Button variant="ghost" size="sm" className="h-8 text-xs" onClick={clearOrderFilters}>
            <X className="h-3 w-3 mr-1" /> Clear ({activeOrderFilterCount})
          </Button>
        )}
        <span className="ml-auto text-xs text-muted-foreground">{filteredOrders.length}{hasMoreOrders ? "+" : ""} result{filteredOrders.length !== 1 ? "s" : ""}</span>
      </div>

      <DataTable
        columns={columns}
        data={filteredOrders}
        searchKey="display_id"
        searchPlaceholder="Search by order ID..."
        emptyMessage={statusFilter === "all" ? "No orders created yet." : `No ${statusFilter} orders.`}
        renderMobileCard={(row: any) => (
          <div className="rounded-lg border bg-card p-3">
            <div className="flex items-start justify-between gap-2">
              <div className="min-w-0 flex-1">
                <div className="flex items-center gap-1.5 flex-wrap mb-1">
                  <span className="font-mono text-xs text-primary font-medium">{row.display_id}</span>
                  <Badge variant="secondary" className="text-xs h-5 px-1.5">{row.order_type}</Badge>
                  <Badge variant="outline" className="text-xs h-5 px-1.5">{row.source}</Badge>
                </div>
                <h3 className="font-semibold text-sm text-foreground truncate">{row.stores?.name || "—"}</h3>
                <p className="text-xs text-muted-foreground truncate">{row.customers?.name || "—"}</p>
              </div>
              <StatusBadge status={row.status === "delivered" ? "active" : row.status as any} label={row.status} />
            </div>
            <div className="flex items-center justify-between mt-2 pt-2 border-t border-border/50 gap-2 flex-wrap">
              <p className="text-[10px] text-muted-foreground">{new Date(row.created_at).toLocaleString("en-IN", { dateStyle: "short", timeStyle: "short" })}</p>
              {row.status === "pending" && (
                <div className="flex items-center gap-1.5">
                  <Button variant="outline" size="sm" className="h-7 text-xs text-green-600 border-green-600/40" onClick={(e) => { e.stopPropagation(); handleOpenFulfillment(row.id); }} disabled={loadingOrderDetails === row.id}>
                    {loadingOrderDetails === row.id ? <Loader2 className="h-3 w-3 mr-1 animate-spin" /> : <Package className="h-3 w-3 mr-1" />}Fulfill
                  </Button>
                  <Button variant="outline" size="sm" className="h-7 text-xs text-destructive border-destructive/40" onClick={(e) => { e.stopPropagation(); setCancelOrderId(row.id); }}>
                    <XCircle className="h-3 w-3 mr-1" />Cancel
                  </Button>
                </div>
              )}
              {row.status === "cancelled" && row.cancellation_reason && (
                <span className="text-xs text-muted-foreground italic truncate max-w-[180px]">{row.cancellation_reason}</span>
              )}
            </div>
          </div>
        )}
      />

      {hasMoreOrders && (
        <div className="flex justify-center pt-2">
          <Button variant="outline" size="sm" onClick={() => setLoadedPages((p) => p + 1)} disabled={isFetching} className="gap-1.5">
            {isFetching ? <Loader2 className="h-3.5 w-3.5 animate-spin" /> : null}
            Load more
          </Button>
        </div>
      )}

      <Dialog open={showAdd} onOpenChange={(v) => { setShowAdd(v); if (!v) resetForm(); }}>
        <DialogContent className="max-w-lg max-h-[90vh] overflow-y-auto">
          <DialogHeader><DialogTitle>Create Order</DialogTitle></DialogHeader>
          <form onSubmit={handleAdd} className="space-y-4">
            <div>
              <Label>Customer</Label>
              <Select value={customerId} onValueChange={(v) => { setCustomerId(v); setStoreId(""); }}>
                <SelectTrigger className="mt-1"><SelectValue placeholder="Select customer" /></SelectTrigger>
                <SelectContent>{customers?.map((c) => <SelectItem key={c.id} value={c.id}>{c.name}</SelectItem>)}</SelectContent>
              </Select>
            </div>
            <div>
              <Label>Store</Label>
              <Select value={storeId} onValueChange={setStoreId} disabled={!customerId}>
                <SelectTrigger className="mt-1"><SelectValue placeholder="Select store" /></SelectTrigger>
                <SelectContent>{stores?.map((s) => <SelectItem key={s.id} value={s.id}>{s.name} ({s.display_id})</SelectItem>)}</SelectContent>
              </Select>
            </div>
            <div>
              <Label>Order Type</Label>
              <Select value={orderType} onValueChange={setOrderType}>
                <SelectTrigger className="mt-1"><SelectValue /></SelectTrigger>
                <SelectContent>
                  <SelectItem value="simple">Simple (Note only)</SelectItem>
                  <SelectItem value="detailed">Detailed (Products + Qty)</SelectItem>
                </SelectContent>
              </Select>
            </div>

            <div>
              <Label>Requirement Note</Label>
              <Textarea value={requirementNote} onChange={(e) => setRequirementNote(e.target.value)} className="mt-1" placeholder="e.g., Need water bottles urgently" />
            </div>

            {orderType === "detailed" && (
              <div>
                <div className="flex items-center justify-between mb-2">
                  <Label>Products</Label>
                  <Button type="button" variant="outline" size="sm" onClick={addItem}><Plus className="h-3 w-3 mr-1" />Add</Button>
                </div>
                <div className="space-y-2">
                  {orderItems.map((item, idx) => (
                    <div key={idx} className="flex items-center gap-2">
                      <Select value={item.product_id} onValueChange={(v) => { const u = [...orderItems]; u[idx].product_id = v; setOrderItems(u); }}>
                        <SelectTrigger className="flex-1"><SelectValue placeholder="Product" /></SelectTrigger>
                        <SelectContent>{products?.map((p) => <SelectItem key={p.id} value={p.id}>{p.name} ({p.sku})</SelectItem>)}</SelectContent>
                      </Select>
                      <Input type="number" min={1} value={item.quantity} onChange={(e) => { const u = [...orderItems]; u[idx].quantity = Number(e.target.value); setOrderItems(u); }} className="w-20" placeholder="Qty" />
                      {orderItems.length > 1 && (
                        <Button type="button" variant="ghost" size="icon" onClick={() => removeItem(idx)}><Trash2 className="h-4 w-4 text-destructive" /></Button>
                      )}
                    </div>
                  ))}
                </div>
              </div>
            )}

            <Button type="submit" className="w-full" disabled={saving}>
              {saving && <Loader2 className="mr-2 h-4 w-4 animate-spin" />}
              Create Order
            </Button>
          </form>
        </DialogContent>
      </Dialog>

      {/* Order Fulfillment Dialog */}
      <OrderFulfillmentDialog
        order={fulfillOrder}
        open={!!fulfillOrder}
        onOpenChange={(open) => { if (!open) setFulfillOrder(null); }}
        onFulfilled={() => qc.invalidateQueries({ queryKey: ["orders"] })}
      />

      {/* Cancel Order Dialog */}
      <Dialog open={!!cancelOrderId} onOpenChange={(v) => { if (!v) { setCancelOrderId(null); setCancelReason(""); } }}>
        <DialogContent>
          <DialogHeader><DialogTitle>Cancel Order</DialogTitle></DialogHeader>
          <div className="space-y-4">
            <p className="text-sm text-muted-foreground">
              Are you sure you want to cancel order <span className="font-mono font-medium text-foreground">{orders?.find((o) => o.id === cancelOrderId)?.display_id}</span>?
            </p>
            <div>
              <Label>Reason for cancellation</Label>
              <Select value={cancelReason} onValueChange={setCancelReason}>
                <SelectTrigger className="mt-1"><SelectValue placeholder="Select reason" /></SelectTrigger>
                <SelectContent>
                  <SelectItem value="By Mistake">By Mistake</SelectItem>
                  <SelectItem value="Stock Available">Stock Available</SelectItem>
                  <SelectItem value="Other Brands">Other Brands</SelectItem>
                  <SelectItem value="Other">Other</SelectItem>
                </SelectContent>
              </Select>
            </div>
            <div className="flex gap-2 justify-end">
              <Button variant="outline" onClick={() => { setCancelOrderId(null); setCancelReason(""); }}>Back</Button>
              <Button variant="destructive" onClick={handleCancel} disabled={cancelling || !cancelReason}>
                {cancelling && <Loader2 className="mr-2 h-4 w-4 animate-spin" />}
                Confirm Cancel
              </Button>
            </div>
          </div>
        </DialogContent>
      </Dialog>
    </div>
  );
};

export default Orders;

import { PageHeader } from "@/components/shared/PageHeader";
import { DataTable } from "@/components/shared/DataTable";
import { StatusBadge } from "@/components/shared/StatusBadge";
import { Badge } from "@/components/ui/badge";
import { Package, Pencil, X, Save, AlertTriangle, Grid3X3, Download, Tags, CheckSquare, DollarSign, Box } from "lucide-react";
import { ImageUpload } from "@/components/shared/ImageUpload";
import { ProductAccessMatrix } from "@/components/products/ProductAccessMatrix";
import { ProductCategories } from "@/components/products/ProductCategories";
import { useQuery } from "@tanstack/react-query";
import { supabase } from "@/integrations/supabase/client";
import { useAuth } from "@/contexts/AuthContext";
import { logActivity } from "@/lib/activityLogger";
import { Checkbox } from "@/components/ui/checkbox";
import { Loader2 } from "lucide-react";
import { useState, useMemo } from "react";
import { useIsMobile } from "@/hooks/use-mobile";
import {
  Dialog, DialogContent, DialogHeader, DialogTitle,
} from "@/components/ui/dialog";
import { NoticeBox } from "@/components/shared/NoticeBox";
import {
  AlertDialog, AlertDialogAction, AlertDialogCancel, AlertDialogContent,
  AlertDialogDescription, AlertDialogFooter, AlertDialogHeader, AlertDialogTitle,
} from "@/components/ui/alert-dialog";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Button } from "@/components/ui/button";
import { Switch } from "@/components/ui/switch";
import { Textarea } from "@/components/ui/textarea";
import {
  Select, SelectContent, SelectItem, SelectTrigger, SelectValue,
} from "@/components/ui/select";
import { toast } from "sonner";
import { useQueryClient } from "@tanstack/react-query";

const Products = () => {
  const { user, role } = useAuth();
  const isMobile = useIsMobile();
  const canEdit = role === "super_admin" || role === "manager";
  const [showAdd, setShowAdd] = useState(false);
  const [showMatrix, setShowMatrix] = useState(false);
  const [showCategories, setShowCategories] = useState(false);
  const [editProduct, setEditProduct] = useState<any>(null);
  const [name, setName] = useState("");
  const [sku, setSku] = useState("");
  const [price, setPrice] = useState("");
  const [unit, setUnit] = useState("PCS");
  const [category, setCategory] = useState("");
  const [description, setDescription] = useState("");
  const [imageUrl, setImageUrl] = useState("");
  const [hsnCode, setHsnCode] = useState("");
  const [gstRate, setGstRate] = useState("18");
  const [saving, setSaving] = useState(false);
  const [selectMode, setSelectMode] = useState(false);
  const [selectedIds, setSelectedIds] = useState<Set<string>>(new Set());
  const [confirmBulkDeactivate, setConfirmBulkDeactivate] = useState(false);
  const [searchTerm, setSearchTerm] = useState("");
  const qc = useQueryClient();

  const { data: products, isLoading } = useQuery({
    queryKey: ["products"],
    queryFn: async () => {
      const { data, error } = await supabase
        .from("products")
        .select("*")
        .order("created_at", { ascending: false });
      if (error) throw error;
      return data;
    },
  });

  const { data: categoryList } = useQuery({
    queryKey: ["product-categories"],
    queryFn: async () => {
      const { data, error } = await supabase
        .from("product_categories")
        .select("id, name")
        .order("name");
      if (error) throw error;
      return data || [];
    },
  });

  // Filter products based on search term
  const filteredProducts = useMemo(() => {
    if (!products) return [];
    if (!searchTerm.trim()) return products;
    const term = searchTerm.toLowerCase();
    return products.filter((p: any) => 
      p.name?.toLowerCase().includes(term) || 
      p.sku?.toLowerCase().includes(term) ||
      p.category?.toLowerCase().includes(term)
    );
  }, [products, searchTerm]);

  const handleAdd = async (e: React.FormEvent) => {
    e.preventDefault();
    setSaving(true);
    const { error } = await supabase.from("products").insert({
      name,
      sku,
      base_price: parseFloat(price) || 0,
      unit,
      category: category || null,
      description: description || null,
      image_url: imageUrl || null,
      hsn_code: hsnCode.trim() || null,
      gst_rate: parseFloat(gstRate) || 18,
      is_gst_inclusive: true,
    });
    setSaving(false);
    if (error) {
      toast.error(error.message);
    } else {
      toast.success("Product added");
      logActivity(user!.id, "Added product", "product", name);
      setShowAdd(false);
      resetForm();
      qc.invalidateQueries({ queryKey: ["products"] });
    }
  };

  const openEdit = (product: any) => {
    setEditProduct(product);
    setName(product.name || "");
    setSku(product.sku || "");
    setPrice(String(product.base_price || 0));
    setUnit(product.unit || "PCS");
    setCategory(product.category || "");
    setDescription(product.description || "");
    setImageUrl(product.image_url || "");
    setHsnCode(product.hsn_code || "");
    setGstRate(String(product.gst_rate || 18));
  };

  const handleEdit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!editProduct) return;
    setSaving(true);
    const { error } = await supabase.from("products").update({
      name,
      sku,
      base_price: parseFloat(price) || 0,
      unit,
      category: category || null,
      description: description || null,
      image_url: imageUrl || null,
      hsn_code: hsnCode.trim() || null,
      gst_rate: parseFloat(gstRate) || 18,
    }).eq("id", editProduct.id);
    setSaving(false);
    if (error) {
      toast.error(error.message);
    } else {
      toast.success("Product updated");
      logActivity(user!.id, "Updated product", "product", name, editProduct.id);
      setEditProduct(null);
      resetForm();
      qc.invalidateQueries({ queryKey: ["products"] });
    }
  };

  const handleToggleActive = async (product: any) => {
    const newVal = !product.is_active;
    const { error } = await supabase.from("products").update({ is_active: newVal }).eq("id", product.id);
    if (error) {
      toast.error(error.message);
      return;
    }
    toast.success(`Product ${newVal ? "activated" : "deactivated"}`);
    qc.invalidateQueries({ queryKey: ["products"] });
  };

  const resetForm = () => {
    setName(""); setSku(""); setPrice(""); setUnit("PCS"); setCategory(""); setDescription(""); setImageUrl(""); setHsnCode(""); setGstRate("18");
  };

  const toggleSelect = (id: string) => {
    setSelectedIds((prev) => {
      const next = new Set(prev);
      next.has(id) ? next.delete(id) : next.add(id);
      return next;
    });
  };

  const handleBulkStatus = async (activate: boolean) => {
    const ids = Array.from(selectedIds);
    if (!ids.length) return;
    const { error } = await supabase.from("products").update({ is_active: activate }).in("id", ids);
    if (error) { toast.error(error.message); return; }
    toast.success(`${ids.length} product(s) ${activate ? "activated" : "deactivated"}`);
    setSelectedIds(new Set());
    setSelectMode(false);
    qc.invalidateQueries({ queryKey: ["products"] });
  };

  const columns = [
    ...(selectMode ? [{
      header: "",
      accessor: (row: any) => (
        <Checkbox
          checked={selectedIds.has(row.id)}
          onCheckedChange={() => toggleSelect(row.id)}
          onClick={(e: React.MouseEvent) => e.stopPropagation()}
        />
      ),
      className: "w-10",
    }] : []),
    { header: "Product", accessor: (row: any) => (
      <div className="flex items-center gap-2">
        {row.image_url && <img src={row.image_url} alt="" loading="lazy" className="h-8 w-8 rounded-md object-cover" />}
        <span className="font-medium">{row.name}</span>
      </div>
    )},
    { header: "SKU", accessor: "sku" as const, className: "font-mono text-xs text-muted-foreground hidden sm:table-cell" },
    { header: "Category", accessor: (row: any) => row.category ? <Badge variant="secondary">{row.category}</Badge> : <span className="text-muted-foreground">—</span>, className: "hidden md:table-cell" },
    { header: "Base Price", accessor: (row: any) => `₹${Number(row.base_price).toLocaleString()}` },
    { header: "Unit", accessor: "unit" as const, className: "hidden sm:table-cell" },
    { header: "Status", accessor: (row: any) => (
      <div className="flex items-center gap-2">
        <StatusBadge status={row.is_active ? "active" : "inactive"} />
        {canEdit && (
          <Switch
            checked={row.is_active}
            onCheckedChange={() => handleToggleActive(row)}
            className="scale-75"
          />
        )}
      </div>
    )},
    ...(canEdit ? [{
      header: "Actions",
      accessor: (row: any) => (
        <Button variant="ghost" size="sm" className="h-7 text-xs gap-1" onClick={(e: React.MouseEvent) => { e.stopPropagation(); openEdit(row); }}>
          <Pencil className="h-3 w-3" /> Edit
        </Button>
      ),
      hideOnMobile: true,
    }] : []),
  ];

  if (isLoading) {
    return <div className="flex items-center justify-center py-20"><Loader2 className="h-8 w-8 animate-spin text-primary" /></div>;
  }

  if (showMatrix) {
    return <ProductAccessMatrix onBack={() => setShowMatrix(false)} />;
  }

  if (showCategories) {
    return <ProductCategories onBack={() => setShowCategories(false)} />;
  }

  return (
    <div className="space-y-6 animate-fade-in">
      <PageHeader
        title="Products"
        subtitle="Manage your product catalog and pricing"
        primaryAction={{ label: "Add Product", onClick: () => { resetForm(); setShowAdd(true); } }}
        actions={[
          { label: "Categories", icon: Tags, onClick: () => setShowCategories(true), priority: 1 },
          { label: "Product Access", icon: Grid3X3, onClick: () => setShowMatrix(true), priority: 2 },
          ...(canEdit ? [{ label: selectMode ? "Done" : "Select", icon: CheckSquare, onClick: () => { setSelectMode((v) => !v); setSelectedIds(new Set()); }, priority: 3 }] : []),
        ]}
      />

      {selectMode && selectedIds.size > 0 && (
        <NoticeBox
          variant="premium"
          message={
            <div className="flex flex-wrap items-center gap-2 w-full">
              <span className="font-semibold">{selectedIds.size} selected</span>
              <div className="flex gap-2 ml-3">
                <Button size="sm" variant="outline" className="h-8 bg-background text-green-600 border-green-600/40" onClick={() => handleBulkStatus(true)}>Activate</Button>
                <Button size="sm" variant="outline" className="h-8 bg-background text-destructive border-destructive/40" onClick={() => setConfirmBulkDeactivate(true)}>Deactivate</Button>
                <Button size="sm" variant="ghost" className="h-8 ml-auto" onClick={() => setSelectedIds(new Set())}>Clear</Button>
              </div>
            </div>
          }
        />
      )}

      {/* Desktop: Card Grid, Mobile: DataTable */}
      {!isMobile ? (
        <div className="space-y-4">
          {/* Search bar for desktop */}
          <Input 
            placeholder="Search products..." 
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
            className="max-w-sm"
          />
          
          <div className="entity-grid">
            {filteredProducts.map((row: any) => (
              <div
                key={row.id}
                onClick={() => { if (selectMode) { toggleSelect(row.id); } else if (canEdit) { openEdit(row); } }}
                className={`group entity-card ${!row.is_active ? "entity-card-inactive" : ""} ${selectedIds.has(row.id) ? "entity-card-selected" : ""}`}
              >
                {/* Header with image */}
                <div className="entity-card-header !h-36">
                  {row.image_url ? (
                    <img src={row.image_url} alt={row.name} loading="lazy" className="w-full h-full object-cover group-hover:scale-105 transition-transform duration-200" />
                  ) : (
                    <Package className="h-12 w-12 text-muted-foreground/30" />
                  )}
                  <div className="absolute top-2 right-2 flex items-center gap-2">
                    {selectMode && (
                      <Checkbox 
                        checked={selectedIds.has(row.id)}
                        onClick={(e: React.MouseEvent) => { e.stopPropagation(); toggleSelect(row.id); }}
                        className="bg-background"
                      />
                    )}
                    <StatusBadge status={row.is_active ? "active" : "inactive"} />
                  </div>
                </div>

                {/* Content */}
                <div className="entity-card-content">
                  <div>
                    <h3 className="entity-card-title">{row.name}</h3>
                    <p className="entity-card-subtitle mt-0.5">{row.sku}</p>
                  </div>

                  {row.category && (
                    <Badge variant="secondary" className="text-xs">{row.category}</Badge>
                  )}

                  {/* HSN and GST info */}
                  {(row.hsn_code || row.gst_rate) && (
                    <div className="flex items-center gap-2 text-xs text-muted-foreground">
                      {row.hsn_code && <span>HSN: {row.hsn_code}</span>}
                      {row.gst_rate && <span className="bg-blue-100 text-blue-700 px-1.5 py-0.5 rounded font-medium">{row.gst_rate}% GST</span>}
                    </div>
                  )}

                  {/* Price and unit */}
                  <div className="entity-card-stat">
                    <div className="flex items-center gap-1.5 text-muted-foreground">
                      <Box className="h-3.5 w-3.5" />
                      <span className="text-xs">{row.unit}</span>
                    </div>
                    <div className="text-right">
                      <p className="entity-card-label">Price (incl. GST)</p>
                      <p className="font-bold text-foreground">₹{Number(row.base_price).toLocaleString()}</p>
                    </div>
                  </div>

                  {/* Actions */}
                  {canEdit && (
                    <div className="pt-2 border-t flex items-center justify-between">
                      <Switch
                        checked={row.is_active}
                        onCheckedChange={() => handleToggleActive(row)}
                        onClick={(e: React.MouseEvent) => e.stopPropagation()}
                        className="scale-90"
                      />
                      <Button 
                        variant="ghost" 
                        size="sm" 
                        className="h-8 text-xs gap-1.5"
                        onClick={(e: React.MouseEvent) => { e.stopPropagation(); openEdit(row); }}
                      >
                        <Pencil className="h-3.5 w-3.5" /> Edit
                      </Button>
                    </div>
                  )}
                </div>
              </div>
            ))}
          </div>
          {filteredProducts.length === 0 && (
            <div className="text-center py-12 text-muted-foreground">
              No products found.
            </div>
          )}
        </div>
      ) : (
        <DataTable
          columns={columns}
          data={products || []}
          searchKey="name"
          searchPlaceholder="Search products..."
          onRowClick={(row) => { if (canEdit && !selectMode) openEdit(row); }}
          renderMobileCard={(row: any) => (
            <div className={`entity-card-mobile ${!row.is_active ? "entity-card-inactive" : ""}`} onClick={() => { if (selectMode) { toggleSelect(row.id); } else if (canEdit) { openEdit(row); } }}>
              <div className="w-14 h-14 rounded-lg bg-muted flex items-center justify-center overflow-hidden shrink-0">
                {row.image_url ? (
                  <img src={row.image_url} alt={row.name} loading="lazy" className="w-full h-full object-cover" />
                ) : (
                  <Package className="h-6 w-6 text-muted-foreground/40" />
                )}
              </div>
              <div className="flex-1 min-w-0">
                <div className="flex items-start justify-between gap-2">
                  <h3 className="font-semibold text-sm text-foreground truncate">{row.name}</h3>
                  <div className="flex items-center gap-1.5 shrink-0">
                    <StatusBadge status={row.is_active ? "active" : "inactive"} />
                    {canEdit && (
                      <Switch
                        checked={row.is_active}
                        onCheckedChange={(e) => { handleToggleActive(row); }}
                        onClick={(e: React.MouseEvent) => e.stopPropagation()}
                        className="scale-90"
                      />
                    )}
                  </div>
                </div>
                <p className="entity-card-subtitle mt-0.5">{row.sku}</p>
                <div className="flex items-center gap-2 mt-1">
                  <span className="text-sm font-bold text-foreground">₹{Number(row.base_price).toLocaleString()}</span>
                  <span className="text-xs text-muted-foreground">/ {row.unit}</span>
                </div>
                {row.category && (
                  <Badge variant="secondary" className="mt-1 text-xs h-5">{row.category}</Badge>
                )}
              </div>
            </div>
          )}
        />
      )}

      {/* Add Product Dialog */}
      <Dialog open={showAdd} onOpenChange={setShowAdd}>
        <DialogContent className="max-w-lg">
          <DialogHeader>
            <DialogTitle>Add Product</DialogTitle>
          </DialogHeader>
          <form onSubmit={handleAdd} className="space-y-4">
            <div className="flex items-start gap-4">
              <ImageUpload folder="products" currentUrl={imageUrl || null} onUploaded={setImageUrl} onRemoved={() => setImageUrl("")} />
              <div className="flex-1 space-y-3">
                <div><Label>Name</Label><Input value={name} onChange={e => setName(e.target.value)} required className="mt-1" /></div>
                <div><Label>SKU</Label><Input value={sku} onChange={e => setSku(e.target.value)} required className="mt-1" placeholder="WB-500" /></div>
              </div>
            </div>
            <div className="grid grid-cols-2 gap-4">
              <div><Label>Price (₹) <span className="text-xs text-muted-foreground">(incl. GST)</span></Label><Input type="number" value={price} onChange={e => setPrice(e.target.value)} required className="mt-1" /></div>
              <div><Label>Unit</Label><Input value={unit} onChange={e => setUnit(e.target.value)} className="mt-1" /></div>
            </div>
            <div className="grid grid-cols-2 gap-4">
              <div><Label>HSN Code</Label><Input value={hsnCode} onChange={e => setHsnCode(e.target.value)} className="mt-1" placeholder="22011010" /></div>
              <div>
                <Label>GST Rate (%)</Label>
                <Select value={gstRate} onValueChange={setGstRate}>
                  <SelectTrigger className="mt-1"><SelectValue /></SelectTrigger>
                  <SelectContent>
                    <SelectItem value="0">0% (Exempt)</SelectItem>
                    <SelectItem value="5">5%</SelectItem>
                    <SelectItem value="12">12%</SelectItem>
                    <SelectItem value="18">18%</SelectItem>
                    <SelectItem value="28">28%</SelectItem>
                  </SelectContent>
                </Select>
              </div>
            </div>
            <div>
              <Label>Category</Label>
              <Select value={category || "__none__"} onValueChange={(v) => setCategory(v === "__none__" ? "" : v)}>
                <SelectTrigger className="mt-1"><SelectValue placeholder="Select category" /></SelectTrigger>
                <SelectContent>
                  <SelectItem value="__none__">No category</SelectItem>
                  {categoryList?.map((c) => (
                    <SelectItem key={c.id} value={c.name}>{c.name}</SelectItem>
                  ))}
                </SelectContent>
              </Select>
            </div>
            <div><Label>Description</Label><Textarea value={description} onChange={e => setDescription(e.target.value)} className="mt-1" rows={2} /></div>
            <Button type="submit" className="w-full" disabled={saving}>
              {saving ? <Loader2 className="mr-2 h-4 w-4 animate-spin" /> : null}
              Add Product
            </Button>
          </form>
        </DialogContent>
      </Dialog>

      {/* Edit Product Dialog */}
      <Dialog open={!!editProduct} onOpenChange={(open) => { if (!open) { setEditProduct(null); resetForm(); } }}>
        <DialogContent className="max-w-lg">
          <DialogHeader>
            <DialogTitle>Edit Product</DialogTitle>
          </DialogHeader>
          {editProduct && !editProduct.is_active && (
            <NoticeBox
              variant="error"
              className="mb-4"
              icon={AlertTriangle}
              message="This product is inactive. Activate it to use in sales."
            />
          )}
          <form onSubmit={handleEdit} className="space-y-4">
            <div className="flex items-start gap-4">
              <ImageUpload folder="products" currentUrl={imageUrl || null} onUploaded={setImageUrl} onRemoved={() => setImageUrl("")} />
              <div className="flex-1 space-y-3">
                <div><Label>Name</Label><Input value={name} onChange={e => setName(e.target.value)} required className="mt-1" /></div>
                <div><Label>SKU</Label><Input value={sku} onChange={e => setSku(e.target.value)} required className="mt-1" /></div>
              </div>
            </div>
            <div className="grid grid-cols-2 gap-4">
              <div><Label>Price (₹) <span className="text-xs text-muted-foreground">(incl. GST)</span></Label><Input type="number" value={price} onChange={e => setPrice(e.target.value)} required className="mt-1" /></div>
              <div><Label>Unit</Label><Input value={unit} onChange={e => setUnit(e.target.value)} className="mt-1" /></div>
            </div>
            <div className="grid grid-cols-2 gap-4">
              <div><Label>HSN Code</Label><Input value={hsnCode} onChange={e => setHsnCode(e.target.value)} className="mt-1" placeholder="22011010" /></div>
              <div>
                <Label>GST Rate (%)</Label>
                <Select value={gstRate} onValueChange={setGstRate}>
                  <SelectTrigger className="mt-1"><SelectValue /></SelectTrigger>
                  <SelectContent>
                    <SelectItem value="0">0% (Exempt)</SelectItem>
                    <SelectItem value="5">5%</SelectItem>
                    <SelectItem value="12">12%</SelectItem>
                    <SelectItem value="18">18%</SelectItem>
                    <SelectItem value="28">28%</SelectItem>
                  </SelectContent>
                </Select>
              </div>
            </div>
            <div>
              <Label>Category</Label>
              <Select value={category || "__none__"} onValueChange={(v) => setCategory(v === "__none__" ? "" : v)}>
                <SelectTrigger className="mt-1"><SelectValue placeholder="Select category" /></SelectTrigger>
                <SelectContent>
                  <SelectItem value="__none__">No category</SelectItem>
                  {categoryList?.map((c) => (
                    <SelectItem key={c.id} value={c.name}>{c.name}</SelectItem>
                  ))}
                </SelectContent>
              </Select>
            </div>
            <div><Label>Description</Label><Textarea value={description} onChange={e => setDescription(e.target.value)} className="mt-1" rows={2} /></div>
            <Button type="submit" className="w-full" disabled={saving}>
              {saving ? <Loader2 className="mr-2 h-4 w-4 animate-spin" /> : null}
              Save Changes
            </Button>
          </form>
        </DialogContent>
      </Dialog>

      <AlertDialog open={confirmBulkDeactivate} onOpenChange={setConfirmBulkDeactivate}>
        <AlertDialogContent>
          <AlertDialogHeader>
            <AlertDialogTitle>Deactivate {selectedIds.size} product(s)?</AlertDialogTitle>
            <AlertDialogDescription>
              The selected products will no longer appear in order forms. This can be reversed by reactivating them.
            </AlertDialogDescription>
          </AlertDialogHeader>
          <AlertDialogFooter>
            <AlertDialogCancel>Cancel</AlertDialogCancel>
            <AlertDialogAction className="bg-destructive hover:bg-destructive/90" onClick={() => { setConfirmBulkDeactivate(false); handleBulkStatus(false); }}>Deactivate</AlertDialogAction>
          </AlertDialogFooter>
        </AlertDialogContent>
      </AlertDialog>
    </div>
  );
};

export default Products;

import { useState, useEffect } from "react";
import { PageHeader } from "@/components/shared/PageHeader";
import { Card, CardContent } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Textarea } from "@/components/ui/textarea";
import { Badge } from "@/components/ui/badge";
import { useQuery, useQueryClient } from "@tanstack/react-query";
import { supabase } from "@/integrations/supabase/client";
import { useAuth } from "@/contexts/AuthContext";
import { Loader2, Plus, RotateCcw, Search, Package, CheckCircle, XCircle, Clock, Eye } from "lucide-react";
import { toast } from "sonner";
import { format } from "date-fns";
import {
  Dialog, DialogContent, DialogHeader, DialogTitle, DialogDescription, DialogFooter,
} from "@/components/ui/dialog";
import {
  Select, SelectContent, SelectItem, SelectTrigger, SelectValue,
} from "@/components/ui/select";
import { DataTable } from "@/components/shared/DataTable";
import { ResponsiveDataView } from "@/components/shared/ResponsiveDataView";
import { useIsMobile } from "@/hooks/use-mobile";

const PurchaseReturns = () => {
  const { user, role } = useAuth();
  const qc = useQueryClient();
  const isMobile = useIsMobile();
  const canApprove = ["super_admin", "manager"].includes(role || "");

  const [showCreate, setShowCreate] = useState(false);
  const [showDetail, setShowDetail] = useState<string | null>(null);
  const [search, setSearch] = useState("");
  const [statusFilter, setStatusFilter] = useState<string>("all");

  // Form state
  const [purchaseId, setPurchaseId] = useState("");
  const [reason, setReason] = useState("");
  const [notes, setNotes] = useState("");
  const [returnItems, setReturnItems] = useState<Array<{ 
    purchase_item_id: string; 
    quantity: number; 
    max_qty: number; 
    item_name: string; 
    unit_price: number;
    item_type: string;
    item_id: string;
  }>>([]);
  const [saving, setSaving] = useState(false);

  const PAGE_SIZE = 100;
  const [loadedPages, setLoadedPages] = useState(1);

  // Fetch returns
  const { data: returns = [], isLoading, isFetching } = useQuery({
    queryKey: ["purchase-returns", loadedPages],
    queryFn: async () => {
      let query = supabase
        .from("purchase_returns")
        .select(`
          *,
          purchases(display_id, total_amount),
          vendors(name),
          profiles:created_by(full_name),
          approver:approved_by(full_name)
        `)
        .order("created_at", { ascending: false });

      query = query.range(0, loadedPages * PAGE_SIZE - 1);
      
      const { data, error } = await query;
      if (error) throw error;
      return data || [];
    },
  });

  const hasMoreReturns = returns.length >= loadedPages * PAGE_SIZE;

  // Fetch purchases for dropdown
  const { data: purchases = [] } = useQuery({
    queryKey: ["purchases-for-return"],
    queryFn: async () => {
      const { data } = await supabase
        .from("purchases")
        .select("id, display_id, purchase_date, total_amount, vendor_id, vendors(name)")
        .order("purchase_date", { ascending: false })
        .limit(100);
      return data || [];
    },
  });

  // Fetch purchase items when purchase is selected
  const { data: purchaseItems = [] } = useQuery({
    queryKey: ["purchase-items-for-return", purchaseId],
    queryFn: async () => {
      if (!purchaseId) return [];
      const { data } = await supabase
        .from("purchase_items")
        .select("id, item_type, item_id, quantity, unit_price, total, products(name), raw_materials(name)")
        .eq("purchase_id", purchaseId);
      return data || [];
    },
    enabled: !!purchaseId,
  });

  // Fetch return detail
  const { data: returnDetail } = useQuery({
    queryKey: ["purchase-return-detail", showDetail],
    queryFn: async () => {
      if (!showDetail) return null;
      const { data: ret } = await supabase
        .from("purchase_returns")
        .select(`
          *,
          purchases(display_id, total_amount, purchase_date),
          vendors(name),
          profiles:created_by(full_name),
          approver:approved_by(full_name)
        `)
        .eq("id", showDetail)
        .single();
      
      const { data: items } = await supabase
        .from("purchase_return_items")
        .select("*, products(name), raw_materials(name)")
        .eq("return_id", showDetail);
      
      return { ...ret, items: items || [] };
    },
    enabled: !!showDetail,
  });

  const resetForm = () => {
    setPurchaseId("");
    setReason("");
    setNotes("");
    setReturnItems([]);
  };

  const handlePurchaseSelect = (id: string) => {
    setPurchaseId(id);
    setReturnItems([]);
  };

  // Update return items when purchase items load - wrapped in useEffect to avoid infinite renders
  useEffect(() => {
    if (purchaseId && purchaseItems.length > 0 && returnItems.length === 0) {
      const items = purchaseItems.map((pi: any) => ({
        purchase_item_id: pi.id,
        quantity: 0,
        max_qty: Number(pi.quantity),
        item_name: pi.item_type === "product" 
          ? (pi.products?.name || "Product") 
          : (pi.raw_materials?.name || "Raw Material"),
        unit_price: Number(pi.unit_price),
        item_type: pi.item_type,
        item_id: pi.item_id,
      }));
      setReturnItems(items);
    }
  }, [purchaseId, purchaseItems]);

  const updateItemQuantity = (idx: number, qty: number) => {
    setReturnItems((prev) => {
      const updated = [...prev];
      updated[idx].quantity = Math.min(Math.max(0, qty), updated[idx].max_qty);
      return updated;
    });
  };

  const calculateTotal = () => {
    return returnItems.reduce((sum, item) => sum + (item.quantity * item.unit_price), 0);
  };

  const handleCreate = async (e: React.FormEvent) => {
    e.preventDefault();
    
    const itemsToReturn = returnItems.filter((i) => i.quantity > 0);
    if (itemsToReturn.length === 0) {
      toast.error("Please select at least one item to return");
      return;
    }
    if (!reason.trim()) {
      toast.error("Please provide a reason for the return");
      return;
    }

    setSaving(true);
    try {
      // Get purchase details
      const purchase = purchases.find((p: any) => p.id === purchaseId);
      
      // Generate display ID
      const { data: displayId } = await supabase.rpc("generate_purchase_return_display_id");
      
      // Calculate total
      const totalAmount = calculateTotal();

      // Create return
      const { data: newReturn, error: returnError } = await supabase
        .from("purchase_returns")
        .insert({
          display_id: displayId,
          purchase_id: purchaseId,
          vendor_id: (purchase as any)?.vendor_id,
          return_date: new Date().toISOString().split("T")[0],
          total_amount: totalAmount,
          reason,
          notes,
          status: "pending",
          created_by: user?.id,
        })
        .select("id")
        .single();

      if (returnError) throw returnError;

      // Create return items
      const returnItemsData = itemsToReturn.map((item) => ({
        return_id: newReturn.id,
        purchase_item_id: item.purchase_item_id,
        item_type: item.item_type,
        item_id: item.item_id,
        quantity: item.quantity,
        unit_price: item.unit_price,
        total: item.quantity * item.unit_price,
      }));

      const { error: itemsError } = await supabase
        .from("purchase_return_items")
        .insert(returnItemsData);

      if (itemsError) throw itemsError;

      toast.success("Purchase return created successfully");
      setShowCreate(false);
      resetForm();
      qc.invalidateQueries({ queryKey: ["purchase-returns"] });
    } catch (err: any) {
      toast.error(err.message || "Failed to create return");
    } finally {
      setSaving(false);
    }
  };

  const handleStatusUpdate = async (id: string, newStatus: "approved" | "rejected" | "completed") => {
    try {
      const updates: any = { status: newStatus };
      if (newStatus === "approved" || newStatus === "rejected") {
        updates.approved_by = user?.id;
        updates.approved_at = new Date().toISOString();
      }

      const { error } = await supabase
        .from("purchase_returns")
        .update(updates)
        .eq("id", id);

      if (error) throw error;

      toast.success(`Return ${newStatus}`);
      qc.invalidateQueries({ queryKey: ["purchase-returns"] });
      qc.invalidateQueries({ queryKey: ["purchase-return-detail", id] });
    } catch (err: any) {
      toast.error(err.message);
    }
  };

  const getStatusBadge = (status: string) => {
    switch (status) {
      case "pending":
        return <Badge variant="secondary" className="bg-yellow-100 text-yellow-800"><Clock className="h-3 w-3 mr-1" />Pending</Badge>;
      case "approved":
        return <Badge variant="secondary" className="bg-blue-100 text-blue-800"><CheckCircle className="h-3 w-3 mr-1" />Approved</Badge>;
      case "completed":
        return <Badge variant="default" className="bg-green-100 text-green-800"><CheckCircle className="h-3 w-3 mr-1" />Completed</Badge>;
      case "rejected":
        return <Badge variant="destructive"><XCircle className="h-3 w-3 mr-1" />Rejected</Badge>;
      default:
        return <Badge variant="outline">{status}</Badge>;
    }
  };

  const filteredReturns = returns.filter((r: any) => {
    const matchesSearch = !search || 
      r.display_id?.toLowerCase().includes(search.toLowerCase()) ||
      r.purchases?.display_id?.toLowerCase().includes(search.toLowerCase()) ||
      r.vendors?.name?.toLowerCase().includes(search.toLowerCase());
    const matchesStatus = statusFilter === "all" || r.status === statusFilter;
    return matchesSearch && matchesStatus;
  });

  const columns = [
    { header: "Return ID", accessor: (r: any) => <span className="font-mono text-sm">{r.display_id}</span> },
    { header: "Purchase", accessor: (r: any) => <span className="font-mono text-sm text-muted-foreground">{r.purchases?.display_id}</span> },
    { header: "Vendor", accessor: (r: any) => r.vendors?.name || "—" },
    { header: "Date", accessor: (r: any) => format(new Date(r.return_date), "dd MMM yyyy") },
    { header: "Amount", accessor: (r: any) => <span className="font-semibold">₹{Number(r.total_amount).toLocaleString()}</span> },
    { header: "Status", accessor: (r: any) => getStatusBadge(r.status) },
    { header: "Actions", accessor: (r: any) => (
      <Button variant="ghost" size="sm" onClick={() => setShowDetail(r.id)}>
        <Eye className="h-4 w-4" />
      </Button>
    )},
  ];

  return (
    <div className="space-y-6 animate-fade-in">
      <PageHeader
        title="Purchase Returns"
        subtitle="Manage returns to vendors"
        primaryAction={{ label: "Record Return", onClick: () => setShowCreate(true), icon: Plus }}
      />

      {/* Filters */}
      <Card className="p-4">
        <div className="flex flex-wrap items-center gap-4">
          <div className="relative flex-1 min-w-[200px]">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-muted-foreground" />
            <Input
              placeholder="Search returns..."
              value={search}
              onChange={(e) => setSearch(e.target.value)}
              className="pl-9"
            />
          </div>
          <Select value={statusFilter} onValueChange={setStatusFilter}>
            <SelectTrigger className="w-[150px]">
              <SelectValue placeholder="All Status" />
            </SelectTrigger>
            <SelectContent>
              <SelectItem value="all">All Status</SelectItem>
              <SelectItem value="pending">Pending</SelectItem>
              <SelectItem value="approved">Approved</SelectItem>
              <SelectItem value="completed">Completed</SelectItem>
              <SelectItem value="rejected">Rejected</SelectItem>
            </SelectContent>
          </Select>
        </div>
      </Card>

      {isLoading ? (
        <div className="flex items-center justify-center py-12">
          <Loader2 className="h-8 w-8 animate-spin text-muted-foreground" />
        </div>
      ) : filteredReturns.length === 0 ? (
        <Card>
          <CardContent className="flex flex-col items-center justify-center py-12">
            <RotateCcw className="h-12 w-12 text-muted-foreground/30 mb-4" />
            <p className="text-muted-foreground">No purchase returns found</p>
          </CardContent>
        </Card>
      ) : isMobile ? (
        <ResponsiveDataView
          data={filteredReturns}
          renderMobileCard={(r: any) => (
            <Card key={r.id} className="entity-card-mobile" onClick={() => setShowDetail(r.id)}>
              <CardContent className="p-4">
                <div className="flex items-start justify-between mb-2">
                  <div>
                    <p className="font-semibold">{r.display_id}</p>
                    <p className="text-sm text-muted-foreground">Purchase: {r.purchases?.display_id}</p>
                  </div>
                  {getStatusBadge(r.status)}
                </div>
                <div className="flex items-center justify-between text-sm">
                  <span className="text-muted-foreground">{r.vendors?.name}</span>
                  <span className="font-semibold">₹{Number(r.total_amount).toLocaleString()}</span>
                </div>
                <p className="text-xs text-muted-foreground mt-1">{format(new Date(r.return_date), "dd MMM yyyy")}</p>
              </CardContent>
            </Card>
          )}
        />
      ) : (
        <DataTable data={filteredReturns} columns={columns} />
      )}

      {hasMoreReturns && (
        <div className="flex justify-center pt-2">
          <Button variant="outline" size="sm" onClick={() => setLoadedPages((p) => p + 1)} disabled={isFetching} className="gap-1.5">
            {isFetching ? <Loader2 className="h-3.5 w-3.5 animate-spin" /> : null}
            Load more
          </Button>
        </div>
      )}

      {/* Create Return Dialog */}
      <Dialog open={showCreate} onOpenChange={(open) => { setShowCreate(open); if (!open) resetForm(); }}>
        <DialogContent className="max-w-2xl max-h-[90vh] overflow-y-auto">
          <DialogHeader>
            <DialogTitle>Record Purchase Return</DialogTitle>
            <DialogDescription>Create a return request for a purchase</DialogDescription>
          </DialogHeader>
          <form onSubmit={handleCreate} className="space-y-4">
            <div>
              <Label>Select Purchase *</Label>
              <Select value={purchaseId} onValueChange={handlePurchaseSelect}>
                <SelectTrigger className="mt-1">
                  <SelectValue placeholder="Select a purchase to return" />
                </SelectTrigger>
                <SelectContent>
                  {purchases.map((p: any) => (
                    <SelectItem key={p.id} value={p.id}>
                      {p.display_id} - {p.vendors?.name} - ₹{Number(p.total_amount).toLocaleString()}
                    </SelectItem>
                  ))}
                </SelectContent>
              </Select>
            </div>

            {purchaseId && returnItems.length > 0 && (
              <div className="space-y-3">
                <Label>Items to Return</Label>
                <div className="border rounded-lg divide-y">
                  {returnItems.map((item, idx) => (
                    <div key={item.purchase_item_id} className="p-3 flex items-center gap-4">
                      <div className="flex-1">
                        <p className="font-medium">{item.item_name}</p>
                        <p className="text-sm text-muted-foreground">
                          {item.item_type === "raw_material" ? "Raw Material" : "Product"} • ₹{item.unit_price} × max {item.max_qty}
                        </p>
                      </div>
                      <div className="flex items-center gap-2">
                        <Label className="text-sm">Qty:</Label>
                        <Input
                          type="number"
                          min={0}
                          max={item.max_qty}
                          value={item.quantity}
                          onChange={(e) => updateItemQuantity(idx, parseInt(e.target.value) || 0)}
                          className="w-20"
                        />
                      </div>
                      <p className="font-medium w-24 text-right">
                        ₹{(item.quantity * item.unit_price).toLocaleString()}
                      </p>
                    </div>
                  ))}
                </div>
                <div className="flex justify-end p-3 bg-muted/50 rounded-lg">
                  <p className="font-semibold">Total Return: ₹{calculateTotal().toLocaleString()}</p>
                </div>
              </div>
            )}

            <div>
              <Label>Reason for Return *</Label>
              <Select value={reason} onValueChange={setReason}>
                <SelectTrigger className="mt-1">
                  <SelectValue placeholder="Select reason" />
                </SelectTrigger>
                <SelectContent>
                  <SelectItem value="damaged">Damaged Product</SelectItem>
                  <SelectItem value="defective">Defective/Quality Issue</SelectItem>
                  <SelectItem value="wrong_item">Wrong Item Received</SelectItem>
                  <SelectItem value="excess">Excess Quantity</SelectItem>
                  <SelectItem value="expired">Expired Product</SelectItem>
                  <SelectItem value="other">Other</SelectItem>
                </SelectContent>
              </Select>
            </div>

            <div>
              <Label>Additional Notes</Label>
              <Textarea
                value={notes}
                onChange={(e) => setNotes(e.target.value)}
                placeholder="Any additional details..."
                className="mt-1"
              />
            </div>

            <DialogFooter>
              <Button type="button" variant="outline" onClick={() => { setShowCreate(false); resetForm(); }}>
                Cancel
              </Button>
              <Button type="submit" disabled={saving || !purchaseId || calculateTotal() === 0}>
                {saving ? <Loader2 className="h-4 w-4 animate-spin mr-2" /> : null}
                Create Return
              </Button>
            </DialogFooter>
          </form>
        </DialogContent>
      </Dialog>

      {/* Return Detail Dialog */}
      <Dialog open={!!showDetail} onOpenChange={(open) => !open && setShowDetail(null)}>
        <DialogContent className="max-w-2xl">
          <DialogHeader>
            <DialogTitle>Return Details</DialogTitle>
            <DialogDescription>{returnDetail?.display_id}</DialogDescription>
          </DialogHeader>
          
          {returnDetail && (
            <div className="space-y-4">
              <div className="grid grid-cols-2 gap-4">
                <div>
                  <p className="text-sm text-muted-foreground">Purchase</p>
                  <p className="font-medium">{returnDetail.purchases?.display_id}</p>
                </div>
                <div>
                  <p className="text-sm text-muted-foreground">Vendor</p>
                  <p className="font-medium">{returnDetail.vendors?.name}</p>
                </div>
                <div>
                  <p className="text-sm text-muted-foreground">Return Date</p>
                  <p className="font-medium">{format(new Date(returnDetail.return_date), "dd MMM yyyy")}</p>
                </div>
                <div>
                  <p className="text-sm text-muted-foreground">Status</p>
                  {getStatusBadge(returnDetail.status)}
                </div>
                <div>
                  <p className="text-sm text-muted-foreground">Created By</p>
                  <p className="font-medium">{returnDetail.profiles?.full_name || "—"}</p>
                </div>
                {returnDetail.approver && (
                  <div>
                    <p className="text-sm text-muted-foreground">Approved By</p>
                    <p className="font-medium">{returnDetail.approver.full_name}</p>
                  </div>
                )}
              </div>

              <div>
                <p className="text-sm text-muted-foreground mb-2">Reason</p>
                <p className="capitalize">{returnDetail.reason?.replace("_", " ")}</p>
              </div>

              {returnDetail.notes && (
                <div>
                  <p className="text-sm text-muted-foreground mb-2">Notes</p>
                  <p>{returnDetail.notes}</p>
                </div>
              )}

              <div>
                <p className="text-sm text-muted-foreground mb-2">Items</p>
                <div className="border rounded-lg divide-y">
                  {returnDetail.items?.map((item: any) => (
                    <div key={item.id} className="p-3 flex items-center justify-between">
                      <div>
                        <p className="font-medium">
                          {item.item_type === "product" 
                            ? (item.products?.name || "Product")
                            : (item.raw_materials?.name || "Raw Material")}
                        </p>
                        <p className="text-sm text-muted-foreground">₹{Number(item.unit_price).toLocaleString()} × {item.quantity}</p>
                      </div>
                      <p className="font-semibold">₹{Number(item.total).toLocaleString()}</p>
                    </div>
                  ))}
                </div>
                <div className="flex justify-end mt-2">
                  <p className="font-bold text-lg">Total: ₹{Number(returnDetail.total_amount).toLocaleString()}</p>
                </div>
              </div>

              {canApprove && returnDetail.status === "pending" && (
                <div className="flex gap-2 pt-4 border-t">
                  <Button 
                    className="flex-1" 
                    onClick={() => handleStatusUpdate(returnDetail.id, "approved")}
                  >
                    <CheckCircle className="h-4 w-4 mr-2" />
                    Approve
                  </Button>
                  <Button 
                    variant="destructive" 
                    className="flex-1"
                    onClick={() => handleStatusUpdate(returnDetail.id, "rejected")}
                  >
                    <XCircle className="h-4 w-4 mr-2" />
                    Reject
                  </Button>
                </div>
              )}

              {canApprove && returnDetail.status === "approved" && (
                <div className="pt-4 border-t">
                  <Button 
                    className="w-full"
                    onClick={() => handleStatusUpdate(returnDetail.id, "completed")}
                  >
                    <CheckCircle className="h-4 w-4 mr-2" />
                    Mark as Completed (Process Return)
                  </Button>
                </div>
              )}
            </div>
          )}
        </DialogContent>
      </Dialog>
    </div>
  );
};

export default PurchaseReturns;

import { PageHeader } from "@/components/shared/PageHeader";
import { DataTable } from "@/components/shared/DataTable";
import { StatusBadge } from "@/components/shared/StatusBadge";
import { Badge } from "@/components/ui/badge";
import { useQuery, useQueryClient } from "@tanstack/react-query";
import { supabase } from "@/integrations/supabase/client";
import { useAuth } from "@/contexts/AuthContext";
import { Loader2, Plus, Trash2, Package, RotateCcw } from "lucide-react";
import { TableSkeleton } from "@/components/shared/TableSkeleton";
import { useState, useEffect } from "react";
import { useNavigate, useLocation } from "react-router-dom";
import { Dialog, DialogContent, DialogHeader, DialogTitle } from "@/components/ui/dialog";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Textarea } from "@/components/ui/textarea";
import { Button } from "@/components/ui/button";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { toast } from "sonner";
import { logActivity } from "@/lib/activityLogger";

interface PurchaseItem {
  item_type: "product" | "raw_material";
  item_id: string;
  quantity: number;
  unit_cost: number;
}

const Purchases = () => {
  const navigate = useNavigate();
  const location = useLocation();
  const { user } = useAuth();
  const qc = useQueryClient();
  const [showAdd, setShowAdd] = useState(false);
  const [saving, setSaving] = useState(false);

  // Form state
  const [vendorId, setVendorId] = useState(location.state?.vendorId || "");
  const [warehouseId, setWarehouseId] = useState("");
  const [purchaseDate, setPurchaseDate] = useState(new Date().toISOString().split("T")[0]);
  const [billNumber, setBillNumber] = useState("");
  const [billAmount, setBillAmount] = useState("");
  const [taxAmount, setTaxAmount] = useState("");
  const [discountAmount, setDiscountAmount] = useState("");
  const [notes, setNotes] = useState("");
  const [items, setItems] = useState<PurchaseItem[]>([{ item_type: "product", item_id: "", quantity: 1, unit_cost: 0 }]);

  const PAGE_SIZE = 100;
  const [loadedPages, setLoadedPages] = useState(1);

  const { data: purchases = [], isLoading, isFetching } = useQuery({
    queryKey: ["purchases", loadedPages],
    queryFn: async () => {
      let query = supabase
        .from("purchases")
        .select("*, vendors(name), purchase_items(*, products(name))")
        .order("purchase_date", { ascending: false });

      query = query.range(0, loadedPages * PAGE_SIZE - 1);

      const { data, error } = await query;
      if (error) throw error;
      return data;
    },
  });

  const hasMorePurchases = purchases.length >= loadedPages * PAGE_SIZE;

  const { data: vendors = [] } = useQuery({
    queryKey: ["vendors-list"],
    queryFn: async () => {
      const { data } = await supabase.from("vendors").select("id, name, display_id").eq("is_active", true);
      return data || [];
    },
  });

  const { data: warehouses = [] } = useQuery({
    queryKey: ["warehouses-list"],
    queryFn: async () => {
      const { data } = await supabase.from("warehouses").select("id, name").eq("is_active", true);
      return data || [];
    },
  });

  const { data: products = [] } = useQuery({
    queryKey: ["products-list"],
    queryFn: async () => {
      const { data } = await supabase.from("products").select("id, name, sku").eq("is_active", true);
      return data || [];
    },
  });

  const { data: rawMaterials = [] } = useQuery({
    queryKey: ["raw-materials-list"],
    queryFn: async () => {
      // Show all active raw materials (vendor assignment is optional)
      const { data, error } = await supabase
        .from("raw_materials")
        .select("id, name, display_id, unit, vendor_id, vendors(name)")
        .eq("is_active", true)
        .order("name");
      if (error) {
        console.error("Error fetching raw materials:", error);
        return [];
      }
      return data || [];
    },
  });

  const resetForm = () => {
    setVendorId(location.state?.vendorId || "");
    setWarehouseId("");
    setPurchaseDate(new Date().toISOString().split("T")[0]);
    setBillNumber("");
    setBillAmount("");
    setTaxAmount("");
    setDiscountAmount("");
    setNotes("");
    setItems([{ item_type: "product", item_id: "", quantity: 1, unit_cost: 0 }]);
  };

  const addItem = () => {
    setItems([...items, { item_type: "product", item_id: "", quantity: 1, unit_cost: 0 }]);
  };

  const removeItem = (index: number) => {
    setItems(items.filter((_, i) => i !== index));
  };

  const updateItem = (index: number, field: keyof PurchaseItem, value: any) => {
    const newItems = [...items];
    newItems[index] = { ...newItems[index], [field]: value };
    setItems(newItems);
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setSaving(true);

    try {
      // Validate items
      const validItems = items.filter(item => item.item_id && item.quantity > 0 && item.unit_cost >= 0);
      if (validItems.length === 0) {
        toast.error("Please add at least one valid item");
        setSaving(false);
        return;
      }

      // Generate display ID
      const { data: idData } = await supabase.rpc("generate_display_id", {
        prefix: "PUR",
        seq_name: "purchases_display_id_seq"
      });

      // Create purchase
      const { data: purchase, error: purchaseError } = await supabase
        .from("purchases")
        .insert({
          display_id: idData,
          vendor_id: vendorId,
          warehouse_id: warehouseId || null,
          purchase_date: purchaseDate,
          bill_number: billNumber.trim() || null,
          bill_amount: parseFloat(billAmount),
          tax_amount: taxAmount ? parseFloat(taxAmount) : 0,
          discount_amount: discountAmount ? parseFloat(discountAmount) : 0,
          notes: notes.trim() || null,
          status: "completed",
          created_by: user!.id
        })
        .select()
        .single();

      if (purchaseError) throw purchaseError;

      // Create purchase items (product or raw material)
      const itemsData = validItems.map(item => ({
        purchase_id: purchase.id,
        product_id: item.item_type === "product" ? item.item_id : null,
        raw_material_id: item.item_type === "raw_material" ? item.item_id : null,
        quantity: item.quantity,
        unit_cost: item.unit_cost,
      }));

      const { error: itemsError } = await supabase
        .from("purchase_items")
        .insert(itemsData);

      if (itemsError) throw itemsError;

      toast.success("Purchase recorded successfully");
      logActivity(user!.id, `Created purchase ${idData}`, "purchase");
      
      qc.invalidateQueries({ queryKey: ["purchases"] });
      qc.invalidateQueries({ queryKey: ["vendors"] });
      qc.invalidateQueries({ queryKey: ["product_stock"] });
      qc.invalidateQueries({ queryKey: ["raw-materials"] });
      
      setShowAdd(false);
      resetForm();
    } catch (error: any) {
      toast.error(error.message || "Failed to create purchase");
    } finally {
      setSaving(false);
    }
  };

  const totalAmount = () => {
    const bill = parseFloat(billAmount) || 0;
    const tax = parseFloat(taxAmount) || 0;
    const discount = parseFloat(discountAmount) || 0;
    return bill + tax - discount;
  };

  const columns = [
    { header: "ID", accessor: "display_id" as const, className: "font-mono text-xs" },
    { header: "Date", accessor: (row: any) => new Date(row.purchase_date).toLocaleDateString("en-IN"), className: "text-sm" },
    { header: "Vendor", accessor: (row: any) => row.vendors?.name || "—", className: "text-sm" },
    { header: "Bill #", accessor: (row: any) => row.bill_number || "—", className: "text-xs text-muted-foreground" },
    { 
      header: "Items", 
      accessor: (row: any) => (
        <span className="text-xs text-muted-foreground">
          {row.purchase_items?.length || 0} item(s)
        </span>
      )
    },
    { header: "Amount", accessor: (row: any) => `₹${Number(row.total_amount).toLocaleString()}`, className: "font-semibold" },
    { header: "Status", accessor: (row: any) => <StatusBadge status={row.status === "completed" ? "active" : row.status as any} label={row.status} /> },
  ];

  if (isLoading) {
    return <TableSkeleton columns={7} />;
  }

  return (
    <div className="space-y-6 animate-fade-in">
      <PageHeader
        title="Purchases"
        subtitle="Record inventory purchases from vendors"
        primaryAction={{ label: "New Purchase", onClick: () => { resetForm(); setShowAdd(true); } }}
        actions={[
          {
            label: "Returns",
            icon: RotateCcw,
            onClick: () => navigate("/purchase-returns"),
            priority: 0,
          },
          {
            label: "Raw Materials",
            icon: Package,
            onClick: () => navigate("/raw-materials"),
            priority: 1,
            variant: "outline"
          }
        ]}
      />

      <DataTable
        columns={columns}
        data={purchases}
        searchKey="display_id"
        searchPlaceholder="Search purchases..."
        emptyMessage="No purchases recorded yet"
        renderMobileCard={(row: any) => (
          <div className="entity-card-mobile">
            <div className="w-10 h-10 rounded-lg bg-primary/10 flex items-center justify-center shrink-0">
              <Package className="h-5 w-5 text-primary" />
            </div>
            <div className="flex-1 min-w-0">
              <div className="flex items-start justify-between gap-2">
                <div className="min-w-0">
                  <h3 className="font-semibold text-sm truncate">{row.vendors?.name || "Unknown Vendor"}</h3>
                  <p className="entity-card-subtitle">{row.display_id}</p>
                </div>
                <StatusBadge status={row.status === "completed" ? "active" : row.status as any} label={row.status} />
              </div>
              <div className="flex items-center justify-between mt-1">
                <div className="flex items-center gap-2 text-xs text-muted-foreground">
                  <span>{new Date(row.purchase_date).toLocaleDateString("en-IN")}</span>
                  <span>•</span>
                  <span>{row.purchase_items?.length || 0} items</span>
                </div>
                <span className="font-bold text-sm">₹{Number(row.total_amount).toLocaleString()}</span>
              </div>
            </div>
          </div>
        )}
      />

      {hasMorePurchases && (
        <div className="flex justify-center pt-2">
          <Button variant="outline" size="sm" onClick={() => setLoadedPages((p) => p + 1)} disabled={isFetching} className="gap-1.5">
            {isFetching ? <Loader2 className="h-3.5 w-3.5 animate-spin" /> : null}
            Load more
          </Button>
        </div>
      )}

      {/* Add Purchase Dialog */}
      <Dialog open={showAdd} onOpenChange={(open) => { setShowAdd(open); if (!open) resetForm(); }}>
        <DialogContent className="max-w-4xl max-h-[90vh] overflow-y-auto">
          <DialogHeader>
            <DialogTitle>Record New Purchase</DialogTitle>
          </DialogHeader>
          <form onSubmit={handleSubmit} className="space-y-6">
            {/* Basic Details */}
            <div className="grid grid-cols-2 gap-4">
              <div>
                <Label>Vendor *</Label>
                <Select value={vendorId} onValueChange={setVendorId} required>
                  <SelectTrigger className="mt-1">
                    <SelectValue placeholder="Select vendor" />
                  </SelectTrigger>
                  <SelectContent>
                    {vendors.map((v: any) => (
                      <SelectItem key={v.id} value={v.id}>
                        {v.name} ({v.display_id})
                      </SelectItem>
                    ))}
                  </SelectContent>
                </Select>
              </div>
              <div>
                <Label>Warehouse</Label>
                <Select value={warehouseId} onValueChange={setWarehouseId}>
                  <SelectTrigger className="mt-1">
                    <SelectValue placeholder="Select warehouse (optional)" />
                  </SelectTrigger>
                  <SelectContent>
                    {warehouses.map((w: any) => (
                      <SelectItem key={w.id} value={w.id}>{w.name}</SelectItem>
                    ))}
                  </SelectContent>
                </Select>
              </div>
              <div>
                <Label>Purchase Date *</Label>
                <Input type="date" value={purchaseDate} onChange={e => setPurchaseDate(e.target.value)} required className="mt-1" />
              </div>
              <div>
                <Label>Bill Number</Label>
                <Input value={billNumber} onChange={e => setBillNumber(e.target.value)} className="mt-1" placeholder="Vendor's invoice #" />
              </div>
            </div>

            {/* Purchase Items */}
            <div>
              <div className="flex items-center justify-between mb-3">
                <Label>Purchase Items *</Label>
                <Button type="button" size="sm" variant="outline" onClick={addItem}>
                  <Plus className="h-4 w-4 mr-1" />
                  Add Item
                </Button>
              </div>
              <div className="space-y-3 border rounded-lg p-3">
                {items.map((item, index) => (
                  <div key={index} className="grid grid-cols-12 gap-2 items-end">
                    {/* Type selector - 2 cols */}
                    <div className="col-span-2">
                      <Label className="text-xs text-muted-foreground mb-1 block">Type</Label>
                      <Select value={item.item_type} onValueChange={(value) => {
                        const newType = value as "product" | "raw_material";
                        // Update both item_type and clear item_id in a single state update
                        setItems(prevItems => {
                          const newItems = [...prevItems];
                          newItems[index] = { ...newItems[index], item_type: newType, item_id: "" };
                          return newItems;
                        });
                      }}>
                        <SelectTrigger className="h-9">
                          <SelectValue />
                        </SelectTrigger>
                        <SelectContent position="popper" sideOffset={4}>
                          <SelectItem value="product">Product</SelectItem>
                          <SelectItem value="raw_material">Raw Material</SelectItem>
                        </SelectContent>
                      </Select>
                    </div>
                    {/* Item selector - 4 cols */}
                    <div className="col-span-4">
                      <Label className="text-xs text-muted-foreground mb-1 block">Item</Label>
                      <Select key={`${index}-${item.item_type}`} value={item.item_id} onValueChange={(value) => updateItem(index, "item_id", value)}>
                        <SelectTrigger className="h-9">
                          <SelectValue placeholder={item.item_type === "product" ? "Select product" : "Select raw material"} />
                        </SelectTrigger>
                        <SelectContent position="popper" sideOffset={4}>
                          {item.item_type === "product" ? (
                            products.length > 0 ? products.map((p: any) => (
                              <SelectItem key={p.id} value={p.id}>
                                {p.name} {p.sku && `(${p.sku})`}
                              </SelectItem>
                            )) : (
                              <div className="py-2 px-3 text-sm text-muted-foreground">No products available</div>
                            )
                          ) : (
                            rawMaterials.length > 0 ? rawMaterials.map((rm: any) => (
                              <SelectItem key={rm.id} value={rm.id}>
                                {rm.name} ({rm.display_id})
                                {rm.vendors?.name && ` - ${rm.vendors.name}`}
                              </SelectItem>
                            )) : (
                              <div className="py-2 px-3 text-sm text-muted-foreground">No raw materials available</div>
                            )
                          )}
                        </SelectContent>
                      </Select>
                    </div>
                    {/* Quantity - 2 cols */}
                    <div className="col-span-2">
                      <Label className="text-xs text-muted-foreground mb-1 block">Qty</Label>
                      <Input 
                        type="number" 
                        min="1" 
                        value={item.quantity}
                        onChange={e => updateItem(index, "quantity", parseInt(e.target.value) || 1)}
                        className="h-9"
                      />
                    </div>
                    {/* Unit Cost - 2 cols */}
                    <div className="col-span-2">
                      <Label className="text-xs text-muted-foreground mb-1 block">Unit Cost</Label>
                      <Input 
                        type="number" 
                        step="0.01" 
                        min="0"
                        value={item.unit_cost} 
                        onChange={e => updateItem(index, "unit_cost", parseFloat(e.target.value) || 0)}
                        className="h-9"
                      />
                    </div>
                    {/* Total + Delete - 2 cols */}
                    <div className="col-span-2 flex items-center justify-between gap-1">
                      <span className="text-sm font-medium whitespace-nowrap">
                        ₹{(item.quantity * item.unit_cost).toLocaleString()}
                      </span>
                      <Button 
                        type="button" 
                        size="icon" 
                        variant="ghost" 
                        className="h-8 w-8 shrink-0"
                        onClick={() => removeItem(index)}
                        disabled={items.length === 1}
                      >
                        <Trash2 className="h-4 w-4 text-destructive" />
                      </Button>
                    </div>
                  </div>
                ))}
              </div>
            </div>

            {/* Bill Details */}
            <div className="grid grid-cols-3 gap-4">
              <div>
                <Label>Bill Amount *</Label>
                <Input 
                  type="number" 
                  step="0.01" 
                  value={billAmount} 
                  onChange={e => setBillAmount(e.target.value)} 
                  required 
                  className="mt-1" 
                  placeholder="0.00"
                />
              </div>
              <div>
                <Label>Tax Amount</Label>
                <Input 
                  type="number" 
                  step="0.01" 
                  value={taxAmount} 
                  onChange={e => setTaxAmount(e.target.value)} 
                  className="mt-1" 
                  placeholder="0.00"
                />
              </div>
              <div>
                <Label>Discount Amount</Label>
                <Input 
                  type="number" 
                  step="0.01" 
                  value={discountAmount} 
                  onChange={e => setDiscountAmount(e.target.value)} 
                  className="mt-1" 
                  placeholder="0.00"
                />
              </div>
            </div>

            <div className="flex items-center justify-between p-4 bg-muted rounded-lg">
              <span className="font-semibold">Total Amount:</span>
              <span className="text-2xl font-bold">₹{totalAmount().toLocaleString()}</span>
            </div>

            <div>
              <Label>Notes</Label>
              <Textarea value={notes} onChange={e => setNotes(e.target.value)} className="mt-1" rows={3} />
            </div>

            <div className="flex gap-2 justify-end">
              <Button type="button" variant="outline" onClick={() => { setShowAdd(false); resetForm(); }} disabled={saving}>
                Cancel
              </Button>
              <Button type="submit" disabled={saving}>
                {saving && <Loader2 className="mr-2 h-4 w-4 animate-spin" />}
                Record Purchase
              </Button>
            </div>
          </form>
        </DialogContent>
      </Dialog>
    </div>
  );
};

export default Purchases;

import { PageHeader } from "@/components/shared/PageHeader";
import { DataTable } from "@/components/shared/DataTable";
import { StatusBadge } from "@/components/shared/StatusBadge";
import { Badge } from "@/components/ui/badge";
import { useQuery, useQueryClient, useMutation } from "@tanstack/react-query";
import { supabase } from "@/integrations/supabase/client";
import { useAuth } from "@/contexts/AuthContext";
import { Loader2, Plus, Pencil, Trash2, Package, Link2 } from "lucide-react";
import { TableSkeleton } from "@/components/shared/TableSkeleton";
import { useState, useMemo } from "react";
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogFooter } from "@/components/ui/dialog";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Textarea } from "@/components/ui/textarea";
import { Button } from "@/components/ui/button";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { toast } from "sonner";
import { logActivity } from "@/lib/activityLogger";

interface RawMaterial {
  id: string;
  display_id: string;
  name: string;
  description?: string;
  unit: string;
  category?: string;
  min_stock_level: number;
  current_stock: number;
  unit_cost: number;
  hsn_code?: string;
  is_active: boolean;
  created_at: string;
}

interface VendorLink {
  id: string;
  vendor_id: string;
  raw_material_id: string;
  unit_price: number;
  lead_time_days: number;
  is_preferred: boolean;
  vendors?: { id: string; name: string; display_id: string };
}

const UNITS = ["kg", "g", "L", "mL", "pcs", "box", "pack", "ton", "unit"];
const CATEGORIES = ["Chemicals", "Packaging", "Labels", "Caps & Closures", "Raw Ingredients", "Consumables", "Other"];

const RawMaterials = () => {
  const { user, role } = useAuth();
  const qc = useQueryClient();
  const [showAdd, setShowAdd] = useState(false);
  const [editingItem, setEditingItem] = useState<RawMaterial | null>(null);
  const [showLinkVendor, setShowLinkVendor] = useState(false);
  const [linkMaterialId, setLinkMaterialId] = useState<string>("");
  const [deletingId, setDeletingId] = useState<string | null>(null);

  // Form state
  const [name, setName] = useState("");
  const [description, setDescription] = useState("");
  const [unit, setUnit] = useState("kg");
  const [category, setCategory] = useState("");
  const [minStockLevel, setMinStockLevel] = useState("");
  const [unitCost, setUnitCost] = useState("");
  const [hsnCode, setHsnCode] = useState("");
  const [vendorId, setVendorId] = useState("");
  const [saving, setSaving] = useState(false);

  // Vendor link form
  const [linkVendorId, setLinkVendorId] = useState("");
  const [linkUnitPrice, setLinkUnitPrice] = useState("");
  const [linkLeadTime, setLinkLeadTime] = useState("7");
  const [linkIsPreferred, setLinkIsPreferred] = useState(false);

  const { data: materials = [], isLoading } = useQuery({
    queryKey: ["raw-materials"],
    queryFn: async () => {
      const { data, error } = await supabase
        .from("raw_materials")
        .select("*, vendors(name, display_id)")
        .order("name");
      if (error) throw error;
      return data as RawMaterial[];
    },
  });

  const { data: vendors = [] } = useQuery({
    queryKey: ["vendors-list"],
    queryFn: async () => {
      const { data } = await supabase.from("vendors").select("id, name, display_id").eq("is_active", true);
      return data || [];
    },
  });

  const { data: vendorLinks = [] } = useQuery({
    queryKey: ["vendor-raw-materials", linkMaterialId],
    queryFn: async () => {
      if (!linkMaterialId) return [];
      const { data, error } = await supabase
        .from("vendor_raw_materials")
        .select("*, vendors(id, name, display_id)")
        .eq("raw_material_id", linkMaterialId);
      if (error) throw error;
      return data as VendorLink[];
    },
    enabled: !!linkMaterialId,
  });

  const resetForm = () => {
    setName("");
    setDescription("");
    setUnit("kg");
    setCategory("");
    setMinStockLevel("");
    setUnitCost("");
    setHsnCode("");
    setVendorId("");
    setEditingItem(null);
  };

  const resetLinkForm = () => {
    setLinkVendorId("");
    setLinkUnitPrice("");
    setLinkLeadTime("7");
    setLinkIsPreferred(false);
  };

  const handleSave = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!name.trim()) {
      toast.error("Name is required");
      return;
    }
    setSaving(true);

    try {
      if (editingItem) {
        const { error } = await supabase
          .from("raw_materials")
          .update({
            name: name.trim(),
            description: description.trim() || null,
            unit,
            category: category || null,
            vendor_id: vendorId || null,
            min_stock_level: minStockLevel ? parseFloat(minStockLevel) : 0,
            unit_cost: unitCost ? parseFloat(unitCost) : 0,
            hsn_code: hsnCode.trim() || null,
            updated_at: new Date().toISOString(),
          })
          .eq("id", editingItem.id);
        if (error) throw error;
        toast.success("Raw material updated");
        logActivity(user!.id, `Updated raw material: ${name}`, "inventory");
      } else {
        // Generate display ID
        const { data: idData } = await supabase.rpc("generate_display_id", {
          prefix: "RM",
          seq_name: "raw_materials_display_id_seq"
        });

        const { error } = await supabase.from("raw_materials").insert({
          display_id: idData,
          vendor_id: vendorId || null,
          name: name.trim(),
          description: description.trim() || null,
          unit,
          category: category || null,
          min_stock_level: minStockLevel ? parseFloat(minStockLevel) : 0,
          unit_cost: unitCost ? parseFloat(unitCost) : 0,
          hsn_code: hsnCode.trim() || null,
          created_by: user!.id,
        });
        if (error) throw error;
        toast.success("Raw material added");
        logActivity(user!.id, `Created raw material: ${name}`, "inventory");
      }

      qc.invalidateQueries({ queryKey: ["raw-materials"] });
      setShowAdd(false);
      resetForm();
    } catch (error: any) {
      toast.error(error.message || "Failed to save");
    } finally {
      setSaving(false);
    }
  };

  const handleEdit = (item: RawMaterial) => {
    setEditingItem(item);
    setName(item.name);
    setDescription(item.description || "");
    setUnit(item.unit);
    setCategory(item.category || "");
    setVendorId((item as any).vendor_id || "");
    setMinStockLevel(item.min_stock_level?.toString() || "");
    setUnitCost(item.unit_cost?.toString() || "");
    setHsnCode(item.hsn_code || "");
    setShowAdd(true);
  };

  const deleteMutation = useMutation({
    mutationFn: async (id: string) => {
      const { error } = await supabase.from("raw_materials").delete().eq("id", id);
      if (error) throw error;
    },
    onSuccess: () => {
      qc.invalidateQueries({ queryKey: ["raw-materials"] });
      toast.success("Raw material deleted");
      setDeletingId(null);
    },
    onError: (e: Error) => {
      toast.error(`Cannot delete: ${e.message}`);
      setDeletingId(null);
    },
  });

  const linkVendorMutation = useMutation({
    mutationFn: async (data: { vendor_id: string; raw_material_id: string; unit_price: number; lead_time_days: number; is_preferred: boolean }) => {
      // If setting as preferred, unset other preferred vendors for this material
      if (data.is_preferred) {
        await supabase
          .from("vendor_raw_materials")
          .update({ is_preferred: false })
          .eq("raw_material_id", data.raw_material_id);
      }
      const { error } = await supabase.from("vendor_raw_materials").insert(data);
      if (error) throw error;
    },
    onSuccess: () => {
      qc.invalidateQueries({ queryKey: ["vendor-raw-materials"] });
      toast.success("Vendor linked");
      resetLinkForm();
    },
    onError: (e: Error) => {
      toast.error(`Failed: ${e.message}`);
    },
  });

  const unlinkVendorMutation = useMutation({
    mutationFn: async (id: string) => {
      const { error } = await supabase.from("vendor_raw_materials").delete().eq("id", id);
      if (error) throw error;
    },
    onSuccess: () => {
      qc.invalidateQueries({ queryKey: ["vendor-raw-materials"] });
      toast.success("Vendor unlinked");
    },
  });

  const handleLinkVendor = () => {
    if (!linkVendorId || !linkMaterialId) {
      toast.error("Select a vendor");
      return;
    }
    linkVendorMutation.mutate({
      vendor_id: linkVendorId,
      raw_material_id: linkMaterialId,
      unit_price: linkUnitPrice ? parseFloat(linkUnitPrice) : 0,
      lead_time_days: parseInt(linkLeadTime) || 7,
      is_preferred: linkIsPreferred,
    });
  };

  const columns = [
    { header: "ID", accessor: "display_id" as const, className: "font-mono text-xs" },
    { header: "Name", accessor: "name" as const, className: "font-medium" },
    { header: "Vendor", accessor: (row: any) => row.vendors?.name || "—", className: "text-sm text-muted-foreground" },
    { header: "Category", accessor: (row: RawMaterial) => row.category || "—", className: "text-sm text-muted-foreground" },
    { header: "Unit", accessor: "unit" as const, className: "text-sm" },
    { header: "Stock", accessor: (row: RawMaterial) => `${row.current_stock} ${row.unit}`, className: "text-sm" },
    { header: "Unit Cost", accessor: (row: RawMaterial) => `₹${row.unit_cost?.toLocaleString() || 0}`, className: "text-sm" },
    {
      header: "Status",
      accessor: (row: RawMaterial) => (
        <StatusBadge 
          status={row.current_stock <= row.min_stock_level ? "inactive" : "active"} 
          label={row.current_stock <= row.min_stock_level ? "Low Stock" : "OK"} 
        />
      ),
    },
    {
      header: "Actions",
      accessor: (row: RawMaterial) => (
        <div className="flex gap-1">
          <Button variant="ghost" size="icon" className="h-8 w-8" onClick={() => { setLinkMaterialId(row.id); setShowLinkVendor(true); }}>
            <Link2 className="h-4 w-4" />
          </Button>
          <Button variant="ghost" size="icon" className="h-8 w-8" onClick={() => handleEdit(row)}>
            <Pencil className="h-4 w-4" />
          </Button>
          <Button variant="ghost" size="icon" className="h-8 w-8 text-destructive" onClick={() => setDeletingId(row.id)}>
            <Trash2 className="h-4 w-4" />
          </Button>
        </div>
      ),
    },
  ];

  if (isLoading) {
    return <TableSkeleton columns={8} />;
  }

  return (
    <div className="space-y-6 animate-fade-in">
      <PageHeader
        title="Raw Materials"
        subtitle="Manage inventory raw materials and link vendors"
        primaryAction={{ label: "Add Material", onClick: () => { resetForm(); setShowAdd(true); } }}
      />

      <DataTable
        columns={columns}
        data={materials}
        searchKey="name"
        searchPlaceholder="Search materials..."
        emptyMessage="No raw materials yet"
        renderMobileCard={(row: RawMaterial) => (
          <div className="entity-card-mobile flex-col !items-stretch">
            <div className="flex items-start justify-between gap-2">
              <div className="flex-1 min-w-0">
                <p className="entity-card-subtitle">{row.display_id}</p>
                <h3 className="font-semibold text-sm truncate">{row.name}</h3>
                <div className="flex items-center gap-1.5 flex-wrap mt-1">
                  <span className="text-[10px] px-1.5 py-0.5 rounded bg-muted text-muted-foreground">
                    {row.category || "Uncategorized"}
                  </span>
                  {row.vendors?.name && (
                    <span className="text-[10px] px-1.5 py-0.5 rounded bg-primary/10 text-primary">
                      {row.vendors.name}
                    </span>
                  )}
                </div>
              </div>
              <StatusBadge 
                status={row.current_stock <= row.min_stock_level ? "inactive" : "active"} 
                label={row.current_stock <= row.min_stock_level ? "Low" : "OK"} 
              />
            </div>
            
            {/* Stock and Cost Info */}
            <div className="flex items-center justify-between mt-2 pt-2 border-t">
              <div>
                <p className="entity-card-label">Stock</p>
                <p className="font-semibold text-sm">{row.current_stock} {row.unit}</p>
              </div>
              <div className="text-right">
                <p className="entity-card-label">Unit Cost</p>
                <p className="font-semibold text-sm">₹{row.unit_cost?.toLocaleString() || 0}</p>
              </div>
            </div>

            {/* Actions */}
            <div className="flex gap-2 mt-2 pt-2 border-t">
              <Button variant="outline" size="sm" className="flex-1 h-8 text-xs" onClick={() => { setLinkMaterialId(row.id); setShowLinkVendor(true); }}>
                <Link2 className="h-3.5 w-3.5 mr-1" />
                Link Vendor
              </Button>
              <Button variant="outline" size="icon" className="h-8 w-8" onClick={() => handleEdit(row)}>
                <Pencil className="h-3.5 w-3.5" />
              </Button>
              <Button variant="outline" size="icon" className="h-8 w-8 text-destructive" onClick={() => setDeletingId(row.id)}>
                <Trash2 className="h-3.5 w-3.5" />
              </Button>
            </div>
          </div>
        )}
      />

      {/* Add/Edit Dialog */}
      <Dialog open={showAdd} onOpenChange={(open) => { setShowAdd(open); if (!open) resetForm(); }}>
        <DialogContent className="max-w-2xl max-h-[90vh] overflow-y-auto">
          <DialogHeader>
            <DialogTitle>{editingItem ? "Edit Raw Material" : "Add Raw Material"}</DialogTitle>
          </DialogHeader>
          <form onSubmit={handleSave} className="space-y-4 py-2">
            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
              <div className="space-y-2">
                <Label>Name *</Label>
                <Input value={name} onChange={(e) => setName(e.target.value)} placeholder="e.g., Sodium Chloride" required />
              </div>
              <div className="space-y-2">
                <Label>Vendor</Label>
                <Select value={vendorId} onValueChange={setVendorId}>
                  <SelectTrigger>
                    <SelectValue placeholder="Select vendor (optional)" />
                  </SelectTrigger>
                  <SelectContent>
                    <SelectItem value="">No Vendor</SelectItem>
                    {vendors.map((v: any) => (
                      <SelectItem key={v.id} value={v.id}>
                        {v.name} ({v.display_id})
                      </SelectItem>
                    ))}
                  </SelectContent>
                </Select>
              </div>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
              <div className="space-y-2">
                <Label>Unit</Label>
                <Select value={unit} onValueChange={setUnit}>
                  <SelectTrigger>
                    <SelectValue />
                  </SelectTrigger>
                  <SelectContent>
                    {UNITS.map((u) => (
                      <SelectItem key={u} value={u}>{u}</SelectItem>
                    ))}
                  </SelectContent>
                </Select>
              </div>
              <div className="space-y-2">
                <Label>Category</Label>
                <Select value={category} onValueChange={setCategory}>
                  <SelectTrigger>
                    <SelectValue placeholder="Select" />
                  </SelectTrigger>
                  <SelectContent>
                    {CATEGORIES.map((c) => (
                      <SelectItem key={c} value={c}>{c}</SelectItem>
                    ))}
                  </SelectContent>
                </Select>
              </div>
            </div>
            <div className="grid grid-cols-2 gap-4">
              <div className="space-y-2">
                <Label>Unit Cost (₹)</Label>
                <Input type="number" step="0.01" min="0" value={unitCost} onChange={(e) => setUnitCost(e.target.value)} />
              </div>
              <div className="space-y-2">
                <Label>Min Stock Level</Label>
                <Input type="number" step="0.01" min="0" value={minStockLevel} onChange={(e) => setMinStockLevel(e.target.value)} />
              </div>
            </div>
            <div className="space-y-2">
              <Label>HSN Code</Label>
              <Input value={hsnCode} onChange={(e) => setHsnCode(e.target.value)} placeholder="e.g., 25010010" className="font-mono" />
            </div>
            <div className="space-y-2">
              <Label>Description</Label>
              <Textarea value={description} onChange={(e) => setDescription(e.target.value)} placeholder="Optional notes..." />
            </div>
            <DialogFooter>
              <Button type="button" variant="outline" onClick={() => setShowAdd(false)}>Cancel</Button>
              <Button type="submit" disabled={saving}>
                {saving && <Loader2 className="mr-2 h-4 w-4 animate-spin" />}
                {editingItem ? "Update" : "Add"}
              </Button>
            </DialogFooter>
          </form>
        </DialogContent>
      </Dialog>

      {/* Link Vendor Dialog */}
      <Dialog open={showLinkVendor} onOpenChange={(open) => { setShowLinkVendor(open); if (!open) { resetLinkForm(); setLinkMaterialId(""); } }}>
        <DialogContent className="max-w-lg">
          <DialogHeader>
            <DialogTitle>Manage Vendors</DialogTitle>
          </DialogHeader>
          
          {/* Existing Links */}
          {vendorLinks.length > 0 && (
            <div className="space-y-2 mb-4">
              <Label className="text-xs text-muted-foreground">Linked Vendors</Label>
              <div className="space-y-2">
                {vendorLinks.map((link) => (
                  <div key={link.id} className="flex items-center justify-between p-3 rounded-lg border bg-muted/30">
                    <div>
                      <p className="font-medium text-sm">{link.vendors?.name}</p>
                      <p className="text-xs text-muted-foreground">
                        ₹{link.unit_price?.toLocaleString()}/unit • {link.lead_time_days} days lead time
                      </p>
                    </div>
                    <div className="flex items-center gap-2">
                      {link.is_preferred && <Badge variant="secondary" className="text-[10px]">Preferred</Badge>}
                      <Button 
                        variant="ghost" 
                        size="icon" 
                        className="h-7 w-7 text-destructive" 
                        onClick={() => unlinkVendorMutation.mutate(link.id)}
                      >
                        <Trash2 className="h-3.5 w-3.5" />
                      </Button>
                    </div>
                  </div>
                ))}
              </div>
            </div>
          )}

          {/* Add New Link */}
          <div className="space-y-4 pt-4 border-t">
            <Label>Link New Vendor</Label>
            <div className="space-y-3">
              <Select value={linkVendorId} onValueChange={setLinkVendorId}>
                <SelectTrigger>
                  <SelectValue placeholder="Select vendor" />
                </SelectTrigger>
                <SelectContent>
                  {vendors
                    .filter((v: any) => !vendorLinks.some((l) => l.vendor_id === v.id))
                    .map((v: any) => (
                      <SelectItem key={v.id} value={v.id}>
                        {v.name} ({v.display_id})
                      </SelectItem>
                    ))}
                </SelectContent>
              </Select>
              <div className="grid grid-cols-2 gap-3">
                <Input 
                  type="number" 
                  step="0.01" 
                  min="0"
                  placeholder="Unit price (₹)" 
                  value={linkUnitPrice} 
                  onChange={(e) => setLinkUnitPrice(e.target.value)} 
                />
                <Input 
                  type="number" 
                  min="1"
                  placeholder="Lead time (days)" 
                  value={linkLeadTime} 
                  onChange={(e) => setLinkLeadTime(e.target.value)} 
                />
              </div>
              <label className="flex items-center gap-2 text-sm">
                <input 
                  type="checkbox" 
                  checked={linkIsPreferred} 
                  onChange={(e) => setLinkIsPreferred(e.target.checked)} 
                  className="rounded border-gray-300"
                />
                Set as preferred vendor
              </label>
            </div>
            <Button 
              onClick={handleLinkVendor} 
              disabled={!linkVendorId || linkVendorMutation.isPending}
              className="w-full"
            >
              {linkVendorMutation.isPending && <Loader2 className="mr-2 h-4 w-4 animate-spin" />}
              Link Vendor
            </Button>
          </div>
        </DialogContent>
      </Dialog>

      {/* Delete Confirmation */}
      <Dialog open={!!deletingId} onOpenChange={() => setDeletingId(null)}>
        <DialogContent className="max-w-sm">
          <DialogHeader>
            <DialogTitle>Delete Raw Material?</DialogTitle>
          </DialogHeader>
          <p className="text-sm text-muted-foreground">This cannot be undone. Linked vendors will also be removed.</p>
          <DialogFooter>
            <Button variant="outline" onClick={() => setDeletingId(null)}>Cancel</Button>
            <Button variant="destructive" onClick={() => deletingId && deleteMutation.mutate(deletingId)} disabled={deleteMutation.isPending}>
              {deleteMutation.isPending && <Loader2 className="mr-2 h-4 w-4 animate-spin" />}
              Delete
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>
    </div>
  );
};

export default RawMaterials;

import { useParams, useNavigate } from "react-router-dom";
import { useQuery, useQueryClient } from "@tanstack/react-query";
import { supabase } from "@/integrations/supabase/client";
import { getCurrentPosition } from "@/lib/proximity";
import { useAuth } from "@/contexts/AuthContext";
import { useState, useMemo } from "react";
import { toast } from "sonner";
import { Card, CardContent, CardHeader } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Separator } from "@/components/ui/separator";
import {
  Dialog, DialogContent, DialogHeader, DialogTitle, DialogFooter,
} from "@/components/ui/dialog";
import {
  ArrowLeft, MapPin, Store as StoreIcon, Navigation, LocateFixed,
  Loader2, Route as RouteIcon, RefreshCw, Building2, AlertTriangle,
  ChevronRight, DollarSign, CheckCircle2,
} from "lucide-react";
import { nearestNeighborOrder, getDistanceMeters as haversineDistance } from "@/lib/proximity";

// Local types compensate for migration columns not yet in generated types
type RouteRow = {
  id: string;
  name: string;
  is_active: boolean;
  store_type_id: string;
  created_at: string;
  factory_lat: number | null;
  factory_lng: number | null;
  store_types: { name: string } | null;
};

type StoreRow = {
  id: string;
  display_id: string;
  name: string;
  address: string | null;
  lat: number | null;
  lng: number | null;
  outstanding: number | string;
  store_order: number | null;
  photo_url: string | null;
  customers: { name: string } | null;
};

export default function RouteDetail() {
  const { id } = useParams<{ id: string }>();
  const navigate = useNavigate();
  const { role } = useAuth();
  const qc = useQueryClient();
  const canEdit = role === "super_admin" || role === "manager";

  const [showSetFactory, setShowSetFactory] = useState(false);
  const [factoryLatInput, setFactoryLatInput] = useState("");
  const [factoryLngInput, setFactoryLngInput] = useState("");
  const [savingFactory, setSavingFactory] = useState(false);
  const [recomputing, setRecomputing] = useState(false);
  const [gettingGps, setGettingGps] = useState(false);

  // ── Company settings (fallback factory location) ──────────────────────────
  const { data: companySettings } = useQuery({
    queryKey: ["company-settings"],
    queryFn: async () => {
      const { data } = await supabase.from("company_settings").select("key, value");
      return Object.fromEntries((data || []).map((r: any) => [r.key, r.value]));
    },
  });
  const companyLat = companySettings?.company_lat ? parseFloat(companySettings.company_lat) : null;
  const companyLng = companySettings?.company_lng ? parseFloat(companySettings.company_lng) : null;
  const companyLocationAvailable = companyLat != null && !isNaN(companyLat) && companyLng != null && !isNaN(companyLng);

  // ── Data ──────────────────────────────────────────────────────────────────
  const { data: route, isLoading: routeLoading } = useQuery<RouteRow | null>({
    queryKey: ["route-detail", id],
    queryFn: async () => {
      const { data, error } = await (supabase as any)
        .from("routes")
        .select("*, store_types(name)")
        .eq("id", id!)
        .single();
      if (error) throw error;
      return data as RouteRow;
    },
    enabled: !!id,
  });

  const { data: stores, isLoading: storesLoading } = useQuery<StoreRow[]>({
    queryKey: ["route-stores", id],
    queryFn: async () => {
      const { data, error } = await (supabase as any)
        .from("stores")
        .select("id, display_id, name, address, lat, lng, outstanding, store_order, photo_url, customers(name)")
        .eq("route_id", id!)
        .order("store_order", { ascending: true, nullsFirst: false });
      if (error) throw error;
      return (data || []) as StoreRow[];
    },
    enabled: !!id,
  });

  // Today's visited store IDs (across any route session for this route)
  const todayStart = new Date().toISOString().split("T")[0] + "T00:00:00";
  const { data: visitedStoreIds } = useQuery<Set<string>>({
    queryKey: ["route-visits-today", id],
    queryFn: async () => {
      const { data } = await (supabase as any)
        .from("store_visits")
        .select("store_id, route_sessions!inner(route_id)")
        .eq("route_sessions.route_id", id!)
        .gte("visited_at", todayStart);
      return new Set((data || []).map((v: any) => v.store_id));
    },
    enabled: !!id,
  });

  // ── Derived stats ─────────────────────────────────────────────────────────
  const totalOutstanding = useMemo(
    () => (stores || []).reduce((s, st) => s + Number(st.outstanding || 0), 0),
    [stores]
  );
  const storesWithCoords = useMemo(
    () => (stores || []).filter((s) => s.lat != null && s.lng != null).length,
    [stores]
  );

  // Pre-compute distances between consecutive stops for display
  const storesWithDist = useMemo(() => {
    if (!stores) return [];
    const hasFactory = route?.factory_lat != null && route?.factory_lng != null;
    return stores.map((store, idx) => {
      let distFromPrev: number | null = null;
      if (idx === 0 && hasFactory && store.lat && store.lng) {
        distFromPrev = haversineDistance(route.factory_lat!, route.factory_lng!, store.lat, store.lng);
      } else if (idx > 0) {
        const prev = stores[idx - 1];
        if (prev.lat && prev.lng && store.lat && store.lng) {
          distFromPrev = haversineDistance(prev.lat, prev.lng, store.lat, store.lng);
        }
      }
      return { ...store, distFromPrev };
    });
  }, [stores, route]);

  // Open factory dialog — pre-fill from existing route value or fall back to company coords
  const openFactoryDialog = () => {
    if (route?.factory_lat) {
      setFactoryLatInput(String(route.factory_lat));
      setFactoryLngInput(String(route.factory_lng));
    } else if (companyLocationAvailable) {
      setFactoryLatInput(String(companyLat));
      setFactoryLngInput(String(companyLng));
    } else {
      setFactoryLatInput("");
      setFactoryLngInput("");
    }
    setShowSetFactory(true);
  };

  const handleUseCompanyLocation = () => {
    if (!companyLocationAvailable) return;
    setFactoryLatInput(String(companyLat));
    setFactoryLngInput(String(companyLng));
  };

  // ── Actions ───────────────────────────────────────────────────────────────
  const handleUseGps = async () => {
    setGettingGps(true);
    const pos = await getCurrentPosition();
    if (pos) {
      setFactoryLatInput(String(pos.lat));
      setFactoryLngInput(String(pos.lng));
    } else {
      toast.error("Could not get GPS location");
    }
    setGettingGps(false);
  };

  const handleSaveFactory = async (e: React.FormEvent) => {
    e.preventDefault();
    const lat = parseFloat(factoryLatInput);
    const lng = parseFloat(factoryLngInput);
    if (isNaN(lat) || isNaN(lng)) { toast.error("Enter valid coordinates"); return; }
    if (lat < -90 || lat > 90) { toast.error("Latitude must be between -90 and 90"); return; }
    if (lng < -180 || lng > 180) { toast.error("Longitude must be between -180 and 180"); return; }
    setSavingFactory(true);
    const { error } = await (supabase as any).from("routes").update({ factory_lat: lat, factory_lng: lng }).eq("id", id!);
    setSavingFactory(false);
    if (error) { toast.error(error.message); return; }
    toast.success("Factory location saved");
    setShowSetFactory(false);
    qc.invalidateQueries({ queryKey: ["route-detail", id] });
    qc.invalidateQueries({ queryKey: ["routes-with-stores"] });
  };

  const handleRecomputeOrder = async () => {
    if (!route?.factory_lat || !route?.factory_lng) {
      toast.error("Set a factory/depot location first");
      setShowSetFactory(true);
      return;
    }
    if (!stores || stores.length === 0) {
      toast.error("No stores on this route");
      return;
    }
    setRecomputing(true);
    const ordered = nearestNeighborOrder(
      { lat: route.factory_lat, lng: route.factory_lng },
      stores
    );
    // Persist store_order for each store
    const updates = ordered.map((store, idx) =>
      (supabase as any).from("stores").update({ store_order: idx + 1 }).eq("id", store.id)
    );
    const results = await Promise.all(updates);
    const firstError = results.find((r) => r.error);
    setRecomputing(false);
    if (firstError?.error) {
      toast.error("Failed to save order: " + firstError.error.message);
    } else {
      toast.success(`Optimal order computed for ${ordered.length} stores`);
      qc.invalidateQueries({ queryKey: ["route-stores", id] });
      qc.invalidateQueries({ queryKey: ["routes-with-stores"] });
    }
  };

  // ── Loading / error states ────────────────────────────────────────────────
  if (routeLoading || storesLoading) {
    return (
      <div className="flex items-center justify-center py-24">
        <Loader2 className="h-8 w-8 animate-spin text-primary" />
      </div>
    );
  }

  if (!route) {
    return (
      <div className="space-y-4">
        <Button variant="ghost" size="sm" onClick={() => navigate("/routes")} className="gap-1.5 -ml-2 text-muted-foreground">
          <ArrowLeft className="h-4 w-4" /> Routes
        </Button>
        <p className="text-muted-foreground">Route not found.</p>
      </div>
    );
  }

  const factorySet = route.factory_lat != null && route.factory_lng != null;

  return (
    <div className="space-y-6 animate-fade-in">
      {/* Back */}
      <Button variant="ghost" size="sm" onClick={() => navigate("/routes")} className="gap-1.5 text-muted-foreground hover:text-foreground -ml-2">
        <ArrowLeft className="h-4 w-4" /> Routes
      </Button>

      {/* Header card */}
      <Card className="overflow-hidden">
        <div className="h-20 sm:h-28 bg-gradient-to-br from-primary/20 via-accent/30 to-primary/10" />
        <CardContent className="relative px-4 sm:px-6 pb-5 -mt-8">
          <div className="flex items-end gap-4">
            <div className="h-16 w-16 sm:h-20 sm:w-20 rounded-xl border-4 border-card bg-primary/10 flex items-center justify-center shadow-md shrink-0">
              <RouteIcon className="h-8 w-8 text-primary" />
            </div>
            <div className="flex-1 min-w-0 pb-1">
              <div className="flex flex-wrap items-center gap-2">
                <h1 className="text-xl sm:text-2xl font-bold text-foreground">{route.name}</h1>
                <Badge variant={route.is_active ? "default" : "secondary"}>
                  {route.is_active ? "Active" : "Inactive"}
                </Badge>
              </div>
              {(route as any).store_types?.name && (
                <Badge variant="outline" className="mt-1 text-xs">{(route as any).store_types.name}</Badge>
              )}
            </div>
          </div>
        </CardContent>
      </Card>

      {/* Stats row */}
      <div className="grid grid-cols-2 sm:grid-cols-4 gap-3">
        <div className="rounded-xl border bg-card p-4 flex items-center gap-3">
          <div className="h-9 w-9 rounded-lg bg-primary/10 flex items-center justify-center shrink-0">
            <StoreIcon className="h-4 w-4 text-primary" />
          </div>
          <div>
            <p className="text-xs text-muted-foreground">Stores</p>
            <p className="text-lg font-bold">{stores?.length || 0}</p>
          </div>
        </div>
        <div className="rounded-xl border bg-card p-4 flex items-center gap-3">
          <div className="h-9 w-9 rounded-lg bg-warning/10 flex items-center justify-center shrink-0">
            <DollarSign className="h-4 w-4 text-warning" />
          </div>
          <div>
            <p className="text-xs text-muted-foreground">Outstanding</p>
            <p className="text-lg font-bold">₹{totalOutstanding.toLocaleString()}</p>
          </div>
        </div>
        <div className="rounded-xl border bg-card p-4 flex items-center gap-3">
          <div className="h-9 w-9 rounded-lg bg-info/10 flex items-center justify-center shrink-0">
            <MapPin className="h-4 w-4 text-info" />
          </div>
          <div>
            <p className="text-xs text-muted-foreground">With GPS</p>
            <p className="text-lg font-bold">{storesWithCoords}<span className="text-sm font-normal text-muted-foreground">/{stores?.length || 0}</span></p>
          </div>
        </div>
        <div
          className={`rounded-xl border bg-card p-4 flex items-center gap-3 ${canEdit ? "cursor-pointer hover:bg-accent/30 transition-colors" : ""}`}
          onClick={canEdit ? openFactoryDialog : undefined}
        >
          <div className={`h-9 w-9 rounded-lg flex items-center justify-center shrink-0 ${factorySet ? "bg-success/10" : "bg-muted"}`}>
            <Building2 className={`h-4 w-4 ${factorySet ? "text-success" : "text-muted-foreground"}`} />
          </div>
          <div className="min-w-0">
            <p className="text-xs text-muted-foreground">Factory / Depot</p>
            {factorySet ? (
              <p className="text-xs font-mono font-medium text-success truncate">
                {Number(route.factory_lat).toFixed(4)}, {Number(route.factory_lng).toFixed(4)}
              </p>
            ) : (
              <p className="text-sm font-medium text-muted-foreground">{canEdit ? "Tap to set" : "Not set"}</p>
            )}
          </div>
        </div>
      </div>

      {/* Warning when no factory set */}
      {!factorySet && (stores?.length || 0) > 0 && (
        <div className="flex flex-col sm:flex-row sm:items-center gap-3 rounded-xl border border-warning/30 bg-warning/5 p-4">
          <div className="flex items-start gap-3 flex-1">
            <AlertTriangle className="h-5 w-5 text-warning shrink-0 mt-0.5" />
            <div>
              <p className="text-sm font-medium">Factory / depot location not set</p>
              <p className="text-xs text-muted-foreground mt-0.5">
                {companyLocationAvailable
                  ? "Click below to use the company location from Settings, or set a custom one."
                  : "Set the factory/depot starting point to compute the optimal navigation order."}
              </p>
            </div>
          </div>
          {canEdit && (
            <div className="flex gap-2 flex-wrap">
              {companyLocationAvailable && (
                <Button variant="default" size="sm" onClick={() => { handleUseCompanyLocation(); setSavingFactory(false); openFactoryDialog(); }} className="gap-1.5">
                  <Building2 className="h-3.5 w-3.5" /> Use Company Location
                </Button>
              )}
              <Button variant="outline" size="sm" onClick={openFactoryDialog} className="gap-1.5">
                <MapPin className="h-3.5 w-3.5" /> Set Custom
              </Button>
            </div>
          )}
        </div>
      )}

      {/* Action bar */}
      {canEdit && (
        <div className="flex flex-wrap gap-2">
          <Button variant="outline" size="sm" onClick={openFactoryDialog} className="gap-1.5">
            <Building2 className="h-3.5 w-3.5" /> {factorySet ? "Update Factory" : "Set Factory Location"}
          </Button>
          <Button
            size="sm"
            onClick={handleRecomputeOrder}
            disabled={recomputing || !stores || stores.length === 0}
            className="gap-1.5"
          >
            {recomputing ? <Loader2 className="h-3.5 w-3.5 animate-spin" /> : <RefreshCw className="h-3.5 w-3.5" />}
            Recompute Optimal Order
          </Button>
        </div>
      )}

      {/* Store list */}
      <Card>
        <CardHeader className="pb-3 px-4 sm:px-6">
          <div className="flex flex-col sm:flex-row sm:items-center sm:justify-between gap-1">
            <h2 className="font-semibold text-base">Stores on Route</h2>
            <span className="text-xs text-muted-foreground">{stores?.length || 0} stores · sorted by navigation order</span>
          </div>
        </CardHeader>
        <CardContent className="px-3 sm:px-6 pb-5">
          {storesLoading ? (
            <div className="flex items-center justify-center py-10 gap-3 text-muted-foreground">
              <Loader2 className="h-5 w-5 animate-spin" />
              <span className="text-sm">Loading stores…</span>
            </div>
          ) : !stores || stores.length === 0 ? (
            <div className="rounded-lg border bg-muted/30 p-10 text-center text-muted-foreground">
              <StoreIcon className="h-8 w-8 mx-auto mb-2 opacity-30" />
              <p className="text-sm">No stores assigned to this route yet.</p>
              <p className="text-xs mt-1">Assign stores via the Stores page.</p>
            </div>
          ) : (
            <div className="space-y-2">
              {/* Factory origin row */}
              <div className={`flex items-center gap-3 rounded-lg border p-3 ${factorySet ? "border-primary/30 bg-primary/5" : "border-dashed opacity-50"}`}>
                <div className="h-7 w-7 rounded-full bg-primary/20 flex items-center justify-center text-xs font-bold text-primary shrink-0">
                  ⌂
                </div>
                <div className="flex-1 min-w-0">
                  <p className="text-sm font-semibold">Factory / Depot</p>
                  <p className="text-xs text-muted-foreground">
                    {factorySet
                      ? `${Number(route.factory_lat).toFixed(5)}, ${Number(route.factory_lng).toFixed(5)}`
                      : "Not set — click 'Set Factory Location'"}
                  </p>
                </div>
              </div>

              {/* Stores */}
              {storesWithDist.map((store, idx) => {
                const hasCoords = store.lat != null && store.lng != null;
                const visitedToday = visitedStoreIds?.has(store.id) ?? false;
                return (
                  <div
                    key={store.id}
                    className="flex items-center gap-2 sm:gap-3 rounded-lg border bg-card p-2.5 sm:p-3 hover:bg-accent/30 transition-colors cursor-pointer group"
                    onClick={() => navigate(`/stores/${store.id}`)}
                  >
                    {/* Order badge */}
                    <div className={`h-7 w-7 rounded-full flex items-center justify-center text-xs font-bold shrink-0 ${store.store_order ? "bg-primary text-primary-foreground" : "bg-muted text-muted-foreground"}`}>
                      {store.store_order ?? "?"}
                    </div>

                    {/* Photo — hidden on very small screens */}
                    <div className="hidden xs:flex h-10 w-10 rounded-lg bg-muted overflow-hidden shrink-0 items-center justify-center sm:flex">
                      {store.photo_url ? (
                        <img src={store.photo_url} alt={store.name} loading="lazy" className="w-full h-full object-cover" />
                      ) : (
                        <StoreIcon className="h-5 w-5 text-muted-foreground/40" />
                      )}
                    </div>

                    {/* Info */}
                    <div className="flex-1 min-w-0">
                      <div className="flex items-center gap-1.5 flex-wrap">
                        <p className="text-sm font-semibold truncate">{store.name}</p>
                        <span className="hidden sm:inline text-[10px] font-mono text-muted-foreground shrink-0">{store.display_id}</span>
                        {visitedToday && (
                          <span className="inline-flex items-center gap-0.5 text-[10px] font-semibold px-1.5 py-0.5 rounded-full bg-success/10 text-success shrink-0">
                            <CheckCircle2 className="h-3 w-3" /> Visited
                          </span>
                        )}
                      </div>
                      <p className="text-xs text-muted-foreground truncate">
                        {store.address || "No address"}
                        {!hasCoords && <span className="ml-1 text-warning">· No GPS</span>}
                      </p>
                      {store.distFromPrev != null && (
                        <p className="text-[10px] text-muted-foreground">
                          {idx === 0 ? "From depot: " : "From prev: "}
                          {store.distFromPrev < 1000
                            ? `${Math.round(store.distFromPrev)} m`
                            : `${(store.distFromPrev / 1000).toFixed(1)} km`}
                        </p>
                      )}
                    </div>

                    {/* Outstanding — hidden on mobile */}
                    <div className="hidden sm:block text-right shrink-0">
                      <p className="text-sm font-bold">₹{Number(store.outstanding).toLocaleString()}</p>
                      <p className="text-[10px] text-muted-foreground">outstanding</p>
                    </div>

                    {/* Nav button */}
                    {hasCoords && (
                      <Button
                        variant="ghost"
                        size="icon"
                        className="h-8 w-8 shrink-0 text-muted-foreground hover:text-primary"
                        onClick={(e) => {
                          e.stopPropagation();
                          window.open(`https://www.google.com/maps/dir/?api=1&destination=${store.lat},${store.lng}`, "_blank");
                        }}
                        title="Get directions"
                      >
                        <Navigation className="h-4 w-4" />
                      </Button>
                    )}

                    <ChevronRight className="h-4 w-4 text-muted-foreground/40 shrink-0 group-hover:text-muted-foreground transition-colors" />
                  </div>
                );
              })}
            </div>
          )}
        </CardContent>
      </Card>

      {/* Set Factory Dialog */}
      <Dialog open={showSetFactory} onOpenChange={setShowSetFactory}>
        <DialogContent>
          <DialogHeader>
            <DialogTitle>Set Factory / Depot Location</DialogTitle>
          </DialogHeader>
          <p className="text-sm text-muted-foreground">
            The factory/depot is the starting point for computing the optimal navigation order
            of stores on this route.
          </p>
          <form onSubmit={handleSaveFactory} className="space-y-4 mt-2">
            <div className={`grid gap-2 ${companyLocationAvailable ? "grid-cols-2" : "grid-cols-1"}`}>
              {companyLocationAvailable && (
                <Button
                  type="button"
                  variant="default"
                  className="w-full gap-2"
                  onClick={handleUseCompanyLocation}
                >
                  <Building2 className="h-4 w-4" /> Company Location
                </Button>
              )}
              <Button
                type="button"
                variant="outline"
                className="w-full gap-2"
                onClick={handleUseGps}
                disabled={gettingGps}
              >
                {gettingGps ? <Loader2 className="h-4 w-4 animate-spin" /> : <LocateFixed className="h-4 w-4" />}
                My GPS
              </Button>
            </div>

            <div className="grid grid-cols-2 gap-3">
              <div className="space-y-1.5">
                <Label className="text-xs">Latitude</Label>
                <Input
                  placeholder="e.g. 15.8281"
                  value={factoryLatInput}
                  onChange={(e) => setFactoryLatInput(e.target.value)}
                  required
                />
              </div>
              <div className="space-y-1.5">
                <Label className="text-xs">Longitude</Label>
                <Input
                  placeholder="e.g. 80.4417"
                  value={factoryLngInput}
                  onChange={(e) => setFactoryLngInput(e.target.value)}
                  required
                />
              </div>
            </div>

            <DialogFooter>
              <Button type="button" variant="ghost" onClick={() => setShowSetFactory(false)}>Cancel</Button>
              <Button type="submit" disabled={savingFactory} className="gap-1.5">
                {savingFactory && <Loader2 className="h-3.5 w-3.5 animate-spin" />}
                Save Location
              </Button>
            </DialogFooter>
          </form>
        </DialogContent>
      </Dialog>
    </div>
  );
}

import { PageHeader } from "@/components/shared/PageHeader";
import { Tabs, TabsContent, TabsList, TabsTrigger } from "@/components/ui/tabs";
import { MapPin, Store, Loader2, ChevronRight, Unlock } from "lucide-react";
import { RouteSessionPanel } from "@/components/routes/RouteSessionPanel";
import { RouteAccessMatrix } from "@/components/routes/RouteAccessMatrix";
import { useQuery, useQueryClient } from "@tanstack/react-query";
import { useAuth } from "@/contexts/AuthContext";
import { supabase } from "@/integrations/supabase/client";
import { useState } from "react";
import { useNavigate } from "react-router-dom";
import {
  Dialog, DialogContent, DialogHeader, DialogTitle,
} from "@/components/ui/dialog";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Button } from "@/components/ui/button";
import {
  Select, SelectContent, SelectItem, SelectTrigger, SelectValue,
} from "@/components/ui/select";
import { toast } from "sonner";

const Routes = () => {
  const { role, user } = useAuth();
  const isAdmin = role === "super_admin" || role === "manager";
  const isScopedStaff = role === "agent" || role === "marketer" || role === "pos";
  const navigate = useNavigate();
  const [showAdd, setShowAdd] = useState(false);
  const [showAccessDialog, setShowAccessDialog] = useState(false);
  const [name, setName] = useState("");
  const [storeTypeId, setStoreTypeId] = useState("");
  const [saving, setSaving] = useState(false);
  const qc = useQueryClient();

  const { data: storeTypes, isLoading: typesLoading } = useQuery({
    queryKey: ["store-types"],
    queryFn: async () => {
      const { data } = await supabase.from("store_types").select("*").eq("is_active", true);
      return data || [];
    },
  });

  const { data: routes, isLoading: routesLoading } = useQuery({
    queryKey: ["routes-with-stores", role, user?.id],
    queryFn: async () => {
      const { data, error } = await supabase
        .from("routes")
        .select("*, store_types(name), stores(id, outstanding)")
        .eq("is_active", true);
      if (error) throw error;

      const allRoutes = data || [];
      if (!isScopedStaff || !user?.id) return allRoutes;

      const { data: accessRows, error: accessError } = await supabase
        .from("agent_routes")
        .select("route_id, enabled")
        .eq("user_id", user.id);
      if (accessError) throw accessError;

      if (!accessRows || accessRows.length === 0) {
        return allRoutes;
      }

      const enabledRouteIds = new Set(
        accessRows.filter((row: any) => row.enabled).map((row: any) => row.route_id)
      );
      return allRoutes.filter((route: any) => enabledRouteIds.has(route.id));
    },
    enabled: !!role && !!user,
  });

  const handleAdd = async (e: React.FormEvent) => {
    e.preventDefault();
    setSaving(true);
    const { error } = await supabase.from("routes").insert({ name, store_type_id: storeTypeId });
    setSaving(false);
    if (error) {
      toast.error(error.message);
    } else {
      toast.success("Route created");
      setShowAdd(false);
      setName(""); setStoreTypeId("");
      qc.invalidateQueries({ queryKey: ["routes-with-stores"] });
    }
  };

  if (typesLoading || routesLoading) {
    return <div className="flex items-center justify-center py-20"><Loader2 className="h-8 w-8 animate-spin text-primary" /></div>;
  }

  const defaultTab = storeTypes?.[0]?.id || "";

  return (
    <div className="space-y-6 animate-fade-in">
      <PageHeader
        title="Routes"
        subtitle="Manage delivery routes by store type"
        actions={
          isAdmin
            ? [
                {
                  label: "Route Access",
                  icon: Unlock,
                  onClick: () => setShowAccessDialog(true),
                  variant: "outline",
                  priority: 2, // Lower priority than primary action
                },
              ]
            : undefined
        }
        primaryAction={isAdmin ? { label: "Create Route", onClick: () => setShowAdd(true) } : undefined}
      />

      {role === "agent" && <RouteSessionPanel />}

      {storeTypes && storeTypes.length > 0 ? (
        <Tabs defaultValue={defaultTab} className="w-full">
          <div className="w-full overflow-x-auto pb-2 scrollbar-none">
            <TabsList className="bg-muted/50 p-1 h-11">
              {storeTypes.map((type) => (
                <TabsTrigger key={type.id} value={type.id}>{type.name}</TabsTrigger>
              ))}
            </TabsList>
          </div>

          {storeTypes.map((type) => {
            const typeRoutes = routes?.filter(r => r.store_type_id === type.id) || [];
            return (
              <TabsContent key={type.id} value={type.id} className="space-y-4 mt-4">
                {typeRoutes.length === 0 ? (
                  <div className="rounded-2xl border border-dashed bg-card/50 p-12 text-center flex flex-col items-center justify-center animate-in fade-in zoom-in-95 duration-300">
                    <div className="h-12 w-12 rounded-full bg-muted/50 flex items-center justify-center mb-3">
                      <MapPin className="h-6 w-6 text-muted-foreground/40" />
                    </div>
                    <p className="text-sm text-muted-foreground font-medium">No routes for {type.name}</p>
                    {isAdmin && <p className="text-xs text-muted-foreground/60 mt-1">Create a new route to get started.</p>}
                  </div>
                ) : (
                  typeRoutes.map((route) => {
                    const storeCount = route.stores?.length || 0;
                    const totalOutstanding = route.stores?.reduce((sum: number, s: any) => sum + Number(s.outstanding || 0), 0) || 0;
                    return (
                      <div
                        key={route.id}
                        className="flex items-center justify-between rounded-xl border bg-card p-5 hover:shadow-md hover:bg-accent/20 transition-all cursor-pointer group"
                        onClick={() => navigate(`/routes/${route.id}`)}
                      >
                        <div className="flex items-center gap-4">
                          <div className="flex h-11 w-11 items-center justify-center rounded-lg bg-primary/10">
                            <MapPin className="h-5 w-5 text-primary" />
                          </div>
                          <div>
                            <h3 className="font-semibold">{route.name}</h3>
                            <div className="flex items-center gap-3 mt-1 text-sm text-muted-foreground">
                              <span className="flex items-center gap-1"><Store className="h-3.5 w-3.5" />{storeCount} stores</span>
                              <span>Outstanding: <span className="font-medium text-foreground">₹{totalOutstanding.toLocaleString()}</span></span>
                            </div>
                          </div>
                        </div>
                        <ChevronRight className="h-5 w-5 text-muted-foreground/40 group-hover:text-muted-foreground transition-colors shrink-0" />
                      </div>
                    );
                  })
                )}
              </TabsContent>
            );
          })}
        </Tabs>
      ) : (
        <div className="rounded-xl border bg-card p-10 text-center text-muted-foreground">
          No store types configured. Add them in Settings first.
        </div>
      )}

      <Dialog open={showAdd} onOpenChange={setShowAdd}>
        <DialogContent>
          <DialogHeader><DialogTitle>Create Route</DialogTitle></DialogHeader>
          <form onSubmit={handleAdd} className="space-y-4">
            <div><Label>Route Name</Label><Input value={name} onChange={e => setName(e.target.value)} required className="mt-1" /></div>
            <div>
              <Label>Store Type</Label>
              <Select value={storeTypeId} onValueChange={setStoreTypeId} required>
                <SelectTrigger className="mt-1"><SelectValue placeholder="Select store type" /></SelectTrigger>
                <SelectContent>
                  {storeTypes?.map(t => <SelectItem key={t.id} value={t.id}>{t.name}</SelectItem>)}
                </SelectContent>
              </Select>
            </div>
            <Button type="submit" className="w-full" disabled={saving}>
              {saving ? <Loader2 className="mr-2 h-4 w-4 animate-spin" /> : null}
              Create Route
            </Button>
          </form>
        </DialogContent>
      </Dialog>

      <Dialog open={showAccessDialog} onOpenChange={setShowAccessDialog}>
        <DialogContent className="max-w-4xl max-h-[80vh] overflow-hidden flex flex-col">
          <DialogHeader>
            <DialogTitle>Route Access Matrix</DialogTitle>
          </DialogHeader>
          <div className="flex-1 overflow-y-auto min-h-0">
            <RouteAccessMatrix />
          </div>
        </DialogContent>
      </Dialog>
    </div>
  );
};

export default Routes;

import { useState, useEffect } from "react";
import { PageHeader } from "@/components/shared/PageHeader";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Textarea } from "@/components/ui/textarea";
import { Badge } from "@/components/ui/badge";
import { useQuery, useQueryClient } from "@tanstack/react-query";
import { supabase } from "@/integrations/supabase/client";
import { useAuth } from "@/contexts/AuthContext";
import { Loader2, Plus, RotateCcw, Search, Package, CheckCircle, XCircle, Clock, Eye } from "lucide-react";
import { toast } from "sonner";
import { format } from "date-fns";
import {
  Dialog, DialogContent, DialogHeader, DialogTitle, DialogDescription, DialogFooter,
} from "@/components/ui/dialog";
import {
  Select, SelectContent, SelectItem, SelectTrigger, SelectValue,
} from "@/components/ui/select";
import { DataTable } from "@/components/shared/DataTable";
import { ResponsiveDataView } from "@/components/shared/ResponsiveDataView";
import { useIsMobile } from "@/hooks/use-mobile";

const SaleReturns = () => {
  const { user, role } = useAuth();
  const qc = useQueryClient();
  const isMobile = useIsMobile();
  const canApprove = ["super_admin", "manager"].includes(role || "");

  const [showCreate, setShowCreate] = useState(false);
  const [showDetail, setShowDetail] = useState<string | null>(null);
  const [search, setSearch] = useState("");
  const [statusFilter, setStatusFilter] = useState<string>("all");

  // Form state
  const [saleId, setSaleId] = useState("");
  const [reason, setReason] = useState("");
  const [notes, setNotes] = useState("");
  const [returnItems, setReturnItems] = useState<Array<{ sale_item_id: string; quantity: number; max_qty: number; product_name: string; unit_price: number }>>([]);
  const [saving, setSaving] = useState(false);

  // Fetch returns
  const { data: returns = [], isLoading } = useQuery({
    queryKey: ["sale-returns"],
    queryFn: async () => {
      const { data, error } = await supabase
        .from("sale_returns")
        .select(`
          *,
          sales(display_id, total_amount),
          stores(name, customers(name)),
          profiles:created_by(full_name),
          approver:approved_by(full_name)
        `)
        .order("created_at", { ascending: false });
      if (error) throw error;
      return data || [];
    },
  });

  // Fetch sales for dropdown
  const { data: sales = [] } = useQuery({
    queryKey: ["sales-for-return"],
    queryFn: async () => {
      const { data } = await supabase
        .from("sales")
        .select("id, display_id, created_at, total_amount, store_id, customer_id, stores(name, customers(name))")
        .order("created_at", { ascending: false })
        .limit(100);
      return data || [];
    },
  });

  // Fetch sale items when sale is selected
  const { data: saleItems = [] } = useQuery({
    queryKey: ["sale-items-for-return", saleId],
    queryFn: async () => {
      if (!saleId) return [];
      const { data } = await supabase
        .from("sale_items")
        .select("id, product_id, quantity, unit_price, total, products(name)")
        .eq("sale_id", saleId);
      return data || [];
    },
    enabled: !!saleId,
  });

  // Fetch return detail
  const { data: returnDetail } = useQuery({
    queryKey: ["sale-return-detail", showDetail],
    queryFn: async () => {
      if (!showDetail) return null;
      const { data: ret } = await supabase
        .from("sale_returns")
        .select(`
          *,
          sales(display_id, total_amount, created_at),
          stores(name, customers(name)),
          profiles:created_by(full_name),
          approver:approved_by(full_name)
        `)
        .eq("id", showDetail)
        .single();
      
      const { data: items } = await supabase
        .from("sale_return_items")
        .select("*, products(name)")
        .eq("return_id", showDetail);
      
      return { ...ret, items: items || [] };
    },
    enabled: !!showDetail,
  });

  const resetForm = () => {
    setSaleId("");
    setReason("");
    setNotes("");
    setReturnItems([]);
  };

  const handleSaleSelect = (id: string) => {
    setSaleId(id);
    // Initialize return items from sale items
    const items = saleItems.map((si: any) => ({
      sale_item_id: si.id,
      quantity: 0,
      max_qty: si.quantity,
      product_name: si.products?.name || "Product",
      unit_price: si.unit_price,
    }));
    setReturnItems(items);
  };

  // Update return items when sale items load
  const updateReturnItemsFromSale = () => {
    if (saleItems.length > 0 && returnItems.length === 0) {
      const items = saleItems.map((si: any) => ({
        sale_item_id: si.id,
        quantity: 0,
        max_qty: Number(si.quantity),
        product_name: si.products?.name || "Product",
        unit_price: Number(si.unit_price),
      }));
      setReturnItems(items);
    }
  };

  // Call when saleItems changes - wrapped in useEffect to avoid infinite renders
  useEffect(() => {
    if (saleId && saleItems.length > 0 && returnItems.length === 0) {
      updateReturnItemsFromSale();
    }
  }, [saleId, saleItems]);

  const updateItemQuantity = (idx: number, qty: number) => {
    setReturnItems((prev) => {
      const updated = [...prev];
      updated[idx].quantity = Math.min(Math.max(0, qty), updated[idx].max_qty);
      return updated;
    });
  };

  const calculateTotal = () => {
    return returnItems.reduce((sum, item) => sum + (item.quantity * item.unit_price), 0);
  };

  const handleCreate = async (e: React.FormEvent) => {
    e.preventDefault();
    
    const itemsToReturn = returnItems.filter((i) => i.quantity > 0);
    if (itemsToReturn.length === 0) {
      toast.error("Please select at least one item to return");
      return;
    }
    if (!reason.trim()) {
      toast.error("Please provide a reason for the return");
      return;
    }

    setSaving(true);
    try {
      // Get sale details
      const sale = sales.find((s: any) => s.id === saleId);
      
      // Generate display ID
      const { data: displayId } = await supabase.rpc("generate_sale_return_display_id");
      
      // Calculate total
      const totalAmount = calculateTotal();

      // Create return
      const { data: newReturn, error: returnError } = await supabase
        .from("sale_returns")
        .insert({
          display_id: displayId,
          sale_id: saleId,
          store_id: sale?.store_id,
          customer_id: sale?.customer_id,
          return_date: new Date().toISOString().split("T")[0],
          total_amount: totalAmount,
          reason,
          notes,
          status: "pending",
          created_by: user?.id,
        })
        .select("id")
        .single();

      if (returnError) throw returnError;

      // Create return items
      const returnItemsData = itemsToReturn.map((item) => ({
        return_id: newReturn.id,
        sale_item_id: item.sale_item_id,
        product_id: saleItems.find((si: any) => si.id === item.sale_item_id)?.product_id,
        quantity: item.quantity,
        unit_price: item.unit_price,
        total: item.quantity * item.unit_price,
      }));

      const { error: itemsError } = await supabase
        .from("sale_return_items")
        .insert(returnItemsData);

      if (itemsError) throw itemsError;

      toast.success("Sale return created successfully");
      setShowCreate(false);
      resetForm();
      qc.invalidateQueries({ queryKey: ["sale-returns"] });
    } catch (err: any) {
      toast.error(err.message || "Failed to create return");
    } finally {
      setSaving(false);
    }
  };

  const handleStatusUpdate = async (id: string, newStatus: "approved" | "rejected" | "completed") => {
    try {
      const updates: any = { status: newStatus };
      if (newStatus === "approved" || newStatus === "rejected") {
        updates.approved_by = user?.id;
        updates.approved_at = new Date().toISOString();
      }

      const { error } = await supabase
        .from("sale_returns")
        .update(updates)
        .eq("id", id);

      if (error) throw error;

      toast.success(`Return ${newStatus}`);
      qc.invalidateQueries({ queryKey: ["sale-returns"] });
      qc.invalidateQueries({ queryKey: ["sale-return-detail", id] });
    } catch (err: any) {
      toast.error(err.message);
    }
  };

  const getStatusBadge = (status: string) => {
    switch (status) {
      case "pending":
        return <Badge variant="secondary" className="bg-yellow-100 text-yellow-800"><Clock className="h-3 w-3 mr-1" />Pending</Badge>;
      case "approved":
        return <Badge variant="secondary" className="bg-blue-100 text-blue-800"><CheckCircle className="h-3 w-3 mr-1" />Approved</Badge>;
      case "completed":
        return <Badge variant="default" className="bg-green-100 text-green-800"><CheckCircle className="h-3 w-3 mr-1" />Completed</Badge>;
      case "rejected":
        return <Badge variant="destructive"><XCircle className="h-3 w-3 mr-1" />Rejected</Badge>;
      default:
        return <Badge variant="outline">{status}</Badge>;
    }
  };

  const filteredReturns = returns.filter((r: any) => {
    const matchesSearch = !search || 
      r.display_id?.toLowerCase().includes(search.toLowerCase()) ||
      r.sales?.display_id?.toLowerCase().includes(search.toLowerCase()) ||
      r.stores?.name?.toLowerCase().includes(search.toLowerCase()) ||
      r.stores?.customers?.name?.toLowerCase().includes(search.toLowerCase());
    const matchesStatus = statusFilter === "all" || r.status === statusFilter;
    return matchesSearch && matchesStatus;
  });

  const columns = [
    { header: "Return ID", accessor: (r: any) => <span className="font-mono text-sm">{r.display_id}</span> },
    { header: "Sale", accessor: (r: any) => <span className="font-mono text-sm text-muted-foreground">{r.sales?.display_id}</span> },
    { header: "Customer", accessor: (r: any) => r.stores?.customers?.name || r.stores?.name || "—" },
    { header: "Date", accessor: (r: any) => format(new Date(r.return_date), "dd MMM yyyy") },
    { header: "Amount", accessor: (r: any) => <span className="font-semibold">₹{Number(r.total_amount).toLocaleString()}</span> },
    { header: "Status", accessor: (r: any) => getStatusBadge(r.status) },
    { header: "Actions", accessor: (r: any) => (
      <Button variant="ghost" size="sm" onClick={() => setShowDetail(r.id)}>
        <Eye className="h-4 w-4" />
      </Button>
    )},
  ];

  return (
    <div className="space-y-6 animate-fade-in">
      <PageHeader
        title="Sale Returns"
        subtitle="Manage product returns from customers"
        primaryAction={{ label: "Record Return", onClick: () => setShowCreate(true), icon: Plus }}
      />

      {/* Filters */}
      <Card className="p-4">
        <div className="flex flex-wrap items-center gap-4">
          <div className="relative flex-1 min-w-[200px]">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-muted-foreground" />
            <Input
              placeholder="Search returns..."
              value={search}
              onChange={(e) => setSearch(e.target.value)}
              className="pl-9"
            />
          </div>
          <Select value={statusFilter} onValueChange={setStatusFilter}>
            <SelectTrigger className="w-[150px]">
              <SelectValue placeholder="All Status" />
            </SelectTrigger>
            <SelectContent>
              <SelectItem value="all">All Status</SelectItem>
              <SelectItem value="pending">Pending</SelectItem>
              <SelectItem value="approved">Approved</SelectItem>
              <SelectItem value="completed">Completed</SelectItem>
              <SelectItem value="rejected">Rejected</SelectItem>
            </SelectContent>
          </Select>
        </div>
      </Card>

      {isLoading ? (
        <div className="flex items-center justify-center py-12">
          <Loader2 className="h-8 w-8 animate-spin text-muted-foreground" />
        </div>
      ) : filteredReturns.length === 0 ? (
        <Card>
          <CardContent className="flex flex-col items-center justify-center py-12">
            <RotateCcw className="h-12 w-12 text-muted-foreground/30 mb-4" />
            <p className="text-muted-foreground">No sale returns found</p>
          </CardContent>
        </Card>
      ) : isMobile ? (
        <ResponsiveDataView
          data={filteredReturns}
          renderMobileCard={(r: any) => (
            <Card key={r.id} className="entity-card-mobile" onClick={() => setShowDetail(r.id)}>
              <CardContent className="p-4">
                <div className="flex items-start justify-between mb-2">
                  <div>
                    <p className="font-semibold">{r.display_id}</p>
                    <p className="text-sm text-muted-foreground">Sale: {r.sales?.display_id}</p>
                  </div>
                  {getStatusBadge(r.status)}
                </div>
                <div className="flex items-center justify-between text-sm">
                  <span className="text-muted-foreground">{r.stores?.customers?.name || r.stores?.name}</span>
                  <span className="font-semibold">₹{Number(r.total_amount).toLocaleString()}</span>
                </div>
                <p className="text-xs text-muted-foreground mt-1">{format(new Date(r.return_date), "dd MMM yyyy")}</p>
              </CardContent>
            </Card>
          )}
        />
      ) : (
        <DataTable data={filteredReturns} columns={columns} />
      )}

      {/* Create Return Dialog */}
      <Dialog open={showCreate} onOpenChange={(open) => { setShowCreate(open); if (!open) resetForm(); }}>
        <DialogContent className="max-w-2xl max-h-[90vh] overflow-y-auto">
          <DialogHeader>
            <DialogTitle>Record Sale Return</DialogTitle>
            <DialogDescription>Create a return request for a sale</DialogDescription>
          </DialogHeader>
          <form onSubmit={handleCreate} className="space-y-4">
            <div>
              <Label>Select Sale *</Label>
              <Select value={saleId} onValueChange={handleSaleSelect}>
                <SelectTrigger className="mt-1">
                  <SelectValue placeholder="Select a sale to return" />
                </SelectTrigger>
                <SelectContent>
                  {sales.map((s: any) => (
                    <SelectItem key={s.id} value={s.id}>
                      {s.display_id} - {s.stores?.customers?.name || s.stores?.name} - ₹{Number(s.total_amount).toLocaleString()}
                    </SelectItem>
                  ))}
                </SelectContent>
              </Select>
            </div>

            {saleId && returnItems.length > 0 && (
              <div className="space-y-3">
                <Label>Items to Return</Label>
                <div className="border rounded-lg divide-y">
                  {returnItems.map((item, idx) => (
                    <div key={item.sale_item_id} className="p-3 flex items-center gap-4">
                      <div className="flex-1">
                        <p className="font-medium">{item.product_name}</p>
                        <p className="text-sm text-muted-foreground">₹{item.unit_price} × max {item.max_qty}</p>
                      </div>
                      <div className="flex items-center gap-2">
                        <Label className="text-sm">Qty:</Label>
                        <Input
                          type="number"
                          min={0}
                          max={item.max_qty}
                          value={item.quantity}
                          onChange={(e) => updateItemQuantity(idx, parseInt(e.target.value) || 0)}
                          className="w-20"
                        />
                      </div>
                      <p className="font-medium w-24 text-right">
                        ₹{(item.quantity * item.unit_price).toLocaleString()}
                      </p>
                    </div>
                  ))}
                </div>
                <div className="flex justify-end p-3 bg-muted/50 rounded-lg">
                  <p className="font-semibold">Total Return: ₹{calculateTotal().toLocaleString()}</p>
                </div>
              </div>
            )}

            <div>
              <Label>Reason for Return *</Label>
              <Select value={reason} onValueChange={setReason}>
                <SelectTrigger className="mt-1">
                  <SelectValue placeholder="Select reason" />
                </SelectTrigger>
                <SelectContent>
                  <SelectItem value="damaged">Damaged Product</SelectItem>
                  <SelectItem value="defective">Defective/Quality Issue</SelectItem>
                  <SelectItem value="wrong_item">Wrong Item Delivered</SelectItem>
                  <SelectItem value="not_needed">Not Needed Anymore</SelectItem>
                  <SelectItem value="expired">Expired Product</SelectItem>
                  <SelectItem value="other">Other</SelectItem>
                </SelectContent>
              </Select>
            </div>

            <div>
              <Label>Additional Notes</Label>
              <Textarea
                value={notes}
                onChange={(e) => setNotes(e.target.value)}
                placeholder="Any additional details..."
                className="mt-1"
              />
            </div>

            <DialogFooter>
              <Button type="button" variant="outline" onClick={() => { setShowCreate(false); resetForm(); }}>
                Cancel
              </Button>
              <Button type="submit" disabled={saving || !saleId || calculateTotal() === 0}>
                {saving ? <Loader2 className="h-4 w-4 animate-spin mr-2" /> : null}
                Create Return
              </Button>
            </DialogFooter>
          </form>
        </DialogContent>
      </Dialog>

      {/* Return Detail Dialog */}
      <Dialog open={!!showDetail} onOpenChange={(open) => !open && setShowDetail(null)}>
        <DialogContent className="max-w-2xl">
          <DialogHeader>
            <DialogTitle>Return Details</DialogTitle>
            <DialogDescription>{returnDetail?.display_id}</DialogDescription>
          </DialogHeader>
          
          {returnDetail && (
            <div className="space-y-4">
              <div className="grid grid-cols-2 gap-4">
                <div>
                  <p className="text-sm text-muted-foreground">Sale</p>
                  <p className="font-medium">{returnDetail.sales?.display_id}</p>
                </div>
                <div>
                  <p className="text-sm text-muted-foreground">Customer</p>
                  <p className="font-medium">{returnDetail.stores?.customers?.name || returnDetail.stores?.name}</p>
                </div>
                <div>
                  <p className="text-sm text-muted-foreground">Return Date</p>
                  <p className="font-medium">{format(new Date(returnDetail.return_date), "dd MMM yyyy")}</p>
                </div>
                <div>
                  <p className="text-sm text-muted-foreground">Status</p>
                  {getStatusBadge(returnDetail.status)}
                </div>
                <div>
                  <p className="text-sm text-muted-foreground">Created By</p>
                  <p className="font-medium">{returnDetail.profiles?.full_name || "—"}</p>
                </div>
                {returnDetail.approver && (
                  <div>
                    <p className="text-sm text-muted-foreground">Approved By</p>
                    <p className="font-medium">{returnDetail.approver.full_name}</p>
                  </div>
                )}
              </div>

              <div>
                <p className="text-sm text-muted-foreground mb-2">Reason</p>
                <p className="capitalize">{returnDetail.reason?.replace("_", " ")}</p>
              </div>

              {returnDetail.notes && (
                <div>
                  <p className="text-sm text-muted-foreground mb-2">Notes</p>
                  <p>{returnDetail.notes}</p>
                </div>
              )}

              <div>
                <p className="text-sm text-muted-foreground mb-2">Items</p>
                <div className="border rounded-lg divide-y">
                  {returnDetail.items?.map((item: any) => (
                    <div key={item.id} className="p-3 flex items-center justify-between">
                      <div>
                        <p className="font-medium">{item.products?.name || "Product"}</p>
                        <p className="text-sm text-muted-foreground">₹{Number(item.unit_price).toLocaleString()} × {item.quantity}</p>
                      </div>
                      <p className="font-semibold">₹{Number(item.total).toLocaleString()}</p>
                    </div>
                  ))}
                </div>
                <div className="flex justify-end mt-2">
                  <p className="font-bold text-lg">Total: ₹{Number(returnDetail.total_amount).toLocaleString()}</p>
                </div>
              </div>

              {canApprove && returnDetail.status === "pending" && (
                <div className="flex gap-2 pt-4 border-t">
                  <Button 
                    className="flex-1" 
                    onClick={() => handleStatusUpdate(returnDetail.id, "approved")}
                  >
                    <CheckCircle className="h-4 w-4 mr-2" />
                    Approve
                  </Button>
                  <Button 
                    variant="destructive" 
                    className="flex-1"
                    onClick={() => handleStatusUpdate(returnDetail.id, "rejected")}
                  >
                    <XCircle className="h-4 w-4 mr-2" />
                    Reject
                  </Button>
                </div>
              )}

              {canApprove && returnDetail.status === "approved" && (
                <div className="pt-4 border-t">
                  <Button 
                    className="w-full"
                    onClick={() => handleStatusUpdate(returnDetail.id, "completed")}
                  >
                    <CheckCircle className="h-4 w-4 mr-2" />
                    Mark as Completed (Process Refund)
                  </Button>
                </div>
              )}
            </div>
          )}
        </DialogContent>
      </Dialog>
    </div>
  );
};

export default SaleReturns;

