function exportCSV(data: any[], columns: { header: string; key: string }[], filename: string) {
  const header = columns.map((c) => c.header).join(",");
  const rows = data.map((row) =>
    columns.map((c) => {
      const val = c.key.includes(".") ? c.key.split(".").reduce((o: any, k) => o?.[k], row) : row[c.key];
      const str = String(val ?? "").replace(/"/g, '""');
      return `"${str}"`;
    }).join(",")
  );
  const csv = [header, ...rows].join("\n");
  const blob = new Blob([csv], { type: "text/csv" });
  const url = URL.createObjectURL(blob);
  const a = document.createElement("a");
  a.href = url;
  a.download = filename;
  a.click();
  URL.revokeObjectURL(url);
  toast.success(`Exported ${data.length} rows`);
}

interface SaleItem {
  product_id: string;
  quantity: number;
  unit_price: number;
}

const POS_STORE_ID = "00000000-0000-0000-0000-000000000001";
const PAGE_SIZE = 100;

// Type for order fulfillment
interface FulfillOrder {
  id: string;
  display_id: string;
  store_id: string;
  customer_id: string | null;
  order_type: "simple" | "detailed";
  status: string;
  requirement_note: string | null;
  order_items?: Array<{
    id: string;
    product_id: string;
    quantity: number;
    unit_price: number | null;
    products?: {
      id: string;
      name: string;
      sku: string;
      base_price: number;
      image_url?: string;
    };
  }>;
  stores?: {
    id: string;
    name: string;
    store_type_id: string | null;
    customer_id: string | null;
  };
}

const Sales = () => {
  const { user, role } = useAuth();
  const navigate = useNavigate();
  const isPosUser = role === "pos";
  const { allowed: canOverridePrice } = usePermission("price_override");
  const { allowed: canRecordBehalf } = usePermission("record_behalf");
  const qc = useQueryClient();
  const [showAdd, setShowAdd] = useState(false);
  const [saving, setSaving] = useState(false);
  const [selectedSaleId, setSelectedSaleId] = useState<string | null>(null);
  const [receiptSaleId, setReceiptSaleId] = useState<string | null>(null);
  const [fulfillOrder, setFulfillOrder] = useState<FulfillOrder | null>(null);
  const [loadingOrderId, setLoadingOrderId] = useState<string | null>(null);

  // POS users are locked to the POS store
  const isAdmin = role === "super_admin" || role === "manager";
  const [searchParams, setSearchParams] = useSearchParams();
  const [storeId, setStoreId] = useState(isPosUser ? POS_STORE_ID : (searchParams.get("store") ?? ""));

  // When navigated with ?store=<id>, auto-open the add dialog
  useEffect(() => {
    const storeParam = searchParams.get("store");
    if (storeParam && !isPosUser) {
      setStoreId(storeParam);
      setShowAdd(true);
      setSearchParams({}, { replace: true });
    }
  }, [searchParams, isPosUser, setSearchParams]);
  const [cashAmount, setCashAmount] = useState("");
  const [upiAmount, setUpiAmount] = useState("");
  const [recordedFor, setRecordedFor] = useState("");
  const [saleDate, setSaleDate] = useState("");

  // List filters
  const today = new Date().toISOString().split("T")[0];
  const thirtyDaysAgo = new Date(Date.now() - 30 * 24 * 60 * 60 * 1000).toISOString().split("T")[0];
  const [filterFrom, setFilterFrom] = useState(thirtyDaysAgo);
  const [filterTo, setFilterTo] = useState(today);
  const [filterStore, setFilterStore] = useState("all");
  const [filterUser, setFilterUser] = useState("all");
  const [filterPayment, setFilterPayment] = useState("all");
  const [items, setItems] = useState<SaleItem[]>([{ product_id: "", quantity: 1, unit_price: 0 }]);
  const [loadedPages, setLoadedPages] = useState(1);

  // Reset to page 1 whenever any filter changes
  useEffect(() => {
    setLoadedPages(1);
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [filterFrom, filterTo, filterStore, filterUser, filterPayment]);

  const { data: sales, isLoading, isFetching } = useQuery({
    queryKey: ["sales", isAdmin ? "all" : user?.id, filterFrom, filterTo, filterStore, filterUser, filterPayment, loadedPages],
    queryFn: async () => {
      let query = supabase
        .from("sales")
        .select("*, stores(name, display_id), customers(name, display_id)")
        .order("created_at", { ascending: false });
      // Non-admin roles (agents, pos, marketer) only see their own records
      if (!isAdmin) query = query.eq("recorded_by", user!.id);
      // Server-side filters
      if (filterFrom) query = query.gte("created_at", filterFrom + "T00:00:00");
      if (filterTo) query = query.lte("created_at", filterTo + "T23:59:59");
      if (filterStore !== "all") query = query.eq("store_id", filterStore);
      if (filterUser !== "all") query = query.eq("recorded_by", filterUser);
      if (filterPayment === "cash") query = query.gt("cash_amount", 0);
      if (filterPayment === "upi") query = query.gt("upi_amount", 0);
      if (filterPayment === "outstanding") query = query.gt("outstanding_amount", 0);
      // Cursor pagination: fetch all pages up to current
      query = query.range(0, loadedPages * PAGE_SIZE - 1);
      const { data, error } = await query;
      if (error) throw error;
      return data;
    },
  });

  const hasMoreSales = (sales?.length || 0) >= loadedPages * PAGE_SIZE;

  const { data: profiles } = useQuery({
    queryKey: ["profiles"],
    queryFn: async () => {
      const { data } = await supabase.from("profiles").select("user_id, full_name, avatar_url");
      return data || [];
    },
  });

  const profileMap = new Map(profiles?.map((p) => [p.user_id, p]) || []);

  // Filtering is now done server-side; local array mirrors the fetched page(s)
  const filteredSales = sales || [];

  const activeFilterCount = [filterStore !== "all", filterUser !== "all", filterPayment !== "all", filterFrom !== thirtyDaysAgo, filterTo !== today].filter(Boolean).length;

  const clearSalesFilters = () => {
    setFilterFrom(thirtyDaysAgo);
    setFilterTo(today);
    setFilterStore("all");
    setFilterUser("all");
    setFilterPayment("all");
  };

  const { data: stores } = useQuery({
    queryKey: ["stores-for-sale"],
    queryFn: async () => {
      const { data } = await supabase.from("stores").select("id, name, outstanding, display_id, store_type_id, customer_id, lat, lng, is_active").order("is_active", { ascending: false }).order("name");
      return data || [];
    },
  });

  // Fetch store types for credit limits
  const { data: storeTypes } = useQuery({
    queryKey: ["store-types-credit"],
    queryFn: async () => {
      const { data } = await supabase.from("store_types").select("id, credit_limit_kyc, credit_limit_no_kyc");
      return data || [];
    },
  });

  // Fetch customer KYC status for credit limit determination
  const { data: customers } = useQuery({
    queryKey: ["customers-kyc-for-sale"],
    queryFn: async () => {
      const { data } = await supabase.from("customers").select("id, kyc_status, credit_limit_override");
      return data || [];
    },
  });

  const selectedStore = stores?.find((s) => s.id === storeId);
  const selectedStoreTypeId = selectedStore?.store_type_id;

  const { data: availableProducts } = useQuery({
    queryKey: ["products-for-sale", selectedStoreTypeId, storeId],
    queryFn: async () => {
      if (!selectedStoreTypeId) return [];
      const { data: accessData } = await supabase
        .from("store_type_products")
        .select("product_id, products(id, name, sku, base_price)")
        .eq("store_type_id", selectedStoreTypeId);

      let productList: any[];
      if (accessData && accessData.length > 0) {
        productList = accessData.map((a: any) => a.products).filter(Boolean);
      } else {
        const { data } = await supabase.from("products").select("id, name, base_price, sku").eq("is_active", true);
        productList = data || [];
      }

      const { data: typePricing } = await supabase
        .from("store_type_pricing")
        .select("product_id, price")
        .eq("store_type_id", selectedStoreTypeId);
      const typePriceMap: Record<string, number> = {};
      typePricing?.forEach((p) => { typePriceMap[p.product_id] = Number(p.price); });

      const { data: storePricing } = await supabase
        .from("store_pricing")
        .select("product_id, price")
        .eq("store_id", storeId);
      const storePriceMap: Record<string, number> = {};
      storePricing?.forEach((p) => { storePriceMap[p.product_id] = Number(p.price); });

      return productList.map((p) => {
        let effectivePrice = Number(p.base_price);
        let priceSource = "base";
        if (typePriceMap[p.id]) { effectivePrice = typePriceMap[p.id]; priceSource = "type"; }
        if (storePriceMap[p.id]) { effectivePrice = storePriceMap[p.id]; priceSource = "store"; }
        return { ...p, effectivePrice, priceSource };
      });
    },
    enabled: !!storeId && !!selectedStoreTypeId,
  });

  // Fetch pending orders for the selected store (shown in record sale dialog)
  const { data: pendingOrders, isLoading: loadingPendingOrders } = useQuery({
    queryKey: ["pending-orders-for-store", storeId],
    queryFn: async () => {
      const { data } = await supabase
        .from("orders")
        .select(`
          id, display_id, order_type, requirement_note, created_at,
          order_items(id, product_id, quantity, unit_price, products(id, name, sku))
        `)
        .eq("store_id", storeId)
        .eq("status", "pending")
        .order("created_at", { ascending: false })
        .limit(10);
      return data || [];
    },
    enabled: !!storeId && showAdd,
  });

  // Fetch sale items for the selected sale detail
  const { data: saleItems, isLoading: loadingSaleItems } = useQuery({
    queryKey: ["sale-items", selectedSaleId],
    queryFn: async () => {
      const { data } = await supabase
        .from("sale_items")
        .select("*, products(name, sku)")
        .eq("sale_id", selectedSaleId!);
      return data || [];
    },
    enabled: !!selectedSaleId,
  });

  const selectedSale = sales?.find((s) => s.id === selectedSaleId);

  const totalAmount = items.reduce((s, i) => s + i.quantity * i.unit_price, 0);
  const cash = parseFloat(cashAmount) || 0;
  const upi = parseFloat(upiAmount) || 0;
  const outstandingFromSale = totalAmount - cash - upi;
  const oldOutstanding = Number(selectedStore?.outstanding || 0);
  const newOutstanding = oldOutstanding + outstandingFromSale;

  // Credit limit calculation
  const creditLimitInfo = selectedStore && storeTypes && customers
    ? resolveCreditLimit(selectedStore, storeTypes, customers)
    : null;

  const creditExceeded = creditLimitInfo && creditLimitInfo.limit > 0 && newOutstanding > creditLimitInfo.limit;
  const creditWarning = creditLimitInfo && creditLimitInfo.limit > 0 && newOutstanding > creditLimitInfo.limit * 0.8 && !creditExceeded;

  const addItem = () => setItems([...items, { product_id: "", quantity: 1, unit_price: 0 }]);
  const removeItem = (idx: number) => setItems(items.filter((_, i) => i !== idx));
  const updateItem = (idx: number, field: keyof SaleItem, value: any) => {
    const updated = [...items];
    (updated[idx] as any)[field] = value;
    if (field === "product_id") {
      const p = availableProducts?.find((pr: any) => pr.id === value);
      if (p) updated[idx].unit_price = p.effectivePrice;
    }
    setItems(updated);
  };

  // Fetch staff users for "record on behalf" selector
  const { data: staffUsers } = useQuery({
    queryKey: ["staff-for-behalf"],
    queryFn: async () => {
      const { data: roles } = await supabase.from("user_roles").select("user_id, role").neq("role", "customer");
      const staffIds = roles?.map((r) => r.user_id) || [];
      const { data: profs } = await supabase.from("profiles").select("user_id, full_name").in("user_id", staffIds);
      return profs?.filter((p) => p.user_id !== user?.id) || [];
    },
    enabled: canRecordBehalf,
  });

  const resetForm = () => {
    setStoreId(isPosUser ? POS_STORE_ID : ""); setCashAmount(""); setUpiAmount(""); setRecordedFor(""); setSaleDate("");
    setItems([{ product_id: "", quantity: 1, unit_price: 0 }]);
  };

  const handleStoreChange = (newStoreId: string) => {
    setStoreId(newStoreId);
    setItems([{ product_id: "", quantity: 1, unit_price: 0 }]);
  };

  // Open fulfillment dialog for a pending order
  const handleFulfillOrder = async (orderId: string) => {
    setLoadingOrderId(orderId);
    try {
      const { data: orderData, error } = await supabase
        .from("orders")
        .select(`
          *,
          stores(id, name, store_type_id, customer_id),
          order_items(id, product_id, quantity, unit_price, products(id, name, sku, base_price, image_url))
        `)
        .eq("id", orderId)
        .single();

      if (error) throw error;
      setShowAdd(false); // Close the record sale dialog
      setFulfillOrder(orderData as unknown as FulfillOrder);
    } catch (error) {
      console.error("Error loading order:", error);
      toast.error("Failed to load order details");
    } finally {
      setLoadingOrderId(null);
    }
  };

  const handleAdd = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!storeId || items.some((i) => !i.product_id)) {
      toast.error("Please fill all required fields");
      return;
    }
    if (items.some((i) => i.quantity <= 0)) {
      toast.error("All item quantities must be greater than zero");
      return;
    }
    if (totalAmount === 0) {
      toast.error("Sale total cannot be zero");
      return;
    }
    // POS users: payment must equal total (no outstanding allowed)
    if (isPosUser && (cash + upi) !== totalAmount) {
      toast.error("POS sales require full payment. Cash + UPI must equal Total.");
      return;
    }
    setSaving(true);

    // Proximity check for agents
    if (role === "agent" && selectedStore) {
      const { checkProximity } = await import("@/lib/proximity");
      const result = await checkProximity(selectedStore.lat ?? null, selectedStore.lng ?? null);
      if (!result.withinRange) {
        toast.error(result.message);
        setSaving(false);
        return;
      }
      if (result.skippedNoGps) {
        toast.warning("Store has no GPS coordinates — location check skipped");
      }
    }

    const customerId = selectedStore?.customer_id;
    if (!customerId) {
      toast.error("Store has no linked customer");
      setSaving(false);
      return;
    }

    // Queue sale for offline sync if no network connection
    if (!navigator.onLine) {
      const effectiveRecordedByOffline = recordedFor || user!.id;
      const loggedByOffline = recordedFor ? user!.id : null;
      await addToQueue({
        id: crypto.randomUUID(),
        type: "sale",
        payload: {
          saleData: {
            store_id: storeId,
            customer_id: customerId,
            recorded_by: effectiveRecordedByOffline,
            logged_by: loggedByOffline,
            total_amount: totalAmount,
            cash_amount: cash,
            upi_amount: upi,
            outstanding_amount: outstandingFromSale,
            old_outstanding: oldOutstanding,
            new_outstanding: newOutstanding,
            ...(saleDate ? { created_at: new Date(saleDate).toISOString() } : {}),
          },
          saleItems: items.filter((i) => i.product_id).map((i) => ({
            product_id: i.product_id,
            quantity: i.quantity,
            unit_price: i.unit_price,
            total_price: i.quantity * i.unit_price,
          })),
          storeUpdate: { outstanding: newOutstanding },
        },
        createdAt: new Date().toISOString(),
      });
      toast.warning("You're offline — sale queued and will sync automatically when back online");
      setSaving(false);
      setShowAdd(false);
      resetForm();
      return;
    }

    const { data: displayId } = await supabase.rpc("generate_display_id", { prefix: "SALE", seq_name: "sale_display_seq" });

    const effectiveRecordedBy = recordedFor || user!.id;
    const loggedBy = recordedFor ? user!.id : null;

    const saleItems = items.filter((i) => i.product_id).map((i) => ({
      product_id: i.product_id,
      quantity: i.quantity,
      unit_price: i.unit_price,
      total_price: i.quantity * i.unit_price,
    }));

    // Count pending orders before insert for the success toast
    const { data: pendingOrders } = await supabase
      .from("orders").select("id").eq("store_id", storeId).eq("status", "pending");
    const pendingCount = pendingOrders?.length || 0;

    // Single atomic RPC — insert sale + items, enforce credit limit, deliver orders, fix balance
    const { data: result, error } = await supabase.rpc("record_sale", {
      p_display_id: displayId,
      p_store_id: storeId,
      p_customer_id: customerId,
      p_recorded_by: effectiveRecordedBy,
      p_logged_by: loggedBy,
      p_total_amount: totalAmount,
      p_cash_amount: cash,
      p_upi_amount: upi,
      p_outstanding_amount: outstandingFromSale,
      p_sale_items: saleItems,
      p_created_at: saleDate ? new Date(saleDate).toISOString() : null,
    });

    if (error) {
      if (error.message.includes("credit_limit_exceeded")) {
        toast.error("Credit limit exceeded. Increase payment or reduce items.");
      } else {
        toast.error(error.message);
      }
      setSaving(false);
      return;
    }

    const saleRow = (result as any)?.[0];
    logActivity(user!.id, "Recorded sale", "sale", displayId, saleRow?.sale_id, { total: totalAmount, store: storeId });

    if (pendingCount > 0) {
      toast.success(`Sale recorded. ${pendingCount} pending order(s) auto-marked as delivered.`);
      qc.invalidateQueries({ queryKey: ["orders"] });
    } else {
      toast.success("Sale recorded successfully");
    }

    // Notify admins/managers (fire-and-forget with error handling)
    const storeName = stores?.find((s) => s.id === storeId)?.name || "store";
    getAdminUserIds()
      .then((ids) => {
        const others = ids.filter((id) => id !== user!.id);
        if (others.length > 0) {
          sendNotificationToMany(others, {
            title: "New Sale Recorded",
            message: `Sale ${displayId} of ₹${totalAmount.toLocaleString()} at ${storeName}`,
            type: "payment",
            entityType: "sale",
            entityId: saleRow?.sale_id,
          });
        }
      })
      .catch((err) => {
        // Don't block on notification failures
        console.warn("Failed to notify admins:", err);
      });

    setSaving(false);
    setShowAdd(false);
    resetForm();
    qc.invalidateQueries({ queryKey: ["sales"] });
  };

  const getRecorderName = (userId: string) => {
    const p = profileMap.get(userId);
    return p?.full_name || "Unknown";
  };

  const getRecorderAvatar = (userId: string) => {
    const p = profileMap.get(userId);
    return p?.avatar_url || null;
  };

  const columns = [
    { header: "Sale ID", accessor: "display_id" as const, className: "font-mono text-xs", hideOnMobile: true },
    { header: "Store", accessor: (row: any) => (
      <div className="flex items-center gap-2">
        <StoreIcon className="h-3.5 w-3.5 text-muted-foreground shrink-0" />
        <span>{row.stores?.name || "—"}</span>
      </div>
    ), className: "font-medium" },
    { header: "Total", accessor: (row: any) => <span className="font-semibold">₹{Number(row.total_amount).toLocaleString()}</span> },
    { header: "Cash", accessor: (row: any) => `₹${Number(row.cash_amount).toLocaleString()}`, className: "text-sm hidden lg:table-cell" },
    { header: "UPI", accessor: (row: any) => `₹${Number(row.upi_amount).toLocaleString()}`, className: "text-sm hidden lg:table-cell" },
    { header: "Outstanding", accessor: (row: any) => (
      <span className={Number(row.outstanding_amount) > 0 ? "text-destructive font-medium" : "text-muted-foreground"}>
        ₹{Number(row.outstanding_amount).toLocaleString()}
      </span>
    ), className: "text-sm hidden md:table-cell" },
    { header: "Recorded By", accessor: (row: any) => (
      <div className="flex items-center gap-2">
        <Avatar className="h-6 w-6">
          <AvatarImage src={getRecorderAvatar(row.recorded_by) || undefined} />
          <AvatarFallback className="text-[10px] bg-primary/10 text-primary">{getRecorderName(row.recorded_by).charAt(0)}</AvatarFallback>
        </Avatar>
        <span className="text-xs text-muted-foreground">{getRecorderName(row.recorded_by)}</span>
      </div>
    ), className: "hidden lg:table-cell" },
    { header: "Date", accessor: (row: any) => (
      <span className="text-xs text-muted-foreground">{format(new Date(row.created_at), "dd MMM yy, hh:mm a")}</span>
    ), className: "hidden sm:table-cell" },
    { header: "Actions", accessor: (row: any) => (
      <div className="flex items-center gap-1">
        <Button
          variant="ghost"
          size="icon"
          className="h-7 w-7"
          onClick={(e) => { e.stopPropagation(); setReceiptSaleId(row.id); }}
          title="View Receipt"
        >
          <Receipt className="h-3.5 w-3.5" />
        </Button>
        {isAdmin && !row.has_invoice && (
          <Button
            variant="ghost"
            size="icon"
            className="h-7 w-7"
            onClick={(e) => { e.stopPropagation(); navigate("/invoices/new", { state: { saleIds: [row.id] } }); }}
            title="Generate Invoice"
          >
            <FileText className="h-3.5 w-3.5" />
          </Button>
        )}
        {row.has_invoice && (
          <Badge variant="outline" className="text-[10px] px-1.5">Invoiced</Badge>
        )}
      </div>
    ), className: "hidden sm:table-cell" },
  ];

  if (isLoading) {
    return <TableSkeleton columns={7} />;
  }

  const getPriceLabel = (product: any) => {
    if (product.priceSource === "store") return "(store price)";
    if (product.priceSource === "type") return "(type price)";
    return "(base price)";
  };

  return (
    <div className="space-y-6 animate-fade-in">
      <PageHeader
        title="Sales"
        subtitle="View and record sales transactions"
        primaryAction={{ label: "Record Sale", onClick: () => setShowAdd(true) }}
        actions={[
          {
            label: "Returns",
            icon: RotateCcw,
            priority: 0,
            onClick: () => navigate("/sale-returns"),
          },
          {
            label: "Export CSV",
            icon: Download,
            priority: 1,
            onClick: () => {
              exportCSV(
                filteredSales.map((s: any) => ({ ...s, store_name: s.stores?.name || "", customer_name: s.customers?.name || "", recorder: getRecorderName(s.recorded_by) })),
                [
                  { header: "Sale ID", key: "display_id" },
                  { header: "Store", key: "store_name" },
                  { header: "Customer", key: "customer_name" },
                  { header: "Total", key: "total_amount" },
                  { header: "Cash", key: "cash_amount" },
                  { header: "UPI", key: "upi_amount" },
                  { header: "Outstanding", key: "outstanding_amount" },
                  { header: "Recorded By", key: "recorder" },
                  { header: "Date", key: "created_at" },
                ],
                "sales-export.csv"
              );
            },
          },
        ]}
      />

      <div className="flex flex-wrap items-center gap-2 p-3 rounded-lg border bg-muted/30">
        <Popover>
          <PopoverTrigger asChild>
            <Button variant="outline" className="h-8 text-xs gap-1.5 justify-start font-normal flex-1 min-w-[100px] sm:flex-none">
              <CalendarIcon className="h-3 w-3 shrink-0" />
              {filterFrom ? format(new Date(filterFrom + "T00:00:00"), "dd MMM yy") : "From"}
            </Button>
          </PopoverTrigger>
          <PopoverContent className="w-auto p-0" align="start">
            <Calendar mode="single" selected={filterFrom ? new Date(filterFrom + "T00:00:00") : undefined} onSelect={(d) => setFilterFrom(d ? format(d, "yyyy-MM-dd") : "")} initialFocus />
          </PopoverContent>
        </Popover>
        <Popover>
          <PopoverTrigger asChild>
            <Button variant="outline" className="h-8 text-xs gap-1.5 justify-start font-normal flex-1 min-w-[100px] sm:flex-none">
              <CalendarIcon className="h-3 w-3 shrink-0" />
              {filterTo ? format(new Date(filterTo + "T00:00:00"), "dd MMM yy") : "To"}
            </Button>
          </PopoverTrigger>
          <PopoverContent className="w-auto p-0" align="start">
            <Calendar mode="single" selected={filterTo ? new Date(filterTo + "T00:00:00") : undefined} onSelect={(d) => setFilterTo(d ? format(d, "yyyy-MM-dd") : "")} initialFocus />
          </PopoverContent>
        </Popover>
        <Select value={filterStore} onValueChange={setFilterStore}>
          <SelectTrigger className="h-8 text-xs flex-1 min-w-[120px] sm:flex-none sm:w-40"><SelectValue placeholder="All stores" /></SelectTrigger>
          <SelectContent>
            <SelectItem value="all">All stores</SelectItem>
            {stores?.map((s: any) => <SelectItem key={s.id} value={s.id}>{s.name}</SelectItem>)}
          </SelectContent>
        </Select>
        <Select value={filterUser} onValueChange={setFilterUser}>
          <SelectTrigger className="h-8 text-xs flex-1 min-w-[120px] sm:flex-none sm:w-40"><SelectValue placeholder="All users" /></SelectTrigger>
          <SelectContent>
            <SelectItem value="all">All users</SelectItem>
            {profiles?.map((p: any) => <SelectItem key={p.user_id} value={p.user_id}>{p.full_name}</SelectItem>)}
          </SelectContent>
        </Select>
        <Select value={filterPayment} onValueChange={setFilterPayment}>
          <SelectTrigger className="h-8 text-xs flex-1 min-w-[120px] sm:flex-none sm:w-40"><SelectValue placeholder="Payment method" /></SelectTrigger>
          <SelectContent>
            <SelectItem value="all">All methods</SelectItem>
            <SelectItem value="cash">Cash only</SelectItem>
            <SelectItem value="upi">UPI only</SelectItem>
            <SelectItem value="outstanding">Has outstanding</SelectItem>
          </SelectContent>
        </Select>
        {activeFilterCount > 0 && (
          <Button variant="ghost" size="sm" className="h-8 text-xs" onClick={clearSalesFilters}>
            <X className="h-3 w-3 mr-1" /> Clear ({activeFilterCount})
          </Button>
        )}
        <span className="ml-auto text-xs text-muted-foreground">{filteredSales.length}{hasMoreSales ? "+" : ""} result{filteredSales.length !== 1 ? "s" : ""}</span>
      </div>

      <DataTable
        columns={columns}
        data={filteredSales}
        searchKey="display_id"
        searchPlaceholder="Search by sale ID..."
        emptyMessage="No sales recorded yet."
        onRowClick={(row: any) => setSelectedSaleId(row.id)}
        renderMobileCard={(row: any) => (
          <div className="rounded-lg border bg-card p-3 cursor-pointer active:bg-muted/30" onClick={() => setSelectedSaleId(row.id)}>
            {/* Header row: ID + Date */}
            <div className="flex items-center justify-between mb-1.5">
              <span className="font-mono text-xs text-primary font-medium">{row.display_id}</span>
              <span className="text-[10px] text-muted-foreground">{format(new Date(row.created_at), "dd MMM yy, hh:mm a")}</span>
            </div>
            {/* Store name */}
            <div className="flex items-center gap-1.5 mb-2">
              <StoreIcon className="h-3.5 w-3.5 text-muted-foreground shrink-0" />
              <span className="font-medium text-sm truncate">{row.stores?.name || "—"}</span>
            </div>
            {/* Amounts row - inline compact */}
            <div className="flex items-center gap-3 text-xs">
              <span className="font-bold text-foreground">₹{Number(row.total_amount).toLocaleString()}</span>
              <span className="text-muted-foreground">Cash: ₹{Number(row.cash_amount).toLocaleString()}</span>
              <span className="text-muted-foreground">UPI: ₹{Number(row.upi_amount).toLocaleString()}</span>
            </div>
            {/* Footer: Recorder + Outstanding */}
            <div className="flex items-center justify-between mt-2 pt-2 border-t border-border/50">
              <div className="flex items-center gap-1.5">
                <Avatar className="h-4 w-4">
                  <AvatarImage src={getRecorderAvatar(row.recorded_by) || undefined} />
                  <AvatarFallback className="text-[8px] bg-primary/10 text-primary">{getRecorderName(row.recorded_by).charAt(0)}</AvatarFallback>
                </Avatar>
                <span className="text-[10px] text-muted-foreground truncate max-w-[100px]">{getRecorderName(row.recorded_by)}</span>
              </div>
              {Number(row.outstanding_amount) > 0 && (
                <span className="text-xs font-semibold text-destructive">Due: ₹{Number(row.outstanding_amount).toLocaleString()}</span>
              )}
            </div>
          </div>
        )}
      />

      {hasMoreSales && (
        <div className="flex justify-center pt-1">
          <Button variant="outline" size="sm" onClick={() => setLoadedPages((p) => p + 1)} disabled={isFetching} className="gap-1.5">
            {isFetching ? <Loader2 className="h-3.5 w-3.5 animate-spin" /> : null}
            Load more
          </Button>
        </div>
      )}

      {/* Sale Detail Dialog */}
      <Dialog open={!!selectedSaleId} onOpenChange={(v) => { if (!v) setSelectedSaleId(null); }}>
        <DialogContent className="max-w-md">
          <DialogHeader><DialogTitle>Sale Details</DialogTitle></DialogHeader>
          {selectedSale && (
            <div className="space-y-4">
              <div className="flex items-center justify-between">
                <span className="font-mono text-sm text-muted-foreground">{selectedSale.display_id}</span>
                <span className="text-xs text-muted-foreground">{format(new Date(selectedSale.created_at), "dd MMM yy, hh:mm a")}</span>
              </div>
              <div className="flex items-center gap-2">
                <StoreIcon className="h-4 w-4 text-muted-foreground" />
                <span className="font-medium">{(selectedSale as any).stores?.name || "—"}</span>
              </div>
              <div className="rounded-lg border bg-muted/30 p-3 space-y-1 text-sm">
                <div className="flex justify-between"><span>Total</span><span className="font-bold">₹{Number(selectedSale.total_amount).toLocaleString()}</span></div>
                <div className="flex justify-between"><span>Cash</span><span>₹{Number(selectedSale.cash_amount).toLocaleString()}</span></div>
                <div className="flex justify-between"><span>UPI</span><span>₹{Number(selectedSale.upi_amount).toLocaleString()}</span></div>
                <div className="flex justify-between font-medium"><span>Outstanding</span><span className={Number(selectedSale.outstanding_amount) > 0 ? "text-destructive" : ""}>₹{Number(selectedSale.outstanding_amount).toLocaleString()}</span></div>
              </div>

              {/* Items */}
              <div>
                <p className="text-sm font-medium mb-2 flex items-center gap-1.5"><Package className="h-4 w-4 text-muted-foreground" /> Items</p>
                {loadingSaleItems ? (
                  <div className="flex justify-center py-4"><Loader2 className="h-5 w-5 animate-spin text-muted-foreground" /></div>
                ) : saleItems && saleItems.length > 0 ? (
                  <div className="space-y-1.5">
                    {saleItems.map((item: any) => (
                      <div key={item.id} className="flex items-center justify-between rounded-lg border bg-card p-2.5 text-sm">
                        <div>
                          <p className="font-medium">{item.products?.name || "—"}</p>
                          <p className="text-[11px] text-muted-foreground">{item.products?.sku} · Qty: {Number(item.quantity)}</p>
                        </div>
                        <div className="text-right">
                          <p className="font-semibold">₹{Number(item.total_price).toLocaleString()}</p>
                          <p className="text-[11px] text-muted-foreground">@ ₹{Number(item.unit_price).toLocaleString()}</p>
                        </div>
                      </div>
                    ))}
                  </div>
                ) : (
                  <p className="text-xs text-muted-foreground">No items recorded</p>
                )}
              </div>

              {/* Recorder */}
              <div className="flex items-center gap-2 pt-2 border-t">
                <Avatar className="h-5 w-5">
                  <AvatarImage src={getRecorderAvatar(selectedSale.recorded_by) || undefined} />
                  <AvatarFallback className="text-[9px] bg-primary/10 text-primary">{getRecorderName(selectedSale.recorded_by).charAt(0)}</AvatarFallback>
                </Avatar>
               <span className="text-xs text-muted-foreground">Recorded by {getRecorderName(selectedSale.recorded_by)}</span>
              </div>
              {(selectedSale as any).logged_by && (
                <div className="flex items-center gap-2">
                  <Avatar className="h-5 w-5">
                    <AvatarImage src={getRecorderAvatar((selectedSale as any).logged_by) || undefined} />
                    <AvatarFallback className="text-[9px] bg-accent/20 text-accent-foreground">{getRecorderName((selectedSale as any).logged_by).charAt(0)}</AvatarFallback>
                  </Avatar>
                  <span className="text-xs text-muted-foreground">Logged by {getRecorderName((selectedSale as any).logged_by)}</span>
                </div>
              )}
            </div>
          )}
        </DialogContent>
      </Dialog>

      {/* Record Sale Dialog */}
      <Dialog open={showAdd} onOpenChange={(v) => { setShowAdd(v); if (!v) resetForm(); }}>
        <DialogContent className="max-w-lg max-h-[90vh] overflow-y-auto">
          <DialogHeader><DialogTitle>Record Sale</DialogTitle></DialogHeader>
          <form onSubmit={handleAdd} className="space-y-4">
            {canRecordBehalf && (
              <div>
                <Label>Record on behalf of</Label>
                <Select value={recordedFor || "self"} onValueChange={(v) => setRecordedFor(v === "self" ? "" : v)}>
                  <SelectTrigger className="mt-1"><SelectValue placeholder="Myself (default)" /></SelectTrigger>
                  <SelectContent>
                    <SelectItem value="self">Myself</SelectItem>
                    {staffUsers?.map((s) => (
                      <SelectItem key={s.user_id} value={s.user_id}>{s.full_name}</SelectItem>
                    ))}
                  </SelectContent>
                </Select>
              </div>
            )}

            {isAdmin && (
              <div>
                <Label>Sale Date <span className="text-muted-foreground text-xs font-normal">(leave blank to use current time)</span></Label>
                <Input
                  type="datetime-local"
                  value={saleDate}
                  onChange={(e) => setSaleDate(e.target.value)}
                  className="mt-1"
                />
              </div>
            )}

            <div>
              <Label>Store</Label>
              {isPosUser ? (
                <div className="mt-1 flex h-10 w-full items-center rounded-md border border-input bg-muted px-3 text-sm text-muted-foreground">
                  POS Counter (auto-selected)
                </div>
              ) : (
                <div className="flex gap-2 mt-1">
                  <Select value={storeId} onValueChange={handleStoreChange}>
                    <SelectTrigger className="flex-1"><SelectValue placeholder="Select store" /></SelectTrigger>
                    <SelectContent>{stores?.map((s) => (
                      <SelectItem key={s.id} value={s.id} disabled={!s.is_active}>
                        {s.name} ({s.display_id}){!s.is_active ? " — Inactive" : ""}
                      </SelectItem>
                    ))}</SelectContent>
                  </Select>
                  <QrStoreSelector onStoreSelected={handleStoreChange} />
                </div>
              )}
              {selectedStore && (
                <div className="text-xs text-muted-foreground mt-1 space-y-0.5">
                  <p>Current outstanding: ₹{oldOutstanding.toLocaleString()}</p>
                  {creditLimitInfo && creditLimitInfo.limit > 0 && (
                    <p>Credit limit ({creditLimitInfo.source}): ₹{creditLimitInfo.limit.toLocaleString()} — <span className={oldOutstanding > creditLimitInfo.limit * 0.8 ? "text-destructive font-medium" : "text-muted-foreground"}>{Math.round((oldOutstanding / creditLimitInfo.limit) * 100)}% used</span></p>
                  )}
                </div>
              )}
            </div>

            {/* Pending Orders Section - Show before products to encourage fulfillment */}
            {storeId && pendingOrders && pendingOrders.length > 0 && (
              <div className="rounded-lg border-2 border-primary/30 bg-primary/5 p-3 space-y-2">
                <div className="flex items-center gap-2">
                  <ShoppingCart className="h-4 w-4 text-primary" />
                  <span className="text-sm font-medium">Pending Orders ({pendingOrders.length})</span>
                </div>
                <p className="text-xs text-muted-foreground">
                  This store has pending orders. Click to fulfill an order instead of creating a new sale.
                </p>
                <div className="space-y-1.5 max-h-40 overflow-y-auto">
                  {pendingOrders.map((order: any) => (
                    <Card 
                      key={order.id} 
                      className="cursor-pointer hover:bg-accent/50 transition-colors"
                      onClick={() => handleFulfillOrder(order.id)}
                    >
                      <CardContent className="p-2.5 flex items-center justify-between gap-2">
                        <div className="min-w-0 flex-1">
                          <div className="flex items-center gap-1.5 mb-0.5">
                            <span className="font-mono text-xs font-medium text-primary">{order.display_id}</span>
                            <Badge variant="secondary" className="text-[10px] h-4 px-1">
                              {order.order_type}
                            </Badge>
                          </div>
                          {order.order_type === "detailed" && order.order_items?.length > 0 ? (
                            <p className="text-[11px] text-muted-foreground truncate">
                              {order.order_items.slice(0, 2).map((i: any) => i.products?.name || "Item").join(", ")}
                              {order.order_items.length > 2 && ` +${order.order_items.length - 2} more`}
                            </p>
                          ) : order.requirement_note ? (
                            <p className="text-[11px] text-muted-foreground truncate">{order.requirement_note}</p>
                          ) : null}
                          <p className="text-[10px] text-muted-foreground/70">
                            {format(new Date(order.created_at), "dd MMM, hh:mm a")}
                          </p>
                        </div>
                        <div className="flex items-center gap-1 shrink-0">
                          {loadingOrderId === order.id ? (
                            <Loader2 className="h-4 w-4 animate-spin text-primary" />
                          ) : (
                            <>
                              <span className="text-xs text-primary font-medium">Fulfill</span>
                              <ChevronRight className="h-4 w-4 text-primary" />
                            </>
                          )}
                        </div>
                      </CardContent>
                    </Card>
                  ))}
                </div>
                <div className="pt-1 border-t border-primary/20">
                  <p className="text-[11px] text-center text-muted-foreground">— or create a new sale below —</p>
                </div>
              </div>
            )}

            {storeId && (
              <div>
                <div className="flex items-center justify-between mb-2">
                  <Label>Products</Label>
                  <Button type="button" variant="outline" size="sm" onClick={addItem}><Plus className="h-3 w-3 mr-1" />Add</Button>
                </div>
                {(!availableProducts || availableProducts.length === 0) && (
                  <p className="text-xs text-muted-foreground py-2">No products available for this store type. Configure the product access matrix first.</p>
                )}
                <div className="space-y-2">
                  {items.map((item, idx) => (
                    <div key={idx} className="space-y-1">
                      <div className="flex items-center gap-2">
                        <Select value={item.product_id} onValueChange={(v) => updateItem(idx, "product_id", v)}>
                          <SelectTrigger className="flex-1"><SelectValue placeholder="Product" /></SelectTrigger>
                          <SelectContent>
                            {availableProducts?.map((p: any) => (
                              <SelectItem key={p.id} value={p.id}>{p.name} ({p.sku})</SelectItem>
                            ))}
                          </SelectContent>
                        </Select>
                        <Input type="number" min={1} value={item.quantity} onChange={(e) => updateItem(idx, "quantity", Number(e.target.value))} className="w-16" placeholder="Qty" />
                        <Input type="number" value={item.unit_price} onChange={(e) => updateItem(idx, "unit_price", Number(e.target.value))} className={`w-24 ${!canOverridePrice ? "bg-muted cursor-not-allowed" : ""}`} placeholder="Price" readOnly={!canOverridePrice} title={!canOverridePrice ? "Price override not allowed" : undefined} />
                        {items.length > 1 && (
                          <Button type="button" variant="ghost" size="icon" onClick={() => removeItem(idx)}><Trash2 className="h-4 w-4 text-destructive" /></Button>
                        )}
                      </div>
                      {item.product_id && availableProducts && (
                        <p className="text-[11px] text-muted-foreground pl-1">
                          {(() => {
                            const p = availableProducts.find((pr: any) => pr.id === item.product_id);
                            return p ? `₹${p.effectivePrice.toLocaleString()} ${getPriceLabel(p)}` : "";
                          })()}
                        </p>
                      )}
                    </div>
                  ))}
                </div>
              </div>
            )}

            <div className="rounded-lg border bg-muted/30 p-3 space-y-1 text-sm">
              <div className="flex justify-between"><span>Total</span><span className="font-semibold">₹{totalAmount.toLocaleString()}</span></div>
            </div>

            <div className="grid grid-cols-2 gap-4">
              <div><Label>Cash (₹)</Label><Input type="number" value={cashAmount} onChange={(e) => setCashAmount(e.target.value)} className="mt-1" placeholder="0" /></div>
              <div><Label>UPI (₹)</Label><Input type="number" value={upiAmount} onChange={(e) => setUpiAmount(e.target.value)} className="mt-1" placeholder="0" /></div>
            </div>

            <div className="rounded-lg border bg-muted/30 p-3 space-y-1 text-sm">
              <div className="flex justify-between"><span>Payment</span><span>₹{(cash + upi).toLocaleString()}</span></div>
              <div className="flex justify-between font-semibold"><span>New Outstanding</span><span className={newOutstanding > oldOutstanding ? "text-destructive" : "text-success"}>₹{newOutstanding.toLocaleString()}</span></div>
              {creditLimitInfo && creditLimitInfo.limit > 0 && (
                <div className="flex justify-between text-xs"><span>Credit Limit ({creditLimitInfo.source})</span><span>₹{creditLimitInfo.limit.toLocaleString()}</span></div>
              )}
              {isPosUser && (cash + upi) !== totalAmount && totalAmount > 0 && (
                <p className="text-xs text-destructive mt-1">⚠ POS sales require full payment (Cash + UPI = Total)</p>
              )}
            </div>

            {creditExceeded && (
              <div className="rounded-lg border border-destructive bg-destructive/10 p-3 text-sm text-destructive">
                🚫 <strong>Credit limit exceeded!</strong> New outstanding (₹{newOutstanding.toLocaleString()}) exceeds the {creditLimitInfo?.source} credit limit of ₹{creditLimitInfo?.limit.toLocaleString()}. Increase payment or reduce items.
              </div>
            )}
            {creditWarning && (
              <div className="rounded-lg border border-yellow-500/50 bg-yellow-500/10 p-3 text-sm text-yellow-700 dark:text-yellow-400">
                ⚠️ Outstanding approaching credit limit ({Math.round((newOutstanding / creditLimitInfo!.limit) * 100)}% used).
              </div>
            )}

            <Button type="submit" className="w-full" disabled={saving || (!!creditExceeded && !isAdmin)}>
              {saving && <Loader2 className="mr-2 h-4 w-4 animate-spin" />}
              Record Sale
            </Button>
          </form>
        </DialogContent>
      </Dialog>

      {/* Receipt Modal */}
      <SaleReceipt
        saleId={receiptSaleId || ""}
        open={!!receiptSaleId}
        onClose={() => setReceiptSaleId(null)}
      />

      {/* Order Fulfillment Dialog */}
      <OrderFulfillmentDialog
        order={fulfillOrder}
        open={!!fulfillOrder}
        onOpenChange={(open) => { if (!open) setFulfillOrder(null); }}
        onFulfilled={() => {
          qc.invalidateQueries({ queryKey: ["orders"] });
          qc.invalidateQueries({ queryKey: ["sales"] });
          qc.invalidateQueries({ queryKey: ["pending-orders-for-store"] });
        }}
      />
    </div>
  );
};

export default Sales;

import { useParams, useNavigate } from "react-router-dom";
import { useQuery, useQueryClient } from "@tanstack/react-query";
import { supabase } from "@/integrations/supabase/client";
import { DataTable } from "@/components/shared/DataTable";
import { Avatar, AvatarFallback, AvatarImage } from "@/components/ui/avatar";
import { StatusBadge } from "@/components/shared/StatusBadge";
import { StatCard } from "@/components/shared/StatCard";
import { Tabs, TabsContent, TabsList, TabsTrigger } from "@/components/ui/tabs";
import { Card, CardContent } from "@/components/ui/card";
import { Separator } from "@/components/ui/separator";
import { Badge } from "@/components/ui/badge";
import { Switch } from "@/components/ui/switch";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import {
  Dialog, DialogContent, DialogHeader, DialogTitle, DialogFooter,
} from "@/components/ui/dialog";
import {
  Loader2, ArrowLeft, DollarSign, ShoppingCart, Banknote,
  MapPin, Store as StoreIcon, Phone,
  Pencil, X, Save, AlertTriangle, ScanLine, Trash2, Scale, ArrowRightLeft, Package, ShieldCheck, FileText,
} from "lucide-react";
import {
  Select, SelectContent, SelectItem, SelectTrigger, SelectValue,
} from "@/components/ui/select";
import { Button } from "@/components/ui/button";
import { useState } from "react";
import { toast } from "sonner";
import { useAuth } from "@/contexts/AuthContext";
import { usePermission } from "@/hooks/usePermission";
import { parseUpiQr } from "@/lib/upiParser";
import { StoreLedger } from "@/components/stores/StoreLedger";
import { logActivity } from "@/lib/activityLogger";
import { ImageUpload } from "@/components/shared/ImageUpload";
import { KycReviewDialog } from "@/components/customers/KycReviewDialog";
import { CustomerStatement } from "@/components/reports/CustomerStatement";

const StoreDetail = () => {
  const { id } = useParams<{ id: string }>();
  const navigate = useNavigate();
  const qc = useQueryClient();
  const { role, user } = useAuth();
  const canEdit = role === "super_admin" || role === "manager";
  const { allowed: canEditBalance } = usePermission("edit_balance");

  const [editing, setEditing] = useState(false);
  const [saving, setSaving] = useState(false);
  const [toggling, setToggling] = useState(false);
  const [showQrScanner, setShowQrScanner] = useState(false);
  const [showAdjustBalance, setShowAdjustBalance] = useState(false);
  const [showTransfer, setShowTransfer] = useState(false);
  const [showStatement, setShowStatement] = useState(false);
  const [showKycDialog, setShowKycDialog] = useState(false);
  const [transferCustomerId, setTransferCustomerId] = useState("");
  const [transferSaving, setTransferSaving] = useState(false);
  const [adjustSaving, setAdjustSaving] = useState(false);
  const [newBalanceInput, setNewBalanceInput] = useState("");
  const [adjustReason, setAdjustReason] = useState("");
  const [photoUrl, setPhotoUrl] = useState<string | null>(null);
  const [form, setForm] = useState({
    name: "",
    phone: "",
    alternate_phone: "",
    street: "",
    area: "",
    city: "",
    district: "",
    state: "",
    pincode: "",
    store_type_id: "",
    route_id: "",
  });

  const { data: store, isLoading } = useQuery({
    queryKey: ["store", id],
    queryFn: async () => {
      const { data, error } = await supabase
        .from("stores")
        .select("*, customers(id, name, is_active, kyc_status, kyc_selfie_url, kyc_aadhar_front_url, kyc_aadhar_back_url, kyc_rejection_reason, kyc_submitted_at, kyc_verified_at), store_types(name, credit_limit_kyc, credit_limit_no_kyc), routes(name)")
        .eq("id", id!)
        .maybeSingle();
      if (error) throw error;
      return data;
    },
    enabled: !!id,
  });

  // Customer list for transfer
  const { data: allCustomers } = useQuery({
    queryKey: ["customers-for-transfer"],
    queryFn: async () => {
      const { data } = await supabase.from("customers").select("id, name, display_id").eq("is_active", true).order("name");
      return data || [];
    },
    enabled: canEdit,
  });

  const { data: allRoutes } = useQuery({
    queryKey: ["routes-for-edit"],
    queryFn: async () => {
      const { data } = await supabase.from("routes").select("id, name").order("name");
      return data || [];
    },
    enabled: canEdit,
  });

  const { data: allStoreTypes } = useQuery({
    queryKey: ["store-types-for-edit"],
    queryFn: async () => {
      const { data } = await supabase.from("store_types").select("id, name").order("name");
      return data || [];
    },
    enabled: canEdit,
  });

  // Products with pricing hierarchy for the Products tab
  const { data: storeProducts } = useQuery({
    queryKey: ["store-products-tab", id, store?.store_type_id],
    queryFn: async () => {
      if (!store?.store_type_id) {
        const { data } = await supabase.from("products").select("id, name, sku, base_price").eq("is_active", true).order("name");
        return data || [];
      }
      const { data: accessData } = await supabase
        .from("store_type_products")
        .select("product_id, products(id, name, sku, base_price)")
        .eq("store_type_id", store.store_type_id);
      if (accessData && accessData.length > 0) {
        return accessData.map((a: any) => a.products).filter(Boolean);
      }
      const { data } = await supabase.from("products").select("id, name, sku, base_price").eq("is_active", true).order("name");
      return data || [];
    },
    enabled: !!store,
  });

  const { data: storeTypePricing } = useQuery({
    queryKey: ["store-type-pricing-tab", store?.store_type_id],
    queryFn: async () => {
      const { data } = await supabase.from("store_type_pricing").select("product_id, price").eq("store_type_id", store!.store_type_id!);
      const map: Record<string, number> = {};
      data?.forEach((p) => { map[p.product_id] = Number(p.price); });
      return map;
    },
    enabled: !!store?.store_type_id,
  });

  const { data: storePricingMap } = useQuery({
    queryKey: ["store-pricing-tab", id],
    queryFn: async () => {
      const { data } = await supabase.from("store_pricing").select("product_id, price").eq("store_id", id!);
      const map: Record<string, number> = {};
      data?.forEach((p) => { map[p.product_id] = Number(p.price); });
      return map;
    },
    enabled: !!id,
  });

  const getEffectivePrice = (productId: string, basePrice: number): { price: number; label: string } => {
    if (storePricingMap && productId in storePricingMap) return { price: storePricingMap[productId], label: "store" };
    if (storeTypePricing && productId in storeTypePricing) return { price: storeTypePricing[productId], label: "type" };
    return { price: basePrice, label: "base" };
  };

  const handleTransfer = async () => {
    if (!store || !id || !transferCustomerId) return;
    if (transferCustomerId === store.customer_id) {
      toast.error("Store already belongs to this customer");
      return;
    }
    setTransferSaving(true);
    const { error } = await supabase.from("stores").update({ customer_id: transferCustomerId }).eq("id", id);
    setTransferSaving(false);
    if (error) { toast.error(error.message); return; }
    const newCust = allCustomers?.find((c) => c.id === transferCustomerId);
    logActivity(user!.id, `Transferred store to ${newCust?.name}`, "store", store.display_id, id);
    toast.success(`Store transferred to ${newCust?.name}`);
    setShowTransfer(false);
    setTransferCustomerId("");
    qc.invalidateQueries({ queryKey: ["store", id] });
    qc.invalidateQueries({ queryKey: ["stores"] });
  };

  const { data: sales } = useQuery({
    queryKey: ["store-sales", id],
    queryFn: async () => {
      const { data } = await supabase.from("sales").select("*, stores(name)").eq("store_id", id!).order("created_at", { ascending: false }).limit(50);
      return data || [];
    },
    enabled: !!id,
  });

  const { data: profiles } = useQuery({
    queryKey: ["profiles"],
    queryFn: async () => {
      const { data } = await supabase.from("profiles").select("user_id, full_name, avatar_url");
      return data || [];
    },
  });

  const profileMap = new Map(profiles?.map((p) => [p.user_id, p]) || []);
  const getRecorder = (uid: string) => profileMap.get(uid);


  const { data: transactions } = useQuery({
    queryKey: ["store-transactions", id],
    queryFn: async () => {
      const { data } = await supabase.from("transactions").select("*").eq("store_id", id!).order("created_at", { ascending: false }).limit(50);
      return data || [];
    },
    enabled: !!id,
  });

  const { data: orders } = useQuery({
    queryKey: ["store-orders", id],
    queryFn: async () => {
      const { data } = await supabase.from("orders").select("*").eq("store_id", id!).order("created_at", { ascending: false }).limit(50);
      return data || [];
    },
    enabled: !!id,
  });

  const { data: visits } = useQuery({
    queryKey: ["store-visits", id],
    queryFn: async () => {
      const { data } = await supabase.from("store_visits").select("*, route_sessions(routes(name))").eq("store_id", id!).order("visited_at", { ascending: false }).limit(50);
      return data || [];
    },
    enabled: !!id,
  });

  const { data: balanceAdjustments } = useQuery({
    queryKey: ["balance-adjustments", id],
    queryFn: async () => {
      const { data } = await supabase.from("balance_adjustments").select("*").eq("store_id", id!).order("created_at", { ascending: false });
      return data || [];
    },
    enabled: !!id,
  });

  const { data: qrCodes } = useQuery({
    queryKey: ["store-qr-codes", id],
    queryFn: async () => {
      const { data } = await supabase.from("store_qr_codes").select("*").eq("store_id", id!).order("created_at", { ascending: false });
      return data || [];
    },
    enabled: !!id,
  });


  const handleQrScanned = async (rawData: string) => {
    const upi = parseUpiQr(rawData);
    if (!upi) { toast.error("Not a valid UPI QR code"); return; }
    const { error } = await supabase.from("store_qr_codes").insert({
      store_id: id!,
      upi_id: upi.pa,
      payee_name: upi.pn || null,
      raw_data: rawData,
    });
    if (error) {
      if (error.message.includes("duplicate")) toast.error("This QR is already linked to a store");
      else toast.error(error.message);
      return;
    }
    toast.success("QR code linked to store");
    qc.invalidateQueries({ queryKey: ["store-qr-codes", id] });
  };

  const handleDeleteQr = async (qrId: string) => {
    const { error } = await supabase.from("store_qr_codes").delete().eq("id", qrId);
    if (error) { toast.error(error.message); return; }
    toast.success("QR code removed");
    qc.invalidateQueries({ queryKey: ["store-qr-codes", id] });
  };

  const handleAdjustBalance = async () => {
    if (!store || !id || !user) return;
    const newBal = parseFloat(newBalanceInput);
    if (isNaN(newBal)) { toast.error("Enter a valid amount"); return; }
    const oldBal = Number(store.outstanding);
    if (newBal === oldBal) { toast.error("New balance is the same as current"); return; }

    setAdjustSaving(true);
    const adjustment = newBal - oldBal;

    const { error } = await supabase.from("balance_adjustments").insert({
      store_id: id,
      customer_id: store.customer_id,
      old_outstanding: oldBal,
      new_outstanding: newBal,
      adjustment_amount: adjustment,
      reason: adjustReason || null,
      adjusted_by: user.id,
    });

    if (error) { toast.error(error.message); setAdjustSaving(false); return; }

    await supabase.from("stores").update({ outstanding: newBal }).eq("id", id);
    logActivity(user.id, "Balance adjustment", "store", store.display_id, id, { old: oldBal, new: newBal, adjustment });

    toast.success("Balance adjusted");
    setAdjustSaving(false);
    setShowAdjustBalance(false);
    setNewBalanceInput("");
    setAdjustReason("");
    qc.invalidateQueries({ queryKey: ["store", id] });
    qc.invalidateQueries({ queryKey: ["balance-adjustments", id] });
  };

  const startEditing = () => {
    if (!store || !store.is_active) return;
    setForm({
      name: store.name || "",
      phone: store.phone || "",
      alternate_phone: store.alternate_phone || "",
      street: store.street || "",
      area: store.area || "",
      city: store.city || "",
      district: store.district || "",
      state: store.state || "",
      pincode: store.pincode || "",
      store_type_id: store.store_type_id || "",
      route_id: store.route_id || "",
    });
    setPhotoUrl(store.photo_url || null);
    setEditing(true);
  };

  const handleSave = async () => {
    if (!id) return;
    setSaving(true);
    const address = [form.street, form.area, form.city, form.district, form.state, form.pincode].filter(Boolean).join(", ");
    const { error } = await supabase
      .from("stores")
      .update({
        name: form.name,
        phone: form.phone || null,
        alternate_phone: form.alternate_phone || null,
        street: form.street || null,
        area: form.area || null,
        city: form.city || null,
        district: form.district || null,
        state: form.state || null,
        pincode: form.pincode || null,
        address: address || null,
        store_type_id: form.store_type_id || null,
        route_id: form.route_id || null,
        photo_url: photoUrl || null,
      })
      .eq("id", id);
    setSaving(false);
    if (error) { toast.error(error.message); return; }
    toast.success("Store updated");
    setEditing(false);
    qc.invalidateQueries({ queryKey: ["store", id] });
    qc.invalidateQueries({ queryKey: ["stores"] });
  };

  const handleToggleActive = async () => {
    if (!store || !id) return;
    // Prevent activating store if customer is inactive
    const customerActive = (store as any).customers?.is_active;
    if (!store.is_active && customerActive === false) {
      toast.error("Cannot activate store: the customer is inactive. Activate the customer first.");
      return;
    }
    const newVal = !store.is_active;
    setToggling(true);
    const { error } = await supabase.from("stores").update({ is_active: newVal }).eq("id", id);
    setToggling(false);
    if (error) { toast.error(error.message); return; }
    toast.success(`Store ${newVal ? "activated" : "deactivated"}`);
    setEditing(false);
    qc.invalidateQueries({ queryKey: ["store", id] });
    qc.invalidateQueries({ queryKey: ["stores"] });
    qc.invalidateQueries({ queryKey: ["customer-stores", store.customer_id] });
  };

  if (isLoading) {
    return <div className="flex items-center justify-center py-20"><Loader2 className="h-8 w-8 animate-spin text-primary" /></div>;
  }

  if (!store) {
    return <div className="text-center py-20 text-muted-foreground">Store not found</div>;
  }

  const isInactive = !store.is_active;
  const totalSales = sales?.reduce((s, r) => s + Number(r.total_amount), 0) || 0;
  const totalCollected = transactions?.reduce((s, r) => s + Number(r.total_amount), 0) || 0;
  const fullAddress = [store.street, store.area, store.city, store.district, store.state, store.pincode].filter(Boolean).join(", ") || store.address || "Not provided";




  const orderColumns = [
    { header: "Order ID", accessor: "display_id" as const, className: "font-mono text-xs" },
    { header: "Type", accessor: "order_type" as const, className: "hidden sm:table-cell" },
    { header: "Source", accessor: "source" as const, className: "hidden sm:table-cell" },
    { header: "Status", accessor: (row: any) => <StatusBadge status={row.status === "delivered" ? "active" : row.status === "cancelled" ? "rejected" : "pending"} label={row.status} /> },
    { header: "Date", accessor: (row: any) => new Date(row.created_at).toLocaleDateString("en-IN"), className: "text-muted-foreground text-xs" },
  ];

  const visitColumns = [
    { header: "Route", accessor: (row: any) => (row.route_sessions as any)?.routes?.name || "—" },
    { header: "Notes", accessor: (row: any) => row.notes || "—", className: "text-sm hidden sm:table-cell" },
    { header: "Location", accessor: (row: any) => row.lat ? `${row.lat.toFixed(4)}, ${row.lng.toFixed(4)}` : "—", className: "text-xs text-muted-foreground hidden md:table-cell" },
    { header: "Visited At", accessor: (row: any) => new Date(row.visited_at).toLocaleString("en-IN", { dateStyle: "short", timeStyle: "short" }), className: "text-muted-foreground text-xs" },
  ];

  // Unified compact card renderer
  const renderCompactCard = (type: "sale" | "txn" | "order" | "visit") => (row: any) => {
    const p = type !== "visit" ? getRecorder(row.recorded_by || row.created_by) : null;
    return (
      <div className="rounded-xl border bg-card px-3 py-2.5 shadow-sm">
        <div className="flex items-center justify-between">
          <span className="font-mono text-[11px] text-muted-foreground">
            {type === "visit" ? ((row.route_sessions as any)?.routes?.name || "Visit") : row.display_id}
          </span>
          <span className="text-[11px] text-muted-foreground">
            {new Date(type === "visit" ? row.visited_at : row.created_at).toLocaleDateString("en-IN")}
          </span>
        </div>

        {type === "sale" && (
          <>
            <div className="flex items-center justify-between mt-1.5">
              <span className="text-sm font-bold text-foreground">₹{Number(row.total_amount).toLocaleString()}</span>
              <span className={`text-xs font-medium ${Number(row.outstanding_amount) > 0 ? "text-destructive" : "text-muted-foreground"}`}>
                Due: ₹{Number(row.outstanding_amount).toLocaleString()}
              </span>
            </div>
            <div className="flex items-center justify-between mt-1.5 text-[11px] text-muted-foreground">
              <span>Cash ₹{Number(row.cash_amount).toLocaleString()} · UPI ₹{Number(row.upi_amount).toLocaleString()}</span>
              {p && (
                <div className="flex items-center gap-1">
                  <Avatar className="h-4 w-4">
                    <AvatarImage src={p?.avatar_url || undefined} />
                    <AvatarFallback className="text-[8px] bg-primary/10 text-primary">{(p?.full_name || "?").charAt(0)}</AvatarFallback>
                  </Avatar>
                  <span>{p?.full_name || "—"}</span>
                </div>
              )}
            </div>
          </>
        )}

        {type === "txn" && (
          <>
            <div className="flex items-center justify-between mt-1.5">
              <span className="text-sm font-bold text-foreground">₹{Number(row.total_amount).toLocaleString()}</span>
              <span className="text-xs text-muted-foreground">
                Bal: ₹{Number(row.old_outstanding).toLocaleString()} → ₹{Number(row.new_outstanding).toLocaleString()}
              </span>
            </div>
            <div className="flex items-center justify-between mt-1.5 text-[11px] text-muted-foreground">
              <span>Cash ₹{Number(row.cash_amount).toLocaleString()} · UPI ₹{Number(row.upi_amount).toLocaleString()}</span>
              {row.notes && <span className="truncate max-w-[120px]">{row.notes}</span>}
            </div>
          </>
        )}

        {type === "order" && (
          <>
            <div className="flex items-center justify-between mt-1.5">
              <StatusBadge status={row.status === "delivered" ? "active" : row.status === "cancelled" ? "rejected" : "pending"} label={row.status} />
              <span className="text-xs text-muted-foreground capitalize">{row.order_type} · {row.source}</span>
            </div>
            {row.requirement_note && (
              <p className="text-[11px] text-muted-foreground mt-1.5 truncate">{row.requirement_note}</p>
            )}
          </>
        )}

        {type === "visit" && (
          <>
            <div className="flex items-center justify-between mt-1.5">
              <span className="text-sm font-medium text-foreground">
                {new Date(row.visited_at).toLocaleTimeString("en-IN", { hour: "2-digit", minute: "2-digit" })}
              </span>
              {row.lat && <span className="text-[11px] text-muted-foreground">{row.lat.toFixed(4)}, {row.lng?.toFixed(4)}</span>}
            </div>
            {row.notes && <p className="text-[11px] text-muted-foreground mt-1.5 truncate">{row.notes}</p>}
          </>
        )}
      </div>
    );
  };

  return (
    <div className="space-y-6 animate-fade-in">
      <Button variant="ghost" size="sm" onClick={() => navigate("/stores")} className="gap-1.5 text-muted-foreground hover:text-foreground -ml-2">
        <ArrowLeft className="h-4 w-4" />
        Stores
      </Button>

      {isInactive && (
        <div className="flex items-center gap-3 rounded-xl border border-destructive/30 bg-destructive/5 p-4">
          <AlertTriangle className="h-5 w-5 text-destructive shrink-0" />
          <div>
            <p className="text-sm font-medium text-destructive">This store is inactive</p>
            <p className="text-xs text-muted-foreground mt-0.5">No sales, orders, or modifications can be made. Activate the store to resume operations.</p>
          </div>
        </div>
      )}

      <Card className={`overflow-hidden ${isInactive ? "opacity-75" : ""}`}>
        {/* Banner */}
        <div className="h-24 sm:h-32 bg-gradient-to-br from-primary/20 via-accent/30 to-primary/10 relative">
          {store.lat && store.lng && (
            <a
              href={`https://www.google.com/maps?q=${store.lat},${store.lng}`}
              target="_blank" rel="noopener noreferrer"
              className="absolute top-3 right-3 flex items-center gap-1.5 text-xs font-medium bg-card/80 backdrop-blur-sm rounded-full px-3 py-1.5 text-primary hover:bg-card transition-colors shadow-sm"
            >
              <MapPin className="h-3.5 w-3.5" /> Map
            </a>
          )}
        </div>

        <CardContent className="relative px-4 sm:px-6 pb-5 -mt-10 sm:-mt-12">
          {/* Identity row: photo + name/id */}
          <div className="flex items-end gap-4">
            <div className="h-20 w-20 sm:h-24 sm:w-24 rounded-xl border-4 border-card bg-muted flex items-center justify-center overflow-hidden shadow-md shrink-0">
              {store.photo_url ? (
                <img src={store.photo_url} alt={store.name} loading="lazy" className="w-full h-full object-cover" />
              ) : (
                <StoreIcon className="h-10 w-10 text-muted-foreground/40" />
              )}
            </div>
            <div className="flex-1 min-w-0 pb-1">
              <div className="flex flex-wrap items-center gap-2">
                <h1 className="text-xl sm:text-2xl font-bold text-foreground leading-tight">{store.name}</h1>
                <StatusBadge status={store.is_active ? "active" : "inactive"} />
              </div>
              <div className="flex flex-wrap items-center gap-2 mt-1">
                <span className="text-sm text-muted-foreground font-mono">{store.display_id}</span>
                {(store as any).store_types?.name && (
                  <Badge variant="secondary" className="text-xs">{(store as any).store_types.name}</Badge>
                )}
              </div>
            </div>
          </div>

          {/* Action bar — separate row, always wraps cleanly */}
          <div className="mt-3 flex flex-wrap items-center gap-2">
            {canEdit && (
              <>
                <div className="flex items-center gap-2 rounded-full border bg-muted/50 px-3 py-1.5">
                  <Label htmlFor="store-active-toggle" className="text-xs font-medium text-muted-foreground cursor-pointer select-none">
                    {store.is_active ? "Active" : "Inactive"}
                  </Label>
                  <Switch
                    id="store-active-toggle"
                    checked={store.is_active}
                    onCheckedChange={handleToggleActive}
                    disabled={toggling}
                  />
                </div>
                {!isInactive && (
                  !editing ? (
                    <Button variant="outline" size="sm" onClick={startEditing} className="gap-1.5 rounded-full h-8">
                      <Pencil className="h-3.5 w-3.5" /> Edit
                    </Button>
                  ) : (
                    <div className="flex gap-1.5">
                      <Button variant="ghost" size="sm" onClick={() => setEditing(false)} disabled={saving} className="rounded-full h-8 w-8 p-0">
                        <X className="h-4 w-4" />
                      </Button>
                      <Button size="sm" onClick={handleSave} disabled={saving} className="gap-1.5 rounded-full h-8">
                        {saving ? <Loader2 className="h-3.5 w-3.5 animate-spin" /> : <Save className="h-3.5 w-3.5" />}
                        Save
                      </Button>
                    </div>
                  )
                )}
              </>
            )}
            {canEditBalance && !isInactive && (
              <Button variant="outline" size="sm" onClick={() => { setNewBalanceInput(String(store.outstanding)); setShowAdjustBalance(true); }} className="gap-1.5 rounded-full h-8">
                <Scale className="h-3.5 w-3.5" /> Adjust Balance
              </Button>
            )}
            {canEdit && (
              <Button variant="outline" size="sm" onClick={() => setShowTransfer(true)} className="gap-1.5 rounded-full h-8">
                <ArrowRightLeft className="h-3.5 w-3.5" /> Transfer
              </Button>
            )}
            <Button variant="outline" size="sm" onClick={() => setShowStatement(true)} className="gap-1.5 rounded-full h-8">
              <FileText className="h-3.5 w-3.5" /> Statement
            </Button>
          </div>

          <Separator className="my-4" />

          {editing ? (
            <div className="space-y-4">
              <div className="flex items-start gap-4">
                <ImageUpload folder="stores" currentUrl={photoUrl} onUploaded={setPhotoUrl} onRemoved={() => setPhotoUrl(null)} size="lg" />
                <div className="flex-1 grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-4">
                  <div className="space-y-1.5"><Label className="text-xs">Store Name</Label><Input value={form.name} onChange={(e) => setForm({ ...form, name: e.target.value })} /></div>
                  <div className="space-y-1.5"><Label className="text-xs">Phone</Label><Input value={form.phone} onChange={(e) => setForm({ ...form, phone: e.target.value })} /></div>
                  <div className="space-y-1.5"><Label className="text-xs">Alt. Phone</Label><Input value={form.alternate_phone} onChange={(e) => setForm({ ...form, alternate_phone: e.target.value })} /></div>
                  <div className="space-y-1.5">
                    <Label className="text-xs">Store Type</Label>
                    <Select value={form.store_type_id} onValueChange={(v) => setForm({ ...form, store_type_id: v === "__none" ? "" : v })}>
                      <SelectTrigger className="h-9 text-sm"><SelectValue placeholder="Select type" /></SelectTrigger>
                      <SelectContent>
                        <SelectItem value="__none">None</SelectItem>
                        {allStoreTypes?.map((t) => <SelectItem key={t.id} value={t.id}>{t.name}</SelectItem>)}
                      </SelectContent>
                    </Select>
                  </div>
                  <div className="space-y-1.5">
                    <Label className="text-xs">Route</Label>
                    <Select value={form.route_id} onValueChange={(v) => setForm({ ...form, route_id: v === "__none" ? "" : v })}>
                      <SelectTrigger className="h-9 text-sm"><SelectValue placeholder="Select route" /></SelectTrigger>
                      <SelectContent>
                        <SelectItem value="__none">None</SelectItem>
                        {allRoutes?.map((r) => <SelectItem key={r.id} value={r.id}>{r.name}</SelectItem>)}
                      </SelectContent>
                    </Select>
                  </div>
                  <div className="space-y-1.5"><Label className="text-xs">Street</Label><Input value={form.street} onChange={(e) => setForm({ ...form, street: e.target.value })} /></div>
                  <div className="space-y-1.5"><Label className="text-xs">Area</Label><Input value={form.area} onChange={(e) => setForm({ ...form, area: e.target.value })} /></div>
                  <div className="space-y-1.5"><Label className="text-xs">City</Label><Input value={form.city} onChange={(e) => setForm({ ...form, city: e.target.value })} /></div>
                  <div className="space-y-1.5"><Label className="text-xs">District</Label><Input value={form.district} onChange={(e) => setForm({ ...form, district: e.target.value })} /></div>
                  <div className="space-y-1.5"><Label className="text-xs">State</Label><Input value={form.state} onChange={(e) => setForm({ ...form, state: e.target.value })} /></div>
                  <div className="space-y-1.5"><Label className="text-xs">Pincode</Label><Input value={form.pincode} onChange={(e) => setForm({ ...form, pincode: e.target.value })} /></div>
                </div>
              </div>
            </div>
          ) : (
            <div className="space-y-3">
              <div className="grid grid-cols-2 sm:grid-cols-3 lg:grid-cols-6 gap-x-6 gap-y-2">
                <InfoItem label="Customer" value={(store as any).customers?.name || "—"} />
                <InfoItem label="Route" value={(store as any).routes?.name || "Not assigned"} />
                <InfoItem label="Phone" value={store.phone || "Not provided"} />
                <InfoItem label="Address" value={fullAddress} />
                <InfoItem label="Opening Bal." value={`₹${Number(store.opening_balance).toLocaleString()}`} />
                <InfoItem label="Created" value={new Date(store.created_at).toLocaleDateString("en-IN", { year: "numeric", month: "short", day: "numeric" })} />
              </div>
              {/* Credit Limits — visible to all staff (from store_types) */}
              <div className="flex flex-wrap gap-4 pt-1 border-t border-border/50">
                <div className="flex items-center gap-2">
                  <span className="text-[10px] text-muted-foreground uppercase tracking-wider">Credit (No KYC)</span>
                  <span className="text-sm font-semibold text-foreground">₹{Number((store as any).store_types?.credit_limit_no_kyc || 0).toLocaleString()}</span>
                </div>
                <div className="flex items-center gap-2">
                  <span className="text-[10px] text-muted-foreground uppercase tracking-wider">Credit (KYC Done)</span>
                  <span className="text-sm font-semibold text-success">₹{Number((store as any).store_types?.credit_limit_kyc || 0).toLocaleString()}</span>
                </div>
                {/* Customer KYC status */}
                {(() => {
                  const cust = (store as any).customers;
                  if (!cust) return null;
                  const kycStatus: string = cust.kyc_status || "not_requested";
                  return (
                    <div className="flex items-center gap-2 ml-auto">
                      <ShieldCheck className="h-3.5 w-3.5 text-muted-foreground" />
                      <span className="text-[10px] text-muted-foreground uppercase tracking-wider">Customer KYC:</span>
                      <Badge
                        variant="outline"
                        className={
                          kycStatus === "verified" ? "border-emerald-300 text-emerald-600 bg-emerald-50" :
                          kycStatus === "pending" ? "border-amber-300 text-amber-600 bg-amber-50" :
                          kycStatus === "rejected" ? "border-red-300 text-red-600 bg-red-50" :
                          "text-muted-foreground"
                        }
                      >
                        {kycStatus.replace("_", " ")}
                      </Badge>
                      {canEdit && (kycStatus === "pending" || kycStatus === "rejected") && (
                        <Button size="sm" variant="outline" className="h-6 text-[10px] px-2 rounded-full" onClick={() => setShowKycDialog(true)}>
                          Review KYC
                        </Button>
                      )}
                    </div>
                  );
                })()}
              </div>
            </div>
          )}
        </CardContent>
      </Card>

      <div className="grid grid-cols-2 lg:grid-cols-4 gap-3 sm:gap-4">
        <StatCard title="Total Sales" value={`₹${totalSales.toLocaleString()}`} icon={DollarSign} iconColor="primary" />
        <StatCard title="Collections" value={`₹${totalCollected.toLocaleString()}`} icon={Banknote} iconColor="success" />
        <StatCard title="Outstanding" value={`₹${Number(store.outstanding).toLocaleString()}`} icon={Banknote} iconColor="warning" />
        <StatCard title="Orders" value={String(orders?.length || 0)} icon={ShoppingCart} iconColor="info" />
      </div>

      <Tabs defaultValue="ledger">
        <TabsList className="w-full sm:w-auto overflow-x-auto">
          <TabsTrigger value="ledger" className="text-xs sm:text-sm">Ledger ({(sales?.length || 0) + (transactions?.length || 0)})</TabsTrigger>
          <TabsTrigger value="orders" className="text-xs sm:text-sm">Orders ({orders?.length || 0})</TabsTrigger>
          <TabsTrigger value="products" className="text-xs sm:text-sm">
            <Package className="h-3.5 w-3.5 mr-1" />Products ({storeProducts?.length || 0})
          </TabsTrigger>
          <TabsTrigger value="visits" className="text-xs sm:text-sm">Visits ({visits?.length || 0})</TabsTrigger>
          <TabsTrigger value="qr" className="text-xs sm:text-sm">QR ({qrCodes?.length || 0})</TabsTrigger>
        </TabsList>
        <TabsContent value="ledger" className="mt-4">
          <StoreLedger
            sales={sales || []}
            transactions={transactions || []}
            balanceAdjustments={balanceAdjustments || []}
            openingBalance={Number(store.opening_balance)}
            storeCreatedAt={store.created_at}
            profileMap={profileMap}
          />
        </TabsContent>
        <TabsContent value="orders" className="mt-4">
          {(orders?.length || 0) === 0 ? <EmptyTab label="No orders yet" /> : (
            <DataTable columns={orderColumns} data={orders || []} searchKey="display_id" searchPlaceholder="Search orders..."
              renderMobileCard={renderCompactCard("order")} />
          )}
        </TabsContent>
        <TabsContent value="products" className="mt-4">
          {(!storeProducts || storeProducts.length === 0) ? (
            <EmptyTab label="No products assigned to this store type" />
          ) : (
            <div className="space-y-2">
              {storeProducts.map((p: any) => {
                const { price, label } = getEffectivePrice(p.id, Number(p.base_price));
                return (
                  <div key={p.id} className="flex items-center justify-between rounded-lg border bg-card px-4 py-3">
                    <div className="min-w-0 flex-1">
                      <p className="text-sm font-medium truncate">{p.name}</p>
                      <Badge variant="outline" className="text-[10px] mt-0.5">{p.sku}</Badge>
                    </div>
                    <div className="text-right shrink-0 ml-4">
                      <p className="text-sm font-bold">₹{price.toLocaleString()}</p>
                      <span className={`text-[10px] font-medium capitalize px-1.5 py-0.5 rounded-full ${
                        label === "store" ? "bg-primary/10 text-primary" :
                        label === "type" ? "bg-blue-100 text-blue-600 dark:bg-blue-900/30 dark:text-blue-400" :
                        "bg-muted text-muted-foreground"
                      }`}>
                        {label} price
                      </span>
                    </div>
                  </div>
                );
              })}
            </div>
          )}
        </TabsContent>
        <TabsContent value="visits" className="mt-4">
          {(visits?.length || 0) === 0 ? <EmptyTab label="No visits recorded" /> : (
            <DataTable columns={visitColumns} data={visits || []} searchKey="notes" searchPlaceholder="Search..."
              renderMobileCard={renderCompactCard("visit")} />
          )}
        </TabsContent>
        <TabsContent value="qr" className="mt-4">
          <div className="space-y-4">
            {canEdit && (
              <Button variant="outline" size="sm" onClick={() => setShowQrScanner(true)} className="gap-2">
                <ScanLine className="h-4 w-4" /> Scan & Add QR
              </Button>
            )}
            {(qrCodes?.length || 0) === 0 ? <EmptyTab label="No QR codes linked" /> : (
              <div className="space-y-2">
                {qrCodes?.map((qr: any) => (
                  <div key={qr.id} className="flex items-center justify-between rounded-lg border bg-card p-3">
                    <div>
                      <p className="font-mono text-sm">{qr.upi_id}</p>
                      {qr.payee_name && <p className="text-xs text-muted-foreground mt-0.5">{qr.payee_name}</p>}
                      <p className="text-[11px] text-muted-foreground mt-0.5">Added {new Date(qr.created_at).toLocaleDateString("en-IN")}</p>
                    </div>
                    {canEdit && (
                      <Button variant="ghost" size="icon" className="h-8 w-8 text-destructive" onClick={() => handleDeleteQr(qr.id)}>
                        <Trash2 className="h-4 w-4" />
                      </Button>
                    )}
                  </div>
                ))}
              </div>
            )}
          </div>
        </TabsContent>
      </Tabs>
      {/* Adjust Balance Dialog */}
      <Dialog open={showAdjustBalance} onOpenChange={(v) => { setShowAdjustBalance(v); if (!v) { setNewBalanceInput(""); setAdjustReason(""); } }}>
        <DialogContent className="max-w-sm">
          <DialogHeader><DialogTitle>Adjust Balance</DialogTitle></DialogHeader>
          <div className="space-y-4">
            <div>
              <Label className="text-xs text-muted-foreground">Current Outstanding</Label>
              <p className="text-lg font-bold">₹{Number(store?.outstanding || 0).toLocaleString()}</p>
            </div>
            <div>
              <Label>New Outstanding (₹)</Label>
              <Input type="number" value={newBalanceInput} onChange={(e) => setNewBalanceInput(e.target.value)} className="mt-1" />
              {newBalanceInput && !isNaN(parseFloat(newBalanceInput)) && (
                <p className="text-xs mt-1 text-muted-foreground">
                  Adjustment: <span className={parseFloat(newBalanceInput) - Number(store?.outstanding || 0) > 0 ? "text-destructive font-medium" : "text-success font-medium"}>
                    {parseFloat(newBalanceInput) - Number(store?.outstanding || 0) > 0 ? "+" : ""}₹{(parseFloat(newBalanceInput) - Number(store?.outstanding || 0)).toLocaleString()}
                  </span>
                </p>
              )}
            </div>
            <div>
              <Label>Reason</Label>
              <Input value={adjustReason} onChange={(e) => setAdjustReason(e.target.value)} className="mt-1" placeholder="e.g. Correction after physical count" />
            </div>
            <Button onClick={handleAdjustBalance} className="w-full" disabled={adjustSaving}>
              {adjustSaving && <Loader2 className="mr-2 h-4 w-4 animate-spin" />}
              Confirm Adjustment
            </Button>
          </div>
        </DialogContent>
      </Dialog>
      {/* Transfer Store Dialog */}
      <Dialog open={showTransfer} onOpenChange={setShowTransfer}>
        <DialogContent className="max-w-sm">
          <DialogHeader><DialogTitle>Transfer Store</DialogTitle></DialogHeader>
          <p className="text-sm text-muted-foreground">Move <strong>{store?.name}</strong> from <strong>{(store as any)?.customers?.name}</strong> to another customer.</p>
          <div className="space-y-3 mt-2">
            <div>
              <Label>New Customer</Label>
              <Select value={transferCustomerId} onValueChange={setTransferCustomerId}>
                <SelectTrigger className="mt-1"><SelectValue placeholder="Select customer" /></SelectTrigger>
                <SelectContent>
                  {allCustomers?.filter((c) => c.id !== store?.customer_id).map((c) => (
                    <SelectItem key={c.id} value={c.id}>{c.name} ({c.display_id})</SelectItem>
                  ))}
                </SelectContent>
              </Select>
            </div>
          </div>
          <DialogFooter>
            <Button variant="outline" onClick={() => setShowTransfer(false)}>Cancel</Button>
            <Button onClick={handleTransfer} disabled={transferSaving || !transferCustomerId}>
              {transferSaving && <Loader2 className="mr-2 h-4 w-4 animate-spin" />}
              Transfer
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>
      {/* KYC Review Dialog */}
      {canEdit && showKycDialog && (store as any).customers && (
        <KycReviewDialog
          customer={(store as any).customers}
          open={showKycDialog}
          onOpenChange={setShowKycDialog}
          onDone={() => {
            setShowKycDialog(false);
            qc.invalidateQueries({ queryKey: ["store", id] });
          }}
        />
      )}

      {/* Statement Modal */}
      {showStatement && store && (
        <div className="fixed inset-0 z-50 bg-background/80 backdrop-blur-sm overflow-y-auto">
          <div className="container max-w-4xl py-6">
            <CustomerStatement
              customerId={store.customer_id}
              customerName={store.customers?.name || "Customer"}
              storeId={store.id}
              storeName={store.name}
              onClose={() => setShowStatement(false)}
            />
          </div>
        </div>
      )}
    </div>
  );
};

function InfoItem({ label, value }: { label: string; value: string }) {
  return (
    <div className="min-w-0">
      <p className="text-[10px] text-muted-foreground uppercase tracking-wider">{label}</p>
      <p className="text-sm font-medium text-foreground truncate">{value}</p>
    </div>
  );
}

function EmptyTab({ label }: { label: string }) {
  return <div className="rounded-xl border border-dashed bg-card p-10 text-center text-muted-foreground">{label}</div>;
}

export default StoreDetail;

import { PageHeader } from "@/components/shared/PageHeader";
import { DataTable } from "@/components/shared/DataTable";
import { StatusBadge } from "@/components/shared/StatusBadge";
import { Badge } from "@/components/ui/badge";
import { Switch } from "@/components/ui/switch";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { useQuery, useQueryClient } from "@tanstack/react-query";
import { supabase } from "@/integrations/supabase/client";
import { useAuth } from "@/contexts/AuthContext";
import { Loader2, Plus, Pencil, Trash2, ShieldCheck } from "lucide-react";
import { useState } from "react";
import { Dialog, DialogContent, DialogHeader, DialogTitle } from "@/components/ui/dialog";
import { useNavigate } from "react-router-dom";
import {
  AlertDialog,
  AlertDialogAction,
  AlertDialogCancel,
  AlertDialogContent,
  AlertDialogDescription,
  AlertDialogFooter,
  AlertDialogHeader,
  AlertDialogTitle,
} from "@/components/ui/alert-dialog";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { toast } from "sonner";
import { TableSkeleton } from "@/components/shared/TableSkeleton";

const StoreTypes = () => {
  const { role } = useAuth();
  const qc = useQueryClient();
  const isAdmin = role === "super_admin";

  const navigate = useNavigate();

  const [showAdd, setShowAdd] = useState(false);
  const [editingType, setEditingType] = useState<any>(null);
  const [deletingType, setDeletingType] = useState<any>(null);
  const [newTypeName, setNewTypeName] = useState("");
  const [newOrderType, setNewOrderType] = useState("simple");
  const [creditLimitKyc, setCreditLimitKyc] = useState("");
  const [creditLimitNoKyc, setCreditLimitNoKyc] = useState("");
  const [saving, setSaving] = useState(false);
  const [deleting, setDeleting] = useState(false);

  const { data: storeTypes, isLoading } = useQuery({
    queryKey: ["store-types"],
    queryFn: async () => {
      const { data, error } = await supabase.from("store_types").select("*").order("created_at");
      if (error) throw error;
      return data;
    },
  });

  const openEdit = (row: any) => {
    setEditingType(row);
    setNewTypeName(row.name);
    setNewOrderType(row.order_type);
    setCreditLimitKyc(String(row.credit_limit_kyc || 0));
    setCreditLimitNoKyc(String(row.credit_limit_no_kyc || 0));
    setShowAdd(true);
  };

  const handleClose = (open?: boolean) => {
    if (open) return;
    setShowAdd(false);
    setEditingType(null);
    setNewTypeName("");
    setNewOrderType("simple");
    setCreditLimitKyc("");
    setCreditLimitNoKyc("");
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setSaving(true);
    if (editingType) {
      const { error } = await supabase.from("store_types").update({
        name: newTypeName,
        order_type: newOrderType,
        credit_limit_kyc: parseFloat(creditLimitKyc) || 0,
        credit_limit_no_kyc: parseFloat(creditLimitNoKyc) || 0,
      }).eq("id", editingType.id);
      setSaving(false);
      if (error) toast.error(error.message);
      else { toast.success("Store type updated"); handleClose(); qc.invalidateQueries({ queryKey: ["store-types"] }); }
    } else {
      const { error } = await supabase.from("store_types").insert({
        name: newTypeName,
        order_type: newOrderType,
        credit_limit_kyc: parseFloat(creditLimitKyc) || 0,
        credit_limit_no_kyc: parseFloat(creditLimitNoKyc) || 0,
      });
      setSaving(false);
      if (error) toast.error(error.message);
      else { toast.success("Store type added"); handleClose(); qc.invalidateQueries({ queryKey: ["store-types"] }); }
    }
  };

  const handleDelete = async () => {
    if (!deletingType) return;
    setDeleting(true);
    const { error } = await supabase.from("store_types").delete().eq("id", deletingType.id);
    setDeleting(false);
    if (error) {
      if (error.message.includes("violates foreign key")) {
        toast.error("Cannot delete: this store type is in use by stores or routes");
      } else {
        toast.error(error.message);
      }
    } else {
      toast.success("Store type deleted");
      qc.invalidateQueries({ queryKey: ["store-types"] });
    }
    setDeletingType(null);
  };

  const toggleAutoOrder = async (id: string, current: boolean) => {
    await supabase.from("store_types").update({ auto_order_enabled: !current }).eq("id", id);
    qc.invalidateQueries({ queryKey: ["store-types"] });
  };

  const toggleActive = async (id: string, current: boolean) => {
    await supabase.from("store_types").update({ is_active: !current }).eq("id", id);
    qc.invalidateQueries({ queryKey: ["store-types"] });
  };

  const columns = [
    { header: "Name", accessor: "name" as const, className: "font-medium" },
    { header: "Order Type", accessor: (row: any) => <Badge variant="secondary">{row.order_type}</Badge> },
    { header: "Credit (KYC)", accessor: (row: any) => (
      <span className="text-sm font-medium">₹{Number(row.credit_limit_kyc || 0).toLocaleString()}</span>
    )},
    { header: "Credit (No KYC)", accessor: (row: any) => (
      <span className="text-sm text-muted-foreground">₹{Number(row.credit_limit_no_kyc || 0).toLocaleString()}</span>
    )},
    { header: "Auto Order", accessor: (row: any) => (
      <Switch checked={row.auto_order_enabled} onCheckedChange={() => toggleAutoOrder(row.id, row.auto_order_enabled)} disabled={!isAdmin} />
    )},
    { header: "Status", accessor: (row: any) => <StatusBadge status={row.is_active ? "active" : "inactive"} /> },
    ...(isAdmin ? [{ header: "Actions", accessor: (row: any) => (
      <div className="flex gap-2">
        <Button variant="outline" size="sm" className="h-7 text-xs" onClick={() => openEdit(row)}>
          <Pencil className="h-3 w-3 mr-1" /> Edit
        </Button>
        <Button variant={row.is_active ? "destructive" : "default"} size="sm" className="h-7 text-xs" onClick={() => toggleActive(row.id, row.is_active)}>
          {row.is_active ? "Disable" : "Enable"}
        </Button>
        <Button variant="ghost" size="sm" className="h-7 text-xs text-destructive hover:text-destructive" onClick={() => setDeletingType(row)}>
          <Trash2 className="h-3 w-3" />
        </Button>
      </div>
    )}] : []),
  ];

  const renderMobileCard = (row: any) => (
    <div className="entity-card-mobile flex-col !items-stretch">
      <div className="flex items-center justify-between">
        <div className="flex items-center gap-2 min-w-0">
          <h3 className="text-sm font-semibold text-foreground truncate">{row.name}</h3>
          <StatusBadge status={row.is_active ? "active" : "inactive"} />
        </div>
        <Badge variant="secondary" className="text-[10px] shrink-0">{row.order_type}</Badge>
      </div>
      <div className="grid grid-cols-2 gap-2 mt-2">
        <div className="rounded-lg bg-muted/50 p-2 text-center">
          <p className="text-[10px] text-muted-foreground uppercase">Credit (KYC)</p>
          <p className="text-sm font-medium">₹{Number(row.credit_limit_kyc || 0).toLocaleString()}</p>
        </div>
        <div className="rounded-lg bg-muted/50 p-2 text-center">
          <p className="text-[10px] text-muted-foreground uppercase">Credit (No KYC)</p>
          <p className="text-sm font-medium">₹{Number(row.credit_limit_no_kyc || 0).toLocaleString()}</p>
        </div>
      </div>
      <div className="flex items-center justify-between mt-2 pt-2 border-t">
        <div className="flex items-center gap-2">
          <span className="text-xs text-muted-foreground">Auto Order</span>
          <Switch
            checked={row.auto_order_enabled}
            onCheckedChange={() => toggleAutoOrder(row.id, row.auto_order_enabled)}
            disabled={!isAdmin}
          />
        </div>
        {isAdmin && (
          <div className="flex items-center gap-1.5">
            <Button variant="outline" size="sm" className="h-7 text-xs px-2" onClick={() => openEdit(row)}>
              <Pencil className="h-3 w-3 mr-1" /> Edit
            </Button>
            <Button variant={row.is_active ? "destructive" : "default"} size="sm" className="h-7 text-xs px-2" onClick={() => toggleActive(row.id, row.is_active)}>
              {row.is_active ? "Disable" : "Enable"}
            </Button>
            <Button variant="ghost" size="icon" className="h-7 w-7 text-destructive hover:text-destructive" onClick={() => setDeletingType(row)}>
              <Trash2 className="h-3.5 w-3.5" />
            </Button>
          </div>
        )}
      </div>
    </div>
  );

  if (isLoading) return <TableSkeleton columns={5} />;

  return (
    <div className="space-y-6 animate-fade-in">
      <PageHeader
        title="Store Types"
        subtitle="Manage store type categories and their settings"
        actions={[{ label: "Store Type Access", icon: ShieldCheck, onClick: () => navigate("/store-types/access"), priority: 1 }]}
        primaryAction={isAdmin ? { label: "Add Store Type", icon: Plus, onClick: () => setShowAdd(true) } : undefined}
      />

      <DataTable
        columns={columns}
        data={storeTypes || []}
        searchKey="name"
        searchPlaceholder="Search store types..."
        renderMobileCard={renderMobileCard}
      />

      <Dialog open={showAdd} onOpenChange={handleClose}>
        <DialogContent>
          <DialogHeader><DialogTitle>{editingType ? "Edit Store Type" : "Add Store Type"}</DialogTitle></DialogHeader>
          <form onSubmit={handleSubmit} className="space-y-4">
            <div><Label>Type Name</Label><Input value={newTypeName} onChange={(e) => setNewTypeName(e.target.value)} required className="mt-1" placeholder="e.g., Retail, Wholesale" /></div>
            <div>
              <Label>Order Type</Label>
              <Select value={newOrderType} onValueChange={setNewOrderType}>
                <SelectTrigger className="mt-1"><SelectValue /></SelectTrigger>
                <SelectContent>
                  <SelectItem value="simple">Simple</SelectItem>
                  <SelectItem value="detailed">Detailed</SelectItem>
                </SelectContent>
              </Select>
            </div>
            <div className="grid grid-cols-2 gap-4">
              <div><Label>Credit Limit (KYC) ₹</Label><Input type="number" min={0} value={creditLimitKyc} onChange={(e) => setCreditLimitKyc(e.target.value)} className="mt-1" placeholder="e.g., 5000" /></div>
              <div><Label>Credit Limit (No KYC) ₹</Label><Input type="number" min={0} value={creditLimitNoKyc} onChange={(e) => setCreditLimitNoKyc(e.target.value)} className="mt-1" placeholder="e.g., 1000" /></div>
            </div>
            <p className="text-xs text-muted-foreground">Set 0 for no credit limit. These apply per store of this type.</p>
            <Button type="submit" className="w-full" disabled={saving}>
              {saving && <Loader2 className="mr-2 h-4 w-4 animate-spin" />}
              {editingType ? "Update Store Type" : "Add Store Type"}
            </Button>
          </form>
        </DialogContent>
      </Dialog>

      <AlertDialog open={!!deletingType} onOpenChange={(open) => !open && setDeletingType(null)}>
        <AlertDialogContent>
          <AlertDialogHeader>
            <AlertDialogTitle>Delete Store Type</AlertDialogTitle>
            <AlertDialogDescription>
              Are you sure you want to delete <strong>{deletingType?.name}</strong>? This cannot be undone. Store types that are in use by stores or routes cannot be deleted.
            </AlertDialogDescription>
          </AlertDialogHeader>
          <AlertDialogFooter>
            <AlertDialogCancel disabled={deleting}>Cancel</AlertDialogCancel>
            <AlertDialogAction onClick={handleDelete} disabled={deleting} className="bg-destructive text-destructive-foreground hover:bg-destructive/90">
              {deleting ? <Loader2 className="mr-2 h-4 w-4 animate-spin" /> : <Trash2 className="mr-2 h-4 w-4" />}
              Delete
            </AlertDialogAction>
          </AlertDialogFooter>
        </AlertDialogContent>
      </AlertDialog>
    </div>
  );
};

