import { useIsMobile } from "@/hooks/use-mobile";
import { Button } from "@/components/ui/button";
import {
  Select, SelectContent, SelectItem, SelectTrigger, SelectValue,
} from "@/components/ui/select";
import { toast } from "sonner";
import { logActivity } from "@/lib/activityLogger";
import {
  AlertDialog, AlertDialogAction, AlertDialogCancel, AlertDialogContent,
  AlertDialogDescription, AlertDialogFooter, AlertDialogHeader, AlertDialogTitle,
} from "@/components/ui/alert-dialog";

const Stores = () => {
  const navigate = useNavigate();
  const { user, role } = useAuth();
  const isMobile = useIsMobile();
  const { allowed: canCreateStores } = usePermission("create_stores");
  const [showAdd, setShowAdd] = useState(false);
  const [showImport, setShowImport] = useState(false);
  const [pricingStore, setPricingStore] = useState<any>(null);
  const [selected, setSelected] = useState<Set<string>>(new Set());
  const [selectMode, setSelectMode] = useState(false);
  const [bulkRoute, setBulkRoute] = useState("");
  const [editMode, setEditMode] = useState(false);
  const [editData, setEditData] = useState<Record<string, { name: string; phone: string }>>({});
  const [bulkSaving, setBulkSaving] = useState(false);
  const [confirmBulkDeactivate, setConfirmBulkDeactivate] = useState(false);
  const [filters, setFilters] = useState<FilterValues>({});
  const qc = useQueryClient();
  const PAGE_SIZE = 50;
  // const [loadedPages, setLoadedPages] = useState(1);
  const canManagePricing = role === "super_admin" || role === "manager";
  const canBulk = role === "super_admin" || role === "manager";
  const canEdit = role === "super_admin" || role === "manager";

  const {
    data,
    fetchNextPage,
    hasNextPage,
    isFetchingNextPage,
    isLoading
  } = useInfiniteQuery({
    queryKey: ["stores"],
    queryFn: async ({ pageParam = 0 }) => {
      const { data, error } = await supabase
        .from("stores")
        .select("*, customers(name), store_types(name), routes(name)")
        .order("created_at", { ascending: false })
        .range(pageParam * PAGE_SIZE, (pageParam + 1) * PAGE_SIZE - 1);
      if (error) throw error;
      return data;
    },
    initialPageParam: 0,
    getNextPageParam: (lastPage, allPages) => {
      if (!lastPage || lastPage.length < PAGE_SIZE) return undefined;
      return allPages.length;
    },
  });

  const stores = useMemo(() => data?.pages.flatMap((page) => page) || [], [data]);

  const { data: allRoutes } = useQuery({
    queryKey: ["all-routes"],
    queryFn: async () => {
      const { data } = await supabase.from("routes").select("id, name").eq("is_active", true);
      return data || [];
    },
  });

  const { data: storeTypes } = useQuery({
    queryKey: ["store-types-list"],
    queryFn: async () => {
      const { data } = await supabase.from("store_types").select("id, name").eq("is_active", true);
      return data || [];
    },
  });

  const { data: customersList } = useQuery({
    queryKey: ["customers-list"],
    queryFn: async () => {
      const { data } = await supabase.from("customers").select("id, name, display_id").eq("is_active", true);
      return data || [];
    },
  });

  const enterEditMode = () => {
    const data: Record<string, { name: string; phone: string }> = {};
    (stores || []).forEach((s: any) => {
      data[s.id] = { name: s.name || "", phone: s.phone || "" };
    });
    setEditData(data);
    setEditMode(true);
  };

  const cancelEditMode = () => { setEditMode(false); setEditData({}); };

  const saveAllEdits = async () => {
    setBulkSaving(true);
    const changed = (stores || []).filter((s: any) => {
      const d = editData[s.id];
      if (!d) return false;
      return d.name !== (s.name || "") || d.phone !== (s.phone || "");
    });
    if (changed.length === 0) {
      toast.info("No changes to save");
      setBulkSaving(false);
      setEditMode(false);
      return;
    }
    const results = await Promise.all(
      changed.map((s: any) => {
        const d = editData[s.id];
        return supabase.from("stores").update({ name: d.name || null, phone: d.phone || null }).eq("id", s.id);
      })
    );
    setBulkSaving(false);
    const errCount = results.filter((r) => r.error).length;
    if (errCount > 0) { toast.error(`${errCount} update(s) failed`); }
    else {
      toast.success(`${changed.length} store(s) updated`);
      logActivity(user!.id, `Bulk updated ${changed.length} stores`, "store");
    }
    setEditMode(false);
    setEditData({});
    qc.invalidateQueries({ queryKey: ["stores"] });
  };

  const setField = (id: string, field: keyof typeof editData[string], value: string) =>
    setEditData((prev) => ({ ...prev, [id]: { ...prev[id], [field]: value } }));

  const handleCsvImport = async (rows: Record<string, string>[]) => {
    let success = 0;
    const errors: string[] = [];
    const currentCount = stores?.length || 0;

    for (let i = 0; i < rows.length; i++) {
      const row = rows[i];

      // Match customer by name or display_id
      const customer = customersList?.find(
        (c) => c.name.toLowerCase() === row.customer?.toLowerCase() || c.display_id === row.customer
      );
      if (!customer) {
        errors.push(`Row ${i + 2}: Customer "${row.customer}" not found`);
        continue;
      }

      // Match store type by name
      const storeType = storeTypes?.find((t) => t.name.toLowerCase() === row.store_type?.toLowerCase());
      if (!storeType) {
        errors.push(`Row ${i + 2}: Store type "${row.store_type}" not found`);
        continue;
      }

      // Optionally match route
      let routeId: string | null = null;
      if (row.route) {
        const route = allRoutes?.find((r) => r.name.toLowerCase() === row.route?.toLowerCase());
        if (!route) {
          errors.push(`Row ${i + 2}: Route "${row.route}" not found`);
          continue;
        }
        routeId = route.id;
      }

      const displayId = `STR-${String(currentCount + success + 1).padStart(6, "0")}`;
      const { error } = await supabase.from("stores").insert({
        display_id: displayId,
        name: row.name,
        customer_id: customer.id,
        store_type_id: storeType.id,
        route_id: routeId,
        phone: row.phone || null,
        address: row.address || null,
      });
      if (error) {
        errors.push(`Row ${i + 2}: ${error.message}`);
      } else {
        success++;
      }
    }

    if (success > 0) {
      logActivity(user!.id, `Imported ${success} stores via CSV`, "store");
      qc.invalidateQueries({ queryKey: ["stores"] });
    }
    return { success, errors };
  };

  const toggleSelect = (id: string) => {
    setSelected((prev) => {
      const next = new Set(prev);
      if (next.has(id)) next.delete(id); else next.add(id);
      return next;
    });
  };

  const toggleAll = () => {
    if (selected.size === (stores?.length || 0)) {
      setSelected(new Set());
    } else {
      setSelected(new Set(stores?.map((s) => s.id) || []));
    }
  };

  const handleBulkStatus = async (active: boolean) => {
    if (selected.size === 0) return;
    const ids = Array.from(selected);
    const { error } = await supabase.from("stores").update({ is_active: active }).in("id", ids);
    if (error) { toast.error(error.message); return; }
    toast.success(`${ids.length} stores ${active ? "activated" : "deactivated"}`);
    setSelected(new Set());
    qc.invalidateQueries({ queryKey: ["stores"] });
  };

  const handleBulkRoute = async () => {
    if (selected.size === 0 || !bulkRoute) return;
    const ids = Array.from(selected);
    const { error } = await supabase.from("stores").update({ route_id: bulkRoute }).in("id", ids);
    if (error) { toast.error(error.message); return; }
    toast.success(`Route assigned to ${ids.length} stores`);
    setSelected(new Set());
    setBulkRoute("");
    qc.invalidateQueries({ queryKey: ["stores"] });
  };

  const columns = [
    ...(canBulk && selectMode ? [{
      header: () => (
        <Checkbox
          checked={selected.size === (stores?.length || 0) && (stores?.length || 0) > 0}
          onCheckedChange={toggleAll}
        />
      ),
      accessor: (row: any) => (
        <Checkbox
          checked={selected.has(row.id)}
          onCheckedChange={() => toggleSelect(row.id)}
          onClick={(e: React.MouseEvent) => e.stopPropagation()}
        />
      ),
      className: "w-10",
      hideOnMobile: true,
    }] : []),
    { header: "ID", accessor: "display_id" as const, className: "font-mono text-xs hidden lg:table-cell", hideOnMobile: true },
    { header: "Store", accessor: (row: any) => (
      <div className="flex items-center gap-2">
        {row.photo_url && <img src={row.photo_url} alt="" loading="lazy" className="h-8 w-8 rounded-md object-cover" />}
        {editMode ? (
          <input
            className="border border-input rounded px-2 py-0.5 text-sm bg-background w-36 focus:outline-none focus:ring-1 focus:ring-ring"
            value={editData[row.id]?.name ?? row.name ?? ""}
            onChange={(e) => setField(row.id, "name", e.target.value)}
            onClick={(e) => e.stopPropagation()}
          />
        ) : (
          <span className="font-medium">{row.name}</span>
        )}
      </div>
    )},
    { header: "Customer", accessor: (row: any) => row.customers?.name || "—", className: "text-muted-foreground text-sm hidden sm:table-cell" },
    { header: "Phone", accessor: (row: any) => editMode ? (
      <input
        className="border border-input rounded px-2 py-0.5 text-sm bg-background w-32 focus:outline-none focus:ring-1 focus:ring-ring"
        value={editData[row.id]?.phone ?? row.phone ?? ""}
        onChange={(e) => setField(row.id, "phone", e.target.value)}
        onClick={(e) => e.stopPropagation()}
        placeholder="Add phone"
      />
    ) : (
      <span className="text-muted-foreground text-sm">{row.phone || "—"}</span>
    ), className: "hidden md:table-cell" },
    { header: "Type", accessor: (row: any) => row.store_types?.name ? <Badge variant="secondary">{row.store_types.name}</Badge> : "—", className: "hidden sm:table-cell" },
    { header: "Route", accessor: (row: any) => row.routes?.name || "—", className: "text-sm hidden lg:table-cell" },
    { header: "Outstanding", accessor: (row: any) => `₹${Number(row.outstanding).toLocaleString()}`, className: "font-semibold" },
    { header: "Status", accessor: (row: any) => <StatusBadge status={row.is_active ? "active" : "inactive"} /> },
    ...(canManagePricing ? [{ header: "Pricing", accessor: (row: any) => (
      <Button variant="ghost" size="sm" className="h-7 text-xs" onClick={(e: React.MouseEvent) => { e.stopPropagation(); setPricingStore(row); }}>
        <DollarSign className="mr-1 h-3 w-3" />Set Prices
      </Button>
    ), hideOnMobile: true }] : []),
  ];

  const filteredStores = useMemo(() => {
    return applyFilters(stores || [], filters, {
      dateField: "created_at",
      routeField: "route_id",
      storeTypeField: "store_type_id",
      statusField: "is_active",
      outstandingField: "outstanding",
    });
  }, [stores, filters]);

  if (isLoading) {
    return <TableSkeleton columns={7} />;
  }

  return (
    <div className="space-y-6 animate-fade-in">
      <PageHeader
        title="Stores"
        subtitle="Manage store locations and assignments"
        primaryAction={canCreateStores ? { label: "Add Store", onClick: () => setShowAdd(true) } : undefined}
        filterNode={
          <AdvancedFilters
            config={{
              dateRange: true,
              outstandingRange: true,
              storeType: { options: storeTypes?.map((t) => ({ id: t.id, name: t.name })) || [] },
              route: { options: allRoutes?.map((r) => ({ id: r.id, name: r.name })) || [] },
              status: true,
            }}
            values={filters}
            onChange={setFilters}
          />
        }
        actions={[
          { label: "Store Types", icon: Settings2, onClick: () => navigate("/store-types"), priority: 1 },
          ...(canCreateStores ? [{ label: "Import CSV", icon: Upload, onClick: () => setShowImport(true), priority: 2 as const }] : []),
          ...(canBulk ? [{ label: selectMode ? "Done" : "Select", onClick: () => { setSelectMode((v) => !v); setSelected(new Set()); }, priority: 3 as const }] : []),
          ...(canEdit && !editMode ? [{ label: "Bulk Edit", onClick: enterEditMode, priority: 4 as const }] : []),
        ]}
      />

      {editMode && (
        <div className="flex flex-wrap items-center gap-3 rounded-xl border border-primary/30 bg-primary/5 p-3">
          <span className="text-sm font-medium text-primary">Bulk edit — modify name or phone then save</span>
          <div className="ml-auto flex gap-2">
            <Button size="sm" variant="outline" onClick={cancelEditMode} disabled={bulkSaving}>Cancel</Button>
            <Button size="sm" onClick={saveAllEdits} disabled={bulkSaving}>
              {bulkSaving && <Loader2 className="mr-2 h-3.5 w-3.5 animate-spin" />}
              Save All
            </Button>
          </div>
        </div>
      )}

      {canBulk && selectMode && selected.size > 0 && (
        <div className="flex flex-wrap items-center gap-3 rounded-xl border bg-accent/50 p-3">
          <span className="text-sm font-medium">{selected.size} selected</span>
          <Button variant="outline" size="sm" onClick={() => handleBulkStatus(true)}>Activate</Button>
          <Button variant="outline" size="sm" className="text-destructive border-destructive/40" onClick={() => setConfirmBulkDeactivate(true)}>Deactivate</Button>
          <div className="flex items-center gap-2">
            <Select value={bulkRoute} onValueChange={setBulkRoute}>
              <SelectTrigger className="h-8 w-40"><SelectValue placeholder="Assign route" /></SelectTrigger>
              <SelectContent>{allRoutes?.map((r) => <SelectItem key={r.id} value={r.id}>{r.name}</SelectItem>)}</SelectContent>
            </Select>
            <Button variant="outline" size="sm" onClick={handleBulkRoute} disabled={!bulkRoute}>Assign</Button>
          </div>
          <Button variant="ghost" size="sm" onClick={() => setSelected(new Set())}>Clear</Button>
        </div>
      )}

      {/* Desktop: Table, Mobile: Card Grid */}
      {isMobile ? (
        <div className="space-y-4">
          <div className="entity-grid">
            {filteredStores.map((row: any) => {
              return (
                <div
                  key={row.id}
                  onClick={() => { if (!editMode) navigate(`/stores/${row.id}`); }}
                  className={`group entity-card ${!row.is_active ? "entity-card-inactive" : ""}`}
                >
                  {/* Header with image */}
                  <div className="entity-card-header">
                    {row.photo_url ? (
                      <img src={row.photo_url} alt={row.name} className="w-full h-full object-cover group-hover:scale-105 transition-transform duration-200" />
                    ) : (
                      <div className="entity-card-icon-box">
                        <Store className="h-8 w-8 text-muted-foreground" />
                      </div>
                    )}
                    <div className="absolute top-2 right-2">
                      <StatusBadge status={row.is_active ? "active" : "inactive"} />
                    </div>
                    {row.store_types?.name && (
                      <div className="absolute bottom-2 left-2">
                        <Badge variant="secondary" className="text-xs">{row.store_types.name}</Badge>
                      </div>
                    )}
                  </div>

                  {/* Content */}
                  <div className="entity-card-content">
                    <div>
                      <h3 className="entity-card-title">{row.name}</h3>
                      <p className="entity-card-subtitle mt-0.5">{row.display_id}</p>
                    </div>

                    {/* Customer */}
                    <div className="text-sm">
                      <p className="entity-card-label mb-1">Customer</p>
                      <p className="font-medium text-foreground truncate">{row.customers?.name || "—"}</p>
                    </div>

                    {/* Contact info */}
                    <div className="space-y-1.5 text-sm">
                      {row.phone && (
                        <div className="flex items-center gap-2 text-muted-foreground">
                          <Phone className="h-3.5 w-3.5 shrink-0" />
                          <span className="truncate">{row.phone}</span>
                        </div>
                      )}
                      {row.address && (
                        <div className="flex items-center gap-2 text-muted-foreground">
                          <MapPin className="h-3.5 w-3.5 shrink-0" />
                          <span className="truncate text-xs">{row.address}</span>
                        </div>
                      )}
                    </div>

                    {/* Route */}
                    {row.routes?.name && (
                      <div className="pt-2 border-t text-sm">
                        <p className="text-xs text-muted-foreground">Route: <span className="font-medium text-foreground">{row.routes.name}</span></p>
                      </div>
                    )}

                    {/* Outstanding */}
                    <div className="entity-card-stat">
                      <p className="entity-card-label">Outstanding</p>
                      <p className="font-bold text-lg text-foreground">₹{Number(row.outstanding).toLocaleString()}</p>
                    </div>

                    {/* Pricing button for admins */}
                    {canManagePricing && (
                      <Button 
                        variant="outline" 
                        size="sm" 
                        className="w-full text-xs" 
                        onClick={(e: React.MouseEvent) => { 
                          e.stopPropagation(); 
                          setPricingStore(row); 
                        }}
                      >
                        <DollarSign className="mr-1 h-3 w-3" />
                        Set Prices
                      </Button>
                    )}
                  </div>
                </div>
              );
            })}
          </div>
          {filteredStores.length === 0 && (
            <div className="text-center py-12 text-muted-foreground">
              No stores found.
            </div>
          )}
        </div>
      ) : (
        <VirtualDataTable
          columns={columns}
          data={filteredStores}
          searchKey="name"
          searchPlaceholder="Search stores..."
          onRowClick={(row) => { if (!editMode) navigate(`/stores/${row.id}`); }}
          height="calc(100vh - 240px)"
          renderMobileCard={(row: any) => (
            <div className={`entity-card-mobile ${!row.is_active ? "entity-card-inactive" : ""}`} onClick={() => { if (!editMode) navigate(`/stores/${row.id}`); }}>
              <div className="w-14 h-14 rounded-lg bg-muted flex items-center justify-center overflow-hidden shrink-0">
                {row.photo_url ? (
                  <img src={row.photo_url} alt={row.name} className="w-full h-full object-cover" />
                ) : (
                  <Store className="h-6 w-6 text-muted-foreground/40" />
                )}
              </div>
              <div className="flex-1 min-w-0">
                <div className="flex items-start justify-between gap-2">
                  <h3 className="font-semibold text-sm text-foreground truncate">{row.name}</h3>
                  <StatusBadge status={row.is_active ? "active" : "inactive"} />
                </div>
                <div className="flex items-center gap-1.5 mt-0.5">
                  <p className="entity-card-subtitle truncate">{row.display_id}</p>
                  {row.store_types?.name && <Badge variant="outline" className="text-xs h-5 px-1.5 rounded-sm border-muted-foreground/30 text-muted-foreground">{row.store_types.name}</Badge>}
                </div>
                <div className="flex items-center justify-between mt-1.5">
                  <span className="text-xs text-muted-foreground truncate">{row.customers?.name || "—"}</span>
                  <p className={`font-bold text-sm ${Number(row.outstanding) > 0 ? 'text-red-600' : 'text-foreground'}`}>₹{Number(row.outstanding).toLocaleString()}</p>
                </div>
              </div>
            </div>
          )}
        />
      )}

      {hasNextPage && (
        <div className="flex justify-center pt-2">
          <Button variant="outline" size="sm" onClick={() => fetchNextPage()} disabled={isFetchingNextPage} className="gap-1.5">
            {isFetchingNextPage ? <Loader2 className="h-3.5 w-3.5 animate-spin" /> : null}
            Load more
          </Button>
        </div>
      )}

      {showAdd && (
        <CreateStoreWizard
          open={showAdd}
          onOpenChange={setShowAdd}
        />
      )}

      <CsvImportDialog
        open={showImport}
        onOpenChange={setShowImport}
        templateName="stores"
        fields={[
          { key: "name", label: "Store Name", required: true },
          { key: "customer", label: "Customer (name or ID)", required: true },
          { key: "store_type", label: "Store Type", required: true },
          { key: "route", label: "Route" },
          { key: "phone", label: "Phone" },
          { key: "address", label: "Address" },
        ]}
        onImport={handleCsvImport}
      />

      <StorePricingDialog
        store={pricingStore}
        open={!!pricingStore}
        onOpenChange={(open) => { if (!open) setPricingStore(null); }}
      />

      <AlertDialog open={confirmBulkDeactivate} onOpenChange={setConfirmBulkDeactivate}>
        <AlertDialogContent>
          <AlertDialogHeader>
            <AlertDialogTitle>Deactivate {selected.size} store(s)?</AlertDialogTitle>
            <AlertDialogDescription>
              The selected stores will be deactivated and unavailable for new sales or orders until reactivated.
            </AlertDialogDescription>
          </AlertDialogHeader>
          <AlertDialogFooter>
            <AlertDialogCancel>Cancel</AlertDialogCancel>
            <AlertDialogAction className="bg-destructive hover:bg-destructive/90" onClick={() => { setConfirmBulkDeactivate(false); handleBulkStatus(false); }}>Deactivate</AlertDialogAction>
          </AlertDialogFooter>
        </AlertDialogContent>
      </AlertDialog>
    </div>
  );
};

export default Stores;

import { PageHeader } from "@/components/shared/PageHeader";
import { DataTable } from "@/components/shared/DataTable";
import { useQuery, useQueryClient } from "@tanstack/react-query";
import { supabase } from "@/integrations/supabase/client";
import { logActivity } from "@/lib/activityLogger";
import { sendNotificationToMany, getAdminUserIds } from "@/lib/notifications";
import { addToQueue } from "@/lib/offlineQueue";
import { useAuth } from "@/contexts/AuthContext";
import { Loader2, X, CalendarIcon, Store as StoreIcon, Banknote, CreditCard } from "lucide-react";
import { Avatar, AvatarFallback, AvatarImage } from "@/components/ui/avatar";
import { QrStoreSelector } from "@/components/shared/QrStoreSelector";
import { TableSkeleton } from "@/components/shared/TableSkeleton";
import { useState, useEffect } from "react";
import { useSearchParams } from "react-router-dom";
import { usePermission } from "@/hooks/usePermission";
import {
  Dialog, DialogContent, DialogHeader, DialogTitle,
} from "@/components/ui/dialog";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Button } from "@/components/ui/button";
import { Calendar } from "@/components/ui/calendar";
import { Popover, PopoverContent, PopoverTrigger } from "@/components/ui/popover";
import {
  Select, SelectContent, SelectItem, SelectTrigger, SelectValue,
} from "@/components/ui/select";
import { toast } from "sonner";
import { format } from "date-fns";

const Transactions = () => {
  const { user, role } = useAuth();
  const isAdmin = role === "super_admin" || role === "manager";
  const { allowed: canRecordBehalf } = usePermission("record_behalf");
  const qc = useQueryClient();
  const [searchParams, setSearchParams] = useSearchParams();
  const [showAdd, setShowAdd] = useState(false);
  const [saving, setSaving] = useState(false);
  const [storeId, setStoreId] = useState(searchParams.get("store") ?? "");
  const PAGE_SIZE = 100;

  // When navigated with ?store=<id>, auto-open the add dialog
  useEffect(() => {
    const storeParam = searchParams.get("store");
    if (storeParam) {
      setStoreId(storeParam);
      setShowAdd(true);
      setSearchParams({}, { replace: true });
    }
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);
  const [cashAmount, setCashAmount] = useState("");
  const [upiAmount, setUpiAmount] = useState("");
  const [notes, setNotes] = useState("");
  const [recordedFor, setRecordedFor] = useState("");
  const [txnDate, setTxnDate] = useState("");

  // List filters
  const today = new Date().toISOString().split("T")[0];
  const thirtyDaysAgo = new Date(Date.now() - 30 * 24 * 60 * 60 * 1000).toISOString().split("T")[0];
  const [filterFrom, setFilterFrom] = useState(thirtyDaysAgo);
  const [filterTo, setFilterTo] = useState(today);
  const [filterStore, setFilterStore] = useState("all");
  const [filterPayment, setFilterPayment] = useState("all");
  const [loadedPages, setLoadedPages] = useState(1);

  // Reset to page 1 whenever any filter changes
  useEffect(() => {
    setLoadedPages(1);
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [filterFrom, filterTo, filterStore, filterPayment]);

  const { data: transactions, isLoading, isError, error: txnError, isFetching } = useQuery({
    queryKey: ["transactions", isAdmin ? "all" : user?.id, filterFrom, filterTo, filterStore, filterPayment, loadedPages],
    queryFn: async () => {
      let query = supabase
        .from("transactions")
        .select("*, stores(name)")
        .order("created_at", { ascending: false });
      // Non-admin roles only see their own records
      if (!isAdmin) query = query.eq("recorded_by", user!.id);
      // Server-side filters
      if (filterFrom) query = query.gte("created_at", filterFrom + "T00:00:00");
      if (filterTo) query = query.lte("created_at", filterTo + "T23:59:59");
      if (filterStore !== "all") query = query.eq("store_id", filterStore);
      if (filterPayment === "cash") query = query.gt("cash_amount", 0);
      if (filterPayment === "upi") query = query.gt("upi_amount", 0);
      // Cursor pagination
      query = query.range(0, loadedPages * PAGE_SIZE - 1);
      const { data, error } = await query;
      if (error) throw error;
      return data;
    },
  });

  const hasMoreTransactions = (transactions?.length || 0) >= loadedPages * PAGE_SIZE;

  const { data: stores } = useQuery({
    queryKey: ["stores-for-txn"],
    queryFn: async () => {
      const { data } = await supabase.from("stores").select("id, name, outstanding, display_id, customer_id, is_active").order("is_active", { ascending: false }).order("name");
      return data || [];
    },
  });

  const { data: allProfiles } = useQuery({
    queryKey: ["profiles-for-txn"],
    queryFn: async () => {
      const { data } = await supabase.from("profiles").select("user_id, full_name, avatar_url");
      return data || [];
    },
  });
  const profileMap = new Map((allProfiles || []).map((p: any) => [p.user_id, p]));
  const getRecorderName = (id: string) => (profileMap.get(id) as any)?.full_name || "Unknown";
  const getRecorderAvatar = (id: string) => (profileMap.get(id) as any)?.avatar_url || null;

  // Fetch staff users for "record on behalf" selector
  const { data: staffUsers } = useQuery({
    queryKey: ["staff-for-behalf-txn"],
    queryFn: async () => {
      const { data: roles } = await supabase.from("user_roles").select("user_id, role").neq("role", "customer");
      const staffIds = roles?.map((r) => r.user_id) || [];
      const { data: profs } = await supabase.from("profiles").select("user_id, full_name").in("user_id", staffIds);
      return profs?.filter((p) => p.user_id !== user?.id) || [];
    },
    enabled: canRecordBehalf,
  });

  const cash = parseFloat(cashAmount) || 0;
  const upi = parseFloat(upiAmount) || 0;
  const totalPayment = cash + upi;
  const selectedStore = stores?.find((s) => s.id === storeId);
  const oldOutstanding = Number(selectedStore?.outstanding || 0);
  const newOutstanding = oldOutstanding - totalPayment;

  const resetForm = () => {
    setStoreId(""); setCashAmount(""); setUpiAmount(""); setNotes(""); setRecordedFor(""); setTxnDate("");
  };

  // Force fresh fetch on mount to bypass any stale cache
  useEffect(() => {
    qc.invalidateQueries({ queryKey: ["transactions"] });
  }, []);

  const handleAdd = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!storeId || totalPayment <= 0) {
      toast.error("Please select a store and enter payment amount");
      return;
    }
    if (cash < 0 || upi < 0) {
      toast.error("Cash and UPI amounts cannot be negative");
      return;
    }

    const customerId = selectedStore?.customer_id;
    if (!customerId) {
      toast.error("Store has no linked customer");
      return;
    }

    setSaving(true);

    // Queue transaction for offline sync if no network connection
    if (!navigator.onLine) {
      const effectiveRecordedByOffline = recordedFor || user!.id;
      const loggedByOffline = recordedFor ? user!.id : null;
      await addToQueue({
        id: crypto.randomUUID(),
        type: "transaction",
        payload: {
          txData: {
            store_id: storeId,
            customer_id: customerId,
            recorded_by: effectiveRecordedByOffline,
            logged_by: loggedByOffline,
            cash_amount: cash,
            upi_amount: upi,
            notes: notes || null,
            ...(txnDate ? { created_at: new Date(txnDate).toISOString() } : {}),
          },
        },
        createdAt: new Date().toISOString(),
      });
      toast.warning("You're offline — transaction queued and will sync automatically when back online");
      setSaving(false);
      setShowAdd(false);
      resetForm();
      return;
    }

    try {
      const { data: displayId } = await supabase.rpc("generate_display_id", { prefix: "PAY", seq_name: "pay_display_seq" });

      const effectiveRecordedBy = recordedFor || user!.id;
      const loggedBy = recordedFor ? user!.id : null;

      // Single atomic RPC: locks store row, computes outstanding server-side,
      // inserts transaction, updates store balance, and handles backdated recalc
      const { data, error } = await supabase.rpc("record_transaction", {
        p_display_id: displayId,
        p_store_id: storeId,
        p_customer_id: customerId,
        p_recorded_by: effectiveRecordedBy,
        p_logged_by: loggedBy,
        p_cash_amount: cash,
        p_upi_amount: upi,
        p_notes: notes || null,
        p_created_at: txnDate ? new Date(txnDate).toISOString() : null,
      });

      if (error) { toast.error(error.message); setSaving(false); return; }

      const serverOutstanding = data?.[0]?.new_outstanding ?? newOutstanding;

      logActivity(user!.id, "Recorded transaction", "transaction", displayId, undefined, { total: totalPayment, store: storeId });
      toast.success(`Transaction recorded — Outstanding: ₹${Number(serverOutstanding).toLocaleString()}`);

      // Notify admins/managers
      const storeName = stores?.find((s) => s.id === storeId)?.name || "store";
      getAdminUserIds()
        .then((ids) => {
          const others = ids.filter((id) => id !== user!.id);
          if (others.length > 0) {
            sendNotificationToMany(others, {
              title: "Payment Collected",
              message: `₹${totalPayment.toLocaleString()} collected from ${storeName} (${displayId})`,
              type: "payment",
              entityType: "transaction",
              entityId: displayId,
            });
          }
        })
        .catch((err) => {
          console.warn("Failed to notify admins:", err);
        });
    } catch (err: unknown) {
      const message = err instanceof Error ? err.message : "Transaction failed";
      toast.error(message);
    }

    setSaving(false);
    setShowAdd(false);
    resetForm();
    qc.invalidateQueries({ queryKey: ["transactions"] });
    qc.invalidateQueries({ queryKey: ["stores"] });
  };

  // Filtering is now done server-side; local array mirrors the fetched page(s)
  const filteredTransactions = transactions || [];

  const activeTxnFilterCount = [filterStore !== "all", filterPayment !== "all", filterFrom !== thirtyDaysAgo, filterTo !== today].filter(Boolean).length;

  const clearTxnFilters = () => {
    setFilterFrom(thirtyDaysAgo);
    setFilterTo(today);
    setFilterStore("all");
    setFilterPayment("all");
  };

  const columns = [
    { header: "Payment ID", accessor: "display_id" as const, className: "font-mono text-xs" },
    { header: "Store", accessor: (row: any) => row.stores?.name || "—", className: "font-medium" },
    { header: "Total", accessor: (row: any) => `₹${Number(row.total_amount).toLocaleString()}`, className: "font-semibold" },
    { header: "Cash", accessor: (row: any) => `₹${Number(row.cash_amount).toLocaleString()}`, className: "text-sm hidden md:table-cell" },
    { header: "UPI", accessor: (row: any) => `₹${Number(row.upi_amount).toLocaleString()}`, className: "text-sm hidden md:table-cell" },
    { header: "Old Bal.", accessor: (row: any) => `₹${Number(row.old_outstanding).toLocaleString()}`, className: "text-muted-foreground text-sm hidden lg:table-cell" },
    { header: "New Bal.", accessor: (row: any) => `₹${Number(row.new_outstanding).toLocaleString()}`, className: "text-sm hidden lg:table-cell" },
    { header: "Date", accessor: (row: any) => new Date(row.created_at).toLocaleString("en-IN", { dateStyle: "short", timeStyle: "short" }), className: "text-muted-foreground text-xs hidden sm:table-cell" },
  ];

  if (isLoading) {
    return <TableSkeleton columns={8} />;
  }

  if (isError) {
    return (
      <div className="rounded-xl border bg-destructive/10 p-6 text-center text-destructive">
        <p className="font-semibold">Failed to load transactions</p>
        <p className="text-xs mt-1">{(txnError as any)?.message || "Unknown error"}</p>
      </div>
    );
  }

  return (
    <div className="space-y-6 animate-fade-in">
      <PageHeader title="Transactions" subtitle="View and record payment transactions" primaryAction={{ label: "Record Transaction", onClick: () => setShowAdd(true) }} />



      <div className="flex flex-wrap items-center gap-2 p-3 rounded-lg border bg-muted/30">
        <Popover>
          <PopoverTrigger asChild>
            <Button variant="outline" className="h-8 text-xs gap-1.5 justify-start font-normal flex-1 min-w-[100px] sm:flex-none">
              <CalendarIcon className="h-3 w-3 shrink-0" />
              {filterFrom ? format(new Date(filterFrom + "T00:00:00"), "dd MMM yy") : "From"}
            </Button>
          </PopoverTrigger>
          <PopoverContent className="w-auto p-0" align="start">
            <Calendar mode="single" selected={filterFrom ? new Date(filterFrom + "T00:00:00") : undefined} onSelect={(d) => setFilterFrom(d ? format(d, "yyyy-MM-dd") : "")} initialFocus />
          </PopoverContent>
        </Popover>
        <Popover>
          <PopoverTrigger asChild>
            <Button variant="outline" className="h-8 text-xs gap-1.5 justify-start font-normal flex-1 min-w-[100px] sm:flex-none">
              <CalendarIcon className="h-3 w-3 shrink-0" />
              {filterTo ? format(new Date(filterTo + "T00:00:00"), "dd MMM yy") : "To"}
            </Button>
          </PopoverTrigger>
          <PopoverContent className="w-auto p-0" align="start">
            <Calendar mode="single" selected={filterTo ? new Date(filterTo + "T00:00:00") : undefined} onSelect={(d) => setFilterTo(d ? format(d, "yyyy-MM-dd") : "")} initialFocus />
          </PopoverContent>
        </Popover>
        <Select value={filterStore} onValueChange={setFilterStore}>
          <SelectTrigger className="h-8 text-xs flex-1 min-w-[120px] sm:flex-none sm:w-40"><SelectValue placeholder="All stores" /></SelectTrigger>
          <SelectContent>
            <SelectItem value="all">All stores</SelectItem>
            {stores?.map((s: any) => <SelectItem key={s.id} value={s.id}>{s.name}</SelectItem>)}
          </SelectContent>
        </Select>
        <Select value={filterPayment} onValueChange={setFilterPayment}>
          <SelectTrigger className="h-8 text-xs flex-1 min-w-[120px] sm:flex-none sm:w-40"><SelectValue placeholder="Payment method" /></SelectTrigger>
          <SelectContent>
            <SelectItem value="all">All methods</SelectItem>
            <SelectItem value="cash">Cash only</SelectItem>
            <SelectItem value="upi">UPI only</SelectItem>
          </SelectContent>
        </Select>
        {activeTxnFilterCount > 0 && (
          <Button variant="ghost" size="sm" className="h-8 text-xs" onClick={clearTxnFilters}>
            <X className="h-3 w-3 mr-1" /> Clear ({activeTxnFilterCount})
          </Button>
        )}
        <span className="ml-auto text-xs text-muted-foreground">{filteredTransactions.length}{hasMoreTransactions ? "+" : ""} result{filteredTransactions.length !== 1 ? "s" : ""}</span>
      </div>

      <DataTable
        columns={columns}
        data={filteredTransactions}
        searchKey="display_id"
        searchPlaceholder="Search by payment ID..."
        emptyMessage="No transactions recorded yet."
        renderMobileCard={(row: any) => (
          <div className="rounded-lg border bg-card p-3">
            {/* Header row: ID + Date */}
            <div className="flex items-center justify-between mb-1.5">
              <span className="font-mono text-xs text-primary font-medium">{row.display_id}</span>
              <span className="text-[10px] text-muted-foreground">{format(new Date(row.created_at), "dd MMM yy, hh:mm a")}</span>
            </div>
            {/* Store name */}
            <div className="flex items-center gap-1.5 mb-2">
              <StoreIcon className="h-3.5 w-3.5 text-muted-foreground shrink-0" />
              <span className="font-medium text-sm truncate">{row.stores?.name || "—"}</span>
            </div>
            {/* Amounts row - inline compact */}
            <div className="flex items-center gap-3 text-xs">
              <span className="font-bold text-foreground">₹{Number(row.total_amount).toLocaleString()}</span>
              <span className="text-muted-foreground">Cash: ₹{Number(row.cash_amount).toLocaleString()}</span>
              <span className="text-muted-foreground">UPI: ₹{Number(row.upi_amount).toLocaleString()}</span>
            </div>
            {/* Footer: Recorder + Balance */}
            <div className="flex items-center justify-between mt-2 pt-2 border-t border-border/50">
              <div className="flex items-center gap-1.5">
                <Avatar className="h-4 w-4">
                  <AvatarImage src={getRecorderAvatar(row.recorded_by) || undefined} />
                  <AvatarFallback className="text-[8px] bg-primary/10 text-primary">{getRecorderName(row.recorded_by).charAt(0)}</AvatarFallback>
                </Avatar>
                <span className="text-[10px] text-muted-foreground truncate max-w-[100px]">{getRecorderName(row.recorded_by)}</span>
              </div>
              <div className="flex items-center gap-1.5 text-xs">
                <span className="text-muted-foreground">Bal:</span>
                <span className={Number(row.new_outstanding) < Number(row.old_outstanding) ? "font-semibold text-green-600" : "text-muted-foreground"}>
                  ₹{Number(row.new_outstanding).toLocaleString()}
                </span>
              </div>
            </div>
          </div>
        )}
      />

      {hasMoreTransactions && (
        <div className="flex justify-center pt-2">
          <Button variant="outline" size="sm" onClick={() => setLoadedPages((p) => p + 1)} disabled={isFetching} className="gap-1.5">
            {isFetching ? <Loader2 className="h-3.5 w-3.5 animate-spin" /> : null}
            Load more
          </Button>
        </div>
      )}

      <Dialog open={showAdd} onOpenChange={(v) => { setShowAdd(v); if (!v) resetForm(); }}>
        <DialogContent className="max-w-lg">
          <DialogHeader><DialogTitle>Record Transaction</DialogTitle></DialogHeader>
          <form onSubmit={handleAdd} className="space-y-4">
            {canRecordBehalf && (
              <div>
                <Label>Record on behalf of</Label>
                <Select value={recordedFor || "self"} onValueChange={(v) => setRecordedFor(v === "self" ? "" : v)}>
                  <SelectTrigger className="mt-1"><SelectValue placeholder="Myself (default)" /></SelectTrigger>
                  <SelectContent>
                    <SelectItem value="self">Myself</SelectItem>
                    {staffUsers?.map((s) => (
                      <SelectItem key={s.user_id} value={s.user_id}>{s.full_name}</SelectItem>
                    ))}
                  </SelectContent>
                </Select>
              </div>
            )}
            {isAdmin && (
              <div>
                <Label>Transaction Date <span className="text-muted-foreground text-xs font-normal">(leave blank to use current time)</span></Label>
                <Input
                  type="datetime-local"
                  value={txnDate}
                  onChange={(e) => setTxnDate(e.target.value)}
                  className="mt-1"
                />
              </div>
            )}
            <div>
              <Label>Store</Label>
              <div className="flex gap-2 mt-1">
                <Select value={storeId} onValueChange={setStoreId}>
                  <SelectTrigger className="flex-1"><SelectValue placeholder="Select store" /></SelectTrigger>
                  <SelectContent>{stores?.map((s) => (
                      <SelectItem key={s.id} value={s.id} disabled={!(s as any).is_active}>
                        {s.name} ({s.display_id}){!(s as any).is_active ? " — Inactive" : ""}
                      </SelectItem>
                    ))}</SelectContent>
                </Select>
                <QrStoreSelector onStoreSelected={setStoreId} />
              </div>
              {selectedStore && (
                <p className="text-xs text-muted-foreground mt-1">Current outstanding: ₹{oldOutstanding.toLocaleString()}</p>
              )}
            </div>
            <div className="grid grid-cols-2 gap-4">
              <div><Label>Cash (₹)</Label><Input type="number" value={cashAmount} onChange={(e) => setCashAmount(e.target.value)} className="mt-1" placeholder="0" /></div>
              <div><Label>UPI (₹)</Label><Input type="number" value={upiAmount} onChange={(e) => setUpiAmount(e.target.value)} className="mt-1" placeholder="0" /></div>
            </div>
            <div className="rounded-lg border bg-muted/30 p-3 space-y-1 text-sm">
              <div className="flex justify-between"><span>Total Payment</span><span className="font-semibold">₹{totalPayment.toLocaleString()}</span></div>
              <div className="flex justify-between font-semibold"><span>New Outstanding</span><span className={newOutstanding < oldOutstanding ? "text-success" : ""}>₹{newOutstanding.toLocaleString()}</span></div>
            </div>
            <div><Label>Notes (optional)</Label><Input value={notes} onChange={(e) => setNotes(e.target.value)} className="mt-1" placeholder="Payment reference..." /></div>
            <Button type="submit" className="w-full" disabled={saving}>
              {saving && <Loader2 className="mr-2 h-4 w-4 animate-spin" />}
              Record Transaction
            </Button>
          </form>
        </DialogContent>
      </Dialog>
    </div>
  );
};

export default Transactions;

import { useParams, useNavigate } from "react-router-dom";
import { useQuery, useQueryClient, useMutation } from "@tanstack/react-query";
import { supabase } from "@/integrations/supabase/client";
import { ArrowLeft, Building2, Phone, Mail, MapPin, CreditCard, FileText, IndianRupee, Boxes, Plus, Pencil, Trash2, Loader2 } from "lucide-react";
import { Button } from "@/components/ui/button";
import { Card } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { Tabs, TabsContent, TabsList, TabsTrigger } from "@/components/ui/tabs";
import { StatusBadge } from "@/components/shared/StatusBadge";
import { TableSkeleton } from "@/components/shared/TableSkeleton";
import { DataTable } from "@/components/shared/DataTable";
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogFooter } from "@/components/ui/dialog";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Textarea } from "@/components/ui/textarea";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { toast } from "sonner";
import { useState } from "react";
import { useAuth } from "@/contexts/AuthContext";

const UNITS = ["kg", "g", "L", "mL", "pcs", "box", "pack", "ton", "unit"];
const CATEGORIES = ["Chemicals", "Packaging", "Labels", "Caps & Closures", "Raw Ingredients", "Consumables", "Other"];

const VendorDetail = () => {
  const { id } = useParams();
  const navigate = useNavigate();
  const { user } = useAuth();
  const qc = useQueryClient();

  // Raw material form state
  const [showRawMaterialDialog, setShowRawMaterialDialog] = useState(false);
  const [editingMaterial, setEditingMaterial] = useState<any>(null);
  const [materialMode, setMaterialMode] = useState<"link" | "create">("link"); // Mode: link existing or create new
  const [selectedExistingMaterialId, setSelectedExistingMaterialId] = useState("");
  const [materialName, setMaterialName] = useState("");
  const [materialDesc, setMaterialDesc] = useState("");
  const [materialUnit, setMaterialUnit] = useState("kg");
  const [materialCategory, setMaterialCategory] = useState("");
  const [materialMinStock, setMaterialMinStock] = useState("");
  const [materialUnitCost, setMaterialUnitCost] = useState("");
  const [materialHsn, setMaterialHsn] = useState("");
  const [savingMaterial, setSavingMaterial] = useState(false);
  const [deletingMaterialId, setDeletingMaterialId] = useState<string | null>(null);

  const resetMaterialForm = () => {
    setMaterialMode("link");
    setSelectedExistingMaterialId("");
    setMaterialName("");
    setMaterialDesc("");
    setMaterialUnit("kg");
    setMaterialCategory("");
    setMaterialMinStock("");
    setMaterialUnitCost("");
    setMaterialHsn("");
    setEditingMaterial(null);
  };

  const { data: vendor, isLoading } = useQuery({
    queryKey: ["vendor", id],
    queryFn: async () => {
      const { data, error } = await supabase
        .from("vendors")
        .select("*")
        .eq("id", id)
        .single();
      if (error) throw error;
      return data;
    },
  });

  const { data: purchases = [] } = useQuery({
    queryKey: ["vendor-purchases", id],
    queryFn: async () => {
      const { data, error } = await supabase
        .from("purchases")
        .select("*, purchase_items(*, products(name))")
        .eq("vendor_id", id)
        .order("purchase_date", { ascending: false });
      if (error) throw error;
      return data;
    },
  });

  const { data: payments = [] } = useQuery({
    queryKey: ["vendor-payments", id],
    queryFn: async () => {
      const { data, error} = await supabase
        .from("vendor_payments")
        .select("*")
        .eq("vendor_id", id)
        .order("payment_date", { ascending: false });
      if (error) throw error;
      return data;
    },
  });

  const { data: rawMaterials = [] } = useQuery({
    queryKey: ["vendor-raw-materials", id],
    queryFn: async () => {
      const { data, error } = await supabase
        .from("raw_materials")
        .select("*")
        .eq("vendor_id", id)
        .order("name");
      if (error) throw error;
      return data;
    },
  });

  // Query for unlinked raw materials (no vendor assigned)
  const { data: unlinkedMaterials = [] } = useQuery({
    queryKey: ["unlinked-raw-materials"],
    queryFn: async () => {
      const { data, error } = await supabase
        .from("raw_materials")
        .select("id, display_id, name, unit, category")
        .is("vendor_id", null)
        .eq("is_active", true)
        .order("name");
      if (error) throw error;
      return data || [];
    },
  });

  // Raw Material mutations
  const saveMaterialMutation = useMutation({
    mutationFn: async (data: any) => {
      if (data.id) {
        // Edit existing material
        const { error } = await supabase
          .from("raw_materials")
          .update({
            name: data.name,
            description: data.description || null,
            unit: data.unit,
            category: data.category || null,
            min_stock_level: data.min_stock_level || 0,
            unit_cost: data.unit_cost || 0,
            hsn_code: data.hsn_code || null,
            updated_at: new Date().toISOString(),
          })
          .eq("id", data.id);
        if (error) throw error;
      } else if (data.mode === "link") {
        // Link existing material to this vendor
        const { error } = await supabase
          .from("raw_materials")
          .update({ vendor_id: id, updated_at: new Date().toISOString() })
          .eq("id", data.existing_material_id);
        if (error) throw error;
      } else {
        // Create new material
        const { data: idData } = await supabase.rpc("generate_display_id", {
          prefix: "RM",
          seq_name: "raw_materials_display_id_seq"
        });

        const { error } = await supabase.from("raw_materials").insert({
          display_id: idData,
          vendor_id: id,
          name: data.name,
          description: data.description || null,
          unit: data.unit,
          category: data.category || null,
          min_stock_level: data.min_stock_level || 0,
          unit_cost: data.unit_cost || 0,
          hsn_code: data.hsn_code || null,
          created_by: user!.id,
        });
        if (error) throw error;
      }
    },
    onSuccess: () => {
      qc.invalidateQueries({ queryKey: ["vendor-raw-materials", id] });
      qc.invalidateQueries({ queryKey: ["unlinked-raw-materials"] });
      qc.invalidateQueries({ queryKey: ["raw-materials-list"] });
      toast.success(editingMaterial ? "Material updated" : materialMode === "link" ? "Material linked" : "Material added");
      setShowRawMaterialDialog(false);
      resetMaterialForm();
    },
    onError: (e: Error) => {
      toast.error(`Failed: ${e.message}`);
    },
  });

  const deleteMaterialMutation = useMutation({
    mutationFn: async (materialId: string) => {
      const { error } = await supabase.from("raw_materials").delete().eq("id", materialId);
      if (error) throw error;
    },
    onSuccess: () => {
      qc.invalidateQueries({ queryKey: ["vendor-raw-materials", id] });
      toast.success("Material deleted");
      setDeletingMaterialId(null);
    },
    onError: (e: Error) => {
      toast.error(`Cannot delete: ${e.message}`);
      setDeletingMaterialId(null);
    },
  });

  const handleSaveMaterial = () => {
    // Validation
    if (materialMode === "link") {
      if (!selectedExistingMaterialId) {
        toast.error("Please select a material to link");
        return;
      }
    } else {
      if (!materialName.trim()) {
        toast.error("Name is required");
        return;
      }
    }

    setSavingMaterial(true);
    saveMaterialMutation.mutate({
      id: editingMaterial?.id,
      mode: materialMode,
      existing_material_id: selectedExistingMaterialId,
      name: materialName.trim(),
      description: materialDesc.trim(),
      unit: materialUnit,
      category: materialCategory,
      min_stock_level: materialMinStock ? parseFloat(materialMinStock) : 0,
      unit_cost: materialUnitCost ? parseFloat(materialUnitCost) : 0,
      hsn_code: materialHsn.trim(),
    });
    setSavingMaterial(false);
  };

  const openEditMaterial = (material: any) => {
    setEditingMaterial(material);
    setMaterialName(material.name);
    setMaterialDesc(material.description || "");
    setMaterialUnit(material.unit);
    setMaterialCategory(material.category || "");
    setMaterialMinStock(material.min_stock_level?.toString() || "");
    setMaterialUnitCost(material.unit_cost?.toString() || "");
    setMaterialHsn(material.hsn_code || "");
    setShowRawMaterialDialog(true);
  };

  // Calculate ledger entries (purchases as debits, payments as credits)
  const ledgerEntries = [
    ...purchases.map((p: any) => ({
      id: p.id,
      date: p.purchase_date,
      type: "Purchase",
      reference: p.display_id,
      debit: p.total_amount,
      credit: 0,
      balance: 0, // Will calculate below
      status: p.status,
    })),
    ...payments.map((p: any) => ({
      id: p.id,
      date: p.payment_date,
      type: "Payment",
      reference: p.display_id,
      debit: 0,
      credit: p.amount,
      balance: 0,
      status: p.status,
    })),
  ].sort((a, b) => new Date(a.date).getTime() - new Date(b.date).getTime());

  // Calculate running balance
  let runningBalance = 0;
  ledgerEntries.forEach((entry) => {
    if (entry.status === 'completed') {
      runningBalance += entry.debit - entry.credit;
      entry.balance = runningBalance;
    }
  });

  const purchaseColumns = [
    { header: "ID", accessor: "display_id" as const, className: "font-mono text-xs" },
    { header: "Date", accessor: (row: any) => new Date(row.purchase_date).toLocaleDateString("en-IN"), className: "text-sm" },
    { header: "Bill #", accessor: (row: any) => row.bill_number || "—", className: "text-sm" },
    { 
      header: "Items", 
      accessor: (row: any) => (
        <span className="text-xs text-muted-foreground">
          {row.purchase_items?.length || 0} item(s)
        </span>
      )
    },
    { header: "Amount", accessor: (row: any) => `₹${Number(row.total_amount).toLocaleString()}`, className: "font-semibold" },
    { header: "Status", accessor: (row: any) => <StatusBadge status={row.status === "completed" ? "active" : row.status as any} label={row.status} /> },
  ];

  const paymentColumns = [
    { header: "ID", accessor: "display_id" as const, className: "font-mono text-xs" },
    { header: "Date", accessor: (row: any) => new Date(row.payment_date).toLocaleDateString("en-IN"), className: "text-sm" },
    { header: "Method", accessor: (row: any) => <Badge variant="outline">{row.payment_method}</Badge> },
    { header: "Reference", accessor: (row: any) => row.payment_reference || "—", className: "text-xs text-muted-foreground" },
    { header: "Amount", accessor: (row: any) => `₹${Number(row.amount).toLocaleString()}`, className: "font-semibold text-green-600" },
    { header: "Status", accessor: (row: any) => <StatusBadge status={row.status === "completed" ? "active" : row.status as any} label={row.status} /> },
  ];

  const ledgerColumns = [
    { header: "Date", accessor: (row: any) => new Date(row.date).toLocaleDateString("en-IN"), className: "text-sm" },
    { header: "Type", accessor: (row: any) => <Badge variant={row.type === "Purchase" ? "secondary" : "outline"}>{row.type}</Badge> },
    { header: "Reference", accessor: "reference" as const, className: "font-mono text-xs" },
    { 
      header: "Debit", 
      accessor: (row: any) => row.debit > 0 ? `₹${Number(row.debit).toLocaleString()}` : "—",
      className: "text-red-600 font-medium"
    },
    { 
      header: "Credit", 
      accessor: (row: any) => row.credit > 0 ? `₹${Number(row.credit).toLocaleString()}` : "—",
      className: "text-green-600 font-medium"
    },
    { 
      header: "Balance", 
      accessor: (row: any) => (
        <span className={`font-semibold ${row.balance > 0 ? 'text-red-600' : row.balance < 0 ? 'text-green-600' : ''}`}>
          ₹{Number(row.balance).toLocaleString()}
        </span>
      )
    },
  ];

  const rawMaterialColumns = [
    { header: "ID", accessor: "display_id" as const, className: "font-mono text-xs" },
    { header: "Name", accessor: "name" as const, className: "font-medium" },
    { header: "Category", accessor: (row: any) => row.category || "—", className: "text-sm text-muted-foreground" },
    { header: "Unit", accessor: "unit" as const, className: "text-sm" },
    { header: "Stock", accessor: (row: any) => `${row.current_stock} ${row.unit}`, className: "text-sm" },
    { header: "Unit Cost", accessor: (row: any) => `₹${row.unit_cost?.toLocaleString() || 0}`, className: "text-sm" },
    {
      header: "Status",
      accessor: (row: any) => (
        <StatusBadge 
          status={row.current_stock <= row.min_stock_level ? "inactive" : "active"} 
          label={row.current_stock <= row.min_stock_level ? "Low Stock" : "OK"} 
        />
      ),
    },
    {
      header: "Actions",
      accessor: (row: any) => (
        <div className="flex gap-1">
          <Button variant="ghost" size="icon" className="h-8 w-8" onClick={(e) => { e.stopPropagation(); openEditMaterial(row); }}>
            <Pencil className="h-4 w-4" />
          </Button>
          <Button variant="ghost" size="icon" className="h-8 w-8 text-destructive" onClick={(e) => { e.stopPropagation(); setDeletingMaterialId(row.id); }}>
            <Trash2 className="h-4 w-4" />
          </Button>
        </div>
      ),
    },
  ];

  if (isLoading) {
    return <TableSkeleton columns={4} />;
  }

  if (!vendor) {
    return (
      <div className="flex flex-col items-center justify-center h-96">
        <p className="text-muted-foreground mb-4">Vendor not found</p>
        <Button onClick={() => navigate("/vendors")}>Back to Vendors</Button>
      </div>
    );
  }

  return (
    <div className="space-y-6 animate-fade-in">
      {/* Header */}
      <div className="flex items-center gap-4">
        <Button variant="ghost" size="sm" onClick={() => navigate("/vendors")}>
          <ArrowLeft className="h-4 w-4 mr-2" />
          Back
        </Button>
      </div>

      {/* Vendor Info Card */}
      <Card className="p-6">
        <div className="flex items-start justify-between mb-6">
          <div className="flex items-center gap-4">
            <div className="w-16 h-16 rounded-lg bg-purple-100 flex items-center justify-center">
              <Building2 className="h-8 w-8 text-purple-600" />
            </div>
            <div>
              <h1 className="text-2xl font-bold">{vendor.name}</h1>
              <p className="text-sm text-muted-foreground font-mono">{vendor.display_id}</p>
            </div>
          </div>
          <StatusBadge status={vendor.is_active ? "active" : "inactive"} />
        </div>

        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
          {/* Contact Info */}
          <div className="space-y-3">
            <h3 className="text-sm font-semibold text-muted-foreground uppercase">Contact</h3>
            {vendor.contact_person && (
              <div className="flex items-center gap-2 text-sm">
                <span className="text-muted-foreground">Contact:</span>
                <span>{vendor.contact_person}</span>
              </div>
            )}
            {vendor.phone && (
              <div className="flex items-center gap-2 text-sm">
                <Phone className="h-4 w-4 text-muted-foreground" />
                <span>{vendor.phone}</span>
              </div>
            )}
            {vendor.email && (
              <div className="flex items-center gap-2 text-sm">
                <Mail className="h-4 w-4 text-muted-foreground" />
                <span className="truncate">{vendor.email}</span>
              </div>
            )}
            {vendor.address && (
              <div className="flex items-start gap-2 text-sm">
                <MapPin className="h-4 w-4 text-muted-foreground mt-0.5" />
                <span className="text-xs">{vendor.address}</span>
              </div>
            )}
          </div>

          {/* Tax Info */}
          <div className="space-y-3">
            <h3 className="text-sm font-semibold text-muted-foreground uppercase">Tax Details</h3>
            {vendor.gstin && (
              <div className="text-sm">
                <span className="text-muted-foreground">GSTIN:</span>
                <p className="font-mono">{vendor.gstin}</p>
              </div>
            )}
            {vendor.pan && (
              <div className="text-sm">
                <span className="text-muted-foreground">PAN:</span>
                <p className="font-mono">{vendor.pan}</p>
              </div>
            )}
          </div>

          {/* Payment Terms */}
          <div className="space-y-3">
            <h3 className="text-sm font-semibold text-muted-foreground uppercase">Payment</h3>
            <div className="text-sm">
              <span className="text-muted-foreground">Terms:</span>
              <p>{vendor.payment_terms}</p>
            </div>
            <div className="text-sm">
              <span className="text-muted-foreground">Credit Limit:</span>
              <p className="font-semibold">₹{Number(vendor.credit_limit).toLocaleString()}</p>
            </div>
          </div>

          {/* Account Summary */}
          <div className="space-y-3">
            <h3 className="text-sm font-semibold text-muted-foreground uppercase">Account</h3>
            <div className="space-y-2">
              <div className="flex justify-between text-sm">
                <span className="text-muted-foreground">Total Purchases:</span>
                <span className="font-semibold text-red-600">₹{Number(vendor.total_debit).toLocaleString()}</span>
              </div>
              <div className="flex justify-between text-sm">
                <span className="text-muted-foreground">Total Paid:</span>
                <span className="font-semibold text-green-600">₹{Number(vendor.total_credit).toLocaleString()}</span>
              </div>
              <div className="flex justify-between text-sm pt-2 border-t">
                <span className="font-semibold">Outstanding:</span>
                <span className={`font-bold text-lg ${Number(vendor.outstanding) > 0 ? 'text-red-600' : 'text-green-600'}`}>
                  ₹{Number(vendor.outstanding).toLocaleString()}
                </span>
              </div>
            </div>
          </div>
        </div>

        {vendor.notes && (
          <div className="mt-6 pt-6 border-t">
            <h3 className="text-sm font-semibold text-muted-foreground uppercase mb-2">Notes</h3>
            <p className="text-sm text-muted-foreground">{vendor.notes}</p>
          </div>
        )}
      </Card>

      {/* Tabs for Purchases, Payments, Ledger, Raw Materials */}
      <Tabs defaultValue="ledger" className="w-full">
        <TabsList>
          <TabsTrigger value="ledger">
            <FileText className="h-4 w-4 mr-2" />
            Ledger ({ledgerEntries.length})
          </TabsTrigger>
          <TabsTrigger value="purchases">
            <IndianRupee className="h-4 w-4 mr-2" />
            Purchases ({purchases.length})
          </TabsTrigger>
          <TabsTrigger value="payments">
            <CreditCard className="h-4 w-4 mr-2" />
            Payments ({payments.length})
          </TabsTrigger>
          <TabsTrigger value="materials">
            <Boxes className="h-4 w-4 mr-2" />
            Raw Materials ({rawMaterials.length})
          </TabsTrigger>
        </TabsList>

        <TabsContent value="ledger" className="mt-6">
          <Card className="p-6">
            <h3 className="text-lg font-semibold mb-4">Account Ledger</h3>
            <DataTable
              columns={ledgerColumns}
              data={ledgerEntries}
              searchKey="reference"
              searchPlaceholder="Search by reference..."
              emptyMessage="No transactions yet"
            />
          </Card>
        </TabsContent>

        <TabsContent value="purchases" className="mt-6">
          <Card className="p-6">
            <div className="flex items-center justify-between mb-4">
              <h3 className="text-lg font-semibold">Purchase History</h3>
              <Button size="sm" onClick={() => navigate("/purchases", { state: { vendorId: vendor.id } })}>
                New Purchase
              </Button>
            </div>
            <DataTable
              columns={purchaseColumns}
              data={purchases}
              searchKey="display_id"
              searchPlaceholder="Search purchases..."
              emptyMessage="No purchases yet"
              onRowClick={(row) => navigate(`/purchases/${row.id}`)}
            />
          </Card>
        </TabsContent>

        <TabsContent value="payments" className="mt-6">
          <Card className="p-6">
            <div className="flex items-center justify-between mb-4">
              <h3 className="text-lg font-semibold">Payment History</h3>
              <Button size="sm" onClick={() => navigate("/vendor-payments", { state: { vendorId: vendor.id } })}>
                Record Payment
              </Button>
            </div>
            <DataTable
              columns={paymentColumns}
              data={payments}
              searchKey="display_id"
              searchPlaceholder="Search payments..."
              emptyMessage="No payments yet"
            />
          </Card>
        </TabsContent>

        <TabsContent value="materials" className="mt-6">
          <Card className="p-6">
            <div className="flex items-center justify-between mb-4">
              <h3 className="text-lg font-semibold">Raw Materials from this Vendor</h3>
              <Button size="sm" onClick={() => { resetMaterialForm(); setShowRawMaterialDialog(true); }}>
                <Plus className="h-4 w-4 mr-1" />
                Add Material
              </Button>
            </div>
            <DataTable
              columns={rawMaterialColumns}
              data={rawMaterials}
              searchKey="name"
              searchPlaceholder="Search materials..."
              emptyMessage="No raw materials yet"
              renderMobileCard={(row: any) => (
                <div className="rounded-xl border bg-card p-4 shadow-sm">
                  <div className="flex items-start justify-between mb-2">
                    <div>
                      <p className="font-mono text-xs text-muted-foreground">{row.display_id}</p>
                      <h3 className="font-semibold">{row.name}</h3>
                      <p className="text-xs text-muted-foreground">{row.category || "Uncategorized"}</p>
                    </div>
                    <StatusBadge 
                      status={row.current_stock <= row.min_stock_level ? "inactive" : "active"} 
                      label={row.current_stock <= row.min_stock_level ? "Low" : "OK"} 
                    />
                  </div>
                  <div className="flex items-center justify-between mt-3 pt-3 border-t text-sm">
                    <span>{row.current_stock} {row.unit}</span>
                    <span className="font-medium">₹{row.unit_cost?.toLocaleString() || 0}/{row.unit}</span>
                  </div>
                  <div className="flex gap-2 mt-3">
                    <Button variant="outline" size="sm" className="flex-1" onClick={() => openEditMaterial(row)}>
                      <Pencil className="h-4 w-4 mr-1" />
                      Edit
                    </Button>
                    <Button variant="outline" size="sm" className="text-destructive" onClick={() => setDeletingMaterialId(row.id)}>
                      <Trash2 className="h-4 w-4" />
                    </Button>
                  </div>
                </div>
              )}
            />
          </Card>
        </TabsContent>
      </Tabs>

      {/* Add/Edit Raw Material Dialog */}
      <Dialog open={showRawMaterialDialog} onOpenChange={(open) => { setShowRawMaterialDialog(open); if (!open) resetMaterialForm(); }}>
        <DialogContent className="max-w-lg">
          <DialogHeader>
            <DialogTitle>{editingMaterial ? "Edit Raw Material" : "Add Raw Material"}</DialogTitle>
          </DialogHeader>
          <div className="space-y-4 py-4">
            {!editingMaterial && (
              <div className="space-y-2">
                <Label>Mode *</Label>
                <Select value={materialMode} onValueChange={(value: "link" | "create") => setMaterialMode(value)}>
                  <SelectTrigger>
                    <SelectValue />
                  </SelectTrigger>
                  <SelectContent>
                    <SelectItem value="link">Link Existing Material</SelectItem>
                    <SelectItem value="create">Create New Material</SelectItem>
                  </SelectContent>
                </Select>
              </div>
            )}

            {materialMode === "link" && !editingMaterial ? (
              <div className="space-y-2">
                <Label>Select Material *</Label>
                <Select value={selectedExistingMaterialId} onValueChange={setSelectedExistingMaterialId}>
                  <SelectTrigger>
                    <SelectValue placeholder="Choose a material to link" />
                  </SelectTrigger>
                  <SelectContent>
                    {unlinkedMaterials.length === 0 ? (
                      <div className="py-2 px-3 text-sm text-muted-foreground">No unlinked materials available</div>
                    ) : (
                      unlinkedMaterials.map((m: any) => (
                        <SelectItem key={m.id} value={m.id}>
                          {m.name} ({m.display_id}) - {m.unit}
                        </SelectItem>
                      ))
                    )}
                  </SelectContent>
                </Select>
                {unlinkedMaterials.length === 0 && (
                  <p className="text-xs text-muted-foreground">All raw materials are already linked to vendors. Switch to "Create New Material" mode.</p>
                )}
              </div>
            ) : (
              <>
                <div className="space-y-2">
                  <Label>Name *</Label>
                  <Input value={materialName} onChange={(e) => setMaterialName(e.target.value)} placeholder="e.g., Sodium Chloride" />
                </div>
                <div className="grid grid-cols-2 gap-4">
                  <div className="space-y-2">
                    <Label>Unit</Label>
                    <Select value={materialUnit} onValueChange={setMaterialUnit}>
                      <SelectTrigger>
                        <SelectValue />
                      </SelectTrigger>
                      <SelectContent>
                        {UNITS.map((u) => (
                          <SelectItem key={u} value={u}>{u}</SelectItem>
                        ))}
                      </SelectContent>
                    </Select>
                  </div>
                  <div className="space-y-2">
                    <Label>Category</Label>
                    <Select value={materialCategory} onValueChange={setMaterialCategory}>
                      <SelectTrigger>
                        <SelectValue placeholder="Select" />
                      </SelectTrigger>
                      <SelectContent>
                        {CATEGORIES.map((c) => (
                          <SelectItem key={c} value={c}>{c}</SelectItem>
                        ))}
                      </SelectContent>
                    </Select>
                  </div>
                </div>
                <div className="grid grid-cols-2 gap-4">
                  <div className="space-y-2">
                    <Label>Unit Cost (₹)</Label>
                    <Input type="number" step="0.01" min="0" value={materialUnitCost} onChange={(e) => setMaterialUnitCost(e.target.value)} />
                  </div>
                  <div className="space-y-2">
                    <Label>Min Stock Level</Label>
                    <Input type="number" step="0.01" min="0" value={materialMinStock} onChange={(e) => setMaterialMinStock(e.target.value)} />
                  </div>
                </div>
                <div className="space-y-2">
                  <Label>HSN Code</Label>
                  <Input value={materialHsn} onChange={(e) => setMaterialHsn(e.target.value)} placeholder="e.g., 25010010" className="font-mono" />
                </div>
                <div className="space-y-2">
                  <Label>Description</Label>
                  <Textarea value={materialDesc} onChange={(e) => setMaterialDesc(e.target.value)} placeholder="Optional notes..." />
                </div>
              </>
            )}
          </div>
          <DialogFooter>
            <Button variant="outline" onClick={() => setShowRawMaterialDialog(false)}>Cancel</Button>
            <Button onClick={handleSaveMaterial} disabled={savingMaterial || saveMaterialMutation.isPending}>
              {(savingMaterial || saveMaterialMutation.isPending) && <Loader2 className="mr-2 h-4 w-4 animate-spin" />}
              {editingMaterial ? "Update" : materialMode === "link" ? "Link" : "Create"}
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>

      {/* Delete Material Confirmation */}
      <Dialog open={!!deletingMaterialId} onOpenChange={() => setDeletingMaterialId(null)}>
        <DialogContent className="max-w-sm">
          <DialogHeader>
            <DialogTitle>Delete Raw Material?</DialogTitle>
          </DialogHeader>
          <p className="text-sm text-muted-foreground">This cannot be undone.</p>
          <DialogFooter>
            <Button variant="outline" onClick={() => setDeletingMaterialId(null)}>Cancel</Button>
            <Button variant="destructive" onClick={() => deletingMaterialId && deleteMaterialMutation.mutate(deletingMaterialId)} disabled={deleteMaterialMutation.isPending}>
              {deleteMaterialMutation.isPending && <Loader2 className="mr-2 h-4 w-4 animate-spin" />}
              Delete
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>
    </div>
  );
};

export default VendorDetail;

import { PageHeader } from "@/components/shared/PageHeader";
import { DataTable } from "@/components/shared/DataTable";
import { StatusBadge } from "@/components/shared/StatusBadge";
import { Badge } from "@/components/ui/badge";
import { useQuery, useQueryClient } from "@tanstack/react-query";
import { supabase } from "@/integrations/supabase/client";
import { useAuth } from "@/contexts/AuthContext";
import { Loader2, CreditCard } from "lucide-react";
import { TableSkeleton } from "@/components/shared/TableSkeleton";
import { useState } from "react";
import { useNavigate, useLocation } from "react-router-dom";
import { Dialog, DialogContent, DialogHeader, DialogTitle } from "@/components/ui/dialog";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Textarea } from "@/components/ui/textarea";
import { Button } from "@/components/ui/button";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { toast } from "sonner";
import { logActivity } from "@/lib/activityLogger";

const VendorPayments = () => {
  const navigate = useNavigate();
  const location = useLocation();
  const { user } = useAuth();
  const qc = useQueryClient();
  const [showAdd, setShowAdd] = useState(false);
  const [saving, setSaving] = useState(false);

  // Form state
  const [vendorId, setVendorId] = useState(location.state?.vendorId || "");
  const [paymentDate, setPaymentDate] = useState(new Date().toISOString().split("T")[0]);
  const [amount, setAmount] = useState("");
  const [paymentMethod, setPaymentMethod] = useState("cash");
  const [paymentReference, setPaymentReference] = useState("");
  const [notes, setNotes] = useState("");

  const { data: payments = [], isLoading } = useQuery({
    queryKey: ["vendor_payments"],
    queryFn: async () => {
      const { data, error } = await supabase
        .from("vendor_payments")
        .select("*, vendors(name, display_id)")
        .order("payment_date", { ascending: false });
      if (error) throw error;
      return data;
    },
  });

  const { data: vendors = [] } = useQuery({
    queryKey: ["vendors-with-outstanding"],
    queryFn: async () => {
      const { data } = await supabase
        .from("vendors")
        .select("id, name, display_id, outstanding")
        .eq("is_active", true);
      return data || [];
    },
  });

  const selectedVendor = vendors.find((v: any) => v.id === vendorId);

  const resetForm = () => {
    setVendorId(location.state?.vendorId || "");
    setPaymentDate(new Date().toISOString().split("T")[0]);
    setAmount("");
    setPaymentMethod("cash");
    setPaymentReference("");
    setNotes("");
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setSaving(true);

    try {
      const paymentAmount = parseFloat(amount);
      
      if (paymentAmount <= 0) {
        toast.error("Amount must be greater than zero");
        setSaving(false);
        return;
      }

      // Generate display ID
      const { data: idData } = await supabase.rpc("generate_display_id", {
        prefix: "VPY",
        seq_name: "vendor_payments_display_id_seq"
      });

      // Create payment
      const { error } = await supabase
        .from("vendor_payments")
        .insert({
          display_id: idData,
          vendor_id: vendorId,
          payment_date: paymentDate,
          amount: paymentAmount,
          payment_method: paymentMethod,
          payment_reference: paymentReference.trim() || null,
          notes: notes.trim() || null,
          status: "completed",
          created_by: user!.id
        });

      if (error) throw error;

      toast.success("Payment recorded successfully");
      logActivity(user!.id, `Recorded payment ${idData}`, "vendor_payment");
      
      qc.invalidateQueries({ queryKey: ["vendor_payments"] });
      qc.invalidateQueries({ queryKey: ["vendors"] });
      qc.invalidateQueries({ queryKey: ["vendor-payments"] });
      
      setShowAdd(false);
      resetForm();
    } catch (error: any) {
      toast.error(error.message || "Failed to record payment");
    } finally {
      setSaving(false);
    }
  };

  const columns = [
    { header: "ID", accessor: "display_id" as const, className: "font-mono text-xs" },
    { header: "Date", accessor: (row: any) => new Date(row.payment_date).toLocaleDateString("en-IN"), className: "text-sm" },
    { header: "Vendor", accessor: (row: any) => row.vendors?.name || "—", className: "text-sm font-medium" },
    { 
      header: "Method", 
      accessor: (row: any) => (
        <Badge variant="outline" className="capitalize">
          {row.payment_method.replace("_", " ")}
        </Badge>
      )
    },
    { header: "Reference", accessor: (row: any) => row.payment_reference || "—", className: "text-xs text-muted-foreground font-mono" },
    { header: "Amount", accessor: (row: any) => `₹${Number(row.amount).toLocaleString()}`, className: "font-semibold text-green-600" },
    { header: "Status", accessor: (row: any) => <StatusBadge status={row.status === "completed" ? "active" : row.status as any} label={row.status} /> },
  ];

  if (isLoading) {
    return <TableSkeleton columns={7} />;
  }

  return (
    <div className="space-y-6 animate-fade-in">
      <PageHeader
        title="Vendor Payments"
        subtitle="Record payments made to vendors"
        primaryAction={{ label: "Record Payment", onClick: () => { resetForm(); setShowAdd(true); }, icon: CreditCard }}
      />

      <DataTable
        columns={columns}
        data={payments}
        searchKey="display_id"
        searchPlaceholder="Search payments..."
        emptyMessage="No payments recorded yet"
        renderMobileCard={(row: any) => (
          <div className="entity-card-mobile">
            <div className="w-10 h-10 rounded-lg bg-green-100 flex items-center justify-center shrink-0">
              <CreditCard className="h-5 w-5 text-green-600" />
            </div>
            <div className="flex-1 min-w-0">
              <div className="flex items-start justify-between gap-2">
                <div className="min-w-0">
                  <h3 className="font-semibold text-sm truncate">{row.vendors?.name || "Unknown Vendor"}</h3>
                  <p className="entity-card-subtitle">{row.display_id}</p>
                </div>
                <StatusBadge status={row.status === "completed" ? "active" : row.status as any} label={row.status} />
              </div>
              <div className="flex items-center justify-between mt-1">
                <div className="flex items-center gap-2">
                  <span className="text-xs text-muted-foreground">{new Date(row.payment_date).toLocaleDateString("en-IN")}</span>
                  <Badge variant="outline" className="capitalize text-[10px] h-5">{row.payment_method}</Badge>
                </div>
                <span className="font-bold text-green-600">₹{Number(row.amount).toLocaleString()}</span>
              </div>
            </div>
          </div>
        )}
      />

      {/* Record Payment Dialog */}
      <Dialog open={showAdd} onOpenChange={(open) => { setShowAdd(open); if (!open) resetForm(); }}>
        <DialogContent className="max-w-lg">
          <DialogHeader>
            <DialogTitle>Record Vendor Payment</DialogTitle>
          </DialogHeader>
          <form onSubmit={handleSubmit} className="space-y-4">
            <div>
              <Label>Vendor *</Label>
              <Select value={vendorId} onValueChange={setVendorId} required>
                <SelectTrigger className="mt-1">
                  <SelectValue placeholder="Select vendor" />
                </SelectTrigger>
                <SelectContent>
                  {vendors.map((v: any) => (
                    <SelectItem key={v.id} value={v.id}>
                      <div className="flex items-center justify-between w-full">
                        <span>{v.name} ({v.display_id})</span>
                        {v.outstanding > 0 && (
                          <span className="ml-4 text-xs text-red-600">
                            Outstanding: ₹{Number(v.outstanding).toLocaleString()}
                          </span>
                        )}
                      </div>
                    </SelectItem>
                  ))}
                </SelectContent>
              </Select>
              {selectedVendor && selectedVendor.outstanding > 0 && (
                <p className="text-xs text-muted-foreground mt-2">
                  Current outstanding balance: <span className="font-semibold text-red-600">₹{Number(selectedVendor.outstanding).toLocaleString()}</span>
                </p>
              )}
            </div>

            <div className="grid grid-cols-2 gap-4">
              <div>
                <Label>Payment Date *</Label>
                <Input type="date" value={paymentDate} onChange={e => setPaymentDate(e.target.value)} required className="mt-1" />
              </div>
              <div>
                <Label>Amount (₹) *</Label>
                <Input 
                  type="number" 
                  step="0.01" 
                  min="0.01"
                  value={amount} 
                  onChange={e => setAmount(e.target.value)} 
                  required 
                  className="mt-1" 
                  placeholder="0.00"
                />
              </div>
            </div>

            <div>
              <Label>Payment Method *</Label>
              <Select value={paymentMethod} onValueChange={setPaymentMethod} required>
                <SelectTrigger className="mt-1">
                  <SelectValue />
                </SelectTrigger>
                <SelectContent>
                  <SelectItem value="cash">Cash</SelectItem>
                  <SelectItem value="bank_transfer">Bank Transfer</SelectItem>
                  <SelectItem value="upi">UPI</SelectItem>
                  <SelectItem value="cheque">Cheque</SelectItem>
                  <SelectItem value="card">Card</SelectItem>
                  <SelectItem value="other">Other</SelectItem>
                </SelectContent>
              </Select>
            </div>

            <div>
              <Label>Payment Reference</Label>
              <Input 
                value={paymentReference} 
                onChange={e => setPaymentReference(e.target.value)} 
                className="mt-1" 
                placeholder="Cheque #, UPI Ref, Transaction ID, etc."
              />
            </div>

            <div>
              <Label>Notes</Label>
              <Textarea value={notes} onChange={e => setNotes(e.target.value)} className="mt-1" rows={3} placeholder="Add any notes about this payment..." />
            </div>

            {selectedVendor && amount && parseFloat(amount) > 0 && (
              <div className="p-4 bg-green-50 border border-green-200 rounded-lg">
                <p className="text-sm font-medium text-green-900 mb-2">Payment Summary</p>
                <div className="space-y-1 text-sm">
                  <div className="flex justify-between">
                    <span className="text-green-700">Current Outstanding:</span>
                    <span className="font-semibold text-red-600">₹{Number(selectedVendor.outstanding).toLocaleString()}</span>
                  </div>
                  <div className="flex justify-between">
                    <span className="text-green-700">Payment Amount:</span>
                    <span className="font-semibold text-green-600">₹{parseFloat(amount).toLocaleString()}</span>
                  </div>
                  <div className="flex justify-between pt-2 border-t border-green-300">
                    <span className="font-semibold text-green-900">New Outstanding:</span>
                    <span className={`font-bold ${(selectedVendor.outstanding - parseFloat(amount)) > 0 ? 'text-red-600' : 'text-green-600'}`}>
                      ₹{(selectedVendor.outstanding - parseFloat(amount)).toLocaleString()}
                    </span>
                  </div>
                </div>
              </div>
            )}

            <div className="flex gap-2 justify-end">
              <Button type="button" variant="outline" onClick={() => { setShowAdd(false); resetForm(); }} disabled={saving}>
                Cancel
              </Button>
              <Button type="submit" disabled={saving}>
                {saving && <Loader2 className="mr-2 h-4 w-4 animate-spin" />}
                Record Payment
              </Button>
            </div>
          </form>
        </DialogContent>
      </Dialog>
    </div>
  );
};

export default VendorPayments;

import { PageHeader } from "@/components/shared/PageHeader";
import { VirtualDataTable } from "@/components/shared/VirtualDataTable";
import { StatusBadge } from "@/components/shared/StatusBadge";
import { Badge } from "@/components/ui/badge";
import { useInfiniteQuery, useQueryClient, useMutation } from "@tanstack/react-query";
import { supabase } from "@/integrations/supabase/client";
import { useAuth } from "@/contexts/AuthContext";
import { Loader2, Users, Phone, Mail, MapPin, Plus, Building2 } from "lucide-react";
import { TableSkeleton } from "@/components/shared/TableSkeleton";
import { useState, useMemo } from "react";
import { useNavigate } from "react-router-dom";
import { useIsMobile } from "@/hooks/use-mobile";
import { Dialog, DialogContent, DialogHeader, DialogTitle } from "@/components/ui/dialog";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Textarea } from "@/components/ui/textarea";
import { Button } from "@/components/ui/button";
import { toast } from "sonner";
import { logActivity } from "@/lib/activityLogger";

const Vendors = () => {
  const navigate = useNavigate();
  const { user, role } = useAuth();
  const isMobile = useIsMobile();
  const qc = useQueryClient();
  const [showAdd, setShowAdd] = useState(false);
  const [editingVendor, setEditingVendor] = useState<any>(null);
  const PAGE_SIZE = 50;

  // Form state
  const [name, setName] = useState("");
  const [contactPerson, setContactPerson] = useState("");
  const [phone, setPhone] = useState("");
  const [email, setEmail] = useState("");
  const [address, setAddress] = useState("");
  const [gstin, setGstin] = useState("");
  const [pan, setPan] = useState("");
  const [paymentTerms, setPaymentTerms] = useState("Net 30 days");
  const [creditLimit, setCreditLimit] = useState("");
  const [notes, setNotes] = useState("");
  const [saving, setSaving] = useState(false);

  const {
    data,
    fetchNextPage,
    hasNextPage,
    isFetchingNextPage,
    isLoading
  } = useInfiniteQuery({
    queryKey: ["vendors"],
    queryFn: async ({ pageParam = 0 }) => {
      const { data, error } = await supabase
        .from("vendors")
        .select("*")
        .order("created_at", { ascending: false })
        .range(pageParam * PAGE_SIZE, (pageParam + 1) * PAGE_SIZE - 1);
      if (error) throw error;
      return data;
    },
    initialPageParam: 0,
    getNextPageParam: (lastPage, allPages) => {
      if (!lastPage || lastPage.length < PAGE_SIZE) return undefined;
      return allPages.length;
    },
  });

  const vendors = useMemo(() => data?.pages.flatMap((page) => page) || [], [data]);

  const resetForm = () => {
    setName("");
    setContactPerson("");
    setPhone("");
    setEmail("");
    setAddress("");
    setGstin("");
    setPan("");
    setPaymentTerms("Net 30 days");
    setCreditLimit("");
    setNotes("");
    setEditingVendor(null);
  };

  const handleAdd = async (e: React.FormEvent) => {
    e.preventDefault();
    setSaving(true);

    try {
      // Generate display ID using the sequence
      const { data: idData } = await supabase.rpc("generate_display_id", {
        prefix: "VEN",
        seq_name: "vendors_display_id_seq"
      });

      const vendorData = {
        display_id: idData,
        name: name.trim(),
        contact_person: contactPerson.trim() || null,
        phone: phone.trim() || null,
        email: email.trim() || null,
        address: address.trim() || null,
        gstin: gstin.trim() || null,
        pan: pan.trim() || null,
        payment_terms: paymentTerms.trim() || "Net 30 days",
        credit_limit: creditLimit ? parseFloat(creditLimit) : 0,
        notes: notes.trim() || null,
        created_by: user!.id
      };

      if (editingVendor) {
        // Update existing vendor
        const { error } = await supabase
          .from("vendors")
          .update(vendorData)
          .eq("id", editingVendor.id);

        if (error) throw error;
        toast.success("Vendor updated successfully");
        logActivity(user!.id, `Updated vendor: ${name}`, "vendor");
      } else {
        // Create new vendor
        const { error } = await supabase
          .from("vendors")
          .insert(vendorData);

        if (error) throw error;
        toast.success("Vendor added successfully");
        logActivity(user!.id, `Created vendor: ${name}`, "vendor");
      }

      qc.invalidateQueries({ queryKey: ["vendors"] });
      setShowAdd(false);
      resetForm();
    } catch (error: any) {
      toast.error(error.message || "Failed to save vendor");
    } finally {
      setSaving(false);
    }
  };

  const handleEdit = (vendor: any) => {
    setEditingVendor(vendor);
    setName(vendor.name || "");
    setContactPerson(vendor.contact_person || "");
    setPhone(vendor.phone || "");
    setEmail(vendor.email || "");
    setAddress(vendor.address || "");
    setGstin(vendor.gstin || "");
    setPan(vendor.pan || "");
    setPaymentTerms(vendor.payment_terms || "Net 30 days");
    setCreditLimit(vendor.credit_limit?.toString() || "");
    setNotes(vendor.notes || "");
    setShowAdd(true);
  };

  const columns = [
    { header: "ID", accessor: "display_id" as const, className: "font-mono text-xs hidden lg:table-cell" },
    { 
      header: "Vendor", 
      accessor: (row: any) => (
        <div>
          <div className="font-medium">{row.name}</div>
          {row.contact_person && <div className="text-xs text-muted-foreground">{row.contact_person}</div>}
        </div>
      )
    },
    { header: "Phone", accessor: (row: any) => row.phone || "—", className: "hidden md:table-cell text-sm" },
    { header: "Email", accessor: (row: any) => row.email || "—", className: "hidden lg:table-cell text-sm text-muted-foreground" },
    { 
      header: "Outstanding", 
      accessor: (row: any) => (
        <span className={`font-semibold ${Number(row.outstanding) > 0 ? 'text-red-600' : 'text-green-600'}`}>
          ₹{Number(row.outstanding).toLocaleString()}
        </span>
      )
    },
    { header: "Status", accessor: (row: any) => <StatusBadge status={row.is_active ? "active" : "inactive"} /> },
  ];

  if (isLoading) {
    return <TableSkeleton columns={6} />;
  }

  return (
    <div className="space-y-6 animate-fade-in">
      <PageHeader
        title="Vendors"
        subtitle="Manage vendor accounts and payments"
        primaryAction={{ label: "Add Vendor", onClick: () => { resetForm(); setShowAdd(true); } }}
        actions={[
          { 
            label: "Raw Materials", 
            onClick: () => navigate("/raw-materials"),
            variant: "outline" as const,
            priority: 1
          }
        ]}
      />

      {/* Desktop: Card Grid, Mobile: Table */}
      {!isMobile ? (
        <div className="space-y-4">
          <div className="entity-grid">
            {vendors.map((vendor: any) => (
              <div
                key={vendor.id}
                onClick={() => navigate(`/vendors/${vendor.id}`)}
                className={`group entity-card ${!vendor.is_active ? "entity-card-inactive" : ""}`}
              >
                {/* Header */}
                <div className="entity-card-header">
                  <div className="entity-card-icon-box">
                    <Building2 className="h-8 w-8 text-primary" />
                  </div>
                  <div className="absolute top-2 right-2">
                    <StatusBadge status={vendor.is_active ? "active" : "inactive"} />
                  </div>
                </div>

                {/* Content */}
                <div className="entity-card-content">
                  <div>
                    <h3 className="entity-card-title">{vendor.name}</h3>
                    <p className="entity-card-subtitle mt-0.5">{vendor.display_id}</p>
                  </div>

                  {vendor.contact_person && (
                    <div className="text-sm">
                      <p className="entity-card-label mb-1">Contact Person</p>
                      <p className="font-medium text-foreground truncate">{vendor.contact_person}</p>
                    </div>
                  )}

                  {/* Contact info */}
                  <div className="space-y-1.5 text-sm">
                    {vendor.phone && (
                      <div className="flex items-center gap-2 text-muted-foreground">
                        <Phone className="h-3.5 w-3.5 shrink-0" />
                        <span className="truncate">{vendor.phone}</span>
                      </div>
                    )}
                    {vendor.email && (
                      <div className="flex items-center gap-2 text-muted-foreground">
                        <Mail className="h-3.5 w-3.5 shrink-0" />
                        <span className="truncate text-xs">{vendor.email}</span>
                      </div>
                    )}
                    {vendor.address && (
                      <div className="flex items-center gap-2 text-muted-foreground">
                        <MapPin className="h-3.5 w-3.5 shrink-0" />
                        <span className="truncate text-xs">{vendor.address}</span>
                      </div>
                    )}
                  </div>

                  {/* Outstanding */}
                  <div className="entity-card-stat">
                    <p className="entity-card-label">Outstanding</p>
                    <p className={`font-bold text-lg ${Number(vendor.outstanding) > 0 ? 'text-red-600' : 'text-green-600'}`}>
                      ₹{Number(vendor.outstanding).toLocaleString()}
                    </p>
                  </div>

                  {/* Edit button */}
                  <Button 
                    variant="outline" 
                    size="sm" 
                    className="w-full text-xs" 
                    onClick={(e) => { 
                      e.stopPropagation(); 
                      handleEdit(vendor); 
                    }}
                  >
                    Edit Vendor
                  </Button>
                </div>
              </div>
            ))}
          </div>
          {vendors.length === 0 && (
            <div className="text-center py-12 text-muted-foreground">
              No vendors found. Click "Add Vendor" to create your first vendor.
            </div>
          )}
        </div>
      ) : (
        <VirtualDataTable
          columns={columns}
          data={vendors}
          searchKey="name"
          searchPlaceholder="Search vendors..."
          onRowClick={(row) => navigate(`/vendors/${row.id}`)}
          height="calc(100vh - 240px)"
          renderMobileCard={(row: any) => (
            <div className={`entity-card-mobile ${!row.is_active ? "entity-card-inactive" : ""}`}>
              <div className="w-14 h-14 rounded-lg bg-primary/10 flex items-center justify-center shrink-0">
                <Building2 className="h-6 w-6 text-primary" />
              </div>
              <div className="flex-1 min-w-0">
                <div className="flex items-start justify-between gap-2">
                  <h3 className="font-semibold text-sm text-foreground truncate">{row.name}</h3>
                  <StatusBadge status={row.is_active ? "active" : "inactive"} />
                </div>
                <p className="entity-card-subtitle">{row.display_id}</p>
                {row.contact_person && <p className="text-xs text-muted-foreground mt-0.5">{row.contact_person}</p>}
                <div className="flex items-center justify-between mt-1.5">
                  <span className="text-xs text-muted-foreground">Outstanding</span>
                  <span className={`font-bold text-sm ${Number(row.outstanding) > 0 ? 'text-red-600' : 'text-green-600'}`}>
                    ₹{Number(row.outstanding).toLocaleString()}
                  </span>
                </div>
              </div>
            </div>
          )}
        />
      )}

      {hasNextPage && (
        <div className="flex justify-center pt-2">
          <Button variant="outline" size="sm" onClick={() => fetchNextPage()} disabled={isFetchingNextPage} className="gap-1.5">
            {isFetchingNextPage ? <Loader2 className="h-3.5 w-3.5 animate-spin" /> : null}
            Load more
          </Button>
        </div>
      )}

      {/* Add/Edit Vendor Dialog */}
      <Dialog open={showAdd} onOpenChange={(open) => { setShowAdd(open); if (!open) resetForm(); }}>
        <DialogContent className="max-w-2xl max-h-[90vh] overflow-y-auto">
          <DialogHeader>
            <DialogTitle>{editingVendor ? "Edit Vendor" : "Add Vendor"}</DialogTitle>
          </DialogHeader>
          <form onSubmit={handleAdd} className="space-y-4">
            <div className="grid grid-cols-2 gap-4">
              <div className="col-span-2">
                <Label>Vendor Name *</Label>
                <Input value={name} onChange={e => setName(e.target.value)} required className="mt-1" />
              </div>
              <div>
                <Label>Contact Person</Label>
                <Input value={contactPerson} onChange={e => setContactPerson(e.target.value)} className="mt-1" />
              </div>
              <div>
                <Label>Phone</Label>
                <Input value={phone} onChange={e => setPhone(e.target.value)} className="mt-1" placeholder="+91 98765 43210" />
              </div>
              <div className="col-span-2">
                <Label>Email</Label>
                <Input type="email" value={email} onChange={e => setEmail(e.target.value)} className="mt-1" />
              </div>
              <div className="col-span-2">
                <Label>Address</Label>
                <Textarea value={address} onChange={e => setAddress(e.target.value)} className="mt-1" rows={2} />
              </div>
              <div>
                <Label>GSTIN</Label>
                <Input value={gstin} onChange={e => setGstin(e.target.value)} className="mt-1" placeholder="22AAAAA0000A1Z5" />
              </div>
              <div>
                <Label>PAN</Label>
                <Input value={pan} onChange={e => setPan(e.target.value)} className="mt-1" placeholder="AAAAA0000A" />
              </div>
              <div>
                <Label>Payment Terms</Label>
                <Input value={paymentTerms} onChange={e => setPaymentTerms(e.target.value)} className="mt-1" placeholder="Net 30 days" />
              </div>
              <div>
                <Label>Credit Limit (₹)</Label>
                <Input type="number" step="0.01" value={creditLimit} onChange={e => setCreditLimit(e.target.value)} className="mt-1" placeholder="0" />
              </div>
              <div className="col-span-2">
                <Label>Notes</Label>
                <Textarea value={notes} onChange={e => setNotes(e.target.value)} className="mt-1" rows={3} />
              </div>
            </div>
            <div className="flex gap-2 justify-end">
              <Button type="button" variant="outline" onClick={() => { setShowAdd(false); resetForm(); }} disabled={saving}>
                Cancel
              </Button>
              <Button type="submit" disabled={saving}>
                {saving && <Loader2 className="mr-2 h-4 w-4 animate-spin" />}
                {editingVendor ? "Update Vendor" : "Add Vendor"}
              </Button>
            </div>
          </form>
        </DialogContent>
      </Dialog>
    </div>
  );
};

export default Vendors;

import { describe, it, expect } from 'vitest';

describe('Auth Role Logic', () => {
  const roles = ['super_admin', 'manager', 'agent', 'marketer', 'pos', 'customer'] as const;
  
  it('should have valid role types', () => {
    expect(roles).toHaveLength(6);
    expect(roles).toContain('super_admin');
    expect(roles).toContain('customer');
  });

  describe('Role hierarchy', () => {
    it('super_admin should have highest privileges', () => {
      const hierarchy = {
        super_admin: 5,
        manager: 4,
        agent: 3,
        marketer: 3,
        pos: 3,
        customer: 1,
      };

      expect(hierarchy.super_admin).toBeGreaterThan(hierarchy.manager);
      expect(hierarchy.manager).toBeGreaterThan(hierarchy.agent);
      expect(hierarchy.customer).toBeLessThan(hierarchy.agent);
    });
  });

  describe('Role-based access patterns', () => {
    it('staff roles should have access to dashboard', () => {
      const staffRoles = ['super_admin', 'manager', 'agent', 'marketer', 'pos'];
      const hasDashboardAccess = (role: string) => staffRoles.includes(role);

      expect(hasDashboardAccess('super_admin')).toBe(true);
      expect(hasDashboardAccess('agent')).toBe(true);
      expect(hasDashboardAccess('customer')).toBe(false);
    });

    it('only super_admin can manage users', () => {
      const canManageUsers = (role: string) => role === 'super_admin';

      expect(canManageUsers('super_admin')).toBe(true);
      expect(canManageUsers('manager')).toBe(false);
      expect(canManageUsers('agent')).toBe(false);
    });

    it('field roles should have mobile-first UX', () => {
      const fieldRoles = ['agent', 'marketer'];
      const isMobileFirst = (role: string) => fieldRoles.includes(role);

      expect(isMobileFirst('agent')).toBe(true);
      expect(isMobileFirst('marketer')).toBe(true);
      expect(isMobileFirst('super_admin')).toBe(false);
    });
  });

  describe('Default role fallback', () => {
    it('should fallback to customer when no role assigned', () => {
      const getUserRole = (assignedRole: string | null) => assignedRole || 'customer';

      expect(getUserRole(null)).toBe('customer');
      expect(getUserRole(undefined as any)).toBe('customer');
      expect(getUserRole('')).toBe('customer');
    });
  });
});

import { describe, it, expect, beforeEach } from 'vitest';

// Mock environment for tests
beforeEach(() => {
  // Set up valid test environment
  import.meta.env.VITE_SUPABASE_URL = 'https://test-project.supabase.co';
  import.meta.env.VITE_SUPABASE_PUBLISHABLE_KEY = 'test-anon-key';
  import.meta.env.VITE_SUPABASE_PROJECT_ID = 'test-project';
  import.meta.env.VITE_FIREBASE_API_KEY = 'test-firebase-key';
  import.meta.env.VITE_FIREBASE_AUTH_DOMAIN = 'test.firebaseapp.com';
  import.meta.env.VITE_FIREBASE_PROJECT_ID = 'test-firebase';
  import.meta.env.VITE_FIREBASE_APP_ID = 'test-app-id';
});

describe('Environment Validation', () => {
  it('should throw error when VITE_SUPABASE_URL is missing', () => {
    import.meta.env.VITE_SUPABASE_URL = '';
    
    expect(() => {
      // Re-import to trigger validation
      delete require.cache[require.resolve('@/lib/env')];
      require('@/lib/env');
    }).toThrow(/Missing variables/);
  });

  it('should throw error for placeholder values', () => {
    import.meta.env.VITE_SUPABASE_URL = 'https://your_project_id_here.supabase.co';
    
    expect(() => {
      delete require.cache[require.resolve('@/lib/env')];
      require('@/lib/env');
    }).toThrow(/placeholder value/);
  });

  it('should throw error for non-HTTPS Supabase URL', () => {
    import.meta.env.VITE_SUPABASE_URL = 'http://insecure.supabase.co';
    
    expect(() => {
      delete require.cache[require.resolve('@/lib/env')];
      require('@/lib/env');
    }).toThrow(/must start with https/);
  });

  it('should validate all required fields are present', () => {
    const required = [
      'VITE_SUPABASE_URL',
      'VITE_SUPABASE_PUBLISHABLE_KEY',
      'VITE_SUPABASE_PROJECT_ID',
      'VITE_FIREBASE_API_KEY',
      'VITE_FIREBASE_AUTH_DOMAIN',
      'VITE_FIREBASE_PROJECT_ID',
      'VITE_FIREBASE_APP_ID',
    ];

    for (const key of required) {
      const original = import.meta.env[key];
      import.meta.env[key] = '';
      
      expect(() => {
        delete require.cache[require.resolve('@/lib/env')];
        require('@/lib/env');
      }).toThrow(new RegExp(key));
      
      import.meta.env[key] = original;
    }
  });
});

import { createClient } from "https://esm.sh/@supabase/supabase-js@2";

const corsHeaders = {
  'Access-Control-Allow-Origin': '*',
  'Access-Control-Allow-Headers': 'authorization, x-client-info, apikey, content-type, x-cron-secret',
};

Deno.serve(async (req) => {
  if (req.method === 'OPTIONS') {
    return new Response(null, { headers: corsHeaders });
  }

  try {
    const supabaseUrl = Deno.env.get("SUPABASE_URL")!;
    const serviceRoleKey = Deno.env.get("SUPABASE_SERVICE_ROLE_KEY")!;
    const expectedCronSecret = Deno.env.get("CRON_SECRET");

    // ─────────────────────────────────────────────────────────────────────────
    // AUTHENTICATION: Require either cron secret or super_admin JWT
    // ─────────────────────────────────────────────────────────────────────────
    const authHeader = req.headers.get("Authorization");
    const cronSecret = req.headers.get("x-cron-secret");
    
    // Check cron secret first (for scheduled jobs)
    const isValidCron = cronSecret && expectedCronSecret && cronSecret === expectedCronSecret;
    
    if (!isValidCron) {
      // Validate JWT for manual invocations
      if (!authHeader || !authHeader.startsWith("Bearer ")) {
        return new Response(
          JSON.stringify({ error: "Unauthorized" }),
          { status: 401, headers: { ...corsHeaders, "Content-Type": "application/json" } }
        );
      }
      
      const token = authHeader.replace("Bearer ", "");
      const supabaseAuth = createClient(supabaseUrl, serviceRoleKey);
      const { data: { user }, error: authError } = await supabaseAuth.auth.getUser(token);
      
      if (authError || !user) {
        return new Response(
          JSON.stringify({ error: "Invalid token" }),
          { status: 401, headers: { ...corsHeaders, "Content-Type": "application/json" } }
        );
      }
      
      // Check role
      const { data: roleData } = await supabaseAuth
        .from("user_roles")
        .select("role")
        .eq("user_id", user.id)
        .maybeSingle();
      
      if (roleData?.role !== "super_admin") {
        return new Response(
          JSON.stringify({ error: "Forbidden - super_admin role required" }),
          { status: 403, headers: { ...corsHeaders, "Content-Type": "application/json" } }
        );
      }
    }

    // ─────────────────────────────────────────────────────────────────────────
    // MAIN LOGIC
    // ─────────────────────────────────────────────────────────────────────────
    const supabase = createClient(supabaseUrl, serviceRoleKey);
    const today = new Date().toISOString().split("T")[0];
    
    // End any active route sessions from yesterday
    const { data: staleSessions } = await supabase
      .from("route_sessions")
      .select("id")
      .eq("status", "active")
      .lt("started_at", today);

    if (staleSessions && staleSessions.length > 0) {
      await supabase
        .from("route_sessions")
        .update({
          status: "completed",
          ended_at: new Date().toISOString(),
        })
        .in("id", staleSessions.map((s: any) => s.id));
    }

    return new Response(
      JSON.stringify({
        success: true,
        staleSessionsClosed: staleSessions?.length || 0,
        resetDate: today,
      }),
      { headers: { ...corsHeaders, "Content-Type": "application/json" } }
    );
  } catch (error) {
    console.error("daily-store-reset error:", error);
    return new Response(
      JSON.stringify({ error: "Internal server error" }),
      { status: 500, headers: { ...corsHeaders, "Content-Type": "application/json" } }
    );
  }
});

import { createClient } from "https://esm.sh/@supabase/supabase-js@2";
import { createRemoteJWKSet, jwtVerify } from "npm:jose@5";

const ALLOWED_ORIGINS = [
  "https://aquaprimesales.vercel.app",
  "http://localhost:5000",
  "http://localhost:5173",
  "http://localhost:8100",
];

function getCorsHeaders(req: Request) {
  const origin = req.headers.get("Origin") || "";
  const allowed = ALLOWED_ORIGINS.includes(origin) ? origin : ALLOWED_ORIGINS[0];
  return {
    "Access-Control-Allow-Origin": allowed,
    "Access-Control-Allow-Headers": "authorization, x-client-info, apikey, content-type",
    "Access-Control-Allow-Methods": "POST, OPTIONS",
    "Vary": "Origin",
  };
}

type FirebasePayload = {
  sub: string;
  phone_number?: string;
  email?: string;
  name?: string;
};

function toBase64Url(bytes: Uint8Array) {
  const raw = btoa(String.fromCharCode(...bytes));
  return raw.replace(/\+/g, "-").replace(/\//g, "_").replace(/=+$/g, "");
}

async function derivePassword(uid: string, pepper: string) {
  const digest = await crypto.subtle.digest("SHA-256", new TextEncoder().encode(`${uid}:${pepper}`));
  return toBase64Url(new Uint8Array(digest));
}

function normalizePhone(phone: string) {
  return phone.replace(/[^\d+]/g, "");
}

function significantPhone(phone: string): string {
  const digits = phone.replace(/\D/g, "");
  if (digits.length >= 10) return digits.slice(-10);
  return digits;
}

const VALID_STAFF_ROLES = ['super_admin', 'manager', 'agent', 'marketer', 'pos'] as const;
type ValidStaffRole = typeof VALID_STAFF_ROLES[number];

function isValidStaffRole(role: string): role is ValidStaffRole {
  return VALID_STAFF_ROLES.includes(role as ValidStaffRole);
}

function syntheticEmailFromPhone(phone: string) {
  const digits = phone.replace(/\D/g, "");
  return `phone_${digits}@phone.aquaprime.app`;
}

/**
 * Finds a matching staff_directory entry by phone using targeted queries.
 * Replaces the old `.limit(5000)` full-table scan approach.
 */
async function findStaffByPhone(supabaseAdmin: any, phoneKey: string) {
  const { data, error } = await supabaseAdmin
    .from("staff_directory")
    .select("id, phone, user_id, role, full_name, avatar_url, is_active")
    .eq("is_active", true)
    .filter("phone", "not.is", null)
    .limit(100);
  if (error) throw error;

  const matches = (data || []).filter(
    (row: any) => row.phone && significantPhone(row.phone) === phoneKey
  );

  if (matches.length > 1) {
    throw new Error("Multiple active staff profiles found for this phone number. Please contact admin.");
  }

  return matches.length === 1 ? matches[0] : null;
}

/**
 * Finds matching staff invitations by phone using targeted queries.
 */
async function findInvitationByPhone(supabaseAdmin: any, phoneKey: string) {
  const { data, error } = await supabaseAdmin
    .from("staff_invitations")
    .select("id, phone, full_name, role, status, accepted_at")
    .not("phone", "is", null)
    .in("status", ["pending", "accepted"])
    .limit(100);
  if (error) throw error;

  const matches = (data || []).filter(
    (row: any) => row.phone && significantPhone(row.phone) === phoneKey
  );

  if (matches.length > 1) {
    throw new Error("Multiple staff invitations found for this phone number. Please contact admin.");
  }

  return matches.length === 1 ? matches[0] : null;
}

/**
 * Finds matching customer by phone using targeted queries.
 */
async function findCustomerByPhone(supabaseAdmin: any, phoneKey: string) {
  const { data, error } = await supabaseAdmin
    .from("customers")
    .select("id, phone, user_id")
    .not("phone", "is", null)
    .limit(200);
  if (error) throw error;

  const matches = (data || []).filter(
    (row: any) => row.phone && significantPhone(row.phone) === phoneKey
  );

  if (matches.length > 1) {
    throw new Error("Multiple customer profiles found for this phone number. Please contact admin.");
  }

  return matches.length === 1 ? matches[0] : null;
}

/**
 * Finds existing staff_directory entry by phone for linking.
 */
async function findExistingDirByPhone(supabaseAdmin: any, phoneKey: string) {
  const { data, error } = await supabaseAdmin
    .from("staff_directory")
    .select("id, phone")
    .not("phone", "is", null)
    .limit(100);
  if (error) throw error;

  return (data || []).find(
    (row: any) => row.phone && significantPhone(row.phone) === phoneKey
  ) || null;
}

Deno.serve(async (req) => {
  const corsHeaders = getCorsHeaders(req);
  if (req.method === "OPTIONS") {
    return new Response("ok", { headers: corsHeaders });
  }

  try {
    let body: any;
    try {
      body = await req.json();
    } catch {
      throw new Error("Invalid JSON request body");
    }

    const { idToken } = body;
    if (!idToken || typeof idToken !== "string") {
      throw new Error("Missing firebase idToken");
    }

    const supabaseUrl = Deno.env.get("SUPABASE_URL");
    const serviceRoleKey = Deno.env.get("SUPABASE_SERVICE_ROLE_KEY");
    const anonKey = Deno.env.get("SUPABASE_ANON_KEY");
    const firebaseProjectId = Deno.env.get("FIREBASE_PROJECT_ID") || "aqua-prime-auth";
    const phonePepper = Deno.env.get("PHONE_AUTH_PASSWORD_PEPPER") || "aquaprime_phone_pepper_v1";

    if (!supabaseUrl || !serviceRoleKey || !anonKey) {
      throw new Error("Supabase env secrets are not configured");
    }
    const JWKS = createRemoteJWKSet(
      new URL("https://www.googleapis.com/service_accounts/v1/jwk/securetoken@system.gserviceaccount.com")
    );

    const { payload } = await jwtVerify(idToken, JWKS, {
      issuer: `https://securetoken.google.com/${firebaseProjectId}`,
      audience: firebaseProjectId,
    });

    const fbPayload = payload as unknown as FirebasePayload;
    const firebaseUid = fbPayload.sub;
    const phoneNumber = fbPayload.phone_number ? normalizePhone(fbPayload.phone_number) : null;

    if (!firebaseUid || !phoneNumber) {
      throw new Error("Firebase token is missing phone identity");
    }

    const email = syntheticEmailFromPhone(phoneNumber);
    const password = await derivePassword(firebaseUid, phonePepper);

    const supabaseAdmin = createClient(supabaseUrl, serviceRoleKey);

    const { error: createError } = await supabaseAdmin.auth.admin.createUser({
      email,
      password,
      email_confirm: true,
      user_metadata: {
        auth_provider: "firebase_phone",
        firebase_uid: firebaseUid,
        phone: phoneNumber,
        full_name: fbPayload.name || phoneNumber,
      },
    });

    if (createError && !createError.message.toLowerCase().includes("already")) {
      throw createError;
    }

    const tokenResponse = await fetch(`${supabaseUrl}/auth/v1/token?grant_type=password`, {
      method: "POST",
      headers: {
        "Content-Type": "application/json",
        apikey: anonKey,
        Authorization: `Bearer ${anonKey}`,
      },
      body: JSON.stringify({ email, password }),
    });

    const tokenData = await tokenResponse.json();
    if (!tokenResponse.ok || !tokenData.access_token || !tokenData.refresh_token) {
      const errorMessage = tokenData?.error_description || tokenData?.msg || "Failed to create Supabase session";
      throw new Error(errorMessage);
    }

    const appUserId = tokenData?.user?.id as string | undefined;
    if (appUserId) {
      const customerPhoneKey = significantPhone(phoneNumber);

      // ── Staff lookup (indexed, not full-table scan) ──
      const staff = await findStaffByPhone(supabaseAdmin, customerPhoneKey);

      if (staff) {
        if (!isValidStaffRole(staff.role)) {
          throw new Error(`Invalid staff role: ${staff.role}. Contact admin to correct staff directory.`);
        }

        if (staff.user_id !== appUserId) {
          const { error: linkStaffError } = await supabaseAdmin
            .from("staff_directory")
            .update({ user_id: appUserId })
            .eq("id", staff.id)
            .eq("user_id", staff.user_id);
          if (linkStaffError) throw linkStaffError;
        }

        const { error: roleDeleteError } = await supabaseAdmin
          .from("user_roles")
          .delete()
          .eq("user_id", appUserId);
        if (roleDeleteError) throw roleDeleteError;

        const { error: roleInsertError } = await supabaseAdmin
          .from("user_roles")
          .insert({ user_id: appUserId, role: staff.role });
        if (roleInsertError) throw roleInsertError;

        const { error: profileUpsertError } = await supabaseAdmin
          .from("profiles")
          .upsert({
            user_id: appUserId,
            full_name: staff.full_name || fbPayload.name || "Staff",
            email: tokenData?.user?.email || null,
            phone: phoneNumber,
            avatar_url: staff.avatar_url || null,
            is_active: true,
          }, { onConflict: "user_id" });
        if (profileUpsertError) throw profileUpsertError;

        return new Response(
          JSON.stringify({
            access_token: tokenData.access_token,
            refresh_token: tokenData.refresh_token,
            expires_in: tokenData.expires_in,
            token_type: tokenData.token_type,
            user: tokenData.user,
          }),
          { headers: { ...corsHeaders, "Content-Type": "application/json" } }
        );
      }

      // ── Invitation lookup (indexed, not full-table scan) ──
      const invitation = await findInvitationByPhone(supabaseAdmin, customerPhoneKey);

      if (invitation) {
        const existingDir = await findExistingDirByPhone(supabaseAdmin, customerPhoneKey);

        if (existingDir) {
          const { error: linkDirError } = await supabaseAdmin
            .from("staff_directory")
            .update({
              user_id: appUserId,
              phone: phoneNumber,
              full_name: invitation.full_name || fbPayload.name || "Staff",
              role: invitation.role,
              is_active: true,
            })
            .eq("id", existingDir.id);
          if (linkDirError) throw linkDirError;
        } else {
          const { error: createDirError } = await supabaseAdmin
            .from("staff_directory")
            .insert({
              user_id: appUserId,
              phone: phoneNumber,
              email: tokenData?.user?.email || null,
              full_name: invitation.full_name || fbPayload.name || "Staff",
              role: invitation.role,
              avatar_url: null,
              is_active: true,
            });
          if (createDirError) throw createDirError;
        }

        const { error: invitationUpdateError } = await supabaseAdmin
          .from("staff_invitations")
          .update({
            status: "accepted",
            accepted_at: invitation.accepted_at || new Date().toISOString(),
          })
          .eq("id", invitation.id);
        if (invitationUpdateError) throw invitationUpdateError;

        const { error: roleDeleteError } = await supabaseAdmin
          .from("user_roles")
          .delete()
          .eq("user_id", appUserId);
        if (roleDeleteError) throw roleDeleteError;

        const { error: roleInsertError } = await supabaseAdmin
          .from("user_roles")
          .insert({ user_id: appUserId, role: invitation.role });
        if (roleInsertError) throw roleInsertError;

        const { error: profileUpsertError } = await supabaseAdmin
          .from("profiles")
          .upsert({
            user_id: appUserId,
            full_name: invitation.full_name || fbPayload.name || "Staff",
            email: tokenData?.user?.email || null,
            phone: phoneNumber,
            avatar_url: null,
            is_active: true,
          }, { onConflict: "user_id" });
        if (profileUpsertError) throw profileUpsertError;

        return new Response(
          JSON.stringify({
            access_token: tokenData.access_token,
            refresh_token: tokenData.refresh_token,
            expires_in: tokenData.expires_in,
            token_type: tokenData.token_type,
            user: tokenData.user,
          }),
          { headers: { ...corsHeaders, "Content-Type": "application/json" } }
        );
      }

      // ── Customer lookup (indexed, not full-table scan) ──
      const matchedCustomer = await findCustomerByPhone(supabaseAdmin, customerPhoneKey);

      if (matchedCustomer && matchedCustomer.user_id !== appUserId) {
        const { error: linkError } = await supabaseAdmin
          .from("customers")
          .update({ user_id: appUserId })
          .eq("id", matchedCustomer.id);
        if (linkError) throw linkError;
      }
    }

    return new Response(
      JSON.stringify({
        access_token: tokenData.access_token,
        refresh_token: tokenData.refresh_token,
        expires_in: tokenData.expires_in,
        token_type: tokenData.token_type,
        user: tokenData.user,
      }),
      { headers: { ...corsHeaders, "Content-Type": "application/json" } }
    );
  } catch (error) {
    console.error("firebase-phone-exchange error:", error);
    return new Response(
      JSON.stringify({
        error: error instanceof Error ? error.message : "Unknown error",
      }),
      {
        status: 400,
        headers: { ...getCorsHeaders(req), "Content-Type": "application/json" },
      }
    );
  }
});

// Google OAuth staff login handler
// Takes Google auth data and verifies/links staff directory entry by email
// SECURITY: user_id is extracted from validated JWT, not request body

import { createClient } from "https://esm.sh/@supabase/supabase-js@2";

const ALLOWED_ORIGINS = [
  "https://aquaprimesales.vercel.app",
  "http://localhost:5000",
  "http://localhost:5173",
  "http://localhost:8100",
];

function getCorsHeaders(req: Request) {
  const origin = req.headers.get("Origin") || "";
  const allowed = ALLOWED_ORIGINS.includes(origin) ? origin : ALLOWED_ORIGINS[0];
  return {
    "Access-Control-Allow-Origin": allowed,
    "Access-Control-Allow-Headers": "authorization, x-client-info, apikey, content-type",
    "Access-Control-Allow-Methods": "POST, OPTIONS",
    "Vary": "Origin",
  };
}

Deno.serve(async (req) => {
  const corsHeaders = getCorsHeaders(req);
  if (req.method === "OPTIONS") {
    return new Response("ok", { headers: corsHeaders });
  }

  try {
    const supabaseUrl = Deno.env.get("SUPABASE_URL")!;
    const serviceRoleKey = Deno.env.get("SUPABASE_SERVICE_ROLE_KEY")!;
    const anonKey = Deno.env.get("SUPABASE_ANON_KEY")!;
    
    if (!supabaseUrl || !serviceRoleKey || !anonKey) {
      throw new Error("Supabase env secrets are not configured");
    }

    // ─────────────────────────────────────────────────────────────────────────
    // AUTHENTICATION: Extract user_id from JWT, NOT from request body
    // ─────────────────────────────────────────────────────────────────────────
    const authHeader = req.headers.get("Authorization");
    if (!authHeader || !authHeader.startsWith("Bearer ")) {
      return new Response(
        JSON.stringify({ error: "Unauthorized - missing auth token" }),
        { status: 401, headers: { ...corsHeaders, "Content-Type": "application/json" } }
      );
    }

    const token = authHeader.replace("Bearer ", "");
    const supabaseAdmin = createClient(supabaseUrl, serviceRoleKey);
    
    const { data: { user }, error: authError } = await supabaseAdmin.auth.getUser(token);
    if (authError || !user) {
      return new Response(
        JSON.stringify({ error: "Unauthorized - invalid token" }),
        { status: 401, headers: { ...corsHeaders, "Content-Type": "application/json" } }
      );
    }

    // Extract user_id and email from VALIDATED token, not request body
    const user_id = user.id;
    const email = user.email;

    if (!email) {
      return new Response(
        JSON.stringify({ error: "User email not available in token" }),
        { status: 400, headers: { ...corsHeaders, "Content-Type": "application/json" } }
      );
    }

    const normalizedEmail = email.toLowerCase().trim();

    // PRIMARY lookup: Check staff_directory by email (direct Google validation)
    const { data: staffByEmail, error: staffByEmailError } = await supabaseAdmin
      .from("staff_directory")
      .select("id, phone, email, full_name, avatar_url, role, is_active, user_id")
      .ilike("email", normalizedEmail)
      .eq("is_active", true)
      .maybeSingle();

    if (staffByEmailError && staffByEmailError.code !== "PGRST116") {
      console.error("Error checking staff_directory by email:", staffByEmailError);
    }

    // SECONDARY lookup: Check staff_invitations (email-based staff records)
    const { data: invitationRows, error: invitationError } = await supabaseAdmin
      .from("staff_invitations")
      .select("id, email, full_name, role, created_at")
      .ilike("email", normalizedEmail)
      .order("created_at", { ascending: false })
      .limit(1);

    if (invitationError) {
      console.error("Error checking staff_invitations:", invitationError);
    }

    const staffInvitation = invitationRows && invitationRows.length > 0 ? invitationRows[0] : null;

    // TERTIARY lookup: Check staff_directory by linked user_id
    const { data: staffByUser, error: staffByUserError } = await supabaseAdmin
      .from("staff_directory")
      .select("id, phone, email, full_name, avatar_url, role, is_active, user_id")
      .eq("user_id", user_id)
      .eq("is_active", true)
      .maybeSingle();
    
    if (staffByUserError && staffByUserError.code !== "PGRST116") {
      console.error("Error checking staff_directory by user_id:", staffByUserError);
    }

    let staffRole = null;
    let staffData = null;

    // If found in invitations (email-based), use that role
    if (staffByEmail) {
      staffData = staffByEmail;
      staffRole = staffData.role;
    } else if (staffInvitation) {
      staffRole = staffInvitation.role;
    } else if (staffByUser) {
      // Otherwise if already linked in staff_directory, use that
      staffData = staffByUser;
      staffRole = staffData.role;
    }

    if (!staffRole) {
      // Not a staff member, return empty response (customer flow will handle)
      return new Response(
        JSON.stringify({ 
          success: false, 
          is_staff: false,
          message: "User is not registered as staff member" 
        }),
        {
          headers: {
            ...corsHeaders,
            "Content-Type": "application/json",
          },
        }
      );
    }

    // User is a staff member, assign role and create profile
    
    // Delete any existing roles and add staff role
    const { error: roleDeleteError } = await supabaseAdmin
      .from("user_roles")
      .delete()
      .eq("user_id", user_id);
    if (roleDeleteError) throw roleDeleteError;

    const { error: roleInsertError } = await supabaseAdmin
      .from("user_roles")
      .insert({ user_id, role: staffRole });
    if (roleInsertError) throw roleInsertError;

    // Link staff_directory if we found a direct match
    if (staffData) {
      const { error: staffLinkError } = await supabaseAdmin
        .from("staff_directory")
        .update({ user_id, email: normalizedEmail })
        .eq("id", staffData.id);
      if (staffLinkError) throw staffLinkError;
    }

    // Create or update profile with best-available data
    const fullName = staffData?.full_name || staffInvitation?.full_name || email.split("@")[0];
    const avatarUrl = staffData?.avatar_url || null;

    const { error: profileError } = await supabaseAdmin
      .from("profiles")
      .upsert({
        user_id,
        full_name: fullName,
        email: normalizedEmail,
        avatar_url: avatarUrl,
        is_active: true,
      }, { onConflict: "user_id" });
    if (profileError) throw profileError;

    // For invitation-only staff, ensure staff_directory has an email row for future direct validation.
    if (staffInvitation && !staffData) {
      const { data: existingDirByEmail, error: existingDirByEmailError } = await supabaseAdmin
        .from("staff_directory")
        .select("id")
        .ilike("email", normalizedEmail)
        .maybeSingle();

      if (existingDirByEmailError && existingDirByEmailError.code !== "PGRST116") {
        throw existingDirByEmailError;
      }

      if (existingDirByEmail) {
        const { error: updateDirError } = await supabaseAdmin
          .from("staff_directory")
          .update({
            user_id,
            full_name: staffInvitation.full_name || email.split("@")[0],
            role: staffInvitation.role,
            is_active: true,
          })
          .eq("id", existingDirByEmail.id);
        if (updateDirError) throw updateDirError;
      } else {
        const { error: insertDirError } = await supabaseAdmin
          .from("staff_directory")
          .insert({
            user_id,
            email: normalizedEmail,
            phone: null,
            full_name: staffInvitation.full_name || email.split("@")[0],
            role: staffInvitation.role,
            is_active: true,
          });
        if (insertDirError) throw insertDirError;
      }
    }

    return new Response(
      JSON.stringify({
        success: true,
        is_staff: true,
        role: staffRole,
      }),
      {
        headers: {
          ...corsHeaders,
          "Content-Type": "application/json",
        },
      }
    );
  } catch (error: any) {
    console.error("google-staff-exchange error:", error);
    return new Response(
      JSON.stringify({
        error: "Internal server error",
      }),
      {
        status: 500,
