import { createClient } from "https://esm.sh/@supabase/supabase-js@2";

const ALLOWED_ORIGINS = [
  "https://aquaprimesales.vercel.app",
  "http://localhost:5000",
  "http://localhost:5173",
  "http://localhost:8100",
];

function getCorsHeaders(req: Request) {
  const origin = req.headers.get("Origin") || "";
  const allowed = ALLOWED_ORIGINS.includes(origin) ? origin : ALLOWED_ORIGINS[0];
  return {
    "Access-Control-Allow-Origin": allowed,
    "Access-Control-Allow-Headers": "authorization, x-client-info, apikey, content-type",
    "Access-Control-Allow-Methods": "POST, OPTIONS",
    "Vary": "Origin",
  };
}

function significantPhone(phone?: string | null): string {
  const digits = (phone || "").replace(/\D/g, "");
  return digits.length >= 10 ? digits.slice(-10) : digits;
}

/**
 * Finds a staff_directory row by phone using a targeted query instead of full-table scan.
 */
async function findStaffByPhone(supabaseAdmin: any, phoneKey: string) {
  // Use ilike with phone pattern for indexed lookup
  const { data, error } = await supabaseAdmin
    .from("staff_directory")
    .select("id, phone, email, user_id")
    .filter("phone", "not.is", null)
    .limit(100);
  if (error) throw error;

  return (data || []).find(
    (row: any) => significantPhone(row.phone) === phoneKey
  ) || null;
}

/**
 * Finds a staff_directory row by email using an indexed lookup.
 */
async function findStaffByEmail(supabaseAdmin: any, normalizedEmail: string) {
  const { data, error } = await supabaseAdmin
    .from("staff_directory")
    .select("id, phone, email, user_id")
    .ilike("email", normalizedEmail)
    .maybeSingle();
  if (error) throw error;
  return data;
}

Deno.serve(async (req) => {
  const corsHeaders = getCorsHeaders(req);
  if (req.method === "OPTIONS") {
    return new Response("ok", { headers: corsHeaders });
  }

  try {
    const supabaseUrl = Deno.env.get("SUPABASE_URL");
    const serviceRoleKey = Deno.env.get("SUPABASE_SERVICE_ROLE_KEY");
    const anonKey = Deno.env.get("SUPABASE_ANON_KEY");

    if (!supabaseUrl || !serviceRoleKey || !anonKey) {
      throw new Error("Supabase env secrets are not configured");
    }

    // Verify caller is super_admin
    const authHeader = req.headers.get("Authorization");
    if (!authHeader) {
      return new Response(JSON.stringify({ error: "Missing authorization header" }), {
        status: 401,
        headers: { ...corsHeaders, "Content-Type": "application/json" },
      });
    }

    const callerClient = createClient(supabaseUrl, anonKey, {
      global: { headers: { Authorization: authHeader } },
    });
    const supabaseAdmin = createClient(supabaseUrl, serviceRoleKey);

    const { data: { user: caller } } = await callerClient.auth.getUser();
    if (!caller) throw new Error("Unauthorized");

    const { data: callerRole } = await supabaseAdmin
      .from("user_roles")
      .select("role")
      .eq("user_id", caller.id)
      .single();
    if (callerRole?.role !== "super_admin") throw new Error("Only super_admin can invite staff");

    // Validate request body
    let body: any;
    try {
      body = await req.json();
    } catch {
      throw new Error("Invalid JSON request body");
    }

    const { email, phone, full_name, role, avatar_url } = body;

    if (!full_name || typeof full_name !== "string" || full_name.trim().length === 0) {
      throw new Error("Missing required field: full_name");
    }

    if (!role || typeof role !== "string") {
      throw new Error("Missing required field: role");
    }

    const validRoles = ["super_admin", "manager", "agent", "marketer", "pos"];
    if (!validRoles.includes(role)) {
      throw new Error(`Invalid role: ${role}. Must be one of: ${validRoles.join(", ")}`);
    }

    const normalizedEmail = email ? String(email).toLowerCase().trim() : null;

    if (normalizedEmail && !/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(normalizedEmail)) {
      throw new Error("Invalid email format");
    }

    if (!phone && !normalizedEmail) {
      throw new Error("At least one of phone or email is required");
    }

    // If phone provided, handle phone-based registration
    if (phone) {
      const phoneKey = significantPhone(phone);
      if (phoneKey.length !== 10) throw new Error("Phone number must contain 10 digits");

      // Indexed lookup instead of full-table scan
      const matchedStaff = await findStaffByPhone(supabaseAdmin, phoneKey);

      if (matchedStaff) {
        const { error: updateStaffError } = await supabaseAdmin
          .from("staff_directory")
          .update({
            full_name: full_name.trim(),
            role,
            avatar_url: avatar_url || null,
            phone,
            is_active: true,
            email: normalizedEmail,
            updated_at: new Date().toISOString(),
          })
          .eq("id", matchedStaff.id);
        if (updateStaffError) throw updateStaffError;
      } else {
        const { error: insertStaffError } = await supabaseAdmin
          .from("staff_directory")
          .insert({
            phone,
            full_name: full_name.trim(),
            role,
            avatar_url: avatar_url || null,
            is_active: true,
            email: normalizedEmail,
          });
        if (insertStaffError) throw insertStaffError;
      }
    }

    // If no email, return early (phone-only registration)
    if (!normalizedEmail) {
      return new Response(JSON.stringify({ success: true, mode: "phone_registered", phone }), {
        headers: { ...corsHeaders, "Content-Type": "application/json" },
      });
    }

    // Check if already invited and pending (indexed query)
    const { data: existing } = await supabaseAdmin
      .from("staff_invitations")
      .select("id")
      .eq("email", normalizedEmail)
      .eq("status", "pending")
      .maybeSingle();
    if (existing) throw new Error("An invitation is already pending for this email");

    // Create user with admin API
    const { data: newUser, error: createError } = await supabaseAdmin.auth.admin.createUser({
      email: normalizedEmail,
      email_confirm: true,
      user_metadata: { full_name: full_name.trim() },
    });
    if (createError) throw createError;

    // Assign role
    await supabaseAdmin
      .from("user_roles")
      .update({ role })
      .eq("user_id", newUser.user.id);

    // Link staff directory (indexed lookups instead of full-table scan)
    if (phone) {
      const phoneKey = significantPhone(phone);
      const staffToLink = await findStaffByPhone(supabaseAdmin, phoneKey);
      if (staffToLink) {
        await supabaseAdmin
          .from("staff_directory")
          .update({ user_id: newUser.user.id, email: normalizedEmail })
          .eq("id", staffToLink.id);
      }
    } else {
      const staffByEmail = await findStaffByEmail(supabaseAdmin, normalizedEmail);

      if (staffByEmail) {
        await supabaseAdmin
          .from("staff_directory")
          .update({
            user_id: newUser.user.id,
            full_name: full_name.trim(),
            role,
            avatar_url: avatar_url || null,
            is_active: true,
            updated_at: new Date().toISOString(),
          })
          .eq("id", staffByEmail.id);
      } else {
        const { error: insertEmailStaffError } = await supabaseAdmin
          .from("staff_directory")
          .insert({
            user_id: newUser.user.id,
            email: normalizedEmail,
            phone: null,
            full_name: full_name.trim(),
            role,
            avatar_url: avatar_url || null,
            is_active: true,
          });
        if (insertEmailStaffError) throw insertEmailStaffError;
      }
    }

    // Record the invitation
    await supabaseAdmin.from("staff_invitations").insert({
      email: normalizedEmail,
      phone: phone ? String(phone).trim() : null,
      full_name: full_name.trim(),
      role,
      invited_by: caller.id,
      status: "accepted",
      accepted_at: new Date().toISOString(),
    });

    // Send password reset
    await supabaseAdmin.auth.admin.generateLink({
      type: "recovery",
      email: normalizedEmail,
      options: { redirectTo: `${req.headers.get("origin") || supabaseUrl}/reset-password` },
    });

    return new Response(JSON.stringify({ success: true, user_id: newUser.user.id, mode: "staff_email_provisioned" }), {
      headers: { ...corsHeaders, "Content-Type": "application/json" },
    });
  } catch (error: any) {
    console.error("invite-staff error:", error);
    return new Response(JSON.stringify({ error: error.message }), {
      status: 400,
      headers: { ...getCorsHeaders(req), "Content-Type": "application/json" },
    });
  }
});

import { createClient } from "https://esm.sh/@supabase/supabase-js@2";

const ALLOWED_ORIGINS = [
  "https://aquaprimesales.vercel.app",
  "http://localhost:5000",
  "http://localhost:5173",
  "http://localhost:8100",
];

function getCorsHeaders(req: Request) {
  const origin = req.headers.get("Origin") || "";
  const allowed = ALLOWED_ORIGINS.includes(origin) ? origin : ALLOWED_ORIGINS[0];
  return {
    "Access-Control-Allow-Origin": allowed,
    "Access-Control-Allow-Headers": "authorization, x-client-info, apikey, content-type",
    "Access-Control-Allow-Methods": "POST, OPTIONS",
    "Vary": "Origin",
  };
}

function normalizeEmail(email?: string | null): string | null {
  if (!email) return null;
  return String(email).trim().toLowerCase();
}

function significantPhone(phone?: string | null): string | null {
  if (!phone) return null;
  const digits = String(phone).replace(/\D/g, "");
  return digits.length >= 10 ? digits.slice(-10) : digits || null;
}

function maskPhoneLast3(phone?: string | null): string {
  const digits = significantPhone(phone) || "";
  return digits.length >= 3 ? `***${digits.slice(-3)}` : "***";
}

function isSyntheticPhoneEmail(email?: string | null): boolean {
  if (!email) return false;
  return /^phone_\d+@phone\.aquaprime\.app$/i.test(String(email).trim());
}

/**
 * Finds a staff_directory row matching the user by user_id, email, or phone.
 * Uses indexed queries instead of full-table scan.
 */
async function findStaffMatch(
  supabaseAdmin: any,
  userId: string,
  canonicalEmail: string | null,
  canonicalPhone: string | null
) {
  const cols = "id, user_id, full_name, avatar_url, role, email, phone, is_active";

  // 1. Try by user_id (exact indexed lookup)
  const { data: byUserId } = await supabaseAdmin
    .from("staff_directory")
    .select(cols)
    .eq("user_id", userId)
    .eq("is_active", true)
    .maybeSingle();
  if (byUserId) return byUserId;

  // 2. Try by email (uses staff_directory_email_unique_idx)
  if (canonicalEmail) {
    const { data: byEmail } = await supabaseAdmin
      .from("staff_directory")
      .select(cols)
      .ilike("email", canonicalEmail)
      .eq("is_active", true)
      .maybeSingle();
    if (byEmail) return byEmail;
  }

  // 3. Try by phone (uses staff_directory_phone_key_idx via RPC or text match)
  if (canonicalPhone) {
    const { data: byPhone } = await supabaseAdmin
      .from("staff_directory")
      .select(cols)
      .eq("is_active", true)
      .filter("phone", "not.is", null)
      .limit(100);

    // Filter by significant phone digits (last 10) - limited set, not full table
    if (byPhone) {
      const match = byPhone.find(
        (row: any) => significantPhone(row.phone) === canonicalPhone
      );
      if (match) return match;
    }
  }

  return null;
}

/**
 * Finds a staff_invitation matching the user by email or phone.
 * Uses indexed queries instead of full-table scan.
 */
async function findInvitationMatch(
  supabaseAdmin: any,
  canonicalEmail: string | null,
  canonicalPhone: string | null
) {
  const cols = "id, email, phone, full_name, role, status, accepted_at, created_at";

  // 1. Try by email (uses idx_staff_invitations_email)
  if (canonicalEmail) {
    const { data: byEmail } = await supabaseAdmin
      .from("staff_invitations")
      .select(cols)
      .eq("email", canonicalEmail)
      .in("status", ["pending", "accepted"])
      .order("created_at", { ascending: false })
      .limit(1)
      .maybeSingle();
    if (byEmail) return byEmail;
  }

  // 2. Try by phone (uses staff_invitations_phone_key_idx)
  if (canonicalPhone) {
    const { data: byPhone } = await supabaseAdmin
      .from("staff_invitations")
      .select(cols)
      .in("status", ["pending", "accepted"])
      .filter("phone", "not.is", null)
      .order("created_at", { ascending: false })
      .limit(50);

    if (byPhone) {
      const match = byPhone.find(
        (row: any) => significantPhone(row.phone) === canonicalPhone
      );
      if (match) return match;
    }
  }

  return null;
}

/**
 * Finds a customer matching the user by user_id, email, or phone.
 * Uses indexed queries instead of full-table scan.
 */
async function findCustomerMatch(
  supabaseAdmin: any,
  userId: string,
  canonicalEmail: string | null,
  canonicalPhone: string | null
) {
  const cols = "id, user_id, phone, email";

  // 1. Try by user_id (uses idx_customers_user_id)
  const { data: byUserId } = await supabaseAdmin
    .from("customers")
    .select(cols)
    .eq("user_id", userId)
    .maybeSingle();
  if (byUserId) return byUserId;

  // 2. Try by phone (uses customers_phone_key_idx / idx_customers_phone)
  if (canonicalPhone) {
    const { data: byPhone } = await supabaseAdmin
      .from("customers")
      .select(cols)
      .filter("phone", "not.is", null)
      .limit(100);

    if (byPhone) {
      const match = byPhone.find(
        (row: any) => significantPhone(row.phone) === canonicalPhone
      );
      if (match) return match;
    }
  }

  // 3. Try by email (non-synthetic only)
  if (canonicalEmail && !isSyntheticPhoneEmail(canonicalEmail)) {
    const { data: byEmail } = await supabaseAdmin
      .from("customers")
      .select(cols)
      .ilike("email", canonicalEmail)
      .maybeSingle();
    if (byEmail) return byEmail;
  }

  return null;
}

Deno.serve(async (req) => {
  const corsHeaders = getCorsHeaders(req);
  if (req.method === "OPTIONS") {
    return new Response("ok", { headers: corsHeaders });
  }

  try {
    const supabaseUrl = Deno.env.get("SUPABASE_URL");
    const serviceRoleKey = Deno.env.get("SUPABASE_SERVICE_ROLE_KEY");
    const anonKey = Deno.env.get("SUPABASE_ANON_KEY");

    if (!supabaseUrl || !serviceRoleKey || !anonKey) {
      throw new Error("Supabase env secrets are not configured");
    }

    const authHeader = req.headers.get("Authorization");
    if (!authHeader) {
      return new Response(JSON.stringify({ error: "Missing authorization header" }), {
        status: 401,
        headers: { ...corsHeaders, "Content-Type": "application/json" },
      });
    }

    const callerClient = createClient(supabaseUrl, anonKey, {
      global: { headers: { Authorization: authHeader } },
    });
    const supabaseAdmin = createClient(supabaseUrl, serviceRoleKey);

    const {
      data: { user },
      error: userError,
    } = await callerClient.auth.getUser();
    if (userError || !user) {
      throw userError || new Error("Unauthorized");
    }

    const userId = user.id;
    const canonicalEmail = normalizeEmail(user.email);
    const canonicalPhone = significantPhone(user.phone);
    const providers = (user.app_metadata?.providers || []) as string[];
    const primaryProvider = user.app_metadata?.provider as string | undefined;
    const identityProviders = (user.identities || []).map((identity: any) => identity?.provider);
    const hasGoogle =
      providers.includes("google") ||
      identityProviders.includes("google") ||
      primaryProvider === "google";
    const loginMethod = hasGoogle ? "google" : "phone";

    // Indexed lookup: user_roles by user_id
    const { data: roleData } = await supabaseAdmin
      .from("user_roles")
      .select("role")
      .eq("user_id", userId)
      .maybeSingle();

    const currentRole = roleData?.role || null;

    // Indexed lookups instead of full-table scan
    const staffMatch = await findStaffMatch(supabaseAdmin, userId, canonicalEmail, canonicalPhone);
    const invitationMatch = await findInvitationMatch(supabaseAdmin, canonicalEmail, canonicalPhone);

    const resolvedStaffRole =
      currentRole && currentRole !== "customer"
        ? currentRole
        : staffMatch?.role || invitationMatch?.role || null;

    if (resolvedStaffRole) {
      const { error: roleDeleteError } = await supabaseAdmin
        .from("user_roles")
        .delete()
        .eq("user_id", userId);
      if (roleDeleteError) throw roleDeleteError;

      const { error: roleInsertError } = await supabaseAdmin
        .from("user_roles")
        .insert({ user_id: userId, role: resolvedStaffRole });
      if (roleInsertError) throw roleInsertError;

      if (staffMatch) {
        const { error: linkStaffError } = await supabaseAdmin
          .from("staff_directory")
          .update({
            user_id: userId,
            email: canonicalEmail || staffMatch.email || null,
            phone: canonicalPhone || staffMatch.phone || null,
            is_active: true,
          })
          .eq("id", staffMatch.id);
        if (linkStaffError) throw linkStaffError;
      } else if (invitationMatch) {
        const { data: existingDirByUser } = await supabaseAdmin
          .from("staff_directory")
          .select("id")
          .eq("user_id", userId)
          .maybeSingle();

        if (existingDirByUser) {
          const { error: updateDirError } = await supabaseAdmin
            .from("staff_directory")
            .update({
              email: canonicalEmail || invitationMatch.email || null,
              phone: canonicalPhone || invitationMatch.phone || null,
              full_name: invitationMatch.full_name || null,
              role: invitationMatch.role,
              is_active: true,
            })
            .eq("id", existingDirByUser.id);
          if (updateDirError) throw updateDirError;
        } else {
          const { error: insertDirError } = await supabaseAdmin
            .from("staff_directory")
            .insert({
              user_id: userId,
              email: canonicalEmail || invitationMatch.email || null,
              phone: canonicalPhone || invitationMatch.phone || null,
              full_name: invitationMatch.full_name || "Staff",
              role: invitationMatch.role,
              avatar_url: null,
              is_active: true,
            });
          if (insertDirError) throw insertDirError;
        }

        const { error: invitationUpdateError } = await supabaseAdmin
          .from("staff_invitations")
          .update({
            status: "accepted",
            accepted_at: invitationMatch.accepted_at || new Date().toISOString(),
          })
          .eq("id", invitationMatch.id);
        if (invitationUpdateError) throw invitationUpdateError;
      }

      const fullName = staffMatch?.full_name || invitationMatch?.full_name || user.user_metadata?.full_name || "Staff";
      const profileEmail = !isSyntheticPhoneEmail(canonicalEmail) ? canonicalEmail : null;
      const { error: profileUpsertError } = await supabaseAdmin
        .from("profiles")
        .upsert(
          {
            user_id: userId,
            full_name: fullName,
            display_name: fullName,
            email: profileEmail,
            phone: canonicalPhone || null,
            avatar_url: staffMatch?.avatar_url || null,
            is_active: true,
            phone_verified: !!canonicalPhone,
            google_linked: hasGoogle,
            onboarding_complete: true,
          },
          { onConflict: "user_id" }
        );
      if (profileUpsertError) throw profileUpsertError;

      return new Response(
        JSON.stringify({
          type: "staff",
          role: resolvedStaffRole,
          staffId: staffMatch?.id || null,
        }),
        { headers: { ...corsHeaders, "Content-Type": "application/json" } }
      );
    }

    // Indexed customer lookup instead of full-table scan
    const customerMatch = await findCustomerMatch(supabaseAdmin, userId, canonicalEmail, canonicalPhone);

    if (customerMatch) {
      if (customerMatch.user_id && customerMatch.user_id !== userId) {
        return new Response(
          JSON.stringify({
            type: "new_customer_known_phone",
            maskedPhone: maskPhoneLast3(customerMatch.phone),
          }),
          { headers: { ...corsHeaders, "Content-Type": "application/json" } }
        );
      }

      if (!customerMatch.user_id) {
        const { error: linkError } = await supabaseAdmin
          .from("customers")
          .update({ user_id: userId })
          .eq("id", customerMatch.id);
        if (linkError) throw linkError;
      }

      const { error: roleUpsertError } = await supabaseAdmin
        .from("user_roles")
        .upsert({ user_id: userId, role: "customer" }, { onConflict: "user_id" });
      if (roleUpsertError) throw roleUpsertError;

      const profileEmail = !isSyntheticPhoneEmail(canonicalEmail) ? canonicalEmail : null;
      const profileName = user.user_metadata?.full_name || user.user_metadata?.name || "Customer";
      const { error: profileUpsertError } = await supabaseAdmin
        .from("profiles")
        .upsert(
          {
            user_id: userId,
            full_name: profileName,
            display_name: profileName,
            email: profileEmail,
            phone: canonicalPhone || null,
            is_active: true,
            phone_verified: !!canonicalPhone,
            google_linked: hasGoogle,
            onboarding_complete: true,
          },
          { onConflict: "user_id" }
        );
      if (profileUpsertError) throw profileUpsertError;

      return new Response(
        JSON.stringify({
          type: "existing_customer",
          customerId: customerMatch.id,
          googleLinked: hasGoogle,
        }),
        { headers: { ...corsHeaders, "Content-Type": "application/json" } }
      );
    }

    const profileEmail = !isSyntheticPhoneEmail(canonicalEmail) ? canonicalEmail : null;
    const profileName = user.user_metadata?.full_name || user.user_metadata?.name || null;
    const { error: profileUpsertError } = await supabaseAdmin
      .from("profiles")
      .upsert(
        {
          user_id: userId,
          full_name: profileName,
          display_name: profileName,
          email: profileEmail,
          phone: canonicalPhone || null,
          is_active: true,
          phone_verified: !!canonicalPhone,
          google_linked: hasGoogle,
          onboarding_complete: false,
        },
        { onConflict: "user_id" }
      );
    if (profileUpsertError) throw profileUpsertError;

    return new Response(
      JSON.stringify({
        type: "onboarding_required",
        authUserId: userId,
        loginMethod,
      }),
      { headers: { ...corsHeaders, "Content-Type": "application/json" } }
    );
  } catch (error) {
    console.error("resolve-user-identity error:", error);
    return new Response(
      JSON.stringify({
        error: "Internal server error",
      }),
      {
        status: 500,
        headers: {
          ...getCorsHeaders(req),
          "Content-Type": "application/json",
        },
      }
    );
  }
});

